INSERT INTO `plant_family` VALUES ('1', '金边龙舌兰', 'Agave americanavar. Marginata', '金边龙舌兰', '', '不容易死', '西南、华南。原产美洲的沙漠地带', 'http://www.boqii.com/entry/photo/2126/0,http://www.boqii.com/entry/photo/2126/5401', '　', '', '', '', '龙舌兰科', '龙舌兰属', '', 'Agave americanavar. Marginata', 'Agave americana var.variegata', '　　 　　金边龙蛇兰为多年生常绿草本。茎短、稍木质。叶多丛生，呈剑形，大小不等，小者长145～25cm，宽5～7cm，大者长可达1m，质厚，平滑，绿色，边缘有黄白色条带镶边，有红或紫褐色刺状锯齿。花叶有多数横纹，花黄绿色，肉质；雄蕊6，花药丁字形着生；子房3室，花柱钻形。蒴果长椭圆形，胞间开裂。种子多数，扁平，黑色。花期夏季。', '　　金边龙舌兰的栽培难度并不高，是很多花友都非常', '　　　　金边龙舌兰常用分株和播种繁殖。分株，常在早春4月换盆时进行，将母株托出，把母株旁的蘖芽剥下另行栽植。播种，则通过异花授粉才能结实，采种后于4－5月播种，约2周后发芽，幼苗', 'http://img.boqiicdn.com/Data/BK/P/imagick37971445246358.jpg', 'http://www.boqii.com/entry/detail/2126.html', '');
INSERT INTO `plant_family` VALUES ('2', '花烟草', 'Nicotiana', '花烟草', '花烟草、长花烟草、大花烟草', '不容易死', '原产阿根延和巴西，中国哈尔滨、北京、南京等市有引种栽培', 'http://www.boqii.com/entry/photo/1976/0,http://www.boqii.com/entry/photo/1976/5551', '植物　　', '被子植物门', '双子叶植物纲', '管状花目', '茄科', '烟草属', '花烟草', 'Nicotiana alata Link et Otto', 'Nicotiana alata', '　　 　　花烟草高0.6－1.5米，全体被粘毛。叶在茎下部铲形或矩圆形，基部稍抱茎或具翅状柄，向上成卵形或卵状矩圆形，近无柄或基部具耳，接近花序即成披针形。花序为假总状式，疏散生几朵花；花梗长5－20毫米。花萼杯状或钟状，长15－25毫米，裂片钻状针形，不等长；花冠淡绿色，筒长5－10厘米，筒部直径约3－4毫米，喉部直径约6－8毫米，檐部宽15－25毫米，裂片卵形，短尖，2枚较其余3枚为长；雄蕊不等长，其中1枚较短。蒴果卵球状，长12－17毫米。种子长约0.7毫米，灰褐色。', '　　的外形比较特殊，有些花友非常喜爱，所以会烟草作为观赏用，但是花烟草原产于南美，所以性耐旱但是不耐寒，如果你栽培了花烟草的话则需注意为花烟草提供一个合适的生长环境，以免花烟草冻伤。　　花烟草喜温暖、向阳的环境及肥沃疏松的土壤，耐旱，不耐寒。喜温暖、向阳环境，不耐寒，较耐热。　　日照需充足，日照不足植株易徒长，开花疏松而色淡不美观。定植成活后摘心一次，促使多分枝。梅雨需防患长期潮湿，适温约10－25度。栽培花烟草土质以富含有机质之砂质壤土为佳，排水需良好，排水不良根部容易导致腐烂。　　花烟草喜在肥沃、排水良好的土壤环境下生长。花烟草上盆必须及时，否则会引起根系的严重盘结和植株老化。为保证生长的顺利，基质尽量保证透水透气、保肥，土壤pH值为5.5～5.8，在生产中，可采用pH值6.0的混合基质。这一阶段的土壤温度很重要，对于刚移植的种苗，白天温度为18℃～21℃，晚间温度应在16℃～18℃。温度过低会引起白化苗，温度剧升会引起叶片灼伤，严重时会导致部分种苗。移苗后的第一次浇水必须浇透，否则会影响成苗率及后期盆花生长的整齐度。花烟草的育苗阶段很关键，其后期生长也很重要。', '　　花烟草的花期较长，并且花色鲜艳，有一定的观赏价值，由于花烟草的花期一般在6－9月，所以也是夏季园林中的优良　　花烟草种子粒径较小，每克约11500粒，中国国内生产商一般采用丸粒化种子。育苗基质应选保湿效果好、透气性好的进口草炭为宜，pH值为5.5～5.8，播种前要求基质湿度饱和。　　育苗依苗期　　\n第一阶段\n　　胚根萌发阶段，　\n　第二阶段\n　　茎和子叶长出，时间从第一阶段结束到根长1.2～1.4cm，子叶长出。土壤温度降低，保持20℃～24℃，光照调至5400～13000lux。子叶一旦展开每周即可施用50～75ppm的14－0－14缓释肥，幼苗根系穿透基质后可让土壤见干见湿，但避免干燥，否则幼苗将停止生长。这一阶段一般持续7～10天。　\n　第三阶段\n　　根系深入穴盘，达2.5cm，出现2～3片真叶。这一阶段的重点应放在浇水和施肥管理上，使花烟草产生发达的根系。每24小时进行一次干湿循环周期，增加施肥的浓度，一般一周施用一次100～150ppm氮肥，　\n　第四阶段\n　　这一阶段后期，发达的根系占据整个穴孔，花茎应有3～4片叶子。此阶段的重点还在于浇水和施肥管理。土壤温度必须保持16℃～17℃，光照可上升至16000～38000lux。施肥同第三阶段，但此阶段后期上盆前7～10天需减少浇水与施肥，以适当炼苗。', 'http://img.boqiicdn.com/Data/BK/P/imagick84711440409959.jpg', 'http://www.boqii.com/entry/detail/1976.html', '');
INSERT INTO `plant_family` VALUES ('3', '锦晃星', 'Echeveria pulvinata', '锦晃星', '金晃星、绒毛掌猫耳朵', '不容易死', '原产墨西哥', 'http://www.boqii.com/entry/photo/2089/0,http://www.boqii.com/entry/photo/2089/5438', '', '', '', '', '', '', '', '', '', '　　锦晃星为景天科拟石莲属多肉植物，是现在比较常见的多肉植物 　　锦晃星为多年生小灌木状多浆植物，灰绿色卵状倒披针形肥厚肉质叶轮状互生，全缘，椭圆尖头，长3cm－4cm，宽2cm～2.5cm，厚约1cm，玲凉季节阳光下，叶端及上缘呈红色。棕褐色茎细棒状，0.8cm～1cm，下端横卧，分枝群生，高15cm～20cm。晚秋至初春由枝头抽出花梗，开鲜红色5瓣花，小花钟形，半开状，花长1－5cm，穗状花序。　　　　　　　　　　　　　　　　', '　　的栽培较为普遍，喜欢凉爽、干燥和阳光充足的环境，忌水湿和闷热。锦晃星的外形非常可爱，叶片上布满了细短的白色毫毛，叶缘顶端在光照充足的情况下会出现红色，非常鲜艳夺目。　　锦晃星性喜干燥、温暖、阳光充足；要求排水良好的砂质壤土，忌积水；怕低温，冬季室温最好保持在10℃左右。　　每年早春换盆，加入疏松肥沃的腐叶土、土和粗沙的混合土。生长期不宜多浇水，盆土过湿，茎叶易徒长，叶片和根部霉烂，失去观赏价值。特别在冬季低温条件下，水分过多，根部易。盛夏高温，也不宜多浇水，否则基部叶片发黄萎缩。阳台栽培切忌阵雨冲淋。每年早春换盆，同时换上疏松肥土。生长期每月施肥1次，以保持叶片青翠碧绿。每次不可过浓，浓肥伤根。但施肥过多，引起节间拉长，影响姿态。如枝条徒长或衰老，可短剪施肥，更新复壮。　　每15～20天施一次“低氮高磷、钾”的薄肥，施肥时注意肥水不要溅到叶片上，以免形成难看的斑痕，很难去掉。冬季放在室内阳光充足处，保持6～8℃的，节制浇水，以防因低温、潮湿引起的烂根。盛夏高温时也不宜浇水过多，否则会因根部腐烂而造成叶片萎缩、脱落，并加强通风，防止暴雨冲淋。　　每年春季翻盆一次，盆土要求疏松、排水良好。常用腐叶土、园土、粗沙各1份，混匀后使用，并加少量的骨粉作基肥。栽培3～4年以后的锦晃星，植株容易老化，应培育新苗对老株进行更新。　　冬季放在室内阳光充足处，保持6℃至8℃的温度，节制浇水，以防因低温潮湿引起的烂根。盛夏高温时也不宜浇水过多，否则会因根部腐烂而造成的叶片萎宿、脱落，并加强通风，防止暴雨冲淋。本种虽然在半阴处也能正常生长，但叶缘及叶片上部的红色会减退，甚至消失。', '　　　　枝插一般切取带有叶片的顶枝，长10厘米左右，插于沙土中，10～15天即可生根；叶插是将叶片切下，待切口晾干后，插入或平卧在沙床上，保持稍有潮气，20天左右生根。叶插较为困难，常切取旁生的幼株进行扦插。　　在8至10月间最为适宜，在温室四季都可进行。枝插，插条用嫩枝、老枝、叶片都可以。在8－10月切取顶枝，长20－25厘米，插于沙床，约10－15天生根。叶插，将叶片切下，待切口晾干后，插入或平卧在沙床，保持插壤稍有湿润，约20－30天生根。', 'http://img.boqiicdn.com/Data/BK/P/imagick14741443603797.jpg', 'http://www.boqii.com/entry/detail/2089.html', '');
INSERT INTO `plant_family` VALUES ('4', '丽格海棠', 'Rieger begonias', '丽格海棠', '', '不容易死', '热带和亚热带地区', 'http://www.boqii.com/entry/photo/2092/0,http://www.boqii.com/entry/photo/2092/5435', '', '', '', '', '', '', '', '', '', '　　 　　丽格海棠为须根系，株形丰满，株高15～30厘米，枝叶翠绿，茎枝肉质多汁。单叶互生，不对称心形，叶色多翠绿，少有红棕色。花形多样，多为重瓣，花色丰富，有红、橙、黄、白等，花朵硕大、色彩艳丽，具有独特的姿、色、香；而且花期长，可从12月持续至翌春4月。盛花期为4至6月和9至12月。　　　　　　　　　　　　　　　　　　　　　', '　　丽格海棠常作室内栽培，也是一种比较难得的温室盆栽观赏花卉，我们常见的丽格海棠多为重瓣，非常漂亮。很多朋友或许对丽格海棠并不熟悉，小编就为你介绍一下丽格海棠的栽培方法及注意事项。　　丽格海棠属于温室定量型短日照植物，其适温为18℃～22℃。家庭丽格海棠应注意，温度不可低于15℃，夏季则应注意降温，温度最好不要超过25℃。等到10月下旬后，可适当增强丽格海棠的光照，11月中旬后作短日处理，尽量让他充分接受光照，以保证生长开花。　　丽格海棠浇水应视气候条件决定，要掌握见干见湿的原则。通常夏季水分蒸发快，则需水量多，浇水宜在早晚，次数视盆土湿润度而定。同时还应注意保持空气湿度，时常喷洒叶面水，不过不能将水喷到花朵上。冬季气温低，则要少浇水，尽量在晴天中午浇水，水温也应与室温相近，以免水温低冻伤根系。　　丽格海棠对肥料的要求较为严格。小苗以氮肥为主，可促进成型，随着植株生长，应逐渐加大磷、钾肥含量，开花前加大施肥量，还可适当均匀的喷施叶面肥，不过浓度不可过大，控制在1％一2％即可，正反面都要喷。丽格海棠要薄施勤肥，同时还可以选择丽格海棠栽培专用肥哦。　　家养丽格海棠病虫害较少，不过还是要注意防治。定期定量喷施一些杀菌剂，以细菌性软腐病和白粉病，可采用农用链霉素200ug／g他多茵灵1000倍液喷雾哦。当然为了避免农药污染家居空气，我们可以自己学着配制土农药，防治效果更佳，还没有危害哦。', '　　　\n　一、扦插\n　　丽格海棠不仅可以枝插，也可以叶插。枝插时，枝条长短要适度，用刀片将枝条下部切成马蹄形；叶插时，要选用生长旺盛六分成熟的叶子，将叶柄下端用刀片斜切。扦插基质为蛭石粉或素砂，已污染的基质要消毒再用。将插穗插入后要浇透水，但叶面上不可积水。而且用塑料膜将其罩上，放于散射光处，适当通风，避免高温。约3周插条就可发根。　　当见有新叶长出时，说明已发根。用枝插法获得的植株没有地下块茎。插叶经过3周后叶柄下部也可长出须根，但需再经一个半月才能从叶柄下部长出不定芽，并逐渐出土。照片2便是用插叶培养的植株。　\n　二、播种\n　　1、播种：由于种子非常小，必须采用小粒种子播种法。目前，丽格海棠的种子基本上都是进口的，分包衣粒和非包衣粒两种。最好从大的花木公司邮购原包装且没有破损的种子，这样可以保证发芽成苗，散装的种子很难发芽。　　2、播种容器，包衣粒种子由于可以分拣，可用穴苗盘，非包衣粒种子只能用育苗盘。播种基质为草炭土和蛭石粉各l份，粉碎消毒，然后掺和搅拌，成半湿状态待用。因草炭土在干燥状态下具有斥水性，浇不进水，故不能在干燥状态下使用。播种时先将基质放人育苗盘中，再用喷壶浇透水。包衣粒种子可用镊子分拣，每穴一粒，非包衣粒种子可掺人适量的微细蛭石粉，撒播于育苗盘中。　　播种后均不必覆土，只用细喷壶喷雾即可，再用透明塑膜将育苗盘包住。在环境温度20℃左右的条件下，大约12天开始出苗。当小苗长出真叶时，可适当透气，促其发根。小苗头3个月内长得很慢。初夏播种的小苗，整个　　立秋后天气凉爽了，可逐渐揭掉塑料膜炼苗，到初冬时就可上盆了。要用较小的底部多孔的花盆，培养土可用草炭土2份和蛭石粉1份（或者用素砂1份）混合配制，上盆前控制浇水，使育苗盘中的培养土处于半干状态，这样起苗时可不散团伤根。刚上盆的小苗要防止天气变化温度过高，同时要用塑料膜罩上，但不可过于严密，要适当通风，以防烂苗。　　在家庭条件下，头一年长不成大株，但可见花，到第二年才能培养成大株。第二年时可换大些的花盆。　\n　三、组织培养\n　　这是快速获得大量花苗的有效方法，在家庭条件下也可获得成功。在生长迁盛', 'http://img.boqiicdn.com/Data/BK/P/imagick50981443604909.jpg', 'http://www.boqii.com/entry/detail/2092.html', '');
INSERT INTO `plant_family` VALUES ('5', '火焰兰', 'Renanthera coccinea Lour.', '火焰兰', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2418/0,http://www.boqii.com/entry/photo/2418/4997', '植物　　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '火焰兰属', '火焰兰', 'Renanthera coccinea Lour.', '', '　　 　　火焰兰茎攀援，粗壮，质地坚硬，圆柱形，长1米以上，粗约1.5厘米，通常不分枝，节间长3-4厘米。叶二列，斜立或近水平伸展，舌形或长圆形，长7-8厘米，宽1.5-3.3厘米，先端稍不等侧2圆裂，基部抱茎并且下延为抱茎的鞘。', '　　火焰兰是由其匍匐茎的伸长而生长，其蔓生能力较强。火焰兰的花色艳丽，是兰科植物中观赏价值非常高的一类热带珍稀，目前在国外非常受欢迎，那么火焰兰应该如何才能养好呢？　　　喜高温环境，生长适宜温度为18~35℃。不耐寒，冬季需在中温或高温温室中，在保持适宜温度条件下，植株无休眠期。　　　　是)中较为喜光的种类，需较强的光照。但附生于树上时不能接受强烈阳光的曝晒，否则叶片会发黄。　　　　无休眠期，在整个生长期间都喜较充足的水。应充分供给水分，以保持盆土的湿润。　　　　喜较高的空气相对湿度，应经常喷洒叶面水，保持空气相对湿度70%?80%，否则会影响植株的生长。　　　　种植时需注意施用基肥，并在生长季每半月追施1次。近开花时要注意增施磷钾肥。　　　　可用蕨根、木炭、树皮块、椰壳等材料配制。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick97441452591977.jpg', 'http://www.boqii.com/entry/detail/2418.html', '');
INSERT INTO `plant_family` VALUES ('6', '金鱼草', 'Snapdragon, Dragon', '金鱼草', '龙头花、狮子花、龙口花、洋彩雀', '不容易死', '中海，广西南宁', 'http://www.boqii.com/entry/photo/1905/0,http://www.boqii.com/entry/photo/1905/5624', '', '', '', '', '', '', '', '', '', ' 　　金鱼草的外形与金鱼非常相似，便于牢记故叫做金鱼草。它的花色丰富多彩、花朵鲜艳结实、花型美丽大方，是一种高达80厘米的花卉植物，具有很高的观赏价值，可以用来点缀家居环境。接下来我们了解下金鱼草的养殖方法。　　喜阳光，也能耐半阴。性较耐寒，不耐酷暑。适生于疏松肥沃、排水良好的突然，在石灰质土壤中也能正常生长。　　1.土壤：金鱼草对土壤要求不高，土壤宜用肥沃、疏松和排水良好的微酸性沙质壤土。　　2.浇水：金鱼草对水分比较敏感，盆土必须保持湿润，盆栽苗必须充分浇水。但盆土排水性要好，不能积水，否则根系腐烂，茎叶枯黄凋萎。　　3.阳光：金鱼草为喜光性草本。阳光充足条件下，植株矮生，丛状紧凑，生长整齐，高度一致，开花整齐，花色鲜艳。半阴条件下，植株生长偏高，花序伸长，花色较淡。　　4.　　5.施肥：金鱼草要加强肥水管理。施肥应注意氮、磷、钾的配合。金鱼草具有根瘤菌，本身有固氮作用，一般情况下不用施氮肥，适量增加磷、钾肥即可。在生长期内，结合浇水每半个月施一次发酵的油渣水，出现花蕾时，用0.1%～0.2%磷酸二氢钾溶液喷洒更佳，每次施肥前应松土除草。　　6.修剪：金鱼草幼苗长至10厘米左右时，就可以做摘心处理，以缩短植株高度，增加侧枝数量，增加花朵。修剪时剪去病弱枝、枯老枝和过密枝条，每次开完花后，剪去开过花的枝条，促使其萌发新枝条继续开花。　　金鱼草是观赏价值很高的一种植物，花色很多，开放时非常艳丽好看，用来布置家居效果肯定很好，金鱼草的养殖方法告诉大家了，希望对大家有所帮助。 　　盆栽的金鱼草宜选择植株低矮，花繁的品种，以提高盆栽的观赏价值。　　盆栽的容器宜用盆径为15厘米左右的泥盆或塑料盆，但透气性要好。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick22501428056022.jpg', 'http://www.boqii.com/entry/detail/1905.html', '');
INSERT INTO `plant_family` VALUES ('7', '乙女心', 'Sedum pachyphyllum', '乙女心', '', '不容易死', '世界多地', 'http://www.boqii.com/entry/photo/2079/0,http://www.boqii.com/entry/photo/2079/5448', '', '', '', '', '', '', '', '', '', '　　 　　叶片密集排列在枝干的顶端。叶片肥厚，叶色翠绿至粉红，新叶色浅、老叶色深，长圆型的叶片靠近枝干处仔细　　　　　　　　　　　　', '　　的栽种难度并不高，不需要花友们花太多的时间精力去打理，所以乙女心对于新手朋友们来说也是很好的选择。不过乙女心在栽种过程中需要少浇水或不浇水，尽可能的保持干燥，才能让乙女心活下来。　　　乙女心比较耐干旱，换盆后浇水不宜多，叶片增大时稍增加。乙女心在要充分给水，不然它会自残，就是大家常说的大把的掉叶。因为，有限的、甚至于没有的水源，不能满足本身，要生存只能让部分枝叶作出“牺牲”。　　　日照充足乙女心更能显示其和形状，不过，如果你将植物一下从低光条件下的室内搬到充满阳光的户外，这个时候要警惕过快的转变强烈的太阳会烧伤叶片，凡事都要有一个过渡的过程，这样才会安全有保证。在夏季生长的理想温度范围是5－25℃，凉爽的秋季干燥，气温会让叶子的颜色变得更加迷人、更加鲜艳美丽。　　　乙女心较喜肥。秋季可施肥1～2次，需控制氮肥用量。盆土太湿，就要用小木棍打松土壤，尽可能让它充满空气，将花盆也尽可能的摆放在通风处，花盆底放一个小铁（木）架，让空气上下对流，良好的空气运动才能减免虫害和疾病的风险。', '　　　　乙女心为景天科景天属多肉植物，对于乙女心的繁殖一般采用扦插的方式进行繁殖。扦插与叶插都可以，扦插时用剪刀剪掉头部，用刀砍都可以，需要注意的是砍下来的枝条需要进行晾干处理，然后干土发根，不要怕它们皱，给水后很快就会恢复到正常的状态。　　有些花友', 'http://img.boqiicdn.com/Data/BK/P/imagick56501443173854.jpg', 'http://www.boqii.com/entry/detail/2079.html', '');
INSERT INTO `plant_family` VALUES ('8', '铁线蕨', 'Adiantum Capillus－veneris L.', '铁线蕨', '铁丝草、少女的发丝、铁线草、水猪毛土', '不容易死', '', 'http://www.boqii.com/entry/photo/2013/0,http://www.boqii.com/entry/photo/2013/5514', '　', '蕨类植物门', '蕨纲', '真蕨目', '铁线蕨科', '铁线蕨属', '', 'Adiantum Capillus－veneris L.', 'Adiantum Capillus－veneris', '　　 　　铁线蕨叶远生或近生，叶脉多回二歧分叉，直达边缘，两面均明显。叶脉多回二歧分叉，直达边缘，两面均明显。叶干后薄草质，草绿色或褐绿色，两面均无毛；叶轴、各回羽轴和小羽柄均与叶柄同色，往往略向左右曲折。', '　　', '　　很多花友在栽培　　铁线蕨常用分株或孢子繁殖，分株繁殖在室内四季均可，但一般在早春结合换盆进行。将母株从盆中取出，切断其根状茎，使每块均带部分根茎和叶片，然后分别种于小盆中。根茎周围覆混合土，灌水后置于阴湿环境中　　孢子繁殖的方法是：将作为基质的泥炭和细砂置于烘箱内高温　　注意在分植前1～2天要移开播种盆上的玻璃进行透气，以免引起植株腐烂或病虫害发生。此外，在温暖阴湿的环境下极易散布孢子自行繁殖。', 'http://img.boqiicdn.com/Data/BK/P/imagick60501441704980.jpg', 'http://www.boqii.com/entry/detail/2013.html', '');
INSERT INTO `plant_family` VALUES ('9', '山茶花', 'Camellia japonica L.', '山茶花', '茶花、曼佗罗树、薮春、山椿', '不容易死', '重庆、浙江、四川、江西及山东；日本、朝鲜半岛', 'http://www.boqii.com/entry/photo/1911/0,http://www.boqii.com/entry/photo/1911/5618', '', '', '', '', '', '', '', '', '', ' 　　含苞待放的山茶花在绿叶的衬托下，阳光的照耀下显的格外羞涩美丽，春天是山茶花盛开的　　以6月中旬和8月底左右最为适宜。选树冠外部组织充实、叶片完整、叶芽饱满的当年生半熟枝为插条，长8～10厘米，先端留2片叶。剪取时，基部尽可能带一点老枝，插后易形成愈伤组织，发根快。插条清晨剪下，要随剪随插，插入基质3厘米左右，扦插时要求叶片互相交接，插后用手指按实。以浅插为好，这样透气，愈合生根快。插床需遮荫，每天喷雾叶面，保持湿润，温度维持在20～25℃，插后约3周开始愈合，6周后生根。当根长3～4厘米时移栽上盆。扦插时使用0．4％～0．5％吲哚丁酸溶液浸蘸插条基部2～5秒，有明显促进生根的效果。　　常用于扦插生根困难或繁殖材料少的　　高枝压条多在4～5月间进行方法是选上年生枝条，在高压部位环状剥皮，环剥宽0.5厘米；用适度大小的塑料薄膜包裹环剥部位，包裹长度10～15厘米，先将下部口扎紧，内装湿润培养土，常保持土壤湿润，再扎紧上部口；发根后即可剪下另行栽植。 　　适用于单瓣或半重瓣品种。种子10月中旬成熟，即可播种。以浅播为好，用蛭石作基质，覆盖6毫米，室温21℃，每晚照光10小时，能促进种子萌发，播后15天开始萌发，30天内苗高达到8厘米，幼苗具2～3片叶时移栽。　　外植体常用实生苗，经常规消毒后切成1厘米长接种在添加激动素1毫克／升、6－苄氨基腺嘌呤1毫克／升和吲哚乙酸0．1毫克／升的MS培养基上，经4周培养只形成愈伤组织，而不形成芽。再转移到新的培养基后，开始形成4厘米的单个枝条，然后在吲哚丁酸0．5毫克／升溶液中浸泡20分钟，再转移到1／2MS培养基上，4周后长根。在长根培养基上生长8周后将苗移栽到装有珍珠岩和泥炭的盆中。　　以上是山茶花的五种繁殖方法，总的来说还是比较容易繁殖的，只要操作方法对、管理好培养基以及控制好环境温度，那么山茶花一定可以繁殖成功的。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick96241428056732.jpg', 'http://www.boqii.com/entry/detail/1911.html', '');
INSERT INTO `plant_family` VALUES ('10', '莲花掌', 'Aeonium tabuliforme f.cristata', '莲花掌', '', '不容易死', '世界各地', 'http://www.boqii.com/entry/photo/2257/0,http://www.boqii.com/entry/photo/2257/5268', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '莲花掌属', '', 'Aeonium tabuliforme f.cristata', 'Aeonium tabuliforme', '　　 　　莲花掌为多年生肉质草本植物，株高可达60厘米，有匍匐茎。叶丛紧密，直立呈莲座状，叶倒卵形，肉质、无毛，表面被白粉，以翠绿色为主，少数为粉蓝或墨绿色。花梗白叶丛中抽出，花茎柔软，有苞片，具白霜。有8～24朵花，聚伞花序，花冠红色，花瓣披针形不张开，花期6～10月。', '　　的叶片莲座状排列，是非常常见的多肉，不但可以盆栽在室内，也可以地载，用于花坛、花境的点缀。那么人工栽培莲花掌应该注意哪些问题呢？　　莲花掌喜阳光充足、通风良好的环境，需有大量的阳光直接照射，在期间也是如此。家庭种植时，应将其摆放在露天的阳台上，或能照射到阳光的窗台上。如果缺乏阳光照射，植株的叶子就会变长，还会提早脱落。　　　莲花掌植株为阳性植物，不耐寒。春夏季正常的室温即可，越冬期间温度要保持在10℃以上。　　　莲花掌期间适量浇水，冬季如果将植株放在10℃的环境之中让其休眠的话，要等到培养土上半部分干后才可浇水。　　　　莲花掌在生长旺盛期间，每两星期施标准液肥一次。　　　　种植大座莲的盆土宜用腐叶土，或用泥炭和珍珠岩拌合，并稍加骨粉或过磷酸钙的混合土。由于植株生长迅速，每年或隔年需换盆一次。换盆时注意将植株栽牢。', '　　多肉　　通常繁殖莲花掌多用分株法，但是为了满足大量　　选择健壮无病的莲花掌老株，将其最外几轮的充实叶片小心摘下，注意最好保持叶片完整，尤其是叶片基部，因为小植株从这里长出。把取下的叶片平放在无日光直射的明亮之处放上一周以使伤口愈合，经过这样处理插穗不容易烂，新株可以很快长出。然后将它们平插在盛有素土的花盆里，只需把叶片基部稍微入土即可。用喷壶小心喷水一次，接着将花盆移到间有日光直射的地方，保持环境温度在20℃至30\'C。大约经过4周至6周，莲花掌叶片基部表面就会长出小凸起，这就是莲花掌新株。照样还是见干浇水，待莲花掌新株冠径达到1厘米左右时，迫施一次稀薄液体', 'http://img.boqiicdn.com/Data/BK/P/imagick71761448529487.jpg', 'http://www.boqii.com/entry/detail/2257.html', '');
INSERT INTO `plant_family` VALUES ('11', '高砂之翁', '', '高砂之翁', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2410/0,http://www.boqii.com/entry/photo/2410/5005', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '拟石莲花属', '高砂之翁', '', '', '　　 　　高砂之翁茎部粗壮，会随着', '　　的外形比较特别，和绿化带中的比较像，但完全不是同一类。高砂之翁日照，对水分的要求并不高，春秋可以正常浇水，由于高砂之翁是大型植株，所以想要养好的话，就需要注意小编为你整理的四个注意事项。　喜阳光，高砂之翁需要接受充足日照叶色才会艳丽，株型才会更紧实美观；日照太少则叶色浅，叶片排列松散。夏季炎热时要注意通风、遮荫，避免强阳光直射。　　不干不浇，浇必浇透，宁干勿湿。冬季及阴雨天不浇水。空气干燥时可向叶面喷水。　　一般不需要施肥，每年在换盆时，在盆底放少量有机肥即可。　　高砂之翁是大型植株，随着生长的状态须每1-2年换盆一次，盆径可以比株径大1-2寸，这样可促进植株成长。', '　　　　高砂之翁需要接受充足日照叶色才会艳丽，株型才会更紧实美观。日照太少则叶色浅，叶片排列松散。高砂之翁是大型植株，随着', 'http://img.boqiicdn.com/Data/BK/P/imagick16691452503343.png', 'http://www.boqii.com/entry/detail/2410.html', '');
INSERT INTO `plant_family` VALUES ('12', '金银花', 'Lonicera japonica Thunb.', '忍冬', '金银藤、银藤、二色花藤、二宝藤、右转藤、子风藤、鸳鸯藤、二花', '不容易死', '', 'http://www.boqii.com/entry/photo/1984/0,http://www.boqii.com/entry/photo/1984/5543', '', '', '', '', '', '', '', '', '', '　　 　　金银花属多年生半常绿缠绕及匍匐茎的灌木。小枝细长，中空，藤为褐色至赤褐色。卵形叶子对生，枝叶均密生柔毛和腺毛。夏季开花，苞片叶状，唇形花有淡香，外面有柔毛和腺毛，雄蕊和花柱均伸出花冠，花成对生于叶腋，花色初为白色，渐变为黄色，黄白相映，球形浆果，熟时黑色。　　　　　　　　　　　　　　　　　　　　　　　', '　　金银花又名鸳鸯藤、双花等，由于金银花初开为雪白，后变金黄色，并且同时在枝条上两色分明，故此命名。金银花的藤条可以缠绕别的物体，人工栽培的时候需要注意为其打造一个可供缠绕的支架以便金银花生长。', '　　　\n　一、扦插\n　　一年四季除严冬外，据山东产区试验均可大田扦插，成活率都很高。　\n　二、扦插地点\n　　花盆里就可以扦插。应选土层深厚肥沃、疏松的沙质壤土。要求土壤既不板结，又不能过于松散，保水、肥力强，有利于生根、发芽。花湓最好东西向，夏秋便于遮荫。　\n　三、选择插穗\n　　春扦应选择生长健壮、充实、发育良好，无病虫害、无损伤的1－2年生枝条。这种枝条一般为棕褐色，有青绿色的纵裂，直径0.4－0.7厘米。夏、秋扦插应选当年生新梢下部木质部充实的部分，上部太嫩，产生愈合组织的能力差，不宜作插穗。多年生枝条发芽力弱，生出枝条纤细瘦弱，作插穗也不好。选好插穗，接着进行剪截。一般长度留16－18厘米，2－3对腋芽，腋芽上部留1－1.2厘米，防抽干。上部以芽取齐，下部不管节、芽一律取齐。春插剪好后应每200根1捆，随时埋人沙内，保持水分；夏插一般边剪边插，将下部几节叶片去掉，仅留上边的1对叶子即可。　　在花盆里挖出10厘米的小坑，将插穗斜插于土壤里，深度以刚露出上面1对芽为度，覆土踏实，大水漫灌，使插条与土密接，成活率90％以上。　　插后春季20天，夏、秋12天左右即萌发新根。据试验，春插先发芽后生根，夏秋插先生根后发芽。要保持地面湿润，防止板结。经常喷水、松土、除草。新梢长到15－20厘米即行摘心，促发新枝，一般进行3－4次。也可利用夏、秋阴雨连绵　　要注意充分遮荫，在新叶长出后，变为颜色深绿的老叶时，才可以照射阳光。', 'http://img.boqiicdn.com/Data/BK/P/imagick30351440581995.jpg', 'http://www.boqii.com/entry/detail/1984.html', '');
INSERT INTO `plant_family` VALUES ('13', '姬星美人', 'Sedum anglicum', '姬星美人', '', '不容易死', '原生地位于西亚与北非的干旱地区', 'http://www.boqii.com/entry/photo/2032/0,http://www.boqii.com/entry/photo/2032/5495', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '景天属', '姬星美人', 'Sedum anglicum', '', '　　姬 　　姬星美人为多年生肉质植物，株高5－10厘米，茎多分枝，叶膨大互生，倒卵圆形，长2厘米，绿色，叶片肉质，深绿色，似翡翠深绿色肉质叶片在阳光照射下非常鲜艳美丽。春季开花，花淡粉白色。', '　　姬星美人叶片肉质，深绿色。值得注意的是，姬星美人原产于北非与西亚的干旱地区，所以非常耐旱，但是不喜欢谁，所以人工栽培的过程中需注意少浇水，不然姬星美人很容易发生。　　　姬星美人喜欢干燥、阳光充足的环境，较耐寒，怕水湿，生长适温为13－23度，冬季温度不低于5度，夏季高温的时候要适当遮光，但荫蔽不宜过长，否则茎叶柔嫩，易倒伏，秋季可放在阳光充足处养殖。生长期的阳光可以是全日照，阳光强了，植株会变的矮小，匍匐在地上，也会呈现非常迷人的蓝色，非常的可爱。如果光照短，遮阳时间久了就容易长的高高的，叶片也不够紧凑，徒长明显，更加容易伏倒，变的不美观。　　　姬星美人耐干旱，耐贫瘠，可不必施肥，浇水一般是干透浇透、不干不浇的原则，夏季要可以不断水，最多就是延长浇水的次数与间隔，可以每个月浇一次水，浇水的时候不要采用浸盆的方式，可以选择在傍晚或者晚上的时候浇水，多雨的时候要严格控制浇水，不要造成盆土积水就好。　　　姬星美人的土壤栽培要求不是很严格，可以采用煤渣混合泥炭土，配土还是比较随意的，注意以透气为主。', '　　很多多肉爱好者都非常　　1、姬星美人播种：一般在每年的2－5月进行，采用室内盆播，发芽适温为18－21℃，播后12－15天发芽。　　2、姬星美人扦插：全年均可进行，极易成活，以春秋季为好，剪取顶端叶片紧凑的短枝，长5－7厘米，插入沙床，插壤保持稍湿润，插后10－12天生根。也可用单叶扦插，将成熟充实的肉质叶撒放在沙床上，喷水数次即行，几周后从叶片基部生根并长出幼株。　　其实姬星美人扦插比想象中的要容易的多，花友可放心的操作。', 'http://img.boqiicdn.com/Data/BK/P/imagick81601442222732.jpg', 'http://www.boqii.com/entry/detail/2032.html', '');
INSERT INTO `plant_family` VALUES ('14', '黄蝉', 'Yellow allamanda', '黄蝉', '黄兰蝉', '不容易死', '', 'http://www.boqii.com/entry/photo/2250/0,http://www.boqii.com/entry/photo/2250/5275', '　　', '被子植物门', '双子叶植物纲', '捩花目', '()科', '黄蝉属', '黄蝉', 'Allemanda neriifolia Hook.', '', '　　 　　黄蝉是直立灌木', '　　为)科黄蝉属的半蔓性常绿灌木，黄蝉的花期较长，现在常被制作成中型盆栽摆放在厅堂、阳台等处，观赏价值比较高。在花坛、花境中也时常能见到它们的身影。　　黄蝉为热带植物，喜高温高湿，不耐寒冷，忌霜冻，遇长期5、6C低温，枝叶受害。华南一般年份，可在露地，特寒年份，枝叶有冻害，春暖后可萌发。华南北部以至华中、华北的广大地区，只宜作盆栽，冬季移入保温棚或室内，室温以不低于lOC较宜。喜光、稍耐半遮荫。喜肥沃湿润的沙壤土，粘重土较差，贫瘩土不宜生长，较耐水湿，不耐干旱，土壤宜经常保持湿润。喜肥，种植时施腐熟饼肥或垃圾作基肥，春季花前和夏季盛花期，分别施复合肥1次，可促进开花多和延长花时。根系发达，盆栽植株宜每年或隔年换盆1次。枝条多参差不齐，每年冬春季，强度修剪1次，使多发侧枝，形成团国树冠或将较长的蔓生枝，盘扎成圆球形，控制枝条徒长，可促使多开花，形态亦较美。枝条较易衰老，5、6年生可将老枝全部剪去，使其萌芽更新或重新种植。', '　　　　黄蝉花花后结实，葫果有软刺，种子有翅，不宜久藏，宜随采随播，1年生苗可出圃。', 'http://img.boqiicdn.com/Data/BK/P/imagick86871448358077.jpg', 'http://www.boqii.com/entry/detail/2250.html', '');
INSERT INTO `plant_family` VALUES ('15', '凝脂菊', 'Haworthia，cymbiformis，fvariegata', '凝脂菊', '京之华锦', '不容易死', '大部分地区', 'http://www.boqii.com/entry/photo/2385/0,http://www.boqii.com/entry/photo/2385/5031', '　', '被子植物门（Angiospermae）', '双子叶植物纲（Dicotyledoneae）', '', '百合科', '瓦苇属（十二卷属）', '', 'Haworthia，cymbiformis，fvariegata', '', '　　 　　凝脂菊属软叶系，叶质较软，叶片短而肥，通常顶端较肥厚或呈截形，有透明或半透明的“窗”，并有明显的脉纹。光线可透过“窗”，进入植株体内进行', '　　为京之华的斑锦变异品种，喜欢明亮的光线，但是对直射阳光较敏感，所以人工栽培时最好放在玻璃后接受光照，对水分的要求不高，喜欢松软的土质。　　对水分需求不多，长积水容易，可经常喷雾保持空气中的湿度。夏季高温注意减少浇水量即可，春秋见干见湿，可大量浇水，很容易群生。　对日照需求不多，日照时间增加可以使白色锦斑叶片转变为金黄色。喜欢明亮的光线，但对直射阳光较敏感，最好放在玻璃后接受日照，可半阴养殖。　喜欢松软的土质。　无明显　夏季高温注意减少浇水量即可。　温度过低时减少浇水量，注意防结冰。　　无明显病虫害', '　　　　凝脂菊', 'http://img.boqiicdn.com/Data/BK/P/imagick14601451898319.jpg', 'http://www.boqii.com/entry/detail/2385.html', '');
INSERT INTO `plant_family` VALUES ('16', '山茶花', 'Common camellia', '茶花', '山茶、山茶花', '不容易死', '', 'http://www.boqii.com/entry/photo/1931/0,http://www.boqii.com/entry/photo/1931/5599', '', '', '', '', '', '', '', '', '', '　　山茶花又名山茶，古时候称其为海 　　山茶花惧风喜阳、地势高爽、空气流通、温暖湿润、排水良好、疏松肥沃的砂质壤土，黄土或腐殖土。pH5.5－6.5最佳。适温在20－32 ℃之间，29℃以上时停止生长，35 ℃时叶子会有焦灼现象，要求有一定　　　　　　　　　　　　　　　　　　　　　　　　Linn.，1753　　　　', '　　山是很多花友都非常喜欢的花卉品种，由于山茶花的品种非常多，并且花色艳丽多彩，花瓣多为重瓣，所以深受人们的喜爱。有很多花友都选择自己在家中盆栽山茶花，但是却有很多花友种不出漂亮的山茶花，那么山茶花在盆栽的时候应该注意哪些问题呢？　　1、土壤是盆栽山茶花的生长基础，因为茶花根系依赖土壤生长、，茶花生命活动所需要的水分和养分主要从土壤中吸取。茶花喜欢偏酸性、含腐殖质较高、疏松通气的山地红（黄）壤土，pH值在5至6。5之间，不能采用碱性土或黏性重的土壤作盆栽茶花基质。土壤配制：山泥土（种作物的熟化红壤土）50％，木屑或食用菌渣40％，饼肥粉或牲畜粪和磷肥粉10％，三者拌匀，浇水适量装袋熟化，夏秋20天以上，春冬30天以上，这种土壤不仅疏松通气，还能保肥保水，适合茶花。　　2、山茶花需要合适的光照，但是又怕高温烈日直射。春季、秋末时将山茶花要移到见光多的阳台上或地面，接受全天光照，促使植株生长发育，促使它花芽分化，花蕾健壮。进入夏天阳光最为强烈，就要将花盆移到见光背阳、通风良好的环境中，也可以移到北边阳台上或南边阳台内下边莳养，还可以用75％遮阳网，从上午9时到下午5时将植株盖好，避免烈日直射，引起叶面创伤或小株枯萎，有条件的将山茶移到阳棚下安全越夏。　　3、温度是山茶花生长的重要条件之一。山茶花喜欢温暖，生长最宜的温度为18℃至25℃，相对湿度60％至65％。茶花的生长，春梢一般在3月中下旬萌动，4月份开始抽芽，5月中下旬形成顶芽，停止生长，逐渐分化出叶芽或花芽，从花芽形成直到开花要180天至240天。夏梢在7月下旬萌动，至9月上旬停止生长。山茶虽然耐低温，但遇寒潮侵入，气温骤然下降0℃以下或又遇上干燥西北大风，就会引起嫩枝冻害，花蕾受冻害则枯萎，为此，就将花盆移到背北向南处养护，使它安全。　　4、山茶花叶片多，叶片面积大，蒸腾作用快。山茶花喜欢湿度较大气候，也喜湿润的土壤。因此，要给盆栽茶花补足水分，在春秋生长季节每天浇水1次，在夏天特别是“三伏天”每天早晚各浇水1次，如果地面干燥还要向花盆的地面和周边浇水或喷水1次至2次，保持一定的空气湿度，植株就生长茂盛。同时，注意因浇水多，而且大多数家庭都是浇自来水，天长日久花盆的土壤就会碱化。为此，在浇水时，每月补浇0。5％至1％硫酸亚铁水，也可以采用5％至8％食用酸醋液，对叶片进行喷施。山茶花喜欢湿润的土壤，但又怕花盆内积水，在下雨天如果盆内积水，必须及时排除，以免根系浸泡在水中闷死、腐烂。　　5、山茶花是喜肥花卉，因为树势健壮，叶片较多，花期也较长，因而需肥量也多。在施肥过程中，施足液肥，结合换盆施足长效肥，根据花盆大小，每盆施3克至80克腐熟饼肥粉或晒干鸡鸭粪，放到盆底下与底土拌匀。根据植株生长时期，增施有机肥。除冬夏最冷最热时外，每月施1次至2次腐熟枯饼水，其施肥方法：将盆边土壤扒开2分左右，将液肥施入沟内即用土壤覆盖，避免发生异味。也可以将腐熟的饼肥粉施在盆边与盆土拌匀，让花卉慢慢吸收。城市花友可以上花市购买花卉专用肥，既卫生又安全。为使茶花生长更好，在山茶花生旺盛期，每月要进行1次至2次根外施肥，以0.2％至0.3％磷酸二氢钾和1％至2％的植物生长素喷施叶片。施肥的原则：宜轻不宜重，宜淡不宜浓，宜少不宜多，必须坚持薄肥勤施的方法，特别是不要施生肥。　　6、山茶花喜欢生长在空气适度流动的环境中生长，最喜爱微风吹动，它喜东南风带来的水汽，但怕西北风和大风，而使水分蒸发过快，茶花供求失去平衡，株叶也易损伤，造成植株落蕾落花现象。冬季茶花要放在避风向阳环境中养护，并有一定温度和湿度。春秋季节要将花盆移到阳台，使它通风透光，受微风摇动，这样不仅植株生长良好，也有利于花芽分化，花蕾生长发育，还能减少病虫害的发生。通过多年的实践表明，适度通风，适宜光照，能起到预防病虫害的作用。', '　　山　\n　一、扦插养殖\n　　以6月中旬和8月底左右最为适宜。选树冠外部组织充实、叶片完整、叶芽饱满的当年生半熟枝为插条，长8～10厘米，先端留2片叶。剪取时，基部尽可能带一点老枝，插后易形成愈伤组织，发根快。插条清晨剪下，要随剪随插，插入基质3厘米左右，扦插时要求叶片互相交接，插后用手指按实。以浅插为好，这样透气，愈合生根快。插床需遮荫，每天喷雾叶面，保持湿润，温度维持在20～25℃，插后约3周开始愈合，6周后生根。当根长3～4厘米时移栽上盆。扦插时使用0.4％～0.5％吲哚丁酸溶液浸蘸插条基部2～5秒，有明显促进生根的效果。　\n　二、嫁接养殖\n　　常用于扦插生根困难或养殖材料少的　　\n三、压条养殖\n　　梅雨季选用健壮1年生枝条，离顶端20厘米处，行环状剥皮，宽1厘米，用腐叶土缚上后包以塑料薄膜，约60天后生根，剪下可直接盆栽，成活率高。　\n　四、播种养殖\n　　适用于单瓣或半重瓣品种。种子10月中旬成熟，即可播种。以浅播为好，用蛭石作基质，覆盖6毫米，室温21℃，每晚照光10小时，能促进种子萌发，播后15天开始萌发，30天内苗高达到8厘米，幼苗具2～3片叶时移栽。　\n　五、组培养殖\n　　外植体常用实生苗，经常规', 'http://img.boqiicdn.com/Data/BK/P/imagick8011439286458.jpg', 'http://www.boqii.com/entry/detail/1931.html', '');
INSERT INTO `plant_family` VALUES ('17', '虎刺梅', 'Euphorbia milii Ch. des Moulins', '铁海棠', '麒麟刺、虎刺、虎刺梅', '不容易死', '', 'http://www.boqii.com/entry/photo/1944/0,http://www.boqii.com/entry/photo/1944/5585', '', '', '', '', '', '', '', '', '', '　　 　　虎刺梅的茎多分枝，长60－100厘米，直径5－10毫米，具纵棱，密生硬而尖的锥状刺，刺长1－1.5 （2.0）厘米，直径0.5－1.0 毫米，常呈3－5列排列于棱脊上，呈旋转。叶互生，通常集中于嫩枝上，倒卵形或长圆状匙形，长1.5－5.0 厘米，宽0.8－1.8厘米，先端圆，具小尖头，基部渐狭，全缘；无柄或近无柄；托叶钻形，长3－4毫米，极细，早落。　　　　　　　　　　　　　　　　　　　　铁海棠　', '　　虎刺梅又名铁海棠、麒麟刺、，由于虎刺梅原产于非洲，所以其耐高温不耐寒，在栽种的时候需要注意为虎刺梅打造一个合适的栽培环境。一般虎刺梅适合栽种在家中的庭院里，如果你也养了虎刺梅，不妨跟小编一起了解一下虎刺梅的栽培方法。　　盆栽每年春季换盆，浇水不宜过多。夏秋期需充足水分，每月施肥1次。冬季低，叶片脱落，进入，应保持盆土干燥。3－12月花期，土壤湿度保持适中能花开不断，如果冬季室温在15℃以上，可继续开花。植株生长过于拥挤茂密时，可在春季萌发新叶前加以修剪整株。　　虎刺梅生性特别，生长慢，每年只长10厘米左右，但寿命长，盆栽能活30年以上。花期长，如光照温度得宜，可全年开放。虎刺梅枝条不易分枝，会长得很长，开花少，姿态凌乱，影响观赏，故每年必须及时修剪，摘尖等，使其多发新枝，多开花，一般枝条在摘尖后，可生出两个新枝。虎刺梅根系发达，生长旺盛，可作嫁接仙人指、蟹爪兰的砧木，但属浅根系，横走很远，根毛却不多。　　虎刺梅性喜温暖，不耐寒，白昼22℃左右，夜间15℃左右生长最好，在温室保持15℃至20℃，可终年开花不绝，如下降至10℃则落叶转入半休眠状态，至次春吐露新叶，继续开花。虎刺梅喜光，花前阳光越充足，花越鲜艳夺目，经久不谢，光照不足，则花色暗淡，长期置阴处，则不开花。另须注意保持空气流通。　　虎刺梅可用垫蹄角片作底肥，生长期每隔半月施肥一次，立秋后停止施肥，忌用带油脂的肥料，防根腐烂。虎刺梅耐旱，春秋两季浇水要见干见湿。夏季可每天浇水一次，雨季防渍水，冬季不干不浇水，盆内不宜长期湿润；花期也要控制水分，水大易引起落花烂根。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick67861439544559.jpg', 'http://www.boqii.com/entry/detail/1944.html', '');
INSERT INTO `plant_family` VALUES ('18', '紫罗兰', 'Matthiola incana', '紫罗兰', '草桂花、四桃克、草紫罗兰', '不容易死', '原产欧洲南部', 'http://www.boqii.com/entry/photo/1913/0,http://www.boqii.com/entry/photo/1913/5616', '', '', '', '', '', '', '', '', '', '　　 　　　　　　　　　　　　　　　　　　', '　　紫罗兰的花语是永恒的美丽，是非常适合送给天秤座的姑娘的。在欧洲，园丁们非常将其栽种在窗台下，这样可以让风将紫罗兰的花香带入屋内。现在越来越多的花友也开始盆栽紫罗兰了，并且紫罗兰盆栽的难度也不高，只要注意小编为你整理的紫罗兰的栽培要点，你的紫罗兰就能够的很好。　　　　培养土可用堆肥土加1／3腐熟木屑、1千克／立方米的45％高浓复合肥混合配制。　　　苗期施肥2－3次，以氮肥为主。在上盆后的生长盛期，还应追肥2～3次。为了避免植株徒长，追肥应以磷、钾肥为主，少施氮肥。在开花前追施一次腐熟的饼肥水，会使紫罗兰花大色艳。地栽留种的，每平方米可施入5～7千克腐熟的堆肥和20～30克的45％高浓复合肥。　　　掌握见干见湿、盆花略偏湿、地栽留种略偏干的浇水原则。对处于生长期的紫罗兰，盆栽的则应每1－2天浇一次水。地栽留种的可以每5－7天浇一次透水，　　　要养成大株或对高性品种，必须打头，上盆前留4－5叶摘心。矮性品种以小盆花或组合盆栽形式出售的，不能摘心。　　紫罗兰为中日性，只要温度适宜，不论日照长短，均能正常开花。因此可以用改变播种期的方法来控制它的花期。如在温室内2月播种，5月开花；4月播种，7月开花；5月下旬播种，8月开花。　　在白天温度为20℃左右，夜间温度不低于4－5℃的条件下，紫罗兰从播种到开花一般需要120～140天。矮性重瓣品种不摘心的90－95天开花。8、9月播种的紫罗兰，冬季在温室、大棚中培养，11～2月开花；要元旦开花，摘心的8月20日播种，不摘心的9月10日播种。　　　紫罗兰易患病毒病，其是叶面皱缩，叶色深浅不匀，花朵扭曲，深色花的花色变浅变白。若发现此种植株，应即拔除。灰霉病、菌核病分别用速克灵、、菌核净防治。', '　　紫罗兰在我国已经成为了栽培非常广泛的花卉，由于紫罗　　\n一、紫罗兰播种繁殖\n　　紫罗兰多采用种子播种繁殖，播种时间一般在8月中旬至10月上旬，注意播种的时间不能太晚，否则将影响植株的　　\n二、紫罗兰叶插繁殖\n　　叶插是紫罗兰繁殖最常用的方法，一般在春、秋季进行，从植株中挑选健壮的叶片，无病虫害感染，若为斑叶品种，则选择　　\n三、紫罗兰水插繁殖\n　　紫罗兰也可用水插方法进行繁殖，将紫罗兰斜剪出一片叶子，叶柄插在清水中，注意底部需要保持悬浮，注意加水换水约1个月左右即可生根成苗。叶插过程中，采用25毫克／升的激素处理叶柄24小时，对生根有利。　　紫罗兰的繁殖可以用的方法比较多，其中播种、叶插等方式是用的比较多的，另外还有分株、组织', 'http://img.boqiicdn.com/Data/BK/P/imagick64291438766891.jpg', 'http://www.boqii.com/entry/detail/1913.html', '');
INSERT INTO `plant_family` VALUES ('19', '齿缘吊钟花', 'Enkianthus serrulatus （Wils.） Schneid.', '齿缘吊钟花', '白吊钟、九骨筋、山枝仁、野支子', '不容易死', '', 'http://www.boqii.com/entry/photo/2436/0,http://www.boqii.com/entry/photo/2436/4979', '植物　', '被子植物门', '双子叶植物纲', '()目', '杜鹃花科', '吊钟花属', '齿缘吊钟花', 'Enkianthus serrulatus （Wils.） Schneid.', '', '　　 　　齿缘吊钟花为落叶灌木或小乔木，高2.6－6米。小枝光滑，无毛；芽鳞12－15｝枚，宿存。叶密集枝顶，厚纸质，长圆形或长卵形，长6－8（－11）厘米，宽（2.8－）3.2－3.5（－4）厘米，先端短渐尖或渐尖，基部宽楔形或钝圆，边缘具细锯齿，不反卷，表面无毛，或中脉有微柔毛，背面中脉下部被白色柔毛，中脉、侧脉及网脉在两面明显，在背面隆起；叶柄较纤细，长6－12（－20）毫米，无毛。伞形花序顶生。每花序上有花2－6朵，花下垂；花梗长1－1.5 （－2）厘米，结果时直立，变粗壮，长可达3厘米；花萼绿色，萼片5，三角形；花冠钟形，白绿色，长约1厘米，口部5浅裂，裂片反卷；雄蕊10枚，花丝白色，长约5毫米，下部宽扁并具白色柔毛，花药具2反折的芒；子房圆柱形，5室，每室有胚珠10－15枚，花柱长约5毫米，无毛。', '　　原产于秘鲁、智利、玻利维亚等中南美洲国家，现在在世界各地被广泛栽培，已经成为了非常重要的花卉品种之一。齿缘吊钟花非常适合用于花架、案头等处的点缀，那么如何才能养好齿缘吊钟花呢？　　　盆栽齿缘吊钟花的基质宜用肥沃、疏松、排水良好的土，一般可用腐叶土加沙质壤土加腐熟的有机和磷肥均匀混和，而不需施加基肥，以免烂根。粘重板结的土壤对齿缘吊钟花生长不利，更不适合于刚扦插成活的小苗。　　　齿缘吊钟花虽然喜阴，但这并不代表它不需要阳光，在缺少阳光的情况下不仅容易徒长，而且还会导致花色变淡花朵变小甚至落蕾。因此，在家庭种植齿缘吊钟花的过程中可以将其放置在阳光充足的阳台或露台上，以便其进行光合作用。　　　齿缘吊钟花生长的温度为10—28℃，夏天的温度不能超过30℃，因此夏天应做好降温工作。要求阳光充足，培养土温度不能低于5℃，否则就会引起冻害，必须采取保温措施。另外，无论冬天或夏天都要注意通风。　　　齿缘吊钟花平时浇水要掌握见干见湿的原则，春季天气干燥和夏季炎热高温季节可每天往枝叶上喷水1—2次，如果浇水过多会造成盆土积水。冬季室温低更要严格控制浇水、停止施肥，以防烂根。每次施肥浇水后要及时松土，以利通气。　　　因齿缘吊钟花生长快，开花次数多，故在生长期间要掌握薄肥勤施，约每隔10天施1次稀薄饼肥或复合肥料，开花期间也应每月施1次磷、钾为主的液肥，但高温季节停止施肥。施肥前盆土要偏干，施肥后用细喷头喷水1次，以免叶片腐烂。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick90521453109126.jpg', 'http://www.boqii.com/entry/detail/2436.html', '');
INSERT INTO `plant_family` VALUES ('20', '冬美人', 'Pachyveria pachytoides', '冬美人', '东美人', '不容易死', '杂交品种，自然界无分布', 'http://www.boqii.com/entry/photo/2102/0,http://www.boqii.com/entry/photo/2102/5425', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '厚叶草属', '冬美人', 'Pachyveria pachytoides', '', '　　 　　冬美人的植株为多年生无毛肉质草本植物，冬美人叶片环状排列，匙型，有叶尖，叶缘圆弧状，叶片肥厚，叶片光滑微量白粉，叶片蓝绿色至灰白色。阳光充足叶片紧密排列，叶片顶端和叶心会轻微粉红，弱光则叶色浅灰绿，叶片变的窄且长，叶片间的间距会徒长拉长。冬美人的花杆很高。簇状花序，红色花朵，花朵倒钟形，串状排列，花开五瓣，初夏开花。', '　　在温差大或日照长的情况下会变为淡粉色，大多时候为宝蓝色，并且叶片上海有一层白粉。冬美人耐旱，但不耐湿，所以在栽培过程中需注意浇水量。　　冬美人喜温暖、干燥和光照充足的环境，耐旱性强，喜疏松、排水透气性良的土壤，无明显，即便夏季都可全日照。生长适温18－25度，在冬季温暖、夏季冷凉的气候条件下生长良好。　　冬美人无明显休眠期，可以全日照。夏天的时候通风遮阳，每个月3到4次水，少量在盆边给水慢慢度过盛夏，维持植株根系不会因为过度干燥而干枯就可以。低于3度就要逐渐少水，0度以下保持盆土干燥，尽量保持不低于零下5度。这样就可以安全了，冬天尽量少点水，开春给水要循序渐进否则可能出现烂根。　　南北差异比较大，家庭和大棚的养殖方法都不一样，冬美人倒是比较好养的一个品种，无明显病虫害。风筝也就每年入夏和入冬撒点呋喃丹在土表就可以了。容易掉叶片是因为水分太充足的时候或者换季水分给的太多，轻轻碰叶片就容易掉叶片啦，少点水，或者循序渐进给水，就可以尽量避免掉叶片的。', '　　　　冬美人的繁殖方法主要有播种和分株、砍头、叶插。风筝一般用叶插来繁殖，土壤用的是泥炭混合珍珠岩加了煤渣，大概比例1：1：1，为了隔离植株和土表　　冬美人掉的叶片只要饱满都可以叶插的，非常容易活。丢在土表它们会自然萌发根系和小叶片，成为独立的小植株。冬美人砍头后容易长侧枝，不砍头一直养，植株的老杆会长很长，然后才开始分枝，为了更加漂亮。长的差不多的时候就应该砍头萌发侧芽，这样植株群生了才漂亮。', 'http://img.boqiicdn.com/Data/BK/P/imagick37611444468476.jpg', 'http://www.boqii.com/entry/detail/2102.html', '');
INSERT INTO `plant_family` VALUES ('21', '雷神', '雷神', '', '雷神', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/1916/0,http://www.boqii.com/entry/photo/1916/5613', '　　', '', '', '', '龙舌兰', '龙舌兰', '', '', '', '　　 　　雷神的叶基丛生，莲座状排列。叶倒卵状匙形，长20－ 25厘米，宽9－11厘米，基部较狭，厚，灰白色或淡青色，叶端、叶缘着生黑褐色刺，叶缘具倒锯齿。无叶柄。株周围易生子株而蘸生。花序高3米，花径约5厘米，黄绿色。', '　　雷神的适应性比较强，并且较耐寒，所以人工栽培雷神的难度并不高，但是在栽培过程中还是需要注意栽培方法及细节，这样才能让你的雷神更加漂亮。', '　　　　\n播种繁殖：\n　　\n分株繁殖：\n　　\n扦插繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick69581438853360.jpg', 'http://www.boqii.com/entry/detail/1916.html', '');
INSERT INTO `plant_family` VALUES ('22', '万年青', 'Rohdea Roth', '', '', '不容易死', '中国，日本', 'http://www.boqii.com/entry/photo/1953/0,http://www.boqii.com/entry/photo/1953/5574', '', '', '', '', '', '', '', '', '', '　　万年青为被子 万年青 　　万年青根状茎粗1.5－2.5厘米。叶3－6枚，厚纸质，矩圆形、披针形或倒披针形，长15 －50厘米，宽2.5－7厘米，先端急尖，基部稍狭，绿色，纵脉明显浮凸；鞘叶披针形，长 5－12厘米。花葶短于叶，长2.5－4厘米；穗状花序长3－4厘米，宽1.2－1.7厘米；具 几十朵密集的花；苞片卵形，膜质，短于花，长2.5－6毫米，宽2－4毫米；花被长4－5 毫米，宽6毫米，淡黄色，裂片厚；花药卵形，长1.4－1.5毫米。浆果直径约8毫米，熟 时红色。花期5－6月，果期9－11月。　　　　　　　　　　　　　　　　　　　　　　　', '　　万年青是现在非常流行的室内观叶植物，放在家中不但能改善环境，还能有意想不到的家居风格，并且万年青的叶片宽厚，如果在家中摆放一个好的位置的话，还能改善风水。那么，人工栽种万年青应该注意哪些呢？万年青　　1、栽植：春季栽植或翻盆换土。对土壤要求不严，但怕积水，地栽或盆栽时忌硬的黏土和碱土。盆栽一般采用腐叶土加沙的混合土上盆。　　2、光照与：万年青喜半阴环境，怕夏季太阳直晒。温室栽培，春、夏、秋三季应遮荫60％以上，冬季遮荫40％。光线太强易受日灼伤，光线太弱不易开花结果。可使用促花王3号，促进花芽分化，多开花，多结果。冬季休眠入温室，放在向阳的地方，温度保持在10℃以上，最低温度不能低于5℃。长江流域可露地，叶子虽然有冻害，但翌年仍可重新萌发新叶。　　3、浇水与施肥：生长每隔10－15夭追施1次液肥结合喷施新高脂膜增强肥效，则花繁叶茂，灿烂多姿。夏季要加强通风，防暑降温，并充分供水，经常保持盆土湿润和周围环境的空气湿度。夏季每天要浇水1－2次。冬季减少浇水，停止施肥。　　4、整形修剪：为保持植株的良好造型，提高观赏价值，随着植株的生长，株下部的黄叶、残叶、部分老叶要及时修剪。剪口处要涂抹愈伤防腐膜，防病菌侵袭，仍能萌发新枝，于晚秋再次开花。家庭盆养时可用软布蘸啤酒擦拭叶片并结合喷施壮茎灵，既可去掉尘土，又给叶片增加了营养，使叶片亮绿、干净。', '　　万年青是很多花友都非常万年青　　\n一、分株繁殖：\n　\n　二、扦插繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick5371439890988.jpg', 'http://www.boqii.com/entry/detail/1953.html', '');
INSERT INTO `plant_family` VALUES ('23', '白凤', 'Echeveria ‘Hakuhou’', '白凤', '', '碧玉莲', '', 'http://www.boqii.com/entry/photo/2459/0,http://www.boqii.com/entry/photo/2459/4957', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '拟石莲花属', '', 'Echeveria ‘Hakuhou’', '', '　　 　　白凤的叶形', '　　为景天科石莲花属栽培，夏季为白凤的茂盛期，需要注意的是，白凤的叶片有很薄的一层白粉，所以在浇水的时候需要注意避开叶片中心，以免影响美观。　　白凤喜阳光照射，可全日照养殖。平时为绿色，日照增多后会慢慢变为红色。耐寒能力很一般，可耐寒到0－5度的低温，露养白凤时，结霜时需防。开花后可将花茎剪去，以免浪费养分。　　白凤耐干旱，不宜频繁浇水。两三年以上的白凤会开出花剑，花色橘红，呈钟形，非常漂亮。白凤对水分的需求不多，叶片中心有薄薄的一层白粉，浇水时不要浇到叶片的中心，以免影响美观。', '　　　　\n1、播种：\n　　\n2、扦插：\n　　\n3、分株：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick79451453886480.jpg', 'http://www.boqii.com/entry/detail/2459.html', '');
INSERT INTO `plant_family` VALUES ('24', '朱莲', 'BluseGarden', '朱莲', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2467/0,http://www.boqii.com/entry/photo/2467/4950', '', '', '', '', '景天科', '伽蓝菜属', '', '', '', '　　 　　朱莲日常的叶片', '　　朱莲常被盆栽在室内，摆放在阳台、办公桌、窗台等处，有一定的观赏价值，也受到很多花友的喜爱。朱莲在日照充足的情况下，叶片会变成红色，非常漂亮。　　朱莲非常日照，叶片肥厚抗晒，可全日照，几乎没有休眠期。春秋时期可以大量浇水。朱莲是少见的多肉里对水的需求量较多的，同时日照需求也大，每天要日照4个小时，每个月要浇四次水。　　朱莲在早春栽植或上盆换上。盆栽采用腐叶土（或混炭土）、园土和粗沙混合的土作盆土，并加入适量腐熟的有机饼肥作基肥。朱莲为长日照，适当延长光照有利于生长。生长期要放在光照充足的地方，尽量多接受日光照射。但夏季炎热时要遮荫或放在树下疏荫处，避免强阳光直射，并且注意通风，过湿、过热的环境植株生长不良。适宜生长20－30℃。冬季应放在室内向阳处，室温保持10℃左右。', '　　　　朱莲的繁殖方式以扦插为主，较容易繁殖。挑选', 'http://img.boqiicdn.com/Data/BK/P/imagick34191454058966.jpg', 'http://www.boqii.com/entry/detail/2467.html', '');
INSERT INTO `plant_family` VALUES ('25', '石榴花', 'Pomegranate flowers', '石榴花', '安石榴、金罂、金庞、涂林 、天浆、若榴、丹若、山力叶、珠实等', '不容易死', '原产中亚的伊朗、阿富汗', 'http://www.boqii.com/entry/photo/1959/0,http://www.boqii.com/entry/photo/1959/5568', '　', '', '', '桃金娘目', '石榴科', '石榴属', '', 'Punicagranatum', '', '　　 　　石榴是落叶灌木或小乔木。株高2～5m，高达7m。树干灰褐色，有片状剥落，嫩 枝黄绿光滑，常呈四棱形，枝端多为刺状，无顶芽。单叶对生或簇生，矩圆形或倒卵形，长2～8cm不等，全缘，叶面光滑，短柄，新叶嫩绿或古铜色。花朵至数朵生于枝顶或叶腋；花尊钟形，肉质，先端6裂，表面光滑具腊质，橙红色，宿存。花瓣5～7枚红色或白色，单瓣或重瓣。浆果球形，黄红色。种子多数具肉质外种皮，9～10月果熟。石榴栽培种分果石榴和花石榴两大类。', '　　', '　　　　1、播种法，选充分成熟的果实，将种子取出洗干净阴干，层积沙藏，第二年春季谷雨前后播于苗床，覆土1厘米厚，约20天左右即可发芽，有4片真叶时可移栽。　　2、扦插法，夏季采用幼茎插条繁殖率高，也可在芽萌动前或冬季', 'http://img.boqiicdn.com/Data/BK/P/imagick3491439977388.jpg', 'http://www.boqii.com/entry/detail/1959.html', '');
INSERT INTO `plant_family` VALUES ('26', '荷花玉兰', 'Magnolia grandiflora  L.', '荷花玉兰', '广玉兰、洋玉兰、泽玉兰、木莲花', '不容易死', '', 'http://www.boqii.com/entry/photo/2209/0,http://www.boqii.com/entry/photo/2209/5318', '植物　', '被子植物门', '双子叶植物纲', '毛茛目', '木兰科', '木兰属', '荷花玉兰', 'Magnolia grandiflora  L.', '', '　　荷花 　　荷花玉兰在原产地高达30米；树皮淡褐色或灰色，薄鳞片状开裂；小枝粗壮，具横隔的髓心；小枝、芽、叶下面，叶柄、均密被褐色或灰褐色短绒毛（幼树的叶下面无毛）。叶厚革质，椭圆形，长圆状椭圆形或倒卵状椭圆形，长10－20厘米，宽4－7（10）厘米，先端钝或短钝尖，基部楔形，叶面深绿色，有光泽；侧脉每边8－10条；叶柄长1.5－4厘米，无托叶痕，具深沟。', '　　荷花', '　　　　\n一、播种法：\n　　\n二、嫁接法：\n　　\n三、压条法：\n　　\n四、扦插法：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick6521447234735.jpg', 'http://www.boqii.com/entry/detail/2209.html', '');
INSERT INTO `plant_family` VALUES ('27', '白凤菊', 'Oscularia pedunculata', '白凤菊', '姬鹿角', '不容易死', '原产地位于南非及美国部分沿海地区', 'http://www.boqii.com/entry/photo/2337/0,http://www.boqii.com/entry/photo/2337/5079', '　　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '覆盆花属', '白凤菊', 'Oscularia pedunculata', '', '　　 　　白凤菊为多年生肉质植物，大株植物呈亚灌木状，茎分枝匍匐或直立，老枝茎干呈棕红色，嫩枝稍带浅红色或黄绿色，叶着生于茎节处，肉质多汁具三棱形，边缘有小锯齿，花顶生头状花序，花瓣、花丝呈淡紫色，花药呈黄色，花期春末夏初。', '　　白凤菊为大株植物呈亚灌木状，由于白凤菊没有明显的，很多朋友不知道应该如何养护白凤菊，小编就为你整理了白凤菊在栽培过程中需要注意的三大。　　　白凤菊喜欢阳光充足、温暖干燥的环境，无明显的休眠期。可置于阳光充足的阳台、明亮的室内养殖，夏季高温注意遮荫，通风。生长适温15－25度，冬季不低于5度。　　　生长期浇水一般是浇水干透浇透，夏季高温控制浇水，冬季保持盆土干燥。此外白凤菊对的要求不高，生长期可每月施肥1次多肉专用缓释肥，施肥遵循少量多次原则进行，休眠期要停止施肥较好。　　　　白凤菊对土壤的基本要求是疏松透气、排水性好，配土一般可用泥炭、和珍珠岩的混合土。', '　　　　白凤菊繁殖可播种、扦插、分株，扦插是最常用的繁殖方法，砍头的枝条可以直接扦插在微湿的土里，或者就平放在微湿润的土表，阴凉通风发根。　　白凤菊的植株容易群生，也是容易长高的', 'http://img.boqiicdn.com/Data/BK/P/imagick86391450429419.jpg', 'http://www.boqii.com/entry/detail/2337.html', '');
INSERT INTO `plant_family` VALUES ('28', '锦鸡儿', 'Caragana', '锦鸡儿', '黄雀花、土黄豆、粘粘袜、酱瓣子、阳雀花、黄棘', '不容易死', '分布于中国长江流域及华北地区的丘陵、山区的向阳坡地', 'http://www.boqii.com/entry/photo/2200/0,http://www.boqii.com/entry/photo/2200/5327', '植物　', '被子植物门', '双子叶植物纲', '蔷薇目', '豆科', '锦鸡儿属', '锦鸡儿', 'Caragana sinica （Buchoz） Rehd.', 'Caragana sinica', '　　 　　锦鸡儿为灌木，高1－2米。树皮深褐色；小枝有棱，无毛。托叶三角形，硬化成针刺，长5－7毫米；叶轴脱落或硬化成针刺，针刺长7－15（25）毫米；小叶2对，羽状，有时假掌状，上部1对常较下部的为大，厚革质或硬纸质，倒卵形或长圆状倒卵形，长1－3.5厘米，宽5－15毫米，先端圆形或微缺，具刺尖或无刺尖，基部楔形或宽楔形，上面深绿色，下面淡绿色。', '　　又名黄雀花、金雀花等，我国有40余种。锦鸡儿不但可以观赏或作为绿篱，其花朵还可食用，经济价值比较高。锦鸡儿的适应能力比较强，常生于山坡向阳处和灌丛中，人工栽培难度不高。　　　金雀梅半荫环境，在秋、冬、春三季可以给予充足的阳光，但在夏季要遮荫50％以上。放在室内时，尽量放在有明亮光线的地方，如采光良好的客厅、卧室、书房等场所。在室内养护一段时间后（一个月左右），就要把它搬到室外有遮荫（冬季有保温条件）的地方养护一段时间（一个月左右），如此交替调换。　　　对于盆栽金雀梅，除了在上盆时添加有机肥料外，在平时的养护过程中，还要进行适当地肥水管理。　　　锦鸡儿主产中国北部、中部及东部，西南也有分布。用以制作盆景材料历史很悠久。', '　　　　锦鸡儿根系发达，具根瘤，抗旱耐瘠，能在山石缝隙处　　锦鸡儿可行播种、扦插、分株、压条等法繁殖。播种最好随采随播，如经干藏，次春播种前应行浸种催芽；扦插可于2～3月进行硬枝扦插，也可于梅雨', 'http://img.boqiicdn.com/Data/BK/P/imagick37381447061228.jpg', 'http://www.boqii.com/entry/detail/2200.html', '');
INSERT INTO `plant_family` VALUES ('29', '花叶寒月夜', 'Aeonium subplanum', '花叶寒月夜', '灿烂', '不容易死', '加那利群岛', 'http://www.boqii.com/entry/photo/2469/0,http://www.boqii.com/entry/photo/2469/4948', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '莲花掌属', '花叶寒月夜', 'Aeonium subplanum f. variegata', 'Aeonium subplanum', '　　 　　花叶寒月夜的肉质叶呈莲座状排列，叶盘直径15厘米至20厘米。叶片倒卵形，中间绿色至墨绿色，边缘有黄色中略带粉红色的', '　　为园艺栽培，人工栽培时放在南阳台或南窗台即可。人工栽培花叶寒月夜最好保持通风，并且注意节制浇水。花叶寒月夜在冬季饲养时不低于10℃，才能保证其健康成长。　　夏季可将花叶寒月夜放在通风良好处养护，严格控制浇水，甚至可以完全断水，不可长期雨淋，使其在通风、凉爽、干燥的环境中度过炎热的夏季，避免闷热、潮湿的环境，否则植株很容易烂掉。9月下甸以后，植株逐渐进入生长期，可移置光照充足处养护，若光照不足，会使植株徒长，叶片排列松散不紧凑，叶面上的黄色斑纹减退。保持盆土湿润而不积水，以防造成烂根，但也不宜长期干旱，否则植株停止生长，叶片干枯脱落。每月施1次腐熟的稀薄液肥，以给植株提供充足的养分，使其生长健壮，枝叶繁茂。　　冬季放在室内阳光充足的地方，夜间最好保持5℃以上，白天则在15℃以上，使其有一定的昼夜，这样植株可继续生长，如果维持不了那么高的温度，控制浇水，使植株休眠，也能耐短期的0℃低温，但如果长期温度过低，则会产生冻害，使叶片脱落。每年的9月换盆一次，盆土要求疏松，肥沃，具有良好的排水、透气性，可用腐叶土2份、园土1份、粗砂2份的。', '　　　　花叶寒月夜的繁殖可用分株，或用旁生的小株进行扦插。本种株形小巧奇特，叶色斑斓，宜作小型盆栽，点缀几案、窗台等处。　　花叶寒月夜的繁殖，可在10月至翌年3月的生长季节进行扦插，4月扦插虽然也能成活，但由于生长', 'http://img.boqiicdn.com/Data/BK/P/imagick10341454060052.jpg', 'http://www.boqii.com/entry/detail/2469.html', '');
INSERT INTO `plant_family` VALUES ('30', '木荷', 'Schima superba Gardn. et Champ.', '木荷', '荷木、木艾树、何树、柯树、木和、回树、木荷柴、横柴', '不容易死', '产浙江、福建、台湾、江西、湖南、广东、海南、广西、贵州。', 'http://www.boqii.com/entry/photo/2169/0,http://www.boqii.com/entry/photo/2169/5359', '植物　', '被子植物门', '双子叶植物纲', '侧膜胎座目', '山茶科', '木荷属', '木荷种', 'Schima superba Gardn. et Champ.', 'Schima superba', '　　 　　木荷为大乔木，高25米，嫩枝通常无毛。花生于枝顶叶腋，常多朵排成总状花序，直径3厘米，白色，花柄长1－2.5厘米，纤细，无毛；苞片2，贴近萼片，长4－6毫米，早落；萼片半圆形，长2－3毫米，外面无毛，内面有绢毛；花瓣长1－1.5厘米，最外1片风帽状，边缘多少有毛；子房有毛。蒴果直径1.5－2厘米。花期6－8月。', '　　', '　　　　1、育苗地选择选择地势平坦，排水良好，土层深厚疏松的酸性沙壤土作圃地。在排水不良的圃地，　　2、整地、施肥圃地要深耕翻土，使土壤充分风化。施足基肥，用混合　　3、播种多采用春播，高床，条播，行距20。25cm，播幅10－－15cm，每亩播种量2.5－3kg。幼芽出土力弱，覆土不宜过厚，以0.5cm左右为宜，覆土材料以轻松的沙壤或火烧土为好，要盖一层薄草。　　4、苗期管理播后2－3周即可发芽，约半数幼苗出土时揭草，搭设荫棚以防日灼和早害，遮阳', 'http://img.boqiicdn.com/Data/BK/P/imagick6731446198782.jpg', 'http://www.boqii.com/entry/detail/2169.html', '');
INSERT INTO `plant_family` VALUES ('31', '梭鱼草', 'Pontederia cordata', '梭鱼草', '北美梭鱼草、海寿花', '不容易死', '原产南北美洲，我国长江流域及华南地区有栽培应用', 'http://www.boqii.com/entry/photo/2168/0,http://www.boqii.com/entry/photo/2168/5360', '　', '被子植物门', '单子叶植物纲', '鸭跖草目', '雨久花科（Pontederiaceae）', '梭鱼草属', '梭鱼草', 'Pontederia cordata', '', '　　梭 　　梭鱼草为多年生挺水或湿生草本植物，叶柄绿色，圆筒形，叶片较大，长可达25厘米，宽可达15厘米，深绿色，叶形多变。大部分为倒卵状披针形，长约10－20厘米。上方两花瓣各有两个黄绿色斑点，花葶直立，通常高出叶面。 根茎为须状不定根，长15～30厘米，具多数根毛。地下茎粗壮，黄褐色，有芽眼，地茎叶丛生，株高80～150厘米。叶柄绿色，圆筒形，横切断面具膜质物。叶片光滑，呈橄榄色，倒卵状披针形。叶基生广心形，端部渐尖。', '　　梭鱼草常用于池边点缀园林，只要光照充足，环境温暖湿润，梭鱼草都能够成长。梭鱼草的花期为5－10月，花葶直立，通常高出叶面。　　梭鱼草为多年生挺水或湿生草本，喜温、喜阳、喜肥、喜湿、怕风不耐寒，静水及水流缓慢的水域中均可生长，适宜在20厘米以下的浅水中生长，适温15℃至30℃，越冬温度不宜低于5℃，梭鱼草生长迅速，繁殖能力强，条件适宜的前提下，可在短时间内覆盖大片水域。　　梭鱼草的生长习性为喜温暖湿润、光照充足的环境条件，常栽于浅水池或塘边，适宜的温度为18－35℃，18℃以下生长缓慢，10℃以下停止生长，冬季必须进行越冬。　　其叶色翠绿，花色迷人，花期较长，可用于家庭盆栽、池栽，也可广泛用于园林美化，栽植于河道两侧、池塘四周、人工湿地，与千屈菜、花叶芦竹、水葱、再力花等相间种植，每到花开时节，串串紫花在片片绿叶的映衬下，别有一番情趣。　　近年来，梭鱼草在我国的水景园中得到了一定的应用，是一种较有前途的水生观赏植物。主要应用的有白心梭鱼草与蓝花梭鱼草。', '　　梭鱼草的小花密集，在200朵以上，蓝紫色带黄斑点，开花时非常漂亮，现在常被用在池边做点缀用。人工繁殖梭鱼草一般用播种及分株的方法，小编就为你介绍一下梭鱼草的繁殖方法。　　多年生挺水或湿生草本　　我国梭鱼草主要分布在华北地区、东北地区、华东地区、华南地区、西北地区、华中地区、西南地区。养殖梭鱼草可以采用分株法和种子繁殖法，分株可以在春夏两季进行，从植株的基部进行切开，而种子繁殖法则要在春季进行了，并且种子要保持在25度左右的环境下才有用。', 'http://img.boqiicdn.com/Data/BK/P/imagick88871446198442.jpg', 'http://www.boqii.com/entry/detail/2168.html', '');
INSERT INTO `plant_family` VALUES ('32', '阔叶十大功劳', 'Mahonia bealei', '阔叶十大功劳', '土黄柏、土黄连、八角刺、刺黄柏、黄天竹', '不容易死', '甘肃、河南、浙江、安徽等。', 'http://www.boqii.com/entry/photo/2167/0,http://www.boqii.com/entry/photo/2167/5361', '　', '被子植物门', '双子叶植物纲', '毛茛目', '小檗科', '十大功劳属', '', 'Mahonia bealei', 'Mahonia bealei', '　　 　　阔叶十大功劳为灌木或小乔木，高0.5－4（－8）米。叶狭倒卵形至长圆形，长27－51厘米，宽10－20厘米，具4－10对小叶，最下一对小叶距叶柄基部0.5－2.5厘米，上面暗灰绿色，背面被白霜，有时淡黄绿色或苍白色，两面叶脉不显，叶轴粗2－4毫米，节间长3－10厘米；小叶厚革质，硬直，自叶下部往上小叶渐次变长而狭，最下一对小叶卵形，长1.2－3.5厘米，宽1－2厘米，具1－2粗锯齿，往上小叶近圆形至卵形或长圆形，长2－10.5厘米，宽2－6厘米，基部阔楔形或圆形，偏斜，有时心形，边缘每边具2－6粗锯齿，先端具硬尖，顶生小叶较大，长7－13厘米，宽3.5－10厘米，具柄，长1－6厘米。总状花序直立，通常3－9个簇生；芽鳞卵形至卵状披针形，长1.5－4厘米，宽0.7－1.2厘米；花梗长4－6厘米；苞片阔卵形或卵状披针形，先端钝，长3－5毫米，宽2－3毫米；花黄色；外萼片卵形，长2.3－2.5毫米，宽1.5－2.5毫米，中萼片椭圆形，长5－6毫米，宽3.5－4毫米，内萼片长圆状椭圆形，长6.5－7毫米，宽4－4.5毫米；花瓣倒卵状椭圆形，长6－7毫米，宽3－4毫米，基部腺体明显，先端微缺；雄蕊长3.2－4.5毫米，药隔不延伸，顶端圆形至截形；子房长圆状卵形，长约3.2毫米，花柱短，胚珠3－4枚。浆果卵形，长约1.5厘米，直径约1－1.2厘米，深蓝色，被白粉。花期9月至翌年1月，果期3－5月。', '　　阔叶十大功劳对环境要求不严，耐半阴、耐旱，较耐寒，人工栽培难度并不高。阔叶十大功劳不但可以用于园林观赏，全株还能药用，经济价值非常高。那么阔叶十大功劳应该如何种植呢？　　　　全年中耕锄草3～5次，使土壤疏松，增加土壤通透性，利于植株和结果。中耕时根际周围宜浅，远处可稍深，切勿伤根，利于植株生长和结果。及时疏花及拔除杂草，每当灌水和雨后都要松土。　　　管理较为粗放。一般在早春萌动时移栽。栽植时施足底肥，栽植后压实土，浇透水。干旱时注意浇水，最好能进行灌溉，可采用沟灌、喷灌、浇灌等方式。每年入冬前浇一次腐熟饼肥或禽畜粪肥，就能健壮生长。生长每20天施一次腐熟的稀薄液肥，每年追肥2－3次即可，早春适量施人饼肥。如果盆栽，则应保持盆土湿润而不积水。冬季移至室内阳光充足处，不宜过高。地栽植株管理较为粗放，可在早春萌动前带土球移植，栽植时要施足基肥。1－2年生苗，第3年开始生长加快。　　　阔叶十大功劳喜温暖气候，但不耐高温，也不耐干旱，养护时不要放在楼项上，要放在湿润的地方养护。', '　　　\n　一、播种繁殖方法\n　　果实在11月下旬方可成熟，12月采果，先不要脱粒，把它们堆积起来过一段　　苗需要在育苗床培育2－3年后，当苗高30－40cm时即可移栽，一般在每年3－4月移栽，干旱半干旱地区秋天9－10月份移栽为好。栽植前把幼苗挖出来，并且剪去一部分叶子，减少蒸发面积。整好地，做成130cm宽的畦，畦长根据miaomu.w.cn苗子的多少和地形具体确定。行株距各按30cm挖坑栽一株，填土踏实至和地面相平，浇定根水，水渗后在盖一层隔墒土。　　阔叶十大功劳分株在10月中旬至11月中旬或春季2月下旬至3月下旬进行。阔叶十大功劳的茎杆呈丛壮直立向上　　\n三、扦插繁殖方法\n　　阔叶十大功劳的扦插繁殖应在3月下旬进行，采冬季落叶的健壮茎杆做插穗，按15cm一段截开，插入疏松肥沃的沙壤土中，入土深10cm，并搭设苇帘或遮阳网蔗阴。在北方应在6～7月采嫩枝扦插，插条长10～12cm，保留先端1个复叶，将复叶先端的小叶剪掉，只留基部2枝小叶并将其剪掉1／2，用素沙土插入大花盆中，入土深5cm，蔗阴养护，立秋以后可以长出新根，入冬前分苗上盆，然后移入冷室', 'http://img.boqiicdn.com/Data/BK/P/imagick55381446197975.jpg', 'http://www.boqii.com/entry/detail/2167.html', '');
INSERT INTO `plant_family` VALUES ('33', '黑心菊', 'Rudbeckia hirta L.', '黑心菊', '黑心金光菊、黑眼菊', '不容易死', '原产美国东部地区，我国客地庭园常见栽培，供观赏', 'http://www.boqii.com/entry/photo/2211/0,http://www.boqii.com/entry/photo/2211/5316', '植物　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '金光菊属', '黑心金光菊', 'Rudbeckia hirta L.', '', '　　 　　黑心菊的露地适应性很强，较耐寒，很耐旱，不择土壤，极易栽培，应选择排水良好的沙壤土及向阳处栽植，喜向阳通风的环境。主产北美，多年生草本，一般作1－2年生栽培，枝叶粗糙，全株被毛，近根出叶，上部叶互生，叶匙形及阔披针形，头状花序，呈半球形。适应性强，耐寒，耐旱，喜向阳通风的环境，一般土壤均可栽培，花期5－9月。', '　　为属，由于黑心菊的栽培难度不高，经过培育，现在变种也有很多。黑心菊原产于美国东部地区，虽然耐寒性不强，但是在华中地区可露地。　　黑心菊在露地适应性很强，较耐寒，很耐旱，不择土壤，极易栽培，应选择排水良好的沙壤土及向阳处栽植，喜向阳通风的环境。　　黑心菊主产北美，多年生草本，一般作1－2年生栽培，枝叶粗糙，全株被毛，近根出叶，上部叶互生，叶匙形及阔披针形，头状花序，呈半球形。适应性强，耐寒，耐旱，喜向阳通风的环境，一般土壤均可栽培，花期5－9月。　　春、夏、秋气温在21℃－30℃均可播种，土质以排水良好。约15天发芽。肥沃壤土，日照充足，半日照也能正常。8片叶移植，成活后适当施肥，浇水，开花期，炎夏应适当遮阴，以利保持花艳丽。花后剪除残枝叶可促再生。注意防止排水不良，产生根腐病。', '　　　　\n一、播种繁殖\n　　黑心菊的播种　\n　二、分株繁殖\n　　黑心菊分株繁殖春秋两季均可进行，一般对多年生老株进行分株。　\n　三、扦插繁殖\n　　黑心菊一般选择根部萌生的新芽做插穗，春季或秋季均可进行。春季应待萌芽抽生至15cm左右时进行，秋季于花后根际萌孽后进行。', 'http://img.boqiicdn.com/Data/BK/P/imagick90701447235657.jpg', 'http://www.boqii.com/entry/detail/2211.html', '');
INSERT INTO `plant_family` VALUES ('34', '桔梗', 'Balloon Flower', '', '桔梗、铃当花', '不容易死', '中国、朝鲜半岛、日本和西伯利亚东部', 'http://www.boqii.com/entry/photo/1920/0,http://www.boqii.com/entry/photo/1920/5609', '', '', '', '', '', '', '', '', '', '　　桔梗又名包袱花、铃铛花等，为多年生草本 　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　很少有花友在家中自行栽培的，由于桔梗的药用价值比较高，所以很多花农会大规模栽培桔梗用来药用，并且桔梗还能食用。不过桔梗为周期性很强的，所以桔梗的价格波动比较大。　　　桔梗适宜在较疏松的土壤中，尤喜坡地和山地，以半阴半阳的地势为最佳，平地栽培要有良好的排水条件。桔梗不宜连作。　　　　桔梗有较长的肉质根，因此最好是垄上栽培。于早春（4月中下旬）撒上农家肥将地翻耕耙细整平（深翻30厘米）。做垄时，先在地上隔2米打上格线，开沟，然后将沟里的土向两边分撩，做成垄宽1.7米，沟宽30厘米左右的垄床，如遇旱，可沿沟灌溉，以备播种。　　　桔梗在大田播种前可亩施农家肥2000～3000公斤、粮食复合肥40公斤、过磷酸钙30公斤，为蛴螬可在翻倒农家肥时每吨施入1公斤甲敌粉与农家肥混合均匀在翻地前施入，后期追肥主要用清粪水或尿素，可在当年7月和第二年7～8月份用尿素25公斤或清粪水进行追肥提苗。清粪水每亩每次可施2吨左右，浓度可在10％左右，追肥后若浓度较大应及时用清水洗苗。', '　　由于桔梗常被大量繁殖，所以桔梗的繁殖最好选用高产的植株来进行留种。桔梗一般采用播种法来进行繁殖，也可以采用育苗移栽法，一般桔梗秋播的质量最好，冬季或春季播种也可以。桔梗', 'http://img.boqiicdn.com/Data/BK/P/imagick98641438855128.jpg', 'http://www.boqii.com/entry/detail/1920.html', '');
INSERT INTO `plant_family` VALUES ('35', '多叶羽扇豆', 'Lupinus polyphyllus', '多叶羽扇豆', '鲁冰花', '', '', 'http://www.boqii.com/entry/photo/2438/0,http://www.boqii.com/entry/photo/2438/3702', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '豆科', '羽扇豆属', '多叶羽扇豆', 'Lupinus polyphyllus', '', '　　 　　多叶羽扇豆为多年生草本，高50－100厘米。茎直立。分枝成丛。全株无毛或上部被稀疏柔毛。掌状复叶，小叶（5）9－15（－18）枚；叶柄远长于小叶；托叶披针形，下半部连生于叶柄。先端长锥尖；小叶椭圆状倒披针形，长（3）4－10（－15）厘米，宽l－2.5厘米，先端钝圆至锐尖，基部楔形，上面通常无毛，下面多少被贴伏毛。总状花序远长于复叶，长15－40厘米；花多而稠密，互生。长10－15毫米；苞片卵状披针形。长5毫米，被毛，早落；花梗长4－10毫米；萼二唇形。密被贴伏绢毛，上唇较短，具双齿尖，下唇全缘；花冠蓝色至堇青色。无毛，旗瓣反折，龙骨瓣喙尖，先端呈蓝黑色。荚果长圆形。长3－5厘米。宽1.5－2厘米，密被绢毛。有种子4－8粒。种子卵圆形，长4毫米。宽3毫米。灰褐色。具深褐色', '　　的花色艳丽丰富，并且花朵非常漂亮，是非常适合盆栽摆设的花卉。多叶羽扇豆有着吉祥安康的寓意，所以也是家庭盆栽观赏的首选。人工栽培多叶羽扇豆的难度并不是非常高。　　多叶羽扇豆性喜凉爽，忌炎热；宜阳光充足，略耐阴；要求酸性土壤，在中性或微碱性土中不良或苗期即。直根性，不宜移植，需深厚肥沃而排水良好之砂质土壤。较耐寒，在上海地区可露地。　　上海地区夏季炎热多雨，极不利于羽扇豆的生长，无论盆栽或地栽常不能越夏而死亡，因此必须在早春前发棵，使其早开花，早结籽，否则也常因初夏时种子来不及成熟遇热或雨而早枯。盆栽苗可于早春定植园地，株距40厘米。', '　　　　多叶羽扇豆繁殖以播种为主，春秋　　自然条件下选择秋播比较好，9月份到10月中旬播种，第二年4－6月就会开花。发芽适温25℃左右，保证土壤湿润，一周或者两周不到种子就会出土发芽，而且发芽率较高。', 'http://img.boqiicdn.com/Data/BK/P/imagick19711453110190.jpg', 'http://www.boqii.com/entry/detail/2438.html', '');
INSERT INTO `plant_family` VALUES ('36', '白睡莲', 'Nymphaea alba L.', '白睡莲', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2361/0,http://www.boqii.com/entry/photo/2361/5055', '　', '被子植物门', '双子叶植物纲', '毛茛目', '睡莲科', '睡莲属', '白睡莲', 'Nymphaea alba L.', '', '　　白 　　白睡莲是多年水生草本植物；根状茎匍匐；叶纸质，近圆形，直径10－25厘米，基部具深弯缺，裂片尖锐，近平行或开展，全缘或波状，两面无毛，有小点；叶柄长达50厘米。花直径10－20厘米，芳香；花梗略和叶柄等长；萼片披针形，长3－5厘米，脱落或花期后', '　　白)的观赏价值比较高，也是比较常见的水中品种。在水草造景中，白睡莲的使用也非常多，人工栽培白睡莲的难度并不高，但是需要根据其习性来布置环境，才能养出漂亮的白睡莲。　　白睡莲喜强光，通风良好，在岸边有树萌的池塘，虽能开花，但生长较弱。对土质要求不严，pH值6－8，均生长正常，但喜富含有机质的壤土。生长池水深度以不超过80厘米为宜。3－4月萌发长叶，5－8月陆续开花，每朵花开2－5天，日间开放，晚间闭合。花后结实。10－11月茎叶枯萎。翌年春季又重新萌发。生长季节池水深度以不超过80厘米为宜。在长江流域3月下旬至4月上旬萌发，4月下旬或5月上旬孕蕾，6－8月为盛花期，10－11月为黄叶期，11月后进入。生于池沼、湖泊中，一些公园的水池中常有栽培。', '　　白　　\n1、根茎繁殖法\n　　白睡莲主要是以根茎方式繁殖，一开始先将白睡莲栽种在花盆内，然后放于水中，大概过上个一年左右，白睡莲的根茎便会长的十分茂密，这是就可以将白睡莲进行分茎栽种了，首先将根茎部分的泥土退去，把根须剪短，将横生出来的根茎带茎叶剪上差不多10cm左右，然后将盆地放入底砂　\n　2、分割种植法\n　　在种植的时候将白睡莲的顶点露出水面一点或是高于盆沿都可以，栽种好的时候马上就放入水中，在水中需要将白睡莲固定住，保持一定的水深。白睡莲种植需要在白睡莲长至一定的阶段就需要分枝栽种，且需要经常施肥，保证肥料的充足，水质要清澈。', 'http://img.boqiicdn.com/Data/BK/P/imagick2641450949213.jpg', 'http://www.boqii.com/entry/detail/2361.html', '');
INSERT INTO `plant_family` VALUES ('37', '带叶兜兰', 'Paphiopedilum hirsutissimum', '带叶兜兰', '', '不容易死', '东南亚', 'http://www.boqii.com/entry/photo/2427/0,http://www.boqii.com/entry/photo/2427/4988', '　　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '兜兰属', '带叶兜兰', 'Paphiopedilum hirsutissimum （Lindl. ex Hook.） Stein', 'Paphiopedilum hirsutissimum', '　　带叶兜兰为兰科、兜兰属地生或半附生 　　带叶兜兰是地生或半附生植物。叶基生，二列，5－6枚；叶片带形，革质，长16－45厘米，宽1.5－3厘米，先端急尖并常有2小齿，上面深绿色，背面淡绿色并稍有紫色斑点，特别是在近基部处，中脉在背面略呈龙骨状突起，无毛，基部收狭成叶柄状并对折而多少套叠。', '　　带叶兜兰的花朵开放的时间比较长，属于观赏类花草，是很多兰花爱好者喜欢的品种。带叶兜兰在我国广西和贵州境内比较常见，多为野生存在，具有很高的观赏价值，那么人工栽培带叶兜兰应该注意哪些呢？　　带叶兜兰喜温暖、半阴和潮湿的环境。喜肥沃、富含腐殖质、排水良好的沙质土壤。夏季在荫棚下栽培，冬季在温室中放于光线充足处；为保持较高的空气湿度，每天向植株和周围地面喷水。定植40多天以后可以追施稀薄液肥；每2—3年换盆1次；期需充分供水，休眠期和新芽初出时，要控制浇水。　　带叶兜兰的生长适宜18—25℃；越冬适温约12℃，不宜低于5℃，若在1—2℃下，则叶片枯萎，植株；长期在20℃以上，则不能正常进行花芽分化，难以开花，而且容易发生病。夏天应适当遮荫；冬天则要充分光照。要求肥沃和排水透气良好的栽培基质。', '　　　　带叶兜兰常用分株繁殖，也可播种。当苗株有6个以上叶丛时，即可分株，常于花后休眠期中进行。将株丛从花盆中取出，去掉附着的', 'http://img.boqiicdn.com/Data/BK/P/imagick7191452763089.jpg', 'http://www.boqii.com/entry/detail/2427.html', '');
INSERT INTO `plant_family` VALUES ('38', '棣棠花', 'Kerria', '棣棠花', '棣棠、地棠、蜂棠花、黄度梅、金棣棠梅、黄榆梅', '不容易死', '', 'http://www.boqii.com/entry/photo/2093/0,http://www.boqii.com/entry/photo/2093/5434', '植物　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '棣棠花属', '棣棠花', 'Kerria japonica .', '', '　　 　　棣棠花是落叶灌木，高1－2米，稀达3米；小枝绿色，圆柱形，无毛，常拱垂，嫩枝有棱角。叶互生，三角状卵形或卵圆形，顶端长渐尖，基部圆形、截形或微心形，边缘有尖锐重锯齿，两面绿色，上面无毛或有稀疏柔毛，下面沿脉或脉腋有柔毛；叶柄长5－10毫米，无毛；托叶膜质，带状披针形，有缘毛，早落。', '', '　　　\n　一、选地\n　　选地应选择温暖湿润的、土壤要求松软、排水良好的、非碱性土壤。移栽地的准备：施入基肥、堆肥、厩肥、腐熟人粪尿等，混拌均匀，整平，春季发芽前或10月间移栽露地或上盆。　\n　二、\n　　中耕除草，5－6月份除草，一般不需要经常浇水，盆栽要在午后浇饼肥水，不易多浇。　　\n三、\n　　棣棠花于3月中旬萌芽，一般宜在萌芽前移栽，定植后需注意修剪枯枝和老枝。生长期每2个月施肥1次，每隔2－3年全面更新1次，剪除地上部，促使多发新枝。北方栽培时，冬季需要培土，防止枯梢。', 'http://img.boqiicdn.com/Data/BK/P/imagick98841443605197.jpg', 'http://www.boqii.com/entry/detail/2093.html', '');
INSERT INTO `plant_family` VALUES ('39', '大花紫薇', 'Lagerstroemia speciosa （L.） Pers.', '大花紫薇', '大叶紫薇、百日红、巴拿巴、五里香、红薇花、百日红、佛泪花', '不容易死', '印度，斯里兰卡，澳洲，马来西亚，越南，菲律宾，中国', 'http://www.boqii.com/entry/photo/2251/0,http://www.boqii.com/entry/photo/2251/5274', '植物　　', '被子植物门', '双子叶植物纲', '()目', '千屈菜科', '紫薇属', '大花紫薇', 'Lagerstroemia speciosa （L.） Pers.', '', '　　 　　大花紫薇为大乔木，高可达25米；树皮灰色，平滑；小柱圆柱形，无毛或微被糠批状毛。叶革质，矩圆状椭圆形或卵状椭圆形，稀披针形，甚大，长10－25厘米，宽6－12厘米，顶端钝形或短尖，基部阔楔形至圆形，两面均无毛，侧脉9－17对，在叶缘弯拱连接；叶柄长6－15毫米，粗壮。花淡红色或紫色，直径5厘米，顶生圆锥花序长15－25厘米，有时可达46厘米；花梗长1－1.5厘米，花轴、花梗及花萼外面均被黄褐色糠粃状的密毡毛；花萼有棱12条，被糠粃状毛，长约13毫米，6裂，裂片三角形，反曲，内面无毛，附属体鳞片状；花瓣6，近圆形至矩圆状倒卵形，长2.5－3.5厘米，几不皱缩，有短爪，长约5毫米；雄蕊多数，达100－200；子房球形，4－6室，无毛，花柱长2－3厘米。蒴果球形至倒卵状矩圆形，长2－3.8厘米，直径约2厘米，褐灰色，6裂；种子多数，长10－15毫米。', '　　大花紫薇的花大且密集，花期较长，观赏效果非常好，并且，大花紫薇的树冠广阔，遮阴的效果也俱佳。现在很多公园、庭院、湖畔等处均能看见大花紫薇的身影。那么大花紫薇应该如何栽种呢？　　大花紫薇性喜温暖湿润的气候，比较不耐寒，适应能力强。喜光，耐高温烈日，不耐隐蔽。喜疏松，排水良好的酸性土壤，缓坡地红壤也能。黏重土壤生长较差，干旱贫瘠地生长极差。侧根多，容易成活。生长适温为20－－23摄氏度。　　大花紫薇因紫薇根系萌蘖性强，10月份进行分株繁殖，栽于圃地或盆中养坯，一般2～3年可以开花。也可以在10～11月份剪取成熟果穗，于翌年3月播种，2～3个周左右就可以出苗。　　大花紫薇土壤要求富含有机质、排水良好的壤土，可选用腐叶土或沙质土5份、火烧土2份、煤球灰1份充分混合配制。　　春冬两季应保持盆土湿润，节每天早晚要浇水一次，干旱高温时每天可适当增加浇水次数，以河水、井水、雨水以及贮存2天至3天的自来水浇施。　　盆栽大花应紫薇每隔2年至3年更换一次盆土，用5份疏松的山土、3份田园土、2份细河沙混合配制成土，换盆时可用骨粉、豆饼粉等有机肥作基肥，但不能使直接与根系接触，以免伤及根系，影响植株生长。', '　　大花紫薇原产于印度，现在在我国的分布也较广。大花紫薇成株可高达25米，为大乔木，人工栽培难度不高，可以通过压条繁殖的方法繁殖，小编就为你介绍一下大花紫薇的压条繁殖的方法及', 'http://img.boqiicdn.com/Data/BK/P/imagick85821448358709.jpg', 'http://www.boqii.com/entry/detail/2251.html', '');
INSERT INTO `plant_family` VALUES ('40', '金光菊', 'Rudbeckia laciniata L.', '金光菊', '黑眼菊、黄菊、黄菊花、假向日葵、肿柄菊', '不容易死', '加拿大及美国', 'http://www.boqii.com/entry/photo/2255/0,http://www.boqii.com/entry/photo/2255/5270', '　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '金光菊属', '金光菊', 'Rudbeckia laciniata L.', '', '　　 　　金光菊为多年生草本，高50－200厘米。茎上部有分枝，无毛或稍有短糙毛。叶互生，无毛或被疏短毛。下部叶具叶柄，不分裂或羽状5－7深裂，裂片长圆状披针形，顶端尖，边缘具不等的疏锯齿或浅裂；中部叶3－5深裂，上部叶不分裂，卵形，顶端尖，全。缘或有少数粗齿，背面边缘被短糙毛。头状花序单生于枝端，具长花序梗，径7－12厘米。总苞半球形；总苞片2层，长圆形，长7－10毫米，上端尖，稍弯曲，被短毛。花托球形；托片顶端截形，被毛，与瘦果等长。舌状花金黄色；舌片倒披针形，长约为总苞片的2倍，顶端具2短齿；管状花黄色或黄绿色。瘦果无毛，压扁，稍有4棱，长约5－6毫米，顶端有具4齿的小冠。', '　　', '　　　　金光菊繁殖可采用播种或分株繁殖，但通常多采用分株法，尤其重瓣', 'http://img.boqiicdn.com/Data/BK/P/imagick6651448444908.jpg', 'http://www.boqii.com/entry/detail/2255.html', '');
INSERT INTO `plant_family` VALUES ('41', '接骨木', 'Flower of Williams Elder', '接骨木', '公道老，扦扦活、马尿骚、大接骨丹', '不容易死', '', 'http://www.boqii.com/entry/photo/2083/0,http://www.boqii.com/entry/photo/2083/5444', '　', '被子植物门', '双子叶植物纲', '茜草目', '忍冬科', '接骨木属', '接骨木', 'Sambucus williamsii', '', '　　 　　接骨木花与叶同出，圆锥形聚伞花序顶生，长5－11厘米，宽4－14厘米，具总花梗，花序分枝多成直角开展，有时被稀疏短柔毛，随即光滑无毛；花小而密；萼筒杯状，长约1毫米，萼齿三角状披针形，稍短于萼筒；花冠蕾时带粉红色，开后白色或淡黄色，筒短，裂片矩圆形或长卵圆形，长约2毫米；雄蕊与花冠裂片等长，开展，花丝基部稍肥大，花药黄色；子房3室，花柱短，柱头3裂。', '　　又名公道老，是忍冬科接骨木属落叶灌木或小乔木，常生于海拔540－1600米的山坡、灌丛、沟边等地，是很好的园林。小编就为你介绍一下接骨木的水肥管理与修剪方法。　　　接骨木喜肥，除在栽植时施入适量的农家肥作基肥外，6月初还应追施一次尿素，这次肥可有效提高植株的长势，对植株长枝长叶非常有利，秋末需再施一次农家肥。第二年春天施用一次尿素，6月中旬施用一次磷钾复合肥，秋末再施用一次农家肥。从第三年起只需于秋末施用一次农家肥即可。　　　接骨木萌芽力强，非常耐修剪，其常见株型有两种：多干式灌丛形、单干式。　　多干式灌丛形，有两种修剪方式，一是在园林栽植时用几株小苗组合在一起，将各个“主干”上萌发的枝条及时疏除，保留几个直立的“主干”，对于“主干”间向内的枝条全部疏除，只保留向外生长的枝条，这样多干式灌丛形就形成了。此后主要对树冠内过密枝、冗杂枝、病虫枝、徒长枝进行修剪即可。二是在苗圃内就培育出多干式灌丛形植株，可对长势较强的植株进行平茬处理，在其新萌发出的枝条中选择4至5个长势健壮的枝条作主干，不断疏除主干上的侧枝，只保留向外侧生长的枝条。　　单干式植株的培养，待到植株长至2.5米以上时，对其进行短截，在的枝条中，选择3至4个分布均匀、长势健壮、生长角度开张，且不在同一轨迹的新枝作主枝培养，秋末对其进行中短截，翌年在每个主枝上的新生枝条中选择两个健壮枝作侧枝培养，其他新生枝条全部疏除，这样基本树形形成。此后只需根据树势调整冠幅即可，对过密枝，病虫枝和徒长枝及时进行修剪。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick89961443433830.jpg', 'http://www.boqii.com/entry/detail/2083.html', '');
INSERT INTO `plant_family` VALUES ('42', '红缘莲花掌', 'Aeonium haworthii kwebb et Berth', '红缘莲花掌', '', '不容易死', '大西洋的加那利群岛', 'http://www.boqii.com/entry/photo/2390/0,http://www.boqii.com/entry/photo/2390/5026', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '莲花掌属', '', 'Aeonium haworthii kwebb et Berth', '', '　　红缘 　　红缘莲花掌为多年生肉质草本植物，植株呈多分枝的亚灌木状，高25～50厘米，分枝顶端的叶子排列成莲座状。叶片倒卵形，具细尖，叶长2.5～5厘米，质稍厚，蓝绿至灰绿色，被白霜，叶面具光泽，叶缘红色至红褐色，并有细齿。聚伞花序，花浅黄色，有时带红晕。莲花掌为莲花掌属植物，植株多分枝，肉质叶在枝头排成莲座状，叶片较薄，形状有倒卵形、舌形、肾形，叶缘有短毛，总状花序，花后植株枯死。', '　　红缘)会开花，但是花后植株会枯死，所以和部分多肉一样，想要红缘莲花掌继续活下去的话就需要将花剪除。人工栽培红缘莲花掌需要注意以下两点：　要放在阳光充足、通风良好的地方。夏季进入休眠，要求半阴和通风良好的环境，在温度高时应搭棚遮荫或放在大树下疏荫处，也可以放在室内，但应保持通风良好，温度在25℃以上。冬季应故在温室或室内向阳处，室温保持10℃以上，最低温度不能低于5℃，温度过低要做好防寒措施。　　春秋生长旺季，要注意浇水，保持盆土湿润偏干状态，不能积水和过湿。夏季进入休眠，特别是在高温高湿环境下，要保持良好的通风条件，控制浇水，以免引起落叶和根部。冬季要减少浇水，盆土以保持稍干燥为宜。浇水要掌握“见干见温、浇则浇透”的原则。', '　　红缘　　红缘莲花掌的繁殖多用扦插法繁殖。可以在早春剪下莲座叶盘扦插，剩下的茎上会群出蘖芽。很好繁殖的', 'http://img.boqiicdn.com/Data/BK/P/imagick94751451983395.jpg', 'http://www.boqii.com/entry/detail/2390.html', '');
INSERT INTO `plant_family` VALUES ('43', '杏花', 'Apricot， Armenian plum', '杏花', '', '不容易死', '在我国分布范围很广，除南部沿海及台湾省外，大多数省区皆有分布', 'http://www.boqii.com/entry/photo/2076/0,http://www.boqii.com/entry/photo/2076/5451', '　　', '被子植物门 Magnoliophyta', '木兰纲 Magnoliopsida', '蔷薇目 Rosales', '蔷薇科Rosaceae', '杏属 Armeniaca', '', 'Armeniaca vulgaris', '', '　　 　　杏树为', '　　杏花就是我们熟知的能够吃的杏子的花，每年的3－4月，是杏花开放的', '　　杏花是我国非常着名的观赏树木，花色又红又白，非常漂亮，当开花的时候，是很多杏花爱好者争相观赏的。小编就为你整理了关于杏花的繁殖方法，有兴趣的朋友们可以一起了解。　　嫁接砧木可选山桃、梅、东北杏等，于7月中下旬进行丁字形芽接。芽接不可不晚，否则离皮困难，成活率低。如当年芽接末成活，可至次年春季枝接。也可用分蘖繁殖。　　杏花寿命长，华北、西北各地常见百年以上大树，产量仍很高。经济寿命亦很长，在40～50年间。杏对土壤、地势的适应能力强，多种植在山坡梯田和丘陵地上，在800～1000米的高山上也能正常', 'http://img.boqiicdn.com/Data/BK/P/imagick48981443172810.jpg', 'http://www.boqii.com/entry/detail/2076.html', '');
INSERT INTO `plant_family` VALUES ('44', '千兔耳', 'Kalanchoemillotii', '千兔耳', '', '不容易死', '原产于非洲马达加斯加岛', 'http://www.boqii.com/entry/photo/2419/0,http://www.boqii.com/entry/photo/2419/4996', '　　', '', '', '', '景天科', '景天科伽蓝菜属', '', 'Kalanchoemillotii', '', '　　 　　和其他兔耳一样，千兔耳叶子表面也是有一层软绒毛，摸起来很有手感，千兔耳的美，除了它的毛毛叶外，还有那非常对称整齐的对生叶，锯齿状的叶，有点萌萌白枫叶的即视感，整体跟人一种毛绒绒的可爱感。枝干易木质化，可通过断水来塑型。也有称白兔耳可开粉红色的花。大概因为其叶片多呈现白色，因此也有人误称为白兔耳，白兔耳的叶片会更像兔子', '　　的外形非常可爱，因其叶片多呈现白色，因此会有人误称为白兔耳，但是相对来说，白兔耳会比较少见一些，所以价格会更贵一些。人工栽培千兔耳的难度并不高，小编就为你介绍一下在栽培千兔耳时应该注意哪些。　　千兔耳属于夏种型，非常喜欢日照，日照充足的情况下叶片呈白色，缺少日照转变为绿色并慢慢往下塌，对水分要求稍多，生长速度相对较快，几乎全年都在生长。可以忍受轻微的霜害，可以容忍很高的温度，平常可以全日照或着轻微遮蔽，可以常浇水（兔子系列大都是夏型种）。会开花，小白花，从抽生花梗到花朵全开完经历的时间可以多达几个月。同类的还有“)”等，属“夏种型”，夏季依然生长，冬季休眠。可全日照，日照充足叶片呈白色，缺光叶片会变成绿色并慢慢往下塌，但是不影响生长，千兔耳对水分需求稍多，生长速度相对较快。简单来说千兔耳很好养，很好活，是成就感很高的多肉。毛茸茸的毛、半边锯齿状的叶，缺口会再冒出小芽，夏型（冬眠），喜光照、可直晒、耐热（但要通风），适合春、秋。夏天要注意浇水不可过多，也不能太少。适合肥沃、排水性佳的沙土。很会长，可长到30公分左右，日晒不足会徒长。', '　　　　千兔耳会开花，小白花，从抽生花梗到花朵全开完经历的', 'http://img.boqiicdn.com/Data/BK/P/imagick26991452676359.jpg', 'http://www.boqii.com/entry/detail/2419.html', '');
INSERT INTO `plant_family` VALUES ('45', '大花六道木', 'A.grandiflora（Andre）Rehd', '大花六道木', '', '不容易死', '华东、西南及华北', 'http://www.boqii.com/entry/photo/2259/0,http://www.boqii.com/entry/photo/2259/5266', '植物　', '被子植物门', '', '', '忍冬科', '六道木属', '大花六道木', 'A.grandiflora（Andre）Rehd', '', '　　大花六道木的 　　大花六道木非常美丽，枝条柔顺下垂，树姿婆娑，无论是作为园中配植，还是用作', '　　的花期非常长，从夏季开始可以一直持续到深秋，将近半年的时间，所以在观赏花木中是非常珍贵的。大花六道木的花白色，非常漂亮，但是我国引进的时间不长，所以并不是很普及。如果你养了大花六道木，不妨跟着小编一起了解一下大花六道木的栽培要点。　　1、多株并栽上盆可以更快地形成冠幅，缩短时间和减少修剪多次。　　2、栽培的基质：疏松透气且排水良好的介质，如60％泥炭＋30％松鳞介质＋10％珍珠岩。　　3、：加适量的APEX21－5－12长效控释肥（4千克／立方米）、微量元素肥与介质混合。　　4、种植与水分：随起、随种、随浇水；浇水把握“见干见湿”的原则。　　5、控制好摆放密度。以叶片不相接为宜，有利于植株充分，并在管理过程中及时拉疏，保证苗间通风良好。', '　　由于', 'http://img.boqiicdn.com/Data/BK/P/imagick83341448530093.jpg', 'http://www.boqii.com/entry/detail/2259.html', '');
INSERT INTO `plant_family` VALUES ('46', '冬红', 'Holmskioldia sanguinea Retz.', '冬红', '', '不容易死', '原产喜马拉雅。现我国广东、广西、台湾等地有栽培', 'http://www.boqii.com/entry/photo/2416/0,http://www.boqii.com/entry/photo/2416/4999', '　　', '被子植物门', '双子叶植物纲', '管状花目', '马鞭草科', '冬红属', '', 'Holmskioldia sanguinea Retz.', '', '　　 　　冬红为常绿灌木，高3-7米；小枝四棱形，具四槽，被毛。叶对生，膜质，卵形或宽卵形，基部圆形或近平截，叶缘有锯齿，两面均有稀疏毛及腺点，但沿叶脉具毛较密；叶柄长1-2厘米，具毛及腺点，有沟槽。聚伞花序常2-6个再组成圆锥状，每聚伞花序有3花，中间的一朵花柄较两侧为长，花柄及花序梗具短腺毛及长单毛；花萼朱红色或橙红色，由基部向上扩张成一阔倒圆锥形的碟，直径可达2厘米，边缘有稀疏', '　　为马鞭草科冬红属常绿灌木，在冬季依然能够开放出绚丽的红色花朵，非常漂亮。冬红性喜高温，适用于花架或盆栽，在园林绿化中也经常能看到。　　冬红花顶生，花萼伞形，花冠喇叭形，橙红色，盛开时极为鲜艳夺目。适用于花架、花廊或盆栽。冬红好栽易管，南北适宜，抗旱抗涝，抗病虫害能力强在对它的多年培育中发现对碱地的适应性比其他一般强很多。　　冬红冬季忌潮湿，干旱有利开花，花后进行强剪，促使其萌发新枝。冬红性喜高温，适温23-32℃，适用于花架、花廊或盆栽。', '　　　　冬红在热带地区，用于园林绿化，诱引于花架或墙壁上。亚热带、温带地区可作温室盆栽。冬红喜光，喜温热及排水良好的环境。人工繁殖冬红常用播种或扦插繁殖，需保湿、保温。盆栽介质可用排水良好的肥沃壤土。', 'http://img.boqiicdn.com/Data/BK/P/imagick49391452590787.jpg', 'http://www.boqii.com/entry/detail/2416.html', '');
INSERT INTO `plant_family` VALUES ('47', '香水草', 'Heliotropium arborescens', '香水草', '天芥菜、洋茉莉', '不容易死', '原产地为秘鲁', 'http://www.boqii.com/entry/photo/2274/0,http://www.boqii.com/entry/photo/2274/5251', '植物　　', '', '', '', '紫草科', '天芥菜属', '', 'Heliotropium arborescens', '', '　　香 　　香水草的植株高约50厘米，茎部木质化呈亚灌木状；枝条黄褐色，直立或开展，嫩枝被有白色刚毛，叶互生，叶柄短，叶片卵圆形至卵状披针形，全缘，叶面粗糙，叶脉7～8对，主脉与侧脉均下陷，使叶片表面呈绉摺状，叶背有白色茸毛。顶生聚繖花序，花小，花萼与花筒等长；花冠5裂，漏斗状，裂片短，宽阔外翻，堇色或紫色，具有特别的香气。', '　　香水草的香味非常诱人，现在常被用于提炼香花型化妆品。人工栽培香水草需要注意为其提供充足的阳光，这是因为香水草是喜光植物，如果在光照不足的环境下，香水草则容易生长瘦弱，严重的会不能开花。　　　盆栽土壤宜用排水良好的肥沃疏松壤土，一般采用园土4份、堆肥土3份、砂土2份和草木灰1份配合调制。从幼苗至开花一般需2—3个月。植株根系发达，须根生长极旺，故在此期间宜换盆1—2次，以利根系。　　　移栽上盆后，要从幼苗开始及时进行摘心，促其分枝而多开花。需要翻盆的也要摘心，使其形成繁密圆满的株形。如要培养较大的株型，可用支柱扶撑绑架，并剥除其所有的侧芽，使枝条向高度生长。待茎干长高后反复摘心，使其成长为一株伞形的植株。　　　香水草喜湿润的环境，春季生长旺盛季节，盆土应保持湿润，过干过湿都会引起叶片发黄，一般春、秋季节每天浇1次水，夏季生长缓慢，最好是早晚各浇1次水。冬季时适当控制水分不可过湿，3～4天浇一次水即可。　　　香水草属喜肥，上盆一周后便可开始追肥，在生长期间每周施一次稀薄腐熟的饼肥水，或经过发酵的鸡粪液；每隔2－－3周增施一次复合化肥。冬季室温低和夏季炎热。可延长追肥的间隔或者停止施肥。　　　　香水草是喜光植物，要求充足的阳光，在日光不足的环境里，容易生长瘦弱，枝纤花小，或不能开花。冬季时将其移至阳光充足的场所；夏季时再把香水草放置在荫棚下或是遮光处，遮去强烈的日光，否则叶片很容易灼伤枯黄；春、秋两季时就可以让香水草得到充足的日照。　　　夏季气温超过30℃时，植株生长缓慢进入半休眠状态，如经烈日曝晒，叶片易枯黄。因此夏季应将花盆移至凉爽而又通风的地方，生长适温为15℃～25℃，冬季室温保持在13℃以上就能继续开花，温室内一年四季均可开花，越冬温度5—7℃，温度下降到0℃左右，即受冻害。', '　　　\n　一、扦插繁殖\n　　扦插的适期，四季都可以进行，但以春、秋两季较好；播种适期秋季即为秋播，香水草的　　室内扦插多在2－－3月进行，嫩枝扦插。一般在梅雨　　摘除插穗下部叶片，仅留上部2～3片。扦插介质通常采用河沙。扦插的深度为插穗的1／3，插后轻压基部周围，使插穗与沙密接，插后浇足水，并遮荫，之后保持一定的湿度，3周左右可发根，然后先移栽到小盆中，盆土可选用腐殖土、沙、园土，加入少量草木灰拌匀混合即可。20天后翻盆种植到较大的盆内。当苗长高7～8厘米时进行摘心。加强肥水　\n　二、播种繁殖\n　　播种适期秋季即为秋播，香水草的寿命很短，只能维持1年，所以采收的种子宜早播，以便获得较高的出苗率，气温22℃，约20—30天发芽。', 'http://img.boqiicdn.com/Data/BK/P/imagick43491448961232.jpg', 'http://www.boqii.com/entry/detail/2274.html', '');
INSERT INTO `plant_family` VALUES ('48', '大花美人蕉', 'Canna generalis', '大花美人蕉', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2356/0,http://www.boqii.com/entry/photo/2356/5060', '　', '被子植物门', '单子叶植物纲', '目', '美人蕉科', '美人蕉属', '大花美人蕉', 'Canna generalis L. H. Bailey ＆ E. Z. Bailey', 'Canna generalis', '　　 　　大花美人蕉株高约1.5米，茎、叶和花序均被白粉。叶片椭圆形，长达40厘米，宽达20厘米，叶缘、叶鞘紫色。总状花序顶生，长15－30厘米（连总花梗）；花大，比较密集，每一苞片内有花2－1朵；萼片披针形，长1.5－3厘米；花冠管长5－10毫米，花冠裂片披针形，长4.5－6.5厘米；外轮退化雄蕊3，倒卵状匙形，长5－10厘米，宽2－5厘米，', '　　大花', '　　大花　\n　一、播种法\n　　播种之前，先锉刀坚硬的种皮，然后放在25℃的水中浸泡24小时，再点播于素沙土中。覆土最好不要太厚，以种子直径的1－2倍为宜。播完之后，保持土壤湿润，20℃左右　\n　二、分根茎法\n　　在每年3月初，把前一年贮存的根茎分切成块，去掉腐烂部分、使每块带有两三个芽眼，然后直接栽于花盆中或者埋于素沙之中，注意保持土壤湿润，温度保持在10－15度之间。20天左右，当芽长为4－5厘米时，即可分盆。　　\n三、分株法\n　　一般在6－7月阴雨天或傍晚时候，针对株间或株丛间距在4－5厘米以上，未出花序者，用锋利的工具从株间垂直向下切割，快速分株或分株丛，注意多带宿土，不要损伤枝叶，然后直接栽入定植穴内，栽后及时浇透水。如遇环境比较干旱，还要适当遮阳，以增加湿度。经过10天左右的', 'http://img.boqiicdn.com/Data/BK/P/imagick55011450864382.jpg', 'http://www.boqii.com/entry/detail/2356.html', '');
INSERT INTO `plant_family` VALUES ('49', '西府海棠', 'Malus micromalus Makino', '西府海棠', '海红、子母海棠、小果海棠', '不容易死', '中国云南、甘肃、陕西、山东、山西、河北、辽宁等地', 'http://www.boqii.com/entry/photo/2049/0,http://www.boqii.com/entry/photo/2049/5478', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '苹果属', '', 'Malus micromalus Makino', '', '　　 　　西府海棠为小乔木，高达2.5－5米，树枝直立性强；小枝细弱圆柱形，嫩时被短柔毛，老时脱落，紫红色或暗褐色，具稀疏皮孔；冬芽卵形，先端急尖，无毛或仅边缘有绒毛，暗紫色。叶片长椭圆形或椭圆形，长5－10厘米，宽2.5－5厘米，先端急尖或渐尖，基部楔形稀近圆形，边缘有尖锐锯齿，嫩叶被短柔毛，下面较密，老时脱落；叶柄长2－3.5厘米；托叶膜质，线状披针形，先端渐尖，边缘有疏生腺齿，近于无毛，早落。伞形总状花序，有花4－7朵，集生于小枝顶端，花梗长2－3厘米，嫩时被长柔毛，逐渐脱落；苞片膜质，线状披针形，早落；花直径约4厘米；萼筒外面密被白色长绒毛；萼片三角卵形，三角披针形至长卵形，先端急尖或渐尖，全缘，长5－8毫米，内面被白色绒毛，外面较稀疏，萼片与萼筒等长或稍长；花瓣近圆形或长椭圆形，长约1.5厘米，基部有短爪，粉红色；雄蕊约20，花丝长短不等，比花瓣稍短；花柱5，基部具绒毛，约与雄蕊等长。果实近球形，直径1－1.5厘米，红色，萼洼梗洼均下陷，萼片多数脱落，少数宿存。花期4－5月，果期8－9月。', '　　西府海棠为小乔木，花在蕾时非常红艳，开花后呈淡粉色，适应能力比较强，在我国北方的干燥地区生长良好，所以是绿化中非常受欢迎的。那么西府海棠在栽种过程中应该注意哪些问题呢？　　　每年秋季落叶后在其根际挖沟施人腐熟有机肥，覆土后浇透水。成株浇水不宜多，水多易产生黄叶。一般春季浇2－3次水，节浇1－2次水，入冬时再浇1次水。　　　当苗高80－100厘米时，养成骨干枝。在落叶后至早春萌芽前进行一次修剪，修剪过密枝、内向枝、重叠枝、把枯弱枝、病虫枝剪除，以保持树体疏散，通风透光，树冠圆整。为促进植株开花旺盛，须将徒长枝进行短截，以减少发芽的养分消耗。结果枝、蹭枝则不必修剪。在生长期间，如能及时进行摘心，早期限制营养生长，则效果更为显着。　　　西府海棠易受红蜘蛛、蚜虫、、天牛等害虫的。如发现红蜘蛛，立即喷施15％哒螨灵乳油1500倍液、205％螨死净悬浮剂2000倍液。发现蚜虫用50％蚜松乳油1000～1500倍液、50％辛硫磷乳油2000倍液。如发现，在冬季剪除虫枝和人工刮除；在若虫孵化盛期，喷25％亚胺硫磷乳油1000倍液。天牛主要危害树干和枝梢，可利用成虫的假死性人工捕杀；用铁丝钩杀幼虫；在幼虫危害期，先用镊子或嫁接刀将有新鲜虫粪排出的排粪孔清理干净，然后塞人磷化铝片剂或磷化锌毒签，并用粘泥堵死其它排粪孔，或用注射器注射80％敌敌畏。', '　　　\n　1、嫁接法：\n　　\n2、分株法：\n　\n　3、埋根法：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick2301442482822.jpg', 'http://www.boqii.com/entry/detail/2049.html', '');
INSERT INTO `plant_family` VALUES ('50', '铁十字秋海棠', 'Begonia masoniana', '铁十字秋海棠', '马蹄海棠', '不容易死', '原产于我国和马来西亚', 'http://www.boqii.com/entry/photo/2268/0,http://www.boqii.com/entry/photo/2268/5257', '', '', '', '', '', '', '', '', '', '　　 　　铁十字秋海棠的根茎横卧，肉质。叶柄上长有长绒毛，叶柄直接长在根茎上。叶近心形，长16－20cm，状突起和刺毛，淡绿色。中间有一类似十字形的紫褐色斑纹。花小、黄绿色。　　　　　　　　　　　　　　　', '　　是比较常见的观叶植物，由于其叶片的图案比较特殊，所以有较高的观赏价值。铁十字秋海棠的栽培难度并不高，想要保持铁十字秋海棠的观赏价值，那么在栽培过程中需要做到以下几点：　　1、盆土干湿适中。由于铁十字秋海棠叶片较大，因此在需注意盆土不能太干，但也要避免浇水过勤而使盆土长处于过湿状态或积水，引起生长不好甚至死亡。夏季与冬季盆土偏干些为好，但要求空气湿度高，特别在夏天高温季节，湿度保持在80％较好，故要经常向叶面和地面喷水，并要注意通风，否则易得病害。　　2、温度与光照适宜。铁十字海棠生长适宜温度为22～25℃，最低温度不能低于10℃，最高温度不能超过30℃。因此，在夏天天气炎热要采取遮荫、通风、喷水降温、避免阳光直射等措施；要增温，使温度保持在10℃以上，而置于向阳处。家庭莳养，春、秋季节可放在室内光线明亮处，冬季可放在朝南向阳地方，注意保温；夏季移至北面窗台上，注意通风降温。为了增湿，需经常向叶面喷水而盆土不能太湿。　　3、翻盆与施肥。每年春季应翻1次盆，换上新的肥沃、疏松的培养土，盆底要多垫上碎瓦片或砾石，以利排水，并施上腐熟的有机肥或颗粒肥料。生长期间，每隔半个月需施入稀薄饼肥或液肥，冬、夏两季要停止施肥。施肥时要注意勿溅到叶片上，施好后需洒1次水，以免造成肥害。', '　　　　铁十字秋海棠常用分株和叶插繁殖。分株繁殖以春季换盆时进行为好，选择鲜嫩有顶芽的根芭切开，每盆栽2－3段即可。叶插可在5－6月，采成熟叶片，留叶柄1厘米剪下，将叶片剪成直径6－7厘米大小，插入沙床，约20－25天生根，2个月后可盆栽。　　铁十字秋海棠在换盆时分株。叶插一般在夏季进行分株，保持床面潮湿，空气湿度不宜过高，否则易烂。约30余天，即能长出小植株。待长出小叶后即可移植。', 'http://img.boqiicdn.com/Data/BK/P/imagick43711448875920.jpg', 'http://www.boqii.com/entry/detail/2268.html', '');
INSERT INTO `plant_family` VALUES ('51', '矮雪轮', 'Silene pendula', '矮雪轮', '大蔓樱花', '不容易死', '地中海地区', 'http://www.boqii.com/entry/photo/2372/0,http://www.boqii.com/entry/photo/2372/5044', '', '', '', '', '石竹科', '蝇子草属', '', 'Silene pendula', '', '　　 　　矮雪轮高30厘米左右，全株具白色柔毛，上部具腺，多分枝；茎自基部有外倾性呈半匍匐状；叶对生，卵状披针形或狭椭圆形；花腋生，聚伞花序，花瓣倒心脏形，先端二裂，粉红色，栽培种中花色较多，有白、淡紫、浅粉、', '　　的植株矮生密集，花后澎大萼笥仍十分美丽，是很好的花坛和花境的材料，其矮生品种常被用于点缀居室、岩石园等。矮雪轮的栽培难度并不高，人工也较简单。　　矮雪轮性喜阳光充足、耐寒、耐肥，栽种在富含腐殖质、排水畅通的湿润土壤上生长良好。　　8月下旬至9月上旬播种在露地苗床，入冬前移植在有防寒的冷床内越冬，来年春季定植露地。若用于布置花坛，因具半匍匐性，宜及早定植。一再移栽时要尽量多带些原土坨，以减少根系的损伤，并及时浇透水。　　春雨一定要注意土壤疏松而排水良好，防止雨水过多使根颈部，导致整株苗枯死。生长期间要勤施肥、勤浇水，同时要注意适时进行中耕除草，使其生长健壮，开花繁茂。', '　　　　矮雪轮常采用播种繁殖，9月初播种，入冬前移植于有防寒冷　　9月下旬播于露地苗床，发芽的适温为20℃。华北地区阳畦', 'http://img.boqiicdn.com/Data/BK/P/imagick7491451381613.jpg', 'http://www.boqii.com/entry/detail/2372.html', '');
INSERT INTO `plant_family` VALUES ('52', '初恋', 'xGraptoveria ', '初恋', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2365/0,http://www.boqii.com/entry/photo/2365/5051', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '风车草属与拟属杂交（风车石莲属）', '', 'xGraptoveria \'Douglas Huth\'', '', '　　 　　初恋的叶片呈莲座状松散排列；有蜡质的白色薄霜粉；匙形叶，平坦微内凹，先端上翘；在不同光照环境下外形差异很大。露天养护（全日照）时是粉红色（可能微带橙黄色调），室内养护时是蓝绿色。花浅黄色，内侧有红色斑点，5瓣。老植株会从基部萌生侧芽，成为群生的植株', '　　为景天科拟石莲属多肉植物，春末会开花，花黄色。初恋如果养的好的话，是品相相当高的粉色系多肉植物。初恋的栽培难度并不高，小编就为你介绍一下如何养好初恋。　　初恋属于比较好的，除夏季要注意遮阴通风外，其他季节可尝试露养，种植土壤选择疏松透气的配土，如泥炭土和珍珠岩，3：2比例，浇水可干透浇透，如不确定浇水时机，可在觉得土壤已经干了的情况多等一两天再浇水。　　初恋比较怕热，夏季应注意遮阴通风控水，延长浇水间隔，甚至可等到叶片感觉有点软了再浇水。夏季初恋下部叶片慢慢变黄枯萎属正常现象，不用太害怕，浇水过于勤快，盆土过于潮湿，可能会出现掉叶，或者一碰就掉的情况。　　初恋对温度和光照敏感，大棚刚出来的初恋，因温度较高，小，光照质量也不算好，往往是灰绿色，叶片也较长，不紧凑，不像初恋反而像失恋。反之在家养环境，秋冬季节，温差大、光线足够的情况下，初恋的颜色会变得粉红起来，初恋变色的过程，往往是从叶缘叶尖开始，然后叶片不规则的一点两点多点慢慢变红，非常美妙。此外，初恋比较容易群生，往往种植半年一年左右就会从下部萌生出许多侧芽。', '　　初恋是比较容易栽培的多肉　　初恋的人工繁殖方式一般有分株、扦插和播种繁殖。砍头扦插的方式最容易存活，会长出小侧芽。　　初恋叶片肥厚宽大，呈松散莲座状', 'http://img.boqiicdn.com/Data/BK/P/imagick59061451294928.jpg', 'http://www.boqii.com/entry/detail/2365.html', '');
INSERT INTO `plant_family` VALUES ('53', '金丝桃', 'Hypericum monogynum L.', '金丝桃', '土连翘', '不容易死', '中国、日本', 'http://www.boqii.com/entry/photo/2138/0,http://www.boqii.com/entry/photo/2138/5389', '　', '被子植物门', '双子叶植物纲', '侧膜胎座目', '藤黄科', '金丝桃属', '金丝桃', 'Hypericum monogynum L.', 'Hypericum monogynum', '　　 　　金丝桃为灌木，高0.5－1.3米，丛状或通常有疏生的开张枝条。茎红色，幼时具2（4）纵线棱及两侧压扁，很快为圆柱形；皮层橙褐色。花序具1－15（－30）花，自茎端第1节生出，疏松的近伞房状，有时亦自茎端1－3节生出，稀有1－2对次生分枝；花梗长0.8－2.8（－5 ）厘米；苞片小，线状披针形，早落。花直径3－6.5厘米，星状；花蕾卵珠形，先端近锐尖至钝形。萼片宽或狭椭圆形或长圆形至披针形或倒披针形，先端锐尖至圆形，边缘全缘，中脉分明，细脉不明显，有或多或少的腺体，在基部的线形至条纹状，向顶端的点状。花瓣金黄色至', '　　', '　　　　金丝桃常用分株、扦插和播种法繁殖。分株在冬春季进行，较易成活。扦插用硬枝，宜在早春萌芽前进行。播种在3－4月进行，因其种子　　金丝桃的扦插多在梅雨季节进行，用嫩枝作插穗，插穗最好带踵，用当年生粗壮枝，剪成8一10厘米长，顶端留2一3片叶，插人1／2，扦插苗需遮阴，但不宜过湿。插后当年可长到20厘米左右，翌年可移栽。', 'http://img.boqiicdn.com/Data/BK/P/imagick88821445506838.jpg', 'http://www.boqii.com/entry/detail/2138.html', '');
INSERT INTO `plant_family` VALUES ('54', '繁星花', 'Star－cluster', '繁星花', '雨伞花、五星花、星形花、埃及众星花、草本仙丹花', '不容易死', '原产非洲热带，马达加斯加，阿拉伯地区；我国南部有栽培', 'http://www.boqii.com/entry/photo/2368/0,http://www.boqii.com/entry/photo/2368/5048', '植物　', '被子植物门', '双子叶植物纲', '茜草目', '茜草科', '五星花属', '', 'Pentas Lanceolata', '', '　　 　　繁星花为直立或外倾的亚灌木，高30－70厘米，被毛。叶卵形、椭圆形或披针状长圆形，长可达15厘米，有时仅3厘米，宽达5厘米，有时不及1厘米，顶端短尖，基部渐狭成短柄。聚伞花序密集，顶生；花无梗，二型，花柱异长，长约2.5厘米；花冠淡紫色，喉部被密毛，冠檐开展，直径约1.2厘米。花期夏秋。', '　　原产于热带非洲，人工栽培难度不高，耐旱、耐高温，花期较长，花色繁多，现在受到很多花友的，非常适合盆栽及花坛等布置。　　　使用无菌、稍含肥料且排水良好的泥炭土。pH值以6.5－6.8为宜，以避免铁和镁的缺乏。如果pH值低于6.0，由于铁中毒，会产生严重的的叶缘烧灼现象，而使植株停止。　　　定植后1周开始施用“叶绿精”800－1000倍液，每7－10天浇一次。植株进入生长中期（即株高8－10厘米）时，可改施用“开花精”800－1000倍溶液，每周一次，以促使花芽分化和生长良好。　　　　繁星花喜日照充足的环境，光线愈强，植株愈紧密、矮壮。因此在弱光、短日照的冬季，应注意补充光照。　　　繁星花较耐旱，但不耐水湿。生长期间不宜过度浇水，同时应避免栽培介质积水，以免诱发根腐病。浇水时，水温不宜过低（即水温与介质应保持一致），过度浇水，常使植株黄化，花朵生长缓慢。　　　暖热而日照充足有助于繁星花的生长，生长期间，宜保持夜温在17－18℃以上，日温22－24℃以上。温度低于10℃，会使开花不整齐并延迟或妨碍花朵的开放。', '　　繁星花的　　繁星花在育苗阶段由于种子　　播种后7－9星期即可移植上盆，花盆直径以10－15cm为宜。栽培介质使用无菌，稍含肥料且排水良好的泥炭土。PH值以6.5－6.8为宜，暖热而日照充足有助于繁星花的生长，生长期间宜保持夜温17－18℃以上，日温22－24℃以上，　　繁星花喜日照充足的环境，光线强可提高植株的品质，光线愈强，植株愈紧密。冬季栽培应注意', 'http://img.boqiicdn.com/Data/BK/P/imagick14751451296244.jpg', 'http://www.boqii.com/entry/detail/2368.html', '');
INSERT INTO `plant_family` VALUES ('55', '红彩阁', 'Euphorbia enopla Boiss.var.enopla', '红彩阁', '仙人球', '不容易死', '非洲', 'http://www.boqii.com/entry/photo/2480/0,http://www.boqii.com/entry/photo/2480/4937', '　', '被子植物门', '双子叶植物纲', '大戟目', '大戟科', '大戟属', '红彩阁', 'Euphorbia enopla Boiss.var.enopla', '', '　　 　　红彩阁的形态为多分枝灌木，分枝全部向上生长。3－4棱，通常3棱，粗4－6厘米、长15－25厘米，但在栽培中分 枝较细而更长。棱缘有坚硬短齿。表皮深绿色有白色晕纹。对生刺红褐色，0.3－0.4厘米长。在分枝上部每棱上都有卵圆形带短尖的绿色叶，叶长3—5厘 米，叶质很薄。冬季寒冷时会落叶，翌年5月萌发新叶。', '　　为大戟科大戟属多肉，为灌木状肉质植物。红彩阁的外形特殊，非常适合盆栽在室内观赏，人工栽培红彩阁的难度并不高，那么如何才能养好红彩阁呢？　　1、光照：最适宜摆放在温暖通风的环境里。　　2、：冬季室温不得低于5℃，最适宜生长温度25℃至28℃，以18～30℃为宜。春到秋可以充分浇水并施肥，也可直接在露地栽培。　　3、水分管理：多肉植物对水十分敏感，浇水不匀或过多会引起，每次浇水时都要浇透，等盆土干透后再浇第二次，如盆土不好浇透时可浸灌，及把整个盆放到水里，水面不超过盆缘，等盆土全部湿透为止。　　4、肥料：生长初期每盆施颗粒肥5～10粒，每隔7－10天施一次，进行正常的管理。', '　　红彩阁的栽培难度并不高，但是光照不足或　　红彩阁一般选用扦插的繁殖方法，可挑选', 'http://img.boqiicdn.com/Data/BK/P/imagick61011454404773.jpg', 'http://www.boqii.com/entry/detail/2480.html', '');
INSERT INTO `plant_family` VALUES ('56', '枝干番杏', 'Drosanthemum eburneum', '枝干番杏', '', '不容易死', '非洲南部，大洋洲，中太平洋', 'http://www.boqii.com/entry/photo/2242/0,http://www.boqii.com/entry/photo/2242/5283', '　　', '被子植物门', '双子叶植物纲', '石竹目', '番杏科', '番杏属', '枝干番杏', 'Drosanthemum eburneum', '', '　　 　　枝干番杏为多年生肉质小灌木，叶非常肉质，对生，棒形，覆有一层透明反光的隆起。嫩茎呈绿色，老茎则呈暗红色或棕色，多年生枝条容易木质化，没有明显的休眠期。枝干番杏幼苗形似“碧光环”，在网络上早已被混淆，后者生长极为缓慢，终生都只有一对肉质叶，形似兔耳朵，且老株有块根，高温时会进入休眠状态，叶片枯萎，且没有枝条，比较好区分。', '　　的叶片是半透明的，非常漂亮，并且其叶片排列的和兔非常像，已经成为了非常受欢迎的多肉植物。那么如何才能种好枝干番杏呢？小编就为你简单介绍一下。　　　　用以播种的土壤应采用质地疏松透气，保水效果佳的土壤。土壤最好是用混合土，混合土的可由营养土、煤灰、砂子、草木灰、珍珠岩组成，配比为4：4：2：1：1；另外还可以将营养土、蛭石、珍珠岩进行配比混合，比例为4：6：1。　　　　枝干番杏种子在发芽后一到两个月的时候就可以对它施肥了。需要注意的是，要将买来的尽量地稀释，依然用浸灌的方式施肥。如果对施肥没有经验，也可以先不施肥。当枝干番杏的小苗长出来很多以后，为了能让小苗们吸收到足够的养料，应该对它们进行及时的分盆。分盆后的小苗需要在一周之后才浇水。', '　　　　\n一、播种\n　　在播种之前，要先在土壤的表面均匀地铺撒一层　\n　二、苗期管理\n　　当枝干番杏种子发芽之后，由于幼苗比较脆弱，所以一定要精心地管理。在枝干番杏的发芽期乃至苗期，都应该切忌过于潮湿，以防植株发生　　有的时候枝干番杏小苗的根部会长到土壤的表面，这是需要轻轻地将苗根埋进土壤。由于枝干番杏', 'http://img.boqiicdn.com/Data/BK/P/imagick89511448270297.jpg', 'http://www.boqii.com/entry/detail/2242.html', '');
INSERT INTO `plant_family` VALUES ('57', '银星', 'Graptoveria ‘Silver Star’', '银星', '', '未知', '', 'http://www.boqii.com/entry/photo/2485/0,http://www.boqii.com/entry/photo/2485/4931', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '风车草属', '银星种', 'Graptoveria ‘Silver Star’', '', '　　 ', '　　为景天科风车草属多肉植物，为杂交品种，在中国多地均有栽培。银星的亲本均产于南非，所以温暖干燥且阳光充足的环境。那么如何才能养好银星呢？　　　银星多肉土壤可以采用的是泥炭混合珍珠岩加了煤渣，大概比例1：1：1，为了隔离植株和土表，也为了更加透气，可以铺上颗粒的干净河沙，河沙尺寸3到5毫米。　　　　银星多肉浇水是干透才浇透，不干不浇水。　　　银星多肉春天和秋天是生长期，可以全日照，夏天一旦温度高于35度，就需要遮阳，然后慢慢少水，整个夏季的少水或不给水，到了9月中旬温度下来了，就开始恢复浇水，银星夏天还是可以正常生长的，休眠不太明显。冬季如果温度能够保持0度以上，都是可以给水的，0度以下就要断水，否则就容易。冬季虽然寒冷，可也不是一个冬季都不给一点水，也会在适当的时候微微给点水在植株的根部，冬季切勿喷雾或给大水，叶心水分停留太久，容易引起腐烂，平时通风好，可以淋透，清洗清洗叶片也是比较好的，通风很关键哦。春季温度上升后就可以慢慢恢复正常给水。', '　　银星为杂交　　其实银星的繁殖方式很简单，一般可以采用扦插的方式进行繁殖。扦插的', 'http://img.boqiicdn.com/Data/BK/P/imagick78691455441296.jpg', 'http://www.boqii.com/entry/detail/2485.html', '');
INSERT INTO `plant_family` VALUES ('58', '花叶艳山姜', 'Alpinia zerumbet ', '花叶艳山姜', '彩叶姜、斑纹月桃', '不容易死', '中国和印度', 'http://www.boqii.com/entry/photo/2223/0,http://www.boqii.com/entry/photo/2223/5304', '', '', '', '', '', '', '', '', '', '　　 　　花叶艳山姜为多年生草本，发达的地上茎。植株高1－2米，具根茎。叶具鞘，长椭圆形，两端渐尖，叶长约50厘米，宽15－20厘米，有金黄色纵　　　　　　　　　　　　　　　　　　　　', '　　喜高温、多湿的环境，不耐寒，喜阳光。由于花叶艳山姜的观赏效果甚佳，所以非常适合做成盆栽摆放在厅堂，也可在室外栽培用于点缀或池畔处。花叶艳山姜的花期为6－7月，花香诱人，但是由于其叶片更加特别并且四季常绿，所以常作观叶植物栽培。　　花叶艳山姜栽培土质以疏松、排水和通气性好的基质，可用国产泥炭种植，将泥炭加水拌匀，待上杯种植。用分株繁殖，春、夏季挖出地下根茎，剪去地上部分茎叶，割取根茎分栽，分栽植株放半阴处，待萌发新芽后恢复正常。　　花叶艳山姜生长期每月施肥1次，以磷、钾肥为主，盆土保持湿润，夏、秋季经常给叶面喷水，盛夏放半阴处，叶面会更显目。室外地栽，选择排水好的疏松壤土，春末夏初多见阳光，盛夏稍加遮阴，秋、冬季将根茎挖出放室内贮藏。', '　　花叶艳山姜的花姿优美，叶片艳丽，是很有观赏价值的室内观叶　　花叶艳山姜的分株繁殖是母株从花盆内取出，抖掉多余的盆土，把盘结在一起的根系尽可能地分开，用锋利的小刀把它剖开成两株或两株以上，分出来的每一株都要带有相当的根系，并对其叶片进行适当地修剪，以利于成活。　　播种繁殖　　花叶艳山姜分株装盆后灌根或浇一次透水。由于它的根系受到很大的损伤，吸水能力极弱，大约需要3～4周才能恢复萌发新根，因此，在分株后的3～4周内要节制浇水，以免烂根，但它的叶片的蒸腾没有受到影响，为了维持叶片的水分平衡，每天需要给叶面喷雾1～3次。这段', 'http://img.boqiicdn.com/Data/BK/P/imagick58961447666128.jpg', 'http://www.boqii.com/entry/detail/2223.html', '');
INSERT INTO `plant_family` VALUES ('59', '一串红', 'Salvia splendens Ker－Gawler', '一串红', '爆仗红（炮仗红）、拉尔维亚、象牙红、西洋红、洋赪桐', '不容易死', '原产地在巴西，中国各地庭园中广泛栽培。', 'http://www.boqii.com/entry/photo/2269/0,http://www.boqii.com/entry/photo/2269/5256', '　', '被子植物门', '双子叶植物纲', '唇形目', '唇形科', '鼠尾草属', '', 'Salvia splendens Ker－Gawler', 'Scarlet Sage 、Tropical Sage', '　　 　　一串红为亚灌木状草本，高可达90厘米。茎钝四棱形，具浅槽，无毛。叶卵圆形或三角状卵圆形，长2.5－7厘米，宽2－4.5厘米，先端渐尖，基部截形或圆形，稀钝，边缘具锯齿，上面绿色，下面较淡，两面无毛，下面具腺点；茎生叶叶柄长3－4.5厘米，无毛。', '　　一串红是我们非常熟悉的植物，在很多地方我们都能见到一串红的身影。其实一串红的栽培难度并不高，但是想要一串红开出漂亮鲜艳的花朵就需要注意小编为你整理的下列。　　1、土壤：种植一串红要求疏松、肥沃和排水良好的沙质壤土，土壤要求为5.5～6.0，对用甲基溴化物处理的土壤和碱性土壤反映非常敏感。　　2、：一串红的生长适温为20－25℃，10℃以下叶子变黄脱落，高于20℃则叶子和花变小。夏季气温超过35℃以上或连续阴雨，叶片黄化脱落。因此，夏季高温期，需降温或适当遮荫。　　3、水肥：在生长期间，为避免一串红徒长，应少浇水，勤中耕除草。生长期间以施鸡粪便肥为主，少施氮肥，以满足其生长需要，可每隔10天喷施1次0.2％的磷酸二氢钾溶液。在每次除蕾后要浇足水，经一周后施淡肥水，其后勤施肥水，并适当增施P、K肥，可促生新梢，开花繁盛。　　4、光照：一串红喜光，充足的阳光可以使一串红花色鲜艳，枝叶翠绿，但在夏季温度高阳光强的时候，需适当遮阳降温。　　5、修剪：种植一串红需及时摘心整枝，可促进分枝，防止茎节间徒长，茎杆变细，控制植株高度，增加开花数及种子数量。在一串红幼苗有4－6片真叶时进行第1次摘心，长到8－10片真叶时2次摘心，以后视生长情况进行，每次摘心留1－2节为宜。', '　　　　\n1、扦插法\n　　以扦插法来繁殖一串红可以在夏秋5月—8月进行，插穗取组织充实的嫩枝，摘去顶芽再插，生根容易。在夏季高温干燥　\n　2、播种法\n　　播种法也是一串红常用的繁殖方法，在南方地区通常在3月下旬至4月初是一串红露地播种最好时机，选背风向阳、排水条件好的沙质土壤为苗床，畦面翻松打碎整平，让其在太阳下暴晒几天，再用', 'http://img.boqiicdn.com/Data/BK/P/imagick86671448876137.jpg', 'http://www.boqii.com/entry/detail/2269.html', '');
INSERT INTO `plant_family` VALUES ('60', '旱金莲', 'nasturtium.', '旱金莲', '旱荷、寒荷、金莲花、旱莲花、金钱莲、寒金莲、大红雀', '不容易死', '', 'http://www.boqii.com/entry/photo/2299/0,http://www.boqii.com/entry/photo/2299/5225', '', '', '', '', '', '', '', '', '', '　　 　　旱金莲多年生做一年生栽培，茎叶稍肉质，草本，半蔓生，无毛或被疏毛。单花腋生，花柄长6－13厘米；花黄色、紫色、桔红色或杂色，直径2.5－6厘米；花托杯状；萼片5，长椭圆状披针形，长1.5－2厘米，宽5－7毫米，基部合生，边缘膜质，其中一片延长成一长距，距长2.5－3.5厘米，渐尖；花瓣5，通常圆形，边缘有缺刻，上部2片通常全缘，长2.5－5厘米，宽1－1.8厘米，着生在距的开口处，下部3片基部狭窄成爪，近爪处边缘具　　　　　　　　　　　　　　　　', '　　旱金莲又名、旱荷，为旱金莲科肉质草本花卉，旱金莲喜温暖、湿润的环境，栽培难度非常低。旱金莲为半蔓性，所以开花后会比较凌乱。　　旱金莲性喜温和气候，不耐严寒酷暑。适生为18至24摄氏度。能忍受短期0℃喜温暖湿润，越冬温度10℃以上。夏季高温时不易开花，35℃以上生长受抑制。冬、春、秋需充足光照，夏季盆栽忌烈日曝晒。盆栽需疏松、肥沃、通透性强的，喜湿润怕渍涝。　　开花后要减少浇水，防止枝条旺长，如果浇水过量、排水不好，根部容易受湿，轻者叶黄脱落重者全株蔫萎死亡。旱金莲喜阳光充足，不耐荫蔽，春秋季节应放在阳光充足处培养，夏季适当遮阴，盛夏放在阴凉通风处，北方10月中旬入室，放在向阳处养护，室温保持10－－15℃，适当控制肥水。　　同时，旱金莲的花、叶趋光性强，栽培或观赏时要经常更换位置，使其均匀生长。　　旱金莲茎蔓生，一般都必须立支架加强，如任其自然生长，势必茎蔓太长，影响观赏。为了控制其茎蔓无限生长，当旱金莲进入初花期，其茎蔓生长已达30－40厘米时，用100PPM的多效唑溶液进行叶面喷施，促其矮化。喷后三天就能见效，主蔓增粗，顶蔓延长迟缓，侧蔓上的花朵相继开放，颇为美丽。', '　　　　1、器皿和介质的选择　　扦插的器皿可以选用小一点的，这样比较容易控制介质的湿度，不容易出现烂根的情况，建议可以用一次性塑料水杯，至于介质，则比较宽泛，泥炭，　　2、　　成功的扦插，时间的选择上很重要，根据对花友扦插成功的调查，发现，5月份、10月份11月份12月份扦插的成功率都很高，其他月份没有试过，不过根据花友的反馈来看，只要　　3、枝条的选择，截取5－7厘米左右的顶芽枝条扦插即可，一般来说生根时间在1周左右，扦插后放置在散光处，保持土壤湿润，但是不要积水。敲千万字，不如一张图，下面是旱金莲扦插的过程图，花友模仿扦插即可，很容易的哦。', 'http://img.boqiicdn.com/Data/BK/P/imagick94931449568030.jpg', 'http://www.boqii.com/entry/detail/2299.html', '');
INSERT INTO `plant_family` VALUES ('61', '黄金钮', 'Borzicactus aureispina', '黄金钮', '金毛花冠柱', '不容易死', '', 'http://www.boqii.com/entry/photo/2479/0,http://www.boqii.com/entry/photo/2479/4938', '　　', '被子植物门', '双子叶植物纲', '', '仙人掌科', '群蛇柱属', '', 'Borzicactus aureispina', '', '　　黄金钮为 　　黄金钮茎细圆柱形，粗1.5—2.5厘米，高卜1.5米，多分枝，攀援或匍匐下垂，鲜绿色，具低矮棱16—18条，被金黄色刚毛状细刺。单株似金丝', '　　', '　　　　黄金钮在　　黄金钮扦插最好用柱状　　可在生长期剪取顶端充实的变态茎作插穗，长15－20厘米，待剪口稍干燥后再插入沙床，插壤不宜过湿。插后约50－60天生根。根长2－3厘米时移栽上盆。嫁接，多在5－6月进行，可采用直立柱状仙人掌如梨果仙人掌、大花蛇鞭柱等作砧木。取黄金钮顶端变态茎10厘米作接穗，接后约50天愈合。', 'http://img.boqiicdn.com/Data/BK/P/imagick96571454404481.jpg', 'http://www.boqii.com/entry/detail/2479.html', '');
INSERT INTO `plant_family` VALUES ('62', '点地梅', 'Herba Androsacis', '点地梅', '喉咙草、铜钱草', '不容易死', '全国各地', 'http://www.boqii.com/entry/photo/2261/0,http://www.boqii.com/entry/photo/2261/5264', '　　', '被子植物门', '双子叶植物纲', '()目', '报春花科', '点地梅属', '点地梅', 'Androsace umbellata', '', '　　 　　点地梅的主根不明显，具多数须根。叶全部基生，叶片近圆形或卵圆形，直径5－20毫米，叶柄长1－4厘米，被开展的柔毛。花葶通常数枚自叶丛中抽出，高4－15厘米，被白色短柔毛。伞形花序4－15花；苞片卵形至披针形，长3.5－4毫米；花梗纤细，长1－3厘米，果实伸长可达6厘米，被柔毛并杂生短柄腺体；花萼杯状，长3－4毫米，密被短柔毛，分裂近达基部，裂片菱状卵圆形，具3－6纵脉，果期增大，呈星状展开；花冠白色，直径4－6毫米，筒部长约2毫米，短于花萼，喉部黄色，裂片倒卵状长圆形，长2.5－3毫米，宽1.5－2毫米。', '　　的分布非常广，在我国各地均有分布。园林中，点地梅常平铺地面，被用于园栽植及灌木丛旁做地被材料。那么人工栽种点地梅应该注意哪些呢？　　点地梅喜湿润、温暖、向阳环境和肥沃土壤，常生于山野草地或路旁。但是不论是在高山草原，还是在河谷滩地，只要有一丁点瘠薄的土壤它就能生根发芽。它的种子能自播繁殖。也可在冰天雪地中生存。点地梅生于向阳地、疏林下及林绿、草地等处。　　若栽培点地梅，一般可在4月份播种，穴播、条播均可。苗高10～16厘米时移栽。', '　　　　点地梅常用播种繁殖，高山上夏季很短。点地梅在8月底前发芽。然后在冰雪中度过9个月的', 'http://img.boqiicdn.com/Data/BK/P/imagick33181448531087.jpg', 'http://www.boqii.com/entry/detail/2261.html', '');
INSERT INTO `plant_family` VALUES ('63', '蔓花生', 'Arachis duranensis', '蔓花生', '长喙花生', '不容易死', '', 'http://www.boqii.com/entry/photo/2320/0,http://www.boqii.com/entry/photo/2320/5203', '　', '被子植物门 Angiospermae', '双子叶植物纲 Dicotyledoneae', '蔷薇目 Rosales', '豆科 Leguminosae', '落花生属 Arachis', '', 'Arachis duranensis', '', '　　 　　蔓花生的叶柄基部有潜伏芽，分枝多，可节节生根，铺地平坦，草层厚度为4－10厘米，在全日照及半日照条件下生长良好，有较强的耐阴性，对土壤要求不严，但以沙质壤土为佳。生长适温为18－32℃。', '　　原产于亚洲热带及南美洲，观赏性较强，四季常青，对于有害气体的抗性较强，非常适合应用在园林中做地被。人工栽培蔓花生的难度并不高，小编就为你介绍一下蔓花生的栽培要点。　　蔓花生在做地被时，栽培株行距以25x30厘米为宜，在短期内就可形成致密的草坪。在草坪建植前每亩施入1000—1500公斤腐熟有机肥，在期根据情况追肥。如果土壤较肥沃，蔓花生长势良好，可不必施肥，或根据植株长势而定。一般追肥可选用磷钾缓释性，每亩施用10—15公斤。', '　　　　蔓花生可以用播种及扦插繁殖，由于种子采收较费工，现大量繁殖均采用扦插。扦插可于春、夏、秋季进行，一般选择在雨季或阴天进行，以中段节位做插条为佳，可促使其早生根，分枝也较多、返青之后再适当施肥促其生长。', 'http://img.boqiicdn.com/Data/BK/P/imagick58041450085359.jpg', 'http://www.boqii.com/entry/detail/2320.html', '');
INSERT INTO `plant_family` VALUES ('64', '明镜', 'Aeonium tabulaeforme', '明镜', '盘叶莲花掌', '未知', '', 'http://www.boqii.com/entry/photo/2486/0,http://www.boqii.com/entry/photo/2486/4930', '', '', '', '', '', '', '', '', '', '　　多肉 　　明镜的叶片无柄，匙形，叶色草绿至灰绿、深绿，叶缘有白色纤毛，叶片全部由中心水平向周围辐射', '　　的外形非常奇特，其叶盘的排列就像一副精美绝伦的几何图案，受到很多多肉爱好者的喜爱。明镜的栽培应注意给予合适的环境，如果光照不足，则会引起明镜叶间距离较大，大大降低其观赏价值。　　明镜原产于大西洋加那利群岛，该地区属地中海气候，夏季干热、少雨，冬季温和、湿润，因此明镜适宜在凉爽、干燥和阳光充足的环境中，耐半阴和干旱，怕水涝。主要生长期在春、秋两季，生长应给予充足的光照，如果光照不足会造成，株形散乱，叶间距较大，叶丛不呈盘状，严重影响观赏。　　浇水做到“不干不浇，浇则浇透”，避免盆土积水，否则会造成烂根；每半个月左右施一次腐熟的稀薄液肥或复合肥。冬季放在室内阳光充足处，夜间最低温度在10℃左右，并有一定的昼夜，植株能继续生长，可正常浇水、施肥；如果保持不了这么高的温度，控制浇水，维持盆土干燥，使植株休眠，也可耐5℃低温。　　栽培中如不留种子，当叶盘中心开始凸起，即将出现花葶时，要及时将其剪除，以促发侧芽。每1、2年的春季或秋季翻盆一次，盆土宜用肥沃疏松、排水良好的沙质土壤，可用腐叶土、园土、河沙等混合配制，也可掺入少量的骨粉等钙质材料。', '　　　　繁殖明镜，可在', 'http://img.boqiicdn.com/Data/BK/P/imagick21031455441711.jpg', 'http://www.boqii.com/entry/detail/2486.html', '');
INSERT INTO `plant_family` VALUES ('65', '俏黄栌', 'Euphorbia cotinifolia', '俏黄栌', '紫锦木、非洲红、非洲黑美人', '不容易死', '非洲热带', 'http://www.boqii.com/entry/photo/2293/0,http://www.boqii.com/entry/photo/2293/5231', '　　', '', '', '', '大戟科', '山麻杆属', '', '', '', '　　 　　俏黄栌的小枝红色。叶柄长，叶片薄，宽椭圆形至近圆形，长11厘米，宽约8.5厘米，红色至紫红色。顶生圆锥花序松散。', '　　又称非洲黑姑娘，原产于热带非洲，现在在温暖地区多用于园林布置。俏黄栌的叶片终年红色，非常漂亮，现在有不少花友将俏黄栌制作成盆栽，小编就为你介绍一下俏黄栌的人工栽培要点，喜欢的朋友可以一起了解。　　盆栽基质可用土、泥炭土和粗砂混合配制。期浇水不宜过多，避免盆内出现积水的现象。秋冬气温降低，应严格控制浇水，盆土过湿易引起落叶，甚至导致根茎腐烂。生长季节可每半月施肥一次，并可增施2～3磷钾肥，保持植株枝繁叶茂，防止枝叶徒长。　　生长季节宜阳光充足的环境，但夏季须遮荫，避免强光直射。栽培过程中，应尽量少搬动，以免折断枝叶，流出乳汁。生长适温：4～9月为18～24℃，９月至翌年４月为13～18℃。越冬不宜低于10℃，否则叶片易变色脱落。　　俏黄栌耐修剪，分枝能力强。植株越冬季节叶色易变淡或枯黄脱落，应结合春季换盆进行整形修剪，去除枯枝，压低株形，促其多分枝。同时，俏黄栌夏季生长较快，若植株过高，可适当进行摘心，保持植株丰满、美观。', '　　　　1、扦插繁殖以初夏为宜，剪取　　2、播种繁殖可在种子采收后立即进行，否则种子易丧失发芽力。将种子均匀撒入湿润沙床中，保持25～30℃的床温，1个月左右即可发芽，幼苗长至10厘米时便可进行移植。', 'http://img.boqiicdn.com/Data/BK/P/imagick19291449480057.jpg', 'http://www.boqii.com/entry/detail/2293.html', '');
INSERT INTO `plant_family` VALUES ('66', '蜡梅', 'Chimonanthus praecox （Linn.） Link', '蜡梅', '金梅、腊梅、蜡花、蜡梅花、蜡木、麻木紫、石凉茶、唐梅、香梅', '不容易死', '分布于中国大陆以及朝鲜、美洲、日本、欧洲', 'http://www.boqii.com/entry/photo/1969/0,http://www.boqii.com/entry/photo/1969/5558', '植物　　', '被子植物门', '双子叶植物纲', '樟目 Laurales', '蜡梅科', '蜡梅属', '蜡梅', 'Chimonanthus praecox （Linn.） Link', 'Chimonanthus praecox', '　　 　　蜡梅为落叶灌木，高达4米；幼枝四方形，老枝近圆柱形，灰褐色，无毛或被疏微毛，有皮孔；鳞芽通常着生于第二年生的枝条叶腋内，芽鳞片近圆形，覆瓦状排列，外面被短柔毛。叶纸质至近革质，卵圆形、椭圆形、宽椭圆形至卵状椭圆形，有时长圆状披针形，长5－25厘米，宽2－8厘米，顶端急尖至渐尖，有时具尾尖，基部急尖至圆形，除叶背脉上被疏微毛外无毛。', '　　', '　　很多人将　\n　一、播种法\n　　1、秋播：7～8月果实成熟以后进行采收，将种子从果托中取出，随时播种，播后10多天便可出苗，当年苗可长高达20厘米。　　2、春播：多半在3～4月份进行（种子是上一年采收贮藏的），播种前，种子需放入30～40℃温水中浸泡12小时，以促进发芽，而后在沙壤土中作条插，浇足水，15～20天便可出苗，移植　\n　二、分株法\n　　当叶芽刚开始萌动时（3～4月），便可以进行。被分株的植株，应离地20～30厘米以上，最好在上一年年底进行截顶，以便母株多积累养分。分株时先将母株四周的土掏出，用利刀劈下一部分，以便移出另行栽植。　\n　三、嫁接法：\n　　1、切接：宜在每年3～4月，腊梅芽萌动时进行（芽如麦粒大小）。接穗应超前1个月，从2～3年生腊梅树选取健壮的一年生枝条，截取枝条的中段部分。砧木宜选4～5年生腊梅实生苗或狗牙腊梅作为砧木。切接法操作：接穗长6～7厘米，留1～2对芽，将接穗两面削去皮层。略见木质部，刀口斜面长3～4厘米。将砧木离地3～6厘米处剪去，在砧木直径面横截1／3处向下切，劈开4～5厘米，将接穗插入砧木，使接穗与砧木的形成层对齐，并用塑料带扎紧接口初，涂上2克备好的湿泥，然后培土到接穗的顶部以保湿。　　2、靠接：靠接法操作：在每年5月6～21日之间进行靠接最好。将砧木置于腊梅优良品种之侧，选择与其粗细基本一致的枝条作接穗。将择砧木和接穗的枝条各用利刀削去3～9厘米的切口，注意应稍带木质部。砧木切口位置不宜过高，在20厘米以下为好，切口削好以后，将砧木的伤口与接穗的伤口相对合，尤应将双方的形成层相互紧贴，而后用绳带稍绑紧，在接口处抹上湿泥，再用塑料薄膜包扎严，然后对砧木上的枝条作适当轻剪，但不要截去顶端，使之能继续', 'http://img.boqiicdn.com/Data/BK/P/imagick76191440150067.jpg', 'http://www.boqii.com/entry/detail/1969.html', '');
INSERT INTO `plant_family` VALUES ('67', '五色苋', 'Alternanthera bettzickiana', '五色苋', '红绿草、五色草、模样苋、法国苋、彩叶草', '不容易死', '全国各地', 'http://www.boqii.com/entry/photo/2232/0,http://www.boqii.com/entry/photo/2232/5295', '植物　　', '被子植物门', '双子叶植物纲', '石竹目', '苋科（Amaranthaceae）', '莲子草属', '五色苋', 'Alternanthera bettzickiana', '', '　　 　　多年生草本，作一、二年生栽培。茎直立斜生，多分枝，节膨大，高10 －20cm。单叶对生，叶小，椭圆状披针形，红色、黄色或紫褐色，或绿色中具彩色斑。叶柄极短。花腋生或顶生，花小，白色。胞果，常不', '　　五色苋为多年生草本，原产于巴西，现在，五色苋在我国各地均有栽培，在东北地区的栽培更为盛行。五色苋的栽培难度不高，但是想要栽种出漂亮的五色苋，就需要注意根据其习性来进行栽培。　　五色苋性喜高温，最适宜在22℃至32℃之间的条件下，极不耐寒，冬季宜在15℃左右、湿度在70％左右的温室中越冬。五色苋喜光、略耐阴，不耐夏季酷热，不耐湿也不耐旱，对土壤要求不严。生长季节喜湿润，要求排水良好。高温、高湿或低温、高湿都易引起植株。　　五色苋种植盆土以富含富含腐殖质、疏松肥沃、高燥的砂质壤土为宜，忌粘质壤土。盆栽时，一般每盆种3～8株。生长季节，适量浇水，保持土壤湿润。一般不需施肥，为促其生长，也可追施0.2％的磷酸铵。喜光，略耐阴。五色苋喜温暖湿润环境。不耐热，也不耐旱。极不耐寒，冬季宜在15℃温室中越冬。', '　　五色苋的观赏价值比较高，人工栽培的难度并不高，但是由于五色苋在北方地区栽种时不能生产种子，所以常使用扦插的方法进行繁殖。那么五色苋在繁殖过程中应该注意哪些　　不同地区培育母株的时期不同，辽宁一般8月下旬至9月上旬进行。在　　大量用苗繁殖应在4月上旬进行，从母株上剪取插条，按3厘米左右株行距插入床内，管理方法同培育母株。4月末5月初即可使用。温暖', 'http://img.boqiicdn.com/Data/BK/P/imagick53231447839313.jpg', 'http://www.boqii.com/entry/detail/2232.html', '');
INSERT INTO `plant_family` VALUES ('68', '大花马齿苋', 'Portulaca grandiflora  Hook.', '大花马齿苋', '半支莲、松叶牡丹、龙须牡丹、金丝杜鹃、洋马齿苋、太阳花', '不容易死', '', 'http://www.boqii.com/entry/photo/2290/0,http://www.boqii.com/entry/photo/2290/5234', '　　', '被子植物门', '双子叶植物纲', '中央种子目', '马齿苋科', '马齿苋属', '大花马齿苋', 'Portulaca grandiflora  Hook.', '', '　　 　　大花马齿苋一年生草本，高10－30厘米。茎平卧或斜升，紫红色，多分枝，节上丛生毛。叶密集枝端，较下的叶分开，不规则互生，叶片细圆柱形，有时微弯，长1－2.5厘米，直径2－3毫米，顶端圆钝，无毛；叶柄极短或近无柄，叶腋常生一撮白色长柔毛。', '　　大花', '　　大花　\n　一、种子繁殖：\n　　\n二、分株繁殖：\n　　\n三、田间\n', 'http://img.boqiicdn.com/Data/BK/P/imagick69091449222374.jpg', 'http://www.boqii.com/entry/detail/2290.html', '');
INSERT INTO `plant_family` VALUES ('69', '蟆叶秋海棠', '', '蟆叶秋海棠', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2278/0,http://www.boqii.com/entry/photo/2278/5247', '', '', '', '', '', '', '', '', '', '　　 　　蟆叶秋海棠为多年生草本植物。无地上茎，地下根状茎平卧　　　　　　　　　　　', '　　是秋海棠中的大型观叶植物，耐阴，所以非常适合栽种在室内。蟆叶秋海棠的普及度非常广，受到世界各地人民的喜爱，在欧美的一些国家，蟆叶秋海棠尤为盛行，那么如何才能养好蟆叶秋海棠呢？　　盆土以1份腐叶土、1份园土与1份河沙混合，并配以少见骨粉或过磷酸钙作荃肥，盆栽时不宜过深。以根状茎与盆土表面平齐为好。盛夏气温高于32℃时停止，并开始出现边缘干燥、幼叶不能展开甚至枯死的现象。室内置阳光充足处养护，光照不足时叶柄细长，叶色变浅。室外养护时忌烈日直射，春末至秋末期间应特别注意遮荫。春秋为秋海棠生长旺季，可经常浇水以保持盆土湿润；夏季南方的高溢闷热天气对秋海棠的越夏十分不利，此时植株处于休眠阶段，管理不当就有可能导致植株干枯或。　　除将植株移至半阴和较为通风的地方外，切忌盆上过湿，可常向地面喷水，以达到局部降温和提高空气湿度的目的。冬季减少浇水，保持盆土稍湿即可。生长期每半个月追施I次稀薄液肥，注意勿将肥液溅到叶片上。每1一2年换盆1次，宜春季进行，换盆时将旧土及腐烂的根去掉，用新土重新栽植。', '　　蟆叶秋海棠是秋海棠的一种，也是秋海棠中最具　　\n1、分株繁殖：\n　　\n2、叶插繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick53211449046317.jpg', 'http://www.boqii.com/entry/detail/2278.html', '');
INSERT INTO `plant_family` VALUES ('70', '狗牙花', 'Grape－jasmine', '狗牙花', '白狗花、狮子花、豆腐花', '不容易死', '中国南部沿海诸省', 'http://www.boqii.com/entry/photo/2210/0,http://www.boqii.com/entry/photo/2210/5317', '植物　　', '被子植物门', '双子叶植物纲', '捩花目', '夹竹桃科', '狗牙花属', '狗牙花', 'Ervatamia divaricata （L.） Burk. cv. Gouyahua', '', '　　狗牙花为 　　狗牙花为灌木或小树。除花萼被毛外，其余均无毛。叶对生，坚纸质，椭圆形或长椭圆形，长5－12cm，宽1.5－3.5cm。聚伞花序腋生，通常双生，集在小枝端部呈假二歧状，有花6－10朵；花萼5裂，内面基部有腺体；花冠白色，重瓣，边缘有皱褶，花冠筒长达2cm。蓇葖果叉开或弯曲，内有种子3－6颗，种子长圆形，无种毛。花期6－11月，果期秋季，本种与狗牙花的区别为花单瓣。', '　　狗牙花为灌木或小树，由于狗牙花的花色洁白，绿叶青翠，所以经常被花友制作成盆栽', '　　　　狗牙花可用扦插或高压繁殖，主要用扦插。华南地区春至秋季皆可繁殖，但以春季为佳。剪取12－－15厘米长，1－2年生的嫩枝做插穗，伤口处有乳汁流出，先洗净汁液，再插入湿沙床内，遮荫或全光照均可。　　温室内全年都可进行，室外以6－7月进行扦插最佳，选一年生健枝剪取8－12厘米长的枝梢，扦入　　狗牙花的栽培基质可以选用一般的园土或塘泥，定植地栽或盆栽，但以地栽为主，一般在春季进行，对土壤要求不高。肥水栽培', 'http://img.boqiicdn.com/Data/BK/P/imagick85141447235311.jpg', 'http://www.boqii.com/entry/detail/2210.html', '');
INSERT INTO `plant_family` VALUES ('71', '金纽仙人鞭', 'Aporocactas flagelliformis（L.）Lem', '金纽仙人鞭', '金纽', '未知', '原产地墨西哥', 'http://www.boqii.com/entry/photo/2489/0,http://www.boqii.com/entry/photo/2489/4837', '　　', '被子植物门', '单子叶植物纲', '', '仙人掌科', '', '', 'Aporocactas flagelliformis（L.）Lem', '', '　　 　　金纽仙人鞭茎粗约1.3～2.5公分，长及2公尺左右呈长鞭形下垂，由基部或中间会生侧鞭。茎上有10～12棱，棱上密生刺座，每座有刺11～16枚。刺长针形，黄褐色约0.6公分长。花由茎侧开出，呈紫红色，长约7～8公分， 春季开花，属于多花性品种。果圆球形，表面有刚毛。', '　　为仙人掌科下的品种，原产于墨西哥，所以人工栽培时需要注意给予半遮阴或明亮的散射光照。金纽仙人鞭的适宜生长为5－30℃，春季开花。　在半遮荫或明亮的散射光照下发育会较良好。　土质可用粗沙或木屑混入壤土配置，生长适温5～30℃。　　春、夏季生长期间可充分给水，但用土需排水良好。　　可余生长期间每两周1次。', '　　　　金纽仙人鞭在半遮荫或明亮的散射光照下', 'http://img.boqiicdn.com/Data/BK/P/imagick96241455528894.jpg', 'http://www.boqii.com/entry/detail/2489.html', '');
INSERT INTO `plant_family` VALUES ('72', '红睡莲', 'Nymphaea alba var. rubra Lonnr.', '红睡莲', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2422/0,http://www.boqii.com/entry/photo/2422/4994', '　　', '被子植物门', '双子叶植物纲', '毛茛目', '睡莲科', '睡莲属', '白睡莲', 'Nymphaea alba var. rubra Lonnr.', '', '　　红 　　红睡莲是多年水生草本植物；根状茎匍匐；叶纸质，近圆形，直径10-25厘米，基部具深弯缺，裂片尖锐，近平行或开展，全缘或波状，叶缘有浅三角形齿牙，两面无毛，有小点；幼叶紫红色。老时上面转为墨绿色，有光泽，下面暗紫红色，叶柄长达50厘米。', '　　红)是)的变种，主要分布于中国、印度、等地区。由于红睡莲是水生草本，所以家庭养殖的会相对较少，小编就为你介绍一下红睡莲的栽培要点，的朋友可以一起了解。　　1、花盆：要尽量选择开口向外的，开口向外叶子的会比向内的叶子长的好，盆口越宽的花会越大朵（与盆底大小关系不大），花盆深浅，则影响开花间隔，越深间隔越久。　　2、土：尽量选择粘性较高的土，如：粘土、阳明山土。　　3、接着在盆底放少许长效肥或根肥（太多会烂根），花盆里放约1/4~1/3的土，压紧，之后将球茎芽点朝上埋入土中，球茎埋的深，开花间隔会较长但较大朵，埋的浅则间隔会较短较小朵。种好之后，移至光线充足处，将水加满，等待长叶开花（叶片太多可修剪一些）。　　4、若要将二颗以上球茎种一起时，与种其他花不同，要二颗球茎紧邻一起来种，因若分开种，因当较强势的一棵叶片遮到较弱势的一棵芽点时，较弱势那棵照不到光线，就会阵亡，另外，要种一起时，最好是同种或同色系，因深色系（如：紫色、蓝色），会比浅色系（白色、黄色）来得强势，切记！　　5、开花后，可将花剪下来插（子时莲例外），花的生命期约3~6天，第一天花会较直，之后越来越弯，直到弯至水中，若有剪花下来插，开花间隔会缩短，若任之谢掉则间隔较久。　　6、加肥：约每隔一个半月至二个半月，在离球茎旁约3~5公分处追加长效肥或根肥，但在9月底之后就不要再加了，因已渐进秋天，睡莲也将进入休眠期，加肥，反而会造成烂根。　　7、进入秋冬之后，睡莲也会随着气温的下降而进入休眠期，此时最好不要再去动它，只有在水少时将水加满，香水莲，叶片有斑点的品种休眠期会比无斑点的长，浅色系会比深色系长。', '　　红　　分株繁殖是红睡莲的主要繁殖方法，于每年春季3～4月份，芽刚刚萌动时将根茎掘起，用利刀分成几块。保证根茎上带有两个以上充实的芽眼，栽入池内或缸内的河泥中。　　红睡莲主要采取分株繁殖。耐寒种通常在早春发芽前3-4月进行分株，不耐寒种对气温和', 'http://img.boqiicdn.com/Data/BK/P/imagick92221452677674.jpg', 'http://www.boqii.com/entry/detail/2422.html', '');
INSERT INTO `plant_family` VALUES ('73', '福禄考', 'Phlox drummondii Hook.', '福禄考', '福禄花、福乐花、五色梅', '不容易死', '原产北美南部，现世界各国广为栽培', 'http://www.boqii.com/entry/photo/2128/0,http://www.boqii.com/entry/photo/2128/5399', '', '', '', '', '', '', '', '', '', '　　 　　福禄考的部叶对生，上部叶互生，宽卵形、长圆形和披针形，长2－7.5厘米，顶端锐尖，基部渐狭或半抱茎，全缘，叶面有柔毛；无叶柄。圆锥状聚伞花序顶生，有短柔毛，花梗很短；花萼筒状，萼裂片披针状钻形，长2－3毫米，外面有柔毛，结果时开展或外弯；花冠高脚碟状，直径1－2厘米，淡红、深红、紫、白、淡黄等色，裂片圆形，比花冠管稍短；雄蕊和花柱比花冠短很多。蒴果椭圆形，长约5毫米，下有宿存花萼。种子长圆形，长约2毫米，褐色。　　　　　　　　　　　　　　　　　　　　　　', '　　是比较常见的观花植物，又名天蓝绣球，也称为锥花福禄考，耐低温，在我国东北地区是可以露地越冬的。福禄考的园艺非常多，并且花色丰富，栽培难度也比较低，是基础花坛的主要栽培品种。　　露地栽培应选背风向阳而又排水良好的土地，结合整地施入厩肥或堆肥作基肥，化肥以磷酸二铵效果最好。5月初至5月中旬移植，株距40～45cm为宜，栽植深度比原深度略深1～2cm。期经常浇水，保持土面湿润。6～7月生长旺季，可追1～3次人粪或饼肥。在东北，有些品种应在根部盖草或覆土保护越冬。在11月中旬，应浇一次封冻水，开春浇一遍“返青水”。　　盆栽应在每年春季新芽萌发后换一次盆，换盆时要换土，园土3份，鹿粪3份，炉灰1份混合。盆底可施入少量的磷酸二铵作基肥，换盆后应浇透水。当新芽生长到6～7cm时，应根据盆的大小，选留部分健壮的芽，剪出多余的，一般口径20cm的盆可留4～5个芽。生长期间要及时追肥，可用腐熟的人粪尿、豆饼水、化肥溶液，2～3周追肥一次。注意浇水，保持土壤疏松、湿润，注意调节向光性，使植株健壮，挺直。　　宿根福禄考宜生长在阳光充足、气候凉爽的环境条件下。栽培过程中必须保持良好的株行距，防止拥挤而影响株形及产生病虫害。如生长过密，可利用分株繁殖法进行疏苗。宿根福禄考枝叶繁茂，浇水、施肥时应避免污染叶面，以防枝叶。对的要求不严，在整地时加施有机肥，每亩施入500～1000公斤。生长期可以适当施入少量氮肥及磷肥，长叶期以氮肥为主，开花期可喷施磷肥。发现杂草需人工清除，不要喷洒除草剂。', '　　福禄考是多年生宿根草本花卉，人工栽种难度不高，并且耐低温，在我国的东北地区可以露地越冬，非常适合栽种在疏松的沙质土壤中。由于福禄考的园艺品种比较多，并且花期非常长，所以深受人们的欢迎，小编就为你简单介绍一下福禄考的繁殖方法。　　福禄考常用的繁殪方法有分株繁殖、扦插繁殖、播种繁殖。分株繁殖操作简便，成活迅速，在早春或秋季进行，将母株周围分生的萌蘖株挖出栽植，尽量带完整根系，以提高成活率。扦插繁殖在花后进行，适用于大批量生产。取', 'http://img.boqiicdn.com/Data/BK/P/imagick36631445246907.jpg', 'http://www.boqii.com/entry/detail/2128.html', '');
INSERT INTO `plant_family` VALUES ('74', '眩美玉', 'Notocactus uebelmannianus', '眩美玉', '', '不容易死', '原产巴西中南部高原', 'http://www.boqii.com/entry/photo/2447/0,http://www.boqii.com/entry/photo/2447/4969', '', '', '', '', '', '', '', '', '', '　　 　　眩美玉植株单生，圆球形至椭圆形，球径6－8厘米，高10－12厘米，体色暗绿色。具13－15个圆疣状的浅棱。辐射状周刺8－10枚；无中刺；新刺黄褐色，老刺灰褐色。花：春夏', '　　为植株单生，一般为圆球形至椭圆形，春夏顶生紫红色钟状花，花期为6－7月。由于眩美玉的外形比较特别，并且栽培难度并不高，所以受到很多花友的喜爱。　　眩美玉为喜阳光充足的环境，但夏季高温高热时节宜适当遮阳，生长期需要较高的空气湿度。　　眩美玉喜温暖干燥与阳光充足环境，耐干旱和半阴，不耐水湿。生长适温18°C—24°C，不耐寒，冬季不低于5°C，短期可耐0°C低温。以肥沃、疏松、排水良好的砂质壤土为宜，可用腐叶土、土和粗砂的混合土。　　眩美玉的栽培容易，生长强健迅速。根系发达，盆栽每年春季换盆，修剪根系。生长期盆土保持湿润，适量施肥。冬季保持土壤干燥，可增强抗寒能力。　　为保持其株体干净美观，最好栽培在温室、玻璃橱内或用透明塑料薄膜袋罩住植株。适应富含腐殖质的透水性良好的砂壤土。冬季保持盆土稍干燥，可耐3°C低温。', '　　　\n　一、播种\n　　由于眩美玉为开花多，易结果，收集到的种子可当年播种，出苗率高，小苗生长不太慢，若将小苗早期嫁接催长，生长快捷，并可提早见花。　　4—5月进行，发芽适温20°C—24°C，播后1—2周发芽，幼苗生长较快，翌年径粗可达1cm以上。扦插：以春秋季进行为宜，将母株旁生子球切下，晾干伤口后插于沙床，经25—30天可生根。　\n　二、嫁接\n　　眩美玉为大都不易孳生仔球，通常采用嫁接苗球切顶促生仔球后，取下仔球嫁接繁殖。在5—6月进行，砧木可用', 'http://img.boqiicdn.com/Data/BK/P/imagick66291453713606.jpg', 'http://www.boqii.com/entry/detail/2447.html', '');
INSERT INTO `plant_family` VALUES ('75', '松霞', '', '松霞', '', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/2473/0,http://www.boqii.com/entry/photo/2473/4944', '', '', '', '', '科', '', '', '', '', '　　 　　松霞仙人球植株群生，椭圆形，单体球径约2厘米，体色暗绿色。具5－8个圆锥疣突的螺旋棱。白色刚毛状周刺30－40枚，黄褐色细针刺状中刺5－9枚。春季侧生淡黄色小型钟状花，花径1.5－2厘米，果实鲜红，经久不落，异常有趣。', '　　松霞是能开花结果的', '　　　　松霞的繁殖常用播种、扦插、分株和嫁接繁殖。播种，4－5月进行，种子', 'http://img.boqiicdn.com/Data/BK/P/imagick14471454318541.jpg', 'http://www.boqii.com/entry/detail/2473.html', '');
INSERT INTO `plant_family` VALUES ('76', '赤鬼城', 'Crassula fusca', '赤鬼城', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2380/0,http://www.boqii.com/entry/photo/2380/5036', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '青锁龙属', '', 'Crassula fusca', '', '　　 　　赤鬼城为亚灌木，不容易长高。植株叶片对生且紧密排列在枝干上，叶片长且窄。新叶绿色，老叶褐色或者暗褐色，', '　　为亚灌木，其叶片常而窄，耐干旱、能忍耐零下4度的室内低温。虽然赤鬼城耐半荫，但是也不能长期不给光照，不然容易导致赤鬼城徒长。　　　赤鬼城温暖干燥、阳光充足的环境，耐低温，能够忍耐零下4度的室内低温。此外赤鬼城稍耐半阴，阴久了叶片变绿叶片基部也容易徒长拉长，叶杆变的嫩弱。夏季高温炎热天气要适当遮阳，避免暴晒。　　　赤鬼城耐干旱，夏季因为温度高会短暂休眠但不很长。整个夏季是可以给大水的，基本是兜头淋。根系好，就不会有，花友需要注意的一个问题就是，夏季的赤鬼城避免兜头淋，不如容易烂哦。　　　赤鬼城对土壤的基本要求是肥沃又排水透气好的养殖土，一般可选用煤渣混合泥炭蛭石珍珠岩，差不多透气就可以，土表铺上颗粒的天然河沙。', '　　　　赤鬼城的繁殖可以在早春砍头扦插，剩下的茎上会群出蘖芽，也可以叶插，取', 'http://img.boqiicdn.com/Data/BK/P/imagick86511451554169.jpg', 'http://www.boqii.com/entry/detail/2380.html', '');
INSERT INTO `plant_family` VALUES ('77', '火焰木', 'Spathodea campanulata Beauv.', '火焰木', '火焰木、苞萼木', '不容易死', '香港，夏威夷、东南亚、厦门', 'http://www.boqii.com/entry/photo/2140/0,http://www.boqii.com/entry/photo/2140/5387', '　', '被子植物门', '双子叶植物纲', '管状花目', '紫葳科', '火焰树属', '火焰树', 'Spathodea campanulata Beauv.', 'Spathodea campanulata', '　　 　　火焰木为常绿乔木，株高10—20米，树干通直，灰白色，易分枝；叶为奇数羽状复叶，全缘，小叶具短柄， 卵状披针形或长椭圆形；圆锥或总状花序，顶生，花冠钟形，红色或橙红色，单花长约10厘米，花期4—8月。果为蒴果，长椭圆形状披针形，长约20厘米，种子具翅。羽状复叶对生，连叶柄长达45厘米；小叶13－17枚，叶片椭圆形或倒卵形，长5－10厘米，宽3－5厘米。', '　　', '　　火焰木原产于热带非洲，所以在其　　火焰木繁殖用扦插法、播种法或高压法。扦插和播种法均宜在春季进行，种子发芽后，一般在5－6午后即可开花。火焰木需较高　　起苗应在土壤湿润的状态下进行，起苗前3小时充分洒水，使湿润的土附在根群上，避免根群', 'http://img.boqiicdn.com/Data/BK/P/imagick65541445507653.jpg', 'http://www.boqii.com/entry/detail/2140.html', '');
INSERT INTO `plant_family` VALUES ('78', '罂粟花', 'Cultivated Opium Poppy', '', '鸦片、大烟、米壳花、罂子粟、御米、象谷、米囊、囊子、阿芙蓉', '不容易死', '', 'http://www.boqii.com/entry/photo/1990/0,http://www.boqii.com/entry/photo/1990/5537', '　　', '被子植物门', '双子叶植物纲', '罂粟目', '罂粟科', '罂粟属', '罂粟', 'Papaver somniferum L', '', '　　 　　罂粟花单生；花梗长达25厘米，无毛或稀散生刚毛。花蕾卵圆状长圆形或宽卵形，长1.5－3.5厘米，宽1－3厘米，无毛；萼片2，宽卵形，绿色，边缘膜质；花瓣4，近圆形或近扇形，长4－7厘米，宽3－11厘米，边缘浅波状或各式分裂，白色、粉红色、红色、紫色或杂色；雄蕊多数，花丝线形，长1－1.5厘米，白色，花药长圆形，长3－6毫米，淡黄色；子房球形，直径1－2厘米，绿色，无毛，柱头（5－）8－12（－18），辐射状，连合成扁平的盘状体，盘边缘深裂，裂片具细圆齿。', '　　在我国，是明令禁止种植的，根据我国《刑法》规定，种植罂粟满500株以上的可以追究刑事责任，不满500株的拘留或罚款，所以小编不建议私人种植罂粟花，并且罂粟花的栽培难度也比较高。　　罂粟花种植对环境有特殊要求：雨水少但土地要湿润，日照长但不干燥，土壤养分充足而酸性小，海拔高度在900米～1300米为好。在缅甸、泰国和老挝三国交界地区的“金三角”正好满足上述条件，这里是太平洋气流和印度洋气流的接合部，群山连绵，丛林密布，气候温润，是世界上最适宜罂粟生长的地区之一。　　罂粟花种植光照充足和通风良好的地方；耐寒，不耐湿、热，不宜在过肥的土壤上栽植，不宜重茬种植。不宜在低洼、潮湿，水肥大，光线差的地方育苗和栽植；否者生长不良，还易出病害。　　罂粟花种植对土壤要求不严，但以疏松肥沃沙壤土最好，行距20厘米，播后用地膜覆盖，或于早春地表刚解冻时播种，出苗后逐步揭去地膜。当幼苗有5～6片叶子时，进行间苗，株行距一般为30cm×30cm。不耐移植，因此最好园地直播。幼苗生长期，浇水不能过多，但需保持湿润。花前追施2～3次稀薄液肥，但施肥不可过多，否则易发虫害。发现病株，要及时进行治，并注意田间卫生。', '　　由于　　罂粟花主要通过播种繁殖。春、秋季均可播种，一般情况下，春播在3～4月，花期6～7月；秋播在9～11月，花期为次年的5～6月。若为了收集种子，最好采取秋播的方式。土壤整理要细，做畦浇透水，然后撒播或条播。由于种子', 'http://img.boqiicdn.com/Data/BK/P/imagick45201441014523.jpg', 'http://www.boqii.com/entry/detail/1990.html', '');
INSERT INTO `plant_family` VALUES ('79', '大白杜鹃', 'Rhododendron decorum', '大白杜鹃', '大白花杜鹃', '不容易死', '', 'http://www.boqii.com/entry/photo/2433/0,http://www.boqii.com/entry/photo/2433/4982', '植物　　', '被子植物门', '双子叶植物纲', '()目', '杜鹃花科', '杜鹃属', '', 'Rhododendron decorum Franch.', 'Rhododendron decorum', '　　 　　大白杜鹃是常绿灌木或小乔木，高1－3米，稀达6－7米；树皮灰褐色或灰白色；幼枝绿色，无毛，老枝褐色。冬芽顶生，卵圆形，长9－10毫米，无毛。叶厚革质，长圆形、长圆状卵形至长圆状倒卵形，长5－14.5厘米，宽3－5.7厘米，先端钝或圆，基部楔形或钝，稀近于圆形，无毛，边缘反卷，上面暗绿色，下面白绿色，中脉在上面稍凹下，黄绿色，下面凸出，侧脉约18对，在上面微凹入，下面稍凸起；叶柄圆柱形，长1.7－2.3厘米，黄绿色，无毛。', '　　', '　　　\n　1、扦插繁殖：\n　　\n2、嫩枝繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick10521452851080.jpg', 'http://www.boqii.com/entry/detail/2433.html', '');
INSERT INTO `plant_family` VALUES ('80', '紫叶小檗', 'Berberis thunbergii var.atropurpurea Chenault', '紫叶小檗', '红叶小檗', '不容易死', '原产中国华东、华北及秦岭以北。', 'http://www.boqii.com/entry/photo/2090/0,http://www.boqii.com/entry/photo/2090/5437', '植物　', '被子植物门', '双子叶植物纲', '毛茛目', '小檗科', '小檗属', '日本小檗', 'Berberis thunbergii var.atropurpurea Chenault', '', '　　 　　紫叶小檗是日本小檗的自然变种。落叶灌木。幼枝淡红带绿色，无毛，老枝暗红色具条棱；节间长1－1.5厘米。叶菱状卵形，长5－20（35）毫米，宽3－15毫米，先端钝，基部下延成短柄，全缘，表面黄绿色，背面带灰白色，具细乳突，两面均无毛。花2－5朵成具短总梗并近簇生的伞形花序，或无总梗而呈簇生状，花梗长5－15毫米，花被黄色；小苞片带红色，长约2毫米，急尖；外轮萼片卵形，长4－5毫米，宽约2。5毫米，先端近钝，内轮萼片稍大于外轮萼片；花瓣长圆状倒卵形，长5.5－6毫米，宽约3.5毫米，先端微缺，基部以上腺体靠近；雄蕊长3－3.5毫米，花药先端截形。浆果红色，椭圆', '　　紫叶小檗是园林绿化中非常重要的色叶灌木，常和)、大叶黄杨组成色块、色带，用来花坛。此外，紫叶小檗也是制作盆景的好材料，人工栽种子夜小檗需要为其布置一个合适的栽培环境。　　紫叶小檗小苗喜半阴，尤其播种繁殖小苗常采取遮阴措施。雨季注意排水，以免积水造成根系缺氧，发生腐烂。　　紫叶小檗是观花、观叶的，在8月中旬开始摘除老叶，摘叶前后各施1次氮肥；结合修剪整出造型，提高盆栽、地栽观赏价值，盆栽冬季可以移到室内观赏至12月中旬；紫叶小檗怕涝，浇水时应见干见湿，在4～10月的季节应保持土壤湿润，在落叶后，也就是11月～翌年3月土壤不易太湿，大面积育苗时应在施足沤制基肥的情况下，在生长季节可以勤施液肥，花果期应喷施钾肥，还可以在灌水时加入少量的杀虫剂、杀菌剂以及化学，既可以除虫防病，还可以为植株提供养分。', '　　紫叶小檗又名红叶小檗，在初春，紫叶小檗会呈嫩红色，盛夏则变为深紫红色，入秋后又回呈血红色，但是当光照不充足时，紫叶小檗部分会褪成绿色。常用播种、扦插、分株及压条的方法进行繁殖。　　\n1、播种\n　　紫叶小檗在北方易结实，故常用播种法繁殖。秋季种子采收后，洗尽果肉，阴干，然后选地势高燥处挖坑，将种子与沙按1：3的比例放于坑内贮藏，第二年春季进行播种，这样经过沙藏的种子出苗率高，播种易成功，也可采收后进行秋播。　\n　2、扦插\n　　可用硬枝插和嫩枝插两种方法。六七月取半木质化枝条，剪成10至12厘米长，上端留叶片，插于砂或碎石中，保持湿度在90％左右，　　\n3、分株\n　　紫叶小檗萌芽力强，　　\n4、压条繁殖\n　　压条繁殖是在5月份把紫叶小檗木质化枝条每15cm处环剥一下，宽度在0.50～1cm，然后用萘乙酸溶液涂在环剥处，再把该枝条埋入土中。同时枝条的上部（没木质化的梢），以保证整棵紫叶小檗进行光合作用。还要保证土壤湿润，2个月左右就会发现长出小根，然后进行母体分离，按正常的株行距进行培育苗子。', 'http://img.boqiicdn.com/Data/BK/P/imagick38071443604128.jpg', 'http://www.boqii.com/entry/detail/2090.html', '');
INSERT INTO `plant_family` VALUES ('81', '番红花', 'Hibiscus rosa－sinensis  cv. ', '番红花', '', '不容易死', '', 'http://www.boqii.com/entry/photo/1980/0,http://www.boqii.com/entry/photo/1980/5547', '', '被子植物门', '双子叶植物纲', '锦葵目', '锦葵科', '木槿属', '朱槿', 'Hibiscus rosa－sinensis  cv. \'Saffron\'', '', '　　 　　番红花株高约1－3米；小枝圆柱形，疏被星状柔毛。叶阔卵形或狭卵形，长4－9厘米，宽2 5厘米，先端渐尖，基部圆形或楔形，边缘具粗齿或缺刻，两面除背面沿脉上有少许疏毛外均无毛；叶柄长5－20毫米，上面被长柔毛；托叶线形，长5－12毫米，被毛。', '　　为阳性，所以在栽培过程中最好放在阳光充足的地方，但是番红花不耐旱，所以人工栽培番红花应注意养护环境。番红花为常绿灌木，在养护过程中需要注意定期修剪，以保证其生长。　　番红花盆栽用土宜选用疏松、肥沃的沙质壤土，每年早春4月移出室外前，应进行换盆。换盆时要做3件事：一是换上新的培养土；二是剪去部分过密的卷曲的须根；三是施足基肥，盆底略加磷肥。为了保持树型优美，着花量多，根据扶桑发枝萌蘖能力强的特性，可于早春出房前后进行修剪整形，各枝除基部留2－3芽外，上部全部剪截，剪修可促使发新枝，长势将更旺盛，株形也亦美观。修剪后，因地上部分消耗减少，要适当节制水肥。　　番红花于种植后20～30天开始出苗，出苗前可再灌水一次，出苗后3～4天即开花，花期较短。11月中、下旬，在北方地区须搭防寒风障，入冬前灌一次冻水。冬季在畦面上均匀地施农家肥4000千克，既起到增加肥力，又起到保暖防冻作用。2月中旬返青后，公顷施饼肥1500千克，自3月起西红花进入生长旺盛阶段，每10天喷1次0.2％磷酸二氢钾，连续2～3次。在1月份气温最低时，可在畦面上加一层覆盖，2月下旬，除去覆盖物。3～4月，为番红花生长最旺盛时期，此时应注意经常松土除草，防止土壤板结和杂草丛生，以利球茎的膨大。4月中旬，再灌水一次，5月采挖球茎，休眠。', '　　番红花为朱槿的园艺　\n　一、分球繁殖\n　　用球茎繁殖，5月上中旬于番红花地上部分尚未完全回苗时，挖取球茎，按大小分开，放通风干燥处贮存。9月上中旬栽种。栽前用苯来特稀释液浸泡球茎，同时用安百亩处理土壤，对消灭土壤中线虫，防止病虫害蔓延效果较好。早下种球茎先发根后发芽，早出苗，有利于植株　\n　二、播种繁殖\n　　由于番红花不易结籽，需通过人工授粉后才能得到种子。待种子成熟后，随收随播种于露地苗床或盆内。种子播种密度不能过大，以稀些为好，因为植株需长球，一般2年内不能起挖，从种子播种到植株开花，往往要经3～4年的时间。', 'http://img.boqiicdn.com/Data/BK/P/imagick18831440495428.jpg', 'http://www.boqii.com/entry/detail/1980.html', '');
INSERT INTO `plant_family` VALUES ('82', '宝绿', 'Glottiphyllum linguiforme', '宝绿', '牛舌叶、佛手掌、牛舌花、舌叶花、舌叶菊', '不容易死', '原产南非冬季温暖，世界各国多有栽培。', 'http://www.boqii.com/entry/photo/2449/0,http://www.boqii.com/entry/photo/2449/4967', '　　', '被子植物门', '木兰纲', '石竹目', '番杏科', '舌叶花属', '', 'Glottiphyllum linguiforme', '', '　　 　　宝绿的肉质叶很象舌头，叶长约6厘米，呈舌状稍卷曲，叶色鲜绿，叶面光洁透明，叶片紧抱轮生于短茎上，而整个形态有点象佛手而由此得名。对生2裂，长约7cm，宽2－3，鲜绿色，平滑有光泽。叶端略向外反转，株形像佛手。秋冬季开花，花自叶丛中抽出，花冠金黄色。', '　　的栽培难度并不高，原产于非洲南部，喜欢光照充足、温暖湿润的环境，宝绿的叶片很像舌头，所以又有舌叶花的别称。那么，如何才能养出健康的宝绿呢？　　宝绿喜冬季温暖，夏季凉爽干燥环境，植株且呈半休眠状态。须保持在10℃以上。宜于肥沃、排水良好的沙壤土生长。回到顶部　　每年春季换盆，去除干枯叶片。生长期每半月施肥1次，夏季高温时，浇水需谨慎，盆土宜略干燥。如高温多湿，茎叶易腐烂。此时，需遮阴和通风，以凉爽、半阴为好，达到安全越夏。秋季生长最旺盛，浇水应多些，入冬后气温下降，生长减慢，浇水相应减少。早春开花期，浇水可酌量增加。一般栽培3－4年植株需更新。　　宝绿的家庭养护应特别重视越冬和过夏期间的。当环境气温超过32℃，植株将进入半休眠状态，此时应将盆栽植株搬放至阴凉处，停肥控水，保持盆土略呈干燥，注意环境通风透气，待秋凉后再恢复正常的水肥供应。冬季应保持棚室温度不低于10℃，维持盆土始终处于湿润状态，改浇水为喷水，停止施肥，确保其能安全过冬。家庭繁殖通常于9月至10月间进行扦插，扦插基质可用干净的湿沙，待切口收干后再将其插入沙床中，维持20℃左右的生根适温，一个月后即可生根，待其新根长至2厘米至3厘米长时，再行移栽上盆。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick88631453714474.jpg', 'http://www.boqii.com/entry/detail/2449.html', '');
INSERT INTO `plant_family` VALUES ('83', '迷迭香', 'Rosmarinus officinalis', '迷迭香', '海洋之露，艾菊', '不容易死', '欧洲中部、北非地中海沿岸', 'http://www.boqii.com/entry/photo/2328/0,http://www.boqii.com/entry/photo/2328/5091', '', '', '', '', '', '', '', '', '', '　　 　　迷迭香为灌木，高达2米。茎及老枝圆柱形，皮层暗灰色，不规则的纵裂，块状剥落，幼枝四棱形，密被白色星状细绒毛。叶常常在枝上丛生，具极短的柄或无柄，叶片线形，长1－2.5厘米，宽1－2毫米，先端钝，基部渐狭，全缘，向背面卷曲，革质，上面稍具光泽，近无毛，下面密被白色的星状绒毛。　　　　　　　　　　　　　　　　　　　　　　', '　　为多年生常绿亚灌木，其缓慢，但再生能力较强。迷迭香较能耐旱，人工栽培迷迭香时不必浇水过多。现在越来越多的花友会在家中种上一盆迷迭香，不但可以用于观赏，其香味还能够保持家中的空气清新，有一定的驱虫效果。　　定植过后迷迭香最重要的就是，这时应该及时浇水，并进行中耕锄草，以免杂草丛生影响迷迭香生长。为了刺激迷迭香多分枝，增加产量，在栽培的过程中应该适当进行摘心。迷迭香生长比较缓慢，所以并不是很耗，栽培期间每3个月施一次复合肥即可。　　种植迷迭香应注意时常通风、保持凉爽，光照要能充足，水肥适量，需避免高温多湿气候及环境，病虫害最容易发于不通风，且阳光照不到的隐匿地点。平时应注意修剪，剪掉过多和老化的枯枝叶，并随时捡掉盆土表面的枯枝叶，以免招来病虫害，影响迷迭香生长。', '　　　　迷迭香常用种子繁殖、扦插繁殖和压条繁殖等繁殖方法。种子繁殖一般于早春温室内进行育苗，可用纸巾催芽法，土法或穴盘育苗均可。扦插繁殖多在冬季至早春进行，选取新鲜', 'http://img.boqiicdn.com/Data/BK/P/imagick66841450257683.jpg', 'http://www.boqii.com/entry/detail/2328.html', '');
INSERT INTO `plant_family` VALUES ('84', '红花银桦', 'Grevillea banksii var forsteri', '红花银桦', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2377/0,http://www.boqii.com/entry/photo/2377/5039', '植物　　', '被子植物门', '双子叶植物纲', '山龙眼目', '山龙眼科', '银桦属', '红花银桦', 'Grevillea banksii var forsteri', '', '　　 　　红花银桦为常绿小乔木，树高可达5米，幼枝有毛。叶互生，一回羽状裂叶，小叶线形，叶背密生白色毛茸。春至夏季开花，总状花序，顶生，花色橙红至鲜红色。蓇葖果歪卵形，扁平，熟果呈褐色。花、叶均美观。', '　　的花期较长，盛花期为11月至第二年5月，在原产地，红花银桦的花期可长达250多天。红花银桦主要在花境、中应用，其适应性强，迅速且萌芽力强，栽培难度并不高。　　红花银桦又名贝克斯银桦，原产于澳大利亚昆士兰海滨及附近海岛，现西双版纳地区有引种栽培；它是一种集观花、叶、形于一身的密集灌木，株形多变，分枝纤细，树冠飘逸；盛花时满树繁花，红艳一片，格外耀眼。　　红花银桦可耐干旱贫瘠的土壤，适宜排水性良好、略酸性土壤，适宜在春季进行移植。为提高红花银桦开花量，应需每年修剪一次。在花境中，红花银桦可作为上层树种做背景种植，或配置其它灌木及地被道路作为隔离带树种；在公园绿地及庭园中，可作为观赏树孤植或群植。', '　　　　红花银桦做为室内小盆栽时，可先将种子播于育苗盆中，等发芽后再将', 'http://img.boqiicdn.com/Data/BK/P/imagick88891451468250.jpg', 'http://www.boqii.com/entry/detail/2377.html', '');
INSERT INTO `plant_family` VALUES ('85', '七叶树', 'Aesculus chinensis', '七叶树', '梭椤树、梭椤子、天师栗、开心果、猴板栗', '不容易死', '中国大陆的河北、河南、山西、陕西等地', 'http://www.boqii.com/entry/photo/2061/0,http://www.boqii.com/entry/photo/2061/5466', '植物　', '被子植物门', '双子叶植物纲', '无患子目', '七叶树科', '七叶树属', '七叶树', 'Aesculus chinensis', '', '　　 　　七叶树为', '　　七叶树是世界着名的观赏树种之一，其树干通直，姿态雄伟，非常适合作为行道树和庭荫树。成株的七叶树可高达25米，喜光、耐寒，但是萌芽力不强，', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick25131442915530.jpg', 'http://www.boqii.com/entry/detail/2061.html', '');
INSERT INTO `plant_family` VALUES ('86', '月兔耳', 'Kalanchoe tomentosa', '月兔耳', '', '不容易死', '原产中美洲干燥地区及马达加斯加', 'http://www.boqii.com/entry/photo/2186/0,http://www.boqii.com/entry/photo/2186/5342', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '伽蓝菜属', '月兔耳', 'Kalanchoe tomentosa', '', '　　 　　月兔耳的叶片奇特，形似兔耳，植株密被绒毛，叶片边缘着生褐色斑纹，植株为直立的肉质灌木，容易长高，中型品种。植株叶片对生，长梭型，整个叶片及茎干密布凌乱绒毛，新叶金黄色，老叶片颜色微微黄褐色，叶尖圆型，植株的叶片非常可爱，月兔耳和黑兔耳的区别是月兔耳的叶片边缘不容易发黑，黑兔耳的叶片边缘容易发黑。初夏开花，聚伞花序，花序较高，小花管状向上，花开白粉色，花瓣4片，花期较长。', '　　月兔耳的外形很容易让人联想到', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick30031446714856.jpg', 'http://www.boqii.com/entry/detail/2186.html', '');
INSERT INTO `plant_family` VALUES ('87', '大花萱草', 'Hemerocallis middendorffii', '大花萱草', '大苞萱草', '不容易死', '产黑龙江、吉林和辽宁。生于海拔较低的林下、湿地、草地上', 'http://www.boqii.com/entry/photo/2398/0,http://www.boqii.com/entry/photo/2398/5017', '', '', '', '', '', '', '', '', '', '　　大花萱草为百合科、萱草属多年生草本 　　大花萱草的叶翠绿狭长，基生呈带状排成两列。花苔从中部抽出，螺旋状聚伞花序，每个花絮可着花数十朵。花蕾似簪，开如漏斗，裂片翻卷，为百合形花冠，花瓣先端裂开。花被基部合生呈筒状，雄蕊6枚，3长3短，花药呈丁字形背着在花丝顶端，除蓝色和纯白色以外其余花色均有栽培品种。花径变化大，花形各异，花期从晚春一直到秋季。大多数品种的花只开一天，但盛花期可以延续几周甚至几个月，有些品种单花', '　　又名金针花、忘忧草，其单花寿命不超过24小时，一般在清晨开放，暮色时分闭合，到了晚上就会萎蔫。大花萱草的大部分品种都不结实，并且栽培难度并不高。　　大花萱草原产中国、南欧及日本。我国南北均可种植，根状茎可在～20℃低温冻土中，华北地区可露地越冬。性喜气候温暖，喜阳光，耐半阴，抗旱，抗病虫能力强，适应性广，土壤要求疏松肥沃湿润。特别对碱土壤有特别的耐性。　　大花萱草栽培要求种植在排水良好，夏季不积水，富含有机质的土壤上，栽植株行距保持在30cm×40cm。大花萱草栽培简单，由于花期长，除种植时施足基肥（以腐熟的牛粪或猪粪为宜）外，花前及花期需追肥2～3次，以补充磷钾肥为主，也可喷施0.2%的磷酸二氢钾，促使花朵肥大，并可达到延长花期的效果，花后，自地面剪除花茎，并及时清除株丛基部的枯残叶片。', '　　　\n　一、播种法：\n　　播种是快速大量生产种苗的方法，但因种子发芽率低，需先浸种发芽，播后一年才可定植。每年9月左右进入采种期，要求植株生长健壮，果实饱满，无病虫害。次年春季播种。　　苗床要先施足底肥，床宽1.3至1.7米，长30米左右，两侧挖排水沟。播种时每隔20厘米开深约3厘米的浅沟，把种子均匀的播入沟内，盖一层细土，再薄铺一层细沙。出苗前要浇水和除草，保持好土壤湿度，秋季即可起苗栽植。每亩苗床用种子2.5公斤，可育苗5至6万株。　　也可将种子浸种催芽后露地播种育苗，每亩播种量为5至7公斤，采用平地条播。按行距30厘米开沟，深约3厘米左右，每隔3至5厘米播一粒种子，等植株长出2至3片叶后，施稀薄人粪尿一次。　\n　二、分芽法：\n　　分芽指大花萱草花茎上小的植株。花芽可以从花茎上切割下来，若体积较大，在种植前可以进一步分割。移植后的花芽在一周后即可生根。可以利用生根的花芽繁殖植株，提高栽植的数量，最终提高经济效益。　　\n三、组培法：\n　　组培用幼嫩叶片、花丝和花苔等器官培养成植株。方法是先诱导幼嫩器官产生愈伤组织，然后用适当培养基在适宜的温湿光气等条件下培养成幼小植株。再将小苗假植于营养钵，经一段时间培养成植株幼苗，之后定植。但这种方法还没有被广泛接受。　\n　四、分株法：\n　　分割萱草丛块是最常用的繁殖方法。该方法操作简单，植株容易存活，长势比较一致。分株可将母株丛全部挖出，重新分栽;或者是由母株丛一侧挖出一部分植株做种苗，留下的继续生长。　　分株多在春季萌芽前或秋季落叶后进行。春季分株移栽，当年即可抽苔开花;秋季分株移栽，翌年才能抽苔开花。移栽时应选用生长旺盛、花蕾多、品质好、无病虫害的植株。　　分株时挖取株丛的一部分分蘖作为种苗，挖取部分要带根，从短缩茎处割开，将老根、朽根和病根剪除，尽量保留肉质根，适当剪短约留10厘米)后即可栽植。栽植应选在晴天进行，边挖苗，边分苗，边栽苗，尽量少伤根，这样缓苗快。一般2至3年分株一次，以保证植株旺盛的生长势。', 'http://img.boqiicdn.com/Data/BK/P/imagick39641452072217.jpg', 'http://www.boqii.com/entry/detail/2398.html', '');
INSERT INTO `plant_family` VALUES ('88', '九里香', 'Murraya exotica L.', '九里香', '石辣椒、九秋香、九树香、七里香、千里香、万里香、过山香等', '不容易死', '中国云南、贵州、湖南、广东、广西、福建、台湾 海南等地。', 'http://www.boqii.com/entry/photo/2040/0,http://www.boqii.com/entry/photo/2040/5487', '', '', '', '', '', '', '', '', '', '　　　　九里香为小乔木，高可达8米。枝白灰或淡黄灰色，但当年生枝绿色。叶有小叶3—5—7片，小叶倒卵形或倒卵状椭圆形，两侧常不对称，长1—6厘米，宽0.5—3厘米，顶端圆或钝，有时微凹，基部短尖，一侧略偏斜，边全缘，平展；小叶柄甚短。　　　　　　　　　　　　　　　　　　　　　　　', '　　九里香是一种热带常绿，在开花的时候香味浓郁，现在常被制作成花卉来进行栽培。有的花友对于九里香可能并不熟悉，小编就为你介绍一下九里香的栽培要点，有兴趣的朋友可以一起了解。　　1、土壤：种植九里香的时候如果是当和观赏植物就是种在一个盆子里，这个盆子要有排水孔，可以用砂，粘土或酸性土壤都可以，但是土质一琮要有排水功能，这样才不会烂根。　　2、温度：喜温暖的环境，最低温度5摄氏度。　　3、光线：喜充足的阳光，不过的时候要进行遮荫。　　4、水分：九里香的水分蒸发得很快，所以说要多淋些水，同时要保持土质的湿润，九里香是一种耐旱的植物，但是要在条件好的情况下下才能得好，花才开得好。　　5、空气湿度：喜湿润的空气，可经常向植株周围喷水。　　6、换盆：小苗时期每年春季换盆1次，稍长大后，根据需要2－3年换盆1次。　　7、修剪：果期一过，要对九里香进行修剪，来年才会长出花，才会再结果。', '　　　　播种繁殖可在春季进行，温度适宜在15～25°C，播种后要保持基质湿度，25～35天发芽。出苗后可逐渐接受阳光照射。苗期', 'http://img.boqiicdn.com/Data/BK/P/imagick7411442309508.jpg', 'http://www.boqii.com/entry/detail/2040.html', '');
INSERT INTO `plant_family` VALUES ('89', '鱼尾葵', 'Caryota ochlandra Hance', '鱼尾葵', '假桄榔、青棕、钝叶、董棕、假桃榔', '不容易死', '原产亚洲热带、亚热带及大洋洲。中国南部、西南部', 'http://www.boqii.com/entry/photo/2152/0,http://www.boqii.com/entry/photo/2152/5375', '', '', '', '', '', '', '', '', '', '　　 　　鱼尾葵为乔木状，高10－15（－20）米，直径15－35厘米，茎绿色，被白色的毡状绒毛，具环状叶痕。叶长3－4米，幼叶近革质，老叶厚革质；羽片长15－60厘米，宽3－10厘米，互生，罕见顶部的近对生，最上部的1羽片大，楔形，先端2－3裂，侧边的羽片小，菱形，外缘笔直，内缘上半部或1／4以上弧曲成不规则的齿缺，且延伸成短尖或尾尖。佛焰苞与花序无糠秕状的鳞秕；花序长3－3.5（－5）米，具多数穗状的分枝花序，长1.5－2.5米；雄花花萼与花瓣不被脱落性的毡状绒毛，萼片宽圆形，长约5毫米，宽6毫米，盖萼片小于被盖的侧萼片，表面具疣状凸起，边缘不具半圆齿，无毛，花瓣椭圆形，长约2厘米，宽8毫米，黄色，雄蕊（31－）50－111枚，花药线形，长约9毫米，黄色，花丝近白色；雌花花萼长约3毫米，宽5毫米，顶端全缘，花瓣长约5毫米；退化雄蕊3枚，钻状，为花冠长的1／3倍；子房近卵状三棱形，柱头2裂。果实球形，成熟时红色，直径1.5－2厘米。种子1颗，罕为2颗，胚乳嚼烂状。花期5－7月，果期8－11月。　　　　　　　　　　　　　　　　　　　　　', '　　尾葵的树形优美，叶片翠绿，由于其叶片形似鱼尾，故此得名。鱼尾葵现在被用作大型盆栽树种，非常适合在客厅、会场、餐厅等处放置，其羽叶剪下做的配叶也非常好看。　　1、喜疏松、肥沃、富含腐殖质的中性土壤，不耐盐碱，也不耐强酸，不耐干旱瘠薄，也不耐水涝。　　2、喜温暖，不耐寒，适温为25—30℃，越冬温度要在10℃以上。　　3、耐荫性强，忌阳光直射，叶面会变成黑褐色，并逐渐枯黄；夏季荫棚下养护，生长良好。　　4、喜湿，在干旱的环境中叶面粗糙，并失去光泽，生长期每2天浇水一次，夏季应每天浇水，并向叶面喷水。　　5、盆栽或换盆时，另加少量腐熟饼肥作基肥，生长期每15天施追肥一次，立秋后停止施肥；鱼尾葵生长较快，根系发达，应每年早春换盆一次，换盆时切除部分老根，剪除植株基部的枯黄老叶，更换一些新的土，有利生长。　　6、病虫害：夏季多雨湿热季节，易染霜霉病，可喷1000倍的甲基托布津防治，发现介壳虫可用氧化乐果喷杀。', '　　　　鱼尾葵可用播种和分株繁殖，一般于春季将种子播于透水通气的砂质壤土为基质的浅盆上，覆盖5厘米左右基质，置于遮阴度30％左右及　　多年生的植株分蘖较多，当植株生长茂密时可分切种植，将根基部萌生的蘖芽切下单独栽植，如孽芽无根，可将其插入砂中，保持一定湿度，温度保持25℃左右，一个月后可生根。但分切的植株往往生长较慢，并且不宜产生多数的蘖芽，所以一般少用此法繁殖。', 'http://img.boqiicdn.com/Data/BK/P/imagick76571445937475.jpg', 'http://www.boqii.com/entry/detail/2152.html', '');
INSERT INTO `plant_family` VALUES ('90', '木槿', 'Chinese rose', '木槿', '木棉、荆条、朝开暮落花、喇叭花', '不容易死', '', 'http://www.boqii.com/entry/photo/2015/0,http://www.boqii.com/entry/photo/2015/5512', '', '', '', '', '', '', '', '', '', '　　木槿为落叶灌木，为木槿属下所有物种的统称，是一种在 木槿 　　木槿高3－4米，小枝密被黄色星状绒毛。叶菱形至三角状卵形，长3－10厘米，宽2－4厘米，具深浅不同的3裂或不裂，有明显三主脉，先端钝，基部楔形，边缘具不整齐齿缺，下面沿叶脉微被毛或近无毛；叶柄长5－25毫米，上面被星状柔毛；托叶线形，长约6毫米，疏被柔毛。　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　木槿是我国的传统名花，也是现在韩国和马来西亚的国花。由于木槿的栽培难度不高，并且孤植、丛植均可，所以非常适合做园林花式绿篱。小编就为你介绍一下木槿的栽培方法与栽培要点。　　木槿适应性强，南北各地都有栽培。喜阳光也能耐半阴。耐寒，在华北和西北大部分地区都能露地越冬，对土壤要求不严，较耐瘠薄，能在粘重或碱性土壤中生长，惟忌干旱，生长期需适时适量浇水，经常保持土壤湿润。　　木槿在绿地、定植宜深栽施入基肥，栽后不需要特殊管理，但要经常保持土壤湿润。干旱幼枝易枯，叶片常早期脱落，花期缩短，在中应随时疏剪残老枯枝，新枝，保持植株清新健壮。　　木槿枝条柔韧，可盆栽造型，编成图案花饰，如透空花窗，相当别致。木槿对烟尘和有毒气体的抵抗力很强，可大量栽植，是优良的环保。', '　　　\n　一、播种繁殖\n　　一般在春季4月进行。果实10月成熟后，11～12月采种最适宜，采收后剥出种子低温干藏，到翌春4月条播或撒播。分株繁殖在秋天落叶后或早春发芽之前，挖取植株根际的萌株，另行栽植。栽前可适当修剪根部，并对地上部实行重短截。木槿适应性强，栽培简单，管理粗放，一般可任其自由　　\n二、扦插育苗\n　　木槿扦插成活率高，扦插材料的取得也较容易，因而常以扦插法繁殖。扦插育苗宜在早春枝叶萌发前进行，选无病虫害的健壮植株为母株，在母树萌发前选取1～2年生、径粗1厘米以上的中、上部枝条为繁殖材料，将枝条剪成15～20厘米长的枝段，清水浸泡4～6小时后进行扦插。插前整好苗床，按畦带沟宽130厘米、高25厘米作畦，每平方米施入厩肥6公斤、火烧土1。5公斤、钙镁磷75克作为基肥。扦插要求沟深15厘米，沟距20～30厘米，株距8～10厘米，插穗上端露出土面3～5厘米或入土深度为插条的2／3，插后培土压实，及时浇水。扦插苗一般1个月左右生根出芽，采用塑料大棚等保温增温设施，也可在秋季落叶后进行扦插育苗，将剪好的插穗用100～200毫克／升的NAA溶液浸泡18～24小时，及时浇水，覆盖农膜，保持　　由于木槿扦插极易生根，栽培数量较少时，可进行直插栽培，直接将插穗按栽培密度栽入定植穴中，不需移栽定植；也可用长枝条直插栽培，要深入土深度在20厘米以上，以防倒伏和由于根系过浅而受旱害。', 'http://img.boqiicdn.com/Data/BK/P/imagick61941441705666.jpg', 'http://www.boqii.com/entry/detail/2015.html', '');
INSERT INTO `plant_family` VALUES ('91', '蓝松', 'Senecioserpens', '蓝松', '', '未知', '南非海角', 'http://www.boqii.com/entry/photo/2488/0,http://www.boqii.com/entry/photo/2488/4928', '　　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '千里光属', '', 'Senecioserpens', '', '　　 ', '　　', '　　　　蓝松的繁殖方式以扦插为主，也可以叶插，几乎不用太多', 'http://img.boqiicdn.com/Data/BK/P/imagick3311455443338.jpg', 'http://www.boqii.com/entry/detail/2488.html', '');
INSERT INTO `plant_family` VALUES ('92', '黄水仙', 'Narcissus pseudonarcissus L.', '黄水仙', '洋水仙、喇叭水仙', '不容易死', '', 'http://www.boqii.com/entry/photo/2378/0,http://www.boqii.com/entry/photo/2378/5038', '　　', '被子植物门', '单子叶植物纲', '百合目', '石蒜科', '水仙属', '', 'Narcissus pseudonarcissus L.', '', '　　 　　黄水仙为多年生草本。有皮鳞茎卵圆形。直径2.5－3.5厘米。叶4－6枚，直立向上，宽线形，长25－40厘米，宽8－15毫米，钝头。花茎高约30厘米，顶端生花1朵；佛焰苞状总苞长3.5－5厘米；花梗长12－18毫米；花被管倒圆锥形，长1.2－1.5厘米，花被裂片长圆形，长2.5－3.5厘米，淡黄色；副花冠稍短于花被或近等长。花期春季。', '　　为多年生草本，对光照的反应不敏感，除叶片期需要充足的阳光以外，开花期以半荫的环境为好。人工栽培黄水仙的难度并不高，盆栽黄水仙需要注意环境的布置，一般都能成功开花。　　黄水仙喜冬季湿润、夏季干热的生长环境。因此，盆栽黄水仙秋冬根生长期和春季地上部生长期均需充足水分，但不能积水。　　盆栽黄水仙常用15－20厘米盆，每盆栽鳞茎3－5个，栽后鳞茎上方覆土6－8厘米，浇透水后放半阴处。在冬季根部生长期和春季叶片生长期保持盆土湿润，3－4月就能正常开花。　　盆栽黄水仙常用促成栽培，将鳞茎放35℃下贮藏5天，再经17℃贮藏至花芽分化完全，约1个月，然后放9℃低温下贮藏6－8周，盆栽后白天室温21℃、晚间15℃，60－70天后开花。　　在黄水仙的叶片生长期可施用“卉友”15－15－30盆花专用肥或施腐熟农用肥1－2次。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick69821451468448.jpg', 'http://www.boqii.com/entry/detail/2378.html', '');
INSERT INTO `plant_family` VALUES ('93', '红背竹芋', 'C.rufibara', '红背竹芋', '红背卧花竹芋', '不容易死', '', 'http://www.boqii.com/entry/photo/2253/0,http://www.boqii.com/entry/photo/2253/5272', '　　', '', '', '', '', '', '红背竹芋', 'C.rufibara', '', '　　红背 ', '　　红背是竹芋科中比较着名的，并且栽培也非常普遍的之一，喜阴，在室内盆栽的观赏效果非常好，所以常被用于布置书房、客厅等场所。红背竹芋的叶片还可以做插花的配叶，观赏期也非常长。　　红背竹芋盆栽可用腐叶土、园土和河沙等量混合并加少量基肥作为土。　　红背竹芋生长季须给予充足的水分，保持盆土经常湿润，并注意向叶面喷水；尤其气温较高、空气干燥时，还须经常向叶面及周围喷水，以保持较高的空气湿度。但要注意不宜使盆土积水，以免影响根系通气性，导致生长不良或烂根；秋末后气温较低，要控制浇水量，保持盆土微湿即可。　　红背竹芋在生长季每月施1—2次液肥，以保证其生长健壮、枝叶繁茂。红背竹芋喜阴，忌阳光直晒，不可置于阳光下，否则叶片褪绿，失去光泽，严重的会造成日灼病；但也不宜长期放在阴暗及通风不良处，以免叶片发黄、脱落。', '　　红背　　分株宜于春季气温回暖后进行，生长旺盛的植株每l－2年可分盆一次。沿地下根茎生长方向将丛生植株分切为数丛，然后分别上盆种植，置于较阴蔽处　　也可利用抽长的带节茎叶进行扦插繁殖。扦插可于霉雨', 'http://img.boqiicdn.com/Data/BK/P/imagick9331448443666.jpg', 'http://www.boqii.com/entry/detail/2253.html', '');
INSERT INTO `plant_family` VALUES ('94', '紫荆', 'Cercis chinensis Bunge', '紫荆', '裸枝树，紫珠', '不容易死', '', 'http://www.boqii.com/entry/photo/2016/0,http://www.boqii.com/entry/photo/2016/5511', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '豆科', '紫荆属', '紫荆', 'Cercis chinensis Bunge', '', '　　 　　', '　　', '　　　　1、播种：10～11月采种，经日晒搓擦脱粒得净种，适干藏，发芽率保持85％。冬播或春播均可。播前用温水30－40℃浸种一昼夜，捞出晾干条播，条距15厘米、播深3厘米。覆土1厘米，亩播种约3公斤。4月末可发芽出土。当小苗具2片真叶时，进行间苗、补苗一次。　　2、分株：多在春季芽萌动前进行。因其根部的韧皮部发达，不易截断，分株时应用利刀或剪刀分离，也可在春季进行少量压条繁殖。　　3、扦插：在夏季的　　4、压条：在整个生长季节都可进行，但要等到第二年才能生根，因此法较为繁琐，繁殖系数不高，而且成苗后植株长势较弱，故生产中很少采用。', 'http://img.boqiicdn.com/Data/BK/P/imagick32131441705909.jpg', 'http://www.boqii.com/entry/detail/2016.html', '');
INSERT INTO `plant_family` VALUES ('95', '吊灯扶桑', 'Hibiscus schizopetalus  （Masters） Hook.f.', '吊灯扶桑', '裂瓣朱槿、珊瑚扶桑、风铃扶桑、吊灯花、灯笼花、假西藏红花', '不容易死', '', 'http://www.boqii.com/entry/photo/2423/0,http://www.boqii.com/entry/photo/2423/4992', '　　', '被子植物门', '双子叶植物纲', '()目', '锦葵科', '木槿属', '吊灯扶桑', 'Hibiscus schizopetalus  （Masters） Hook.f.', '', '　　 　　吊灯扶桑是常绿直立灌木植物，高达3米；小枝细瘦，常下垂，平滑无毛。叶椭圆形或长圆形，长4-7厘米，宽1.5-4厘米，先端短尖或短渐尖，基部钝或宽楔形，边缘具齿缺，两面均无毛；叶柄长1-2厘米，上面被星状柔毛；托叶钻形，长约2毫米，常早落。', '　　的外形就像一个低耳垂听的风铃，吊灯扶桑不但可以用于观赏，其叶子部分可以入药，所以经济价值非常高。现在在很多私人花园中，也常常能见到吊灯扶桑的身影。　　吊灯扶桑系强阳性，性喜温暖、湿润，要求日光充足，不耐阴，不耐寒、旱，在长江流域及以北地区，只能盆栽，在温室或其他保护地保持12℃-15℃气温。室温低于5℃时叶片转黄脱落，低于0℃，即遭冻害。耐修剪，发枝力强。对土壤的适应范围较广，但以富含有机质，pH6.5-pH7的微酸性壤土最好。', '　　　\n　一、扦插\n　　5-10月进行，冬季在温室内进行，但以梅雨　\n　二、嫁接\n　　在春、秋季进行。多用于扦插困难或生根较慢的扶桑', 'http://img.boqiicdn.com/Data/BK/P/imagick45191452677901.jpg', 'http://www.boqii.com/entry/detail/2423.html', '');
INSERT INTO `plant_family` VALUES ('96', '海仙花', 'Korean Weigela', '海仙花', '朝鲜锦带、花关门、柴门关柴、临界海棠', '不容易死', '华北、华东、华中等', 'http://www.boqii.com/entry/photo/2301/0,http://www.boqii.com/entry/photo/2301/5223', '植物　', '被子植物门', '木兰纲', '川续断目', '忍冬科', '锦带花属', '海仙花', 'Primula poissonii Franch.', 'Primula poissonii', '　　 　　海仙花为多年生草本，无香气，不被粉。根茎极短，向下发出一丛粗长的支根。叶丛（至少部分叶）冬季不枯萎，叶片倒卵状椭圆形至倒披针形，长（2.5）4－10（13）厘米，宽1.2－5厘米，先端圆钝，稀具小骤尖头，基部狭窄，下延，边缘具近于整齐的三角形小牙齿；叶柄极短或与叶片近等长，具阔翅。', '　　海仙花的花色艳丽，对氯化氢的抗性较强，可以作为抗污染绿化树种栽培。海仙花非常适合栽种在庭院、绿地群植造景，也可作', '　　海仙花的花枝茂密、花色鲜艳，人工栽培的难度并不高，适应能力较强。由于海仙花的萌芽力强，在北京地区可以露地越冬。人工繁殖海仙花可以用扦插、分株及播种的方法，小编就为你介绍一下海仙花常用的繁殖方法及注意事项。　\n　一、扦插繁殖\n　　海仙花采用常规的嫩枝扦插繁殖，时间在4～5月，选取当年　　插穗，要切取当年生长的健壮新枝顶端，每段长约8～10厘米，带叶连踵剪下，保留顶端嫩尖嫩叶，下部叶片全部剪除，若要防止插穗留叶过多，因蒸腾作用使插穗失水，可将留下的3～4片叶子，每片再剪去尖端的一半。为了使插穗伤口愈合快，生根早，可用0.05％～0.1％浓度的萘乙酸水溶液，浸泡插穗基部5秒钟，随浸随插，插入基质深度4～5厘米。株行距为8厘米×8厘米，插后将花盆轻轻震动一下，使之密贴。浇水时可用浸盆法浇透，直到盆土表面见湿后取出，置于湿润荫蔽处。必要时用白色塑料袋套在盆沿上，创造生根环境小气候，生根萌发后进行正常　　\n二、分株繁殖\n　　海仙花栽培时间长，植株基部出现丛生状后，可用分株的方法进行无性繁殖，时间宜在秋季落叶后。分株时，将海仙花从花盆中带土团取出，剔去附着土，在根茎着生枝条的空隙部位，用利刀切开，再按每株1～2根枝条，切成多块，每块上都要有须根，切后用草木灰涂抹切口，用　\n　三、播种繁殖\n　　海仙花的育种繁殖，要在开花时进行。采用人工授精的方法，使海仙花挂果，9～10月果实成熟，采收后贮藏，待至来年3～4月，用花盆苗床播种，基质可用山泥土、腐叶土和砂质园田土各等份，混合后曝晒，整细过筛上盆备用。　　海仙花种子有翅，播种时可用40℃温开水泡种24小时，待种子膨胀吸足水分后，播于苗床内，覆土1厘米，用浸盆法浇透水，覆盖玻璃，置于温暖处，大约20天左右种子开始萌发，这时，可揭去玻璃，置于向阳处莳养，加强肥水管理，当幼苗长出4片新叶后，便可分盆移栽。', 'http://img.boqiicdn.com/Data/BK/P/imagick50201449569170.jpg', 'http://www.boqii.com/entry/detail/2301.html', '');
INSERT INTO `plant_family` VALUES ('97', '佛甲草', 'Sedum lineare', '佛甲草', '万年草、佛指甲、半支连', '不容易死', '云南、贵州、广东、湖南、湖北等地', 'http://www.boqii.com/entry/photo/2017/0,http://www.boqii.com/entry/photo/2017/5510', '', '', '', '', '', '', '', '', '', '　　 　　佛甲草为多年生草本，无毛，茎高10～20厘米。3叶轮生，少有4叶轮或对生的，叶线形，长20～25毫米，宽约2毫米，先端钝尖，基部无柄，有短距。　　　Sedum lineare　　　　　　　　　　　　　　　　　　　　　　　　　', '　　佛甲草的适应能力非常强，不但栽培难度不大，还有一定的药用价值，是非常有经济价值的多肉。虽然佛甲草的外形并不起眼，但是经常为用作盆栽的配饰，那么如此平凡的佛甲草在栽种时应该注意哪些问题呢？　　1、土壤：生性强健，能耐贫薄，在黏性、沙质等各种壤土中都能正常，盆栽时，可用较小型的花盆，盆土可采用普通园土和少量河沙混合成的土。　　2、浇水：当春季气温转暖，佛甲草开始萌发时，浇水应充足，注意保持土壤湿润，到4－5月时，则可以稍干一些，此植物比较耐旱。若此时水分过多、盆土过湿，反而生长不好。　　3、光照：佛甲草有一种，“随光应变”的特性。在阳光充足的地方，其叶片为黄绿色；若移置稍阴暗的地方，叶片会变成较深的绿色。要是长缺乏光照，其茎蔓会生长得过分繁茂，节间抽长，植株变得不充实。　　4、温度：稍能耐寒，在冬季寒冷时，只要气温不低于10℃，它仍能生长较好，若能把它放置在向阳避风的地方，盆土不要太干或太湿，它就不会被冻伤，来年春季又可以茁壮生长。　　5、施肥：在佛甲草的生长季节，最好每月浇1次腐熟的粪肥，这样可以使其长得青翠旺盛，茎蔓四壁。到了5－6月时，就会开花更多，长得黄花满盆，形成很好的观赏效果。', '　　　\n　1、撒种繁殖\n　　此种方法，是我院科研人员通过实验得出，效果甚好。撒种主要适合于雨季或阴天进行，要求地势平坦，疏松，湿润的已耕耙地块，做畦，要求畦不宜过大，过大操作不便，2×25m即可。把　　\n2、扦插繁殖\n　　扦插适合于夏、秋两季进行，要求地势平坦，疏松，湿润的已耕耙地块，做畦划沟，沟距10－15cm均可，把生长旺盛的茎叶剪成10cm左右，以3－4根伟一组，扦插于沟内埋土，大概埋3－4cm的土。把地整平后，大水漫灌，要求水一定要足。每隔三天一次，大概2－3次即可（据气温和地温而定）。　　\n3、移植繁殖\n　　移栽在春、夏、秋三季均可进行，要求地势平坦，疏松，湿润的已耕耙地块，做畦划沟，沟距10－15cm左右均可，把植株从苗圃地带根移出，以株距为5cm进行定植。定植完后整平地块，进行灌水，要求大水漫灌水一定要足。每隔三天一次，大概2－3次即可（据气温和地温而定）。', 'http://img.boqiicdn.com/Data/BK/P/imagick10141441790417.jpg', 'http://www.boqii.com/entry/detail/2017.html', '');
INSERT INTO `plant_family` VALUES ('98', '月见草', 'Evening primrose', '月见草', '晚樱草、待霄草、山芝麻、野芝麻', '不容易死', '北美洲、南美、阿根廷、中国', 'http://www.boqii.com/entry/photo/2064/0,http://www.boqii.com/entry/photo/2064/5463', '', '', '', '', '', '', '', '', '', '　　 　　月见草为直立二年生粗状草本，基生莲座叶丛紧贴地面；茎高50～200厘米，不分枝或分枝，被曲柔毛与伸展　　花序穗状，不分枝，或在主序下面具次级侧生花序；苞片叶状，芽时长及花的1／2，长大后椭圆状披针形，自下向上由大变小，近无柄，长1.5～9厘米，宽0.5～2厘米，果时宿存，花蕾锥状长圆形，长1.5～2厘米，粗4～5毫米，顶端具长约3毫米的喙；花管长2.5～3.5厘米，径1～1.2毫米，黄绿色或开花时带红色，被混生的柔毛、伸展的长毛与短腺毛；花后脱落；萼片绿色，有时带红色，长圆状披针形，长1.8～2.2厘米，下部宽大处4～5毫米，先端骤缩成尾状，长3～4毫米，在芽时直立，彼此靠合，开放时自基部反折，但又在中部上翻，毛被同花管；花瓣黄色，稀淡黄色，宽倒卵形，长2.5～3厘米，宽2～2.8厘米，先端微凹缺；花丝近等长，长10～18毫米；花药长8～10毫米，花粉约50％发育；子房绿色，圆柱状，具4棱，长1～1.2厘米，粗1.5～2.5毫米，密被伸展长毛与短腺毛，有时混生曲柔毛；花柱长3.5～5厘米，伸出花管部分长0.7～1.5厘米；柱头围以花药。开花时花粉直接授在柱头裂片上，裂片长3～5毫米。　　　　　　　　　　　　　　　　　　　　　　', '　　月见草的适应能力比较强，但是土壤太潮湿的话其根部就会比较容易得病。月见草原产于南北美洲，在引入欧洲后，就在世界各地传播，月见草是本世纪发现的非常重要的营养药物，不但具有保健功能，对于很多疾病也有显着疗效。其实月见草是可以在家中栽种的，小编就为你简单介绍一下。　　月见草生性强健，耐寒、耐旱、耐瘠薄，喜光照，忌积涝。庭院栽培在通风敞亮处，疏松肥沃、排水良好的沙壤土地段，最好，也可盆栽摆放阳台观赏，在的月光下，阵阵幽香令人神清气爽。月见草自播能力强，经一次种植，其自播苗即可每年自生，开花不绝。人工播种繁殖，宜在10月间秋播。入冬后将小苗囤在阳畦假植，夜间覆盖防寒。翌春定植露地或上盆栽培。也可于早春3月播种，当年开花，但花的质量不如秋播的好。播种苗长出2片至3片真叶时分苗移栽一次促壮，待长到6片至7片真叶时再行定植。月见草主根发达，一般上盆成活后即可摘心促发分枝而多开花。期看长势强弱，可每两周适量追施一次有机或无机液肥，经常保持盆土湿润。花后及时剪除残花，减少养分消耗，以期再次开花。可在早春室内盆播，因种子粒小，撒播不可太密，覆土不宜太厚，待幼苗长出6片真叶时整坨脱出，带土分栽下地或上盆，5月即可开花，一直开到10月末。　　', '　　很多朋友对于月见草的作用都非常了解，也有的花友会在家中盆栽或在　　\n一、播种：\n　　\n二、扦插繁殖：\n　　1、温度：插穗生根的最适温度为18℃～25℃，低于18℃，插穗生根困难、缓慢；高于25℃，插穗的剪口容易受到病菌侵染而　　2、湿度：扦插后必须保持空气的相对湿度在75～85％。可以通过给插穗进行喷雾来增加湿度，每天1～3次，晴天温度越高喷的次数越多，阴雨天温度越低喷的次数则少或不喷。但过度地喷雾，插穗容易被病菌侵染而腐烂，因为很多种类的病菌就存在于水中。　　3、光照：扦插繁殖离不开阳光的照射，但是，光照越强，则插穗体内的温度越高，插穗的蒸腾作用越旺盛，消耗的水分越多，不利于插穗的成活。因此，在扦插后必须把阳光遮掉50～80％，待根系长出后，再逐步移去遮光网：晴天时每天下午4：00除下遮光网，第二天上午9：00前盖上遮光网。', 'http://img.boqiicdn.com/Data/BK/P/imagick93141442916303.jpg', 'http://www.boqii.com/entry/detail/2064.html', '');
INSERT INTO `plant_family` VALUES ('99', '卧牛', 'Gasteria armstrongii', '卧牛锦', '', '可不死', '原产地为南非开普省', 'http://www.boqii.com/entry/photo/2499/0,http://www.boqii.com/entry/photo/2499/4092', '', '', '', '', '', '', '', '', '', '　　 　　卧牛的繁殖可结合春季换盆进行分株，将母株旁萌生的幼株取下，另行栽种即可，有时这些幼株的叶片会不带黄色　　也可用播种法繁殖，在4－5月进行，发芽适温18－20℃；播后两周内出苗，幼苗中卧牛、卧牛锦都有，应注意', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick88061455787425.jpg', 'http://www.boqii.com/entry/detail/2499.html', '');
INSERT INTO `plant_family` VALUES ('100', '美人蕉', 'Canna indica L.', '美人蕉', '红艳蕉、小花美人蕉、小芭蕉', '不容易死', '', 'http://www.boqii.com/entry/photo/2057/0,http://www.boqii.com/entry/photo/2057/5470', '', '', '', '', '', '', '', '', '', '　　美人蕉为多年生草本 　　美人蕉植株全部绿色，高可达1.5米。叶片卵状长圆形，长10－30厘米，宽达10厘米。总状花序疏花；略超出于叶片之上；花红色，单生；苞片卵形，绿色，长约1.2厘米；萼片3，披针形，长约1厘米，绿色而有时染红；花冠管长不及1厘米，花冠裂片披针形，长3－3.5厘米，绿色或红色；外轮退化雄蕊3－2枚，鲜红色，其中2枚倒披针形，长3.5－4 厘米，宽5－7毫米，另一枚如存在则特别小，长1。5厘米，宽仅1毫米；唇瓣披针形，长3厘米，弯曲；　　　　　　　　　　　　　　　　　　　', '　　美人蕉在温暖的地区是没有的，可以终年生长，适宜生长的为22－25℃，虽然美人蕉充足的阳光，但是长暴晒也会出现灼伤的，所以人工种植美人蕉则需要注意为其提供一个适宜的环境。　　1、土壤：美人蕉对土壤要求不严，在疏松肥沃、排水良好的沙土壤中生长最佳，也适应于肥沃粘质土壤生长。　　2、阳光：美人蕉在生长期要求光照充足，保证每天要接受至少5个小时的直射阳光。环境太阴暗，光照不足，会使美人蕉开花期向后延迟。　　3、温度：美人蕉喜温暖，忌严寒，适宜长温度16－30℃，5－10℃将停止生长，低于0℃时就会出现冻害。美人蕉开花时，为延长花期，可放在温度低、无阳光照射的地方，环境温度不宜低于10℃。　　4、浇水：美人蕉的根茎尚未长出新根前，要少浇水。盆土以潮润为宜，土壤过湿易烂根。美人蕉花葶长出后应经常浇水，保持盆土湿润，若缺水，美人蕉开花后易出现“叶里夹花”现象。冬季应减少浇水，以“见干见湿”为原则。　　5、施肥：种植美人蕉，首先要施足基肥，在生长旺季每月应追施3－4次稀薄饼液肥。花葶抽生后喷施0。2％磷酸二氢钾水溶液1－2次，可促使花大色艳。每次花谢后都应及时剪除残花和花筵，增施肥料，以保证它重复开花所需要的养料。入秋之后继续追施1－2次液肥，便可使美人蕉陆续开花不断。　　6、病虫害：美人蕉适应性很强，管理上比较粗放，并不娇，虫害也很少。每年5－8月要注意卷叶虫害，以免伤其嫩叶和花序。可用50％敌敌畏800倍液或50％杀暝松乳油1000倍液喷洒。', '　　　　\n一、播种法\n　　播种之前，先锉刀坚硬的种皮，然后放在25℃的水中浸泡24小时，再点播于素沙土中。覆土最好不要太厚，以种子直径的1－2倍为宜。播完之后，保持土壤湿润，20℃左右　\n　二、分根茎法\n　　在每年3月初，把前一年贮存的根茎分切成块，去掉　\n　三、分株法\n　　一般在6－7月阴雨天或傍晚时候，针对株间或株丛间距在4－5厘米以上，未出花序者，用锋利的工具从株间垂直向下切割，快速分株或分株丛，注意多带宿土，不要损伤枝叶，然后直接栽入定植穴内，栽后及时浇透水。如遇环境比较干旱，还要适当遮阳，以增加湿度。经过10天左右的', 'http://img.boqiicdn.com/Data/BK/P/imagick14761442828778.jpg', 'http://www.boqii.com/entry/detail/2057.html', '');
INSERT INTO `plant_family` VALUES ('101', '金缕梅', 'Hamamelis mollis Oliver', '金缕梅', '木里香、牛踏果', '不容易死', '中国广西、湖南、湖北、安徽、江西、浙江等省。', 'http://www.boqii.com/entry/photo/2104/0,http://www.boqii.com/entry/photo/2104/5423', '植物　', '被子植物门', '双子叶植物纲', '蔷薇目', '金缕梅科', '金缕梅属', '金缕梅', 'Hamamelis mollis Oliver', 'Hamamelis mollis', '　　 　　金缕梅为落叶灌木或小乔木，高达8米；嫩枝有星状绒毛；老枝秃净；芽体长卵形，有灰黄色绒毛。叶纸质或薄革质，阔倒卵圆形，长8－15厘米，宽6－10厘米，先端短急尖，基部不等侧心形，上面稍粗糙，有稀疏星状毛，不发亮，下面密生灰色星状绒毛；侧脉6－8对，最下面1对侧脉有明显的第二次侧脉，在上面很显着，在下面突起；边缘有波状钝齿；叶柄长6－10毫米，被绒毛，托叶早落。', '　　的花形奇特，花瓣如缕和比较像，并且花色金黄，故此命名，一般在2月前后先叶开放。由于金缕梅的耐寒能力比较强，又有“忍冬花”的美名，小编就为你介绍一下金缕梅的栽培要点。　　金缕)形奇特，具有芳香，草春先叶开放，黄色细长花瓣宛如金缕，缀满枝头，十分惹人喜爱。国内外庭园常有栽培，并有一些好品种出现，是着名观赏花木之一。在角隅、池边、溪畔、山石间及树丛外缘都很合适。此外，花枝可作瓶插材料。　　金缕梅喜光，耐半阴，喜温暖湿润气候，较耐寒，对土壤要求不严，常生长于富含腐殖质的山林中。栽植前将地上部分适当修剪，否则不易成活，第二年即可开花。每年4～5月开花，在新梢、嫩叶、花朵同时抽发与开放时，保持土壤湿润。开花过程中施1次磷肥。花后至秋末，适当修剪整形，保持优美姿态。', '　　　　播种繁殖金缕　　苗木种子　　压条繁殖春、秋两季均可进行。将枝条在节下割伤，埋人已挖好的沟内，沟深6-8厘米。顶梢朝上，枝条用竹签固定，然后覆土，土壤经常保持湿润。翌年春季可与母株切割分栽。　　移植金缕梅较耐移植。一般在10-11月进行。移植过迟，会影响早春开花。中小苗移植带宿土，大苗移植需带土球。', 'http://img.boqiicdn.com/Data/BK/P/imagick92051444469017.jpg', 'http://www.boqii.com/entry/detail/2104.html', '');
INSERT INTO `plant_family` VALUES ('102', '粉花绣线菊', 'Spiraea japonica L. f.', '粉花绣线菊', '蚂蟥梢、火烧尖、日本绣线菊', '不容易死', '', 'http://www.boqii.com/entry/photo/2309/0,http://www.boqii.com/entry/photo/2309/5214', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '绣线菊属', '粉花绣线菊', 'Spiraea japonica L. f.', '', '　　 　　粉花绣线菊为直立灌木，高达1.5米；枝条细长，开展，小枝近圆柱形，无毛或幼时被短柔毛；冬芽卵形，先端急尖，有数个鳞片。复伞房花序生于当年生的直立新枝顶端，花朵密集，密被短柔毛；花梗长4－6毫米；苞片披针形至线状披针形，下面微被柔毛；花直径4－7毫米；花萼外面有稀疏短柔毛，萼筒钟状，内面有短柔毛；萼片三角形，先端急尖，内面近先端有短柔毛；花瓣卵形至圆形，先端通常圆钝，长2.5－3.5毫米，宽2－3毫米，粉红色；雄蕊25－30，远较花瓣长；花盘圆环形，约有10个不整齐的裂片。', '　　的适应性较强，可做地被观花植物，在园林绿化的应用中非常广。人工栽培粉花绣线菊的难度并不高，可以根据其习性来为其打造一个适宜的生长环境。　　粉花绣线菊喜光，阳光充足则开花量大，耐半阴；耐寒性强，能耐一10℃低温，喜四季分明的温带气候，在无明显四季交替的亚热带、热带地区生长不良；耐瘠薄、不耐湿，在湿润、肥沃富含有机质的土壤中生长茂盛，生长需水份较多，但不耐积水，也有一定的耐干旱能力。　　粉花绣线菊可作花坛、花境，或植于草坪及园路角隅等处构成夏日佳景，亦可作基础种植。粉花绣线)色妖艳，甚为醒目，且花期正值少花的春末夏初，应大力推广应用。可成片配置于草坪、蹯边、花坛、花径，或丛植庭园一隅，亦可作，盛开时宛若锦带。庭院观赏、花篱、丛植、花境、可布置草坪及小路角隅等处，或种植于门庭两侧。', '　　粉花绣线　\n　一、播种繁殖\n　　秋天种子成熟后，采摘、晒干、脱粒、贮藏，翌年春天将种子取出进行播盆，因其种子　\n　二、分株繁殖\n　　一般，2～3月结合移植，从母株上分离萌蘖条，适当修剪后分栽，也可以在分株前培肥土，促使母株多发萌蘖，第2年再掘起分栽。　　\n三、扦插繁殖\n　　理论上粉花绣线菊的嫩枝和硬枝都可以扦插，但嫩枝的扦插效果要明显优于硬枝，所以大多情况下，选取嫩枝扦插。', 'http://img.boqiicdn.com/Data/BK/P/imagick55991449740748.jpg', 'http://www.boqii.com/entry/detail/2309.html', '');
INSERT INTO `plant_family` VALUES ('103', '风铃草', 'Campanula medium L', '风铃草', '钟花、瓦筒花，风铃花', '不容易死', '多数产于欧亚大陆北部', 'http://www.boqii.com/entry/photo/2319/0,http://www.boqii.com/entry/photo/2319/5204', '植物　　', '被子植物门', '双子叶植物纲', '桔梗目', '桔梗科', '风铃草属', '', 'Campanula medium L', '', '　　风铃花又名钟花，因其花朵钟状和风铃非常相似，并且花色素雅，在欧洲非常盛行，有许多栽培观赏种。现在 　　风铃草株高约1米，多毛。莲座叶卵形至倒卵形，叶缘圆齿状波形，粗糙。叶柄具翅。茎生叶小而无柄。总状花序，小花1朵或2朵茎生。花冠钟状，有5浅裂，基部略膨大。种子多数，椭圆状。', '　　又名钟花，目前有200多种，其外形和风铃类似，颜色素雅，非常受人欢迎。风铃草非常适合栽种在，小编就为你介绍一下风铃草的栽培要点。　　土质酸碱度应在5.5－6.0之间，疏松、养分充足、易排水，多孔基质，粘土占20－30％，内含铁螯合物，1m3施1－1.5kg完全平衡肥。　　在胚根长出前保证水分充足，维持在高湿度水平，同时土壤随之保持湿润，可能的话在刚长出的幼苗上加一层粗粒蛭石，以保证水分不会流失。另外，正常情况下，浇水间隔时期土壤可以稍微干一些。　　适合生长的正常温度13－18℃。冬季没有霜降的气候，温度可以在3－5℃，在外面培育需保温。春天在15－18℃的温度培育5－9个星期，在13－15℃的温度下会增加养殖期。　它长时间的光照，日常光照14小时会自然开花，如果需要提早开花的时间，可以通过4小时间断黑夜30天调节。　一个星期按照1：1.5的比例交替施浓度在150－200ppm的氮肥和钾平衡肥，若要加速幼苗的生长，可以施加30－50ppm的钙氮肥，再施加钙肥。植株需要被施浓度为0。025％的硫化镁及铁螯合物1－2次，以保证这些微量元素。注意9月中旬后不可施肥。　植株是不用在生长其调节和摘心，以开始可能外形不够整洁，但在后期的生长中会自然调节，也就用不着修剪了。', '　　　　风铃草以播种养殖为主，亦可分株或扦插育苗。花后结成蒴果，果内有种子多粒。种子极　　播后不再覆土或薄盖过筛细土。幼苗期用喷器喷水，并视苗的　　扦插多于春季摘取基部萌发的新芽，插入湿沙床上，经常喷雾保湿，长根后进行移植。', 'http://img.boqiicdn.com/Data/BK/P/imagick57361450084558.jpg', 'http://www.boqii.com/entry/detail/2319.html', '');
INSERT INTO `plant_family` VALUES ('104', '芳香波', 'Stomatium niveum', '芳香波', '', '不容易死', '原产地为于非洲南部地区', 'http://www.boqii.com/entry/photo/2456/0,http://www.boqii.com/entry/photo/2456/4960', '　　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '楠舟属', '芳香波', 'Stomatium niveum', '', '　　芳 ', '　　芳在夏季会有短暂的休眠期，一般在春季开花，由于的花友香味，是多肉中比较特别的，所以也受到很多多肉爱好者的喜爱。那么如何才能养出健康漂亮的芳香波呢？　　芳香波喜温暖、干燥和阳光充足的环境，不耐寒，忌水湿和酷暑，夏季休眠。芳香波适温15－25度，冬季不低于10度；配土一般可用泥炭、和珍珠岩的混合土；生长期浇水不宜多，勤喷水控制浇水，保持盆土稍潮润即可；生长期施肥一般每月一次；特别要掌握好夏季休眠期的控水、通风、遮荫、停肥等环节。', '　　芳　　芳香波主要是分株扦插的方式繁殖，当然也可以采用播种的方式，只不过播种的方式比较麻烦，一般不常用。芳香波扦插尅剪下一段插入土中，过一段', 'http://img.boqiicdn.com/Data/BK/P/imagick1561453801000.jpg', 'http://www.boqii.com/entry/detail/2456.html', '');
INSERT INTO `plant_family` VALUES ('105', '玉龙观音', '', '玉龙观音', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2317/0,http://www.boqii.com/entry/photo/2317/5206', '　', '', '', '', '景天', '莲花掌属', '玉龙观音', '', '', '　　玉龙观音为景天科 　　玉龙观音在多不胜举的绿植中脱颖而出、赢得信赖的重要原因在于其出众的吸附空气中有害物质及杂质的能力。当', '　　很多多肉爱好者都会饲养玉龙观音，但是却往往不了解其习性而导致玉龙观音越长越难看，甚至出现的情况。其实玉龙观音的栽培难度并不高，小编就为你整理了玉龙观音的生长习性及栽培要点，有兴趣的朋友可以一起了解。　　玉龙观音春秋冬三个季节都是生长季。冬季虽然冷一些，但是只要保持10度，依然会生长明显，夏季温度过高时休眠迹象也是很明显的，叶片会完全卷起来，这一点相比“)锦”和“黑法师原始种”又要好很多了。　　玉龙观音日常是很简单滴。最开始每天保持3小时左右的日照，成长出长长的枝干后少晒一点也没问题的，浇水的话，生长期一周最少一次，有时候会更频繁一些，所以生长得很快，夏季在我们这里是不断水滴。现在基本上2周一次浇水，形态一直都保持得非常好。　　通风相对来说要差一点，但一点也不影响，也许是适应我家的环境了吧。毕竟也养了这么久了，还有一个特点，经常会发出非常臭的气味，特别是叶片上，用手轻轻一摸就会沾上，像是“香港脚”的味道，大家要注意了。　　目前花市上也是非常常见的了。特别是山东地区，青岛的花市里就有非常多，但是状态和我家的还不太一样，要养成这样)状的样子其实也挺简单的。买回家后混合颗粒比例较大的土壤，种好后少量浇水，以后每次浇水量减少，浇水频率减少慢慢就会出来漂亮额玫瑰型啦。养出状态后继续坚持这种养护方案，就能够一直保持玫瑰型。', '　　多肉植物的繁殖最常见的就是叶插了，但是对于想要　　玉龙观音的繁殖方式以扦插为主，剪下一段插入土中即可，比较容易成功。此外玉龙观音可以说是莲花掌里面的巨无霸，可以', 'http://img.boqiicdn.com/Data/BK/P/imagick2791450084100.jpg', 'http://www.boqii.com/entry/detail/2317.html', '');
INSERT INTO `plant_family` VALUES ('106', '灰莉', 'Fagraea ceilanica Thunb.', '灰莉', '非洲茉莉、华灰莉、鲤鱼胆、灰刺木、箐黄果、小黄果', '不容易死', '中国、印度、中南半岛和东南亚各国', 'http://www.boqii.com/entry/photo/2315/0,http://www.boqii.com/entry/photo/2315/5208', '　　', '被子植物门', '双子叶植物纲', '捩花目', '马钱科', '灰莉属', '灰莉', 'Fagraea ceilanica Thunb.', '', '　　 　　灰莉为乔木，高达15米，有时附生于其他树上呈攀援状灌木；树皮灰色。小枝粗厚，圆柱形，老枝上有凸起的叶痕和托叶痕；全株无毛。', '　　为常绿乔木或灌木，适应能力比较强，所以栽种难度并不高。灰莉枝繁叶茂，花大而芬芳，非常适合栽种在，也有花友将灰莉盆栽，那么灰莉在栽培过程中需要注意哪些呢？　　1、合理调光。灰莉性喜阳光温暖的环境，但夏秋应避开中午太阳直射光，以免造成叶片灼伤。同时，其向光性较强，放在室内每隔10～15天需转动一次花盆，防止偏冠，在光线不足的环境放置不宜超过两个月，否则会因光照不足而造成叶片发黄而脱落。　　2、合理增湿。灰莉喜空气湿度高，通风良好的环境。因此，夏季浇水量要多一些，并置于荫凉处。同时，喷洒叶面水，增加局部空气湿度，以保持叶片浓绿。　　3、合理施肥。生长期每隔15～20天追施一次含氮、磷、钾比例适中的腐熟薄豆饼肥，注意防止氮肥过多而引起徒长，影响开花和树形。入秋后适当喷施0.2％～0.3％的磷酸二氢钾，秋末浇水量要逐渐减少，并停止施肥。冬季，北方盆栽灰莉放在5℃以上的室内即可。　　4、合理修剪。灰莉萌芽和萌蘖比较强，极耐修剪，生长期可随意造型修剪，通常可剪成球形、平台形、扇形，为保持优美的树形，植株底部萌蘖芽应及时剪去，以免消耗植株过多的养分。', '　　　\n　一、扦插\n　　灰莉繁殖，用扦插、播种、压条、分株均可，但北方以扦插为主。7～8月采取当年生枝条，剪成8～10厘米为一段做插穗，保留3～4枚顶叶，插入干净的河沙内，置于温室，40～60天可生根，成活率达85％以上。　\n　二、分株\n　　3至4月间，当植株刚开始萌动时，将丛状植株从花盆中脱出，或将地栽的丛生', 'http://img.boqiicdn.com/Data/BK/P/imagick95071449826176.jpg', 'http://www.boqii.com/entry/detail/2315.html', '');
INSERT INTO `plant_family` VALUES ('107', '凤眼莲', 'water hyacinth', '凤眼莲', '水葫芦、凤眼蓝、水葫芦苗', '不容易死', '原产巴西，现广布于中国长江、黄河流域及华南各省。', 'http://www.boqii.com/entry/photo/2180/0,http://www.boqii.com/entry/photo/2180/5348', '　', '被子植物门', '单子叶植物纲', '', '雨久花科', '凤眼蓝属', '凤眼莲', 'Eichhornia crassipes', '', '　　 　　凤眼莲为浮　　凤眼莲叶在基部丛生，莲座状排列，一般5－10片；叶片圆形，宽卵形或宽菱形，长4.5－14.5厘米，宽5－14厘米，顶端钝圆或微尖，基部宽楔形或在幼时为浅心形，全缘，具弧形脉，表面深绿色，光亮，质地厚实，两边微向上卷，顶部略向下翻卷；叶柄长短不等，中部膨大成囊状或纺锤形，内有许多多边形柱状细胞组成的气室，维管束散布其间，黄绿色至绿色，光滑；叶柄基部有鞘状苞片，长8－11厘米，黄绿色，薄而半透明；花葶从叶柄基部的鞘状苞片腋内伸出，长34－46厘米，多棱；穗状花序长17－20厘米，通常具9－12朵花；花被裂片6枚，花瓣状，卵形、长圆形或倒卵形，紫蓝色，花冠略两侧对称，直径4－6厘米，上方1枚裂片较大，长约3.5厘米，宽约2.4厘米，三色即四周淡紫红色，中间蓝色，在蓝色的中央有1黄色圆斑，其余各片长约3厘米，宽1.5－1.8厘米，下方1枚裂片较狭，宽1.2－1.5厘米，花被片基部合生成筒，外面近基部有腺毛；雄蕊6枚，贴生于花被筒上，3长3短，长的从花被筒喉部伸出，长1.6－2厘米，短的生于近喉部，长3－5毫米；花丝上有腺毛，长约0.5毫米，3（2－4）细胞，顶端膨大；花药箭形，基着，蓝灰色，2室，纵裂；花粉粒长卵圆形，黄色；子房上位，长梨形，长6毫米，3室，中轴胎座，胚珠多数；花柱1，长约2厘米，伸出花被筒的部分有腺毛；柱头上密生腺毛。蒴果卵形。花期7－10月，果期8－11月。', '　　凤眼莲原产于巴西，也就是我们常说的，现在在我国非常常见。由于凤眼莲具有一定的耐寒性，所以在我国的北京地区虽然引种成功，但是种子不能成熟。　　凤眼莲在长江中下游每年8月至10月开花，花期较长。每茬花4～5天，第一茬花谢后4～5天，本株又开第二茬花，共开两至三茬。生长良好的大秆花穗有花苞15～18朵，最少的有三朵以上。开花时平均25℃，漂泊在沼泽边坡，潮湿岸边生长的极易开花，比水中浮生的多开一至两年。每穗约5～10朵花。　　喜高温湿润的气候。一般25－35℃为生长的最适温度。39℃以上则抑制生长。7－10℃处于休眠状态；10℃以上开始萌芽，但深秋季节偶到霜冻后，很快枯萎。耐碱性，pH值为9时仍生长正常。抗病力亦强。极耐肥，好群生。但在多风浪的水面上，则生长不良。花期长，自夏至秋开花不绝。　　凤眼莲批量栽培可利用房前屋后潮湿的零散地或空闲的沼泽地，在6、7月间，将健壮的、株高偏低的种苗进行移栽，要预留出50％的空地以利栽后分蘖繁殖。移栽后适当管理，保持土层湿润，加强光照，确保通风。如果想花期延长，可进行塑料棚保温，中午通风一、二小时。在花芽形成后可移栽到小盆。用偏酸性土或营养液培养。摘除老叶，留4～5片嫩叶及花穗，既能延长花期，又可移至案头等地观赏。　　凤眼莲喜生长在浅水而土质肥沃的池塘里，水深以30厘米左右为宜。我国各省多采用母株防寒，春季放养于池塘中。高温季节，繁殖迅速。其各种栽培管理同其他水生花卉。', '　　　　凤眼莲无性繁殖能力极强。由腋芽长出的匍匐枝既形成新株。母株与新株的匍匐枝很脆嫩，断离后又可成为新株。春天将母株从分离或切离母株腋生小芽放入水中，可生根，极易成活。也可播种繁殖，但不多用。　　凤眼莲喜生长在浅水而土质肥沃的池塘里，水深以30厘米左右为宜。我国各省多采用母株防寒越冬，春季放养于池塘中。高温季节，繁殖迅速。其各种栽培管理同其他水生', 'http://img.boqiicdn.com/Data/BK/P/imagick37971446543432.jpg', 'http://www.boqii.com/entry/detail/2180.html', '');
INSERT INTO `plant_family` VALUES ('108', '美叶凤尾蕉', 'Zamia furfuracea', '美叶凤尾蕉', '阔叶苏铁', '不容易死', '', 'http://www.boqii.com/entry/photo/2313/0,http://www.boqii.com/entry/photo/2313/5210', '植物　', '', '', '', '泽米铁科', '泽米铁属', '', 'Zamia furfuracea', '', '　　 　　美叶凤尾蕉干高15～20cm，单干或罕有分枝，有时呈丛生状，粗枝，圆柱形，表面密被暗褐色的排排叶痕，在多年生的老干基部茎盘处，可由不定芽萌发而长出幼小的萌蘖，称为吸芽，地下为肉质的须根系。叶为大型偶数羽状复叶，生于茎干顶端，叶长60～120cm，硬革质，叶柄长15～20cm，疏生坚硬小刺。羽状小叶7～12对，小叶长椭圆形，两侧不等，基部2／3处全缘，上端密生小钝锯齿，顶部钝渐尖，边缘背卷，无中脉，叶背可见明显突起的平行脉纹40条，由基部直达叶尖。', '　　美叶凤尾蕉原产于墨西哥、哥伦比亚地区，其适应性比较强，非常适合在室内栽培。美叶凤尾蕉的栽培难度虽然不高，但是想要养出漂亮的美叶凤尾蕉则需要注意根据其习性来布置环境。　　1、美叶凤尾蕉在进行盆栽之前，要进行花盆的。选择种植美叶凤尾蕉的花盆尽量是泥质花盆、瓷盆或陶盆，尽量不要用塑料花盆，它的排水性不好。　　2、花盆的大小需要根据美叶凤尾蕉植株的大小来选择，不宜太大或太小。花盆太小会影响植株的，太大又会影响整体的美观。小型美叶凤尾蕉可选用其叶展径的1／2左右盆径的盆，中、大型美叶凤尾蕉可选用其叶展径的1／4－1／3左右盆径的盆。　　3、对已经种植好的美叶凤尾蕉除了要进行日常的管理之外，还要进行定期的修剪和杂草等。春季气温升高后，应保持盆土的湿润。夏季生长旺盛期，除浇水外，每天喷水2－3次，保持叶片青翠碧绿。秋末、冬季、春初气温较低时（10℃以下），应保持盆土偏干，以利于其越冬。美叶凤尾蕉，对要求不高。秋末、冬季、春初不施肥，春季气温上升后可以开始追肥，每隔1个月追腐熟的5倍液肥1次，或每月施1000倍“花多多”通用肥1次。　　养殖美叶凤尾蕉时应放半阴处养护，避免强光暴晒，否则会使叶色变黄和失去光泽。美叶凤尾蕉应每2年换盆1次，当新的羽状复叶生长2轮时，基部叶片往往老化，叶片变黄，应逐个剪除。在多年生的老干基部茎盘上，常萌发不定芽，如不作繁殖用，应及时剪除。　　4、养殖美叶凤尾蕉时，要注意给予它充足的阳光和水分，并做好防虫害措施。', '　　　　1、播种：因种子较大，春季采用室内盆播。发芽适温为24～30℃，播后约15天发芽。　　2、分株：以4～5月进行为宜。分割主茎旁吸芽，切割时应少伤茎皮，待切口稍干后，先插入沙床，保持室温26～30℃，待生根后栽盆。', 'http://img.boqiicdn.com/Data/BK/P/imagick6751449824895.jpg', 'http://www.boqii.com/entry/detail/2313.html', '');
INSERT INTO `plant_family` VALUES ('109', '金苞花', 'Aphelandra Pachystachys lutea', '金苞花', '黄虾花、珊瑚爵床、金包银、金苞虾衣花黄色皇后、黄金宝塔', '不容易死', '原产于美洲热带地区、落叶阔叶林区、南亚热带常绿阔叶林区', 'http://www.boqii.com/entry/photo/2305/0,http://www.boqii.com/entry/photo/2305/5219', '', '', '', '', '', '', '', '', '', '　　 　　金苞花的株高可达1米，盆栽仅15－20厘米。叶对生，卵形或长卵形，先端锐形，革质，中肋与羽状侧脉黄白色。夏、秋季花开，顶生，花苞金黄色，花期持久，花叶俱美。 艳苞花株高50－80厘米，盆栽15－30厘米。叶长椭圆形或披针形，中用银白色，夏，秋季开花，顶生，花苞红色，花期持久。此类　　　　　　　　　　　　　　　　　　　　　　　', '　　', '　　　　金苞花主要用扦插繁殖，　　金苞花常用扦插法繁殖。全年均可进行，以6－7月为佳。插穗应选择健壮、节间短的枝条，去除下部叶片，留顶端叶，长8－10厘米，插于素沙中，遮阴保湿度，2周后生根，当年扦插，当年即可开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick51051449653595.jpg', 'http://www.boqii.com/entry/detail/2305.html', '');
INSERT INTO `plant_family` VALUES ('110', '紫玉兰', 'Magnolia liliflora Desr.', '紫玉兰', '木兰、辛夷、木笔、望春', '不容易死', '', 'http://www.boqii.com/entry/photo/2087/0,http://www.boqii.com/entry/photo/2087/5440', '　　', '被子植物门', '双子叶植物纲', '毛茛目', '木兰科', '木兰属', '紫玉兰', 'Magnolia liliflora Desr.', '', '　　紫 　　紫玉兰属落叶灌木，高达3米，常丛生，树皮灰褐色，小枝绿紫色或淡褐紫色。叶椭圆状倒卵形或倒卵形，长8－18厘米，宽3－10厘米，先端急尖或渐尖，基部渐狭沿叶柄下延至托叶痕，上面深绿色，幼嫩时疏生短柔毛，下面灰绿色，沿脉有短柔毛；侧脉每边8－10条，叶柄长8－20毫米，托叶痕约为叶柄长之半。花蕾卵圆形，被淡黄色绢毛；花叶同时开放，瓶形，直立于粗壮、被毛的花梗上，稍有香气；花被片9－12，外轮3片萼片状，紫绿色，披针形长2－3.5厘米，常早落，内两轮肉质，外面紫色或紫红色，内面带白色，花瓣状，椭圆状倒卵形，长8－10厘米，宽3－4.5厘米；雄蕊紫红色，长8－10毫米，花药长约7毫米，侧向开裂，药隔伸出成短尖头；雌蕊群长约1.5厘米，淡紫色，无毛。聚合果深紫褐色，变褐色，圆柱形，长7－10厘米；成熟蓇葖近圆球形，顶端具短喙。花期3－4月，果期8－9月。', '　　紫)为我国特有植物，主要分布在我国云南、福建、四川等地，但由于不易移植和，所以是非常珍贵的花木。小编就为你整理了关于紫玉兰的栽培要点，对紫玉兰有兴趣的花友们可以一起学习。　紫玉兰喜湿润，怕涝，因此适时适量浇水很重要。立春到开花，盆土保持润而不湿；花后盆土保持湿润而不渍水；落叶后盆土保持微润而不干即可。任何时候都不能干旱，也不能渍水，特别是雨季要注意排水防涝。　　紫玉兰喜肥，施肥要抓住花前2月和花后5月这两个关键时机，十天左右施一次氮磷钾复合肥，前者使蕾膨大，鲜花开放，后者促进多孕蕾，翌春花多。入冬落叶时施一次以磷钾为主的，增强其抗寒越冬能力，其余时间少施或不施。忌单施氮肥。　紫玉兰喜光，置于向阳的、屋顶花园，多见阳光生长健壮繁茂，半阴条件下虽也能生长，但较瘦弱且花少，过阴则无花。它较耐寒，北京及其以南地区都可在室外越冬。　紫玉兰根部萌蘖力强，如不需繁殖，随长随剪，每盆保持3株主干即可。对于过高过长的枝条，可于花后刚展叶时剪短，因其伤愈能力差，剪后要涂硫磺粉防腐，如无必要则不修剪。花后如不需要留种繁殖，应将残花带蒂剪掉。', '　　　\n　一、紫玉兰砧木的选择与处理\n　　砧木应选择不现蕾或现蕾较少的初、盛蕾期的劣种。先将树冠从主枝锯去。距地面的水平高度要相近，避免因顶端优势而造成各主枝势力的不均衡，上层主枝要比下一枝主枝短，主干的高度宜稍高于最上一层主枝。接口应选在平滑处，锯口要用切接刀削平。　\n　二、接穗的选择与处理\n　　接穗应选品种优良的猴巴掌串榆、大毛桃串榆或二毛桃串榆单株，选择生长健壮、　　嫁接技术以春季萌芽前后至展叶期进行为宜。一般为3月中下旬，只工腋芽不萌发，　　劈接多用于粗枝。先用劈接刀或利斧从接口处劈开，劈口中心插上木橛，把接穗截成长10厘米左右，基部削成楔形，插入劈口中，使外侧的形成层相互对齐。每劈口两边可各接一个接穗。接后，轻轻拔出木橛。切接是在接口处稍带木质部纵切一刀，将接穗截成长5厘米左右，把基部两侧削成一长一短两个削面（长面约3厘米，短面约1。5厘米），将短面朝外插入切口内，紧靠一端对齐形成层。　　芽接是在枝组内缺枝处利用芽接填补空缺，使枝组完整。　　用上列方法嫁接完毕后，均应立即用塑料薄膜条把接口包严、绑紧，并让接穗裸露在外。　\n　三、嫁接后\n　　嫁接后20天左右接穗成活后，即可抽技展叶。要注意，及时把砧木上萌发芽摘除。没成活的，应在砧木上位置合适处进行夏季芽接。当接穗新梢长50厘米时可以摘心，以增加分枝，及早形成树冠。', 'http://img.boqiicdn.com/Data/BK/P/imagick88131443519815.jpg', 'http://www.boqii.com/entry/detail/2087.html', '');
INSERT INTO `plant_family` VALUES ('111', '花木蓝', 'Indigofera Kirilowii', '花木蓝', '吉氏木蓝、山绿豆、山扫帚、山花子、白秔子梢、朝鲜庭藤', '不容易死', '中国、朝鲜、日本', 'http://www.boqii.com/entry/photo/2408/0,http://www.boqii.com/entry/photo/2408/5007', '', '', '', '', '', '', '', '', '', '　　 　　花木蓝为小灌木，高30-100厘米。茎圆柱形，无毛，幼枝有棱，疏生白色丁字毛。羽状复叶长6-15厘米；叶柄长（0.5-）1-2.5厘米，叶轴上面略扁平，有浅槽，被毛或近无毛；托叶披针形，长4-6毫米，早落；小叶（2-）3-5对，对生，阔卵形、卵状菱形或椭圆形，长1.5-4厘米，宽1-2.3厘米，先端圆钝或急尖，具长的小尖头，基部楔形或阔楔形，上面绿色，下面粉绿色，两面散生白色丁字毛，中脉上面微隆起，下面隆起，侧脉两面明显；小叶柄长2.5毫米，密生毛；小托叶钻形，长2-3毫米，宿存。', '　　的适应性较强，耐贫瘠，耐干旱，并且抗病性也较强，对土壤要求不严。在北方，花木蓝是难得的绿化、美化材料，那么人工栽培花木蓝应该注意哪些呢？　喜温暖湿润气候，适宜在南温带及亚热带中低海拔地区栽培。夏季高温、雨量充足的地区，最旺。冬季温度低、无持久霜冻的情况下，可保持青绿。遇严霜后，叶片脱落，枝条仍能安全。翌春，枝条上的嫩芽开始萌发生长。自然脱落的种子，能在地表，与嫩芽同期出苗生长。　　耐旱，喜湿，但不耐水渍。低洼地不适宜种植。　对土壤要求不严，在pH4.5-7.0的红壤、黄壤和紫红壤上生长良好。　　表现喜光，但又具有一定的耐荫性。　　具有较强的抗逆性，适宜栽培的范围广，迄今未发现有严重的病虫害。', '　　　\n　一、播种繁殖\n　　4月中旬至5月初，用板镐顺床向或横床向开4cm深的沟，沟距25cm。将种子撒人沟内，种距约3~4cm。覆土厚度2~3cm，拍实覆土，播种量约7kg/667m2。也可撒播，即将种子均撒床表，再全面覆土2cm厚。　　\n二、分株繁殖\n　　将山上或圃地多年生植株在4月初挖出，按3~5个单株苗进行分墩，集中栽植于圃地，株行距15×15（cm），踩实土，浇足水。搞好常规的追肥、除草，防虫', 'http://img.boqiicdn.com/Data/BK/P/imagick81411452245981.jpg', 'http://www.boqii.com/entry/detail/2408.html', '');
INSERT INTO `plant_family` VALUES ('112', '红背桂花', 'Excoecaria cochinchinensis Lour', '红背桂花', '红紫木、紫背桂', '不容易死', '我国台湾、广东、广西、云南等地普遍栽培。亚洲东南部各国也有。', 'http://www.boqii.com/entry/photo/2147/0,http://www.boqii.com/entry/photo/2147/5380', '植物界', '被子植物门 Angiospermae', '双子叶植物纲 Dicotyledoneae', '大戟目 Euphorbiales', '大戟科 Euphorbiaceae', '海漆属 Excoecaria', '红背桂花', 'Excoecaria cochinchinensis Lour', '', '　　红背 　　红背桂花为常绿灌木，高达1米许；枝无毛，具多数皮孔。叶对生，稀兼有互生或近3片轮生，纸质，叶片狭椭圆形或长圆形，长6－14厘米，宽1.2－4厘米，顶端长渐尖，基部渐狭，边缘有疏细齿，齿间距3－10毫米，两面均无毛，腹面绿色，背面紫红或血红色；中脉于两面均凸起，侧脉8－12对，弧曲上升，离缘弯拱连接，网脉不明显；叶柄长3－10毫米，无腺体；托叶卵形，顶端尖，长约1毫米。', '　　红背)又名紫背桂等，原产于马来西亚岛屿，在我国很早就有引种栽培。现在常常制作成盆栽，用于观赏，此外，红背桂花还有一定的药用价值，可入药。　　盆栽红背桂花时，盆土宜用富含腐殖质的微酸性土壤。栽培较容易，夏季应置于荫棚下，可保持叶色浓绿；冬季可适当增加光照。平时保持盆土湿润即可，防止盆内积水引起病害。生长期可每月施肥一次，夏、秋季要加施少量的磷、钾肥或淡饼肥水。也可将家禽粪晒干后磨成粉状，随浇水施入盆内。同时，为保持盆土的微酸性，适时浇一些淡矾肥水为宜。平时浇水要适当，新梢发出前要少浇水，保持土壤含水量在40％左右即可；新梢发出后至7～8月间盆土含水量宜为60％～70％，保持土壤湿润，但忌积水。为提高空气湿度，盛夏还应早晚向叶面喷水。　　盆栽植株宜２年换盆一次，可于春季萌发新芽前进行换盆，换盆时可施加一些基肥，以保持植株健壮，叶色鲜艳美观。红背桂生长适温为20～28℃，越冬宜15℃以上。秋、冬季节可适当修剪，以保持良好的株型。', '　　红背　\n　一、扦插\n　　最佳时间为春芽尚未萌动前，此期间的枝条内含激素丰富，营养物质积累多，插后温度回升，插穗很快产生愈合组织。如错过时机，则可在春梢停止生长后，花芽和秋梢尚未萌动前的7月下旬至8月中旬扦插，但必须选用当年春季萌发生长的嫩枝作为插穗，才能达到理想的成活率。　\n　二、插床准备\n　　扦插时，选向阳地方，挖一个长12米、宽1.2米、深0.7米的平底长方形坑，底部填写层厚度为40厘米的蓄粪，或其他生热物质，上面再铺一层15—20厘米的　　\n三、扦插操作\n　　扦插时选健壮无病虫害的头年生秋梢作为插穗，剪成长8—10厘米，保留顶端2—3片叶，然后用0.05％—0.1％的萘乙酸水溶液，浸泡插穗基部2厘米处约5秒钟，随剪、随浸、随插。插时按10×10厘米株行距，先用木（竹）棍扎一小洞，插入插穗，覆基质后轻压实，用细孔喷壶浇透水，然后盖上薄膜和草帘凉棚。秋季扦插方法与春季相同，但应特别控制好温度，以免温度过高影响成活。', 'http://img.boqiicdn.com/Data/BK/P/imagick55681445850406.jpg', 'http://www.boqii.com/entry/detail/2147.html', '');
INSERT INTO `plant_family` VALUES ('113', '香龙血树', 'Dracaena fragrans', '香龙血树', '芳香龙血树、花虎斑木、王莲千年木、香花龙血树、香千年木', '不容易死', '', 'http://www.boqii.com/entry/photo/2137/0,http://www.boqii.com/entry/photo/2137/5390', '　', '被子植物门', '百合纲', '百合目', '龙舌兰科', '龙血树属', '香龙血树', 'Dracaena fragrans', '', '　　 　　香龙血树为直立单茎灌木。叶丛生于茎顶，长宽线形，无柄，叶缘具波纹，深绿色。常见', '　　香龙血树的叶片碧绿，生机盎然，是现在在世界上都非常流行的室内，有着“观叶植物的新星”的美名。目前，香龙血树的分布较广，列荷兰盆栽植物产值的第二位，人工栽培香龙血树的难度不高。　香龙血树的适应性较强，对土壤要求不严，但以疏松肥沃且排水良好的微酸性土壤生长最佳，可用松柏林下腐殖质含量高的壤土与河沙混合栽培，也可用腐叶土与河沙混合栽培。香龙血树在栽培的过程中，需要每月左右施用一次硫酸亚铁，可确保土壤的PH值适宜，呈微酸性，适宜其正常生长。　香龙血树喜欢蔬松肥饶，通透性好的基质，可采用无土培育的方法，进行栽培治理。基质可用、珍珠岩、泥炭土充分混合。这种基质，通透性好、干净、无菌无味。香龙血树且这种基质栽培在高级中，可以数年不翻盆、不换土、植株根系发达，生长健壮。无土栽培的肥水治理，主要是追施营养液。假如栽培数目少，可以不专门配制营养液。　香龙血树既喜欢暖和潮湿和阳光照射的环境，也能耐阴。但是，在室内莳养，若长时间置于过于荫蔽的环境，也会导致叶片退色。所以最好把花盆放在东南方向的窗台上，使之充分接受阳光的照射。假如肥香龙血树置于阳台上莳养，当夏季阳光过于强烈的时候，要把花盆移入室内，特别是中午，要适当进行遮荫，一般光照度为40－50％即可，以免骄阳灼伤叶片。香龙血树喜暖和，不耐寒冷。', '　　　　香龙血树常用扦插繁殖。5～6月选用成熟健壮的茎干，截成5～10厘米一段，平放在沙床上，保持25～30℃室温和80％的空气湿度，约30～40天可生根，50天可直接盆栽。也可将长出3～4片叶的茎干新芽剪下作插穗，插入沙床，保持高温多湿，插后30天可生根。还可用水插和高压法繁殖，但必须在25℃以上条件下进行。', 'http://img.boqiicdn.com/Data/BK/P/imagick20801445505540.jpg', 'http://www.boqii.com/entry/detail/2137.html', '');
INSERT INTO `plant_family` VALUES ('114', '金鸡菊', 'Coreopsis', '金鸡菊', '小波斯菊、金钱菊、孔雀菊', '不容易死', '原产美国南部', 'http://www.boqii.com/entry/photo/2143/0,http://www.boqii.com/entry/photo/2143/5384', '　　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '金鸡菊属', '', 'Coreopsis drummondii Torr。 et Gray', 'Coreopsis drummondii', '　　 　　金鸡菊为多年生宿根草本，叶片多对生，稀互生、全缘、浅裂或切裂。花单生或疏圆锥花序，总苞两列，每列3枚，基部合生。舌状花1列，宽舌状，呈黄、棕或粉色。管状花黄色至褐色。', '　　的花色为金黄色，非常吸引人，由于它对二氧化硫的抗性较强，所以非常适合种植在花坛、道路等绿化场所。金鸡菊的栽培难度不高，耐寒、耐旱，常常能够自行繁殖。　　种植金鸡菊最好是疏松、透气好、富含腐殖质的土壤。种植金鸡菊前需松土，雨后松土有利于金鸡菊根部呼吸，雨季每周除草一次。　　金鸡菊栽培容易，在种植后浇一次透水，以后控制浇水，防止。　　金鸡菊喜欢阳光直射，在过阴的环境中金鸡菊易徒长。近几居室短日照植物，短日照条件可以保证金鸡菊开花鲜艳。　　种植金鸡菊前，土壤可用腐叶作基肥（1Kg／m2），在金鸡菊期向开花期过渡时，要停止施肥，长出4花蕾后追肥。　　当金鸡菊长到6cm高时，需摘1次心，分枝10cm时摘第二次心，并且及时除柳芽。　金鸡菊常见的病害有白粉病、，时淋雨和土中有杂菌导致的，可用和托布津交替使用且每10天一次。金鸡菊常见的虫害有蚜虫、地老虎、蛴螬，可将氧化乐果、杀灭菊酯交替用且每10天一次。', '　　　　金鸡菊播种繁殖一般在8月进行，也可春季4月底露地直播，7－8月开花，花期延续到10月中旬。二年生的金鸡菊，在早春5月底6月初就会开花，花期延续到10月中旬。为了使金鸡菊多了开花，可以在花后摘除残花，7－8月追一次肥，10在国庆节时就可花繁叶茂。　　栽培治理比较简略，要求肥水恰当，不然易影响孕蕾开花，因而花期应中止施肥，避免枝叶徒长。花后应实时剪去花梗，以利基部萌生嫩芽，普通植株在栽植5一6年后进行更新。栽培时应留意：花期中止施肥，避免枝叶徒长而影响开花；花后实时剪去花梗，以利萌生株。', 'http://img.boqiicdn.com/Data/BK/P/imagick58161445591297.jpg', 'http://www.boqii.com/entry/detail/2143.html', '');
INSERT INTO `plant_family` VALUES ('115', '泥鳅掌', 'Senecio pendulus', '泥鳅掌', '地龙、初膺', '不容易死', '我国南方均有分布', 'http://www.boqii.com/entry/photo/2481/0,http://www.boqii.com/entry/photo/2481/4936', '　', '被子植物门', '双子叶植物纲', '菊目', '菊科', '千里光属', '泥鳅掌', 'Senecio pendulus', '', '　　 　　泥鳅掌的植株呈矮小的肉质灌木状，茎圆筒形，两头略尖，匍匐性，', '　　的外形奇特，比较少见，可以通过修剪做成不同的造型，受到很多花友的喜爱。泥鳅掌在夏季高温潮湿的会进入休眠或半休眠状态，这时应注意浇水量，并且适当遮阴，避免植株甚至死亡。　　泥鳅掌喜温暖和阳光充足，室内摆放时一定要有阳光照射。夏季休眠要节制浇水，平时施肥要谨慎。土中可混入较多的粗砂，盆面最好也要铺沙，有条件时直接栽在砂床中的比盆栽的好。冬季放室内阳光充足处，冬季最好维持10C以上，但如保持盆土干燥和阳光充足也能耐3—5℃的低温。平时水肥不宜过大，以土壤稍干燥为宜，施肥与否要求不严。　　因本种根系较浅，宜用浅盆栽种，并在盆土表面铺以砂砾或小石子。盆栽用土要求排水良好的沙壤土，土壤中可混入较多的粗砂。由于植株生长较快，对过密的株丛可随时疏去一些过密的茎段，以保持植株疏密有致，形态优美。', '　　　　人工繁殖泥鳅掌多用扦插。在', 'http://img.boqiicdn.com/Data/BK/P/imagick771454405017.jpg', 'http://www.boqii.com/entry/detail/2481.html', '');
INSERT INTO `plant_family` VALUES ('116', '木棉', '', '木棉', '攀枝花、红棉树、英雄树', '不容易死', '中国西南及台湾等省，越南、印度、缅甸、爪哇亦有分布', 'http://www.boqii.com/entry/photo/2010/0,http://www.boqii.com/entry/photo/2010/5517', '植物　　', '被子植物门', '双子叶植物纲', '锦葵目', '木棉科', '木棉属', '木棉', '', '攀枝花、红棉树、英雄树', '　　 　　木棉外观多变化：春天时，一树橙红；', '　　', '　　　\n　一、砧木的培育\n　　在攀枝花市地区，木棉种子4～5月成熟即可采收。由于种子含油量高，易变坏丧失萌发力，一般要求采后当年及时播种。苗床育苗采用条播和撒播，条播的行距20cm，深5cm，沟内点播种子。覆土2cm，表土盖草，播后6～7d开始发芽，13～15d基本出齐。幼苗出土后及时松土除草，并适当间苗除草，注意病虫害　\n　二、嫁接时间\n　　在攀枝花地区，宜选2～3月份和6～7月份嫁接木棉。2～3月份气温回升快，木棉开始萌动抽梢，此时嫁接易于成活。4～5月气温高，易导致接穗干枯。6～7月份是攀枝花地区雨季较集中时期，气温有所下降，嫁接时应避开雨天。　\n　三、选择接穗\n　　从已开花的木棉母树上选择两年生的生长健壮、充实、芽体饱满、无病虫害的当年未花枝条作接穗。要求所选的接穗径粗介于0.17cm～1.2cm，芽眼间距1～2cm。采集的取穗条要立即剪去叶片，以减少枝条的水分散失，并将枝条用湿　\n　四、嫁接方法\n　　木棉嫁接时采用单芽切接较好，试验发现无论接穗留几个芽，当第1个芽萌动抽梢后，其余芽眼萌发均受到抑制。嫁接时先削取接穗，方法是：在接穗上选定一饱满芽，并在反面下端0.15cm处起刀削微带或不带木质部的长度为1.5～2cm的平面，在反面削45°的斜断面，在芽上端1cm处截断，接穗长度4cm。对砧木苗要求在离地高15cm处剪砧，在砧木平滑面纵切一刀，长度115cm～2m，微带木质部为宜，把削好的接穗插入嫁接口，使两边形成层对齐密接，接穗上端露白。最后用塑料薄膜带由下而上捆扎密实，接穗芽眼处只包扎一层嫁接膜，易于嫁接成活后自动破膜。', 'http://img.boqiicdn.com/Data/BK/P/imagick85911441619210.jpg', 'http://www.boqii.com/entry/detail/2010.html', '');
INSERT INTO `plant_family` VALUES ('117', '紫鹅绒', 'Gynura aurantiana', '紫鹅绒', '紫绒三七、天鹅绒三七、土三七、橙黄土三七、红凤菊', '不容易死', '印度尼西亚等亚洲的热带地区', 'http://www.boqii.com/entry/photo/2237/0,http://www.boqii.com/entry/photo/2237/5290', '', '', '', '', '', '', '', '', '', '　　 　　紫鹅绒为常绿多年生草本　　　　　　　　　　　　　　　　　　', '　　为多年生草本，原产于亚热带地区，现在有很多花友将紫鹅绒制作成盆栽或吊盆种植，放在室内作为绿植装饰。如果紫鹅绒在栽培过程中光照不足的话，则会呈现绿色而不是我们常见的紫色。　　紫鹅绒盆栽要求基质富含腐殖质、疏松透气，一般可用1份园土、1份腐叶土及少量河沙混合配制。除在种植时加入少量腐熟基肥外，季每1－2个月施肥一次。施肥时注意多施磷钾肥，以利枝叶健壮充实；氮肥不宜过多，以免引起植株徒长，叶色淡化不鲜艳。它喜明亮的漫射光，忌阳光直射；但也不能过于阴暗，否则叶色褪绿、枝条生长纤细。一般以半阴或明亮的散射光为宜，以保持叶色和茸毛的光泽。生长季要满足枝叶快速生长之需给予较充足的水分。一般夏季高温每天浇水一次；春秋季2－3天浇一次水，平时保持盆土经常湿润即可。浇水时要注意不要向叶片直接喷水，否则茸毛全滞留水滴，容易引起叶片。　　另外，紫鹅绒在适宜的环境条件下，一般1－2个生长季即可长满盆，所以每年要结合繁殖，进行摘枝、换盆等工作，以保证株形良好。', '　　　　紫鹅绒繁殖容易，以扦插为主。常于4－6月结合翻盆、修剪进行。剪取长约10厘米的顶端枝梢作插穗，插后保持室温20-25℃、遮荫和较高的空气相对湿度，约15天可生根成活。在空气相对湿度较高时，植株常会在茎基部或匍匐', 'http://img.boqiicdn.com/Data/BK/P/imagick12101447924871.jpg', 'http://www.boqii.com/entry/detail/2237.html', '');
INSERT INTO `plant_family` VALUES ('118', '垂丝海棠', 'Malus Halliana Koehne', '垂丝海棠', '垂枝海棠', '不容易死', '中国江苏、浙江、安徽、陕西、四川和云南', 'http://www.boqii.com/entry/photo/2050/0,http://www.boqii.com/entry/photo/2050/5477', '植物　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '苹果属', '垂丝海棠', 'Malus Halliana Koehne', 'Malus Halliana', '　　 　　垂丝海棠为落叶小乔木，树冠疏散，枝开展。小枝细弱，微弯曲，圆柱形，最初有毛，不久脱落，紫色或紫褐色。冬芽卵形，先端渐尖，无毛或仅在鳞片边缘具柔毛，紫色。叶片卵形或椭圆形至长椭卵形，长3.5－8厘米，宽2.5－4.5厘米，先端长渐尖，基部楔形至近圆形，锯齿细钝或近全缘，质较厚实，表面有光泽。中脉有时具短柔毛，其余部分均无毛，上面深绿色，有光泽并常带紫晕。叶柄长5－25毫米，幼时被稀疏柔毛，老时近于无毛；托叶小，膜质，披针形，内面有毛，早落。', '　　在早春期间会开始开花，一般花色粉红，并且向下垂，非常特别。现在有很多花友会将垂丝海棠盆栽，但是地栽的依然非常多，小编就为你介绍一下垂丝海棠的栽培要点，垂丝海棠的朋友可以一起了解。　　1、土壤：土壤要求不严，微酸或微碱性土壤均可成长，但以土层深厚、疏松、肥沃、排水良好略带粘质的生长更好。　　2、阳光：垂丝海棠性喜阳光，不耐阴，爱温暖湿润环境，适生于阳光充足、背风之处。　　3、：生长适温为15～28摄氏度。地栽植株冬季能耐一150摄氏度的低温，盆栽能耐一5摄氏度的低温。夏季盆栽要适当遮阳，同时喷水增湿降温。冬季一般不须放进室内，将盆埋于土中即可。　　4、浇水：生长要有充足的水分供应，以不积水为准。春、夏应多浇水，夏季高温时早晚各浇一次水；梅雨期间及遇到久雨不晴要注意排水，防止盆内积水烂根；秋季减少浇水量，抑制生长，有利于。　　5、修剪：先剪掉弱枝，病枝，不良枝，主干上长出来的小枝。再看看有没有重叠枝，有的话适当剪掉。向上的枝条最好也剪掉，尽量让芽舒长开。太长了可以适当短截，留2～3个芽。', '　　　\n　一、扦插。\n　　扦插以采用春插为多，方法是惊蛰时在室中进行，先在盆内装入疏松的砂质土壤，再从母株株丛基部取12一16厘米长的侧枝，插入盆土中，插入的深度约为1／3至1／2，然后将士稍加压实，浇一次透水，放置遮荫处，此后注意经常保持土壤湿润，约经3个月可以生根。清明后移出温室，置背风向阳处。立夏以后视生根情况，若植株长至超过25厘米时，须进行摘心，10天后即施第一次追肥（熟透稀粪液）；夏至过后换一次盆；立冬时移入室内。若盆土干燥须浇些水，但勿过多。次年清明移出温室，不久即可绽蕾开花。　　夏插。夏插一般在入伏后进行。先选准母株株丛中中等枝条（基部已开始木质化的），剪取带2－3个叶的枝梢，插入盆土（如上法　　\n二、分株。\n　　分株方法简易，只须在春季3月问将母株根际旁边萌发出的小苗轻轻分离开来，尽量注意保留分出枝干的须根，剪去干梢，另植在预先准备好的盆中，注意保持盆土湿润。冬入室、夏遮荫，适当按时浇施肥液，2年即可开花。　\n　三、压条。\n　　压条在立夏至伏天之间进行，最为相宜。压条时，选取母株周围1－2个小株的枝条拧弯，压埋土中，深约12－16厘米，使枝梢大部分仍朗上露出地面。待来年清明后切离母株，栽入另一新盆中。', 'http://img.boqiicdn.com/Data/BK/P/imagick17371442483212.jpg', 'http://www.boqii.com/entry/detail/2050.html', '');
INSERT INTO `plant_family` VALUES ('119', '葱兰', 'Zephyranthes candida （Lindl.）Herb.', '葱莲', '玉帘、白花菖蒲莲、韭菜莲、肝风草', '不容易死', '南美各国，中国栽培广泛', 'http://www.boqii.com/entry/photo/2264/0,http://www.boqii.com/entry/photo/2264/5261', '　', '被子植物门', '单子叶植物纲', '百合目', '()科', '葱莲属', '葱莲', 'Zephyranthes candida （Lindl.）Herb.', '', '　　 葱莲 　　葱莲为多年生草本。鳞茎卵形，直径约2.5厘米，具有明显的颈部，颈长2.5－5厘米。叶狭线形，肥厚，亮绿色，长20－30厘米，宽 2－4毫米。花茎中空；花单生于花茎顶端，下有带褐红色的佛焰苞状总苞，总苞片顶端2裂；花梗长约1厘米；花白色，外面常带淡红色；几无花被管，花被片6，长3－5厘米，顶端钝或具短尖头，宽约1厘米，近喉部常有很小的鳞片；雄蕊6，长约为花被的1／2；花柱细长，柱头不明显3裂。', '　　很多朋友或许听到葱兰的名字就以为它是)，其实葱兰是石蒜科多年生草本，和兰科完全没有关系。葱兰在我们日常生活中是非常常见的，常会在花坛、路边看到它们的身影。　　葱兰多用于地被植物，或用于花坛、花边、林下，也有作盆栽栽培粗放。葱兰，喜肥沃的土壤，耐半阴或低温环境。以分株和播种为主，但要达到春季栽种下半年开花，分栽鳞茎把握最大。葱兰极易自然分球，分株繁殖容易，黄淮地区栽培需注意冬季应适当防寒。　　葱兰在期间浇水要充足，宜经常保持盆土湿润，但不能积水。天气干旱还要经常向叶面上喷水，以增加空气湿度，否则叶尖易黄枯。对肥水要求较多，但最怕乱施肥、施浓肥和偏施氮、磷、钾肥，要求遵循“量少次多、淡肥勤施、营养齐全”和“间干间湿，干要干透，不干不浇，浇就浇透”的两个施肥和施水原则，在施肥过后，晚上要保持叶片和花朵干燥。　　寒冷地区球根不能露地越冬，入冬前应收取鳞茎，稍晾干，用湿润细砂拌和入窑贮藏。栽培数年后应重新种植，以促其生长健壮。生长旺季应视长势酌情浇水、追肥。冬季可将鳞茎挖起贮藏。管理较粗放。葱兰还可在水箱中栽种，长出叶片鲜亮。进入8月份，株高已达30多厘米，这时可抽出几十个花茎，到9月下旬，开出白花。', '　　　　1、基质　　2、催芽：用温热水（温度和洗脸水差不多）把种子浸泡12～24个小时，直到种子吸水并膨胀起来。对于很常见的容易发芽的种子，这项工作可以不做。　　3、播种：对于用手或其它工具难以夹起来的细小的种子，可以把牙签的一端用水沾湿，把种子一粒一粒地粘放在基质的表面上，覆盖基质1公分厚，然后把播种的花盆放入水中，水的深度为花盆高度的1／2～2／3，让水慢慢地浸上来（这个方法称为“盆浸法”）；对于能用手或其它工具夹起来的种粒较大的种子，直接把种子放到基质中，按3×3公分的间距点播。播后覆盖基质，覆盖厚度为种粒的2～3倍。　　4、播种后的管理：在秋季播种后，遇到寒潮低温时，可以用塑料薄膜把花盆包起来，以利保温保湿；幼苗出土后，要及时把薄膜揭开，并在每天上午的9：30之前，或者在下午的3：30之后让幼苗接受太阳的光照，否则幼苗会生长得非常柔弱；大多数的种子出齐后，需要适当地间苗：把有病的、生长不', 'http://img.boqiicdn.com/Data/BK/P/imagick65321448617401.jpg', 'http://www.boqii.com/entry/detail/2264.html', '');
INSERT INTO `plant_family` VALUES ('120', '紫珍珠', 'Echeveria ', '紫珍珠', '纽伦堡珍珠', '不容易死', '', 'http://www.boqii.com/entry/photo/2124/0,http://www.boqii.com/entry/photo/2124/5403', '', '', '', '', '', '', '', '', '', '　　紫珍珠为景天科拟石莲属多肉植物，又名纽伦堡珍珠，由于紫珍珠的紫色比较特别，也使得紫珍珠更有观赏性。紫珍珠喜光照，耐旱、耐寒、耐阴，适应力非常强，没有明显的休眠期。 　　紫珍珠是一种拥有美丽的粉紫色叶片的多肉植物，叶缘呈白色。叶片呈莲座形螺旋排列。在光照充足且有较大　　　　　　　　　　　　　　　　　　　', '　　为中小型，非常适合做成盆栽饲养，但是紫珍珠也需要充足的光照，这样紫珍珠的颜色才会更加美观。紫珍珠的花型和大多数的石莲花一样，经过多年修剪的老桩会显得非常壮观。　　紫珍珠需要在通风的环境养护，否则容易生病。其生长适温15－25度，冬季不低于5度；生长期浇水干透浇透，空气干燥时可向植株周围洒水，但叶面，特别是叶丛中心不宜积水，否则会造成烂心；生长期施肥一般每20天左右一次。生长是春秋两季盆土完全干透后再浇水，夏季需要遮阴，减少浇水。冬季放于室内向阳处养护。　　紫珍珠生对水分的需求不多，生长期浇水干透浇透，夏季除遮荫，还要节制浇水，空气干燥时，可向植株周围洒水，不要向叶面和叶心浇水。冬季移入室内向阳处养护。介质可用泥炭、和珍珠岩的混合土，添加适量的骨粉。　　紫珍珠生长缓慢，植株属于中小型，直径可达二十到三十厘米。喜温暖、干燥和通风，又阳光充足的环境。耐旱、耐寒、耐阴，适应力较强，不耐烈日暴晒。　　紫珍珠无明显的，生长适温15－25摄氏度，冬季不低于5摄氏度，对水分的需求不多，生长期浇水干透浇透，夏季除遮荫，还要节制浇水，空气干燥时，可向植株周围洒水，不要向叶面和叶心浇水，以免腐烂。冬季将紫珍珠移入室内向阳处养护。配土一般用泥炭＋蛭石＋珍珠岩各一份，并添加适量的骨粉，也可用腐叶土3份、河沙3份、园土1份、炉渣1份混合配制。', '　　在多肉　　紫珍珠有扦插、分株，扦插分叶插和插穗，叶插将完整的成熟叶片平铺在潮润的沙土上，叶面朝上，叶背朝下，不必覆土，放置阴凉处，10天左右从叶片基部可长出小叶丛及新根，将根系埋入土中，往后让它多晒太阳，适当浇水、施肥，渐渐地便会长成一棵茁壮的新株，插穗可用单叶、蘖枝或顶枝，剪取的插穗长短不限，但剪口要干燥后，去掉下部叶片，再插入沙床，插后一般20天左右生根，插壤不能太湿，否则剪口易发黄', 'http://img.boqiicdn.com/Data/BK/P/imagick31751444902469.jpg', 'http://www.boqii.com/entry/detail/2124.html', '');
INSERT INTO `plant_family` VALUES ('121', '条纹十二卷', 'Haworthia fasciata （Willd.） Haw', '条纹蛇尾兰', '锦鸡尾，条纹十二卷', '不容易死', '非洲', 'http://www.boqii.com/entry/photo/2157/0,http://www.boqii.com/entry/photo/2157/5370', '　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '十二卷属', '', 'Haworthia fasciata （Willd.） Haw', 'Haworthia fasciata', '　　 　　条纹十二卷为多年生肉质草本。叶片紧密轮生在茎轴上，呈莲座状；叶三角状披针形，先端锐尖；叶表光滑，深绿色；叶背绿色，具较大的白色瘤状突起，这些突起排列成横条纹，与叶面的深绿色形成鲜明的对比。多年生肉质草本，无茎，基部抽芽，群生。根生叶簇生，多数，三角状披针形，先端细尖呈剑形，表面平滑，深绿色，北面横生整齐的白色瘤状突起。花葶长，总状花序，小花绿白色。园艺变型有大叶条纹十二卷，叶片大而宽，叶背瘤点多而散生；大型种，叶宽而下垂，叶背瘤点密集。', '　　又名雉鸡尾，这是由于条纹十二卷肥厚的三角状披针形叶片上镶嵌有带状白色新店花纹，非常像雉鸡尾上的羽毛。条纹十二卷的株型小巧，耐阴，是很理想的室内小型盆栽植物。　　条纹十二卷喜温暖干燥和阳光充足环境。怕低温和潮湿。以肥沃、疏松的沙壤土为宜。耐干旱，要求排水良好营养丰富的土壤。对的适应性较强，生长最佳温度为20－30℃之间，冬季越冬需要保持在10℃以上，低于5℃即进入休眠状态。冬季需充足阳光，但若光线过强，休眠的叶片会变红。高于30℃时生长会受到一定的影响，可稍增加些空气湿度，并增强通风。不能长期置于荫蔽处，否则不但生长受到抑制，条纹也会逐渐变得暗淡。夏季需要以半阴环境养护，避开强烈的光照，以防灼伤。冬季则需要充足的光照条件，光线不足易造成叶片退化、缩小，严重影响正常的生长。条纹十二卷不耐高温，夏季应适应遮阴，但若光线过弱，叶片退化缩小。　　条纹十二卷夏季有一段休眠期，此时要控制浇水，放疏阴条件下其安全度夏。平时养护放半光处，冬季放阳光充足地方。生长浇水要适量，盆土宜偏干。浇水过多、排水不良易引起根部腐烂。如因浇水不当根系已腐烂，要及时将植株从盆内磕出，剪除腐烂部分，略晾干后涂抹上木炭粉，再栽入沙质土内，喷少量水，经过一段养护又可重根。　　冬天盆土过湿，易引起根部腐烂和叶片萎缩。如发生可从盆内托出，剪除腐烂部分，稍晾干后，重新扦插入砂床，生根后再进行盆栽，或砂栽一段时间成活开始生长后换盆。　　它比较耐受干旱，不耐水湿，但绝对不是喜干旱，所以浇水应遵循干湿交替进行，浇水一定要浇透，在浇水时要注意盆土是否有缝隙漏水，要及时堵塞，否则即使是浇水很勤快，依然盆土不能浇透，长期下去必将有害。放于室外者，在雨季要防止雨水的冲洗，小雨是可以淋的，但大雨或连阴雨需要提防避免。冬季如果环境温度低于15℃，则需要保持一定的干燥状态，利于越冬。', '　　　\n　一、分株繁殖\n　　分株时间：最好是在早春（二、三月份）土壤解冻后进行。　　分株方法：把母株从花盆内取出，抖掉多余的盆土，把盘结在一起的根系尽可能地分开，用锋利的小刀把它剖开成两株或两株以上，分出来的每一株都要带有相当的根系，并对其叶片进行适当地修剪，以利于成活。　　分株装盆后灌根或浇一次透水。由于它的根系受到很大的损伤，吸水能力极弱，大约需要3～4周才能恢复萌发新根，因此，在分株后的3～4周内要节制浇水，以免烂根，但它的叶片的蒸腾没有受到影响，为了维持叶片的水分平衡，每天需要给叶面喷雾1～3次（温度高多喷，温度低少喷或不喷）。这段时间也不要浇肥。分株后，还要注意太阳光过强，最好是放在遮荫棚内养护。　\n　二、组培快繁\n　　1、材料：条纹十二卷茎根部幼芽（植物细胞具有全能性，即任何一个植物细胞都具有形成该植物体的能力。换言之，任何一个高度分化的细胞都具有回复到原始未分化细胞的能力，并且能分化为其他形式的高分化细胞。这种“全能性”就是植物组织培养的理论基础。依据植物细胞的这种特性，可以任意的培养植物体的任何一个高分化的细胞，而幼芽就是高分化的部位，所以选择之）。条纹十二卷　　2、培养条件：以MS为基本培养基。（　　从盆栽条纹十二卷母株茎根部切取生有4－5片幼叶的腋芽。流水冲洗5min，0.2％新洁尔灭浸泡30min，流水冲洗10min（这种方法比较节约水源，且污染率很低）。将材料至于超净台上用0.1％HgCl2消毒8min，无菌水冲洗10次，无菌滤纸吸干水份。用解剖刀切取芽部分，并将切下的幼叶分割成0.5cm的小块儿。接种到培养基中培养。　　3、芽培养：条纹十二卷的芽在培养基上迅速膨大并　　4、愈伤组织及芽　　5、根诱导及其转化：将幼叶截段放入D中培养一个月，在伤口处形成许多白色球状根系并不断增多。将这些根转入培养基中培养约一星期，根系转绿并有愈伤组织生出，在转入另一培养基中二星期后有球状胚体产生，有些胚体开始长出幼叶。　　6、继代增殖与快速繁殖：将得到的该种植物的离体繁殖系经过反复的分离和微扦插，即可达到几何数级的增殖，此过程就是所谓的快速微繁殖或者快速繁殖（Rapidpropagation）。植物快速繁殖通常是在离体繁殖系建成之后进行，有时也可以将愈伤组织进行快速增殖，此时通常采用液体悬浮培养。将上述得到的小苗丛或球状胚粗略分割，接于另一培养基中即可大量增殖，平均每两周增殖一倍。用一个芽作外殖体，两个月后已经得到20多瓶继代植株（每瓶约30株左右）。　　7、壮苗生根：将大苗接种于培养基E中，加强光照到10h／d，一星期后生根，再培养约一星期便可移栽。（当应用组织培养技术建成了某种植物的整体形态，即得到了有茎、根、叶的苗子，要经历一定的炼苗处理，使之逐步由无菌环境到有菌环境，由　　8、移栽：在出瓶前打开瓶口，炼苗两天。将有根的苗洗去培养基移于蛭石＋珍珠岩的无菌基质中，保持湿度，成活率高于90％。', 'http://img.boqiicdn.com/Data/BK/P/imagick74991446086489.jpg', 'http://www.boqii.com/entry/detail/2157.html', '');
INSERT INTO `plant_family` VALUES ('122', '臭牡丹', 'Glorybower', '臭牡丹', '大红袍、臭八宝、矮童子、野朱桐、臭枫草、臭珠桐', '不容易死', '河北、河南、陕西、浙江、安徽、江西、湖北云南、贵州、广东等地', 'http://www.boqii.com/entry/photo/2260/0,http://www.boqii.com/entry/photo/2260/5265', '植物　　', '被子植物门', '双子叶植物纲', '管状花目', '马鞭草科', '大青属', '臭牡丹', 'Clerodendrum bungei Sterd.', '', '　　 　　臭牡丹为灌木，高1－2米，植株有臭味；花序轴、叶柄密被褐色、黄褐色或紫色脱落性的柔毛；小枝近圆形，皮孔显着。叶对生，叶片纸质，宽卵形或卵形，长8－20厘米，宽5－15厘米，顶端尖或渐尖，基部宽楔形、截形或心形，边缘具粗或细锯齿，侧脉4－6对，表面散生短柔毛，背面疏生短柔毛和散生腺点或无毛，基部脉腋有数个盘状腺体；叶柄长4－17厘米。', '　　的外形非常漂亮，非常适合栽种在坡地、林下或树从旁，也可作地被。臭牡丹在我国分布非常广，并且也常用作药用植物，经济价值非常高。　　臭牡丹喜阳光充足和湿润环境，适应性强，耐寒耐旱，也较耐阴，宜在肥沃、疏松的腐叶土中。生于山坡、林缘或沟旁。分布于华北、西北、西南各省。主要用分株繁殖，也可用根插和播种繁殖。分株，在秋、冬季落叶后至春季萌芽前，挖取地上萌蘖株分栽即行。根插，梅雨将横走的根蘖切下插于沙土中，插后1－2周生根。播种，9－10月采种，冬季沙藏，翌春播种，播后2－3周发芽。生长期要控制根蘖扩展。保持土壤湿润，5－6月可施肥1次，并随时修剪过多的萌蘖苗。冬季将干枯的地上部割除，减少病虫。', '　　　　臭牡丹主要用分株繁殖，也可用根插和播种繁殖。分株，在秋、冬季落叶后至春季萌芽前，挖取地上萌蘖株分栽即行。根插，梅雨', 'http://img.boqiicdn.com/Data/BK/P/imagick27841448530875.jpg', 'http://www.boqii.com/entry/detail/2260.html', '');
INSERT INTO `plant_family` VALUES ('123', '梨花', 'Pear Blossoms', '梨花', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2045/0,http://www.boqii.com/entry/photo/2045/5482', '植物　', '', '', '', '蔷薇科', '梨属', '', 'Pear Blossoms', '', '　　 　　梨花在我国约有2000余年的栽培历史，', '　　很多朋友或许不清楚，梨树除了能够结出爽口的梨，其花卉的观赏价值也是非常高的。往往在春季开放，有的朋友们会分辨不清楚梨花和的区别。如果你对梨花有兴趣的话，可以跟着小编了解一下梨花的栽种要点。　　　栽植密度不同，栽植形式不同，所采用的树形，地上、地下管理措施也就不同，这样就形成了不同的栽培管理制度。最优的栽培管理制度应当是幼树期叶面积系数迅速增大，进入丰产期之后能维持较高的有效面积，而且应当方便管理。稀植的梨园，结果晚、见效慢。采用变化密度设计，就是采用永久植株和临时植株同时定植，666.6m栽植333株或111株比较好。永久行株距2m，行距5m：在永久行中间1m栽植2行临时行，株行距均为1m，这样666。6m可栽植333株。栽植三年见果，四年很容易超过1500公斤。若小行距2m，大行距4m，株距2m，666.6m可栽植111株。　　　　春季栽植的果园，要在头年秋季整地。永久植株挖直径1100厘米、深80－100厘米的定植穴。栽植密度较大、株距小的临时植株可以开50－60厘米宽、深60厘米的定植沟。挖穴、沟时不要打乱土层，表土放在一边，心土放在一边，回填时注意先将肥沃表土填在根际周围。每株需要施15－25千克土杂肥和50－100克氮素化肥。栽树时把表土和有机肥按3：1的比例混匀填在树苗根系附近。挖出的土回填到80％时就灌水沉实，等水渗下以后再整理。秋末冬初，要施好底肥，保障树体营养供给，确保树体的健壮，为来年丰产增收奠定基础。　　　　1、因地制宜，确定树形　　因梨树栽培地理环境不同和栽植方式不同而确定不同的树形。　　集约栽培用矮干整形，房前屋后庭园经济则可稍高定干。中国内地一般用疏散分层式，而福建、浙江及沿海一带，有些地方台风为害严重则采用棚架式，土质好的地区修剪不宜过重，山地丘陵则修剪要适当加重，同时在修剪口涂抹愈伤防腐膜，保护伤口愈合。　　2、因树造形，随枝修剪　　梨树多用疏散分层式和多主枝自然形两种。梨树极性强，分枝力弱，不一定按照人们的愿望形成理想的树形，只能因树造形，不能强求一致。否则，反而影响产量。　　3、主从分明，结构合理　　梨树干性强，要求有中央领导干。还要在中央领导千周围配备主枝，主枝上配备侧枝。中央领导干比主枝强，主枝比侧枝强，侧枝比生长在侧枝上的二级侧枝强，生长枝比结果枝强。各主枝均匀分布在主干四周，主枝之间生长要平衡。有两层主枝的，第二层与第一层的层间要有一定距离。第二层的两个主枝要安排在不影响第一层主枝光照的方向。　　4、既充分利用空间，又通风透光　　梨树直立性强，容易形成一把伞，影响通风和光照。梨树分枝力弱，又往往容易造成局部空虚。对空缺部位要用拉枝、侧芽分枝、刻伤等措施来弥补。对过密的枝叶要用开“窗户”的方法去解决。梨树对光照的要求较高，中国的砀山梨的品质，在甘肃比其原产地安徽的好，很重要的一个原因是西北地区的光照条件比安徽强。为解决光照，要求梨树下大上小，上不打伞，下不着地，上空下不空的疏散分层式。　　5、控上促下，控强扶弱　　梨树极性强，往往造成上大下小中空的形态，一定要注意控制上部，促下部生长。控制过强部分，扶持较弱部分，达到平衡生长。', '　　梨树对于土壤的适应能力很强，但是不同土壤的质量对于结出果实的品质会产生影响。一般，梨树多采用嫁接法进行繁殖，那么具体应该如何操作呢？　　常用的砧木有杜梨、山梨、豆梨、砂梨。梨树的矮化栽培是　　梨树绝大多数品种自花不结实，即使有些品种自花授粉有一定结实能力，但异花授粉可以结实更好，因此，梨园配置良好的授粉组合和足够授粉数量非常必要的。一般按照主栽品种与授粉品种3∶1，4∶1的比例为宜。　　栽植密度应考虑地力、品种。一般在土壤深厚肥沃、灌溉方便的平原，树体大，栽植应稀些，行株距2～4米×5～7米，亩栽株数23～66株。山地、沙荒、', 'http://img.boqiicdn.com/Data/BK/P/imagick17571442396763.jpg', 'http://www.boqii.com/entry/detail/2045.html', '');
INSERT INTO `plant_family` VALUES ('124', '矢车菊', 'Centaurea cyanus L.', '矢车菊', '蓝芙蓉、翠兰、荔枝菊', '不容易死', '德国的山坡、田野、水畔、路边、房前屋后到处都有它的踪迹。', 'http://www.boqii.com/entry/photo/2011/0,http://www.boqii.com/entry/photo/2011/5516', '', '', '', '', '', '', '', '', '', '　　 　　矢车菊的头状花序多数或少数在茎枝顶端排成伞房花序或圆锥花序。总苞椭圆状，直径1－1.5厘米，有稀疏蛛丝毛。总苞片约7层，全部总苞片由外向内椭圆形、长椭圆形，外层与中层包括顶端附属物长3－6毫米，宽2－4毫米，内层包括顶端附属物长1－11厘米，宽3－4毫米。全部苞片顶端有浅褐色或白色的附属物，中外层的附属物较大，内层的附属物较大，全部附属物沿苞片短下延，边缘流苏状锯齿。边花增大，超长于中央盘花，蓝色、白色、红色或紫色，檐部5－8裂，盘花浅蓝色或红色。　　　　　　　　　　　　　　　　　　　　　　　　　', '　　原产于欧洲，被奉为德国的国花，矢车菊不但可以观赏还能品尝，是一种很好的蜜源植物，并且还有一定的药用价值，可以说经济价值非常高。有的花友自己动手盆栽矢车菊，小编就为你整理了关于矢车菊的栽培方法及栽培过程中需要注意的一些问题，有需要的朋友可以一起了解。　　矢车菊喜阳光充足、凉爽气候、忌夏季炎热，宜肥沃疏松的土壤。因为直根性，宜直播。秋播为提早开花，可于冷床，矢车菊春末就可开花。矢车菊因不耐移植性，移栽时一定要带土团，否则不易缓苗。栽植成活后每隔10天或斗月施5倍水的腐熟人粪尿液一次，到第二年三月停止施肥以待开花。若盆栽，盆土要疏松肥沃，最用园土腐叶、草木要灰等配以混合土，当苗具6－7片叶时，进行第一次移植；以后，至少换到三筒盆中，因矢车菊为直根系，大苗不耐移栽。冬季可连续埋在土中，到3月上旬取出，施肥要勤，至花蕾出现时停止施肥。　　耐寒力强，在华东地区可露地栽植，华北地区要覆盖才能越冬；喜肥沃及疏松土壤；喜阳光充足；能自播；适应性强，易栽培。作切花栽培时，通常利用温室催花：8月播种，9月定植，翌年2月即可产花。关内暖地一般多在8－9月播种，露地覆盖越冬，第二年早春定植，初夏开花。东北地区在温室春播。由于矢车菊的根为直根性，侧根很少，故移栽要在小苗时带土进，苗大则不易成活，所以常常在春季直播。矢车菊也可以自播繁衍，此外矢车菊喜密植，否则反而生长不良。　　矢车菊性强健，较耐寒，喜阳光，要求肥沃、疏松、排水好的土壤。一般在9月份直播于苗床，华中以南地区可露地越冬，冬季不必防寒，于11月份或来年3月上旬移栽。华北地区秋播苗长出2～3片真叶时移植1次，入冬前进阳畦，冬天加盖防寒物，翌年早春定植于露地。定植前应施入基肥。因矢车菊为直根系，不耐移植，移植时必须带上较大的土团。矢车菊茎杆细弱，容易倒伏，因此定植距离不宜过密，要防止生长过密，通风不良而引起倒伏。幼苗期需打顶摘心，促使多分枝并使植株矮化，这样开花多，株形也优美。生长期每20天追施1次液肥，但应注意不宜多施氮肥，应适当多施些磷、钾肥，使茎杆坚挺，花色鲜艳。同时，浇水要适量，不可过多，雨季一定要注意及时排水，否则会造成烂根，影响植株的正常生长。', '　　　\n　一、播种繁殖：\n　　不耐移栽，定植时应带土球。栽植前应施基肥。生长期间适量浇水，防止烂根，每月追施一次液肥可促进生长。其茎秆纤弱，在苗期打顶摘心，促进多分侧枝及植株矮化。　　栽培要点：　　春秋均可播种，以秋播为好。9月中下旬播种在备好的苗床里，覆土以不见种子为度，稍加压实，盖上草、浇足水，经常保持土壤湿润，发芽后去盖草。待幼苗具6－7片小叶时，可移栽或定植，株距约30厘米，栽植成活后每隔10天或斗月施5倍水的腐熟人粪尿液一次，到第二年三月停止施肥以待开花。若盆栽，盆土要疏松肥沃，最用园土腐叶、草木要灰等配以混合土，当苗具6－7片叶时，进行第一次移植；以后生长，爱眇换到三筒盆中，因矢车菊为直根系，大苗不耐移栽。冬季可连续埋在土中　　\n二、播种方法：\n　　1、育苗：选疏松肥沃土壤作床，覆土约0.2厘米。　　2、栽培：待幼苗本叶发至6－7枚时移植，盆栽每13－17厘米盆植一株。幼苗定植后成活后，摘心一次，促使多分枝，能多开花，反之若分枝过多，必要时应摘去部分侧芽，可获得较大花朵。因为直根性，宜直播秋播露地覆盖越冬，初夏开花，如冷床越冬可于春末开花，春播应尽早播种。6月份开花。　　3、用土：较喜爱疏松肥沃、排水性佳的砂质壤土。栽培土应尽量使其排水及通气良好，土壤若黏性较重时，可混合3－4成的蛇木屑或珍珠石来改良。　　4、浇水：浇水原则上每日一次即已足够，但夏日较干旱时，可早晚各浇一次，以保持盆土湿润并降低盆栽的温度，但忌积水。　　5、施肥：矢车菊喜多肥，　　6、开花期管理：矢车菊能自然侧枝，侧枝多则花朵较小，必要时可摘去部分侧芽，只留较小的分枝，则可获得较大的花朵。矢车菊乃长日性植物，冬季时日照', 'http://img.boqiicdn.com/Data/BK/P/imagick70311441619512.jpg', 'http://www.boqii.com/entry/detail/2011.html', '');
INSERT INTO `plant_family` VALUES ('125', '时钟花', 'Turnera ulmifolia', '时钟花', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2295/0,http://www.boqii.com/entry/photo/2295/5229', '', '', '', '金虎尾目', '时钟花科', '时钟花属', '', 'Turnera ulmifolia', '', '　　 　　时钟花的形状很像时钟上的文字盘 ，花萼和花冠结合成筒状；果实为蒴果，种子有网状纹。', '　　的外形非常像时钟上的文字盘，故此命名。时钟花的习性也非常特别，其花开花谢非常有规律，但是时钟花是生长在南美洲热带雨林中的，所以人工栽培时钟花的难度较大，如果你收到了时钟花，它代表了什么意思呢？小编就为你分析一下时钟花的花语。　　　时钟花献给了公元十三世纪为了救济贫穷而成为修女的汉堡公主，她的一举动都比一般人高贵，因此，时钟花的花语是高贵。受到时钟花祝福而生的人，天生具有高贵的气质，对于感情被动而且消极。也许听父母或亲戚的劝告，经由相亲而结婚，会比较幸福。　　　时钟花的花朵形状就像时钟上的文字盘，所以被称为“时钟花”。时钟花如同时钟一般每天在同一开放，踏实，稳健，因此，时钟花的花语是踏实。受到这种时钟花祝福而生的人，决定一件事情，常会花费相当长的时间去沉思。虽然深思熟虑可减少错误，但是当你遇到自己喜爱的人时，稍微轻率一下也无妨。', '　　　　时钟花的花开花谢非常有规律。早上开晚上闭，更有意思的是，它的花几乎同开同谢，奇特无比。有研究表明，时钟花的开花规律与日照、温度的变化密切相关，同时受内在体内一种物质——时钟酶的控制。　　这种酶调节着时钟花的', 'http://img.boqiicdn.com/Data/BK/P/imagick51761449480717.jpg', 'http://www.boqii.com/entry/detail/2295.html', '');
INSERT INTO `plant_family` VALUES ('126', '黄兰', 'Michelia champaca Linn.', '黄兰', '黄玉兰、黄缅桂、大黄桂、黄葛兰', '不容易死', '', 'http://www.boqii.com/entry/photo/2326/0,http://www.boqii.com/entry/photo/2326/5196', '', '', '', '', '', '', '', '', '', '　　黄兰为常绿乔木，花期为6－7月。黄兰在中国、印度、尼泊尔等国均有分布，是非常着名的观赏树种。黄兰对于有毒气体的抗性较强，观赏价值也比较高。 黄兰 　　黄兰是常绿乔木　　　　　　　　　　　木兰科　　　　　　　', '　　是非常着名的观赏花卉，在我国南方地区可露地栽种，作为行道树来装点环境是非常好的，但是在我国北方黄兰只能温室地载或盆栽。此外，黄兰还可以作为切花，也是非常漂亮的。　　黄兰喜微潮偏一F的土壤环境，在定植后浇透水一次。在树苗新叶前，应该加强浇水管理，不宜使土壤干燥。以后只要不是土壤过干，基本可以利用自然降雨供水。除在定植前给植株施用腐叶作为基肥外，在生长旺盛季节里，还应每周追施一次富含氮、磷、钾的液体肥料。在整个生长过程中，应该保证有适当的直射日光，每天接受直射日光不宜少于4小时，避免环境荫蔽。应该保持环境通风，这样以利光合作用顺利进行。黄兰喜温暖，忌严寒，在20－30℃的范围内生长较好，温度不宜低于5t，可耐短期的0℃低温。应该随时剪去黄兰的病弱枝、千枯枝、细弱枝。在实际栽培中，黄兰会被根霉病、等，易受刺蛾、褐软蚜、蜻类等有害动物的侵袭。', '　　　　黄兰繁殖以播种为主，也可嫁接。种子刚开裂而出现红色时应及时采收，采后沙藏至翌年春播。播后一般1个月左右开始发芽，但也有近2个月才发芽的。幼苗移植宜在傍晚或阴天进行，移植后应搭荫棚遮荫，待植株长高后逐渐拆棚。一年生实生苗最高可达40～50厘米，树冠可达40厘米，比嫁接苗', 'http://img.boqiicdn.com/Data/BK/P/imagick23941450172150.jpg', 'http://www.boqii.com/entry/detail/2326.html', '');
INSERT INTO `plant_family` VALUES ('127', '星乙女', 'Crassulaperforata ssp. kougaensis', '钱串景天', '', '不容易死', '南非', 'http://www.boqii.com/entry/photo/2420/0,http://www.boqii.com/entry/photo/2420/4995', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '青锁龙属', '钱串景天', 'Crassulaperforata ssp. kougaensis', '', '　　 　　星乙女为多年生肉质草本植物，植株呈亚灌术状高约60厘米，具小分枝，茎肉质以后稍木质化。肉质叶灰绿至浅绿色，叶缘稍具红色，交互对生，卵圆状三角形，无叶柄，基部连在一起，幼叶上下叠生，战叶上下有少许间隔。叶长1.5~2.5厘米，宽0.9~1.3厘米，花白色，4~5月开放。', '　　星乙女的株型奇特，小巧可爱，是很多多肉爱好者喜欢栽种的，现在很多人更喜欢将其称为)。星乙女的栽培难度并不高，具有冷凉生长，夏季高温休眠的习性，为多肉植物中典型的“冬型种”植物。　　星乙女生长期宜保持土壤湿润，避免积水，否则会造成植株根、基部腐烂。每15天左右施一次腐熟的稀薄液肥，以促进植株的生长。　　冬季放在室内阳光处，如果能维持10℃以上，可继续浇水，酌情施些肥，使植株继续生长；如果保持不了这么高的，控制浇水，使植株休眠，也能耐5℃左右的低温。　　夏季高温时植株或完全停止，可放在通风良好处养护，适当遮光，避免烈日曝晒，并停止施肥，节制浇水，也不要长期雨淋，以免植株腐烂。　　星乙女在栽培中应经常修剪，剪去过乱的枝条，以保持株形的优美。当植株生长过于拥挤时可在春季或秋季换盆，种植盆应根据植株的大小进行选择，花盆过大或过小都不利于其生长。　　此外，还要考虑花盆的美观性。盆土要求疏松肥沃，具有良好的排水透气性，可用腐叶土、园土、粗砂或蛭石混合土栽种。', '　　星乙女的栽培难度并不高，但是需要给予充足的光照，不然星乙女很容易出现徒长的情况。星乙女的繁殖一般在秋天到翌年的春天进行，这个　　\n1、茎插：\n　\n  2、叶插：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick22431452677246.jpg', 'http://www.boqii.com/entry/detail/2420.html', '');
INSERT INTO `plant_family` VALUES ('128', '彩叶凤梨', '', '彩叶凤梨', '贞凤梨', '不容易死', '', 'http://www.boqii.com/entry/photo/2298/0,http://www.boqii.com/entry/photo/2298/5226', '　', '被子植物门', '单子叶植物纲', '', '凤梨科', '', '', '', '', '　　 ', '　　的栽培难度并不高，非常适合在室内盆栽，作为插花、瓶景欣赏都非常好。彩叶凤梨在开花前内轮叶会变成红色，并且可持续数月之久，非常漂亮。　　1、土壤：彩叶凤梨土应具有良好的保水性和透气性，宜选用泥炭土、树橛碎片、煤屑渣等物，能满足调节水分和通气的要求。　　2、浇水：彩叶凤梨属于好湿性的气生凤梨，在日常中要特别重视浇水。夏季炎热，蒸发量大，每天都得浇透水，保持叶基部水分不中断；冬天适当控制浇水，叶筒底部保持湿润即可。　　3、阳光：彩叶凤梨喜光照，叶片在充足的光照下更艳丽，但夏季要避免强阳光直射，以免灼伤叶片。一般先在较强的阳光下培养出具有美丽色彩的叶片，然后放明亮的室内欣赏。光线过暗，会使叶片色彩变淡。　　4、温度：彩叶凤梨最适宜温度为22－25℃，冬季应放在温度为15℃以上的室内，低于15℃停止生长，长期低于10℃会受冻害。　　5、施肥：彩叶凤梨生长每半月施1次复台花肥或化学液肥，以叶面喷施效果好。但要切忌浓度过高，以免肥料累积在植株茎部而侵害叶片。', '　　彩叶凤梨属于好湿性的气生凤梨，所以人工栽种彩叶凤梨应注意浇水问题。如果你的彩叶凤梨长到一定程度了，那么不妨自己动手繁殖一株新的彩叶凤梨。　　彩叶凤梨多采用分株法繁殖。夏季一般会从植株基部长出几个蘖芽。待蘖芽长出6片叶后，应适时切下，扦插于沙床，插后20天即可生根，40天即可上盆。　　彩叶凤梨为附生', 'http://img.boqiicdn.com/Data/BK/P/imagick28331449567736.jpg', 'http://www.boqii.com/entry/detail/2298.html', '');
INSERT INTO `plant_family` VALUES ('129', '小红衣', 'Echeveria ‘Vincent Catto’', '小红衣', '新版小红衣、小红莓、文森特卡托', '不容易死', '', 'http://www.boqii.com/entry/photo/2425/0,http://www.boqii.com/entry/photo/2425/4990', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科 Crassulaceae', ' Echeveria', '', 'Echeveria ‘Vincent Catto’', '', '　　 　　小红衣的小叶片呈莲座状紧密排列，叶片呈微扁的卵形，叶尖两侧有突出的薄翼。强光下，叶缘和叶尖会呈现出漂亮的红色。', '　　小红衣为小型种，但是栽培难度比较大，所以在市场上价格也比较昂贵。栽培小红衣的花友们一定不希望自己的小红衣被养死，所以如何养好小红衣就成为了许多多肉爱好者都关心的', '　　　　小红衣殖方式以分株扦插为主，也可以尝试播种繁殖。小红衣容易群生，繁殖方法有播种和分株、砍头。一般用分株法繁衍。小红衣', 'http://img.boqiicdn.com/Data/BK/P/imagick69111452762428.jpg', 'http://www.boqii.com/entry/detail/2425.html', '');
INSERT INTO `plant_family` VALUES ('130', '神想曲', 'Adromischus poellnitzianus', '神想曲', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2455/0,http://www.boqii.com/entry/photo/2455/4961', '', '', '', '', '', '', '', 'Adromischus poellnitzianus', '', '　　 　　神想曲，叶子比天章叶子长，叶先端无波纹，茎褐色被密生的气生根包裹，姿态奇特。不开花。', '　　', '　　　　神想曲喜阳光充足和凉爽、干燥的环境，无明显休眠期。几乎全年都在生长的品种，对日照需求不多，忌暴晒，可半阴养殖，散光养殖也能生长的很好。对水分要求不多，水分过多容易涝死。神想曲很容易群生，繁殖可用叶片进行扦插，繁殖方法主要是叶插。除夏季高温外，10度以上均可进行，选取健壮、充实的叶片，晾1～2天后，平放在土壤上，不久就会生根、发芽，但不宜过早移栽。', 'http://img.boqiicdn.com/Data/BK/P/imagick83701453800257.jpg', 'http://www.boqii.com/entry/detail/2455.html', '');
INSERT INTO `plant_family` VALUES ('131', '芙蓉葵', 'Hibiscus moscheutos', '芙蓉葵', '草芙蓉、大花秋葵', '不容易死', '原产北美', 'http://www.boqii.com/entry/photo/2355/0,http://www.boqii.com/entry/photo/2355/5061', '　', '被子植物门', '双子叶植物纲', '', '锦葵科', '木槿属', '芙蓉葵', 'Hibiscus moscheutos Linn.', 'Hibiscus moscheutos', '　　 　　芙蓉葵为多年生草本，高1～2m，茎亚冠木桩，粗壮，丛生，斜出，光滑被白粉。单叶互生，叶长8～22cm，叶背及柄生灰色星状毛，叶形多变。基部圆形，缘具梳齿。花大，直径28cm，单生茎上不叶腋，花色', '　　原产北美，现在在我国分布较广，是华北地区常见的额夏秋。芙蓉葵对土壤的要求不严，但是想要养出漂亮的芙蓉葵还是需要根据其习性进行栽培。　　芙蓉葵适应性较强，耐寒，耐旱，在较湿润的条件下能良好。北至营口、南至，均较好。极耐高温和曝晒，在北京地区36℃和烈日之下，开花旺盛，是北京旺夏的一种有希望的宿根花卉。　　芙蓉葵对土壤要求不严。但以较疏松的沙壤土较好。在碱性过强的土壤里，易患缺铁症。对土壤肥力水平要求不高，在新垫土地上连作三年不施放任何基肥、追肥的情况之下，仍能正常生长和开花。　　每次开花过后，应及时修剪，把上次开花后的空枝及形成的种子剪除，这样可以增加下一个开花高峰的花量，尤其第二高峰过后，更应及时修剪保证下一次花的量与质。如任其自然生长，后期花量也相应减少。', '　　　　1、播种繁殖：芙蓉葵适合在5月上旬露地直播，芙蓉葵种皮紧硬，播种前需将种子用55℃温水浸种10至15小时后再播种，种子播下后，要保持土壤湿润，大约1至2周就会被发芽，。当芙蓉葵长至3至4片真叶时即可移栽。　　2、分株繁殖：分株繁殖可在春、秋两季进行，将芙蓉葵老株上茎芽带根切下栽培，分株繁殖容易成活，芙蓉葵当年就可开花。　　3、扦插繁殖：在芙蓉葵生长期间，取半木质化的枝条，插入湿润沙壤土中，并保持湿润，约一个月芙蓉葵就可以生根。', 'http://img.boqiicdn.com/Data/BK/P/imagick9331450864206.jpg', 'http://www.boqii.com/entry/detail/2355.html', '');
INSERT INTO `plant_family` VALUES ('132', '美叶光萼荷', 'Aechmea fasciata', '美叶光萼荷', '美叶尖萼荷', '不容易死', '', 'http://www.boqii.com/entry/photo/2283/0,http://www.boqii.com/entry/photo/2283/5242', '　　', '被子植物门', '百合纲', '凤梨目', '凤梨科', '光萼荷属', '美叶光萼荷', 'Aechmea fasciata', '', '　　 　　多年生附生常绿草本植物。叶基生，莲座状叶丛基部围成筒状，可以贮水。叶条形至剑形，长可达45－70厘米以上，革质，被灰色鳞片，绿色，有虎纹状银白色横纹，边缘有黑色小刺。花葶直立，花序穗状，密集成阔圆锥状球形花头。苞片革质，先端尖，淡', '　　美叶光萼荷的叶基生，呈连座状叶丛基部围成筒状，可以储水，是比较常见的园艺品种。美叶光萼荷喜欢阳光充足的环境，也耐阴，人工栽培的难度并不高，小编就为你详细介绍一下美叶光萼荷的栽培要点。　　美叶光萼荷较喜光，但又怕强光直射。夏季需遮去50％～60％的阳光，冬季可不遮光。室内栽培时应放在充分照光而又远离阳光直射的地方。夏季宜放在北窗附近；春、秋两季放东窗附近；冬季放在朝南窗台上，使其充分接受光照，以保持叶色更加鲜绿，花色更加亮丽。如果长期放在光线阴暗处，就会使叶片失去花纹和光泽。　　生长适温为18～22℃，开花季节不得低于18℃。不耐寒，越冬适温为白天20℃以上，夜间12～15℃。温度过低会导致植株腐烂。应注意避免日夜温度相等或夜间温度高于白天。　　生长季节可大量浇水，但盆土不能积水，否则植株会腐烂。夏秋干旱季节应使莲座中央的“贮水筒”中保持有水，但每隔半月左右要用清水冲洗更换，保持水分新鲜。，若室温达到22℃左右，“贮水筒”里可留些水，但在16～18℃时，筒内不宜存水。相对湿度一般为50％～60％。高温季节要向植株叶面上喷水以提高空气湿度。　　每年4～9月为生长旺盛期，应每月施一次液肥，通常用发酵的有机肥或氮磷钾全肥。也可向叶片正反面上喷施0.1％尿素加0.2％磷酸二氢钾溶液，或向叶筒内灌些极稀薄的液肥（其浓度比正常追肥浓度稀释3～5倍），既利于吸收，又节省。　　盆栽宜选用疏松的腐叶土或褐泥炭土为主，加入少量河沙、蛭石配制的土。盆栽时底部1／4填充颗粒状的排水物，以利根部透气和排水。如能在盆底放入少量腐熟鸡粪、饼肥末或骨粉作基肥则长势更好。幼嫩植株每年换一次盆。', '　　　\n　1、播种繁殖：\n　\n　2、分株繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick85181449133648.jpg', 'http://www.boqii.com/entry/detail/2283.html', '');
INSERT INTO `plant_family` VALUES ('133', '桂花', 'Sweet Olive', '桂花', '岩桂、木犀、九里香、金粟', '不容易死', '', 'http://www.boqii.com/entry/photo/1921/0,http://www.boqii.com/entry/photo/1921/5608', '', '', '', '', '', '', '', '', '', '　　 　　　　　　　　　　　　　　　　　　　', '　　我们常说“八月香”，但我们能够感受到桂花香的时候却一般为9－10月，其实这里说的八月指的是农历。桂花的作用有很多，不但可以观赏，还能够食用，桂花酒、糖桂花都是对人体非常有益的食品。那么桂花应该如何栽培呢？小编就为你介绍一下桂花栽培过程中需注意的一些问题。　　　　桂花喜温暖环境，宜在土层深厚，排水良好，肥沃、富含腐殖质的偏酸性砂质壤土中生长。不耐干旱瘠薄，在浅薄板结贫瘠的土壤上，生长特别缓慢，枝叶稀少，叶片瘦小，叶色黄化，不开花或很少开花，甚至有周期性的枯顶现象，严重时桂花整株；它喜阳光，但也有一定的耐阴能力。桂花适宜栽植在通风透光的地方；桂花喜欢洁净通风的环境，不耐烟尘危害，受害后往往不能开花；　　　桂花的浇水主要在新种植后的一个月内和种植当年的夏季。新种植的桂花一定要浇透水，有条件的应对植株的树冠喷水，以保持一定的空气湿度。桂花不耐涝，及时排涝或移植受涝害植株，并加入一定量的种植，可促进新根生长。　　　桂花喜肥，需加强追肥，4～5月，每半月左右施一次，6～7月，每隔7～10天施肥一次。8月初施最后一次，这样桂花不但生长茂盛，开花多而且香。可用腐熟的饼肥水，鸡鸭鸽粪，鳞水，过磷酸钙以及骨粉等等，如果施肥不足，则会枝少，花儿也少，而且不香。　　　　桂花根系发达，萌发力强，成年的桂花树，每年抽稍两次。因此，要使它花繁叶茂，应保持生殖生长和营养生长的生理平衡，就必须进行适当的整形与修剪。中秋后，将夏，秋季生出的徒长枝全部剪去，留下健壮的春生枝条，到明春发芽之前，再将细弱枝，密生枝，病虫枝等剪去。这样，既有利于通风透光，又能将养分完全集中到春生枝与花芽之上，为秋季开花创造了良好的先决条件，可以收到“一举数得”之效了。', '　　　　\n一、播种繁殖：\n压条繁殖可分为高压繁殖和低压繁殖，高压繁殖是在春季时从母树上选取1—2年生的粗壮枝条，选易弯曲部位用刀切割或环剥，深度要达到木质部，然后压入3～5cm深的条沟内，并用木条固定被压枝条，仅留梢端和叶片在外面。低压繁殖时间是春季至夏季，选取比较粗壮的低干母树，必须要选用低分枝或丛生状的1—2生的母株，同高压法切割一圈或者是环剥。在培养过程中，始终保持基质湿润，到秋季发根后，剪离母株　\n　三、嫁接繁殖：\n　\n　四、扦插繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick25651438940297.jpg', 'http://www.boqii.com/entry/detail/1921.html', '');
INSERT INTO `plant_family` VALUES ('134', '千日红', 'Gomphrena globosa L.', '千日红', '火球花、百日红', '不容易死', '热带和亚热带地区', 'http://www.boqii.com/entry/photo/2289/0,http://www.boqii.com/entry/photo/2289/5235', '', '', '', '', '', '', '', '', '', '　　 　　一年生直立草本，高20－60厘米，茎粗壮，有分枝，枝略成四棱形，有灰色糙毛，幼时更密，节部稍膨大。叶片纸质，长椭圆形或矩圆状倒卵形，长3.5－13厘米，宽1.5－5厘米，顶端急尖或圆钝，凸尖，基部渐狭，边缘波状，两面有小斑点、白色长柔毛及缘毛，叶柄长1－1.5厘米，有灰色长柔毛。　　　　　　　　　　　　　　　　　　', '　　的栽培难度并不高，对于环境的要求也不严，但是千日红性喜阳光、炎热干燥的气候，所以人工栽培的过程中需要注意为千日红提供一个阳光充足的环境。　　千日红为阳性，除幼苗阶段，不宜阳光直射，上盆后2～3周便可在阳光充足的环境生长。光照充足，有利形成圆整、低矮的株形，栽培过程中必须注意保持足够的株行距，以免相互拥挤，缺乏光照而株形不佳。　　千日红栽培的中心是培育出良好的株形，宜以保持阳光充足、采用矮壮素、负的DIF值（昼温减夜温值2～3℃）等措施达到目标。此花卉耐热，但不耐寒，经不住霜冻。　　盆栽千日红上盆后要保持湿润，并注意遮荫。生长期结合浇水进行追肥。此花对肥水、土壤要求不严，管理可较粗放。残花谢后进行整枝修剪，仍能萌发新枝，于晚秋再次开花，但须多施薄肥。', '　　　　千日红播种一般选择春播。春3月至4月播于露地苗床，播种前要先进行浸种　　千日红繁殖主要用播种法：4一5月播种于露地苗床，如3月：至4月初播种，由于气温不高、发芽不良、生长较慢，发芽　　千日红种子发芽比较困难，以用温水浸种半天，然后播种，持', 'http://img.boqiicdn.com/Data/BK/P/imagick89031449222007.jpg', 'http://www.boqii.com/entry/detail/2289.html', '');
INSERT INTO `plant_family` VALUES ('135', '玉吊钟', 'Kalanchoe fedtschenkoi ', '玉吊钟', '洋吊钟、蝴蝶之舞', '不容易死', '原产马达加斯加岛干燥、阳光充足的热带地区', 'http://www.boqii.com/entry/photo/2181/0,http://www.boqii.com/entry/photo/2181/5347', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '伽蓝菜属', '玉吊钟', 'Kalanchoe fedtschenkoi \'Rosy Dawn\'', 'Kalanchoe fedtschenkoi', '　　 　　玉吊钟为多年生肉质草本植物，株高20～30厘米，分枝较密，叶交互对生，肉质叶扁平，卵形至长圆形，长2.5～4厘米，宽2～3厘米，边缘有齿，叶蓝绿或灰绿色，上面有不规则的乳白、粉红、黄色斑块，极富变化，新叶更是绚丽多姿、五彩斑斓，是多肉植物中的观叶佳品，非常美丽。松散的聚伞花序，小花红或橙红色。', '　　玉吊钟又名变叶景天，是比较常见的多肉', '　　　　1、介质：素砂、　　2、枝条的选择，选用肥厚充实的顶端茎，剪取10－12厘米长；如果是叶插，取肥厚叶片即可。　　3、具体操作，枝条和叶片都要在阴凉处晾一下，让伤口愈合然后再扦插如介质中。　　4、扦插　　玉吊钟在扦插过程中，要尽量保持土壤的潮湿，但是不要过湿，不要阳光暴晒，散光即可。', 'http://img.boqiicdn.com/Data/BK/P/imagick66941446629050.jpg', 'http://www.boqii.com/entry/detail/2181.html', '');
INSERT INTO `plant_family` VALUES ('136', '小球玫瑰', 'Phedimus. spurius ', '小球玫瑰', '龙血景天', '不容易死', '格鲁吉亚（高加索地区）、伊朗北部、土耳其东北部等地', 'http://www.boqii.com/entry/photo/2094/0,http://www.boqii.com/entry/photo/2094/5433', '　　', '', ' 双子叶植物纲', '蔷薇目', '景天科', '费菜属', '小球玫瑰', 'Phedimus. spurius \'Schorbusser Blut\'', '', '　　小球 　　小球玫瑰这个', '　　的生命力非常顽强，耐寒冷、耐干旱，适应力比较强，并且休眠不明显。由于小球玫瑰的外形娇小，是很多多肉爱好者收集的。小编就为你介绍一下小球玫瑰的栽培要点，喜欢的朋友可以一起了解。　　　小球玫瑰喜温暖干燥和阳光充足的环境，所以要给予足够的光照，若光照不足，水分过多，会引起小球玫瑰节茎伸长，叶片疏散，变绿，有负龙血之名，充分的光照及合适的温差巨大会使小球玫瑰变为血红色，株型也会保持得很漂亮，不逊色于玫瑰。　　　盆土尽量疏松透气，可泥炭土与颗粒土3比2的比例配制，　　　夏季尽量遮荫降温，给极微量的水，甚至断水，若给水应在傍晚时分。其他浇水可不干不浇，浇则浇透，适量的少浇水，可以让小球玫瑰更玫瑰。', '　　小球　　小球玫瑰一般选用枝插的方式。小球玫瑰随着生长，会有基部叶片脱落使茎干变长，可对此类枝条进行修剪，促进其再度分枝生长，剪下的枝条可用来枝插，非常易成活，繁殖的　　小球玫瑰随着生长，会有基部叶片脱落使茎干变长，可对此类枝条进行修剪，促进其再度分枝生长，剪下的枝条可用来枝插，非常易成活，繁殖的季节尽量避开寒冬酷暑。　　如果收到的花很干了，还没死就放到水里泡一个晚上，第二天拿出来，把顶端的4厘米长的花枝剪下来，然后用小镊子插到土里，浸盆，拿到有阳光的地方养就可以了。这样的方法很容易救活，小球玫瑰是非常', 'http://img.boqiicdn.com/Data/BK/P/imagick11211444295692.jpg', 'http://www.boqii.com/entry/detail/2094.html', '');
INSERT INTO `plant_family` VALUES ('137', '非洲紫罗兰', 'Saintpaulia ionantha Wendl', '非洲紫罗兰', '非洲堇、非洲苦苣苔、非洲紫苣苔、圣包罗花', '不容易死', '非洲东部', 'http://www.boqii.com/entry/photo/2383/0,http://www.boqii.com/entry/photo/2383/5033', '　　', '被子植物门', '双子叶植物纲', '管状花目', '苦苣苔科', '非洲紫罗兰属', '', 'Saintpaulia ionantha Wendl', 'Saintpaulia ionantha', '　　非洲 　　非洲紫罗兰全株有毛；叶基部簇生，稍肉质，叶片圆形或卵圆形，背面带紫色，有长柄。花1朵～6朵簇生在有长柄的聚伞花序上；花有短筒，花冠2唇，裂片不相等，花色多样，有白色、紫色、淡紫色或粉色。蒴果，种子极', '　　的植株娇小，非常适合盆栽。由于非洲紫罗兰为半荫性植物，所以每天以8小时光照为合适，夏季光照太强则需遮阳防护。小编就为你介绍一下非洲紫罗兰的栽培要点。　　一般选择泥炭、蛭石、珍珠岩；我一直只选用蛭石栽培，保，易生根，好管理。　　干透再浇。非洲紫罗兰喜湿润环境，但忌积水。　放置在南向阳台东侧，花架最底层，阳光不直晒，只有傍晚时有余晖斜射，光线不是很强。　非洲紫罗兰叶片繁多，容易造成拥挤遮挡；特别是花蕾初上时，繁多的叶片会遮挡花蕾的；这时候可以适当的摘除拥挤的叶片（摘下来的叶片可以扦插繁殖），以利于通风和透光。　　我所有的都是用马掌，非洲紫罗兰我没有给肥，如果大家要施肥的话，建议多用磷钾肥，少用氮肥，防止叶片徒长，施肥以薄肥勤施为宜。　　不要放在太阳趋向之处，只要室内有散射光都可以生长，非洲紫罗兰是很耐阴的室内植物，反面不适合室外种植，最好的位置是放在窗台边。', '　　非洲　\n　一、叶插法\n　　非洲紫罗兰常用扦插繁殖法，主要进行的是叶插，花后选用健壮充实叶片，叶柄留2厘米长剪下，稍晾干，插入沙床，保持较高的空气湿度，室温为18～24℃，插后3周生根，2～3个月将产生幼苗，移入6厘米盆。扦插过程中，用维生素比　\n　二、茎插法\n　　茎插繁殖法也是非洲紫罗兰会选用的繁殖方法，主要是春季花谢后。结合翻盆换土分割地下块茎栽种，成苗快，但株形不够好看，同时由于植株没有更新，生长不够旺盛。　\n　三、组织\n　　现在非洲紫罗兰比较流行的繁殖方法就是组织培养法繁殖法，以叶片、叶柄、表皮组织为外植体。用MS培养基加1毫克／升6－苄氨基腺嘌呤和1毫克／升萘乙酸。接种后4周长出不定芽，3个月后生根小植株可栽植。小植株移植于腐叶土和泥炭　\n　四、播种法\n　　非洲紫罗兰播种繁殖可在春、秋季进行，温室栽培以9～10月秋播为好，发芽率高，幼苗生长健壮，翌年春季开花棵大花多。2月播种，8月开花，但生长势稍差，开花少。非洲紫罗兰种子细小，播种盆土应细，播后不覆土，压平即行。发芽适温18～24℃，播后15～20天发芽，2～3个月移苗。幼苗期注意盆土不宜过湿。一般从播种至开花需6～8个月。', 'http://img.boqiicdn.com/Data/BK/P/imagick12051451555061.jpg', 'http://www.boqii.com/entry/detail/2383.html', '');
INSERT INTO `plant_family` VALUES ('138', '红稚莲', 'Echeveria macdougallii', '红稚莲', '', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/2231/0,http://www.boqii.com/entry/photo/2231/5296', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '石莲花属', '红稚莲', 'Echeveria macdougallii', '', '　　 　　红稚莲的叶片莲座型松散排列，叶片广卵形至散三角卵形，叶面有石莲花少有的细微纹路，叶片先端急尖。', '　　红稚莲的叶色为常年绿色至黄红色，当昼夜大或冬季低温时，叶缘会出现大红或深红色，如果光照不够，叶色则会变浅，叶片也会拉长。当红稚莲在多年栽培并且群生后，植株就会变得非常壮观，观赏价值也大大提高。　　红稚莲的生长适温15－25度，冬季不低于5度；配土一般用泥炭＋＋珍珠岩各一份，并添加适量的骨粉，也可用腐叶土3份、河沙3份、园土1份、炉渣1份混合配制；生长期浇水干透浇透，空气干燥时可向植株周围洒水；生长期施肥一般每20天左右一次。　　红稚莲生长期需保持土壤湿润，避免积水。土壤用煤渣混合泥炭、少量珍珠岩，比例大概5：4：1，红稚莲在盆土干燥的情况下能耐零下4℃左右的低温，是室内的温度，非露天，再低叶片的顶端生长点就会出现，干枯，整个冬季基本断水，5度以下就要开始慢慢断水。夏季高温时整个植株或完全停止，这个时候要通风良好且适当遮光，避免曝晒，节制浇水，不能长期雨淋，以免植株腐烂。', '　　　　红稚莲的繁殖一般是砍头爆小崽扦插和叶插，砍下来的植株可以直接扦插在干的颗粒土中，发根后就可以少量给水了。是个非常好养的', 'http://img.boqiicdn.com/Data/BK/P/imagick91451447839036.jpg', 'http://www.boqii.com/entry/detail/2231.html', '');
INSERT INTO `plant_family` VALUES ('139', '扶桑', 'Chinese rose', '朱槿', '扶桑、赤槿、佛桑、红木槿、桑槿、大红花、状元红', '不容易死', '', 'http://www.boqii.com/entry/photo/2046/0,http://www.boqii.com/entry/photo/2046/5481', '', '', '', '', '', '', '', '', '', '　　扶桑就是我们常说的朱槿，又名中国蔷薇、佛槿等，由于扶桑的花色艳丽，并且花型很大，所以在我国岭南一带俗称大红花。 扶桑 　　扶桑株高约1－3米；小枝圆柱形，疏被星状柔毛。叶阔卵形或狭卵形，长4－9厘米，宽2 5厘米，先端渐尖，基部圆形或楔形，边缘具粗齿或缺刻，两面除背面沿脉上有少许疏毛外均无毛；叶柄长5－20毫米，上面被长柔毛；托叶线形，长5－12毫米，被毛。　　　　　　　　　　　　　　　　　　　', '　　扶桑花的话语为新鲜的恋情，微妙的美。扶桑是中国的名花，在华南地区普及度非常广，并且由于扶桑花的花期长，可以说终年不绝，所以深受人们的欢迎。现在扶桑另一层意思也代指日本，那么如何才能好扶桑花呢？扶桑　　　每年四月移出室外之前，应该进行换盆。土壤宜选用疏松、肥沃的沙质土壤。换盆的时候还要换上新的土，剪去部分过密的卷曲的须根，施足基肥，盆底略加磷肥。　　　移出室外之后，进行修剪，各枝除基部留2－3芽外，上部全部剪截，剪修可促使发新枝，长势将更旺盛，株形也亦美观。修剪后，要适当节制水肥。　　　在霜降后至立冬前必须移入室内，因为扶桑不耐霜冻的。越冬温度不低于5℃，以免遭受冻害；不高于15℃，以免影响休眠。天气较冷时可盖纸或盖塑料薄膜保暖。初移室内每天白天要开窗通风，留意盆土干湿变化，适当浇水。最冷天，浇水有预防冻害的作用，但施肥应停止。　　　管理方面也是十分重要的，在5月初要移到室外放在阳光充足处的时候，要加强肥水、松土、拔草等管理工作。每隔7－10天施一次稀薄液肥，浇水的时候注意盆土干湿情况，过干或过湿都会影响开花。秋后管理要谨慎，要注意后期少施肥，以免抽发秋梢。秋梢组织幼嫩，抗寒力弱，冷天会遭冻害。　　　在过冬期间盆保持略湿润即可，一般每隔5天～10天浇水一次浇水的水量不宜太多，避免低温高湿的土壤环境引发根系。北方冬季气候干燥会出现叶色淡黄、叶缘干枯等现象，要注意提高室内空气湿度。可采取喷洗枝叶或罩塑料薄膜等方法增加植株周围空气湿度为其创造适宜的湿度条件。', '　　扶桑　　家庭栽培扶桑一般采用扦插繁殖。插穗选二年生健壮枝条或当年生半木质化枝条，剪取10厘米，留顶端叶片，切口要平，插于沙床，深4～5厘米（沙床要求铺沙15～20厘米）。插后立即浇1次透水，随后用塑料布遮盖，插床应经常喷水，以增加湿度。1周之后，可逐渐接受阳光，在18—25℃下，20天左右即可生根。　　扦插后一个月左右，扦插苗已具强大的根系，这时应及时上盆。盆的大小可根据所栽植株的大小来确定。一般成活的小苗用口径12—15厘米的盆即可。盆土的配比按田园土、饼肥、沙以10：1：2的体积比配制。栽植时应尽量少伤根系，适当遮阳，以减少对幼苗的伤害，利于幼苗尽早恢复', 'http://img.boqiicdn.com/Data/BK/P/imagick69121442397623.jpg', 'http://www.boqii.com/entry/detail/2046.html', '');
INSERT INTO `plant_family` VALUES ('140', '绯牡丹', 'Gymnocalycium mihanovichii', '绯牡丹', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2322/0,http://www.boqii.com/entry/photo/2322/5200', '　', '被子植物门', '双子叶植物纲', '仙人掌目', '仙人掌科', '裸萼球属', '', 'Gymnocalycium mihanovichii var friedrichii', 'Gymnocalycium mihanovichii', '　　 　　绯牡丹为多年生肉质植物。茎扁球形，直径3－4㎝，鲜红、深红橙红、粉红或紫红色，具8棱，有突出的横脊。成熟球体群生子球。刺座小，无中刺，辐射刺短或脱落。花细长，着生在顶部的刺座上，漏斗形，粉红色，花期春夏季。果实细长，纺锤形，红色。种子黑褐色。', '　　绯牡丹在夏季开花，花色粉红，形似牡丹，故此命名。绯牡丹是科多肉植物，栽培难度不高，但是想要让绯牡丹开出娇艳的花朵并不容易，小编就为你介绍一下绯牡丹的栽培要点，喜欢的朋友可以一起学习。　　绯牡丹配土比较简单，珍珠岩混合了泥炭，加了蛭石和煤渣，比例随意，透气为主，绯牡丹这个不是非常耐暴晒，生长期干透给水，成株尽量少点水。平时风筝是看土壤非常干了，才给水，基本是浇透。　　夏季是生长期，植株也需要轻微遮阳且通风，7～9月高温期基本是阴凉通风，9～12月水分也是干透给水。整个寒冷的冬季，温度低于2度以下，风筝几乎不给水，这时植株进入了，少水也可以防止低温出现的和烂根，盆土干燥的情况下绯牡丹是比较耐低温的，风筝的阳光房零下4度，绯牡丹不会出现任何变化，这个温度是在阳光房内测得的哦，风筝一般会在阳光房内摆一盆水，如果水结冰，就要加温了，只要不是露天，这样的温度绯牡丹都是可以承受的。生长期给水基本是干透再给水，可以兜头淋，通风不好也是容易烂的。春季给水必须循序渐进，注意天气的变化。', '　　　　绯牡丹主要用嫁接繁殖。温室栽培全年均可进行，以春季或初夏最好，愈合快，成活率较高。选取粗壮而柔嫩的砧木（常用', 'http://img.boqiicdn.com/Data/BK/P/imagick76191450170596.jpg', 'http://www.boqii.com/entry/detail/2322.html', '');
INSERT INTO `plant_family` VALUES ('141', '红丁香', 'Syringa villosa Vahl', '红丁香', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2387/0,http://www.boqii.com/entry/photo/2387/5029', '植物　', '被子植物门', '双子叶植物纲', '捩花目', '木犀科', '丁香属', '', 'Syringa villosa Vahl', '', '　　红 　　红丁香为灌木，枝直立，粗壮，灰褐色，具皮孔，小枝淡灰棕色，无毛或被微柔毛，具皮孔。叶片卵形，椭圆状卵形、宽椭圆形至倒卵状长椭圆形，长4－11（－15）厘米，宽1.5－6（－11）厘米，先端锐尖或短渐尖，基部楔形或宽楔形至近圆形，上面深绿色，无毛，下面粉绿色，贴生疏柔毛或仅沿叶脉被须状柔毛或柔毛，稀无毛；叶柄长0.8－2.5厘米，无毛或略被柔毛。圆锥花序直立，由顶芽抽生，长圆形或塔形，长5－13（－17）厘米，宽3－10厘；米；花序轴与花梗、花萼无毛，或被微柔毛、短柔毛或柔毛；花序轴具皮孔；花梗长0.5－1.5毫米；花芳香；花萼长2－4毫米，萼齿锐尖或钝；花冠淡紫红色、粉红色至白色，花冠管细弱，稀较粗达3毫米，近圆柱形，长0.7－1.5厘米，裂片成熟时呈直角向外展开，卵形或长圆状椭圆形，长3－5毫米，先端内弯呈兜状而具喙，喙凸出；花药黄色，长约3毫米，位于花冠管喉部或稍凸出。果长圆形，长1－1.5厘米，宽约6毫米，先端凸尖，皮孔不明显。', '　　红喜光，喜温暖及阳光充足的环境，稍耐阴，但是如果长期处在半阴或全阴处，则会引起生长衰弱，开花稀少的情况，对于其观赏价值会有很大的影响。想要红丁香能开出漂亮的花，就需要注意栽培过程中的一些小细节。　红丁香对土壤的要求并不高，只要是肥沃、疏松、排水良好的土壤都适合红丁香生长。　红丁香的管理比较粗放，适应环境的能力比较强，平时只要注意除草，雨季防涝，干旱时注意浇水，便可顺利生长，其它不必要太在意是否应该浇水。　　红丁香是一种光照的，所以种植在能够接受阳光照射的地方更好。　红丁香原产区气候特点属于赤道雨林气候，最低月平均气温21度，所以我们养殖时应注意温度控制，尽量不要使温度过低，低于3度将会导致植株。　　红丁香对肥料的需求不是太大，一般只要能保证其正常养分吸收即可，切忌施肥过多，以免引起枝条徒长，影响开花。', '　　　\n　一、播种\n　　可于春、秋两季在室内盆播火露地畦播。北方以春播为佳，于3月下旬至四月初进行，播前将种子在0～7℃条件下砂藏1～2个月，可是种子在播后半个月内出苗。播种时可开条沟，沟深3厘米左右，株行距2～10厘米。当庙长到4～5对叶片时，要进行分盆移栽或间苗。幼苗怕涝，雨季应注意，苗木排水。对当年生幼苗，华北地区在冬季要进行防寒处理。　　\n二、扦插\n　　可于花后1个月，选当年生木质化健壮枝条作插穗，插穗长15厘米左右，居2～3对芽。插穗剪好后，用50～100毫克／升的吲哚丁酸处理15～18小时，然后插在有塑料薄膜覆盖的砂床中，1个月可生根。也可在秋、冬取木质化枝条作插穗，先露地埋土贮藏，翌春再行扦插。　\n　三、嫁接\n　　砧木多用欧洲丁香或　　1、芽接，一般在6月下旬至7月中旬，选择当年生健壮枝上面包满的休眠芽作接穗，以不带木质部的盾状芽接法，接到离地面5～10厘米高的砧木干茎上，冬季注意保护。　　2、枝接，于秋、冬季采条，经露地埋藏后于翌春进行，直接成活的接穗当年萌发生长，长可达50～80厘米，但新枝梢很少形成花芽，因此，第二年芽萌动前需将枝干离地面30～40厘米处截短，促其萌发侧枝，使枝条成熟并能正常开花结实。嫁接成活的植株，要及时剪除砧木的萌蘖枝条。', 'http://img.boqiicdn.com/Data/BK/P/imagick8121451898935.jpg', 'http://www.boqii.com/entry/detail/2387.html', '');
INSERT INTO `plant_family` VALUES ('142', '牡丹', 'Paeonia suffruticosa Andrews', '牡丹', '鼠姑、鹿韭、白茸、木芍药、百雨金、洛阳花、富贵花', '不容易死', '', 'http://www.boqii.com/entry/photo/1941/0,http://www.boqii.com/entry/photo/1941/5588', '', '', '', '', '', '', '', '', '', '　　牡丹是我国非常有名的 　　牡丹是落叶灌木。茎高达2米；分枝短而粗。叶通常为二回三出复叶，偶尔近枝顶的叶为3小叶；顶生小叶宽卵形，长7－8厘米，宽5.5－7厘米，3裂至中部，裂片不裂或2－3浅裂，表面绿色，无毛，背面淡绿色，有时具白粉，沿叶脉疏生短柔毛或近无毛，小叶柄长1.2－3厘米；侧生小叶狭卵形或长圆状卵形，长4.5－6.5厘米，宽2.5－4厘米，不等2裂至3浅裂或不裂，近无柄；叶柄长5－11厘米，和叶轴均无毛。　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　是我国非常常见并且也非常受人喜欢的观赏花卉，喜欢牡丹花的朋友不但可以在公园、花坛等地欣赏到牡丹花，还能自己在家盆栽。牡丹花性喜凉、畏热、喜燥、恶湿，并且牡丹花还喜肥，了解了牡丹花的这一习性，一般都能栽培出牡丹花。小编就为你介绍一下盆栽牡丹花的栽培要点，有兴趣自己盆栽的朋友可以一起了解。　　牡丹除露地栽培外，还可以进行盆栽观赏。栽植季节以9－10月为最好。盆栽牡丹应选择适应性强、早开花、花型较好的洛阳红、胡红、赵粉等品种。植株宜选用芍药作砧木嫁接的3－4年小棵牡丹或具有3－5个枝干的分株苗。　　盆栽时，盆底可用粗砂或小石子铺3－5厘米厚，以利排水。盆土宜用黄砂土和饼肥的混合土，或用充分腐熟的厩肥、园土、粗砂以1：1：1的比例混匀的土。填土要使根系舒展，不能卷曲；覆土后要用手压实，使根系与泥土紧密接触，才易于成活。　　上盆后浇一次透水，放半阴处缓苗。转入正常管理后，可放置向阳处，保证其有充分的阳光照射。期间要经常松土，每隔半个月左右施一次复合肥。新上盆的牡丹，不能施肥，特别忌施浓肥，否则肉质根会发霉烂死。半年后可逐渐施些薄肥，如腐熟的鸡粪水或豆水等，肥水比例以20％－30％为宜。新上盆的牡丹第一年不一定能开出好花，但培养1－2年后，就能连年开花。牡丹一年在4月中、下旬开花，开花前可追施1－2次液肥；开花后半个月再追施1－2次液肥；伏天可用麻酱渣（每盆约40－50克）施1次干肥，以利花芽分化。　　牡丹系肉质根，稍能耐旱，最怕积水，故浇水是否得当，是盆栽牡丹成败的一个关键问题。一般早春出室的牡丹，应先施一次肥水，然后浇透水，水稍干后松土。以后浇水应根据天气、盆土情况，适时、适量进行，经常保持盆土湿润，有利牡丹生长开花。合理的浇水，应该是见干见湿，不宜浇大水，防止盆内积水，以免烂根落叶。　　牡丹开花时，可设棚覆盖或暂时放在室内，避免阳光直射，这样可延长开花期，对主枝顶芽是叶芽的，应摘去，以免徒长，影响开花。为使牡丹开花鲜艳，花期可用0.5％－1％的磷酸二氢溶液进行叶面喷施2－3次。牡丹花谢后，要进行一次整形修剪，及时剪去残花及花梗，不令结籽，保留茎部的1－2个外侧芽，这样可使植株生长旺盛，保证次年开花。　　牡丹虽然较耐寒，但在华北等寒冷的地区，立冬前后，应搬入室内，放在房间的向阳处，室温保持0度左右即可。次年出室不宜过早，须待清明前后再出室。不太寒冷的地区，可选隐风处将花盆埋入土壤内，使盆面与地面平齐，以保持盆土的湿度和温度，也可保证牡丹。待第二年春天牡丹花现蕾后，再连盆将牡丹从地中挖出，进行正常管理。', '　　牡丹花的繁殖方法一般可分为有性繁殖和无性繁殖。有性繁殖也叫种子繁殖，由于牡丹花用种子繁殖的话需要三年后才开始开花结子，时间比较长，所以比较少用。而无性繁殖则包括了分株、嫁接及扦插繁殖，这三种方法是比较常见的。', 'http://img.boqiicdn.com/Data/BK/P/imagick77551439459374.jpg', 'http://www.boqii.com/entry/detail/1941.html', '');
INSERT INTO `plant_family` VALUES ('143', '蜡菊', 'Helichrysum bracteatum', '蜡菊', '麦秆菊，七彩菊', '不容易死', '原产于澳大利亚，在东南亚和欧美栽培较广', 'http://www.boqii.com/entry/photo/2275/0,http://www.boqii.com/entry/photo/2275/5250', '　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '蜡菊属', '蜡菊', 'Helichrysum bracteatum （Vent. ） Andr.', 'Helichrysum bracteatum', '　　 　　蜡菊为一年或二年生草本。茎直立，高20－120厘米，分枝直立或斜升。叶长披针形至线形，长达12厘米，光滑或粗糙，全缘，基部渐狭窄，上端尖，主脉明显。头状花序径2－5厘米，单生于枝端。总苞片外层短，履瓦状排列，内层长，宽披针形，基部厚，顶端渐尖，有光泽，黄色或白、红、紫色。小花多数；冠毛有近羽状糙毛。瘦果无毛。', '　　的有很多，由于蜡菊干燥的花瓣呈金黄色，并且花色鲜艳，长久不褪，所以受到很多花友们的喜爱，常常被制作成干花来环境。人工栽培蜡菊的难度并不高，但是想要种出漂亮的蜡菊，还是要根据其习性来布置环境。　　蜡菊不耐寒、怕暑热，夏季生长停止，多不能开花。喜肥沃、湿润而排水良好的土壤上生长。喜向阳处生长，施肥不宜过多以免花色不艳。原产澳大利亚。在东南亚和欧美栽培较广，中国也有栽培，新疆有野生，一般土壤中均可生长，但以贫瘠的砂壤土与向阳地长势最好。阳光要充足，过湿地不宜浅种。　　蜡菊株高75～120厘米，要在株间插杆，设立支架，以防倒伏。蜡菊根系浅，抗旱能力差，注意浇水防旱。在施足底肥基础上，为了提高结实率，促进种子早熟，在现蕾期前，增施1次磷肥。及时打药，注意蚜虫、卷叶虫和地下害虫。', '　　　　蜡菊的种子采集后可晒干，贮藏于室内通风阴凉处。以秋、冬季播种为宜，从江南秋季播种到开花需110一120天。气温较低的地区，可在塑料大棚内保温播种　　播种时正值秋冬，为便于管理，最好用育苗盘在疏松床土上播种。播种前将种子浸水数小时，捞出晾干后密播于育苗盘；或在育苗盘上装床土，稍压实，刮平浇水，播干种子，每平方米苗床播种量6克左右，筱土后盖地膜或扣小拱栩。在适宜的条件下，种子5－－7天出苗。当苗有1－2片真叶时移植，可用直径8厘米的', 'http://img.boqiicdn.com/Data/BK/P/imagick76241448961739.jpg', 'http://www.boqii.com/entry/detail/2275.html', '');
INSERT INTO `plant_family` VALUES ('144', '锦上珠', 'Senecio citriformis／Senecio pusillus', '锦上珠', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2462/0,http://www.boqii.com/entry/photo/2462/4954', '　　', '', '', '', '菊科', '', '', 'Senecio citriformis／Senecio pusillus', '', '　　 　　锦上珠的茎部直立或匍匐', '　　锦上珠的栽培难度并不大，但是想要让锦上珠长得漂亮却没那么简单。锦上珠的适应性较强，成活对于锦上珠来说并不难，那么如何才能养出漂亮的锦上珠呢？　　1、由于锦上珠的肉质多，汁水丰富，所以较耐寒。所以在栽培的过程中，应该少浇水。在炎热干燥的，可以经常给植株的叶子、枝蔓部分喷水，从而保持整个植株的青翠度。由于锦上珠喜欢半阴的环境，所以应该为它营造一个良好的生长环境。　　2、由于锦上珠的根系比较浅，所以应该用浅盆进行栽植。为了增加盆内的透气性和滤水性，可以在盆底垫上一片粗陶，并在粗陶上铺一层粗砂或细煤渣。在锦上珠的土里还可以加入一些腐叶和砂子，提升透气性。　　3、锦上珠耐寒、喜爱潮湿温暖的气候，所以可以将温度控制在20℃～28℃之间，避免温度过高或过低。特别是当温度达到30℃以上时，珍珠)就不在生长了，而且这个时候应该减少浇水和施肥的次数，以免发生烂根现象。　　4、在锦上珠生长旺盛的春秋两季，应该注意多次施用薄肥，经常在)的叶面上喷洒浓度为1－3‰的氮肥和磷酸二氢钾，从而促使珍珠吊兰珠体更加饱满，是它更加具有观赏性。', '　　锦上珠的栽培难度虽然不高，但是在不同地区的　\n　一、扦插繁殖\n　　枝蔓极易生气生根，可于春秋剪下几节，一半埋入沙子或疏松的土中，保持湿润但不积水，很快就会生根以供栽植（春秋季约半月，而冬夏则不易生根，遇盆株不够均匀丰满却生长过长的情况时，就可以采用这种措施予以弥补。）　　锦上珠一般采用扦插的方式进行养植。在剪枝条的时候注意挑选健康壮实的，在枝条凸起处旁下刀。将剪下来的部分直接埋在土里即可。接着在土壤中浇适量的水，使土能够粘在减下来的锦上珠上。在接下来的一个月内不需要对它浇水。一般来说，如果温度控制在15℃的话，两到三周珍珠　\n　二、分株繁殖\n　　除冬季气温过低不适于分株外，其它季节均可进行。盆栽2—3年的植株，在春季换盆时将密集的盆苗，去掉旧', 'http://img.boqiicdn.com/Data/BK/P/imagick93301453972502.jpg', 'http://www.boqii.com/entry/detail/2462.html', '');
INSERT INTO `plant_family` VALUES ('145', '帝冠', 'Obregonia denegrii', '帝冠', '帝冠牡丹', '不容易死', '墨西哥 塔毛利帕斯州 维多利亚城', 'http://www.boqii.com/entry/photo/2430/0,http://www.boqii.com/entry/photo/2430/4985', '', '', '', '', '', '', '', '', '', '　　帝冠又名帝冠牡丹，原产于墨西哥，由于帝冠的疣以几何图形有序排列，非常特别，所以是 帝冠 　　帝冠植株单生，属小型种，是仙人掌类　　　　　　　　　　　　　　　　　　　　', '　　呈球状或扁平球状，成株顶端会有白毛群生，是难得的仙人掌类精品，也是仙人掌类的代表种之一。但是帝冠的栽培难度比较高，并没有我们想象中仙人掌很好养活的概念，小编就为你介绍一下帝冠在栽培的过程中应该注意哪些。　　帝冠种植较为困难，由于帝冠根部粗大，且根系十分发达，故盆栽应采用深盆，盆土以赤玉土、粗沙、碎砖和少量骨粉或为好。盆底多垫瓦片，有利于排水。帝冠极为缓慢，实生的幼年植株生长更为缓慢，一般要经过3年甚至更长时间的正常生长后才看的出有明显生长的迹象。成年植株一般约3—5年换盆1次，盆不宜过大。生长期可充足浇水，需充足阳光。帝冠适应性较差，切忌盆土积水，否则极易。每月施肥1次。白天气温24—29摄氏度，晚间16—18摄氏度是生长。冬季要求冷凉，但不能低于5℃，盆土保持干燥，否则在低温湿润的环境下极易腐烂。', '　　　\n　一、播种：\n　\n　二、嫁接：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick86831452848556.jpg', 'http://www.boqii.com/entry/detail/2430.html', '');
INSERT INTO `plant_family` VALUES ('146', '九轮塔', 'Haworthia reinwardtii var. Chalwini', '九轮塔', '霜百合', '不容易死', '原产于西南非洲', 'http://www.boqii.com/entry/photo/2474/0,http://www.boqii.com/entry/photo/2474/4943', '　', '被子植物门', '双子叶植物纲', '', '百合科', '十二卷属', '九轮塔', 'Haworthia reinwardtii var. Chalwini', '', '　　 　　九轮塔的茎轴极短，不向高处', '　　的外形比较特别，虽然其普及度并不广，但是是很多花友们见过就很难忘的一个。九轮塔的栽培难度并不高，但是需要注意给予合适的环境，才能让九轮塔成长。　　九轮塔喜阳光，不耐荫，不耐高温酷热，不耐寒。要求排水良好和富含腐殖质的沙壤土，较耐旱。九轮塔均用小盆栽植，用腐叶土加河沙作土。盆土保持湿润，不干不浇。夏季适当遮荫，每年追肥2～3次。冬季温度不低于5℃。因生长缓慢，盆土不必年年换。', '　　　　九轮塔的繁殖采叶腋或茎轴基部长出的小侧枝扦插。可挑选', 'http://img.boqiicdn.com/Data/BK/P/imagick43411454319182.jpg', 'http://www.boqii.com/entry/detail/2474.html', '');
INSERT INTO `plant_family` VALUES ('147', '珊瑚藤', 'Antigonon leptopus Hook. ＆ Arn.', '珊瑚藤', '紫苞藤、朝日蔓、旭日藤', '不容易死', '原产于墨西哥及中美洲', 'http://www.boqii.com/entry/photo/2335/0,http://www.boqii.com/entry/photo/2335/5081', '　　', '', '', '', '蓼科', '珊瑚藤属', '珊瑚藤', 'Antigonon leptopus Hook. ＆ Arn.', '', '　　 　　珊瑚藤为双子叶植物纲的一科。一年生或多年生草本，稀为灌木或小乔木。茎通常具膨大的节。叶为单叶，互生，有托叶鞘。花两性，稀为单性，辐射对称；花序由若干小聚伞花序排成总状、穗状或圆锥状，花有时单生；花被片3～6；雄蕊6～9，极少为16，有花盘；雌蕊1，子房上位，1室。瘦果卵形，具3棱或扁平，通常包于宿存的花被内；胚弯生或直立，胚乳丰富。约40属800种，主要分布于北温带，少数在热带。中国产11属200余种。', '　　珊瑚藤有“藤蔓植物之后”的美名，是比较有观赏价值的花卉之一，人工栽培珊瑚藤的难度并不高，开花后非常漂亮。珊瑚藤原产于中美洲地区，现在在我国台湾、海南、广州等地均有栽培。　　珊瑚藤栽培土质以肥沃之壤土或腐植质壤土最佳，排水、日照需良好，日照不足开花疏而色淡。性喜高温，生育适温约22～30度。　　幼株茎蔓伸长后需设立支柱供攀缘，若枝条多，选留2～3支作主枝，其他加以剪除，待上棚架后再摘心，促其多分枝。春至夏季生育期，水份补给要充足，施肥可用各种有机或三要素，每1～2个月少量施用一次。　　北部冬季有落叶现象，可趁此修剪整枝，将枝条剪短；植株老化采用强剪。露地栽培主要在华南地区。由于枝蔓较长，露地栽植不宜太密，一般作为篱垣，株距以4米为宜。盆栽要求高温温室。　　珊瑚藤性喜湿润，故在生长期间应充分浇水，经常保持盆土湿润，在夏季高温要向叶面喷水。休眠期内要少浇水，只要盆土不干掉即可。　　夏季盆栽在室外养护，最好置于树阴下养护，但每天至少要有3－4小时的直射光照。如果生长环境处太阴湿，则易造成植株徒长，开花稀疏，色淡且小。　　生长期需肥较多，每7一l0天需施1次25％的沤熟饼肥。当花现蕾时，则要多施磷肥、钾肥。这样可使茎干坚挺，花色更加鲜艳。如果想要使长成灌丛状，在生长初期须要通过多次摘心，促其多分枝，从而可使株形丰满。', '　　珊瑚藤的花期为3－12月，花期非常长，是有观赏价值的　　珊瑚藤可用播种或扦插法，但以播种为主。由于不耐移植，最好用直播或盆播为佳。　　春至夏季为适期，发芽适温约22～28度。播种前先将种子浸水4～6小时，使之充分吸水，再浅埋于土中约一公分，保持湿度，约经30天能发根。　　春季为扦插适期。一般在春季或秋季，剪取未结蕾的', 'http://img.boqiicdn.com/Data/BK/P/imagick47881450344812.jpg', 'http://www.boqii.com/entry/detail/2335.html', '');
INSERT INTO `plant_family` VALUES ('148', '荷花', 'Lotus flower', '荷花', '莲花、水芙蓉、藕花、芙蕖、水芝、水华、泽芝、中国莲', '不容易死', '', 'http://www.boqii.com/entry/photo/1955/0,http://www.boqii.com/entry/photo/1955/5572', '', '', '', '', '', '', '', '', '', '　　 　　荷花　　　　　　　　　　　　　　　　　　　', '　　由于荷花为水生，比较特别，所以想要自己在家中进行盆栽的话，不但环境有一定的要求，栽培方法也和别的植物有所不同。小编就为你介绍一下关于荷花的栽培方法与注意事项，想要自己动手栽种荷花的朋友可千万别错过了。　　盆栽荷花通常使用荷花浅盆、术桶盆，或口径60厘米以上的浅缸。使用旧盆要里外刷洗干净。如用家庭水缸，因高度偏高，可于缸的底层铺以砖石，使之变浅，缸太深，常叶多花少。　　栽培用土，一般用含腐殖质丰富的塘泥或稻田泥。先把泥捣过筛，若有杂质、石砾等，需要拣去，使泥粘泞。放人盆内，厚度一般为10一15厘米。同时可用晒干的鸡鸭粪、人粪干、豆饼、菜、鸡毛、头发、青草等任何一种作为基肥。　　盆裁荷花可选在清明节前后。清明节前7一lO天，即3月下旬栽种最好。过早易使藕节腐烂，植株开花不良，即使开花，花往会在叶子下面，影响观赏价值。　　栽种时，盆底先放入3—4厘米厚的疏松泥土，然后放人基肥。如加肥嫩青草，需要切细后放入。或放入豆饼、鸡毛等任何一种，再加上疏松泥土，然后把藕秧放人上面。藕秧肥大壮实的放入l一2条。瘦弱的可放人3—4条平行排列。排列时，藕头与藕尾朝同一方向，节间的芽头应该向上。排放好后，盖上泥土，使芽头稍微露出泥面，藕尾略挺起，以便透气。然后放置太阳光下面任其日晒（如雨天可加遮盖），待泥土干裂开，方可放入清水。因泥土粘泞，干后会结成块，有利于固定藕秧，放水后藕秧也不会浮起。将来长出新叶不会因风吹摇动影响藕秧生长。所以，土一定要晒干达裂的程度，才可放水。水深约5厘米即可。放水后再进行日晒。使其水分收干。但不像第一次那样使泥土干裂，只需晒到用手指下去感到软而不粘就可以再加水。以后盆水经常保持高出5—6厘米。到5月中下旬，有小叶片伸出水面时，盆水可增加到10～15厘米深。　　盆栽荷花经30一45天，有叶片伸出水面时，可施肥一次。用死鱼烂虾壅入藕节旁边的泥土下面，待其腐熟之后，使藕节根系吸收。此时天气炎热，不可让盆内水量减少。以后荷叶不断抽出，花蕾也随之露出水面，陆续开花。如浮叶过多，可将烂叶塞入泥中。　　入秋以后，叶停止生长，不需要施肥。10月份以后水分可以减少。11月份以后可移人室内，冬季不能使其受冻或断水，至明年清明前后移到室外。　　盆栽荷花需要年年翻种，否则生长不良，叶子不茂盛，也不易开花。', '　　　　分株法盆栽荷花，事前要做好各种准备工作。如果要种大莲花，需准备矮边的缸（缸底不能和栽其他花那样开出水洞），缸内要放肥沃的种植土（荷花喜肥），并加水将土搞成糊状（注意拣去杂质和石块）并施入鸡粪肥、猪圈肥或黄粪作基肥，盆或缸内盛土约占盆、缸深度的2／3，其余1／3留作盛水之用。栽植的时间宜在3月底、4月初，当气温在25度时进行最好。荷花　　采用播种繁殖荷花，一般在4月上旬进行。莲花的种子即莲子，有极坚硬的种皮。先将选好的良种带皮莲子，用利刀将顶端种皮割去2－3毫米，使水可以浸入，置入水中浸泡2－3天，待种子吸水膨胀后播种于盆中（盆土', 'http://img.boqiicdn.com/Data/BK/P/imagick20101439891602.jpg', 'http://www.boqii.com/entry/detail/1955.html', '');
INSERT INTO `plant_family` VALUES ('149', '蜀葵', 'Althaea rosea （Linn.）Cavan.', '蜀葵', '一丈红、大蜀季、戎葵、吴葵、卫足葵、胡葵、斗蓬花、秫秸花', '不容易死', '在中国分布很广，华东、华中、华北、华南地区均有', 'http://www.boqii.com/entry/photo/2276/0,http://www.boqii.com/entry/photo/2276/5249', '　　', '被子植物门', '双子叶植物纲', '锦葵目', '锦葵科', '蜀葵属', '', 'Althaea rosea （Linn.）Cavan.', 'Althaea rosea', '　　 　　蜀葵成株可高达2米，茎枝密被刺毛。叶近圆心形，直径6－16厘米，掌状5－7浅裂或波状棱角，裂片三角形或圆形，中裂片长约3厘米，宽4－6厘米，上面疏被星状柔毛，粗糙，下面被星状长硬毛或绒毛；叶柄长5－15厘米，被星状长硬毛；托叶卵形，长约8毫米，先端具3尖。', '　　虽然又名一丈红，但是和我们熟知的毒药并不是一回事。蜀葵全株可入药，有清热解毒、镇咳利尿的功效，从蜀葵花中提取的花青素还可以做成的着色剂，经济价值非常高。那么人工栽培蜀葵应该注意哪些呢？　　蜀葵喜凉爽气候，忌炎热与霜冻，喜光，略耐阴；宜土层深厚、肥沃、排水良好的土壤。　　蜀葵栽培较为简易，幼苗长出2至3片真叶时，应移植一次，加大株行距。移植后应适时浇水，开花前结合中耕除草施追肥1至2次，追肥以磷、钾肥为好。播种苗经1次移栽后，可于11月定植。幼苗期，施2－3次液肥，以氮肥为主。　　同时经常松土、除草，以利于植株生长健壮。当蜀葵叶腋形成花芽后，追施1次磷、钾肥。为延长花期，应保持充足的水分。花后及时将地上部分剪掉，还可萌发新芽。盆栽时，应在早春上盆，保留独本开花。', '　　　　\n一、播种\n　　春播、秋播均可。依蜀葵种子多少，可播于露地苗床，再育苗移栽，也可露地直播，不再移栽。南方常采用秋播，通常宜在9月份秋播于露地苗床，发芽整齐。而北方常以春播为主。　　蜀葵种子成熟后即可播种，正常情况下种子约7天就可以萌发。蜀葵种子的发芽力可保持4年，但播种苗2～3年后就出现　　\n二、分株\n　　蜀葵的分株在秋季进行，适时挖出多年生蜀葵的丛生根，用快刀切割成数小丛，使每小丛都有两三个芽，然后分栽定植即可。春季分株稍加强水分　\n　三、扦插\n　　扦', 'http://img.boqiicdn.com/Data/BK/P/imagick79581448962134.jpg', 'http://www.boqii.com/entry/detail/2276.html', '');
INSERT INTO `plant_family` VALUES ('150', '金盏菊', 'pot marigold', '金盏菊', '金盏花、黄金盏、长生菊、醒酒花、常春花、金盏', '不容易死', '', 'http://www.boqii.com/entry/photo/2256/0,http://www.boqii.com/entry/photo/2256/5269', '', '', '', '', '', '', '', '', '', '　　 　　金盏菊株高30～60cm，为二年生草本植物，全株被白色茸毛。单叶互生，椭圆形或椭圆状倒卵形，全缘，基生叶有柄，上部叶基抱茎。头状花序单生茎顶，形大，4－6cm，舌状花一轮，或多轮平展，金黄或桔黄色，筒状花，黄色或褐色。也有重瓣（实为舌状花多层）、卷瓣和绿心、深紫色花心等栽培　　　　　　　　　　　　　　　　　　　　　', '　　的用处非常多，并且人工栽培观赏价值也很高，花期为12月至次年6月，盛花期为3－6月。人工栽种金盏菊的难度并不高，由于金盏菊的强健，只要注意其生长习性为其布置生长环境，金盏菊都能长的非常好。　　金盏菊的生长期每半月施肥1次，或用“卉友”20－20－20通用肥。充足，金盏菊开花多而大。相反，肥料不足，花朵明显变小退化。花期不留种，将凋谢花朵剪除，有利花枝萌发，多开花，延长观花期。留种要选择花大色艳、纯正的植株，应在晴天采种，防止脱落。　　金盏菊的生长期间应保持土壤湿润，每15－30天施10倍水的腐熟尿液一次，施肥至2月底止。在金盏菊长至幼苗后期，叶片4－5个时，实行摘尖（即摘心）能够促使侧枝，增加开花数量，在第一茬花谢之后立即抹头，也能促发侧枝再度开花。', '　　　　金盏菊的播种常在9月中下旬以后进行秋播：基质消毒对播种用的基质进行消毒，最好的方法就是把它放到锅里炒热，什么病虫都能烫死。另外低温　\n　一、催芽\n　　用温热水（　　\n二、播种\n　　对于用手或其它工具难以夹起来的细小的种子，可以把牙签的一端用水沾湿，把种子一粒一粒地粘放在基质的表面上，覆盖基质1公分厚，然后把播种的花盆放入水中，水的深度为花盆高度的1／2～2／3，让水慢慢地浸上来（这个方法称为“盆浸法”）；以免把种子冲起来。　　\n三、播种后的\n　　在秋季播种后，遇到寒潮低温时，可以用塑料薄膜把花盆包起来，以利保温保湿；幼苗出土后，要及时把薄膜揭开，并在每天上午的9：30之前，或者在下午的3：30之后让幼苗接受太阳的光照，否则幼苗会生长得非常柔弱；大多数的种子出齐后，需要适当地间苗：把有病的、生长不健康的幼苗拔掉，使留下的幼苗相互之间有一定的空间；当大部分的幼苗长出了3片或3片以上的叶子后就可以移栽上盆了。', 'http://img.boqiicdn.com/Data/BK/P/imagick17501448445669.jpg', 'http://www.boqii.com/entry/detail/2256.html', '');
INSERT INTO `plant_family` VALUES ('151', '金露梅', 'Potentilla fruticosa', '金露梅', '金腊梅、金老梅', '不容易死', '', 'http://www.boqii.com/entry/photo/2341/0,http://www.boqii.com/entry/photo/2341/5076', '植物　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '委陵菜属', '', 'Potentilla fruticosa', '', '　　 　　金露梅高0.5－2米，多分枝，树皮纵向剥落。小枝红褐色，幼时被长柔毛。羽状复叶，有小叶2对，稀3小叶，上面一对小叶基部下延与叶轴汇合；叶柄被绢毛或疏柔毛；小叶片长圆形、倒卵长圆形或卵状披针形，长0.7－2厘米，宽0.4－1厘米，全缘，边缘平坦，顶端急尖或圆钝，基部楔形，两面绿色，疏被绢毛或柔毛或脱落近于几毛；托叶薄膜质，宽大，外面被长柔毛或脱落。单花或数朵生于枝顶，花梗密被长柔毛或绢毛；花直径2.2－3厘米。', '　　因其花型似梅而命名，但金露梅其实并不是梅，但与梅花同为蔷薇科。金露梅极其耐寒，可以忍受零下50℃的低温，在我国青藏高原地区被称为格桑花。　　金露梅产于青海、甘肃、四川及云南；东北、华北有分布；北温带广泛分布。金露梅主要分布于海拔1800m以上山地，原生地土壤为山地草甸土。植株形适中，姿态美观，花色金黄，鲜艳明亮，具有较高的园林观赏价值。　　金露梅小苗装盆或养了几年的大株转盆时，先在盆底放入2～3公分厚的粗粒基质作为滤水层，其上撒上一层充分腐熟的有机作为基肥，厚度约为1～2公分，再盖上一薄层基质，厚约1～2公分，然后放入植株，以把肥料与根系分开，避免烧根。上盆用的基质可以选用下面的一种：菜园土：炉渣＝3：1；或者园土：中粗河沙：锯末（茹渣）＝4：1：2；或者水稻土、塘泥、腐叶土中的一种。上完盆后浇一次透水，并放在遮荫环境一周。小苗移栽时，先挖好种植穴，在种植穴底部撒上一层有机肥料作为底肥（基肥），厚度约为4～6公分，再覆上一层土并放入，以把肥料与根系分开，避免烧根。放入苗木后，回填土壤，把根系覆盖住，并用脚把土壤踩实，浇一次透水。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick76551450430600.jpg', 'http://www.boqii.com/entry/detail/2341.html', '');
INSERT INTO `plant_family` VALUES ('152', '皱叶椒草', 'Peperomia caperata', '皱叶椒草', '皱叶豆瓣绿、四棱椒草', '不容易死', '', 'http://www.boqii.com/entry/photo/2258/0,http://www.boqii.com/entry/photo/2258/5267', '', '', '', '', '', '', '', '', '', '　　 　　皱叶椒草为簇生型植株，茎短，叶圆心形丛生于短茎顶。叶柄长10～15 cm，株高约20 cm。叶面浓绿有光泽，叶背灰绿。主脉及第一侧脉向下凹陷，使叶面折皱不平。　　　　　　　　　　　　　　', '　　皱叶椒草是非常好的室内观叶植物，原产于巴西，在我国的南方可以自然栽培，但是北方则需要注意温室，以免出现冻害的情况。皱叶椒草较耐阴，喜欢明亮的散射光，有吸附甲醛的功能，所以深受人们的喜爱。　　1、盆土以排水良好的腐叶土为宜，可用园土、腐叶土、河沙等混合而成的疏松土，并可加入少量的饼肥作基肥。　　2、生长季节可每月施肥一次，宜用充分腐熟的饼肥水或以氮肥为主的稀薄液肥。施肥时，避免与叶面。　　3、中生，浇水以盆土湿润为宜，不可积水，季气温高，生长旺盛，可2-3天浇水一次，冬季要控制水量。　　4、盆栽宜置于半阴处，光线太强，叶片颜色变黄，光线太弱时叶片又易失去光泽，冬季可放于阳光充足的地方。　　5、为使植株丰满、枝叶密集，可于初夏摘心修剪。　　6、盆栽皱叶椒草，宜2年换盆一次。', '　　　　皱叶椒草对环境适应力良好，即使土质，', 'http://img.boqiicdn.com/Data/BK/P/imagick13881448529822.jpg', 'http://www.boqii.com/entry/detail/2258.html', '');
INSERT INTO `plant_family` VALUES ('153', '黑兔耳', 'Kalancho tomentosa cv.Chocolate Soldier', '黑兔耳', '巧克力兔耳', '碧玉莲', '原产中美洲干燥地区。', 'http://www.boqii.com/entry/photo/2460/0,http://www.boqii.com/entry/photo/2460/4956', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '伽蓝菜属', '黑兔耳', 'Kalancho tomentosa cv.Chocolate Soldier', '', '　　 　　黑兔耳是月兔耳的栽培品种。株高80厘米，株幅20厘米。更加短小厚实的叶子，叶片被深褐色的斑点包围，像是涂上一层', '　　黑兔耳原产于中美洲的干燥地区，晚秋到早春为旺盛期，喜欢阳光充足的环境，夏季需要注意适当遮阴，但也不能过于荫蔽。人工栽培黑兔耳需要注意环境的布置，这样才能保证黑兔耳的生长。　　　黑兔耳喜欢阳光充足、凉爽干燥的环境，耐半阴，忌闷热潮湿，夏季要适当遮荫，不能过于荫蔽。黑兔耳喜光，若光照不足植株容易徒长，叶与叶之间的上下距离会拉的更长，使得株型松散，茎变的很脆弱，叶片也会拉长，也会变淡。而在阳光充足之处生长的植株，株型矮壮，叶片之间排列会相对紧凑点。　　　黑兔耳生长期需保持土壤微湿，避免积水。此外它夏季生长缓慢，这个时候应减少浇水，防止因盆土过度潮湿引起根部，并加强通风。', '　　　　黑兔耳需要阳光充足和凉爽、干燥的环境，耐半阴，怕水涝，忌闷热潮湿。具有冷凉季节', 'http://img.boqiicdn.com/Data/BK/P/imagick84671453887123.jpg', 'http://www.boqii.com/entry/detail/2460.html', '');
INSERT INTO `plant_family` VALUES ('154', '变叶木', 'Garden Croton', '变叶木', '洒金榕', '不容易死', '原产东南亚和太平洋群岛的热带地区', 'http://www.boqii.com/entry/photo/2108/0,http://www.boqii.com/entry/photo/2108/5419', '', '', '', '', '', '', '', '', '', '　　 　　变叶木为灌木或小乔木，高可达2米。枝条无毛，有明显叶痕。叶薄革质，形状大小变异很大，线形、线状披针形、长圆形、椭圆形、披针形、卵形、匙形、提琴形至倒卵形，有时由长的中脉把叶片间断成上下两片。长5－30厘米，宽（0.3－） 0.5－8厘米，顶端短尖、渐尖至圆钝，基部楔形、短尖至钝，边全缘、浅裂至深裂，两面无毛，绿色、淡绿色、紫红色、紫红与黄色相间、黄色与绿色相间或有时在绿色叶片上散生黄色或金黄色斑点或　　　　　　　　　　　　　　　　　　　　　　　　　', '　　又称洒金榕、变色月桂等，由于其叶片含花青素，所以叶片非常多。但是，变叶木的汁液有毒，人畜误食都会引起腹泻、腹痛等症状，如果只是，并不会对人体有害。　　1、土壤：变叶木喜肥沃湿润、排水良好的土壤。盆栽可用3份园土、1份堆肥、1份河沙，或3份粗泥炭、3份腐叶土和2份沙混合作为基质。　　2、阳光：变叶木对光线适应范围较宽，但充足的阳光有利于促进其良好，并获得较高观赏价值，因此，除了夏季强光下需适当遮阴外，春、夏、秋三季在露天光照条件下叶片的颜色变得更美丽。变叶木不太耐阴，一般适宜放在室内有较强散光处，而且时间不宜超过2－3周。如果长期缺乏光照或光线不足，会使叶色缺少光泽，还容易落叶。', '　　　　1、扦插繁殖：于6～8月，选用顶端枝条，长10厘米，切口有乳汁，晾干后再插入沙床，插后保持湿润和25～28℃室温，约20～25天可生根，35～40天后盆栽。　　2、压条繁殖：以7月高温　　3、播种繁殖：7～8月种子成熟，秋播，室温必须25～28℃，播后14～21天发芽，翌年春季幼苗才能盆栽。发芽时', 'http://img.boqiicdn.com/Data/BK/P/imagick17801444641394.jpg', 'http://www.boqii.com/entry/detail/2108.html', '');
INSERT INTO `plant_family` VALUES ('155', '异叶南洋杉', 'Araucaria heterophylla （Salisb.） Franco', '异叶南洋杉', '', '不容易死', '大洋洲诺和克岛', 'http://www.boqii.com/entry/photo/2248/0,http://www.boqii.com/entry/photo/2248/5277', '', '', '', '', '', '', '', '', '', '　　异叶 异叶南洋杉 　　异叶南洋杉为乔木，在原产地高达50米以上，胸径达1.5米；树干通直，树皮暗灰色，裂成薄片状脱落；树冠塔形，大枝平伸，长达15米以上；小枝平展或下垂，侧枝常成羽状排列，下垂。叶二型：幼树及侧生小枝的叶排列疏松，开展，钻形，光绿色，向上弯曲，通常两侧扁，具3－4棱，长6－12毫米，上面具多数气孔线，有白粉，下面气孔线较少或几无气孔线；大树及花果枝上的叶排列较密，微开展，宽卵形或三角状卵形，多少弯曲，长5－9毫米，基部宽，先端钝圆，中脉隆起或不明显，上面有多条气孔线，有白粉，下面有疏生的气孔线。雄球花单生枝顶，圆柱形。　　　　　　　　　　　　　　　', '　　异叶)为南洋杉科南洋杉属常绿乔木，现在很多花友都会将异叶南洋杉制作成盆景放在室内观赏，但异叶南洋杉并不适合制作成悬崖式和临水式。人工栽培异叶南洋杉的难度并不高，只要对其习性特点稍加了解，就能养出健康漂亮的异叶南洋杉。　　异叶南洋杉喜温暖湿润和阳光充足的环境，稍耐半阴，春夏秋三季为其季节，可放在室外通风良好、阳光充足处养护，浇水做到“不干不浇，浇则浇透”，并在空气干燥时向植株喷水，以使叶色清新；每20天左右施一次腐熟的稀薄液肥，为使叶色浓绿，可喷施叶面宝等叶面肥。冬季放在避风向阳处，若遇寒流可移至室内，也可在冷室内越冬，控制浇水，保持盆土0℃以上不结冰即可。异叶南洋杉顶端优势较强，当植株长到一定的高度后，可将顶部截去，以控制植株高度；对于侧枝也要疏剪，以使其高低错落，疏密有致，合乎造型要求，但对于轮生枝则要有选择地保留，以突出，保持其特有风貌。每1至2年的春季翻盆一次，盆土宜用疏松肥沃，含腐殖质丰富的中性至微酸性土壤。', '　　异叶南洋杉又名　\n　一、扦插床的建造\n　　扦插床用砖砌成，高25m，宽10Ocm，长度以扦插数量而定，床底平整，床内放大扦插基质，稍微整平压实即可投入使用。　\n　二、扦插环境的选择\n　　扦插环境的选择对扦插成活十分重要，异叶南洋杉适宜的生根温度为15－25度，湿度为70％－80％，并有足够的光照，以弱度遮荫为好，选择在这样湿润条件下设置的扦插场所进行扦插繁殖，容易形成不定根和不定芽，成活率高。　\n　三、扦插方法\n　　根插以行插为好，株距4cm，行距6cm为宜，用宽6cm，长1OOcm，厚2cm的板条为尺子，放在沙床上为行距，用小铲沿着木板的边缘开斜沟，深度为7cm左右，穗条插入沙床以2／3为好，然后以4cm左右的等距离将穗条整齐地摆在沟内，务必将头朝上，然后覆沙压实，插完后浇一次透水。', 'http://img.boqiicdn.com/Data/BK/P/imagick92131448356993.jpg', 'http://www.boqii.com/entry/detail/2248.html', '');
INSERT INTO `plant_family` VALUES ('156', '凤凰木', 'Delonix regia', '凤凰木', '红花楹树、凤凰树、火树、红花楹、影树、金凤', '不容易死', '中国南部及西南部、原产地马达加斯加及世界各热带地方', 'http://www.boqii.com/entry/photo/2106/0,http://www.boqii.com/entry/photo/2106/5421', '蓝藻　', '被子门', '双子叶植物纲', '蔷薇目', '豆科', '凤凰木属', '凤凰木', 'Delonix regia', '', '　　 　　凤凰木为高大落叶乔木，无刺，高达20余米，胸径可达1米；树皮粗糙，灰褐色；树冠扁圆形，分枝多而开展；小枝常被短柔毛并有明显的皮孔。浅根性，但根系发达，抗风能力强。抗空气污染。萌发力强，', '　　不但是非洲马达私家共和国的国树，也是厦门市、台湾台南市、四川攀枝花的市树。凤凰木的植株比较高大，在热带地区是遮阴树，现在在我国南部及西南部有分布。　　凤凰木原产地为非洲马达加斯加，野外属。目前已由人工作为观赏树引种栽培。世界各热带、暖亚热带地区广泛引种。凤凰木为热带树种，喜光和高温多湿气候，适温20～30℃，不耐寒。栽培地以全日照或半日照均能适应。土质以深厚肥沃、富含有机质的沙质壤土为宜；怕积水，排水须良好，较耐干旱，耐瘠薄土壤。浅根性，但根系发达，抗风能力强，抗污染。不怕轻霜，在深厚肥沃的冲积土上生长较好。　　凤凰木在移栽以春季发芽前成活率高，也可雨季栽植，但要剪去部分枝叶，保其成活。植株葫芽力强，可以来取截干法大苗，定植后每年松土，除草2～3次，适时浇水，春、秋各施一次追肥，及时除去根部萌蘖条，以保证树体生长良好。', '　　凤凰木是比较常见的树种，常见于　　凤凰木主要用播种法繁殖。12月种子成熟，采集荚果取出种子干藏，翌年春季播种。播种前用开水浸种，待冷却后继续浸泡1～2天，中间换清水1—2次，播种后6—7天开始发芽，20多天可出齐苗，一年生苗可达1.5米左右。　\n　1、种子采集\n　　凤凰木多用播种法繁殖。采种母树应选择10～25年生，树干通直健壮、无病虫害的植株，于每年的10月下旬～12月中旬进行采种。由于凤凰木果实成熟后不易自然脱落，采种期可持续到第2年开花前，若春季育苗，当地又有种源，可不必提前采种保存。凤凰木种子果皮角质厚实，比较耐藏，2～3年种子仍不失发芽力。每1kg种子1000～1200粒，发芽率在50％左右。　\n　2、苗圃地的实地选择\n　　苗圃是生产苗木的基地。苗圃地的选择，直接关系到育苗工作的成功与失败，影响到苗木的产量。　　①土壤条件：选择疏松、肥沃、排水良好的壤土或沙壤土，这样的土壤适于苗木种子的发芽、　\n　3、苗圃地的准备\n　　育苗可在原有固定苗圃进行，但若新选临时苗圃，应选择交通方便或离栽植地较近的地点，通风良好，地势较平缓，利于排灌且地下水位较低的地块。播种前1个月深翻晒土，清除杂草、施入腐熟有机肥，以厩肥和堆肥为最好，667m2施2500kg左右，同时撒施过磷酸钙50～100kg和70％的甲基托布津粉剂0.5kg。经犁耙形成细土，然后作畦。畦面平整，土壤疏松。畦面宽1m，长度因地形而定，步行道宽30cm，床向应有利于通风透光，以南北向最佳，每667m2用3％呋喃丹及50％敌克松各1kg进行土壤消毒。　　\n4、种子处理\n　　凤凰木种子的种　　', 'http://img.boqiicdn.com/Data/BK/P/imagick2021444470101.jpg', 'http://www.boqii.com/entry/detail/2106.html', '');
INSERT INTO `plant_family` VALUES ('157', '藿香蓟', 'Ageratum conyzoides  L.', '藿香蓟', '霍香蓟、胜红蓟、一枝香', '不容易死', '', 'http://www.boqii.com/entry/photo/2245/0,http://www.boqii.com/entry/photo/2245/5280', '', '', '', '', '', '', '', '', '', '　　藿香 藿香蓟 　　藿香蓟是一年生草本植物，高50－100厘米，有时又不足10厘米。无明显主根。茎粗壮，基部径4毫米，或少有纤细的，而基部径不足1毫米，不分枝或自基部或自中部以上分枝，或下基部平卧而节常生不定根。全部茎枝淡红色，或上部绿色，被白色尘状短柔毛或上部被稠密开展的长绒毛。　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　藿香)原产于墨西哥，光照充足的环境，并且不耐寒。人工栽种的难度并不高，只要根据其习性为其布置适宜的生活环境即可。盆栽藿香蓟应该注意以下几点。　　1、光照：喜阳光照射，也耐半阴。　　2、：不耐寒，喜温暖气候，遇酷暑则。　　3、土壤：对土壤要求不严，除黏重土壤外，均可栽植。　　4、浇水：根据土壤干湿情况浇水，使基质干湿交替，如果床土过湿易得病。定植后，可每5～7天浇1次水。　　5、施肥：在其生长期，可追施腐熟有机液肥1～2次。　　6、修剪：霍香蓟花期长，要保持株型矮、紧凑，多花美观，必须进行多次摘心，一般要摘心打尖3—4次。要形成圆整的株型，各分枝顶端都能形成花蕾，同期开花，使其枝叶繁茂，花多色艳。第一批花开过后，要及时整枝修剪，一般老枝保留5—6厘米高，上部剪掉，同时疏剪过密枝条。　　7、冬季管理：霍香蓟不耐寒，在霜冻来临前要移入室内，放阳光充足地方，夜间温度应在5℃以上，白天温度10℃—15℃便能正常生长开花。每隔3—5天浇1次水，每半月浇1次稀饼肥水。', '　　藿香', 'http://img.boqiicdn.com/Data/BK/P/imagick4051448271542.jpg', 'http://www.boqii.com/entry/detail/2245.html', '');
INSERT INTO `plant_family` VALUES ('158', '毛海星', 'Crassula sp.（Transvaal，Drakensberg）', '毛海星', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2451/0,http://www.boqii.com/entry/photo/2451/4965', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '青锁龙属', '毛海星', 'Crassula sp.（Transvaal，Drakensberg）', '', '　　 　　毛海星叶片交互环生。叶片有很多毛刺，容易群生，花季在晚冬到早春，花开白色，五瓣，花朵在枝条顶端穗状簇生，花杆带绒毛。', '　　的栽培难度并不高，比较容易群生，但是也并不慢。毛海星原产于南非，现在在世界多地均有栽培，并且越来越多的花友将毛海星盆栽放在室内观赏。　　毛海星春天和秋天是生长期，可以全日照，浇水是干透才浇透，不干不浇水。会轻微休眠，通风遮阳，每个月3到4次水，少量在盆边给水。以维持植株根系不会因为过度干燥而干枯。低于5度就要逐渐断水，3度以下保持盆土干燥，尽量保持不低于零下5度，可以耐轻微的霜冻。', '　　由于　　毛海星的繁殖方式一般有分株、砍头及扦插等几种方式。一般用侧芽分株繁殖比较好，剩下部分会萌生更多的侧芽，当然了对于毛海星的繁殖还有播种的方式，一般播种繁殖的方式适合大量种植毛海星的，像多肉大棚那样，由于毛海星的植株授粉必须是异花授粉，它的花朵比较小，一般授粉都有点难度，需要用微型的授粉笔耐心授粉。为此一般对于花友来说不建议用播种的方式繁殖。', 'http://img.boqiicdn.com/Data/BK/P/imagick41891453715532.jpg', 'http://www.boqii.com/entry/detail/2451.html', '');
INSERT INTO `plant_family` VALUES ('159', '六倍利', 'Lobelia erinus Thunb', '六倍利', '翠蝶花、山梗菜、花半边莲、南非半边莲', '不容易死', '原产于南非洲，我国多个省份都有分布', 'http://www.boqii.com/entry/photo/2148/0,http://www.boqii.com/entry/photo/2148/5379', '', '', '', '', '', '', '', '', '', '　　 　　六倍利的株高约12～20公分，茎枝细密。茎上部叶较小成披针形，近基部的叶稍大，成广匙形，叶互生。花顶生或腋出，花冠先端五裂， 下3裂片较大，形似蝴蝶展翅，花色有红、桃红、紫、紫蓝、白等色。 可以入药。　　　　　　　　　　　　　　　　　', '　　六倍利为桔梗科半边莲属下的一个种，为多年生草本', '　　　　\n一、播种方法\n　　要注意翠蝶花的种子细小，所以播种时可混入一些细砂再行播种，或先育苗至本叶6～8枚时移入盆中或花坛栽培；并使用细孔之喷壶浇水，力道千万不可过猛，以防种子流失。1－3月播种，7月以后开花；8－10月播种，第二年开花。种子在22摄氏度温度下播种后20天可以发芽。一般普遍用作盆栽与吊盆植物或与其它花卉混合种植。植株生长缓慢，种子非常细小，发芽时不需覆盖。对高温不适应，12－15摄氏度气温下生长较好。播种后65可以开花。一般每穴播8－12粒种子。　　幼苗期注意松土除草。栽种后施1次稀人粪尿；夏季收获后追施1次畜粪或硫酸铵、尿素等；冬季施腐熟肥或堆肥。遇干旱季要灌从，经济保持土壤湿润，以利生长。在定植的同时要加入长效肥，之后每隔三周左右再追肥，尤其在花期来临前，要　　不少花友不知道六倍利什么时候播种，对于六倍利的播种　　8月播种，苗会很早成型，大概在2月底到3月初可以开花，但是由于气候条件的原因，花草开花日照和温度很难保证，开花效果不理想，比较稀疏。随着气温的升高，枝条节间变长，开出来的效果会松散，达不到很丰满的目标，当然，你要是　　9月播种是最适合的，特别是中旬的气候条件。10月播种，气温下降会比较快，苗期漫长，整个冬天生长缓慢，所以比较考验花友的耐心。随着春天气温的升高，苗才逐步生长，留给摘心控制的时间会比较短，要想出来很好的效果会有难度10月份播种的苗也能拉扯大，也能开花，但是因为正适合生长的季节气温已经比较高了，所以节间会比较长，开花的密集程度也会大打折扣。　　因为这个花卉比较不耐热，所以在很多地方赏花时间是有限的，你也不希望好不容易拉扯了半年多的，一下子就没了吧。　　\n二、播种要点\n　　要注意翠蝶花的种子细小，所以播种时可混入一些细砂再行播种，或先育苗至本叶6～8枚时移入盆中或花坛栽培；并使用细孔之喷壶浇水，力道千万不可过猛，以防种子流失。　　1－3月播种，7月以后开花；8－10月播种，第二年开花。种子在22摄氏度温度下播种后20天可以发芽。一般普遍用作盆栽与吊盆植物或与其它花卉混合种植。植株生长缓慢，种子非常细小，发芽时不需覆盖。对高温不适应，12－15摄氏度气温下生长较好。播种后65可以开花。一般每穴播8－12粒种子。', 'http://img.boqiicdn.com/Data/BK/P/imagick11371445851246.jpg', 'http://www.boqii.com/entry/detail/2148.html', '');
INSERT INTO `plant_family` VALUES ('160', '吹雪之松锦', 'Anacampseros telephiastrum Sunset', '吹雪之松锦', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2370/0,http://www.boqii.com/entry/photo/2370/5046', '　　', '被子植物门', '双子叶植物纲', '中央种子目', '科', '回欢草属', '', 'Anacampseros telephiastrum Sunset', '', '　　 　　吹雪之松锦的顶端叶片似莲花展开，叶面厚实，五彩雍华，喜阳（全日照），但忌长', '　　吹雪之松锦又称回欢草，其栽培难度不高，非常适合放在阳台、窗前。吹雪之松锦的休眠期为冬夏两季，人工栽培时应注意休眠期的浇水量，以免植株出现的情况。　　1、和光照：吹雪之松锦光照充足的生长环境，春天和秋天可以全日照，此外夏季要适当遮阳，防止植株被晒伤。　　2、浇水：吹雪之松锦的浇水方式和大多数多肉一样，都是干透后浇透，夏季要避免雨淋，冬季可以适当浇点水，一般零下3度就要保持盆土干燥。', '　　　　吹雪之松锦繁殖可以用种子播种或侧枝，取下', 'http://img.boqiicdn.com/Data/BK/P/imagick89351451380066.jpg', 'http://www.boqii.com/entry/detail/2370.html', '');
INSERT INTO `plant_family` VALUES ('161', '兜唇石斛', 'Dendrobium aphyllum （Roxb. ） C. E. Fischer', '兜唇石斛', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2351/0,http://www.boqii.com/entry/photo/2351/5065', '　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '石斛属', '兜唇石斛', 'Dendrobium aphyllum （Roxb. ） C. E. Fischer', '', '　　兜唇 　　兜唇石斛是草本', '　　兜唇石斛为草本植物，常生于海拔400－1500米的疏林中树干上或山谷上，开花后非常漂亮，有一定的观赏价值，受到很多花友的喜爱。　　根据兜唇石斛的习性，石斛类栽培地宜选半阴半阳的环境，空气湿度在80％以上，冬季气温在0℃以上地区。人工可控环境也可，树种应以黄桷树、梨树、樟树等且应树皮厚有纵沟、含水多、枝叶茂、树干粗大的活树，石块地也应在阴凉、湿润地区，石块上应有生长及表面有少量腐殖质。　　栽植初期先放在阴凉阴凉并有散射光处，仅向叶面上喷些水，勿向盆内浇水。约10－15天后，待萌发出新根后两移至阴棚下养护。生长季节浇水要干湿相间保持适度干薄饼肥水。生长旺盛期树每天浇水一次，干旱季节和炎夏还需经常在花盆四周地面上喷水，以保持较高的空气湿度，并要注意通风良好。冬季应少浇水。后期空气湿度过小要经常浇水保湿，可用喷雾器以喷雾的形式浇水。　　由于石斛类为气生根，因此要喷施适宜的叶面肥作为营养液，以供给植株充足的养分，利早发根长芽。叶面肥可以选择硝酸钾、磷酸二氢钾、腐植酸类等，以及进口三元复合肥和稀释的MS基等。一般移栽后一周，植株新根发生后开始喷施千分之一的硝酸钾或磷酸二氢钾，7－10天喷一次，连续喷3次。长出新芽后每隔10－15天喷3‰的三元复合肥等。生长地贫瘠应注意追肥，第一次在清明前后，以氮肥混合猪牛粪及河泥为主。第二次在立冬前后用花生鼓、菜籽饼、过磷酸钙等加入河泥调匀糊在根部，此外尚可根外追肥。', '　　兜唇　\n　一、分株\n　　选择　\n　二、分芽\n　　盆裁3年以上的植株或部分秋石斛茎的顶部或基部长有小植株时，可以进行切芽繁殖。选择具有3－4片叶，2－3条根，根长4－5厘米的小植株，从母株上切下，用草木灰或70％的代森锰锌处理伤口，将苗植入盆中即可。汪意要浅植。栽培2年后一般可开花成为商品花。　　\n三、扦插\n　　扦插繁殖可以结合花后换盆和分株时一起进行。石触兰多具有细长、带肉质的茎，茎上有许多节，节上能长芽，所以能用扦播繁殖。选择未开花且较充实的整做播条，将技条切成数段，每段具2－3个节，在伤口上涂上草木灰或70％的代森锰锌处理伤口。将茎一段一段地插入', 'http://img.boqiicdn.com/Data/BK/P/imagick38131450776421.jpg', 'http://www.boqii.com/entry/detail/2351.html', '');
INSERT INTO `plant_family` VALUES ('162', '豆瓣绿', 'Peperomia magnolifolia', '豆瓣绿', '椒草、翡翠椒草、青叶碧玉、豆瓣如意、小家碧玉', '不容易死', '原产西印度群岛、巴拿马、南美洲北部', 'http://www.boqii.com/entry/photo/1968/0,http://www.boqii.com/entry/photo/1968/5559', '', '', '', '', '', '', '', '', '', '　　 　　豆瓣绿株高15－20厘米。无主茎。叶簇生，茎肉质较肥厚，倒卵形，灰绿色杂以深绿色脉纹。穗状花序，灰白色。栽培种有斑叶型，其叶肉质有红晕；花叶型，其叶中部绿色，边缘为一阔金黄色镶边；亮叶型，叶心形，有金属光泽。皱叶型，叶脉深深凹陷，形成多皱的叶面，极为有趣。　　　　　　　　　　　　　　　　　', '　　豆瓣绿又名胡椒草，由于植株比较矮小，并且四季常青，深受花友们的喜爱。豆瓣绿原产于巴西，但是忌强光，怕寒冷，所以根据其习性是非常适合在室内栽培的。　　盆土要求疏松，排水良好。常用腐叶土、园土和碧糠灰各1份混合使用。平时注意光线适度，肥水合理。豆瓣绿喜阴凉湿润环境，在散射光下生长较好。春秋季节气候温和，阳光不太强烈，可把盆栽放置室外。但夏季不能受强光直射，尤其不能放在西晒太阳的场所，否则会造成枝叶发黄。因此，在春来之后，需把盆移到阳台、走廊等凉爽遮阳处或放置在室内，既可避免光硒，又可点级室内。　　豆瓣绿不耐藉冻，在秋末后应移到室内培养。严寒冬季尽放在朝南窗口有阳光的地方，室温5℃就能越冬。　　肥水管理也很重要，一般2年生的植株生长较好，3年以上植株长势逐渐衰退，应考虑更新。　　施肥不必太勤，一般春秋季节每隔10天左右施1次20％的腐熟饼肥水就可以。夏季高温，停止施肥，以免烂根。　　浇水要盆土干湿相宜，生长过程中，春秋是旺季，水量多些。夏季天气炎热但植株因高，其生长反而缓慢，可早晨或傍晚各浇水1次，高温多湿茎叶易烂，具体看天气及盆土而定。盆土应略偏干一些，因其茎叶肉质肥厚，过湿易使根部腐烂，特别是冬季因气温低，呈休眠状态，盆土宜带干。此外，为了保持植株叶色翠绿，3年以后需要更新。', '　　豆瓣绿是非常有名也非常常见的室内　　在豆瓣绿的　　扦插的基质可以选择营养土或河砂、泥碳土等材料都可以，分株比较简单就不多说了。　　当然有花友会问及豆瓣绿叶插繁殖，豆瓣绿叶插生根很容易，但是发芽的　　当然也有花友', 'http://img.boqiicdn.com/Data/BK/P/imagick4801440149795.jpg', 'http://www.boqii.com/entry/detail/1968.html', '');
INSERT INTO `plant_family` VALUES ('163', '若绿', '', '若绿', '', '不容易死', '纳米比亚', 'http://www.boqii.com/entry/photo/2354/0,http://www.boqii.com/entry/photo/2354/5062', '　', '', '', '', '景天科', '青锁龙属', '', '', '', '　　 　　若绿的叶片很小，且大部分时间会呈现绿色，只有日照充足时顶部的叶片才会变红。', '　　具有冷凉，夏季高温休眠的习性，所以在不同的环境下对于若绿的栽培也应做出相应的改变。若绿的生长强健，人工栽培的难度不高，小编就为你介绍一下若绿的栽培要点，的朋友可以一起了解。　　若绿生长适温15－30度，冬季不低于5度；配土一般用泥炭、粗沙的混合土；生长期浇水干透浇透；生长期施肥一般每两月一次；特别适合放在组合盆栽中，因其生长迅速很容易就能遮盖住组合中的空白部分，单独栽种效果略逊于组合，选择好花器再搭配起来就会很美观！　　每年的9月至第二年的6月为若绿的生长期（花友的环境不一样，生长期也有长短），若光照不足会使，叶与叶之间的上下距离拉长，使得株型松散，叶杆变嫩，而在阳光充足之处生长的植株，株型矮壮，茎节之间排列相对紧凑。　　若绿最应该引起注意的是浇水量一定要少、浇水频率要低。由于景天类根系很弱，需要排水良好的条件，尤其在冬季更需要尽快排出多余水分，否则会引起烂根。', '　　　\n　1、扦插\n　　春夏期间，将饱满鳞片状茎枝剪下，即可插入盛有砂或砂壤盆、箱内，喷水增加盆土和空间湿度，置阴蔽处，生根较易。　\n　2、分株\n　　从春至秋，均宜进行分株繁殖，方法是将小盆植株翻盆倒出，去掉根部部分泥土，用小剪刀把当年生匍匐状叶片，齐根剪开，用小刀切开分成几份，然后连土带根，移栽上盆。根据植株大小，分栽成几个小盆。上盆后，用细土覆掩根部，让鳞状叶片露出土面，而后捏住盆缘在地上轻轻墩实，浇透水，再摆入室内或荫棚内，一周后即成活。仙人柏全年均可在室内', 'http://img.boqiicdn.com/Data/BK/P/imagick89581450863968.jpg', 'http://www.boqii.com/entry/detail/2354.html', '');
INSERT INTO `plant_family` VALUES ('164', '白芨', 'Bletilla striata', '白芨', '紫兰、苞舌兰、连及草等', '不容易死', '长江流域各省，朝鲜半岛和日本等', 'http://www.boqii.com/entry/photo/2075/0,http://www.boqii.com/entry/photo/2075/5452', '　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '白芨属', '白芨', '', 'Bletilla striata', '　　 　　白芨的初生假鳞茎是圆球形，　　白芨的花序具3－10朵花，常不分枝或极罕分枝；花序轴或多或少呈“之”字状曲折；花苞片长圆状披针形，长2－2.5厘米，开花时常凋落；花大，紫红色或粉红色；萼片和花瓣近等长，狭长圆形，长25－30毫米，宽6－8毫米，先端急尖；花瓣较萼片稍宽；唇瓣较萼片和花瓣稍短，倒卵状椭圆形，长23－28毫米，白色带紫红色，具紫色脉；唇盘上面具5条纵褶片，从基部伸至中裂片近顶部，仅在中裂片上面为波状；蕊柱长18－20毫米，柱状，具狭翅，稍弓曲。花期4－5月。果期7－9月。有变种白花白芨，花白色，园艺', '　　在我国大多还是依赖野生，但是随着市场对于白芨的需求日益增大，野生的白芨资源就越来越少。现在，人工种植白芨已经成为了一些人的经济来源，那么白芨应该如何栽种呢？　　1、选地整地：选择疏松肥沃的沙质壤土和腐殖质壤土，温暖、稍阴湿环境，不耐寒。排水良好的山地栽种时，宜选阴坡生荒地栽植。把土翻耕20厘米以上，施厩肥和堆肥，每亩施农家肥1000公斤，没有农家肥可撒施三元复合肥50公斤。再翻地使土和拌均匀。栽植前浅耕一次，把土整细、耙平、作宽130～150厘米的高畦。　　2、田间　　（1）中耕除草：白芨对田间管理除草要求很严格，种植好喷洒除草剂乙草胺封闭。白芨苗出齐后，5～6月份的很旺盛，杂草也长的很快，必须及时除草。结合搂松畦面，除草时要浅锄，免得伤根。　　（2）追肥：白芨是喜肥的，每个月喷施一次磷酸二氢钾或稀薄的人畜粪尿，7～8月停止生长进入休眠，但是要防止杂草丛生。　　（3）灌溉和排水：白芨喜荫，经常保持湿润，干旱时要浇水，7～9月份早晚各浇一次水。白芨又怕涝，大雨及时排水避免伤根。', '　　　　白芨喜温暖、阴凉和较阴湿的环境，不耐寒。常常野生在丘陵和低山地区的溪河两岸、山坡草丛中及疏林下。故应选择肥沃、疏松而排水良好的砂质壤土或腐殖质壤土栽培，要求栽培在阴坡或较阴湿的地块。　　白芨用种子播种较难，分块茎繁殖较易，大面积发展时可选用组培苗繁殖。块茎繁殖一般9－－11月初将白芨挖出，选大小中等，芽眼多，无病的块茎，每块带1－－2个芽，沾草木灰后栽种。开沟沟距20－－－25厘米，深5－－6厘米，按株距10－－－12厘米放块茎一个，芽向上，填上，压实，浇水，覆草，经常保持潮湿，3－－4月出苗。亩用种苗100公斤。', 'http://img.boqiicdn.com/Data/BK/P/imagick55171443172018.jpg', 'http://www.boqii.com/entry/detail/2075.html', '');
INSERT INTO `plant_family` VALUES ('165', '珍珠梅', 'Sorbaria sorbifolia （L.） A. Br.', '珍珠梅', '山高粱条子，高楷子，八本条（东北土名）', '不容易死', '中国华北地区、西北地区，苏联、朝鲜、日本、蒙古亦有分布。', 'http://www.boqii.com/entry/photo/2086/0,http://www.boqii.com/entry/photo/2086/5441', '', '', '', '', '', '', '', '', '', '　　　　珍珠梅为灌木，高达2米，枝条开展；小枝圆柱形，稍屈曲，无毛或微被短柔毛，初时绿色，老时暗红褐色或暗黄褐色；冬芽卵形，先端圆钝，无毛或顶端微被柔毛，紫褐色，具有数枚互生外露的鳞片。羽状复叶，小叶片11－17枚，连叶柄长13－23厘米，宽10－13厘米，叶轴微被短柔毛；小叶片对生，相距2－2.5厘米，披针形至卵状披针形，长5－7厘米，宽1.8－2.5厘米，先端渐尖，稀尾尖，基部近圆形或宽楔形，稀偏斜，边缘有尖锐重锯齿，上下两面无毛或近于无毛，羽状网脉，具侧脉12－16对，下面明显；小叶无柄或近于无柄；托叶叶质，卵状披针形至三角披针形，先端渐尖至急尖，边缘有不规则锯齿或全缘，长8－13毫米，宽5－8毫米，外面微被短柔毛。　　　　　　　　　　　　　　　　　　　　　　　', '　　耐寒、耐半荫，在排水良好的砂质土壤中能够良好，也是良好的夏季观花植物。此外，珍珠梅还耐一定的水湿环境，但是不能长的积水，不然容易烂根。　　珍珠梅适应性强，对要求不高，除新栽植株需施少量底肥外，以后不需再旋肥，但需浇水，一般在叶芽萌动至开花期间浇2－3次透水，立秋后至霜冻前浇2～3次水，其中包括l次防冻水，夏季视干旱情况浇水，雨多时不必浇水。花谢后花序枯黄，影响美观，因此应剪去残花序，使植株干净整齐，并且避免残花序与植株争夺养分与水分。秋后或春初还应剪除病虫枝和老弱枝，对一年生枝条可进行强修剪，促使枝条更新与花繁叶茂。　　1、对土壤要求不严，但是栽培在深厚肥沃的沙壤土中则生长更好，开花更繁茂。　　2、对施肥要求不高，刚栽培时需施足基肥，就能满足其生长要求，一般不再施追肥。以后结合冬季，每隔1～2年施1次基肥即可。　　3、春季干旱时要及时浇水，夏秋干旱时，浇水要透，以保持土壤不干旱；入冬前还需浇1次防冻水。　　4、花后要及时修剪掉残留花枝、病虫枝和老弱枝，以保持株型整齐，避免养分消耗，促使其生长健壮，花繁叶茂。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick20601443519568.jpg', 'http://www.boqii.com/entry/detail/2086.html', '');
INSERT INTO `plant_family` VALUES ('166', '紫玄月', 'Othonna capensis', '黄花新月', '紫弦月', '不容易死', '南非、纳米比亚', 'http://www.boqii.com/entry/photo/2375/0,http://www.boqii.com/entry/photo/2375/5041', '　', '种子植物门', '双子叶植物纲', '钟花目', '菊科', '厚敦菊属', '黄花新月', 'Othonna capensis', '', '　　 　　紫玄月的叶片非常奇特，高度肉质化，纺锤形，日照充足时为扁球形。茎不太肉质，平卧地面或垂吊，平常绿色，日照充分的情况下会从绿色变为紫红色，故得名。秋冬开黄色小花，头状花序，具舌状花，花序直径约1－2cm。', '　　的栽培难度并不高，但是需注意的是，紫玄月几乎没有，夏季高温时应注意减少浇水量。人工栽培紫玄月的难度并不高，需要注意布置合适的环境。　　紫玄月喜温暖和阳光充足的环境，较喜水，忌强光暴晒，夏季高温半休眠，在露天环境下叶片于枝条会变为紫红色，对于新扦插的枝条，用微潮的土壤，扦插枝条可以覆盖一层薄土，或者用回形针将枝条固定在土表，保持盆土湿润，做好通风，不要太低。浇水的话，用喷壶喷表土就好了，不要搬来搬去的。', '　　　　紫玄月可以通过扦插或是叶插的方式繁殖，　　紫弦月扦插繁殖非常容易，随便剪下一段插入土中，立马浇水，然后等着生根就可以了。', 'http://img.boqiicdn.com/Data/BK/P/imagick30971451467626.jpg', 'http://www.boqii.com/entry/detail/2375.html', '');
INSERT INTO `plant_family` VALUES ('167', '五色梅', 'Lantana camara', '五色梅', '山大丹、如意草、五彩花、五雷丹、五色绣球、变色草、大红绣球', '不容易死', '原产于南美洲、西印度，现世界各国广为栽培。', 'http://www.boqii.com/entry/photo/2144/0,http://www.boqii.com/entry/photo/2144/5383', '', '', '', '', '', '', '', '', '', '　　 　　五色梅为常绿灌木，高1～2米，有时枝条生长呈藤状。茎枝呈四方形，有短柔毛， 通常有短而倒钩状刺。单叶对生，卵形或卵状长圆形，先端渐尖，基部圆形，两面粗糙有毛，揉烂 有强烈的气味，头状花序腋生于枝梢上部，每个花序20多朵花，花冠筒细长，顶端多五裂，状似 梅花。花冠　　　　　　　　　　　　　　　　　　　　　　　　', '　　五色梅的适应能力比较强，耐旱耐瘠，耐碱抗风，耐移植，耐修剪，耐高温。由于五色梅的花色富于变化，每朵花都会有几种相间，非常特殊。现在，五色梅常被用于盆栽或花坛美化等，非常受人欢迎。　　1、五色梅属长日照阳性植物，需强光。栽培地块应选在日照充足处。土壤以肥沃的腐殖土最好，勿渍水。最适宜20℃－30℃。霜冻、降雪时应加盖透光性能较好的防冻材料，若能在室内明亮的窗边培育最佳，因气温低于3℃或长时间没有阳光照射，叶片会变黑，甚至全株枯死。在没有防冻条件时，可在根部培厚土，即使遇到霜冻，枝叶冻坏了，根部也能存货，一遇天气转暖，水分充足，又能旺盛生长起来。　　2、春末至秋季五色梅生长旺盛，要经常修建，保持树形优美。修剪下来的枝条可扦插与苗。旺长、开花期和幼苗期要常浇水。冬季主要应注意防寒防冻，若在封闭式阳台和温室里越冬，则可按常规，不仅能保持枝叶常青并不断开花，而且随时均可扦插与苗。　　3、有人认为五色梅必须经常挪动地方使其接受阳光暴晒才能生长良好。但以我的经验，还是环境稳定，保持恒温为号。冬春如果在采光充足的室内培育，不必经常搬动。如果在温度较低、通风不良、光线较暗的地方，或经数天阴雨，光照不足，一旦天气放晴转暖，则有必要搬到阳光下晒一晒，晚上又搬回室内防冻。', '　　　　\n播种法：\n　　\n扦插法：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick90221445591728.jpg', 'http://www.boqii.com/entry/detail/2144.html', '');
INSERT INTO `plant_family` VALUES ('168', '球花石斛', 'Dendrobium thyrsiflorum Rchb. f.', '球花石斛', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2342/0,http://www.boqii.com/entry/photo/2342/5075', '植物　', '子植物门', '单子叶植物纲', '微子目', '兰科', '石斛属', '球花石斛', 'Dendrobium thyrsiflorum Rchb. f.', '', '　　球花 　　球花石斛茎直立或斜立，圆柱形，粗状，长12－46厘米，粗7－16毫米，基部收狭为细圆柱形，不分枝，具数节，黄褐色并且具光泽，有数条纵棱。叶3－4枚互生于茎的上端，革质，长圆形或长圆状披针形，长9－16厘米，宽2.4－5厘米，先端急尖，基部不下延为抱茎的鞘，但收狭为长约6毫米的柄。', '　　球花有一定的园林价值，可以作为园艺品种，也可以栽种在庭院或者花坛当物。此外，还是很好的切花原料，但是球花石斛的花期短暂，所以我们能看到其开花的时间并不长，那么如何才能养好球花石斛呢？　　　球花石斛通常选用四壁多孔的塑料或陶瓷花盆，用碳根、泥炭藓、树皮块、木炭块等作盆栽材料。根据兰苗的大小，选择不同规格的花盆，但不宜用大盆栽小苗口上述栽好材料在使用前必需在清水中浸泡1天以上备用。盆底要多垫大瓦片或碎砖块，深度至盆底约1／3处，然后将兰苗放于盆中央，并在一旁插一细竹竿以固定兰苗，再填入其他栽培材料，注意根与根之间用材料隔开。　　　　栽植初期先放在阴凉阴凉并有散射光处，仅向叶面上喷些水，勿向盆内浇水。约10－15天后，待萌发出新根后两移至阴棚下养护。生长浇水要干湿相间保持适度干薄饼肥水。生长旺盛期树每天浇水一次，干旱季节和炎夏还需经常在花盆四周地面上喷水，以保持较高的空气湿度，并要注意通风良好。冬季应少浇水。后期空气湿度过小要经常浇水保湿，可用喷雾器以喷雾的形式浇水。　　　　刚移栽的组培苗对水分很敏感，缺水则生长缓慢、干枯、成活率低。而喷雾过多则渍水烂根，温度高、湿度大时还易引发软腐病大规模发生。移栽后一周内（幼苗尚未发新根）空气湿度宜保持在90％左右，一周后，植株开始发新根，空气湿度可保持在70％－80％。种植畦干湿交潜有利于发根长芽。忌强光直射，春秋两季早上可见阳光，冬季可置光照充足处，其他时间置于具有明亮散射光而又通风的地方。越冬温度保持在8－10℃即可。　　　由于石斛类为气生根，因此要喷施适宜的叶面肥作为营养液，以供给植株充足的养分，利早发根长芽。叶面肥可以选择硝酸钾、磷酸二氢钾、腐植酸类等，以及进口三元复合肥和稀释的MS培养基等。一般移栽后一周，植株新根发生后开始喷施千分之一的硝酸钾或磷酸二氢钾，7－10天喷一次，连续喷3次。长出新芽后每隔10－15天喷3‰的三元复合肥等。生长地贫瘠应注意追肥，第一次在清明前后，以氮肥混合猪牛粪及河泥为主。第二次在立冬前后用花生鼓、菜籽饼、过磷酸钙等加入河泥调匀糊在根部，此外尚可根外追肥。　　　　石斛生长地的都闭度在60％左右，因此要经常对附生树进行整枝修剪，以免过于荫蔽或郁闭度不够。每年春天前发新整时，结合采收老茎将丛内的枯茎剪除，并除去病茎、弱茎以及病者根，栽种6－8年后视丛蔸生长情况翻蔸重新分枝繁殖。', '　　很多人都知道球花　\n　一、分株\n　　选择　　\n二、分芽\n　　盆裁3年以上的植株或部分秋石斛茎的顶部或基部长有小植株时，可以进行切芽繁殖。选择具有3－4片叶，2－3条根，根长4－5厘米的小植株，从母株上切下，用草木灰或70％的代森锰锌处理伤口，将苗植入盆中即可。汪意要浅植。栽培2年后一般可开花成为商品花。　\n　三、扦插\n　　扦插繁殖可以结合花后换盆和分株时一起进行。石触兰多具有细长、带肉质的茎，茎上有许多节，节上能长芽，所以能用扦播繁殖。选择未开花且较充实的整做播条，将技条切成数段，每段具2－3个节，在伤口上涂上草木灰或70％的代森锰锌处理伤口。将茎一段一段地插入', 'http://img.boqiicdn.com/Data/BK/P/imagick40531450430822.jpg', 'http://www.boqii.com/entry/detail/2342.html', '');
INSERT INTO `plant_family` VALUES ('169', '雪莲', 'Echeveria laui', '雪莲', '', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/2435/0,http://www.boqii.com/entry/photo/2435/4980', '', '', '', '', '', '', '', '', '', '　　 　　雪莲茎部约5～10厘米长，直径约1.5厘米。通常不出侧芽或分枝。叶片呈倒卵形，宽大肥厚，顶端圆钝或稍尖，偶尔出现叶片呈现出短尖头的植株。成株叶片长约5.0～8.5厘米，宽约3～4.5厘米，厚约0.3～0.8厘米。叶片腹面平坦或稍有凹陷。灰绿色的叶片被浓厚的浅蓝色或白色霜粉覆盖，在阳光充足的环境下会呈现出浅粉色或浅紫色。　　　　　　　　　　　　　　　', '　　在多肉中是非常受欢迎的，很多多肉爱好者都非常迷恋雪莲。雪莲正常的叶片表面会有一层白粉，好像覆盖了一层薄雪一样，那么，如何才能养出漂亮的雪莲呢？小编就为你介绍一下。　　雪莲植株茎很短，肉质的叶片呈莲座状排列生长，叶片表面覆盖着灰白或淡蓝色粉末，叶片顶端圆钝或微尖。雪莲叶片厚薄均匀，擦去白粉，雪莲叶片呈现淡紫红色，雪莲生长比较缓慢，冬季温度低于5度基本就休眠了。植料用的是泥炭＋珍珠岩＋浮石，比例1.5：1：3混合后就可以了。因为雪莲是石莲花属的，一般上盆后会浇透水，放在通风的地方等待长新根。生长后就可以见直射光了，起来还是非常简单的，生长期水分也是干透才可以浇水，水分一定不要弄到叶片上，不然就留下了难看的疤痕了，夏季半阴养护，也就是早上到11点可以见到太阳，其他时间都是散射光。入秋后就可以全日照了。冬季温度到了5度后，就渐渐停止给水，雪莲肥厚的叶片足够一个冬天的生长。不过虽然是休眠期，冬季还是会微弱给点点水的，春天温度上升后就可以正常养护了。', '　　　　雪莲一般采用叶插和播种的繁殖方法。叶插选取已成熟但没有发黄的叶片，放在明亮通风处风干伤口，然后把叶片平放在稍稍湿润的沙土或粗沙上，放在阴凉通风的地方等待生根，生根以后，叶片上就会慢慢长出小芽。等小芽长到有点大了才可以移盆，移盆的时候尽量带点土，这样有利于小苗在新环境里', 'http://img.boqiicdn.com/Data/BK/P/imagick84071453108567.jpg', 'http://www.boqii.com/entry/detail/2435.html', '');
INSERT INTO `plant_family` VALUES ('170', '姬红小松', '', '姬红小松', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2332/0,http://www.boqii.com/entry/photo/2332/5085', '植物　　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '舌叶花属', '', '', '', '　　 　　姬红小松株高15－20cm，株幅20cm。茎干肥厚多肉，多分枝，粗糙，黄褐色，顶端丛生纺锥形肉质小叶，淡绿色，长1－2cm，顶端丛生细短白毛。花顶生，', '　　很多花友会将姬红小松当做风水植物来，由于姬红小松的植株娇小，摆放在家中不但能够净化空气，还能用于观赏，是作用非常多的多肉植物。人工栽培姬红小松的难度并不高，小编就为你介绍一下姬红小松的栽培要点。　　栽培小松要注意水不能浇的太多，小松的根为肉质根，积水容易烂根，春秋三至四天浇一次，夏季气温高水分蒸发快一天浇两次，早上一次傍晚一次。气温低可以七至十天浇一次，用15℃左右的温水浇，不能用很冷的水浇，要在晴天的中午浇，要浇透。在春夏秋三季的期间七至十天浇一次液肥。液肥是动植物残渣加水经过充分发酵腐熟而成的高浓度肥料，使用前要用水以1：5～10的比例稀释后施。　　对小松要经常进行修剪，截短过长的枝条留二至三组对叶，删除过密枝，抹去根蘖芽。每年需翻盆换土。三年的小松的根便会达到可喜的程度。', '　　　　姬红小松的繁殖用当年生壮健枝5～6厘米去除枝端1厘米处的叶片，插入', 'http://img.boqiicdn.com/Data/BK/P/imagick99541450343905.jpg', 'http://www.boqii.com/entry/detail/2332.html', '');
INSERT INTO `plant_family` VALUES ('171', '火炬树', 'Rhus Typhina Nutt', '火炬树', '鹿角漆、火炬漆、加拿大盐肤木', '不容易死', '', 'http://www.boqii.com/entry/photo/2098/0,http://www.boqii.com/entry/photo/2098/5429', '植物　', '被子植物门', '双子叶植物纲', '无患子目', '漆树科', '盐肤木属', '火炬树', 'Rhus Typhina Nutt', '', '　　 　　火炬树为漆树科，盐肤木属，落叶小乔木。高达12m。柄下芽。小枝密生灰色茸毛。奇数羽状复叶，小叶19～23（11～31），长椭圆状至披针形，长5～13cm，缘有锯齿，先端长渐尖，基部圆形或宽楔形，上面深绿色，下面苍白色，两面有茸毛，老时脱落，叶轴无翅。', '　　在秋天的时候叶子会变成鲜艳的红色，具有一定的观赏价值，也是优良的秋景树。但是由于火炬树的繁殖速度非常快，已经被认定有严重的潜在了。　　火炬树，科名漆树科，为漆树科肤木属落叶小乔木。奇数羽状复叶互生，长圆形至披针形。直立圆锥花序顶生，果穗鲜红色。果扁球形，有红色刺毛，紧密聚生成火炬状。果实9月成熟后经久不落，而且秋后树叶会变红，十分壮观。原产欧美，常在开阔的沙土或砾质土上。　　中国1959年由中国科学院研究所引种，1974年以来向全国各省区推广。以黄河流域以北各省（区）栽培较多，主要用于荒山绿化兼作盐碱荒地风景林树种。火炬树繁殖速度之快，直到2012年许多绿化树种都无法相比的，它具有独特的优良特性和严重的潜在危害。', '　　由于　　火炬树繁殖用播种、分孽、根插均可。播种于9月采集成熟果穗，暴晒脱粒，以低温湿沙层积至第二年春播。播前用碱少揉搓，去其种皮上的蜡质，然后用so℃的热水浸烫5分，不断搅拌，然后捞出，混湿沙置于20℃室内催芽，20天左右露芽时即可行条播，每亩播种量3一5千克。只要保持土壤湿润，20天以后基本出齐，当年苗高可达0.8一1米。火炬树的萌孽力极强，二年生以上的', 'http://img.boqiicdn.com/Data/BK/P/imagick66321444382790.jpg', 'http://www.boqii.com/entry/detail/2098.html', '');
INSERT INTO `plant_family` VALUES ('172', '矮牵牛', 'Petunia hybrida （J. D. Hooker） Vilmorin', '碧冬茄', '矮牵牛／杂种撞羽朝颜／灵芝牡丹／毽子花／矮喇叭／番薯花／撞羽朝颜', '不容易死', '原产于南美洲阿根廷，现世界各地广泛栽培', 'http://www.boqii.com/entry/photo/2215/0,http://www.boqii.com/entry/photo/2215/5312', '', '', '', '', '', '', '', '', '', '　　 　　矮牵牛为多年生草本，常作一、二年生栽培； 株高15～80cm，也有丛生和匍匐类型； 叶椭圆或卵圆形； 播种后当年可开花，花期长达数月，花冠喇叭状； 花形有单瓣、重瓣、瓣缘皱褶或呈不规则锯齿等； 花色有红、白、粉、紫及各种带斑点、网纹、条纹等； 蒴果，种子极小，千粒重约0.1g。园艺　　　　　　　　　　　　　　　　　　　　　　　', '　　随着人们对的喜爱程度越来越深，矮牵牛的品种也越来越多，不过，不同品种的矮牵牛栽种方法都是一样的。现在矮牵牛不但可以露地栽培，还常被花友制作成垂吊型吊篮，非常特别。　用288穴的育苗盘育苗，直接移入10～12厘米口径的营养钵。也可先定植于苗床上，再移入营养钵内，矮牵牛移植后恢复较慢，所以在上盆时应注意尽量多带土。　　矮牵牛为阳性，、开花均需要阳光充足，夏季比较耐高温，一般只在移植后几天加以遮荫，缓苗，在整个生长期均不需要遮荫。非常适宜的光照可以促进开花，增加开花的数量。　　浇水始终遵循不干不浇，浇则浇透的原则，夏季生产盆花，小苗生长前期应勤施薄肥，肥料选择以N、K含量高，P适当偏低。N肥可选择尿素，复合肥则选择N–P–K比例为15–15–15或含N、K高的，浓度控制在0.1～0.2％左右，水溶性肥料一般选择20–10–20和14–0–14两种，浓度在50～100ppm，浓度过高，特别在高温季节易造成肥害。冬季生产盆花，在3～4月勤施复合肥，视生长情况，适当追施N肥。在过于干燥的情况下植株会比较瘦弱，可以通过肥水管理来调节是可以恢复的；但台风或者暴风的情况下对植株造成伤害，是比较难恢复的。　促进分枝可以增加开花数量，在比较大的植株株型不整齐可以进行整理。在分枝的顶端可修剪，这样就会很容易增加一层分枝，一般在计划开花前10天以上进行。长时间观赏的植株太大的情况下，保留1／3的健全的植株进行修剪。在适宜的条件下，恢复的时间需要20天。', '　　　　\n一、扦插繁殖法：\n　　矮牵牛扦插宜在晚春至梅雨期气温不很炎热的时期进行，较易生根成活，也可在秋凉后进行扦插，剪取萌发的顶端嫩枝，长10厘米，插入沙床，插壤　　\n二、播种繁殖法：\n　　矮牵牛的种子甚小，播法及养护得当，发芽率可达60%以上。　　\n三、组织培养繁殖法：\n　　外植体用种子、叶片和受精子房等。若用种子，在洗衣粉溶液中浸泡5分钟，取出后用水冲洗干净。在无菌条件下，先在75％酒精中浸8分钟，再在0.1％氯化汞溶液中浸泡7分钟，取出用无菌水冲洗后，接种在MS（添加6－苄氨基腺嘌呤0.5～1.0毫克／升和萘乙酸0.1毫克／升）的培养基上，接种15天出现小芽，将小芽切割转原来的培养基上进行继代培养，20天后1个小芽可得到10多个芽。将1厘米的壮芽接入含萘乙酸0.05～0.2毫克／升的1／2MS培养基上，10天后，100％生根，成为完整小植株。', 'http://img.boqiicdn.com/Data/BK/P/imagick48711447322252.jpg', 'http://www.boqii.com/entry/detail/2215.html', '');
INSERT INTO `plant_family` VALUES ('173', '彩色马蹄莲', 'Zantedeschia hybrida Spr.', '彩色马蹄莲', '彩色海芋', '不容易死', '原产非洲', 'http://www.boqii.com/entry/photo/2321/0,http://www.boqii.com/entry/photo/2321/5201', '', '', '', '', '', '', '', '', '', '　　彩色 　　彩色马蹄莲为球根花卉。肉质块茎肥大。叶基生，叶片亮绿色，全缘。肉穗花序鲜黄色，直立于佛焰中央，多数品种叶片有半透明斑点。花序具有大型的佛焰苞漏斗状，似马蹄 先端尖反卷。佛焰苞依品种不同，　　　　　　　　　　　　　　　　　', '　　彩色)的栽培管理和白色马蹄莲并没有太大的区别，喜欢温暖湿润且阳光充足的环境，彩色马蹄莲不耐寒冷和干旱，当高于25℃或低于5℃的情况下，就会被迫进入休眠。　　　　块茎需要很多的水分，在生长早期要有规律的浇水，但不要让土太湿，等叶抽出来进入旺盛生长期时注意见干见湿。一般早上浇水，如果天气太热就需要在下午浇水。　　使用滴灌能很好的保持水分，在有风的天气下更适于使用。如果要用喷雾灌溉的话，喷头的距离要精确，以保证水量的均匀分布。喷头必须比植株高1米，喷灌系统必须要有足够的压力（至少4千克压力）。植株在水分过多或过少时抗病性会降低，尤其对软腐病抗性会降低。　　　彩色马蹄莲属于需肥不高的，不同的类型要求不同的肥料水平。用NPK比为20－20－20或12：10：10的均衡肥料，以100ppm的氮浓度每周施一次或200ppm的氮浓度每周施两次左右。　　　　盆栽彩色马蹄莲通常高30－50厘米，可根据种植盆的规格和市场需求来决定是否进行矮化处理。嘧啶醇和多效唑对彩色马蹄莲是有效的，矮化处理对叶片的长度有明显的控制，但对花梗的抽长影响不太明显。', '　　彩色　　彩色马蹄莲可以通过种子进行繁殖，在20度的室温下种子会发芽，也可以通过球茎进行繁殖。当彩色马蹄进入', 'http://img.boqiicdn.com/Data/BK/P/imagick80361450085551.jpg', 'http://www.boqii.com/entry/detail/2321.html', '');
INSERT INTO `plant_family` VALUES ('174', '蓝黛莲', 'xPachyveria ‘Glauca’', '蓝黛莲', '灰蓝奇莲华', '不容易死', '', 'http://www.boqii.com/entry/photo/2463/0,http://www.boqii.com/entry/photo/2463/4953', '　　', '被子植物门', '双子叶植物纲', '', '景天科', 'xPachyveria 厚叶草属与拟属杂交', '蓝黛莲', 'xPachyveria ‘Glauca’', '', '　　 　　蓝黛莲为多年生无毛肉质草本植物。丛生。叶丛莲座状。植株叶片呈环状密集排列，基生，扁梭形或卵形，向内弯曲，有叶尖，叶缘圆弧状，叶背有棱线。叶片光滑，表面覆盖微量白粉，叶片草绿色至墨绿色。阳光充足叶片紧密排列边缘和叶尖会黄红。蓝黛莲的花杆很高。簇状花序红色花朵，花朵倒钟形，串状排列，花开五瓣，初夏开花，可异花授粉。', '　　是景天科的一个杂交品种，有的新手朋友会分不清楚蓝黛莲和)的区别，其实这两者还是有很多不同之处的。想要让蓝黛莲长的漂亮，充足的阳光和正确的浇水是需要非常注意的。　　蓝黛莲夏天的时候通风遮阳，每个月3到4次水，少量在盆边给水慢慢度过盛夏，维持植株根系不会因为过度干燥而干枯就可以。冬天低于3度就要逐渐少水，0度以下保持盆土干燥，尽量保持不低于零下3度。这样就可以安全了，冬天尽量少点水，开春给水要否则可能出现烂根。南北差异比较大，家庭和大棚的养殖方法都不一样，蓝黛莲是比较好养的一个品种，无明显病虫害，每年入夏和入冬撒点呋喃丹在土表就可以了。', '　　　　蓝黛莲的繁殖方法主要有播种和分株、砍头、叶插。很多多肉爱好者一般用叶插来繁殖，土壤用的是泥炭混合珍珠岩加了煤渣，大概比例1：1：1，为了隔离植株和土表', 'http://img.boqiicdn.com/Data/BK/P/imagick29171453972752.jpg', 'http://www.boqii.com/entry/detail/2463.html', '');
INSERT INTO `plant_family` VALUES ('175', '红蕉', 'Musa coccinea', '红蕉', '红花蕉、观赏芭蕉、指天蕉、红姬芭蕉', '不容易死', '中国云南东南部（河口、金平一带）广东、广西、福建等省', 'http://www.boqii.com/entry/photo/2407/0,http://www.boqii.com/entry/photo/2407/5008', '植物　　', '被子植物门', '单子叶植物纲', '芭蕉目', '芭蕉科', '芭蕉属', '红蕉', 'Musa coccinea', '', '　　 　　红蕉的假茎高1-2米。叶片长圆形，长1.8～2.2米，宽68～80厘米，叶面黄绿色，叶背淡黄绿色，无白粉，基部显著不相等，浑圆而无耳；叶柄长30～50厘米，有张开的窄翼。花序直立，序轴无毛，苞片外面鲜红而美丽，内面粉红色，皱折明显，每一苞片内有花一列，约6朵；雄花花被片乳黄色，合生花被片具5 (3+2) 齿裂，二侧裂片具角，离生花被片先端尖且具细齿，与合生花被片几等长。浆果果身直，在序轴上斜向下垂，灰白色，无棱，长10～12厘米，直径约4厘米，果柄长3～3.5厘米，果内种子极多。', '　　红蕉为多年生草本植物，叶大型，并且整个植株和非常相似，故此命名。红蕉的整个花序的苞叶连同小花都呈红色，非常漂亮，所以受到很多花友的喜爱。　　红蕉盆栽可选用大口径的土陶花盆和疏松肥沃、富含腐殖质的砂质土壤进行栽培。在整个生长，盆土需保持湿润，但要控制植株徒长，浇水必须掌握干透浇透的原则。　　盆栽置于室内培育，要定期将盆株移出室外，进行有效的阳光照射，使叶片翠绿光亮。初秋至晚秋要使植株充分逐渐降低的气温，使之逐步适应寒冷的气候，为越冬创造有利的条件。入冬后将盆株置于南向的窗台上，加强日光彩夺目照射，提高室内温度。此时，要控制浇水，经常用25℃的温水喷洒叶片，保持适当的空气湿度。白天温度应控制在15-20℃，夜间在10-15℃，在5℃左右。　　红蕉喜肥不择肥，可用厩肥、堆肥作基肥，或者把拌和在土壤中，使盆土具有较好的肥力。生长季节每15-20天施一次腐熟的有机液体肥料，室内培育可施复合颗粒化肥。5-6月为抽生花葶和花芽分化期，可施以磷、钾肥，或者追施0.2%的磷酸二氢钾水溶液，促进花葶粗壮和花芽早日分化。秋末花谢后可施2-3次速效性无机肥料，使植株尽快恢复。入冬前施以磷、钾肥，以提高植株的抗菌能力。', '　　　　人工繁殖红蕉主要用分株繁殖。5-8月为适期，此时正值', 'http://img.boqiicdn.com/Data/BK/P/imagick34461452245755.jpg', 'http://www.boqii.com/entry/detail/2407.html', '');
INSERT INTO `plant_family` VALUES ('176', '二乔木兰', 'Magnolia soulangeana Soul.-Bod.', '二乔木兰', '二乔玉兰', '不容易死', '中国大陆的广州、杭州、昆明等地', 'http://www.boqii.com/entry/photo/2406/0,http://www.boqii.com/entry/photo/2406/5009', '　', '被子植物门', '双子叶植物纲', '毛茛目', '木兰科', '木兰属', '二乔木兰', 'Magnolia soulangeana Soul.-Bod.', '', '　　二乔木兰为 　　二乔木兰为小乔木，小枝无毛。叶纸质，倒卵形，长6-15厘米，宽4-7.5厘米，先端短急尖，2/3以下渐狭成楔形，上面基部中脉常残留有毛，下面多少被柔毛，侧脉每边7-9条，干时两面网脉凸起，叶柄长1-1.5厘米，被柔毛，托叶痕约为叶柄长的1/3。花蕾卵圆形，花先叶开放，浅红色至深红色，花被片6-9，外轮3片花被片常较短约为内轮长的2/3；雄蕊长1-1.2厘米，花药长约5毫米，侧向开裂，药隔伸出成短尖，雌蕊群无毛，圆柱形，长约1.5厘米。聚合果长约8厘米，直径约3厘米；蓇葖卵圆形或倒卵圆形，长1-1.5厘米，熟时黑色，具白色皮孔；种子深褐色，宽倒卵圆形或倒卵圆形，侧扁。花期2-3月，果期9-10月。', '　　二乔木兰为落叶灌木或小乔木，花大而美丽，非常适合用于园林观赏或环境绿化树种。由于是玉兰与)的杂交种，栽培难度并不是非常高，小编就为你介绍一下二乔木兰的习性及栽培要点。　　二乔木兰性喜阳光和温暖湿润的气候。对很敏感，南北花期可相差4~5个月，即使在同一地区，每年花期早晚变化也很大。对低温有一定的抵抗力，能在-21℃条件下。本种是玉兰与辛夷的杂交种，杭州、广州、昆明有栽培，本种的花被片大小形状不等，紫色或有时近白色，芳香或无芳香。在园艺栽培约有20栽培种。', '　　二乔木兰外面带紫红，花萼长度是花瓣的一半，有的花友会分不清楚它和木兰的区别。二乔木兰是玉兰和辛夷的杂交品种，在园艺栽培中约有20种栽培种。人工繁殖二乔木兰可以用播种、扦插、嫁接、压条和组培等方法。　\n　1、播种：\n　\n　2、扦插：\n　\n　3、嫁接：\n　\n　4、压条：\n　\n　5、组织\n', 'http://img.boqiicdn.com/Data/BK/P/imagick50411452244725.jpg', 'http://www.boqii.com/entry/detail/2406.html', '');
INSERT INTO `plant_family` VALUES ('177', '小和锦', 'EcheveriaPurpusorumcv./E. Purpusorum cv.', '小和锦', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2414/0,http://www.boqii.com/entry/photo/2414/5001', '　', '', '', '', '景天科', '拟属', '', 'EcheveriaPurpusorumcv./E. Purpusorum cv.', '', '　　小和锦为 　　小和锦厚实的叶片上，有漂亮的红褐色花纹。相比大和锦，尺寸更加迷你可爱。', '　　小和锦属于夏季休眠的多肉，但是其不明显。小和锦的栽培难度并不高，叶形和叶色都非常漂亮，有一定的观赏价值，在我国多地均有栽培。　　由于小和锦比较好养的关系，浇水可比较随意，配土接近干透或者半干的时候，就可以浇透一次水，切忌不要让土壤长期保持湿润。配土应选择透气排水性良好的土壤，可泥炭土、颗粒土1:1的比例。除了盛夏适当遮阴，均可全日照，充足的光照，可以让小和锦的叶色更红润斑斓。春秋，土干透后，浇透水。夏季避免烈日炙烤，放在通风明亮的地方少量喷水降温。需要放在向阳的室内。', '　　　\n　枝插：\n　　\n叶插：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick7991452590010.jpg', 'http://www.boqii.com/entry/detail/2414.html', '');
INSERT INTO `plant_family` VALUES ('178', '碧玉兰', 'Cymbidium lowianum （Rchb. f.） Rchb. f.', '碧玉兰', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2421/0', '　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '兰属', '碧玉兰', 'Cymbidium lowianum （Rchb. f.） Rchb. f.', '', '　　 　　碧玉兰是附生植物；假鳞茎狭椭圆形，略压扁，长6-13厘米，宽2-5厘米，包藏于叶基之内。叶5-7枚，带形，长65-80厘米，宽2-3.6厘米，先端短渐尖或近急尖，关节位于距基部6-9厘米处。', '　　为附生，其花色艳丽，容易开花，有着较高的园艺价值，也受到很多花友的喜爱。通常，碧玉兰的每一母株可开花2-3枝，所以给人视觉上有非常热闹的感觉，并且碧玉)期可长达1-2个月。那么如何才能养好碧玉兰呢？　　　　盆土不用泥土。可选用水苔、椰糠、碎杪椤、炭块、碎砖、石子、树皮、泥炭等，经清洗后，根据不同品种的需要搭配成不同胞水程度的混合植料，PH值在5.6~6之间。盆具宜窄宜深、通气性好，最好采用素烧盆。因大多数品种的根部需要较高的湿度，盆壁不宜有太大的孔洞。　　　若种植刚培育的小苗，由于种植时植料是潮湿的，种植后应在叶面喷水数次。5天后增加用水量；10天开始生长新根；约2周后叶色转深绿，表示已成活，但还需要经常检查温度和成活情况。　　若是移植大苗，种植后须立即冲掉盆内泥砂杂质，水应迅速自排水孔流出，直至水清为好。若排水不畅，应重新种植。栽后一周只能作叶面喷雾。分株后一年四季都需充足给水。冬季和早春每日晨间浇水一次，初夏至深秋每日8时前与傍晚5时后各浇水一次。　　　碧玉兰较其他洋兰喜肥。使用的无机肥以复合肥为主，浓度约为0.1%~0.2%，每周一次，全年施用。有机肥可以是发酵过的油粕类混合骨粉或过磷酸钙，制成直径约2厘米的丸状置于盆面，随水分的渗透慢慢释放肥力。每丸的有效期为1个月，全年施放七八次。在生长的旺期还应追施腐熟的饼肥。另外，在初夏即开始8个月的孕花期前就应施用钾肥。　　　碧玉兰的生长过程需要充足的散射光。光照不足时，球茎脊瘦难以抽蕾。可以给其罩上50%的遮光网，日照时间在6小时以上；阴天或冬季要打开遮光网接受直射光。但处于开花期的兰株所需的光线较弱，直射光会使小花蕾黄花脱落，弱光下开出的花更好看。　　　碧玉兰以冷凉的气候条件为宜。15~25℃时生长最旺。但一年生小苗不能在5℃以下露地过冬，夏季能够忍受的最高温度为35℃。', '　　碧　　碧玉兰分株适宜时间是植株开花后，新芽未长出之前。分株前使盆土适当干燥，跟略发白，产生不明显的干缩，如此根较柔软，操作时不易折断。　　分盆时首先用五指用力，托住盆土及盆苗，将盆倒置过来，然后轻轻叩击盆的四周，使盆与根和盆土脱离。操作时要小心抓住没有嫩芽的假球茎，以免碰伤新芽，同时剪除枯黄的叶片、过老的假球茎及腐烂的老根。　　最后用利刀将相连过多的假球茎分切开来，分切后的每丛兰苗应带有2~3枝假球茎，其中一枝必须是前一年新形成的，为避免伤口　　碧玉兰分栽后放半阴处，不可立即浇水。发现过干时可向叶面积盆面少量喷水，以防叶片干枯、脱落和假球茎严重干缩。', 'http://img.boqiicdn.com/Data/BK/P/imagick75601452677466.jpg', 'http://www.boqii.com/entry/detail/2421.html', '');
INSERT INTO `plant_family` VALUES ('179', '星王子', '', '星王子', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2415/0,http://www.boqii.com/entry/photo/2415/5000', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '青锁龙属', '星王子', '', '', '　　 　　星王子直立', '　　星王子的外形和)非常像，但实际上，星王子比钱串子要大很多。人工栽培星王子的难度并不是非常高，盆栽星王子可以将其放在电视、电脑旁，不但可以观赏，还能吸附甲醛等物质。　　星王子需要阳光充足和凉爽、干燥的环境，耐半阴，怕水涝，忌闷热潮湿。具有冷凉季节生长，夏季高温休眠的习性，为多肉中的“冬型种”。每年的9月至第二年的6月为植株的生长期（花友的环境不一样，生长期也有长短），若光照不足会使，叶与叶之间的上下距离拉长，使得株型松散，叶缘的红色也会减退，叶杆变嫩；而在阳光充足之处生长的植株，株型矮壮，茎节之间排列紧凑。星王子就是养在全日照的阳光房里。生长期需保持土壤湿润，避免积水。土壤就用了煤渣混合泥炭、少量珍珠岩，比例大概5:4:1，土表铺上小石头。星王子能耐零下2℃左右的低温，是室内的温度，非露天，再低叶片的顶端生长点就会出现冻伤，干枯死亡，来年会在枯萎处重新萌发新侧枝。整个冬季基本断水，5度以下就要开始慢慢断水。夏季高温时整个植株或完全停止，这个时候要通风良好且适当遮光，避免曝晒，节制浇水，不能长期雨淋，以免植株。星王子在养殖过程中需经常修剪，剪去过乱的枝条，以保持株形的漂亮体态。', '　　　　其实星王子的繁殖很简单，一般繁殖方法主要有扦插和分株的方式。采用扦插的方式用剪子剪下来一小段直接插入潮土中即可生根。也可结合春季换盆进行分株的方式，方法是将', 'http://img.boqiicdn.com/Data/BK/P/imagick45571452590450.jpg', 'http://www.boqii.com/entry/detail/2415.html', '');
INSERT INTO `plant_family` VALUES ('180', '垂枝红千层', 'Callistemon viminalis', '垂枝红千层', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2417/0,http://www.boqii.com/entry/photo/2417/4998', '', '', '', '', '', '', '', '', '', '垂枝', '　　垂枝)为阳性树种，抗酷暑，较耐寒，并且有抗大气污染的能力，所以是很好的园林景观树。的花色鲜艳，开花时非常漂亮，那么人工栽培垂枝红千层应该注意哪些呢？　　　由于快，管理过程中土壤保持湿润，小苗要采取薄肥勤施，一般用1000倍的尿素水淋施，每半个月1次，中苗用花生麸，挪威复合肥混合使用，每月1次。　　　垂枝多花红千层枝条比较软，长至50厘米左右，要插竹扶植，促使其主干明显，株形丰满。　　　用泥炭土、草菇泥、河沙、红泥、塘泥等均可，扦插小苗用8份的泥炭土、2份的河沙或8份已发酵的草菇泥、2份河沙的比例种植，长势较好。中苗长势良好，用7份的泥炭土或已发酵的草菇泥、三份红泥、塘泥种植均可。　　　　垂枝多花红千层按其用途分类，可修剪成圆柱形、球形、塔形、自然形。按造型要求采取相应的修剪方法。', '　　垂枝　　\n一、扦插法\n　　3月剪半成熟不开花的侧枝，长10～12厘米，基部稍带1年成熟枝，扦插于半砂泥中，搭棚盖荫保持湿度，约40天左右可发根，待根群生长旺盛后，即上盆；　　选择健壮无病的成熟的垂枝红千层插穗，剪成8厘米长一段，将其外轮的叶片进行疏理，插穗基部剪成斜面。具体做法一：用长槽做苗床，将花槽底部放人黑士和沙子1：1混合的基质，厚度为4厘米。上部放沙子，厚度为4厘米。将插条按8×8厘米的株行距插入苗床，插进的深度3厘米，插好后浇一遍透水，放到日光直射的温床里，将玻璃盖上，白天要进行喷水，保持环境相对温度80％左右，温度25—35℃，30天后大部插穗生根。做法二：也可以温室地面做苗床，选择阳光充足的地方，建塑料棚，高度50厘米即可，面积可视插穗多少而定，具体插法及要求同做法一。待根系发达，插穗放出新叶，即可上到四寸盆里，索沙土为宜，此时　　\n二、播种法\n　　4月采成熟果实，将种子与细砂匀和，而后撒播之，稍覆细土保持湿度，约35天左右发芽，适', 'http://img.boqiicdn.com/Data/BK/P/imagick36751452591507.jpg', 'http://www.boqii.com/entry/detail/2417.html', '');
INSERT INTO `plant_family` VALUES ('181', '独占春', 'Cymbidium eburneum Lindl.', '独占春', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2431/0,http://www.boqii.com/entry/photo/2431/4984', '　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '兰属', '独占春', 'Cymbidium eburneum Lindl.', '', '　　 　　独占春是附生植物；假鳞茎近梭形或卵形，长4－8厘米，宽2.5－3.5厘米，包藏于叶基之内，基部常有由叶鞘撕裂后残留的纤维状物。叶6－11枚，每年继续发出新叶，多者可达15 17枚，长57－65厘米，宽1.4－2. 1厘米，带形，先端为细微的不等的2裂，基部二列套叠并有褐色膜质边缘，边缘宽1－1.5毫米，关节位于距基部4－8厘米处。', '　　独占春原产于中国海南、广西和云南，现在在尼泊尔、印度、缅甸也有分布。独占春可以人工栽培，具有较高的观赏价值，是很多花友都非常的品种之一。　　在独占春盛期，夏季一旦缺水，则盆兰生长不良，)需八分干、二分湿。浇水应本着“干则浇，湿则停，适当偏干”的原则。浇水必须浇透，不可浇半截水。浇水次数可视盆兰的植料而定。如、红砖粒、浮水石等硬质疏水植料，每天可供水1次；塘泥、腐殖土等吸水性强的植料，则可两三天供水1次。浇水一般在清晨或傍晚进行，切忌在中午浇水和当头倾注。应以清洁无污染、微酸性水（pH值5.5－6.5）为好。兰花烂根，叶面出现黑点，叶芽等病态，多与供水不当有关。　　农家肥是很好的有机肥，但一定要堆放腐熟一年以上才能施用。可用这种肥液对水10－20倍浇施，尽量施在盆沿处，不接触根部，不沾兰叶。施用化肥时，要注意氮、磷、钾的平衡，并严格控制浓度，叶艺苗要控制叶绿素的合成，不宜施氮肥，也不可施含锰、镁的肥料（如钙镁磷肥等），因为锰、镁元素能加速叶绿素的合成对花艺兰，如果培育大瓣型花，可适量增施氮肥。', '　　　\n　一、分株\n　　在春秋两季均可进行，一般每隔三年分株一次。凡植株　　独占春种子极细，种子内仅有一个发育不完全的胚，发芽力很低，加之种皮不易吸收水分，用常规方法播种不能萌发，故需要用兰菌或人工', 'http://img.boqiicdn.com/Data/BK/P/imagick65911452850264.jpg', 'http://www.boqii.com/entry/detail/2431.html', '');
INSERT INTO `plant_family` VALUES ('182', '硫华菊', 'Cosmos sulphureus', '硫华菊', '黄秋英 黄花波斯菊 硫黄菊 硫磺菊 黄芙蓉', '不容易死', '原产于墨西哥', 'http://www.boqii.com/entry/photo/2270/0,http://www.boqii.com/entry/photo/2270/5255', '　　', '被子植物门', '双子叶植物纲', '菊目', '菊科 Asteraceae', '秋英属', '硫华菊', 'Cosmos sulphureus', '', '　　 　　硫华菊喜阳光充足，不耐寒。多分枝，叶为对生的二回羽状复叶，深裂，裂片呈披针形，有短尖，叶缘粗糙，与大波斯菊相比叶片更宽。花为舌状花，有单瓣和重瓣两种，直径3－5厘米，', '　　虽然花大色艳，但是株型却不是很整齐，所以适合多株丛植或者片植，单独栽培的观赏价值不高，现在也有花友将硫华菊做用。人工栽种硫华菊的难度并不高，小编就为你介绍一下硫华菊的栽培要点。　　栽种硫华菊可以用松散的腐殖土，20％～30％黏土、10％～15％（或沙石）1.5千克／平方米，少量铁和微量元素，pH值：5.5～5.8。硫华菊的适宜为15℃～17℃。光照需良好，荫蔽处不易开花。需要注意的是，硫华菊的“宇光”花朵不耐水淋，浇水时要特别注意。在生长适温的范围内，温度低并保持干燥将提升植株后期的品质。', '　　　\n　一、播种繁殖\n　　硫华菊一般选用4月春播，播种后注意及　　\n二、扦插繁殖\n　　硫华菊扦插繁殖则在初夏用嫩枝作插条，插后15－20天可生根。幼苗具4－5片真叶时摘心，并进行移植或盆栽。生长期每半月施肥1次，但不宜过量，否则枝叶徒长，影响开花。植株长高后，设立支柱，防生倒伏。种子陆续成熟，容易脱落，需及时采收。', 'http://img.boqiicdn.com/Data/BK/P/imagick55151448876793.jpg', 'http://www.boqii.com/entry/detail/2270.html', '');
INSERT INTO `plant_family` VALUES ('183', '八角金盘', 'Fatsia japonica （Thunb.） Decne. et Planch.', '八角金盘', '八金盘、八手、手树、金刚纂', '不容易死', '', 'http://www.boqii.com/entry/photo/2038/0,http://www.boqii.com/entry/photo/2038/5489', '', '', '', '', '', '', '', '', '', '　　 　　八角金盘为常绿灌木或小乔木，高可达5m。茎光滑无刺。叶柄长10－30cm；叶片大，革质，近圆形，直径12－30cm，掌状7－9深裂，裂片长椭圆状卵形，先端短渐尖，基部心形，边缘有疏离粗锯齿，上表面暗亮绿以，下面色较浅，有粒状突起，边缘有时呈金黄色；侧脉搏在两面隆起，网脉在下面稍显着。　　　　　　　　　　　　　　', '　　八角金盘四季翠绿，观赏价值比较高，不但在园林中比较常见，还能制作成观叶用于室内。那么如何才能让栽种的八角金盘四季常绿呢？小编就为你介绍一下。　　栽培以腐殖质壤土最佳。栽培处宜半阴，日照约50％－60％。叶片蒸发面广，要经常保持适润，不可干旱枯萎影响生育。性喜冷凉，忌高温，生育适温约13～23℃。夏季力求阴凉通风。　　生根、长叶后，杂草生长要早拔，拔净，不使杂草与苗木争夺养分、水分。草拔净之后，浇一次稀薄粪水，供新根吸收，促进苗木生长。　　八角金盘适宜生长于肥沃疏松而排水良好的土壤中。盆土可用园土3份加1份砻糠灰混合使用，加点基肥。平时养护要避免烈日直射，放置在建筑物北侧等半阴处通风良好的环境比较适合。在新叶生长期，浇水要适当多些，保持土壤湿润；以后浇水要掌握间干间湿。　　气候干燥时，还应向植株及周围喷水增湿。5—9月时，每月施饼肥水2次。花后不留种子的，要剪去残花梗，以免消耗养分。冬季在长江以南地区露地过冬基本无恙，盆栽的花苗，以放入冷室较为。', '　　　\n　一、播种\n　　八角金盘果实成熟后，立即采收，否则会自然落地。果实采回后堆积在墙角下，用沙皮袋盖好，经过一星期左右　\n　二、扦插\n　　八角金盘扦插育苗应在早春或秋季进行，选用1年至3年生苗干做插穗，插穗长20厘米左右，不带叶片，剪好后每50根一捆扎好，用60ppm的萘乙酸溶液浸泡插穗基部20个小时左右，或用ABT一号生根粉200ppm溶液泡30分钟至60分钟，取出后扦插。　　因八角金盘枝条较粗，扦插时，先用同插穗粗度相差不大的木棒打洞，然后插入，插入深度为插穗长的2／3，扦插株行距离为10厘米×20厘米，插好后将其四周土壤踏实，浇透水即可。春插于3月份进行，插好后即搭棚进行遮阴。遮阴用50％以上黑色遮荫网，或用芦柴帘子亦可。用芦柴帘子遮荫，最好早盖晚揭，让插穗接受自然雨露滋润。为保证插穗生根、长叶需要的水分，要经常喷水，使土壤处于湿润状态。秋插，除搭棚架盖塑料薄膜保湿保温外，早期还要在塑料薄膜上进行遮阴。　　苗木生根、长叶后，杂草生长要早拔，拔净，不使杂草与苗木争夺养分、水分。草拔净之后，浇一次稀薄粪水，供新根吸收，促进苗木生长。', 'http://img.boqiicdn.com/Data/BK/P/imagick2381442308920.jpg', 'http://www.boqii.com/entry/detail/2038.html', '');
INSERT INTO `plant_family` VALUES ('184', '令箭荷花', 'Nopalxochia', '令箭荷花', '孔雀仙人掌、孔雀兰、荷令箭', '不容易死', '原产中美洲墨西哥', 'http://www.boqii.com/entry/photo/2062/0,http://www.boqii.com/entry/photo/2062/5465', '', '', '', '', '', '', '', '', '', '　　令箭 　　令箭荷花为附生类仙人掌植物，茎直立，多分枝，群生灌木状，高约50～100厘米。植株基部主干细圆，分枝扁平呈令箭状，绿色。茎的边缘呈钝齿形。齿凹入部分有刺座，具0.3～0.5厘米长的细刺，并生有丛状短刺。扁平茎中脉明显突出。花大型，从茎节两侧的刺座中开出，花筒细长，喇叭状，花被重瓣或复瓣，白天开花，夜晚闭合，一朵花仅开1～2天，花色有紫红、大红、粉红、洋红、黄、白、蓝紫等，夏季白天开花，花期为4～6月。果实隗椭圆形红色浆果，种子黑色。　　　　　　　　　　　　　　', '　　是家庭养殖的常见花卉，而人工栽培令箭荷花的养护也是很多花友都非常关心的问题。想要令箭荷花开的娇艳的话，就需要做好的工作了，令箭荷花喜光，可以摆在室外背风向阳的地方饲养。　　春季是令箭荷花季节，要注意光照充足，施肥及时。每10天至15天施氮磷结合的肥料一次，促花叶健壮成长。浇水要见干见湿，忌盆内积水，以防烂根。从4月份起，在肉质的上半部叶片边缘处生出花蕾，并逐渐膨大，半个月后就绽放。如果这时植株营养不足，长势衰弱，它就不开花或少开花，有的虽已育蕾，也会提前枯萎脱落。为防止此种现象发生，可提前增施1次至2次速效性磷肥。同时还要抹去过多的侧芽和基部的枝芽，对细弱枝条也要剪去，以减少养分消耗，使养分集中供给健壮枝叶和花蕾。　　令箭荷花在夏初5月至6月花谢后，转入生长旺盛期，应及时施入1至2次以氮为主的追肥。这样既促使它长新枝叶，又有利于明春多长蕾开花。要想增加茎片的数量，就要抓住这个有利时期留芽，使之所留芽一次就可长到所需要的高度。如因发芽过晚或因长势不良，一次达不到所需要高度的茎片，就不要吝惜，干脆剪去不要，防止出现形茎片，影响株形美观。盛夏高温时，令箭荷花进入半休眠时期，应放置在通风凉爽的半阴处，停止施肥，浇水不可过多，盆土保持稍干些，并防止过于荫蔽，以免徒长而影响开花。也可放置在窗口通风处，每天有3个至4个小时日光即可，但要防止中午烈日照晒，否则叶片会泛黄。　　秋季它继续生长枝叶，也是一年中的第二次生长旺盛期，新叶逐渐老化成熟。管理养护方法基本和春季与夏初一样，可施2次至3次追肥，以磷钾肥为主，并增加光照时间。　　霜降后天气转冷，为了防止冰冻和霜雪，需移入室内保暖，可放置在室内向阳处，室温保持在8℃即可。停止施肥，节制浇水，盆土偏干为佳，过湿会引起叶片萎蔫倒伏和烂根。春后3月中旬至4月上旬，可随气温上升逐步延长开窗通风锻炼时间，为以后移出室外养护打基础。　　此外，令箭荷花1年至2年换盆土一次，春、秋两季均可进行。换盆土时，去掉部分陈土和枯根，补充新的培养土（腐叶土、菜园土、沙土、有机肥混合而成），并放入蹄片作基肥。', '　　令箭荷花有名令箭、荷花令箭等，在中国，令箭荷花以盆栽为主，也是很多花友都比较　\n　一、扦插繁殖\n　　在每年3～4月间进行为好。首先剪取10厘米长的健康扁平茎作插穗，剪下后要晾2～3天，然后插入湿润砂土或蛭石内，深度以插穗的1／3为度，　\n　二、嫁接繁殖\n　　宜在25℃时进行。砧木可选　　多年生老株下部萌生形成的枝丛多，也可用分株繁殖。', 'http://img.boqiicdn.com/Data/BK/P/imagick78161442915861.jpg', 'http://www.boqii.com/entry/detail/2062.html', '');
INSERT INTO `plant_family` VALUES ('185', '广东万年青', 'Aglaonema modestum', '广东万年青', '大叶万年青、井干草 界 植物界', '不容易死', '菲律宾、越南以及中国大陆的广西、云南、广东等地', 'http://www.boqii.com/entry/photo/2218/0,http://www.boqii.com/entry/photo/2218/5309', '', '被子植物门', '单子叶植物纲', '天南星目', '天南星科', '广东万年青属', '', 'Aglaonema modestum', '', '　　 　　广东万年青为多年生常绿草本，茎直立或上升，高40－70厘米，粗1。5厘米，节间长1－2厘米，上部的短缩。鳞叶草质，披针形，长7－8厘米，长渐尖，基部扩大抱茎。叶柄长（5－）20厘米，1／2以上具鞘；叶片深绿色，卵形或卵状披针形，长15－25厘米，宽（6－）10－13厘米，不等侧，先端有长2厘米的渐尖，基部钝或宽楔形，1级侧脉4－5对，上举，表面常下凹，背面隆起，II级侧脉细弱，不显。', '　　的株型不高，但是耐阴性比较强，并且四季常绿，所以是很好的室内观叶。人工栽培广东万年青的难度并不高，只要根据其习性为其布置一个合适的生长环境，广东万年青就能健康成长了。　　　广东万年青喜阴湿环境，怕直射阳光，可长年放在蔽荫处生长，短时间的曝晒叶面也会变白后黄枯。生长适温为20～28℃，不耐寒，冬季需保持在8℃以上。过低，易受冻害。一经落叶就会死亡。夏季高温季节需每天早晚各浇一次水，此外，还应向周围地面喷水，以提高空气湿度。春、秋两季浇水要掌握见干见湿，冬季要节制浇水，若此时盆土过湿，叶片易变黄并引起根部腐烂。在生长期间盆土不能过干，否则水分缺乏易使叶片萎黄枯落。春、秋两季每隔15～20天追施一次含氮、钾较多的液肥，盛夏季节一般应停止施肥。　　　广东万年青疏松肥沃、排水良好的栽培基质，不耐盐碱。盆土可用腐叶土、园土和少量河沙混合配制。一般1～2年换盆一次。盆栽用土为腐叶土3份、壤土1份、粗沙1份混合，加入适量底肥。生长期间保持盆土湿润和较高的空气湿度，使空气湿度不低于40％，夏季注意遮荫，每2周浇施1次稀薄的酸性肥水，冬季温室内温度不低于10℃。每年春天视植株大小换盆一次。　　　粗肋草喜光线明亮通风良好的环境，春季光照控制在15000LX－20000Lx；夏季由于温度较高，高温高湿，要加强遮阴、通风，光照控制在8000－10000Lx较为理想；秋冬季节温度较低，光照控制到20000－30000Lx或全日照。光线太强叶片会黄绿，遮阴太过会很徒长、倒伏，影响观赏效果。　　　粗肋草喜高温，不耐寒，生长适温25－30℃。最低越冬温度在12℃以上。一旦受冻则叶片黄萎、顶芽坏死。冬季养护需要加温设备，如果没用加温设施，可采用双层保温设施，冬季下午在温度下降到22－24℃时要及时封棚（一般大棚北面的要密封，大棚南边的可适当留些空间，便于棚内的空气流动，防治棚内湿度过大）。夏季如果用简易棚种植，晴天应掀去薄膜，棚顶盖1层密度为75％的遮阳网，棚内可再加一层50％遮阳网，这样可以通风、降温的作用。但在连续阴雨天要盖上薄膜，防治雨水过多导致盆内基质长期过湿而引起烂根、烂茎现象，夏季可加强遮荫和通风，同时不宜采用远距离的连栋大棚，而应采用独立单顶棚。　　　生长期供水需充足，盛夏每天早晚叶面喷水，冬季茎叶生长减慢，应控制水分，盆土不宜过湿。南方地区夏季常半阴处养护。5－10月茎叶生长旺盛期每半月施肥1次。冬季搬进室内如叶片泛黄，加施1次稀释氮肥。生长数年后的母株，常呈匍匐状，姿态欠佳，应重新扦插更新。', '　　　\n　一、分株繁殖：\n　　\n二、扦插繁殖：\n　　同时，在产业化', 'http://img.boqiicdn.com/Data/BK/P/imagick28621447407155.jpg', 'http://www.boqii.com/entry/detail/2218.html', '');
INSERT INTO `plant_family` VALUES ('186', '千代田之松', 'Pachyphytum compactum', '千代田之松', '', '不容易死', '产于墨西哥伊达尔戈州', 'http://www.boqii.com/entry/photo/2344/0,http://www.boqii.com/entry/photo/2344/5073', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '厚叶草属', '千代田之松', 'Pachyphytum compactum', '', '　　 　　千代田之松的茎10厘米高，叶30－60枚，略扁的圆柱形，互生，淡绿至灰白色，被白粉。2－4厘米长，1.2、1.6厘米宽，0.9－1.2厘米厚，圆润，但尖端部分略有棱。花序30厘米高，小花懦红色。', '　　千代田之松耐旱、耐半荫，不耐水湿，无明显休眠期，如果光线不足的话，千代田之松的茎会伸长，植株的形状会变的松散，大大降低了观赏价值。虽然千代田之松的很少，但是人工栽培千代田之松的难度并不高。　　千代田之松慢，用小盆和素沙土种植。春秋两季可充分浇水，夏季要遮荫通风并减少浇水，冬季维持5℃以上。适合与迷你多肉植物组合栽培，很适合以点缀的方式加入到组合中去。单独栽培的效果也很不错，相比其他同种类植物来说出彩的地方稍少。　　千代田之松的土壤用的是泥炭混合珍珠岩加了煤渣，大概比例1：1：1，为了隔离植株和土表，也为了更加透气，河沙尺寸3到5毫米。浇水是干透才浇透，不干不浇水。无明显休眠期，可以全日照。　　夏天的时候通风遮阳，每个月3到4次水，少量在盆边给水慢慢度过盛夏，维持植株根系不会因为过度干燥而干枯就可以。冬天低于3度就要逐渐少水，0度以下保持盆土干燥，尽量保持不低于零下3度。这样就可以安全过冬了，冬天尽量少点水，开春给水要循序渐进否则可能出现烂根。南北差异比较大，家庭和大棚的养殖方法都不一样，千代田之松是比较好养的一个，无明显病虫害。', '　　　　千代田之松叶插与扦插均可，叶插容易群生，比较容易繁殖。　　千代田之松一般用叶插来繁殖，土壤用的是泥炭混合珍珠岩加了煤渣，大概比例1：1：1，为了隔离植株和土表', 'http://img.boqiicdn.com/Data/BK/P/imagick17401450689825.jpg', 'http://www.boqii.com/entry/detail/2344.html', '');
INSERT INTO `plant_family` VALUES ('187', '百子莲', 'Agapanthus', '百子莲', '紫君子兰、蓝花君子兰、非洲百合', '不容易死', '华南和西南地区', 'http://www.boqii.com/entry/photo/2185/0,http://www.boqii.com/entry/photo/2185/5343', '　', '种子植物门', '单子叶植物纲', '百合目', '石蒜科', '百子莲属', '朱顶红', 'Agapanthus africanus Hoffmgg.', 'Agapanthus Africanus', '　　 　　百子莲科多年生草本。有根状茎；叶线状披针形，近革质；花茎直立，高可达60厘米；伞形花序，有花10朵～50朵，花漏斗状，深蓝色或白色，花药最初为黄色，后变成黑色；花期7月～8月。', '　　原产于南非，性喜温暖湿润的环境，不耐寒，稍耐阴。需要注意的是，百子莲好肥，人工栽种的过程中应保证百子莲的肥力，才能让百子莲并且开出艳丽的花朵。　　盆栽百子莲宜选用大而充实的鳞茎，栽种于18～20厘米口径的花盆中，4月盆栽的，6月可开花；9月盆栽的，置于温暖的室内，次年春三四月可开花。用含腐殖质肥沃壤土混合以细沙作盆栽土最为合适，盆底要铺沙砾，以利排水。鳞茎栽植时，顶部要稍露出土面。将盆栽植株置于半阴处，避免阳光直射。和开花期间，宜追施2～3次肥水。鳞茎，浇水量减少到维持鳞茎不枯萎为宜。若浇水过多，温度又高，则茎叶徒长，妨碍休眠，影响正常开花。　　栽种百子莲，宜选排水良好的场地。露地栽种，于春天3～4月植球，应浅植，时鳞茎顶部稍露出土面即可，5月下旬至6月初开花。冬季休眠，地上叶从枯死，10月上旬挖出鳞茎，置于不上冻的地方，待第二年栽种。　　在栽种中，茎、叶及鳞茎上又赤红色的病害斑点，宜在鳞茎休眠期，以40℃～44℃温水浸泡一小时预防。', '　　百子莲到冬季会处于休眠状态，所以人工栽种的过程中应该注意冬季的　\n　1、分球繁殖\n　　分球繁殖于3～4月进行，将母球周围的小球取下另行栽植，栽植时覆土不宜过多，以小鳞茎顶端略露出土面为宜。此法繁殖，需经2年培育方能开花。　\n　2、分割鳞茎法繁殖\n　　分割鳞茎法繁殖一般于7－8月份进行。首先将鳞茎纵切数块，然后，再按鳞片进行分割，外层以2鳞片为一个单元，内层以3鳞片为一个单元，每个单元均需带有部分鳞茎盘。此法繁殖，若被分割的鳞茎直径为6cm以上，则每球可分割成20个以上双鳞片和三鳞片的插穗，将插穗斜插于基质中（pH值最好为8左右），保持25～28℃和适当的空气湿度，30～40天后，每个插穗的鳞片之间均可产生1～2个小鳞茎，而且基部生有根系，此法繁殖的小鳞茎，需　\n　3、鳞片扦插繁殖\n　　选　\n　4、刻伤法繁殖\n　　选择鳞茎周径24～26厘米种球，将鳞茎用1％硫酸铜液浸5分钟，用水洗净后，切去鳞茎的1／3，用刀轻轻刻伤鳞茎中心的主芽，平放在沙床上，室温保持18～22℃，维持较高的空气湿度，2个月后在鳞片之间形成若干小鳞茎。　　\n5、播种法繁殖\n　　由于百子莲种子扁平、极薄，容易失水，丧失发芽力，应采种后即播。如种球生产，花后及时剪除花茎，以免消耗鳞茎养分。待长出叶片后，加强施肥，促使鳞茎增大和产生新鳞茎。鳞茎在13℃条件可贮藏8～10周，在5℃温度下，可长期贮藏。　\n　6、组织培养法繁殖\n　　常用MS培养基，以茎盘、休眠鳞茎组织、花梗和子房为外植体。经组培后先产生愈伤组织，30天后形成不定根，3～4个月后形成不定芽。', 'http://img.boqiicdn.com/Data/BK/P/imagick43661446631260.jpg', 'http://www.boqii.com/entry/detail/2185.html', '');
INSERT INTO `plant_family` VALUES ('188', '龙柏', 'Sabina chinensis （L.） Ant. cv. Kaizuca', '龙柏', '龙爪柏、爬地龙柏、匍地龙柏', '不容易死', '', 'http://www.boqii.com/entry/photo/2043/0,http://www.boqii.com/entry/photo/2043/5484', '植物　', '裸子植物门', '松杉纲', '松杉目', '柏科', '圆柏属', '圆柏', 'Sabina chinensis （L.） Ant. cv. Kaizuca', 'Juniperus chinensis \'Kaizuka\'', '　　 　　龙柏是圆柏的人工栽培变种。树冠圆柱状或柱状塔形；枝条向上直展，常有扭转上升之势，小枝密、在枝端成几相等长之密簇；鳞叶排列紧密，幼嫩时淡黄绿色，后呈翠绿色；球果蓝色，微被白粉。', '　　', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick3861442396213.jpg', 'http://www.boqii.com/entry/detail/2043.html', '');
INSERT INTO `plant_family` VALUES ('189', '子持莲华', 'Orostachys boehmeri', '子持莲华', '', '不容易死', '日本北海道', 'http://www.boqii.com/entry/photo/1987/0,http://www.boqii.com/entry/photo/1987/5540', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '瓦松属', '子持莲华', 'Orostachys boehmeri', '', '　　 　　子持莲华的叶形叶色较美，有一定的观赏价值；盆栽可放置于电视、电脑旁，有一定的防辐射作用，亦可栽植于室内以吸收甲醛等物质，净化空气。', '　　对于环境的要求并不高，所以栽培难度也并没有我们想象的那么高。子持莲华的外形非常漂亮，叶片上还有一层淡淡的白粉，所以深受人们的喜爱，也是很多多肉爱好者都会收藏的品种之一。　　子持莲华的植料用的是泥炭混合珍珠岩加了浮石，比例1：1：1，为了隔离植株和土表接触，也为了更加透气，特地铺上颗粒的干净河沙，河沙尺寸3到5毫米，沙层厚度5毫米。浇水是干透才浇透，不干不浇水。　　春天和秋天是子持莲华生长期，可以全日照。夏天基本不会休眠。通风遮阳，炎热夏季每个月4到5次水，不浇透。以维持植株的正常生长，夏季水太大容易腐烂。低于5度就要逐渐断水，3度以下保持盆土干燥，尽量保持不低于零下3度。这样就可以了。　　花友平时在为子持莲华浇水的时候尽量浇在土里，叶片沾上水分会影响美观。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick91771441012489.jpg', 'http://www.boqii.com/entry/detail/1987.html', '');
INSERT INTO `plant_family` VALUES ('190', '茑萝', 'Quamoclit pennata', '茑萝松', '金丝线、锦屏封、茑萝', '不容易死', '全中国各地都有分布', 'http://www.boqii.com/entry/photo/2340/0,http://www.boqii.com/entry/photo/2340/5077', '植物　', '被子植物门', '双子叶植物纲', '茄目', '旋花科', '茑萝属', '', 'Quamoclit pennata （Desr.） Boj. FOC已修订', 'Quamoclit pennata', '　　 　　茑萝为一年生柔弱缠绕草本，无毛。叶卵形或长圆形，长2～10厘米，宽1～6厘米，单叶互生，叶的裂片细长如丝，羽状深裂至中脉，具10～18对线形至丝状的平展的细裂片，裂片先端锐尖；叶柄长8～40毫米，基部常具假托叶。', '　　', '　　茑萝的栽培难度并不高，如果是露地栽培的话，茑萝是能自播的，人工栽培可引种栽培。茑萝的抗逆力强，', 'http://img.boqiicdn.com/Data/BK/P/imagick12761450430056.jpg', 'http://www.boqii.com/entry/detail/2340.html', '');
INSERT INTO `plant_family` VALUES ('191', '稠李', 'Prunus padus L.', '稠李', '臭耳子（甘肃）、臭李子（东北）', '不容易死', '东北地区、内蒙古、河北、山西、陕西、朝鲜、俄罗斯、日本、欧洲', 'http://www.boqii.com/entry/photo/2175/0,http://www.boqii.com/entry/photo/2175/5353', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '稠李属', '', 'Prunus padus L.', '', '　　 　　稠李（原变种）为落叶乔木，高可达15米；树皮粗糙而多', '　　为蔷薇科李属，花色洁白，花期为4月，但由于稠李在开花后会有异味，所以普及度并不高。稠李的花与叶同时开放，盛花期非常漂亮。　　稠李因花瓣略有异味，所以又名臭李子，小枝紫褐色有棱，近无毛，叶缘具尖细锯齿，有侧脉8－11对，叶柄近叶片基部有2腺体，腋生总状花序下垂，基部常有小叶1－4枚，有花10－20朵，花部无毛，花瓣白色，核果近球形，黑或紫红色。　　稠李喜光也耐阴，抗寒力较强，怕积水涝洼，不耐干旱瘠薄，在湿润肥沃的砂质壤土上良好，萌蘖力强，病虫害少。产黑龙江、吉林、辽宁、内蒙古、河北、山西、河南、山东等地。生于山坡、山谷或灌丛中，海拔880－2500米。朝鲜、日本、苏联也有分布。　　稠李在欧洲和北亚长期栽培，有垂枝、花叶、大花、小花、重瓣、黄果和红果等变种，供观赏用。果实可招引类，庭荫树。花序长而美丽，秋叶变红色，果成熟时亮黑色，是一种耐寒性较强的观赏树。木材优良；花有密，是蜜源树种。', '　　人工栽培稠李的难度并不高，人工繁殖稠李可用播种的方法，只要了解了稠李的生长习性，稠李播种的成活率也可以提高很多。小编就为你介绍一下稠李的播种繁殖，', 'http://img.boqiicdn.com/Data/BK/P/imagick36921446457354.jpg', 'http://www.boqii.com/entry/detail/2175.html', '');
INSERT INTO `plant_family` VALUES ('192', '小人祭', 'Aeonium sedifolius', '小人祭', '妹背镜、日本小松', '不容易死', '北非和加那利群岛等地', 'http://www.boqii.com/entry/photo/2247/0,http://www.boqii.com/entry/photo/2247/5278', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '莲花掌属', '小人祭', 'Aeonium sedifolius', '', '　　 　　小人祭株型迷你，多分枝。因为它的老桩如松般苍劲，因此还有个别名日本小松。', '　　的习性强健，喜温暖、阳光充足的环境，原产于北非的小人祭耐干旱。人工栽培小人祭的难度不高，基本不用担心。那么如何才能养出漂亮的小人祭呢？　　1、温度：适温15－25度，冬季不低于5度。夏季温度过高会休眠，休眠时类似包菜，全部叶片紧抱在一起。冬季温度低于5度时容易冻伤。　　2、光照：喜阳光充足的环境，稍耐阴。日常为绿色，日照时间增加及温差增大后整株颜色会变深，在一些空气独特的地区甚至整株会变红色。小人祭虽然稍耐阴，但阴久了叶片也会变绿、徒长导致株型不紧致，影响观赏性，因此，建议给足光照。但夏季高温应适度遮阴。　　3、浇水：浇水的话，可以干透浇透，可以不用及时给水，适当延长浇水的间隔，可以让小人祭的叶片更紧致，颜色更亮眼。且生长期对水需求比较大，冬季保持盆土干燥。　　4、施肥：春季是小人祭开花的，可在浇水的时候适当施肥，给予足够的营养开花。生长期施肥一般每月一次，建议少施肥或不施肥，以免造成烧根而死。', '　　小人祭的习性强健，人工栽培难度不高，只要正常进行栽培，基本不用担心会出现　　小人祭繁殖方式一般为扦插繁殖，可以在早春剪下莲座叶盘扦插，剩下的茎上会群出蘖芽，是很好繁殖的', 'http://img.boqiicdn.com/Data/BK/P/imagick20611448356658.jpg', 'http://www.boqii.com/entry/detail/2247.html', '');
INSERT INTO `plant_family` VALUES ('193', '白斑玉露', 'Haworthia cooperi', '白斑玉露', '水晶白玉露', '不容易死', '原产自南非开普省', 'http://www.boqii.com/entry/photo/2471/0,http://www.boqii.com/entry/photo/2471/4946', '　　', '被子植物门', '单子叶植物纲', '天门冬目', '独尾草科', '十二卷属', '玉露', 'Variegata’', 'Haworthia cooperi', '　　白斑 　　为玉露的锦斑', '　　白斑)为玉露的锦斑品种，植株较易群生。白斑玉露在春秋两季为季，当夏季进入高温则会进入半休眠状态。人工栽培白斑玉露需要给予充足的光照，并且要注意控制浇水量，避免白斑玉露徒长，造成观赏价值降低的情况。白斑玉露　　白斑玉露的生长期应给予充足的光照，若过于荫蔽，会造成株形松散，不紧凑，叶片瘦长，“窗”的透明度差。如光照过强，则叶片生长不良，呈浅红褐色，有时强烈的直射阳光还会灼伤叶片，留下难看的斑痕，在半荫处生长的植株，叶片肥厚饱满，透明度高。　　生长期浇水掌握“不干不浇，浇则浇透”，避免积水，更不能雨淋，尤其是不能长期雨淋，这些都是为了避免烂根。但也不宜长期干旱，否则植株虽然不会死亡，但叶片干瘪，叶色黯淡，缺乏生机。　　白斑玉露有一定空气湿度的环境，空气干燥时可经常向植株及周围环境喷水，以增加空气湿度，在生长季节还可用剪去上半部的透明无色饮料瓶将植株罩起来，使其在空气湿润的小环境中生长，这样可使叶片饱满，“窗”的透明度也更高。但夏季高温季节一定要把花葶去掉，以免因闷注意的是花葶不要用剪子剪，要用手左右晃着拔掉，这样可以避免残花梗残留在叶与叶之间，对以后新叶的生长造成不利影响。', '　　　　\n1、分株\n　　目前已经有花友进行的繁殖方法中，以分株繁殖最为常见，白斑玉露很容易群生，可结合换盆进行分株，也可在生长　　\n2、播种\n　　播种也是玉露的繁殖方法之一，但要通过人工授粉。种子可随采随播，播种土可用　　\n3、叶插\n　　可选择健壮充实的白斑玉露肉质叶，生长期在蛭石或粗沙等排水良好的基质中扦插，插后保持盆土稍湿润，肉质叶基部易生根，并长出小芽，等小芽稍大些再另行栽种即可。', 'http://img.boqiicdn.com/Data/BK/P/imagick70341454061029.jpg', 'http://www.boqii.com/entry/detail/2471.html', '');
INSERT INTO `plant_family` VALUES ('194', '薄雪万年青', 'Sedum hispanicum', '薄雪万年草', '矶小松', '不容易死', '广布南欧至中亚地区，归化在美国东北和日本东南地区', 'http://www.boqii.com/entry/photo/2112/0,http://www.boqii.com/entry/photo/2112/5415', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '景天属', '薄雪万年草', 'Sedum hispanicum', '矶小松', '　　 ', '　　薄雪万年草为须根性，其茎匍匐生长，地面则容易生长不定根。薄雪万年草喜好全日照环境，半日照的情况下也能生长，但是其叶片排列就会比较松散，观赏价值大打折扣。那么，如何才能养好薄雪万年草呢？　　介质略干再浇水，亦可适应湿度较高的环境，介质使用砂质壤土或一般土均可，耐贫瘠；可不必施肥，长期生长；会有基部叶片脱落使茎部裸露的现象，可进行修剪，促进再度分枝生长，剪下的茎可以作为繁殖材料进行扦插。　　生长期可放在室外阳光充足之处，即使盛夏高温季节也不要遮光，以使得株型紧凑美观。在半阴处虽然也能生长，但株型松散，影响观赏性。　　光照不足则会造成植株徒长，使得叶与叶之间的距离拉长，看上去稀松难看，而且植株长势孱弱，很容易引起等病症，使得整盆植株腐烂，全军覆没。生长期保持盆土湿润，避免积水，也不要长期雨淋，这些都是为了避免植株腐烂。由于其性耐瘠薄，栽培中施肥与否要求不严。冬季置于光照充足之处，控制浇水，保持土壤不结冰即可。　　夏季高温季节要求有良好的通风，避免闷热潮湿的环境，以免造成植株腐烂。薄雪万年草生长迅速，应注意及时掐掉影响美观的枝条，当生长过密时要进行分盆，以保持株型的美观。其肉质茎较脆，很容易断，换盆时应小心，避免把较长的枝条弄断，影响观赏效果。　　平常以绿色为主，日照增加及温差巨大会使整株变为粉红色，并且株型也会保持的很漂亮。缺光后会长的很难看，长时间缺光容易引发病虫害。', '　　薄雪万年青　　薄雪万年草的繁殖可结合换盆进行分株，方法是将丛生的植株分开，分别栽种即可。也可在　　1、剪下枝条；　　2、摘掉纸条底侧小叶子防止扦插时埋到土中腐烂；　　3、阴凉处晾一天；　　4、准备好盆土，土质要松软潮土适合发根；　　5、晾好上盆不要太密集开始不要给太多水。　　介质略干再浇水，亦可适应湿度较高的环境，介质使用砂质壤土或一般', 'http://img.boqiicdn.com/Data/BK/P/imagick68421444728196.jpg', 'http://www.boqii.com/entry/detail/2112.html', '');
INSERT INTO `plant_family` VALUES ('195', '报春花', 'Primula malacoides Franch', '报春花', '小种樱草、七重楼', '不容易死', '原产中国的云南、贵州，各地栽培', 'http://www.boqii.com/entry/photo/2114/0,http://www.boqii.com/entry/photo/2114/5413', '', '', '', '', '', '', '', '', '', '　　 　　报春花为二年生草本，通常被粉，少数植株无粉。花葶1至多枚自叶丛中抽出，高10－40厘米，被柔毛或变无毛，无粉或散布少量白粉；伞形花序（1）2－6轮，每轮4－20花；苞片线形或线状披针形，长3－8毫米，被粉或无粉；花梗纤细，长1.5－4厘米；花萼钟状，长3－7毫米，果时稍增大，通常被乳白色粉，分裂达中部，裂片三角形，先端锐尖；花冠粉红色，淡蓝紫色或近白色，冠筒长4－6毫米，喉部无环状附属物，冠檐直径5－15毫米（在栽培条件下直径可达3厘米），裂片阔倒卵形，先端深2裂；长花柱花：冠筒约与花萼等长，雄蕊着生处距冠筒基部1.5－2毫米，花柱长约3毫米，接近筒口；短花柱花：冠筒长于花萼约0.5倍，雄蕊着生处略高于冠筒中部，花柱长约1毫米。蒴果球形，直径约3毫米。花期2－5月，果期3－6月。　　　　　　　　　　　　　　　', '　　报春花又名樱草、年景花等，原产于中国。报春花在世界上的栽培非常广，并且栽培历史也非常久远，但是近几年的发展比较迅速，已经成为现在比较重要的一类园林', '　　报春花又名　　报春花的种子待朔果开始转黄时采收，阴干，忌日晒。干后去果壳，贮藏。报春花常用播种繁殖。种子发芽率40％，隔年种子很少发芽。种子细小，不易收到。我国从南到北，可于3月至5月前后，当盆中报春花开放时，疏松盆土，让种子自落于盆中。若原盆较小，可采种播种。种子可播于一作苗床的大盆内。用坐盆法使盆土湿透，盖上玻璃，略加遮荫，发芽适温15℃至20℃，5天至6天即可出苗。出苗后，拿去玻璃，以免长成高脚苗。小苗半月要稀植。夏季注意遮荫、通风并保持适当干燥。到9月初，待苗放出真叶，即分苗上盆。亦可8月至9月播种，管理比较方便，但植株生长矮小。　　报春花中一些重瓣品种，常不易得到种子，因而只有用扦插或分株的方法进行繁殖。扦插在5月至6月进行，分株则最好在秋季。常见室内盆栽', 'http://img.boqiicdn.com/Data/BK/P/imagick30141444730024.jpg', 'http://www.boqii.com/entry/detail/2114.html', '');
INSERT INTO `plant_family` VALUES ('196', '金手指', '', '手指', '', '不容易死', '墨西哥伊达尔戈州', 'http://www.boqii.com/entry/photo/1923/0,http://www.boqii.com/entry/photo/1923/5606', '', '', '', '', '', '', '', '', '', '　　 　　金手指的茎肉质，形似人的手指。全株布满黄色的软刺。初始单生，后易丛基部孳生仔球，圆球形至圆筒形，单体株径1.5－2厘米，体色明绿色。具13－21个圆锥疣突的螺旋棱。黄白色刚毛样短小周刺15－20枚，黄褐色针状中刺1枚，易脱落。春季侧生淡黄色小型钟状花，花径1－1.5厘米。', '　　我们都知道，仙人掌的栽培难度比较低，而今天要介绍的金手指也是仙人掌的一个品种，栽培难度也不高，也是非常适合用于家居环境的一个装饰植物。如果你的金手指栽培的好的话，常年都会开花，虽然不多，但是也是非常漂亮的。那么如何才能栽种出漂亮并且常年开花的金手指呢？　　1、。喜温暖，适温为15－22摄氏度。越冬期间应注意防寒，保暖。　　2、光照。喜阳光充足的环境，秋至春季应将植株置于阳光充足处。　　3、浇水。喜干燥，耐干旱。浇水应掌握“不干不浇，浇则浇透”，保持稍微干燥状态。　　4、施肥。对一般，生长期每月施一次追肥，腐熟饼肥，颗粒复合肥均可。冬季休眠期应停止施肥。　　5、翻盆。每1－2年应翻盆一次。喜肥沃，排水良好的沙质土壤。　　6、病虫害的防治。有炭疽病，斑枯病与介壳虫，红等危害，应及时防治。红蜘蛛，介壳虫在通风不良时发病，应注意环境通风。', '　　虽然　　因为金手指的刺内卷，用手触摸不会被刺痛，加上被黄色短刺得细筒状球体犹如伸展的手指，因而得名金手指。金手指喜温暖湿润的环境，3－4天左右浇一次水，不干不浇，见干见湿室内栽培，可在窗台上用铅丝与塑料薄膜营造一个高温、高湿的封闭式空间，大多数　　繁殖金手指用土，要求排水透气良好、含石灰质的沙土或沙壤土。新栽植的仙人掌先不要浇水，每天喷雾几次即可，半个月后才可少量浇水，一个月后新根长出才能正常浇水。冬季气温低，植株进入休眠时，要节制浇水。开春后随着气温的升高，植株休眠逐渐解除，浇水可逐步增加。每10天到半个月施一次腐熟的稀薄液肥，冬季则不要施肥。', 'http://img.boqiicdn.com/Data/BK/P/imagick11691439198155.jpg', 'http://www.boqii.com/entry/detail/1923.html', '');
INSERT INTO `plant_family` VALUES ('197', '瓜叶菊', 'Florists Cineraria', '瓜叶菊', '', '不容易死', '原产大西洋加那利群岛，中国各地公园或庭院广泛栽培。', 'http://www.boqii.com/entry/photo/2334/0,http://www.boqii.com/entry/photo/2334/5082', '', '', '', '', '', '', '', '', '', '　　 　　瓜叶菊为多年生草本。茎直立，高30－70厘米，被密白色长柔毛。小花紫红色，淡蓝色，粉红色或近白色；舌片开展，长椭圆形，长2.5－3.5厘米，宽1－1.5厘米，顶端具3小齿；管状花黄色，长约6毫米。瘦果长圆形，长约1.5毫米，具棱，初时被毛，后变无毛。冠毛白色，长4－5毫米。花果期3－7月。有紫色、紫白色、紫色，紫白色比较常见。　　　　　　　　　　　　　　　　　瓜叶菊属　　　', '　　瓜叶菊是比较常见的卉，可以用于装点或居室，花色鲜艳美丽，色彩繁多，受到很多花友的喜爱。瓜叶菊的栽培难度并不高，小编就为你整理了瓜叶菊的栽培要点，的朋友可以一起了解。　　瓜叶菊在生长期内喜阳光，不宜遮荫。要定期转动花盆，使枝叶受光均匀，株形端正不偏斜。每半月施液肥1次，在花芽分化前2周，停止施肥，减少灌水，在稍干燥的情况下，着花率较高。开花期最适宜的为10－15℃，越冬温度8℃以上。花朵萎谢后植株仍需适度光照，以适应种子。　　瓜叶菊喜肥，定植时要施足基肥，盆土以腐叶土和园土加饼肥屑配置为佳。据有关资料报道：有人用60份腐叶土加30份园土、6份饼肥粉和4份骨粉的比例混合配制的盆栽土，效果很好。选直径为12～17cm的盆，盆土用腐叶土2份、壤土3份、砂土1份配合而成，并适当施以豆饼、骨粉或过磷酸钙作基肥。定植时要注意将植株栽于花盆正中央保持植株端正，浇足水置于阴凉处，成活后给予全光照。', '　　　　1、播种法：播种一般在7月下旬进行，至春节就可开花，从播种到开花约半年　　播种盆土由园土1份、腐叶土2份、砻糠灰2份，加少量腐熟基肥和过磷酸钙混合配成。播种可用浅盆或播种　　2、扦插或分株繁殖：重瓣品种不易结实，可用扦插。1－－6月，剪取根部萌芽或花后的腋芽作插穗，插于砂中。约20－－30天可生根，碚育5－－6个月即可开花。亦可用根部嫩芽分株繁殖。', 'http://img.boqiicdn.com/Data/BK/P/imagick80281450344632.jpg', 'http://www.boqii.com/entry/detail/2334.html', '');
INSERT INTO `plant_family` VALUES ('198', '孔雀草', 'Tagetes patula L.', '孔雀草', '小万寿菊，红黄草，西臭菊番菊，缎子花', '不容易死', '中国四川、贵州、云南等地', 'http://www.boqii.com/entry/photo/2205/0,http://www.boqii.com/entry/photo/2205/5322', '', '', '', '', '', '', '', '', '', '　　 　　一年生草本，高30－100厘米，茎直立，通常近基部分枝，分枝斜开展。叶羽状分裂，长2－9厘米，宽1.5－3厘米，裂片线状披针形，边缘有锯齿，齿端常有长细芒，齿的基部通常有1个腺体。　　　　　　　　　　　　　　　　　　　　　', '　　孔雀草原产于墨西哥，现在在园林、庭院中被广泛栽培，孔雀草的适应能力比较强，并且全草可入药，所以深受人们的欢迎。那么人工栽培孔雀草应该注意哪些', '　　孔雀草的栽培难度并不高，但人工栽种孔雀草常作一年生草本　　播种11月至3月间进行。冬春播种的3至5月开花。播种可在　　迎“五一”、庆“十一”用花，2月中旬在温室或室内播种，经一次移植后，假植于口径20厘米的花盆中。晚霜后脱盒定植于露地。盛夏时花少，可全面剪短一次。立秋后在新生侧枝顶部又可开花，也可以不剪短，只是植株比较松散。　　由于孔雀草的', 'http://img.boqiicdn.com/Data/BK/P/imagick68641447148898.jpg', 'http://www.boqii.com/entry/detail/2205.html', '');
INSERT INTO `plant_family` VALUES ('199', '紫藤', 'Wisteria sinensis （Sims）Sweet', '紫藤', '朱藤、招藤、招豆藤、藤萝', '不容易死', '中国，朝鲜、日本', 'http://www.boqii.com/entry/photo/2006/0,http://www.boqii.com/entry/photo/2006/5521', '', '', '', '', '', '', '', '', '', '　　 　　紫藤为落叶藤本。茎右旋，枝较粗壮，嫩枝被白色柔毛，后秃净；冬芽卵形。奇数羽状复叶长15～25厘米；托叶线形，早落；小叶3～6对，纸质，卵状椭圆形至卵状披针形，上部小叶较大，基部1对最小，长5～8厘米，宽2～4厘米，先端渐尖至尾尖，基部钝圆或楔形，或歪斜，嫩叶两面被平伏毛，后秃净；小叶柄长3～4毫米，被柔毛；小托叶刺毛状，长4～5毫米，宿存。紫藤　　被子植物门　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　为温带及暖带，对于外界环境和土壤的适应能力都比较强，也比较耐寒，由于紫藤的生长速度较快并且缠绕能力比较强，所以对于其他植物有一定的绞杀作用。现在很多花友会将紫藤制作成栽种，当紫藤开花时会非常漂亮。　　　　紫藤主根长，所以种植的地方需要土层深厚。紫藤耐贫瘠，但肥沃的土壤更有利生长。紫藤对土壤的酸碱度适应性也强。　　　　紫藤是大藤本植物，性喜光照，耐热耐寒，能略微耐荫，适应能力很强。为了使紫藤有良好的空间，植株较大一般都在棚架内栽培，矮小的紫藤品种也用来制作盆景。　　　　紫藤的根系发达，能到达很深的土层，所以紫藤拥有出色的耐旱能力，但是在湿润的土壤环境中能生长的更好。若紫藤根系长时间泡在水里，则容易烂根。每年给紫藤施2－3次复合肥就基本可以满足其对营养的需求。', '　　　\n　1、播种繁殖\n　　\n2、扦插繁殖\n　　\n3、压条繁殖法\n　　\n4、分蘖繁殖法\n　　\n5、嫁接繁殖法　\n　　紫藤直根性强，故移植时宜尽量多掘侧根，并带土地。多于早春定植，定植前须先搭架，并将粗枝分别系在架上，使其沿架攀援，由于紫藤寿命长，枝粗叶茂，制架材料必须坚实耐久。幼树初定植时，枝条不能形成花芽，以后才会着花生蕾。', 'http://img.boqiicdn.com/Data/BK/P/imagick80411441533948.jpg', 'http://www.boqii.com/entry/detail/2006.html', '');
INSERT INTO `plant_family` VALUES ('200', '爱染锦', 'Aeonium domesticum fa.variegata', '爱染锦', '黄笠姬锦', '不容易死', '原产地位于大西洋诸岛、北非和地中海沿岸', 'http://www.boqii.com/entry/photo/2429/0,http://www.boqii.com/entry/photo/2429/4986', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '莲花掌属', '爱染锦', 'Aeonium domesticum fa.variegata', '', '　　爱染锦又名黄笠姬锦、墨染等，为景天科 　　爱染锦为矮小灌木状植株。茎有落叶痕迹，半木质化有气生根，叶片匙形，颜色如同', '　　', '　　　　爱染锦多采用播种、扦插、芽插。以扦插为主，剪下一小颗插入土中即可生根。但叶插时，因叶片较薄，不易成活，不宜采用。爱染锦繁殖以茎插为好，因为成活率很高，而且爱染锦分枝性好，不过叶插因叶片较薄，不太易成活。', 'http://img.boqiicdn.com/Data/BK/P/imagick72651452848369.jpg', 'http://www.boqii.com/entry/detail/2429.html', '');
INSERT INTO `plant_family` VALUES ('201', '红掌', 'Anthurium', '红掌', '花烛、安祖花、火鹤花、红鹤芋、红鹅掌等', '不容易死', '原产于南美洲热带、现在欧洲、亚洲、非洲皆有广泛栽培', 'http://www.boqii.com/entry/photo/1961/0,http://www.boqii.com/entry/photo/1961/5566', '', '', '', '', '', '', '', '', '', '　　 　　红掌性喜温热多湿而又排水良好的环境，怕干旱和强光暴晒。其适宜　　　　　　　　　　　　　　　　　　　', '　　盆栽红掌是现在非常常见的，红掌的外形非常特别，并且在成长的过程中，红掌的也会发生一系列的变化，所以深受人们的喜爱。一般越小的红掌植株栽培难度就越大，所以新手朋友们最好选择植株已经长大的红掌来进行盆栽。　　红掌属于对较敏感的花卉品种，因此，应尽量把基质pH值控制在5.2－6.1之间，最适红掌生长。如果pH值过小，花茎变短，就会降低观赏价值。自来水适宜栽植红掌，但价格贵；天然雨水是红掌栽培中最好的水源。　　对红掌进行根部施肥比叶面追肥效果要好得多。因为红掌的叶片表面有一层蜡质，不能对肥料进行很好的吸收。液肥施用要掌握定期定量的原则，秋季一般3－4天为一个周期，如气温高，可以视盆内基质干湿程度可2－3天浇肥水一次；夏季可2天浇肥水一次，气温高时可多浇一次水；秋季一般5－7天浇肥水一次。施肥因气候环境而异，一般情况下，在上午8时至下午17时前施用；冬季或初春在上午9时至下午16时前进行。　　红掌是按照“叶→花→叶→花”的循环生长的。花序是在每片叶的腋中形成的。这就导致了花与叶的产量相同，产量的差别最重要的因素是光照。如果光照太少，在的影响下植株所产生的同化物也很少；当光照过强时，植株的部分叶片就会变暖，有可能造成叶片变色、灼伤或焦枯现象。　　盆栽红掌有时会出现花早衰、畸形、粘连、裂隙及玻璃化和蓝斑等现象，这多为施肥、盆土和空气湿度不当或品种原因引起的生理性病害。防止方法是改善栽培管理，合理施肥，适当通风。', '　　红掌的花语是大展宏图、热情，所以，常常被人摆放在室内　　\n一、分株繁殖\n　　红掌具有较强的分蘖能力，可以结合间苗、移苗及切花除芽等工作，将母株上的中小侧芽与母体分离，再将侧芽培养成新的植株，具体方法须按以下几方面进行：　　1、分株时期主要在凉爽高湿的春季，秋季阴凉天气也可分株。切忌在炎热的夏天或干燥寒冷的季节分株。　　2、分株时须注意以不伤母株为原则，太大的侧芽不分，靠太紧的侧芽不分，太弱小的侧芽也不分，主要分出比较容易与母株分离且较为健壮、至少有2条主要根系以上的侧芽。　　3、移植苗时分株可用手均匀用力，将侧芽与母株在地下茎芽眼处分离，较难分离时用锐利的　　4、切开的侧芽待伤口稍干后将其假植于阴凉处进行促根及恢复生长。种植时须使根系平展，植株直立，必要时进行支撑，种后不能立即浇水，可向叶面喷水保持湿度，2天后即可依情况进行浇水或施稀薄肥液。　　分株、扦插繁殖的缺点是生长较慢，且材料难于消毒，容易携带病虫害（如根结线虫、细菌和病毒等）。分株苗和组培苗在栽培技术上的要求是一样的，只是前者比后者植株高大、强壮一些而已。　\n　二、播种繁殖\n　　红掌在育种上，通过播种是获得红掌新　\n　三、组织培养\n　　组织培养是将植物材料的切块置于培养基中进行培育，并获得新植株的一种繁殖方法，整个过程在实验室无菌条件下完成。繁育材料首先必须严格消毒并经过脱毒培养，才能为获得无毒克隆苗提供保障。　　红掌的繁育材料主要采用愈伤组织和叶片。用愈伤组织作为繁育材料的原因是得到的克隆苗不易发生变异，但要获得无毒的愈伤组织非常困难。叶片容易消毒且操作比较方便，不利的是叶片不光滑，且用以培养形成的植株容易发生突变，但这种突变可以人为控制。　　组培苗在瓶苗阶段都是在人为提供的各种最适生长条件下完成生长过程的。实验条件同外界自然条件差异很大，因此，让瓶苗经历一个过渡的健化炼苗过程很有必要，以使瓶苗顺利适应外界的', 'http://img.boqiicdn.com/Data/BK/P/imagick38801439978611.jpg', 'http://www.boqii.com/entry/detail/1961.html', '');
INSERT INTO `plant_family` VALUES ('202', '黄槿', 'Cuban Bast', '黄槿', '糕仔树、桐花、盐水面夹果、朴仔、榄麻、海麻、海罗树、弓背树。', '不容易死', '主要分布华南', 'http://www.boqii.com/entry/photo/2224/0,http://www.boqii.com/entry/photo/2224/5303', '植物　　', '被子植物门', '双子叶植物纲', '锦葵目', '锦葵科', '木槿属', '黄槿', 'Hibiscus tiliaceus', '', '　　 　　黄槿的花两性，单生，腋生。常数花排列成聚散花序，总花梗长4－5cm；花梗长1－3cm，基部有1对托叶状苞片；小苞片7－10，线状披针形，被绒毛，中部以下连合成杯状；萼长1.5－2.5cm，基部合生，萼裂5，外具附萼（总苞），附萼5裂；花瓣5枚，披针形，被绒毛；花冠钟形，直径6－7cm，花瓣黄色，内面基部暗紫色，倒卵形，长约4.5cm，外面密被黄色星状柔毛；雄蕊往长约3cm，平滑无毛；花柱枝5，被细腺毛。雨果卵圆形，长约2cm，被绒毛，果爿。木质。种子光滑，肾形。', '　　黄槿是阳性，喜阳光，并且生性强健。由于黄槿的抗风力强，所以有防风定沙的功效，也非常适合在海边种植。黄槿在盛花期时，枝梢的黄花非常多，是非常优雅的观花树，那么如何才能养好黄槿呢？　　当枝条开始萌动时，应及时追肥，以速效肥为主，促进营养；现蕾前追施1～2次磷、钾肥，促进植株孕蕾；5～10月盛花期间结合除草、培土进行追肥两次，以磷钾肥为主，辅以氮肥，以保持花量及树势；冬季间进行除草清园，在植株周围开沟或挖穴施肥，以农家肥为主，辅以适量无机复合肥，以供应来年生长及开花所需养分。长期干旱无雨天气，应注意灌溉，而雨水过多时要排水防涝。　　新栽植的黄槿植株较小，在前1～2年可放任其生长或进行轻修剪，即在秋冬季将枯枝、病虫弱枝、衰退枝剪去。树体长大后，应对黄槿植株进行整形修剪。整形修剪宜在秋季落叶后进行。　　直立型黄槿枝条着生角度小，近直立，萌芽力强，成枝力相对较差，不耐长放，可将其改造成有主干不分层树形，主干上选留3～4个主枝，其余疏除，在每个主枝上可选留1～2个侧枝，称为有主干开心形。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick8451447667211.jpg', 'http://www.boqii.com/entry/detail/2224.html', '');
INSERT INTO `plant_family` VALUES ('203', '紫叶李', 'Prunus Cerasifera Ehrhar f. atropurpurea （Jacq.） R', '紫叶李', '红叶李、樱桃李', '不容易死', '原产亚洲西南部，中国华北及其以南地区广为种植。', 'http://www.boqii.com/entry/photo/2028/0,http://www.boqii.com/entry/photo/2028/5499', '', '', '', '', '', '', '', '', '', '　　 　　紫叶李为灌木或小乔木，高可达8米；多分枝，枝条细长，开展，暗灰色，有时有棘刺；小枝暗红色，无毛；冬芽卵圆形，先端急尖，有数枚覆瓦状排列鳞片，紫红色，有时鳞 片边缘有稀疏缘毛。叶片椭圆形、卵形或倒卵形，极稀椭圆状披针形，长（2）3－6厘米，宽2－3（2）厘米，先端急尖，基部楔形或近圆形，边缘有圆钝锯 齿，有时混有重锯齿，上面深绿色，无毛，中脉微下陷，下面　　　　　　　　　　　　　　　　　　　', '　　最特别的就是其常年紫红色的叶片，是我国非常有名的观叶树种，在园林中应用非常广泛，也非常适合用作背景植物。当紫叶李在绿色植物丛中，就会像一株株不败的花朵。那么紫叶李在栽种过程中应该注意哪些问题呢？　　　紫叶李为暖温带树种，喜光，应种植于光照充足处，光照不足不仅使植株不良，还会使叶片发绿。紫叶李耐旱、喜湿，但不耐积水，栽种于干燥之处可正常生长。紫叶李喜肥沃、湿润的中性或酸性沙质壤土，也能耐轻度碱土，紫叶李较耐寒，种植于背风向阳处。叶片为紫红色，种植时注意搭配，可显出叶色的美观。　　1、紫叶李喜湿润环境，对于新栽植的苗除浇好三水外，在4月、5月、6月、9月各浇1－2次透水。7、8两月降雨充沛，可不浇水，雨水较多时，应及时排水，防止水大烂根。11月上中旬还应浇足、浇透封冻水。在第二年的管理中也应于3月初、4月、5月、6月、9月和11月上中旬各浇水1次。从第3年起只需每年早春和初冬浇足、浇透解冻水和封冻水即可，可靠天自然生长。需要注意的是：进入秋季一定要控制浇水，防止水大而使枝条徒长，在冬季遭受冻害。　　2、紫叶李喜肥，除栽植时在坑底施入适量腐熟发酵的圈肥外，以后每年在浇封冻水前可施入一些农家肥，可使植株生长旺盛，叶片鲜亮。每年在秋末施1次肥即可，而且要适量，如果施肥次数过多或施肥量过大，会使叶片颜色发暗而不鲜亮，降低观赏价值。　　　紫叶李最佳的树形是“疏散分层形”。这种树形，树冠开张且不失紧凑，而且主干明显，主枝错落有致。紫叶李的整形一般分四年进行。第一年的修剪在栽植后进行，在干高0.8至1.2米处短截，剪口下的第一个芽作为主枝延长枝，另在第一个芽的下方选取3至4个粗壮的新生枝条作为主枝，枝条应均匀分布，可不在同一轨迹，但上下不应差5厘米以上，且应呈45度角向上展开。在生长期要摘心，促其粗壮。第二年冬剪时，适当短截主枝延长枝，选取壮芽，在其上1厘米处短截，芽的方向应与头年主干延长枝的方向相反，主枝进行短截，留粗壮的外芽。第三年冬剪时，主干延长枝再与第二年的主干延长枝方向相反，并选留第二层主枝，也同样保留外芽，长成后与第二年主枝错落分布。第四年以此类推。', '　　紫叶李高可达8米，可以再　　1、插条准备选择树龄3至4年，生长健壮的树作为母树。在深秋落叶后从母树上剪取无病虫害的当年生枝条，也可结合整形修剪将剪下的粗壮、芽饱满，无病虫害及机械损伤的枝条作为插条。将选出的插条剪成40至50厘米的枝段，按100至200支打捆，用湿沙埋入贮藏。　　2、紫叶李苗圃地选择和整地苗圃地应选择排灌和交通运输方便的地方，土层要求为深厚、肥沃、疏松的沙壤土。整地前，每亩地均匀撒施1至1.5吨腐熟农家肥，并用50％　　3、紫叶李最佳扦插　　4、扦插方法扦插前，先将刚剪下的或贮藏在湿沙中的枝条，剪去细弱枝和失水干缩部分，然后自下而上，将长枝条剪成长10至12厘米，有3至5个芽的插穗。插穗下端近芽处剪成光滑斜面，以增加形成层与土壤的接触面，有利于生根。插穗上端距芽眼0.8至1厘米处剪齐成平面。插穗剪好后，应立即将其下端斜面浸入清水中浸泡15至20个小时，使插条充分吸足水。用50×10－6ABT6号生根粉按比例配成生根剂，蘸浸插穗以利生根。插穗斜面向下插入土中，株行距5×5厘米，上端的芽露出地面0.5至1厘米。扦插后立即放水洇灌，使插穗与土壤密接。待地面稍干后用双层地膜覆盖保墒，同时在畦面上搭1米高与畦面同宽的塑料小拱棚以利保温、御寒。　　5、扦插苗　　6、移植苗管理4月下旬，选阴雨天或晴天的下午4点后进行移植。起苗前，苗床灌足水，以利起苗减少伤根，根系又能多带泥土。现起苗现栽植，提高移植成活率。移植时株行距20厘米×30厘米。移植前每亩地施4至5吨腐熟农家肥和含量各15％的三元复合肥0.05吨，深耕细耙后移植。栽后浇足水，育苗地保持不干不过湿，并加强病虫草害防治。6月初，阴雨天前或土壤干旱灌溉前，每亩地撒施尿素0.025吨，以促进苗木生长。当年移植苗平均高度可达1.5米左右，地径1.5厘米。', 'http://img.boqiicdn.com/Data/BK/P/imagick77741441964405.jpg', 'http://www.boqii.com/entry/detail/2028.html', '');
INSERT INTO `plant_family` VALUES ('204', '奔龙', '', '奔龙', '', '其花寿命3~5日', '', 'http://www.boqii.com/entry/photo/2502/0,http://www.boqii.com/entry/photo/2502/4088', '', '', '', '', '', '', '', '', '', '　　 　　奔龙的繁殖方式比较简单，一般以分株扦插繁殖为主。另外由于奔龙的根系比较强大，一般选用深一点的花盆。奔龙的日常', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick95601455788682.png', 'http://www.boqii.com/entry/detail/2502.html', '');
INSERT INTO `plant_family` VALUES ('205', '福娘', 'Cotyledon orbiculata var.dinteri', '福娘', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2409/0,http://www.boqii.com/entry/photo/2409/5006', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '银波锦属', '福娘', 'Cotyledon orbiculata var.dinteri', '', '　　 　　福娘叶片尖细狭长呈棒形，叶对生开黄红花，叶尖叶缘有暗红或褐红色。', '　　又名丁氏轮回，为多分枝的肉质灌木，其叶片近似棒形，灰绿色，上面覆盖白粉，叶尖和叶缘为红褐色，比较特别。福娘现在被很多多肉爱好者所喜爱，现在在世界多地均有栽培。　　福娘排水良好的土壤，喜阳光，稍耐寒。夏季适当遮光。注意浇水和避雨，防止水分过多导致腐烂。适温15-25度，冬季不低于5度；配土一般可用泥炭、和珍珠岩的混合土；生长期浇水干透浇透，夏季要通风降温、节制浇水，盛夏时尤其不能浇水，冬季保持盆土稍干燥。生长期施肥一般每月一次。', '　　　　福娘的繁殖方式主要用扦插繁殖，在', 'http://img.boqiicdn.com/Data/BK/P/imagick75341452503139.jpg', 'http://www.boqii.com/entry/detail/2409.html', '');
INSERT INTO `plant_family` VALUES ('206', '凤仙花', 'Garden Balsam，Toutch－me－not', '凤仙花', '指甲花、急性子、女儿花、金凤花、桃红', '不容易死', '原产印度、马来西亚和中国', 'http://www.boqii.com/entry/photo/2156/0,http://www.boqii.com/entry/photo/2156/5371', '', '', '', '', '', '', '', '', '', '　　 　　凤仙花为一年生草本，高60－100cm。凤仙花全株分根、茎、叶子、花、果实和种子六个部分。茎粗壮，肉质，直立，不分枝或有分枝，无毛或幼时被疏柔毛，基部直径可达8mm，具多数纤维状根，下部节常膨大。　　　　　　　　　　　　　　　　　　　　　　　　　', '　　又名指甲花，这是由于凤仙花的花瓣可以用来染指甲，现在，很多朋友都会将凤仙花作为盆栽栽种在家中，装饰家居环境。那么，人工栽种凤仙花应该注意哪些问题呢？　一般于春季3－4月播种，可播种在苗床内，或直接播于花坛。　凤仙花的理想营养生长温度是白天22到25度，夜间在20到21度之间。5周之后对于紧凑型植株白天的生长温度在20到21度之间，夜间18度，这个温度是凤仙花分化和发育的理想温度。当白天的温度超过28到29度，就要进行遮阴了，否则会减小花的大小。　定植后应及时灌水，勤施肥，特别注意不可忽干忽湿。夏季切忌在烈日下给枯萎的植株浇水。特别在开花期，不能受旱，否则易落花。　　如果要使花期推迟，可在7月初播种。也可采用摘心的方法，同时摘除早开的花朵及花蕾，使植株不断扩大，每15－20天追肥1次。9月以后形成更多的花蕾，使它们在国庆节开花。同时还要注意病害的防治。', '　　　　凤仙花一般用播种繁殖。3―9月进行播种，以4月播种最为适宜，移栽不择　　长到8cm左右时，每盆保留1―3株。长到20―30厘米时摘心，定植后，对植株主茎要进行打顶，增强其分枝能力，株形丰满。5片叶以后，每隔半个月施一次腐熟稀薄人粪尿等，孕蕾前后施一次磷肥及草木灰。　　花开后剪去花蒂，不使其结籽，则花开得更加繁盛；基部开花随时摘去，这样会促使各枝顶部陆续开花，但容易变异。　　6月上、中旬即可开花，花期可保持两个多月。播种前，应将苗床浇透水，使其保持湿润，凤仙花的种子比较小，播下后不能立即浇水，以免把种子冲掉。再盖上约3―4毫米一层薄土，注意遮荫，约10天后可出苗。当小苗长出2－3片叶时就要开始移植，以后逐步定植或上盆培育。', 'http://img.boqiicdn.com/Data/BK/P/imagick18231446024381.jpg', 'http://www.boqii.com/entry/detail/2156.html', '');
INSERT INTO `plant_family` VALUES ('207', '凌霄', 'Chinese trumpet creeper', '凌霄', '紫葳、女藏花、凌霄花、中国凌霄、凌苕', '不容易死', '分布于中国华东、华中、华南等地；日本也有栽培。', 'http://www.boqii.com/entry/photo/2044/0,http://www.boqii.com/entry/photo/2044/5483', '', '', '', '', '', '', '', '', '', '　　 　　凌霄为攀援藤本；茎木质，表皮脱落，枯褐色，以气生根攀附于它物之上。叶对生，为奇数羽状复叶；小叶7－9枚，卵形至卵状披针形，顶端尾状渐尖，基部阔楔形，两侧不等大，长3－6（－9）厘米，宽1.5－3（－5）厘米，侧脉6－7对，两面无毛，边缘有粗锯齿；叶轴长4－13厘米；小叶柄长5（－10）毫米。　　　　　　　　　　　　　　　　　　　　　　', '　　是非常有名的园林，色彩鲜艳，为大红或金黄色，且花期较长，攀援，是优良的园林绿化材料。此外，凌霄的花、茎均可入药，深受人们的欢迎。　　早期管理要注意浇水，后期管理可粗放些。植株长到一定程度，要设立支杆。每年发芽前可进行适当疏剪，去掉枯枝和过密枝，使树形合理，利于。开花之前施一些复合肥、堆肥，并进行适当灌溉，使植株生长旺盛、开花茂密。盆栽宜选择5年以上植株，将主干保留30－40cm短截，同时修根，保留主要根系，上盆后使其重发新枝。萌出的新枝只保留上部3－5个，下部的全部剪去，使其成伞形，控制水肥，经一年即可成型。搭好支架任其攀附，次年夏季现蕾后及时疏花，并施一次液肥，则花大而鲜丽。冬季置不结冰的室内越冬，严格控制浇水，早春萌芽之前进行修剪。', '　　　　中国凌霄和美国凌霄都喜肥、好湿，春季发芽之后就应加水施肥，方可叶茂花繁。　　繁殖主要用扦插或压条法，因不易结果，难得种子，故不用播种法。它们的根蘖较易萌发，也可用分株法繁殖。早春宜将组织不充实、过冬枯干及拥挤的枝条剪掉，以保持整洁。若进行盆栽观赏，可以选择五年生以上植株，主干保留高30厘米左右截去掘起，将根部适当修剪，只留主要根系，上盆栽好；利用其萌发能力强的特点，重发新枝，仍将下部剪去，只留上部3－5枝，成伞形。并控制水肥，不使生长过旺，', 'http://img.boqiicdn.com/Data/BK/P/imagick83461442396431.jpg', 'http://www.boqii.com/entry/detail/2044.html', '');
INSERT INTO `plant_family` VALUES ('208', '牵牛花', 'Pharbitis nil （L.） Choisy', '牵牛花', '牵牛、喇叭花、筋角拉子、大牵牛花、勤娘子', '不容易死', '原产热带美洲', 'http://www.boqii.com/entry/photo/2149/0,http://www.boqii.com/entry/photo/2149/5378', '　', '被子植物门', '双子叶植物纲', '管状花目', '旋花科', '牵牛属', '牵牛', 'Pharbitis nil （L.） Choisy', 'Ipomoea nil', '　　 　　牵牛花为一年生缠绕草本，茎上被倒向的短柔毛及杂有倒向或开展的长硬毛。叶宽卵形或近圆形，深或浅的3裂，偶5裂，长4－15厘米，宽4.5－14厘米，基部圆，心形，中裂片长圆形或卵圆形，渐尖或骤尖，侧裂片较短，三角形，裂口锐或圆，叶面或疏或密被微硬的柔毛；叶柄长2－15厘米，毛被同茎。', '　　的人工栽培难度并不高，但是，牵牛花对及基质的要求比较高，所以，想要养出漂亮的牵牛花，基质及环境都是非常重要的。　　牵牛花生性强健，喜气候温和、光照充足、通风适度，对土壤适应性强，较耐干旱碱、不怕高温酷暑、属深根性植物，好生肥沃、排水良好的土壤，忌积水。栽植牵牛花时，首先要选择排水性好的土壤，并给与适量通风及充分日照，生育期盆土表面略干时进行灌水，半月施加稀薄肥料一次，控制好氮肥的度，防止茎叶过于茂盛，盆栽需设支柱撑着。　　牵牛花的真叶长出三四片后，中心开始生蔓，这时应该摘除。第一次摘心后，叶腋间又生枝蔓，待枝蔓生出三四片叶后，再次摘心，同时结合整形。每次摘心后都应追肥，所用肥料和)用的追肥类似。注意不使肥水和泥浆沾污叶片（包括子叶），以免叶片脱落。枝蔓成长后即进入花期（一般在定植后一个月），理想的情况是枝蔓的第一叶又生腋芽，第二和第三叶的叶腋发出花苞。待花苞成形后，可将花苞的托叶摘掉，以利花苞发展。为保证养分充分供应花苞而开出大而艳丽的花朵，还可以除掉一些花苞，培育独朵的花。', '　　牵牛花的适应能力比较强，　　1、育苗：牵牛花子发芽　　2、定植：小盆中的幼苗长出两三片真叶后，此时根系已发展好，即可定植在中盆中，并预先加好底肥。正如梅先生所说，牵牛花不怕重肥，可以用马掌、熟麻渣等作底肥。牵牛花的根系发展需要温度，据日本研究者认为，用黑盆比用红盆吸热好。要经常转盆使阳光照射均匀，使根系发展完备。　　3、摘心：牵牛花的真叶长出三四片后，中心开始生蔓，这时应该摘除。第一次摘心后，叶腋间又生枝蔓，待枝蔓生出三四片叶后，再次摘心，同时结合整形。每次摘心后都应追肥，所用肥料和菊花用的追肥类似。注意不使肥水和泥浆沾污叶片（包括子叶），以免叶片脱落。枝蔓成长后即进入花期（一般在定植后一个月），理想的情况是枝蔓的第一叶又生腋芽，第二和第三叶的叶腋发出花苞。　　4、留种：好的品种一定要留好种子，待入秋成熟后取种分类标注保存。如出现变种，更应加意留存。牵牛花的杂交在选好母本和父本后，在开花的前一天黄昏将花苞上端剪去，然后除去雄蕊，用蜡纸袋包扎。第二天清晨取下蜡纸袋，用父本的雄蕊进行人工授粉，然后再用蜡纸袋包扎，一二周后可除去蜡纸袋，但授粉的子包一定要作好标记，作好记录。翌年要把所杂交的全部种子种好，待开花后看成果，由之可以研究各种遗传因子的作用。　　5、冬种牵牛花的培育方法是：秋季及时选择和采集优良花色的牵牛花种子，立冬后，将种子播于盆土。盆土要求埋施三四片马掌或掺匀少量麻渣面作底肥。播种后，用25℃左右的温水浇透盆土，并盖玻璃板或套上塑料袋，置于温暖向阳的窗台上。小苗出土后，及时去掉覆盖物，经过间苗、蹲苗，最后选留2株－3株壮苗，竖以架杆，引导蔓茎上爬，任其自然', 'http://img.boqiicdn.com/Data/BK/P/imagick19311445851432.jpg', 'http://www.boqii.com/entry/detail/2149.html', '');
INSERT INTO `plant_family` VALUES ('209', '麦李', 'Cerasus glandulosa （Thunb.） Lois.', '麦李', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2265/0,http://www.boqii.com/entry/photo/2265/5260', '', '被子门', '双子叶植物纲', '蔷薇目', '蔷薇科', '樱属', '麦李', 'Cerasus glandulosa （Thunb.） Lois.', '', '　　 　　麦李是灌木，高0.5－1.5米，稀达2米。小枝灰棕色或棕褐色，无毛或嫩枝被短柔毛。冬芽卵形，无毛或被短柔毛。叶片长圆披针形或椭圆披针形，长2.5－6厘米，宽1－2厘米，先端渐尖，基部楔形，最宽处在中部，边有细钝重锯齿，上面绿色，下面淡绿色，两面均无毛或在中脉上有疏柔毛，侧脉4－5对；叶柄长1.5－3毫米，无毛或上面被疏柔毛；托叶线形，长约5毫米。', '　　的适应能力非常强，并且有一定的耐寒性，所以在、路边都能常常见到，在我国和日本分布较广。麦李的观赏性较高，春天叶前开花，非常漂亮。　　麦李有一定耐寒性适应性强，喜光，较耐寒，适应性强，耐旱，也较耐水湿；根系发达。忌低洼积水、土壤粘重，喜生于湿润疏松排水良好的沙壤中。　　麦李定植时要带土坨、坐水栽植，待水渗透后再覆土踩实。若带叶移栽，则要用50％的遮荫网遮荫。载后最好采用喷灌，每天喷30秒。缓苗期内一般7－10天浇一次水。在要进行3－4次除草、松土。麦李自引种以来每年要进行采条扦插繁殖，没有影响树势的生长。麦李的树冠整齐丰满，树形椭圆球状，十分完美，不必修剪。如果作为花篱种植，株距以每米3株为宜，亦不必重剪，只需将个别突出部分修剪即可。', '　　　　麦李常用分株或嫁接法繁殖，砧木用山桃。扦插繁殖，主要夏季半成熟枝插易成活。每年6月末至7月初为扦插育苗最佳时期。采用直插法，插前先用木条在基质上打孔，株行距为5厘米×5米，每行20株插穗。药剂选用（GGR）生根粉、吲哚丁酸（IBA）、吲哚乙酸（IAA）、萘乙酸（NAA）四种生根促进剂，设定50×10－6、100×10－6、200×10－6、500、1000×10－6、2000×10－6，6个浓度梯度，前三个低浓度为长时间浸泡处理（1小时、2小时），后3个高浓度为5s速蘸处理，每个处理40根插穗，3次重复，同时以清水处理插穗为对照。扦插深度为插穗长的1／3（约3厘米），压实插穗周围基质，立即用喷壶浇透水，使插穗与基质充分接触。床上横插拱形钢筋架，架上蒙盖塑料薄膜（内置温', 'http://img.boqiicdn.com/Data/BK/P/imagick21131448617713.jpg', 'http://www.boqii.com/entry/detail/2265.html', '');
INSERT INTO `plant_family` VALUES ('210', '油菜花', 'Rape flowers', '油菜花', '芸薹', '不容易死', '在我国栽培较广，以长江流域和以南各地', 'http://www.boqii.com/entry/photo/2030/0,http://www.boqii.com/entry/photo/2030/5497', '　', '被子植物门', '双子叶植物纲', '白花菜目', '十字花科', '芸薹属', '油菜花', 'Blassikakapestris', '', '　　 　　油菜花四片花瓣，整齐地围绕着花蕊，朴实个性。花瓣十分精致，有细细的纹路，那是技艺多么高超的雕刻家也无法雕琢出来的。中间的花蕊弯曲着凑在一块，仿佛在说着悄悄话。它有坚韧的根茎，茂密的叶，有着像栽种它们的农民们一样的淳朴与粗犷。', '　　是很多农民种植的主要油料作物，并且当成片的油菜花开放的时候，观赏价值也很高，有很多朋友也会在油菜花期观赏油菜花的美。那么油菜花的栽种应该注意哪些呢？小编就为你整理了相关知识。　　　苗期：油菜每亩要留苗1.2万～1.5万株（一般20－25株／㎡左右），而出苗数要远远超出这个范围。因此，油菜出苗后，应及时疏苗。为了保证越冬，11月中下旬，在土壤封冻前的10—15天，日均温5℃左右，早冻午消时，要浇越冬水。还可采用培土、盖土、盖干粪等防冻措施。　　返青期：返青后浇返青水，一般在3月中、下旬进行，可适当晚浇。结合灌水每亩追施尿素15千克或相当数量的硝酸铵、碳铵（返青后生长迅速，返青期应尽量追施速效肥）。　　苔、花期：抽苔前后结合防虫、每亩喷施0.10～0.15千克磷酸二氢钾。油菜的花期是需水的临界期，开花期要勤浇、轻浇、保持土壤湿润。在抽薹至开花阶段，结合浇水及时追肥，薹高8～12厘米时，结合灌水每亩追施尿素10千克或相当数量的硝酸胺、碳铵。　　　　栽时要施足底肥，移栽成活后搞好中耕除草，增强土壤通透性。移栽后重点施好三次肥。1、开盘肥。在12月下旬至1月上旬，以农家肥为主，适当掺和氮肥，每挑水肥兑尿素100D150克，可增加分枝数。2、蕾苔肥。时间在2月上旬，以速效磷钾肥为主，兑在水粪中施用，可增加角果数量。3、花肥。时间在开花期，亩用硼肥200克兑磷酸二氢钾150克，进行喷雾，可增加花的受精率。　　追施花肥是油菜后期增产的重要措施。施花肥要根据苗情、地力等条件而定。达到秋发冬壮、春季稳长的油菜，可在初花期，叶、茎色略有褪淡的基础上追施花肥，每亩可施尿素5－7.5千克，或硫铵10－15千克。春发较好，土壤后劲足，初花期叶色较深或群体发展过大的油菜，应严格控制施用花肥。春发不足，开花期长势明显减退的菜田，花肥应适当提早施。　　　花角期雨水较多时，要清沟排水降湿，控制地下水位，防渍害及病害。干旱少雨时，要保持一定的田间湿度。', '　　　\n　1、播种前的准备\n　　油菜适应性较强，对土壤要求不严格，但以土层较厚，肥沃疏松的土壤为宜。油菜种子小，幼芽顶土力弱，要求精细整地才能出好苗。　　底肥每亩施农家肥500—1000公斤，尿素8—10公斤，普钙20—25公斤，钾肥5—7公斤，或油菜专用肥20—30公斤，硼砂1—1.5公斤，混合做沟肥。　　播种前的7—10天要浇足底墒水，使苗全、苗匀、苗壮，并为全　　冬油菜的播种', 'http://img.boqiicdn.com/Data/BK/P/imagick1061441965157.jpg', 'http://www.boqii.com/entry/detail/2030.html', '');
INSERT INTO `plant_family` VALUES ('211', '黄花风铃木', 'Tabebuia chrysantha', '黄花风铃木', '黄金风铃木、巴西风铃木、伊蓓树', '不容易死', '巴西国花，原产墨西哥、中美洲、南美洲', 'http://www.boqii.com/entry/photo/2164/0,http://www.boqii.com/entry/photo/2164/5363', '植物　', '被子植物门', '双子叶植物纲', '管状花目', '紫葳科', '风铃木属', '黄花风铃木', 'Tabebuia chrysantha', '', '　　 　　黄花风铃木约4－6m高。干直立，树冠圆伞形。掌状复叶，小叶4－5枚，倒卵形，纸质有疏锯齿，叶色黄绿至深绿，全叶被褐色细茸毛。', '　　是会随着四季变化而变换风貌的树，非常特别，在一年四季都会展现出独特的风貌。黄花风铃木的栽培难度并不高，并且适应能力也比较强，当环境适合的话，黄花风铃木就能长的比较好。　　　黄花风铃木生长适温23－30oC，不耐寒，在我国仅适合于热带亚热带地区栽培。　　在苗期也要求较强的光照，特别是在温室环境进行播种育苗时，极易因为光照和通风不足造成小苗长势弱并发生猝倒病。因此在种子发芽、真叶展开后，要保证生长环境的遮光率不超过50％，同时保持足够的通风。　　　黄花风铃木培育大苗的圃地应选择土壤疏松肥沃，浇灌与排水良好的地方，做好规划和整理好排灌水的沟渠，每亩种植3000株左右，种植时每穴下250克的复合肥或1千克的有机肥作基肥，基肥应与泥土充公搅拌后再种苗。种苗时，要去掉育苗袋，种稳压实。　　　合适株行距2.5m＊2.5m，挖穴至少50cm＊50cm＊40cm，施肥一般10斤左右，混合75％畜禽肥、18％磷肥、7％钾肥、微量硫酸锌（促使分蘖、分枝，使树冠饱满）做基肥。追肥要勤施薄施，隔两个月施追肥一次，第一次施尿素，以后施复合肥。金花风铃木枝条软，注意一定要立杆扶直。', '　　　　黄花风铃木果实成熟后易在树上开裂。种子飞散。用种子繁殖时，须在蒴果成熟后且未开裂的及时采收种子。播种时注意排水，播种苗床稍加抬高。因种子较细且轻，苗床须用细而疏松的园土或摹质，土壤弱酸性或中性。播种后用细土稍加覆盖。保持湿润，10d左右即可发芽。种子发芽后，加强', 'http://img.boqiicdn.com/Data/BK/P/imagick80921446110386.jpg', 'http://www.boqii.com/entry/detail/2164.html', '');
INSERT INTO `plant_family` VALUES ('212', '冷水花', 'Pilea notata C. H. Wright', '冷水花', '透明草、透白草、铝叶草、白雪草、长柄冷水麻', '不容易死', '中国大部地区。', 'http://www.boqii.com/entry/photo/2134/0,http://www.boqii.com/entry/photo/2134/5393', '', '', '', '', '', '', '', '', '', '　　 　　冷水花为多年生草本，具匍匐茎。茎肉质，纤细，中部稍膨大，高25－70厘米，粗2－4毫米，无毛，稀上部有短柔毛，密布条形钟乳体。叶纸质，同对的近等大，狭卵形、卵状披针形或卵形，长4－11厘米，宽1.5－4.5厘米，先端尾状渐尖或渐尖，基部圆形，稀宽楔形，边缘自下部至先端有浅锯齿，稀有重锯齿，上面深绿，有光泽，下面浅绿色，钟乳体条形，长0.5－0.6毫米，两面密布，明显，基出脉3条，其侧出的二条弧曲，伸达上部与侧脉环结，侧脉8－13对，稍斜展呈网脉；叶柄纤细，长1 7厘米，常无毛，稀有短柔毛；托叶大，带绿色，长圆形，长8－12毫米，脱落。　　　　　　　　　　　　　　　　　　　', '　　', '　　　　1、扦插法繁殖：扦插在春、夏均可进行。夏季高温季节不适于扦插，冬季扦插则　　2、分株繁殖：冷水花的丛生性很强，可结合翻盆换土把整墩柱丛分成几份分别上盆，同时对老茎进行短截，保留茎干基部2～3节，成活后腋芽很快就可萌发而抽生新的侧枝。', 'http://img.boqiicdn.com/Data/BK/P/imagick43651445419400.jpg', 'http://www.boqii.com/entry/detail/2134.html', '');
INSERT INTO `plant_family` VALUES ('213', '青枫', '鸡爪枫，槭树等', '鸡爪槭', '', '不容易死', '日本、朝鲜、韩国、中国、蒙古东部和俄罗斯东南部、美国', 'http://www.boqii.com/entry/photo/2130/0,http://www.boqii.com/entry/photo/2130/5397', '植物　', '被子植物门', '双子叶植物纲', '无患子目', '槭树科', '槭属', '鸡爪槭', 'Acer palmatum Thunb', 'Acer palmatum Thunb.', '　　 　　青枫为落叶小乔木。树皮深灰色。小枝细瘦；当年生枝紫色或淡紫绿色；多年生枝淡灰紫色或深紫色。叶纸质，', '　　', '　　　　青枫最常用的繁殖方法为播种育苗，优点是繁殖速度快，规模化，量大，摆脱其他树种长期无性繁殖的蜕化缺点，树苗抗病性好。一般每亩用种子约6～8公分，秋播春播俱佳，出芽率高。播种行距为15～20厘米，幼苗不能全日光照，要做好遮阳措施，苗高20公分进行第一次间苗，拨出弱苗病苗，35～40公分进行第二次间苗，每株苗保持较好的　　当年青枫苗可长高1.2～1.5米，根径0.8～1.3公分，第二年早春进行分株定植，株行距50＊120公分，缓苗后一月开始第一次施肥，用量不可过多，可用有机肥埋施，配合化肥撒施。视情况进行除草浇水，生长高峰期20天施肥一次。按照此方法培育青枫苗，两年可长高2～2.3米高，直径2.5～3公分。而且树杆通直，植株健壮，是优良的行道树半成品苗。建议零售价15～20元一株，也可自己留用行道树栽培。', 'http://img.boqiicdn.com/Data/BK/P/imagick98461445332142.jpg', 'http://www.boqii.com/entry/detail/2130.html', '');
INSERT INTO `plant_family` VALUES ('214', '天鹅绒竹芋', 'Maranta arundinacea var. variegata Hort.', '斑叶竹芋', '天鹅绒竹芋、绒叶竹芋、斑马竹芋', '不容易死', '', 'http://www.boqii.com/entry/photo/2158/0,http://www.boqii.com/entry/photo/2158/5369', '　　', '种子植物门', '单子叶植物纲', '目', '竹芋科', '肖竹芋属', '斑叶竹芋', 'Maranta arundinacea var. variegata Hort.', 'Maranta arundinacea var。 variegata', '　　天鹅绒 　　天鹅绒竹芋为多年生草本，具根茎；植株具地下根茎，高50厘米至60厘米。叶片长椭圆形，长30厘米至60厘米，宽10厘米至20厘米，叶色有华丽的天鹅绒光泽，并伴有深绿略带紫色和浅绿色交织的斑马形的羽状条纹，叶背深紫红色。花紫色。', '　　天鹅绒原产于南美的热带雨林中，早在1732年就被引种到英国，作为温室，现在在我国，天鹅绒竹芋的普及度也非常广，是比较常见的室内喜阴观叶植物。我国栽培天鹅绒竹芋的时间并不长，那么如何才能养好天鹅绒竹芋呢？首先，我们需要了解天鹅绒竹芋的习性特点。　　天鹅绒竹芋的生长适温18～25℃，3～9月为21～27℃，9月至翌年3月为18～21℃。冬季温度不低于13℃，夏季温度超过35℃，否则对天鹅绒竹芋的生长极为不利，使茎叶生长停止或受冻死亡。　　天鹅绒竹芋对水分的反应十分敏感。生长，须充分浇水，保持盆土湿润。但土壤过湿，会引起根部，甚至死亡，应特别注意。同时，若空气湿度小，叶片即刻卷曲，反应十分灵敏。室内栽培，空气湿度必须保持在70％～80％。冬季保持稍干燥，过湿叶片易变黄枯萎。　　天鹅绒竹芋喜低光度或半阴环境下生长，但长期在室内低光度下生长，植株柔弱，叶片失去特有的色彩。相反，盛夏在强光下暴晒片刻，叶片容易灼伤。以1万～2万勒克斯光照强度最合适。　　土壤以肥沃、疏松和排水良好的腐叶土最宜。盆栽用土、泥炭土和粗沙的混合土。', '　　天鹅绒竹芋的栽培难度并不大，人工繁殖天鹅绒竹芋可以选用分株法和组培法，如果你的天鹅绒竹芋正处在', 'http://img.boqiicdn.com/Data/BK/P/imagick69131446086743.jpg', 'http://www.boqii.com/entry/detail/2158.html', '');
INSERT INTO `plant_family` VALUES ('215', '金盏花', 'Marigold', '金盏花', '金盏菊、盏盏菊、黄金盏、长生菊、醒酒花、常春花、金盏等', '不容易死', '原产欧洲', 'http://www.boqii.com/entry/photo/2058/0,http://www.boqii.com/entry/photo/2058/5469', '植物　　', '被子植物门', '双子叶植物纲', '菊目', '菊科', '金盏花属', '金盏花', 'Calendula officinalis L.', 'Calendula officinalis', '　　 　　金盏花为两年生草本，全株被毛。叶互生，长圆形。头状花序单生，花径5厘米左右，有黄、橙、橙红、白等色，也有重瓣、卷瓣和绿心、深紫色花心等栽培', '　　', '　　金盏花的适应能力较强，现在常常可以在花坛中见到它们的身影。其叶和花瓣均可使用，并且还有一定的药用价值，也是现在很多化妆品的原材料。金盏花一般可用播种和扦插两种方法进行繁殖，小编就为你详细介绍一下。　\n　一、播种繁殖\n　　常在9月中下旬以后进行秋播：基质　　1、催芽　　用温热水（温度和洗脸水差不多）把种子浸泡3～10个小时，直到种子吸水并膨胀起来。对于很常见的容易发芽的种子，这项工作可以不做。　　2、播种　　对于用手或其它工具难以夹起来的　　3、播种后的　　在秋季播种后，遇到寒潮低温时，可以用塑料薄膜把花盆包起来，以利保温保湿；幼苗出土后，要及时把薄膜揭开，并在每天上午的9：30之前，或者在下午的3：30之后让幼苗接受太阳的光照，否则幼苗会生长得非常柔弱；大多数的种子出齐后，需要适当地间苗：把有病的、生长不健康的幼苗拔掉，使留下的幼苗相互之间有一定的空间；当大部分的幼苗长出了3片或3片以上的叶子后就可以移栽上盆了。　\n　二、扦插繁殖\n　　1、扦插基质　　就是用来扦插的营养土或河砂、泥碳土等材料。家庭扦插限于条件很难弄到理想的扦插基质，建议使用本站提供的已经配制好并且消过毒的扦插基质；用中粗河砂也行，但在使用前要用清水冲洗几次。海砂及盐碱地区的河砂不要使用，它们不适合花卉　　2、扦插枝条的选择　　用来扦插的枝条称为插穗。通常结合摘心工作，把摘下来的粗壮、无病虫害的顶梢作为插穗，直接用顶梢扦插。', 'http://img.boqiicdn.com/Data/BK/P/imagick18261442829086.jpg', 'http://www.boqii.com/entry/detail/2058.html', '');
INSERT INTO `plant_family` VALUES ('216', '虞美人', 'Common poppy；Corn Poppy ；Field Poppy ；Flanders Pop', '虞美人', '丽春花、赛牡丹、满园春、仙女蒿、虞美人草、舞草', '不容易死', '', 'http://www.boqii.com/entry/photo/2036/0,http://www.boqii.com/entry/photo/2036/5491', '', '', '', '', '', '', '', '', '', '　　 　　虞美人全体被伸展的刚毛，稀无毛。茎直立，高25－90厘米，具分枝，被淡黄色刚毛。叶互生，叶片轮廓披针形或狭卵形，长3－15厘米，宽1－6厘米，羽状分裂，下部全裂，全裂片披针形和二回羽状浅裂，上部深裂或浅裂、裂片披针形，最上部粗齿状羽状浅裂，顶生裂片通常较大，小裂片先端均渐尖，两面被淡黄色刚毛，叶脉在背面突起，在表面略凹；下部叶具柄，上部叶无柄。　　　　　　　　　　　　　　　　　　　　　　　　', '　　的外形很多人会和罂粟花搞混，这两种植物的确在外形上会非常相似，但是虞美人却是可以的。虞美人原产于欧洲和亚洲，性耐寒，不耐酷暑湿热，所以人工栽培虞美人应注意外界环境。　　喜凉爽，忌高温，冬暖夏凉最宜其，生长期要求光照充足，每天至少要有4小时的直射日光。如果生长环境阴暗，光照不足，植株生长瘦弱，花色暗淡。　虞美人耐寒，怕暑热，适宜生长温度12－20℃。夏季温度升高，虞美人长势减弱，地上部分枯黄，夜间低温有利于生长开花，在高海拔山区生长良好。　　在播种时，要施足底肥，生长期喜潮润的土壤，要适时浇水。浇水应掌握“见干见湿”的原则，刚栽植时，控制浇水，以促进根系生长，现蕾后充足供水，保持土壤湿润。　　在开花前应施稀薄液肥1－2次，现蕾后每间隔3天叶面喷施1次0.1％磷酸二氢钾液，进行催花。开虞美人花后及时剪去凋萎花朵，使余花开得更好。', '　　　　虞美人一般要头年秋季播种，经过露地　　3月初，待地刚一解冻时，选择一块土质疏松肥沃，背风向阳之地。略加整理，做成几个大小不拘的畦。浇一次透水，并把畦面整平。待水渗入土中后，把虞美人的种子按照每份加上二十份细砂土的比例混合在一起，然后将此混合物均匀地撒在畦里。在播种后不用镇压或盖土。　　用一块无色塑料薄膜下面撑几根竹杆加以保湿、挡风，好来保护小苗长出。待虞美人的小苗高约2厘米时，逐渐撤去无色塑料薄膜。当虞美人的小苗高约6厘米时，保持10厘米左右的株行距进行间苗。以后见干浇水，从4月上旬至5月上旬间，虞美人的　　在播种时，要施足底肥，生长期喜潮润的土壤，要适时浇水。浇水应掌握“见干见湿”的原则，刚栽植时，控制浇水，以促进根系生长，现蕾后充足供水，保持土壤湿润。在开花前应施稀薄液肥1－2次，现蕾后每间隔3天叶面喷施1次0。1％磷酸二氢钾液，进行催花。开花后及时剪去凋萎花朵，使余花开得更好。5月中旬，相当数量的虞美人已经开放出了绚丽的花朵。不久，这些地栽的虞美人远望就像一块缀着鲜花的绿色地毯那样美丽动人了。', 'http://img.boqiicdn.com/Data/BK/P/imagick7211442224811.jpg', 'http://www.boqii.com/entry/detail/2036.html', '');
INSERT INTO `plant_family` VALUES ('217', '麝香百合', 'Lilium longiflorum Thumb.', '麝香百合', '白百合，夜合，铁炮百合，龙牙百合', '不容易死', '', 'http://www.boqii.com/entry/photo/2281/0,http://www.boqii.com/entry/photo/2281/5244', '植物　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '百合属', '麝香百合', 'Lilium longiflorum Thumb.', '', '　　 　　麝香百合鳞茎球形或近球形，高2.5－5厘米；鳞片白色。茎高45－90厘米，绿色，基部为淡红色。叶散生，披针形或矩圆状披针形，长8－15厘米，宽1－1.8厘米，先端渐尖，全缘，两面无毛。', '　　麝香)大而洁白，非常适合用于布置或做材料，现在在欧美，也是复活节非常重要的盆花。人工栽种摄像百科的难度并不高，小编就为你介绍一下麝香百合的栽种要点。　　麝香百合宜选用腐叶土、沙土、园土混合调制的培养土，并放置蹄片作基肥，土壤ph值5.5至6较宜。从春季萌芽出土开始，到开花初期，每隔15天施一次稀薄饼肥水，使鳞茎充实，花繁叶茂，花期内可施磷钾肥1次至2次，盆土需每年换一次。　　麝香百合喜充足的散射光线，忌过强的直射阳光，在生长期应注意转动盆向，以免株形偏长畸形发展，过于荫蔽则生长衰弱不能开花。浇水以保持盆土略湿润为好，如盆土过湿再加通风不良，易使鳞茎，可向植株周围喷水，保持较高的空气湿度，湿度不足，又是不能生长良好的原因之一。生长适温为15℃至18℃，出现小花蕾后，白天保持25℃至28℃，昼夜温差要求在10℃以内。花后要及时摘去残花，施以腐熟的磷钾肥，加强培养，保持盆土微潮至秋季换盆。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick50021449048202.jpg', 'http://www.boqii.com/entry/detail/2281.html', '');
INSERT INTO `plant_family` VALUES ('218', '康乃馨', 'Dianthus caryophyllus', '香石竹', '康乃馨、狮头石竹、麝香石竹、大花石竹、麝香石竹、荷兰石竹', '不容易死', '南欧、地中海北岸、法国到希腊', 'http://www.boqii.com/entry/photo/1930/0,http://www.boqii.com/entry/photo/1930/5600', '', '', '', '', '', '', '', '', '', '　　康乃馨是我们日常生活中非常常见的观花 　　康乃馨主要分布于欧洲温带以及中国大陆的福建、湖北等地，原产于地中海地区。康乃馨是肯尼亚的主要出口　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　康乃馨又名香石竹，由于康乃馨花期比较长，并且花香清淡，花色艳丽，所以现在被世界各国广为栽培，也是世界上非常重要的切花品种。很多花友会选择自己在家盆栽康乃馨，那么需要注意哪些问题呢？　　1、光照条件。康乃馨属中日照，喜阳光充足。除育苗期和盛花期外，无须担心强光为害，且借助辅助光可增加花冠直径和花色鲜艳度。光强与单位面积切花产量有明显的正相关性。　　2、条件。康乃馨喜凉爽，不耐炎热，可忍受一定程度的低温。若夏季气温高于35℃，冬季低于9℃，均十分缓慢甚至停止。在夏季高温时期，应采取相应降温措施，冬季则需盖塑料薄膜或进入温室，以保持适当的温度。　　3、水分条件。康乃馨根系为须根系，土壤或介质长期积水或湿度过高、叶片表面长期高温，均不利于其正常生长。因此提倡滴灌，另外还应注意水质及水分含量的问题。　　4、土壤条件。康乃馨喜保肥、通气和排水性能良好的土壤，其中以重壤土为好。适宜其生长的土壤pH值是5.6－－6.4。从一些土壤分析实验表明，pH值在5.95－7.9范围内，土壤有机质含量对开花无明显影响，主要决定于土壤质地。', '　　康乃馨繁殖也分为无性繁殖和有性繁殖两种，但是由于康乃馨的结籽率比较低，所以在康乃馨的生产上应用的比较少。而扦插繁殖的性状稳定，并且成活率较高，所以被广泛应用在康乃馨的繁殖生产上。　　\n一、采穗母本园的建立\n　　实践证明，采穗母株必须具备的条件是：植株相对年龄年轻，开花性状好，发病指数为零，取穗部位应严格控制在第6个节位以上。因此，建立专一的采穗母本园是非常必要而关键的，而且也是现代康乃馨种苗生产过程中一个不可缺少的环节。它既是形成优质种苗的前提，又是全年规模性育苗的基础。　　采穗母本园的母株必须是组织　\n　二、扦插技术\n　　1、插穗的选择。选择无病虫害、　　2、扦插时间。一般应避开炎热夏季7－－8月份，要求插穗质量好，采用颗粒较大的珍珠岩作为扦插母质，　　3、插穗时的采取与扦插。插穗的采取一般与对康乃馨的疏芽同时进行。采插穗应按标准进行，采穗时用手掰芽而不用剪刀剪，以免病毒交叉感染。基部要略带主干皮层，但不损伤母枝，保留插穗顶端叶片4－－5片，基余均摘除。整理成束后，浸入清水30分钟，使插穗吸足水。其切面要紧贴节间，并用生长调节剂　　4、插穗的储藏。储藏插穗可为全年育苗和全年均衡供花提供极大的方便，而且可以一次性进行批量作业，节省人力物力。储藏要求：温度1－－2℃，且变幅越小越好，最好在±1℃以内；储藏前稍作失水处理；插穗应用超薄塑料膜包装。　　5、扦插管理。插床应有间歇喷雾设施，喷雾量控制在使叶片刚好湿润。若无喷雾措施，需盖塑料薄膜，1周后改用苇帘，但不要遮光太多，以防徒长。当扦插苗根长1厘米时进行移栽，注意少伤根。', 'http://img.boqiicdn.com/Data/BK/P/imagick9591439286120.jpg', 'http://www.boqii.com/entry/detail/1930.html', '');
INSERT INTO `plant_family` VALUES ('219', '非洲凤仙', 'Zanzibar Balsamico', '非洲凤仙', '苏丹凤仙花、玻璃翠、沃勒凤仙、何氏凤仙花、苏氏凤仙花', '不容易死', '原产东非洲，现在世界各地常广泛引种栽培', 'http://www.boqii.com/entry/photo/2199/0,http://www.boqii.com/entry/photo/2199/5328', '', '', '', '', '', '', '', '', '', '　　 　　非洲凤仙为多年生肉质草本，草本高30－70厘米。茎直立，绿色或淡红色，不分枝或分枝，无毛或稀在枝端被柔毛。叶互生或上部螺旋状排列，具柄，叶片宽椭圆形或卵形至长圆状椭圆形，长4－12厘米，宽2.5－5.5厘米，顶端尖或渐尖，有时突尖，基部楔形，稀多少圆形，狭成长1.5－6厘米的叶柄，沿叶柄具1－2、稀数个具柄腺体，边缘具圆齿状小齿，齿端具小尖，侧脉5－8对，两面无毛。　　　　植物界　　　　　　　　苏丹凤仙花　　　　　', '　　的别名有很多，现在非洲凤仙在室内观赏装饰中的作用非常多，并且在国际上的知名度也很高。很多花友对于非洲凤仙都非常喜爱，也有一些国家已经将非洲凤仙引种栽培。　　非洲风仙的茎含水分较多，非常脆弱而易折断，所以在小苗时要精心，一定要把握好盆土的浇水量，不能缺水，应给予充分的水分，又不能过湿，以免烂根，但在花期更应避免浇大水，而造成烂根。为避免徒长，在只需适当追施少量稀薄液肥，并以磷、钾肥为主，忌施氮肥。夏季为避免高温，应放置于阴栩下的通风处，防止烈日暴晒，并要加大浇水量。', '　　　　室内栽培时，全年均可播种，非洲凤仙种子　　非洲凤仙的繁殖主要用播种和扦插繁殖的方式。播种全年均可，多于4月进行，播种时不覆土，其发芽适温为22一24℃，播种后8一12天即可出苗。扦插亦可随时进行，选取生长强健的枝条，剪取约10cm长的顶端部分，插于沙中，约20天左右生根。　　非洲风仙具有较强分枝能力，因此，盆栽植株要及时修剪整形，促使萌发新的分枝，使株形丰满，开花繁茂。一般在小苗10cm左右高时，留2一3个节将尖掐掉，这样，每个株就能分生出3一5个枝条，10周后即可形成冠幅直径为30一50cm的成品。值得注意的是，每次整形修剪后都应该，立即喷洒杀菌剂，以保证伤口不受病菌污染。', 'http://img.boqiicdn.com/Data/BK/P/imagick33541447060787.jpg', 'http://www.boqii.com/entry/detail/2199.html', '');
INSERT INTO `plant_family` VALUES ('220', '西瓜皮椒草', 'Peperomia argyreia （Miq.） E. Morr.', '西瓜皮椒草', '', '不容易死', '原产巴西，现作为观赏植物广泛分布于世界各地', 'http://www.boqii.com/entry/photo/2323/0,http://www.boqii.com/entry/photo/2323/5199', '', '', '', '', '', '', '', '', '', '　　 　　西瓜皮椒草（Peperomia argyreia），簇生型植株，短茎上丛生西瓜皮状盾形叶。株高约15～20厘米。叶卵形，长3～5cm，宽2～4cm。叶柄红褐色，长10～15cm。叶脉由中央向四周呈辐射状；主脉11条，浓绿色，脉间银灰色，如同西瓜皮状。茎短，具暗红色的叶柄。叶密集，肉质，盾形或宽卵形，长2～5厘米，叶面绿色，叶背为红色。叶脉绿色，叶面间以银白色的规则色带，形似西瓜的　　　　　　　　　　　　　　　　　　　　　', '　　西瓜皮椒草的植株娇小可爱，并且由于西瓜皮椒草的叶色奇特，所以非常适合制作成盆栽放在室内栽培。西瓜皮椒草的栽培难度并不高，是非常适合新手栽培的。　　西瓜皮椒草性喜温暖、湿润、半阴及空气湿度较大的环境。生长适温为19～29℃，超过30℃和低于16℃则生长缓慢。耐寒力差，冬季最低不宜低于13℃，否则易受冻害。　　盆栽宜选用疏松、排水透气良好的材料作基质。生长季节保持盆土湿润，但盆内不能积水，否则易烂根落叶，甚至整株死亡。平时摆放在半阴处培养，避免强光直射，尤其夏季更应注意遮阳，春、秋季节可适当增加些光照。生长期间每月施1～2次稀薄饼肥水或复合肥液。若施肥过多，尤其是氮肥过多易造成斑纹不显着，观赏效果。气候干燥时和夏季宜每天向叶面上喷清水1～2次，并向花盆周围地面上洒水，以维持较高的空气湿度，促使叶片斑纹的形成。最好在春、秋季节将盆花移至室外，放在通风良好而又略见阳光处养护一段再搬回室内观赏，这样植株生长健壮，叶片上斑纹明显，观赏价值高。', '　　　\n　一、分株繁殖\n　　可于春秋两季进行，挑选母株根基处发有新芽的植株，结合翻盆换土取出植株，抖去附着的土，用利刀根据新芽的位置，切取新芽盆栽。分株时，注意保护好母株和新芽的根系。也可在植株长满盆时，将植株倒出分成数盆栽植。　\n　二、扦插繁殖：\n　　1、枝插可在春夏季进行，选取健壮的枝条，剪取5～8厘米的接穗，去除下部叶片，晾干剪口，然后插入湿润沙床中。在半阴下，保持18～25℃的　　2、叶插多在5～10月进行。叶插时选择健壮充实的叶片，将带有叶柄的充实叶片全部摘下，带2－3厘米的叶柄，晾干2～3小时待伤口稍干后，斜插于沙床或盆中，叶柄与苗床的角度为35度～45度，基质用洗净的河砂配上20％～30％的', 'http://img.boqiicdn.com/Data/BK/P/imagick71401450171081.jpg', 'http://www.boqii.com/entry/detail/2323.html', '');
INSERT INTO `plant_family` VALUES ('221', '鸾凤玉', 'Astrophytum myriostigma', '鸾凤玉', '', '不容易死', '原产地墨西哥北部和中部高山地区', 'http://www.boqii.com/entry/photo/2292/0,http://www.boqii.com/entry/photo/2292/5232', '　', '', '', '', '仙人掌科', '', '', '', 'Astrophytum myriostigma', '　　 　　鸾凤玉的植株球形，老株变为细长筒状。球体直径10～20厘米，有3～9条明显的棱，多数为5棱。棱上的刺座无刺，但有褐色绵毛。球体灰白色密被白色星状毛或小鳞片。花朵着生在球体顶部的刺座上，漏斗形，黄色或有红心。三棱的“三角鸾凤玉”较稀有名贵，四棱的“四角鸾凤玉”也称四方玉，四条阔棱均匀对称，也很有趣。', '　　的外形比较特殊，其植株单生，初呈球状，长大后为柱状。有三角状棱，也有四棱的，非常漂亮。鸾凤玉原产于墨西哥，对于栽种环境的要求不高，小编就为你介绍一下鸾凤玉的栽培要点，喜欢的朋友可以一起了解。　　鸾凤玉是同一种植物种子等植物学状及都极为相似，只是鸾凤玉相互抱合形成一个扁球形或圆球形的球茎。成熟时，成为主要部分，而细叶及叶柄往往是在植株较嫩的时候才茴香肥厚的叶鞘部鲜嫩质脆。　　一般鸾凤玉是一种很受定植后90天部分单球重达到。发芽期从种子吸水、萌动到发芽需幼苗期幼苗第一片真叶展开到第五至六片真叶。叶丛期从第五片真叶开始到叶鞘肥结实，整个生殖生长期约需。冷鸾凤玉凉的气候条件，但适应性广泛，耐寒、耐热力均强，种子发芽的适宜为，生长适温，超过。茴香喜冷凉气候，过高或过低都将影响生长和品质。苗期能耐。整个过程尤其在苗期及叶鞘，要空气相对湿度和湿润的土壤旱。　　鸾凤玉属植物，全过程都需要充足可促进花芽形成，在通过春化阶段后在长日照高温条件下开花结实。鸾凤玉，顶端残留有突起的，有时有细小的果梗。分果圆形，背面有纵棱，接合面较宽。背面茴香气，味微甜、辛。果圆形。茴香温和气候条件下生，鸾凤玉耐寒耐热力均较强苗期对要求，有利于壮苗的形成。鸾凤玉对土壤要求不严格，范围内均能正常生长。　　栽培上为保证产品的质量和产量，宜选择保肥、保水力强的肥沃壤土种植。圆球形类型株高无大差异，但形更紧实，略淡。外形似拳头，鞘短缩明显，抱合紧，不仅左右两侧膨大，前后也有明显的膨大，但外层叶鞘常常紧贴地面。如遇低温高湿天气极易。育苗期正处于气候炎热的，应选择四面通风，排水条件好，灌水方便的场地，做好防雨降温。土中，拌匀，靶平；然后开沟将种子均匀的撒进沟内，然后覆土浇水。出苗后进行间苗，间隔2～3厘米留1株无病的健壮苗，苗期应小水勤浇，保持土壤见干见湿，定植前浇1次透水，切方，囤苗。时定植。', '　　鸾凤玉为仙人掌科星球属植物，原产于墨西哥中部，喜欢温热、昼夜　　\n一、播种繁殖\n　　种子易发芽，在25℃左右的条件下5天左右即可发芽。实生苗根系发达，但成球慢，经3－4年才能开花。可通过　\n　二、扦插繁殖\n　　除盛夏酷暑多湿期外，全年均可操作，很容易成活，而以春秋季节最为适合。一般在盛花期后，结合整形修剪，选取当年生健壮枝条作插穗一节叶片去掉，插入素沙、等松散的质中。保温保湿，疏荫，即可生根，及时分栽，鸾凤玉翌年即可开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick38001449479621.jpg', 'http://www.boqii.com/entry/detail/2292.html', '');
INSERT INTO `plant_family` VALUES ('222', '彩叶草', 'Coleus scutellarioides', '彩叶草', '五彩苏、老来少、五色草、锦紫苏', '不容易死', '原产于亚太热带地区，印度尼西亚爪哇。现在世界各国广泛栽培', 'http://www.boqii.com/entry/photo/2188/0,http://www.boqii.com/entry/photo/2188/5341', '', '', '', '', '', '', '', '', '', '　　 　　彩叶草为多年生草本植物，老株可长成亚灌木状，但株形难看，观赏价值低 ，故多作一、二年生栽培。株高50～80cm，栽培苗多控制在30cm以下。全株有毛，茎为四棱，基部木质化。单叶对生，卵圆形，先端长渐尖，缘具钝齿牙，叶可长15cm，叶面绿色，有淡黄、桃红、朱红、紫等色彩鲜艳的　　　　　　　　　　　　　　　　　　　', '　　彩叶草喜欢阳光充足的环境，如果光线不充足的话，彩叶草的叶片颜色就会没有预想的那么漂亮。人工栽培彩叶草的难度并不高，繁殖成活率也较高，小编就为你介绍一下彩叶草盆栽的方法与。　　彩叶草于8－9月开花。彩叶草开花前，先要选择色彩鲜艳的植株留种；开花时，应对花序用毛笔沾花粉刷柱头的形式进行人工授粉，然后套纸袋隔离，以防杂交退化。在开花前期，应施用一些磷钾肥，保证结实时的。　　彩叶草盆栽要求富含腐殖质、疏松肥沃、排水透气性能良好的沙质培养土。对水分的需求，应保持盆土及环境经常湿润适度，忌干旱、防积涝，以免叶片脱水失色，根系软腐。光照柔和充足，叶色艳丽显着，但忌盛夏晴空烈日强光直射致叶面粗糙失去光泽度。而在蔽荫环境条件，叶色也不鲜艳。　　彩叶草盆栽以小型为好，一般成苗上内径10厘米筒盆，经20天至30天养护，彩叶草植株高达15厘米即可摆放观赏，室内放置应选南窗口漫射光线较强处，保持盆土干湿适度，空气清新，环境清洁。室外养护，入夏应放疏荫环境。　　彩叶草的日常比较简单，只需注意及时摘心，促发新枝，形成丰满的球形，养成株丛。花序生成即应除去，以免影响叶片观赏效果。　　彩叶草是优良的盆栽观叶花卉，也可应用于节的花坛，色彩鲜艳，非常美丽。同时可以剪取枝叶做切花，或花篮的配料，亦可与鸭跖草同栽一盆，为布置客厅、书房的好材料。', '　　彩叶草的叶片非常漂亮，所以又有人称其为老来变，彩叶草的叶色鲜艳，　\n　一、播种\n　　彩叶草播种育苗可产生叶色富有变化的植株。在条件适宜一年四季可随时播种，华南露地常于3－－4月播种，北方温室多在2－3月播种。北方春播在温室播种，用疏松的床土播种，将床土过细筛，装人播种床或育苗盘，稍压实刮平，用喷壶浇足底水，每平方米播种子约20克，与细沙混匀后撒播，搜细土后地温控制在20℃左右，种子10－15天出苗。出苗后　　\n二、扦插\n　　彩叶草易发生不定根，有一些品种结实性很差，只能采用扦插繁殖方法育苗。扦插育苗四季均可进行，以春、秋两季为好。剪取枝条上部5一7厘米作插穗，剪去叶片。插人', 'http://img.boqiicdn.com/Data/BK/P/imagick50731446715226.jpg', 'http://www.boqii.com/entry/detail/2188.html', '');
INSERT INTO `plant_family` VALUES ('223', '绒针', '', '绒针', '银箭', '不容易死', '', 'http://www.boqii.com/entry/photo/2389/0,http://www.boqii.com/entry/photo/2389/5027', '　', '被子植物门', '双子叶植物纲', '', '景天科', '青锁龙属', '绒针', '', '', '　　 　　绒针的植株不太大有矮小的细茎，随着', '　　温暖干燥的环境，耐半荫，但长期没有充足的光照会引起徒长的情况。绒针是非常容易群生的多肉植物，如果养的好的话，是非常漂亮的。　　绒针比较喜欢日照，日常为绿色，日照增加及增大后会慢慢变色。可以全日照，喜欢干燥温暖的生长环境。对水分需求不多，过多的水分容易滋害及涝死。夏季高温有短暂休眠，注意减少浇水，冬季可以持续生长。　新疆之外可以全日照，新疆地区夏季需遮阳。　　每月浇水两次。过多的水分容易滋生病害及涝死。夏季高温时休眠，更要注意减少浇水，冬季可以持续生长。　　一般可用泥炭、蛭石和珍珠岩的混合土，也可用泥炭和粗沙的混合土；生长期浇水一般干透浇透，冬季保持盆土干燥，生长期施肥一般每2月一次。', '　　　　绒针是非常容易群生的', 'http://img.boqiicdn.com/Data/BK/P/imagick64871451983146.jpg', 'http://www.boqii.com/entry/detail/2389.html', '');
INSERT INTO `plant_family` VALUES ('224', '天人菊', 'Gaillardia Pulchella Foug.', '天人菊', '虎皮菊、老虎皮菊', '不容易死', '原产北美，中国中、南部广为栽培', 'http://www.boqii.com/entry/photo/2179/0,http://www.boqii.com/entry/photo/2179/5349', '　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '天人菊属', '天人菊', 'Gaillardia Pulchella Foug.', 'Gaillardia Pulchella', '　　 　　天人菊为一年生草本，高20－60厘米。茎中部以上多分枝，分枝斜升，被短柔毛或锈色毛。下部叶匙形或倒披针形，长5－10厘米，宽1－2厘米，边缘波状钝齿、浅裂至琴状分裂，先端急尖，近无柄，上部叶长椭圆形，倒披针形或匙形，长3－9厘米，全缘或上部有疏锯齿或中部以上3浅裂，基部无柄或心形半抱茎，叶两面被伏毛。头状花序径5厘米。总苞片披针形，长1.5厘米，边缘有长缘毛，背面有腺点，基部密被长柔毛。舌状花黄色，基部带紫色，舌片宽楔形，长1厘米，顶端2－3裂；管状花裂片三角形，顶端渐尖成芒状，被节毛。瘦果长2毫米，基部被长柔毛。冠毛长5毫米。花果期6－8月。', '　　的适应能力比较强，生性强韧，常被用作防风定砂植物。天人菊在酸性土壤中不但难获壮苗，在盛夏时还会枯萎，所以栽培天人菊的配土还需注意选用适合天人菊的。　　　较高的空气湿度，空气湿度过低，会加快单花凋谢。也怕雨淋，晚上需要保持叶片干燥。最适空气相对湿度为65～75％。　　　耐热，不耐霜寒。　　　喜阳光充足，略耐半荫。　　　天人菊与其它草花一样，对肥水要求较多，但要求遵循“淡肥勤施、量少次多、营养齐全”的施肥（水）原则，并且在施肥过后，晚上要保持叶片和花朵干燥。　　　是天人菊的生长旺季，肥水管理按照“花宝”——“花宝”——清水——“花宝”——“花宝”——清水的顺序循环（最起码每周要保证两次“花宝”）。进入开花期后适当控肥，以利种子成熟。', '　　天人菊性喜高温、干燥和阳光充足的环境，适应能力较强，但是不耐酸性土壤。天人菊是良好的防风定砂植物，通常作为一年生草本植物栽种，花期为7－10月，人工繁殖可以用播种及扦插的方法。　　\n一、播种繁殖\n　　常在夏季进行播种，对播种用的基质进行　\n　二、扦插繁殖\n　　用来扦插的枝条称为插穗。通常结合摘心工作，把摘下来的粗壮、无病虫害的顶梢作为插穗，直接用顶梢扦插。扦插后应注意以下管理：温度：插穗生根的最适温度为18℃～25℃，低于18℃，插穗生根困难、缓慢；高于25℃，插穗的剪口容易受到病菌侵染而', 'http://img.boqiicdn.com/Data/BK/P/imagick70211446543088.jpg', 'http://www.boqii.com/entry/detail/2179.html', '');
INSERT INTO `plant_family` VALUES ('225', '鼠尾掌', 'Salvia officinalis', '鼠尾掌', '药用鼠尾草、撒尔维亚', '不容易死', '墨西哥及中美洲', 'http://www.boqii.com/entry/photo/2399/0,http://www.boqii.com/entry/photo/2399/5016', '　　', '', '', '', '仙人掌科', '鼠尾掌属', '', 'Salvia officinalis', '', '　　 　　鼠尾掌变态茎细长、匍匐，通常扭状下垂，在原产地可长达2米，一般栽培20—30厘米，具气生根。幼茎绿色，以后变灰，径1.5—2厘米，无叶，具10—14棱，隔0.5厘米着生15—20枚短刺丛，初生略带红色，以后变至黄褐色，因其外形酷似', '　　的观赏价值比较高，但是如果不注意栽培的话，鼠尾掌的观赏价值就会大大降低。由于鼠尾掌原产于墨西哥高山荒漠地带，所以想要你的鼠尾掌能够长得更漂亮就需要注意为其布置一个合适的环境。　　鼠尾掌原产墨西哥高山荒漠地带，性喜温暖且昼夜温差大，夏季湿润而冬季干燥，光照强而短的环境条件。要求排水良好，忌雨涝。在华南亚热带地区可以露地栽培，其他地区只能盆栽并在室内越冬。盆土用腐叶土、砂土及壤土等量配制，并掺入少量麻酱渣、骨粉作基肥。在室外莳养要置于光线充足而又避雨之处；在室内莳养，夏季要保持一定湿度，切忌长期干燥，以防变态茎枯黄。冬季须相对干燥，控制浇水。浇水须注意干透浇透，不可使土壤过湿，以免烂根。尤其在花蕾出现后更应节水，避免落蕾落花。生长期间10—15天施一次液肥，促使生长繁茂，花大色艳。盆栽一般在霜降前入室，室温应不低于10℃；出室以清明过后为宜。鼠尾掌易受红蜘蛛的，被害部位呈黄褐色，影响观赏效果。因此夏季要特别注意通风，最好放到室外莳养，酷暑盛夏须适当遮荫降温进行。', '　　　\n　1、扦插，\n　\n　2、嫁接，\n', 'http://img.boqiicdn.com/Data/BK/P/imagick23161452155199.jpg', 'http://www.boqii.com/entry/detail/2399.html', '');
INSERT INTO `plant_family` VALUES ('226', '非洲菊', 'Gerbera jamesonii Bolus', '非洲菊', '扶郎花，灯盏花，秋英，波斯花，千日菊，太阳花、猩猩菊、日头花', '不容易死', '主产地南非，我国分布在华南、华东、华中等地区', 'http://www.boqii.com/entry/photo/2216/0,http://www.boqii.com/entry/photo/2216/5311', '', '', '', '', '', '', '', '', '', '　　非洲菊为菊科多年生草本 　　非洲菊为多年生、被毛草本。根状茎短，为残存的叶柄所围裹，具较粗的须根。花葶单生，或稀有数个丛生，长25－60cm，无苞叶，被毛，毛于顶部最稠密，头状花序单生于花葶之顶，于花期舌瓣展开时直径6－10厘米；总苞钟形，约与两性花等长，直径可达2cm；总苞片2层，外层线形或钻形，顶端尖，长8－10mm，宽约1－1.5mm，背面被柔毛，内层长圆状披针形，顶端尾尖，长10－14mm，宽约2mm，边缘干膜质，背脊上被疏柔毛；花托扁平，裸露，蜂窝状，直径6－8mm；外围雌花2层，外层花冠舌状，舌片淡红色至紫红色，或白色及黄色，长圆形，长2.5－3.5cm，宽2－4mm，顶端具3齿，内2裂丝状，卷曲，长4－5mm，花冠管短，长约为舌片的1／8，退化雄蕊丝状，长3－4mm，伸出于花冠管之外；内层雌花比两性花纤细，管状二唇形，长6－7mm，二唇等长，外唇具3细齿或有时为2齿和1裂片，内唇2深裂，裂片线形，长约4mm，卷曲，退化雄蕊4－5枚，线形或丝状，藏于花冠管内；中央两性花多数，管状二唇形，长8－9mm，外唇大，具3齿，内唇2深裂，裂片通常宽，卷曲；花药长约4mm，具长尖的尾部；雌花和两性花的花柱分枝均短，顶端钝，长不足1mm。　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　非洲菊是我们常见的花卉品种，由于非洲菊的栽培难度不高，并且颜色繁多，色彩鲜艳，成为了现在主要的切花品种之一。现在，非洲菊在家居布置中也非常常见，那么人工栽培非洲菊应该注意哪些问题呢？　　1、要求。应用栽培设施，尽量满足非洲菊苗期、期和开花期对温度的要求，以利正常生长和开花。我国华南地区外均不能露地，需进行温室栽培，长江流域以外可用不加温的大棚栽培。在夏季，棚顶需覆盖遮荫网，并掀开大棚两侧塑料薄膜降温。冬季外界夜温接近0C时，封紧塑料薄膜降，棚内一定需增盖塑料薄膜。遇晴暖天气，中午揭开大棚南端薄膜通风约一小时。　　2、光照要求。非洲菊为喜光花卉，冬季需全光照，但夏季应注意适当遮荫，并加强通风，以降低温度，防止高温引起休眠。　　3、灌水要求。定植后苗期应保持适当湿润并蹲苗，促进根系，迅速成苗。生长旺盛应保持期应保持供水充足，夏季每3－4天浇一次，冬季约半个月一次。花期灌水要注意不要使叶丛中心沾水，防止花芽腐烂。露地栽培要注意防涝。另外，灌水时可结合施肥。　　4、追肥要求。非洲菊为喜肥，对肥料需求大，施肥氮、磷、钾的比例为15：18：25。追肥时应特别注意补充钾肥。一般每亩施销酸钾2.5公斤，硝酸铵或磷酸铵1.2公斤，春秋季每5－6天一次，冬夏季每10天一次。若高温或偏低温引起植株半休眠状态，则停止施肥。', '　　由于　　1、分株：　　2、扦插：这个操作不便，总结起来就是砍头，然后用发的大量侧芽扦插，我没有尝试过，也不推荐大家使用。　　3、种子：用进口的为好。菊科', 'http://img.boqiicdn.com/Data/BK/P/imagick73001447322923.jpg', 'http://www.boqii.com/entry/detail/2216.html', '');
INSERT INTO `plant_family` VALUES ('227', '花叶万年青', 'Dieffenbachia picta Lodd.', '花叶万年青', '黛粉叶', '不容易死', '', 'http://www.boqii.com/entry/photo/2203/0,http://www.boqii.com/entry/photo/2203/5324', '', '', '', '', '', '', '', '', '', '　　 　　花叶万年青茎高1米，粗1.5－2.5厘米，节间长2－4厘米；下部的叶柄具长鞘，中部的叶柄达中部具鞘，上部叶柄长，鞘几达顶端，有宽槽；叶片长圆形、长圆状椭圆形或长圆状披针形，长15－30厘米，宽7－12厘米，基部圆形或锐尖，先端稍狭具锐尖头，二面暗绿色，发亮，脉间有许多大小不同的长圆形或线状长圆形斑块，斑块白色或黄绿色，不整齐；1级侧脉15－20对，上举，II级侧脉较纤细，背面隆起。花序柄短。佛焰苞长圆披针形，狭长，骤尖。肉穗花序：下部雌花序达中部；不育中性花序占全长1／3，花星散；子房心皮2或3，柱头近分离。浆果橙黄绿色，2－3室。　　　　　被子植物门　　　　　　　　　　　', '　　约有30种原生种，现在在全世界被广泛栽培，栽培品种也越来越多，已经成为了非常理想的室内绿化装饰的观叶植物。花叶万年青的栽培难度并不高，一般条件下，花叶万年青都能长期存活。　　　花叶万年青的适温为25～30℃，白天温度在30℃，晚间温度在25℃效果好。可生长范围，在2月至9月为18－30℃，9月至翌年2月为13～18℃。由于它很不耐寒，10月中旬就要移入温室内。如果冬季温度低于10℃，叶片易受冻害。特别是冬季温度低于10℃时，如果浇水过多，还会引起落叶和茎顶溃烂。如果低温引起植株落叶，茎部未烂时，则待温度回升后，仍能长出新叶。　　　花叶万年青喜湿怕干，盆土要保持湿润，在生长期应充分浇水，并花叶万年青向周围喷水，向植株喷雾。如久不喷水，则叶面粗糙，失去光泽。夏季保持空气湿度60％～70％，冬季在40％左右。土壤湿度以干湿有序最宜，夏季应多浇水，冬季需控制浇水，否则盆土过湿，根部易腐烂，叶片变黄枯萎。放在室内观赏的，要常用软布擦洗叶面，保持叶片，使之亮艳生辉。　　　花叶万年青耐阴怕晒。光线过强，叶面变得粗糙，叶缘和叶尖易枯焦，甚至大面积灼伤。光线过弱，会使黄白色斑块的颜色变绿或褪色，以明亮的散射光下生长最好，叶色鲜明更美。日照约40％～60％生育最理想。春秋除早晚可见阳光外，中午前后及夏季都要遮荫。绿叶多的品种较耐阴耐寒，因此乳白愈多的品种，愈缺乏叶绿素，应特别注意光线要明亮些，低温时特别注意保温。　　　花叶万年青的栽培土壤以肥沃、疏松和排水良好、富含有机质的壤土为宜。盆栽土壤用腐叶土和粗沙等的混合土壤，如何用腐叶土2份，锯末或泥炭1份，砂1份混合。盆栽常用15～20厘米盆。盆栽植株生长1～2年后，基部的萌蘖较多，可结合换盆进行分株繁殖。如植株生长较高，可留基部2～3节剪除地上部，留下的茎节仍可萌芽发枝，保持较好株形。　　　花叶万年青6～9月为生长旺盛期，10天施一次饼肥水，入秋后可增施2次磷钾肥。春至秋季间每1～2个月施用1次氮肥能促进叶色富光泽。室温低于15℃以下，则停止施肥。', '　　　\n　一、分株繁殖\n　　可利用基部的萌蘖进行分株繁殖，一般在春季结合换盆时进行。操作时将植株从盆内托出，将茎基部的根茎切断，涂以草木灰以防腐烂，或稍放半天，待切口干燥后再盆栽，浇透水，栽后浇水不宜过多。10天左右能恢复　\n　二、扦插繁殖\n　　以7～8月高温期扦插最好，剪取茎的顶端7～10厘米，切除部分叶片，减少水分蒸发，切口用草木灰或硫磺粉涂敷，插于沙床或用水苔包扎切口，保持较高的空气湿度，置半阴处，日照约50％～60％，在室温24～30℃下，插后15～25天生根，待茎段上萌发新芽后移栽上盆。也可将老基段截成具有3节的茎段，直插土中1／3或横埋土中诱导生根长芽。　　花叶万年青的汁液有毒，其英文名DUMBCANES意为哑蔗，指其茎有毒，误食会使舌头剧痛而无法发声，应加以注意。扦插操作时不要使汁液', 'http://img.boqiicdn.com/Data/BK/P/imagick84911447147926.jpg', 'http://www.boqii.com/entry/detail/2203.html', '');
INSERT INTO `plant_family` VALUES ('228', '勋章菊', 'Gazania rigens', '勋章菊', '勋章花、非洲太阳花', '不容易死', '原产于南非和莫桑比克', 'http://www.boqii.com/entry/photo/2393/0,http://www.boqii.com/entry/photo/2393/5022', '　', '被子植物门', '双子叶植物纲', '菊目', '菊科', '勋章菊属', '勋章菊', 'Gazania rigens', '', '　　 　　勋章菊为多年生宿根草本植物。具根茎。叶丛生，披针形或倒卵状披针形，全缘或有浅羽裂，叶背密被白绵毛。舌状花白、黄、橙红色有光泽。勋章菊株高15－40厘米，具根茎，叶丛生，叶披针形或线形，深绿色，丛生，长15厘米，全缘或有浅羽裂，一般背面有白色丝状柔毛，叶背密被白绵毛，有的', '　　的花形奇特，花色鲜艳多彩，其花心具有深色眼斑，整体看很像勋章，非常特别，现在常在园林中作为盆栽花卉或用来布置花坛。人工栽培勋章菊的难度并不高，但是需要根据其生长习性来进行环境控制。　　　采用10至16厘米的花盆栽培，用排水良好的介质栽培，介质的pH值为5.8至6.2，EC值在1.0至1.5，盆土保持干燥，每次待盆土干燥后再进行浇水。浇水宜上午进行，以利于叶面在夜间保持干燥，防止病害发生。水分过多会产生徒长，过干会提早开花，且在强光下易灼伤叶面。　　　勋章菊为强阳性花卉，需要在阳光充足的场所生长，花朵需要在阳光下才能开放，阴天花朵会闭合。如栽培场所光照不足，植株叶片柔软，花蕾减少，花朵变小，花色变淡。相反，阳光充足，花色鲜艳，开花不断。　　　移植上盆后，温度可下调至夜间为12℃至16℃，白天为16℃至22℃，当温度高于26℃时，植株易出现徒长，这时用矮壮素比久（B－9）喷施，会有一定效果。冬季温度不要低于5℃，但短能耐0℃低温，如时间长，易发生冻害。　　　勋章菊是一种抗性很强的花卉，只要阳光充足便能开花。耐干旱，耐高温，甚至耐盐碱，可以说是适合各种环境。勋章菊对水分比较敏感，茎叶生长期虽需土壤湿润，但梅雨季土壤水分过多，植株容易受涝造成全株。同时，夏季高温时，空气湿度不宜过高，盆土不宜积水，否则均对勋章菊生长和开花不利。花谢后要及时剪除败花，这样可减少营养消耗，促使形成更多花蕾。冬季放于室内栽培仍可继续开花。', '　　　\n　1、播种繁殖：\n　　\n2、分株繁殖：\n　\n　3、扦插繁殖：\n　\n　4、组培繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick52011451984995.jpg', 'http://www.boqii.com/entry/detail/2393.html', '');
INSERT INTO `plant_family` VALUES ('229', '地涌金莲', 'Musella lasiocarpa', '地涌金莲', '千瓣莲花、地金莲、不倒金钢', '不容易死', '原产中国云南西北部金沙江干热河谷', 'http://www.boqii.com/entry/photo/2392/0,http://www.boqii.com/entry/photo/2392/5024', '　　', '被子植物门', '单子叶植物纲', '目', '芭蕉科', '地涌金莲属', '地涌金莲', 'Musella lasiocarpa （Franch.） C. Y. Wu ex H. W. Li', 'Musella lasiocarpa', '　　 　　地涌金莲的植株丛生，具水平向根状茎。假茎矮小，高不及60厘米，基径约15厘米，基部有宿存的叶鞘。叶片长椭圆形，长达0.5米，宽约20厘米，先端锐尖，基部近圆形，两侧对称，有白粉。花序直立，直', '　　地涌金莲的花朵全身金黄形似莲花，故此命名。地涌金莲原产于我国云南，由于其生性喜爱温暖湿润的环境，所以多的南方，但由于地涌金莲受到很多花友的喜爱，很多在北方盆栽的朋友也可以种植了。　　地涌金莲喜温暖环境，不耐寒，寒冷地区宜在温室内栽培。需阳光充足，不耐阴，要求夏季湿润、冬春稍干燥的气候。宜在排水良好、肥沃、疏松和湿润的壤土中栽培。它的繁殖一般以分株为主，亦可用播种的方法繁殖。地涌金莲适应性强，耐寒耐旱，栽培简单，管理粗放。但在土壤疏松，排水良好，光照条件好，温暖湿润的环境条件中生长较好。冬季不低于－3℃时能正常，但严重霜冻时会造成地上部分的叶片焦枯而失去观赏价值。　　盆栽时盆土可用泥炭土55％、园土20％、河沙20％、有机复合肥5％配制，另加少量花生麸作基肥。生长浇水宜干湿相间，约每月施1～2次稀薄肥水。春、秋、冬三季摆放在向阳处，夏季和初秋中午前后日照强度大，藉注意适当遮荫。冬季温度控制在6℃以上，控制浇水，便可安全越冬。由于地涌金莲生长较快，故需每年春季换1次盆。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick37181451984798.jpg', 'http://www.boqii.com/entry/detail/2392.html', '');
INSERT INTO `plant_family` VALUES ('230', '八仙花', 'big leaf hydrangea', '八仙花', '绣球、粉团花、草绣球、紫绣球、紫阳花', '不容易死', '', 'http://www.boqii.com/entry/photo/2073/0,http://www.boqii.com/entry/photo/2073/5454', '植物　', '被子植物门', '双子叶植物纲', '()目', '虎耳草科', '八仙花属', '八仙花', 'Hydrangea macrophylla', '', '　　 　　八仙花为落叶灌木，小枝粗壮，皮孔明显。叶大而稍厚，对生，倒卵形，边缘有粗锯齿，叶面鲜绿色，叶背黄绿色，叶柄粗壮。花大型，由许多不孕花组成顶生伞房花序。花色多变，初时白色，渐转蓝色或粉红色。高1－4米；茎常于基部发出多数放射枝而形成一圆形灌丛；枝圆柱形，粗壮，无毛，具少数长形皮孔。叶纸质或近革质，近圆形或阔卵形，长1.4－2.4厘米，宽1－2.4厘米，粉红色、淡蓝色或白色；孕性花极少数，具2－4毫米长的花梗；萼筒倒圆锥状，长1.5－2毫米，与花梗疏被卷曲短柔毛，萼齿卵状三角形，长约1毫米；花瓣长圆形，长3－3.5毫米；雄蕊10枚，近等长，不突出或稍突出，花药长圆形，长约1毫米；子房大半下位，花柱3，结果时长约1.5毫米，柱头稍扩大，半环状。', '　　', '　　人工栽培　　八仙花繁殖易成活。繁殖可采用分株繁殖、压条繁殖、扞插繁殖和组培繁殖方法。　　分株繁殖在春季植株萌发前进行，将已生根的枝条与母株根据根势将其分开成数株，剪除老根和过长根，直接盆栽，浇透水，在半阴处　　压条繁殖适宜在春季植株未萌发前进行，选取1－2年生健壮枝条，在节下轻刻，造成局部创伤，剪去埋人地下部位的叶片，埋入土中，固定好枝条，进行保湿，30天左右开始生根，第二年春季与母株切断，带土移植。　　扦插繁殖宜在春、夏　　现代花丼生产中，八仙花组培繁殖技术应用广泛，采用诱导', 'http://img.boqiicdn.com/Data/BK/P/imagick48751443087982.jpg', 'http://www.boqii.com/entry/detail/2073.html', '');
INSERT INTO `plant_family` VALUES ('231', '黄花照波', 'Bergeranthus multiceps （SALM－DYCK） SCHWANT', '黄花照波', '仙女花', '不容易死', '原生地位于南非南部及纳米比亚等地区', 'http://www.boqii.com/entry/photo/2359/0,http://www.boqii.com/entry/photo/2359/5057', '　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '照波属', '黄花照波', 'Bergeranthus multiceps （SALM－DYCK） SCHWANT', '', '　　 　　黄花照波为多年生肉质植物，叶片肥厚多汁，清雅别致，夏季开出金黄色花朵。灼灼耀目，十分惹人喜爱。', '　　的叶片肥厚多汁，清雅别致，在夏季会开出金黄色花朵，非常耀眼夺目，受到很多多肉爱好者的喜爱。黄花照波喜爱太阳，但是忌长放在烈日下。　　黄花照波可放在窗前、阳台和其他散射光明亮处。冬夏休眠期应节水遮阳。春秋期交水水时要注重等盆土干透后再浇，浇则要将土浇透。黄花照波生长较快，栽培容易，细长的浓绿色叶3厘米左右，开黄色花。浇水也是以干湿交替进行，但要防止长期干旱与湿涝。　　黄花照波一年四季都可放在室外，冬天0度以上都能活，、栽培较易，生长较快，一个夏季可以长成满满一盆。去年由于上海的冬季较长，自己也懒得去打理它们，在零下5五度的环境度过，原本满满一大盆只有小小2株成活。可能经受严寒的考验，花朵巨大，花色更纯。　　黄花照波主要分布在南非和纳米比亚，对日照要求不是很大，散光下也可以存活，但是植株会相对难看，如果想多看花就要增加日照时间，黄花照波对水分需求不大，一定要严格困难灌水，番杏科植物很容易因为水分过多而涝死，在原生地环境下，几个月没有雨水，也没有。黄花照波一般下午或者傍晚开花。', '　　黄花照波为多年生肉质　　黄花照波以分株为主，从老株上剪下一棵插入土中，一段　　分株时先把母株从花盆中脱出来，抖掉外围泥土，用利刀或修枝剪把叶丛之间相连的地下茎断开，即可分成数株分开栽种了。分株繁殖的时间随　　方法是：先将泥团从盆中抠出，摔掉泥土，细心观察，按照根的自然伸展间隔，顺势从缝隙中用手分开或利刀切开，每株只能分2－3株，不宜过多，分开的根与枝的多少要相称得当，使整个植株保持平衡均匀。分开后加以修剪，并除去烂根，有条件的还宜在切口涂以木炭粉或硫磺粉消毒后，再行定植。', 'http://img.boqiicdn.com/Data/BK/P/imagick49721450947635.jpg', 'http://www.boqii.com/entry/detail/2359.html', '');
INSERT INTO `plant_family` VALUES ('232', '鹿角海棠', 'Astridia velutina', '鹿角海棠', '熏波菊', '不容易死', '原产非洲西南部', 'http://www.boqii.com/entry/photo/2022/0,http://www.boqii.com/entry/photo/2022/5505', '　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '鹿角海棠属', '鹿角海棠', 'Astridia velutina', '', '　　 　　鹿角海棠为多浆肉质灌木。林高25—35厘米，老枝灰褐色，分枝处有节间。叶粉绿色，交互对生，对生叶在基部合生。叶半月形，肉质，三棱状，长2.5～3.5厘米，宽0.3－0.4厘米，叶端稍狭。全株密被极细短茸毛。花顶生，具短梗，单出或数朵间生，花径3.5 －－4.5厘米，花白或粉红色。冬季开花。', '　　和别的多肉不同的是，鹿角海棠的休眠期并不明显，但是也在夏季，只要注意夏季的阴凉通风，鹿角海棠就能够度夏了。鹿角海棠群生的话会非常漂亮，但是速度不快，所以鹿角海棠是需要一定耐心的。　　鹿角海棠栽植宜选地势稍高不易积水、向阳的地方。土壤为中性偏碱，pH值不低于7。上质要求疏松，但不能过于肥沃，栽植穴应根据根系大小而确定，栽植深度以距地面10厘水为宜，最好带土团栽植，栽后浇足水。喷施新高脂膜，隔绝病虫害，提高存活率。　　鹿角海棠每年春季换盆，并整株修剪，加入肥沃的泥炭土或腐叶土和粗沙组成的混合土壤，稍加喷水即可。春季生长期以保持盆土不干燥为准，多在地面喷水，保持一定的空气湿度。夏季，鹿角海棠呈半休眠状态，可放半阴处，保持盆土不过分干燥。秋后，鹿角海棠开始继续生长，每半月施肥1次。临冬茎叶生长进入旺盛期，并开始开花。冬季室温保持在15－20℃时，开花不断。盆栽2－3年后，需重新扦插更新。　　鹿角海棠生长适温18－25度，冬季不低于10度；配土一般可用肥沃的泥炭土或腐叶土和粗沙组成的混合土壤；浇水一般春秋季生长期以保持盆土不干燥为准，多在地面喷水，保持一定的空气湿度，夏季放半阴处养护，保持盆土不过分干燥；生长期施肥一般每半月1次；繁殖方式常用播种和扦插繁殖，播种，4－5月采用室内盆播，播后10天左右发芽，幼苗根细而浅，需谨慎浇水，1个月后移苗，扦插以春、秋季进行为好，选取充实茎节，剪成8－10厘米，插于沙床，约15－20天可生根。', '　　　　\n1、扦插：\n　　\n2、播种：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick32671441877349.jpg', 'http://www.boqii.com/entry/detail/2022.html', '');
INSERT INTO `plant_family` VALUES ('233', '锦葵', 'Malva Sinensis  Cavan', '锦葵', '荆葵，钱葵，小钱花，金钱紫花葵，小白淑气花，淑气花，棋盘花', '不容易死', '', 'http://www.boqii.com/entry/photo/2386/0,http://www.boqii.com/entry/photo/2386/5030', '植物　　', '被子植物门', '双子叶植物纲', '锦葵目', '锦葵科', '锦葵属', '锦葵', 'Malva Sinensis  Cavan', '', '　　 　　锦葵分枝多，疏被粗毛。叶圆心形或肾形，具5－7圆齿状钝裂片，长5－12厘米，宽几相等，基部近心形至圆形，边缘具圆锯齿，两面均无毛或仅脉上疏被短糙伏毛；叶柄长4－8厘米，近无毛，但上面槽内被长硬毛；托叶偏斜，卵形，具锯齿，先端渐尖。', '　　为锦葵科、双子叶植物，是7月3日的生日花。由于锦葵有一定的观赏价值，并且还有一定的药用价值，现在常被栽种在中，养护锦葵需要注意以下五点，才能让锦葵开出漂亮的花朵。　　1、栽植：宜在清明前，选用PH值为5.5～6.5的营养土或腐叶土，盆栽后放置在半天有阳光这处，才能叶绿花繁，否则很难开花。　　2、施肥：因锦葵开花次数比较多，需要足够的营养。5月起进入生长期，施入氮磷结合的1～2次，6月起陆续开花一直到10月，每月应追施以磷为主的肥料1～2次，使花连开不断。　　3、浇水：盛夏高温，盆土应偏干忌湿，防烂根。有时会落叶，翌春会重长出新叶。　　4、修剪：随时剪去枯枝、病枝、弱枝、过密枝和残花残梗，以利通风透光，单瓣的还应截短徒和长枝，使之多生侧枝、多开花。　　5、防冻保暖：入冬后应及时移入室内，放置向阳温暖之处，保持室内3～5℃，可以越冬，盆土应偏干忌湿，防烂根。有时会落叶，翌春会重长出新叶。', '　　　　锦葵繁殖主要有扦插法、压条法。扦插时，选1～2年生健壮枝条，剪成10厘米左右，只留上部叶片和顶芽，削平基部，插入干净的细砂土中，浇足水，罩以塑料薄膜，并置荫棚下，月余可生根；压条法有高压和普通压法两种。高压法可采取塑料袋两端扎紧的方法。可当年成活。', 'http://img.boqiicdn.com/Data/BK/P/imagick32521451898600.jpg', 'http://www.boqii.com/entry/detail/2386.html', '');
INSERT INTO `plant_family` VALUES ('234', '火祭', 'Crassula capitella ', '火祭', '秋火莲', '不容易死', '', 'http://www.boqii.com/entry/photo/2002/0,http://www.boqii.com/entry/photo/2002/5525', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '青锁龙属', '火祭', 'Crassula capitella \'Campfire\'', 'Crassula capitella', '　　 　　多肉植物，植株丛生，长圆形肉质叶交互对生，排列紧密，使植株呈四棱状，叶面有毛点，在光照充足的条件下肉质叶呈浅绿色至深红色，特别是秋末至春季，由于此时昼夜', '　　火祭为景天科青锁龙属的园艺品种，火祭最特别的是其在光照充足的情况下叶片会变成鲜红色，非常漂亮。但是想要养出火红的火祭还是需要注意栽培中的一些细节，小编就为你介绍一下火祭的栽培方法。　　火祭喜凉爽干燥和阳光充的环境，耐干旱，怕水涝，有一定的耐寒能力。在半阴或荫蔽处植株虽然也能生长，但叶色不红，呈绿色，难以突出品种，因此一年四季都要给予充足的光照，这样可使株型矮壮紧凑，叶色红艳。平时不要水、肥过大，特别是氮肥不能过多，否则会造成植株徒长、叶色不红，影响观赏。栽培中如果控制水、肥，使植株生长得慢一些，反而会收到良好的效果，所以要等盆土完全干透后再浇水，每月施一次以磷钾为主的薄肥。盛夏也不必遮光，但要求有良好的通风，以免因闷热潮湿引起根部腐烂或其它病虫害危害。　　栽培中注意打头摘心，以控制植株高度，并促使基部萌发新的枝叶，使株型丰满，及时摘除干枯、腐烂的叶片，维持株形的优美，剪下的枝条可作为插穗，进行扦插繁殖。冬季放在阳光充足的室内，保持盆土干燥，只要霜雪不直接淋到植株上，盆土不结冰，0℃以上可越冬。每1～2年的春季换盆一次，换盆时将腐烂、过长的根系剪短，再用新的栽种，培养土宜用排水透气性良好的沙质土壤，常用腐叶土、沙土和园土各三分之一混匀后配制。　　对于生长多年的火祭老株，还可选择形态优美的植株，用修剪、金属丝蟠扎等造型方法，将其制作成不同款式的盆景，其枝干虬曲苍劲，古朴多姿。如摘去老叶，用不了多久就会萌发新叶，其新叶颜色鲜红，犹如朵朵梅花绽开在枝头，疏影横斜，色彩靓丽，观赏价值更高。　　平时不要水、肥过大，特别是氮肥不能过多，否则会造成植株徒长、叶色不红。要等盆土完全干透后再浇水，每月施一次以磷钾为主的薄肥。当植株长得过高时要及时修剪，以控制植株高度，促使基部萌发新的枝叶，维持株形的优美。春秋生长土干燥后再浇水，要减少浇水，保持盆土微干，并且避免暴晒，冬季放在室内向阳处。火祭在光线不足的地方，虽然也能生长，但茎会拔高柔弱形成徒长，色彩也会比较平淡，丧失了名字的含义。', '　　　　砍头，晾干伤口后，扦插在微湿的透气的土里，等待发根就可以，扦插的苗基本为绿色，火祭的土壤用的是煤渣混合了少量泥炭，没有铺设石头，因为火祭枝条容易匍匐，也容易长根。所以就不铺设河沙了。平时浇水是干透浇透，春天和秋天是生长期，干透浇透，夏天会有短暂休眠，需要通风并且遮阳，一般到了持续32度的高温就会遮阳。慢慢少水，一个月也就给2到3次水，维持根系不干。　　到了天气转凉，慢慢恢复给水。温度不低于零度基本是可以正常给水的，火祭在盆土干燥的情况下能够忍耐零下5度的低温。火祭不容易长虫子。不过必要的预防还是要的，入冬和入夏都埋一次呋喃丹，以防万一啊。　　繁殖火祭以扦插为主，当然也可以叶插，不过生根', 'http://img.boqiicdn.com/Data/BK/P/imagick63401441532698.jpg', 'http://www.boqii.com/entry/detail/2002.html', '');
INSERT INTO `plant_family` VALUES ('235', '东京樱花', 'Cerasus yedoensis  （Matsum.） Yu et Li', '东京樱花', '江户樱花、日本樱花', '不容易死', '', 'http://www.boqii.com/entry/photo/1975/0,http://www.boqii.com/entry/photo/1975/5552', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '樱属', '东京樱花', 'Cerasus yedoensis  （Matsum.） Yu et Li', '', '　　东京 　　东京樱花高4－16米，树皮灰色。小枝淡紫褐色，无毛，嫩枝绿色，被疏柔毛。冬芽卵圆形，无毛。叶片椭圆卵形或倒卵形，长5－12厘米，宽2。5－7厘米，先端渐尖或骤尾尖，基部圆形，稀楔形，边有尖锐重锯齿，齿端渐尖，有小腺体，上面深绿色，无毛，下面淡绿色，沿脉被稀疏柔毛，有侧脉7－10对；叶柄长1.3－1.5厘米，密被柔毛，顶端有1－2个腺体或有时无腺体；托叶披针形，有羽裂腺齿，被柔毛，早落。', '　　东京樱花常以地栽为主，也有特别喜欢的朋友将其作为来种植，一般建议春秋两季来进行栽植，由于东京樱花为浅根性树种，所以在栽培的时候不必挖过大过深的栽植穴。小编就为你介绍一下东京樱花的栽种要点。　　　　生长18－20℃无论地栽还是盆栽，均应置于阳光充足的地方。冬季盆栽樱花入室后应放在背风、向阳、光线好的地方，否则生长不良。中原地带可露地，北京地区幼曲及新植苗木需采取防寒措施，逐渐适应，栽植小环境要有一定的湿度，这样对樱花的正常有好处。当新植植株生长发育稳定后，对低温的适应性也逐渐增强，即抗寒性增强。　　　栽植后浇透水，先不施肥。为使樱花枝叶茂盛，花繁色艳，可于秋季落叶后、春季发芽前施有机肥。向树体经常喷水，小必常浇水。如果发现植株生长不良或叶片黄化时，可放入硫酸亚铁500倍液随浇水施入树穴。盆栽樱花可在夏季多施儿次稀薄肥水，一般每隔7天施1次。　　　地裁撄花以自然树形为主，不需刻意雕琢。剪去干枯枝、病弱枝、徒长枝、过密枝，对留下的枝适当短截即可。盆栽樱花可根据个人爱好拿枝整形，要求整体树姿与盆防调，小要太大太高、比例失控。修剪时间应在花后行，短截后促多生侧枝，利于翌年开好花：　　　若想春节见花，可提前40天将盆株移入室内，置于阳光充足的地方，室温保持15－20℃，并经常向盆周喷水保湿，保持盆土不干，春节即可见花。', '　　东京　　切接一般在3月进行。选', 'http://img.boqiicdn.com/Data/BK/P/imagick23191440409633.jpg', 'http://www.boqii.com/entry/detail/1975.html', '');
INSERT INTO `plant_family` VALUES ('236', '玉兰', 'Magnolia', '玉兰', '白玉兰、木兰、玉兰花、望春、应春花、玉堂春、玉兰', '不容易死', '原产于长江流域，伏牛山、庐山、黄山、峨眉山等处有野生', 'http://www.boqii.com/entry/photo/2020/0,http://www.boqii.com/entry/photo/2020/5507', '植物　', '被子植物门', '双子叶植物纲', '毛茛目', '木兰科', '木兰属', '玉兰', 'Magnolia denudata Desr.', 'Magnolia denudata', '　　 　　玉兰花为落叶乔木，高达25米，胸径1米，枝广展形成宽阔的树冠；树皮深灰色，粗糙开裂；小枝稍粗壮，灰褐色；冬芽及花梗密被淡灰黄色长绢毛。叶纸质，倒卵形、宽倒卵形或、倒卵状椭圆形，基部徒长枝叶椭圆形，长10－15（18）厘米，宽6－10 （12）厘米，先端宽圆、平截或稍凹，具短突尖，中部以下渐狭成楔形，叶上深绿色，嫩时被柔毛，后仅中脉及侧脉留有柔毛，下面淡绿色，沿脉上被柔毛，侧脉每边8－10条，网脉明显；叶柄长1－2.5厘米，被柔毛，上面具狭纵沟；托叶痕为叶柄长的1／4－1／3。花蕾卵圆形，花先叶开放，直立，芳香，直径10－16厘米；花梗显着膨大，密被淡黄色长绢毛；花被片9片，白色，基部常带粉红色，近相似，长圆状倒卵形，长6－8（10）厘米，宽2.5－4.5（6.5）厘米；雄蕊长7－12毫米，花药长6－7毫米，侧向开裂。', '　　是很好的美化庭院的花卉品种，在开花的时候，玉兰高雅洁白，并且还散发出阵阵清香，非常受人喜爱，但是玉兰的花期比较短，一般在10天左右。那么这个在中国非常有名的花木应该如何栽培呢？　白玉兰适生于土层深厚的微酸性或中性土壤，喜肥沃适当湿润而排水良好的弱酸性土壤（pH5～6），不耐盐碱但亦能于碱性土（pH7～8）中，土壤贫瘠时生长不良。　白玉兰的根系肉质根，不耐积水。开花生长期宜保持土壤稍湿润。入秋后应减少浇水，延缓玉兰生根，促使枝条成熟，以利越冬。冬季一般不浇水，只有在土壤过干时浇一次水。　　白玉兰适宜住阳光充足的环境中生长。光照充足可使植株枝繁叶茂，花多更芳香。　　白玉兰对温度比较敏感，温度高可使开花提前，能忍耐－20℃的短时间低温，但温度低于－20℃时需采取防寒措施。　白玉兰较喜肥，但忌大肥；生长期一般施两次肥即可有利于花芽分化和促进生长。一次是在早春时施，再一次是在5－6月份进行。肥料多用充分腐熟的有机肥。新栽植的树苗可不必施肥，待落叶后或翌年春天再施肥。　　白玉兰常见病虫害有炭疽病、叶斑病、有炸蝉、红蜡蚧、吹绵蚧、红、大蓑蛾、天牛等，一旦发现可用喷杀之。但有天牛蛀枝干及根茎部，有时可将树致死，如发现有锯末屑虫粪，就应寻找虫孔，用棉球蘸敌敌畏原液塞进虫孔，再用泥封口，即可熏杀。　白玉兰枝干伤口愈合能力较差，故一般不进行修剪。但为了树形的合理，对徒长枝、枯枝、病虫枝以及有碍树形美观的枝条，仍应在展叶初期剪除。', '　　我国的　\n　一、播种\n　　玉兰最宜秋播，当9～10月份种子成熟后随采随播。也可将种子沙藏到第二年春季3～4月进行播种。播种前应用50℃左右的温水进行浸种，去掉种子外面的蜡质层。去掉蜡质层的方法，既可用沙揉搓，也可用0.5％的碱水或草木灰水浸泡l～2天。播种采用开沟条播，育苗地选用肥沃的沙壤土。播后覆土2厘米，浇透水，覆草，并经常保持土壤湿润。一般约经过2个月即可出苗。夏季需要遮荫，冬季注意防冻。第二年春季土壤解冻后进行分栽。　\n　二、嫁接\n　　这是繁殖玉兰最常用的方法。它既可保持优良　　玉兰因扦插不容易生根、成活率低，一般很少采用这种繁殖方法。但如果扦插前将插穗基部沾上生根粉或在25ppm的蔡乙酸溶液中浸泡20小时，可促进生根，提高成活率。6～7月份扦插，插穗采自', 'http://img.boqiicdn.com/Data/BK/P/imagick81361441791493.jpg', 'http://www.boqii.com/entry/detail/2020.html', '');
INSERT INTO `plant_family` VALUES ('237', '鸭脚木', 'Schefflera octophylla （Lour.） Harms', '鹅掌柴', '鸭掌木、鹅掌木', '不容易死', '台湾、广东、福建等地', 'http://www.boqii.com/entry/photo/1983/0,http://www.boqii.com/entry/photo/1983/5544', '　　', '被子植物门 Angiospermae', '木兰纲 Magnoliopsida（双子叶植物纲 Dicotyledoneae）', '伞形目 Apiales', '五加科 Araliaceae', '鹅掌柴属 Schefflera', '鹅掌柴', 'Schefflera octophylla （Lour.） Harms', 'Schefflera octophylla', '　　 　　鸭脚木是被子植物门五加科下的一个物种，该物种是为热带、亚热带地区常绿阔叶林常见的植物，该物种是中国南方冬季的蜜源植物；木材质软，为火柴杆及制作蒸笼原料；叶及根皮民间供药用，', '　　鸭掌木又名', '　　　\n　一、扦插繁殖。\n　\n　二、全光雾插繁殖。\n　　\n三、高枝压条繁殖。\n', 'http://img.boqiicdn.com/Data/BK/P/imagick3111440581679.jpg', 'http://www.boqii.com/entry/detail/1983.html', '');
INSERT INTO `plant_family` VALUES ('238', '八宝景天', 'Hylotelephium erythrostictum （Miq.） H. Ohba', '八宝景天', '华丽景天，长药八宝，大叶景天，八宝，活血三七，对叶景天', '不容易死', '中国、朝鲜、日本、苏联', 'http://www.boqii.com/entry/photo/2037/0,http://www.boqii.com/entry/photo/2037/5490', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '八宝属', '八宝', 'Hylotelephium erythrostictum （Miq.） H. Ohba', '', '　　 　　八宝景天株高30～50cm。地下茎肥厚，地上茎簇生，粗壮而直立，全株略被白粉，呈灰绿色。叶轮生或对生，倒卵形，肉质，具波状齿。伞房花序密集如平头状，花序径10～13cm，花淡粉红色，常见栽培的尚有白色、紫红色、玫红色品种。 花期，7～10月。', '　　', '　　　　八宝景天可采用分株法和扦插法繁殖，也可用播种法繁殖。分株繁殖和扦插繁殖速度快、操作简单，因此较为常用。　　分株繁殖在早春萌芽前将植株连根挖出，根据植株大小分成若干小植株，分栽入事先准备好的、施有底肥的种植穴中，保持土壤湿润即可成活。扦插繁殖可于4一8月选取枝梢部分做插穗，插穗长5一10cm，保留2一3枚叶片，切口以平剪、光滑为宜，插穗采集后置于蔽阴处，待切口干燥一天后，扦插至经过', 'http://img.boqiicdn.com/Data/BK/P/imagick63581442308679.jpg', 'http://www.boqii.com/entry/detail/2037.html', '');
INSERT INTO `plant_family` VALUES ('239', '凤尾兰', 'Yucca gloriosa L', '凤尾兰', '菠萝花、厚叶丝兰、凤尾丝兰', '不容易死', '原产北美东部和东南部。中国长江流域及以南和山东，河南有引种', 'http://www.boqii.com/entry/photo/2121/0,http://www.boqii.com/entry/photo/2121/5406', '植物　　', '被子植物门', '单子叶植物纲', '天门冬目', '龙舌兰科', '丝兰属', '凤尾兰', 'Yucca gloriosa L', 'Yucca gloriosa', '　　 　　凤尾兰的花梗和子房长约5.5毫米；花白色，伸展；中萼片长圆形，长7毫米，宽2.5毫米，先端急尖；侧萼片斜卵形，长6毫米，宽4毫米，先端急尖，基部收狭；花瓣镰刀状倒披针形，长7毫米，宽2毫米，先端稍急尖；唇瓣厚肉质，3裂；侧裂片紫色，直立，三角形，很小，先端钝；中裂片白色带紫色先端，宽卵形，弯曲向上，长约1毫米，宽约2.5毫米，先端钝，基部（在两侧裂片之间的前方）具1个舌形带毛茸的肉突；距圆锥形，长约2.5毫米，内面背壁具1个舌状附属物。夏秋从叶基部抽出粗壮的花茎，高1米多，圆锥花序，每个花序着花200至400 朵，从下至上逐渐开放，乳白色，杯状，下垂。', '　　的叶色常年浓绿，数株成丛且高低不一，由于凤尾兰对于有害气体的抗性比较强，可以在工矿做美化绿化材料。家庭养殖凤尾兰可以选用较大的盆种植，也可以从根部切取萌蘖丛生的小株，栽于小花钵中，置于几桌上。　　凤尾兰喜温暖湿润和阳光充足环境，耐寒，耐阴，耐旱也较耐湿，对土壤要求不严。对有害气体如SO2、HCl、HF等都有很强的抗性和吸收能力。试验表明，在二氧化硫日平均浓度为0.15毫升∕立方米的环境下，许多树木如松柏、石楠、迎春、泡桐等都出现严重的受害症状，而丝兰仍然挺拔键壮。丝兰吸收氟化氢的能力也较强，据测定，1公斤干叶能吸收氟266毫克。　　凤尾兰性强健，耐寒、耐旱、耐湿、耐瘠薄，对土壤、肥料要求不高。喜排水好的沙质壤土，瘠薄多石砾的堆土废地亦能适应。对酸碱度的适应范围较广，除碱地外均能。　　喜光照。抗污染，萌芽力强，适应性强，花后顶端停止生长，旁边自叶痕发生侧芽。生长强健，有粗壮的肉质根，茎易产生不定芽，很容易生长萌蘖，扩展植株，更新能力很强。　　凤尾兰喜阳、耐阴，可置于散射光充足的门厅内观赏。它对土壤要求不严，以肥沃疏松的沙壤土为佳。　　凤尾兰对肥料的和多少也不苛求。盆栽时，春秋两季各施一两次氮磷钾复合肥即可，冬夏不施肥。', '　　凤尾兰又称凤尾丝兰，为龙舌兰科丝兰属灌木或小乔木，凤尾兰的适应能力强，耐水湿，是非常好的　\n　一、分株\n　　凤尾兰在春季2—3月根蘖芽露出地面时可进行分栽。分栽时，每个芽上最好能带一些肉根。先挖坑施肥，再将分开的蘖芽埋人其中，埋土不要太深，稍盖顶部即可。也可截取茎端簇生叶的部分，带9－12cm长的一段茎，把叶子摘掉一部分，留7片叶左右，埋人12—15cm深的坑中，埋后浇水。由于凤尾兰叶片密生广展，顶端尖锐，起苗时行捆扎，裸根带宿土均可。　　栽培多年的凤尾兰植株会从根部萌生小子株。待小子株稍长大时，将其切离母株。有根者直接栽种，无根者可作插穗；在切口涂抹硫磺粉，然后种在　\n　二、扦插\n　　扦插，在春季或初夏，挖取茎干，剥去叶片，剪成10厘米长，茎干粗可纵切成2－4块，开沟平放，纵切面朝下，盖下5厘米，保持湿度，插后20－30天发芽。分株，每年春、春秋挖取带叶茎干直接栽植。　\n　三、播种\n　　凤尾兰，种子繁殖需经人工授粉才可实现。人工授粉以5月份为好，授粉后约70天种子成熟，当年9月下旬播种，经一个月出苗，出苗率约40％以上。亦可将种子干藏至春季播种。扦插容易成活。在春季或初夏，取茎干去叶片，按每段10厘米锯断，粗的能纵切成2块或4块，开沟平放，纵切面朝下，盖土5——10厘米厚，插后注意土壤不能太湿，防止茎块腐烂。取肉质根作扦插材料更好。凤尾兰在黄河下游及其以南地区，可露地', 'http://img.boqiicdn.com/Data/BK/P/imagick13461444899797.jpg', 'http://www.boqii.com/entry/detail/2121.html', '');
INSERT INTO `plant_family` VALUES ('240', '水竹', 'Phyllostachys heteroclada Oliver', '水竹', '', '不容易死', '黄河流域及其以南各地均有分布', 'http://www.boqii.com/entry/photo/2056/0,http://www.boqii.com/entry/photo/2056/5471', '', '', '', '', '', '', '', '', '', '　　 　　水竹竿可高6米许，粗达3厘米，幼竿具白粉并疏生短柔毛；节间长达30厘米，壁厚3－5毫米；竿环在较粗的竿中较平坦，与箨环同高，在较细的竿中则明显隆起而高于箨环；节内长约5毫米；分枝角度大，以致接近于水平开展。箨鞘背面深绿带紫色（在　　　　　　　　　　　　　　黄河流域及其以南各地均有分布', '　　花草的朋友都对竹子情有独钟，因为竹子给人一种高风亮节的感觉，如果做成盆景的话，别有一番风味。水竹是观赏竹子中比较常见的品种，但是很多朋友往往不知道应该如何栽培，小编就为你介绍一下。　　1、土壤：对土壤要求不严，以肥沃稍粘的土质为宜。　　2、浇水：生长要保持土壤湿润，或直接栽入不漏水的盆，保持盆中有5厘米左右深的水，可免去天天浇水的麻烦，气温较高时还要注意进行叶面喷水保持湿度。　　3、光照：对光线适应范围较宽，全日照或半阴处都可良好生长，忌烈日曝晒，夏季放半阴处对其生长更有利，可保持叶片嫩绿不老。　　4、：不耐寒，华东地区露地稍加保护可以，冬季温度不低于5℃。　　5、施肥：施肥要薄肥勤施，在春、夏季可水施1％的复合肥。避免施肥过多容易引起叶片变黄。水竹不太好肥，只要用一两片肥片兑水溶解浇之即可。水竹水培时水面接触根部上端3厘米，不要浸没过多，以免烂根影响呼吸。如果出现杆部就必须将腐烂的部分及时去剪断免腐烂部分扩大，最好是从竹节的地方剪断。一般来说水竹一旦生根就不容易发生腐烂，如果出现腐烂情况除了剪断腐烂部分还可以在水里放一些亮绿宝用来催根。　　6、虫病害：常发生叶枯病和红蜘蛛危害。叶枯病可用50％托布津1000倍液喷洒，红蜘蛛用40％乐果乳油1500倍液喷洒。', '　　水竹是很多　　水竹常用分株和扦插繁殖，也可播种。扦插于6－7月进行，选开花前的健枝最易生根。取茎顶梢3－5厘米，并将轮生的叶短剪一半，以减少水分蒸发，然后扦于砂或蛭石，使叶片贴在基质上，浇透水，以后保持基质湿润，20天就能生根。根系纤细，可切根分株繁植，分株全年都可进行，但以3月中下旬翻盆时进行最宜。4月播种，也容易萌发成苗。　　水竹茎挺叶茂，层次分明，秀雅自然，四季常绿，十极佳的室内观赏', 'http://img.boqiicdn.com/Data/BK/P/imagick74291442828434.jpg', 'http://www.boqii.com/entry/detail/2056.html', '');
INSERT INTO `plant_family` VALUES ('241', '金凤花', 'Caesalpinia pulcherrima  （L.） Sw.', '金凤花', '黄金凤、蛱蝶花、黄蝴蝶、洋金凤、红蝴蝶', '不容易死', '', 'http://www.boqii.com/entry/photo/2221/0,http://www.boqii.com/entry/photo/2221/5306', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '豆科', '云实属', '金凤花', 'Caesalpinia pulcherrima  （L.） Sw.', '', '　　 　　金凤花为大灌木或小乔木；枝光滑，绿色或粉绿色，散生疏刺。二回羽状复叶长12－26厘米；羽片4－8对，对生，长6－12厘米；小叶7－11对，长圆形或倒卵形，长1－2厘米，宽4－8毫米，顶端凹缺，有时具短尖头，基部偏斜；小叶柄短。', '　　为热带树种，开花时非常漂亮，也是花中的佼佼者，深受人们的喜爱。金凤花的耐寒能力比较低，所以长期低温的环境会使金凤花的枝条受到冷害。　　金凤花温热温湿的环境，不耐寒，属于热带树种；一般遇到5－8℃的低温时，它的枝条会受到霜冻的冷害。金凤花只能进行盆栽，冬季时要记得移入温室内，室内不宜低于10℃；喜欢阳光，不耐荫庇，耐高温，比较适合种植在阳光充沛的地方；对土壤的要求不高，砂性土或粘重土都行。　　金凤花对的要求不甚高，一般中等肥沃的土壤就行；在阳光水分充足的情况下，它色泽鲜艳，开的花更是繁密。中可以适当进行截干或者修枝整形，让它的树冠更加丰满，让它们4－5株种植在一起，可以提高观赏效果。', '　　　　金凤花常用种子繁殖，从6月中旬至12月中旬，荚果陆续成熟，以9～10月份为成熟盛期，采集盛期成熟的果荚，置日光下暴晒，开裂后脱出种子，可以随采随播种，幼苗防寒　　条播法，幼苗生长速度中等，苗期施氮肥2～3次追苗，10月份以后，停施氮肥，施钾肥一致，促使早期木质化，冬季注意覆盖防霜，1年生苗可出圃定植，2年生幼树，即可开花供观赏。', 'http://img.boqiicdn.com/Data/BK/P/imagick16701447408428.jpg', 'http://www.boqii.com/entry/detail/2221.html', '');
INSERT INTO `plant_family` VALUES ('242', '霜之朝', 'Pachyveria ', '霜之朝', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2212/0,http://www.boqii.com/entry/photo/2212/5315', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '厚叶石莲属 xPachyveria', '', 'Pachyveria \'Powder Puff\'', '', '　　 　　霜之朝为多年生无毛多肉植物，植株叶片环状排列，扁长梭型叶片，有叶尖，叶缘圆弧状，叶片肥厚，叶背有棱线，叶面凹陷，叶片向叶心轻微弯曲。叶片光滑有白粉，抹去覆盖的白粉后呈绿蓝色或灰绿色。阳光充足时叶片紧密排列，叶片呈淡紫色或粉红色；弱光环境下徒长，叶色呈浅蓝或蓝绿色，叶片变得窄且长，叶片间的间距会拉长。总状花序，花朵外部呈粉红色，内部呈橙黄色，钟形，串状排列，五瓣或六瓣。于初夏开花。可以异花授粉。', '　　', '　　很多新手朋友一定都听说过多肉　　霜之朝的繁殖方法主要有播种和分株、砍头、叶插。一般用叶插来繁殖，由于', 'http://img.boqiicdn.com/Data/BK/P/imagick28461447320082.jpg', 'http://www.boqii.com/entry/detail/2212.html', '');
INSERT INTO `plant_family` VALUES ('243', '蓝雪花', 'Ceratostigma plumbaginoides Bunge', '蓝雪花', '山灰柴、假靛（河南），角柱花', '不容易死', '我国特产，现在世界热带各地均有栽培', 'http://www.boqii.com/entry/photo/2154/0,http://www.boqii.com/entry/photo/2154/5373', '植物界', '被子植物门', '双子叶植物纲', '白花丹目', '白花丹科', '蓝雪花属', '蓝雪花', 'Ceratostigma plumbaginoides Bunge', 'Ceratostigma plumbaginoides', '　　 　　蓝雪花为多年生直立草本，通常高约20－30（60）厘米，每年由地下茎上端接近地面的几个节上生出数条更新枝成为地上茎。地下茎分枝多，直径约2－3毫米，节上有一红褐至褐色鳞片，鳞片卵形而基部抱茎。　　地上茎细弱（常较地下茎为细），不分枝或分枝，茎枝基部无芽鳞，沿节多少呈之字形曲折，略有棱或在上部节间兼有较为明显的沟，枝上部的棱上有稀少硬毛，被　　叶宽卵形或倒卵形，长（2）4－6（10）厘米，宽（0.8）2－3（5.3）厘米，枝两端者较小，先端渐尖或偶而钝圆，基部骤窄而后渐狭或仅为渐狭，除边缘外两面无毛或近无毛，常有细小钙质颗粒。', '　　的强健，适应能力比较强，如果在6月初上盆的话，7月初即可见花。蓝雪花性喜温暖、喜光照，稍耐阴，花期持续时间较长，一般可达2个月。　　　蓝雪花以泥炭种植比较好，园土种的明显生长要慢一些，掺些珍珠岩就行了。　　　　蓝雪花以较宽的盆为好，不必太深，蓝雪花属于灌木，会地下窜根横向发新枝。选大花盆，生长迅速，要大量的水肥，小花盆限制生长。　　　　蓝雪花喜肥，底肥可以用奥绿，马掌之类的长效缓释肥。平常追肥没有太讲究，基本都能用。我用花多多灌根，追肥固体肥用雷力海富生。叶面喷肥有很好的效果，花多多加海藻精。　　　蓝雪花较湿润的基质，缺水如果马上补水，能缓过来。如果长期缺水，叶子容易发黄，植株衰弱。　　　　蓝雪花不怕修剪，花后剪去残花，大概20－30天又可以开花，老枝不可超过两年。', '　　　\n　一、扦插繁殖\n　　蓝雪花扦插可在春季、夏季初或夏末进行。每年春季结合换盆修剪进行。夏季扦插选二年生健壮充实的嫩枝或半成熟枝条10－15厘米，插于沙床中，生根　\n　二、播种繁殖\n　　蓝雪花很好播种，而且当年就能看花。种点小天吧，不仅不爱长虫子，花期还长。　　1、穴盘规格：288、200、128或72穴盘　　2、介质：选择无病虫害、排水良好的轻型介质，可用草炭、　　3、播种后用粗蛭石覆盖温度发芽适温22～23℃，苗期　　4、发芽天数：4～6天　　5、光照：发芽阶段不需要光，但发芽后及时补光可有效缩短种植周期　　6、水分：育苗期间保持介质潮湿，避免幼苗萎蔫　　7、肥料：子叶露出后开始每周施1～2次100ppm的肥料。后期氮肥浓度提高到150－175ppm，可用氮、磷、钾配比为13－2－13或14－0－14与20－10－20的肥料交替施用　　8、生长调节剂：穴盘苗阶段不需要使用　　9、穴盘育苗天数：6～8周（288穴盘）', 'http://img.boqiicdn.com/Data/BK/P/imagick2901445938137.jpg', 'http://www.boqii.com/entry/detail/2154.html', '');
INSERT INTO `plant_family` VALUES ('244', '蓝目菊', 'Arctotis stoechadifoli var.grandis', '蓝目菊', '非洲万寿菊、非洲雏菊、大花蓝目菊', '不容易死', '原产南非', 'http://www.boqii.com/entry/photo/2204/0,http://www.boqii.com/entry/photo/2204/5323', '　　', '', '', '菊目', '菊科', '菊属', '蓝目菊', 'Arctotis stoechadifoli var.grandis', '', '　　 　　蓝目菊为半灌木或多年生宿根草本植物，株高20～60厘米。基生叶丛生，茎生叶互生，羽裂。顶生头状花序，中央为蓝紫色管状花，舌瓣花，花色有白色、紫色、淡色、橘色等。', '　　蓝目菊为半灌木或多年生宿根草本植物，原产于南非，对于环境的要求不严。由于蓝目菊的色彩鲜艳，植株小巧，所以深受花友们的喜爱，那么蓝目菊时应该注意哪些问题呢？　　　蓝目菊据说怕热，但去年两棵放在窗台都安全度过来了。　　　蓝目菊窗台的蓝目菊比露天的早见花约有半个多月，原因可能是露天气温较低。至于花量，看片片就知道了，这是半个月前的图，当时花量已经不少了。　　　　放在窗台上养殖的蓝目)期非常长，可以达到17天，原因应该是窗台风雨少。如果是露天的那棵，不超过一个礼拜就得谢了。另外，窗台靠近室内，如果室内开灯早能延长蓝目的开花时间。　　　蓝目菊光线充足就行，无日照的窗台能开，阴天如果散射光够也能开。', '　　　　1、准备播种土，最好用翠筠的播种土。　　2、细小种子播种用土最好先过一下筛，就用家里常用的漏水果菜篮，晒下的细土放一边，先用筛除的枝枝杈杈垫底，因为育苗盘底部都有小手指头大小的底洞，细土容易流失、正好可以把这些大块的家伙利用起来，然后把细土直到穴填满为止。细土放在表面，目的是为了更好的与小种子浸润，有利于发芽。其实用翠筠播种土，不筛也　　3、播种土的湿度要合适，以手攥住成团、手松开就散为宜。有人可能要问，种子入土再喷水还不是一样？还真是不一样，用过的人都知道，　　4、把筛完剩下的粗大的土放在苗盘孔的下部，细土放在上面。　　5、喷水：使土表面充分湿润，如果手上有1＃水，可以用其500倍稀释液喷，有利于发芽。　　6、播种：用牙签蘸水后粘起种子、一次一粒、放入穴孔中央，包衣种子最好稍稍往土里按压一下。细小种子一般都是喜光的，不用覆土，最好一穴一粒，播种完毕把苗盘放到有水的底盆里，让水慢慢渗透。大粒种子嫌光，种子上要覆土、盖住种子，而且发芽前最好放在阴凉、暗的地方。（矮牛嫌光，所以覆盖的塑料膜可以用黑色的膜）。苗盘只适合细小种子播种，像　　7、种子播完后再喷水，直到土壤全部湿透，然后用塑料膜覆盖。发芽前不要取开塑料膜，最好每天补充喷水一次，直到发芽后再接去塑料膜，给小苗正常光照。自己做个家庭小温室吧。把苗盘放进这样的家庭小温室吧。盖好盖子直到发芽。气温高时温室放在凉爽的地方，气温底时白天可以放在外面晒太阳，晚上拿回屋里，需要注意的是，一旦有苗苗发芽一定要让晒太阳，否则一两天的　　8、出芽后要通风、日照，土壤不能老是濡湿状态，不然很容易茎枯。第一场夏雨来报道了，蓝目菊也冒出了嫩黄的小芽。大粒种子如果是单棵直播也没有关系，如果是多粒混播最好。', 'http://img.boqiicdn.com/Data/BK/P/imagick99851447148491.jpg', 'http://www.boqii.com/entry/detail/2204.html', '');
INSERT INTO `plant_family` VALUES ('245', '白晶菊', 'Chrysanthemum paludosum', '白晶菊', '晶晶菊', '不容易死', '原产于：北非、西班牙', 'http://www.boqii.com/entry/photo/2191/0,http://www.boqii.com/entry/photo/2191/5336', '植物　', '', '', '', '菊科', '茼蒿属', '白晶菊', 'Chrysanthemum paludosum', '', '　　 　　白晶菊株高15至25厘米，叶互生，一至两回羽裂。头状花序顶生，盘状，边缘舌状花银白色，中央筒状花金黄色，色彩分明、鲜艳，花径3至4厘米。株高长到15厘米即可开花，花期从冬末至初夏，3至5月是其盛花期。花后结瘦果，5月下旬成熟。白晶菊矮而强健，多花，花期早，花期长，成片栽培耀眼夺目，适合盆栽、组合盆栽观赏或早春花坛美化。株高10馀公分。叶羽状深裂。花顶生，花径约2～3公分，外围舌状花瓣纯白，中心管状花鲜黄色，成簇栽培，殊为高雅脱俗。瘦果。开花期早春至春末，花期极长，花谢花开，可维持2～3个月。', '　　白晶菊在3－5月为盛花期，当成片的白晶菊开放的时候耀眼夺目，非常漂亮。白晶菊的栽培难度不高，非常适合盆栽、组合盆栽或早春花坛的美化。小编就为你介绍一下白晶菊人工栽培的方法及。　　白晶菊喜阳光充足而凉爽的环境，光照不足开花不良。耐寒，不耐高温，适温为15℃至25℃，花坛露地栽培－5℃以上能越冬，－5℃以下长低温，叶片受冻，干枯变黄，当温度升高后仍能萌叶，孕蕾开花。白晶菊忌高温多湿，夏季随着温度升高，花朵凋谢加快，30℃以上生长不良，摆放在阴凉通风的环境中能延长花期。　　白晶菊适应性强，不择土壤，但以种植在疏松、肥沃、湿润的壤土或砂质壤土中生长最佳。平时土保持湿润，切忌长期过湿，造成烂根，影响生长发育。生长期内每半个月施一次氮、磷、钾复合肥，比例为2∶1∶2。白晶菊多花且花期极长，花期还需要及时补充磷、钾肥。花谢后，若不留种子，可随时剪去残花，促发侧枝产生新蕾，增加开花数量，延长花期。', '　　白晶菊　　白晶菊用播种繁殖，通常在秋季9至10月播种，发芽适宜', 'http://img.boqiicdn.com/Data/BK/P/imagick91851446717339.jpg', 'http://www.boqii.com/entry/detail/2191.html', '');
INSERT INTO `plant_family` VALUES ('246', '水鬼蕉', 'Hymenocallis littoralis （Jacq.） Scalisb.', '水鬼蕉', '美洲水鬼蕉、蜘蛛兰、蜘蛛百合', '不容易死', '原产美洲南部和中部，国内分布于海南省。', 'http://www.boqii.com/entry/photo/2190/0,http://www.boqii.com/entry/photo/2190/5337', '　', '被子植物门', '单子叶植物纲', '百合目', '()科', '水鬼蕉属', '水鬼蕉', 'Hymenocallis littoralis （Jacq.） Scalisb.', 'Hymenocallis Spciosa', '　　 　　水鬼蕉为多年生草本。有鳞茎。叶数枚，集生基部，抱茎；剑形，长45～75厘米，宽2。5～6厘米，深绿色，多脉。花茎扁平，实心，高30～80厘米，外苞片长5～7厘米，基部极阔；花白色，无柄，3～8朵生于花茎之顶；花被管圆柱形，纤弱，长短不等，约10厘米以上，裂片线形，常短于管；雄蕊生于管之喉部，花丝基部合成杯形，上部分离，花药丁字，子房下位，花柱头状。花期夏末秋初。叶剑形，端锐尖，多直立，鲜绿色，长50～80ca，宽2.5～6ca。花葶扁平，高30～80cm；花白色，无梗，呈伞状着生；有芳香；花筒部长短不一，带绿色；花被片线状，一般比筒部短；副冠钟形或阔漏斗形，具齿牙缘。鳞茎径7～11cm。为庭园栽培植物。', '　　的外形比较特别，很多人会将水鬼蕉花朵的中间部分看成蜘蛛的身体。水鬼蕉对土壤的适应性较广，不耐寒，喜温暖湿润的环境。人工栽培水鬼蕉可以根据其习性特点来栽培，以保证水鬼蕉更加健康。　　1、土壤：水鬼蕉对土壤要求不严，可用腐叶土盆栽，也可栽植粘质的土壤中。　　2、浇水：水鬼蕉春季出房后，随着气温的升高，要逐步增加浇水量。盛夏时，浇水最好是早晨喷1次，下午再浇透，保持土壤经常湿润和有较高的。冬季移放室内后，则要控制浇水，只要保持盆土稍有湿润就能度过寒冬。　　3、阳光：水鬼蕉喜半阴环境，忌强光暴晒，夏季光照过强时，宜适当遮阴或将花盆移至半阴处。　　4、：水鬼蕉喜温暖，不耐寒冷，所以盆栽温度15℃以上。　　5、施肥：水鬼蕉在期每半月施肥1次。进入花期以后，应每隔7－10天施1次粪肥，如能适当补充磷、钾肥，可使花开得更加旺盛。', '　　　　水鬼蕉的分球繁殖于春季结合换盆进行，　　此花爱温暖湿润环境，喜光但畏烈日，不耐寒，露地栽培时，遭霜冻地上部分即受冻枯萎，故多作温室盆栽，对土壤适应性广，适宜在富含腐殖质且稍粘的壤土中', 'http://img.boqiicdn.com/Data/BK/P/imagick75841446716517.jpg', 'http://www.boqii.com/entry/detail/2190.html', '');
INSERT INTO `plant_family` VALUES ('247', '五十铃玉', 'Fenestraria aurantiaca', '橙黄棒叶花', '五十铃玉', '不容易死', '原产地是南非和纳米比亚等地', 'http://www.boqii.com/entry/photo/2176/0,http://www.boqii.com/entry/photo/2176/5352', '　　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '棒叶花属', '五十铃玉', 'Fenestraria aurantiaca', '', '　　 　　五十铃玉的植株非常肉质，密集成丛，株丛直径10厘米，根很细。肉质叶棍棒状几乎垂直', '　　的植株非常肉质，密生成丛，叶为棍棒状，很耐干旱。适宜的为15－30摄氏度，如果低于或高于这一温度区间，植株的生长就会变慢甚至开始休眠。　　五十铃玉性喜阳光充足，耐干旱，不耐高温高湿，不耐水湿和强光暴晒，无明显。栽培要点：生长适温15－30度，冬季不低于5度，配土一般可用泥炭＋蛭石＋珍珠岩各一份，以透气透水为佳，生长期适当浇水，夏制浇水，浇水的方法最好采用浸盆法，从盆底给水，水位不要超过花盆的三分之二，大概15秒就可以了，浇水的时机，当看到叶面萎缩，有皱皮现象就可以浸盆，也可以采用叶面喷水，施肥一般生长季每月施肥一次。　　1、夏季不要从上面浇水，持续闷热时尽量用浸盆法，陶盆可以浸透但是透气性不好的盆最好浸半湿，没有必要时尽量避免向植株喷水。　　2、不要淋雨，如遇闷热或暴雨前期，因为空气湿度很大最好不要给水。　　3、每日日晒5小时就可以了，我是放在户外的窗台上，不要不晒太阳其实大棚里更热的，不晒太阳的话一个是颜色不好看另外就是植株不强壮，空气、阳光、水，这是植物生长三要素。　　4、冬天在北方家中有暖气的可以适时浇水。　　5、当叶子上出现皱纹时在过个2－3天可以浇水，植物平时摆放的地方最好以通风为主。', '　　　　五十铃玉主要采用种子繁殖方法，可以参考', 'http://img.boqiicdn.com/Data/BK/P/imagick51651446541082.jpg', 'http://www.boqii.com/entry/detail/2176.html', '');
INSERT INTO `plant_family` VALUES ('248', '三色堇', 'Pansy', '三色堇', '三色堇菜、猫儿脸、蝴蝶花、人面花、猫脸花、阳蝶花、鬼脸花', '不容易死', '', 'http://www.boqii.com/entry/photo/2001/0,http://www.boqii.com/entry/photo/2001/5526', '', '', '', '', '', '', '', '', '', '　　 　　三色堇花大，直径约3.5－6cm，每个茎上有3－10朵，通常每花有紫、白、黄三色；花梗稍粗，单生叶腋，上部具2枚对生的小苞片；小苞片极小，卵状三角形；萼片绿色，长圆状披针形，长1.2－2.2cm，宽3－5mm，先端尖，边缘狭膜质，基部附属物发达，长3－6mm，边缘不整齐；上方花瓣深紫堇色，侧方及下方花瓣均为三色，有紫色条纹，侧方花瓣里面基部密被须毛，下方花瓣距较细，长5－8mm；子房无毛，花柱短，基部明显膝曲，柱头膨大，呈球状，前方具较大的柱头孔。　　　　　　　　　　　　　　　　　　　　　　　　', '　　三色堇又名、人面花、鬼脸花等，由于三色堇的一朵花上往往有三种，故此命名。由于三色堇较耐寒，其开花受光照的影响比较大，所以一般三色堇在花坛、庭园中比较常见，也可以在阳台上进行盆栽，但是不适合在室内种植。　　1、　　人冬后苗仍然较幼嫩，应适度防寒。　　2、光照　　冬季给予充分光照。　　3、水肥　　冬季充分浇水。期内要勤施肥、除草，开花后停止施肥。栽培中水肥充足，才能使花多、花大、花期长。　　必须经常保持土壤微湿，在开花前施3次稀薄的复合液肥，孕蕾期加施2次0。2％的磷酸二氢钾溶液。进入冬季后，植株必须搬入室内阳光充足的地方，白天温度不超过12度，晚上温度不低于7度，在晴天时必须在中午开窗通风换气。　　室内养护时，如果温度太高，会降低花的品质，因此要选择晴天中午开窗透气，使植株生长健壮，花色艳丽。三色堇花后要剪除残花，减少养分损耗，以保证后期开花的质量。', '　　　　\n一、播种繁殖\n　　三色堇一般在9月上旬用撒播法进行播种，要求苗床或播种盆内的土壤必须排水良好，播后覆土是种子的2倍，用细喷壶浇足水，放在光线充足的地方。　　三色堇发芽适温为18－21℃，避光条件下7－10天发芽，　　三色堇播后可用蛭石覆盖种子，土温18－24℃，保持介质湿润，胚根长出前不需要光照，一般7－14天可出苗。三色堇小苗成长阶段土壤温度为15－24℃，温度越低植株生长越慢，植株越健壮。浇水前让土壤干透但要避免植株永久性萎焉，这有利于三色堇根的生长。土壤　　\n二、扦插繁殖\n　　为了保持三色堇母株的优良性状，一般会进行扦插繁殖，一般在在初夏时行，剪取植株基部抽生的枝条作为插穗，开花枝条不能作插穗，扦插3－7月均可进行，扦插后约2－3个星期即可生根，成活率很高。　　\n三、压条繁殖\n　　在初夏进行的三色堇繁殖方法还有压条繁殖法，成活力也很高，与扦插繁殖法是最常见的三色堇繁殖方法。', 'http://img.boqiicdn.com/Data/BK/P/imagick62431441188242.jpg', 'http://www.boqii.com/entry/detail/2001.html', '');
INSERT INTO `plant_family` VALUES ('249', '大花葱', 'Allium giganfeum', '大花葱', '吉安花、巨葱、高葱、硕葱', '不容易死', '亚洲中部和喜马拉雅地区', 'http://www.boqii.com/entry/photo/2316/0,http://www.boqii.com/entry/photo/2316/5207', '　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '葱属', '', 'Allium giganfeum', '', '　　大花葱又名硕葱、吉安花等，为多年生球根 　　大花葱多年生草本', '　　的小花多达上千朵，紫红色的小花非常漂亮，也因其花序硕大而闻名，非常适合在我国北方地区栽培。人工栽培大花葱需要给予充足的阳光，忌积水。　　大花葱期及时松土浇水，每2－3周施肥1次。4－5月抽莛开花，如花后不采种，可剪去花茎以集中营养供鳞茎生长。鳞茎在排水不良的情况下易，应挖起鳞茎放室内通风处保存。　　选择地下水位低、排水良好、疏松、肥沃的沙壤土作栽培地。生长期及时松土浇水，每2－3周施肥1次。4－5月抽莛开花，如花后不采种，可剪去花茎以集中营养供鳞茎生长。鳞茎在排水不良的情况下易腐烂，应挖起鳞茎放室内通风处保存。空气干燥的地方适量人工喷雾或遮阳。　　大花葱是鳞茎自然增殖率极低的一种花卉，但若在花葶出现后及早去除，使养分集中于更新球与子鳞茎的，则可适当增加小鳞茎的数目。夏季地上部分枯死，可将鳞茎挖出，大小鳞茎分开，置通风处越夏。　　秋后栽植，鳞茎达3厘米以上者种植后可开花，小于3厘米者需要养植一年后方能开花，鳞茎增殖率大花葱性喜冷凉、阳光充足的环境，要求疏松肥沃的沙壤土，忌积水，适合我国北方地区栽培。　　露地栽培应选择地下水位低、排水良好、疏松、肥沃的砂壤土地作栽培地。栽球的，北京地区宜9月中下旬至10月上旬。株行距20cm×30cm，种植的深度为鳞茎上覆土厚为鲜茎高的2～3倍。　　大花葱栽后稍压平穴面，然后浇水。冬季不必覆盖防寒。翌年春季3月份叶片出土时，及时松土浇水，配合液态追肥每10～15天浇一次水。注意中耕、松土、除草。空气干燥的地方适量增加少量人工喷雾或遮荫，可以缓和初夏时叶片枯黄的变化。花后茎叶枯萎，雨季来临前及早挖取鳞茎，免得遭雨后腐烂。置于通风干燥处晾干后收起，分摊在室内通风处存放，待9～1O月栽种。栽种地不宜连作，注意施用腐熟有机肥，夏季多雨，需及时排水。', '　　　　\n一、种子繁殖\n　　7月上旬种子成熟，阴干，5－7℃低温贮藏。9－10月秋播，翌年3月发芽出苗。夏季也上部枯萎，形成小鳞茎，播种苗约需栽培5年才能开花。　　\n二、分株繁殖\n　　9月中旬将主鳞茎周围的子鳞茎剥下种植。9月中旬将主鳞茎周围的子鳞茎剥选择地下水位低、排水良好、疏松、肥沃的沙壤土作栽培地。分球繁殖于夏秋进行，每一母球可分1～3个小球，其中较大的鳞茎种植后第二年可开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick12841449826388.jpg', 'http://www.boqii.com/entry/detail/2316.html', '');
INSERT INTO `plant_family` VALUES ('250', '红掌', 'Anthurium', '红掌', '花烛、安祖花、火鹤花、红鹤芋、红鹅掌等', '不容易死', '原产于南美洲热带、现在欧洲、亚洲、非洲皆有广泛栽培', 'http://www.boqii.com/entry/photo/2000/0,http://www.boqii.com/entry/photo/2000/5527', '', '', '', '', '', '', '', '', '', '　　红掌原名花烛，其外形独特，又寓意着大展宏图，所以深受人们的喜爱，也是现在比较常见的室内 　　红掌为多年生常绿草本花卉。性喜温热多湿而又排水良好的环境，怕干旱和强光暴晒。其适宜　　　　　　　　　　　　　　　　　', '　　红掌是产自南美洲的花卉，也是现在非常常见的室内。一般红掌可以通过盆栽或水培的方法来进行栽培，小编今天为你介绍的是红掌盆栽的方法及，有兴趣的朋友可以一起了解。　　　种植红掌的土壤基质一定要保持具有良好的通透性，不积水。家庭养殖时可以选择在园艺店购买配置好的并增加些陶粒及干树皮混合（陶粒：干树皮＝2：1）做基质。种植前需要对基质进行消毒避免红掌在生长的后期受虫害。　　　最适合红掌的生长环境温度要控制在14－35度之间。冬季，温度低于10度时，容易造成红冻害。要注意给红掌保暖增温。夏季，温度高于35度时应及时给红掌加湿及周围进行喷水。做到这一点即使是高温，但如果湿度高的话，红掌也不易受到伤害。　　　较其它观叶植物来说红掌对镁肥的需求更高一些。家庭养殖给红掌施肥时建议到园艺店购买魔力康肥料配合叶面肥一起施用。或者花多多通用型等全水溶性复合肥稀释成800—1000倍液肥定期施用（每周不少于1次）。红掌施肥的原则是少施厚肥，勤施薄肥。　　　根据盆内基质的干燥程度来进行给红掌浇水。夏天气温较高建议2天浇一次水，中午还要利用喷淋系统向叶面喷水，以增加室内的相对湿度。冬天，建议5－7天浇一次。寒冷季节浇水应在上午9时至下午4时前进行，以免冻伤根系。一般春秋两季可以每3天浇一次水。避免在植株严重缺水情况下加水，会影响红掌的生长。在浇水过程中一定要干湿交替进行，切莫在植株发生缺水严重的情况下浇水，这样会影响其正常生长发育。', '　　由于红掌是异花授粉植物，所以红掌的播种繁殖难度较大，并且产生的变异也很大。一般红掌采用分株繁殖、扦插繁殖以及组培的较多。小编就为你详细介绍一下红掌的三种繁殖方法，喜欢红掌的朋友可以一起了解。　　\n一、分株繁殖\n　　红掌具有较强的分蘖能力，可以结合间苗、移苗及　　1、分株时期主要在凉爽高湿的春季，秋季阴凉天气也可分株。切忌在炎热的夏天或干燥寒冷的季节分株。　　2、分株时须注意以不伤母株为原则，太大的侧芽不分，靠太紧的侧芽不分，太弱小的侧芽也不分，主要分出比较容易与母株分离且较为健壮、至少有2条主要根系以上的侧芽。　　3、移植苗时分株可用手均匀用力，将侧芽与母株在地下茎芽眼处分离，较难分离时用锐利的　　4、切开的侧芽待伤口稍干后将其假植于阴凉处进行促根及恢复生长。种植时须使根系平展，植株直立，必要时进行支撑，种后不能立即浇水，可向叶面喷水保持湿度，2天后即可依情况进行浇水或施稀薄肥液。　　分株、扦插繁殖的缺点是生长较慢，且材料难于消毒，容易携带病虫害（如根结线虫、细菌和病毒等）。分株苗和组培苗在栽培技术上的要求是一样的，只是前者比后者植株高大、强壮一些而已。　\n　二、播种繁殖\n　　红掌在育种上，通过播种是获得红掌新　\n　三、组织培养\n　　组织培养是将植物材料的切块置于培养基中进行培育，并获得新植株的一种繁殖方法，整个过程在实验室无菌条件下完成。繁育材料首先必须严格消毒并经过脱毒培养，才能为获得无毒克隆苗提供保障。　　红掌的繁育材料主要采用愈伤组织和叶片。用愈伤组织作为繁育材料的原因是得到的克隆苗不易发生变异，但要获得无毒的愈伤组织非常困难。叶片容易消毒且操作比较方便，不利的是叶片不光滑，且用以培养形成的植株容易发生突变，但这种突变可以人为控制。　　组培苗在瓶苗阶段都是在人为提供的各种最适生长条件下完成生长过程的。实验条件同外界自然条件差异很大，因此，让瓶苗经历一个过渡的健化炼苗过程很有必要，以使瓶苗顺利适应外界的', 'http://img.boqiicdn.com/Data/BK/P/imagick98771441187701.jpg', 'http://www.boqii.com/entry/detail/2000.html', '');
INSERT INTO `plant_family` VALUES ('251', '雏菊', 'Bellis perennis', '雏菊', '春菊，马兰头花，延命菊', '不容易死', '原产欧洲和地中海区域，现世界各地均有栽培', 'http://www.boqii.com/entry/photo/2069/0,http://www.boqii.com/entry/photo/2069/5458', '', '', '', '', '', '', '', '', '', '　　 　　雏菊为多年生或一年生葶状草本，高10厘米左右。叶基生，草质，匙形，顶端圆钝，基部渐狭成柄，上半部边缘有疏钝齿或波状齿。头状花序单生，直径2.5－3.5厘米，花葶被毛；总苞半球形或宽钟形；总苞片近2层，稍不等长，长椭圆形，顶端钝，外面被柔毛。舌状花一层，雌性，舌片白色带粉红色，开展，全缘或有2－3齿，中央有多数两性花，都结果实，筒状，檐部长，有4－5裂片。　　　　　　　　　　　　　　　　　', '此阶段根系已经形成完好，种苗基本上可以出售，并且通过炼苗而变得耐寒，这个阶段持续7天左右。温度、湿度、施肥浓度基本和第三阶段相同。应注意及时移栽上盆。第三、四阶段，需7至14天时间。　　为菊科中多年生草本，随着播种时间的不同，雏菊可以在春季开花，也可在夏季，也被意大利人奉为国花。那么雏菊在不同的阶段应该如何呢？　　　胚根萌发阶段从胚根穿破种皮开始，幼根接触到土壤，到长出子叶为第一阶段。应保持在18℃。种子发芽具好光性，故播种时无需覆土，但需保持栽培介质的湿润，切勿于本阶段出现介质干燥的情况。此阶段pH值保持在5。5至6。2之间，相对湿度为100％。应避免阳光直射，在播种后对种子进行遮阴。　　　从长出子叶开始，到长出真叶为第二阶段。温度仍保持在18℃。适当降低栽培介质的湿度，但仍不可太过于干燥，湿度大约在70％至80％，能使其根系扎入介质吸收养分供子叶的伸展。第一、二阶段，需14至21天时间。　　　从长出真叶开始，到有80％的种苗可以出售为第三阶段。温度降低至15℃左右。空气湿度也需逐渐降低，两次浇水间可让基质有一个干透的过程，从而形成干湿循环，利于促进根系发育。　', '　　雏菊是菊科　\n　一、种子繁殖\n　　南方多在秋季8－9月份播种，也可春播，但往往夏季　\n　二、分株繁殖\n　　由于实生苗变异较大，对于一些优良　\n　三、扦插繁殖\n　　在整个生长', 'http://img.boqiicdn.com/Data/BK/P/imagick21551443002548.jpg', 'http://www.boqii.com/entry/detail/2069.html', '');
INSERT INTO `plant_family` VALUES ('252', '黄连木', 'Pistacia chinensis Bunge', '黄连木', '楷木、惜木、孔木、鸡冠果等', '不容易死', '黄河流域、两广及西南各省均有；以河北、河南、山西、陕西最多。', 'http://www.boqii.com/entry/photo/2081/0,http://www.boqii.com/entry/photo/2081/5446', '　', '被子植物门', '双子叶植物纲', '无患子目', '漆树科', '黄连木属', '黄连木', 'Pistacia chinensis Bunge', '', '　　 　　黄连木为', '　　随着近年来人们对', '　　　\n　1、采种：\n　　黄连木3至4月开花，9至10月果熟。当果实从红色变为铜锈色时及时采果，否则10天后自行脱落，铜绿色果实是成熟饱满的种子，红色、淡红色果多为空粒。采种选择20～40年　\n　2、种子\n　　将采收的种子浸入40℃～50℃的草木灰温水中浸泡2～3天，或用5％的石灰水浸泡2～3天，搓烂果肉，除去种皮蜡质，捞出沉在水干后储藏。秋季育苗，随采随播，种子不进行处理，于晚秋土壤封冻前播下。　\n　3、层积贮藏 ：\n　　第二年春季育苗，当年冬季种子需要贮藏。选择地势较高排水良好的地块，挖深、宽各一米的坑，将种子与湿沙按1：3的比例混合均匀，倒入坑中，距地面15厘米处填入河沙，做成土堆，在坑内竖一通气草把。来年2～3月，取出育苗。　　\n4、圃地选择：\n　　黄连木喜光，圃地应选排水良好，土壤深厚肥沃的沙壤土每亩施入2000公斤基肥。　\n　5、播种育苗 ：\n　　春播一般在2月下到3月中旬。采用开沟条播，行距20～30cm，播幅为5～6cm，播种深3cm，播前灌足底水，将种子均匀撤入沟内，播种量为每亩10kg左右，播后覆土2～3cm，轻轻压实后覆草，保持湿润。出苗时分次揭去覆草，1个月后苗可出齐，发芽率50％～60％。　　\n6、苗期\n　　种子出苗前，要保持土壤湿润。为提高成活率，要及早间苗，第一次间苗在苗高3～4cm时进行，去弱留强，以后根据幼苗生长发育间苗1～2次。幼苗生长期间，每隔10～20天除草松土1次，多在灌溉后或雨后进行，行内松土厚度要浅于覆土厚度，行间松土可适当加深。苗高10cm时即可定苗，苗距5～10cm。后期根据幼苗的生长情况追肥灌水2次，幼苗生长期以氮肥、磷肥为主，速生期以氮肥、磷肥、钾肥混合，', 'http://img.boqiicdn.com/Data/BK/P/imagick16281443431678.jpg', 'http://www.boqii.com/entry/detail/2081.html', '');
INSERT INTO `plant_family` VALUES ('253', '棕榈', 'Trachycarpus fortunei （Hook.） H. Wendl.', '棕榈', '唐棕、拼棕、中国扇棕、棕树、山棕', '不容易死', '中国、日本、印度、缅甸', 'http://www.boqii.com/entry/photo/2018/0,http://www.boqii.com/entry/photo/2018/5509', '', '', '', '', '', '', '', '', '', '　　 　　棕榈为乔木状，高3－10米或更高，树干圆柱形，被不易脱落的老叶柄基部和密集的网状纤维，除非人工剥除，否则不能自行脱落，裸露树干直径10－15厘米甚至更粗。叶片呈3／4圆形或者近圆形，深裂成30－50片具皱折的线状剑形，宽约2.5－4厘米，长60－70厘米的裂片，裂片先端具短2裂或2齿，硬挺甚至顶端下垂；叶柄长75－80厘米或甚至更长，两侧具细圆齿，顶端有明显的戟突。花序粗壮，多次分枝，从叶腋抽出，通常是棕榈Trachycarpus fortunei （Hook.） H. Wendl.唐棕、拼棕、中国扇棕、棕树、山棕　　　　　　　　　　　　', '　　随着人们对棕榈的栽培，现在棕榈可以分为热带棕榈和耐寒棕榈两类，适合在不同环境下的园林栽种。有的朋友对于棕榈非常喜爱，还会将棕榈制作成盆栽进行栽培，那么盆栽棕榈应该注意哪些问题呢？　　棕榈在北方亦可盆栽，6年生以下的植株可盆栽，8～9年生植株应栽入木桶。20年生以上即势大大减退，老叶枯黄易失去观赏价值，应以淘汰。炎夏每天浇水l次。春秋浇水次数较少些为好。10月在北方需进入低温温室，5月移出。10余天浇水1次。2～3年以后分苗移栽，以3～4月份移栽成活率高。移前去掉部分叶片，浅栽以免使生长点埋入土中。5年后生长加快，即可地栽或上盆。地栽选沙质壤土，并施足量有机肥料。　　棕榈为抗逆性较强的，栽培管理较容易。在湿润、肥沃且排水良好的中性土壤中生长，但在酸性、微碱性土壤中也能良好生长。较耐寒冷，大树可耐－10℃左右的低温。对光照要求也不严，既能在全日照下生长良好，又能在较阴的室内良好生长。它还具有一定的耐旱和耐湿能力，故小苗盆栽观赏管理可稍粗放。棕榈对二氧化硫、氟化氢等有毒气体的抗性也较强，因此可在工厂区的室内、外绿化中广泛栽植或盆栽布置，从而对改善环境、减轻污染起到良好的作用。', '　　　\n　一、采种贮藏：\n　　\n二、浸种\n　\n　三、整地作床：\n　\n　四、播种：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick54101441790662.jpg', 'http://www.boqii.com/entry/detail/2018.html', '');
INSERT INTO `plant_family` VALUES ('254', '狗娃花', '', '狗娃花', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2413/0,http://www.boqii.com/entry/photo/2413/5002', '', '', '', '', '', '', '', '', '', '　　 　　狗娃花有垂直的纺锤状根，茎高30-50有时达150厘米，单生，有时数个丛生，被上曲或开展的粗毛，下部常', '　　', '　　　　狗娃花广泛分布于我国北部、西北部及东北部各省，也见于四川东北部城口、巫山、万县)、湖北、安徽、江西北部、浙江及台湾。生于荒地、路旁、林缘及草地。海拔达2400米。狗娃花常采用播种、分株繁殖。分株在春、秋季进行，易成活，栽培容易。', 'http://img.boqiicdn.com/Data/BK/P/imagick95661452504616.jpg', 'http://www.boqii.com/entry/detail/2413.html', '');
INSERT INTO `plant_family` VALUES ('255', '夹竹桃', 'Nerium indicum', '夹竹桃', '柳叶桃，绮丽，半年红，甲子桃', '不容易死', '中国、伊朗、印度、尼泊尔；现广植于世界热带地区', 'http://www.boqii.com/entry/photo/2021/0,http://www.boqii.com/entry/photo/2021/5506', '　', '被子植物门', '双子叶植物纲', '捩花目', '夹竹桃科', '夹竹桃属', '', 'Nerium indicum Mill.', 'Nerium indicum', '　　 　　夹竹桃为聚伞花序顶生，着花数朵；总花梗长约3厘米，被微毛；花梗长7－10毫米；苞片披针形，长7毫米，宽1.5毫米；花芳香；花萼5深裂，红色，披针形，长3－4毫米，宽1.5－2毫米，外面无毛，内面基部具腺体；花冠深红色或粉红色，栽培演变有白色或黄色，花冠为单瓣呈5裂时，其花冠为漏斗状，长和直径约3厘米，其花冠筒圆筒形，上部扩大呈钟形，长1.6－2厘米，花冠筒内面被长柔毛，花冠喉部具5片宽鳞片状副花冠，每片其顶端撕裂，并伸出花冠喉部之外，花冠裂片倒卵形，顶端圆形，长1.5厘米，宽1厘米；花冠为重瓣呈15－18枚时，裂片组成三轮，内轮为漏斗状，外面二轮为辐状，分裂至基部或每2－3片基部连合，裂片长2－3.5厘米，宽约1－2厘米，每花冠裂片基部具长圆形而顶端撕裂的鳞片；雄蕊着生在花冠筒中部以上，花丝短，被长柔毛，花药箭头状，内藏，与柱头连生，基部具耳，顶端渐尖，药隔延长呈丝状，被柔毛；无花盘；心皮2，离生，被柔毛，花柱丝状，长7－8毫米，柱头近球圆形，顶端凸尖；每心皮有胚珠多颗。', '　　夹竹桃虽然有一定的毒性，但还是有很多花友', '　　很多喜欢　\n　一、扦插法\n　　扦插法采用硬插、软插均可。硬枝扦插是在早春结合苗木修剪时进行，剪取枝长15－20cm，每20根捆在一起，浸入20℃的清水中，1／3处浸入水种，经常换水，8天左右入浸部分枝条发白，顶部发沾时，取出插入苗床中。或者把枝条浸水中30－40天，生根后插入砂床中，进行遮荫，容易成活。另外，把插条浸入0.1％　\n　二、压条繁殖法\n　　压条繁殖法分高压和低压两种，3－4月进行，高压多用盆载。30－40天后即可生根。地压多在多雨的夏季进行，把母株上接近地面的枝条，将表皮作环状切割后埋入土中，嫩枝压条3－4天后才能浇水，保持湿润。如果遇到雨季，压后7天即可生根，生根后切去一半，秋季全部切去，进行秋栽或春栽。　\n　三、种子繁殖\n　　种子在春末进行，温度18－21℃很快发芽，如果不需要大量繁殖，可采用分株繁殖为好。　\n　四、移栽\n　　移栽可春栽或秋栽，秋天和', 'http://img.boqiicdn.com/Data/BK/P/imagick87431441791786.jpg', 'http://www.boqii.com/entry/detail/2021.html', '');
INSERT INTO `plant_family` VALUES ('256', '筒叶花月', 'Crassula oblique ', '筒叶花月', '吸财树、玉树卷、马蹄角、马蹄红', '不容易死', '产于南非纳塔尔省', 'http://www.boqii.com/entry/photo/2136/0,http://www.boqii.com/entry/photo/2136/5391', '', '', '', '', '', '', '', '', '', '　　　　筒叶花月的植株呈多分枝的灌木状，茎明显，圆形，表皮黄褐色或灰褐色。叶互生，在茎或分枝顶端密集成簇　　　　　　　　　　　　　　　　　　', '　　筒叶花月是原种花月在长期栽培种产生的一个叶型特殊的变种，由于其叶片扭曲成筒状，故此命名。筒叶花月又名吸财树，是非常适合在室内栽培的小型多肉，那么如何才能养出漂亮的筒叶花月呢？　　筒叶花月喜温暖干燥和阳光充足的环境，耐干旱和半阴，不耐寒。除盛夏高温时要避免烈日曝晒外，其他季节都要给予充足的光照。筒叶花月为园艺变种，叶形奇特，色彩宜人，是理想的室内小型。　用大小与筒叶花月相当的花盆，盆土可选择疏松透气的配土，可适当增加点。　期浇水干透浇透。夏季高温注意遮阴，浇水选择晚上进行。冬季休眠期，盆土保持稍干燥。　　生长期施肥一般每月一次，用稀释饼肥水或用15－15－30盆花专用缓释肥。施肥过多，造成茎叶徒长，植株会提早老化。　　春季换盆时，进行疏剪造型，剪短长枝剪除密枝，促使分枝。', '　　筒叶花月的外形娇小可爱，是很多朋友都非常　\n　1、筒叶花月叶插\n　　取植株中下部成熟　　移栽的时候，尽量要带一些旧土，并且　\n　2、筒叶花月枝插\n　　剪取健康粗壮的枝条做插枝，在剪取前要将下部叶片去除，剪枝后待伤口皱缩再扦插，这样可以有效地防止扦插时烂茎，如果基部出现　\n　3、枝插繁殖\n', 'http://img.boqiicdn.com/Data/BK/P/imagick32471445505010.jpg', 'http://www.boqii.com/entry/detail/2136.html', '');
INSERT INTO `plant_family` VALUES ('257', '子孙球', 'Rebutia minuscula', '子孙球', '', '不容易死', '南美洲的高山地区', 'http://www.boqii.com/entry/photo/2369/0,http://www.boqii.com/entry/photo/2369/5047', '　　', '', '', '', '', '', '', 'Rebutia minuscula', '', '　　 　　子孙球为矮小扁球状仙人球。球体基部极易分生子球，常形成大型群生株，故得名子孙球。球体绿色。棱底由螺旋状排列的疣构成，疣的顶端为刺座，生有灰白色细短刺。花多，从球茎的中下部开出，漏斗状，鲜红色。花期3－5月，冰果。球体小巧玲珑，扁球形，其上无棱，而是许多螺旋状排列的疣状小突起，密被灰白色或黄色的的细短刺。花生于球体基部，花小但量大，并且鲜艳。', '　　子孙球原产于阿根廷及巴西南部，为多年生多浆肉质植物。子孙球在白天气孔会关闭，在夜间进行气体交换，释放氧气吸收二氧化碳，所以有净化空气的作用。　　家庭栽培子孙球可放在南阳台或南窗台，若过于荫蔽会使球细长，开花稀少甚至不开花，即是盛夏也不必遮光，但要通风良好。　　保持盆土湿润而不积水，浇水时不要从球顶淋水，以免水积存在球体顶部的“小坑”内，造成。每月施一次“低氮，高磷钾”的复合肥。冬季移至室内光线明亮处，维持8至10度的温度。节制浇水，使植株休眠，以使来年多开花。　　每年春季翻盆一次，翻盆时将根系剪去一半，晾2至3天后，栽入新的土中，培养土用园土、腐叶土（可用市售的)土代替）各1份，粗沙或蛭石2份混合配制，并掺入少量的骨粉、碎蛋壳等石灰质材料。橙红子孙球的繁殖可在掰取仔球，晾干伤口后进行扦插，成活率很高，但生长较为缓慢，开花也迟。为加快生长速度，早日开花，可用三棱箭（有称量天尺、三角柱）、草球等作砧木进行嫁接，效果很好。', '　　子孙球球体绿色，常形成大型群生株，花小但量大，加上子孙球富有寓意的名字，受到很多多肉爱好者的欢迎，在家中栽培子孙球的难度也不高，所以子孙球的普及率比较高。人工繁殖子孙球可以用播种及扦插的方法。　\n　一、播种\n　　球体于春、夏从基部开花，白天开放，朝开暮闭，可延续数日。浆果成熟后要及时采收洗去果肉，将黑色种子晒干收藏。播种可在4月下旬至5月上旬进行。播种时的天气以晴好为佳，昼夜温差大，不但出苗快，而且幼苗　　播种土可取用纯净的河砂、素砂土、纯腐叶土等。纯砂消毒容易，但保水性差，出苗后必须立即移植。土壤要严格消毒，可将土配好后装盆，然后连盆一起用蒸锅蒸1小时。　　播种盆宜用浅紫砂盆或釉盆，最好不用木盆。盆和盆底排水物都应洗净晾干再用。播种前2－－3天用0.3％的　　家庭也可用医用酒精进行消毒，但消毒时间要短，浸泡种子后必须尽快取出种子让酒精挥发掉。然后立即播种。可用细砂土混合后撒播，播后将土轻轻压平，浸水后盖上玻璃，将盆放在温暖而隐蔽处，种子开始出苗后，必须控制光照，将苗盆移至有遮荫的室内。播种苗　\n　二、扦插\n　　当子球长到足够大时，这时我们可以把爆出的小仔用手或工具掰下，放在阴凉处晾干，五月份以后晾一周就可以扦插。　　扦插用土，赤玉土、粗砂、炉渣各三份，再加上些活性炭或砻糠灰。花盆用4——5厘米的浅盆，小仔发根不需要过深的花盆，方便观察盆土的干湿度。把配置好的土壤由粗到细铺设至表面，用喷壶把土壤微微打湿，再把小仔整齐的码放在表面即可。　　看到盆土干后即使喷水，对于球体有绒毛的仙人球不要采用对小球直接喷水。由于土壤透水好，加之盆较浅，不宜积水，很容易促进小仔生根，大多数在半个月后会发根，而且保证新根', 'http://img.boqiicdn.com/Data/BK/P/imagick31081451379863.jpg', 'http://www.boqii.com/entry/detail/2369.html', '');
INSERT INTO `plant_family` VALUES ('258', '红千层', 'Stiff Bottle－brush', '红千层', '瓶刷木、金宝树', '不容易死', '澳大利亚、中国', 'http://www.boqii.com/entry/photo/2135/0,http://www.boqii.com/entry/photo/2135/5392', '植物界', '被子植物门', '双子叶植物纲', '桃金娘目', '桃金娘科', '红千层属', '红千层', 'Callistemon rigidus R. Br.', 'Callistemon rigidus', '　　 　　红千层为小乔木；树皮坚硬，灰褐色；嫩枝有棱，初时有长丝毛，不久变无毛。叶片坚革质，线形，长5－9厘米，宽3－6毫米，先端尖锐，初时有丝毛，不久脱落，油腺点明显，干后突起，中脉在两面均突起，侧脉明显，边脉位于边上，突起；叶柄极短。', '　　的树形小巧，无毒无害，在红千层的盛花季繁花似锦，凉爽宜人，对于园林有着别样的美。同时，红千层也是庭院观花、行道景观、小区绿化的首选树种，也有花友将红千层制成高档盆景，价格不菲。　　红千层栽培的土壤不能过湿，也不能过于干燥，土球成圆柱形为宜，切忌锅底形。要施好基肥，按土杂肥1：1施于底部，上加净土，避免根系与接触而灼伤。拆去土球包装物，将植株置于穴中，土球面与地面持平，然后分层填土夯实，使底部不存空隙，种后要立即灌透水。　　红千层虽然经过上述培育，能保存较为良好而又完整的须根。但移植后，水分的平衡也不会很快恢复正常，起苗前的修剪是减少水分蒸腾的有效措施。　　有利于保持植株体内水分平衡，特别是在炎热的移植，蒸发量大，修剪更为重要。所剪除枝叶，大约占全植株的三分之一左右，主要是内膛枝和刚抽出的嫩枝，在冬、春季移植，要保留好有花芽的顶枝，使移植后夏季便能开花，而收到绿化效果。　　红千层种后每天浇水1～2次，均应浇透土层，同时并对枝叶喷水，保持植株枝叶湿润，有降低水分蒸腾，保持植株体内水分平衡的重要作用。对枝叶喷水是种后能成活的又一重要环节。有些植株部分泥土散落，如加强对枝叶喷水，也能成活。　　施肥对植株迅速恢复长势，极为重要，种后15天可薄施一次氮肥，一个月后施一次优质有机肥每年花期过后，进行一次修剪和整枝，控制生长高度，树形美观，可促使萌发更多新枝开花。', '　　　　\n1、扦插法：\n　\n　2、播种法：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick40321445419771.jpg', 'http://www.boqii.com/entry/detail/2135.html', '');
INSERT INTO `plant_family` VALUES ('259', '文心兰', 'Dancing－Doll Orchid', '文心兰', '吉祥兰，跳舞兰、金蝶兰、瘤瓣兰、舞女兰', '不容易死', '巴西、美国、哥伦比亚、厄瓜多尔及秘鲁等国家', 'http://www.boqii.com/entry/photo/2391/0,http://www.boqii.com/entry/photo/2391/5025', '', '', '', '', '', '', '', '', '', '　　文心兰可分为薄叶种、厚叶种和剑叶种。文心兰是兰科中文心兰属 　　文心兰分布于墨西哥、巴西、牙买加等中南美热带地区。文心　　　　　　　　　　　　　　　　　　　　　　　　', '　　', '　　文心兰为复茎类洋兰，成株后都会长出子株，所以非常适合用分株的方法进行繁殖，此外，文心兰还可用组培的方法来繁殖。小编就为你简单介绍一下文心兰的这两种繁殖方法，　　\n一、分株繁殖\n　　春、秋季均可进行，常在春季新芽萌发前结合换盆进行分株最好。将带2个芽的假鳞茎剪下，直接栽植于水苔的盆内，保持较高的空气湿度，很快恢复萌新芽和长新根。　　\n二、组织\n　　选取文心兰基部萌发的嫩芽为外植体，用70％酒精进行表面', 'http://img.boqiicdn.com/Data/BK/P/imagick57221451983623.jpg', 'http://www.boqii.com/entry/detail/2391.html', '');
INSERT INTO `plant_family` VALUES ('260', '雷童', 'Delosperma echinatum', '刺叶露子花', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2252/0,http://www.boqii.com/entry/photo/2252/5273', '　　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '露子花属', '', 'Delosperma echinatum', '', '　　 　　雷童为多年生肉质草本植物，呈分枝密集的灌木状，高约30厘米，二歧分枝，老枝灰褐色或浅褐色，新枝淡绿色，上有白色小突起。肉质叶卵圆半球形，长1～1.3厘米，厚0.6～0.7厘米，基部合生，暗绿色，表皮具白色半透明的肉质刺，老叶的肉质刺常脱落，留下圆形疵状疤痕。花单生，具短梗，花很小，径仅1.2一1.5厘米，花白色或淡黄色。', '　　', '　　雷童　　雷童栽培中要避免长期雨淋，防止根部受损，枝条变黄　　雷童花的繁殖可在生长', 'http://img.boqiicdn.com/Data/BK/P/imagick12521448443502.jpg', 'http://www.boqii.com/entry/detail/2252.html', '');
INSERT INTO `plant_family` VALUES ('261', '大花蕙兰', 'Cymbidium', '大花蕙兰', '喜姆比兰、蝉兰、西姆比兰', '不容易死', '广西西南部、四川西南部、贵州西南部、云南和西藏东南部', 'http://www.boqii.com/entry/photo/1981/0,http://www.boqii.com/entry/photo/1981/5546', '', '', '', '', '', '', '', '', '', '　　 　　大花蕙兰是由兰属中的大花附生种、小花垂生种以及一些地生兰经过一百多年的多代人工杂交育成的品种群。世界上首个大花蕙兰品种为Cymbidium\'Eburneo－lowianum‘），是用原产于中国的独占春（C.eburneum）做母本，碧玉兰（C.lowianum）作父本，于1889年在英国首次培育而得。其后美花兰（C.insigne）、　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　大花是兰花中比较特别的，由于大花蕙兰的花朵硕大并且花色鲜艳，可以说是兰花中的新秀，深受人们的欢迎。有的花友可能会不知道如何养出品质优良的大花蕙兰，就让小编来告诉你。　　大花蕙兰喜强光，大花蕙兰原产亚洲热带和亚热带高原，性喜凉爽高湿的环境，生长适温为10－25℃，冬季应放在低温温室内管护，当夜间在10℃左右时长势良好，花茎正常伸长，多在2—3月开花。在冬季低于5℃时，叶片略呈黄色且花期推迟，花茎短。但温度在15℃左右时，则植株叶片绿且有光泽，开花提前到1－2月，以供应春节市场。非常喜湿，但要注意通风，否则易得炭疽病，小苗湿度应在80％至90％，中大苗湿度应在60％至85％。花径柔软，须竖以支柱支撑，保持直立状态。　生长期氮、磷、钾比例为1：1：1，催花期比例为1：2：2至3，肥液pH值为5.8至6.2。一般而言，小苗施肥浓度为3500至4000倍，中大苗为2000至3500倍，夏季1至2次／天（水肥交替施用），其他季节通常3天施一次肥。有机肥：从组培苗出瓶到开花前都要每月施一次有机肥，生长期豆饼：骨粉的比率为2：1，催花期施用纯骨粉。有机肥不能施于根上。骨粉如含盐量太大可先用水冲洗后再施用。冬季最好停止施用有机肥。　　生产上通常用喷灌，5月和9月每天浇一次水，7至8月份一天浇2次水，10月至次年4月每2至3天浇一次水。浇水次数视苗大小和天气状况随时调整。　（三年）春天3至6月夜温为15℃至20℃，日温为23℃至25℃。6至10月夜温为15℃至20℃，日温为20℃至25℃；11月以后夜温为10℃至15℃，日温为20℃。2至4月份每月施有机肥10克／盆（豆饼：骨粉2：1），4月以后每次施有机肥14克／盆。6至10月加大温差，平地栽培者一般要上山栽培，此间主要施骨粉，每盆15克左右，花芽出现后，立即停有机肥，11月后花穗形成，花箭确定后抹去所有新发生芽，大部分品种9至10月底可见花芽，如果长出叶芽应剥除。花箭用直径5毫米包皮铁丝作支柱，当花芽长到15厘米时竖起。绑花箭的最低部位为10厘米，间隔6至8厘米，支柱一般选择80厘米和100厘米长。　品种选择，要选用切花品种进行栽培。上山催花：第一次开花时切花栽培技术与盆栽相同，夏季6月份上山越夏催花，开放时剪切切花。植株于花后留芽2个以便来年开花用，以后不再上山。这种植株花期比上山的花期要晚，结果就相当于延长了供花期。　　花序开放20～30％为合适采收期，储存于2～5℃冷库中。切花用软纸包装，放入纸箱中运输。瓶插寿命可达30天以上。', '　　大花　　1、分株法。分株在开花后。新芽尚未长大之前的短暂　　2、作为生产种苗单位，可用植物组织培养方法，用极少量材料可繁殖大量的商品苗。', 'http://img.boqiicdn.com/Data/BK/P/imagick85241440496118.jpg', 'http://www.boqii.com/entry/detail/1981.html', '');
INSERT INTO `plant_family` VALUES ('262', '天狗之舞', '', '天狗之舞', '', '不容易死', '墨西哥，非洲', 'http://www.boqii.com/entry/photo/2364/0,http://www.boqii.com/entry/photo/2364/5052', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '青锁龙属', '天狗之舞', '', '', '　　 　　天狗之舞为多年生肉质草本植物，植株丛生，有', '　　为多年生肉质草本植物，叶片有点薄，绿色，叶缘为褐红色，当温差大且光照充足时，叶缘的褐红色会更加明显。人工栽培天狗之舞需要注意环境，天狗之舞原产于墨西哥，夏季高温会进入休眠期。　　天狗之舞具有冷凉季节，夏季高温休眠的习性。每年的9月至第二年的6月为植株的生长期。喜欢凉爽干燥、通风良好的环境。耐半阴，怕水涝，忌闷热潮湿。　用煤渣混合泥炭、少量珍珠岩，比例大概5：4：1，土表铺设小石头。　　较喜欢日照，可半阴养，阴养时间过长叶间距会变长，但不影响生长。而在阳光充足之处生长的植株，株型矮壮，茎节之间排列会紧凑。日常为绿色，日照时间增加后，叶边会慢慢变红。　对水分需求不多，过多水分容易发害（白粉病）及腐烂。夏季休眠注意减少浇水量，冬季可持续生长。　天狗之舞能耐零下2℃左右的低温，是室内的温度，非露天，再低叶片的顶端生长点就会出现冻伤，干枯，来年会在枯萎处重新萌发新侧枝。', '　　天狗之舞如果浇水过多会容易滋生病害，主要是白粉病、　　天狗之舞繁殖一般就是在　　叶片和叶片间容易长出很多小根。碰到合适的土壤就会把根牢牢扎在土里。砍头繁殖还有一个好处就是可以让母株得到更好的造型，有心的花友可以尝试尝试，砍头后的地方会重新萌发新的生长点，有的会萌发2个枝条。', 'http://img.boqiicdn.com/Data/BK/P/imagick48221451294704.jpg', 'http://www.boqii.com/entry/detail/2364.html', '');
INSERT INTO `plant_family` VALUES ('263', '光叶子花', 'Bougainvillea glabra', '光叶子花', '三角梅、三叶梅、毛宝巾、簕杜鹃、三角花', '不容易死', '原产巴西，中国引种栽培', 'http://www.boqii.com/entry/photo/2402/0,http://www.boqii.com/entry/photo/2402/5013', '植物　　', '被子植物门', '双子叶植物纲', '中央种子目', '紫茉莉科', '叶子花属', '光叶子花', 'Bougainvillea glabra', '', '　　光 　　光叶子花的花顶生枝端的3个苞片内，花梗与苞片中脉贴生，每个苞片上生一朵花；苞片3枚，叶状，紫色或洋红色，长圆形或椭圆形，长2.5-3.5厘米，宽约2厘米，纸质；花被管长约2厘米，淡绿色，疏生柔毛，有棱，顶端5浅裂；雄蕊6-8；花柱侧生，线形，边缘扩展成薄片状，柱头尖；瘦果有5棱。种子有胚乳。花盘基部合生呈环状，上部撕裂状。花期冬春间（广州、海南、昆明），北方温室栽培3-7月开花。', '　　一般在冬春季节开花，是园林绿化和庭院中非常重要的品种之一，由于光叶子花在室内难以栽培，所以往往是在开花时期买来放在室内观赏，开花后再阳光较强的阳台上栽培或露地栽培。　生长季节喜温暖，冬季保持凉爽，最低温度夜间7-10摄氏度。　喜强阳光，在华北地区春露地栽植于阳光直接照射到的地方，生长良好，冬季放在有阳光直接照到的室内。为了在10月开花，可以提前经过30?40天的短口照,效果较好。　　叶子花喜水但忌积水，每年栽植或上盆、换盆后浇1次透水，生长旺季每天上午喷水1次、下午浇水1次（下午4点以后浇）。生长时期的春夏秋季，应经常保持盆土中有充足的水分。尤其在夏季高温期，植株耗水量较大，有时1天要浇2次水。冬季适当减少浇水量，保持稍千。　　冬季室内加温期间和北方春季十分干燥，应经常向植株周围喷水，并少量向叶面喷水。　腐叶土或泥炭土加部分有机肥配成盆栽用土。生长时期每1?2周施1次液体肥料，秋季停止施肥。每年畚季换盆，并进行修剪。', '　　由于光　　要快速繁殖光叶子花，一般选用压条的方式繁殖；每年5月初到6月中旬进行，每次压条约一个月左右；在光叶子花母株上选择筷子头以上粗细的健壮枝条，估计处于营养钵中心位置的枝条部位，用小刀对枝条进行环切，去掉一圈树皮，深度要达到木质部，露出木质部，将营养钵套在枝条上，再用木棒扎成三角架固定，填入干湿适度的泥土，最后浇透水。', 'http://img.boqiicdn.com/Data/BK/P/imagick45301452156489.jpg', 'http://www.boqii.com/entry/detail/2402.html', '');
INSERT INTO `plant_family` VALUES ('264', '樱水晶', 'Haworthia cooperi var. picturata', '', '', '不容易死', '南非', 'http://www.boqii.com/entry/photo/2443/0,http://www.boqii.com/entry/photo/2443/4973', '', '', '', '', '百合科', '十二卷属', '', '', '', '　　 　　樱水晶的肉质叶呈紧凑的莲座状排列，叶片肥厚饱满，翠绿色，上半段呈透明或半透明状，有深色的线状脉纹，在阳光较为充足的条件下，其脉纹为褐色，叶顶端有', '　　樱水晶的叶片晶莹剔透，和玉石雕刻一样，受到很多多肉爱好者的喜爱。但是新手朋友们对于樱水晶和三角琉璃莲会分不清楚，其实这两个植物仔细还是会发现很多不同的。樱水晶的栽培难度不高，小编就为你介绍一下樱水晶的栽培要点。　　樱水晶对日照需求不多，温暖干燥的半阴环境，夏季高温时要避免烈日暴晒。樱水晶喜凉爽的半荫环境，主要生长期在春、秋，耐干旱，不耐寒，忌高温潮湿和烈日暴晒，怕荫蔽，也怕土壤积水。　　多肉樱水晶，喜阳或温暖干燥的半阴环境，耐干旱，怕积水。要求有一定的空气湿度，春、秋季节的生长期浇水掌握“见干见湿”，空气干燥时向植株喷水，以增加空气湿度，使叶片肥美，每月施一次薄肥。夏季高温时避免烈日暴晒，注意通风良好。冬季给予充足的光照，室内保持盆土干燥在宁波可。盆土要求疏松肥沃，透气性良好，并有一定的颗粒度。', '　　樱水晶是比较容易养护的多肉　\n　一、分株\n　　可结合换盆进行，也可在生长季节挖取母株旁边的幼株，有根或无根都能成活，有根可直接栽种，无根的苗要晾1～2天，等伤口干燥后再种植，新栽的植株浇水不宜过多，以免引起　\n　二、扦插\n　　樱水晶在植株下部的叶腋会长出幼芽，对于不易生幼芽的　\n　三、叶插\n　　可选择健壮充实的樱水晶肉质叶，生长期在', 'http://img.boqiicdn.com/Data/BK/P/imagick74351453367683.jpg', 'http://www.boqii.com/entry/detail/2443.html', '');
INSERT INTO `plant_family` VALUES ('265', '刺桐', 'Erythrina variegata Linn.', '刺桐', '海桐(详情介绍)、山芙蓉、空桐树、木本象牙红', '不容易死', '原产热带亚洲，中国福建、广东、海南、台湾、江苏等地均有栽培。', 'http://www.boqii.com/entry/photo/2116/0,http://www.boqii.com/entry/photo/2116/5411', '', '', '', '', '', '', '', '', '', '　　刺桐为豆科、刺桐属 刺桐 　　刺桐是落叶大乔木，高可达20米。树皮灰褐色，枝有明显叶痕及短圆锥形的黑色直刺，髓部疏松，颓废部分成空腔。羽状复叶具3小叶，常密集枝端；托叶披针形，早落；叶柄长10－15厘米，通常无刺；小叶膜质，宽卵形或菱状卵形，长宽15－30厘米，先端渐尖而钝，基部宽楔形或截形；基脉3条，侧脉5对；小叶柄基部有一对腺体状的托叶。　　　　　　　　　　　　　　　　　　　　　　　　', '　　是我国泉州的市花，而“刺桐城”也是泉州市的别称。刺桐喜强光照，高温、湿润的环境以及排水良好的肥沃沙壤土。刺桐在每年的花期，花色鲜红并且花形和相似，非常受人欢迎。　　刺桐适合于阳光充足，温度高而通风较好的环境；须见干见湿，但不宜涝。不耐寒，10月下旬人室，温度保持15℃左右，不能低于4℃，并应注意控制水分。耐瘠薄、对土壤要求不严，盆栽可用蹄角片作底肥，每隔2－3周追施一次豆饼液肥，薄肥勤施。在露地栽培中，幼龄树应注意修剪，以养成圆整树形。盆栽宜选规格稍大的盆，温室盆栽可用大缸。刺桐的根木质化程度高，须根少，如盆土排水不良或盆土积水，极易烂根，故应以疏松肥沃的砂质壤土作上，忌用排水不良的粘质土壤。上盆或换盆时，一般中等植株每盆应施用100～150g蹄角片作底肥。从5～9月，应每半月追施一次腐熟有机液肥。刺桐不喜大水，盆土以经常保持半干半湿为好。夏季气温高，蒸发量大，可每天浇一次水。炎热的夏季，需放置室外半荫处。冬季一般可每2～3天浇一次水。入室前修剪抹头的植株，可每10～15天浇一次水。老龄植株要适当截干，以利调整株形。对生跃过长的枝条，可在花后采取摘心的办法控制枝长势，也可将开过花的枝条从基部剪除，萌生的枝条开花更为繁茂。每年春季进行换盆。　　刺桐于春、秋季剪取枝条，长10～15厘米，进行温床砂插，后遮阳，注意浇水保湿，极易生根成苗。温室盆栽需用大盆，春、夏要求水分充足，通风透光。过分炎热应放置半阴处培育。5～8月每隔2周施液肥1次。冬季要控制浇水，盆土湿润即可。老龄植株，要适当截干，重发枝叶后，调整树形。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick41451444730476.jpg', 'http://www.boqii.com/entry/detail/2116.html', '');
INSERT INTO `plant_family` VALUES ('266', '钓钟柳', 'Penstemon campanulatus', '钓钟柳', '象牙红', '不容易死', '原产墨西哥及危地马拉', 'http://www.boqii.com/entry/photo/2304/0,http://www.boqii.com/entry/photo/2304/5220', '植物　　', '', '', '', '玄参科', '钓钟柳属', '', 'Penstemon campanulatus', '', '　　 　　钓钟柳为多年生常绿草本，株高15－45cm。圆锥形花序，钟状花，混色，茎光滑，稍被白粉。全株被绒毛，叶对生，基生叶卵形，茎生叶披针形。花单生或3～4朵生于叶腋与总梗上，呈不规则总状花序，花冠筒长约2。5cm，组成顶', '　　为多年生常绿草本，花期为4－5月，非常适合种植在园林绿化的花坛、花境中。红花钓钟柳原产于美国犹他州至墨西哥一带，是被墨西哥当地居民认可的一种草药。　　钓钟柳喜阳光充足、空气湿润、通风良好的环境，不耐寒，忌炎热干燥和酸性土壤，且必须排水性能良好，含石灰质的肥沃砂质壤土。稍耐半阴，要求排水良好的土壤。　　钓钟柳花色鲜丽，花期长，适宜花境种植，与其他蓝色宿根配置，可组成极鲜明的色彩景观。也可盆栽观赏。同属约250种，常见栽培的有红花钓钟柳（P.barbatus）；堇花钓钟柳（P.hirsutus）等。', '　　钓钟柳花色艳丽，并且花期较长，是很多花友都非常喜欢的　\n　1、播种繁殖\n　　多在秋季进行，种子采收后即可播种。幼苗期娇嫩，需要注意保持基质湿润，经常洒水或浸盆。播种繁殖较易发生变异，因此许多优良品种一般不采用此法。　\n　2、扦插繁殖\n　　优良品种可于秋季进行扦插繁殖，扦插可于10月进行。选择生长强健的花后嫩枝梢，剪成长约10cm左右的插穗，切口部位用　\n　3、分株繁殖\n　　多选择在春季。在母株刚露新芽的几天内，掘起母株土坨或脱盆，根据萌芽确定新分植株，用刀将新株与母体割离，直接定植。定植后浇透水，可很快扩大根系长成可观植株。栽培', 'http://img.boqiicdn.com/Data/BK/P/imagick87611449653386.jpg', 'http://www.boqii.com/entry/detail/2304.html', '');
INSERT INTO `plant_family` VALUES ('267', '孔雀竹芋', 'Calathea makoyana', '孔雀竹芋', '蓝花蕉、五色葛郁金', '不容易死', '原产于热带美洲及印度洋的岛域中', 'http://www.boqii.com/entry/photo/2053/0,http://www.boqii.com/entry/photo/2053/5474', '', '', '', '', '', '', '', '', '', '　　孔雀 　　孔雀竹芋为多年生常绿草本。高30～60厘米，叶长15～20厘米，宽5～10厘米，卵状椭圆形，叶薄，革质，叶柄紫红色。绿色叶面上隐约呈现金属光泽，且明亮艳丽，沿中脉两侧分布着羽状、暗绿色、长椭圆形的绒状斑块，左右交互排列。叶背紫红色。　　　　　　　　　　　　　　', '　　原产于美洲，人工栽培难度不高，并且不耐光照，所以非常适合在室内栽种。并且，孔雀竹芋还是清除空气中氨气的高手，能改善空气质量。　　孔雀竹芋盆栽宜用疏松、肥沃、排水良好、富含腐殖质的微酸性壤土，一般可用腐叶土3份、泥炭或锯末1份、砂1份混合配制，并加少量豆饼作基肥，忌用粘重的园土。上盆时盆底先垫上3厘米厚的粗砂作排水层，以利排水。　　期要给予充足的水分，尤其夏秋季除经常保持盆土湿润外，还须经常向叶面喷水，以降温保湿；它要求有较高的空气湿度，最好能达到70％至80％；忌空气干燥、盆土发干，但不能积水。秋末后应控制水分，以利抗寒越冬。冬季保持干燥的环境，过湿则基部叶片菱黄枯焦，影响其观赏价值。　　孔雀竹芋缺肥时植株明显矮小，叶色暗淡，金色光泽不艳。生长期每20天施稀薄液肥一次，氮磷钾比例应为2∶1∶1，可使叶色光泽艳丽，切忌氮肥比例过大，如平时每隔10天用0。2％的液肥直接喷洒叶面，对萌芽和生长均极为有利。冬季和夏季停止旋肥。　　5—9月生长季要置于阴蔽或半阴处，保持40％－60％的透光率，避免烈日直射，光照过强或空气干燥容易造成叶缘叶尖枯焦、叶面暗淡无光；但光线也不宜太弱，若长时期放在阴暗室内，低、光照不足，也会长势衰弱，不利叶色形成，失去叶面特有的金属光泽。冬季可接受通过玻璃的直射阳光。　　雀竹芋喜高温、湿润，生长适温为18℃－25℃，喜空气湿润，在20℃以上的5月－10月生长最快，在每年10月至翌年4月低温季节，北方应移入温室越冬，冬季越冬温度不宜低于15℃，否则叶色暗，叶片卷缩，叶尖发黄，如受冻轻微，及时改变环境条件，来春仍能发出新叶，如受冻严重叶子先后枯死，甚至全株死亡。如室内昼夜大可用塑料薄膜套盆或用玻璃箱保温保湿，每月并用温水清洗叶面一次，以保持叶片的色泽。', '　　孔雀　　孔雀竹芋的繁殖可采用分株、扦插、组织培养等方法进行。其中常规繁殖常采用分株繁殖。分株繁殖春秋两季皆可进行，但以春季结合换盆较好。分出的每个子株都要保留5片叶片。分切后立即将盆置于阴凉处，一周后移至光线较好的地方，初期应控制浇水，待发出新根后再充分浇水。孔雀竹芋采用根茎扦插时，将根茎从根茎的茎节处用利刀切下，每段保持1～2个节，分切后立即将盆置于阴凉处，1～2周能形成新根。　　孔雀竹芋用分株繁殖。一般多于春末夏初气温20℃左右时结合换盆换土进行。气温太低时分株容易伤根，影响成活或使　　孔雀竹芋丰要用分株和组织培养法繁殖。分株繁殖以春末夏初为好，分株时每个子株至少要保留5个叶片和较多的根系，否则会影响成活和成活后的', 'http://img.boqiicdn.com/Data/BK/P/imagick82831442568772.jpg', 'http://www.boqii.com/entry/detail/2053.html', '');
INSERT INTO `plant_family` VALUES ('268', '虹之玉锦', 'Sedumrubrotinctumcv.‘Aurora', '虹之玉锦', '虹之玉', '不容易死', '', 'http://www.boqii.com/entry/photo/2146/0,http://www.boqii.com/entry/photo/2146/5381', '　', '被子植物门 （Magnoliophyta）', '双子叶植物纲 （Dicotyledoneae）', '蔷薇目 （Rosales）', '景天科 Crassulaceae', '景天属 Sedum', '虹之玉', 'Sedumrubrotinctumcv.‘Aurora\'', '', '　　 　　虹之玉锦为多年生多浆肉质草本', '　　是虹之玉的锦化品种，由于虹之玉锦是向上的植物，所以很容易长成怒放的姿态，非常漂亮，很多多肉爱好者也因为这个而选择栽种虹之玉锦。　　虹之玉锦喜温暖、干燥和光照充足的环境，耐旱性强，要求质地疏松、排水良好的沙壤土。在冬季温暖、夏季冷凉的气候条件下生长良好。为热带喜阳光、耐干旱的植物。不耐寒，冬季最底需在10度以上。要求排水好的土壤。　　栽种虹之玉锦应选择疏松肥沃、排水良好的沙壤土作。生长适量浇水，夏季湿热的条件下要控制浇水，加强通风，注意遮荫，保持较为冷凉的环境。冬季要放在冷凉室内，温度一般不超过10℃，并减少浇水，保持盆土稍干燥。', '　　很多喜欢多肉的朋友们一定都知道　　虹之玉锦常用扦插繁殖。于生长', 'http://img.boqiicdn.com/Data/BK/P/imagick4241445850207.jpg', 'http://www.boqii.com/entry/detail/2146.html', '');
INSERT INTO `plant_family` VALUES ('269', '软枝黄蝉', 'Allamanda cathartica L.', '软枝黄蝉', '黄莺、小黄蝉、重瓣黄蝉、泻黄蝉、软枝花蝉', '不容易死', '原产于巴西等地，中国南方（含台湾）有引种', 'http://www.boqii.com/entry/photo/2310/0,http://www.boqii.com/entry/photo/2310/5213', '　', '被子植物门', '双子叶植物纲', '捩花目', '夹竹桃科', '黄蝉属', '软枝黄蝉', 'Allamanda cathartica L.', '', '　　软枝 　　软枝黄蝉为藤状灌木，长达4米；枝条软弯垂，具白色乳汁。叶纸质，通常3－4枚轮生，有时对生或在枝的上部互生，全缘，倒卵形或倒卵状披针形，端部短尖，基部楔形，无毛或仅在叶背脉上有疏微毛，长6－12厘米，宽2－4厘米；叶脉两面扁平，侧脉每边6－12条；叶柄扁平，长约2－8毫米，基部和腋间均具腺体。', '　　软枝)的花期为6－10月，花期较长，花色鲜艳，在我国南部，几乎整年皆可开花。软枝黄蝉的人工栽培难度不高，非常适合观赏，小编就为你介绍一下软枝黄蝉的栽培要点。　　软枝黄蝉的生长环境性喜高温多湿，为阳性因此栽培处需全日照。一般采用扦插法繁殖，春、秋两季为适期。土壤以排水良好之砂质壤土或腐叶土生育最佳。水分的重点为保持土壤略湿润即可。　　软枝黄蝉原产热带美洲，再高温高湿环境，喜光、畏烈日，不耐寒，宜肥沃排水良好的酸性上，盆栽软枝黄蝉春季出房后，置房屋北面等半阴湿润处，对枯枝、弱枝、扰乱树形的枝条宜进行一次修剪或短裁，并加施几次肥水，促进新技萌发，如植株较高，下部脱脚，可将根部的萌蘖条适当保留并摘心，以逐步替代更新老株。平时烧水不待干透即浇，并要经常向植株及其周围喷水，提高环境湿度。生长季7一10天施肥1次，以粪肥和过磷酸钙交替使用，保证枝条生长充实，花期持久。冬季入室后，室温宜保持10℃以上，盆土也要较湿润。若过低或干湿不当，均会导致叶片脱落。', '　　软枝　　软枝黄蝉一般使用扦插繁殖，春、秋选取1～2年生充实枝条，剪成15－20cm长、带有3～4个节的插穗插于素砂土中，放在光线明亮处，经常保持湿润，在20℃气温条件下约20天生根。苗高10cm时，可摘心移植或上盆。值得注意的是，将插条从母株剪下后，必须等切口的乳汁完全干燥，始可插入砂床，否则成活率不高。', 'http://img.boqiicdn.com/Data/BK/P/imagick56571449741113.jpg', 'http://www.boqii.com/entry/detail/2310.html', '');
INSERT INTO `plant_family` VALUES ('270', '鹅掌藤', 'Schefflera arboricola Hay.', '鹅掌藤', '七叶莲，七叶藤，七加皮，汉桃叶，狗脚蹄', '不容易死', '泉州、漳州、海口、三亚', 'http://www.boqii.com/entry/photo/2198/0,http://www.boqii.com/entry/photo/2198/5329', '植物　', '被子植物门', '单子叶植物纲', '伞形目', '五加科', '属', '鹅掌藤', 'Schefflera arboricola Hay.', 'Scheffera arboricola', '　　 　　鹅掌藤为藤状灌木，高2～3米；小枝有不规则纵皱纹，无毛。叶有小叶7～9，稀5～6或10；叶柄纤细，长12～18厘米，无毛；托叶和叶柄基部合生成鞘状，宿存或与叶柄一起脱落；小叶片革质，倒卵状长圆形或长圆形，长6～10厘米，宽1.5～3.5厘米，先端急尖或钝形，稀短渐尖，基部渐狭或钝形，上面深绿色，有光泽，下面灰绿色，两面均无毛，边缘全缘，中脉仅在下面隆起，侧脉4～6对，和稠密的网脉在两面微隆起；小叶柄有狭沟，长1.5～3厘米，无毛。', '　　又名鸭脚木等，为常绿木质藤本，鹅掌藤的枝叶柔美，色彩清雅，常被人用来盆栽放在厅堂、门廊、会场等处，在南方常被用作园林彩色或造型。鹅掌藤的栽培难度并不高，就让小编为你介绍一下鹅掌藤的栽培要点。　　鹅掌藤性喜高温多湿和半阴的环境。适温20一3090，越冬温度要求5℃以上，0℃以下叶片易脱落。耐阴，忌强光直射。耐旱性强，土壤以疏松肥沃、排水良好的壤土或沙质壤土为佳。　　盆栽土可用腐叶土和园土等U混合配制。每年春季新芽萌发前换1次盆，去掉部分旧土，增加新的土及施入少LIFP－基肥。对过于庞大的老株进行重剪更新，即去掉大部分枝条并把根部切去一部分。重新上盆。生长期土壤保持湿润，夏季要结合叶面喷水，保持较高的空气湿度。适当遮荫，在通风良好的半阴环境下，植株长势良好。若土壤太湿或于早，或长期放置在过于阴暗处，会引起叶片大脱落。每年3－9月是生长旺季，可每月追1一2次腐化的有机肥。有黄、白斑纹的若光照太弱或偏施氮肥会使其斑纹模糊。冬季低温下要适当控水，置于室内阳光充足处。', '　　　　鹅掌藤可用扦插及压条繁殖。扦插繁殖，5－6月份选取健壮成熟的枝条，截成8一10厘米长，剪除部分叶片，插人沙床，适当遮荫，保持湿润，4一6周即可生根。压条繁殖，选取中熟枝条环状剥皮，伤口用湿润的水苔包裹，外面再裹上塑料薄膜，两端扎紧，防止水分蒸发，待愈伤组织生根，即可剪下，单独栽植。', 'http://img.boqiicdn.com/Data/BK/P/imagick42181447060021.jpg', 'http://www.boqii.com/entry/detail/2198.html', '');
INSERT INTO `plant_family` VALUES ('271', '羽叶薰衣草', 'Plantae', '羽叶薰衣草', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2249/0,http://www.boqii.com/entry/photo/2249/5276', '', '', '', '', '', '', '', '', '', '　　羽叶 　　羽叶薰衣草叶形为二回羽状深裂叶，香味较淡；叶对生，叶子表面覆盖粉状物，叶色灰绿。植株开展，茂盛的灌木，花深紫色的管状小花，有深色纹路，上唇比下唇发达，具2唇瓣。香味类似于　　　　　　　　　　　　', '　　一般四季均开花，但是主要的花期集中在11月至第二年5、6月。羽叶薰衣草不但可以用于观赏，泡茶、制作糕点也是不错的原料，有着镇定情绪的作用。那么人工栽种羽叶薰衣草应该注意哪些呢？　　1、土壤：羽叶薰衣草根部不耐积水，因此，养殖羽叶薰衣草的土壤要求排水透气良好，最适用泥炭土。　　2、浇水：羽叶薰衣草喜干燥环境，不耐潮湿，家庭养殖切忌经常浇水，盆土或地面不能积水，应保持通风。浇水的原则是“见干见湿”。一般冬、春季约3、5天一次，夏季则可一天一次。浇水时要注意，水不要直接浇到叶片上，也不要让泥土溅到枝叶上，以免产生病害。　　3、光照：羽叶薰衣草为长日照植物，适合在阳光充足、通风良好的环境养殖。光照对羽叶薰衣草和芳香油的形成有极重要的作用，过分遮光会造成徒长，同时易感病，但酷暑的时候最好能做一些遮阴的处理，避免烈日直射。　　4、施肥：羽叶薰衣草对的要求不高，在其迅速的春季，可按月追施氮、磷、钾复合肥，配制溶液浇灌，浓度1％即可。过多的氮肥易造成徒长。　　5、修剪：羽叶薰衣草应随时将未开花的花苞茎剪下，促使新芽簇簇生长，第二年可有欣欣向荣的茂盛景象。', '　　羽叶　　\n一、扦插繁殖\n　　扦插一般在春、秋季进行。夏季嫩枝扦插也可。扦插的介质可用2／3的粗砂混合1／3的泥炭苔。选择发育健旺的良种植株，选取节距短粗壮且未抽穗的一年生半木质化枝条顶芽，于顶端8～10cm处截取插穗。插穗的切口应近茎节处，力求平滑，勿使韧皮部破裂。将底部2节的叶片去除，插水2小时后再扦插于土中，约2～3星期就会发根。也可选8～10cm的一年生枝条，在排水良好，保持湿润，20～24℃床温的条件下，约40天左右生根。不要用已出现花序的顶芽扦插，因为开花的枝条已老化，会发根不良影响将来长势。地膜扦插，整地做畦。浇透水后覆膜，立即扦插。深5～8厘米，行距20～25cm。注意提高地温，促进根系发育；勤修剪延伸枝，及时摘除花穗，促进分枝，培育壮苗。定植株距60cm，行距120cm。栽后立刻浇水。　　\n二、分株繁殖\n　　春、秋季均可进行，用3－4年生植株，在春季3－4月用成株老根分割，每枝带芽眼。', 'http://img.boqiicdn.com/Data/BK/P/imagick83571448357876.jpg', 'http://www.boqii.com/entry/detail/2249.html', '');
INSERT INTO `plant_family` VALUES ('272', '蓝花楹', 'Jacaranda mimosifolia D. Don', '蓝花楹', '含羞草叶蓝花楹 、蓝雾树、巴西紫葳、紫云木', '不容易死', '原产巴西，中国南部多有引种', 'http://www.boqii.com/entry/photo/2031/0,http://www.boqii.com/entry/photo/2031/5496', '植物　　', '被子植物门', '双子叶植物纲', '管状花目', '紫葳科', '蓝花楹属', '', 'Jacaranda mimosifolia D. Don', '', '　　 　　蓝花楹叶对生，为2回羽状复叶，羽片通常在16对以上，每1羽片有、小叶16－24对；小叶椭圆状披针形至椭圆状菱形，长6－12毫米，宽2－7毫米，顶端急尖，基部楔形，全缘。花蓝色，花序长达30厘米，直径约18厘米。花萼筒状，长宽约5毫米，萼齿5。', '　　在开花时非常漂亮，对于土壤的要求也不严，适合栽种在阳光充足的地方。蓝花楹不但可以观赏，其枝干还可以制作成家具，经济价值非常高，是一种难得的珍奇木本。　　　　蓝花楹原产于美洲热带，喜温暖湿润、阳光充足的环境，不耐霜雪。适宜生长22至30℃，若冬季气温低于15℃，生长则停滞，若低于3至5℃有冷害，夏季气温高于32℃，生长亦受抑制。喜光，能耐半阴。　　　　蓝花楹原产于美洲热带，喜温暖湿润、阳光充足的环境，不耐霜雪。适宜生长温度22至30℃，若冬季气温低于15℃，生长则停滞，若低于3至5℃有冷害，夏季气温高于32℃，生长亦受抑制。喜光，能耐半阴。　　　　喜肥沃湿润的沙壤土或壤土，定植时要施足基肥，成活后春秋两季各需追肥1次，每年早春进行一次修剪整枝，老化的植株需施以重剪。盆栽时，可截干或嫁接矮化，并控制浇水及施用氮肥。', '　　　　蓝花楹用播种、扦插、组织', 'http://img.boqiicdn.com/Data/BK/P/imagick64561441965839.jpg', 'http://www.boqii.com/entry/detail/2031.html', '');
INSERT INTO `plant_family` VALUES ('273', '桃金娘', 'Rhodomyrtus tomentosa', '桃金娘', '山菍、多莲、当梨根、稔子树、豆稔、仲尼、乌肚子、桃舅娘、当泥', '不容易死', '产中国南部各省；多生于丘陵灌丛中及荒山草地中', 'http://www.boqii.com/entry/photo/2068/0,http://www.boqii.com/entry/photo/2068/5459', '植物　　', '被子植物门', '双子叶植物纲', '桃金娘目', '桃金娘科', '桃金娘属', '桃金娘', 'Rhodomyrtus tomentosa', '', '　　 　　桃金娘为灌木，高1－2米；嫩枝有灰白色柔毛。叶对生，革质，叶片椭圆形或倒卵形，长3－8厘米，宽1－4厘米，先端圆或钝，常微凹入，有时稍尖，基部阔楔形，上面初时有毛，以后变无毛，发亮，下面有灰色茸毛，离基三出脉，直达先端且相结合，边脉离边缘3－4毫米，中脉有侧脉4－6对，网脉明显；叶柄长4－7毫米。', '　　桃金娘的花期为夏季，在开花的时候灿若红霞，非常漂亮，并且桃金娘的花期特别长，为4－9月，边开花边结果。但很多朋友碍于环境的因素，没办法自己动手栽种桃金娘，小编就为你介绍一下桃金娘的栽种方法，有兴趣的朋友可以一起来了解。　　　湿润的气候环境，要求环境的空气相对温度在70～80％，空气相对湿度过低，下部叶片黄化、脱落，上部叶片无光泽。　　由于它原产于热带地区，喜欢高温高湿环境，因此对冬季的温度的要求很严，当环境温度在10℃以下停止生长，在霜冻出现时不能安全越冬。　　在夏季：　　1、加强空气对流，以使其体内的温度能散发出去；　　2、放在半荫处，或给它遮荫50％；　　3、给它适当喷雾，每天2～3次。　　在冬季：　　1、搬到室内光线明亮的地方养护；　　2、在室外，可用薄膜把它包起来越冬，但要每隔两天就要在中午温度较高时把薄膜揭开让它透气。　　　喜欢半荫环境，在秋、冬、春三季可以给予充足的阳光，但在夏季要遮荫50％以上。放在室内养护时，尽量放在有明亮光线的地方，如采光良好的客厅、卧室、书房等场所。在室内养护一段后（一个月左右），就要把它搬到室外有遮荫（冬季有保温条件）的地方养护一段时间（一个月左右），如此交替调换。　　　对于盆栽的植株，除了在上盆时添加有机外，在平时的养护过程中，还要进行适当地肥水。　　春、夏、秋三季：这三个季节是它的生长旺季，肥水管理按照“花宝”——清水——“花宝”——清水顺序循环，间隔周期大约为1～4天。　　冬季：在冬季休眠期，主要是做好控肥控水工作，肥水管理按照“花宝”——清水——清水——“花宝”——清水——清水顺序循环，间隔周期大约为3～7天，晴天或高温期间隔周期短些，阴雨天或低温期间隔周期长些或者不浇。对于地栽的植株，春夏两季根据干旱情况，施用2～4次肥水：先在根颈部以外30～100公分开一圈小沟（植株越大，则离根颈部越远），沟宽、深都为20公分。沟内撒进25～50斤有机肥，或者1～5两颗粒复合肥（化肥），然后浇上透水。入冬以后开春以前，照上述方法再施肥一次，但不用浇水。', '　　桃金娘高可达2米，开花的时候非常漂亮，其果实也是鸟类的天然食源，并且全株可供药用，能活血通络。一般家庭养殖桃金娘的非常少，在园林绿化、生态环境建设中能看到桃金娘的身影。桃金娘可使用播种机扦插的方法进行繁殖，小编就为你介绍一下。', 'http://img.boqiicdn.com/Data/BK/P/imagick41821443002166.jpg', 'http://www.boqii.com/entry/detail/2068.html', '');
INSERT INTO `plant_family` VALUES ('274', '若歌诗', 'Crassula Rogersii', '若歌诗', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2272/0,http://www.boqii.com/entry/photo/2272/5253', '', '', '', '', '', '', '', '', '', '　　 　　若歌诗茎细柱状，淡绿色，冷凉　　　　　　　　　　', '　　四季碧绿，形如石松，植株娇小，非常适合盆栽，放在茶几、案头点缀环境。若歌诗的人工栽培难度并不高，对于环境的要求也不严，小编就为你简单介绍一下若歌诗的栽培要点。　　若歌诗喜温暖干燥和阳光充足环境。怕低温和霜雪，耐半阴。对土壤要求不严，以泥炭土加粗沙为好。冬季不低于5℃。　　适温15－25度，冬季不低于5度；　配土一般可用泥炭、和珍珠岩的混合土，也可用泥炭和粗沙的混合土；　生长期浇水一般干透浇透，梅雨季和高温季一般每周浇水1－2次即可，冬季保持盆土干燥；　生长期施肥一般每2月一次。', '　　　　若歌诗繁殖叶插比较难存活，主要用扦插繁殖，全年均能进行，以春、秋季生根快，成活率高。剪掉', 'http://img.boqiicdn.com/Data/BK/P/imagick50671448960398.jpg', 'http://www.boqii.com/entry/detail/2272.html', '');
INSERT INTO `plant_family` VALUES ('275', '新几内亚凤仙', 'Impatiens  hawkeri', '新几内亚凤仙', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2325/0,http://www.boqii.com/entry/photo/2325/5197', '植物　', '被子植物门', '双子叶植物纲', '()目', '凤仙花科', '凤仙花属', '新几内亚凤仙', 'Impatiens  hawkeri', '', '　　 　　新几内亚凤仙为', '　　如果在温度适宜的环境下可一年四季开花不断，新几内亚凤仙是园艺杂交品种，色彩鲜艳。需要注意的是，新几内亚凤仙怕冷，如果遇霜则会全株枯萎。　新几内亚凤仙性喜温暖和光照充足，不耐寒冷，忌烈日曝晒，在20度左右，超过25℃以上则花会变小，超过30℃则必须提高相对湿度才可以使植株持续生长。温度比较低时，植株生长停顿，气温降到7℃以下就会受冻害。　喜湿润怕干旱，忌水涝。水份不足时易造成落花落叶的现象。对土壤适应性强，酸碱度pH值应控制在5.5至6.5之间。宜用腐叶土、菜园土、沙，按5∶3∶2混合成疏松、肥沃透气性好的沙质土。盆不宜过大。盆土要见干见湿，见干即浇，浇至盆底出水即止，渍水会烂根，过干会枝叶枯落。家庭最重要的一环是保持一定的空气湿度，宜常向植株喷水。　新几内亚凤仙花期长，平时需要的养分多，苗期时可适当施点氮肥。生长期、花期10天至15天应施一次氮磷钾复合肥，忌单施氮肥，否则会叶多花少，施肥时如果不小心将肥沾在叶片上，要及时喷水洗掉。', '　　　\n　1、扦插\n　　易生根，成苗快，花色一致，是目前的主要繁殖方式。扦插的具体方法是：从母株上剪取6厘米左右长的枝条，留4片叶，去除其余叶片插于沙土或　　\n2、播种繁殖\n　　可用草炭土和沙土按3：1混合后', 'http://img.boqiicdn.com/Data/BK/P/imagick28351450171861.jpg', 'http://www.boqii.com/entry/detail/2325.html', '');
INSERT INTO `plant_family` VALUES ('276', '卡特兰', 'Cattleya Hybrida', '卡特兰', '嘉徳利亚兰、嘉德丽亚兰、加多利亚兰、卡特利亚兰', '不容易死', '原产热带美洲', 'http://www.boqii.com/entry/photo/2403/0,http://www.boqii.com/entry/photo/2403/5012', '', '', '', '', '', '', '', '', '', '　　 　　卡特兰属常绿，假鳞呈棍棒状或圆柱状，假鳞茎呈纺锤形，株高25厘米以上；一茎有叶2至3枚，叶片厚实呈长卵形。一般秋季开花一次，有的能开花2次，一年四季都有不同卡特兰　　　　　　　　　　　　　　', '　　卡特兰在国际上都非常有名，由于其花大、花色艳丽多变，并且开花后芳香馥郁，受到很多花友们的喜爱。在我国，卡特兰的栽培时间不长，但是现在在市场上却有着很高的，也是节庆的时候送给亲朋好友的重要花卉之一。　　　要栽培好卡特兰首先要有一个适宜的场地和优秀的环境条件，不能靠近有空气污染的工矿区左近和通风差、辐射热强的高层建筑林立处。由于卡特兰是附生性兰花，不合适放在泥地和水泥空中上养护，需求一个避免盆钵倾倒的台架或垂吊的挂架，以及冬季温度不低于12℃的室内环境。　　盆栽基质的准备，卡特兰假鳞茎和叶片肥厚，气生根旺盛，通常需用排水良好、疏松勇气的栽培基质，运用较多的有水苔、蕨根（常用蕨类植物紫箕的根）、树皮颗粒（常用美国红衫树皮，台湾省用龙眼树皮，内地用栎树皮）、碎砖、沸石、椰壳等。这些盆栽基质在运用前必需用水渗透。　　栽植容器的准备，由于栽培卡特兰的方式有盆栽和吊盆2种。盆栽容器必需透水勇气，常用多孔泥盆、塑料盆、釉边陶盆、木框架、金属框架等，吊盆还需求结实的塑料和铁丝挂钩。　　　普通分离分株繁衍停止。从盆中取出兰株，去除粘附在气生根上的栽培基质，分开假鳞茎，显露根系，修剪断根和腐根，如兰株过旺，则可切除底部局部根，每丛至少有3个假鳞茎，并带有新芽，如分剪过小，则对新株的恢复生长和开花都有影响。栽植时，盆底先填充颗粒较大的木炭或碎砖块，有利于排水，再放一薄层栽培基质，将卡特兰的根平均分散放进，四周再填上栽培基质，压紧栽实。　　栽植不宜过深，否则影响兰株开花。留意新芽必需向着盆沿，并留出生长2~3年的位置。新栽的卡特兰在2~3周内放在半阴、湿润的中央，每天向叶面喷少量水，坚持叶片和假鳞茎不干缩。根部不浇水，也不施肥，待新根长出2~3厘米时可开端浇水。　　　春秋季是卡特兰的生长时节，请求充足的水分和较高的空气湿度。但浇水需待盆内基质变干，在睛天的早晚停止，动作要慢，让盆底基质吃透水分。假如盆内一直湿度太大或积水，就会惹起根部病害发作。平常不浇水时，应在早晨给兰株喷一点水，同样不宜过多。夏季卡特兰生长旺盛期，可2~3天浇透水1次，并向空中洒水和叶面喷水，增加空气温度，浇水时间以黄昏为好。　　冬季卡特兰简直中止生长，处于休眠状态，但应经常给兰株叶面喷雾，假如盆内过于枯燥，则选择晴天的上午浇一点水，使栽培基质上下潮湿，还要留意不能过低，否则会伤害兰株，呈现水渍状腐朽斑块。冬季浇水时切勿在叶心鞘中或叶面上留有积水，否则易招致烂心或烂叶，浇水后可用纸吸干叶面和叶心鞘的积水。　　　卡特兰的气生根固然能够从空气中吸收氮而合成兰株可应用的氮素，但合理的施肥能够使幼苗生长更快，兰株更强健，花色更娇艳。但施肥不当，特别是施肥过量，有害无益，轻者烂根，重者枯萎死亡。因而，在栽培卡特兰的过程中，控制施肥的科学办法是十分必要的。', '　　　　卡特兰繁殖手段多用分株、组织', 'http://img.boqiicdn.com/Data/BK/P/imagick33941452156679.jpg', 'http://www.boqii.com/entry/detail/2403.html', '');
INSERT INTO `plant_family` VALUES ('277', '月季花', 'Chinese Rose', '月季', '月月红、月月花、长春花、四季花、胜春', '不容易死', '', 'http://www.boqii.com/entry/photo/1925/0,http://www.boqii.com/entry/photo/1925/5604', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '蔷薇属', '月季', 'Rosa chinensis Jacq.', 'Rosa chinensis', '　　月季在我国是非常有名的 　　月季的自然花期8月到次年4月，花成大型，由内向外，呈发散型，有浓郁香气，可广泛用于园艺栽培和', '　　很多花友都对月季情有独钟，由于月季的美非常特别，有着很多花卉的影子，但又胜过了那些花卉，所以很多花友都钟爱月季。而月季的花期又非常长，如果', '　　很多花友喜欢　　首先，在月季花谢后，先剪去残花，过一到两周　　第二步，将底层的叶子去掉，只留最上面三四个叶子。然后用干净锋利的刀片把下面得花柄面削成斜面，插入已准备好的装满　　第三步，为使切口长出新根，最好采用深色的瓶子，或者在瓶外包上一层黑塑料薄膜。同时，不要让花枝直接晒太阳。　　第四，为避免花枝发霉，最好每天换一次干净的水。　　最后，三个星期左右后，花枝会长根，等幼根长到两厘米左右的时候，就可以移栽到盆中了。为提高成活率，开始移栽时最好能每天浇水一次，以后逐渐减少。　　小贴士：扦插月季时不能心急，有时因为用的插条比较粗壮，内部的营养能促使枝条发芽生叶，让人误以为扦插已经成活，但随着芽叶的长大，枝条营养耗尽，因为没有根部营养和水分的供给，插条就会慢慢枯萎烂掉。所以，一定要', 'http://img.boqiicdn.com/Data/BK/P/imagick78761439199251.jpg', 'http://www.boqii.com/entry/detail/1925.html', '');
INSERT INTO `plant_family` VALUES ('278', '紫娇花', 'Tulbaghia violacea', '紫娇花、洋韭、洋韭菜', '野蒜、非洲小百合', '不容易死', '原产地为南非', 'http://www.boqii.com/entry/photo/2234/0,http://www.boqii.com/entry/photo/2234/5293', '　', '被子植物门', '单子叶植物纲', '百合目', '石蒜科', '紫娇花属', '', 'Tulbaghia violacea', '', '　　 　　紫娇花的鳞茎肥厚，呈球形，直径达2厘米，具白色膜质叶鞘。叶多为半圆柱形，中央稍空，长约30厘米，宽约5毫米，叶鞘长5－20厘米。', '　　', '　　紫娇花为球根　　\n1、播种法繁殖：\n　\n　2、分小鳞茎法：\n　\n　3、鳞片扦插法：\n　\n　4、分珠芽法：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick87021447840583.jpg', 'http://www.boqii.com/entry/detail/2234.html', '');
INSERT INTO `plant_family` VALUES ('279', '百日草', 'Zinnia elegans  Jacq.', '百日菊', '百日草、步步高、火球花、对叶菊 、秋罗、步步登高', '不容易死', '', 'http://www.boqii.com/entry/photo/2280/0,http://www.boqii.com/entry/photo/2280/5245', '', '', '', '', '', '', '', '', '', '　　 　　百日菊是一年生草本植物。茎直立，高30－100厘米，被糙毛或长硬毛。叶宽卵圆形或长圆状椭圆形，长5－10厘米，宽2.5－5厘米，基部稍心形抱茎，两面粗糙，下面被密的短糙毛，基出三脉。　　　　　　　　　　　　　　　　　　　　　　　　', '　　生长强健，人工栽培的难度不高，宜在肥沃深土层土壤中生长。百日草原产于墨西哥，在我国各地都有广泛栽培，是非常有名的园艺花卉品种，那么如何才能养出漂亮的百日草呢？　　　定植时盆底施入2－3克复合肥，定植后用800倍液敌克松灌根。在定植1周内应保持盆土湿润，以促进表层根系生长，待根系生长至盆底就可开始追肥，每周施肥2－3次（晴天施水肥，浓度控制在200mg／kg以内，雨天施粒肥2－3克／盆），还可施1次钙肥。定植1周后开始摘心，摘心后可喷1次杀菌剂并施1次重肥。在最后1次摘心后约两周进入生殖阶段，可逐步增加磷钾肥，如喷施磷酸二氢钾1000倍液，促使出花多且花色艳丽，并相应减少氮肥的用量。期间应保证充足的淋水量，且上午淋水比下午淋水要好，叶片的快速干燥可防止病害的发生并防止徒长。　　　百日草喜温暖向阳、不耐酷暑高温和严寒，生长适温白天18－20℃、夜温15－16℃。夏季生长尤为迅速。可直接采用全日照方式，太阳直射。若日照不足则植株容易徒长，抵抗力亦较弱，此外开花亦会受影响。', '　　百日草的观赏价值比较高，但由于百日草为一年生草本　　百日草种子发芽适温20－25度，一般7－10天萌发，播后约70天左右开花。真叶2－3片移苗，4一5片摘心，经2～3次移植后可定植。　　华北地区多于4月中、下旬播种于露地，大约一周发芽，2－3片真叶时移植或间苗，田间栽植株行距因　　留种要在外轮花瓣开始干枯，中轮花瓣开始失色时进行，剪下花头，晒干去杂、贮存。百日草花期长，后期植株会长势衰退，茎叶杂乱，花变小。所以秋季花坛用花应在夏季重新播种，并摘心1－2次。扦插繁殖可在6月中旬后进行，剪侧枝扦插，遮荫防雨。　　播种前，土壤和种子要经过严格的消毒处理，以防生长期出现病虫害。播种在4月上旬至6月下旬均可，种子消毒用1％高锰酸钾液浸种30分钟，基质用腐叶土2份、河沙1份、泥炭2份、珍珠岩2份混合配制而成，可用0.05％高锰酸钾或1000倍甲醛消毒，土壤可采用高温熏蒸法，杀死其中的病菌、害虫及草种。　　播前基质湿润后点播，百日草为嫌光性花种，播种后须覆盖一层蛭石。在21～23℃　　播种时间根据所需开花时间而定。一般提前2－3个月于温室播种。露地直播宜在早春严寒过后，否则幼苗　　播种至开花因品种不同，从45－75天。春播于3－4月进行，4－5片叶时移植，株距10厘米。6月初定植，株行距30×30厘米。生长期间每10天施一次10倍人粪尿液。7月至霜降开花。百日草也可利用夏季侧枝扦插繁殖，但因气温过高，且多阵雨，应注意防护遮荫。', 'http://img.boqiicdn.com/Data/BK/P/imagick46441449047616.jpg', 'http://www.boqii.com/entry/detail/2280.html', '');
INSERT INTO `plant_family` VALUES ('280', '黄刺玫', 'Rosa xanthina Lindl.', '黄刺玫', '刺玖花、黄刺莓、破皮刺玫、刺玫花', '不容易死', '原产我国东北、华北至西北地区', 'http://www.boqii.com/entry/photo/2099/0,http://www.boqii.com/entry/photo/2099/5428', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '蔷薇属', '黄刺玫', 'Rosa xanthina Lindl.', '', '　　 　　黄刺玫为直立灌木，高2－3米；枝粗壮，密集，披散；小枝无毛，有散生皮刺，无针刺。小叶7－13，连叶柄长3－5厘米；小叶片宽卵形或近圆形，稀椭圆形，先端圆钝，基部宽楔形或近圆形，边缘有圆钝锯齿，上面无毛，幼嫩时下面有稀疏柔毛，逐渐脱落；叶轴、叶柄有稀疏柔毛和小皮刺；托叶带状披针形，大部贴生于叶柄，离生部分呈耳状，边缘有锯齿和腺。', '　　黄刺玫俗称刺玫花，因黄刺玫的花和', '　　　　黄刺玫繁殖栽培种多用分株法，分株时先将枝条重剪，只保留30－50厘米，然后连拫挖起用利刀或斧将根劈开即可。在劈根时注意，分开株丛要有3－5枝，所有枝下都应带好根。另外也可用压条法繁殖；近年又摸出了扦插生根的方法，主要是插床应加底温，并保持较高的湿度，约一个多月就能长好根，栽培黄刺玫应选向阳干燥之处，蔽荫处往往因见光不足而', 'http://img.boqiicdn.com/Data/BK/P/imagick84611444383374.jpg', 'http://www.boqii.com/entry/detail/2099.html', '');
INSERT INTO `plant_family` VALUES ('281', '龙船花', 'Ixora chinensis Lam.', '龙船花', '卖子木、山丹、英丹', '不容易死', '中国、马来西亚、英国、欧洲各国', 'http://www.boqii.com/entry/photo/2139/0,http://www.boqii.com/entry/photo/2139/5388', '　　', '被子植物门', '双子叶植物纲', '茜草目', '茜草科', '龙船花属', '龙船花', 'Ixora chinensis Lam.', 'Ixora chinensis', '　　 　　龙船花为灌木，高0.8－2米，无毛；小枝初时深褐色，有光泽，老时呈灰色，具线条。叶对生，有时由于节间距离极短几成4枚轮生，披针形、长圆状披针形至长圆状倒披针形，长6－13cm，宽3－4cm，顶端钝或圆形，基部短尖或圆形；中脉在上面扁平成略凹入，在下面凸起，侧脉每边7－8条，纤细，明显，近叶缘处彼此连结，横脉松散，明显；叶柄极短而粗或无；托叶长5－7mm，基部阔，合生成鞘形，顶端长渐尖，渐尖部分成锥形，比鞘长。花序顶生，多花，具短总花梗；总花梗长5－15mm，与分枝均呈红色，罕有被粉状柔毛，基部常有小型叶2枚承托；苞片和小苞片微小，生于花托基部的成对；花有花梗或无；萼管长1.5－2mm，萼檐4裂，裂片极短，长0.8mm，短尖或钝；花冠红色或红黄色，盛开时长2.5－3cm，顶部4裂，裂片倒卵形或近圆形，扩展或外反，长5－7mm，宽4－5mm，顶端钝或圆形；花丝极短，花药长圆形，长约2mm，基部2裂；花柱短伸出冠管外，柱头2，初时靠合，盛开时叉开，略下弯。果近球形，双生，中间有1沟，成熟时红黑色；种子长、宽4－4.5mm，上面凸，下面凹。花期5－7月。', '　　是非常重要的盆栽木本花卉，也是缅甸的国花，龙船花的植株低矮，花色丰富，并且花期比较长，在每年的3－12月均可开花。那么人工栽种龙船花应该注意哪些呢？　　龙船花喜温暖、湿润和阳光充足环境。不耐寒，耐半阴，不耐水湿和强光。龙船花的适温为15－25℃，3－9月为24－30℃，9月至翌年3月为13－18℃。冬季温度不低0℃，过低易遭受冻害。相反，龙船花耐高温，32℃以上照常生长。总的来说，龙船花对温度的适应性比较强。龙船花喜湿怕干。茎叶生长期需充足水分，保持盆土湿润，有利于枝梢萌发和叶片生长。但长期过于湿润，容易引起部分根系，影响生长和开花。如土壤过于干燥或时干时湿，水分供给不及时，会产生落叶现象。　　龙船花需阳光充足，尤其是茎叶生长期，充足的阳光下，叶片翠绿有光泽，有利于花序形成，开花整齐，花色鲜艳。在半阴环境下也能生长，但叶片淡绿，缺乏光泽，开花少，花色较浅。但夏季强光时适当遮荫，可延长观花期。　　龙船花栽培土壤以肥沃、疏松和排水良好的酸性砂质壤土为佳。盆栽用、泥炭土和粗沙的混合土壤，pH在5－5.5为宜。', '　　　\n　一、播种繁殖\n　　冬季采种，翌年春播，发芽适温22－24℃，采用室内育苗盘播种，约20－25天发芽。长出3－4对真叶时可移苗于8厘米盆。小苗应及时用加沙的酸性性腐殖质土上盆，盆底排水孔应加大，并做排水层。雨季要注意倒盆排水，栽培期间不可太湿，过分潮湿对开花不利，甚至落叶、烂根。　\n　二、扦插繁殖\n　　于每年春暖后3－10月均可进行扦插繁殖。选取一年生健壮枝条（过嫩不易成活，皮黑有斑过老枝条不易出根），剪成10－15厘米为一段，除去基部叶片，扦插于沙床。插后浇水保持土壤湿润，约50天左右即出根，出根后约十天即可移植或上盆，放半荫处　\n　三、压条繁殖\n　　于开春进行，在分枝多而密集的情况下，离顶端20厘米处，行环状剥皮，用泥炭和薄膜绑扎起来，约2个多月可愈合生根。对新繁殖的小苗，上盆后要放半阴处养护，待成活抽发新梢后，每10－15天施一次薄肥，天气干燥时，要注意喷水增湿。小苗长到15厘米左右时，要摘心，以促发侧枝，使株型丰满。', 'http://img.boqiicdn.com/Data/BK/P/imagick9681445507134.jpg', 'http://www.boqii.com/entry/detail/2139.html', '');
INSERT INTO `plant_family` VALUES ('282', '卷丹百合', 'devil lily； easter lily； tiger lily', '卷丹', '虎皮百合、倒垂莲、药百合、黄百合、宜兴百合、南京百合', '不容易死', '', 'http://www.boqii.com/entry/photo/2346/0,http://www.boqii.com/entry/photo/2346/5071', '植物　　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '百合属', '卷丹', 'Lilium lancifolium  Thunb.', 'Lilium lancifolium Thunb.', '　　 　　卷丹鳞茎近宽球形，高约3.5厘米，直径4－8厘米；鳞片宽卵形，长2.5－3厘米，宽1.4－2.5厘米，白色。茎高0.8－1.5米，带紫色条纹，具白色绵毛。叶散生，矩圆状披针形或披针形，长6.5－9厘米，宽1－1.8厘米，两面近无毛，先端有白毛，边缘有乳头状突起，有5－7条脉，上部叶腋有珠芽。', '　　为百合科百合属植物，野生物种的分布较广泛。卷丹百合的外形特殊，并且有着很高的经济价值，不但可以观赏和食用，还有一定的药用价值，也是我国比较传统的花卉。　　卷丹温暖、湿润和阳光充足的环境。耐寒、耐旱性能良好，盆栽时应选择肥沃腐殖质丰富的砂壤土为好，粘重土不宜。卷丹对生态环境要求不太严格，土壤适应性较强，中性和偏碱性土壤都能生长。卷丹百合夏天生长，开花，冬天地上部分干枯，鳞茎在地下休眠。其实冬天百合地下球茎生理活动仍然旺盛，球茎继续不断增长、积大，为来年生长和开花奠定良好的基础。　　卷丹百合的上盆时间在每年的10月上、中旬进行。当地上部分枯萎以后，要及时剪去，挖出鳞茎，选择充实饱满鳞茎，抖去旧土，在盆的底部垫部分（少量）有机肥，将鳞茎植入盆的中央，覆土10cm一12cm，浇一次透水就完成了栽植过程。要注意是在新的中，最好加入10％新鲜的草木灰，对其生长十分有利。淋过水的草木灰就不要用了，这是因为水带走了其中的有效钾元素及其它元素，基本上没有了使用价值。盆栽百合宜用深盆，以盆深25cm一30cm为宜，盆的质地不限。　　上盆以后，在上冻前，有露地条件的，可以将花盆埋入地下，不露花盆即可。没有院落的，可以将花盆放在室内，0℃～－5℃可安全过冬。卷丹百合在冬季只长根，不出芽，来年春天气候转暖，新芽方出土生长。在生长里，应每月施一次液体肥料，化肥也可以，但不能过量。卷丹百合的茎粗壮，较高，花蕾和花朵较重，易出现头重脚轻现象，茎易弯曲倒伏导致不雅观，应在显蕾后及时设立支架固定，不使其倒伏。在养护期间，要给予较多的光照。光照过弱时，花朵数量可能减少，鲜艳度下降。', '　　　\n　一、分株\n　　卷丹百合最好是在早春（二、三月份）土壤解冻后进行。把母株从花盆内取出，抖掉多余的盆土，把盘结在一起的根系尽可能地分开，用锋利的小刀把它剖开成两株或两株以上，分出来的每一株都要带有相当的根系，并对其叶片进行适当地修剪，以利于成活。　　把分割下来的小株在　\n　三、分株后的管理\n　　分株装盆后灌根或浇一次透水。由于它的根系受到很大的损伤，吸水能力极弱，大约需要3～4周才能恢复萌发新根，因此，在分株后的3～4周内要节制浇水，以免烂根，但它的叶片的蒸腾没有受到影响，为了维持叶片的水分平衡，每天需要给叶面喷雾1～3次（温度高多喷，温度低少喷或不喷）。这段时间也不要浇肥。分株后，还要注意太阳光过强，可以放在遮荫棚内养护。　\n　四、上盆或移栽\n　　小苗装盆时，先在盆底放入2～2公分厚的粗粒基质或者陶粒来作为滤水层，其上撒上一层充分腐熟的有机肥料作为基肥，厚度约为1～2公分，再盖上一层基质，厚约1～2公分，然后放入植株，以把肥料与根系分开，避免烧根。　　上盆用的基质可以选用下面的一种。菜园土：炉渣＝3：1；或者园土：中粗河沙：锯末（茹渣）＝4：1：2；或者水稻土、塘泥、腐叶土中的一种。或者草炭＋珍珠岩＋陶粒＝2份＋2份＋1份；菜园土＋炉渣＝3份＋1份；草炭＋炉渣＋陶粒＝2份＋2份＋1份；锯末＋　　小苗移栽时，先挖好种植穴，在种植穴底部撒上一层有机肥料作为底肥（基肥），厚度约为4～6公分，再覆上一层土并放入苗木，以把肥料与根系分开，避免烧根。放入苗木后，回填土壤，把根系覆盖住，并用脚把土壤踩实，浇一次透水。', 'http://img.boqiicdn.com/Data/BK/P/imagick38861450691425.jpg', 'http://www.boqii.com/entry/detail/2346.html', '');
INSERT INTO `plant_family` VALUES ('283', '大岩桐', 'Sinningia speciosa Benth', '大岩桐', '六雪尼，落雪泥', '不容易死', '现广泛栽培，一般作温室培养', 'http://www.boqii.com/entry/photo/2357/0,http://www.boqii.com/entry/photo/2357/5059', '　', 'Angiospermae （被子植物门）', 'Dicotyledoneae（双子叶植物纲）', '唇形目 Lamiales', 'Gesneriaceae（苦苣苔科）', '大岩桐属', '', 'Sinningia speciosa Benth', '', '　　 　　大岩桐的花朵肥厚而大，卵圆形或长椭圆形，有锯齿；叶脉间隆起，自叶间长出花梗。花顶生或腋生，花冠钟状，先端浑圆，5－6浅裂色彩丰富，有粉红、红、紫蓝、白、复色等色，大而美丽。蒴果，花后1个月种子成熟；种子褐色，', '　　的观赏效果比较好，很多花友都会从市场上养在家中。大岩桐有一定的抗旱能力，生长要求空气湿度大，冬季休眠期则需保持环境干燥。人工栽培大岩桐需注意以下几点。　　　大岩桐生长适温为1－10月为18－22℃，10月至翌年1月为10－12℃。冬季休眠期盆土宜保持稍干燥些，若温度低于8℃、空气湿度又大，会引起块茎腐烂。　　　大岩桐为半阳性，喜半阴环境。故生长期间要注意避免强烈的日光照射；环境也不可过于干燥。在夏季，高温多湿，对植株生长不利，需适当遮荫，要放置在荫棚下有散射光且通风良好的地方，否则极易引起叶片枯萎。供水应根据花盆干湿程度每天浇1－2次水。　　　大岩桐较喜肥，要求肥沃、疏松而排水良好的富含腐殖质土壤，从叶片伸展后到开花前，每隔10－15天应施稀薄的饼肥水一次。当花芽形成时，需增施一次骨粉或过磷酸钙。　　　盆栽大岩桐，常用腐叶土、粗沙和蛭石的混合基质。', '　　大岩桐的园艺　\n　一、分球法\n　　选经过休眠的2年至3年老球茎，于秋季或12月至翌年3月先埋于土中浇透水并保持室温22℃进行催芽。当芽长到0.5厘米左右时，将球掘起，用利刀将球茎切成2块至4块，每块上须带有一个芽，切口涂草木灰防止腐烂。每块栽植一盆，即形成一个新植株。　　大岩桐也可用经过休眠的2年至3年以上的老球茎直接栽入盆中，当新芽长出后保留一个壮芽，其余的弱芽全部抹掉。生长期保持18℃至23℃，每周追施淡肥水1次至2次，植株长大增加浇水量，施肥时切勿将肥水溅到叶面和芽上，否则易发生斑点，甚至会腐烂。一般栽植后3个月至4个月开花。花谢后如不留种，剪去残花以利集中养料继续开花和供球茎生长。　　大岩桐的球茎可连续栽植7年至8年，　\n　二、叶插法\n　　在花落后，选取优良单株，剪取健壮的叶片，留叶柄1厘米，斜插入干净的河沙中（如使用珍珠岩和　　大岩桐扦插可用叶插，也可用芽插。叶插是选用生长健壮、　　芽插则在春季种球萌发新芽长达4厘米至6厘米时进行，将萌发出来的多余新芽从基部掰下，插于沙床中，并保持一定的湿度，经过一段时间的培育，翌年6月至7月开花。　\n　三、枝插\n　　大岩桐块茎上常萌发出嫩枝，扦插时剪取2－3厘米长，插入细砂或膨胀珍珠岩基质中，注意遮荫，避免阳光趋向，维持室温18－20℃，15天即可发根。　　\n四、播种法\n　　大岩桐大都自花不孕，因为它的雌蕊柱头高于花药，且雄蕊早熟，故自花传粉难以孕育。为了取得优良种子，必须进行人工辅助授粉。方法是在开花盛期将雄蕊的花粉采下，用毛笔轻轻涂在雌蕊的柱头上。授粉后30天至40天种子成熟，剥离种子晒晾后贮藏，随时都可播种。种子细小，每克种子28000粒左右。播种不宜过密，播后将盆置浅水中浸透后取出，盆面盖玻璃，置半阴处。温度在20℃至22℃时，约两周出苗，苗期避免强光直晒，经常喷雾，一般从播种到开花约需18周，即秋播后翌年4月至5月开花，春播于7月至8月开花。　　大岩桐留种必须进行人工授粉。大岩桐的花柱高于花药，雄蕊早熟，故自花难孕。人工授粉后，可剪取花瓣，以免花瓣霉烂影响结实。一般授粉后30～40天果实可成熟。　　播种春秋两季均可。播种前，先用将种子浸泡24小时，以促使其提早发芽。用浅盆或木箱装入腐叶土、菜园土和细砂混合的培养土。将土平整后，均匀地撒上种子，盆底润水后，上面盖上玻璃。在18－20℃的湿度条件下，约10天后出苗。出苗后，让其逐渐见阳光。当幼苗长出3－4片真叶时，分栽于小盆。苗期应适当遮荫，避免阳光趋向，经常用水喷雾，以保持较高的湿度。每隔10天左右施一次稀薄的饼肥水，一般播种后6个月可开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick82271450864551.jpg', 'http://www.boqii.com/entry/detail/2357.html', '');
INSERT INTO `plant_family` VALUES ('284', '黄金花月', 'Crassula portulacea cv. OHGONKAGETSU', '黄金花月', '', '不容易死', '原产地位于南非', 'http://www.boqii.com/entry/photo/2374/0,http://www.boqii.com/entry/photo/2374/5042', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '青锁龙属', '黄金花月', 'Crassula portulacea cv. OHGONKAGETSU', '', '　　 　　黄金花月是一种枝干非常容易木质化、并且呈树状', '　　比较容易和玉树混淆，其实黄金花月在阳光充足的情况下叶色会艳丽，是“玉树”的变种，喜欢温暖干燥的环境，耐半荫。夏季为黄金花月的，冬季为生长期。　　黄金花月是中大型植株，随着生长的状态可以几年换盆一次，盆径可以比株径大1～2寸，这样可促进植株成长。介质一定要干燥后才浇水，可以施用缓效肥。　　黄金花月虽然是养在阳光房内，一旦温度高于35度，就会移到明亮的散射光下慢慢断水，整个夏季的休眠期少水或不给水，到了9月中旬温度下来了，就开始慢慢恢复浇水，适应了阳光房的黄金花月是可以正常生长的，休眠不是太明显，但是夏天水分千万不要太大了，不然在夏天就会挂了，生长期叶片可以喷水。　　冬季如果温度能够保持5度以上，都是可以给水的，5度以下就要断水，否则就非常容易了。冬季虽然寒冷，可也不是一个冬季都不给一点水，也可在适当的时候在远离根部的地方微微给点水，切勿喷雾或给大水，姬花月不耐寒，水大容易引起。　　春季温度上升后就可以慢慢恢复正常给水。黄金花月是非常好养的一个品种，四季中除了夏季要注意适当遮阳，其他季节都可以全日照。土壤用的是泥炭混合了颗粒的煤渣等，土表铺设大颗粒石头，配土以透气为主。', '　　　　黄金花月非常适合单独栽培，由于自身后期会', 'http://img.boqiicdn.com/Data/BK/P/imagick63581451467341.jpg', 'http://www.boqii.com/entry/detail/2374.html', '');
INSERT INTO `plant_family` VALUES ('285', '荷包牡丹', 'Bicuculline', '荷包牡丹', '荷包花、蒲包花、兔儿牡丹、铃儿草、鱼儿牡丹', '不容易死', '中国北部，日本及西伯利亚', 'http://www.boqii.com/entry/photo/2296/0,http://www.boqii.com/entry/photo/2296/5228', '', '', '', '', '', '', '', '', '', '　　 　　荷包牡丹为直立草本，高30－60厘米或更高。茎圆柱形，带紫红色。叶片轮廓三角形，长 （15－）20－30（－40）厘米，宽（10－）14－17（－20）厘米，二回三出全裂，第一回裂片具长柄，中裂片的柄较侧裂片的长，第二回裂片近无柄，2或3裂，小裂片通常全缘，表面绿色，背面具白粉，两面叶脉明显；叶柄长约10厘米。总状花序长约15厘米，有（5－） 8－11 （－15）花，于花序轴的一侧下垂；花梗长1－1.5厘米；苞片钻形或线状长圆形，长3－5（－10）毫米，宽约1毫米。　　　　　　　　　　　　　　　　　　　　　　　　', '　　荷包牡丹喜光、可耐半荫，耐寒而不耐夏季高温。荷包牡丹常被用于栽培观赏，也有花友会将荷包牡丹制作成盆栽栽种，非常漂亮。荷包牡丹不但可以用于观赏，还有一定的药用价值，经济价值非常高。　　　荷包牡丹既可地栽，也宜盆植，家庭种植一般以盆栽为主，以选用稍深大、通透性较好的土陶盆种植为佳。如用塑料盆、瓷盆，可在盆底垫层碎木炭块或碎硬塑料泡沫块，增强透气排水。它喜生于含腐殖质较多的壤土中，可用腐叶土与菜园表土等量混合作培养土，在沙土和黏土中均生长不良。　　　　荷包牡丹系肉质根，稍耐旱，怕积水，因此要根据天气、盆土的墒情和植株的生长情况等因素适量浇水，坚持“不干不浇，见干即浇，浇必浇透，不可渍水”的原则，春秋和夏初生长期的晴天，每日或间日浇一次，阴天3天至5天浇一次，常保持盆土半墒，对其生长有利，过湿易烂根，过干生长不良叶黄。盛夏和冬季休眠期，盆土要相对干一些，微润即可。　　荷包牡丹喜肥，上盆定植或翻盆换土时，宜在培养土中加点骨粉或腐熟的有机肥或氮磷钾复合肥，生长期10天至15天施一次稀薄的氮磷钾液肥，使其叶茂花繁，花蕾显色后停止施肥，休眠期不施肥。　　荷包牡丹原产中国河北和东北地区，喜散射光充足的半阴环境，比较耐寒，而怕盛夏酷暑高温，怕强光暴晒，因此宜置于庭院的大树下、架下、高大建筑物的背阴面、东向或北向阳台。夏季休眠期要置于通风良好的阴处，不能见直射光，并常向附近地面洒水，提高空气湿度，降低。　　　荷包牡丹忌久雨过湿和炎热酷暑，遇到长时间的高温多湿天气。会使叶片枯焦、烂根。盛夏酷暑时期，可将盆栽荷包牡丹移至苗棚下遮荫，也可集中埋入土中防暑降温，并保持排水通风良好。无雨时每天进行枝叶及周围喷水、增加空气湿度，保征牡丹花芽分化时期的水分供应，雨季要注意排水，阴雨天要把花盆顿倒，防止盆中积水。开花后，每隔10—15天喷一次150倍波尔多液或800—l000倍托布津药液叶部病害。牡丹根甜，易遭或其蛴螬危害，可用1000倍敌敌畏溶液代水浇灌杀死。五、修剪和越冬。为改善荷包牡丹的通风透光条件，使养分集中，秋、冬季落叶后，也要进行整形修剪。剪去过密的枝条，如并生枝、交叉技、内向技及病虫害技等，使植株保持美丽的造型。秋末冬初，可将盆栽社丹埋入土中，枝条露在地上土外，上边用草或壅土加以保护越冬。也有的将花盆直接放入地窖中越冬，第二年开春去掉覆盖物，搬出窑外，放置透风向阳处，加强肥水管理；令其自然开花。也有的放在温室或塑料大棚内根据节日需要促使提前开花。', '　　　　常用分株或将根茎截段繁殖。秋季将地下部分挖出，将根茎按自然段顺势分开，分别栽植。另可将根茎截成段，每段带有芽眼，插于沙中，待生根后栽植盆内。播种繁殖，实生苗培育3年才能开花。在　　花后地上部分枯萎，可挖起根茎盆栽，保持温度15℃和湿润环境，70天左右又能见花。荷包牡丹的繁殖方法有三：一是最常用的分株法，早春2月当新芽萌动而新叶未展出之前，将植株从盆中脱出，抖掉根部泥土，用利刀将根部周围蘖生的嫩茎带须根切下，两三株植于一盆，覆土高于旧土痕两三厘米，浇水，置阴处，长新叶后按常规', 'http://img.boqiicdn.com/Data/BK/P/imagick39331449480953.jpg', 'http://www.boqii.com/entry/detail/2296.html', '');
INSERT INTO `plant_family` VALUES ('286', '小苍兰', 'Freesia', '小苍兰', '香雪兰', '不容易死', '非洲南部好望角', 'http://www.boqii.com/entry/photo/2373/0,http://www.boqii.com/entry/photo/2373/5043', '', '', '', '', '', '', '', '', '', '　　 　　小苍兰为多年生草本。球茎狭卵形或卵圆形，外包有薄膜质的包被，包被上有网纹及暗红色的斑点。叶剑形或条形，略弯曲，长15－40厘米，宽0.5－1.4厘米，黄绿色，中脉明显。　　　　　　　　　　　　　　　　', '　　小苍兰又名等，花期在春节前后，所以是很好的年宵花，也是冬季室内经常能见到的盆栽。想要小苍兰开出漂亮的花朵，对于其温度及肥水的管理是非常重要的。　　　小苍兰根较细，对土壤要求较高，应选择富含有机质而疏松的土壤种植。种植前要早施有机堆肥或粗颗粒有机肥，以提高土壤肥力和土壤疏松度和通气性能。基肥以有机肥为主，也可适当施一些化学肥料，但量不宜太多，防止引起土壤中类浓度的增加而造成生理障害。追肥以液肥为主。连作极易发生病害，应尽量避免。凡连作者应在种植前做好土壤和改善土壤理化性能的工作。　　　经冷藏的球根栽种后，温度要保持在15℃以上，否则植株矮小，尤其是生长后期，喜较高温度，但温度过高也会引起徒长。无冷藏促成栽培，因球根没有经过冷藏，开始要经过低温阶段后再加温。接近花期的温度管理，品种间有一定的差异，一般是夜间温度控制在10～15℃，白天温度不超过20℃。', '　　　\n　一、分株\n　　待茎叶枯萎后，挖起小球茎，分级贮藏，于9月按个分栽。进入休眠后，去除球茎，此时老球茎已枯死，上面会产业1～3个新球茎，分别剥下，分级贮藏或冷藏后，8～9月时在进行栽植。新球茎直径达1cm以上，栽植后当年既能开花；小的新球茎则需　\n　二、播种\n　　小苍兰也可以播种繁殖，通常5月采种后及时播种于浅盆中。播种后将盆移至背风向阳处，保持湿润，事宜发芽　　采用播种或分植球茎，播种多在秋季室内盆插，2周左右发芽，实生苗约需3至4年才能开花。室内盆栽，通常多在9月上旬栽植球茎，每盆可栽植5至7个球。可以一盆一个品种，亦可一盆多品种。小苍兰的球与百合鳞茎相似，可以在－2℃低温长期贮存，随时皆可在大棚种植。一般来说从种植球茎到开花需历时40至50天。它可根据　　小苍兰茎细弱，易倒伏，盆栽时需要设置支架支撑。花谢后逐渐减少浇水，茎叶枯萎时，则停止浇水，并将球茎挖出，进行短期晾晒，然后进行低温贮存。', 'http://img.boqiicdn.com/Data/BK/P/imagick54011451382522.jpg', 'http://www.boqii.com/entry/detail/2373.html', '');
INSERT INTO `plant_family` VALUES ('287', '夏堇', 'Torenia fournieri Linden.ex Fourn.', '蓝猪耳', '兰猪耳、花公草、夏堇', '不容易死', '原生于越南', 'http://www.boqii.com/entry/photo/2201/0,http://www.boqii.com/entry/photo/2201/5326', '　', '被子植物门 Angiospermae', '双子叶植物纲 Dicotyledoneae', '管花目Tubiflorae', '玄参科Scrophulariaceae', '蝴蝶草属Torenia', '夏堇Torenia fournieri Linden. ex Fourn.', 'Torenia fournieri Linden.ex Fourn.', '', '　　 　　夏堇成株后株高15—30厘米，株形整齐而紧密。花腋生或顶生总状花序，花色有紫青色、桃红色、兰紫、深桃红色及紫色等，种子', '　　的株型圆整、长势旺盛，非常适合盆栽或园林的大规模种植。由于夏堇喜高温、耐炎热，所以非常适合在夏季栽培，但是需要遮阴，以免晒伤。人工栽培夏堇可以根据小编为你整理的这几点来进行栽培。　　　　在整个生长阶段，保持基质pH值为5.5至5.8。发芽阶段，EC值保持为0.5至0.75；满穴阶段，EC值为0.5至1.0；移栽后，EC值保持在1.0至1.5之间。　　　　发芽期间需要光照，如暗室培养植株，需补充100至1000勒克斯的光照，以确保发芽而减少徒长。满穴阶段以后，需要提供不超过3万勒克斯的光照，且要避免直接光照。在夏季，需要保证处于阴凉的环境中，以避免植株遭受热胁迫。弱光环境可能造成茎的徒长，并推迟开花，因此在冬季和早春种植时，补充光照是非常必要的。　　　　播种后至第6天保持含水量5级，直到胚根发出；从第7天开始，将含水量在2级和4级之间交替，即让栽培基质的含水量先达到2级水平，然后再加水达到4级水平。基质如过长的饱和，会减少可移植幼苗的数量；而穴盘太干则会导致植株枯萎。（含水量划分：1级为0至20％，2级为20％至40％，3级为40％至60％，4级为60％至80％，5级为80％至100％。）　　　胚根发出（约播种后6天）前一直保持空气相对湿度为100％；之后降低并保持至40％。满穴阶段，开始将相对湿度保持在40％至70％之间。加强通风，使基质水分蒸发而变干燥，这样可以确保空气到达根部。　　　胚根生出前保持温度为22℃；满穴阶段温度降低至18℃至20℃，直至根系扩展至盆器边缘；移栽后，夜晚温度保持在16℃至18℃之间，白天温度保持在18℃至21℃之间。夜晚温度若低于16℃，可能会造成叶片卷曲，叶色，由黄变红。　　　发芽阶段灌溉施肥，确保EC值不超过0.5。在子叶出现后，每周需施氮浓度为50ppm至75ppm的含钙氮肥（氮磷钾比例为14－2－14或14－4－14）；少量施用磷元素，这样有利于根的生长和开花。在满穴阶段后期幼苗成熟之后，可将肥料浓度提升至75ppm至100ppm。移栽后，可使用氮浓度为150ppm至200ppm的含钙氮肥（氮磷钾比例为13－2－13或14－4－14）。', '　　人工播种　　播种是夏堇最常用的种植方法，春播为主，华南地区宜秋播。室内栽培时，全年都可以播种。如果是8月开花，应该在5月5日左右进行播种。发芽适温20至30℃，播种后大约10至15天可发芽。种子粉末状，播种时要注意保湿。苗高10厘米时移植。　　夏堇一般于春季播种，因种子', 'http://img.boqiicdn.com/Data/BK/P/imagick92631447061608.jpg', 'http://www.boqii.com/entry/detail/2201.html', '');
INSERT INTO `plant_family` VALUES ('288', '九里香', 'Murraya exotica L.', '九里香', '石辣椒、九秋香、九树香、七里香、千里香、万里香', '不容易死', '', 'http://www.boqii.com/entry/photo/1907/0,http://www.boqii.com/entry/photo/1907/5622', '', '', '', '', '', '', '', '', '', '　　九里香别名千里香、七里香、万里香，仔细一看它的别名以及学名几乎都与香有关，大可说明此花的花香味一定很浓郁。九里香是路边花坛常见的观花植物，它的株态优美、花型小巧，用心栽培可修剪成小乔木样，可养在庭院或阳台上，是美化环境与净化空气的最佳之选。紧接着我们来了解下九里香的养护方法及注意事项。　　九里香喜温暖，最适宜生长的温度为20～32℃，不耐寒，冬季当最低气温降至5℃左右时，移入低温(5～10℃)室内越冬，过早不利于锻炼其耐寒性。室温过低易掉叶，影响翌年生长，低于0℃就可能冻死，而室温过高，植株不能很好休眠，甚至在室内萌芽，出室时冷风一吹，芽又缩回，待再次发新芽，则影响当年的生长。　　九里香是阳性树种，宜置于阳光充足、空气流通(每天至少能见五六个小时直射光)的地方才能叶茂花繁而香。开花时可移至窗台上，满室芳香，花谢后仍需置于日照充足处，在半阴处生长不如向阳处健壮，花的香味也淡，过于荫蔽则枝细软、叶色浅、花少或无花。冬季入室亦应置于阳光充足处。　　栽种九里香需要选择一处地势平坦、土壤肥沃的土地，选好之后就先要整地、作畦和挖定植穴，然后就可以种植九里香了。当然也可以利用屋宅周围的环境，结合一些绿化作物将九里香栽植成绿篱，也是很不错的景观哦。　　有灌溉条件的地区可在春季进行定植，没有条件的最好在雨季定植。作为香料植物的九里香最好栽在土壤水肥条件好的地区，以方便日后采花。九里香适当稀植，能够开出更多艳丽花朵，株行距最佳为50*50cm；若是密植，则会生长得枝叶繁茂，株行距宜为25*30cm。　　九里香　　九里香对土壤要求不严，宜选用含腐殖质丰富、疏松、肥沃的沙质土壤。刚栽种或翻盆的九里香，要浇透水，先置于蔽荫处10天左右，然后再放置阳光充足、通风良好处养植。　　九里香喜湿润环境，但盆栽九里香由于盆土有限，极易干燥，如不及时浇水，就会枯死，但浇水不可过多，水分过多会引起徒长，长期积水极易引起烂根导致死亡。所以九里香浇水要掌握“不干不浇，浇则浇透”的原则。　　盆栽九里香的盆土养分有限，为了九里香盆景长势良好，需要注意　　九里香可每隔2-3年翻一次盆，以秋季10-11月为最佳时期，晚春4-5月份也好，冬季一般不适宜翻盆。翻盆可用原来盆或换稍大一号的盆，根据九里香的大小来决定。翻盆时可结合修根、换土。根系太密太长的应予修剪，脱盆时剥掉土球四周50-70%的旧盆土，剪掉烂根及部分老根，然后按照上盆的过程进行处理。如保留较多的原土，则可随时进行翻盆，不受季节限制，如需换去大部分或全部宿土，要严格选择恰当的翻盆时期。所以浇水要掌握“不干不浇，浇则浇透”的原则，一般夏季高温期要早晚各浇一次水，春秋季可每天或隔天浇一次水，冬季可数日浇一次水，梅雨季节或雨天可不浇水。　　九里香的常见病害有白粉病、铁锈病，如遇此类病害，注意及时喷洒药剂杀除，以利于生长。主要虫害有红蜘蛛、天牛、金　　九里香成型后不会停止生长，如任其发展而不加抑制，必影响造型而失去艺术价值，所以要及时修剪，疏枝散叶，以保持其优美树姿。九里香枝条萌生性强，为保持美观树形，须注意经常修剪。　　九里香的养殖方法就这么简单，它不需要你每日陪，也不需要你每日给它浇水施肥，只需要在你百忙之中抽出一点时间来给它做些基本养护工作即可。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick17421428056277.jpg', 'http://www.boqii.com/entry/detail/1907.html', '');
INSERT INTO `plant_family` VALUES ('289', '燕子掌', 'Crassula obliqua', '燕子掌', '玉树、景天树、豆瓣掌', '不容易死', '非洲南部地区', 'http://www.boqii.com/entry/photo/1957/0,http://www.boqii.com/entry/photo/1957/5570', '', '', '', '', '', '', '', '', '', '　　 　　燕子掌植株呈多分枝的亚灌木状，茎明显，圆形，表皮绿色或者黄褐色，叶片上有小点点。肉质叶对生，在茎或分枝顶端密　　　　　　　　　　　　　　', '　　虽然燕子掌的栽培难度不大，并且分布非常广，但是燕子掌的汁液是有毒的，误食会引起中毒，如果不慎溅入，严重的则会导致。所以在栽培燕子掌的过程中需要注意不要让其汁液流出。　　盆栽燕子掌，宜选用2／3的腐叶土和1／3的园土混合并加入少量的河砂作为土，盆底可放少许蹄片等长效肥料，作基肥。为利于排水，盆底还要垫一些碎石或瓦片。从春季到秋季，可1～2天浇水一次，忌盆内积水。夏季高温酷暑，气温高达30℃以上时，植株处于休眠和半休眠状态，要控制浇水。同时，还应做好遮荫降温工作，可每日向盆周围的地面喷水2～3次，并注意通风。进入冬季，应适当减少浇水次数，保持盆土稍干燥。培管理较粗放，一般不施肥，若长势过弱，可追加一些含钾的液肥或生长季节每月追加一次稀薄的腐熟饼肥水。燕子掌生长适温为15～25℃，温度宜保持7℃以上，低于5℃易受冻害。夏季酷暑和强烈日光对植株生长不利。冬季宜将花盆移至棚内向阳处，使其保持叶片清绿。一般1～2年换盆一次，土壤需疏松肥沃、排水性良好。　　生长期间对过长和过密枝杈适度修剪，保持株姿匀称，树势强健。每半月转一次盆，避免枝叶偏斜，影响美观，如光照不足，更应注意防止湿热烂根脱叶。　　每年春季需换盆，加入肥土。燕子掌生长较快，为保持株形丰满，肥水不宜过多。生长期每周浇水2－3次，高温多湿的7－8月严格控制浇水。盛夏如通风不好或过分缺水，也会引起叶片变黄脱落，应放半阴处养护。入秋后浇水逐渐减少。室外栽培时，要避开暴雨冲淋，否则根部积水过多，易造成烂根死亡。每年换盆或秋季放室时，应注意整形修剪，使其株形更加古朴典雅。', '　　燕子掌的适应能力比较强，繁殖一般一年四季均可进行。人工繁殖燕子掌一般采用扦插繁殖的方法来进行繁殖，此种方法一般生根快、成活率高，那么究竟应该如何操作呢？　　1、插枝的选择：从4－9月份将品质优良、　　2、扦插基质和容器：取干净、无菌的水瓶或水杯，盛入　　3、扦插：扦插枝条用泡沫或厚纸片固定后放入杯中，水深以浸入穗1／2－1／3为宜，放入通风荫蔽处，保持　　4、插后管理：扦插后每2－3天换一次水，一般7天左右就可生根，生根率几乎成100％，比土插要提前生根一周左右，生根后应及早上盆，否则根系易折断，上盆后应放在蔽荫处5－7天即可进入正常', 'http://img.boqiicdn.com/Data/BK/P/imagick82281439976564.jpg', 'http://www.boqii.com/entry/detail/1957.html', '');
INSERT INTO `plant_family` VALUES ('290', '长春花', 'Catharanthus roseus （L.） G. Don', '长春花', '日日春、日日草、日日新、三万花、四时春、时钟花、雁来红', '不容易死', '非洲、亚热带、热带以及中国大陆的华东、西南、中南等地', 'http://www.boqii.com/entry/photo/2074/0,http://www.boqii.com/entry/photo/2074/5453', '', '', '', '', '', '', '', '', '', '　　长春花又名金盏草等，现在长春花经过不断的培育选种，以花朵越来越大为趋势。长春花不但有观赏价值，其药用价值也非常高，被提炼的长春花碱和长春新碱作为多种癌症的化学 　　长春花为亚灌木，略有分枝，高达60厘米，有水液，全株无毛或仅有微毛；茎近方形，有条纹，灰绿色；节间长1－3.5厘米。叶膜质，倒卵状长圆形，长3－4厘米，宽1.5－2.5厘米，先端浑圆，有短尖头，基部广楔形至楔形，渐狭而成叶柄；叶脉在叶面扁平，在叶背略隆起，侧脉约8对。　　　　　　　　　　　　　　　　　非洲、亚热带、热带以及中国大陆的华东、西南、中南等地', '　　为多年生草本，长春花的花期长、花朵多，所以也有“日日春”的美名。长春花是阳性植物，在其过程中需要阳光充足，人工栽培长春花的难度病不高，但是想要长春花开出鲜艳的花，修剪和施肥都是非常重要的。　　长春花除正常的肥水管理外，重点要把握的是摘心和雨季茎叶病的。摘心的目的是促进分枝和控制花期。一般4～6片真叶时（8～10厘米）开始摘心，新梢长出4～6片叶时（第一次摘心后15～20天）进行第二次摘心，摘心最好不超过3次（超过3次摘心会影响开花质量）。长春花最后一次摘心直接影响开花期，一般秋季（国庆节用花）最后一次摘心距初花期25天，夏季最后一次摘心比秋季提前3～5天。　　长春花可以不摘心，但为了获得良好的株型，需要摘心一到两次。第一次在3～4对真叶时；第二次，新枝留1～2对真叶。长春花是多年生草本植物，所以如果成品销售不出去，可以重新修剪，等有客户需要时，再培育出理想的高度和株型。栽培过程中，一般可以用调节剂，但不能施用多效唑。', '　　　　\n一、播种繁殖\n　　4月春播。长春花每克种子750粒，发芽适温为18～24℃。用播种盘盛消毒腐叶土、　\n　二、扦插繁殖\n　　春季或初夏剪取嫩枝，长8～10厘米，剪去下部叶，留顶端2～3对叶，插入沙床或腐叶土中，保持插壤稍湿润，室温20～24℃，插后15～20天生根。　\n　三、组培繁殖\n　　采用茎尖作外植体。经消毒的茎尖，剪成数段，每段0.4～0.6厘米，接种在MS培养基附加6－苄氨基腺嘌呤5mg／L和萘乙酸0.2mg／L，经1个月培养，长出不定芽。再转接到1／2MS培养基添加激动素0.2mg／L和吲哚乙酸2mg／L，半个月后开始长出白根，成为完整植株。', 'http://img.boqiicdn.com/Data/BK/P/imagick55371443088504.jpg', 'http://www.boqii.com/entry/detail/2074.html', '');
INSERT INTO `plant_family` VALUES ('291', '鹤望兰', 'Strelitzia reginae Aiton', '鹤望兰', '天堂鸟，极乐鸟花', '不容易死', '非洲南部，美国，德国，意大利，荷兰，菲律宾，中国', 'http://www.boqii.com/entry/photo/1974/0,http://www.boqii.com/entry/photo/1974/5553', '', '', '', '', '', '', '', '', '', '　　 　　鹤望兰为多年生草本，无茎。叶片长圆状披针形，长25－45厘米，宽约10厘米，顶端急尖，基部圆形或楔形，下部边缘波状；叶柄细长。花数朵生于一约与叶柄等长或略短的总花梗上，下托一佛焰苞；佛焰苞舟状，长达20厘米，绿色，边紫红，萼片披针形，长7.5－10厘米，橙黄色，箭头状花瓣基部具耳状裂片，和萼片近等长，暗蓝色；雄蕊与花瓣等长；花药狭线形，花柱突出，柱头3。　　　　　　　　　　　　　　　　　　　　　', '　　由于鹤望兰的花型和仙鹤昂首眺望的样子非常像，故此命名。鹤望兰整体给人以一种高雅端庄的感觉，是非常适合家庭栽培的观花。如果得当，鹤望兰的花期可长达两个多月，并且全年都可开花。那么究竟应该如何栽种出漂亮的鹤望兰呢？　　鹤望兰是肉质根，根系发达，的较快，要注意及时换盆，一般每年换一次，否则过小的花盆会限制了它的生长。花盆最好选用比较深的桶状盆，这样的花盆内部空间大，有利于它的根系均匀的扩展发育。　　因为是肉质根，所以时浇水不能太多，鹤望兰即怕干旱也怕水涝，一般来说浇水要见干见湿，根据季节变化及本身的生长情况来判断。春夏季节浇水要充足，深秋以后减少浇水，冬季则要适当控水。　　鹤望兰较喜肥，充足的肥水使它花色艳丽、枝叶舒展。在生长期间每隔半个月左右施加一次饼肥水，发酵过的淘米水效果也不错。花茎形成后，要及时追施2至3次过磷酸钙，这样才能使花色更加的艳丽。花谢后，如果不准备留籽的话，就及时剪除花茎，减少养分的消耗。另外还要在换盆时将盆土中加入适量的基肥，这样才能保证整个生长期间有足够的营养供应。', '　　　　鹤望兰的植株在原产地由体重仅2g的蜂　　在我国北方地区，鹤望兰往往只能采取分株繁殖的方法来获得新的植株。为了让鹤望兰多萌发侧芽，有利于分株，栽种时应注意适当浅栽，让植株的根颈部略微高出盆土为好。这样每年均可有侧芽发生，让其长到不少于四片叶时，在高温高湿的六、七月份即可实行分株。分株时，将植株整体从盆中倒出以后，先用自来水冲去宿土，待能明显分清根系走向后再小心切割，每组肉质根上应带有一定数量的叶片和2～3个新芽，且使新株所带根系不少于三条。每株叶子不足四片的，可几株合切而不要单独切割成株，否则不容易成活。切割后的植株，无论是新株还是老株，上盆时如根系过长，可适当短截。剪口用草木灰或硫磺粉涂抹，在荫凉处晾放半天，然后直接栽人适合鹤望兰盆栽的“三合土”中，浇透水放半荫处。以后不干不浇，浇则浇透。约经45天后即可按正常情况进行肥水', 'http://img.boqiicdn.com/Data/BK/P/imagick23051440409379.jpg', 'http://www.boqii.com/entry/detail/1974.html', '');
INSERT INTO `plant_family` VALUES ('292', '木芙蓉', 'Hibiscus mutabilis Linn', '木芙蓉', '芙蓉花，拒霜花，木莲，地芙蓉，华木', '不容易死', '分布于中国各地', 'http://www.boqii.com/entry/photo/1960/0,http://www.boqii.com/entry/photo/1960/5567', '', '', '', '', '', '', '', '', '', '　　 　　木芙蓉（原变型）为落叶灌木或小乔木，高2－5米；小枝、叶柄、花梗和花萼均密被星状毛与直毛相混的细绵毛。叶宽卵形至圆卵形或心形，直径10－15厘米，常5－7裂，裂片三角形，先端渐尖，具钝圆锯齿，上面疏被星状细毛和点，下面密被星状细绒毛；主脉7－11条；叶柄长5－20厘米；托叶披针形，长5－8毫米，常早落。　　芙蓉花，拒霜花，木莲，地芙蓉，华木　　　　　　　　　木芙蓉、重瓣木芙蓉　　　　无毒　　', '　　木芙蓉原产于我国，由于木芙蓉不耐寒，所以人工栽培木芙蓉需要有合适的环境。现在，木芙蓉一般分为野生和园艺两种，开花的木芙蓉花色也会随着时间改变，并且一朵花会出现不同的颜色，所以深受人们的喜爱。　　木芙蓉为深根性，根粗壮稍具肉质，喜温暖湿润、阳光充足的环境，亦耐旱，略耐阴。其生性粗放，对土质要求不严，在疏松、透气、排水良好的沙壤土中最好。其栽培宜选择通风良好、土质肥沃之处，尤以邻水栽培为佳。　　木芙蓉的日常较为粗放，天旱时应注意浇水，春季萌芽期需多施肥水，花期前后应追施少量的磷、钾肥。每年冬季或春季可在植株四周开沟，施些腐熟的有机肥，以利植株生长旺盛，花繁叶茂。在花蕾透色时应适当扣水，以控制其叶片生长，使养分集中在花朵上。　　木芙蓉长势强健，萌枝力强，枝条多而乱，应及时修剪、抹芽。木芙蓉耐修剪，根据需要既可将其修剪成乔木状，又可修剪成灌木状。修剪宜在花后及春季萌芽前进行，剪去枯枝、弱枝、内膛枝，以保证树冠内部通风透光良好。在寒冷地区地栽的植株，冬季其嫩枝会冻死，但到了翌年春天又能萌发出更多的新梢。因此，最好将其株形培植成灌木状。　　木芙蓉盆栽宜选用较大的瓷盆或素烧盆，盆土要求疏松肥沃、排水透气性好，生长要有足够的水分。冬季移至温度在0℃至5℃的室内，保证其充分休眠，以利于来年开花。', '　　　\n　一、播种育苗技术\n　　11－12月采收果实，晒干开裂后敲出种子，种子忌烈日暴晒。晾干种子置室内阴凉干爽处贮藏，翌春3－4月播种。播种前需用45t温水浸种2一3小时。床土过细筛，浇足底水，种子混细沙后撤播于露地苗床，7－10天可出苗，40天后可移苗，经6个月培育可定植。　\n　二、扦插育苗技术\n　　10月前后剪取当年生直径1.2－1.5厘米的粗壮枝条，截成15－20厘米长的插穗，上端剪口离芽1厘米左右，每插穗含3个以上芽，捆成捆，埋人沙中至翌春3－4月扦插。翌年春取出插穗，浸泡4一8小时，使其充分吸水，然后进行扦插，扦插深度为插穗长的2／3，株距8厘米，行距25厘米。扦插时切勿伤皮。插后适时浇水保湿，极易生根，当年苗高可达I米左右。也可早春直接剪枝条扦插。插后1个月即能生根。两种方法成苗率均较高。育苗3个月就可定植。　\n　三、分株育苗技术\n　　在早春萌芽前进行。先把丛生母株的枝条从基部以上20－30厘米处短截，然后将母株挖掘出来并分割成若干分株，栽植后由枝干基部萌发而形成新的株丛，当年秋即能开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick26411439977652.jpg', 'http://www.boqii.com/entry/detail/1960.html', '');
INSERT INTO `plant_family` VALUES ('293', '白花小松', 'Villadia batesii （Hemsl.） Baehni ＆ Macbride', '白花小松', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2343/0,http://www.boqii.com/entry/photo/2343/5074', '　', '被子植物门', '木兰纲', '蔷薇目', '景天科', '塔莲属', '白花小松', 'Villadia batesii （Hemsl.） Baehni ＆ Macbride', '', '　　 　　白花小松多年生迷你多肉植物，植株矮小，分枝与叶片很短，贴在肉质茎上，叶肉质轮生，一般旋转展开，叶尖经阳光照射边缘有红色，花顶生，白色。', '　　的栽培难度不高，适应性较强，是一种迷你的多肉，很适合和其他多肉植物混搭栽培。常年绿色，光照充足等情况下整株会变为粉红色，非常漂亮。　　白花小松盆栽，具有一定的耐干性，勿积水，浇水土干透一定要浇透，浇水时针对底部有孔盆器可进行浸盆法（找个大盆打好水，水位不没过植物盆口，小盆一般控制在5分钟左右将植物从水中拿出）进行，针对无孔植物可用小器具如勺子等进行慢慢浇水，水最好尽量不要积具于叶片上，也要防止盆内长期积水。夏季高温要注意通风与遮荫，避免烈日暴晒，其他要给予充足阳光。', '　　　　白花小松繁殖还是很简单的，因为白花小松很容易群生，所以白花小松繁殖多以扦插为主，当然也可以叶插，有兴趣的花友可以试试，扦插和叶插的方法与其他多肉植物相同。　　白花小松是一种比较迷你的多肉植物，很适合与其他多肉植物混搭组合。白花小松常年绿色，日照增多及', 'http://img.boqiicdn.com/Data/BK/P/imagick45921450689552.jpg', 'http://www.boqii.com/entry/detail/2343.html', '');
INSERT INTO `plant_family` VALUES ('294', '碧玉莲', '', '碧玉莲', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2461/0,http://www.boqii.com/entry/photo/2461/4955', '　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '碧玉莲属', '', '', '', '　　 　　碧玉莲叶片很小，非常迷你，对日照需求不算太多，碧玉莲的叶子表层上是很明显有纹路的，叶子短，而且有粉。', '　　碧玉莲在夏季高温时需要特别，不然很容易出现叶片变皱或枯萎掉落的情况。人工栽培碧玉莲的难度并不高，那么如何才能养好碧玉莲呢？　　碧玉莲的根系都很发达，一般我们种花的小盆，底部水分蒸发的快，我们平时养多肉又很怕浇水，生怕烂死了，平时喷喷或少浇水，下面的的根系吸收不到水分，上面的老根又老化吸收力不强，植物缺水，如叶子萎蔫，表皮发皱，这时千万别以为是烂根了，控水控水再控水，只能适得其反，控水过了头，新生的毛细根干死这时候浇大水，无吸收力很可能感染坏死，从底下往上烂，烂了就说是浇水浇多了。　　休眠期也要适当的浸一下盆，几秒即可，人家在大自然里都有地下水气，根系超发达，不会死，有一点雨水就很快恢复过来，喝饱喝足，咱种在小盆子里，休眠期断水断的干净，只靠植物体内的水分，又要适应，又要适应湿度，根干死了还要发根。体质状态不好的挂了也是再所难免。', '　　　\n　1、扦插：\n　\n　2、分株：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick81401453887420.jpg', 'http://www.boqii.com/entry/detail/2461.html', '');
INSERT INTO `plant_family` VALUES ('295', '飘香藤', 'Mandevilla Sanderi', '飘香藤', '红皱藤、双腺藤、双喜藤、文藤、红蝉花', '不容易死', '', 'http://www.boqii.com/entry/photo/2228/0,http://www.boqii.com/entry/photo/2228/5299', '　　', '被子植物门', '双子叶植物纲', '龙胆目', '夹竹桃科', '双腺藤属', '', 'Dipladenia sanderi', '', '　　 　　飘香藤为夹竹桃科多年生常绿藤本植物。叶对生，全缘，长卵圆形，先端急尖，革质，叶面有皱褶，叶色浓绿并富有光泽。花腋生，花冠漏斗形，花色为红色、桃红色、金红色，粉红等色，且富于变化，有“热带藤本植物皇后”的美称。花期主要为夏、秋两季，如', '　　很多人都会将栽种在花园里，当飘香藤开出红花时，其独特的清香也会随风飘来。由于飘香藤在开花期间会出现花多于叶的情况，所以也受到很多花友们的欢迎，那么如何才能养好飘香藤呢？　　飘香藤喜温暖湿润及阳光充足的环境，也可置于稍荫蔽的地方，但光照不足开花减少。适温为20—30℃，对土壤的适应性较强，但以富含腐殖质排水良好的沙质壤土为佳。飘香藤不宜植于过于低洼的场所，以免积水引起缺氧而生长不良。室内盆栽北方可用腐叶土加少量粗砂，南方可使用塘泥、泥炭土、河沙按5：3：2混合配制。在生长期，可适量追施复合肥3—5次，但应控制氮肥施用量，以免营养生长过旺而影响生殖生长，使开花减少。在养护过程中，要适当控制浇水，以形成发达的根系。飘香藤抗逆性强，较少病害，因此在生长期，每月喷洒一次杀菌剂即可对病害起到作用。　　花期过后即可进行修剪，如果是一、二年生植株，可进行轻剪，修剪主要是为了整形。多年生老株可于春季进行强剪，以促其萌发强壮的新枝。飘香藤一般用扦插法繁殖，可于春、夏、秋季进行，也可用组织培养方法进行快繁。飘香藤花大色艳，株形美观，被誉为热带藤本的皇后。室外栽培时，可用于篱垣、棚架、天台、小型庭院美化。因其蔓生性不强，也适合室内盆栽，可置于阳台做成球形及吊盆观赏。栽培几株飘香藤，使庭院及阳台充满异国情调。', '　　　　飘香藤一般用扦插法繁殖，可于春、夏、秋季进行，也可用组织　　室外栽培不宜植于过于低洼的场所，以免积水引起缺氧而生长不良。室内盆栽北方可用腐叶土加少量粗砂，南方可使用塘泥、泥炭土、河沙按5：3：2混合配制。在生长期，可适量追施复合肥3—5次，但应控制氮肥施用量，以免营养生长过旺而影响生殖生长，使开花减少。在养护过程中，要适当控制浇水，以形成发达的根系。　　花期过后即可进行修剪，如果是一、二年生植株，可进行轻剪，修剪主要是为了整形。多年生老株可于春季进行强剪，以促其萌发强壮的新枝。', 'http://img.boqiicdn.com/Data/BK/P/imagick48241447752354.jpg', 'http://www.boqii.com/entry/detail/2228.html', '');
INSERT INTO `plant_family` VALUES ('296', '鲁氏石莲花', 'Echeveria runyonii', '鲁氏石莲花', '', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/2358/0,http://www.boqii.com/entry/photo/2358/5058', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '拟石莲花属', '鲁氏石莲花', 'Echeveria runyonii', '', '　　鲁氏 　　鲁氏石莲为中小型', '　　的叶片形状和)有点像，但是鲁氏石莲花的叶片明显更厚，阳光充足的情况下，鲁氏石莲花的叶片不会被晒红，但是叶色会更艳丽。人工栽培鲁氏石莲花的难度并不高，小编就为你介绍一下栽培过程中的一些。　　　鲁氏石莲花喜欢光照充足的生长环境，可以全日照，鲁氏石莲需要接受充足日照叶色才会艳丽，株型才会更紧实美观。日照太少则叶色浅，叶片排列松散，拉长。夏季要适当采取遮阳措施，冬季需要保持充足的阳光照射，如果可以的话可以在室内阳光充足的地方养殖。　　鲁氏石莲花的浇水一般是介质干燥后才浇水，浇水一定要浇透，夏季一般温度高于35度就要慢慢断水，夏季是鲁氏石莲花的休眠期，可以少给水或者不给水，多雨的时候不要造成盆土积水，等到秋季凉爽季节可以慢慢恢复浇水，冬季养殖气温如果在0度以上都可以给水，0度以下就慢慢断水了，否则植株会。　　鲁氏石莲花对土壤的栽培总体来说不是很高，可以采取用泥炭土混合了颗粒的煤渣，配土以透气为主，可以在土表铺设干净的颗粒河沙。', '　　鲁氏　　鲁氏石莲花的繁殖一般可以采取叶插与砍头的方式，也可以选择播种的方式，砍头全年都可以进行，叶片要选择肥厚的叶片扦插。随着植株的不断生长，可以几年换盆一次，在生长', 'http://img.boqiicdn.com/Data/BK/P/imagick7711450947424.jpg', 'http://www.boqii.com/entry/detail/2358.html', '');
INSERT INTO `plant_family` VALUES ('297', '秋丽', 'xGraptosedum“Francesco Baldi”', '秋丽', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2262/0,http://www.boqii.com/entry/photo/2262/5263', '　', '', '', '', '景天科', 'xGraptosedum', '', 'xGraptosedum“Francesco Baldi”', '', '　　 　　秋丽的叶片较细长，正面平滑微下凹，背面明显突起似龙骨状，顶端稍尖，但整体仍较圆润。秋丽', '　　', '　　　　秋丽的繁殖可选择枝插或者叶插，繁殖较为容易，将叶片掰下，或者枝条剪下通风晾置几天，平铺／插入土中即可。　　秋丽的近似', 'http://img.boqiicdn.com/Data/BK/P/imagick29661448616231.jpg', 'http://www.boqii.com/entry/detail/2262.html', '');
INSERT INTO `plant_family` VALUES ('298', '六月雪', 'Serissa japonica （Thunb.） Thunb.', '六月雪', '满天星、白马骨、碎叶冬青', '不容易死', '江苏、浙江、江西、广东、台湾等东南及中部各省。日本也有分布。', 'http://www.boqii.com/entry/photo/1945/0,http://www.boqii.com/entry/photo/1945/5584', '', '', '', '', '', '', '', '', '', '　　 　　六月雪的花为单生或数朵丛生于小枝顶部或腋生，有被毛、边缘浅波状的苞片；萼檐裂片细小，锥形，被毛；花冠淡红色或白色，长6－12毫米，裂片扩展，顶端3裂；雄蕊突出冠管喉部外；花柱长突出，柱头2，直，略分开。　　　　　　　　　　　　　　　　　　　　　　', '　　在开花的时候非常好看，不过六月雪喜欢温暖的气候，但是畏强光，生长力非常强，并且还有一定的药用价值，所以常被人制作成盆景进行栽培。那么人工栽培六月雪应该注意哪些呢？　　对六月雪的管理基本活儿是浇水施肥。浇水的原则，不干不浇，切勿滥浇，如果盆口长期偏湿，导致根部呼吸困难，易烂根致死。施肥讲究勤薄，施腐熟液肥，夏季不施肥，花期不可施肥，以免妄长走形。5月至6月要进行摘梢，7月的新芽要摘除。　　盆花要固定位置，不宜搬东搬西，六月雪讲究向光性。夏日在烈日下要上面遮阳，保持通风，每天向其叶片喷水1次至2次，保持空气湿度。寒冬可用稻草略加包扎一下（在－10℃左右时），避免冻死。　　夏季高温干燥时，除每天浇水外，早晚应用清水淋洒叶面及附近地面，以降温并增加空气湿度，植株应放于荫棚下，切勿长期放在强烈阳光下曝晒。入秋后，随着气温下降，应逐渐控制浇水量，2天至3天浇一次水。冬季移入不低于0℃的冷室或室内，20天至30天浇一次水；如果室温15℃以上，常绿不落叶，7天至10天浇一次水，要保持湿润的空气和给予阳光照晒。严寒期间切忌受冻，否则易于。每年3月出室前，用腐叶土换盆，盆底用垫蹄角片做底肥。　　六月雪的病虫害一般是介壳虫。可喷洒40％氧化乐果1000倍至1500倍液或25％亚胺硫磷1000倍至1500倍液来。', '　　　　\n一、六月雪扦插：\n　　六月雪很皮实，很容易扦插成活，扦插　\n　二、六月雪分株：\n　　常于春季3月份进行。移植四季均可进行，以春季2～3月为最好。', 'http://img.boqiicdn.com/Data/BK/P/imagick68501439544938.jpg', 'http://www.boqii.com/entry/detail/1945.html', '');
INSERT INTO `plant_family` VALUES ('299', '翠菊', 'Callistephus chinensis （L.） Nees', '翠菊', '江西腊、七月菊、格桑花', '不容易死', '中国、日本、朝鲜', 'http://www.boqii.com/entry/photo/2381/0,http://www.boqii.com/entry/photo/2381/5035', '', '', '', '', '', '', '', '', '', '　　 　　翠兰为一年生或二年生草本，高 （15） 30－100厘米。茎直立，单生，有纵棱，被白色糙毛，基部直径6－7毫米，或纤细达1毫米，分枝斜升或不分枝。下部茎叶花期脱落或生存；中部茎叶卵形、菱状卵形或匙形或近圆形，长2.5－6厘米，宽2－4厘米，顶端渐尖，基部截形、楔形或圆形，边缘有不规则的粗锯齿，两面被稀疏的短硬毛，叶柄长2－4厘米，被白色短硬毛，有狭翼；上部的茎叶渐小，菱状披针形，长椭圆形或倒披针形，边缘有1－2个锯齿，或线形而全缘。　　　　　　　　　　　　　　　　　　　　　　', '　　翠菊原产于我国北部，对日照反应较敏感，如果光照不足，则开花会推迟。翠菊非常适合花坛、花境的栽培，也是非常好的材料，那么如何才能养出漂亮的翠菊呢？　　翠菊喜温暖、湿润和阳光充足环境。怕高温多湿和通风不良。耐寒性弱，也不喜酷热，通风而阳光充足时旺盛。　　翠菊生长适温为15～25℃，冬季温度不低于3℃。若0℃以下茎叶易受冻害。相反，夏季温度超过30℃，开花延迟或开花不良。翠菊为浅根性，生长过程中要保持盆土湿润，有利茎叶生长。同时，盆土过湿对翠菊影响更大，引起徒长、倒伏和发生病害。长日照植物，对日照反应比较敏感，在每天15小时长日照条件下，保持植株矮生，开花可提早。若短日照，植株长高，开花椎迟。　　翠菊喜肥沃湿润和排水良好的壤土、砂壤土，积水时易烂根。夏秋开花。', '　　翠菊为国内外非常重要的园艺　　翠菊常用播种繁殖。因品种和应用要求不同决定播种时间。若以盆栽品种小行星系列为例：可以从11月至翌年4月播种，开花时间可以从4月到8月。翠菊每克种子420～430粒，发芽适温为18～21℃，播后7～21天发芽。幼苗　　可根据需要分批播种控制花期。矮型种2～3月在温室内播种或3月在阳畦内播种，5一6月即可开花；4～5月露地播种7～8月开花；7月上申旬播种，可在“十一”开花；8月上中旬播种，幼苗在冷床中越冬，翌年“五一”开花。中型品种5～6月播种，8～9月开花；8月播种需冷床越冬，翌年5～6月开花。高型品种春夏皆可播种，均于秋季开花，但以初夏播种为宜，早播种开花时株高叶老，下部叶枯黄。', 'http://img.boqiicdn.com/Data/BK/P/imagick80081451554515.jpg', 'http://www.boqii.com/entry/detail/2381.html', '');
INSERT INTO `plant_family` VALUES ('300', '鸡冠刺桐', 'Erythrina crista－galli Linn.', '鸡冠刺桐', '鸡冠豆，巴西刺桐，象牙红', '不容易死', '原产巴西，秘鲁及菲律宾，印度尼西亚，中国湾、云南西双版纳。', 'http://www.boqii.com/entry/photo/2165/0,http://www.boqii.com/entry/photo/2165/5362', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '豆科', '刺桐属', '鸡冠刺桐', 'Erythrina crista－galli Linn.', '', '　　鸡冠 　　鸡冠刺桐为落叶灌木或小乔木，茎和叶柄稍具皮刺。羽状复叶具3小叶；小叶长卵形或披针状长椭圆形，长7－10厘米，宽3－4.5厘米，先端钝，基部近圆形。花与叶同出，总状花序顶生，每节有花1－3朵；花深红色，长3－5厘米，稍下垂或与花序轴成直角；花萼钟状，先端二浅裂；雄蕊二体；子房有柄，具细绒毛。荚果长约15厘米，褐色，种子间缢缩；种子大，亮褐色。', '　　的外形酷似鸡冠，故此命名。鸡冠刺桐为落叶灌木或小乔木，我国的鸡冠刺桐花期为4－7月，成株后树干粗50厘米，树高约5－8米，条件好的话，甚至可以涨到10米左右。　　鸡冠刺桐喜光，也耐轻度荫蔽，喜高温，但具有较强的耐寒能力。适应性强，生性强健，耐旱且耐贫瘠，还能抗碱，但不耐水浸。对土壤要求不严，但排水良好的肥沃壤土或砂质壤土最佳。北方盆栽时，冬季适温应保持4℃以上。栽培不择土壤，植于全日照或半日照之地均能生长迅速，树形较小，适作行道树、远景树。　　鸡冠刺桐在春季定植，定植前应先下足基肥，以有机肥为主。定植后及时水分。定植成活后，每季施一次有机，并每个月浇一次500倍液的尿素水肥，以促进枝叶生长。成株后每年施一次有机肥或复合肥，可保证其正常生长。树干自然分枝低，在园林中可通过定杆抹芽，培植主干作小乔木。', '　　鸡冠　\n　一、播种繁殖\n　　种子随采随播最好。于夏初进行，播前适当浸种，直接播于苗床，苗床土以疏松的沙壤土为宜，播后覆土以盖过种子的两倍高度为宜，注意喷水保湿。10天左右就可出苗，1个月后待幼苗长至20厘米时进行移栽。　\n　二、扦插繁殖\n　　剪去半木质化枝条，长约20－40厘米，插于沙床或疏松苗床中，保持湿润，约15天即可生根发芽，1－2个月即可成苗。华南沿海地区常用长枝扦插，1－2个月后即可生根。', 'http://img.boqiicdn.com/Data/BK/P/imagick57581446111055.jpg', 'http://www.boqii.com/entry/detail/2165.html', '');
INSERT INTO `plant_family` VALUES ('301', '白网纹草', 'Fittonia verschaffeltti', '白网纹草', '费道花、银网草、银网、费丽花、白菲通尼亚草', '不容易死', '秘鲁和南美洲的热带雨林', 'http://www.boqii.com/entry/photo/2213/0,http://www.boqii.com/entry/photo/2213/5314', '', '', '', '', '', '', '', '', '', '　　 　　白网纹草为多年生草本植物，植株低矮，约5～20公分高，枝条斜生，不直立，呈匍匐状蔓生，高约5～20厘米。叶十字对生，卵形或椭圆形，茎枝、叶柄、花梗均密被茸毛，其　　　　　　　　　　　　　　　　', '　　白网纹草的叶片纹理是其最大的特色，现在，白网纹草在欧美国家非常流行，常常能在窗台、阳台甚至居室中发现白网纹草的身影。想要养好白网纹草并不难，只要注意其习性，你的白网纹草也能长的很健康。　　1、浇水：喜多湿的环境。春、夏季生长期宜多浇水，掌握“宁湿勿干”的浇水原则，但不宜盆内积水。另外，维持较高的空气湿度，有利于生长。但尽量避免向叶面喷水，否则易引起叶片和脱落。秋末过了生长期，就应该逐渐减少浇水的次数，叶片不发干即可。　　2、：喜高温，不耐寒。生长适温为20℃——30℃。养好白网纹草比较关键的一点就是温度。白网纹草对温度非常敏感，温度不可低于15℃。冬季需将盆栽移至温暖、防风处。　　3、光照：喜半阴的环境。白网纹草不能接受强烈直射的阳光，尤其是夏季要避免光线过强，否则易导致叶子边缘发焦、脱落。但在长期的栽培过程中，也必须有适宜的光照。长期置于阴暗处，叶片会失去光泽，茎杆纤细。因此，适宜每天有4到6小时的散射光照为好。　　4、土壤：需要肥沃疏松，微酸性的土壤。盆土可用富含有机质的砂质壤土，并加少量基肥配成，也可用疏松和保的草炭营养土。　　5、施肥与维护：毋需施肥即可生长良好。若每1到2月施颗粒状复合肥或稀薄液肥一次，可使叶色与光泽更亮丽。施肥时应注意避免肥料接触叶面。', '　　白网纹草是非常适合盆栽的，但是白网纹草被人工栽培的　　\n一、扦插繁殖：\n　　网纹草在适宜温度条件下，全年可以扦插繁殖，以5～9月温度稍高时扦插效果最好。从长出盆面的匍匐茎上剪取插条，长10厘米左右，一般需有3～4个茎节，去除下部叶片，稍晾干后插入沙床。如插壤温度在24～30℃时，插后7～14天可生根。若温度过低，插条生根较困难。一般在插后1个月可移栽上盆。　\n　二、分株繁殖：\n　　对茎叶　\n　三、组培繁殖：\n　　常以叶片和茎尖作外植体。', 'http://img.boqiicdn.com/Data/BK/P/imagick5561447320555.jpg', 'http://www.boqii.com/entry/detail/2213.html', '');
INSERT INTO `plant_family` VALUES ('302', '翡翠景天', 'Sedum marganianum', '翡翠景天', '串珠草,千佛手，菊丸', '不容易死', '原产墨西哥，世界各国多有栽培', 'http://www.boqii.com/entry/photo/2405/0,http://www.boqii.com/entry/photo/2405/5010', '　', '', '', '', '景天科', '景天属', '', 'Sedum marganianum', '', '　　 　　翡翠景天的整个植株浅绿色，只要栽培得当，串珠状的茎、叶悬垂铺在花盆四周，显得格外雅致。', '质茎匍匐生长肉质叶抱茎生长，整个株形很像人工制作的，是美丽的室内垂吊花卉。温暖半阴环境，冬季放冷室内，维持10℃左右并保持盆土稍干燥。　　为多年生草本肉质，喜欢阳光充足、干燥及通风的环境。由于翡翠景天的肉质叶饱满，整个植株很像人工制作的玛瑙串珠，非常适合在室内垂吊观赏。　　翡翠景天为景天科多肉植物，原产墨西哥,性喜温暖半阴的环境,忌强光直射,适合在疏松砂壤土中生长。室内盆栽,多用草炭土、细沙等量混合配制。　　翡翠景天适应性强,喜光线充足,在室内散射光下生长最好,茎叶肥厚青翠。生长期保持土壤稍干燥,夏季高温时呈半休眠状态,浇水不宜过多,如果盆土过湿,通风不好,极易引起叶子脱落。平时要少搬动,因其小叶极易碰撞脱落。　　翡翠景天成株后茎叶下垂,颇似人工雕刻的绿玛瑙串珠,晶莹光亮,采用吊盆、吊篮栽植剪取嫩枝直接插入素沙温床，在25℃湿度条件下，25天即可生根发芽。栽培较粗放。翡翠景天茎叶肥厚，耐旱，适宜种植在通风、半阴半阳的环境里。　　夏季高温季节，应少浇水，放在阴凉处。冬季，室内温度不应低于lO℃。浇水掌握见干见湿，浇水过多常常会引起烂根黄叶，以少浇为宜。翡翠景天茎、叶肥厚，能贮藏大量水分，比较耐旱，盆栽要求排水良好的沙壤土;喜半荫条件，宜种于室内通风凉爽处，在夏季高温多湿条件下加上通风不良，极易引起落叶腐烂。栽培中浇水不宜过多。肉', '　　　　翡翠景天常扦插繁殖,全年都可进行,但以茎叶　　翡翠景天以扦插法繁殖，可以叶插，也可以用带叶的茎扦插。盆栽用土用泥潭土1份与沙2份的混合土。生长季节保持盆土略干燥，避免因长期潮湿引起的', 'http://img.boqiicdn.com/Data/BK/P/imagick61571452244522.jpg', 'http://www.boqii.com/entry/detail/2405.html', '');
INSERT INTO `plant_family` VALUES ('303', '假龙头花', '', '假龙头花', '随意草、囊萼花、棉铃花、伪龙头、芝麻花、虎尾花、一品香', '不容易死', '', 'http://www.boqii.com/entry/photo/2371/0,http://www.boqii.com/entry/photo/2371/5045', '', '', '', '', '', '', '', '', '', '　　假龙头花为多年生宿根草本，引起花朵排列在花序上酷似芝麻的花，所以又名芝麻花。假龙头花的花期为7－9月，花色淡紫红，较耐寒，能耐轻霜冻，非常适合盆栽观赏或种植在花坛、花境中。 假龙头花 　　假龙头花的茎丛生而直立，四棱形，株高可达0.8米。单叶对生，披针形，亮绿色，边缘具锯齿。穗状花序顶生，长20厘米至30厘米。每轮有花2朵，花筒长约2.5厘米，唇瓣短。　　　　　　　　　　　　', '　　的花色鲜艳，栽培管理的难度不高，非常适合大型盆栽或，在花境、花坛中丛植别有一番风味。由于假龙头花的花色为淡紫红色，属于冷色系，所以非常适合与暖色的)、红鸡冠等职务搭配种植。　　假龙头花喜疏松、肥沃、排水良好的砂质壤土，夏季干燥则不良。花期7～9月。成株丛生状，盛开的花穗迎风摇曳，婀娜多姿。生性强健，地下匍匐茎易生幼苗，栽培1株后，常自行繁殖无数幼株。　　1、土质：栽培土质要求不高，但以排水良好的肥沃砂质壤土生育最佳。　　2、光照：栽培处日光照射需良好，荫蔽处植株易徒长，开花不良。　　3、：切花栽培株距30厘米，整地时预先混合腐熟堆肥作基肥，定植成活后摘心1次，促使多分枝。追肥以氮、磷、钾每月施用1次。磷、钾肥比例稍多，可促进开花。　　4、湿度：春至夏季为盛育期，栽培地宜保持足够的湿度，切勿任其干旱影响生育和开花。老株冬或早春整枝1次，3年生以上宜再更新栽培。　　5、盆栽：宜使用大盆，每8寸盆植2～3株，盆土多有利根部伸展，1～2年后应强制分株换盆。高大的植株，易引起倒伏，切花栽培必要时设立支柱或采用尼龙网固定枝条。性喜温暖至高温，生育适温18～28℃。', '　　　　假龙头花的人工繁殖一般用分株或扦插法。春、秋季为分株适期，只要切取成株长出的幼株或地下根茎另植即可。亦可在秋季剪取健壮新芽，扦插于排水良好的砂床，待发根后再移植。　　因结实率不高，种子稀，故大多用分根繁殖。分根在早春或花后进行，把', 'http://img.boqiicdn.com/Data/BK/P/imagick13091451380956.jpg', 'http://www.boqii.com/entry/detail/2371.html', '');
INSERT INTO `plant_family` VALUES ('304', '荷包花', 'Calceolaria', '荷包花', '元宝花、状元花、蒲包花', '不容易死', '于南美洲墨西哥、秘鲁、智利一带', 'http://www.boqii.com/entry/photo/1970/0,http://www.boqii.com/entry/photo/1970/5557', '植物　', '被子植物门', '双子叶植物纲', '玄参目', '玄参科', '玄参科蒲包花属', '', 'slipper wort；Pocketbook Plant', '', '　　 　　当荷包花最初出生于南美洲安第斯山区时，当地的老乡们对它并不好感，认为它是一个不愿与人沟通的“鼓气袋”，除了孩子们从野外摘来玩耍外，多数成年人对它均不屑一顾。谁料后来有人把它形容为“荷包”之后，当地土人的观念就彻底更新了。', '　　荷包花的花期较长，并且花色艳丽，外形十分独特，所以深受人们的喜爱。在冬春季节，荷包花是比较重要的盆栽，有的花友非常荷包花，但却不知道应该如何养好荷包花，小编就为你整理了关于荷包花的栽培方法与，喜欢的朋友们可以一起了解。　　盆栽荷包花用土，可以2份腐叶土、2份园土、1份碧糠灰混合配制，并加1份厩肥。荷包花对土壤要求严格，忌土湿，以微酸的土壤为好。荷包花喜温暖湿润，但忌土壤过湿，平时浇水不宜过多，待土壤发白时才浇水，并注意不使水聚集在叶面及芽上，以免烂叶烂心。盆周围要常喷水，增加周围环境湿度。幼苗期注意通风，温度保持12～15℃为宜。花前每10天施一次腐熟饼肥水。开花期温度不要高，维持5～7℃即可。花期不能把水浇到花朵上，否则不易结果实。荷包花为长日照，要保证光照充足。花茎抽出后，容易发生蚜虫危害，需注意防治。', '　　　　繁殖荷包花益用播种法，可于八月下旬到九月天气凉爽时进行，不宜太早，髙温闷热天气易使小苗腐烂，播种太晚则植株较小。荷包花种子　　留种要注意选择优良母株并进行人工授粉，在花将凋谢时，可将花冠摘去，以避免腐烂而影响结实，同时也使营养集中有利于种子发育饱满。　　荷包花幼苗期管理必须精细，气温过高、土壤过湿等都会引起倒苗死亡。要及时剔除染病植株，喷代森锌并保持盆土较干燥。室内栽培中，空气过分干燥时，也易发生红蜘蛛与蚜虫的', 'http://img.boqiicdn.com/Data/BK/P/imagick65861440150564.jpg', 'http://www.boqii.com/entry/detail/1970.html', '');
INSERT INTO `plant_family` VALUES ('305', '假昙花', 'Rhipsalidopsis gaertneri', '假昙花', '垂花掌、亮红仙人指、连叶仙人掌', '不容易死', '原产墨西哥，现各地广泛栽培', 'http://www.boqii.com/entry/photo/2080/0,http://www.boqii.com/entry/photo/2080/5447', '植物　', '被子植物门', '', '', '仙人掌科', '假昙花属', '假昙花', 'Rhipsalidopsis gaertneri', '', '　　假 　　假昙花可高2－6米，老茎圆柱状，木质化。分枝多数，叶状侧扁，披针形至长圆状披针形，长15－100厘米，宽5－12厘米，先端长渐尖至急尖，或圆形，边缘波状或具深圆齿，基部急尖、短渐尖或渐狭成柄状，深绿色，无毛，中肋粗大，宽2－6毫米，于两面突起，老株分枝产生气根；小窠排列于齿间凹陷处，小形，无刺，初具少数绵毛，后裸露。', '　　假)又名清明蟹抓兰，与昙花、令箭)相似，和蟹抓兰的外形最为相似，不了解的朋友几乎难以分辨。其实对于低温比较不耐受，当室温低于5摄氏度的话，假昙花就会停止生长。　　假昙花为栽培方法与)相似，假县花喜半阴的环境，在华北地区，夏季需遮光50％～60％，越冬温度不低于10℃。假县花比蟹爪兰耐高温和抗干旱的能力较差。若不善，可能会出现大量枝条脱落，严重时会根系腐烂，植株死亡。原因是在高温干旱时会出现休眠，根系吸收能力显着下陴。适宜的生长温度为15～25℃。花蕾形成后不宜随意搬动，保持盆土湿润，否则容易落蕾落花。　　用泥炭土或腐叶土3份加1份沙或珍珠岩作盆栽用土。这种植物的根系不十分发达，栽种到直径10～13厘米的小盆中，花盆不宜过大。盆栽时，盆下部1／4左右填充颗粒状的碎砖块、盆片等，以利排水，透气，通常在春末或夏初，开花后有哲短的休眠期，此期适宜换盆，换盆时将根部的旧培养土轻轻抖掉，再用新培养土重新栽植。如果用悬吊法种植，则可以用苔藓做盆栽基质，将植株栽种在浅盆中，待植株恢复生长后，悬吊在室内欣赏。　　假昙花在整个生长和开花期需要充足的水分，使盆土经常保持湿润，但避免盆内积水。花期结束后有2～3周休眠期。要少浇水，只维持盆土不完全干燥即可。休眠期过后逐步增加浇水量。开始时盆土表面1厘米左右变干，底土仍然湿时便可以浇水，直到开春为止。冬季室内温降至15℃以下时，应少浇水，以保持盆土不干即可。假昙花喜湿润，为保持较高的空气湿度，可在植株周围台架、地面等处每天洒水数次。', '　　和许多多肉植物不同的是，假昙花在夏季是生长旺期，对于水肥的需求量较大，在中国，假昙花被广泛栽培。有的朋友对假昙花并不是非常了解，就让小编带你认识一下假昙花的繁殖方法。　\n　一、扦插\n　　扦插变态茎繁殖。盆栽用土可以选用2份草炭土和1份粗沙、1份炉渣的混合土。令箭荷花具有耐旱、怕涝、喜肥、畏寒的特点，　　冬季是休眠期，应控制浇水，停止浇肥，使盆土略显干燥。充足的光照是促使令箭荷花开花多的首要条件，因此温室内应保证周年光线充足，避免夏季中午前后的强光直射即可。　\n　二、嫁接\n　　为了培养伞状的悬垂株形，增加观赏价值，可用嫁接法进行繁殖。嫁接通常多在春、秋季进行。砧木多选用量天尺（俗称“三棱箭”），叶仙人掌及片状仙人掌。若用量天尺作砧木，在三个棱分别各接一个接穗；若选用叶仙人掌或片状仙人掌作砧木，可在顶部纵切一裂口，将接穗基部两面用刀片削去皮层，露出木质部，直接插入砧木切口内，用塑料条捆绑并罩上塑料袋，放置在遮阴处进行养护。一周后，接穗仍保持挺拔、鲜绿，表明成活。通常，嫁接40天后，就可将苗盆移到阳光处进行正常养护　\n　三、播种\n　　多用于新品种的培育。从播种需4～5年才能开花。假昙花播种后约2—3周能发芽。　　假昙花原产巴西亚热带地区林下，性喜温暖、半阴环境，适生温度在15℃至25℃，宜于疏松、肥沃、沙壤土生长。生长期每半个月施用一次稀薄有机液肥（浓度为20％），亦可少量施用复合化肥或经过发酵的黄豆浸泡液。夏季须将苗盆置于凉棚下莳养，保持盆土“见干见湿”即可，千万不能水量过大，否则会造成茎节大量脱落。　　假昙花为短日照植物，可以在7月初进行遮光处理，每天见光8小时，其余时间要用不透光的黑色塑料薄膜罩起来，大约9月下旬就可开花。开花时宜将苗盆置于冷凉处，温度以15℃为宜，这样可以延长花期。　　假昙花在空气干燥、通风不良的环境中，主要有叶斑病、枯萎病', 'http://img.boqiicdn.com/Data/BK/P/imagick76261443431323.jpg', 'http://www.boqii.com/entry/detail/2080.html', '');
INSERT INTO `plant_family` VALUES ('306', '大和锦', 'Echeveria pur－pusorum', '大和锦', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2161/0,http://www.boqii.com/entry/photo/2161/5366', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '', '大和锦', 'Echeveria pur－pusorum', '', '　　 　　大和锦为多肉植物，肉质叶排成紧密的莲座状，叶片广卵形至散三角卵形，背面突起呈龙骨状。叶长3cm－4cm，宽约3cm。先端急尖。叶色灰绿。上有红褐色的斑纹。花序高约30cm。小花红色，上部黄色。其株形奇特，酷似一朵莲花。', '　　为多浆植物，其肉质叶片排成紧密的莲座状，非常漂亮。大和锦的叶色为灰绿色，上面有红褐色的，在我国常见的大和锦均为杂交的酒神。小编就为你介绍一下如何才能养好大和锦。　　大和锦它是温暖的通风良好的环境，最适宜自栽培的时候用肥沃并且是排水良好的沙质土壤，在它的生长期间是要求要有一定的空气湿度的，但是土壤也是不必过于湿润的，在冬季也是需要为它节制浇水的，它能够很好的耐5度的低温。　　一般来说光线的越大越多就越能够体现出它的色彩与形状，大和锦它可以经受持续的干燥的和干旱的，但是如果在它的生长季节能够接受到充足的滋润，它们也是能够长得更加的强壮的，大和锦它能够耐霜，但最好是在5－10的气温下过冬的，每个月也是需要施一次腐熟的稀薄的液肥为最佳的。在夏季高温的时候就需要停止施肥了，最好是将它放置在通风良好的，没有直射的阳光的地方进行，冬季还要很好的为它节制浇水。', '　　很多多肉　　将大和锦的叶片掰下，然后晾至1－2天以后放置在或者是扦插在', 'http://img.boqiicdn.com/Data/BK/P/imagick14521446109320.jpg', 'http://www.boqii.com/entry/detail/2161.html', '');
INSERT INTO `plant_family` VALUES ('307', '鹿角蕨', 'Staghorn fern', '鹿角蕨', '麋角蕨、蝙蝠蕨、鹿角羊齿', '不容易死', '澳大利亚东部热带地区，新几内亚岛、小巽他群岛及爪哇、中国云南', 'http://www.boqii.com/entry/photo/2177/0,http://www.boqii.com/entry/photo/2177/5351', '　　', '蕨类植物门', '真蕨纲', '水龙骨目', '鹿角蕨科', '鹿角蕨属', '', 'Platycerium wallichii Hook.', 'Platycerium wallichii', '　　 　　鹿角蕨的根状茎肉质，短而横卧，密被鳞片；鳞片淡棕色或灰白色，中间深褐色，坚硬，线形，长10毫米，宽4毫米。叶2列，二型；基生不育叶 （腐殖叶） 宿存，厚革质，下部肉质，厚达1厘米，上部薄，直立，无柄，贴生于树干上，长达40厘米，长宽近相等，先端截形，不整齐，3－5次叉裂，裂片近等长，圆钝或尖头，全缘，主脉两面隆起，叶脉不明显，两面疏被星状毛，初时绿色，不久枯萎，褐色。正常能育叶常成对', '　　鹿角蕨是水龙骨科鹿角蕨属植物，为附生性观赏蕨，由于鹿角蕨的外形和梅花鹿角很像，故此命名。鹿角蕨独特的外形也让它成为了室内立体绿化的好材料，目前，鹿角蕨在欧美栽培的普及度较广，近几年，我国对鹿角蕨的开发和利用也日趋成熟起来了。　　　　鹿角蕨应在特制的盆钵内（即盆壁上钻若干圆形小孔，每个小孔直径均为3～5厘米）栽时先用新鲜棕榈皮将盆壁及盆底的孔口空隙填好，再放入腐叶土、褐泥炭土及稍湿锯木屑，然后将植株栽入盆内浇透水，放阴凉处。也可用少量的蕨根、或腐叶土加腐熟饼肥作基质，将植株绑扎在带树皮的一段茎杆上，悬挂于阴湿处。待植株恢复生长后，再悬挂在能见到散射光的天花板下或书架上。要尽量避免用手触摸鹿角蕨，否则其叶面的白色绒毛易脱落。　　　生长旺季要多浇水并经常喷水，保持较高的空气湿度。夏季生长盛期需多浇水，在早晨或傍晚低时浇灌，并经常喷水，保持栽培环境有较高的空气湿度，有利于营养叶和孢子叶的生长。冬季低温时，应少浇水，以防止烂根。浇水时间尽量安排在晴天中午温度较高的时候进行。　　　可在生长期，每旬喷施稀释饼肥水或于叶面喷洒速效性稀尿素，保持叶片嫩绿、肥厚。每年在成型鹿角蕨的盆篮中腐叶土或苔藓，以利新孢子体的生长发育。最怕乱施肥、施浓肥和偏施氮、磷、钾肥，要求遵循“淡肥勤施、量少次多、营养齐全”的施肥（水）原则。　　最适生长温度为18℃～30℃，忌寒冷霜冻，越冬温度需要保持在10℃以上，在冬季气温降到4℃以下进入休眠状态，如果环境温度接近0℃时，会因冻伤而死亡。　　　鹿角蕨怕强光照射，要避免强光直射或干燥风吹袭。在室外应置于树荫或荫棚下，同时要注意经常向叶面喷水。室外养护，可吊放荫棚下，要避免烈日照射，以免叶片黄化、灼伤，影响鹿角蕨的观赏价值。每隔一、二个月移到室外半荫处或遮荫养护一个月，以让其积累养分，恢复长势。', '　　鹿角蕨　　鹿角蕨常用分株繁殖，多在晚春或初夏，在成株上剪取幼株另植，剪时要连盾状假叶一起切下，定椬于紫萁纤维、水藓碎末、碎木炭与腐叶土或泥炭土混和的基质中，置阴湿的环境中', 'http://img.boqiicdn.com/Data/BK/P/imagick67121446542148.jpg', 'http://www.boqii.com/entry/detail/2177.html', '');
INSERT INTO `plant_family` VALUES ('308', '琴叶珊瑚', 'Jatropha integerrima Jacq.', '琴叶珊瑚', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2174/0,http://www.boqii.com/entry/photo/2174/5354', '　', '被子植物门', '双子叶植物纲', '大戟目', '大戟科', '麻疯树属', '琴叶珊瑚', 'Jatropha integerrima Jacq.', '', '　　 　　琴叶珊瑚的花为聚伞花序，花瓣5片，花冠红色，似', '　　的乳汁有毒，所以人工栽种过程中需要注意，避免被小孩或误食，如果误触乳汁引起水泡或脓疱，严重发炎，对亦极有毒害。宠物误食青叶珊瑚的落叶的话，还会造成口部严重起泡。　　琴叶珊瑚喜高温高湿环境，怕寒冷与干燥，越冬要保持在12℃以上。喜充足的光照，稍耐半荫；喜于疏松肥沃富含有机质的酸性砂质土壤中。所以，琴叶珊瑚比较适合在深圳生长。　　琴叶珊瑚原产于西印度群岛，我国南方多有栽培。光照不足时易产生叶多花少的情形发生，原产于西印度的日日樱，其原生环境跟台湾非常的类似，故适应的非常好，而被广泛应用于景观上。琴叶珊瑚性喜温暖干燥及充足的阳光，家庭栽培不能放在缺少阳光直射的地方，生长适温26～28℃，如低于10℃则易落叶但仍能开花。', '　　　　琴叶珊瑚常见繁殖用扦插法，于春季进行。琴叶珊瑚是优良的　　随着经济的发展，人们对园林绿化的要求不断提高，琴叶珊瑚的应用越发广泛，琴叶珊瑚因其叶美、花艳、花期长、易于繁殖', 'http://img.boqiicdn.com/Data/BK/P/imagick4201446457037.jpg', 'http://www.boqii.com/entry/detail/2174.html', '');
INSERT INTO `plant_family` VALUES ('309', '芍药', 'Paeonia lactiflora Pall.', '芍药', '将离、离草、婪尾春、余容、犁食、没骨花、黑牵夷、红药等', '不容易死', '中国扬州仪征', 'http://www.boqii.com/entry/photo/2101/0,http://www.boqii.com/entry/photo/2101/5426', '', '', '', '', '', '', '', '', '', '　　 　　芍药花一般独开在茎的顶端或近顶端叶腋处，也有一些稀有　　　　　　　　　　　　　　　　　　　　　喜温耐寒砂质壤土　　　　　　　　　　', '　　自古就作为爱情之花，现在已经被奉为七夕节的代表花卉，在红楼梦中，芍药也是非常重要的花卉。芍药为多年生，其适应性强、耐寒，在我国北方可露地越冬。　　　　一般于8月下旬至9月栽植，宜早不宜晚，最迟不超过10月下旬，否则芍芽已发新根，会影响芍药的产量和质量。为出苗整齐，便于管理，应将芍芽按大小分级进行穴栽。栽植行株距50厘米×30厘米，穴深12厘米、直径20厘米；穴内先浇足水，水渗下后在穴底铺4厘米厚的腐熟厩肥，其上覆土4厘米厚，压实后将芍芽芽尖朝上放入穴中间，每穴放芍芽1－2个。栽后每穴培土10－15厘米高。越冬前要浇足防冻水。　　　　排水要好，芍药喜凉爽气候，我国温带至亚热带地区都适宜栽培，具有春发芽、秋生根的特性，在夏季。高温炎热，植株呈半休眠状态，喜欢肥沃疏松、排水良好的沙质壤土，忌碱土。由于芍药是肉质根，耐旱但怕积水，如土壤板结积水很容易使芍药肉质根，所以低洼地、盐碱地均不宜栽培。　　因此，地栽宜选择凉爽阳光充足之地，盆栽忌浇水过多。入冬至早春的整个休眠期，土壤都应保持湿润，不可太干，但排水要畅通，忌积水，否则地下块根易腐烂致死。　　　芍药是喜肥作物。除施足基肥外，从栽后第2年起，每年需追肥3次；第1次在3月中耕除草后，每亩施人畜粪肥水1500－－－2000公斤；第2次、第3次分别在5月和7月，每次每亩施人畜粪肥水1500公斤、饼肥25－30公斤，或三元复合肥40－－60公斤。芍药喜干怕涝，一般不需浇水，仅需在严重干旱时一次灌透水。多雨季节必须清沟排水，否则淹水6小时后会导致烂根而全株枯死。', '　　　　芍药的繁殖有分根繁殖和种子繁殖等方法，　　芍药还采用分株繁殖。俗语称“春分分芍药，到老不开花”，因此芍药通常于10月份待其地上部分枯萎后进行分株，春季不宜移植。分株时需将根株掘出，用利刀顺根部裂缝处切开，使每丛带有3至5个饱满充实的芽及下面的根群，切忌伤害芽眼，然后栽于施过基肥的沙质土壤中，覆土3至4厘米，保持土壤润而不渍，一般分株栽植后第二年即能开花。　　盆栽芍药可结合分株一两年换盆一次，换盆时应多保留些宿土。如株丛不大，就不要分株。', 'http://img.boqiicdn.com/Data/BK/P/imagick67801444384225.jpg', 'http://www.boqii.com/entry/detail/2101.html', '');
INSERT INTO `plant_family` VALUES ('310', '日本晚樱', 'Oriental Cherry', '日本晚樱', '重瓣樱花', '不容易死', '原产日本，日本庭园中常见栽培；中国引入栽培。', 'http://www.boqii.com/entry/photo/2111/0,http://www.boqii.com/entry/photo/2111/5416', '　', '被子植物门 Angiospermae', '双子叶植物纲 Dicotyledoneae', '蔷薇目 Rosales', '蔷薇科 Rosaceae', '樱属 Cerasus', '日本晩樱', 'Prunus serrulata var. lannesiana', 'Prunus serrulata var. lannesiana', '　　 　　日本晚樱为乔木，高3－8米，树皮灰褐色或灰黑色，有唇形皮孔。小枝灰白色或淡褐色，无毛。冬芽卵圆形，无毛。叶片卵状椭圆形或倒卵椭圆形，长5－9厘米，宽2.5－5厘米，先端渐尖，基部圆形，边有渐尖单锯齿及重锯齿，齿尖有小腺体，上面深绿色，无毛，下面淡绿色，无毛，有侧脉5－8对；叶柄长1－1.5厘米，无毛，先端有1－3圆形腺体；托叶线形，长5－8毫米，边有腺齿，早落。', '　　在日本的栽培历史非常悠久，阳性，喜温湿气候，较耐寒，园艺品种也非常多，有着日本国花的美名。那么日本晚樱在栽培过程中应该注意哪些呢？　　　定植的地点应选阳光充足之处；由于类都是浅根性树种，所以应选土壤肥沃和避风之处；最适宜的地形是有缓坡而低处有湖池的地点。　　　每年开花前和夏末秋初花芽形成期分别松土培根，并施肥1次。　　　　大树可任其自然，不加修剪，以免影响其生长。但应剪除过密弱枝，以改善树冠通风和增加光照。尽早剪除病虫枝。', '　　很多人都见过　　日本晚樱的园艺变种颇丰，以重瓣粉红色品种为上品，其种子甚少，用枝条扦插生根又很困难，故繁殖系数小，限制了它在园林中的应用。以往研究在提高日本晚樱的繁殖系数方面均未取得突破性进展。而梅属　　日本晚樱在苗床土壤选择上一般采用膨胀的　　在用砖垒成的苗床底层铺2至3厘米的河沙，再填入15厘米厚的蛭石。每隔1米装1个离心式喷头，天气转热时要适当遮阴，经常喷水以保证湿度。周围可用树枝作篱笆挡风，插条成行垂直插于蛭石中，株距2厘米，行距4厘米，插后灌透水。扦插深度6至8厘米为宜。', 'http://img.boqiicdn.com/Data/BK/P/imagick78011444642683.jpg', 'http://www.boqii.com/entry/detail/2111.html', '');
INSERT INTO `plant_family` VALUES ('311', '蝴蝶花', '三色堇', '蝴蝶花', 'fringed iris', '不容易死', '原产欧洲北部，现分布世界各地', 'http://www.boqii.com/entry/photo/2072/0,http://www.boqii.com/entry/photo/2072/5455', '', '', '', '', '', '', '', '', '', '　　 　　蝴蝶花为一、二年生或多年生草本，高10－40cm。地上茎较粗，直立或稍倾斜，有棱，单一或分枝。基生叶叶片长卵形或披针形，具长柄；茎生叶叶片卵形、长圆状圆形或长圆状披针形，先端圆或钝，基部圆，边喙具稀疏的圆锯齿或钝锯齿；上部叶叶柄较长，下部者较短；托叶大型，叶状，羽状深裂。花大，直约约3.5－6cm，小苞片对生，极小，卵状三角形，萼片长圆状披针形，基部附属物发达；上方花瓣紫堇色，侧方及下方花瓣均为三色；距较细，长5－8mm，无毛。花期4－7月，果期5－8月。　　　　　　　　　　　　　　　　', '　　很多花友都非常喜欢蝴蝶花，也有花友会在自己家中进行栽培，但是没有经验的花友往往会不得要领而将蝴蝶花养死。小编就为你介绍一下蝴蝶花在过程中的注意要点，喜欢蝴蝶花的朋友可以跟着小编一起学习一下。　　　尽管)较喜阴，但仍需要使兰株能接受部分光照，尤其花期前后，适当的光可促使蝴蝶兰开花，使开出的花艳丽持久，一般应放在室内有散射光处，勿让阳光直射；如放在室内窗台上，要用窗纱遮去部分阳光。　　　可以选择松针叶、花生壳、树皮丝、粘土球等材料作为养殖蝴蝶兰的基质。蝴蝶兰对土壤要求较高，需要透气、耐、微酸、透水。如果自己无法配置好这些材料的话，可以直接到花市蝴蝶兰专用的兰土。（PS：种植蝴蝶兰的盆子可以选择塑料盆或者陶瓷盆，考虑到蝴蝶兰喜欢透气的环境，建议选择多孔浅盆，盆高小于盆直径的最好）。　　　栽培在室内的蝴蝶兰的养殖温度是有讲究的，白天温度最好控制在25－28度之前，夜间的温度需要控制在18－20度。蝴蝶兰产于亚热带，因此高温高湿度的环境很适合蝴蝶兰的生长（夏季温度高于32度时，蝴蝶兰会直接进入半休眠状态，所以要防止高温。），当温度较低的情况下，蝴蝶兰的生长会受到抵制，据有关资料上称，当温度在15度时，蝴蝶兰的生长直接是停滞的状态。而低于15度时，根系会停止对水分的吸收。会造成叶片出现黑斑。北方的冬季天气较为严寒，室内的温度也较低，不过可以开暖气，当室内温度低于15度时，要特别小心的呵护蝴蝶兰，白天将蝴蝶兰放置在向阳的地方，减少浇水次数。或者通过地面洒水的方式。晚上需要对其进行保温，给它套上兰株套袋。利用供暖设备给兰株进行供暖时一定要注意不能让暖气片离花太近。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick29311443087482.jpg', 'http://www.boqii.com/entry/detail/2072.html', '');
INSERT INTO `plant_family` VALUES ('312', '木兰花', 'magnolia', '木兰花', '木兰，辛夷，紫玉兰，木笔', '不容易死', '原产于我国中部，现在各省均有栽培', 'http://www.boqii.com/entry/photo/2005/0,http://www.boqii.com/entry/photo/2005/5522', '植物　', '被子植物门', '', '木兰目', '木兰科', '木兰属', '', 'Magnolia liliflora Desr.', 'M. liliflora Desr', '　　木 　　木兰花高1.5－3m或更高。树皮淡灰褐色；小枝细长，疏生细', '　　木)又名辛夷、紫玉兰等，由于古代将木兰和玉兰统称为木兰，直到明代才将玉兰从木兰中分出来，所以现在木兰和玉兰是两种。木兰花的朋友往往会受到一些限制而不能自己进行栽培，小编就为你介绍一下木兰花的栽培方法及。　　木兰花喜光，较耐寒，但不耐旱。要求肥沃砂质土壤，不耐碱。怕水淹。木兰花喜湿润半阴的气候，喜肥，有良好通透性的土壤冬季要挖穴，施有机肥，如骨粉，饼肥。木兰花耐寒性较强，但忌旱和涝，平时要保证水分的供应，经常向叶面喷水，增加空气湿毒，以免黄叶落叶。　　木兰移栽在春天花前或秋天落叶后进行，中小苗需宿土，大苗带土球。木兰喜肥，每年10～11月施人腐熟的堆厩肥作基肥，花后萌芽抽枝期间，追施2～3次速效氮肥，旱季根际覆盖并适量浇水。翌年可望花繁叶茂。　　木兰要成乔木树形，必须进行除蘖萌芽和整枝。木兰根腐病、红蜘蛛、钻心虫等应及时。', '　　木　　木兰花多用压条、分株法繁殖。有时也用播种。分株，春、秋季均可进行，挖出枝条茂密的母株分别栽植，并修剪根系和短截枝条。压条，选用一二年生枝条，在早春可用堆土法或埋条法繁殖。播种，9月采种，冬季沙藏，翌年春播，播后20－30天发芽。栽培', 'http://img.boqiicdn.com/Data/BK/P/imagick43961441533674.jpg', 'http://www.boqii.com/entry/detail/2005.html', '');
INSERT INTO `plant_family` VALUES ('313', '玫瑰', 'Rosa ', '玫瑰', '徘徊花、刺客、穿心玫瑰', '不容易死', '中国华北、西北和西南', 'http://www.boqii.com/entry/photo/1989/0,http://www.boqii.com/entry/photo/1989/5538', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '蔷薇属', '玫瑰', 'Rosa rugosa', '', '　　 玫瑰花 　　玫瑰为直立灌木，高可达2米；茎粗壮，丛生；小枝密被绒毛，并有针刺和腺毛，有直立或弯曲、淡黄色的皮刺，皮刺外被绒毛。小叶5－9，连叶柄长5－13厘米；小叶片椭圆形或椭圆状倒卵形，长1.5－4.5厘米，宽1－2.5厘米，先端急尖或圆钝，基部圆形或宽楔形，边缘有尖锐锯齿，上面 粉红色，无毛，叶脉下陷，有褶皱，下面灰绿色，中脉突起，网脉明显，密被绒毛和腺毛，有时腺毛不明显；叶柄和叶轴密被绒毛和腺毛；托叶大部贴生于叶柄，离生部分卵形，边缘有带腺锯齿，下面被绒毛。花单生于叶腋，或数朵簇生，苞片卵形，边缘有腺毛，外被绒毛；花梗长5 －22 5毫米，密被绒毛和腺毛；花直径4－5.5厘米；萼片卵状披针形，先端尾状渐尖，常有羽状裂片而扩展成叶状，上面有稀疏柔毛，下面密被柔毛和腺毛；花瓣倒卵形，重瓣至半重瓣，芳香，紫红色至白色；花柱离生，被毛，稍伸出萼筒口外，比雄蕊短很多。果扁球形，直径2－2.5厘米，砖红色，肉质，平滑，萼片宿存。花期5－6月，果期8－9月。', '　　玫瑰是现在非常常见的观赏，也是现在很多情侣之间会送的礼物，由于玫瑰的作用非常多，所以其经济价值很高。玫瑰的香气宜人，深受人们的欢迎，小编就为你整理了关于玫瑰花栽培的方法及，喜欢玫瑰的朋友可以一起了解。玫瑰花　　玫瑰花喜光、喜阳、耐严寒和干旱，在北方冬季不需要特护防冻。只要不出大旱天，不浇水也可生长（指地栽）。对土壤要求不严，一般较肥沃土壤即可生长旺盛，枝繁叶茂，开花良好。夏季施肥要勤，每隔15～20天需施一次，施肥后应及时浇水，以防烧苗。秋季要修剪，以防徒长，影响开花和株型美观。玫瑰多蚜虫，要注意防治。　　玫瑰花的栽培对土壤要求不严，但以中碱性或微土壤最宜，微酸性土壤也可。因此，玫瑰应栽植在通风向阳及浇灌、排水条件好的田间、地边的肥沃壤土中。玫瑰忌低洼易涝地，遇涝时下部叶片变黄脱落乃至全株死亡。玫瑰的花芽和萌动要求平均气温7度以上，从萌动初期到花开期需要效积温365度，一般应当时的气温高低而定。玫瑰花期最忌干热风和土壤干旱，有水利条件的田块可进行一次蕾期灌水。玫瑰在的过程中有两次停止生长期（一般在6－7月称夏眠；11－12月称冬眠），此时不发枝，枝条不伸长。夏眠期是采花苗木的最佳修剪期，可配施底肥、灌好越冬水，为来年花蕾的稳产高产奠定基础。', '　　玫瑰花　\n　一、分株繁殖\n　　分株前1年，要在母株根际附近施足　　\n二、压条繁殖\n　　在每年6～8月梅雨季节，选当年生的健壮枝条，使之弯曲入土，将入土部分刻伤后用土块嵌入伤口，埋入土中，用竹叉或树杈固定，让枝梢露出地面，保持土壤湿润，2～3个月就可生根，翌年春可与母株分离，另行栽植。　　在早春萌芽前，选取生长健壮、无病虫害的1年生枝条，剪成20cm左右长的插穗，斜插于新河砂作成的插床中，深度为12～14cm，压实后浇水，经常保持砂床的', 'http://img.boqiicdn.com/Data/BK/P/imagick95121441014192.jpg', 'http://www.boqii.com/entry/detail/1989.html', '');
INSERT INTO `plant_family` VALUES ('314', '茜之塔', 'Crassula corymbulosa', '茜之塔', '', '不容易死', '南非', 'http://www.boqii.com/entry/photo/2197/0,http://www.boqii.com/entry/photo/2197/5330', '', '', '', '', '', '', '', '', '', '　　 　　茜之塔为多年生肉质草本植物，矮小的植株呈丛生状，高仅5～8厘米，直立　　Crassula corymbulosa　　　　　　　　　　', '　　的叶片肥厚、叶形奇特，四季常绿，所以深受多肉爱好者们的喜爱。人工栽培茜之塔只要注意保证其充足的光照即可，栽培难度并不高。　　茜之塔宜阳光充足和温暖、干燥的环境，不耐寒，忌水湿、高温闷热和过于阴蔽，耐干旱和半阴。主要期在春天、初夏及秋天，要给予充足的光照，否则会因光照不足影响叶色和光泽。保持盆土湿润而不积水。夏季高温时植株处于休眠或半休眠状态，植株或完全停止，宜放在通风凉爽、光线明亮，又无直射阳光处养护，不必浇过多的水，以防。冬季放在室内阳光充足处，10℃以上可使植株继续生长，应适当浇些水，如果保持盆土干燥，使植株休眠，也能耐5℃的低温。　　　要求疏松、肥沃，并具有良好的排水性，可用园土、粗沙或各2份，腐叶土1份混匀后配制，并加少量的骨粉和鸡、牛粪作基肥。　　　生长期浇水“干透浇透”，夏季高温时植株处于休眠或半休眠状态，不必浇过多的水。冬季控制浇水，低于5度停止浇水。　　　生长期每半个月施一次腐熟的稀薄液肥或低氮，高磷、钾的复合肥。但施用量不宜过多，以免茎叶徒长，节间距离伸长，使植株松散，严重影响观赏。　　　当植株长满花盆时，可在春季进行换盆。', '　　　　茜之塔的繁殖可结合春季换盆进行分株，方法是将　　也可在生长', 'http://img.boqiicdn.com/Data/BK/P/imagick6321447059839.jpg', 'http://www.boqii.com/entry/detail/2197.html', '');
INSERT INTO `plant_family` VALUES ('315', '蒜香藤', 'garlic vine', '蒜香藤', '紫铃藤、张氏紫葳', '不容易死', '西印度至阿根廷，中国华南区', 'http://www.boqii.com/entry/photo/2336/0,http://www.boqii.com/entry/photo/2336/5080', '　', '被子植物门', '双子叶植物纲', '管状花目', '紫葳科', '蒜香藤属', '蒜香藤', 'Mansoa alliacea （Lam.）A.H.Gentry', '', '　　 　　蒜香藤为常绿攀缘性', '蒜香藤性喜高温，　　蒜香藤开花时的观赏价值比较高，仿佛垂挂着团团的粉彩绣球，非常漂亮。蒜香藤的生性强健，且少病虫害，栽培难度不高，很适合种成花廊、花架等。　　蒜香藤对土质不拘，盆植或地植皆宜。栽培地点一定要光照充足，否则开花稀疏或不开花，全日照的环境最佳。由于植株具蔓性，若任其自由伸展，枝条易显杂乱，建议每年春季花开后可进行整枝。　　蒜香藤栽培时需要充足的光线和温暖的气候，不耐寒，长期的寒风吹刮会影响生长。一般种植在向阳背风，疏松、肥沃的微酸性的砂质壤土。露地栽培只需在夏季干燥时浇水，盆栽夏季每天浇1次水，冬季每3～4天浇1次水。蒜香藤较天然有机肥，可在定植时，于植穴中施入腐熟，成熟后每月施用1次氮、磷、钾复合肥。露地栽培应选择排水好的地点。盆栽土可选择园土、木屑、泥炭土各一份来调配栽培用土。由于花和叶片具有浓烈的蒜香味，拒绝食用，栽培中尚未发现明显的病虫害。', '　　　　蒜香藤可用播种、扦插或压条繁殖。', 'http://img.boqiicdn.com/Data/BK/P/imagick36431450345019.jpg', 'http://www.boqii.com/entry/detail/2336.html', '');
INSERT INTO `plant_family` VALUES ('316', '半枝莲', 'Scutellaria barbata', '半枝莲', '并头草、韩信草、赶山鞭、牙刷草', '不容易死', '阿根廷、巴西南部、乌拉圭以及中国大陆等地', 'http://www.boqii.com/entry/photo/2039/0,http://www.boqii.com/entry/photo/2039/5488', '', '', '', '', '', '', '', '', '', '　　 　　半枝莲的花单生于茎或分枝上部叶腋内，具花的茎部长4～11厘米；苞叶下部者似叶，但较小，长达8毫米，上部者更变小，长2～4.5毫米，椭圆形至长椭圆形，全缘，上面散布下面沿脉疏被小毛；花梗长1～2毫米，被微柔毛，中部有一对长约0.5毫米具纤毛的针状小苞片。花萼开花时长约2毫米，外面沿脉被微柔毛，边缘具短缘毛，盾片高约1毫米，果时花萼长4.5毫米，盾片高2毫米。花冠紫蓝色，长9～13毫米，外被短柔毛，内在喉部疏被疏柔毛；冠筒基部囊大，宽1.5毫米，向上渐宽，至喉部宽达3.5毫米；冠檐2唇形，上唇盔状，半圆形，长1.5毫米，先端圆，下唇中裂片梯形，全缘，长2.5毫米，宽4毫米，2侧裂片三角状卵圆形，宽1.5毫米，先端急尖。雄蕊4，前对较长，微露出，具能育半药，退化半药不明显，后对较短，内藏，具全药，药室裂口具髯毛；花丝扁平，前对内侧后对两侧下部被小疏柔毛。花柱细长，先端锐尖，微裂。花盘盘状，前方隆起，后方延伸成短子房柄。子房4裂，裂片等大。　　　　　　　　　　　　　　　　　　　　　　　　', '　　半枝莲不但是很好的药用植物，还能盆栽在阳台、窗台等处做观赏用。虽然半枝莲的种植难度并不高，但是想要种出漂亮的半枝莲则需要注意一些栽种的方法。　　1、移苗及上盆：具3片叶时移苗或上盆，盆栽时，花盆口径15厘米的每盆栽苗3株，口径20厘米的每盆栽苗5～6株。露地定植的株距为10～15厘米。对土壤适应性极强，但在肥沃疏松而排水良好的土壤中最好。露地栽植要避免种植在地势低洼、易积水的地方。盆栽基质可用园土、腐叶土、砻糠灰等材料配制。忌黏重土壤，否则易造成根茎腐烂。　　2、：喜温暖，生长适宜温度为20～30℃。不耐寒，最低温度应不低于8°。能耐高温，但30°0以上时不但开花变小，花数也会减少。　　3、光照：对光照反应敏感，为强阳性花卉。不耐荫蔽，整个生长期都需要充足的光照，才能使植株正常生长与开花。夏季高温天气，正值植株生长与开花的最旺时期，也需给予充足的阳光，植株才能开花茂盛、花色鲜艳。偏阴时，开花少而小。如遇多阴或多雨天气，开花会变差，同时容易茎根腐烂。大花马齿苋只在晴天上午开花，所以称为“半日花”；温度太高的晴天也会提早闭合。　　4、浇水：由于肉质的茎叶能贮藏水分，所以具较强的抗旱能力，在较干旱的条件下也能生长与开花。但要使植株能良好生长与开花，也需供给适当的水分。忌过湿和积水，7尺分多时容易引起植株茎叶徒长，甚至烂根。浇水应掌握“不干不浇，涕则浇透”的原则，避免盆土过湿。梅雨期在雨后要及时倒去盆中的积水。　　5、：喜干燥的环境，空气相对湿度不宜大，否则会引起烂茎现象。　　6、施肥：对肥料要求不高，但给予合理的阳水才能生长与开花良好。肥料不足时，植株与花朵均小。苗期需追施2～3次稀薄的氮肥，以使幼苗苗壮和促进分枝。人夏后每半月追施1次氮磷钾结合的肥料，以促使植株的旺盛生长与开花。', '　　半枝莲又称龙须牡丹、　　1、播种：种子发芽需皋20°以上的　　2、扦插：通常用于重瓣', 'http://img.boqiicdn.com/Data/BK/P/imagick84471442309157.jpg', 'http://www.boqii.com/entry/detail/2039.html', '');
INSERT INTO `plant_family` VALUES ('317', '蛛丝卷绢', 'Sempervivum arachnoideum ssp. tomentosum', '蛛丝卷绢', '', '不容易死', '欧洲西南部', 'http://www.boqii.com/entry/photo/2312/0,http://www.boqii.com/entry/photo/2312/5211', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '', '', 'Sempervivum arachnoideum ssp. tomentosum', '', '　　 　　蛛丝卷绢的单株直径1.5－3.5厘米。植株较矮，接近球形，贴地而生。有大量蜘蛛网般质地的绒毛缠绕在叶尖，但野生植株的绒毛可能在秋、冬季消失。野生状态下叶片排列极紧密，极易分株，侧芽长大后会形成稠密的簇状。叶片扁平，一般为嫩绿色，呈竹片形，顶端稍尖。花瓣粉色，有深色条纹。', '　　是长生草属多肉植物，其叶尖有白色的丝，养的久了之后，叶尖的丝则会互相缠绕，就像织满了蛛丝的网。蛛丝卷绢的栽培难度并不高，但需要了解其生长习性，你的蛛丝卷绢才会长得漂亮。　　蛛丝卷绢十分耐寒，对高温敏感，注意空气流通。配土一般可用泥炭、蛭石和珍珠岩的混合土。夏季易腐烂，强光时会红。夏季高温时休眠，基本断水，避强光并保证良好的通风。生长期浇水干透浇透，浇水时注意不要从植株顶部浇水，否则丝状毛会消失，甚至会烂心。夏季休眠期适度遮阴，通风并控制浇水，否则极易腐烂，冬季保持盆土稍干燥；生长期施肥一般每月一次。　　生长适温15－25度，冬季不低于5度；配土，泥炭混合珍珠岩加了煤渣，大概比例1：1：1，为了隔离植株和土表，也为了更加透气，可铺上颗粒的干净河沙，河沙尺寸3到5毫米。浇水是干透才浇透，不干不浇水。春天和秋天是生长期，可以全日照。夏季休眠期适度遮阴，通风并控制浇水，否则极易腐烂，每个月3到4次水，少量在盆边给水。以维持植株不会因为过度干燥而干枯。低于3度就要逐渐断水，0度以下保持盆土干燥，尽量保持不低于零下5度。', '　　　　蛛丝卷绢繁殖方法有播种、分株和砍头扦插。一般用最简便的分株法。取下小侧芽，扦插在微湿的土壤里，阴凉通风的地方等待发根就可以了。扦插用土壤可同成株用土。常用的叶插，枝插，分株的都能繁殖。繁殖用走出枝条萌生的子株，叶插也十分容易，杂交极易获得种子。', 'http://img.boqiicdn.com/Data/BK/P/imagick80311449824694.jpg', 'http://www.boqii.com/entry/detail/2312.html', '');
INSERT INTO `plant_family` VALUES ('318', '清盛锦', 'Aeonium decorum f·variegata', '清盛锦', '艳日晖、灿烂', '不容易死', '', 'http://www.boqii.com/entry/photo/2297/0,http://www.boqii.com/entry/photo/2297/5227', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '莲花掌属', '', 'Aeonium decorum f·variegata', '', '　　 　　清盛锦的植株稍具分枝，叶肉质，呈莲座状排列。叶片倒卵圆形，顶端尖，正面中央稍凹，并具细绒毛，背面有龙骨状凸起，叶缘有睫毛状细锯齿，叶片色彩丰富，中央部分为杏黄色，与淡绿色间杂，外缘则呈红、红褐及粉红等色。花为总状花序，花后全株枯萎死亡，故栽培中一般不让植株开花。', '　　清盛锦的植株多呈分枝的灌木状，喜欢日照，光照充足和缺光会有很大的差别。当环境干燥时，可以适当向植株喷水，以保持叶片清新。人工栽培清盛锦还应该注意哪些呢？　　清盛锦应避免闷热、潮湿的环境，否则植株容易。冬季则尽可能地多见阳光，如果能保持12℃以上的，可继续浇水，使植株。假如维持不了这么高的温度，保持盆土适度干燥，也能耐5℃的低温。值春、秋季生长期，不可过于荫蔽；充分浇水，保持盆土湿润，但不能持续积水，空气干燥时要向植株喷水，以使叶片清新。每20天左右施一次腐熟的稀薄液肥，注意肥水不要溅到叶片上。根据生长情况，每2～3年换盆一次，换盆以初春或初秋植株刚开始生长时为佳，盆土宜用排水、透气性良好的沙壤土。', '　　　　清盛锦的繁殖可在春、秋两季的　　生长适温15－25度，冬季不低于5度；配土一般用泥炭＋蛭石＋珍珠岩各一份；浇水生长', 'http://img.boqiicdn.com/Data/BK/P/imagick63961449567244.jpg', 'http://www.boqii.com/entry/detail/2297.html', '');
INSERT INTO `plant_family` VALUES ('319', '千佛手', 'Sedeveria', '千佛手', '菊丸、王玉珠帘', '不容易死', '各地', 'http://www.boqii.com/entry/photo/2129/0,http://www.boqii.com/entry/photo/2129/5398', '　', '', '', '', '景天科', '景天属', '千佛手', 'Sedeveria\'Harry Butterfield\'', '', '　　千 　　千佛手为草本或亚灌木，千佛手叶互生，有时小而覆瓦状排列，花排成顶生的聚伞花序，常偏生于分枝之一侧，萼4－5裂，花瓣4－5，分离或基部合生，雄蕊与花瓣同数或2倍之，心皮4－5，离生，有时基部连合，有胚珠多颗，果为一蓇葖。', '　　千的栽培难度并不高，并且由于的植株并不大，所以非常适合放在办公桌上。虽然千佛手的栽培难度比较低，但是如果不根据其习性进行饲养的话，千佛手还是会出现被养死的情况的。　　　土壤，用多用专用最方便，如泥炭（草炭）＋砾石＋珍珠岩；　　　生长适温一般为18－25度，冬季不低于5度；　　　水分，依照干透浇透的原则就行（非常耐旱，尽量少浇水）；一个月浇水1～2次，无需过多，否则会烂根。　　　喜光，可以全日照，夏季通常遮些荫；　　　　施肥一般在生长季一月一次，薄肥勤施，可随浇水施入。', '　　千　\n　1、播种繁殖\n　　千佛手种子繁殖可在　\n　2、扦插繁殖\n　　千佛手全年都可扦插，以春秋季扦插效果最好。剪取项端枝，长5一7厘米，稍晾干后插入沙床，插后3－4周生根。也可用中下部成熟叶片扦插，约3周生根，待长出幼株后盆栽。　　一般在生长季将植株下部成熟的叶子轻轻掰下平放在潮土上即可，一般2周左右生根，生根后保持土壤潮润即可。　　千佛手分株繁殖可在生长季将植株周边的小植株（或徒长植株的上部枝条）用利刀割下，晾一周后栽种在潮土中，一周后才可以正常浇水。', 'http://img.boqiicdn.com/Data/BK/P/imagick51541445331959.jpg', 'http://www.boqii.com/entry/detail/2129.html', '');
INSERT INTO `plant_family` VALUES ('320', '春兰', 'Cymbidium goeringii （Rchb. f.） Rchb. f.', '春兰', '朵兰、扑地兰、幽兰、朵朵香、草兰', '不容易死', '中国、日本、朝鲜半岛南端等', 'http://www.boqii.com/entry/photo/2034/0,http://www.boqii.com/entry/photo/2034/5493', '', '', '', '', '', '', '', '', '', '　　 　　春兰为地生植物；假鳞茎较小，卵球形，长1－2.5厘米，宽1－1.5厘米，包藏于叶基之内。叶4－7枚，带形，通常较短小，长20－40（－60）厘米，宽5－9毫米，下部常多少对折而呈V形，边缘无齿或具细齿。　　　　　　　　　　　　　　　　　　', '　　春兰是我国栽种历史最长久的兰花品种之一，经过人们长期的栽培，想要养好春兰就需要遵循古人为我们总结出的“四戒”经验，即“春不出、夏不日、秋不干、冬不湿”。　栽培春兰宜在秋末进行。栽植前宜选用清水浸洗数小时的新瓦盆，如用紫砂盆或塑料盆时需注意排水，盆的大小以花根能在盆内舒展为宜。土以兰花泥最为理想，或用腐叶土（即针叶土是最为理想的腐殖土）和沙壤土混匀使用。切忌用碱性土。　先在盆底排水孔（最好能有3个排水孔）上垫好瓦片，再垫上碎石子、碎木块等物，约占盘的1／5，其上铺一层粗沙，多面手放入培养土，最后将兰苗放入盆中，把根理直，让其自然舒展，填土至一半时，轻提兰苗，同时摇动花盆，使兰根与盆土紧密结合，继续填土至盆面和压紧，距离沿口约3厘米，以使施肥与浇水。　　上盆后浇透水放荫蔽处。早春与冬季放室内，其余放室外荫棚下（最好放在树底下）早晨8点至下午6点遮光，春兰在夏季遮光荫蔽度宜在90％左右，春、秋季为70％至80％左右即可。　　兰花叶片有较厚的角质层和下陷的气孔，比较耐旱，因此需水分不多，以经常保持兰土“七分干、三分湿”为好。春天，2天至3天浇水1次，花后宜保持盆土稍干一些，夏天气温高，可每天浇水1次，秋季则见干见湿，冬季少浇水。　　春兰在花后宜保持盆土稍干一些。但也不能过湿，干旱和炎热，傍晚应向花盆周围地面喷雾，增加空气湿度。　　一般从4月起至立秋止，每隔15天至20天施1次充分腐熟的稀薄饼肥水。', '　　春兰在开花后花香迷人，是非常珍贵的盆栽', 'http://img.boqiicdn.com/Data/BK/P/imagick36641442223694.jpg', 'http://www.boqii.com/entry/detail/2034.html', '');
INSERT INTO `plant_family` VALUES ('321', '大滨菊', 'Leucanthemum maximum （Ramood） DC.', '大滨菊', '西洋滨菊', '不容易死', '', 'http://www.boqii.com/entry/photo/2294/0,http://www.boqii.com/entry/photo/2294/5230', '　　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '茼蒿菊属', '', 'Leucanthemum maximum （Ramood） DC.', 'Leucanthemum maximum', '　　 　　大滨菊茎生叶无柄、线形。头状花序单生于茎顶，舌状花白色，有香气；管状花两性，黄色。瘦果，果熟期8至9月。大滨菊为多年生草本植物。茎直立，少分枝，株高40～110cm，全株光滑无毛。叶互生，基生叶披针形，具长柄；茎生叶线形，稍短于基生叶，无叶柄。头状花序单生茎顶，舌状花白色，多二轮，具香气；管状花黄色。', '　　的花朵洁白素雅，非常适合花境的前景或中景栽植，且大滨菊的花枝是优良的，应用非常广泛。大滨菊原产于欧洲，我国已有引种栽培。　　大滨菊性喜阳光，适生15至30℃，不择土壤，园田土、沙壤土、微碱或微酸性土均能。原产西欧，我国新近引种栽培。秋季或早春播种育苗，15～18℃条件下约7天发芽。老株需隔年秋季分栽。花后及时剪除残花。植株整齐，花量多，华中、华东地区的园林中常见。在花境，切花，花丛中比较常见。', '　　　\n　1、播种繁殖\n　　大滨菊为菊属　\n　2、分株繁殖\n　　分株春、秋季皆可。分株繁殖比较容易，且分株成活率高，开花快。　\n　3、扦插繁殖\n　　以软枝扦插较易成活，多在春季进行。插穗选择母株基部萌芽，待芽长至5～8cm时从芽基部剪取，插于素沙做成的插床上，保持', 'http://img.boqiicdn.com/Data/BK/P/imagick26381449480364.jpg', 'http://www.boqii.com/entry/detail/2294.html', '');
INSERT INTO `plant_family` VALUES ('322', '阿拉伯婆婆纳', 'Veronica persica Poir.', '阿拉伯婆婆纳（中国高等植物图鉴）', '波斯婆婆纳（江苏南部种子植物手册）', '不容易死', '', 'http://www.boqii.com/entry/photo/2285/0,http://www.boqii.com/entry/photo/2285/5240', '　　', '被子植物门', '双子叶植物纲', '管花目', '玄参科', '婆婆纳属', '', 'Veronica persica Poir.', '', '　　 　　阿拉伯婆婆纳为铺散多分枝草本，茎密生两列多细胞柔毛。叶2－4对（腋内生花的称苞片），具短柄，卵形或圆形，长6－20毫米，宽5－18毫米，基部浅心形，平截或浑圆，边缘具钝齿，两面疏生柔毛。总状花序很长；苞片互生，与叶同形且几乎等大；花梗比苞片长，有的超过1倍；花萼花期长仅3－5毫米，果期增大达8毫米，裂片卵状披针形，有', '　　原产于亚洲西部及欧洲，现在在我国的华东、华中及贵州、云南等地比较常见，为归化的路边及荒野杂草。阿拉伯婆婆纳是常见入侵，有一定的药用价值。　　阿拉伯婆婆纳生于路边、宅旁、旱地夏熟作物田，特别是麦田中，对作物造成严重，同时成为黄瓜花叶病毒、李痘病毒、蚜虫等多种微生物和害虫的寄主，分布在菠菜、甜菜、大麦等作物根部的病原菌（Aphanomycescladogamus）同时也寄生在该种植株上。', '　　　　阿拉伯婆婆纳每年有两次萌发高峰，分别在11月底和3～4月。波斯婆婆纳有很强的无性繁殖能力，茎着土易生出不定根，重新形成植株。正因波斯婆婆纳有很强的无性繁殖能力，故可将波斯婆婆纳种植在裸露的地表上，快速覆盖地表。', 'http://img.boqiicdn.com/Data/BK/P/imagick81241449134514.jpg', 'http://www.boqii.com/entry/detail/2285.html', '');
INSERT INTO `plant_family` VALUES ('323', '荷兰菊', 'New York Aster', '荷兰菊', '柳叶菊、纽约紫菀', '不容易死', '北美', 'http://www.boqii.com/entry/photo/1965/0,http://www.boqii.com/entry/photo/1965/5562', '', '', '', '', '', '', '', '', '', '　　 　　荷兰菊，须根较多，有地下走茎，茎丛生、多分枝，高60厘米至100厘米，叶呈线状披针形，光滑，幼嫩时微呈紫色，在枝顶形成伞状花序，花蓝紫色，花期为10月。荷兰菊为多年生草本。株高50—100cm。叶片椭圆形，头状花序，单生，蓝色。荷兰菊为菊科多年生宿根草本花卉，花色蓝紫或玫红，花期8－10月。　　　　　　　　　　　　　　New York Aster', '　　我们常常能在花坛、花镜的布置中看到的身影，有的花友非常喜爱荷兰菊，所以还会将荷兰菊盆栽在家中。其实荷兰菊的耐寒性非常强，即使在我国的东北地区，荷兰菊也可露地。那么盆栽荷兰菊应该注意哪些呢？　　1、适时修剪和摘心。荷兰菊是耐修剪，通过摘心和修剪可促使花朵繁密。　　2、施肥和浇水。栽种前应施足基肥，生长期每2周追施1次稀薄饼肥，促使生长旺盛。同时酌情浇水，天旱时要及时浇水。　　生长季节10－15天追施稀薄肥料1次，并注意及时浇水，入冬前浇冻水1次，即可越冬，翌年由根部重新萌芽，长成新株。每2－3年应分栽1次，剪除老根，将每株分为数丛，重新栽植。经常修剪，控制花期和植株高度。选择向阳和通风场所栽植，定植或盆栽苗高1厘米时，可进行摘心，促使多分枝。生长期每半月施肥1次。　　3、在栽培中发现病虫害要及时喷施药剂。荷兰菊一般易感染白粉病，种植时不宜过密，注意控制湿度和通风，一旦发现染病要及时喷施药剂。', '　　荷兰菊为菊科紫菀属　　\n一、播种繁殖\n　　播种期在3月上旬左右。在温室内温暖向阳处盆播或畦播。在室温不低于15℃左右条件下，7天左右可出齐苗。待苗高5cm左右时及时进行第一次分栽以免徒长。可选择口径12cm小盆或在畦中分栽。5月上旬进行第二次分栽定植，根据需要植入大盆或直接地栽。地栽株距控制在40cm左右，以利其进一步分蘖增生。　\n　二、分蘖繁殖\n　　荷兰菊分蘖能力很强，分蘖植株可单独割离分栽。分栽　\n　三、扦插繁殖\n　　多年生植株在开春后长出大量分蘖苗。可用刀将幼小的分蘖苗切取下来进行扦插。用素沙土或珍珠岩、　\n　四、嫁接栽培\n　　采用野生黄蒿作砧木进行嫁接栽培，效果较好。具体方法如下：在11月底或12月初，将荷兰菊摘去残花并翻盆换土。当室外温度降至5℃左右时，将盆搬入低温温室，不可进入中温或高温房，以免抽芽拔长，使菊苗弱不禁风。翌年立春后，将盆菊搬至室外避风处，清明节前后适量浇些人粪尿等薄肥水。在4月底到6月底期间从野外挖取黄蒿苗，栽人口径5寸或7寸的泥盆中，6、7月份视黄蒿植株', 'http://img.boqiicdn.com/Data/BK/P/imagick32821440064459.jpg', 'http://www.boqii.com/entry/detail/1965.html', '');
INSERT INTO `plant_family` VALUES ('324', '万寿菊', 'Marigold', '万寿菊', '臭芙蓉、万寿灯、蜂窝菊、臭菊花、蝎子菊、金菊花', '不容易死', '原产墨西哥，中国各地有栽培。在广东和云南南部、东南部已归化', 'http://www.boqii.com/entry/photo/2246/0,http://www.boqii.com/entry/photo/2246/5279', '', '', '', '', '', '', '', '', '', '　　万寿菊为菊科、万寿菊属草本植物，常作一年生栽培，也是现在非常常见的 　　万寿菊为一年生草本，高50－150厘米。茎直立，粗壮，具纵细条棱，分枝向上平展。叶羽状分裂，长5－10厘米，宽4－8厘米，裂片长椭圆形或披针形，边缘具锐锯齿，上部叶裂片的齿端有长细芒；沿叶缘有少数腺体。　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　万寿菊原产于墨西哥，为一年生草本，在我国各地，万寿菊均有人栽培观赏。由于万寿菊的花瓣有单瓣和重瓣之分，所以也深受花友们的喜爱。那么人工栽培万寿菊应该注意哪些呢？　　万寿菊栽培管理较简单，移栽容易成活。定植时要略施基肥，生长期可不追肥，开花前15天施追肥1次即可。雨季要注意排水防涝，过分干旱要适当灌溉，并及时防治红。　　万寿菊喜温暖湿润和阳光充足的环境，也能耐干旱。生长适宜为15－25℃，适宜空气相对温度在60－70％，冬季温度不低于5℃。夏季高温不高于30℃。万寿菊为喜光性，充足阳光使万寿菊矮壮，花色艳丽。万寿菊对土壤要求不严，但以肥沃、排水良好的沙质壤土为好。', '　　　　1、备土。万寿菊采用的基质为40％的谷壳灰和60％的河沙，谷壳灰不仅疏松排水，而且能有效防止插穗的　　2、插穗。万寿菊的插穗一般留3至5节，有无顶芽均可。插穗基部的叶片要修剪干净，以免散失过多的水分。修剪时伤口一定要光滑，插穗下部的伤口斜剪45度，上部的伤口平剪。　　3、扦插。先用插穗大小的一根小木棍在基质上打孔，株距3厘米，行距5厘米。将插穗轻轻插入事先打好的孔中，深度为插穗的1／3，用食指和大拇指稍微将插穗周围的沙摁紧。　　4、管理。扦插完后，用喷雾器将叶片喷湿即可，过多的水分容易导致插穗腐烂，然后在80厘米高的上方盖好遮阴网，以后每天上午10点和下午5点左右各喷一次雾，刚好喷湿叶片为宜。放置扦插盘的地方不能被雨淋，不能被太阳西照，否则将前功尽弃。如果遮阴网的', 'http://img.boqiicdn.com/Data/BK/P/imagick53261448271956.jpg', 'http://www.boqii.com/entry/detail/2246.html', '');
INSERT INTO `plant_family` VALUES ('325', '仙女杯', 'Dudleya brittonii', '仙女杯', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2348/0,http://www.boqii.com/entry/photo/2348/5069', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '仙女杯属', '', 'Dudleya brittonii', '', '　　 　　仙女杯有粗壮矮小的茎，会随着', '　　属目前约有100多种，叶片分为白色和绿色两种。仙女杯的观赏价值较高，但是需要充足的光照叶色才会艳丽，株型才会更加美观。那么仙女杯在栽种过程中还需要注意哪些呢？　　仙女杯干旱，光照充足的地方，却害怕暴晒，会休眠，不喜欢潮湿，这样基本上了解了仙女们的喜好，就可以根据这个来进行配土。　一般都用全颗粒土，加一成的泥炭土，颗粒土不管是麦饭石，虹彩石还是绿沸，赤玉等等都可以。你可以选择二三样混合在一起，不建议使用鹿沼，因为假的多，爱粉化，反而不利于透水透气，然后加一成泥炭土就行了。　　建议以透气性好的紫砂，粗陶为主，陶瓷盆子就不建议用了。里外全挂釉，美观够，可是透气却不够好。一次大水，三五天也不干，根容易烂的。', '　　多肉　　仙女杯繁殖只能播种与砍头，不能叶插。仙女杯三个亚属中的所有品种都有一个共同点：不能叶插繁殖。这太奇怪了，因为很多墨西哥的景天科品种都很容易叶插成活，比如和仙女杯外表有几分相像的拟石莲。而这恰好是仙女杯和拟石莲最根本的不同之处。另外由于仙女杯是大型植株，随着', 'http://img.boqiicdn.com/Data/BK/P/imagick45241450775491.jpg', 'http://www.boqii.com/entry/detail/2348.html', '');
INSERT INTO `plant_family` VALUES ('326', '静夜', 'Echeveria derenbergii', '静夜', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2384/0,http://www.boqii.com/entry/photo/2384/5032', '', '', '', '', '', '', '', '', '', '　　 　　静夜为小型　　　　　　　　　　　　　', '　　是很多多肉爱好者都非常的，但是想要养好静夜却不是那么简单。静夜喜欢阳光充足和凉爽、干燥的环境，具有冷凉季节，夏季高温休眠的习性。　　静夜夏季高温日照强烈时会休眠，要适当遮阴、减少浇水量。所以，静夜的生长适温是15－25度，冬季不低于5度，生长期浇水干透浇透，空气干燥时可向植株周围洒水，但叶面，特别是叶丛中心不宜积水，否则会造成烂心，夏季要适度遮阴，通风及节水；生长期施肥一般每20天左右一次。　　静夜对药物比较敏感，用药时要注意，最好不要误喷到叶片。缺少光线会徒长的非常难看，茎拔高生长，叶片松散。所以尽量多给一些日照吧！自身生长较慢，却很容易群生，群生后的效果也很棒。静夜怕热，容易被晒死所以放在半阴凉处，怕潮湿。可以选择一个别致的花器单独栽培。', '　　静夜是比较有名的多肉　　静夜繁殖叶插与扦插都可以，叶插较容易，但叶插苗长出后养护', 'http://img.boqiicdn.com/Data/BK/P/imagick48881451897865.jpg', 'http://www.boqii.com/entry/detail/2384.html', '');
INSERT INTO `plant_family` VALUES ('327', '叶子花', 'Bougainvillea spectabilis Willd.', '叶子花', '三角花、室中花、九重葛、贺春红', '不容易死', '', 'http://www.boqii.com/entry/photo/2183/0,http://www.boqii.com/entry/photo/2183/5345', '', '', '', '', '', '', '', '', '', '　　　　叶子花为藤状灌木。枝、叶密生柔毛；刺腋生、下弯。叶片椭圆形或卵形，基部圆形，有柄。花序腋生或顶生；苞片椭圆状卵形，基部圆形至心形，长2.5－6.5厘米，宽1.5－4厘米，暗红色或淡紫红色；花被管狭筒形，长1.6－2.4厘米，绿色，密被柔毛，顶端5－6裂，裂片开展，黄色，长3.5－5毫米；雄蕊通常8；子房具柄。果实长1－1.5厘米，密生毛。花期冬春间。　　　　　双子叶植物纲　　　　　　　', '　　的外形比较特别，其苞片常常会被误认为花瓣，由于叶子花的习性比较特别，在我国的北方地区可以作为温室盆栽，但是在华南和西南则常被露地栽培，是园林绿化和点缀的重要花卉之一。　　叶子花原产南美巴西，在我国栽培历史不长。叶子花性喜温暖湿润环境；喜光，光照不足会影响其开花；适宜生长湿度为20－30℃，不耐寒。叶子花喜肥，生长期每周须施氮肥1次，花期增施磷肥2－3次。夏季供水不足或冬季浇水过量，易造成植株落叶，所以浇水一定要做到适时、适量。花后浇水要减少。　　叶子花根系发达，生长旺盛，每年需换盆一次，适于在3－4月进行。盆土可用腐叶土或泥炭土2份、园土1份、砂土1份配制而成，盆底放一些腐熟的鸡粪和花生饼作基肥。同时剪去一部分老根和朽根。　　为保持叶子花树型美观，需对其进行修枝整形。每年可进行2次，一次在换盆时，一次可在开花后。盆栽叶子花常整修成圆头形，使其分枝多，开花密，形成丰满的树冠。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick71141446629824.jpg', 'http://www.boqii.com/entry/detail/2183.html', '');
INSERT INTO `plant_family` VALUES ('328', '迎春花', 'Winter Jasmine', '迎春花', '小黄花、金腰带、黄梅、清明花', '不容易死', '', 'http://www.boqii.com/entry/photo/1932/0,http://www.boqii.com/entry/photo/1932/5598', '', '', '', '', '', '', '', '', '', '　　迎春花又名迎春、小黄花等，常在每年的2－4月开花，由于是花卉 　　迎春花株高30－100厘米。小枝细长直立或拱形下垂，呈纷披状。3小叶复叶交互对生，叶卵形至矩圆形。花单生在去年生的枝条上，先于叶开放，有清香，金黄色，外染红晕，花期2－4月。　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　为木犀科素馨属落叶灌木，常被栽种在庭院、花坛，现在也有花友将迎春花盆栽甚至制作成种植在家中。虽然迎春花的外形并不起眼，但是却是我国名贵之一，被很多花友所喜爱。　　迎春性喜阳光，亦较耐阴，抗寒，耐旱。不择土壤，田园土、沙壤土、微酸或微碱性土均能生长。盆栽迎春花在冬季落叶后至春季发芽前上盆，盆土宜用疏松肥沃、具有良好的排水保水性的沙质土壤，栽后浇透水，放在避风向阳处。生长期浇水做到“不干不浇，浇则浇透”，避免盆土积水，否则会造成烂根，9月以后要减少浇水，以控制枝条旺长，使其安全越冬。每年春季花谢后应追施腐熟的有机液肥1次至2次，以开花所消耗的养分，使植株长势尽快得到恢复。　　6月至8月是其花芽分化期，可增加磷钾肥的使用量，并注意扣水，以有利于花蕾的形成。秋季施肥则能增加植株的抗寒能力，并促使花蕾的发育。开花前追施一些肥料，不仅可使花朵肥美，还能延长花期。每1年至2年的春季花谢后翻盆一次，盆土可用园土、腐殖土、沙土各1份混匀后配制，并加入少量腐熟的饼肥、禽畜粪等作基肥。并结合换盆对植株进行修剪，除去干枯枝、病虫枝、徒长枝，生长期注意摘心，以促使植株多分枝，维持树形的完美。由于迎春花枝条细长而柔软，除正常的垂枝生长外，还可编织成花篮形、扇形、圆球形、孔雀开屏等形状，以增加观赏价值。若需元旦或春节开花，可提前3周将苗盆移至室内向阳处莳养，保持15℃至20℃的温度，就能适时开花。迎春的花枝用水泡养，5天至7天就能开花，它是优良的冬季切花材料。', '　　　　选取生长充实的枝条，长约10厘米，去叶插于砂中，保持湿润，1个月之间便能生根成苗，当年即可制成一盆潇洒动人微型盆景。制作中型盆景时，常用分株法，既简单又快速。　　为使迎春花喜报春晓，繁花满枝，必须每年修剪。花后去基部老枝，促发新梢，5－7月间多次摘心，促发秋梢，以增加花枝。如采用催花措施则可于冬季赏花。方法是秋后控水，提前半月移入温室，并保持室温18－20℃即可。　　以扦插为主，也可用压条、分株繁殖。扦插，春、夏、秋三季均可进行，剪取半木质化的枝条12－15厘米长，插入沙土中，保持湿润，约15天生根。压条，将较长的枝条浅埋于沙土中，不必刻伤，40－50天后生根，翌年春季与母株分离移栽。分株，可在春季芽萌动时进行。春季移植时地上枝干截除一部分，需带宿土。在生长过程中，注意土壤不能积水和过分干旱，开花前后适当施肥2－3次。秋、冬季应修剪整形，保持株新花多。病虫害常发生叶斑病和枯枝病，可用50％退菌特可湿性粉剂1500倍液喷洒。虫害有蚜虫和大蓑蛾', 'http://img.boqiicdn.com/Data/BK/P/imagick39451439287149.jpg', 'http://www.boqii.com/entry/detail/1932.html', '');
INSERT INTO `plant_family` VALUES ('329', '珍珠吊兰', 'string－of－pearls', '珍珠吊兰', '佛珠、翡翠珠、绿之铃、绿铃', '不容易死', '原产非洲南部，在世界各地广为栽培。', 'http://www.boqii.com/entry/photo/2065/0,http://www.boqii.com/entry/photo/2065/5462', '', '', '', '', '', '', '', '', '', '　　珍珠 　　珍珠吊兰一粒粒圆润的、肥厚的圆心形叶片，似一串串风铃在风中摇曳，这就是它的叶子。因叶互生，　　　　　　　　　双子叶植物纲　　　　　　　　　', '　　珍珠)的叶片非常特别，圆鼓鼓的和珍珠非常像，人工栽培难度虽然不高，但是不了解其生活习性的话，还是会出现养死的情况，小编就为你整理了关于珍珠吊兰的栽培要点，喜欢的朋友可以一起了解。　　1、由于叶肉质，多汁，故耐旱。栽培中浇水应宁干勿湿，这是成功的关键之一。天气干燥时可以多向叶、蔓喷水以弥补水分的不足，保持珠体的青翠饱满。较喜半阴，暴晒可能灼伤珠体，光线过弱则不强。　　2、植株根系很浅，可浅盆栽植。一般用瓦片垫底孔，并铺上一层煤渣或粗沙以增加透气和滤水性（尤其是现在常用的塑料盆栽植的情况下），土壤最好用腐叶土（秋冬树木的落叶拌入一定量的碎土露於阎冒肽曛烈荒昙纯捎？拌入一定（土、沙比约为1：3左右）。　　3、性喜温暖湿润，较耐寒（江淮地区栽培时可耐0℃的低温），耐高温，最适温度为20℃～28℃左右。高温和低温时都，尤其是30℃以上的高温环境中几乎休眠，应少浇水施肥，否则易烂根－－这也是栽培成功的关键之一。　　4、生长旺盛的春秋季应“薄肥勤施”，常在叶面喷施1－3‰的氮肥和磷酸二氢钾有利于使珠体更加翠绿肥大，提高观赏价值。　　5、珍珠吊兰很少有病虫害，春季蚜虫是其一，及时抹去或喷1500倍氧化乐果杀灭；的螨虫为次，需用1000倍三氯杀螨醇杀灭。注意通风和增加叶面湿度，可减少感染螨虫。', '　　珍珠　\n　扦插：\n　\n　分株：\n　　\n种子：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick62441443000755.jpg', 'http://www.boqii.com/entry/detail/2065.html', '');
INSERT INTO `plant_family` VALUES ('330', '铃兰', 'Convallaria majalis Linn.', '铃兰', '草玉玲、君影草、香水花、鹿铃、小芦铃、草寸香、糜子菜、芦藜花', '不容易死', '', 'http://www.boqii.com/entry/photo/2035/0,http://www.boqii.com/entry/photo/2035/5492', '　　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '铃兰属', '铃兰', 'Convallaria majalis Linn.', '', '　　 　　铃兰是多年生草本', '　　', '　　　　铃兰通常以分割根状茎及根茎端的小鳞茎进行繁殖，春秋均可，但以秋季分栽　　露地栽培要选湿润及半阴环境，要求土质疏松、肥沃及排水良好的土壤。栽种前施足基肥，栽后浇透水，冬季盖草防寒。早春新芽萌发后撒去覆盖物，并进行松土。　　生长期间根据天气情况和土壤墒情补充水分，每隔10～15天施一次稀薄饼肥水或复合液肥，每次浇水施肥后要及时中耕除草。花梗抽生后应停止施肥，以免引起落蕾落花。花谓十后要及时剪去残花梗，使养分集中供应根茎。花谢后和8月底应再各施一次上述液肥，促使根茎生长充实，以利于花芽分化和休眠芽生长。　　铃兰也常作促成栽培，通过调节温度等措施来实现提前或推迟开花。具体方法是：秋末选择已形成花芽的健壮株丛，割取根茎（带2～3个芽），置于2～3℃的室内，经2～3周处理后即可进行促成栽培。　　为了提早开花，可于所需开花', 'http://img.boqiicdn.com/Data/BK/P/imagick11801442224359.jpg', 'http://www.boqii.com/entry/detail/2035.html', '');
INSERT INTO `plant_family` VALUES ('331', '毛娟', 'Rhododendron pulchrum', '毛鹃', '锦绣杜鹃', '不容易死', '', 'http://www.boqii.com/entry/photo/2194/0,http://www.boqii.com/entry/photo/2194/5333', '　', '被子植物门', '双子叶植物纲', '', '杜鹃花科', '杜鹃花属', '毛鹃', 'Rhododendron pulchrum', '', '　　 　　毛娟分枝稀疏，幼枝密生淡棕色扁平伏毛，叶纸质，二型，椭圆形至椭圆状披针形或矩圆状倒披针形，长2.5～5.6cm，宽8～18mm，顶端急尖，有凸尖头，基部楔形，初有散生黄色疏伏毛，以后上面近无毛，端尖钝，基楔形，缘有', '　　很多花友对于和白花杜鹃可能会混淆，其实毛娟的花冠为)紫色，并且体各部没有腺头毛，和白花杜鹃还是有一定区别的。毛娟的适应能力较强，但是不耐长的强光暴晒，想要养出健康漂亮的毛娟可以从以下几个方面入手。　　　喜酸性土壤，要求疏松、排水好，富含腐殖质。取腐植土4份，旧盆土2份，沙土、火烧土、锯木屑各1份，加入适量饼肥混匀，堆沤半个月即可使用。　　　既怕干又怕涝。11月底至次年2月中上旬，大部分露地盆栽锦绣杜鹃处于休眠或半休眠状态，视盆土干湿状况适量浇水。2月下旬气温回升，花芽、叶芽萌动，适当增加浇水次数。3～6月是新梢旺盛期，需水量增大，要酌增浇水次数。7～9月气温高，每天都要浇水。10月以后，浇水量可减少。　　　　不喜大肥，要勤施稀薄肥。基肥用长效肥料，如饼肥、骨粉和干厩熟肥等有机肥，在上盆换盆或冬季埋入盆土中。追肥用速效肥，如人粪有机肥或氮、磷、钾化肥，立春至开花前，每月施1～2次磷钾肥，开花时停止施肥。秋凉后施1～2次磷肥为主的液肥，入冬后停止追肥。', '　　　\n　一、扦插繁殖\n　　在梅雨季进行。选取半成熟嫩枝，长12～15厘米，去掉基部2～3片叶，留顶端叶片并剪去一半。插条用0.8％吲哚丁酸溶液　　\n二、压条繁殖\n　　在4～5月进行，用高空压条法。选取2～3年生成熟枝，在离枝顶20～30厘米处行环状剥皮，宽2厘米，用腐叶土和薄膜包扎。4～5个月愈合生根，秋季剪离盆栽。　\n　三、播种繁殖\n　　以4月为宜，采用室内盆播。发芽适温为22～24℃，播后10～15天发芽，幼苗', 'http://img.boqiicdn.com/Data/BK/P/imagick73031446802560.jpg', 'http://www.boqii.com/entry/detail/2194.html', '');
INSERT INTO `plant_family` VALUES ('332', '金铃花', 'Abutilon striatum', '金铃花', '灯笼花、网花苘麻、红脉商麻', '不容易死', '中国长江流域、华北沿海流域', 'http://www.boqii.com/entry/photo/2347/0,http://www.boqii.com/entry/photo/2347/5070', '植物　　', '被子植物门', '双子叶植物纲', '锦葵目', '锦葵科', '苘麻属', '金铃花', 'Abutilon striatum', 'Abutilon striatum Dickson', '　　 　　金铃花为常绿灌木，成株可高达1米。叶掌状3－5深裂，直径5－8厘米，裂片卵状渐尖形，尖端长渐尖，边缘具锯齿或粗齿，两面均无毛或仅下面疏被星状柔毛；叶柄长3－6厘米，无毛；托叶钻形，长约8毫米，常早落。', '　　', '　　由于　　金铃花的繁殖主要用扦插繁殖，6月－8月扦插。以1年－2年生健壮枝或当年生半木质化的嫩枝作插穗，长10厘米－12厘米，去掉下部叶，插入土中1／2或1／3深，保湿润。　　扦插繁殖的2年生金铃花株高可达2米左右，主茎直径2一3厘米。茎呈灰绿色，多年生植株的茎呈灰色或灰褐色。春季萌发新梢的能力非常强，枝条萌生于叶腋，当年生枝条呈翠绿色，木质化程度较低，枝条柔软。金铃花的叶片有两种，一种是卵圆形，长10厘米，具长叶柄，整个叶柄粗细均匀；另一种是掌状，12一18厘米。叶片排列呈轮生状态，为4一9片叶一轮。在光线好的地方或是健壮的植株，叶片一般为掌状，在光线差的地方或是长势稍弱的植株，叶片为卵圆形。', 'http://img.boqiicdn.com/Data/BK/P/imagick40221450691877.jpg', 'http://www.boqii.com/entry/detail/2347.html', '');
INSERT INTO `plant_family` VALUES ('333', '龟背竹', 'Monstera deliciosa Liebm.', '龟背竹', '蓬莱蕉、铁丝兰、穿孔喜林芋、龟背蕉、电线莲、透龙掌', '不容易死', '原产于墨西哥，福建、广东、广西、云南、北京、湖北等地均有分布', 'http://www.boqii.com/entry/photo/1958/0,http://www.boqii.com/entry/photo/1958/5569', '　　', '被子植物门', '单子叶植物纲', '天南星目', '天南星科', '龟背竹属', '龟背竹', 'Monstera deliciosa Liebm.', '', '　　 　　龟背竹的茎绿色，粗壮，有苍白色的半月形叶迹，周延为环状，余光滑，长3－6米，粗6厘米，节间长6－7厘米，具气生根。叶柄绿色，长常达1米，腹面扁平，宽4－5厘米，背面钝圆，粗糙，边缘锐尖，基部甚宽，对折抱茎，排列为覆瓦状，形如鸢尾，两侧叶鞘宽，向上渐狭，脱落后叶柄边缘成绉波状；叶片大，轮廓心状卵形，宽40－60厘米，厚革质，表面发亮，淡绿色，背面绿白色，边缘羽状分裂，侧脉间有1－2个较大的空洞，靠近中肋者多为横圆形，宽1.5－4厘米，向外的为横椭圆形，宽5－6厘米；中肋及侧脉表面绿色，背面绿白色，两面均隆起；I次侧脉8－10对，基部的相互靠近，向上渐远离，II、III、IV级叶脉网状，不明显。', '　　背竹虽然是比较常见的室内，但是龟背竹净化空气的能力并不像吊兰、芦荟等那么强，不过，龟背竹对于空气中的甲醛净化效果非常明显，所以帮助改善室内空气质量也是有一定的作用的。龟背竹的栽培难度并不大，但是还是需要选用透气性好的土壤，以帮助龟背竹排水。　　1、怕强光暴晒。龟背竹是典型的耐阴植物，规模性须设遮荫设施，可用50％遮阳网，尤其播种幼苗和刚扦插成活苗，切忌阳光直射，以免叶片灼伤。成型植株盛夏期间也要注意遮荫，否则叶片老化，缺乏自然光泽，影响观赏价值。　　2、畏空气干燥。龟背竹自然于热带雨林中，喜湿润，但盆栽土积水同样会烂根，使植株停止生长，叶子下垂，失去光泽，叶片凹凸不平。浇水应掌握宁湿不干的原则，经常保持盆土潮湿，但不积水，春秋季每2～3天浇水1次。盛夏除每天浇水外，需喷水多次，以保持叶面清新，悬挂栽培应喷水更勤。冬季叶片蒸发量减弱，浇水量要减少。　　3、薄肥勤施好。龟背竹是比较耐肥的观叶植物，为使多发新叶，叶色碧绿有自然光泽，生长期每半月施1次肥，施肥时注意不要让肥液沾污叶面。同时，龟背竹的根比较柔嫩，忌施生肥和浓肥，以免烧根。最好使用“卉友”20－8－20四季用高硝酸钾肥和20－20－20通用肥，对龟背竹的生长更为有利。　　4、需绑扎整形。龟背竹为大型观叶植物，茎粗叶大，特别成年植株的分株时，要设架绑扎，以免倒伏变型。待定型后支架拆除。同时，定型后茎节叶片生长过于稠密、枝蔓生长过长时，注意整株修剪，力求自然美观。', '　　　　\n一、播种\n　　龟背竹夏季开花，为了提高种子的结实率，需人工授粉，以上午9～10时和下午3～4时二次授粉最好，授粉成功率高。授粉至种子成熟需要15个月。种子　　播种前先将种子放40℃温水中浸泡10小时，播种土应高温消毒。龟背竹种子较大，可采用点播，播后室温保持20～25℃，箱口盖上塑料薄膜，保持80％以上湿度，播后一般20～25天发芽。播种过程中如室温过低，不仅影响出苗，甚至种子发生水渍状　\n　二、扦插\n　　春、秋两季都能采用茎节扦插，以春季4～5月和秋季9～10月扦插效果最好。因为这段时间气温适宜茎节切口愈合生根，成活快。　　插条选取茎组织充实、　　\n三、分株\n　　在夏秋进行，将大型的龟背竹的侧枝整段劈下，带部分气生根，直接栽植于木桶或钵内，不仅成活率高，而且成型效果快。', 'http://img.boqiicdn.com/Data/BK/P/imagick24791439976961.jpg', 'http://www.boqii.com/entry/detail/1958.html', '');
INSERT INTO `plant_family` VALUES ('334', '海桐', 'Pittosporum tobira', '海桐', '海桐花、山矾、七里香、宝珠香、山瑞香', '不容易死', '中国江苏南部、浙江、福建、台湾、广东等地；朝鲜、日本亦有分布', 'http://www.boqii.com/entry/photo/2023/0,http://www.boqii.com/entry/photo/2023/5504', '植物　', '被子植物门', '双子叶植物纲', '蔷薇目', '海桐科', '海桐花属', '海桐', 'Pittosporum tobira', 'Pittosporum', '　　 　　海桐的嫩枝被褐色柔毛，有皮孔。叶聚生于枝顶，二年生，革质，嫩时上下两面有柔毛，以后变秃净，倒卵形或倒卵状披针形，长4－9厘米，宽1.5－4厘米，上面深绿色，发亮、干后暗晦无光，先端圆形或钝，常微凹入或为微心形，基部窄楔形，侧脉6－8对，在靠近边缘处相结合，有时因侧脉间的支脉较明显而呈多脉状，网脉稍明显，网眼', '　　海桐为常绿灌木或小乔木，四季常青的海桐较耐阴，适应能力比较强，但是在我国黄河以北的地区，海桐多为盆栽，以便在室内', '　　　　海桐一般采用播种或扦插繁殖。春秋　　扦插繁殖可在春季和秋季进行，选取一年生木质化健壮枝条，剪成长10厘米左右插穗，扞插后浇透水，要在保持基质湿度的同时进行遮阴，7-10天后可微弱阳光照晒，促进生根，40天左右可生根。生根后注意水肥管理，春季扦插的桢株，秋季可进行移植；秋季扦插的植株，可在第二年春季进行移植。', 'http://img.boqiicdn.com/Data/BK/P/imagick51341441877569.jpg', 'http://www.boqii.com/entry/detail/2023.html', '');
INSERT INTO `plant_family` VALUES ('335', '紫薇花', 'Lagerstroemia indica L.', '紫薇', '入惊儿树、百日红、满堂红、痒痒树', '不容易死', '', 'http://www.boqii.com/entry/photo/1954/0,http://www.boqii.com/entry/photo/1954/5573', '', '', '', '', '', '', '', '', '', '　　紫薇的花期为6－9月，由于紫薇的花期比较长，并且在夏季和秋季，因此有“百日红”之称，也是非常好的观花、观干、观根的材料。紫薇不但花色艳丽，非常讨人喜爱，其根、皮、叶及花都可入药，所以紫薇的经济价值非常高。 　　紫薇其喜暖湿气候，喜光，略耐阴，喜肥，尤喜深厚肥沃的砂质壤土，好生于略有湿气之地，亦耐干旱，忌涝，忌种在地下水位高的低湿地方，性喜温暖，而能抗寒，萌蘖性强。紫薇还具有较强的抗污染能力，对二氧化硫、氟化氢及氯气的抗性较强。半阴生，喜生于肥沃湿润的土壤上，也能耐旱，不论钙质土或酸性土都　　　　　　　　　　　　　　　　　　　', '　　紫薇是很多花友都非常的观赏，由于紫薇的花期比较长，所以又称为百日红，虽然紫薇是观赏花木，现在也已经被人制作成盆景放在室内栽培。小编就为你介绍一下关于紫薇的栽种方法及注意事项，有兴趣栽种紫薇的朋友可以一起了解。　　在11月落叶后至第二年3月栽植。栽植时留主干高100～130厘米，剪去上部。待新的春梢后选留角度适宜的3～4个主枝，让其开花。　用当年老枝插活的成苗进行盆栽是快速培养盆景的好方法。由于紫薇枝条柔软，盆栽的紫薇可适当进行攀扎。一般在春梢生长停止，枝条趋半木质化时进行盘扎和造形，用细棕绳牵引制成各种姿态的盆景。　　一般紫薇比较粗放。3月上旬应施抽梢肥，氮磷钾结合：5月下旬至6月上旬施一次磷钾肥，以壮枝和催花；7月下旬和9月上旬各施一次花期肥，为饼肥水等，使花开得艳丽。发现病害，用波尔多液或600倍的多菌灵液防治。　　紫薇的花是生长在当年萌发的春梢顶部，萌发力强，树冠不整齐，因此需要进行修剪。　　1、冬季修剪：为保证正常开花，且形成大花序，冬季修剪很重要。地栽的应在主枝定干（拳）高度处剪去当年生的枝条，使翌年抽出壮枝开花；盆栽的首先剪去所有的萌蘖枝、病枯枝、交叉重叠枝，为了美化造型，对其他枝条的饱满顶芽的上方｀1厘米处短截，一般只保留5厘米左右。　　2、花后修剪：在夏季开花后应剪去一部分残花，不让其结籽，以减少养分损耗，促进萌发新枝和开花。生长期修剪切忌对春季萌发的新枝进行修剪或短截，否则易造成只长枝不开花，以上为栽培管理技术资料。', '　　紫薇原产于东南亚至大洋洲，现在在我国栽培非常广泛，由于紫薇有一定的抗旱和抗寒能力，并且花期长，　\n　一、播种养殖\n　　播种养殖可得到大量健壮而整齐的苗木。在10—11月采果，经晾晒，果实开裂，去皮净种。来年春天在沙质壤中条播或洒播。紫薇采种一般在10月下旬至11月中旬，视果子变黄至深黄色且有少数果壳微裂开口时分次采收。因紫薇种子很小，收早了干后种子是瘪的；收晚了果壳大都开裂，饱粒掉落，收的只是半熟种子。所以把握　\n　二、扦插养殖\n　　在处境萌芽前选1—2年生旺盛枝条，剪成长15—20cm的插穗，选取疏松、排水、通气良好的沙质土壤作插床，插深为插条的2／3，然后用塑料薄膜覆盖苗床，并用苇帘遮阴，注意保湿，成活率可达85％－－90％。另外，紫薇还可用分根养殖。　　\n三、育苗\n　　3月下旬至4月上旬做好基床，用河沙铺底，8至10厘米厚，然后用竹板刮平。播前将种子带壳用温水浸泡1天，将水滤去后均匀地撒在床基上，每平方厘米4粒为宜。再覆2厘米厚的干沙，用竹板刮平，浇透水，盖上薄膜。注意', 'http://img.boqiicdn.com/Data/BK/P/imagick26041439891316.jpg', 'http://www.boqii.com/entry/detail/1954.html', '');
INSERT INTO `plant_family` VALUES ('336', '新玉缀', 'Sedum burrito（Sedum morganianum var. burrito）', '新玉缀', '新玉串、维州景天', '不容易死', '原产地墨西哥', 'http://www.boqii.com/entry/photo/2333/0,http://www.boqii.com/entry/photo/2333/5084', '　', '', '', '', '景天科', '景天属', '新玉缀', 'Sedum burrito（Sedum morganianum var. burrito）', '', '　　 　　新玉缀的叶片不弯曲，叶端圆形，长度约1.5㎝，有点像米粒，一粒粒表面幅度基本无曲折，叶表有一层薄薄的白粉，浇水时要浇在土上，尽量不要浇到它的叶片，白粉容易因为浇水、碰触而脱落。叶片不会张开呈花状，不去扒拉叶子，极易掉落，稍微用力就掉。叶子会长成长长的一条，叶片包裹着枝条呈现一种螺旋状成长。', '　　在栽培过程中需要足够的光线，如果光照不足，就会引起徒长，会比较难看。除却夏季中午的强光外，无论是半日照或全日照的环境，只要有阳光，新玉缀都能长的比较好。　　　　新玉缀是耐旱，排水良好的土壤，排水不佳很容易会根腐烂，培植土可以用1：1的粗沙和培养土混合，或以2：1：1的培养土，蛭石加粗沙混合，又或者直接用仙人掌专用土亦可。　　　　它们喜欢昼夜大的环境，最适温度是10－32℃之间；气温低过4℃，或高过33℃时会进入休眠，停止生长；若气温低至接近0℃时，就会冻伤或冻死。所以夏季时要注意空气流通，正午时段宜加上遮荫物避开高温，冬季低温至5℃以下时可移到室内有阳光处避寒。　　　千万别以为在努力催谷之下，新玉缀就会快高长大，太过多水，多肥都不适合。相对湿度40－60％的环境能令新玉缀感觉舒适，平时可以待泥土开始干燥时才浇一些水，每隔一个月左右就要浇透水一次，以花盆底孔开始滴水为准。浇水时应避开叶片，以免叶片因积水太久而腐烂，注意盆底不可积水。', '　　　　可将新玉缀跌下来的新玉缀再次繁殖，栽培方法相当简单，将它当作种子一样平均撒在盆内，然后先不要浇水，待叶片发根后才浇水，接着将它吊挂在阳台阳光充足的不淋雨处，介质干燥才浇水，施肥每季施一次，施肥量不可过多，种它时要小心，不要常常碰它，因为它的叶片超容易脱落，浇水时也要浇在土上，尽量不要浇到它的叶片，因为叶片有薄薄的白粉容易因为浇水、碰触而脱落。', 'http://img.boqiicdn.com/Data/BK/P/imagick21821450344220.jpg', 'http://www.boqii.com/entry/detail/2333.html', '');
INSERT INTO `plant_family` VALUES ('337', '大叶落地生根', 'Kalanchoe daigremontiana', '大叶落地生根', '宽叶不死鸟', '不容易死', '非洲马达加斯加岛的热带地区', 'http://www.boqii.com/entry/photo/2349/0,http://www.boqii.com/entry/photo/2349/5068', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '伽蓝菜属', '大叶落地生根', 'Kalanchoe daigremontiana', '', '　　 　　大叶落地生根的叶对生或轮生，下部叶片较大，常抱茎；叶片肉质，长三角形，具不规则的褐紫色', '　　为景天科多年生常绿多肉，人工栽培的难度非常低，就和其一样，落地即可生根。同属常见的观赏种还有细叶落地生根、红花落地生根、月兔草和伽蓝菜等。　　1、：喜温暖，忌酷暑，冬季室温宜保持在10尤以上，低于10T易落叶，低于5摄氏度易受冻。　　2、光线：大叶落地生根阳光，生长季节每天保持4小时光照则生长健壮，花繁叶茂。　　3、水分：平时浇水要掌握盆土“见干见湿”原则，冬季要严格控制浇水，盆土不太干就不要浇水。　　4、空气湿度：喜湿润环境，夏季注意适当遮阴和通风良好。　　5、施肥：大叶落地生根需肥不多，一般情况下只要盆土较肥沃时不必再施追肥。但为了幵花繁茂，可在开花前1个月左右施1～2次全元素的稀薄复合液肥。', '　　　　大叶落地生根在每个锅齿间能自然长出2片极小的圆形对生叶，在对生叶的下面生出一束纤细的气生根轻触即落，遇到土壤很快生出白色须根，成为新的个体，这是它最基本的繁殖方式，其名也由此而来。人工繁殖可用扦插或栽培不定芽繁殖，叶插，茎插均可。较大的不定芽可直接上小盆。生长', 'http://img.boqiicdn.com/Data/BK/P/imagick94161450775934.jpg', 'http://www.boqii.com/entry/detail/2349.html', '');
INSERT INTO `plant_family` VALUES ('338', '石楠花', 'Photinia serratifolia （Desf.） Kalkman', '石楠花', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2100/0,http://www.boqii.com/entry/photo/2100/5427', '', '', '', '', '', '', '', '', '', '　　 　　石楠为蔷薇科、石楠属常绿灌木或小乔木。叶互生，革质，长椭 圆形，边缘有细锯齿，表面绿色，幼叶红色，鲜艳可爱。初夏开花，白色，复伞房花序。小梨果球形，熟时红色，缀满枝头，极为美丽。叶片革质，长椭圆形，顶端尾尖，边缘有带腺的细锯齿，近基部全缘，幼叶红色，后渐变为绿色而具光泽。花小，白色，成顶生复伞房花序。梨果近球形，红色。　　　　　　　　　　　　　　　　　　　　', '　　)花喜温暖湿润的气候，喜光也耐荫，具有一定的观赏价值，并且也可以做为药用。石楠主要在长江流域及秦岭以南地区被广泛栽培，华北地区有少量栽培。石楠的成本较低并且成活率比较高，所以被广泛用于行道树种植。　　石楠为亚热带树种，分布我国淮河以南平原、丘陵地区。性喜光，亦能耐阴，喜温暖、湿润气候，较耐寒耐旱，能耐－15℃的低温，不会落叶。对土壤要求不严，深根性，在肥沃排水良好的沙壤中良好，粘土中往往生长不良。常生于杂木林中，海拔1000－2500米。　　石楠枝繁叶茂，枝条能自然发展成圆形树冠，终年常绿。其叶片翠绿色，具光泽，早春幼枝嫩叶为紫红色，枝叶浓密，老叶经过秋季后部分出现赤红色，夏季密生白色花朵，秋后鲜红果实缀满枝头，鲜艳夺目，是一个观赏价值极高的常绿阔叶乔木，作为庭荫树或进行栽植效果更佳。它的花香有、的作用，一般花期半个月左右，对人没有什么伤害。', '　　石楠是我们比较常见的行道树，其花期一般在4－5月，由于石楠的成本比较低，并且成活率高，所以比较常见。人工栽种石楠一般以播种繁殖为主。　　石楠的繁殖以播种主，因果实多，所以种源广泛。枝光滑。11月份种子采收后，用清水浸泡，发酵后搓去种皮，漂洗取得种子进行沙藏，翌年播。亦可用扦插、压条繁殖。石楠在园林绿化上是极优良的观赏树种。　\n　一、苗圃地的选择和整理\n　　种植地土壤以质地疏松、肥沃、微酸性至中性为好，且灌溉方便，排水良好。种植前，每亩施入腐熟厩肥3000公斤，过磷酸钙50公斤，土壤翻耕深度在25厘米以上、同时施用杀虫剂防治地下害虫。翻耕后将土壤整平，开排水沟，做苗床，床面宽度为1米左右。　\n　二、种苗移栽\n　　种苗移栽的　\n　三、种苗的选购\n　　购买种苗时，要选择信誉好，能提供优质售后服务的供应商，以保证', 'http://img.boqiicdn.com/Data/BK/P/imagick5761444383680.jpg', 'http://www.boqii.com/entry/detail/2100.html', '');
INSERT INTO `plant_family` VALUES ('339', '龙骨柱', 'Euphorbia trigona', '龙骨柱', '巴西龙骨 龙骨', '不容易死', '', 'http://www.boqii.com/entry/photo/2192/0,http://www.boqii.com/entry/photo/2192/5335', '', '', '', '', '', '', '', '', '', '　　龙骨柱又名龙骨，株型多种多样，有丛状形，三柱形，九柱形等。龙骨柱耐旱不耐寒，所以北方冬季应该在室内莳养，南方可露地栽植。龙骨柱还有“万能砧木”之称，用来为别的 龙骨柱 　　龙骨柱的植株为三棱形状，多分枝，蓝绿色，高4米至5米，棱边有小刺，极短。龙骨柱夏季开白花，4朵至9朵，丛生于上部的刺座上，昼开夜闭（盆栽一般不易开花），浆果小圆形，蓝紫色，可食。　　　　　　　　　', '　　由于的雨衣非常好，所以在家居及办公环境中的应用也非常多。对于新装修完的环境来说，龙骨柱对有害气体有很好的吸附作用。人工栽培龙骨柱的难度并不高，小编就为你介绍一下，龙骨柱在栽培过程中的注意事项。　　龙骨柱不耐寒，但耐旱，喜干燥壤土，北方冬季应置于室内莳养，南方可露地栽植，也可用做篱笆，既是绿色屏障，又可美化庭院，夏季还能观赏到花香和果实。　　龙骨柱有“万能砧木”之称，用龙骨柱做砧可与虎刺梅、蟹爪兰嫁接，奇花异木，多姿多彩。龙骨对土要求不严，但需掺入一定量的河沙，上盆时若掺拌一些基肥，期间不施追肥也能生长良好，以粒状复合肥为好。对于干旱有一定的忍耐能力，浇水要适量，长期处于湿润状态会引起烂根。在室内摆设时，应尽量放在靠近日光的窗边。在要置于适度遮阴下培育，其他时间可让其多见阳光。　　冬季最低可耐5℃的低温。龙骨的繁殖采用扦插法，于5月至9月间剪取母株顶端5厘米至6厘米作插穗，在阴凉处晾干一周，待切口充分干燥后再行扦插，容易生根。', '　　　　龙骨柱繁殖多用扦插，龙骨为多浆　　一种是将龙骨切段扦插，上下切口均应用草木灰封闭，插穗长度应为20厘米至25厘米。　　另一种是从龙骨枝上拿下的分枝，晾晒后即可扦插，但太小幼嫩的不易生根，这种插穗只有生根处有小伤口，扦插生根快。扦插龙骨基质需用　　龙骨柱生根后进行移栽，盆土要求1／2河沙和1／2壤土混均后栽入，用2％高锰酸钾水浇入，既做了土壤', 'http://img.boqiicdn.com/Data/BK/P/imagick82851446801735.jpg', 'http://www.boqii.com/entry/detail/2192.html', '');
INSERT INTO `plant_family` VALUES ('340', '散尾葵', 'Butterfly Palm， Areca palm', '尾葵', '黄椰子、紫葵', '不容易死', '', 'http://www.boqii.com/entry/photo/1998/0,http://www.boqii.com/entry/photo/1998/5529', '', '', '', '', '', '', '', '', '', '　　 　　散尾葵高2－5米，茎粗4－5厘米，基部略膨大。叶羽状全裂，平展而稍下弯，长约1.5米，羽片40－60对，2列，黄绿色，表面有蜡质白粉，披针形，长35－50厘米，宽1.2－2厘米，先端长尾状渐尖并具不等长的短2裂，顶端的羽片渐短，长约10厘米；叶柄及叶轴光滑，黄绿色，上面具沟槽，背面凸圆；叶鞘长而略膨大，通常黄绿色，初时被蜡质白粉，有纵向沟纹。　　　　　　　　　　　　　　　　　　　　　　', '　　散尾葵在世界各地都有栽培，而我国也广泛栽培，由于散尾葵形态优美、四季常青，观赏性较强，所以深受人们的喜爱。不过散尾葵的植株比较高，所以在室内饲养则需要一定的空间，那么究竟如何才能养出漂亮的散尾葵呢？　　　湿润的气候环境，要求生长环境的空气相对在70～80％，空气相对湿度过低，会使叶尖干枯。　　　由于它原产于热带地区，喜欢高温环境，对冬季的温度的要求很严，当低于10℃时生长缓慢，开始进入半休眠或休眠状态；当低于5℃时就不能安全；在夏季，当温度高达35℃以上时也能忍受，但生长会暂时受到阻碍。最适宜的生长温度为18～30℃。　　　对光线要求不严，喜欢阳光充足，也耐半荫，但光照充足时生长得更好。　　　对于盆栽的植株，除了在上盆时添加有机肥料外，在平时的过程中，还要进行适当地肥水管理。　　春、夏、秋三季，这三个季节是它的生长旺季，肥水管理按照“花宝”——清水——“花宝”——清水顺序循环，间隔周期大约为1～4天，晴天或高温期间隔周期短些，阴雨天或低温期间隔周期长些或者不浇。冬季，在冬季休眠期，主要是做好控肥控水工作，肥水管理按照“花宝”——清水——清水——“花宝”——清水——清水顺序循环，间隔周期大约为3～7天。对于地栽的植株，春夏两季根据干旱情况，施用2～4次肥水：先在根颈部以外30～100分开一圈小沟（植株越大，则离根颈部越远），沟宽、深都为20cm。沟内撒进25～50斤有机肥，或者1～5两颗粒复合肥（化肥），然后浇上透水。入冬以后开春以前，照上述方法再施肥一次，但不用浇水。', '　　散尾葵外形优美，四季常绿，常作为华南地区的庭院　　1、播种法：播种繁殖所用种子多系国外进口，国内很难采到成熟的种子。播种常用盆播，覆土厚为种子的1倍，保持盆土湿润，幼苗高8－10厘米时，即可分栽。　　2、分株法：一般于春季结合换盆进行。选分蘖多的植株，去掉部分旧', 'http://img.boqiicdn.com/Data/BK/P/imagick93421441186519.jpg', 'http://www.boqii.com/entry/detail/1998.html', '');
INSERT INTO `plant_family` VALUES ('341', '黑王子', 'Echeveia ‘Black Prince’', '黑王子', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2448/0,http://www.boqii.com/entry/photo/2448/4968', '　', '被子植物门 Magnoliophyta', '双子叶植物纲 Magnoliopsida', '蔷薇目 Rosales', '景天科 Crassulaceae', ' Echeveria', '黑王子', 'Echeveia ‘Black Prince’', '', '　　黑王子为景天科拟 　　黑王子为多年生肉质草本植物，植株具短茎，肉质叶排列成', '　　黑王子在夏季会有短暂的', '　　　　黑王子的繁殖，可在　　繁殖可切顶催生蘖芽，叶插繁殖两种方法，成功率比一般', 'http://img.boqiicdn.com/Data/BK/P/imagick84091453713795.jpg', 'http://www.boqii.com/entry/detail/2448.html', '');
INSERT INTO `plant_family` VALUES ('342', '观音莲', 'Sempervivum tectorum', '观音莲', '佛座莲，母鸡和小鸡（hen and chicks）、houseleek', '不容易死', '欧洲中部、西部和南部的山区', 'http://www.boqii.com/entry/photo/2454/0,http://www.boqii.com/entry/photo/2454/4962', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '长生草属', '', 'Sempervivum tectorum', '', '　　 　　观音莲的株型较大且向外张开，稍扁平，通常直径5－7厘米（较小的植株直径约3厘米，老株单株直径可达20厘米）。匍匐茎短且壮，可达4厘米。幼株叶子较少。', '　　观音莲又称佛座莲，非常漂亮，受到很多花友的喜爱。观音莲的多样且叶片粗厚，光照且阳光充沛的环境，观音莲会开花，但是开花的时间较短，并且开花后会出现死亡的情况。　　盆中土壤要求肥沃疏松透气，排水性好。最好用腐叶、草炭、粗沙或者蛭石各一半，适当掺入少量的骨粉钙质材料，混合均匀就可以了。新栽之后尽量少浇水，保持其半干状态，以利于根系的恢复。　观音莲喜欢半阴温暖的环境，日常生长25度左右适宜，冬季白天15度以上即可，夜间温度不低于5℃，植株能继续生长，可正常浇水，并适当施肥；如果控制浇水，使植株休眠，也能耐0℃的低温。长生草不耐热，5月以后植株生长逐渐停止，进入夏季休眠期，家庭可放在走廊下或阳台内侧等无直射阳光、通风良好、雨淋不到的地方养护，并控制浇水，停止施肥，以免因闷热、潮湿、土壤积水导致植株腐烂。　　夏季高温时和冬季寒冷时植株都处于休眠状态，主要生长期在较为凉爽的春、秋，生长期要求有充足的阳光，如果光照不足会导致株形松散，不紧凑，影响其观赏，而在光照充足处生长的植株，叶片肥厚饱满，株形紧凑，叶色靓丽。　　浇水应注意“不干不浇，浇则浇透”的原则，避免积水植根腐烂，但也不能太干旱，否则植物生长缓慢，发黄甚至死亡。夏季植物蒸发严重，所以应该注意多浇水。叶面缺水就会显得枯萎，所以经常要给叶子喷水，保持湿润，但必须避免盆中积水，否则会引起根系腐烂。　施肥以腐熟的稀薄液肥或低氮高磷钾的复合肥为主，20天施一次。施肥一般在天气晴朗的早上或傍晚进行，不要将肥液溅到叶子上，当天的傍晚或第二天早上浇一次透水，以冲淡土壤中残留的肥液。冬季放在室内阳光充足的地方，倘若夜间最低温度在10℃左右，并有一定的昼夜温差，可适当浇水，酌情施肥，使植株继续生长。如果保持不了这么高的温度，应控制浇水，维持盆土干燥，停止施肥，使植株休眠，也能耐5℃的低温，某些甚至能耐0℃的低温。', '　　　\n　1、叶插：\n　\n　2、插穗：\n　　\n3、分株：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick8891453799699.jpg', 'http://www.boqii.com/entry/detail/2454.html', '');
INSERT INTO `plant_family` VALUES ('343', '乌羽玉', 'Lophophora williamsii', '乌羽玉', '红花乌羽玉、乌鱼、鱼', '不容易死', '原产墨西哥中部和美国得克萨斯州的荒漠地区。', 'http://www.boqii.com/entry/photo/2222/0,http://www.boqii.com/entry/photo/2222/5305', '', '', '', '', '', '', '', '', '', '　　 　　乌羽玉为乌羽玉属植物。产于墨西哥北部。植株具粗大的肉质根，在原产地根部的体积比茎部大好多倍。茎球状，球体柔软，表皮为绿色或灰绿色。棱沟呈螺旋形排列但不明显。植株顶部的　　　　　　　　　　　　　　　　　', '　　乌羽玉为球体扁球形或球形，所以人工栽种应选用深盆种植。由于乌羽玉湿润的环境，所以会有朋友用饮料瓶将球体罩起来养护，但是这种做法很容易因为空气流通差而导致乌羽玉锈病。　　乌羽玉原产墨西哥中部和美国得克萨斯州的荒漠地区，喜温暖、干燥和阳光充足，怕积水，耐干旱和半阴，要求有较大的昼夜温差。冬季较耐寒，夏季耐高温，适应性较强。　　主要在海拔100－1500米生长，间中会在奇瓦瓦沙漠高达1900米处生长，也会在塔毛利帕斯州较温和气候的地区生长。　　要求排水良好的沙质土，栽培宜用较深的筒盆，盆低需多放大粒的石头方便排水透气。喜充足的阳光通风良好的环境。夏季干旱炎热时节需防红蜘蛛。　　夏季高温时植株，要求通风良好，避免闷热、干燥，否则易受红蜘蛛危害，还会产生锈病或茎腐病；并适当遮光，以防强烈的直射光灼伤球体。　　冬季置室内阳光充足处，夜间最低温度在10℃左右，并有一定的昼夜温差，可正常浇水，使植株继续生长，如不能保持10℃，则控制浇水，使植株休眠，5℃以上可越冬。', '　　乌羽玉如果　　1、播种：可在4～5月进行。播种在种子成熟后随采随播，盆土用经过蒸气消毒的素砂土，用盆浸法将盆上浸湿后，将种子均匀地撤播在土壤表面，由于种子细小，不用覆土，在播种盆上盖玻璃片以保持湿度，再盖一张白纸以避免阳光直射。昼夜温差在15～25℃之间，10天左右可发芽。　　2、嫁接：砧木宜采用仙人球属中的花盛球、短毛球等。嫁接应选择接穗和砧木都　　嫁接后的植株可移至避风的半阴处，盆栽到砧木在愈合期内一般不要浇水。嫁后在25℃左右的温度下10天左右可拆线，如切口无异常颜色，接穗饱满，接合处全部或大部分已经粘连在一起，则说明嫁接成功，此时可往盆内浇水，并逐步见光。　　3、扦插：多在生长期进行，将切下的子球或嫁接苗上取下的穗球，放在通风干燥处风干，当球体萎缩脱水时，将球体摆放在潮湿的素砂土上，在球体上盖一张白纸以避光。保持盆土湿润，一个月左右可生根，生根后埋入', 'http://img.boqiicdn.com/Data/BK/P/imagick37601447665568.jpg', 'http://www.boqii.com/entry/detail/2222.html', '');
INSERT INTO `plant_family` VALUES ('344', '孔雀木', 'Dizygotheca elegantissima', '孔雀木', '手树', '不容易死', '', 'http://www.boqii.com/entry/photo/2227/0,http://www.boqii.com/entry/photo/2227/5300', '植物　', '被子植物门', '双子叶植物纲', '伞形目', '五加科', '孔雀木属', '', 'Dizygotheca elegantissima', '', '　　 　　孔雀木为常绿观叶小乔木或灌木，盆栽时常在2米以下。树干和叶柄都有乳白色的斑点。叶互生，掌状复叶，小叶7～11枚，条状披针形，长7－15厘米，宽1－1.5厘米，边缘有锯齿或羽状分裂，幼叶紫红色，后成深绿色。叶脉褐色，总叶柄细长。复伞状花序，生于茎顶叶腋处，小花黄绿色不显着。', '　　原产于澳大利亚及太平洋，现在在我国很多地区已经有引种栽培了。孔雀木的较缓慢，但是其观赏价值比较高，所以还是有很多朋友会人工栽培。孔雀木的人工栽培品种有宽叶及斑叶两种，人工栽培孔雀木时应该注意哪些问题呢？　　盆栽孔雀木，培养土以腐叶土、园土、河沙混合为好，保持疏松肥沃。上盆时，为提高观赏性，可每盆栽植3～4株幼苗。培植幼苗时，夏秋生长季节要充分浇水，并进行叶面喷水。长大后的植株生长季节浇水量要适宜，忌盆土过干或过湿。最好在盆土稍干时再彻底浇水，掌握“见干见湿”的原则。较高的空气湿度，因此全年必须经常予以喷雾，保持生机蓬勃。　　孔雀木在栽培过程中不易过分遮光，可置于棚内明亮处，但忌夏季强光。长期放于阴暗处，要适时补充光照。一般从早春到晚秋都可正常生长，可在生长季节隔1～2周施加稀薄饼肥水一次。冬季，适当控水，停止施肥，增加其抗寒力。生长适温为18～23℃，幼苗则需稍高的温度，尤其冬季，温度最好不要低于15℃，老树可耐5～10℃短期低温，温度再低会受冻害。　　棚内盆栽时，若盆土过于干旱、空气过于干燥或温度过低时，会发生叶片脱落现象。发生这种现象，应及早改善环境条件，还有可能萌发腋芽。或予以强剪，使其下部重新萌发新枝。每年抽生新芽后，可适当摘心，促使分枝，形成丰满的株型。生长过于细弱的植株，在新叶发出之前可进行重短截，基部留10厘米左右；若上部枝条干枯，也宜强剪，以促其萌发枝、叶，剪下的枝条不宜作插条用。', '　　　　孔雀木常用扦插繁殖，于5～6月间选取　　孔雀木树形和叶形优美，叶片掌状，小叶羽状分裂，非常雅致，为名贵的观叶植物，多用户盆栽观赏，大株植株用于厅堂摆放，小袜多装盆后主要用于居室的案几、茶几和窗前摆设。', 'http://img.boqiicdn.com/Data/BK/P/imagick78981447752105.jpg', 'http://www.boqii.com/entry/detail/2227.html', '');
INSERT INTO `plant_family` VALUES ('345', '丽娜莲', 'Echever lilacina', '丽娜莲', '丽娜希娜', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/2267/0,http://www.boqii.com/entry/photo/2267/5258', '', '', '', '', '', '', '', '', '', '　　丽娜莲为景天科拟 丽娜莲 　　丽娜莲株高5～6厘米，株幅12～23厘米。叶片卵圆形，肉质，叶顶端有小尖，叶面中间向内凹，浅粉色，叶片的边缘有着明显的波折，叶片带有白色粉末，　　　　　　　　　　　　　　　　　　', '　　丽娜莲的栽培难度并不高，但是想要丽娜莲长得好看就需要注意很多细节了。丽娜莲养护不当则很容易导致叶片过于摊开，这会使得丽娜莲的观赏价值大打折扣。那么人工栽培丽娜莲应该注意哪些问题呢？　　　丽娜莲春秋季在充足的光照下可以多浇水，配土接近干透即可浇透一次水。但夏季酷热，冬季严寒时，应节制浇水，待干透后，少量浇水即可，是否过度浇水，可参照丽娜莲的叶片包裹度。配土可选择透气排水性良好的土壤，如泥炭土、颗粒土1：1的比例配置。　　　盛夏超过32度需要适当遮阴，其余时间均可全日照，充足的光照，丽娜莲的叶片会包裹得更紧，叶尖边缘呈粉红小波浪状，光照不足容易摊大饼影响观赏。　　　缓苗期间可用干土或者潮土种下（湿度的感觉就像拧干的毛巾一样，越干越好），之后将丽娜莲放在明亮通风处1－2周，再逐渐增加光照。缓苗时间，建议少浇水或者不浇水，水分过多的情况下，丽娜莲叶片会摊开得比较厉害，变得不那么好看，可视叶子包裹程度决定是否浇不浇水。　　　　夏季超过30度则需要适当给丽娜莲遮阴或放在阴凉通风的地方，太热植株容易死亡，超过35度就要断水休眠了，整个休眠期少水或不给水，等温度下来了，再开始恢复浇水，但刚开始浇水的量不要一下太多。冬季如果温度能够保持0度以上，可以正常给水，0度以下就要控水，否则丽娜莲容易冻伤，可在出太阳的时候微微给点水在丽娜莲的根部。', '　　丽娜莲为景天科　　\n1、配土\n　　可用河沙煤渣做为植料，养殖景天，河沙煤渣是很好的养殖土。下图的这个2盆就是混合了煤渣泥炭珍珠岩的植料了。养景天不用太多泥炭一般1：1：1，合适就好，没有绝对精确的比例的。花友可根据自己的实际情况配土。（纯的赤玉土也可以的，3到6毫米的那种）土壤混合以透气为主，土表铺设干净的细沙。　\n　2、砍头\n　　丽娜莲的叶片长的还是很紧凑的，寻找一个合适的位置入刀，初级爱好者有时候不容易　　找好位置，刀尖对准枝干，一手扶住植株，刀慢慢推入，刀尖穿过枝干就可以，继续回刀砍第二下，直到枝干分开，这样砍头就完成了。　　砍头后的母株，晾干伤口再给水生长。伤口不要弄到水分，景天植物不用涂抹　　把事先准备好的盆土，中间挖个小的坑，深点都可以的，然后把砍头的植株放在盆土上，伤口不要', 'http://img.boqiicdn.com/Data/BK/P/imagick76651448875736.jpg', 'http://www.boqii.com/entry/detail/2267.html', '');
INSERT INTO `plant_family` VALUES ('346', '石蒜', 'Lycoris radiata  （L', '红花石蒜', '龙爪花、蟑螂花', '不容易死', '', 'http://www.boqii.com/entry/photo/1971/0,http://www.boqii.com/entry/photo/1971/5556', '植物　', '被子植物亚门', '单子叶植物纲', '百合目', '石蒜科', '石蒜属', '石蒜', 'Lycoris radiata  （L\'Her.） Herb.', '', '　　 　　石蒜的鳞茎近球形，直径1－3厘米。秋季出叶，叶狭带状，长约15厘米，宽约0。5厘米，顶端钝，深绿色，中间有粉绿色带。花茎高约30厘米；总苞片2枚，披针形，长约35厘米，宽约05厘米；伞形花序有花4－7朵，花鲜红色；花被裂片狭倒披针形，长约3厘米，宽约05厘米，强度皱缩和反卷，花被简绿色，长约05厘米；雄蕊显着伸出于花被外，比花被长1倍左右。', '　　石蒜的俗称又叫蟑螂花、蒜头草，而曼珠沙华、彼岸花则是其雅名并且更别人熟知。由于石蒜栽培需要注意环境，人工盆栽石蒜的话也非常多，小编就从石蒜的栽培时间、环境以及栽培方法来为你介绍一下。　　地区适宜的栽培时间是5～11月份，可以同花期控制相结合，切忌在长叶以后的冬季或早春移栽。寒冷地区应在春天栽种。多数喜温暖的气候，最高气温不超过30℃，旬平均气温24℃，适宜石蒜生长。冬季日平均气温8℃以上，最低气温1℃，不影响石蒜生长。　　种植深度不宜太深，以鳞茎顶刚埋入土面为好。要求排水良好的偏酸性沙质土或疏松的，栽植时施适量的基肥，栽培后灌透水。营养生长期要经常灌水，保持土壤湿润，但不能积水，以防鳞茎腐烂。开花前20天至开花期必须要供给适量水分，以达到开花整齐一致，且延长花期。　上海地区可露地栽培。把主球四周的小鳞茎剥下进行繁殖。将主球的残根修掉，晒两天，待伤口干燥后即可栽种。栽培地要求地势高且排水良好，否则应作成高畦深沟，以防涝害。株行距15cm×20cm，覆土时，球的顶部要露出土面。一般每年施肥2～4次，第1次在落叶后至开花前，可使用有机肥或复合肥。做切花的，在花蕾含苞待放前追施。第2次在10月底11月初开花后生长期前。采花之后继续供水供肥，但要减施氮肥，增施磷、钾肥，使鳞茎健壮充实。秋后应停肥、停水，使其逐步休眠。挖球要选晴天，土干时挖起，除去泥土，略加干燥后贮藏。也可剪去叶片后，带土放温室内休眠，室温保持5℃～10℃，室内保持干燥，空气流通，以防球根腐烂。　　上也可采用40cm×60cm的框式栽培法，一般每筐种球16个，此法的优点便于移栽，养护管理方便。生产中注意除草，一般可以喷洒除草剂，在杂草过长时使用，喷洒时间一般选在落叶后和采收后。　　另外，可以进行盆栽，一般选用田间生长3年、能开花的大球，直径在7cm以上，可一盆栽一球，也可一大盆栽3～4个球。要浅植，使球的1／3～1／2居于土面上。上盆后浇水1次，使土略微湿润即可，待发出新叶后再浇水。每半月施液肥1次。在秋季叶片增厚老熟时，可停止浇水。待2～3月萌芽后，再翻盆或更换盆土。　　培养土可用泥炭2份、园土2份、珍珠岩1份混合配制而成，同时加入少量的基肥。夏季休眠期要少浇水，而春秋季需经常保持盆土湿润。生长季节每半月追施1次稀薄饼肥水。石蒜喜半阴，夏季避免阳光直射，春秋季置半阴处养护，越冬期间严格控制浇水，停止施肥。', '　　　　石蒜基本用分球、播种、鳞块基底切割和组织培养等方法繁殖，以分球法为主。最简便的方法是采取分球的方式，在休眠期或开花后将植株挖起来，将母球附近附生的子球取下种植，约一、两年便可开花。君子兰、火球花、文殊兰和葱兰等易结籽的　　\n一、鳞块基底切割法：\n　\n　二、组织培养繁殖法：\n　　\n三、播种法：\n　　', 'http://img.boqiicdn.com/Data/BK/P/imagick42491440150917.jpg', 'http://www.boqii.com/entry/detail/1971.html', '');
INSERT INTO `plant_family` VALUES ('347', '红花檵木', 'Loropetalum chinense var.rubrum', '红花檵木', '红继木、红梽木', '不容易死', '中国、印度', 'http://www.boqii.com/entry/photo/2131/0,http://www.boqii.com/entry/photo/2131/5396', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '金缕梅科', '檵木属', '继木', 'Loropetalum chinense var.rubrum', '', '　　 　　红花檵木为灌木，有时为小乔木，多分枝，小枝有星毛。叶革质，卵形，长2～5厘米，宽1.5～2.5厘米，先端尖锐，基部钝，不等侧，上面略有粗毛或秃净，干后暗绿色，无光泽，下面被星毛，稍带灰白色，侧脉约5对，在上面明显，在下面突起，全缘；叶柄长2～5毫米，有星毛；托叶膜质，三角状披针形，长3～4毫米，宽1.5～2毫米，早落。', '　　红花檵木的花色艳丽，树形多姿，是非常适合用来美化庭院及街道的名贵树种，尤其适用于居民区、草坪灯大面积群植，观赏效果非常好。现在有很多花友会将红花檵木制作成盆景放在家中栽培，那么红花檵木在栽培过程中应该注意哪些问题呢？　　红檵木为白檵木的变种，野生的红檵木在半阴环境，为中性日照植物，适应性强，喜温暖湿润气候，也颇耐寒，耐干旱瘠薄，最适生于微酸性土，虽能耐阴，但在阳光充足的环境条件下，叶色鲜艳，而且花量大，而阴处则观赏价值降低，生长速度较快。檵木分布在大别山、桐柏山和伏牛山南部，红花檵木在河南商丘、平顶山、许昌、信阳等有较多栽培。　　在长江中下游地区，红花檵木可以露地栽培或盆栽。移栽宜在春季萌芽前进行，小苗需带宿土，大苗需带土球。栽后需适当遮阴。每年早春或冬季要适当修剪整形，平时注意排除积水和经常。　　在长江以北地区。主要以盆栽为主，冬季移人温室或室内，温度控制在0℃以上，一般都能安全。春暖后换盆，盆土和浇水均应造成酸性条件。', '　　　\n　一、红花檵木播种繁殖：\n　　\n二、红花檵木扦插繁殖：\n　\n　三、红花檵木嫁接繁殖：\n　\n　四、红花檵木高压繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick27371445332537.jpg', 'http://www.boqii.com/entry/detail/2131.html', '');
INSERT INTO `plant_family` VALUES ('348', '桃花', 'Peach、Peach Tree', '桃', '', '不容易死', '', 'http://www.boqii.com/entry/photo/1919/0,http://www.boqii.com/entry/photo/1919/5610', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '桃属', '桃', 'Amygdalus persica L.', 'Amygdalus persica', '　　 ', '　　现在越来越多人都喜欢了，如果你的庭院有足够的地方，可以在庭院中种上一颗桃树，还可以将桃树制作成放在室内栽培也是一个不错的选择。桃花是春天的一个特点，如果你有兴趣种上一颗桃树的话应该如何进行栽培呢？桃花盆栽　　桃花移栽、定植多在早春或秋冬落叶后进行，种在排水阳光充足的地方，种植穴内当施基肥（人粪尿、堆肥、饼肥、骨粉等），促使花芽分化。幼龄可行裸根移植；大苗及大树，尤其是较名贵的，最好带土团移植，或至少根部浸蘸泥浆，然后移栽，以保证成活。整形以自然开心形为主，修剪可较梅略重，既行疏剪，又加短截，对树冠内的纤细枝，交叉枝和病虫枝，都加以剪除，并于花前进行，盆栽者则可延至花后进行。一般每年冬季施基肥一次，花前和6月前后各追肥一次，以促开花和花芽形成。此外，平时应适当松土、除草。病虫害主要有桃蚜、桃粉蚜、桃浮尘子、梨小食心虫、桃缩叶病等，当及时防治。　　桃花浇水要适量，不干不浇，防止积水造成烂根。每年开花后各施一两次液肥，其余时可不施肥。桃花为一年生充实之桃的腋芽，7月间分化花芽，第二年春季开花的习性，因此要注意修剪，幼桃以养成桃冠为主，开花后及时进行修剪，对开过花的枝条，只保留基部二三个芽，其余剪除。夏季对过旺的枝条，进行摘心，促使花芽形成。对于长势不大好的植株，应避免修剪过多，抑强扶弱，并注意枝条分布均匀，造成优美的株形。盆栽桃花在每年春分时进行。换盆时在盆底放些磷肥作基肥，剪除过密根系，填入新的盆土。', '　　由于　　桃花繁殖以嫁接为主，多用切接或盾形芽接。砧木华东多用毛桃（桃之半栽培类型），北方则用山桃，但用毛桃或山桃砧所接之　　砧木种子以秋播为便；或用湿砂秋后层积种子，至来年早春取出播种即可。播种时，通常行距40～50厘米，株距10～20厘米，沟5厘米，每处一粒。春播时如芽已萌发，要用土覆好幼芽。　　芽接多在7～8月进行，砧木以用一年生充实的实生苗为好，二年生砧亦勉强可用。芽接成活率很高，多在95％以上；当年多不萌发，来春检查一次，成活者去砧芽使桃花接穗抽发，未活者可即补行切接繁殖。　　切接在春季芽已开始萌动时进行，选去春生长充实的桃花枝条，截成6～7厘米长枝段，要带2节芽（1节亦可），切口长2～3厘米，砧木以一、二年生苗为好，过老者欠佳。约在砧木离地5厘米处截顶，然后切接。接后即须培土，略盖过接穗顶端即可。切接成活率，一般可达90％或更高。', 'http://img.boqiicdn.com/Data/BK/P/imagick33051438854597.jpg', 'http://www.boqii.com/entry/detail/1919.html', '');
INSERT INTO `plant_family` VALUES ('349', '铁线莲', 'Clematis florida Thunb.', '铁线莲', '铁线牡丹、番莲、金包银、山木通、番莲、威灵仙', '不容易死', '中国、日本', 'http://www.boqii.com/entry/photo/2063/0,http://www.boqii.com/entry/photo/2063/5464', '　', '被子植物门', '双子叶植物纲', '毛茛目', '毛茛科', '铁线莲属', '铁线莲', 'Clematis florida Thunb.', 'Clematis florida', '　　 　　铁线莲为草质藤本，长约1～2米。茎棕色或紫红色，具六条纵纹，节部膨大，被稀疏短柔毛。二回三出复叶，连叶柄长达12厘米；小叶片狭卵形至披针形，长2～6厘米，宽1～2厘米，顶端钝尖，基部圆形或阔楔形，边缘全缘，极稀有分裂，两面均不被毛，脉纹不显；小叶柄清晰能见，短或长达1厘米；叶柄长4厘米。', '　　铁线莲经过人工培育繁殖，越来越多，人工栽培铁线莲一般需遵循通风、保证水分、8月底前停止施肥的原则。小编就为你介绍一下不同品种的铁线莲的栽培要点，有兴趣的朋友可以一起了解。　　1、一类品种。夏季会继续，正常，注意红蜘蛛和蓟马，最好半个月喷一次药。长瓣不要淋雨，长瓣只要有新枝条萌发都能开花，持续到秋天。常绿，蒙大拿只长枝条。千万不要忘记浇水，毛细根的品种一旦缺水就是死路一条。品种举例：长瓣（蓝鸟、粉红玛卡、塞西尔）。常绿（春早知、银币、苹果花）。蒙大拿（粉玫瑰、绿眼睛、巨星）　　2、二类品种（包括乌托邦、回忆、祝福）。早春大批的开花，花后剪掉残花，如果剪掉开过花的枝条也是可以的。大概花后一个月左右会有部分萌发新的腋芽，发育良好的话，能开花。老叶子会变褐色。5月开始温度逐渐升高，6月是江南的梅雨季，若介质不够透气、枝条深埋，则高发枯萎病。注意新枝条蓟马病虫害。品种举例：粉香槟、蜜蜂之恋、仙女座、水晶喷泉、约瑟芬、沃金美女、冰美人、爱莎等等　　3、三类品种。第一批花开过后，可以剪掉所有开过花的节。大概1个月左右会再发新枝条开花。品种举例：意大利系（紫云、紫罗兰之星、超级杰克、玛格丽特亨特）。全缘（如古、杜兰、舞姬、阿柳）　　4、F系（乌托邦，回忆，祝福除外），奇葩的夏季休眠品种。花后剪掉残花，留下枝条和叶子，以增加水分蒸发量，少枯萎病发生。淋雨也是没的，但是不要给肥料。休眠的表现是叶子枯黄变黑。休眠后可以剪短枝条，剪掉枯叶。但建议最好在8月底前后修剪枝条，因为这个时候F系就该睡醒了，再抽条开花。品种举例：小绿、幻紫、恭子小姐、卡西斯　　5、大道。建议花后轻剪，剪掉开过花的节，6月底前萌发的新枝条，基本都能再开花。夏季按二类管理。品种举例：皮卡迪、塞尚、巴黎风情、欧拉拉、啤酒　　蓟马会让新枝条嫩芽发黑，若发现铁线莲新芽焦黑排除肥害后就要考虑是否是蓟马危害。肥伤主要是叶尖黑，蓟马是嫩芽叶子黑到叶柄。我这大概7月开始出现蓟马，但今年5月月季上已经出现。使用阿维菌素、蚍虫灵等可以预防，爆发后可以每三天喷一次，连喷三次上述药物。', '　　铁线莲原产于中国，目前，全世界的铁线莲　\n　播种：\n　\n　压条：\n　　\n嫁接：\n　\n　分株：\n　\n　扦插：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick14021442916077.jpg', 'http://www.boqii.com/entry/detail/2063.html', '');
INSERT INTO `plant_family` VALUES ('350', '睡莲', 'Nymphaea  L.', '睡莲', '子午莲、粉色睡莲、野生睡莲、矮睡莲、侏儒睡莲', '不容易死', '中国、苏联、朝鲜、日本、印度、越南、美国', 'http://www.boqii.com/entry/photo/1937/0,http://www.boqii.com/entry/photo/1937/5592', '', '', '', '', '', '', '', '', '', '　　 　　睡莲是多年生浮叶型水生草本植物，根状茎肥厚，直立或匍匐。叶二型，浮水叶浮生于水面，圆形、椭圆形或卵形，先端钝圆，基部深裂成马蹄形或心脏形，叶缘波状全缘或有齿；沉水叶薄膜质，柔弱。花单生，花有大小与　　　　　　　　　　　　　　　　　　　　　', '　　睡莲是水生植物中比较有名的，由于睡莲的外形和荷花非常像，所以很多花友或许会分不清楚这两种花卉的区别。现在经过不断培育，睡莲也可以在家中进行栽培了，而现在迷你睡莲是非常火爆的，也是很多花友都非常的品种。那么睡莲究竟应该如何栽培呢？在栽培过程中又应该注意哪些呢？　　1、花盆：要尽量选择开口向外的，开口向外叶子的会比向内的叶子长的好，盆口越宽的花会越大朵（与盆底大小关系不大），花盆深浅，则影响开花间隔，越深间隔越久。　　2、土：尽量选择粘性较高的土，如：粘土、阳明山土。　　3、接着在盆底放少许长效肥或根肥（太多会烂根），花盆里放约1／4～1／3的土，压紧，之后将球茎芽点朝上埋入土中，球茎埋的深，开花间隔会较长但较大朵，埋的浅则间隔会较短较小朵。种好之后，移至光线充足处，将水加满，等待长叶开花（叶片太多可修剪一些）。　　4、若要将二颗以上球茎种一起时，与种其他花不同，要二颗球茎紧邻一起来种，因若分开种，因当较强势的一棵叶片遮到较弱势的一棵芽点时，较弱势那棵照不到光线，就会阵亡，另外，要种一起时，最好是同种或同色系，因深色系（如：紫色、蓝色），会比浅色系（白色、黄色）来得强势，切记！！　　5、开花后，可将花剪下来插（子时莲例外），花的生命期约3～6天，第一天花会较直，之后越来越弯，直到弯至水中，若有剪花下来插，开花间隔会缩短，若任之谢掉则间隔较久。　　6、加肥：约每隔一个半月至二个半月，在离球茎旁约3～5公分处追加长效肥或根肥，但在9月底之后就不要再加了，因已渐进秋天，睡莲也将进入，加肥，反而会造成烂根。　　7、进入秋冬之后，睡莲也会随着气温的下降而进入休眠期，此时最好不要再去动它，只有在水少时将水加满，香水莲，叶片有斑点的品种休眠期会比无斑点的长，浅色系会比深色系长。　　8、移栽与分芽：每年清明过后到中秋之前都可以进行，分芽时要注意不要伤到芽点，球茎大小则不太要紧，一个盆子中建议不要有太多个芽心太挤，叶片会变小且不会开花，因此平均二年就要分芽一次到二次（所以我每年都会将多的送人）。　　9、有些品种会在叶片中心进行另一种无性生殖，若发现叶片中心有长芽心，就先不要理它，让它长，直到该叶片开始发黄时，将叶柄与芽心一同剪下，放在水盆或花盆中，相同的放在光线充足处，约二星期左右，待芽点长大与长根时，就可比照正常株来种，一样会在当年开花。', '　　　　\n一、根茎繁殖法\n　　迷你睡莲主要是以根茎方式繁殖，一开始先将迷你睡莲栽种在花盆内，然后放于水中，大概过上个一年左右，迷你睡莲的根茎便会长的十分茂密，这是就可以将迷你睡莲进行分茎栽种了，首先将根茎部分的泥土退去，把根须剪短，将横生出来的根茎带茎叶剪上差不多10cm左右，然后将盆地放入底砂　\n　二、分割种植法\n　　在种植的时候将迷你睡莲的顶点露出水面一点或是高于盆沿都可以，栽种好的时候马上就放入水中，在水中需要将迷你睡莲固定住，保持一定的水深。迷你睡莲种植需要在迷你睡莲长至一定的阶段就需要分枝栽种，且需要经常施肥，保证肥料的充足，', 'http://img.boqiicdn.com/Data/BK/P/imagick20931439373866.jpg', 'http://www.boqii.com/entry/detail/1937.html', '');
INSERT INTO `plant_family` VALUES ('351', '雅乐之舞', 'Pailulacaria afra var.foliis－variegatis', '雅乐之舞', '斑叶马齿苋树、公孙树、玉叶、金枝玉叶', '不容易死', '非洲南部', 'http://www.boqii.com/entry/photo/1997/0,http://www.boqii.com/entry/photo/1997/5530', '植物　　', '被子植物门', '双子叶植物纲', '中央种子目', '马齿苋科', '马齿苋属', '雅乐之舞', 'Pailulacaria afra var.foliis－variegatis', '', '　　 　　雅乐之舞株高3～4米，老茎紫褐色，嫩枝紫红色，分枝近水平，肉质叶对生，绿色，倒卵形。雅乐之舞植株较矮，枝条也较为细弱，肉质茎红褐色（新茎）或灰白色（老茎）：肉质叶交互对生，新叶的边缘有粉红色晕，以后随着叶片的长大，红晕逐渐后缩，最后在叶缘变成一条粉红色细线，直到完全消失。叶片大部分为黄白色，只有中央的一小部分为淡绿色；小花淡粉色，观赏价值不高。', '　　为马齿笕树的斑锦变异品种，由于雅乐之舞常分布在世界温带和热带地区，所以雅乐之舞的价钱比较高。人工栽培雅乐之舞也应该注意配合其习性来打造一个合适的环境。　　1、光照：雅乐之舞喜阳光充足的环境，虽然在半阴和散射光的条件，雅乐之舞下也能正常生长，但茎节之间的距离拉长，使植株松散，不紧凑，影响观赏，所以可以全日照，高温时要适当的遮阳。此外，夏季高温时注意通风良好，防止因闷热潮湿引起落叶、烂根。　　2、浇水：夏季要严格控制浇水，掌握“不干不浇，浇则浇透”，避免盆土积水，保持盆土稍干燥，高于35度时，须向盆器周围喷雾，增加空气湿度。雨季不要长期淋雨，以免造成烂根。冬季保持盆土干燥，5℃左右即可。　　3、盆土：盆土要求疏松、肥沃，并有良好的排水、透气性。常用腐叶土2份，粗沙、蛭石或珍珠岩2份，园土1份，并掺入少量的草木灰或骨粉作基肥，混匀后使用。　　4、施肥：每半个月施一次腐熟的稀薄液肥或复合肥，注意肥水中的氮肥含量不可过多，以免叶片中带有过多的绿色，不能突出品种特色。　　5、繁殖：雅乐之舞的繁殖用扦插法，一般在生长季节进行，扦条可用整形时修剪下来的枝条，扦插长短要求不严，插后保持稍有潮气，2～3周生根。　　6、盆景造型：雅乐之舞盆景的造型可采用蟠扎、修剪相结合的方法进行，常见的有直干式、曲干式、斜干式、悬崖式、临水式等不同形式。由于是肉质茎，蟠扎时不要将金属丝勒进其表皮，否则会造成肉质茎撕裂。其枝条扶疏，长枝稍微下垂，树冠多采用自然式，潇洒飘逸，疏密得当，很有特色。也可利用其叶片细小密集的特点，经常修剪，促发小枝，将树冠培养成紧凑的三角形或馒头形。对于扦插成活的雅乐之舞，可稍加蟠扎、修剪，栽于小盆中，并配以奇石，即成为玲珑可爱，精巧别致的微型盆景。', '　　　　1、扦插时把修剪整形时剪下来的枝条放好，以便扦插。　　2、准备好多肉种植土，将雅乐之舞小枝扦插在土里。（种植土常用腐叶土2份，粗沙、　　3、扦插后插后保持稍有潮气，2～3周生根。幼苗成活后勤施薄肥，使之生长旺盛，当植株生长到一定大小时就可以进行造型了。　　其实，雅乐之舞的扦插并不难，一般都很容易成活的。', 'http://img.boqiicdn.com/Data/BK/P/imagick70581441186179.jpg', 'http://www.boqii.com/entry/detail/1997.html', '');
INSERT INTO `plant_family` VALUES ('352', '橡皮树', 'Ficus elastica Roxb. ex Hornem.', '', '印度橡皮树、印度榕大叶青、红缅树、红嘴橡皮树', '不容易死', '原产巴西及马来西亚，中国各地多有栽培', 'http://www.boqii.com/entry/photo/2008/0,http://www.boqii.com/entry/photo/2008/5519', '', '', '', '', '', '', '', '', '', '　　 　　橡皮树为大乔木，高可达30米，有丰富乳汁。指状复叶具小叶3片；叶柄长达15厘米，顶端有2 （3－4）枚腺体；小叶椭圆形，长10－25厘米，宽4－10厘米，顶端短尖至渐尖，基部楔形，全缘，两面无毛；侧脉10－16对，网脉明显；小叶柄长1－2厘米。　　　　　　　　　　　　　　　', '　　是非常常见的室内观叶植物，在很多室内场所都能看得到橡皮树的身影。此外，橡皮树的栽培难度并不高，在我国南方地区橡皮树常作室外栽培，此时，橡皮树一般都能长到30cm左右，也是很好的园林绿化。　　盆栽橡皮树一般用泥炭土、腐叶土加1／4河砂及少量基肥配成土，也可用细砂土。　　橡皮树较快、喜肥，每周施1次肥。通常春季新梢生长之前换盆或换土。幼苗高80厘米～100厘米时，根据需要摘心，促进侧枝萌发。一般留3个主枝，其他多余的去掉。若栽培好，3年左右可长成2米的大型植株。橡皮树喜强阳光，春至秋整个生节季节全部在阳光下栽地部，冬季亦应放在室内阳光最强的地方。　　若放在室内观赏，一般2周左右更换1次，不可过久。橡皮树在高湿、潮湿的环境中生长甚快，每5天～7天生出一片叶。这期间必须保证充足的和水分。秋季逐步减少施肥和浇水，促使枝条生长充实。由于橡皮树对干旱的环境有较强的抗性，在华北地区栽培亦较容易。应放在10℃以上的房间内，长期低温和盆土潮湿易造成根部腐烂。每年4月底至10月初搬至室外栽培。', '　　橡皮树是非常着名的盆栽观叶　　家庭栽培一般采用扦插和高枝压条法繁殖，长江流域在每年的4－9月最为适宜，若在春、夏两季进行扦插时，要选择植株上部或中部隔年生的健壮枝条作为插穗。秋季扦插时，宜选当年生的健壮新枝条作插穗。具体步骤为：剪下要作插穗的枝条，去掉顶端的嫩梢和下部的叶片，将中间叶片留下，并将留下的叶片剪掉1／2，为减少叶面的蒸发，最好将叶片卷成筒状，并用小木棍从卷筒当中穿过，插入土壤内，防止插穗倒伏。另外，剪下的插穗要立即用草木灰或泥炭土把上下切口封住，防止乳汁外溢过多而降低成活率。扦插时的深度一般为3cm－4cm，太深了会发生腐烂，太浅就容易倒伏。扦插的基质一般用细', 'http://img.boqiicdn.com/Data/BK/P/imagick46421441618381.jpg', 'http://www.boqii.com/entry/detail/2008.html', '');
INSERT INTO `plant_family` VALUES ('353', '白掌', 'Spathiphyllum kochii', '白掌', '苞叶芋、一帆风顺、和平芋、百合意图、白鹤芋', '不容易死', '白掌原产地中国，喜生于热带雨林中', 'http://www.boqii.com/entry/photo/2025/0,http://www.boqii.com/entry/photo/2025/5502', '', '', '', '', '', '', '', '', '', '　　 　　白掌为多年生草本。具短根茎，有时茎变厚而木质，直立、平卧或用小根攀附于他物上，少数浮水，常有乳状液汁。叶长椭圆状披针形，两端渐尖，叶脉明显，叶柄长，基部呈鞘状，通常基生，如茎生则为互生，呈2行或螺旋状排列，形状各式，剑形而有平行脉至箭形而有网脉，全缘或分裂。花葶直立，高出叶丛，佛焰苞直立向上，稍卷，白色，肉穗花序圆柱状，白色。　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　', '　　白掌因其叶片和　　　　白鹤芋较耐阴，只要有60％左右的散射光即可满足其生长需要，因此可常年放在室内具有明亮散射光处培养。夏季可遮去60％～70％的阳光，忌强光直射，否则叶片就会变黄，严重时出现日灼病。北方冬季温室栽培可不遮光或少遮光。若长期光线太暗则不易开花。白鹤芋为喜高温种类，应在高温温室栽培。冬季夜间最低', 'http://img.boqiicdn.com/Data/BK/P/imagick82341441878218.jpg', 'http://www.boqii.com/entry/detail/2025.html', '');
INSERT INTO `plant_family` VALUES ('354', '金叶女贞', 'Ligustrum vicaryi', '金叶女贞', '黄叶女', '不容易死', '长江以南及黄河流域等地的气候条件均能适应，生长良好', 'http://www.boqii.com/entry/photo/2033/0,http://www.boqii.com/entry/photo/2033/5494', '', '', '', '', '', '', '', '', '', '　　 　　金叶女贞为落叶灌木，是金边卵叶女贞和欧洲女贞的杂交种。叶片较大叶女贞稍小，单叶对生，椭圆形或卵状椭圆形，长2～5厘米。总状花序，小花白色。核果阔椭圆形，紫黑色。金叶女贞叶色金黄，尤其在春秋两季色泽更加璀璨亮丽。金叶女贞高1～2米，冠幅1.5～2米。　　　　　　　　　　　　　　　　　', '　　由于不耐阴，所以不建议放在室内栽培，因其耐修剪，所以被大量的在园林绿化中应用。金叶女贞到了春秋两季的色泽会非常亮丽，有的朋友会选择在自家中选择作为。　　金叶女贞是木犀科女贞属半绿小灌木，被誉为“金玉满堂”。金叶女贞性喜光，耐阴性较差，耐寒力中等，适应性强，以疏松肥沃、通逶性良好的沙壤土为最好。用于绿地广场的组字或图案，还可以用于小庭院装饰。　　金叶女贞适应性强，对土壤要求不严格，在我国长江以南及黄河流域等地的气候条件均能适应，良好。性喜光，稍耐阴，耐寒能力较强，不耐高温高湿，在京津地区，小气候好的楼前避风处，冬季可以保持不落叶。它抗病力强，很少有病虫。', '　　金叶女贞虽然适应能力比较强，对土壤的要求也不严格，但是不耐阴，所以常被用于园林绿化。金叶女贞一般使用扦插的方法进行繁殖，但是想要提高扦插成活率的话就需要注意扦插方法。　　一般采用两年生金叶女贞新梢，最好用木质化部分剪成15厘米左右的插条，将下部叶片全部去掉，上部留2至3片叶即可，上剪口距上芽1厘米平剪，下剪口在芽背面斜剪成马蹄形。扦插基质用粗沙土，0.5％高锰酸钾液　　需要特别注意的是扦插的成活率与扦插的基质，生根粉的浓度，插穗木质化程度及扦插的', 'http://img.boqiicdn.com/Data/BK/P/imagick83311442223069.jpg', 'http://www.boqii.com/entry/detail/2033.html', '');
INSERT INTO `plant_family` VALUES ('355', '禾雀花', 'Mucuna birdwoodiana', '禾雀花', '白花油麻藤、鸡血藤', '不容易死', '亚洲热带和亚热带地区', 'http://www.boqii.com/entry/photo/2118/0,http://www.boqii.com/entry/photo/2118/5409', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '豆科', '黧豆属', '', 'Mucuna birdwoodiana', '', '　　 　　禾雀花为常绿、大型木质藤本。老茎外皮灰褐色，断面淡红褐色，有3－4偏心的同心圆圈，断面先流白汁，2－3分钟后有血红色汁液形成；幼茎具纵沟槽，皮孔褐色，凸起，无毛或节间被伏贴毛。羽状复叶具3小叶，叶长17－30厘米；托叶早落；叶柄长8－20厘米；叶轴长2－4厘米；小叶近革质，顶生小叶椭圆形，卵形或略呈倒卵形，通常较长而狭，长9－16厘米，宽2－6厘米，先端具长达1.3－2厘米的渐尖头，基部圆形或稍楔形，侧生小叶偏斜，长9－16厘米，两面无毛或散生短毛，侧脉3－5，中脉、侧脉、网脉在两面凸起；无小托叶；小叶柄长4－8毫米，具稀疏短毛。', '　　禾雀花为蝶形花科油麻藤属木质藤本，其向上攀爬的本领比较强，可以直接长在藤曼上，由于禾雀花的花形和雀鸟非常像，故此命名。禾雀花主要分布在亚热带地区，人工栽培禾雀花需要注意哪些问题呢？　　　喜欢湿润或半燥的气候环境，要求生长环境的空气相对温度在50～70％，空气相对湿度过低时下部叶片黄化、脱落，上部叶片无光泽。　　　由于它原产于亚热带地区，因此对冬季的温度的要求很严，当环境温度在8℃以下停止生长。　　　对光线适应能力较强。放在室内养护时，尽量放在有明亮光线的地方，如采光良好的客厅、卧室、书房等场所。在室内养护一段时间后（一个月左右），就要把它搬到室外有遮荫（冬季有保温条件）的地方养护一段时间（一个月左右），如此交替调换。　　　对于盆栽的植株，除了在上盆时添加有机外，在平时的养护过程中，还要进行适当地肥水管理。　　春、夏、秋三季：这三个是它的生长旺季，肥水管理按照“花宝”——清水——“花宝”——清水顺序循环，间隔周期大约为1～4天，晴天或高温期间隔周期短些，阴雨天或低温期间隔周期长些或者不浇。　　冬季：在冬季，主要是做好控肥控水工作，肥水管理按照“花宝”——清水——清水——“花宝”——清水——清水顺序循环，间隔周期大约为3～7天，晴天或高温期间隔周期短些，阴雨天或低温期间隔周期长些或者不浇。对于地栽的植株，春夏两季根据干旱情况，施用2～4次肥水：先在根颈部以外30～100公分开一圈小沟（植株越大，则离根颈部越远），沟宽、深都为20公分。沟内撒进25～50斤有机肥，或者1～5两颗粒复合肥（化肥），然后浇上透水。入冬以后开春以前，照上述方法再施肥一次，但不用浇水。　　　　在冬季植株进入休眠或半休眠期，要把瘦弱、病虫、枯死、过密等枝条剪掉。也可结合扦插对枝条进行整理。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick13981444815100.jpg', 'http://www.boqii.com/entry/detail/2118.html', '');
INSERT INTO `plant_family` VALUES ('356', '茶梅', 'Camellia sasanqua', '茶梅', '茶梅花', '不容易死', '中国江苏、浙江、福建、广东等沿江及南方各省', 'http://www.boqii.com/entry/photo/2109/0,http://www.boqii.com/entry/photo/2109/5418', '', '', '', '', '', '', '', '', '', '　　 　　茶梅为常绿灌木或小乔木，高可达12米，树冠球形或扁圆形。树皮灰白色。嫩枝有粗毛，芽鳞表面有倒生柔毛。叶互生，椭圆形至长圆卵形，先端短尖，边缘有细锯齿，革质，叶面具光泽，中脉上略有毛，侧脉不明显。　　　　　　　　　　　　　　　', '　　茶梅主要在我国江苏、浙江、福建等沿江及南方各省分布，为亚热带适生树种。茶梅性喜阴湿，人工栽种茶梅最好选用半阴半阳的环境，碱性土和粘土则不适宜茶梅的种植。　　　土壤是基础，生长好坏，土壤条件至关重要，茶梅树适宜在微酸性，养分丰富的土壤上生长，PH值在5.5－6.5之间，碱性土及粘性重的土壤或积水地均不宜种植茶梅树。酸性或碱性过重的土壤，茶梅树生长发育不良。适合茶梅树生长的土壤条件必须是质地疏松，吸水及排水性能良好，保水性强，透气性好，中性或微酸性的土壤。　　　土壤肥力的高低，主要以氮、磷、钾及微量元素等多少而定。南方的红黄壤，北方的黑钙土，以及山边的腐殖质土，通常呈微酸性，可用于栽培茶梅树。　　　光照，适宜半阳半阴、湿润的环境，最好是上午当阳，下午背阳。南方夏季，小苗需要遮荫。　　　　气温直接影响的生长生育。每一茶梅树品种需要相适应的温度。茶梅树惧怕酷热，耐严寒，喜温暖。一般最适宜它生长的温度为15～25℃。但是，在自然条件下，冬季最低温度不低于5℃，夏季最高温度不超过38℃，茶梅树都能正常生长和开花。冬季－5℃左右，不会受冻害；低于－10℃时，会出受冻害症状，其表现是叶片、花芽甚至枝条被冻伤、掉落或枯死，严重时树干和根系也会受到冻害，最终整株死亡。因此，在北方寒冷地区，栽培茶花要特别注意防冻，可利用温室、塑料棚、地面覆盖物等设施，保护茶花越冬。在南方炎热地区，夏季高温时，要采取喷水和遮荫措施，降低小环境的温度，使茶梅树正常生长发育。　　　浇水过多，容易积水，出现烂根，影响生长，浇水过少，茶梅树会出现萎蔫现象，无法进行正常的生命活动，当根系所吸收的水分，不能于地面部分蒸发失去的水分平衡时，茶梅树就会出现枯萎现象，为了保持茶梅树体内的水分平衡，就需要经常浇水。盆栽，尤需特别注意，冬季盆土宜干。因为冬季茶梅树进入半休眠阶段，生理上要求的水分减少，另外冬天过湿，容易造成盆土冰冻，损伤根系。夏季盆土宜湿。这是因为夏季正是高温干旱季节，又是茶花生长旺盛时期，需要大量的水分。浇水，春秋季宜在上午和下午；夏季中午所温过高，宜在清早和傍晚；而在冬季，则宜在气温较高的中午。高温干旱的天气，每日需浇水2～3次。', '　　　　茶梅可用扦插、嫁接、压条和播种等方法繁殖，一般多用扦插繁殖。因扦插操作简便、　　每年6月初至8月下旬　　家庭漪养茶梅常用盆插。在干净盆里铺排水层，再装人50％沙土，20％黄泥110％腐叶土，20％焦泥灰配成的', 'http://img.boqiicdn.com/Data/BK/P/imagick66371444642156.jpg', 'http://www.boqii.com/entry/detail/2109.html', '');
INSERT INTO `plant_family` VALUES ('357', '露娜莲', 'Echeveria ', '露娜莲', '露娜', '不容易死', '', 'http://www.boqii.com/entry/photo/2282/0,http://www.boqii.com/entry/photo/2282/5243', '', '', '', '', '', '', '', '', '', '　　 　　露娜莲的株高5～7厘米，莲座直径一般8～10厘米，老株直径可达20厘米。叶片肉质，有白色霜粉；卵圆形，先端有小尖，边缘半透明；一般灰绿色，在阳光充足、温差大的环境下变为淡粉色或淡紫色。聚伞花序，花淡红色。　　　　　　　　　　　　　　　　　　　　　　　　', '　　的叶缘比较圆润，当光照充足的情况下，叶片的尖端会变成淡淡的粉红，如果叶片长不碰水，时间久了会有轻微的白粉，非常可爱。露娜莲是丽娜莲和杂交的品种，小编就为你介绍一下露娜莲的栽培要点。　　露娜莲夏季温度超过35度就要断水休眠了。休眠期应该在阴凉通风的地方，太热植株容易死亡，一旦温度高于32度，就会移到明亮的散射光下慢慢开始断水，整个休眠期少水或不给水，到了9月中旬温度下来了，就开始恢复浇水，冬季如果温度能够保持0度以上，都是可以给水的，0度以下就要断水，否则就容易冻伤。冬季虽然寒冷，可也不是一个冬季都不给一点水，也会在适当的时候微微给点水在植株的根部，切勿喷雾或给大水，叶心水分停留太久，容易引起。　　春季温度上升后就可以慢慢恢复正常给水。这点还是和丽娜莲的习性是一样的，四季中除了夏季要注意遮阳，其他都可以全日照。土壤风筝用的是泥炭混合了颗粒的浮石等，土表铺设干净的浮石，配土以透气为主。', '　　喜欢多肉植物的朋友一定会尝试叶插繁殖，　　有人喜欢直接把叶片插入土中，也有人喜欢让叶片平躺在土面，不过不管用哪种方法，影响成功率的最主要因素还是叶片本身。选择健康的叶片就代表成功率大大提升。根据　　如果两个月都没有出根出芽，或者叶片透明化，或者只出根不出芽，基本就宣布该叶片失败了。当叶片出现根须后要将根部轻轻埋入土中，继续等待，直到嫩芽出现，再', 'http://img.boqiicdn.com/Data/BK/P/imagick22011449133260.jpg', 'http://www.boqii.com/entry/detail/2282.html', '');
INSERT INTO `plant_family` VALUES ('358', '巴西鸢尾', 'Brazil iris', '巴西鸢尾', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2184/0,http://www.boqii.com/entry/photo/2184/5344', '　　', '被子植物门 Angiospermae', '单子叶植物纲 Monocotyledoneae', '百合目 Liliiflorae', '鸢尾科Iridaceae', '巴西鸢尾属Neomarica', '巴西鸢尾Neomarica gracilis', 'Neomarica gracilis', '', '　　 　　巴西鸢尾株高约40～50公分，叶从基部根茎处抽出，呈扇形排列。叶宽约2公分，革质，深绿色；花期约春至夏季，花茎扁平似叶状，但中肋较明显突出，花从花茎顶端鞘状苞片内开出，花有6瓣，3瓣外翻的白色苞片，基部有红褐色斑块，另3瓣直立内卷，为蓝紫色并有白色线条。花通常上午开放，至下午3～4点就开始内卷枯萎了，但花鞘内的花开完後，会长出小苗，小苗越长越大最後降至土表，发根成苗，而小苗隔年就有开花能力。 巴西鸢尾的繁殖方式很奇特，像', '　　引入台湾的时间比较长，所以在台湾地区能够经常看到。由于巴西鸢尾的叶片也有一定的观赏价值，并且栽培难度并不高，所以不论是室内还是室外，都是非常好的观赏植物。　　巴西鸢尾栽植容易，对环境的忍受能力也很强，不论是全日照、半日照、明亮散射光处，都可生长良好，但若希望叶子长的青翠繁盛，还是以半日照或有遮阴的环境较佳，因此，墙边、树荫下、或是室内明亮处，都是理想的栽培地点。巴西鸢尾喜欢土壤常保湿润，夏季需注意勿缺水，否则叶尖乾枯，影响观赏价值。在台湾栽种，只有冬季低温时生长会停顿，其馀时节都生长旺盛，常保浓绿。　　巴西鸢尾的栽培土质以肥沃之壤土或腐植质土为佳，排水需良好。全日照、半日照均能成长，但以半阴处日照约60～70％，叶色较美好。施肥可用有机如豆饼、油粕或三要素，每1～2个月施用一次。喜好潮湿，应常保湿度，干旱不良。性喜高温多湿，生育适温约摄氏20～28度C，冬季要温暖避风，寒流来袭10度C以下需寒害，空气干燥会导致叶尖枯焦。栽培多年后丛生的植株过度拥挤，应强制分株栽植。', '　　　　待根状茎伸长时即可进行，每隔2～4年进行一次，春季花后及秋季均可。花后分株，花芽可在秋季分化，次年着花较好。分割根茎时，每块以2～3芽为好，至少要具一芽。播种应于种子成熟后立即进行，播后2～3年开花。　　巴西鸢尾多用鳞茎繁殖，鳞茎可隔2～3年采收一次。采收后，摊放于通风、干燥而冷凉处，其上所附子球及须根不要分离或除去，否则伤口会', 'http://img.boqiicdn.com/Data/BK/P/imagick78531446630637.jpg', 'http://www.boqii.com/entry/detail/2184.html', '');
INSERT INTO `plant_family` VALUES ('359', '塔松', '', '塔松', '', '不容易死', '非洲', 'http://www.boqii.com/entry/photo/2477/0,http://www.boqii.com/entry/photo/2477/4940', '　', '', '', '', '景天科', '景天属', '', '', '', '　　 　　塔松为多年生草本植物株，叶尖尖的，型似“棒子”，生有气根，叶带有白色蜡粉，是灰蓝的，有种朦胧之美，叶在小枝上的排列似云杉，分叉多。', '　　塔松为景天科厚叶草属，人工栽培的难度并不高，又因其外观碧绿，受到很多多肉爱好者的喜爱。塔松的外形和)很像，都是直立的小型多肉植物，但是塔松没有球松强健。　　塔松像一般多肉一样耐旱怕多水，一个月浇水四次左右就可以了。塔松喜凉爽干燥和阳光充足的环境，耐干旱，怕积水，夏季气温在27℃以上呈半休眠状态，冬季在室内，最低在5℃以上，在阳光充足的条件下可继续。塔松如果光照不足，则会节间伸长；分枝少，长长的枝条冲天上扬。有时，下面的叶子落下，光秃秃，缺乏美感。光照充足，节短叶密，分枝多，更象松树，尽显塔松景天之美。自然成型，无需修剪。', '　　　　塔松的人工繁殖以扦插和砍头均可，极易成活。在春秋生长季，把', 'http://img.boqiicdn.com/Data/BK/P/imagick3771454404047.jpg', 'http://www.boqii.com/entry/detail/2477.html', '');
INSERT INTO `plant_family` VALUES ('360', '金边瑞香', 'Daphne odora Thunb. f. marginata Makino', '金边瑞香', '瑞香、睡香、露甲、风流树、蓬莱花', '不容易死', '', 'http://www.boqii.com/entry/photo/2110/0,http://www.boqii.com/entry/photo/2110/5417', '', '', '', '', '', '', '', '', '', '　　 　　金边瑞香为常绿直立灌木；枝粗壮，通常二歧分枝，小枝近圆柱形，紫红色或紫褐色，无毛。呈顶生头花序，花被筒状，上端四裂径约1.5cm，每朵花由数十个小花组成，由外向内开放，花期二个多月，盛花期春节期间，花色紫红鲜艳，香味浓郁。　　　　　　　　　　　　　　　　　　　　', '　　金边瑞香在近代园艺史上和长春和尚君子兰、日本五针被推崇为园艺三包，并且以其“色、香、姿、韵”四绝着称于世。很多花友都会将金边瑞香盆栽，那么盆栽金边瑞香究竟应该注意哪些问题呢？　　盆栽金边瑞香，盆土宜用肥沃疏松、富含腐殖质带酸性的腐叶土，掺拌适量的河沙和腐熟的饼肥。金边瑞香根为肉质，平时要特别注意控制浇水，如浇水过多，盆土长期过湿，易引起烂根。下雨过后，须及时将盆内积水倒掉。　　金边瑞香虽然喜半阴，但冬、春应放在有阳光照到的环境中，期间如光照充足，肥效相宜，能使枝肉叶黛，花艳香浓，夏季应放在通风良好的阴凉处，炎热时要喷水降温。金边瑞香较喜肥，生长季应每隔10天左右浇一次稀薄液肥。开花前后宜各追施一次稀薄饼肥水。霜降后，移入室内向阳处，室温保持在5℃左右，控制浇水；盆土含水量控制在45％左右，方能。此外，金边瑞香枝干丛生，萌发力较强，耐修剪，花后须进行整枝。', '　　金边瑞香是瑞香的变种，也是中国传统名花，不但可供观赏，根还有一定的药用价值，并且其茎皮纤维还是造纸的原料。有的花友非常喜欢金边瑞香，在将其养的健健康康的同时还想要自己动手繁殖，金边瑞香四季均可繁殖，但是需要使用不同的繁殖方法，小编就为你详细介绍一下金边瑞香在不同季节繁殖的方法及注意事项。　　\n一、春季繁殖\n　　以扦插和嫁接为主。春季是金边瑞香的开花期，亦是新梢　　春季也正是嫁接的良好时期，而且最宜在新枝停长后进行。接穗选取树冠中、上部1～2年牛粗壮枝，切成2～3厘米的枝段，留上部一片叶，芽腋处应有明显芽点。用1～2年生白瑞香实生苗或扦插苗作砧木，行切接或腹接。扎缚材料最好用麻绳，因其透气性较好，而且时间长了会腐烂而自行解缚。嫁接时注意不要弄坏枝段上的叶片，甭则将影响成活率。接后根据嫁接的数量，进行套袋或以薄膜覆盖，以保温和防水。嫁接一般一个月可成活，夏季就可萌芽发梢。嫁接苗　　\n二、夏季繁殖\n　　以扦插和高压为主。此时新枝趋于成熟，枝条顶端开始形成花苞，足扦插的良好季节。但由于夏季高温高湿，也给扦插带来许多麻烦，比如：消毒不好或土壤积水，插条易腐烂，且因腐烂往往由切口向上蔓延，不易及时觉察；不能用塑料薄膜覆盖（高温下盖膜易落叶）；晴天至少要喷水两次增湿等等。如果采用水插法，生根快、成活率高（几乎100％），可减少喷水次数。其方法是，用瓶、槽盛水，按前述方法将扦插条处理后，插入水中1／3，扶直固定。平时视水量减少时，加水至原来水位。一个月内即可生根成活。　　高压是繁殖金边瑞香的传统方法，操作简单、生根快、成活率高。而夏季，又是高压繁殖的最佳时期。方法大致同普通高压法，只是若所压为小枝的话，环剥口相应要小些，1～2年生枝的剥口又0.8～1厘米即可。剥口部位最好在分枝点下0.1厘米处，此处为新老枝交接部位，组织致密，养分含量多，愈合生根快，而且剪下后可依分枝数量撕成若干株。在环剥口七若涂上生根激素，可加速愈合生根。如果按腹接法接白瑞香根段于剥口上端，则可以同时具备高压和嫁接的优点。要注意的是，夏季压枝后所包土团易干燥。可加注射器吸清水注入土团内，以维持土团湿润。一个月后根已长出土团，即可剪下定植。若土冈重量大，小枝难以承负，则竖木条支撑便可。　\n　三、秋季繁殖\n　　这一时期新枝均已成熟，花苞逐渐增大，枝条充实，气温也降至适宜，是用各种方法繁殖的好时机，而且扦插苗或高压苗均能正常开花。当气温降至25℃左右时，繁殖的苗木要加塑料薄膜覆盖。喷水量需比夏季大大减少。可隔几天检查一次，视土面发白，适量喷些水，便可在一个月内生根。嫁接的以腹接为好，也可以靠接，按后一个月，视叶片正常，便可断砧、松膜透气，解缚在宜待来年春季进行。　\n　四、冬季繁殖\n　　这时金边瑞香的花苞继续增大，到12月底即绽开苞叶开花。因气温低和即将开花，养分大量消耗，愈合生根较难，但死亡率也低（低温抑制了霉菌的活动）。扦插的如未用温床，则要到开花后方能生根。为防止开花消耗养分，可以待花苞绽开后把小花全部摘去，以促早日生根。嫁接者仍以腹接为主，翌年春季断砧后便可萌芽。高压繁殖由于生根期过长，不宜进行。　　另外，金边瑞香最忌的是“湿”。扦插基质宜以细沙为主，细沙颗粒小，与插枝接触紧密，而且沙可以防止霉菌的侵人和蔓延。又能透水透气，只是保温性能比砻糠灰差些。金边瑞香根为肉质，', 'http://img.boqiicdn.com/Data/BK/P/imagick23821444642468.jpg', 'http://www.boqii.com/entry/detail/2110.html', '');
INSERT INTO `plant_family` VALUES ('361', '朱蕉', 'Cordyline fruticosa （L.） A. Cheval.', '朱蕉', '朱竹、铁莲草、红叶铁树、红铁树', '不容易死', '中国华南地区；印度及太平洋热带岛屿', 'http://www.boqii.com/entry/photo/2113/0,http://www.boqii.com/entry/photo/2113/5414', '　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '朱蕉属', '朱蕉', 'Cordyline fruticosa （L.） A. Cheval.', 'Cordyline fruticosa', '　　 　　朱蕉为灌木状，直立，高1－3米。茎粗1－3厘米，有时稍分枝。叶聚生于茎或枝的上端，矩圆形至矩圆状披针形，长25－50厘米，宽5－10厘米，绿色或带紫红色，叶柄有槽，长10－30厘米，基部变宽，抱茎。', '　　喜高温，不耐寒，对于光照的适应能力比较强，如果过度阴暗，其叶色会转成淡绿，观赏价值则降低了很多。朱蕉不但可以土培，还能水培，水培朱蕉可能是比较新奇的做法，但成功率还是比较高的，小编就为你介绍一下水培朱蕉的。　　水培朱蕉可将土培植株从土中挖出，洗净植株根系泥土，以海绵等柔软之物挟裹根际，置入定植杯里，再将定植杯置入盆具的防枯落物板的孔槽里，使根系的2／3浸入营养液。水培朱蕉也可以直接扦插，通常在5－6月份将插穗插于盛满水的广口瓶中，约3周左右便能生根。　　水培朱蕉需选用霍格兰营养液的1／3－1／2浓度，pH5.8，营养液深度为盆具的2／3。每15－25天更换一次营养液或根据植株生长情况酌情缩短或延长更换营养液的。　　夏季需适当遮阳以避免叶片枯黄，其他需要光照。经常往叶片喷水，有利于茎叶繁茂，叶片鲜艳。为保持叶片的鲜艳彩纹，营养液的以磷、钾为主，氮素偏少。', '　　　\n　1、扦插\n常用的繁殖方法，6－10月扦插。朱蕉分枝力差，一般多专门培养高大健壮母株，进行采条扦插繁殖。家庭繁殖时，多结合修剪，从植株上剪取顶部成熟的枝条，剪截成长10－15厘米的插穗，剪掉枝条上的叶片或保留1／2叶片，然后以沙为基质，插于沙床或盆土中，入土深度为6厘米左右。扦插后摆放在荫棚下。若温度在25－30℃和较高的空气湿度的条件下，30－40天即可生根发芽。待新枝长5厘米左右时即可移栽上盆，进行单株培养。　\n　2、高空压条\n　　家庭繁殖不多又想尽快培养出大株时，可采用高空压条繁殖。一般在5－6月进行。选　\n　3、播种\n　　夏未秋初果实成熟后进行采收。从浆果中取出种子，淘冼干净后晾干，点播干沙床或盆内。播种后，室温保持24℃以上，经20天左右种子便可萌芽出土。待幼苗长到6厘米高左右时，移入花盆，每盆1株，单独继续培养。', 'http://img.boqiicdn.com/Data/BK/P/imagick93231444729766.jpg', 'http://www.boqii.com/entry/detail/2113.html', '');
INSERT INTO `plant_family` VALUES ('362', '勿忘我', 'forget me not', '勿忘我', '勿忘草、星辰花、匙叶草', '不容易死', '亚欧大陆温带、伊朗、俄罗斯、巴基斯坦、印度、中国大陆大部', 'http://www.boqii.com/entry/photo/1986/0,http://www.boqii.com/entry/photo/1986/5541', '', '', '', '', '', '', '', '', '', '　　 　　勿忘我为多年生草本，高30－60cm。全株光滑无毛，茎不分枝。叶大部分基生，平铺地面；具短柄，柄有翅；叶片倒卵状匙形，长8－10cm，宽3－6cm，先端圆形，基部渐狭成短柄，边缘具微波状齿，下面羽状叶脉明显；茎生叶对生，2－3对，无柄，匙形，长1.5－2cm，宽0.7－7cm，先端钝，基部圆，半抱茎，边缘具波状齿。勿忘我　　　　　　　　　　　　　　　　', '　　除了可以观赏之外，还是一种补血草，有一定的药用价值。有的花友对于勿忘我非常喜爱，就会在家中的阳台上自己栽培，勿忘我的栽培难度并不高，但是想要自己的勿忘我长的好看的话，就需要注意栽培的时候采取一些小诀窍了。　　1、种植：勿忘我干燥、肥沃、透气性好、微碱性的沙质壤土。勿忘我的培养土可以将腐熟的有机肥和缓效复合肥均匀搅拌进土中。勿忘我的定植株行距为30cm×40cm，栽植深度以基质稍高于根颈部为宜。勿忘我栽植后应有2个月的保持15℃以下温度，以利植株通过春化阶段，有利于勿忘我的正常生长开花。　　2、光照：勿忘我喜欢充足的阳光，但是忌高温高湿，所以在平时要给予勿忘我充足的光照，光照不足会导致勿忘我叶丛繁茂，影响开花，甚至不开花，但要做好遮荫措施。　　3、温度：勿忘我的生长适温为22－28℃，气温高于30℃或低于5℃不利于勿忘我的生长。因此春夏种植的勿忘我，当种苗未作低温时，需推迟进入大棚的时间，使其充分接受低温，完成春化作用。　　4、浇水：种植勿忘我必须配备排水设施，以防积涝。勿忘我喜土壤微潮，但忌根部积水，平时应尽量保持土壤处于微潮偏于状态。　　5、施肥：在种植勿忘我之前，土壤要施足基肥，以50千克／亩为宜，深翻人土壤中。当勿忘我生出6－8片叶子时，追加一次0.1％的尿素溶液，当勿忘我抽生花葶时，追施0.1％磷酸二氢钾溶液2－3次。　　6、病虫害：勿忘我病害有灰霉病、白粉病、病毒病等。灰霉病可用800－1000百菌清、甲基托布津连续喷洒3－4次防治。白粉病可用粉绣宁等喷洒防治，病毒病主要采取及时拔除病株烧毁，喷洒杀虫剂防止昆虫传病等措施防治。', '　　　　勿忘我有播种繁殖和组织培养育苗两种方式。播种一般在9月一翌年1月，种子具有嫌光性，将种子撒播后要稍加覆土、保持湿度。在15－°20℃适温条件下，经10～15天发芽。播种要注意温度不要超过25℃，萌芽出土后需通风，小苗具5片以上真叶时定植。采用组培技术培育的组培苗，4～6片叶时定植。　　勿忘我性喜干燥，喜土层深厚，疏松透气，微碱性沙质壤土，如腐熟的有机肥和缓效复合肥，施后均匀翻入土中；定植株行距为30厘米×40厘米，栽植深度以基质稍高于根颈部为宜。栽植后应有2个月的　　生长期中施肥总用量，其中氮、钾等70％作为基肥施用，30％用作追肥，磷肥全部作基肥施用，追肥一般1季1次。花期追钾肥、硼肥有利提高　　勿忘我喜干燥及排水良好的环境，忌水涝。整个生育期要适当控制浇水量，否则会导致开花质量及产量下降。', 'http://img.boqiicdn.com/Data/BK/P/imagick77981440582537.jpg', 'http://www.boqii.com/entry/detail/1986.html', '');
INSERT INTO `plant_family` VALUES ('363', '石竹', 'Dianthus chinensis L.', '石竹', '洛阳花、中国石竹、中国沼竹、石竹子花', '不容易死', '中国、韩国、朝鲜、俄罗斯', 'http://www.boqii.com/entry/photo/2127/0,http://www.boqii.com/entry/photo/2127/5400', '', '', '', '', '', '', '', '', '', '　　石竹又名兴安石竹、北石竹等，为石竹属多年生草本 石竹 　　　　　　　　　　　　　　　　　　　石竹族　　　　　　', '　　石竹为石竹科、石竹属多年生草本，石竹科的栽培难度都比较低，并且石竹相对比较耐寒及耐旱，对于土壤的要求也不高。过多施肥对于石竹还会起到反作用。如果你也栽种了石竹，就跟着小编一起了解一下石竹的栽培要点吧。石竹　　　8月施足底肥，深耕细耙，平整打畦。当播种苗长1－2片真叶苗，长出3－4片真叶时移栽。株距15厘米，行距20厘米。移栽后浇水，喷施新高脂膜，提高成活率。　　　　石竹15－20℃。冬季应放温室，温度保持在12℃以上。生长期要求光照充足，摆放在阳光充足的地方，夏季以散射光为宜，避免烈日暴晒。温度高时要遮荫、降温。　　　浇水应掌握不干不浇。当株高10厘米时再移栽1次。秋季播种的石竹，11－12月浇防冻水，第2年春天浇返青水。整个生长期要追肥2～3捉腐熟的人粪尿或饼肥。要想多开花，可摘心，令其多分枝，必须及时摘除腋芽，减少养分消耗。石竹花修剪后可再次开花。', '　　石竹的栽培难度并不高，常用播种的方法进行繁殖，当得不到种子的时候，还可用扦插和分株的方法繁殖。石竹的繁殖难度并不高，并且成活率非常高，所以深受人们的喜爱。石竹　　石竹常用播种、扦插和分株繁殖。种子发芽最适　　石竹的扦插繁殖在10月至翌年2月下旬到3月进行，枝叶茂盛期剪取嫩枝5－6厘米长作插条，插后15－20天主根。分株繁殖多在花后利用老株分株，可在秋季或早春进行。例如可于4月分株，夏季注意排水，9月份以后加强肥水', 'http://img.boqiicdn.com/Data/BK/P/imagick18211445246656.jpg', 'http://www.boqii.com/entry/detail/2127.html', '');
INSERT INTO `plant_family` VALUES ('364', '吊竹梅', 'Zebrina pendula Schnizl', '吊竹梅', '吊竹兰、斑叶鸭跖草、花叶竹夹菜、红莲等', '不容易死', '原产墨西哥', 'http://www.boqii.com/entry/photo/2078/0,http://www.boqii.com/entry/photo/2078/5449', '　　', '被子植物门', '单子叶植物纲', '鸭跖草目', '鸭跖草科', '吊竹梅属', '吊竹梅', 'Zebrina pendula Schnizl', '', '　　 　　吊竹梅为多年生草木。长约1米。茎稍柔弱，半肉质，分枝，披散或悬垂。叶互生，无柄；叶片椭圆形、椭圆状卵形至长圆形，先端急尖至渐尖或稍钝，基部鞘状抱茎，叶鞘被疏', '　　吊竹梅的叶片非常特殊，一般的吊竹梅叶面有两条因绿色闪光条纹，夹着中央的绿色部分，而双色吊竹梅和四色吊竹梅则更是特别。其实吊竹梅的栽种难度并不高，但是四色吊竹梅的栽种难度则比较大，并且想要保持其颜色，就需要注意栽种时注意栽培方法了。　　1、光照：吊竹梅无论什么都需要明亮的光照，以促使植株长出密集而鲜艳的叶子。如果光线太暗，茎会长得细长散乱，叶会。但不可让烈日直射。　　2、：吊竹梅温暖的环境，春夏秋三个季节的温度都能适宜，在较低的温度下生长很缓慢。冬季温度约在10摄氏度时就要注意保温。　　3、浇水：在生长季节，吊竹梅要等到表土约2。5厘米深处干时再进行浇水。盆土稍干，叶色会更鲜艳。在冬季休眠期，等到盆土一半干时再进行适量浇水。　　4、施肥：吊竹梅在生长活跃期，可每半个月施一次以氮为主的复合肥。　　5、繁殖：吊竹梅的老叶易脱落，使得下部显得空荡，因此种植吊竹梅最好经常培育新株用以更新。吊竹梅用茎插很容易生根，甚至可以用水来扦插。上盆时要把5、6株合栽。', '　　吊竹梅又名吊竹兰、斑叶鸭跖草等，是一种投入不多，但是地被绿化覆盖效果又快又好的草本　　吊竹梅的扦插基质，是用来扦插的营养土或河砂、泥碳土等材料。用来扦插的枝条称为插穗。把茎杆剪成6公分长一段，每段带三个以上的叶节，也可用顶梢做插穗。　　吊竹梅叶面有两条银绿色闪光条纹，夹着中央的绿色部分。叶面上有不规则的粉红色、绿色、乳白色和银白色条纹，最漂亮，也最难栽种。要种好吊竹梅，需要注意的', 'http://img.boqiicdn.com/Data/BK/P/imagick74301443173509.jpg', 'http://www.boqii.com/entry/detail/2078.html', '');
INSERT INTO `plant_family` VALUES ('365', '铁树', 'Cycas', '苏铁', '凤尾蕉、避火蕉、凤尾松、金果、铁蕉、火蕉、番蕉', '不容易死', '亚洲东部及东南部、大洋洲及马达加斯加等热带、亚热带地区', 'http://www.boqii.com/entry/photo/2003/0,http://www.boqii.com/entry/photo/2003/5524', '', '', '', '', '', '', '', '', '', '　　铁树又名避火蕉，由于铁树树干如铁般坚硬，并且 　　铁树为常绿　　　　　　　　　　　　　　　　　　　　', '　　喜欢温暖湿润的环境，但是不耐寒，虽然铁树的栽培难度并不高，但是想要种出漂亮的铁树还是需要注意栽培方法的。铁树的约有200年，但是在长江流域及北方各地栽培的铁树极少开花，有的甚至终生不开花。　　1、土。最好是肥沃的沙壤土。配合比例为－份壤土、1份经堆沤的腐殖土，1份煤灰，充分混合。这样的土壤，疏松肥沃，透水透气，很适合铁树。　　2、修剪。当茎干生长高达50公分后，即应于春季割去老叶，以后每年割－圈，或至少3年进行－次。若植株尚小，展开度不够理想，可将叶片全部剪掉，这样不会影响新叶长出的角度，会使植株更完美，修剪时应尽量剪至叶柄基部，使茎干整齐美观。　　3、换盆。盆栽铁树应注意换盆，至少5年换盆－次。换盆时，盆土中可掺拌骨粉等磷肥，换盆时间以气温15摄氏度左右为好。此时，生长旺盛的，还应适当削去些老根，以利于及时长出新根。', '　　　　1、分蘖繁殖。在树干上切取分蘖，栽种在砂质壤土中，行距20－30公分，株距10－15公分，覆土6－8公分，遮阴，在半阴条件下容易成活。　　2、树干切移繁殖。将树干切成10公分左右的段，埋在砂质土壤中，覆土4－6公分，经常浇水保持湿润，待干部发出新芽后，即可分栽。　　3、播种繁殖。种子于秋末采集，随采随播，也可砂藏，于翌春季点播。因种皮厚而坚硬，生芽缓慢，－般4～6个月后发芽。', 'http://img.boqiicdn.com/Data/BK/P/imagick96441441532888.jpg', 'http://www.boqii.com/entry/detail/2003.html', '');
INSERT INTO `plant_family` VALUES ('366', '荷花', 'Lotus flower', '荷花', '莲花、水芙蓉、藕花、芙蕖、中国莲', '不容易死', '印度、泰国、越南、中国', 'http://www.boqii.com/entry/photo/1899/0,http://www.boqii.com/entry/photo/1899/5630', '', '', '', '', '', '', '', '', '', ' 　　荷花是一种　　荷花是水生植物，性喜相对稳定的平静浅水、湖沼、泽地、池塘，是其适生地。荷花的需水量由其品种而定，大株形品种如古代莲、红千叶相对水位深一些，但不能超过1.7米．中小株形只适于20-60厘米的水深。同时荷花对失水十分敏感，夏季只要3小时不灌水，水缸所栽荷叶便萎靡，若停水一日，则荷叶边焦，花蕾回枯．荷花还非常喜光，生育期需要全光照的环境。荷花极不耐荫，在半荫处生长就会表现出强烈的趋光性。　　首先要破壳。5-6月将种子凹进的一端在水泥地上或粗糙的石块上磨破，浸种育苗。要保持水清，经常换水，约一周左右出芽，两周后生根移栽，每盆栽一株，水层要浅，不可将荷叶淹在水中。90%左右当年可开花，但当年开花不多。　　3月中旬至4月中旬是翻盆栽藕的最佳时期。过早栽植会有寒流影响，种藕容易受冻害。北方 　　荷花是水生植物，生长期内时刻都离不开水。生长前期，水层要控制在三厘米左右，水太深不利于提高土温。如用自来水，最好另缸盛放，晒一、二天再用。夏天是荷花的生长高峰期，盆内切不可缺水。入冬以后，盆土也要保持湿润以防种藕缺水干枯。荷花的肥料以磷钾肥为主，辅以氮肥。如土壤较肥，则全年可不必施肥。腐熟的饼肥、鸡鸭鹅粪是最理想的肥料，小盆中施半两即可，大盆中最多只能施1～2两，切不可多施，并要充分与泥土拌和。生长旺期，如发现叶片色黄、瘦弱，可用每盒0·5克尿素拌于泥中，搓成10克左右的小球，每盆施一粒，施在盆中央的泥土中，7天见效。　　入冬以后，将盆放入室内或埋入冻土层下即可，黄河以北地区除埋入冻土层以下还要覆盖农膜，整个冬季要保持盆土湿润。　　如果养殖荷花只是为了观赏那么可以任其自由繁殖，但想要提高观赏价值或想要繁殖莲藕出售那得严格按照以上方法操作了。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick56961428055422.jpg', 'http://www.boqii.com/entry/detail/1899.html', '');
INSERT INTO `plant_family` VALUES ('367', '虹之玉', 'Sedum rubrotinctum', '虹之玉', '圣诞快乐、耳坠草', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/1947/0,http://www.boqii.com/entry/photo/1947/5581', '', '', '', '', '', '', '', '', '', '　　 　　虹之玉为多年生肉质草本植物。株高10－20厘米，多分枝。肉质叶膨大互生，圆筒形至卵形，长2厘米，绿色，表皮光亮、无白粉，在阳光充足的条件下转为红褐色，小花淡黄红色。　　　　　　　　　　　　　　', '　　比较特别的是不怕暴晒，和很多多肉不一样的是，虹之玉的会越晒越红，所以到炎热的夏季，虹之玉不用担心会被晒伤，也不用刻意为虹之玉遮光，长期让虹之玉处于半阴的环境下生长的话，虹之玉的叶片则会变绿，变得没红色那么好看了。　　叶片肉质，呈长椭圆形，约1厘米长，互生。花黄色，星形。在秋冬季节或强光照下，叶片部分或全部转为鲜红色。叶尖处略呈透明状，此时叶片红绿相间，色泽鲜艳，如虹如玉，故又名虹之玉。　　1、温暖及昼夜明显的环境。对温度的适应性较强，在10℃至28℃之间均可良好生长。　　2、秋冬季节气温降低，光照增强，肉质叶片逐渐变为红色，因此栽培过程中人为降温可提高观赏价值。　　3、冬季室温不宜低于5℃。耳坠草喜光，整个生长期应使之充分见光。但夏季曝晒会造成叶片日灼，可适当遮光或半日晒，中午应避免烈日直射。耳坠草，耐干旱，因此不宜大肥大水，应见干浇水且浇透，而冬季室温较低时则要减少浇水量和次数。一般一个月施一次有机液肥。　　4、夏季注意保持通风良好。耳坠草生长较慢，一般栽培3年后株形开始散乱，因此应提前进行修剪。', '　　　\n　虹之玉茎插：\n　\n　虹之玉扦插：\n　\n　虹之玉叶插：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick53031439803630.jpg', 'http://www.boqii.com/entry/detail/1947.html', '');
INSERT INTO `plant_family` VALUES ('368', '垂盆草', 'Sedum sarmentosum Bunge', '垂盆草', '狗牙半支、狗牙瓣、鼠牙半支、石指甲、佛指甲等', '不容易死', '全世界', 'http://www.boqii.com/entry/photo/2055/0,http://www.boqii.com/entry/photo/2055/5472', '', '', '', '', '', '', '', '', '', '　　 　　垂盆草为多年生草本。不育枝及花茎细，匍匐而节上生根，直到花序之下，长10－25厘米。3叶轮生，叶倒披针形至长圆形，长15－28毫米，宽3－7毫米，先端近急尖，基部急狭，有距。聚伞花序，有3－5分枝，花少，宽5－6厘米；花无梗；萼片5，披针形至长圆形，长3.5－5毫米，先端钝，　　　　　　　　　　　　　　　　　　　　　　　', '　　垂盆草的栽种难度并不高，耐干旱、高温，并且吸水能力强，但是一个月不交税也不会干死，所以非常适合，没有栽种经验的朋友。　　垂盆草温暖湿润的气候条件，在温带、暖温带及亚热带都有广泛的分布，垂盆草忌贫瘠的土壤环境，表现出生长衰弱的现象。在北京和天津地区，选择背风向阳的场所可以越冬。　　不择土壤，田园土、中性土、砂壤土均能生长，生命力极强，茎干落地即能生根。垂盆草栽植时，土壤须适量施入有机肥，经过粉碎的棉籽饼、麻酱渣或鸡粪干均可。覆土后栽苗，要求地势稍高，土壤不能积水。垂盆草适宜生长为15℃至28℃，垂盆草忌强光照的环境，遇强光表现出叶片发黄的现象。　　垂盆草生长速度快，需水量比较大，在具有一定遮阴条件下生长良好。生长过程中每半月少量施用一次复合化肥，施肥后要立即浇灌清水，以防烧伤茎叶或根系。', '　　　　垂盆草可采用种子繁殖，也可采用无性繁殖，即采用枝条扦插法、分株繁殖法或压条繁殖法，极易成活。通常采用分株或扦插繁殖。分株宜在早春进行，扦插随时皆可。扦插法在春季或秋季从成年植株上采集垂盆草匍匐茎，将匍匐茎剪切成3至5厘米的小段，扦插在预先准备好的扦插床内，扦插后喷灌水，水要浇足，且保持扦插床内土壤湿润在20℃至25℃', 'http://img.boqiicdn.com/Data/BK/P/imagick36301442828001.jpg', 'http://www.boqii.com/entry/detail/2055.html', '');
INSERT INTO `plant_family` VALUES ('369', '黄杨', 'Chinese boxwood', '黄杨', '黄杨木、瓜子黄杨、锦熟黄杨', '不容易死', '', 'http://www.boqii.com/entry/photo/1973/0,http://www.boqii.com/entry/photo/1973/5554', '植物　', '被子植物门', '双子叶植物纲', '无患子目', '黄杨科', '黄杨属', '黄杨', 'Buxus sinica （Rehd. et Wils.） Cheng', '', '　　 　　黄杨高1－6米，枝圆柱形，有纵棱，灰白色；小枝四棱形，全面被短柔毛或外方相对两侧面无毛，节间长0.5－2厘米。叶革质，阔椭圆形、阔倒卵形、卵状椭圆形或长圆形，大多数长1.5－3.5厘米，宽0.8－2厘米，先端圆或钝，常有小凹口，不尖锐，基部圆或急尖或楔形，叶面光亮，中脉凸出，下半段常有微细毛，侧脉明显，叶背中脉平坦或稍凸出，中脉上常密被白色短线状钟乳体，全无侧脉，叶柄长1－2毫米，上面被毛。', '　　黄杨的栽培难度并不大，很多花友都喜欢将黄杨制作成盆景栽种在家中，不但可以美化环境，还能起到净化空气的作用。那么黄杨盆景应该如何栽培呢？需要注意哪些呢？　　　黄杨喜湿润，盆景需经常浇水，保持盆土湿润，但也不可积水。夏季高温期，要早晚浇水，并喷叶面水。　　　在生长期5～8月，施2～3欢腐熟稀薄的饼肥水即可，冬季施1次基肥，用沤熟厩肥或干饼肥屑均可。　　　　生长期随时剪去徒长枝、重叠枝及影响树形的多余枝条。黄杨萌　　发较快，一般在发新梢后，将先端1～2节剪去，可防止徒长。黄杨结果后，要及时摘去，以免消耗养分，影响树势生长。　　　一般2～3年进行一次，时间以春季萌发前为好。结合翻盆剪去部分老根及过长过密根系，换去1／2旧土，塞以肥沃疏松的，以利根系发育。　　　黄杨主要虫害有介壳虫和黄杨尺螃，介壳虫可用人工刷洗杀之，或用80％1500倍液喷杀；黄杨尺嫂用80％可狙性粉剂喷杀，或用40％氧化乐果1000～2000倍喷杀。主要病＊有煤污病，会引起落叶现象，防治关键是清除介壳虫，并经常喷叶面水，冲洗灰尘，使之生长良好。', '　　　\n　一、播种繁殖\n　　播种要在7月份采收成熟果实，摊放晒干后，脱粒取种，袋藏。冬播或早春播种，如迟于3月播种，当年很少出苗，多数要到第二年才能发芽出土。播种前先用40℃温水浸种一昼夜（自然冷却）晾干后，即可播种。苗床土要选择肥沃疏松的沙质壤土，条播行距15～20厘米，播幅5厘米，播种沟深2厘米，播后覆盖焦泥厚1厘米，再盖稻草。幼苗出土后，及时揭草，搭棚遮荫。苗期要加强　\n　二、扦插繁殖\n　　宜在梅雨', 'http://img.boqiicdn.com/Data/BK/P/imagick9661440408917.jpg', 'http://www.boqii.com/entry/detail/1973.html', '');
INSERT INTO `plant_family` VALUES ('370', '海石竹', 'Armeria maritima', '海石竹', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2306/0,http://www.boqii.com/entry/photo/2306/5218', '　　', '被子植物门', '双子叶植物纲', '白花丹目', '白花丹科', '海石竹属', '', 'Armeria maritima', '', '　　 　　海石竹为蓝雪科矾松属宿根草花，植株低矮，丛生状，株高20－30厘米。叶基生，叶线状长剑形，花为粉红色至', '　　原本是在海边的花，其小花聚生成密集的球状，群植的景观非常漂亮。海石竹的生长强健，对于环境要求并不高，人工栽培的难度不高。小编就为你介绍一下海石竹在栽培过程中需要注意哪些。　　　海石竹以富含有机质的腐叶土为佳。　　　　海石竹生长适温为15～25℃，生长期要求光照充足，摆放在阳光充足的地方，夏季以散射光为宜，避免烈日暴晒。温度高时要遮荫、降温。　　　　海石竹需肥量不多，所以栽培时约2～3周施一次花宝2号1000倍稀释液即可。浇水要适量，气温高、水温低或者久旱后在温度高时浇大量水，会对海石竹的根系造成损害。', '　　　\n　一、播种繁殖\n　　若要5月份开始开花，则在1月份播种；若要越冬之后的春季开花则在7～8月播种（露天栽培），或8、9月播种（玻璃、薄膜温室里）。用　　子叶完全展开后（　　上盆基质为松散而颗粒粗大的草本土，pH值保持在5.8～7.0。温度为13℃～17℃，3℃～5℃下无霜越冬，或在露天应用织物覆盖也可以越冬。温度为15℃～18℃时需10～11周才能春季开花，7℃～12℃低温将减缓生长而导致延长生长周期。当温度低于7℃时则会停止生长。　　\n二、分株繁殖\n　　秋至冬季为适期。分株时把丛生苗挖出，用利刀按每株1～2头芽分开，植于盆中，加强', 'http://img.boqiicdn.com/Data/BK/P/imagick52001449653817.jpg', 'http://www.boqii.com/entry/detail/2306.html', '');
INSERT INTO `plant_family` VALUES ('371', '一品红', 'Euphorbia pulcherrima Willd. et Kl.', '一品红', '象牙红、老来娇、圣诞花、圣诞红、猩猩木', '不容易死', '', 'http://www.boqii.com/entry/photo/1956/0,http://www.boqii.com/entry/photo/1956/5571', '', '', '', '', '', '', '', '', '', '　　 　　一品红是灌木　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　一品红是原产于墨西哥塔斯科地区的某种变色型植物，很多人都会觉得一品红非常漂亮，火红的颜色更是深得人心，但其实一品红真正的花是在叶束中间的部份。有的朋友回选购一些一品红在圣诞节的时候用来装点节日气氛，那么究竟应该如何栽种才能让一品红更加漂亮呢？　　一品红可用培养土、腐叶土和沙混合，或用泥炭土、炭化稻壳、粗河沙以3：1：1的比例混合而成。土壤以微酸性为好，并加入适量钙、镁肥，可使红色苞片更加鲜艳。　　一品红对水分的反应比较敏感，期只要水分供应充足，茎叶生长迅速，有时出现节间伸长、叶片狭窄的徒长现象。相反，盆土水分缺乏或者时干时湿，会引起叶黄脱落。因此，水分的控制直接关系到一品红的生长和。　一品红为短日照植物。在茎叶生长期需充足阳光，促使茎叶生长迅速繁茂。要使苞片提前变红，可将每天光照控制在12小时以内，促使花芽分化。　一品红生长适温为18－25℃，冬季温度不能低于10℃，否则会引起苞片泛蓝，基部叶片变黄脱落，形成“脱脚”现象。当春季气温回升时，从茎干上能继续萌芽抽出枝条。　生长期每半个月施肥1次。通常在花芽分化前两周，对每株补充1茶匙可溶性。冬季肥料浓度应降低一半。　　一品红主要虫害有白粉虱、蓟马、、蚜虫等，可用相关杀虫剂或杀螨剂防治，如40％三氯杀螨醇1000－1500倍液等。此外还应保持栽培环境，及时消除杂草。', '　　由于圣诞花　　一品红的繁殖方法主要采用扦插繁殖，通常采用泥盆或水槽扦插，一品红喜欢疏松、排水良好的混合土，扦插最好在春天进行，可以选用嫩枝，也可采用　　一品红也可以用压条繁殖，一般采用高压繁殖法。首先选择木质化的枝条，一般选头年生', 'http://img.boqiicdn.com/Data/BK/P/imagick6601439891835.jpg', 'http://www.boqii.com/entry/detail/1956.html', '');
INSERT INTO `plant_family` VALUES ('372', '金琥', 'Echinocactus grusonii Hildm.', '金琥', '', '不容易死', '原产墨西哥中部干燥，炎热的热带沙漠地区。', 'http://www.boqii.com/entry/photo/1967/0,http://www.boqii.com/entry/photo/1967/5560', '', '', '', '', '', '', '', '', '', '　　 　　金琥为茎圆球形，单生或成丛，高1.3米，直径80厘米或更大。球顶密被金黄色绵毛。有棱21－37，显着。刺座很大，密生硬刺，刺金黄色，后变褐，有辐射刺8－10，3厘米长，中刺3－5，较粗，稍弯曲，5厘米长。6－10月开花，花生于球顶部绵毛丛中，钟形，4－6厘米，黄色，花筒被尖鳞片。　　　　　　　　　　　　　　　　　　', '　　金琥的是仙人球中非常常见的品种，由于金琥的刺为金黄色，所以深受人们的欢迎，但是金琥也是多肉植物，栽培难度并没有想象中仙人球的栽培那么简单，如果不采取科学的管理方法，是不能栽培出令人满意的金琥的。　　　温度在金琥的周期起重要的作用。冬季金琥处休眠状态。4月金琥苏醒并开始生长。5、6月气温达到金琥的生长适温25～30℃，金琥进入生长旺期。7～8月气温超过35℃，金琥进入夏眠。9月气温降至30℃时，金琥再次苏醒，又开始生长。秋天管理得好，其生长速度可能超过春天。11月中下旬气温降低，金琥渐入。至此，金琥一年一度的生长就告一段落。　　　栽培金琥应尽量满足它对阳光的需求，除冬季入室养护，春、夏、秋季均须全天候放于阳光充足处。如把金琥长期放于室内会影响其体色及长刺，球体畸形变态，丧失观赏价值。金琥冬季入室要放在窗台有阳光处，放一段时间转一下盆，使球体各处受光均匀。在盛夏烈日直射时，要适当遮荫。笔者的做法是，把金琥的上半部用有色塑料袋套住，保护球顶茸毛不受雨淋，再用大的塑料袋连球带盆套住，放于室外阳光照射时间最长之处。盛夏高温时，把大的塑料袋撤去，避免袋内闷湿引起球体腐烂。撤袋后盆球处在通风的环境下，球体生长良好。　　　金琥虽耐旱，但不是不需要水。有的金琥始终养不大，甚至缩小，与长时不浇水有关。金琥在春、秋季生长期应给予充足的水分，冬、夏季休眠期节制浇水。生长初期4、5天或1周浇一次水，应从盆沿处浇水，宜在上午9、10点钟或下午4、5点钟。自来水最好放置2天后再浇。4月下旬至6月金琥需水量增大，浇水早、晚各一次，要浇透。6月梅雨时谨防盆土过湿，导致烂根。7、8月金琥进入夏季休眠，要节制浇水。9月下旬至10月金琥又进入生长期，3、4天浇一次水。11月金琥的生长趋于停滞，浇水可10天一次。12月金琥进入休眠，可不浇水，以增强其抗寒能力。　　　春季应勤施薄肥，1周一次。5、6月4、5天一次，浓度可略高些。盛夏高温时不施肥。9、10月可一周施一次，11月至翌春不施肥。肥料以家禽、残渣或禽粪腐熟后兑水稀释施用，宜早上9～10点或下午5点以后进行，施肥后隔一天再浇水。　　　要求疏松、肥力适中、酸碱度中性或微酸性、富含有机质，市场有袋装土售，也可自行配制：①壤土3份、腐叶土或泥炭土2份，过筛骨粉1份，粗砂4份；②粗砂3份，园土3份，腐叶土2份，石灰质1份，碎砖或瓦片1份，其中加少许过磷酸钙、木炭颗粒或骨粉。　　盆具以透气的泥盆最佳，陶盆、瓷盆等次之。盆的大小视金琥球体而定，球体与盆壁的间隙在3～4厘米。球体大，间隙可适当大些。', '　　金琥是现在非常常见的　　1、播种繁殖法：播种发可即采即播，当年采摘的种子出苗率也非常高。播种　　2、仔球嫁接法：这种方法是将繁殖培育3个月以上的实生金琥仙人球苗嫁接在生长旺盛柔嫩的量天尺植株上催长。待接穗生长到量天尺砧木已经支撑不了的重量时，再切下，晾干伤口后在养殖盆器中进行扦插。在土壤疏松肥沃、通风透气良好的环境下，不经嫁接的金琥仙人球实生苗生长也很快。上盆后的实生苗或嫁接仔球，应放置在半荫处养殖，忌强烈阳光直射，1周至1周半后球体不再萎缩，即可生长成活。', 'http://img.boqiicdn.com/Data/BK/P/imagick86101440149575.jpg', 'http://www.boqii.com/entry/detail/1967.html', '');
INSERT INTO `plant_family` VALUES ('373', '球松', 'Sedum multiceps', '球松', '小松绿', '不容易死', '原产非洲，阿尔及利亚', 'http://www.boqii.com/entry/photo/2236/0,http://www.boqii.com/entry/photo/2236/5291', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '景天属', '球松', 'Sedum multiceps', 'Sedum multiceps', '　　 　　球松的植株低矮，多分枝，株型近似球状，老茎灰白色，新枝浅绿色，以后逐渐转为灰褐色，肉质叶近似针状，但稍宽，长约1cm，簇生于枝头，绿色，老叶干枯后贴在枝干上，形成类似松树皮般的', '　　球松原产于非洲，喜欢凉爽干燥且阳光充足的环境，当夏季环境高于27℃以上时就会呈现半休眠的状态。球松的分枝较多，多肉爱好者们常常会将球松制作成，别有一番风味。　　球松属于夏季休眠品种，温度高于35度基本就会休眠了，此时盆土要保持干燥，每个月少量给水，并且遮阳，球松夏天比较怕热，不小心就容易干枯至死，休眠的时候植株顶端的叶片会慢慢合拢。入秋天气凉了以后，循序渐进给水，合拢的聚生叶片会慢慢打开形成一个一个的球形。冬季零下3度，需保持盆土干燥，冬季的休眠没有夏季明显。植株缺水看叶片就可以看出来的，叶片慢慢合拢无精打采就需要补水了。　　球松是制作微型盆栽很好的材料，一般的拼盘都可以用到，本身植株就不大，长的也像微型的松树，微加修整就是一个很好的盆景。风筝的球松养殖土用的是煤渣混合泥炭，土表铺的是河沙。浇水基本很随意的，不干不浇水。浇水必须浇透。　　球松用一般透气性能好的土壤均可种植，花盆不易太大，夏季气温在27℃以上呈半休眠状态，要控制浇水，见盆土充分干燥后再浇，并遮半荫。冬季在室内，最低温度在5℃以上，在阳光充足的条件下可继续。小松绿用扦插繁殖，极易成活，在春秋生长季，把充实的小枝掰下来，为一个插穗，插在盆土中，控制土壤的温度，放置在散射光较充足的地方，10天左右生根，成为新植株。', '　　　　球松常见的繁殖方式是扦插繁殖，以春、秋', 'http://img.boqiicdn.com/Data/BK/P/imagick36051447924403.jpg', 'http://www.boqii.com/entry/detail/2236.html', '');
INSERT INTO `plant_family` VALUES ('374', '姬胧月', 'Graptopetalum.paraguayense', '姬胧月', '粉莲、宝石花、初霜、缟瓣', '不容易死', '原产地墨西哥', 'http://www.boqii.com/entry/photo/2133/0,http://www.boqii.com/entry/photo/2133/5394', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '风车草属', '姬胧月锦', 'Graptopetalum.paraguayense', '', '　　 　　姬胧月为多年生草本植物，也为多肉植物，株形和石莲花属极为相似，但本属不是瓶状花或钟状花，而是星状花。花瓣被蜡，叶排成延长的莲座状，被白粉或叶尖有须。叶色朱红带褐色，叶呈瓜子型，叶末较尖，开黄色小花，星状。', '　　姬胧月和胧月非常像，也是胧月的杂交变种，和很多景天科多肉一样，姬胧月的栽培方法并不难。人工种植姬胧月2－4年换一次盆，可以促进植株生长，浇水则需注意一定要等配土干燥后才可浇水。　　冬季如果能够保持0度以上，都是可以给水的，0度以下就要断水，否则就容易冻伤烂根。冬季虽然寒冷，可也不是一个冬季都不给一点水，风筝会在适当的时候微微给点水在植株的根部，切勿喷雾或给大水，叶心水分停留太久，容易引起，天气好的时候，通风够，就可以用清水喷雾，清洗一下叶片上的灰尘，因为植株叶盘平滑也有微粉，不容易积水，所以不会影响美观，这样洗后才会让植株更加漂亮。春季温度上升后就可以慢慢恢复正常给水。　　姬胧月算是非常好养的一个，也容易群生，四季中除了夏季要注意适当遮阳，其他季节都可以全日照。土壤风筝用的是泥炭混合了颗粒的煤渣等，配土以透气为主，家庭养殖自然无法和相媲美，干透浇透就可以，姬胧月是一个生长非常强劲的品种，很多地方都有栽培，而且还可以露天养。', '　　　　姬胧月的繁殖课采用叶插法和砍头爆小侧芽，全年都可以进行，也可以播种。姬胧月的繁殖速度超快，特别是叶插，成功率几乎在100％，是新手叶插入门的首选', 'http://img.boqiicdn.com/Data/BK/P/imagick28031445418898.jpg', 'http://www.boqii.com/entry/detail/2133.html', '');
INSERT INTO `plant_family` VALUES ('375', '唐菖蒲', 'Gladiolus', '唐菖蒲', '菖兰、剑兰、扁竹莲、十样锦、十三太保', '不容易死', '', 'http://www.boqii.com/entry/photo/2367/0,http://www.boqii.com/entry/photo/2367/5049', '　', '被子植物门', '单子叶植物纲', '百合目', '鸢尾科', '唐菖蒲属', '唐菖蒲', 'Gladiolus gandavensis Vaniot Houtt', 'Gladiolus gandavensis', '　　 　　唐菖蒲为多年生草本，球茎扁圆球形，直径2.5－4.5cm，外包有棕色或黄棕色的膜质包被。叶基生或在花茎基部互生，剑形，长40－60cm，宽2－4cm，基部鞘状，顶端渐尖，嵌迭状排成2列，灰绿色，有数条纵脉及1条明显而突出的中脉。', '　　原种产于南非，矮生品种可盆栽观赏，也是现在非常重要的鲜材料，常被用于花篮、花束、瓶插等。人工栽培唐菖蒲需要根据其生长习性来布置环境，由于唐菖蒲为球茎花卉，所以盆栽需要注意土质及浇水等细节。　　唐菖蒲为喜光性长日照，忌寒冻，夏季喜凉爽气候，不耐过度炎热，球茎在4～5℃条件下即萌动；20～25℃生长最好。　　性喜肥沃深厚的砂质土壤，要求排水良好，不宜在黏重土壤易有水涝处栽种。在东北、华北地区夏季生长均较广州、为好。在上海冬季可在露地安全过冬，北方则需挖出球茎放于室内。　　唐菖蒲原产非洲热带与地中海地区。唐菖蒲为喜光性长日照植物，忌寒冻，夏季喜凉爽气候，不耐过度炎热，球茎在4～5℃条件下即萌动；20～25℃生长最好。性喜肥沃深厚的砂质土壤，要求排水良好，不宜在黏重土壤易有水涝处栽种。　　在东北、华北地区夏季生长均较广州、上海为好。在上海冬季可在露地安全过冬，北方则需挖出球茎放于室内越冬，阳性，喜通风好，忌闷热湿冷生长类型。', '　　唐菖蒲为鸢尾科唐菖蒲属多年生草本　　\n一、播种繁殖\n　　播种繁殖主要用于杂交育种和新　　\n二、分生繁殖\n　　生产上多采用此法。在唐菖蒲地上部分枯死后，掘出球茎，将大球茎附着的小球茎取下，进行分级，充分晾晒后贮藏于5－10℃的通风干燥处，第二年可条播种植，培育1－2年后即可开花。另外也可用切割球茎的方法繁殖，应选择生长健壮的大球茎，除去外面的皮膜，用　\n　三、组织培养\n　　可用休眠芽、腋芽、球茎切块作为外植体进行组织培养。', 'http://img.boqiicdn.com/Data/BK/P/imagick60801451295611.jpg', 'http://www.boqii.com/entry/detail/2367.html', '');
INSERT INTO `plant_family` VALUES ('376', '唐印', 'Kalanchoe thyrsifolia', '唐印', '牛舌洋吊钟', '不容易死', '原产南非开普省东部和德兰士瓦省。', 'http://www.boqii.com/entry/photo/2338/0,http://www.boqii.com/entry/photo/2338/5078', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '伽蓝菜属', '唐印', 'Kalanchoe thyrsifolia', 'Kalanchoe thyrsifolia', '　　 　　唐印为多年生肉质草本植物，茎粗壮，灰白色，多分枝，叶对生，排列紧密。叶片倒卵形，长10～15厘米，宽5～7厘米，全缘，先端钝圆。叶色淡绿或黄绿，被有浓厚的白粉，因此，看上去呈灰绿色，秋末至初春的冷凉', '　　唐印的栽培难度并不高，被引入我国的并不长，但是已经成为了很多多肉爱好者都非常喜爱的品种。现在唐印除了盆栽观赏外，还可以造型后制成或地载供园林部门布置，观赏效果也很不错。　　唐印需要阳光充足和凉爽、干燥的环境，耐半阴，怕水涝，忌闷热潮湿。具有冷凉，夏季高温休眠的习性。每年的9月至第二年的6月为植株的生长期（花友的环境不一样，生长期也有长短），若光照不足会使植株叶片徒长；而在阳光充足之处生长的植株，株型矮壮，叶片排列会相对紧凑。　　唐印生长期需保持土壤湿润，避免积水。土壤风筝就用了煤渣混合泥炭、少量珍珠岩，比例大概5：4：1，土表铺设了大颗粒的河沙。唐印能耐零下4℃左右的低温，是室内的温度，非露天，再低叶片的顶端生长点就会出现冻伤，干枯死亡，整个冬季基本断水，5度以下就要开始慢慢断水。夏季高温时整个植株生长缓慢或完全停止，这个时候一定要通风良好且适当遮光，避免曝晒，节制浇水，不能长期雨淋，以免植株。', '　　　　唐印的繁殖可在温暖的生长季节进行芽插、叶插或用带有叶片的茎段做插穗都可以，砍下的植株可以直接插在干的颗粒土中，发根后就可以少量给水，或将叶片或插穗稍微晾干1～2天后，待伤口愈合，即可插于粗砂或真珠石和', 'http://img.boqiicdn.com/Data/BK/P/imagick35901450429725.jpg', 'http://www.boqii.com/entry/detail/2338.html', '');
INSERT INTO `plant_family` VALUES ('377', '藏红花', 'Crocus sativus L.', '藏红花', '番红花、西红花', '藏红花为多年生草本', '北京、上海、河北等', 'http://www.boqii.com/entry/photo/1995/0,http://www.boqii.com/entry/photo/1995/3256', '植物　', '被子植物门', '单子植物纲', '百合目', '鸢尾科', '番红花属', '番红花', 'Crocus sativus L.', '', '　　 　　藏红花为多年生草本。地下鳞茎呈球状，外被褐色膜质鳞叶。叶9～15片，白鳞茎生出，无柄，叶片窄长线形，长15～20厘米，宽2～3厘米，叶缘反卷，具细毛，基部由4～5片广阔鳞片包围。花顶生，直径2.5～3厘米；花被6片，倒卵圆形，淡紫色，花筒长4～6厘米，细管状；雄蕊3枚，花药大，基部箭形；雌蕊3，心皮合生，子房下位，花柱细长，黄色，顶端三深裂，伸出花筒外部，下垂，深红色，柱头顶端略膨大，有一开口呈漏斗状。蒴果，长形，具三钝棱，长约3厘米，宽约1.5厘米，当果实成熟时始伸达地上。种子多数，圆球形，种皮革质。花期11月上旬至中旬。', '　　', '　　藏红花又名　　1、分球繁殖。一般在8～9月份进行，成熟球茎有多个主、侧芽，花后从叶丛基部膨大形成新球茎，夏季地上部枯萎后，挖出球茎，分级，阴干，贮藏。而种植　　2、播种繁殖。由于番红花不易结籽，需通过人工授粉后才能得到种子。待种子成熟后，随收随播种于露地苗床或盆内。种子播种', 'http://img.boqiicdn.com/Data/BK/P/imagick741441100314.jpg', 'http://www.boqii.com/entry/detail/1995.html', '');
INSERT INTO `plant_family` VALUES ('378', '邹菊', 'Bellis perennis Linn.', '邹菊', '春菊、马兰头花', '不容易死', '世界各地', 'http://www.boqii.com/entry/photo/1909/0,http://www.boqii.com/entry/photo/1909/5620', '', '', '', '', '', '', '', '', '', ' 　　邹菊又叫春菊、太阳菊，原产地欧洲，早年人们视邹菊为杂草，后来被人类发觉，是一种多年生草本植物，花期在春天，目前是意大利的国花。在中国邹菊的栽培率一直有增无减，那么花友们知道邹菊的繁殖方法吗？　　雏菊性喜冷凉气候， 忌炎热。喜光， 又耐半阴，对栽培地土壤要求不严格。种子发芽适温22-28℃，生育适温20-25℃。西南地区适宜种植中、小花单瓣或半重瓣　　可采用分株、扦插、嫁接、播种等多种方法。嫁接法和播种法，技术要求条件高，繁殖过程比较繁琐，没有高超的削切、嫁接技巧及良种的　　南方多在秋季8-9月份播种，也可春播，但往往夏季生长不良。北方多在春季播种，也可秋播，但在冬季花苗需移入温室进行栽培管理。由于雏菊的种子比较小，通常采取撒播的方式。但播种苗往往不能保持母株的特征。播种前施足腐熟的有机肥为基肥，并深翻细耙，做成平畦。用细沙混匀种子撒播，上覆盖细土厚0.5厘米左右，播种后覆盖遮阳网并浇透水。播后保持温度在28℃左右，在早春阴冷多雨时覆盖塑料薄膜，以保持土壤湿度和温度。浇水宜细喷，以防土壤表层板结。约10天后小苗出土，揭去遮阳网或塑料薄膜，在幼苗具2-3片时即可移栽到大田。　　由于实生苗变异较大，对于一些优良品种可采用分株法繁殖，但生长势不如实生苗，且结实差。在3月中下旬可将老茬菊花菜挖出，露出根颈部，将已有根系的侧芽连同老根切下，移植到大田中。分株繁殖在萌发新梢时进行较适宜。 　　在整个生长季节均可进行扦插繁殖，以4-6月扦插的成活率最高。苗床最好用新土混入经堆沤腐熟的有机肥。剪取具3-5个节位、长8-10厘米的枝条，摘除基部叶片，入土深度为插条长的1/3-1/2。扦插后保持功床湿润，忌涝渍，高温季节需遮阴，而在温度较低时可搭塑料薄膜拱棚保温保湿。一般15天后可移植到大田。　　雏菊长势强，易栽培。雏菊花梗高矮适中，花朵整齐，色彩明媚素净，可做盆植美化庭院阳台，也可用作园林观赏，盆栽、花境、切花等。花期长，耐寒能力强，是早春地被　　邹菊它不仅仅只有观赏作用哦，在一些中草药里也常见到它，具有很高的药用价值，但是家庭栽培的不可随便服用，这得经专业的操作程序才可入药。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick52141428056523.jpg', 'http://www.boqii.com/entry/detail/1909.html', '');
INSERT INTO `plant_family` VALUES ('379', '马蹄莲', 'Lily of the Nile ， Calla lily', '马蹄莲', '慈姑花、水芋、野芋、慈菇花、海芋百合、花芋', '不容易死', '原产埃及、南部非洲，世界各地广泛栽培，中国各地温室均有栽培', 'http://www.boqii.com/entry/photo/1927/0,http://www.boqii.com/entry/photo/1927/5602', '', '', '', '', '', '', '', '', '', '　　 　　马蹄莲为多年生粗壮草本，具块茎。叶基生，叶柄长0.4－1（－1.5）米，下部具鞘；叶片较厚，绿色，心状箭形或箭形，先端锐尖、渐尖或具尾状尖头，基部心形或戟形，全缘，长15－45厘米，宽10－25厘米，无斑块，后裂片长6－7厘米。花序柄长40－50厘米，光滑。　　　　　　　　　　　　　　　　　　　　　　　', '　　马蹄莲又名水芋、慈菇花等，由于马蹄莲的花苞典雅并且叶片也是漂亮的翠绿缀以白斑，所以深受花友们的喜爱。马蹄莲是冬季以及春节期间非常重要的切花品种。现在，马蹄莲比较常见的栽培方式就是地栽以及盆栽两种。', '　　马蹄莲为球根花卉，也是近几年非常流行的花卉品种之一，在花卉市场上，马蹄莲主要用于　　马蹄莲繁殖以分球繁殖为主。植株进入休眠期后，剥下块茎四周的小球，另行栽植。也可播种繁殖，种子成熟后即行盆播。发芽适温20℃左右。　　栽培马蹄莲通常在秋后植球。床植行距25厘米，株距10厘米。用肥沃而略带粘质的土壤，如：可用园土2份、砻糠灰1份、再稍加些骨粉或厩肥；也可用细碎塘泥2份、腐叶土（或堆肥）1份、加入适量过磷酸钙和腐熟的牛粪配制的土。植后覆土3厘米－4厘米厚，20天左右即可出苗。马蹄莲生长期间喜水分充足，要经常向叶面、地面洒水，并注意叶面清洁。每半月追施液肥1次。施肥后还要立即用清水冲洗，以防意外，霜前移入温室，室温保持10℃以上。在　　马蹄莲适宜8月下旬至9月上旬栽植，地栽是用作切花', 'http://img.boqiicdn.com/Data/BK/P/imagick40571439200220.jpg', 'http://www.boqii.com/entry/detail/1927.html', '');
INSERT INTO `plant_family` VALUES ('380', '沙漠玫瑰', 'Adenium obesum', '沙漠玫瑰', '天宝花', '不容易死', '原产非洲的肯尼亚、坦桑尼亚', 'http://www.boqii.com/entry/photo/2060/0,http://www.boqii.com/entry/photo/2060/5467', '　　', '被子植物门（Angiospermae）', '双子叶植物纲', '龙胆目', '()科', '天宝花属', '沙漠玫瑰', 'Adenium obesum', 'Adenium obesum', '　　沙漠 　　沙漠玫瑰为多肉灌木或小乔木，高达4.5m；树干肿胀。单叶互生，集生枝端，倒卵形至椭圆形，长达15cm，全缘，先端钝而具短尖，肉质，近无柄。花冠漏斗状，外面有短柔毛，5裂，径约5cm，外缘红色至粉红色，中部色浅，裂片边缘波状；顶生伞房花序。', '　　沙漠)在欧美地区常被称为沙漠蔷薇或沙漠杜鹃，在原产地可以长至2米高，值得注意的是，全株有毒，误食茎叶或乳汁的话，会引起心跳加速等。　　在栽培中，沙漠玫瑰枝条易徒长，影响株形美观，可用嫁接的方法改变其株形。可在植株一定高度按一定形状将枝条全部剪下，再取剪下的枝条的上端，用劈接法进行嫁接。经嫁接的植株株形美观，开花后则花枝紧凑，观赏性强。　　沙漠玫瑰比较耐干旱，每次浇水量不可过多，如果水分较多，则很容易引起根部腐烂，同时枝条也徒长，修剪起来比较麻烦。夏季高温时，可根据土壤状况来浇水。一般两三天浇水一次，盆内不能积水。冬季气温降低，沙漠玫瑰也随之进入半休眠期，这时要适当的控制浇水，注意保持土壤的干燥，一周浇水一次就可以了。适当干旱非常有利于沙漠玫瑰的生长。（冬季沙漠玫瑰进入休眠期时叶片会逐渐脱落，这是正常落叶，不必为此紧张。）　　沙漠玫瑰喜干燥、阳光充足的环境，耐干旱但不耐水湿，耐炎热但不耐寒。生长适温为20～30℃。家庭栽培时，宜放置阳光或散射光充足的地方，宜用肥沃、疏松及排水良好富含钙质的砂壤土。5～12月是它的花期，花有红、玫红、粉红、白等色。南方温室栽培较易结实。　　沙漠玫瑰比较喜欢磷钾肥，平时一个月左右补充一次。夏季生长旺盛期则需要肥水充足，这样开出的花才能繁茂、鲜艳。另外结合每年一次的换盆，还可以在盆内适当施加一些长效的基肥，如腐熟的豆饼、骨粉等。', '　　沙漠　　\n扦插\n　　以夏季最好，选取1－2年生枝条，以顶端枝最好，剪成10厘米长，待切口晾干后插于沙床，插后约3－4周生根。嫁接，用夹竹桃作砧木，在夏季采用劈接法，成活后植株　　无论花、叶、茎，还是它的形，均优雅别致，自然大方，别具一格，特别适合家庭室内及阳台装饰。盛花时，叶片大部分脱落，花满枝头，姿态优美。栽培中，沙漠玫瑰枝条易徒长，影响株形美观，可用嫁接的方法改变其株形。可在植株一定高度按一定形状将枝条全部剪下，再取剪下的枝条的上端，用劈接法进行嫁接。经嫁接　\n　播种\n　　以春季为佳，用点播法，以便于出苗后管理。播种前，一定要对基质进行', 'http://img.boqiicdn.com/Data/BK/P/imagick75331442915091.jpg', 'http://www.boqii.com/entry/detail/2060.html', '');
INSERT INTO `plant_family` VALUES ('381', '风兰', 'Neofinetia falcata （Thunb. ex A. Murray） H. H. Hu', '风兰', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2366/0,http://www.boqii.com/entry/photo/2366/5050', '植物　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '风兰属', '风兰', 'Neofinetia falcata （Thunb. ex A. Murray） H. H. Hu', '', '　　 　　风兰植株高8－10厘米。茎长1－4厘米，稍扁，被叶鞘所包。叶厚革质，狭长圆状镰刀形，长5－12厘米，宽7－10毫米，先端近锐尖，基部具彼此套叠的V字形鞘。总状花序长约1厘米，具2－3 （－5） 朵花；花苞片卵状披针形，长7－9毫米，先端渐尖；花梗和子房长2.8－5厘米，具5条肋；花白色，芳香；中萼片近倒卵形，长8－10毫米，宽2.5－4毫米，先端钝，具3条脉；侧萼片向前叉开，与中萼片相似而等大，上半部向外弯，背面中肋近先端处龙骨状隆起；', '　　花型优雅端庄，开花后花香浓郁，具有较高的观赏价值，是很多兰花爱好者都非常的观赏花卉。人工栽培风兰需要注意为其准备一个和比较符合的环境，才能保证风兰开出漂亮的花朵。　　　水分调节合不合适基本就能决定风兰能否养殖成功。大家往往问风兰用什么肥料好，事实上风兰不怎么需要施肥。当然，若是合适的施少量肥总比不施好，需注意施肥过量会损伤风兰。　　给风兰浇水时，不可直接用自来水，可用事先接好的水浇花。春、秋建议清晨喷水，以防止晚上气温下降后，仍有剩余水分。夏季同样不可浇太多水，如果盆里留有水分，水会腐臭，使盆内缺氧，容易引起根腐病。但是如果保持干燥状态，兰花会显得很柔弱。所以，需要注意的是一定要做好水分调节工作。　　　不同风兰所需的受光量也不同。例如金楼阁、金孔雀等品种，属于特殊的叶艺品种，它们可以通过受光量改变上一年度长出的叶子颜色。这就是风兰特有的叶艺。日照强烈的话，逐渐会变成黄色，需要调节受光量。　　而虎斑和黄色品种受到强烈的日照光后，黄色才会更明显、更漂亮。即，对虎皮斑而言，今年的日照会一直影响到明年；弁庆丸等无地、叶艺品种，适合在弱光下栽培，这样不仅好养，绿色会更明显、更漂亮。', '　　　　风兰在春秋两季均可进行，一般每隔三年分株一次。凡植株　　风兰分株前要减少灌水，使盆土较于。分株后上盆时，先以碎瓦片覆在盆底孔上，再铺上粗石子，占盆深度1／5至1／4，再放粗粒土及少量细土，然后用富含腐殖质的沙质壤土栽植。　　风兰栽植深度以将假球茎刚刚埋入土中力度，盆边缘留2厘米沿口，上铺翠云草或细石子，最后浇透水，置阴处10－15天，保持土壤潮湿，逐渐减少浇水，进行正常', 'http://img.boqiicdn.com/Data/BK/P/imagick27111451295168.jpg', 'http://www.boqii.com/entry/detail/2366.html', '');
INSERT INTO `plant_family` VALUES ('382', '鸡蛋花', 'Plumeria rubra L. cv. Acutifolia', '鸡蛋花', '缅栀子、蛋黄花', '不容易死', '中国、墨西哥；现广植于亚洲热带及亚热带地区', 'http://www.boqii.com/entry/photo/1935/0,http://www.boqii.com/entry/photo/1935/5594', '', '', '', '', '', '', '', '', '', '　　 　　鸡蛋花属落叶灌木或小乔木。小枝肥厚多肉。叶大，厚纸质，多聚生于枝顶，叶脉在近叶缘处连成一边脉。花数朵聚生于枝顶，花冠筒状，径约5～6cm，5裂。外面乳白色，中心鲜黄色，极芳香。花期5～10月。　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　鸡蛋花的耐寒性较差，所以在我国的一些比较高的地区鸡蛋花比较常见，鸡蛋花最适宜的温度为20－26℃，可以盆栽也可以种植在中，鸡蛋花的观赏性比较强，深受人们的喜爱。那么鸡蛋花究竟应该如何栽培呢？　　鸡蛋花对土壤要求不严，宜种植在含腐殖质较多的疏松土壤中。栽种时可略露根上盆，种好后设置于室内，1周后见弱光，再经半月可放在阳光充足处。鸡蛋花生长迅速，需每年春天换盆1次，一般换入口径30厘米的花盆中。盆土可按园土4份、马粪土4份和河沙2份混合调制，每盆还加放100克饼肥或酱渣，50克过磷酸钙或骨粉。换盆植后浇透水，谷雨前后移置室外向阳处。　　鸡蛋花喜湿润，亦耐旱，但怕涝。浇水要适度，掌握不干不浇，见干即浇，浇必浇透，不可渍水的原则。春秋季间隔1至2天见土干浇一次水。夏季晴天每日早上浇一次，傍晚如土干再浇一次，雨季要注意倒掉盆中积水，防烂根。冬季十天或半月浇一次，保持盆土微润不干即可。　　鸡蛋花是强阳性花卉，日照越充足，生长越繁茂，花多而香。除上盆或翻盆换土后需要荫蔽7天至10天外，其余时间都宜置于阳光充足处。因其原产美洲热带地区，故不耐寒，在温带栽培冬季落叶是其耐寒性差的表现，宜入室。在最低温度降至10℃前，移入室内置于阳光充足处，保持室温10℃至15℃。应放置远离电视辐射和空调暖风的地方，防止掉叶；如低于8℃或是通风不良，也会掉叶，只要保持5℃以上就不会冻死，翌春会发芽长叶。　　6－11月每隔10天施1次腐熟液肥，浓度为15％。南方鸡蛋花在露地种植，冬季落叶，翌年春再生新叶。北方盆栽宜在10月中下旬移入室内南窗处，注意通风见光。室温宜在10℃以上，低温和室内通风不良，会使植株落叶，室内浇水每隔两周浇1次。　　鸡蛋花喜肥，上盆或翻盆换土时，宜在土中加20至30克骨粉，50至80克过磷酸钙。5月至10月，10天至15天施一次淡薄的腐熟有机肥或氮磷钾复合肥，忌单施氮肥，防徒长，冬季不施肥。', '　　　　鸡蛋花枝条扦插容易成活，主要通过扦插繁殖。在热带亚热带适宜露地栽培的地方，一年四季均可以进行扦插。露天栽植地大部分', 'http://img.boqiicdn.com/Data/BK/P/imagick91361439373140.jpg', 'http://www.boqii.com/entry/detail/1935.html', '');
INSERT INTO `plant_family` VALUES ('383', '悬铃花', 'Malvaviscus Rrboreus Cav.', '悬铃花', '垂花悬铃花、小悬铃花、大红袍、粉花悬铃花、卷瓣朱槿、南美朱槿', '不容易死', '中国、墨西哥、秘鲁和巴西，热带及亚热带地区', 'http://www.boqii.com/entry/photo/2300/0,http://www.boqii.com/entry/photo/2300/5224', '植物　', '被子植物门', '双子叶植物纲', '锦葵目', '锦葵科', '悬铃花属', '', 'Malvaviscus Rrboreus Cav.', 'Malvaviscus Rrboreus', '　　 　　悬铃花的叶片较为狭昌浓绿；花朵不若其他朱槿类会完全展开，鲜红的花瓣螺旋卷屈，呈吊钟状，', '　　的外形和朱槿略为相似，但是花朵不像朱槿类会完全展开。悬铃花为常绿灌木，花朵向下悬垂是最大的。人工栽种的难度并不高，小编就为你介绍一下悬铃木的栽培过程中需要注意哪些。　　悬铃花在每年春季换盆，增添腐叶土，盆土宜用含腐殖质丰富的肥沃、疏松和排水良好的微酸性沙质土壤。日照充足，植株较快，茎叶较繁密，开花亦较多；荫蔽处开花不良，结蕾易脱落，或花朵变小，花色暗淡。浇水避免浇到花瓣，以免产生白斑。栽培中当分枝稀少时，要对枝条进行修剪，使其多发侧枝，剪去过长、过乱的枝条及弱枝、病枝，以促发新枝，从而达到多萌发分枝多开花的目的。成株每年春季定期修剪整枝一次，植株老化需强剪，促使枝叶繁密。剪枝直接扦插于篱地，即能发根成长。　　盆栽用20cm盆，每盆栽1株。花坛、绿篱种植株行距25＊30cm。　　生长期每半月施肥1次。盛夏土壤保持湿润，多见阳光，但要防烈日曝晒，早晚在叶面喷水。秋季天气转凉时，应搬入室内，停止施肥，控制浇水，保持通风。', '　　　　悬铃花可在夏、秋　　', 'http://img.boqiicdn.com/Data/BK/P/imagick27301449568506.jpg', 'http://www.boqii.com/entry/detail/2300.html', '');
INSERT INTO `plant_family` VALUES ('384', '熊童子', 'Cotyledon tomentosa', '熊童子', '', '不容易死', '非洲的纳米比亚', 'http://www.boqii.com/entry/photo/1962/0,http://www.boqii.com/entry/photo/1962/5565', '', '', '', '', '', '', '', '', '', '　　 　　熊童子为多年生肉质草本植物，植株多分枝，呈小灌木状，茎深褐色，肥厚的肉质叶交互对生，叶片卵形，长2厘米至3厘米，宽1厘米至2厘米，顶部叶缘有缺刻，叶表绿色，密生白色短毛。　　　　　　　　　　　', '　　的外形非常漂亮，很多多肉爱好者总是会栽培一盆熊童子。但是熊童子的栽培难度并没有想象中那么简单，特别是在炎热的夏季，熊童子的率是非常高的。　　冬季严格控制浇水，保持盆土干燥，能耐5℃的低温。栽培中要避免长期雨淋，也不要经常向植株喷水，否则水滴滞留在叶片的绒毛中，会形成难看的水渍斑，影响观赏。　　熊童子株形不是太大，分枝繁多，可以剪侧枝扦插，也可以叶片繁殖。叶片就平铺在土表，阴凉通风就可以，不用理会，慢慢会长出新叶片。　　长根就可以给水了。枝条扦插更加简单，把的老枝条扦插在微微湿润的沙土就可以。阴凉通风15到20天基本会长根，扦插应该选择春季和秋季，叶片繁殖除了，其他时候都可以。　　要注意每1～2年换盆一次，宜在春季进行，盆土要求中等肥力、且排水性良好的沙质土壤，可用粗砂或、园土、腐叶土各1份，混匀后配制使用。', '　　熊童子是比较常见的多肉　　熊童子的繁殖最好选择的春秋两季进行，气温大约在23度左右，这时熊童子停止休眠开始　　将晾干伤口的枝条插入土壤中，放在阴凉通风处等待发根，因为这时的枝条没有根，暴晒会造成植物叶片水份大量蒸发，造成植株干枯。枝条扦插的土壤最好选择　　等枝条出根后就可正常的进行浇水', 'http://img.boqiicdn.com/Data/BK/P/imagick82501440063226.jpg', 'http://www.boqii.com/entry/detail/1962.html', '');
INSERT INTO `plant_family` VALUES ('385', '栀子花', 'Cape Jasmine', '栀子', '', '不容易死', '产于长江流域，中国中部及中南部都有分布。', 'http://www.boqii.com/entry/photo/1918/0,http://www.boqii.com/entry/photo/1918/5611', '', '', '', '', '', '', '', '', '', '　　 　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　很多花友对于栀子花都清幽，由于栀子花在冬季就开始孕育花苞，但是要到夏季才开始开花，这种隐忍的精神也是很多花友非常喜欢的。栀子花花香浓郁，在家中种上一盆还能够改善家居环境，可以说作用非常多。　　　适宜的pH值为5至6。栽培用土可选腐叶土、泥炭土或沤制锯屑加一半的园土，忌用陈墙土和煤渣　　　　盆土表面见干就浇水，晚上可用喷壶向叶面淋水浇施。过旺、节间较长的，晚上不浇水，早上太阳出来再浇水。　　　在土中可加入3％腐熟饼肥作基肥。生长季节用饼肥加硫酸亚铁沤制的矾肥水每周浇一次，现蕾期浇1次至2次0.1％磷酸二氢钾水溶液，酷暑期气温35℃以上和秋季15℃以下时停肥。　　　栀子喜光，长期在半阴处也能生长，但要保持全日60％的光照，才能满足其生长的需求。　　　　栀子花在北方的严冬后根系会受损害，春季才恢复。所以要将盆花用泡沫塑料等保温材料将花盆包裹好，保护好根系，放在背风向阳处，春季恢复快，开花早。　　　　家庭盆栽当冠幅达到28厘米左右时，换盆土，如果是换盆的话要连土坨栽入新盆。于春季3月换土较好。　　　　根据树形选留三个主枝，要随时剪除根蘖萌出的其他枝条。切记栀子花春季不可短截枝顶，否则当年不会开花。', '　　　\n　一、播种繁殖\n　　一般选择饱满、色深红的成熟果实，连壳晒或晾干作种，播种前，用剪刀将种子果皮剪开，挖出种子，在热水中搓散，去掉浮种或杂质，然后将下沉的充实种子捞出，摊于竹席上，置通风处晾去过多的水分。一般选用选向阳山坡或土坊，土层深厚疏松肥沃的砂质壤土播种，可利用田边地角种植，或与豆科　　栀子花可春播或秋播，一般多在春季进行，春播在雨水前后下种，秋播在秋分前后、播时将种子拌上火灰均匀的播在播种沟内，然后用细土或火土覆盖平播种沟，盖草淋水，经常保持土壤湿润，以利出苗，每亩用种子4－6斤。出苗后要注意及时去掉盖草，在幼苗期应经常除草，注意不要伤幼苗的根，除草后均需要追淡人粪尿水，育苗一年后即可移栽。如运输较远，宜用黄泥浆浆根，盖草保湿，每穴种一株，盖土、压实、淋水即可。定植后每年春夏季各中耕除草追肥一次，施入人畜粪、厩肥、堆肥、饼肥等均可。夏季开花前，施磷钾含量较多的　\n　二、扦插繁殖\n　　可分为春插和秋插。春插于2月中下旬进行；秋插于9月下旬至10月下旬进行，北方和南方稍有区别，但多以夏秋之间成活率最高。插穗选用　　一般1个月可生根，在80％相对湿度条件下，温度20～24℃条件下约15天即可。若用20＊10的－6次方～50＊10的－6次方吲哚丁酸浸泡24小时，效果更佳。待生根小苗开始生长时移栽或单株上盆，2年后可开花。南方还有采用水插法繁殖的，即将插穗插在用苇秆编织的圆盘上，任其漂浮在水面上，使其下部在水中生根，再移植栽培。　\n　三、压条法\n　　一般在4月清明前后或梅雨季节进行，4月份从3年生母株上选取1年生健壮枝条，长25～30厘米进行压条，将其拉到地面，刻伤枝条上的入土部位，如能在刻伤部位蘸上200ppm粉剂案乙酸，再盖上土压实，则更容易生根。如有三叉枝，则可在叉口处，一次可得三苗。一般经20～30天即可生根，在6月生根后可与母株分离，至次春可带土分栽或单株上盆。移植苗木或盆栽以春季为好，在梅雨季节进行，需带土球。生长期保持土壤湿润，花期和盛夏要多浇水。每月施肥1次，开花前增施磷钾肥1次。翌年早春修剪整形，并及时剪去枯枝和徒长枝。', 'http://img.boqiicdn.com/Data/BK/P/imagick31381438854285.jpg', 'http://www.boqii.com/entry/detail/1918.html', '');
INSERT INTO `plant_family` VALUES ('386', '费菜', 'Sedum aizoon L.', '费菜', '土三七、四季还阳、景天三七、长生景天、金不换、田三七', '不容易死', '', 'http://www.boqii.com/entry/photo/2241/0,http://www.boqii.com/entry/photo/2241/5285', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '景天属', '费菜', 'Sedum aizoon L.', 'Sedum aizoon', '　　费菜为景天科景天属多年生草本植物，由于费菜中含有生物碱、果糖、维生素等 　　费菜为多年生草本。根状茎短，粗茎高20－50厘米，有1－3条茎，直立，无毛，不分枝。叶互生，狭披针形、椭圆状披针形至卵状倒披针形，长3.5－8厘米，宽1.2－2厘米，先端渐尖，基部楔形，边缘有不整齐的锯齿；叶坚实，近革质。', '　　费菜又名景天三七，含有丰富的营养，长期食用对、高血压、高血脂都有很好的疗效。由于费菜的栽培难度不高，并且很受消费者的青睐，所以，经济效益也十分可观。那么费菜在栽培时应该注意哪些问题呢？　　　费菜喜温暖气候，不耐霜冻，在炎夏的烈日照射下生长减慢。早春、深秋和冬季可采取日光温室或大棚加小拱棚加草苫覆盖栽培，白天温度保持在15～30℃，超过32℃则要通风降温，夜间温度保持在5℃以上，相对湿度控制在65％～75％。一般10月下旬气温明显下降时盖棚膜，此时气温不是很低，白天可以大通风，夜间关闭风口。12月以后，夜间加盖草苫保温。立春之后，随外界气温升高逐渐加大通风量，4月上旬撤除草苫。夏季和早秋季主要是覆盖遮阳网防高温、防暴雨，这样既可增加产量又可提高品质。　　　尽管费菜耐旱性很强，但充足的水分供应有利于茎叶生长、提高产量和改进品质。定植后浇透水，以后经常保持畦面湿润。浇水要遵循“见干见湿”的原则，一般在早春及冬季低温季节掌握“不旱不浇、浇小水”的原则，结合浇水少量冲施速效肥。高温干旱期要勤灌水，汛期或大雨后及时排涝，沟中不能积水，以免造成烂根。在低温期，保持土壤湿润即可，切勿过湿，更不能积水，否则易引起烂根。定植后15天左右应追施提苗肥，一般667平方米施尿素5～10公斤，以促进多分枝。费菜是多次采收茎叶的蔬菜，最好每采收一次便追一次肥、浇一次水，每次667平方米追施尿素10公斤或有机复合肥15公斤。　　　　定植当年，经常中耕松土能促进费菜早期生长，提高当年产量。每次浇水过后或是大雨过后，都要进行中耕，铲除杂草，以促进植株旺盛生长。', '　　人工繁殖　　\n一、种子繁殖\n　　一般在春季3月中下旬气温稳定在10℃以上时，采用大棚播种育苗。播种前育苗畦667平方米施腐熟有机肥3000公斤，然后做好育苗畦，畦面宽1.2米。苗床浇透底水，趁湿播撒种子，之后覆细土0.2～0.5厘米，播后注意保温、保湿，白天气温保持在25～30℃，达到32℃时要进行通风降温，播后8～10天即可出苗。当苗高5厘米时，结合中耕除草，间去瘦弱苗，保持苗间距2～3厘米；苗期适量浇水，经常保持畦面湿润。在苗龄100天左右、苗高10～15厘米、真叶5～6片时，即可定植大田。设施栽培的养心菜因连续采收嫩茎叶，所以不开花。生产上一般不采用种子繁殖。　　\n二、分株繁殖\n　　分株繁殖一般在3月下旬进行。将费菜连根挖起，选健壮植株进行分株，将其分切成数株，切下的每一段根尽量多带根芽，以缩短缓苗时间，然后定植于苗床或定植穴内，勤浇水保持湿润。分株繁殖成活率高，方法简单，但繁殖系数低，适合小面积生产繁殖。　\n　三、扦插繁殖\n　　费菜分蘖力强，茎为肉质、丛生，肉质根肥大，株高25～40厘米。费菜扦插繁殖技术易操作，不仅成活率高，而且秧苗　　1、扦插繁殖时间。春、秋季　　2、种株选择。扦插繁殖时应选择无病虫害、具有一定成熟度的生长健壮的枝条，不能选过嫩或过老的枝条扦插。　　3、苗床准备。费菜一般用苗床扦插，成活后再移栽到大田，这样既便于苗期　　4、种株处理。选取中上部的充实节段作插穗，每个插穗上留2～4节，长约10厘米，插条上端留2～3片叶，下端叶片剪除，扦插于事先整好的苗床上。为了提高扦插成活率，扦插前将选好的枝条50根扎成一把，然后将基部浸泡于浓度为50毫克／公斤的生根粉溶液中12小时，或在浓度20毫克／公斤的萘乙酸溶液中浸泡15～20分钟，或在浓度为15～30毫克／公斤的吲哚丁酸溶液中浸泡15～20分钟。　　5、扦插。在育苗畦上按10厘米行距开扦插沟，沟深4～5厘米，每畦扦插10行，按株距5厘米将插穗苗插于苗床扦插沟内，入土深度以3～5厘米为宜。　　6、扦插苗床管理。插穗苗扦插后，要立即浇水，并注意保温、保湿；春季扦插繁殖应加盖小拱棚保温、保湿，白天温度保持在20～30℃；夏、秋季繁殖，因气温高、雨水多、湿度大，应覆盖遮阳网以挡雨遮阳。', 'http://img.boqiicdn.com/Data/BK/P/imagick34051448010794.jpg', 'http://www.boqii.com/entry/detail/2241.html', '');
INSERT INTO `plant_family` VALUES ('387', '水仙花', 'Narcissus', '水仙', '凌波仙子、雪中花、中国水仙、天蒜等', '不容易死', '', 'http://www.boqii.com/entry/photo/1902/0,http://www.boqii.com/entry/photo/1902/5627', '', '', '', '', '', '', '', '', '', '　　水仙花是中国的十大名花之一，它的的根茎部很壮实，与风信子、洋葱一般相似，它对生活环境要求不高，很适合新手花友养殖，可养殖在客厅、阳台、书房、闺房等地，下面我们来了解下水仙花的繁殖方法。　　水仙为秋植球根类温室花卉，喜阳光充足，生命力顽强，能耐半阴，不耐寒。7-8月份落叶休眠，在休眠期鳞茎的生长点部分进行花芽分化，具秋冬生长，早春开花，夏季休眠的生理特性。水仙喜光、喜水、喜肥，适于温暖、湿润的气候条件，喜肥沃的砂质土壤。生长前期喜凉爽、中期稍耐寒、后期喜温暖。因此要求冬季无严寒夏季无酷暑，春秋季多雨的气候环境。　　白天水仙花盆要放置在阳光充足的向阳处给予充足的光照。因为植物需要通过叶绿素经过光合作用提供养分 这样才可以使水仙花叶片宽厚、挺拔，叶色鲜绿，花香扑鼻。反之，则叶片高瘦、疲软，叶色枯黄，甚至不开花。以疏松肥沃、土层深厚的冲积沙壤土为最宜，pH在5-7.5时均宜生长。　　这是最普通常用的一种繁殖方法。储球着生在鳞茎球外的两侧，仅基部与母球相连，很容易自行脱离母体，秋季将其与母球分离，单独种植，次年产生新球。　　侧芽是包在鳞茎球内部的芽。只在进行球根阉割时，才随挖出的碎鳞片一起脱离母体，拣出白芽，秋季撒播在苗床上，翌年产生新球。　　一个鳞茎球内包含着很多侧芽，有明显可见的，有隐而不见的。但其基本规律是闲两张鳞片1个芽。用带有两个鳞片的鳞茎盘作繁殖材料就叫双鳞片繁殖。　　其方法是把鳞茎先放在低温4-10℃处4-8周，然后在常温中把鳞茎盘切小，使每块带有两个鳞片，并将鳞片上端切除留下2厘米作繁殖材料，然后用塑料袋盛含水50%的　　用MS培养基，每升附加30克蔗糖与5克的活性炭，用芽尖作外植体，或　　很受大众欢迎的水仙花，它不在乎生命短暂，不怕孤独终老，不畏惧冰雪严寒，始终洁身自爱，带给人间的是一份绿意与正能量。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick68511428055718.jpg', 'http://www.boqii.com/entry/detail/1902.html', '');
INSERT INTO `plant_family` VALUES ('388', '梅花', 'Armeniaca mume', '梅花', '酸梅、黄仔、合汉梅、白梅花、绿萼梅、绿梅花', '不容易死', '江浙一带', 'http://www.boqii.com/entry/photo/1914/0,http://www.boqii.com/entry/photo/1914/5615', '', '', '', '', '', '', '', '', '', '　　 　　　　　　　　　　　　　　　　　　　　　　　', '　　可以说我我国文化的历史见证，繁多的梅花都非常受人欢迎。随着人们对于梅花的了解，现在不但可以在园艺绿化中看到梅花的身影，还能够做成盆栽放在家中欣赏。那么梅花盆栽应该注意哪些方法呢？　　梅花除大树地栽以外，通常进行盆栽，培养盆景，更可养成苍老梅桩。梅花有一个特点，越是枝干枯老越显出苍劲奇观。盆栽梅花的养护方法，不同于其他盆栽，应按照它的特点进行栽培管理。开花后，立即进行修剪整形，将开过花的枝条，留下2～3个芽，其余的除去，并将剪后的梅桩放在日光下晒5～7天，特别需要注意曝晒根部，晒后上盆，上盆时包土坨部分在稀人粪尿中蘸一下再栽。　　盆土的配制，以1／3的谷糠灰与2／3的河泥相混合，加入人粪尿拌匀，置阳光下曝晒后，过筛待用。盆底垫瓦片、石块，以利排水，然后装进较粗粒的土壤，再种下梅桩，埋土压实根部。　　上盆时，不宜浇水；3～4天后，浇水一次；7～10天后，每天浇水一次；成活后，在5～8月每天浇水1～2次。土壤不宜过湿，切忌溃水。　　梅花喜肥沃，在枝叶生长期，以施氮肥为好。8～9月，宜施完全肥料，10月以后，多施磷肥，每隔半月集中施入根部，以利开花。　　家庭盆栽梅花并不困难，但要使梅花年年花繁色艳，则须掌握以下几点养护技巧。　　1、放置场所。梅花喜阳，所以一定要放置在阳光充足、空气流通的地方。　　2、浇水。梅花很怕积水，所以要根据天气变化和生长情况灵活掌握浇水量。通常情况下以保持盆土湿润为原则，不干不浇。　　3、施肥。梅花喜肥，每年花谢后盆底应放入有机肥。在生长期可每隔半个月施薄肥一次，促其生长强壮。在花芽形成前，最好多施磷肥。　　4、修剪。梅花是当年生新枝形成花芽，所以每年花谢后，要及时修剪，将老的花枝截短，权留2～3个芽，并注意使芽向外侧生长，要将影响树形美观的交叉枝、平行枝、重叠枝、对生枝、徒生枝，以及过密、瘦弱的枝条剪去。　　5、翻盆。梅花盆景一般隔1～2年翻盆一次，安排在开花后为好。翻盆时，去掉旧土1／3左右，剪去枯根，修短过长的老根，换以富含腐殖质的腐叶土，掺拌砻糠灰及沙土，使盆土既肥活又疏松、透水。　　其实梅花盆栽的难度并不高，只要注意了解梅花的习性，加上科学的栽培方法，你的盆栽梅花也能够开出漂亮的花。', '　　梅花是我国非常常见的花木，现在有很多花友会将梅花制作成盆景放在家中观赏。梅花一般用嫁接繁殖为主，扦插和压条法偶尔使用，播种法应用的比较少。小编就为你介绍一下这几种繁殖方法的特点，有兴趣的花友们可以一起了解。　\n　一、播种繁殖\n　　梅花果实6月或稍后变色时采收，通过后熟阶段，立秋之后再除去果皮和果肉，洗净晾干备用。在年内（秋季）播种为好，具体　　\n二、嫁接繁殖\n　　梅花的很多品种，如金钱绿萼梅、送春梅、凝香梅等，只能采取嫁接的方法繁殖。嫁接有枝接与芽接两种。砧木除用梅的实生苗外，也用桃（包括毛桃、山桃）、李、杏作砧木。以梅砧最好，亲和力强、成活率高、长势好、寿命亦长。　　枝接在2月中旬至3月上旬或10月中旬至11月进行。接穗选择健壮枝条的中段，长5～6厘米，带有2～3芽，采用切接或劈接。　　芽接以立秋前后（8月上旬）进行成活率高，多采用丁字形芽接法。接活后的当年初冬，在接芽以上5厘米处截去砧木，并修剪侧枝。翌年春接芽抽梢，待长大再将残存的砧木剪除，并随时抹去砧芽。　　以桃为砧，种子易得，嫁接易活，且接后生长快，开花多，故目前在　　\n三、扦插繁殖\n　　扦插繁殖梅花操作简便，技术也不复杂，同时能够完全保持原品种的优良特性。梅花扦插成活率因品种不同而有差别，在常规条件下，素白台阁梅成活率最高，一般可达80％以上；小绿萼梅、宫粉梅等成活率达60％；朱砂梅、龙游梅、大羽梅、送春梅等品种则不易成活。用吲哚丁酸500ppm或萘乙酸1000ppm水剂快浸　　梅花的扦插以11月份为好，因此时落叶，枝条贮有充足的养料，容易生根成活。选一年生10～12厘米长的粗壮枝条作插穗，扦插时将大部分枝条埋入土中，土面仅留2～3厘米，并且留一芽在外。要求扦插地土质疏松，排水良好。扦插后浇一次透水，加盖塑料薄膜，这样能保持小范围的温度和湿度，提高扦插成活率，以后视需要补充水分。扦插后土壤的含水量不能过大，否则影响插条愈合生根。翌年成活后，逐渐给以通风使之适应环境，最后揭去薄膜。第三年春季便可进行定株移栽。若春插，则越夏期间须搭荫棚。　　\n四、压条繁殖\n　　压条繁殖宜在2～3月进行，选择1～2年生枝条，在压入土壤的枝条下方割伤2～3刀，注意不要割得太探，如伤木质部会影响生根，将割伤那段埋入土中，操作时要注意不能使芽苞受损。压后还要培土，最好用疏松肥沃的砂质土壤。夏季注意浇水，保持土壤湿润，秋季生根后就可割离成为新植株。　　高压法往往用作繁殖大苗，来年早春即可开花。可于梅雨　　很多花友都因为梅花在', 'http://img.boqiicdn.com/Data/BK/P/imagick66611438767173.jpg', 'http://www.boqii.com/entry/detail/1914.html', '');
INSERT INTO `plant_family` VALUES ('389', '黄丽', 'Sedum adolphii', '黄丽', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2007/0,http://www.boqii.com/entry/photo/2007/5520', '', '', '', '', '', '', '', '', '', '　　黄丽为多年生多 黄丽 　　黄丽植株具短茎，肉质叶，排列紧密，呈莲座状，叶片匙形，顶端有小尖头，叶片松散，表面附蜡质呈黄绿色或金黄色偏红，长期　　　　　　　　　　　　', '　　黄丽如果光照不充分的话，叶片会变绿，很多变绿后的多肉植物往往会辨识不出来。想要养出漂亮的黄丽就需要注意栽培方法，徒长的黄丽可是真的非常丑的哦！！　　　在盆土全部干燥或干透后浇透水，浇水时要防止积水，注意水最好少喷到叶片及茎部，防止因水湿而腐烂。　　　生长适温为15～28℃左右，夏季30℃以上或冬季低于5℃植物缓缓进入休眠。　　　施肥较少，一般选择市场已经过稀释的仙人掌液体肥，注意肥水勿到肉质叶片为好。　　　　要求疏松、透气透水性较好的土壤，可选择泥炭土、和粗砂的混合土来栽培。　　　　黄丽病虫害较少发生。　　　黄丽盆栽可置于光照充足的窗台、也可置于半阴的室内，但不宜放置在阳光暴晒以及阴湿的场所。　　　植物叶面勿喷水，盆土保持偏干，切勿积水容易导致植物腐烂，夏季应放在通风透光处，忌阳光暴晒。', '　　　　黄丽繁殖主要靠植株侧芽，叶插和砍头三种方式。砍头后从残存茎根上长出的新芽来延续后代，且非常容易长侧芽，存活率比较高。黄丽叶插非常方便，直接把后面的健壮肥硕的叶片左右摇晃掰下来，平躺放在干燥的土表面，放在明亮通风的地方，过些时间就会长出小叶片和根，到时候就可以把根埋在土里，就可以正常浇水了。注意，还没有长出根的时候就不要浇水了，防止叶片潮湿', 'http://img.boqiicdn.com/Data/BK/P/imagick40151441618102.jpg', 'http://www.boqii.com/entry/detail/2007.html', '');
INSERT INTO `plant_family` VALUES ('390', '垂叶榕', 'Ficus benjamina L.', '垂叶榕', '垂榕，黄金垂榕，白榕；小叶榕；细叶榕；柳叶榕；马尾榕；米碎常', '不容易死', '泰国，中国云南、广东、海南等地', 'http://www.boqii.com/entry/photo/2123/0,http://www.boqii.com/entry/photo/2123/5404', '　', '被子植物门 Angiospermae', '双子叶植物纲 Dicotyledoneae', '荨麻目 Urticales', '桑科', '榕属', '垂叶榕', 'Ficus benjamina L.', '', '　　 　　垂叶榕叶薄革质，卵形至卵状椭圆形，长4－8厘米，宽2－4厘米，先端短渐尖，基部圆形或楔形，全缘，一级侧脉与二级侧脉难于区分，平行展出，直达近叶边缘，网结成边脉，两面光滑无毛；叶柄长1－2厘米，上面有沟槽；托叶披针形，长约6毫米。榕果成对或单生叶腋，基部缢缩成柄。', '　　垂叶榕的适应能力比较强，耐热、耐旱、耐湿、耐剪，并且也是易移植的常绿乔木，人工栽种垂叶榕的难度并不高，只需要注意光照、、水肥的就能将垂叶榕栽种的很好了。　　一般应置于光亮处，但应避免强光直射，尤其是花叶品种最忌阳光照射。日照不足，则节间伸长，叶片垂软，长势微弱；在日光下，则叶肉变厚，富有光泽。垂叶榕类虽具一定耐寒能力，但温度不宜低于5℃，生长适温为15—30℃。　　生长旺盛期应经常浇水，保持湿润状态，并经常向叶面和周围空间喷水，以促进植株生长，提高叶片光泽。冬季盆土过湿容易烂根，须待盆干时再浇水。　　盆土可采用富含腐殖质的混合土，如用堆肥与等量的泥炭土混合，并施入一些基肥作底肥。生长季节施肥可以每2周施一次液肥，以氮肥为主，适当配合一些钾肥。盆土与盆的选择。　　花盆的大小依植株的大小而变化。为了形成良好的树姿，每盆可栽３株苗。一般小型盆栽宜每年４月换盆一次，大型盆栽可2—3年换盆一次，以生长所需的养分。', '　　　　垂叶榕的繁殖方式有扦插和好压两种方法，前者比较普遍。扦插繁殖一般宜在春末夏初（4～6月），选择健壮的成熟枝条，截取10～15cm的顶部嫩枝作插穗，上面留下2～3片叶子，去掉下面的叶子。如果剪口有汁液流出，可以用温水洗净或蘸上草木灰，也可以用火烤', 'http://img.boqiicdn.com/Data/BK/P/imagick99581444901534.jpg', 'http://www.boqii.com/entry/detail/2123.html', '');
INSERT INTO `plant_family` VALUES ('391', '文殊兰', 'Crinum asiaticum L. var. sinicum （Roxb. ex Herb.） ', '文殊兰', '文珠兰、罗裙带、文兰树、水蕉、海带七、郁蕉、海蕉、玉米兰', '不容易死', '原产热带、亚洲。中国台湾、广东、福建等省有野生', 'http://www.boqii.com/entry/photo/2376/0,http://www.boqii.com/entry/photo/2376/5040', '　', '被子植物门', '单子叶植物纲', '百合目', '石蒜科', '文殊兰属', '文殊兰 ', 'Crinum asiaticum L. var. sinicum （Roxb. ex Herb.） Baker', 'Crinum asiaticum', '　　 　　文殊兰为多年生粗壮草本。鳞茎长柱形。叶20－30枚，多列，带状披针形，长可达1米，宽7－12厘米或更宽，顶端渐尖，具1急尖的尖头，边缘波状，暗绿色。', '　　文殊兰的观赏价值较高，不但可作为园林景区、校园绿地的点缀品，还可作为庭院装饰，现在更是被很多花友盆栽，非常漂亮。文殊兰不但可以观赏，还可入药，那么如何才能养好文殊兰呢？　　1、大盆深栽。为了满足文殊兰期间所需要的养分，在栽培时，应选择较大的花盆加以深栽，以利保水保土，供应根系。　　2、水肥。在文殊兰正常生长期间，5月至9月以内，每天适量浇水，见干见湿。每隔7天至10天施一次油饼渣加黑矾（硫酸亚铁）沤制的肥水，其浓度应本着先淡后浓，入冬停施。　　3、抹除孽芽。文殊兰在生长旺盛期，总要经常从根茎周围生出孽芽，为保证株形直立，根茎整齐，全株正常生长，应及时抹去孽芽。　　4、日照与遮阴。为使叶片碧绿、美观整齐而又不影响光照，在酷暑盛夏时，对文殊兰应适当遮荫，早7时至12时，应接受全日照，12时至15时应搭荫棚遮阴。同属约100多种。', '　　　　1、分株繁殖。一般在早春结合翻盆进行，将母株四周根芽掰下来，稍晾1～2天，另行上盆。栽植时不宜栽得太浅，每盆1株，一般3年翻盆一次。上盆后浇一次透水，放置在半阴少光处　　2、播种繁殖。以3～4月为宜。在北方需人工辅助授粉，否则不易结实。种子含水量大，宜采后即播。可用浅盆点播，覆土约2厘米厚，浇透水，在16～22℃', 'http://img.boqiicdn.com/Data/BK/P/imagick15451451467914.jpg', 'http://www.boqii.com/entry/detail/2376.html', '');
INSERT INTO `plant_family` VALUES ('392', '合果芋', 'Syngonium podophyllum', '', '', '不容易死', '中美、南美热带雨林中，世界各地均有人工种植。', 'http://www.boqii.com/entry/photo/1895/0,http://www.boqii.com/entry/photo/1895/5634', '', '', '', '', '', '', '', '', '', '　　合果芋为多年生蔓性常绿草本植物，合果芋的叶片呈两型性，初生叶色淡，老叶呈深绿色。合果芋的饲养难度不大，喜高温，适应能力非常强，并且能够适应不同的光照环境。室内种植一盆合果芋，不但能够美化环境，还能够起到净化空气的作用，但是想要养出健康漂亮的合果芋，还是需要注意正确的 　　1、长耳合果芋：别名五指合果芋。为同属常见种。茎分枝，多爬藤。叶片成熟时掌状3－5裂，长25厘米，质厚，基部有2个耳状裂片，浓绿色，有光泽。原产于牙买加。　　2、长叶合果芋：别名大叶合果芋、心叶台果芋。为同属常见种。大型爬藤。叶心形，较大，长22－30厘米，宽15－20厘米，不分裂。攀援性很强，适宜垂直绿化和柱形栽培。　　3、红叶合果芋：为同届常见种。叶戟形，长10－15厘米，宽6－8厘米。叶面红铜绿色，爬藤。原产巴拿马。　　4、白蝴蝶合果芋：别名白蝶合果芋。为台果芋的栽培品种。原产墨西哥、危地马拉、哥斯达黎加。美国育成的园艺品种。叶浅绿色或淡白色，在明亮处栽培叶而保持原色，光线太暗，会转为绿色。叶片盾形，长12－15厘米，宽7－8匣米，大部分为黄白色，叶缘有绿色的条纹或斑块。叶柄长20厘米左右，绿色，微带紫红晕。美丽动人，为最受欢迎的观叶花卉之一，具有一定的发展潜力。　　5、银叶合果芋：别名白玉合果芋。为合果芋的栽培品种。叶心形，银白色，叶边缘绿色。　　6、翠玉合果芋：别名斑叶合果芋。为合果芋的栽培品种。叶戟形，绿色，叶面有不规则乳白色斑块。耐寒性强，节处易生不定根。越冬　　7、粉蝶合果芋：为合果芋的栽培品种。叶淡绿色，叶面中部淡粉色。　　8、箭头合果芋：为合果芋的栽培品种。幼叶箭头形，掌状3裂或心形，叶面绿色，叶脉象牙色，老叶全部变成绿色。　　9、何氏合果芋：为同属常见种。叶面灰绿色，布有银白色脉纹。 　　1、土壤：盆栽合果芋土壤以肥沃、疏松和排水良好的砂质壤土为宜。盆栽土以腐叶土、泥炭土和粗沙的混合土。　　2、浇水：合果芋喜湿怕干。夏季　　3、阳光：合果芋适应性强，生长健状， 能适应不同光照环境。强光处茎叶略呈淡紫色，叶片较大，色浅；弱光处则叶片狭小，色浓暗。在明亮的散射光处生长良好。以遮光50％为宜。斑叶品种在光照不足时则色斑不显着。　　4、温度：合果芋不耐寒，合果芋的生长适温为22～30℃，在15℃时生长较慢，10℃以下则茎叶停止生长。冬季温度在5℃以下叶片出现冻害。　　5、施肥：合果芋生长期每1－2周施稀薄液肥1次。每月喷1次0。2％硫酸亚铁溶液，可保持叶色翠绿可爱。如果摆放于室内，不需生长过快，则须控制施肥量。为增加观赏效果，使叶片白色　　6、虫害：合果芋常见叶斑病和灰霉病危害，可用70％代森锌可湿性粉剂700倍液喷洒。平时，可用等量式波尔多液喷洒预防。虫害有粉虱和蓟马危害茎叶，用40％氧化乐果乳油1500倍液喷杀。　　合果芋是一种很具有代表性的室内植物，虽然合果芋对于光照的适应能力非常强，但是合果芋却不耐寒，所以饲养合果芋的时候一定要注意不要让它们处于温度低的环境下。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick34671428054815.jpg', 'http://www.boqii.com/entry/detail/1895.html', '');
INSERT INTO `plant_family` VALUES ('393', '洋桔梗', 'Eustoma，Lisianthus', '洋桔梗', '草原龙胆，土耳其桔梗、丽钵花、德州兰铃', '不容易死', '原产美国内布拉斯加州和得克萨斯州，引种到欧洲和日本', 'http://www.boqii.com/entry/photo/2331/0,http://www.boqii.com/entry/photo/2331/5086', '', '', '', '', '', '', '', '', '', '　　 　　洋桔梗为多年生草本。茎直立，灰绿色。叶对生，灰绿色，卵形至长椭圆形。花冠钟状，淡紫、淡红、白等色，已选育出重瓣和双色品种。常见矮生品种有美人鱼（Mermaid）系列、蓝利萨（LisaBlue）、红镜（RedGlass）、重瓣伊格尔（DeubleEagle）、伊迪（Eeidi）系列、埃克奥（Echo）、玛丽艾基（Mariachi）。　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　高贵典雅，色调清新，是非常适合盆栽在家中来改善家居环境的。洋桔梗的栽培难度并不高，随着人们对洋桔梗的喜爱越来越深，不少花友都会自己栽种洋桔梗，小编就为你整理了洋桔梗栽种过程中的，的朋友可以一起了解。　　洋桔梗在高温、强光照下，洋桔梗需水量增加，此时要保证基质湿润，干旱影响花茎伸长。栽培基质应为加入草炭土、稻糠及少量石灰等的改良的园土，栽植前加入厩肥、骨粉等作基肥，因其需肥量较大，过程及时追肥，资料表明硝酸钙是很好的肥料，即提供了氮素，又了钙质。　　盆栽的洋桔梗虽然对乙烯不敏感，但在运输过程中，也出现花朵萎蔫的乙烯毒害现象，可在上市前2周喷洒0.3～0.4毫摩尔1升硫代硫酸银1次，以提高洋桔梗盆花的品质。', '　　很多花友都非常　　1、首先准备好育苗土或者是育苗块，为了方便些，可以尽量用单独的育苗小盆种，这样发芽可以避免发芽　　2、用种子的朋友要小心的拆开袋子，因为洋桔梗的种子特别　　3、放好种子后上面如果有盖子可以盖上保湿，如果没有盖子的，可以盖一层家里用的保鲜膜。这样可以保持湿度。每天打开透透气就可以了。也可以每天拿特别细小的喷壶喷喷水，如果觉得掌握不好，可以直接坐在水盆里保持湿度。但一定记得，不要24小时放里，只要每天轻轻喷喷，或者坐一会儿就可以了。我个人觉得种子也需要呼吸的，泡久了种子会泡坏，反而不容易发芽。一般种上15－20天左右就会发芽了，晚一些的也有30天发的。亲们一定要有耐心，不要放弃它们，在没发芽之前一直要保持湿度。　　4、发芽以后就不用盖盖子了，可以晒散光，但千万不要暴晒，因为刚发芽的小苗很脆弱的，一晒很容易就干吧死。这时也不用天天放在水盆里了，看稍干点了再放就可以，刚出芽的尽量轻轻喷，因为小苗很小，一用力喷就会倒的。　　5、等叶子长大些就可以定植了，洋桔梗是直根系，最好少移动，因为每移一回就会多少有些伤害，所以尽量少移动。要记得在盆里放些底肥，这样可以省去很多麻烦。我种的桔梗，从去年5月种，一直到今年开花时，除了放过底肥以外，其他都没有放过，开过花才补的其他肥。所以我个人觉得底肥很重要，即简单又方便，定植以后就要看差不多干透了再浇，不用勤浇了，我觉得你越关注它，它死的越快，我家的桔梗，基本都没怎么管它，就放一边儿，想起时浇遍水，浇水一定要浇透，就可以了。', 'http://img.boqiicdn.com/Data/BK/P/imagick82301450259141.jpg', 'http://www.boqii.com/entry/detail/2331.html', '');
INSERT INTO `plant_family` VALUES ('394', '玉簪花', 'Hosta plantaginea Aschers', '玉簪', '玉春棒、白鹤花、玉泡花、白玉簪', '不容易死', '中国、日本', 'http://www.boqii.com/entry/photo/2096/0,http://www.boqii.com/entry/photo/2096/5431', '　', '被子植物门 Magnoliophyta', '单子叶植物纲 Liliopsida', '百合目 Liliales', '百合科 Liliaceae', '玉簪属 Hosta', '玉簪种 H. plantaginea Aschers', 'Hosta plantaginea Aschers', '', '　　 　　玉簪花的根状茎粗状，有多数须根。叶茎生成丛，心状卵圆形，脸具长柄，叶脉弧形。花向叶丛中抽出，高出叶面，着花9－15朵，组成总状花序。花白色或紫色，有香气，具细长的花被筒，先端6裂，呈漏斗状，花期7－9月。蒴果圆柱形，成熟时3裂，种子黑色，顶端有翅。', '　　花在还未开花时好像簪子的形状，故此命名。大多数都为白色，也有淡紫、堇紫色花的紫萼、狭叶玉簪、波叶玉簪等。玉簪花的花香浓郁，非常适合观赏。　　玉簪性强健，耐寒冷，性喜阴湿环境，不耐强烈日光照射，要求土层深厚，排水良好且肥沃的砂质壤土。玉簪对土壤要求并不十分严格，但是如果有条件，选用富含腐殖质的砂质壤土效果最好。所用盆土可由腐叶、细砂、园土按体积计以1：1：1的比例配成。玉簪根部粗壮，冠幅较大，通常选用大型花盆进行定植。　　玉簪喜微潮的土壤环境，不耐旱，浇水不足叶片容易干尖。其对肥料需求不多，除定植刚在花盆基部施用50克左右的马蹄片等基肥外，旺盛阶段还应每半个月追施1次稀薄液体肥料。当植株抽生花葶后，可以适当多施一些磷肥，例如磷酸二氢钾等，这样花朵会开放得更好。它性喜环境荫蔽，不耐阳光照射，否则叶片容易泛黄。入秋后，随着气温的降低，玉簪的叶片逐渐变黄，开始枯萎，但其地下的根茎却不会，等到翌年春季天气转暖后还会发芽。其喜温暖的环境，在15℃～30℃的温度范围内生长良好。它不怕严寒，可耐－20℃的低温。因此，在我国北方绝大多数地区的阳台上都能够露天。在阳台栽培中，玉簪通常不易罹病，亦很少受到有害动物的侵袭。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick89861444297161.jpg', 'http://www.boqii.com/entry/detail/2096.html', '');
INSERT INTO `plant_family` VALUES ('395', '百合花', 'Lilium brownii var. viridulum', '百合', '强瞿、番韭、山丹、倒仙', '不容易死', '亚洲东部，欧洲，北美洲，北半球', 'http://www.boqii.com/entry/photo/1979/0,http://www.boqii.com/entry/photo/1979/5548', '', '', '', '', '', '', '', '', '', '　　百合是非常常见的多年生草本球根 　　百合为多年生草本，株高70～150厘米。鳞茎球形，淡白色，先端常开放如莲座状，由多数肉质肥厚、卵匙形的鳞片聚合而成。百合花大、多白色、漏斗形，单生于茎顶。蒴果长卵圆形，具钝棱。　　　　　　　　　　　　　　　　　　　　　', '　　百合花在我们生活中是非常常见的，有的花友对百合花非常喜爱，还会自己在家中进行盆栽。不过百合花不论是在什么环境下栽种，都应具备肥沃并且透气性良好的沙壤，这样栽种出的百合花会更加漂亮。　　百合花的大多数品种性喜凉爽、湿润的半阴环境，较耐寒冷。在富含腐殖质的肥沃砂质和排水良好的土壤中生长茂盛，鳞茎发达，花色艳丽。而卷丹百合则性喜温暖、干燥的气候条件，也较耐日光照射。百合适宜氮肥，以豆饼、菜饼，农家堆肥和氮、磷、钾复合肥为最好。在百合的生长期要勤松土、除草，结合浇水施肥进行中耕。一般在生长期施稀释液肥2—3次，以促其株苗生长发育。将近孕蕾开花时，施1—2次磷、钾肥，以保证株苗在孕蕾和开花期有充足营养，不仅可使花朵硕大，色鲜，并可促进球茎的发育。大面积栽植，要注意通风透气和适当遮阴，若小面积栽植或盆栽，对花多而枝秆纤细柔弱的观赏品种要设立支架，以防花枝折断。百合虽病虫害较少，但也要注意。　　栽种百合花，北方宜选择向阳避风处，南方可栽种在略有遮荫的地方。种植以8－9月为宜。种前一个月施足基肥，并深翻土壤，可用堆肥和草木灰作基肥。栽种宜较深（一般深度为鳞茎直径的3－4倍），以利根茎吸收养分。北方如栽种太浅，冬季易受冻害，并会影响根须和小鳞茎的生长。生长期间不宜中耕除草，以免损伤根茎。若有条件，可在种植地面撒一些碎木屑作土壤覆盖。这样，既可防止杂草生长，又可保墒和降低土壤湿度，以利鳞茎发育。　　盆栽宜在9－10月份进行。宜用腐叶土、砂土、园土以1：1：1的比例混合配制，盆底施足充分腐熟的堆肥和少量骨粉及为作基肥。栽种深度一般约为鳞茎直径的2－3倍。百合对肥料要求不很高，通常在春季生长开始及开花初期酌施肥料即可。国外一些栽培者认为，百合对氮、钾肥需要较大，生长期应每隔10－15天施一次，而对磷肥要限制供给，因为磷肥偏多会引起叶子枯黄。花期可增施1－2天磷肥。　　开花后应及时剪去残花，以减少养分消耗，浇水只需保持盆土潮润，但生长旺季和天气干旱时须适当勤浇，并常在花盆周围洒水，以提高空气湿度。盆土不宜过湿，否则鳞茎易，盆栽百合花每年换盆一次，换上新的培养土和基肥。此外，生长期每周还要转动花盆一次。不然植株容易偏长，影响美观。', '　　很多', 'http://img.boqiicdn.com/Data/BK/P/imagick87711440495190.jpg', 'http://www.boqii.com/entry/detail/1979.html', '');
INSERT INTO `plant_family` VALUES ('396', '石楠', 'Photinia serrulata Lindl.', '石楠', '红树叶 石岩树叶、水红树、山官木、细齿石楠、凿木、猪林子', '不容易死', '中国、日本、印度尼西亚', 'http://www.boqii.com/entry/photo/1978/0,http://www.boqii.com/entry/photo/1978/5549', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '石楠属', '石楠', 'Photinia serrulata Lindl.', 'Photinia serrulata', '　　 　　石楠高3－6米，有时可达12米；枝褐灰色，全体无毛；冬芽卵形，鳞片褐色，无毛。叶片革质，长椭圆形、长倒卵形或倒卵状椭圆形，长9－22厘米，宽3－6.5厘米，先端尾尖，基部圆形或宽楔形，边缘有疏生具腺细锯齿，近基部全缘，上面光亮，幼时中脉有绒毛，成熟后两面皆无毛，中脉显着，侧脉25－30对；叶柄粗壮，长2－4厘米，幼时有绒毛，以后无毛。', '　　虽然是观叶，但是也会开花，并且花期为5－7月，常被用于栽种在、草坪及路边等处，并且其抗二氧化硫的能力比较强，所以也是绿化的优良树种。　　石楠为蔷薇科、石楠属常绿灌木或小乔木，喜温暖、湿润和阳光充足的环境，稍耐阴，耐寒冷和干旱，怕积水，萌发力强，耐修剪。在土层深厚、排水良好的肥沃土壤中生长良好。适宜种植在地势稍高，排水顺畅的地方。在3至4月移栽，小苗尽量多带宿土，大苗移栽则要剪去部分枝叶，以减少水分蒸发，保证成活。栽后浇一次透水，以后可根据天气情况进行喷水或浇水，以促使其尽快恢复长势。平时管理为粗放，生长期保持土壤湿润不积水，每年施肥1至2次。　　石楠既可做灌木状丛植，也可做乔木状栽培，灌木状丛植一般3至5干为一丛，夏季适当剔除根部萌发的枝条，其它基本保持自然状态。若作乔木状栽培时，选择一主干，不断的抹芽修枝，当主干高1。5米时进行侧枝的分级，每级保留3至5个壮枝，夏季注意摘心抹芽，以控制生长，保持株型的优美，3至5年可基本成形。　　石楠的病害很少。虫害主要有刺蛾、袋蛾、尺蠖等食叶类害虫，数量少时可人工扑捉，数量多时可用相关进行防治。', '　　　\n　一、播种\n　　果实成熟后采种，在阴凉处堆放5天至7天，使其充分后熟。然后，将果实用清水浸泡2至3天，揉搓洗净，再拌入草木灰搓干、晾干，混沙低温贮藏，翌年春季播种。播种深度1厘米至1.5厘米，播后稍加镇压，并覆盖稻草或架遮阳网，以保持土壤的　　\n二、扦插\n　　在6月至8月生长旺盛期进行全光照喷雾扦插，采当年生半木质化的枝梢做插穗，每段长10厘米至15厘米，有2个至4个芽，顶端保留2片叶子，并剪去一半叶子，插入土中1／2至2／3，及时浇水，以保持空气、土壤湿润。　　\n三、压条\n　　可进行空中压条。也可牵引压条，方法是将基部1至2年生枝条压弯埋入土中，为了促进生根，可在下弯处切一两个伤口，用枝杈固定后，堆土15厘米至20厘米，以后保持湿润，生根后与母体分离。　\n　四、分株\n　　石楠萌发性强，基本易发侧芽，可将其掘出，分成若干个有根的单株，另行栽种，即成为新的植株。', 'http://img.boqiicdn.com/Data/BK/P/imagick90621440494768.jpg', 'http://www.boqii.com/entry/detail/1978.html', '');
INSERT INTO `plant_family` VALUES ('397', '青星美人', 'Pachyphytum ', '青星美人', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2226/0,http://www.boqii.com/entry/photo/2226/5301', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '厚叶草属', '青星美人', 'Pachyphytum \'Dr Cornelius\'', '', '　　青 　　青星美人，有短茎，叶疏散排列为近似莲坐的形态，叶片肥厚，匙型，细长，叶缘圆弧状，有叶尖，叶片光滑微量白粉，叶色翠绿，阳光充足叶片紧密排列边缘和叶尖会发红；弱光则叶色浅绿，叶片变的窄且长，叶片间的间距会徒长拉长。青星美人夏季开花，开花周期长，开花时抽生出长长的花梗，簇状花序，花朵依次开放，花红色，倒钟形，串状排列，花开五瓣，可以异花授粉。', '　　原产于墨西哥，所以耐旱性非常强，喜欢温暖、干燥和光照充足的环境，炎热的夏季在冷凉的环境下也能良好。人工栽培青星美人应注意以下几点：　　　浇水是干透才浇透，不干不浇水。无明显休眠期，可以全日照。的时候通风遮阳，每个月3到4次水，少量在盆边给水慢慢度过盛夏，维持植株根系不会因为过度干燥而干枯就可以。　　　冬天温度低于3度就要逐渐少水，0度以下保持盆土干燥，尽量保持不低于零下3度。这样就可以过冬了，冬天尽量少点水，开春给水要循序渐进否则可能出现烂根。南北差异比较大，家庭和大棚的养殖方法都不一样，青星美人倒是比较好养的一个品种。　　　可以选择泥炭混合珍珠岩加了煤渣，大概比例1：1：1，为了隔离植株和土表接触，也为了更加透气，可铺上颗粒的干净河沙或者浮石，河沙尺寸3到5毫米。', '　　青　　青星美人的繁殖方法主要有播种和分株、砍头、叶插。　　青星美人叶插：可以将叶片丢在土表不管，它们会自然萌发根系和小叶片，成为独立的小植株。　　青星美人砍头后容易长侧枝，不砍头一直养，植株的老杆会长很长，然后才开始分枝，为了更加漂亮。长的差不多的时候就应该砍头萌发侧芽，这样植株群生了才漂亮。', 'http://img.boqiicdn.com/Data/BK/P/imagick43961447751847.jpg', 'http://www.boqii.com/entry/detail/2226.html', '');
INSERT INTO `plant_family` VALUES ('398', '茉莉花', 'Jasminum sambac （L.） Ait.', '茉莉花', '茉莉、香魂、莫利花、没丽、没利、抹厉、末莉、末利、木梨花', '不容易死', '原产印度、中国南方和世界各地', 'http://www.boqii.com/entry/photo/1915/0,http://www.boqii.com/entry/photo/1915/5614', '', '', '', '', '', '', '', '', '', '　　 　　　　　　　　　　　　　　　　　　　　　　　', '　　如果你种植过的话，应该会发现茉莉花土栽比盆栽容易，盆栽如果想要种出和土栽一样的效果的话，那么在栽培的过程中就需要多花一些心思了。小编就为你介绍一下茉莉花盆栽的一些技巧，教你如何盆栽出漂亮的茉莉花。　　1、用土：土壤要求疏松肥沃，排水良好，最好以沙土为主。土壤可以自己用用腐叶土、细砂、园士各一份混匀配成。这样配制的栽培基对魔力的发芽好，寿命长。　　2、浇水：在冬春两季，浇水的量应该按照环境温度来决定，温度越低浇水越少好，保持盒上略微潮湿即可。夏天生长旺盛，对水的需求大，在炎热的中午，还需要给植物叶子上喷洒水。不过夏季还应该助于防止涝害发生。　　3、施肥：给茉莉施肥，应该主要在从春末到秋初这一段时间里。除了花开前，花谢后需给植株施几次浓肥之外，其他时候就要薄肥勤施，大约每周一次即可。肥足茉莉才能枝条勃发，叶片油绿，花香扑鼻。　　4、光照：最好将茉莉放在全日照处。如果条件不许可，也要使它接受每天不少于4小时的日光照射。宜把茉莉放在室外，如果将其放在玻璃窗内侧，则会对植株进行造成一定影响。　　5、控温：要想养好盆栽茉莉，温度控制特别重要，生长旺盛的时候应该把它防止在25－30度的环境处，冬春两级茉莉或者基本不生长，把它防止在温度为5－10度出就可以了，这对确保茉莉夏秋两季正常生长，严寒不致死亡十分关键。　　6、修剪：茉莉生长势强，合理修剪非常重要。通常情况下在冬季就应该给茉莉打掉老枝，保存养料，老年多发新芽。在夏季茉莉开始大量开花后，也要短截已经凋谢的枝条，因为茉莉花朵着生在枝条顶端。这样之后，茉莉长的更加旺盛，寿命也会长一些。', '　　根据　\n　一、扦插时期\n　　一年中有两次最好的扦插时期。一次是7—8月。通常不要超过“处暑”，即所谓秋插。此期扦插，生根快，易　　\n二、插穗的选择和整理\n　　插穗应选择健壮、充实、无病虫害的枝条为好。通常用隔年枝，即皮部已现麻花色的枝最为适度。过分衰老，再生力弱，不易生根、发芽；过分幼嫩，养分储备少，容易　　在扦插时，要随剪随插。为了避免插穗下端皮部“翻毛”损伤，影响愈合，常用“引插”法。先引一孔，然后再将扦穗轻轻插入、压实。插入深度以露一个节为宜。其余大部入土，以尽量减少蒸腾面，扩大吸水面。听了小编的介绍，相信大家对茉莉花扦插繁殖都有了一定的了解。', 'http://img.boqiicdn.com/Data/BK/P/imagick80331438768060.jpg', 'http://www.boqii.com/entry/detail/1915.html', '');
INSERT INTO `plant_family` VALUES ('399', '万代兰', 'Vanda', '万代兰', '桑德万代', '不容易死', '印度、马来西亚、菲律宾、中国南方以及澳大利亚北方', 'http://www.boqii.com/entry/photo/2254/0,http://www.boqii.com/entry/photo/2254/5271', '', '', '', '', '', '', '', '', '', '　　 　　万代兰的植株直立向上，无假球茎，叶片互生于单茎的两边，有如人体前胸的一副排骨。有些长茎的品种还可分枝或攀缘。而叶片呈现带状，肉多质硬，中脉凹下如沟，呈“V”字形，能耐强光和干旱而不容易枯萎。它的气生根又粗又长，有的好像筷子，从茎上的叶间抽出，凡是　　　　　　　　　　　　　', '　　万代兰是新加坡的国花，现在广泛分布于中国、印度、马来西亚等国。万代兰是热带兰中的一大类，并且生命力非常顽强，栽培难度也并不高，但想要养出漂亮的万代兰还是需要注意布置环境，以及适宜的栽培方法。　上述一般品种的万代兰，需要较强的光线，在本地高温季节需使用40～50％的遮光网遮光，冬季甚至不需要遮光。　　西双版纳所栽培的万代兰，均喜欢高温环境。最为20—30℃。因当地全年无霜，万带兰在任何季节都能正常开花。　　上述两个品种的万代兰都是典型的热带气生，日常中必须保证充足的水份和空气湿度。在雨季靠自然条件即可保持旺盛的长势。干季必须通过人工洒水使空气湿度保持在80％左右。　　万代兰所需的肥料较其他洋兰高，因此在生长旺盛期间，可每7～10天施用稀释的肥料1次。最佳的肥料是氮、磷、钾的比例为10：10：5。　　由于万代兰的根属气生根，因此凡排水良好的介质都能适用，像蛇木屑、碎砖块、木炭、粗砾砂等，无论是单独或混合使用都是很好的盆土。种植万代兰除了介质外，盆钵亦须相当讲究，在多种材质的盆钵中，以木条盆及陶盆为优，而且在盆上多穿几个洞，更有利于排水良好及空气流通，而除了木条盆及陶盆外，万代兰亦能在蛇木板或树干上生长良好。无论用何种方式栽培，切记盆土必须排水及通气均非常良好。　　万代兰不宜经常换盆，除非受病虫害侵扰，否则至少3年才能换盆1次。春天的万代兰正要步入旺盛的生长期，是换盆的好时机。生长多年的万代兰，它的根系会紧紧地附在盆钵的内壁，因此倘若是用陶盆种植时，最好将盆子打破，再进行换盆工作，以免在取出植株时，伤及根系。', '　　　　万代兰可以高芽繁殖，于秋末时，万代兰在叶腋处会长出高芽，当高芽长至5～7。5厘米时，应用锋利及已', 'http://img.boqiicdn.com/Data/BK/P/imagick4441448444051.jpg', 'http://www.boqii.com/entry/detail/2254.html', '');
INSERT INTO `plant_family` VALUES ('400', '萼距花', 'Cuphea hookeriana Walp.', '萼距花', '紫花满天星，孔雀兰', '不容易死', '原产墨西哥，现热带、南亚热带地区园林中广泛应用。', 'http://www.boqii.com/entry/photo/2311/0,http://www.boqii.com/entry/photo/2311/5212', '植物　　', '被子植物门', '双子叶植物纲', '()目', '千屈菜科', '萼距花属', '', 'Cuphea hookeriana Walp.', '', '　　 　　萼距花高30－70厘米，直立，粗糙，被粗毛及短小硬毛；分枝细，密被短柔毛。叶薄革质，披针形或卵状披针形，稀矩圆形，顶部的线状披针形，长2－4厘米，宽5－15毫米，顶端长渐尖，基部圆形至阔楔形，下延至叶柄，幼时两面被贴伏短粗毛，后渐脱落而粗糙，侧脉约4对，在上面凹下，在下面明显凸起，叶柄极短，长约1毫米。花单生于叶柄之间或近腋生，组成少花的总状花序；花梗纤细；花萼基部上方具短距，带红色，背部特别明显，密被粘质的柔毛或绒毛；花瓣6，其中上方2枚特大而显着，矩圆形，深紫色，波状，具爪，其余4枚极小，锥形，有时消失；雄蕊11，有时12枚，其中5－6枚较长，突出萼筒之外，花丝被绒毛；子房矩圆形。', '　　萼距花又被亲切的称为紫色满天星，由于萼距花周年开花不断，并且四季常青，所以非常适合栽种在庭院、花坛中，观赏价值和绿化功能都非常高。那么人工栽培萼距花应该注意哪些呢？　　萼距花喜温暖，为20－30℃，不耐寒，冬季温度宜维持在5℃以上，萼距花5°C以下会遭寒害。　　萼距花喜阳光充足的环境，耐半阴，除夏季阳光强烈时需遮直射光照外，其余最好都能给予充足的光照。光照过弱时，萼距花虽能生长，但开花不良，甚至不开花。　萼距花喜湿润的土壤环境，对土壤水分不敏感。萼距花生长期间的浇水应掌握“干湿相间而偏湿”，保持盆土湿润。但忌土壤积水，否则容易引起萼距花根系腐烂。夏季宜酌量增加浇水，冬季则宜节制浇水；保持盆土较为干燥的状态。　萼距花喜湿润的环境，以空气相对湿度50％－60％为宜。夏季高温、天晴而干燥时，在浇水同时还应向萼距花植株及周围喷水，以创造湿润凉爽的环境。　　萼距花耐瘠薄，在贫瘠的土壤中也能正常生长。但由于萼距花枝叶生长迅速，开花量大，生长时应每半月追施1－2次氮磷钾结合的肥料。不宜单纯或过多施用氮肥，否则萼距花虽枝叶生长旺盛，但开花减少。秋季停止施用氮肥，仅施怜钾肥。冬季停止施肥。　　萼距花枝叶生长迅速，耐修剪。萼距花生长期应经常进行摘心或打顶，以控制株髙，促发分枝，形成丰满的株形。随时对萼距花植株进行修剪，剪去过密枝和痩弱枝，以改善植株内部的通风透光，利于植株的生长与开花。　　养殖萼距花每盆种植1－3株，成株每1－2年翻盆1次。萼距花对土壤要求不严，但喜疏、松肥沃、排水良好的砂质壤土，萼距花可用腐叶土、园土、砻糠灰或粗砂等材料配制。', '　　　　\n萼距花扦插繁殖：\n　　扦插基质可以选用营养土或河砂、泥碳土等材料。家庭扦插限于条件很难弄到理想的扦插基质，建议使用已经配制好并且消过毒的扦插基质；用中粗河砂也行，但在使用前要用清水冲洗几次。海砂及　　\n萼距花分株繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick94741449741335.jpg', 'http://www.boqii.com/entry/detail/2311.html', '');
INSERT INTO `plant_family` VALUES ('401', '常春藤', 'Hedera nepalensis K，Koch var.sin ensis （Tobl.） Reh', '常春藤', '土鼓藤、钻天风、三角风、散骨风、枫荷梨藤。洋常春藤', '不容易死', '产于陕西、甘肃及黄河流域以南至华南和西南', 'http://www.boqii.com/entry/photo/1948/0,http://www.boqii.com/entry/photo/1948/5579', '', '', '', '', '', '', '', '', '', '　　 　　常春藤茎灰棕色或黑棕色，光滑，有气生根，幼枝被鳞片状柔毛，鳞片通常有10－20条辐射肋。单叶互生；叶柄长2－9cm，有鳞片；无托叶；叶二型；不能枝上的叶为三角状卵形或戟形，长5－12cm，宽3－10cm，全缘或三裂；花枝上的叶椭圆状披针形，条椭圆状卵形或披针形，稀卵形或圆卵形，全缘；先端长尖或渐尖，基部楔形、宽圆形、心形；叶上表面深绿色，有光泽，下面淡绿色或淡黄绿色，无毛或疏生鳞片；侧脉和网脉两面均明显。　　　　　　　　　　　　　　　　　　　　　', '　　常春藤是非常常见的观叶，由于常春藤的栽培难度比较低，所以很多新手花友都能将常春藤栽种的非常好。不过，还是不乏有的朋友将常春藤养死的情况，那么常春藤在栽培的过程中究竟应该注意哪些呢？　　1、温度要适宜。常春藤性喜温暖，生长适温为20℃一25℃，怕炎热，不耐寒。因此放置在室内养护时，夏季要注意通风降温，冬季室温最好能保持在IO－C以上，最低不能低于5℃。　　2、光照要适度。常春藤喜光，也较耐阴，放在半光条件下则节间较短，叶形一致，叶色鲜明，因此宜放室内光线明亮处培养。若能于春秋两季，各选一段放室外遮荫处，使其早晚多见些阳光，则生机旺盛，叶绿色艳。但要注意防止强光直射，否则易引起日灼病。　　3、适量浇水。生长季节浇水要见干见湿，不能让盆土过分潮湿，否则易引起烂根落叶。冬季室温低，尤其要控制浇水，保持盆土微湿即可。北方冬季气候干燥，最好每周用与室温相近的清水喷洗1次杜川，以保持空气湿度，则植株显得有生气，叶色嫩绿而有光泽。　　4、合理施肥。家庭栽培常春藤，盆土宜选川腐叶或炭土加1／4河沙和少量骨粉混合配成的培养土，生长季节2～3周施1次稀薄饼肥水。一般夏季和冬季不要施肥。施肥时切忌偏施氮肥，否则，花叶品种叶面上的花纹、斑块等就余褪为绿色。氮、磷、钾三者的比例以1：1：l为宜。生长旺季也町向叶片上喷施1～2次0.2％磷酸二氢钾液，这样则会使叶色显得更加美丽。但需注意施液肥时要避免沾污叶片，以免引起叶片枯焦。', '　　常春藤的栽培难度并不高，也是非常常见的管野', 'http://img.boqiicdn.com/Data/BK/P/imagick40671439804146.jpg', 'http://www.boqii.com/entry/detail/1948.html', '');
INSERT INTO `plant_family` VALUES ('402', '星美人', 'Pachyphytum oviferum', '星美人', '白美人、铜锤草、肥天', '不容易死', '原产墨西哥，现世界各地广泛载培', 'http://www.boqii.com/entry/photo/1972/0,http://www.boqii.com/entry/photo/1972/5555', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '厚叶草属', '星美人', 'Pachyphytum oviferum', '', '　　 　　星美人在冬季温暖、夏季冷凉的气候条件下', '　　', '　　　　扦插成活后的幼苗基部的节距较大，叶片较小；但是', 'http://img.boqiicdn.com/Data/BK/P/imagick44381440408395.jpg', 'http://www.boqii.com/entry/detail/1972.html', '');
INSERT INTO `plant_family` VALUES ('403', '酒瓶兰', 'Beaucarnea recurvata  Lem.', '酒瓶兰', '象腿树', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/2103/0,http://www.boqii.com/entry/photo/2103/5424', '', '', '', '', '', '', '', '', '', '　　 　　酒瓶兰为常绿植物，可以长到5m高，具有明显的庞大的茎，地下根肉质，茎干直立，下部肥大，状似酒瓶，可以　　　　　　　　　　　　　　', '　　的栽培难度并不高，由于酒瓶兰特别耐干旱，想要促使其基部膨大可以没半个月施肥一次。酒瓶兰的茎干主要用来储水，半年不浇水酒瓶兰仍然能够正常。　　1、：喜温暖，有一定的耐寒力，一般只要不结冰，就不会冻死。　　2、光照：喜光，也有一定的耐阴能力。忌强烈阳光曝晒，光照过烈会使叶尖枯焦、叶色变黄。5～9月应适当遮荫，遮去阳光的50％左右，或将植株置于散射光充足处，可利于叶片的生长。但也忌过于荫蔽，光照不足时植株的生长纤弱，叶片变得细瘦并呈黄绿色向下软垂。如果在光照不足处置放，连续摆放最好不要超过3～4周。其他时间则需给予充足的阳光。为防止株形偏冠，每隔1个月应将植株转换180°。　　3、浇水：因膨大的根茎部可贮藏水分，因而较耐干旱，涕水应掌握“宁干勿湿”的原则。忌水湿，盆土过湿易导致根系腐烂。置室外时，雨后要及时检查并倒去盆中的积水。但也不宜让盆土过干，否则会引起叶片发黄，甚至焦边。在冬季植株休眠阶段，要减少浇水，保持盆土较为干燥的状态。　　4、：生长时需要湿润的环境，温度高而天气干燥时，更需勤向植株及四周环境喷水，以保持较高的空气相对湿度，可使植株生长良好，叶色青翠而富有光泽。空气过于干燥，会使叶片出现干尖现象。　　5、施肥：酒瓶兰生长慢，不需要很多肥料。每月追肥1次氮磷钾肥料。注意要多施钾肥，可使根茎部长得更为肥大，观赏情趣更高。', '　　　\n　一、播种\n　　在深秋、早春季或冬季播种后，遇到寒潮低温时，可以用塑料薄膜把花盆包起来，以利保温保湿，幼苗出土后，要及时把薄膜揭开，并在每天上午的9：30之前，或者在下午的3：30之后让幼苗接受太阳的光照，否则幼苗会　　大多数的种子出齐后，需要适当地间苗：把有病的、生长不　\n　二、扦插\n　　酒瓶兰扦插常于春末秋初用当年生的枝条进行嫩枝扦插，或于早春用去年生的枝条进行老枝扦插。进行嫩枝扦插时，在春末至早秋植株生长旺盛时，选用当年生粗壮枝条作为插穗。把枝条剪下后，选取壮实的部位，剪成5～15公分长的一段，每段要带3个以上的叶节。　　剪取插穗时需要注意的是，上面的剪口在最上一个叶节的上方大约1公分处平剪，下面的剪口在最下面的叶节下方大约为0。5公分处斜剪，上下剪口都要平整（刀要锋利）。进行硬枝扦插时，在早春气温回升后，选取去年的健壮枝条做插穗。每段插穗通常保留3～4个节，剪取的方法同嫩枝扦插。　　扦插基质用来扦插的营养土或河砂、泥碳土等材料。家庭扦插限于条件很难弄到理想的扦插基质，海砂及盐碱地区的河砂不要使用，它们不适合', 'http://img.boqiicdn.com/Data/BK/P/imagick33841444468734.jpg', 'http://www.boqii.com/entry/detail/2103.html', '');
INSERT INTO `plant_family` VALUES ('404', '大丽花', 'Dahlia pinnata', '大丽花', '大理花、天竺牡丹、东洋菊、大丽菊、西番莲、地瓜花', '不容易死', '原产墨西哥热带高原，全世界广泛栽培。', 'http://www.boqii.com/entry/photo/2189/0,http://www.boqii.com/entry/photo/2189/5339', '', '', '', '', '', '', '', '', '', '　　 　　大丽花为多年生草本，有巨大棒状块根。茎直立，多分枝，高1.5－2米，粗壮。叶1－3回羽状全裂，上部叶有时不分裂，裂片卵形或长圆状卵形，下面灰绿色，两面无毛。头状花序大，有长花序梗，常下垂，宽6－12厘米。总苞片外层约5个，卵状椭圆形，叶质，内层膜质，椭圆状披针形。舌状花1层，白色，红色，或紫色，常卵形，顶端有不明显的3齿，或全缘；管状花黄色，有时在栽培种全部为舌状花。　　　　　　　　　　　　　　　　　　　　', '　　的花期长、花色鲜艳，由于大丽花的变种较多，所以外形也有很多不同，大丽花已经成为了世界上非常优美的。不论是盆栽还是庭院栽培，大丽花都会有其独特的美。　　大丽花的茎部脆嫩，经不住大风侵袭，又怕水涝，地栽时要选择地势高燥、排水良好、阳光充足而又背风的地方，并作成高畦。株行距一般品种1米左右，矮生品种40厘米～50厘米。大丽花茎高多汁柔嫩，要设立支柱，以防风折。浇水要掌握干透再浇的原则，夏季连续阴天后突然暴晴，应及时向地面和叶片喷洒清水来降温，否则叶片将发生焦边和枯黄。伏天无雨时，除每天浇水外，也应喷水降温。显蕾后每隔10天施一次液肥，直到花蕾透色为止。霜冻前留10厘米～15厘米根颈，剪去枝叶，掘起块根，就地晾1～2天，即可堆放室内以干沙贮藏。贮藏室温5C左右。　　盆栽大丽花以采用多次换盆为好。选用口面大的浅盆，同时把盆底的排水孔尽量凿大，下面垫上一层碎瓦片作排水层。土必须含有一半的沙土。最后一次换盆需施入足够的基肥，以供应充足的营养，其他管理同地栽。切花用大丽菊，栽培要点同地栽，株行距50厘米～100厘米，旺季半月追肥一次液肥，适当摘心，多保留侧枝。', '　　　　大丽花扦插全株各部位的顶芽、腋芽、脚芽均可，但以脚芽最好。扦插　　也有一些花友进行过水插、用　　之所以很多花友要尝试扦插大丽花，是因为大丽花的茎既空又脆，容易被风吹倒折断，所以应及时插竹扶持，插竹还可以避免枝条生长弯曲，提高盆栽观赏价值。当植株长高至30厘米以上时，应在每一枝条旁边插一小竹、并用麻皮丝（或细线绳）绑扎固定；随着植株越长越高，还应及时换上更长的插竹，最后插的小竹要顶在花蕾的下部。', 'http://img.boqiicdn.com/Data/BK/P/imagick33821446716143.jpg', 'http://www.boqii.com/entry/detail/2189.html', '');
INSERT INTO `plant_family` VALUES ('405', '倒挂金钟', 'Fuchsia hybrida Voss.', '倒挂金钟', '吊钟海棠、吊钟花、灯笼花', '不容易死', '原产墨西哥，中国西北、西南有栽培', 'http://www.boqii.com/entry/photo/2091/0,http://www.boqii.com/entry/photo/2091/5436', '　　', '被子植物门', '双子叶植物纲', '()目', '柳叶菜科', '倒挂金钟属', '倒挂金钟', 'Fuchsia hybrida Voss.', '', '　　 　　倒挂金钟为半灌木，茎直立，高50－300厘米，粗6－20毫米，多分枝，被短柔毛与腺毛，老时渐变无毛，幼枝带红色。叶对生，卵形或狭卵形，长3－9厘米，宽2.5－5厘米，中部的较大，先端渐尖，基部浅心形或钝圆，边缘具远离的浅齿或齿突，脉常带红色，侧脉6－11对，在近边缘环结，两面尤下面脉上被短柔毛；叶柄长2－3.5厘米，常带红色，被短柔毛与腺毛；托叶狭卵形至钻形，长约1.5毫米，早落。', '　　倒挂金钟又称吊钟海棠，在北方冬春主要是温室盆栽，也是现在非常常见的家庭室内。倒挂金钟的品种比较多，鲜艳，有重瓣和单瓣。有新手朋友可能对倒挂金钟的栽培不了解，就让小编为你介绍一下倒挂金钟的栽培方法。　　盆栽土壤宜用腐叶土（或草屑）50％，沙壤土40％，腐熟饼肥干10％，合三为一为培养土，通常每年春季翻盆换土一次，新土营养全面，则有利于孕蕾开花。　　倒挂金钟春、秋生长迅速，在开花期，每天浇水1～2次，宁湿勿干。但平时浇水要掌握“见干见湿”的原则，春气干燥，夏季炎热高温季节除每天浇水一次外，还需每天向枝叶上喷洒1～2次叶面水，但不可浇水过多而造成盆土积水。在开花期间，盆土过干或过湿，容易造成落蕾、落花、落叶。盆土长期过湿，还会导致烂根、黄叶乃至倒挂金钟整株。冬季室温低时，更严格控制浇水同时也要停止施肥，以防烂根。夏季倒挂金钟在7～8月，不要多浇水，谨防雨淋，淋雨会引起烂根、落叶甚至死亡。　　倒挂金钟平常结合松土每7一10天可施一次稀薄有机液肥，但在炎夏季节，气温高，迫使倒挂金钟一般都进入休眠或半休眠期，夏季的7～8月生长缓慢，应停止施肥，稍浇清水，9一12月每隔10～15天浇一次腐熟的饼肥水，促其陆续开花不断。每次施肥或浇水后，次日要进行松土，以利于透气。　倒挂金钟性喜凉爽气候，最怕炎热高温、日晒和雨淋，因此应注意做好降温增湿。家庭盆栽倒挂金钟夏季当气温超过25℃以上时应移入室内通风阴凉之处，并做好降温工作。可放于风扇下吹风，并扒开盆土，将其根裸露，吹风散热，并在盆花周围的地面洒水和喷叶面水，以减少辐射热、降温增湿为盆花人为地营造一个高湿度的小气候和度夏安全环境。其冬季也畏寒怕冻，若不及时收藏于室内，一定的时间将会冻伤而很难成活。　夏季的6～7月上旬，可将倒挂金钟的叶子可全剪除使其逐渐休眠安全度夏。休眠后的秋初结合翻盆将长枝短截，由于枝茎细长下垂，太密的需摘心整形。摘心时，注意留芽方向及小枝长度，注意保持植株丰满匀称。摘心半月后，长出的新梢又可开花，所以整枝修剪是保证倒挂金钟多开花的一种技法。　　以上所述是一般的修剪方法，若使倒挂金钟多开花可用以下方法：　　倒挂金钟开花通常是在新梢叶腋间着生的花蕾，要让其多开花，就必须多发分枝，而适期摘心是倒挂金钟多生分枝的一项重要措施。一般情况下，幼苗长到约10cm高时，可进行第一次摘心，促使其生分枝，约经一个月，新枝长出6～8片叶时，再进行第二次摘心，并将多余的叶去掉。每株保留5～7个枝条即可。秋凉后，可将太长的枝条剪短，过密的枝条疏掉，使其促发健壮的新枝。每次修剪后都应减少浇水量，待新芽长出后，再逐渐增加浇水量，再转入正常管理。再者倒挂金钟花后可摘心，条件适合的，摘心25天后，新梢又可以开花，一般有养花经验的人利用它的这一习性调节花期，让其陆续不断地开花。多年的老株对高温敏感性强，怕热，抗性差，容易落叶和开花不良，从根本上解决了这一弊病最好是每隔一年培育新株菌养，新株健壮抗性强，炎夏不落叶，开花多而好，这是菌养倒挂金钟的一项积极有效措施。', '　　　　\n1、扦插时间：\n　\n　2、插穗的选择：\n　　\n3、扦插基质及插床的准备：\n　\n　4、扦插方法：\n　\n　5、插后管理：\n　\n　6、幼苗上盆：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick33171443604455.jpg', 'http://www.boqii.com/entry/detail/2091.html', '');
INSERT INTO `plant_family` VALUES ('406', '虎耳草', 'Saxifraga stolonifera Curt.', '虎耳草', '石荷叶、金线吊芙蓉、老虎耳、金丝荷叶、耳朵红', '不容易死', '中国、朝鲜、日本', 'http://www.boqii.com/entry/photo/2066/0,http://www.boqii.com/entry/photo/2066/5461', '', '', '', '', '', '', '', '', '', '　　 　　虎耳草为多年生草本，高8－45厘米。鞭匐枝细长，密被卷曲长腺毛，具鳞片状叶。茎被长腺毛，具1－4枚苞片状叶。基生叶具长柄，叶片近心形、肾形至扁圆形，长1.5－7.5厘米，宽2－12厘米，先端钝或急尖，基部近截形、圆形至心形，（5－）7－11浅裂（有时不明显），裂片边缘具不规则齿牙和腺　　　　　　　　　　　　　　　　　　　　　　　　　', '　　虎耳草是比较耐阴的，所以非常适合在光线较弱的环境下，人工栽培可将虎耳草布置在大型植物下部的阴暗处，也可以单独盆栽，放在花架、茶几上都非常好看。虎耳草的栽培难度并不高，但是需要科学养护才能将虎耳草养好。　　1、春季：适合布置在东、南、西、北朝向阳台上。每年早春换盆1次，换盆前对地上部分进行适当的修剪。盆土最好使用疏松、肥沃、富含腐殖质的土壤。虎耳草喜阴湿，可长年布置在有散射光的阳台一角。春季是虎耳草的生长旺季，应保持盆土的湿润，同时每天向其四周和叶片喷雾洒水数次，以满足其对空气湿度的要求。　　2、夏季：适合布置在东、北朝向阳台上。虎耳草不耐高温，更不耐烈日。夏季气温较高时虎耳草生长不良，应注意补充空气湿度，加强通风降温。气温过高时使盆土略偏干。　　3、秋季：适合布置在东、北朝向阳台上。秋季是虎耳草的又一生长旺季，应注意水肥的供应。秋末气温下降后应注意保持，否则，地上部枯死，根部进入休眠。秋末，可将虎耳草布置于5℃以上室内，虎耳草仍不休眠，仍具观赏性。此时应逐步将其移至有早晚光照的窗台处，其他管理同春季。　　4、冬季：适合布置在东、南、西朝向阳台上。虎耳草不耐寒。如冬季室内气温保持在5℃以上，可，仍具观赏性。冬季应布置在早晚有光照的地方，适当的冬季光照有利于其生长。冬季保持盆土湿润即可，中午气温较高时向其四周喷雾洒水数次。冬季室温较低，虎耳草地上部分枯死，进人休眠。此时应使盆土偏干，并将盆放置在0℃左右的地方越冬。', '　　　　分株方法：春末至秋初将匍匐枝上的小植株剪下，集中植于浅　　播种在3—4月份进行，约半月后即可出苗。', 'http://img.boqiicdn.com/Data/BK/P/imagick34131443001212.jpg', 'http://www.boqii.com/entry/detail/2066.html', '');
INSERT INTO `plant_family` VALUES ('407', '虎尾兰', 'Sansevieria trifasciata Prain', '虎尾兰', '虎皮兰、千岁兰、虎尾掌、锦兰', '不容易死', '非洲及亚洲南部，中国各地有栽培', 'http://www.boqii.com/entry/photo/2048/0,http://www.boqii.com/entry/photo/2048/5479', '', '', '', '', '', '', '', '', '', '　　 　　虎尾兰有横走根状茎。叶基生，常1－2枚，也有3－6枚成簇的，直立，硬革质，扁平，长条状披针形，长30－70（－120）厘米，宽3－5（－8）厘米，有浅绿色和深绿色相间的横带斑纹，边缘绿色，向下部渐狭成长短不等的、有槽的柄。　　　　　　　　　　　　　　　　　　　　　　　　', '　　虎尾兰的适应力比较强，并且还具有一定的装饰性，是很多朋友都非常的室内观叶植物。虽然虎尾兰的栽种难度并不高，但是想要自己的虎尾兰能够健康漂亮还是需要在栽种过程中注意许多问题的，小编就为你整理了在虎尾兰栽种过程中比较常见的八大问题。　　　　虎皮兰土质需求疏松，需要透气性，所以在为虎皮兰配土的时候，一定要注意用2／3的腐叶，外加1／3的园土，切记土一定要疏松透气，不然就会造成水分不易蒸发，导致根茎的。　　　虎皮兰喜光，所以一定要让它时常阳光，最好是能放在可以直接被照射的地方，如果条件不允许的话，那也要放在里阳光比较近的地方，长时间置于阴暗的地方，会造成叶子的发黄。　　　虎皮兰对温度的要求颇高，它的适宜温度为20一30℃，在是最低不要低于10℃，所以一定要注意，特别是在北方地区。　　　虎皮兰对水的要求也颇高，一般来说土质比较疏松的话，每个星期需要浇水两次，而冬天因为气候的因素，则只需要一次就可以了。　　　虎皮兰的生长速度相对于其他家养绿色植物来说，生长的比较快，因此但盆内长满时，就要进行人工修剪，主要是把老叶和过于茂盛的地方剪除，保证其阳光和生长空间。　　　　虎皮兰是多年生植物，一般来说每两年就要给它换一次盆，在换盆的时候要注意在新土中加入养分，这样才能保证它的营养供应。　　　　虎皮兰是根发植物，一般来说只需要种上几株，一年之后，就能收获满盆，在种植时，要先将一部分土垫在盆的下面，然后从盆的一侧开始种植，均匀的种植在盆内。　　　虎皮兰对肥的要求不高，只需要在生长季每月施肥2次就可以了，注意要施稀薄肥液，这样才能保证生长茂盛。', '　　　　\n一、分株法：\n　　\n二、扦插法：\n　　扦插时注意不要倒插，插后注意保持一定的湿度，当扦插基质稍干后，用细眼喷壶喷水，但也不宜过湿，以免　　其他', 'http://img.boqiicdn.com/Data/BK/P/imagick29661442482550.jpg', 'http://www.boqii.com/entry/detail/2048.html', '');
INSERT INTO `plant_family` VALUES ('408', '郁金香', 'Tulips', '郁金香', '洋荷花、草麝香、郁香、荷兰花', '不容易死', '', 'http://www.boqii.com/entry/photo/1951/0,http://www.boqii.com/entry/photo/1951/5576', '', '', '', '', '', '', '', '', '', '　　郁金香是非常常见的冠花之舞，原产于我国古代西域及新疆、西藏一带，所以在古代诗词中也能发现有关郁金香的古诗词的描绘。盆栽郁金香的花友并不多，但是 　　郁金香为多年生草本。鳞茎卵形，直径约2cm，外层皮纸质，内面顶端和基部有少数伏毛。花型有杯型、碗型、卵型、球型、钟型、漏斗型、　　　　　　　　　　　　　　　　　　　　　', '　　由于成片开放的样子比起单株更漂亮，所以在家中单株栽培郁金香的朋友并不多，但是还是有花友会自己在家尝试。郁金香原产于我国古代西域及西藏新疆一带，所以形成了郁金香适应冬季的湿冷和夏季干热的习性特点，此外，夏季是郁金香的，花友们需注意夏季郁金香的养护方法。　　选向阳、排水良好的沙质壤土或粘壤土，地下水位55厘米～70厘米，PH6.5～PH7。栽种前要充分翻耕土壤，并施以有机肥。　　栽种深度及距离因鳞茎大小而定，一般深度为鳞茎高的2倍或略浅。株行距一般10X10厘米。栽种前要调节好土壤水分，要求不干不湿，栽种覆土后不再浇水，覆盖干草一薄层即可，以防止土壤板结和保持土壤湿度。　　种植随栽培目的而异，为使其在自然状态下开花的花坛布置及庭园种植，一般在秋季种植；如作为鲜切花生产的促成栽培，则应根据鲜花上市时间来确定。11月中旬至12月上旬上市者，需超促成栽培，9月中下旬栽植。一般促成栽培是在9月下旬至10月上旬定植，12月上旬至次年1月上旬即可上市。半促成栽培是10月中旬至11月中旬定植，1月中旬至3月下旬上市。　　对肥料要求不高，但在地力低的土壤应追施肥料，肥料可用腐熟堆肥及迟效性颗粒化肥等作为基肥一次性施入，但要防止肥料施用时与鳞茎直接。如基肥不足，春季可追一些氮肥。期间一般不必浇水，保持土壤湿润即可，天气干旱时可适量灌水。　以生产鳞茎为目的时，花蕾见色就要摘除，以减少养分消耗，保证鳞茎生长。早上露水未干不宜搞蕾，以防病菌传播。以生产切花为目的者，可待花蕾充分着色后剪取，根据高矮和花的大小分选，包装。远距离运输的切花，要使其稍许萎凋之后再包装；近距离上市者，则要充分吸水后再装箱。', '　　　　郁金香通常以分球繁殖为主。6月上中旬，将休眠鳞茎掘起，按大小分级贮藏，至10～11月间分别栽种。较大的鳞茎翌春开花，较小的鳞茎多数需继续　　在杂交育种时可采用种子繁殖。种子不休眠，但发芽需要低温，适宜的低温是5C左右，10C以上发芽延缓，25C以上不发芽。在适宜的条件下，发芽率可达90％以上。播种后40～45天即可发芽。发芽后，幼苗在13C下约70天后转移到23C下，可加快子球成熟。在南京地区，11月露地冷框秋播，利用冬季的自然低温，翌春2月中旬发芽。从发芽到收获子球需135天左右。夏季地上部休眠时挖起小鳞茎置20C～25C下贮藏，秋季栽种，照此培植4～5年后开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick43181439805316.jpg', 'http://www.boqii.com/entry/detail/1951.html', '');
INSERT INTO `plant_family` VALUES ('409', '飞燕草', 'Consolida ajacis （L.） Schur', '飞燕草', '大花飞燕草、鸽子花、百部草、鸡爪连、干鸟草、萝小花、千鸟花', '不容易死', '欧洲南部，中国有栽培', 'http://www.boqii.com/entry/photo/2082/0,http://www.boqii.com/entry/photo/2082/5445', '', '', '', '', '', '', '', '', '', '　　 　　飞燕草茎高约达60厘米，与花序均被多少弯曲的短柔毛，中部以上分枝。茎下部叶有长柄，在开花时多枯萎，中部以上叶具短柄；叶片长达3厘米，掌状细裂，狭线形小裂片宽0.4－1毫米，有短柔毛。　　　　　　　　　　毛茛科　　　　　　　　　', '　　飞燕草又名千鸟草、萝卜花等，阳光充足的环境，较耐寒。经过人们不断的繁殖，现在飞燕草的品种也越来越多了，那么飞燕草在栽种过程中应该注意哪些问题呢？　　1、移植：萌芽后6至9周，便可将每株幼苗移植到口径为9至10厘米的花盆中，或者将每3株幼苗移植到口径为13至15厘米的大花盆中。移植时不要将植株种得太深。　　2、基质：栽培基质需排水良好，基质中粘土含量为10％至30％，可加入10％至15％左右的树皮、珍珠岩，每立方米基质中施加1至2千克，2至4千克的缓效肥。基质中应含有铁螯合物和微量营养元素，pH值为5.8至6.5。　　3、光照：为中日照植物。盆栽植株在冬季和春季需补光，同时要结合长日照（14小时）进行培养，这可以提高植株的品质和减少2至3周的栽培。　　4、：适温为13℃至16℃。冬季无霜的条件下，温度可保持在3℃至5℃间。室外栽培需覆盖且栽培基质要保持干燥。春季植株开始在15℃至20℃的温度条件下8至10周。　　5、栽培提示：需干燥、阳光充足和通风透气的栽培环境。植株间需保持一定的间距以保证空气能够良好流通。', '　　飞燕草可用于花坛装饰及边缘绿化，可以盆栽或　　飞燕草果实内种子多，种子较细小，采集后晾干置室内阴凉干爽处贮藏。为了多季开花可分期播种，但南方栽培应使花期错开盛夏暑热天。飞燕草为直根系　　另外，同属异种的多年生飞燕草还可用扦插和分株繁殖。扦插育苗在春季进行，采摘插于湿沙床或沙盘内。分株春秋均可进行，将老株四周萌发的小苗，带根挖起，分割为小株种植，若春季分株当年即可开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick37951443432010.jpg', 'http://www.boqii.com/entry/detail/2082.html', '');
INSERT INTO `plant_family` VALUES ('410', '朱顶红', 'Hippeastrum', '朱顶红', '柱顶红、孤梃花、华胄兰、百子莲、炮打四门', '不容易死', '原产秘鲁和巴西一带。', 'http://www.boqii.com/entry/photo/2163/0,http://www.boqii.com/entry/photo/2163/5364', '', '', '', '', '', '', '', '', '', '　　 　　朱顶红的鳞茎近球形，直径5－7.5厘米，并有葡匐枝。叶6－8枚，花后抽出，鲜绿色，带形，长约30厘米，基部宽约2.5厘米。花茎中空，稍扁，高约40厘米，宽约2厘米，具有白粉；花2－4朵；佛焰苞状总苞片披针形，长约3.5厘米；花梗纤细，长约3.5厘米；花被管绿色，圆筒状，长约2厘米，花被裂片长圆形，顶端尖，长约12厘米，宽约5厘米，洋红色，略带绿色，喉部有小鳞片；雄蕊6，长约8厘米，花丝红色，花药线状长圆形，长约6毫米，宽约3毫米；子房长约1.5厘米，花柱长约10厘米，柱头3裂。花期夏季。　　　　　　　　　　　　　　　　　　　', '　　朱顶红的栽培方法比较简单，多数情况下，将种球查到土里就能枝繁叶茂。但是，想要养好朱顶红却不是那么简单，如果是进口的朱顶红种球，就更需要谨慎对待了。　　1、种球。把球根已经腐朽、干枯的根须剪掉，残存的健康根系继续保留。如果种球外部有多层褐色干枯的外皮，可剥掉部分，最大限度的消除引发溃烂的隐患。　　2、种球补水。如果种球由于期较长失水较多，最好给种球补水，即用比环境温度稍高些的清水浸泡种球中下部1、2个小时，有经验的可在水中加一些赤霉素等激素，又利生根及后期种球膨大，但应注意浓度与浸泡，否则会弄巧成拙。　　3、消毒。是种植的关键环节，一般采用常见的多菌灵、百菌清、甲基托布等消毒剂按说明进行即可，结束后消毒水在种植好后用于浇灌，达到消毒土壤的目的。　　4、介质选择。有限的种植空间下，介质的选择十分重要。朱顶红种植以酥松、透水偏酸性的介质为宜。推荐的介质为泥炭：：珍珠岩＝2：1：1或泥炭：珍珠岩＝1：1构成。不方便的情况下可用一般腐质土替代泥炭，河沙替代珍珠岩。介质中最好拌入10％的骨粉、过磷酸钙等基肥。　　5、种植深度。球根刚种下时，至少露出多半个球体，并经常检查球根的状态，因为这个时段球根非常容易发生溃烂现象，等度过这个时段后，球根的根叶长出了，再覆土到球根的1／2或2／3。　　6、浇水。种植后一次浇透，等盆土基本干透后再浇水，球根出叶前除底肥外，不要另外施肥。　　7、放置环境。种植后先放置在10－15℃的阴凉处以利生根，二周后再移到20－25℃较高温度处以便花箭抽出。', '　　　　\n1、分球繁殖\n　　分球繁殖于3～4月进行，将母球周围的小球取下另行栽植，栽植时覆土不宜过多，以小鳞茎顶端略露出土面为宜。此法繁殖，需经2年培育方能开花。　\n　2、分割鳞茎法繁殖\n　　分割鳞茎法繁殖一般于7－8月份进行。首先将鳞茎纵切数块，然后，再按鳞片进行分割，外层以2鳞片为一个单元，内层以3鳞片为一个单元，每个单元均需带有部分鳞茎盘。此法繁殖，若被分割的鳞茎直径为6cm以上，则每球可分割成20个以上双鳞片和三鳞片的插穗，将插穗斜插于基质中（pH值最好为8左右），保持25～28℃和适当的空气湿度，30～40天后，每个插穗的鳞片之间均可产生1～2个小鳞茎，而且基部生有根系，此法繁殖的小鳞茎，需　　\n3、鳞片扦插繁殖\n　　选发育良好的无病鳞茎，剥去外层过分老熟的鳞片，留下生长充实的中部鳞片供繁殖，但每个鳞片必须带茎盘。9月将鳞片插植沙床，在18℃～20℃下，保持湿润，当年形成小鳞茎、基部生根。翌春于小鳞茎上长出新苗，需继续培养3年成为开花的鳞茎。　　\n4、刻伤法繁殖\n　　选择鳞茎周径24～26厘米种球，将鳞茎用1％硫酸铜液浸5分钟，用水洗净后，切去鳞茎的1／3，用刀轻轻刻伤鳞茎中心的主芽，平放在沙床上，室温保持18～22℃，维持较高的空气湿度，2个月后在鳞片之间形成若干小鳞茎。　　\n5、播种法繁殖\n　　由于朱顶红种子扁平、极薄，容易失水，丧失发芽力，应采种后即播。如种球　\n　6、组织培养法繁殖\n　　常用MS培养基，以茎盘、休眠鳞茎组织、花梗和子房为外植体。经组培后先产生愈伤组织，30天后形成不定根，3～4个月后形成不定芽。', 'http://img.boqiicdn.com/Data/BK/P/imagick43841446109964.jpg', 'http://www.boqii.com/entry/detail/2163.html', '');
INSERT INTO `plant_family` VALUES ('411', '芙蓉雪莲', 'Echeveria laui x lindsayana', '芙蓉雪莲', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2287/0,http://www.boqii.com/entry/photo/2287/5238', '', '', '', '', '', '', '', '', '', '　　 　　芙蓉雪莲的叶片较　　　　　', '　　芙蓉为景天科属多肉植物，在台湾地区又叫大雪莲。但是很多朋友对于雪莲和芙蓉雪莲会分辨不清，小编在之前的文章中有详细介绍过这两者的区别。那么芙蓉雪莲的栽培应该注意哪些呢？　芙蓉雪莲比较喜欢日照，对水分需求较少。浇水秉持干透浇透，注意不要浇到叶片上，因为白粉会被冲掉，再生的话比较困难，影响美观。盛夏高温要注意遮阴，保持土壤干燥，可一个星期浇点水。　芙蓉雪莲的期是春秋二季，培植时应用疏松透气的植料，如煤渣3份＋1份＋草木灰1份＋河沙1份＋园土3份＋珍珠岩1份这样子的，生长期可以是全日照，如果光照短了，就容易徒长，新叶子上的白粉也会很少，影响美观。', '　　芙蓉　　芙蓉雪莲比较喜欢日照，根系生长', 'http://img.boqiicdn.com/Data/BK/P/imagick64991449221190.jpg', 'http://www.boqii.com/entry/detail/2287.html', '');
INSERT INTO `plant_family` VALUES ('412', '蔷薇花', 'Rosa multiflora Thunb.', '野蔷薇', '多花蔷薇', '不容易死', '', 'http://www.boqii.com/entry/photo/2014/0,http://www.boqii.com/entry/photo/2014/5513', '', '', '', '', '', '', '', '', '', '　　 蔷薇 　　蔷薇花多朵，排成圆锥状花序，花梗长1.5－2.5厘米，无毛或有腺毛，有时基部有篦齿状小苞片；花直径1.5－2厘米，萼片披针形，有时中部具2个线形裂片，外面无毛，内面有柔毛；花瓣白色，宽倒卵形，先端微凹，基部楔形；花柱结合成束，无毛，比雄蕊稍长。　　　　　　　　　　　　　　　　　　　', '　　家庭栽种蔷薇一般多用于盆栽观赏，还可以作为的遮阴。有的朋友蔷薇，但是却不知道蔷薇应该如何种植，小编就为你整理了如何栽培蔷薇的方法，喜欢蔷薇的朋友可以一起了解。蔷薇　　蔷薇花的适应性颇广，我国除冬季严寒越冬外，南方广大地区，均宜种植。野生蔷薇少有病虫害，人工栽培的常有锯蜂、、蚜虫以及焦叶病、病、黑斑病等病虫害。除应注意用药液喷杀外，布景时应与其他花木配置使用，不宜一处种植过多。每年冬季，对老枝及密生枝条，常进行强度修剪，保持透光及通风良好，可减少病虫害。修剪，为蔷薇造景整形中不可缺少的重要工序、修剪不善，长成刺蓬一堆，参差不齐，不仅病虫害多，外形亦不雅观。　　植株蔓生愈长，开花愈多，需要的养分亦多，每年冬季需培土施肥1次，保持嫩枝及花芽繁茂，景色艳丽。培育作盆花，更应注意修枝整形。切花因产花量大，产花季每周需施肥1～2次，并应注意培育采花母枝，剪去弱枝上的花蕾。', '　　　　蔷薇花种子可供育苗，但　　扦插要点：　　1、扦插时间：除了夏季，其他时候都可以。　　2、枝条的选择：当年上年的无病害的枝条均可（半木质化的最佳）。　　3、枝条的处理：枝条粗细（0.2cm－0.8cm直径都可以），长度（8cm－15cm长都可以），留3－4节，土中埋1－2节。　　4、扦插的介质：有条件的可以用纯蛭石或者珍珠岩来扦插，如果没有条件的用普通园土也可以。　　5、扦插后', 'http://img.boqiicdn.com/Data/BK/P/imagick10701441705427.jpg', 'http://www.boqii.com/entry/detail/2014.html', '');
INSERT INTO `plant_family` VALUES ('413', '南洋杉', 'Araucaria cunninghamii Sweet', '南洋杉', '', '不容易死', '澳大利亚和新几内亚，中国的广州、海南岛、厦门等地', 'http://www.boqii.com/entry/photo/1896/0,http://www.boqii.com/entry/photo/1896/5633', '', '', '', '', '', '', '', '', '', '　　 　　　1、土壤：南洋杉养殖盆土用腐叶土、园土、河沙各1／3另加少里基肥配制最适合。　　2、浇水：南洋杉性喜湿润环境，为此，干旱季节和夏季应　　3、光照：南洋杉喜阳光充足，北方地区一般于5月上旬搬到南面阳台上或庭院向阳处，入夏后注意适当遮阴，避免曝晒。北方地区莳养，9月底10月初就要移入室内，放在阳光充足处，控制浇水　　4、温度：南洋杉可在多种不同的气温下　　5、施肥：南洋杉生长较迅速，因此在其生长旺盛季节，需要经常施追肥，以补充其生长所需养分。一般从春季新芽萌发时开始，每月注意追施1－2次腐熟稀薄饼肥水，供其吸收利用，才能生长健壮。　　6、修剪：南洋杉易出现下部枝叶逐渐枯黄脱落的现象，造成整个植株头重脚轻，影响美观，在养护上要加以精心管理，进行必要的修剪。　　7、虫害：南洋杉的病害有叶斑病、枝枯病和根瘤病等。叶斑病、枝枯病可选川70％甲基托布津8（“倍液或65％代森锌可湿性粉剂500一600倍液喷洒防治；溃疡病用40％福美砷100倍液或高锰酸钾1001〕倍液涂抹消毒；根瘤病用链霉素1000倍液浸泡。虫害主要有介壳虫危害，少量发生时，用清水冲洗叶片，较严重时，可用40％的氧化乐果乳剂500一1000倍液喷杀。 　　　1、松土浇水　　定植后及时浇水和松表土，减少水分蒸发。平时浇水要适度，生长季节勤浇水，每周浇2～3次，渗深10～15厘米为宜。随着苗木的生长，浇水次数减少，经常保持盆土及周围环境湿润，严防干旱和渍涝。高温干旱时节，应常向叶面及周围环境喷水或喷雾，增加空气湿度，保持土壤湿润。忌夏季盆土过干或冬季水量过大，过干或过湿都易引起下层叶垂软。夏季避免强光曝晒，可置于棚内遮荫处，经常洒水，以保持较高的空气湿度。　　2、整形管理　　南洋杉以株姿直立挺拔为美，在扦插苗的第2年，或者播种苗长至50厘米左右时，应立棍裹扎支撑，以防植株扭曲，影响观赏效果。幼树宜每年或隔年春季换盆1次，五年以上植株每两三年翻盆换土1次，并结合喷洒矮壮素，控制南洋杉的高度。北方地区于4月末或5月初出室放避风向阳处养护，盛夏需适当遮荫，生长季节适时转盆，以防树形生长偏斜，影响观赏。南洋杉不耐严寒，北方地区于9月末或10月初（寒露）移入室内，放阳光充足、空气流通处，禁肥控水，室温不得低于8℃。　　3、勤施肥料　　盆栽南洋杉宜用腐叶土、草炭土、纯净河沙及少量腐熟的有机肥混合配制。盆土以3份壤土、1份腐叶土、1份粗砂和少量草木灰混合为好，土层的深度掌握在上层生根的芽点刚好露在土面上。自春季新芽萌发开始，每月追施1～2次腐熟的稀薄有机液肥和钙肥，可保持株姿清新，叶色油润。　　南洋杉树形高大，既能作为家具盆栽装饰用树种，也能单独种植作为园景树或纪念树，还能作为行道树，南洋杉是世界着名的庭园树之一。如果你在家中饲养了南洋杉，好好饲养的话，能够为你的家居环境带来一番不一样的景色。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick981428055093.jpg', 'http://www.boqii.com/entry/detail/1896.html', '');
INSERT INTO `plant_family` VALUES ('414', '水塔花', 'Billbergia pyramidalis Lindl.', '水塔花', '火焰凤梨、比尔见亚、红藻凤梨、水槽凤梨、红笔凤梨', '不容易死', '', 'http://www.boqii.com/entry/photo/2208/0,http://www.boqii.com/entry/photo/2208/5319', '', '', '', '', '', '', '', '', '', '　　 　　水塔花为草本，茎极短。叶莲座状排列，6－15片，阔披针形，长30－45厘米，直立至稍外弯，顶端钝而有小锐尖，基部阔，边缘至少在上半部有棕色小刺，上面绿色，背粉绿。穗状花序直立，略长于叶；苞片披针形至椭圆状披针形，长5－7厘米，粉红色；萼片有粉被，暗红色，长约为花瓣的1／3，裂片钝至短尖；花瓣红色，长约4厘米，开花时旋扭；雄蕊比花瓣短；子房有粉被。水塔花叶的基部常保持相当量的水分，虽在热带地区最高温度的时候，从未见份量减少或缺少的，有些蚊子专以此为繁殖地。　　　　　　　　　　　　　　　　　凤梨科凤梨亚科　　　　　　　　　　　　　　　　　　', '　　又名火焰凤梨、水槽凤梨等，原产于巴西，现在已经成为了我国良好的室内盆栽观叶。水塔花喜温暖、湿润、半荫的环境，但是不耐寒，人工栽培水塔花应根据四季特点做出相应的环境布置。　　1、冬季保温。冬季要放在温室内，5～10℃可越冬，15℃左右则生长良好。家庭中培养，白天应将盆株放在室内朝南向阳窗口处，充分接受阳光；傍晚把植株移到远离门窗处，防止受冻。　　2、春季翻盆。可于4月份进行翻盆换土，盆土宜用排水性能好、酸性的泥炭土。翻盆后移置室外荫棚下过夏，经常保持较高的空气湿度。　　3、夏季防暑。夏季超过30℃，植株会处在半休眠状态，这时应放在荫棚下，避免强烈阳光照射，同时应经常向地面喷水，以增加空气湿度，起到防暑降温作用。　　4、肥水管理。春秋生长期约2周施1次腐熟的饼肥水；秋季花前增施1～2次磷肥，能使花色鲜艳。大伏天及严冬应停施肥料。盆土常保湿润，并常保持较高的空气湿度，但忌盆土过湿和盆内积水，以防烂根，导致整株。', '　　　　1、分株时间：最好是在早春（二、三月份）土壤解冻后进行。　　2、分株方法：把母株从花盆内取出，抖掉多余的盆土，把盘结在一起的根系尽可能地分开，用锋利的小刀把它剖开成两株或两株以上，分出来的每一株都要带有相当的根系，并对其叶片进行适当地修剪，以利于成活。　　3、装盆　　4、分株后的管理：分株装盆后灌根或浇一次透水。由于它的根系受到很大的损伤，吸水能力极弱，大约需要3～4周才能恢复萌发新根，因此，在分株后的3～4周内要节制浇水，以免烂根，但它的叶片的蒸腾没有受到影响，为了维持叶片的水分平衡，每天需要给叶面喷雾1～3次（温度高多喷，温度低少喷或不喷）。这段时间也不要浇肥。分株后，还要注意太阳光过强，最好是放在遮荫棚内　　5、上盆或移栽：小苗装盆时，先在盆底放入2～3公分厚的基质，然后再加入基质，直到离盆沿约2～3公分。上盆用的基质可以选用下面的一种：草炭：珍珠岩：陶粒＝2：2：1；或者草炭：', 'http://img.boqiicdn.com/Data/BK/P/imagick54821447234250.jpg', 'http://www.boqii.com/entry/detail/2208.html', '');
INSERT INTO `plant_family` VALUES ('415', '绿萝', 'Epipremnum aureum', '绿萝', '魔鬼藤、黄金葛、黄金藤、桑叶', '不容易死', '原产于所罗门群岛，广东、福建、上海栽培', 'http://www.boqii.com/entry/photo/1924/0,http://www.boqii.com/entry/photo/1924/5605', '', '', '', '', '', '', '', '', '', '　　绿萝是非常常见的室内 　　绿萝属阴性植物，喜湿热的环境，忌阳光直射，喜阴。喜富含腐殖质、疏松肥沃、微酸性的土壤。　　　　　　　　　　　　　　　　　　　　　', '　　的栽培难度非常低，所以又有“生命之花”的美称，在环境非常恶劣的情况下，绿萝只要有水就可以存活，并且室内盆栽或是露地栽培都可以让绿萝长的很好。虽然绿萝是非常适合在室内栽培的观叶，但是长期摆放在阴暗处，会使绿萝的叶片变小、叶色淡化等情况，所以即使栽培在室内的绿萝也是需要定期给予光照的。　　1、多浇水。绿萝喜欢生活在湿润的环境，所以多浇水最好，天气炎热，水分散失快，除了多浇水还应该给页面喷水，浇水多少根据盆土而定，绿萝植株大的就应该多浇水。　　2、避免暴晒。绿萝层级生长在大树下的荫蔽地方，所以它是一种喜阴植物，不能在阳光下暴晒，否则刚发芽的新叶会失水变小，颜色暗淡，同时易灼伤叶缘。主需要提供进行光合租用的阳关足矣。　　3、适当的温度。绿萝虽然不喜欢烈日，但对温度还是很敏感的，温度太低就容易被冻伤，室温20度左右就可以了，如果开设暖气设备，绿萝叶子不能离其太近，室内温度控制在10度以上，绿萝就可以度过冬天。　　4、施肥。由于室内养殖，绿萝吸收养分没有室外充足，建议每隔半个月施一次肥料，可以在市场上买专门供绿萝使用的肥料。或者询问花店老板，让其帮忙选肥料。　　5、保持空气湿度。绿萝在空气湿度较大的环境中生长较快，建议保持室内湿度，可以使用加湿器增加空气湿度。具体方法可以给绿萝周围喷水。　　小贴士：水培绿萝一般放在室内的朝阳地方生长可以保持温暖的温度和比较好的光照促进植物生长，另外它不可以直接接受太阳的照射，冬季尤其是在我国北方种植的冬季非常寒冷这时候要适当地采取保温措施。在水培绿萝生长不同阶段要根据生长需要进行追加施肥保证营养供给。水培绿萝对水分要求比较大，要使的土壤保持湿润，一个月浇一次大水，然后每天可以擦拭叶子保证鲜活。定期对水培绿萝进行修剪保持枝叶的有型和翠绿，并要对病虫害进行和治疗。', '　　　　茎插和叶插繁殖的方法：春秋季剪取长15～30cm的两节茎段作插穗，将基部1～2节叶片去掉，修平切口，插入素沙中即可生根。叶插法，用洁净锋利的小刀片，切取上部健壮叶片，用清水洗净后放阴凉处数小时，使切口稍干，然后将叶柄基部插入　　绿萝也可用压条繁殖。可在砂盆内进行，将盆内的绿萝匍匐茎压上土或砂，气生根入土后即能生根，待长出新叶，就可剪断分栽。', 'http://img.boqiicdn.com/Data/BK/P/imagick46701439198388.jpg', 'http://www.boqii.com/entry/detail/1924.html', '');
INSERT INTO `plant_family` VALUES ('416', '长寿花', 'winter pot kalanchoe', '圣诞伽蓝菜', '长寿花、圣诞长寿花、矮生伽蓝菜、寿星花、家乐花、伽蓝花', '', '', 'http://www.boqii.com/entry/photo/1928/0,http://www.boqii.com/entry/photo/1928/3184', '', '', '', '', '', '', '', '', '', '　　很多朋友都不知道长寿花其实是多 　　圣诞伽蓝菜是常绿多年生草本多浆植物。植株小巧，茎直立，株高10－30厘米。叶对生，叶片密集翠绿，长圆状匙形或椭圆形，长4－8厘米，宽2－6厘米，肉质，叶片上部叶缘具波状钝齿，下部全缘，亮绿色，有光泽，叶边略带红色。叶片属厚肉质，密集深绿，有光泽。圆锥状聚伞花序，挺直，深绿色。花序长7－10厘米。每株有花序5－7个，着花60 － 250朵。花小，高脚碟状，花径1.2－ 1.6厘米，花瓣4片，花朵色彩丰富，花色有绯红、桃红、橙红、黄、橙黄和白等。花冠长管状，基部稍膨大，蓇葖果。种子多数。　　　　　　　　　　　　　　　　　　　', '　　长寿花的栽培难度并不高，并且长寿花的花色繁多，深受人们的喜。不过想要长寿花的花朵艳丽也并不是那么简单的，小编就为你介绍一下长寿花的栽培要点，', '　　由于长寿花是多肉', 'http://img.boqiicdn.com/Data/BK/P/imagick93171439285186.jpg', 'http://www.boqii.com/entry/detail/1928.html', '');
INSERT INTO `plant_family` VALUES ('417', '金花茶', 'Camellia nitidissima C. W. Chi', '金花茶', '', '不容易死', '', 'http://www.boqii.com/entry/photo/1949/0,http://www.boqii.com/entry/photo/1949/5578', '', '', '', '', '', '', '', '', '', '　　金花茶为山茶科、山茶属 　　金花茶的花黄色，腋生，单独，花柄长7～10毫米；苞片5片，散生，阔卵形，长2～3毫米，宽3～5毫米，宿存；萼片5片，卵圆形至圆形，长4～8毫米，宽7～8毫米，基部略连生，先端圆，背面略有微毛；花瓣8～12片，近圆形，长1.5～3厘米，宽1.2～2厘米，基部略相连生，边缘有　　　　　　　　　　　　　　　　', '　　', '　　　　金花茶的繁殖可分有性繁殖和无性繁殖两种。由于金花茶结实率低、种子来源困难，所以有性繁殖往往受到限制，不常被使用。而无性繁殖能保持母本的', 'http://img.boqiicdn.com/Data/BK/P/imagick39821439804741.jpg', 'http://www.boqii.com/entry/detail/1949.html', '');
INSERT INTO `plant_family` VALUES ('418', '天竺葵', 'Pelargonium hortorum Bailey', '天竺葵', '洋绣球、入腊红、石腊红、日烂红、洋葵、驱蚊草、洋蝴蝶', '不容易死', '南非、中国、法国、留尼旺岛、西班牙、摩洛哥、埃及、意大利', 'http://www.boqii.com/entry/photo/2026/0,http://www.boqii.com/entry/photo/2026/5501', '', '', '', '', '', '', '', '', '', '　　 　　天竺葵为多年生草本，高30－60厘米。茎直立，基部木质化，上部肉质，多分枝或不分枝， 具明显的节，密被短柔毛，具浓裂　Pelargonium hortorum Bailey　　　　　　　　　　　　　　', '　　为多年生草本，性喜暖、湿润和阳光充足的环境。在西方，天竺葵常被用于装饰窗台的花卉，人工栽种天竺葵的难度并不高，但是如果不注意栽培方法的话，还是会引起天竺葵的。　　天竺葵苗高12～15厘米时进行摘心，促使产生侧枝。盛夏高温时，严格控制浇水，否则半休眠状态的天竺葵如盆土过湿，叶片常发黄脱落。茎叶期，每半月施肥1次，但氮肥不宜施用太多。茎叶过于养殖，需停止施肥，并适当摘去部分叶片，有利于开花。花芽形成期，每2周加施1次磷肥。或“卉友”15－15－30盆花专用肥。为了控制挖株高度，达到花大色艳的目的，除选择矮生天竺葵以外，生长调节物质的应用十分重要。当天竺葵定植于12厘米或15厘米盆后2周，可用0.15％矮壮素或比久喷洒叶面，每周1次，喷洒2次，每天光照14～18小时，这样可以有效地控制天竺葵的高度，提供优质的商品盆花。　　花谢后应立即摘去花枝，以免消耗养分，有利于新花枝的发育和开花。一般盆栽3～4年老株需要重新进行更新。冬春花期，应放阳光充足处，否则叶片易下垂转黄。雨雪天增加人工辅助光照，对开花更为理想。', '　　　\n　一、播种养殖\n　　播种基质使用按8∶1∶1混合的草炭土、蛭石和珍珠岩。播种前先将基质浇透水，然后把种子均匀的播入育苗盘中，覆盖蛭石，厚度为种子直径的3倍左右。用百菌清对播种箱进行消毒，搭拱棚，覆塑料膜。温度20℃至23℃为宜，湿度保持95％以上。一周左右出芽均匀时，掀开塑料膜。由于育苗基质营养成分少，每隔10天喷一次叶面肥，可选用磷钾含量相对较高的复合肥。同时保持室内通风，注意　　播种养殖当小苗长到4至6片叶、扦插养殖插穗生根后，即可移入营养钵或花盆中栽培。盆土以透水性良好的沙壤土为宜，同时施适量底肥，根据花蕾长势还可适当追肥。天竺葵春秋需肥量大，七八月份进入休眠期，可停止施肥。此外，天竺葵长势旺，每年都应对其进行修剪，以促花型丰满。　　\n二、扦插养殖\n　　选长势良好的植株，将顶端5至7厘米用小刀切下。切口倾角为45，剥去基部大叶，留顶部1至2片叶。如顶端叶大可剪去1／3至1／2，以减少水分蒸发。由于天竺葵基部多为肉质，水分多，取下立即扦插易', 'http://img.boqiicdn.com/Data/BK/P/imagick20421441878521.jpg', 'http://www.boqii.com/entry/detail/2026.html', '');
INSERT INTO `plant_family` VALUES ('419', '特玉莲', 'Echeveria runyonii ', '特玉莲', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2207/0,http://www.boqii.com/entry/photo/2207/5320', '　　', '被子植物门 Magnoliophyta', '双子叶植物纲 Magnoliopsida', '蔷薇目 Rosales', '景天科 Crassulaceae', ' Echeveria', '特玉莲', 'Echeveria runyonii \'Topsy Turvy\'', '', '　　 　　特玉莲的叶片叶基部为扭曲的匙形，两侧边缘向外弯曲，导致中间部分拱突，而叶片的先端向', '　　特玉莲喜温暖、干燥并且通风的环境，由于特玉莲没有明显的休眠期，所以人工栽种特玉莲需注意其环境布置。特玉莲的叶片和部分花朵都会有一定程度的扭曲，非常特别，那么如何才能养好特玉莲呢？', '　　　　叶插将完整的成熟叶片平铺在潮润的沙土上，叶面朝上，叶背朝下，不必覆土，放置阴凉处，10天左右从叶片基部可长出小叶丛及新根，将根系埋入土中，往后让它多晒太阳，适当浇水、施肥，渐渐地便会长成一棵茁壮的新株。　　插穗可用单叶、蘖枝或顶枝，剪取的插穗长短不限，但剪口要干燥后，去掉下部叶片，再插入沙床，插后一般20天左右生根，插壤不能太湿，否则剪口易发黄', 'http://img.boqiicdn.com/Data/BK/P/imagick2271447233939.jpg', 'http://www.boqii.com/entry/detail/2207.html', '');
INSERT INTO `plant_family` VALUES ('420', '绯花玉', 'Gymnocalycium baldianum（Speg.） Speg.', '绯花玉', '', '不容易死', '原产于阿根廷安第斯山脉', 'http://www.boqii.com/entry/photo/2141/0,http://www.boqii.com/entry/photo/2141/5386', '　', '被子植物门', '双子叶植物纲', '石竹目', '仙人掌科', '裸萼球属', '', 'Gymnocalycium baldianum（Speg.） Speg.', '', '　　 　　绯花玉为仙人掌科裸萼球属，扁球状，直径可达10cm左右，棱8～16，刺针状，每刺座5根周刺，灰色；中刺时有1根，稍粗，骨色或褐色，最长可达1.5cm。花顶生，长和直径都是3～5cm，白色、红色或', '　　绯花玉在我国是非常常见的', '　　很多', 'http://img.boqiicdn.com/Data/BK/P/imagick57381445590024.jpg', 'http://www.boqii.com/entry/detail/2141.html', '');
INSERT INTO `plant_family` VALUES ('421', '曼陀罗', 'Datura stramonium Linn.', '曼陀罗', '曼茶罗、醉心花、狗核桃等', '不容易死', '原产于印度，广泛分布于世界温带至热带地区。', 'http://www.boqii.com/entry/photo/1926/0,http://www.boqii.com/entry/photo/1926/5603', '', '', '', '', '', '', '', '', '', '　　 　　曼陀罗花原产于印度。广泛分布于世界温带至热带地区。中国各地均有分布。曼陀罗多野生在田间、沟旁、道边、河岸、山坡等地方。喜温暖、向阳及排水良好的砂质壤土。　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　原产于亚热带地区，且适应性比较强，所以种植难度并不高。由于曼陀罗种子的耐寒能力比较强，所以一般多采用播种的方法进行繁殖。那么曼陀罗播种应该如何操作呢？又需要注意哪些呢？　　1、混合你的曼陀罗种子用沙彻底－足以覆盖种子－并将其放置在一个纸箱在你的冰箱。这就是所谓的分层，有利于种子发芽，一旦他们正在播种。　　2、离开种子砂混合物在你的冰箱－或外部，如果不够冷固冻结它－直到你准备种植的种子。　　3、种植在泥炭锅或其他纤维锅里，然后可以直接种植到土壤中，或者，如果你想种植它们直接外面，毕竟霜冻的危险，这样做已经通过启动曼陀罗种子在室内任何时候。　　4、你播下的种子曼陀罗3／4－英寸深。如果你在花园里播种外，选择排水良好和充满阳光的地方和母株24和36英寸远的种子。保持土壤，无论是在锅或在花园里，稍湿润。　　5、覆盖土壤，如果你已经种植外曼陀罗，用黑色塑料片。垃圾袋将正常工作。这有助于温暖的土壤和速度发芽。　　6、继续保持土壤湿润，直到曼陀罗种子发芽。这可能发生在短短两个星期或只要它可能需要为8。', '　　很多花友应该都知道，曼陀罗是　　曼陀罗的适应性较强，喜温暖、湿润、向阳环境，怕涝，对土壤要求不甚严格，一般土壤均可种植，但以富含腐殖质和石灰质土壤为好。种子容易发芽，发芽适温15℃左右，发芽率约40％，从出苗到开花约60天，霜后地上部枯萎，　　1、选地、整地要选向阳、肥沃、排水良好的土地，冬前耕翻30厘米，结合耕翻每亩施入圈肥或土杂肥2000千克，耙细整平，开春后再翻1次，打碎土块，整细耙乎，作成1.5米宽的平畦。　　2、用种子繁殖，于4月上旬，在畦上按株行距60厘米×50厘米，开3厘米深的穴，将种子撒人，每穴5－6粒，覆土1厘米，稍压，保湿。每亩用种量约1千克。若育苗移栽，宜5月下旬，移栽定植。', 'http://img.boqiicdn.com/Data/BK/P/imagick48741439199643.jpg', 'http://www.boqii.com/entry/detail/1926.html', '');
INSERT INTO `plant_family` VALUES ('422', '乌木', '', '乌木', '', '不容易死', '', 'http://www.boqii.com/entry/photo/1906/0,http://www.boqii.com/entry/photo/1906/5623', '', '', '', '', '', '', '', '', '', '　　多肉植物中，乌木这个　　纯乌木至少要具备四个特征，三个外观特征：玉底、黑边（有时候是紫红边）、颗粒纹；一个内在特征：霸气。　　玉底：并不是说一定就是玉色的，而是说不是那种浑绿、傻绿，而是有一种玉的通透、晶莹的感觉。主要是内在的蕴上的玉的神。　　黑边：乌木的典型特征，个人认为黑边越黑越好，范围越大越好，黑与玉的分界越清晰越好，各叶片黑边的一致性越高越好。当然，也有紫红边的，视个人喜欢而定。　　颗粒纹：就是说乌木的纹路像是砂糖粒一样的晶体状叠列的，这样的纹路才能晶莹剔透，无论大小，无论何时，这一特征都是非常明显的。春天、　　霸气：景天类中，乌木已当之无愧的成为一种霸主类的多肉，在国外，乌木的价格也丝毫不低。主要是由于乌木的美区别于一般景天的“萌”之美，而是体现出一种内在的阳刚、大气、胸怀，进而彰显出一种内在的堂堂正正的霸气，是中国传统的王道与霸道的结合。这种霸气的显现，除了上面三个特征之外，还体现在乌木大而厚重的感觉上。乌木的叶片越厚重的这种霸气越重，有些过薄的则显得不足。 　　　现在好像是景天类的只要和乌木一沾上边，就像是沾上了皇家气息一样，身价倍增。其实远非如此。　　第一，真正乌木杂出来的东西，上面必然有比较明显的乌木特征，绝不是随便弄个东西都可以叫乌木杂。　　第二，乌木的内在霸气之美，只有在纯乌木中才体现得淋漓尽致，而杂出来的东西虽然也有另一种美，但是绝大多数都把这种内在的霸气之美给杂没了。特别是随着植株的成长，越大，杂的越显现出它不足的一面。　　　1、不要相信什么橙乌木、红乌木、粉乌木什么的，都是骗人的。记住，酱油不是油啊。经典的乌木必然符合上面的几个特征。　　2、不要轻易冲动就出手，手里拿着钱，就不愁买不到东西。手里拿着东西想再变回来就难了。　　3、对奸商的定义：以次充好、以假冒真、货不对版、有病不说、冠新名卖高价等等。价位要的高不一定是奸商，只要是货真，价位是周瑜打黄盖的问题。只要不是以骗的手段，可以不放在奸商范围。　　乌木的价位算是比较高的，但是想要', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick3081428056199.jpg', 'http://www.boqii.com/entry/detail/1906.html', '');
INSERT INTO `plant_family` VALUES ('423', '向日葵', 'sunflower', 'Helianthusannuus', '朝阳花、转日莲、向阳花、望日莲', '不容易死', '原产北美洲；世界各地均有栽培', 'http://www.boqii.com/entry/photo/1942/0,http://www.boqii.com/entry/photo/1942/5587', '', '', '', '', '', '', '', '', '', '　　 　　向日葵高1～3.5米，茎直立，圆形多棱角，质硬被白色粗硬毛。广卵形的叶片通常互生，先端锐突或渐尖，有基出3脉，边缘具粗锯齿，两面粗糙，被毛，有长柄。头状花序，直径10～30厘米，单生于茎顶或枝端。总苞片多层，叶质，覆瓦状排列，被长硬毛，夏季开花，花序边缘生中性的黄色舌状花，不结实。花序中部为两性管状花，棕色或紫色，能结实。矩卵形瘦果，果皮木质化，灰色或黑色，称葵花籽。　　　　　　　　　　　　　　　　　　　', '　　又名太阳花、朝阳花，我们吃的葵花籽就是向日葵的种子，但由于向日葵是比较大型的花卉，所以很少有花友会在家中种植，而日常生活中，我们也并不常见到向日葵的身影。如果你家的庭院够大，又有兴趣种上属于自己的向日葵的话，可以参考一下小编为你整理的向日葵的栽培方法。　　1、种植上盆：若用苗盘移栽的方式繁育，播种时应播在深的苗盘上，种苗在播后两周即可移栽。移苗的最适土温为15℃。定植的最好为12×12cm。在冬季无霜的地区，可在田间周年生长，而在冬天寒冷的地区，需要在温室保护地栽培。土壤在灭菌和播种之前要翻耕和疏松，以改良土壤的结构和排水性。良好的土壤通透性对向日葵的生长是至关重要的。　　2、光照调节：向日葵为短日照作物。但它对日照的反应并不十分敏感。向日葵喜欢充足的阳光，其幼苗、叶片和花盘都有很强的向光性。苗期日照充足，幼苗健壮；生育中期日照充足，能促进茎叶生长和花芽分化。　　3、温度控制：向日葵原产热带，但对温度的适应性较强，是一种喜温又耐寒的植物。向日葵种子耐低温能力很强，当地温稳定，2℃以上种子就开始萌动；4～5℃时，种子能发芽生根；地温达8～10℃时，就能满足种子发芽出苗的需要。向日葵发芽的最适温度为31～37℃。其生长时最适的白天温度是18～30℃，夜温是10～18℃。向日葵在整个生育过程中，只要温度不低于10℃，就能正常生长。在范围内，温度越高，越快。防止中午温度25℃以上要进行通风换气，夜间温度防止13℃以下要进行保温加热。　　4、水肥管理：向日葵播种和移栽时要求土壤湿润，之后要求土壤中等湿润。花朵成熟时，要减少浇水的次数和浇水量。观赏向日葵植株较之其他草花高大，叶多而密，是耗水较多的作物。向日葵不同生育阶段对水分的要求差异很大。从播种到现蕾，比较抗旱，需水不多。而且适当干旱有利于根系生长，增强抗旱性。现蕾到开花，是需水高峰。此期缺水，对产花量影响很大。如过于干旱，需灌水补充。向日葵喜氮肥，可采用肥水混合的滴溉系统施肥，肥料可交替着施用浓度为175～200ppm水溶态的硝酸钙和硝酸钾，氨态氮可用于促进茎干的生长。根据叶色使用液态肥料，保持底部叶片不是因为缺肥而枯黄即可。避免多肥，出蕾后控制液态肥料的使用。家庭盆栽或者园艺栽培的朋友，可以使用有机肥作为底肥，也可以使用冲施肥追肥。　　5、栽培管理：向日葵对土壤要求不严格，在各类土壤上均能生长，从肥沃土壤到瘠薄的土壤、旱地、盐碱地均可种植，有较强的耐盐碱和抗旱能力。生长最适诶土壤pH值为5.8－6.5。在高温度的设施栽培中株高容易伸长的情况下可以使用矮壮素，子叶展开后至真叶的展开为止使用一回，株高20厘米左右再使用一回。家庭盆栽的朋友可以用泥炭土或者用育苗土与普通土按照随意比例混合，成为栽培用土。　　在多风的，应立支柱拉网支撑以防植株到伏。有的品种可以摘除顶端花苞有利于侧枝的生长，使得侧枝花朵的大小均匀。经过这样的处理后，一个植株可采收7～10枝可售花茎，茎长达70～80cm，整株的高度可达120～170cm。有的品种在每个节处会长出侧蕾，需及时摘除，以利主花蕾的生长。温室种植的向日葵生长得更高。向日葵的栽培要点是：调节昼夜温差，使用低营养启动肥，并且控水、控肥、控光，以控制植株生长。', '　　观赏向日葵的栽培　　首先需要浸种以提高芽率，浸种催芽可使向日葵出苗快而整齐，并清除粘附在种子上的寄生植物的种子。用20度水浸种4－8小时，能提高出苗1－2天。', 'http://img.boqiicdn.com/Data/BK/P/imagick61531439459813.jpg', 'http://www.boqii.com/entry/detail/1942.html', '');
INSERT INTO `plant_family` VALUES ('424', '紫背竹芋', 'Stromanthe sanguinea Sond.', '', '', '不容易死', '原产中美洲及巴西，我国南部各省区有栽培。', 'http://www.boqii.com/entry/photo/1903/0,http://www.boqii.com/entry/photo/1903/5626', '', '', '', '', '', '', '', '', '', '　　 　　1、土壤：紫背竹芋喜疏松、肥沃、湿润而排水良好的酸性土壤，盆栽可用腐叶土、园土和河沙等量混合并加少量基肥作为　　2、浇水：紫背竹芋不耐干旱，生长季须给予充足的水分，保持盆土经常湿润，并注意向叶面喷水；尤其夏秋季气温较高、空气干燥时，还须经常向叶面及周围喷水，以保持较高的空气湿度。但要注意不宜使盆土积水，以免影响根系通气性，导致生长不良或烂根；秋末后气温较低，要控制浇水量，保持盆土微湿即可。　　3、光照：紫背竹芋喜阴，忌阳光直晒，不可置于阳光下，否则叶片褪绿，失去光泽，严重的会造成日灼病；但也不宜长期放在阴暗及通风不良处，以免叶片发黄、脱落。　　4、施肥：在生长　　5、虫病害：紫背竹芋常见病害主要有叶斑病和叶枯病。发病初期，每隔半月用200倍波尔多液喷施2一3次。也可用65％代森锌可湿性粉剂600倍液喷洒防治。常见虫害主要有介壳虫，通风不良时易发生。在若虫期用50％杀螟松乳油1000倍液喷杀。　　6、紫背竹芋是优良的室内喜阴观叶植物，炎热的夏季要防止阳光曝晒，应遮去70％－80％的光照，否则易产生伤害。 　　7、紫背竹芋喜温暖、潮湿、荫蔽环境。生长适温20～30℃，越冬温度15℃。生长期间应充分供给水分，在盆土微干时就应当及时浇水，如果能够经常地面喷水，增加空气湿度会生长很好，但不要使盆土积水，以影响生长和烂根，入秋后应控制浇水量。如果空气湿度低和盆土干旱就会叶片边缘发黄发焦，另外阳光直射也会引起叶片边缘发黄发焦。　　8、紫背竹芋盆栽可用腐叶土、园土和河沙等量混合并加少量基肥作为培养土。要求土壤营养丰富，疏松透气。在生长季节，每月施1－2次液肥，以保证其生长健壮、枝叶繁茂。另外，每1－2年翻盆1次。　　生长旺盛的植株每1－2年可分盆一次。分株宜于春季气温回暖后进行，沿地下根茎生长方向将丛生植株分切为数丛，然后分别上盆种植，置于较阴蔽处养护，待发根后按常规方法管理。另外，也可利用抽长的带节茎叶进行扦插繁殖。　　紫背竹芋原产于巴西，现在在我国南部各省区都有栽培，不过饲养紫背竹芋的话一定要注意其生长习性。紫背竹芋可以长期观赏，但是如果因为饲养导致紫背竹芋的观赏价值下降的话，就要注意采取科学的饲养方式，才能养出', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick98391428055894.jpg', 'http://www.boqii.com/entry/detail/1903.html', '');
INSERT INTO `plant_family` VALUES ('425', '豆瓣绿', 'Peperomia magnolifolia', '豆瓣绿', '', '不容易死', '原产西印度群岛、巴拿马、南美洲北部', 'http://www.boqii.com/entry/photo/1898/0,http://www.boqii.com/entry/photo/1898/5631', '', '', '', '', '', '', '', '', '', '　　 　　　　豆瓣绿喜生长于疏松肥沃、排水良好且富含腐殖质的砂质土壤，不适合生长在粘土中，所以基质通常用腐叶土、河沙和少量腐熟的有机肥料混合即可，好一点的基质可用可选泥炭土与珍珠岩混合栽培。　　　　豆瓣绿比较喜水，不耐干旱，在生长期中要勤浇水，气温高于25℃或崆气干燥时要多浇些水，但也要防止涝渍，气温低于25℃时要以盆土表面干燥时再浇透，气温低于10℃时，可干燥数日不浇水也可耐受。　　　　豆瓣绿喜湿润的生长环境，在湿度大的环境条件下生长繁茂，叶色鲜艳，气温高时或崆气干燥时要加强叶面喷水或在生长环境中洒水，以保持较高的崆气湿度，对植株的生长极为有利。它也能适应短暂的干燥环境，但不宜长久，一般应保持在70％左右。　　　豆瓣绿喜温暖环境，生长适温为20－30℃之间，越冬温度最好保持在10℃以上，10℃以下停止生长，5℃以下易冻害。　　　　豆瓣绿喜半阴或散射光照，除冬季需要充足的光照外，其他季节需要稍加遮阳，特殊是夏季更需遮阳。假如置于荫蔽的环境下，易徒长，枝间增长，观赏性降低，也是不可取的。在半阴条件下，叶色更明亮，光泽更佳，特殊是斑叶 　　　气温高于18℃时，就需要少量施肥，气温低于18℃或高于30℃时少施或不施为宜，施肥最好少量多次进行，以稀释的肥液代替清水灌溉最佳，不耐生肥与浓肥，很轻易造成肥害。也可进行叶面喷施肥液进行施肥，效果良好。肥料以氮肥、钾肥为主，磷肥为次。　　　豆瓣绿的病虫害较少，一般出现的病害皆为护理不当及环境不适所致，可调整下即可逐渐恢复。虫害主要有红蜘蛛危害，但保持较高的崆气湿度时能防备，发生时可通过湿布擦拭叶片或喷施专杀药剂进行　　　　新生繁殖的小苗，在苗高10厘米左右就要摘心增加枝条的数量，这样的株型更丰满，欣赏价值也更高。大株的修剪一般根据长势而定。　　豆瓣绿除了作为观赏植物，还能药用，中医药理上说，豆瓣绿内用可以祛风除湿，止咳祛痰。外用可以治跌打损伤，骨折，虽然现在家中也不会将豆瓣绿入药，但是养的好用来作观赏植物的花友还是很多的。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick76931428055306.jpg', 'http://www.boqii.com/entry/detail/1898.html', '');
INSERT INTO `plant_family` VALUES ('426', '松红梅', 'Leptospermum scoparium', '松红梅', '澳洲茶', '不容易死', '澳洲、新西兰', 'http://www.boqii.com/entry/photo/2286/0,http://www.boqii.com/entry/photo/2286/5239', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '桃金娘科', '薄子木属', '', 'Leptospermum scoparium', '', '　　 　　松红梅的株高约2米，分枝繁茂，枝条红褐色，较为纤细，新梢通常具有绒毛；叶互生，叶片线状或线状披针形，叶长0.7厘米～2厘米，宽0.2厘米～0.6厘米；花有单瓣、重瓣之分，花色有红、粉红、桃红、白等多种颜色，花朵直径0.5厘米～2.5厘米；自然花期晚秋至春末；蒴果革质，成熟时先端裂开。', '　　松红梅是近几年引进的园艺花卉品种，现在，松红梅常被用于', '　　　　松红梅以扦插为主，亦可播种、高压繁殖。依栽培目的不同分为观赏用和繁殖用，在整形修剪方面二者存在明显差异，比如为提供繁殖用的插穗、插条或种子，应多留长枝少剪截，花后不是剪除残花而是补施磷、钾肥，以便结实。　\n　1、扦插：\n　\n　2、播种：\n　　\n3、高压法：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick7781449135161.jpg', 'http://www.boqii.com/entry/detail/2286.html', '');
INSERT INTO `plant_family` VALUES ('427', '白牡丹', 'xGraptoveria ‘Titubans’', '白牡丹', '', '不容易死', '', 'http://www.boqii.com/entry/photo/1908/0,http://www.boqii.com/entry/photo/1908/5621', '', '', '', '', '', '', '', '', '', '　　 　　白牡丹是非常好养的多肉植物之一，和静夜不同，这一品种非常强健（兼具静夜的美丽同时继承了胧月的好养特性）一旦适应当地气候，即便放在屋顶任其接受烈日炙烤与暴雨冲淋，依然可以活得很美丽，是新手练习的首选。　　白牡丹容易长侧枝，侧枝生长也比较迅速，缺光后植株的叶片会拉长，叶片与叶片间会空开很大的距离，叶片也变的比较薄，　　白牡丹的繁殖主要靠植株侧芽，叶片扦插和砍头，砍头后从残存茎根上长出的新芽来延续后代，且非常容易长侧芽，存活率比较高，叶插可以获得大批的苗，是大棚繁殖的首选，春季是侧芽爆发的 　　大部分　　　　其实白牡丹的饲养难度并不大，虽然是和静夜杂交出来的品种，但是适应能力和生长能力可是比静夜好很多。目前市场上的白牡丹已经不只是白色了，有些普货的白牡丹可以颠覆你对白牡丹的印象。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick77471428056336.jpg', 'http://www.boqii.com/entry/detail/1908.html', '');
INSERT INTO `plant_family` VALUES ('428', '菊花', 'Florists Dendranthema', '菊花', '寿客、金英、黄华、秋菊、陶菊、日精、女华、延年、隐逸花', '不容易死', '', 'http://www.boqii.com/entry/photo/1946/0,http://www.boqii.com/entry/photo/1946/5582', '', '', '', '', '', '', '', '', '', '　　 　　菊花为多年生草本，高 60－150厘米。茎直立，分枝或不分枝，被柔毛。叶互生，有短柄，叶片卵形至披针形，长 5－15公分，羽状浅裂或半裂，基部楔形，下面被白色短柔毛，边缘有粗大锯齿或深裂，基部楔形，有柄。头状花序单生或数个集生于茎枝顶端，直径 2.5－20厘米，大小不一，单个或数个集生於茎枝顶端；因品种不同，差别很大。总苞片多层，外层绿色，条形，边缘膜质，外面被柔毛；舌状花白色、红色、紫色或黄色。花色则有红、黄、白、橙、紫、粉红、暗红等各色，培育的品种极多，头状花序多变化，形色各异，形状因品种而有单瓣、平瓣、匙瓣等多种类型，当中为管状花，常全部特化成各式舌状花；花期 9－11月。雄蕊、雌蕊和果实多不　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　菊花为多年生宿根亚灌木，由于栽培历史比较悠久，菊花的也在不断增多，并且花型、花色的变化也非常大。很多喜欢菊花的朋友们往往会自己在家中盆栽菊花，那么如何才能养好菊花呢？　　菊花喜肥，若施肥不当易引起徒长，施肥过多，则株高叶稀，因此基肥应以磷、钾肥为主。施追肥不可过早，如果叶片小而薄、叶色泛黄，可多次喷施0.1％尿素水至转绿时为止。如出现缺磷、钾肥等症状，应喷施0.2％磷酸二氢钾溶液。立秋后至开花前，肥水宜充足，其浓度要逐渐增加，并应注意增施磷钾肥，可使花色正、花期长。　　要让菊花长得矮壮、节密、叶肥、不赤脚，控水是唯一的有效措施。盆菊浇水要适时适量，即使是生长旺盛期，每天的浇水量也只需保持到白天中午蒸发所需的水量，即每天早、晚给叶片喷一次叶面水。　菊花的整个生长过程中，一般需要换盆2―3次。幼苗期移栽在直径约12厘米的小盆养护，壮苗期换入直径约15厘米的盆内，花蕾分化前再换入直径约20厘米左右的盆中培养，这时应适时加施肥料，只有这样，花盆逐渐增大，盆土逐渐增多，才有利于供给各个生长阶段所需的适量水肥。切忌大盆养小苗或小盆养大苗。若发现枝叶过盛，可去掉部分宿土或须根。　及时摘心可促发侧枝，有效地压低株高。盆栽的摘心和次数，因不同选形艺术而异，一般留4―7朵，菊苗定植后留4―5片叶摘心，等其侧枝长出4―5片叶时，每个侧枝再留2―3片叶进行第二次摘心。　　菊花壮苗期，萌发出许多腋芽，需及时用手指捏掉，否则消耗大量养分，且能发出许多小侧枝，使植株显得杂乱无章。孕蕾期，在顶蕾下的小枝上有时出现旁蕾，除因需要保留的以外，也应及早去掉旁蕾，促进顶蕾肥大。　　俗话说“鲜花还需绿叶配”。做到适期扦插，在盆菊生长期间，合理施肥、浇水、病虫害，即可防止脚叶枯黄脱落，又可确保叶片青秀，提高观赏效果。', '　　　　菊花的扦插一般有枝插、芽插和叶插，但以枝插为最普遍，具体扦插步骤如下：　　1、插穗的选择：花谢后选择健壮无病虫害的植株，剪除地上部分，放在冷室或冰箱内，留作母株。　　2、扦插时间：4月中旬至5月上旬为秋菊扦插岁适期。　　3、插穗的准备：第二年春萌发长成新梢后，截取7－8厘米的顶梢为插穗，于基部叶片下方0.2厘米处用利刀修成马蹄形，并除去基部的叶片，仅留上部2－3片叶片，而且将大叶剪去一半。将介质放于插床或盆中铺平，浇水，待水渗下后即可进行扦插。　　4、扦插：扦插时先用竹签将床面戳上小洞，将插穗插入，深度为插条的1／3－1／2，行距8－10厘米，株距2－3厘米。　　5、插后', 'http://img.boqiicdn.com/Data/BK/P/imagick54751439545616.jpg', 'http://www.boqii.com/entry/detail/1946.html', '');
INSERT INTO `plant_family` VALUES ('429', '碰碰香', 'Plectranthus hadiensis var。 tomentosus', '碰碰香', '一抹香、触留香（楚留香）、绒毛香茶菜', '不容易死', '原产非洲好望角', 'http://www.boqii.com/entry/photo/1952/0,http://www.boqii.com/entry/photo/1952/5575', '植物　　', '被子植物门', '双子叶植物纲', '牻牛儿苗目', '牻牛儿苗科', '属', 'Plectranthus hadiensis', 'Plectranthus hadiensis var. tomentosus', '', '　　碰碰香因其特有的香味而被人熟知，其实碰碰香的栽培难度非常低，不但可以盆栽观赏，还能食用，泡茶、煲汤、炒菜均可。由于碰碰香的气味比较特殊，还有人将碰碰香当做 　　碰碰香多分枝，全株被有细密的白色绒毛。肉质叶，交互对生，绿色，卵圆形，边缘有钝锯齿。茎细瘦，匍匐状，分枝多，叶圆形，叶片毛茸茸，花小，白色。因触碰后可散发出令人舒适的香气而享有“碰碰香”的美称。又因其香味浓甜，颇似苹果香味，故又享有“苹果香”美誉。闻之令人神清气爽。', '　　碰碰香的栽培难度并不大，可以说是非常容易栽种成活的植物，但是由于碰碰香比较耐旱，所以在栽种的时候记得少浇水，潮湿很容易导致碰碰香的根部出现。　　　　碰碰香喜阳光，但也较耐阴。怕寒冷，需在温室内栽培。不耐水湿。喜温暖，不耐寒冷。冬季需要5℃—10℃的温度。碰碰香喜欢阳光充足的环境，强光下肉质叶片才会厚实；光照不足叶子会变扁而薄。　　　碰碰香喜疏松、排水良好的土壤。　　　因碰碰香常年在温室中培养，要求空气流通、新鲜，否则易遭。　　　碰碰香不耐潮湿，但过湿则易烂根致死。土壤要见干见湿，阴天应减少或停止浇水、施肥。夏季过后，一定要少浇水，更要控制浇水。一般要看叶子萎蔫了才浇水，否则易徒长。　　　因碰碰香极易分枝，以水平面，所以定植时株行距宜宽，才能使枝叶舒展。适度修剪可促进分枝，生长健壮。', '　　碰碰香的栽培难度不高，但是很多人想要自己在家繁殖碰碰香就没有那么简单了，很多人繁殖的碰碰香总是会遇到很多　\n　方法一：\n　　然后把它插在　　记住：从此就不要浇水了。只等土干了，早晚在花盆周围喷点水气，增加空气湿度。这样坚持半月－1个月，估计根就出来了。　　\n方法二：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick23211439890494.jpg', 'http://www.boqii.com/entry/detail/1952.html', '');
INSERT INTO `plant_family` VALUES ('430', '碧光环', 'Monilaria obconica', '碧光环', '小兔子，兔耳朵', '不容易死', '原生地位于南非', 'http://www.boqii.com/entry/photo/2070/0,http://www.boqii.com/entry/photo/2070/5457', '　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '碧光环属', '碧光环种', 'Monilaria obconica', '', '　　 　　碧光环的叶子呈半透明富有颗粒感，非常可爱。而且具有枝干，易群生。大群生开花是非常壮观的。播种方法参考生石花播种，基本类似。因为生长初期长相像小', '　　碧光环常被亲切的称为小兔子，这是因为其在期的初期形态和小兔子非常像，但是生长期过后，碧光环的叶片就会耷拉下来。很多多肉爱好者都会被碧光环萌萌的样子而到，但是如何才能养好碧光环呢？　　碧光环是属于冬型的植物，其生长期在秋冬春三季，而在夏季的时候才是它的。在休眠期的时候，碧光环原本嫩绿的像兔耳一样的叶子就会慢慢变黄最后枯萎。很多花友以为这是植物了，就用各种办法浇水施肥让其复苏。其实这都是错误的，碧光环在冬季处于休眠期叶片枯萎是属于正常的现象，休眠期的时候不要给其浇水，只要把它放在能够遮阳且通风良好的位置，让其自然生长即可。到了9月份生长期的时候，给其浇水，它就自然的复苏了，标志性的兔耳叶子也会慢慢长出来。　　9月到第二年的5月是碧光环的生长期，在刚进入秋季时候，需要人工浇水来唤醒植物。具体什么时候该唤醒的标准是白天在30度以下，晚上在20度以下的时候即可。各地的温差都不相同，因此要具体测量温度再来决定什么时候浇水唤醒碧光环。碧光环比较喜爱肥料，因此在生长期的换盆的时候可以在盆的地步加入适量的肥料，提供其生长所需的营养物质。冬天温度过低的时候要对其进行保温作用。一般来说，只要温度高于5摄氏度，碧光环就不会停止生长。一旦低于这个温度，就要将其带回室内进行保温种植。　　土壤：土壤的选择最好选择颗粒较多的肥沃土壤，土壤中可以混合钾肥以及其他腐殖质，来提供其生长的养分。　　浇水：浇水要浇透干透，在土壤表面干透以后就要对其进行浇水，每次浇水要浇到水从盆中流出为止。　　环境：碧光环最合适的生长环境是通风且光照充足，但是在夏季高温的时候要对其进行遮阴60％－8％。', '　　　　\n一、播种时间：\n　　国内主要播种　\n　二、播种盆：\n　　播种盆使用6～8厘米浅盆，瓦盆塑料均可，盆土与盆口留1～2CM距离。　　\n三、播种土：\n　　应采用疏松透气。且保水性能好的土壤，一般主料有营养土泥碳土赤玉土鹿沼土木碳粒（透气用）稻壳碳（透气用）草木灰少量（含多种营养及微量元素），辅料有硬煤渣粗沙珍珠岩蛭石细兰石等，可取其中几种主辅料混合后过筛，大些的颗粒放在下面（不要过大）细颗粒放在上面，表面撒上薄薄一层一毫米左右的细颗粒土，消毒用微波炉中火中温五分钟，也可以用开水浸盆）从盆底给水浸透，等土壤完全浸湿后。就可以播种了（也可以用高锰酸钾作为浸盆用，这样播种的同时也给种子消毒了不过浓度稍高些）。　　\n四、播种：\n　　碧光环种子十分细小，播种时要仔细均匀地撒在土表，不要盖土，种子要播的适当密些，切不可在大盆里只播种几粒种子。播种后可用玻璃片将盆盖上，白天高温时可以掀开一角晚上盖好，保持湿度百分之八十。播种以晴天最好，阴雨天气不要播，播种后遇上连续阴雨天气，发芽会推迟（可用一个灯炮照射加温）。播种后将花盆放在温暖湿润和能晒到阳光的地方，温度30度以上要遮荫，种子一般3天开始发芽也有些品种的种子会半个月左右才发芽。发芽期为一个月左右结束，发芽后要特别注意管理，才能很好的　\n　五、苗期管理：\n　　种子发芽后，可以将玻璃片去掉，刚发芽的小苗对阳光的需求很高要及时移到阳光充足又不太强烈的地方，阳光可以起到矮化苗子的作用，如果发芽期光照不足会造成苗细徒长至少得第一次脱皮后才能用光照矮化回来中午阳光强烈就需要遮阴，（不建议用细沙表层如果是用细沙铺的会产生硬沙壳层）种子发芽后小苗的根部很容易暴露在外面。需及时将它埋到土里去，盆土在一个月的发芽期内保持大湿等种子发芽出齐之后，减少水份但必须保证盆土有湿度，当盆土处于微湿时就需要浸盆了（浸盆一般是浸透可用一定的容器定量），施肥是在种子发芽后1－2月进行的，肥要极淡，可当做浇水，用浸水法施肥。　　没有把握时请不要急于施肥，土壤中营养足够它生长一段时间了，大约种子发芽三四个月后苗就要开始第一次退皮，这时可以用电简照射苗子能清楚的见到有一个明显的阴影，这时太阳和给水就需要注意了太阳是必需的水份要适当减少，这样用不了多久新的植株吸收掉老皮的水份，到皮完全干掉后就可以给水了不久带有花纹的小植株就能从老皮中破茧而出。这样在一年内的精心管理下就能长到八毫米至一厘米。', 'http://img.boqiicdn.com/Data/BK/P/imagick31541443086593.jpg', 'http://www.boqii.com/entry/detail/2070.html', '');
INSERT INTO `plant_family` VALUES ('431', '蝴蝶兰', 'Phalaenopsis', '蝴蝶兰', '蝶兰、台湾蝴蝶兰', '不容易死', '', 'http://www.boqii.com/entry/photo/1992/0,http://www.boqii.com/entry/photo/1992/5535,http://www.boqii.com/entry/photo/1992/5534', '', '', '', '', '', '', '', '', '', '　　 　　蝴蝶兰的花序侧生于茎的基部，长达50厘米，不分枝或有时分枝；花序柄绿色，粗4－5毫米，被数枚鳞片状鞘；花序轴紫绿色，多少回折状，常具数朵由基部向顶端逐朵开放的花；花苞片卵状三角形，长3－5毫米；花梗连同子房绿色，纤细，长2.5－4.5厘米；花白色，美丽，花期长；中萼片近椭圆形，长2.5－3厘米，宽1.4－1.7厘米，先端钝，基部稍收狭，具网状脉；侧萼片歪卵形，长2.6－3.5厘米，宽1.4－2.2厘米，先端钝，基部收狭并贴生在蕊柱足上，具网状脉；花瓣菱状圆形，长2.7－3.4厘米，宽2.4－3.8厘米，先端圆形，基部收狭呈短爪，具网状脉；唇瓣3裂，基部具长约7－9毫米的爪；侧裂片直立，倒卵形，长2厘米，先端圆形或锐尖，基部收狭，具红色斑点或细条纹，在两侧裂片之间和中裂片基部相交处具1枚黄色肉突；中裂片似菱形，长1.5－2.8厘米，宽1.4－1.7厘米，先端渐狭并且具2条长8－18毫米的卷须，基部楔形；蕊柱粗壮，长约1厘米，具宽的蕊柱足；花粉团2个，近球形，每个劈裂为不等大的2爿。花期4－6月。　　　　　　　　　　　　　　　　　　', '　　蝴蝶兰又称蝶兰，由于其花型独特，并且花期较长深受人们的喜爱。蝴蝶兰也是洋兰中的极品，现在在寻常百姓家也能经常见到蝴蝶兰的身影。不过，蝴蝶兰的栽培难度比较高，对于环境要求比较严格，如果不注意的话，往往会导致蝴蝶兰的质量欠佳。　蝴蝶兰春后，最适宜的温度是25℃（日间）～18℃（夜间）。经过夏季的旺盛生长后，到了秋天，进入，温度应控制在21℃（日间）～15℃（夜间）。温度高于35℃蝴蝶兰休眠，高达45℃会灼伤植株。　蝴蝶兰生长的最佳湿度为60％～80％，小苗要求达到90％。湿度过高，植株易感病，过低生长缓慢。　蝴蝶兰的生长旺盛期是阳光充足的春季和夏季，它的原生环境树荫浓密，因此在北方栽培时，应遮光，温室栽培要加内外遮阳网，遮光率达50％。　蝴蝶兰生长需要高温环境，浇水以4～5天一次为宜；夏季高温每日应叶片喷雾2～3次以降温，进入秋天可停止喷雾，且等盆土干后再浇水。水质对蝴蝶兰的生长至关重要。一般要求PH6。5左右。　可使用正规厂家生产的)专用肥。在所有的洋兰中，蝴蝶兰从幼苗到开花需2～4年，属生长快速型。因此须经常施肥以保证其生长，一般在生长期每1～2周施肥1次，休眠期和花期则不宜施肥。', '　　　\n　一、播种繁殖法\n　　有一种自然播种法，就是将已开裂蒴果散发出来的种子播于亲本植株的花盆中，这种方法简单易行，无需复杂的无菌程序和操作工具，适用于一般家庭蝴蝶兰种植者，但此法成功的机会甚微，极少应用。还有一种是无菌播种法，这种方法是先将未裂开的成熟蒴果洗净，然后置于75％～90％乙醇或氯仿中浸2～3秒，再用5％～10％的漂白粉溶液或3％的双氧水浸5～20分钟。取出种子在同样的　\n　二、花梗催芽繁殖法\n　　方法是先将花梗中已开完花的部分剪去，然后用刀片或利刃仔细地将花梗上部第一至第三节节间的苞片切除，露出节间中的芽点；用棉签将催芽剂或吲哚丁酸等激素均匀地涂抹在裸露的节间节点上；处理后将兰株置于半阴处，温度保持在25～28℃，2～3周后可见芽体长出叶片，3个月后长成具有3～4片叶并带有气生根的蝴蝶兰小苗；切下小苗上盆，便可成为一棵新的兰株。　　\n三、断心催芽繁殖法\n　　兰株因一些因素而致使其生长点遭到　\n　四、切茎繁殖法\n　　切茎繁殖法的原理是破坏茎尖生长点，以诱发潜伏芽生长。蝴蝶兰植株的叶腋处虽有潜伏芽1～3个，但多不能萌芽成株。可待植株不断向上生长、茎节较长后，再将植株带有根的上部用消毒过的利刃或剪刀切断，植入新盆使其继续生长，下部留有根茎的部分给予适当的水分　　\n五、组织培养法\n　　采用组织培养法来繁殖蝴蝶兰，可以获得与母株完全相同的优良的遗传特性。通过这种方法产生的蝴蝶兰苗通过称为分生苗或组织苗。用于进行分生培养的', 'http://img.boqiicdn.com/Data/BK/P/imagick24831441098711.jpg', 'http://www.boqii.com/entry/detail/1992.html', '');
INSERT INTO `plant_family` VALUES ('432', '麒麟掌', 'Euphorbia neriifolia var.cristata', '麒麟掌', '麒麟角、玉麒麟', '不容易死', '印度东部', 'http://www.boqii.com/entry/photo/2027/0,http://www.boqii.com/entry/photo/2027/5500', '', '', '', '', '', '', '', '', '', '　　 　　麒麟掌为夏型种，　　　　　　　　　　　　　　　　　　　　', '　　麒麟掌又名麒麟角，其变态茎在初期的时候为绿色，而后会渐渐木质化。麒麟掌四季常青，是北方冬季室内摆设的多肉，深受人们的喜爱。那么如何才能养出健康漂亮的麒麟掌呢？　　　　麒麟掌喜光，5月初出房后，先置荫棚下7天至10天，再放在阳光充足处。光照不足易导致变态茎徒长而成为柱状茎。尤其是在生长里更要保证充足的光照，切不可久置室内观赏。冬季虽已休眠，但植株还要进行光合作用，以维持基本的生命活动，因此亦应放置在阳光充足的场所，否则会使叶片发黄脱落。夏秋是麒麟掌的生长旺季。它喜阳光，但忌暴晒，如在室外，可用竹帘遮荫。　　　　麒麟掌比较耐旱，平时浇水以宁干勿湿为原则。当盆土干硬发白、叩击盆壁听到清脆的响声浇透水。冬季浇水比平时还要减少，在室温15℃至18℃的室内，每10天左右浇一次透水即可。浇水过多不但容易发生返祖现象，还会导致根系窒息而死。　　　麒麟掌不太喜肥，供肥原则是宁少勿多，宁淡勿浓。盆土可用腐叶土、煤球渣、园土各1／3混匀配成，上盆时可少放些粉碎的固体肥料作基肥。生长季节每月施一次15％左右充分腐熟的矾肥水。施肥时切忌生肥、浓肥，否则易致烂根、落叶。冬季休眠时可停肥，至翌春开始生长时再逐渐恢复正常的供肥水平。　　　麒麟掌不耐寒。一般在霜降前第一次寒流未来时就应入室。开始应注意室内通风，让其逐渐适应室内小气候。冬季即使天暖，也不可搬到室外晒太阳。冬季室温如能保持15℃以上可保证叶片不落；如已落叶，只要温度在7℃以上就可以安全越冬。俟翌春5月，还可以重新展叶。', '　　麒麟掌为夏型种多肉　　麒麟掌用扦插法繁殖，5－6月份剪取生长充实的茎段为插穗，晾数日，待伤口稍干缩后，插入素少中。刚插入素沙中切记不要浇水。插后马上就浇水，一般茎段就从下往上烂掉了。经过2－3天再进行喷水。20－25℃条件下，40－50天可以生根。　　上盆栽种麒麟掌的盆土是按菜园土3份、腐熟的厩肥土3份、河砂4份混合配制而成。栽种时，先在花盆底部垫上一层（2厘米—3厘米）炉渣或粗砂粒，以利排水，防止渍水烂根。上盆后应浇透水，先放置阴凉处一周后移到弱光处，再逐渐移到较强的光照下放置。它耐干旱，浇水宜少不宜多，掌握见干见湿的原则。　　麒麟掌生长最适宜的温度是22－28℃，30℃对其生长不利，35℃以上即进入休眠。冬季室温如能保持15℃以上可保证叶片不落；低于12℃，叶片会干枯脱落。只要温度在7℃以上就可以安全', 'http://img.boqiicdn.com/Data/BK/P/imagick63021441963723.jpg', 'http://www.boqii.com/entry/detail/2027.html', '');
INSERT INTO `plant_family` VALUES ('433', '吉娃莲', 'Echeveria chihuahuaensis', '吉娃莲', '吉娃娃', '不容易死', '墨西哥奇瓦瓦州', 'http://www.boqii.com/entry/photo/2097/0,http://www.boqii.com/entry/photo/2097/5430', '　　', '被子植物门 Magnoliophyta', '双子叶植物纲 Magnoliopsida', '蔷薇目 Rosales', '景天科 Crassulaceae', '拟属 Echeveria', '吉娃莲', 'Echeveria chihuahuaensis', '', '　　 　　吉娃莲的植株小型，无茎的莲座叶盘非常紧凑。卵形叶较厚，带小尖，长4厘米、宽2厘米。蓝绿至灰绿、淡绿色，并被有浓厚的白粉，日照充足时顶端的小尖呈美丽的玫瑰红或深粉红色。花序20厘米高，先端弯曲，小花约1厘米长，钟状，红色。', '　　吉娃莲的栽培难度并不高，但是需要注意夏季吉娃莲不能浇过多的水，并且，吉娃莲的速度较慢，所以土壤不必含过多的。吉娃莲的植株娇小，叶尖的红色非常漂亮，也是一种观赏性很强的多肉植物。　　吉娃莲对光照要求比较高，一般建议全日照，但是夏季的时候阳光过于猛烈，还是要进行遮阴，并且减少浇水量。在日常浇水的时候，并不需要过多的水，首先是因为其本身植株比较小，不需要这么多水，再者其比较耐旱，如果水过多极易造成烂根。吉娃莲在多肉植物中属于比较缓长型，如果过多的肥料施肥，反而会让其长得更慢，所以建议在盆栽的时候适当的放点腐蚀质即可，不需要施肥。吉娃莲虽然耐寒，但是其耐寒就不会生长，所以建议冬季的时候要进行准备，一般低于5摄氏度就不行了，10摄氏度以上还能正常的生长。夏季也是一个难题，因为夏季注意通风、避免阳光直射。　　吉娃莲是属于栽培比较慢的一种多肉植物，在繁殖方式上建议叶插比较好。等成株的吉娃莲长成，取下其中长势比较好的叶子，就可以进行栽培了。在种植过后一年左右的早春，是其最美的季节。', '　　吉娃莲为景天科　　吉娃莲的栽培不太困难，日照充足时叶片的排列会很紧实，夏天要减少浇水并适当遮阴，积水过多很容易腐烂。因为其　　吉娃莲是属于栽培比较慢的一种多肉植物，在繁殖方式上建议叶插比较好。等成株的吉娃莲长成，取下其中长势比较好健康的叶子，就可以进行栽培了。在种植过后一年左右的早春，是其最美的', 'http://img.boqiicdn.com/Data/BK/P/imagick37821444382540.jpg', 'http://www.boqii.com/entry/detail/2097.html', '');
INSERT INTO `plant_family` VALUES ('434', '龙吐珠', 'Clerodendrum thomsonae Balf.', '龙吐珠', '', '不容易死', '原产非洲西部热带地区', 'http://www.boqii.com/entry/photo/2153/0,http://www.boqii.com/entry/photo/2153/5374', '', '', '', '', '', '', '', '', '', '　　 　　龙吐珠为攀援状灌木，高2－5米；幼枝四棱形，被黄褐色短绒毛，老时无毛，小枝髓部嫩时疏松，老后中空。叶片纸质，狭卵形或卵状长圆形，长4－10厘米，宽1.5－4厘米，顶端渐尖，基部近圆形，全缘，表面被小疣毛，略粗糙，背面近无毛，基脉三出；叶柄长1－2厘米。　　　　　　界：　　　　　　　　　原产非洲西部热带地区', '　　的外形非常特殊，原产于非洲西部，现在被广泛栽培，是盆栽攀援观花。人工栽培龙吐珠的难度并不高，但是需要给龙吐珠一个合适的环境，才能让龙吐珠更漂亮。　　龙吐珠属于观花植物，花期甚长，宜用肥沃、排水良好的微酸性砂质壤土，盆栽龙吐珠，一般每1～2年换盆一次，换盆在早春或花谢后均可。换盆时先用碎瓦片垫好排水孔，再放入少量骨粉作基肥，然后装入新的土（腐土4份、园土4份、沙土2份），栽好植株，上留2～3厘米沿口，以便施肥浇水。换盆后浇透水，放背阴处缓苗，缓苗后移至阳光充足处养护。　　龙吐珠施肥不应过多，开花季节每隔7～10天施1次腐熟的稀薄饼肥水，连施3～4次肥即可。龙吐珠在栽培过程中若发现有黄化现象，可结合施追肥，施用）0.2％硫酸亚铁水，即可使叶片逐渐由黄转绿。', '　　　　\n一、扦插繁殖：\n　　常以枝插、芽插和根插均可。枝插可选健壮无病枝条的顶端嫩枝，也可将下部的老枝剪成8～10厘米的茎段作为插穗。芽接是取枝条上的侧生芽，带一部分木质部，作为插穗。根插是根状匍足球即时比分匐茎剪成8～10厘米长作插穗。插床可用泥炭、珍珠岩、腐叶土、河沙和蛭石等基质，以春、秋季扦插最好，扦插适温为21℃，插床　\n　二、分株繁殖：\n　　在花后，挖取地下匍匐茎上萌发的新枝，带根直接盆栽，放半阴处养护。　　\n三、播种繁殖：\n　　3～4月进行。种子较大，采用室内播盆，室温保持24℃条件下，播后10天左右相继发芽，苗高10厘米时移入小盆养护，第二年就能开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick84631445937816.jpg', 'http://www.boqii.com/entry/detail/2153.html', '');
INSERT INTO `plant_family` VALUES ('435', '草玉露', 'Haworthia cymbiformis var. obtusa', '草玉露', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2302/0,http://www.boqii.com/entry/photo/2302/5222', '　', '被子植物门', '双子叶植物纲', '百合目', '科', '瓦苇属', '', 'Haworthia cymbiformis var. obtusa', 'Haworthia cymbiformis', '　　草 　　草玉露的植株小窗晶莹剔透，叶片为翠绿色，叶尖有一根细长的纤毛，整个植株往叶心合拢，叶片上的窗较小，叶片晶莹剔透，常年翠绿色或黄绿色，晒厉害了会出现深绿色，', '　　草玉露为独尾草科瓦苇属多肉植物，人工栽种的难度并不高，植株小巧，非常适合在室内栽种。那么草玉露在栽种过程中应该注意哪些问题呢？如何才能养好草玉露呢？　　草玉露生长的季节，整个植株看起来非常的漂亮，生长期的盆土一直保持微湿，因为它们大的湿度，不过这个湿度是根系生长完好的情况下噢。花友们要注意的是没有长好根就一直湿润，是会烂根的，具体的发根方法是土壤微湿，把风干伤口的植株种上放在阴凉通风的地方等待出新根，出了新根后才可以循序渐进给水，同时加大光照，如果阴太久植株会变形且徒长，一旦徒长要养回来就要花费很长的时间，不过草玉露叶片不太容易徒长。　　的因为太高，植株基本是缓慢或停止生长，底部叶片也会慢慢干枯。整个夏季盆土保持适度干燥，每个月适当在盆边给点水，不要给到叶心，高温容易烂芯和烂根，（曾经风筝就不小心把水分弄到叶心，大群生根系烂了），保持植株根系缓慢或停止生长需要的水分，不能说因为高温就直接休眠不给水了，那样醒来也要很长时间，根系也会全部干枯，休眠期间容易消耗掉部分叶片的水分和养分，而出现底部乃至整个植株叶片的干煸萎缩。夏季因为生长缓慢，温度高，整个植株叶片基本合拢萎缩，不饱满，每个季节有每个季节的美丽。　　可用透明塑料罩罩起来，盆土保持微湿，一个月给点点水，保温又增加了湿度，白天的阳光可以让温度上升些，空气湿度也很大，这时的叶片特别的饱满，漂亮迷人。', '　　草　\n　一、分株\n　　草玉露的繁殖可结合换盆进行分株，也可在生长　\n　二、叶插\n　　也可在生长季节选择草玉露健壮充实的肉质叶进行叶插，插后保持盆土稍湿润，很容易在基部生根，并长出小芽，等小芽稍大些再另行栽种即可。', 'http://img.boqiicdn.com/Data/BK/P/imagick37211449652806.jpg', 'http://www.boqii.com/entry/detail/2302.html', '');
INSERT INTO `plant_family` VALUES ('436', '球兰', 'Hoya carnosa （L. f.） R. Br.', '球兰', '马骝解、狗舌藤、铁脚板等', '不容易死', '', 'http://www.boqii.com/entry/photo/2105/0,http://www.boqii.com/entry/photo/2105/5422', '', '', '', '', '', '', '', '', '', '　　 　　球兰叶对生，肉质，卵圆形至卵圆状长圆形，长3.5－12厘米，宽3－4.5厘米，顶端钝，基部圆形；侧脉不明显，约有4对。聚伞花序伞形状，腋生，着花约30朵；花白色，直径2厘米；花冠辐状，花冠筒短，裂片外面无毛，内面多乳头状突起；副花冠星状，外角急尖，中脊隆起，边缘反折而成1孔隙，内角急尖，直立；花粉块每室1个，伸长，侧边透明。　　　　　　　　　　　　　　　　　　　　　　　', '　　球兰的外形非常特别，是攀援性植物，常附生在树干、石壁上。球兰在每日只有3－4小时充足阳光的环境下就能开花，如果光照不足的话，球兰只能盆栽观叶。那么球兰在栽培过程中需要注意哪些问题呢？　土质以腐植质壤土为佳，排水需良好。　　球兰为多肉植物，叶片内含有较多水分，生长季节浇水要见干见湿。浇水过多易烂根，但夏季浇水要充足。因其喜湿润，故应注意经常向叶面喷水，以增加空气湿度。　球兰在家庭培养春、秋季节宜放在朝南窗台上或室内南窗附近见光处，即能保持叶色翠绿光亮，开花良好。但夏季要移至遮阴处，防止强光直射，否则叶色易变黄。若长期将其放在光线不足处，则叶色变淡，花少而不艳。　球兰不耐寒，生长适温为15℃－25℃，冬季室温应保持在10℃以上，若低于5℃，则易受寒害，引起落叶，甚至整株。　　球兰施肥主要以有机肥或复合肥料为主；生长旺季每月施1－2次氮磷结合的稀薄饼肥水。其余因为生长缓慢，要停止施肥，以免浪费肥料或造成肥害。　　球兰幼株宜早摘心，促使新枝萌发，并及时设立支架，使其向上攀附生长。花谢之后要任其自然凋落，不能将花茎剪掉，因为第2年的花芽大都还会在同一处萌发，不了解这一习性将其剪掉，将会影晌来年开花数量。　　球兰常见有炭疽病、坏斑病、叶斑病，可用50％多菌灵可湿性粉剂600倍液或用70％代森锰锌可湿性粉剂400－6w倍液喷洒防治。另有介壳虫、粉断危害，可用40％的氧化乐果乳剂800一100倍液或80％敌敌畏乳剂IOC.倍液喷杀。　　球兰花型比较奇特，很具有观赏价值，用来布置家居也比较容易营造出清新自然的舒适感，球兰的养殖方法小编给大家整理到这里了，相信大家对球兰的都有了一定了解，而且能养出效果比较好的球兰盆栽。', '　　　　球兰一、二年生的老茎及当年生的嫩茎，均可作插穗，剪成5～8厘米的一段，留有2节，把插入基质中的叶子剪去，上面只留1～2片叶，待伤口充分晾干后，将插条插入沙床或土质疏松的花盆基质中1／3或1／2部分栽培，如果为180号花盆，每盆可插插条10条左右。　　插条最好随剪随插，以利成活，4～6月光照较强，为保持阴凉环境，可设置2层黑纱网，插条20天左右即可生根，1个月后有新叶片长出，根部', 'http://img.boqiicdn.com/Data/BK/P/imagick34441444469318.jpg', 'http://www.boqii.com/entry/detail/2105.html', '');
INSERT INTO `plant_family` VALUES ('437', '炮仗花', 'Pyrostegia venusta （Ker－Gawl.） Miers', '炮仗花', '鞭炮花，黄鳝藤', '不容易死', '原产中美洲，现世界各地栽培', 'http://www.boqii.com/entry/photo/2088/0,http://www.boqii.com/entry/photo/2088/5439', '　　', '被子植物门', '双子叶植物纲', '管状花目', '紫葳科', '炮仗藤属', '炮仗花', 'Pyrostegia venusta （Ker－Gawl.） Miers', '', '　　 　　炮仗花为藤本植物，具有3叉丝状卷须。叶对生；小叶2－3枚，卵形，顶端渐尖，基部近圆形，长4－10厘米，宽3－5厘米，上下两面无毛，下面具有极', '　　向阳的环境，现在常被很多花友拿来盆栽，人工种植炮仗花需要种植在阳光充足并且通风的地方。现在也有很多朋友将炮仗花种植在庭院、棚架等处做。　　炮仗花无论地植还是盆栽，坑穴和盆的规格均需稍大些，以便施用多量的有机腐殖质作基肥。定植或上盆后要经常浇水保持土壤湿润，排水要好，并稍予遮荫，待成活或恢复后才能接受充足的阳光照射，性喜阳光充足，通风凉爽的环境，也能稍耐阴，不择土壤，但栽植在排水通畅、富含有机质的肥沃砂质土壤中长势更好，粘重土壤对其生长不利。　　华南地区多植于庭院。定植时挖的穴宜大些，并施入腐熟有机肥，露地栽培的每年培土施肥2－3次，盆栽的每月施肥一次。定植后充分浇水，不耐干旱，稍耐水湿，2－4天水一次，生长期内每天浇水1～2次，冬季视土壤情况隔2－3天浇一次。稍加遮荫，约一周后再接受日照。待株高约2m左右，需设棚架将其枝条牵引上棚，并进行摘心，促使萌发更多的侧枝，多开花。　　天旱时及时浇水，生长期间约每月施一次腐熟饼肥水，则生长旺盛，开花繁茂。夏季可每月施一次蹄角泡制度液肥，立秋后植株进入应停止施肥。植株依其卷须固着生长，生长期间切忌翻蔓，折断卷须，否则影响其水分与养分的吸收，造成开花不良甚至不开花。为热带植物，喜温暖，不耐寒冷，冬季温度不宜低于10度。', '　　由于　　\n一、扦插繁殖\n　　扦插于3月中下旬，选择1年生的粗壮枝条作插穗，插入湿沙床内喷雾保湿，当气湿稳定在20℃左右时，插后约25天发根，成活率可达70％。约1个半月左右，可移入圃地培育，1年生苗可出圃定植，翌年可开花，第三年可绿化成景。也可采老茎扦插，即选用基部抽生的粗壮老茎，长可达2米以上，扦插于肥沃砂壤土中，保持半阴，约50～60天开始发根，当年任其抽枝长叶。　　\n二、压条繁殖\n　　压条主要是利用落地的藤蔓，在叶腋处伤皮压土，从春到秋均可进行，以夏季为最宜。20～30天可发根，1个半月左右剪下成新株，当年即可开花。多作盆花栽培，或直接压条于', 'http://img.boqiicdn.com/Data/BK/P/imagick45701443520053.jpg', 'http://www.boqii.com/entry/detail/2088.html', '');
INSERT INTO `plant_family` VALUES ('438', '鸳鸯茉莉', 'Brunfelsia latifolia Benth.', '鸳鸯茉莉', '番茉莉、二色茉莉', '不容易死', '', 'http://www.boqii.com/entry/photo/2122/0,http://www.boqii.com/entry/photo/2122/5405', '植物　　', '被子植物门', '双子叶植物纲', '茄目', '茄科', '鸳鸯茉莉属', '鸳鸯茉莉', 'Brunfelsia latifolia Benth.', '', '　　 　　鸳鸯茉莉为多年生常绿灌木，是华北夏季露天摆放和冬季室内布置的优良', '　　鸳鸯茉莉原产于中美洲及南美洲热带，其耐寒性不强，人工栽培在室内至少要有4小时的光照，只有在充足的光照条件下，鸳鸯茉莉才会开出繁茂的花朵。　　鸳鸯茉莉在华南可地栽也可盆植，在长江流域及其以北，只能盆植。鸳鸯茉莉在期间，要保证充分光照和水肥，及时短截健壮枝，促发侧枝，控制冠形。为使其能多开花，花期前应适当扣水，当花蕾出现后，即恢复正常的水肥管理。　　鸳鸯茉莉生势较弱，但分枝多，一树双色花，且芳香，适用于楼宇、庭院、公园等地点缀或作花篱，亦可盆栽观赏。疏松肥沃沙壤种家庭盆栽宜用腐叶土、菜园土和沙按5：3：2混合作土，忌用粘性土，否则易烂根。种植时在盆花放一层碎硬塑料泡沫块，增强透气、排水，防烂根，并在中加100克至150克骨粉或氮磷钾复合肥。每年早春翻盆换土，宜留宿土1／3左右。喜温怕涝多施肥生长季节要常浇水，并向叶面喷水，保持盆土稍偏湿润而不涝为好，渍水易烂根。冬季休眠期盆土微润不干即可。它喜肥，生长期10天至15天施一次氮磷钾复合肥，忌单施氮肥，否则枝叶徒长而花稀少，休眠期不施肥。　　鸳鸯茉莉喜光喜暖不耐寒生长期宜置于向阳庭院、屋顶花园或南向、西向阳台上多见阳光，但盛夏的中午前后要稍遮荫，此时强光暴晒叶易黄。冬季在最你气温降至5℃左右时搬入室内，置于阳光足的窗台上，3℃以上可，20℃左右还能继续开花。　　鸳鸯茉莉适度修剪株形美置于阳台上的鸳鸯茉莉要注意修剪，常保持30厘米至40厘米高的圆形树冠较美，早春翻盆换土时，留15厘米至20厘米高重剪一次，剪下的健壮枝条可作繁殖用，开花后将残花、内膛枝等轻度修剪即可。', '　　鸳鸯茉莉又名双色茉莉，是华北夏季露天摆放和冬季室内布置的优良盆栽', 'http://img.boqiicdn.com/Data/BK/P/imagick20571444901318.jpg', 'http://www.boqii.com/entry/detail/2122.html', '');
INSERT INTO `plant_family` VALUES ('439', '宝石花', 'Graptopelaum Paraguayense', '宝石花', '', '不容易死', '原产于墨西哥，现世界各地均有栽培', 'http://www.boqii.com/entry/photo/1933/0,http://www.boqii.com/entry/photo/1933/5597', '　　', '种子植物门', '双子叶植物纲', '蔷薇目', '景天科', '拟属', '', 'Graptopelaum Paraguayense', 'Houseleek', '　　 ', '　　的外形娇小，是近几年非常流行的小型多肉植物，并且宝石花算是多肉植物中比较容易栽培的品种了，但是由于很多新手朋友对于宝石花的习性不了解，所以还是会出现将宝石花养死的情况。　　1、春季适合布置在东、南、西朝向阳台上。春季应布置在有光照的窗台。春初气温较低时，宝石花处于半休眠状态，应严格控制浇水，使盆土处于偏干至干燥状态。春季气温稳定在10℃以上时换盆，亦可在9～10月进行。盆土最好使用疏松、排水好的沙质壤土。土壤配好后最好高温后使用，亦可在太阳下曝晒杀菌。一般2年换盆1次。换盆前停止浇水数日，使盆土干燥后脱盆，除去根部全部土壤，修剪去枯死根、断根，放置3～5天，阴干伤口后栽种。如伤口较大，应多晾1～2天待伤口干结后栽种。栽后放置于半阴处，暂不浇水，2～3天后略浇水，保持盆土偏干。气温升高后，开始恢复，可逐步加大浇水量，使盆土湿润偏干，切忌土壤过湿，以土壤干透后再浇为宜。保证充足的光照。生长旺季注意可少量施肥。雨水较多的天气应减少浇水次数。　　2、夏季适合布置在东、南、西朝向阳台上。宝石花耐高温烈日。但光照过强叶片易老化，影响观赏效果，因此气温炎热时应布置于早晚有光照的阳台或窗台上。气温较高时生长减缓，应注意控水，防止高温多湿引起烂根。夏末气温凉爽后移至光照下培养，并增加浇水量。　　3、秋季适合布置在东、南、西朝向阳台上。秋季应放置在有充足的光照而无雨淋的地方培养。气温凉爽后，停止施肥。天气渐凉时可逐步减少浇水量，使盆土偏干至干燥，直至休眠。当气温降至5℃左右时，应防。　　4、冬季适合布置在东、南、西朝向阳台上。宝石花不耐寒，冬季阳台内气温应保持在5。C以上。此时宝石花处于半休眠状态，应严格控制浇水，使盆土处于偏于至干燥状态。保证充足的光照。阳台内气温在10℃以上时，可缓慢生长，此时应适当浇水。', '　　　　宝石花常用扦插，于春、夏进行。茎插、叶插均可。宝石花栽种不用种子，只要在宝石花上剪下一片叶子，叶插时将完整的成熟叶片平铺在潮润的沙土上，叶面朝上，叶背朝下，不必覆土，放置阴凉处，10天左右从叶片基部可长出小叶丛及新根。也可搞分株繁殖，最好在春天进行。常用扦插繁殖。室内扦插，四季均可进行，以8－10月为更好，生根快，成活率高。插穗可用单叶、蘖枝或顶枝，剪取的插穗长短不限，但剪口要干燥后，再插入沙床。插后一般20天左右生根。插壤不能太湿，否则剪口易发黄　　在北方宜温室盆栽。每年三、四月间换盆一次，加些磷肥。平时不施肥也可以，它虽然是耐阴植物，但', 'http://img.boqiicdn.com/Data/BK/P/imagick73781439371850.jpg', 'http://www.boqii.com/entry/detail/1933.html', '');
INSERT INTO `plant_family` VALUES ('440', '仙客来', 'Cyclamen persicum Mill.', '仙客来', '萝卜海棠、兔耳花、兔子花、一品冠、篝火花、翻瓣莲', '不容易死', '原产希腊、叙利亚、黎巴嫩等地；现已广为栽培。', 'http://www.boqii.com/entry/photo/2009/0,http://www.boqii.com/entry/photo/2009/5518', '', '', '', '', '', '', '', '', '', '　　 　　仙客来花葶高15－20厘米，果时不卷缩；花萼通常分裂达基部，裂片三角形或长圆状三角形，全缘；花冠白色或　　　　　　　　　　　　　　　　　　　　', '　　在夏季会进入休眠状态，由于仙客来的比较多，但每个品种都会带有香气，虽然可能香味有浓郁和淡雅之分，所以仙客来是非常适合栽种在室内的。那么在栽种仙客来的时候又有哪些问题是需要注意的呢？　　　经常保持土壤湿润，根部不要积水。仙客来在水分吸收方面有些矛盾，它非常喜欢湿润的环境，但又害怕水太多，因此我们给它浇水的时候，要每天适量浇一次水以保持盆土的湿润度，同时还要控制浇水量，盆土上务必不要积水以免水大腐蚀了它的根部。夏天时要多多为其喷水，以保证正常的水分吸收量。　　　　期每十天施一次薄肥，花期少施或不施氮肥。仙客来是比较喜肥的，但它喜的是薄肥，特别是在它的生长期，我们每隔十天左右就要给它施一次薄肥，等到仙客来孕蕾的时候还要再追施一次液肥。开花期的时候尽量少施肥，就算施肥也是偶尔施一次薄肥，氮肥就不要施了。施肥时要特别小心不要将肥水直接浇在花叶上，不然很容易被腐蚀。　　　阳光照射要温暖和煦，夏天避免阳光直射，且要遮荫。在阳光比较温暖且不刺目时，可以让仙客来多多接受阳光的照射，充足的阳光有利于促进花开，夏天的时候尽量将仙客来放在有散射光照射之地，必要的时候要对其遮荫，以免被炽热的阳光晒伤。　　　仙客来的养殖地点还要有良好的通风条件天气过于闷热四周环境又不通风时，仙客来很容易就会休眠。此外适宜的对仙客来的生长也很重要，白天尽量维持在20度，夏天过热时，一定要做好降温遮荫工作，冬天的话，室内的温度尽量不要低于十度，不然会影响仙客来的正常生长。', '　　仙客来是非常普遍的观花　\n　一、播种繁殖\n　　仙客来播种繁殖的　\n　二、分割块茎繁殖\n　　仙客来虽为多年生球根类花卉，但其块茎不能自然分生子球，因而不能像一般球根花卉那样分球繁殖。在园艺生产上，仙客来大都作一二年生栽培，一二年生植株　　\n三、组织培养繁殖\n　　仙客来快速组培繁殖可采用花蕊、块茎、叶片、幼茎等作为外植体，一般从一二年生幼株上采集，其中以块茎作为外植体最易', 'http://img.boqiicdn.com/Data/BK/P/imagick74751441618658.jpg', 'http://www.boqii.com/entry/detail/2009.html', '');
INSERT INTO `plant_family` VALUES ('441', '杜鹃花', 'Sims Azalea', '杜鹃', '杜鹃花、山踯躅、山石榴、映山红、照山红、唐杜鹃', '不容易死', '', 'http://www.boqii.com/entry/photo/1922/0,http://www.boqii.com/entry/photo/1922/5607', '', '', '', '', '', '', '', '', '', '　　 　　　　　　　　　　　　　　　　　　　　　　　', '　　杜鹃花全株可供药用，并且观赏价值也颇高，所以在我国都非常有名。虽然杜鹃花原产于海拔500－1200米的山地上或松林下，但是还是有不少花友成功的在家中盆栽了杜鹃花，现在杜鹃花也成为了我国中南及西南典型的酸性土指示。　　栽培养殖杜鹃花首先要选择对的培养土。疏松、排水通畅、通气良好，酸性土壤、腐殖质丰富、基肥充足是养殖好杜鹃的基本条件。酸性土壤会使杜鹃生长得旺盛，但在碱性土壤中，很快会枯萎凋谢。腐叶土一般属于酸性土壤，其中以松叶腐殖土最好，是养殖杜鹃花理想的培养土。在山区松柏林下取土，或庭院种植松柏树多的地下取土。在使用前增加一些硫磺粉、白矾，提高土壤酸性。腐殖质含量高的土壤最适合养殖杜鹃。腐殖质多，可及时补充土壤中的养分，改良土壤结构，使土壤保水，保肥、通气、吸热保温，减轻土壤中危害，促进杜鹃根系扩展。　　给杜鹃花浇水也是一项很重要的工作。杜鹃根系比较细弱，过于干燥或过于湿润对植株生长都不利，因此养殖杜鹃时要特别注意控制水量。在展叶期缺水，就会使杜鹃花叶变黄，枝叶卷曲，如干燥严重，则会使其枯死。开花时缺水，则会使花瓣软瘪，花朵下垂，颜色不鲜艳，甚至会花朵凋谢枯萎。所以给杜鹃浇水必须根据天气、空气湿度和土壤含水量等情况酌情浇水。浇水的时间在清晨傍晚，不宜在中午浇水特别在酷热的夏季。浇水时要注意是不干不浇，浇必浇透，不能浇半截水。用水最好用不含漂白粉等药物和杂质的天然雨水，或者河水、池塘水，不宜长期使用自来水。水质采用经过酸化处理的水最佳。通常的方法是每隔2周时间在土壤表面撒上少量硫酸亚铁，或在水中加入1％的浇灌一次，保持土壤的酸性。　　春秋是杜鹃花生长、开花、育蕾的时期，浇水要适当多些；但在杜鹃花期不能浇太多水，防止花朵过早凋谢。一般倩况下，春秋两季，每隔2－3天浇1次。夏季萌发新枝，生长旺盛，消耗的水分多，加之气温高，空气干燥，需每天浇足1、2次。如果连续几天不下雨，空气干燥，则应用细眼喷壶向花叶喷水，增加空气湿度。多雨天，应停止浇水及时排出盆中积水。秋后空气干燥，水分蒸发量大，也要经常浇水保持湿润。花芽分化时，要控制水量，促使花芽成形。花盆移至室内后，浇水量应酌情减少，保持盆土稍有潮湿即可。入室越冬初期，还应该注意开窗通风。如果将杜鹃花长期放置在荫处，则容易发生落蕾现象。越冬室温以10℃左右最佳。不要低于5℃，西洋鹃畏寒，越冬室温不要低于8℃。但温度也不能过高，如过冬季室温过高，新陈代谢加快，会消耗大量养分，不利于翌年杜鹃花的生长发育。　　杜鹃花比较喜肥，养殖杜鹃花较好的方法是采用腐殖熟的饼肥、鱼粉、蚕豆或紫云英等。经过腐殖后掺入弱酸性水浇灌，不宜使用动物粪便。春季移出室内后一直到花蕾吐花前，每隔十天施一次薄肥，浓度为12％－18％，连续一个月，促进杜鹃花老叶转绿，新根生长发育。带到杜鹃花谢后，为促使枝叶生长，在5月中旬至7月上旬每隔半月施肥一次稀饼肥水或稀薄矾肥水。若连续阴雨，可施干肥。移入室内前，杜鹃花的生长即将停止前，还应再施肥1、2次磷酸钙等磷肥。每次施肥之后，还应隔2天浇一次清水，并松土，使土壤充分通气。入冬以后，天气渐冷，杜鹃植株停止生长，施肥也应立即停止。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick88461438940747.jpg', 'http://www.boqii.com/entry/detail/1922.html', '');
INSERT INTO `plant_family` VALUES ('442', '发财树', 'Pachira macrocarpa （Cham. et Schlecht.） Walp.', '瓜栗', '瓜栗、中美木棉、鹅掌钱', '不容易死', '亚洲、美洲', 'http://www.boqii.com/entry/photo/1917/0,http://www.boqii.com/entry/photo/1917/5612', '', '', '', '', '', '', '', '', '', '　　 　　　　　　　　　　　　　　　　　　　', '　　发财树的寓意非常好，所以常被人用来栽种在室内，不但可以净化空气，还能够改善家居环境。其实发财树的栽培难度比较低，只要注意栽培方法，你的发财树也能够健康漂亮。　　　发财树性喜高温湿润和阳光照射，也稍耐阴，忌讳阳光直晒。生长适温20℃至30℃。冬季，不可低于8℃。　　　发财树浇水要适宜，夏季室内养殖应该3～5天浇一次水，避免在中午前后用冷水浇花。春秋可5～10天浇一次。冬季一个月浇一次水即可。　　　　发财树为喜肥花木，发财树生长期，每间隔15天就应施一次腐熟的液肥或育花肥，以促进根深叶茂。　　　　发财树对盆土要求比较严格，发财树要求粘重、中度肥沃、有良好排水性能的土壤，盆土应以略潮、排水良好为宜。　　　　根腐病这是一种严重发财树的常见病害，又称为腐烂病。栽护中每隔10－15天喷施、百菌清、甲基托布津等预防叶枯病。', '　　　　插条采集选择生长健壮、无病虫害、性状优良的当年生半木质化枝条，在阴天或无风的早晨剪取，剪留长度为6至7厘米，下切口为马蹄形，位于叶或腋芽下，切口要光滑，利于形成愈合组织。一般每个插条带2个掌叶。注意不要伤及叶片，以利　　适时扦插于6月下旬至8月上旬进行扦插，应在早晚随剪随插。扦插前，将插条的二分之一放于25PPM的（1）号ABT生根液中浸泡20至24小时，取出后用清水冲洗干净。用小木棍在畦面上打孔，然后顺孔插入，再封孔压实。插条较短时可直插，插条较长时可斜插，扦插深度以不歪倒为准，一般3至5厘米。插后及时浇透水，对不正的插条扶正，用塑料布盖好，四周用土压实。　　苗期', 'http://img.boqiicdn.com/Data/BK/P/imagick85091438853639.jpg', 'http://www.boqii.com/entry/detail/1917.html', '');
INSERT INTO `plant_family` VALUES ('443', '韭莲', 'Zephyranthes grandiflora Lindl', '韭莲', '红玉帘、菖蒲莲、风雨花、风雨兰、韭兰', '不容易死', '热带、亚热带地区', 'http://www.boqii.com/entry/photo/2382/0,http://www.boqii.com/entry/photo/2382/5034', '　', '被子植物门', '单子叶植物纲', '百合目', '石蒜科', '葱莲属', '韭莲', 'Zephyranthes grandiflora Lindl', '', '　　 　　韭莲鳞茎卵球形，直径2－3cm。基生叶常数枚簇生，线形，扁平，长15－30cm，宽6－8mm。花单生于花茎顶端，下有佛焰苞状总苞，总苞片常带淡紫红色，长4－5cm，下部合生成管；花梗长2－3cm；花', '　　韭莲引起外形似韭菜，故此得名，虽然韭莲的花型比较普通，但是成片种植开花时会非常漂亮，有一定的观赏价值。人工栽培韭莲的难度并不高，但需要根据其习性来改变环境。　　韭莲喜温暖，不怕酷暑，耐寒性强，在长江流域能在室外安全，韭莲到冬季叶枯黄，但地下鳞茎不会冻死，翌春又长出新叶。在北方韭莲则应入室。地栽的葱莲和韭莲，秋末冬初将地下鳞茎挖取，晾赶，用微润的沙藏，保持１－５℃，翌春３也再栽。冬季在温室如能保持１５℃以上，光照充足，还可开花。　　韭莲不甚择土，从微酸性到弱碱性土，从沙质土到轻黏土都能适应，以种植在肥沃深厚的沙质土中最佳，可用腐叶土、菜园土各半，掺少量沙，再加点骨粉、氮磷钾复合肥混合成土，盆植者宜在盆底放层碎硬塑料泡沫块或碎砖瓦，以利透气排水。种植时宜将根剪短，浅栽稍露鳞茎颈，使其鳞茎少分蘖，而集中营养开花，如深栽鳞茎，分蘖多、开花少。　　韭莲喜阳光充足的环境，越晒开花越多，半阴处虽也能生长开花，但花少，花期短，过阴则花极少甚至无花。入秋后植株地上部分枯黄时，小心将鳞茎从土中掘出，然后进行分级、晾晒。可将已好的鳞茎置于相对湿度为30％～35％，为2～4℃的环境中进行保存。韭莲的球根通常在上述条件下可贮藏90～100天而不致影响其使用效果。', '　　　　韭莲可用鳞茎分株繁殖，在南方地区地栽两三年后，可于春季将丛生的地下鳞茎挖出，三四个一窝另栽即可，北方将沙藏的鳞茎四五个栽一方，可于间隔两年的春季，将鳞茎带土从盆中磕出，去掉老土，用新', 'http://img.boqiicdn.com/Data/BK/P/imagick99781451554757.jpg', 'http://www.boqii.com/entry/detail/2382.html', '');
INSERT INTO `plant_family` VALUES ('444', '姬秋丽', 'Graptopetalum ', '姬秋丽', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2151/0,http://www.boqii.com/entry/photo/2151/5376', '', '', '', '', '', '', '', '', '', '　　姬秋丽为景天科风车草属多肉 姬秋丽 　　姬秋丽单株直径可达3厘米，丛生植株直径可达25厘米以上，高度可达15厘米，多分枝。叶片饱满圆润，倒卵形，朝上一面扁平或轻微凸起，朝下一面凸起，叶尖钝圆。 长度可达1.0－1.5厘米，宽度约为0.5厘米。从基部至顶端叶片逐渐缩小。在光照充足、　　　　　　　　　　　　　　　', '　　姬秋丽为景天科风车草属多肉，适应能力比较强，当光照充足的情况下，姬秋丽的叶片会出现粉色，非常可爱。那么如何才能养出漂亮的姬秋丽呢？　　　姬秋丽夏季温度超过35度就要断水休眠了，应该在阴凉通风的地方，太热植株容易，风筝虽然是露天养，一旦温度高于35度，就会移到明亮的散射光下慢慢开始断水，整个休眠期少水或不给水（注：环境不一样，有的地方的花友可以不休眠）。　　　姬秋丽四季中除了夏季要注意遮阳，其他都可以全日照。　　　土壤可选择泥炭混合了颗粒的浮石或河沙等，土表铺设干净的河沙，配土以透气为主。　　　　夏季由于气温的升高，姬秋丽进入休眠阶段，整个休眠期少水或不给水。到了9月中旬温度下来了，就开始恢复浇水，冬季如果温度能够保持0度以上，都是可以给水的，0度以下就要断水，否则就容易。冬季虽然寒冷，可也不是一个冬季都不给一点水，也会在适当的时候微微给点水在植株的根部，切勿喷雾或给大水，叶心水分停留太久，容易引起腐烂。春季温度上升后就可以慢慢恢复正常给水。', '　　　　姬秋丽砍头繁殖的话，可以用泥炭＋珍珠岩＋　　湿土干种，在恢复', 'http://img.boqiicdn.com/Data/BK/P/imagick6301445937012.jpg', 'http://www.boqii.com/entry/detail/2151.html', '');
INSERT INTO `plant_family` VALUES ('445', '滴水观音', 'dishgyi（dishlia）', '海芋', '滴水观音、狼毒（地下茎）、天芋、观音莲、羞天草、隔河仙等', '不容易死', '南美洲、南亚、东南亚等地', 'http://www.boqii.com/entry/photo/1934/0,http://www.boqii.com/entry/photo/1934/5595', '', '', '', '', '', '', '', '', '', '　　 　　滴水观音为多年生直立草本，植株高达2米，地下有肉质根茎，叶柄长，有宽叶鞘，叶大型，盾状阔箭形，聚生茎顶，端尖，边缘微波，主脉明显。佛焰苞黄绿色，肉穗花序。　　　　　　　　　　　　　　　　　　　　　　', '　　喜欢植物的朋友应该都听过滴水观音有毒的说法，于是很多朋友都会对滴水观音望而却步，小编要提醒你的是，滴水观音的汁液如果误食的话是会引起的，家中有小孩或的家庭最好是不要栽培，以免误食引起中毒。　　　滴水观音虽然对土的要求不是很高，我尝试过普通的田园土、营养土、纯沙、发现用田园土的滴水观音长势比较慢，瘦弱而且感觉营养不良；纯沙养的滴水观音在小苗期长势不错，但是后期效果不佳，滴水观音比较低矮；营养土养殖的滴水观音植株壮、叶片大、而且长势很快，小苗期到一米多高的我的滴水观音用了6个月的样子。　　总结：有条件的花友，最好选择好一点的土，并非一定要用营养土，可以自己配置比较肥沃、透水性好的图。　　　这个各家的情况不同，有的花友养滴水观音喜欢用小盆的，有的喜欢用大盆的，这里要说一下，如果花友想养一盆小盆栽，那么小盆养滴水观音没什么问题，而且滴水观音由于根部收到限制，也不会长的很庞大，但是如果花友希望滴水观音长的很大，放在客厅做为大的绿摆，那么一定要选择大一点的盆，根据经验，盆越大滴水观音长的就越壮，也越好。　　　滴水观音喜欢半阴环境，不过有的花友的滴水观音直接在院子里也长的很好，这里要和花友解释一下为什么说别人的花在某个环境下可以长的很好，自己的确不可以。植物本身对外界环境有一个适应的过程，虽然说滴水观音喜欢半阴的环境，但是为了活着，它也会去适应其他环境，但是这需要一个过程，也就是为什么有的花友会说，自己的花怎么养都不死，那是因为这盆花已经适应了环境。　　下面开始说浇水，大多数植物在微湿的土壤下都是最快的，有的花友很实在问别人，几天浇一次水，如果照着别人说的做了，花基本必死无疑，为什么这么说，之所以说要给花浇水，是因为土干了，要浇水了，但是土为什么会干，因为有植物吸收，自然蒸发，其中蒸发占大多数。蒸发的条件有很多，比如盆的透气性、空气湿度，是否通风等。所以说每一家的情况都是不一样的！花友浇水一定要根据自己的实际情况来定。　　那么滴水观音要如何浇水呢，小盆养的，盆土干了就浇水，要保证水都了可以从盆底漏出来。大盆深盆，盆土表面干了，可以挖开表面的土看看一下（干土和湿土就不要说怎么区分了）如果下面土湿润的或者潮湿的那么不用浇水，一般来说那种深盆一次浇水半个月乃至一个月不浇水都没有问题。', '　　由于滴水观音的汁液是有毒的，素以在为滴水观音进行繁殖操作时需要注意避免　　可用分株，播种等方法。每逢夏、秋　　海芋截干是针对多年生的老株而言，可结合植株的更新，自株体基部离出土面约5厘米处截干，进行茎干扦插繁殖。海芋截干其利有二：一是由于植株失去顶端生长优势，使养分蓄积基部促使根部及茎基大量萌芽，有助于繁殖速度和繁殖量；二是截取的老茎干可切成长度约15厘米左右枝条，置荫处阴晾半天即可插入沙壤土中培植。　　尤其是顶端正在生长的这一段，剪除所有成型叶片后直接独株上盆，扦插与培植同步进行，经两个月　　在老株培植期间，因环境荫湿或夏、秋季每天早、晚对叶面进行喷水养护，老茎干上偶尔会萌生少许新株（尤其是截干处理后留下的茎基上），并且附生许多气根，可以自子株与母株交接处掰下上盆种植。', 'http://img.boqiicdn.com/Data/BK/P/imagick44321439372442.jpg', 'http://www.boqii.com/entry/detail/1934.html', '');
INSERT INTO `plant_family` VALUES ('446', '黑法师', '', '黑法师', '紫叶莲花掌', '不容易死', '摩洛哥加那利群岛。美国加州。中国多地。', 'http://www.boqii.com/entry/photo/1977/0,http://www.boqii.com/entry/photo/1977/5550', '', '', '', '', '', '', '', '', '', '　　 　　黑法师的植株呈灌木状，直立　　　　　　　　　　　　　　　　　　　　　　　　　', '　　黑法师的叶色比较特殊，很多多肉爱好者会将其作为标本来收集，但是现在人工栽培的也越来越多，并且和其他多肉拼盆还能增添观赏性。　　黑法师性喜温暖、干燥和阳光充足的环境，耐干旱，不耐寒，稍耐半阴。可以用肥沃又排水透气良好的土种植，如有火山灰更加理想。冷凉季节，夏季休眠但时间不长。繁殖可在早春剪下莲座叶盘扦插，剩下的茎上会群出蘖芽。如果初夏时扦插非但成活率受影响，且茎上出芽也少。叶插繁殖不易。　　黑法师天气凉爽时生长较好，夏季会有休眠（可半荫），土质要肥沃疏松、光照要充足，浇水不要太频。休眠时应根据气温观察植株状态，相应减少浇水次数，并适当半荫养护，春秋季节是其主要生长阶段，适当加强水肥。冬季根据自身条件结合植株状态来浇灌，并注意防寒，室内有暖气设施的，注意加强光照，根据长势相应浇水。', '　　　　黑法师扦插先说砍头，砍头的位置很重要，并不是说保留很长的枝干成活率就高，实际情况却是相反的，如果保留根茎过长，植株恢复得会很慢，旧的茎部也会枯萎并死去，顶多长出一两个侧枝。但是给黑法师砍头的时候应该注意不要离头部过近，不然容易导致扦插失败。　　黑法师扦插可以在早春剪下莲座叶盘扦插（剩下的茎上会群出蘖芽）。然后进行潮土干插，放在阴凉通风的位置一个星期后，再适当照照散光。　　ps：有的花友舍不得减掉老的根茎，这其实不对，其实木质化的部分并不适合扦插，半木质化的更扦插更理想，而且叶子不宜保留过多。', 'http://img.boqiicdn.com/Data/BK/P/imagick8201440494551.jpg', 'http://www.boqii.com/entry/detail/1977.html', '');
INSERT INTO `plant_family` VALUES ('447', '蕙兰', 'Cymbidium faberi Rolfe', '蕙兰', '中国兰、九子兰、夏兰、九华兰、九节兰、一茎九花、一品九命', '不容易死', '中国、尼泊尔、印度北部', 'http://www.boqii.com/entry/photo/2054/0,http://www.boqii.com/entry/photo/2054/5473', '', '', '', '', '', '', '', '', '', '　　 　　蕙兰的花葶从叶丛基部最外面的叶腋抽出，近直立或稍外弯，长35～50（～80）厘米，被多枚长鞘；总状花序具5～11朵或更多的花；花苞片线状披针形，最下面的1枚长于子房，中上部的长1～2厘米，约为花梗和子房长度的1／2，至少超过1／3；花梗和子房长2～2.6厘米；花常为浅黄绿色，唇瓣有紫红色斑，有香气；萼片近披针状长圆形或狭倒卵形，长2。53。5厘米，宽6～8毫米；花瓣与萼片相似，常略短而宽；唇瓣长圆状卵形，长2～2.5厘米，3裂；侧裂片直立，具小乳突或细毛；中裂片较长，强烈外弯，有明显、发亮的的乳突，边缘常皱波状；唇盘上2条纵褶片从基部上方延伸至中裂片基部，上端向内倾斜并汇合，多少形成短管；蕊柱长1.2～1.6厘米，稍向前弯曲，两侧有狭翅；花粉团4个，成2对，宽卵形。　　　　　　　　　　　　　　　　　', '　　的繁多，并且花形红尾壮观，在兰花中，蕙兰的气势非常强，并且，蕙兰在开花后香味浓郁，所以，深受人们的喜爱。有的花友在将蕙兰带回家后不知道应该如何，小编就为你介绍一下蕙兰的养护方法。　　　宜选用深盆、陶盆，养植环境干燥的可用透气性一般的兰盆，阴湿环境应选透气性较好的兰盆。　　　宜选用质量比较好的，如营养土（荷王牌峨眉山仙土）30％，兰石（帝王石）或红砖碎30％，日本产植金石30％，蛇木10％，以上植料混合后筛去粉末备用。　　　　上盆填土时应注意下粗上细，连填土边轻轻震动，让兰根与培养上充分接触充实。填土高度以完全盖住假鳞率为宜，盆口留2厘米左右空间，以利浇水。浇水以不干不浇、浇则浇透为宜。　　　多雨季节应注意防治黑斑病、炭疽病等常见病，可在梅雨季节前或下雨后用、多菌灵、咪鲜胺等杀菌剂交替使用，7～10天喷洒叶面一次。如发生虫害应用省时本、杀虫剂等对症下药，及时处理。　　　每年3～6月，晴天宜将蕙兰放在直射的阳光下晒盆5～6个小时（清晨6时至中午12时），能促使生根发苗。如置于朝向东南阳台养植的可任其接受自然日照，气温超过36℃时应注意避开正午及“西山日”的直射。如发现时尖焦黑，排除肥水过多的因素外，很可能是兰根生至盆底，触壁僵硬，反映到叶面上就会发生焦尖现象，这时应及时翻盆换土。先将兰花起盆，分作3～5苗一丛，再重新上盆栽种，浇道水后置阴凉通风处7～10天，再逐渐增加光照，一月后就可放置阳台上养植欣赏了。　　　兰蕙在一年的期中，除冬季休眠期和盛夏高温期外，春、夏、秋三季都需要施肥。具体的说，兰蕙需要的肥料有催芽肥、生长肥、促花肥和抗热抗寒肥。　　1、催芽肥，是为促进早发芽、多发芽而施用的。出房后即开始使用，以植全为主。　　2、生长肥，是为促进兰株新芽快速生长而施用的，是一年中施用肥料时间最长，次数最多的一种，以喜硕、百肥、植本、多木、好康多等各种肥料成分齐全的有机肥、无机肥、生物菌肥交替使用，根施、叶面施交替进行为好。　　3、促花肥，是为促进花芽发育生长，达到开花、花多、花大、色艳、味香的目的而施用的，以植吉、魔肥为主。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick38861442569512.jpg', 'http://www.boqii.com/entry/detail/2054.html', '');
INSERT INTO `plant_family` VALUES ('448', '山影拳', 'Cereussp.f.monst', '山影拳', '山影、仙人山', '不容易死', '原产西印度群岛、南美洲北部及阿根廷东部。', 'http://www.boqii.com/entry/photo/2202/0,http://www.boqii.com/entry/photo/2202/5325', '　　', '被子植物门', '双子叶植物纲', '石竹目', '仙人掌科', '天轮柱属', '山影拳', 'Cereussp.f.monst', '', '　　 　　山影拳形态似山非山，似石非石，而是一种有生命的、郁郁葱葱、伏层起叠、终年翠绿的多肉植物，因外形峥嵘突兀，形似山峦，故名仙人山。约有3－4个', '　　原产于南美洲，喜欢温暖、干燥及阳光充足的环境。人工栽培山影拳的难度不高，但需要注意的是荫蔽的环境比较容易造成山影拳植株的徒长，出现“返祖”的现象，破坏了植株的美感，大大降低观赏价值。　　山影拳栽培容易，生长迅速，掌块小时，每年换盆，加入疏松园土，每周浇水2－3次，不必施肥。肥水过大，容易，若光线不足，生长细长，影响姿态。生长期需充足阳光，盛夏稍加遮阴，盆土稍干些，使生长速度减慢，保持优美株形。　　山影拳喜欢较干燥的空气环境，阴雨天持续的过长，易受病菌侵染。怕雨淋，晚上保持叶片干燥。最适空气相对湿度为40～60％。温度管理：最适生长温度为15℃～32℃，怕高温闷热，在夏季酷暑气温33℃以上时进入休眠状态。忌寒冷霜冻，温度需要保持在10℃以上，在冬季气温降到7℃以下也进入休眠状态，如果环境温度接近4℃时，会因冻伤而死亡。', '　　　　山影拳的扦插，选择姿态美，生长健壮的掌块，用利刀取下，先放阳光下晒晾干1周，插入沙床，不宜过湿，约35－40天可生根。50天移入盆内养护。嫁接，砧木可用　　山影拳和其他的仙人类　　山影拳的繁殖可在生长季节用健壮充实的肉质茎进行扦插，插穗切下后晾几天，等切口干燥后插于沙土中，保持稍湿润，很容易生根。对于一些稀有品种的山影拳也可用草球（花盛球）、短毛球、三角柱等长势较强的仙人掌类植物作砧木，以平接的方法进行嫁接，等接穗长到一定大小时，将其切下落地扦插，长出自己的根系（俗称“蹲盆”），以加快生长速度，使其尽早成形。', 'http://img.boqiicdn.com/Data/BK/P/imagick83021447147462.jpg', 'http://www.boqii.com/entry/detail/2202.html', '');
INSERT INTO `plant_family` VALUES ('449', '文竹', 'Asparagus fern', 'Asparagus setaceus', '云片竹、山草、鸡绒芝', '不容易死', '中国中部、西北、长江流域及南方各地', 'http://www.boqii.com/entry/photo/1943/0,http://www.boqii.com/entry/photo/1943/5586', '', '', '', '', '', '', '', '', '', '　　 　　文竹根部稍肉质，茎柔软丛生，细长。茎的分枝极多，近平滑。叶状枝通常每10～13枚成簇，刚毛状，略具三棱，长4～5毫米；鳞片状叶基部稍具刺状距或距不明显。　　　　　　　　　　　　　　　　　　　　　　　　', '　　是我国非常常见的室内观叶植物，由于文竹的栽培难度不高，并且叶片翠绿非常漂亮，所以深受人们的喜爱。文竹一般4－5年后才开花，如果不觉得影响美观的话，可不必将花摘掉，但是建议文竹在开花期间不要搬动花盆，这样可以避免落花。　　文竹性喜温暖通风、半阴半湿环境，不耐寒，忌阳光直射，适宜生长在富含腐殖质、排水良好的砂质土壤中。文竹栽培中最关键的问题是浇水。浇水过多，盆土过湿，容易引起根部，叶黄脱落；浇水过少，盆土太干，则容易导致叶尖发黄、叶片脱落。所以，平时浇水量和浇水次数，要视天气、长势和盆土情况而定。做到不干不浇，浇则浇透，不能浇“半腰水”，即浇水只湿润表土，下面土壤仍干燥。以水浇下去后很快渗透而表面又不积水为度。天气炎热干燥时，还要用水喷洒叶面。冬季入室后要减少浇水。室温保持在5℃以上，可安全过。　　文竹生长期，可每半月施一次腐熟的薄液肥，当植株定型后，要适当控制施肥，以免徒长，影响株形美观，适当修剪。盆栽文竹，每年最好换一次盆，宜在春季进行。文竹怕烟尘，放置地点要通风，一般很少有病害。　　文竹栽培管理中最关键的问题是水分的供给。因此浇水是否适当就成为养好文竹成败的重要一环。浇水过多，盆土过湿，易引起根部腐烂，叶黄脱落；浇水过少，盆土长期干旱，又易引起叶尖发黄、脱落。所以，生长期间，浇水量和浇水次数要看天气、苗势和盆土干湿情况而定。平日浇水以浇入盆中的水很快渗入土中而土面不积水不度。不干不浇，浇就浇透，不能浇“半腰水”，即浇水量只湿润表土，下面土壤干燥，造成底部根系吸收不到水分，这样枝叶也会枯黄。天气干燥或炎热时，除需保持盆土湿润状态外，还需经常向植株周围地面洒水和用清水喷洗枝叶，以增加空气湿度。冬季入室后要减少浇水次数，经常喷洗枝叶，以保持植株嫩绿清新。', '　　　　要使文竹结籽，也不是一件容易的事，必须精心　　播种前先搓去浆果外皮，取出种子，在温室内播于浅盆中。盆土可用4份细炉碴、3份壤土、2份粪土、1份河泥混合配制。种子播下后，覆土不要太厚，浇透水，室温保持在15－20℃，每天喷1－2次水，使盆土保持湿润，约一个月左右芽。苗高5厘米左右移栽上盆。　　分株养殖在春季进行。将文竹植株带土从原盆中倒出，用刀将根部分割开，使每株具有3－5个丛生枝，尽量保存一些根上原土，然后分别移栽于备用的花盆中，浇上透水，放置于遮荫处，7－10天内忌晒太阳，以利成活。', 'http://img.boqiicdn.com/Data/BK/P/imagick10721439543978.jpg', 'http://www.boqii.com/entry/detail/1943.html', '');
INSERT INTO `plant_family` VALUES ('450', '蟹爪兰', 'Schlumlergera truncata （Haw.） Moran', '蟹爪兰', '圣诞仙人掌、蟹爪莲、仙指花、锦上添花', '不容易死', '原产巴西、全球热带、亚热带地区', 'http://www.boqii.com/entry/photo/1938/0,http://www.boqii.com/entry/photo/1938/5591', '', '', '', '', '', '', '', '', '', '　　 　　蟹爪兰常见杂交种有白色的圣诞白、多塞、吉纳、雪花；黄色的品种有金媚、圣诞火焰、金幻、剑桥；橙色的安特、弗里多；紫色的品种有马多加；粉色的品种有卡米拉、迪斯托和伊娃等，大多从美国、日本、丹麦等国引进。常规品种有茎淡紫色、花红色的圆齿蟹爪兰，花芽白色、开放时粉红色的美丽蟹爪兰，花芽红色的红花蟹爪兰及拉塞尔、巴克利、钝角、圣诞仙人掌等。　　　　　　　　　　　　　　　　　', '　　的外形比较特殊，其茎叶严重变态成节片装，外形和蟹足非常像，故此命名。蟹爪兰的花色也非常多，但是通常2－3个花蕾只能开出一朵花。对于中国人来说，蟹爪兰的观赏价值非常高，但是想要养好蟹爪兰却没有想象中那么简单，一定要了解蟹爪兰的习性，这样才能养出漂亮，观赏价值高的蟹爪兰。　　蟹爪兰一年的过程中，有二次短暂的休眠期（一次在夏季最炎热时，一次在早春开花后），也有二次生长旺盛期（一次在5月中下旬，一次在10月上中旬）。我们在进行蟹爪兰的养殖时一定要分清，并牢记蟹爪兰的不同生命阶段，才能针对性地做出不一样的养殖措施。具体操作如下：　　秋季生长期，应注意把蟹爪兰放在向阳的窗口，让它充分接受阳光。最好在避风向阳的阳台角落搭建塑料温室，这样，当太阳照射到温室，室内便形成了特殊小气候，保证足够的空气湿度利于蟹爪兰生长。　　秋凉以后，蟹爪兰即可孕蕾进入花期，此时要修剪蟹爪形，将参差不齐的茎节及弱小花蕾剪除。这可以使株形匀称，保持伞状，并使蟹爪兰的整个花期都能长势旺盛，花朵大小如一。　　蟹爪兰花期时，可十天施一次颗粒复合肥，施肥方法是沿盆土浅埋泥土中，盆土见湿见干即可。如果作好蟹爪兰花前的管理，就会在冬季和来年初春看到美丽壮观的蟹爪兰花。　　第二年二月底至三月初的时候，蟹爪兰的花势将逐渐减弱以至结束，蟹爪兰即将进入休眠期。原来挂花的那些茎节都要全部剪掉，并注意修整花形。　　春分前后，将蟹爪兰放于阳台避雨通风处，保持盆土干燥，同时经常向植株喷些水雾。待休眠期一过，蟹爪兰新芽萌发，就可正常施肥浇水了。', '　　随着人们对于蟹爪兰的喜爱程度原来越深，不断的有新品种被培育出来，现在市场上常见的蟹爪兰都是杂交品种。　\n　一、扦插繁殖：\n　　\n二、嫁接繁殖：\n　　蟹爪兰嫁接的砧木可选用仙人掌、量天尺等。下面以量天尺为例，介绍其嫁接方法，此法于4月至5月进行，选取健壮的量天尺做砧木。　　\n三、播种繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick67901439458054.jpg', 'http://www.boqii.com/entry/detail/1938.html', '');
INSERT INTO `plant_family` VALUES ('451', '垂笑君子兰', 'Clivia nobilis Lindl.', '垂笑君子兰', '', '不容易死', '非洲南部以及中国大陆的湖北省等地，已由人工引种栽培', 'http://www.boqii.com/entry/photo/2120/0,http://www.boqii.com/entry/photo/2120/5407', '　　', '被子植物门', '单子叶植物纲', '天门冬目', '石蒜科', '君子兰属', '垂笑君子兰', 'Clivia nobilis Lindl.', '', '　　垂笑 　　垂笑君子兰为多年生草本。根为肉质，灰白色。茎基部宿存的叶基呈鳞茎状。基生叶约有十几枚，质厚，深绿色，具光泽，带状，长25－40厘米，宽3－3.5厘米，边缘粗糙。花茎由叶丛中抽出，稍短于叶；伞形花序顶生，有小花数10－30朵左右，每小花6个花瓣，6个雄蕊1个雌蕊。花色有橙黄、橙红、深红等色。多花，开花时花稍下垂；花被狭漏斗形，桔红色，内轮花被裂片色较浅；雄蕊与花被近等长；花柱长，稍伸出花被外。垂笑君子兰的花期为12月至来年5月，花期长达30－50 天。杂交授粉，浆果、果实未成熟时绿色，种子成熟需要8－9个月。', '　　如果你对', '　　人工栽培垂笑　　1、分株法：待到每年春季开花后，将垂笑君子兰的母株旁的子株分下来独立栽培，一般插在含有沙的土壤中，待到大概两个月过后生根便可以一直到盆中栽培。　　2、播种繁殖：垂笑君子兰的播种繁殖需要在冬季进行，室温必须保持在20摄氏度以上，否则会导致种子', 'http://img.boqiicdn.com/Data/BK/P/imagick62891444816217.jpg', 'http://www.boqii.com/entry/detail/2120.html', '');
INSERT INTO `plant_family` VALUES ('452', '凤尾竹', 'Bambusa multiplex ‘Fernleaf’', '', '', '不容易死', '云南、广东、广西、四川、福建等地及日本、印度、湖北', 'http://www.boqii.com/entry/photo/1900/0,http://www.boqii.com/entry/photo/1900/5629', '', '', '', '', '', '', '', '', '', '　　凤尾竹又名观音竹、蓬莱竹等，在之前的文章中小编为你详细分析了一下观音竹叶片发黄的处理方法，这里，小编就为你详细讲解一下观音竹的种植栽培方法与繁殖要点，新手花友们可以参考学习一下。 　　　凤尾竹需要　　1、土壤：凤尾竹喜酸性、微酸性或中性土壤，家庭盆栽可选用腐叶土、园土、河沙各1／3混合配制的　　2、阳光：凤尾竹喜光，室内养护时春、夏、秋三季放朝南窗台附近通风处，冬季放阳光充足的地方，便能生长良好。若放室外培养时，春、秋季节可多接受些光照，夏季要注意遮阳，避免强光曝晒，否则枝叶易发黄，影响美观。　　3、温度：凤尾竹为常绿丛生灌木。喜温暖湿润和半阴环境。耐寒性稍差，不耐强光曝晒，怕渍水，宜肥沃、疏松和排水良好的壤土。冬季温度不低于0度。　　4、浇水：生长期间浇水要适量，保持盆土湿润即可。气候干燥和炎夏季节要经常用清水喷洗叶片，以利保持叶片碧绿。　　5、施肥：凤尾竹在生长期间，每隔20天左右需施1次液肥。凤尾竹肥料以有机肥为主，液肥可用腐熟稀薄的豆饼水，或复合液肥。冬季应停止施肥。　　6、修剪：凤尾竹在生长过程中老竿逐渐枯萎，应及时剪去，以保持优美的姿态。　　　凤尾竹的繁殖多用分株和扦插繁殖。分株，在2—3月间选一二年生母竹3～5株为一丛带土分栽。扦插，在5—6月进行，将一年生枝剪成有2～3节的插穗，去掉一部分叶片，插于沙床中，保持湿润，当年可生根。 　　　栽需在2－3月进行。盆栽，每2～3年换盆1次，将老竹取出，扒去宿土，剪除细小地下茎和老竹，加入肥土。生长期保持盆土湿润，放半阴处养护，勤向叶面喷水，每月施肥1次。冬季搬入室内向阳处。　　　常发生叶枯病和锈病，用65％代森锌可湿性粉剂600倍液　　　凤尾竹株丛密集，竹干矮小，枝叶秀丽，常用于盆栽观赏，点缀小庭院和居室，也常用于制作盆景或作为低矮绿篱材料。　　凤尾竹其实是孝顺竹的一种变异品种，凤尾竹的株型矮小，叶片细密婆娑非常像凤尾。凤尾竹也会开花，但是花期不固定，有些种终生只有一次花期，所以一般人们会将凤尾竹当做观叶', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick24541428055532.jpg', 'http://www.boqii.com/entry/detail/1900.html', '');
INSERT INTO `plant_family` VALUES ('453', '白龙球', 'Mammillaria compressa', '白龙球', '', '未知', '中南美洲', 'http://www.boqii.com/entry/photo/2491/0,http://www.boqii.com/entry/photo/2491/4836', '　', '', '', '', '科', '乳突球属', '', 'Mammillaria compressa', '', '　　 　　白龙球茎球形至棒状，淡灰绿色，球顶部被白色绵毛；疣状突起短粗，腋部有白绵毛及长的白刺毛；刺座上最初有白绵毛，后脱落；刺多为4，有时为5－7，下方刺向外弯曲，2－7厘米长，其它的刺则较短，初为红色，后变白或灰，刺端暗色；花小，钟形，着生于球顶部，呈环状排列，1－1.5厘米长，粉红色。', '　　原产于中南美洲，主要分布在墨西哥中部，人工栽培的难度并不高。由于白龙球在栽培过程中会开出红色的小花，非常漂亮，有一定的观赏价值，也是很多仙人掌爱好者的品种。　　白龙球喜温暖干燥和阳光充足的环境，不耐寒。耐半阴和干旱，怕积水，15℃－25℃，过冬最低不能低于7℃，适宜在肥沃，疏松和排水良好的沙质土壤种植。中国广大地域冬季须如室。　　白龙球性强健，生长较快，容易长成很大的株丛，喜阳光充足，但亦耐半阴，栽培要求肥沃的砂质壤土。白龙球在春季至初秋，每2周浇水一次，盆土可保持一定的湿度，冬季应停止浇水，生长期每月施肥1次，建议薄肥。', '　　　　白龙球的繁殖可切取子球扦插，极易成活。白龙球习性强健，', 'http://img.boqiicdn.com/Data/BK/P/imagick63591455614546.jpg', 'http://www.boqii.com/entry/detail/2491.html', '');
INSERT INTO `plant_family` VALUES ('454', '黄毛掌', 'Opuntia microdasys', '黄毛掌', '金乌帽子', '不容易死', '原产墨西哥北部， 中国也有引种栽培。', 'http://www.boqii.com/entry/photo/2450/0,http://www.boqii.com/entry/photo/2450/4966', '', '', '', '', '', '', '', '', '', '　　黄毛掌是比较常见的 黄毛掌 　　黄毛掌的植株直立多分枝，灌木状，高60厘米至1米。茎节呈较阔的椭圆形或广椭圆形，黄绿色。刺座密被金黄色钩毛。夏季开花，花淡黄色，短漏斗形。浆果圆形，红色，果肉白色。　　　　　仙人掌科　　　　', '　　原产于墨西哥北部，现在在我国有引种栽培，也是非常常见的仙人掌之一。黄毛掌的外形和兔耳朵非常像，并且有一定的抗辐射的能力，是很好的室内观赏。　　黄毛掌喜温暖干燥和阳光充足环境。较耐寒，耐干旱，不耐水湿。对土壤要求不严，以肥沃的沙壤土较好。冬季温度不低于5℃。穗生根后，应及时分栽上盆，否则已生根的插穗易。盆土可用堆肥、壤土各半，再加5％的蛋壳粉和匀最好。春季换盆或新栽植株，不宜立即浇水，只需喷水，使盆土稍湿润即行。　　给黄毛掌水不能过多浇灌，宁干勿湿，生长期需充足阳光，每月施肥1次，肥宜薄肥勤施，但需注意勿将肥液浇在掌上，如已浇在掌上，应立即用清水淋洗，以免腐烂，影响观赏。　　在室内养黄毛掌，可以吸收空气中一氧化碳、二氧化碳和氮氧化物，净化空气。还可以提高空气中负离子浓度，使空气保持清新，有益身体健康。', '　　黄毛掌又名金乌帽子，是非常常见的　\n　一、扦插\n　　多在生长　　插床内基质一般不要铺得太厚，否则不利于基质温度提高，影响生根。插穗剪取后，应晾3～5天，等切口干燥后再插。不宜插得过深，以插穗基部稍入基质为适。插后尽可能保持在生根最适温度（20～25℃）范围内，可以用通风、遮荫或加温的手段调节。扦插基质要保持适度潮润，不可太干或太湿。　　基质内尽可能保持足够的氧气，要定期通风。在插穗少而盆大的情况下，插穗尽量往盆边插，盆边透气好有利生根。光照应适度减弱，随着根的形成、生长，光照可逐步增加。　\n　二、播种\n　　黄毛掌在春季进行，在20～25℃的温度下，发芽非常容易。播后10天左右发芽，幼苗生长很慢，需谨慎', 'http://img.boqiicdn.com/Data/BK/P/imagick88601453714987.jpg', 'http://www.boqii.com/entry/detail/2450.html', '');
INSERT INTO `plant_family` VALUES ('455', '粉苞酸脚杆', '', '粉苞酸脚杆', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2426/0,http://www.boqii.com/entry/photo/2426/4989', '植物　', '被子植物门', '双子叶植物纲', '桃金娘目', '', '酸脚杆属', '', '', '', '　　 　　粉苞酸脚杆的茎四棱或有四翅，分枝扁平，节上有疣状突起。叶对生，卵形或卵状长圆形，无柄，革质，叶表的叶脉内陷。穗状花序下垂，长45厘米，花冠直径2.5厘米，红色；花药顶具喙；花瓣4，倒卵形至圆形；外苞片长3～10厘米，粉红色。浆果球形，粉红色，萼片宿存。', '　　', '　　　　粉苞酸脚杆主要用扦插或播种繁殖。扦插在初夏6～7月或秋季9～10月进行，选半木质化嫩枝，长15～18厘米，插于泥炭', 'http://img.boqiicdn.com/Data/BK/P/imagick27101452762689.jpg', 'http://www.boqii.com/entry/detail/2426.html', '');
INSERT INTO `plant_family` VALUES ('456', '厚萼凌霄', 'Campsis radicans （L.） Seem.', '厚萼凌霄', '美国凌霄，杜凌霄', '不容易死', '', 'http://www.boqii.com/entry/photo/2440/0,http://www.boqii.com/entry/photo/2440/4976', '植物界', '被子植物门 Angiospermae', '双子叶植物纲 Dicotyledoneae', '管状花目 Tubiflorae', '紫葳科 Bignoniaceae', '凌霄属 Campsis', '厚萼凌霄', '', 'Campsis radicans （L.） Seem.', '　　厚萼 　　厚萼凌霄为藤本，具气生根，长达10米。小叶9－11枚，椭圆形至卵状椭圆形，长3.5－6.5厘米，宽2－4厘米，顶端尾状渐尖，基部楔形，边缘具齿，上面深绿色，下面淡绿色，被毛。，至少沿中肋被短柔毛。花萼钟状，长约2厘米，口部直径约1厘米，5浅裂至萼筒的1／3处，裂片齿卵状三角形，外向微卷，无凸起的纵肋。花冠筒细长，漏斗状，橙红色至鲜红色，筒部为花萼长的3倍，约6－9厘米，直径约4厘米。蒴果长圆柱形，长8－12厘米，顶端具喙尖，沿缝线具龙骨状突起，粗约2毫米，具柄，硬壳质。', '　　厚萼)为紫葳科紫葳属的，原产北美，为落叶灌木，有气生根，在我国南方、东南亚地区均有栽培。厚萼凌霄不但可以观赏，还有一定的药用价值。　　厚萼凌霄原产美洲，国内在广西、江苏、浙江、湖南栽培作庭园观赏植物；在越南、印度、巴基斯坦也有栽培。厚萼凌霄喜光，稍耐庇荫，喜温暖，湿润，尚耐寒。耐干旱，也较耐水湿。对土壤要求不严，萌蘖性强。喜疏松、排水良好的土壤。', '　　厚萼　　\n一、扦插繁殖\n　　厚萼凌霄扦插多选带气生根的硬枝春插，夏季压条。分株多用根蘖，播种繁殖的幼苗应行遮荫，每年需要冬剪，疏除过干枯枝。花前追肥水，可促其叶茂花繁。可在春季或雨季进行，北京地区适宜在7－8月。截取较坚实粗壮的枝条，每段长10－16cm，扦插于砂床，上面用玻璃覆盖，以保持足够的　\n　二、压条繁殖\n　　厚萼凌霄在7月间将粗壮的藤蔓拉到地表，分段用土堆埋，露出芽头，保持土湿润，约50天左右即可生根，生根后剪下移栽。南方亦可在春天压条。　\n　三、分株繁殖\n　　宜在早春进行，即将母株附近由根芽生出的小苗挖出栽种。', 'http://img.boqiicdn.com/Data/BK/P/imagick83291453280822.jpg', 'http://www.boqii.com/entry/detail/2440.html', '');
INSERT INTO `plant_family` VALUES ('457', '滇山茶', 'Camellia reticulata Lindl.', '滇山茶', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2432/0,http://www.boqii.com/entry/photo/2432/4983', '植物　', '被子植物门', '双子叶植物纲', '侧膜胎座目', '山茶科', '山茶属', '滇山茶', 'Camellia reticulata Lindl.', '', '　　 　　滇山茶是灌木至小乔木，有时高达15米，嫩枝无毛。叶阔椭圆形，长8－11厘米，宽4－5.5厘米，先端尖锐或急短尖，基部楔形或圆形，上面干后深绿色，发亮，下面深褐色，无毛，侧脉6－7对，在上面能见，在下面突起，边缘有细锯齿，叶柄长8－13毫米，无毛。', '　　原产于中国云南，繁多，可以说是云南产的各种红花山茶中比较有特色的观花。滇山茶和异叶山茶比较像，与该种的区别在于叶基部圆形，先端稍钝，花重瓣，雄蕊变少，它只是一个栽培品种。盆栽滇山茶应该注意哪些呢？小编就为你总结一下。　　盆栽滇山茶可根据幼苗不同长势配不同的花盆。上盆时，先用瓦片2－3片，置于盆底排水孔上。上面铺垫一层粗烂土或陶粒等，再加上羊、牛角碎片等骨料基肥，基肥层一般不超过盆高三分之一。在基肥层上面加入有机肥如腐熟猪粪。最后加入细红土覆盖，植株栽植避免根系直接接触有机肥，在根系四周放入混有腐叶及骨料的中粒土，并将土捣实，再盖上混有腐叶土的细土，最上层铺碎瓦片作保护土层。盆栽需每隔2－3年换盆1次，换盆时间以新枝木质化并略转褐色时为宜。过迟换盆会影响花芽的分化，过早则会影响新枝的发育。换盆前1－3天停止浇水，使盆土干燥。便于“脱盆”。脱盆时尽量保证土球完整性。并清除底部的害虫及烂根、病根。盆pH为5～5。5左右较好。　　滇山茶最适宜的生长发育温度为18－24℃。超过32℃。生长受抑制：在－5℃以下则发生冻害。不同品种的滇山茶对低温的抵抗力有差别，如麻叶桃红、牡丹茶、恨天高、童子面等就特别不耐寒。0℃时花蕾就会脱落，在栽培过程中要注意采取相应的降温防冻措施。　　盆栽滇山茶，土壤要求保持一定的湿度，实践中，常用手指敲打盆壁，土干则音较脆，土湿则音较闷实。浇水时间依据温度变化而定。气温高的季节，在上午或下午温度较低时浇水。地栽滇山茶特别注意要浇定根水及开花前，新梢生长期要有充足的水分保证。其余依据不同天气情况，进行浇灌。旱季每月灌溉2－3次，以湿透耕作层为宜。', '', 'http://img.boqiicdn.com/Data/BK/P/imagick22691452850528.jpg', 'http://www.boqii.com/entry/detail/2432.html', '');
INSERT INTO `plant_family` VALUES ('458', '爆仗竹', 'Russelia equisetiformis Schlecht.et Cham.', '爆仗竹', '爆竹花，吉祥草', '不容易死', '墨西哥及中美洲', 'http://www.boqii.com/entry/photo/2441/0,http://www.boqii.com/entry/photo/2441/4975', '　　', '', '', '', '玄参科', '爆仗竹属', '', 'Russelia equisetiformis Schlecht.et Cham.', '', '　　 　　爆仗竹为多分枝丛生半灌木，高约1m，茎初直立，先端弯垂，花时因重力作用而下垂。小枝轮生，细长，节明显。叶卵形或线状披针形，多退化而微小。由聚伞花序组成的大型圆锥花序具花多朵，向下弯垂；花鲜红色，花冠管状，略二唇形，长约2.5cm。蒴果球形。花期主要在3～6月，暖地常终年开花不绝。', '　　', '　　　\n　一、扦插繁殖\n　　常于春末秋初用当年生的枝条进行嫩枝扦插，或于早春用去年生的枝条进行老枝扦插。家庭扦插限于条件很难弄到理想的扦插基质，建议使用已经配制好并且消过毒的扦插基质；用中粗河砂也行，但在使用前要用清水冲洗几次。海砂及　　进行嫩枝扦插时，在春末至早秋植株生长旺盛时，选用当年生粗壮枝条作为插穗。把枝条剪下后，选取壮实的部位，剪成5～15公分长的一段，每段要带3个以上的叶节。剪取插穗时需要注意的是，上面的剪口在最上一个叶节的上方大约1公分处平剪，下面的剪口在最下面的叶节下方大约为0.5公分处斜剪，上下剪口都要平整（刀要锋利）。进行硬枝扦插时，在早春气温回升后，选取去年的健壮枝条做插穗。每段插穗通常保留3～4个节，剪取的方法同嫩枝扦插。　　\n二、压条繁殖\n　　选取健壮的枝条，从顶梢以下大约15～30公分处把树皮剥掉一圈，剥后的伤口宽度在一公分左右，深度以刚刚把表皮剥掉为限。剪取一块长10～20公分、宽5～8公分的薄膜，上面放些淋湿的园土，象裹伤口一样把环剥的部位包扎起来，薄膜的上下两端扎紧，中间鼓起。约四到六周后生根。生根后，把枝条边根系一起剪下，就成了一棵新的植株。', 'http://img.boqiicdn.com/Data/BK/P/imagick35911453281235.jpg', 'http://www.boqii.com/entry/detail/2441.html', '');
INSERT INTO `plant_family` VALUES ('459', '美丽莲', 'Graptopetalum bellum', '美丽莲', '别露丝', '不容易死', '原产墨西哥', 'http://www.boqii.com/entry/photo/2442/0,http://www.boqii.com/entry/photo/2442/4974', '　　', '', '', '', '景天科', '风车草属', '美丽莲', 'Graptopetalum bellum', '', '　　 　　美丽莲的叶片呈莲座状排列，肉质叶灰绿至灰褐色，卵形，顶端有小尖。花星状，5瓣，深粉红色。美丽莲从前单独一属，称为别露丝。', '　　美丽莲在过去是单独一属，音译名为布鲁丝（别露斯）、贝拉、蝶露珠。美丽莲为小型多肉，直径约为7－8厘米，美丽莲最特别的地方是其开花非常漂亮，这也正是其的来源。　　美丽莲原产地直射光并不强烈，因此美丽莲相对会更耐阴一点，光照不强也不至于徒长明显，同时也耐晒，非夏季露养半露养问题不大，夏季则应当注意遮阴通风控水，冬季控水可耐0℃左右的低温。配土应当选择疏松透气的土壤，如泥炭珍珠岩比例约为3：2的配土。平时浇水可选择土壤接近干透的时候浇透，因为美丽莲叶片光滑又紧贴的关系，基本不用担心叶心会积水。　　也由于叶片紧贴的关系，美丽莲也蛮容易患的，一般发现的时候蚧壳虫也已经密密麻麻，值得庆幸的是，美丽莲的抗药性蛮强的，不太需要担心会造成药伤，蚧必治一喷，又是清清白白的大美女。春季是美丽莲开花的，可在浇水的时候适当施肥，给予足够的营养开花。美丽莲夏季度夏也不用太操心，不管是半露养还是遮阴，都能度过。', '　　　　美丽莲的繁殖可用播种法，但爱好者更多为枝插（叶腋间长出的侧枝）和叶插，也可结合换盆时进行分株。夏季可放室外', 'http://img.boqiicdn.com/Data/BK/P/imagick86001453367358.jpg', 'http://www.boqii.com/entry/detail/2442.html', '');
INSERT INTO `plant_family` VALUES ('460', '青凤凰', '', '青凤凰', '', '未知', '', 'http://www.boqii.com/entry/photo/2483/0,http://www.boqii.com/entry/photo/2483/4933', '', '', '', '', '景天科', '瓦松属', '', '', '', '　　 　　青凤凰和子持非常象，唯一不同的是叶片', '　　很多花友或许会将青凤凰和', '　　　　青凤凰主要靠植株基部蘖芽（砍头后从残存茎根上长出的新芽）延续后代，青凤凰相对于带锦的凤凰和富士要容易长侧芽，可以靠砍头繁殖。浇水是干透才浇透，不干不浇水。', 'http://img.boqiicdn.com/Data/BK/P/imagick51011454490880.jpg', 'http://www.boqii.com/entry/detail/2483.html', '');
INSERT INTO `plant_family` VALUES ('461', '樱麒麟', 'Pereskia nemorosa', '樱麒麟', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2470/0,http://www.boqii.com/entry/photo/2470/4947', '　　', '被子植物门', '双子叶植物纲', '仙人掌目', '仙人掌科', '叶仙人掌属', '', 'Pereskia nemorosa', '', '　　 　　樱麒麟外形呈灌木或藤本状。株高一般6～7米，最高可达15米。枝条较粗壮，茎部光润，节部明显，虽然多肉，但易木质化。叶基腋处生有数枚深褐色长锐刺。叶片多肉质而肥厚，有短柄，表面光滑具蜡质，全缘，叶亮绿色。总状花序顶生，花淡紫红色，辐射状，直径5～6厘米，花期5～10月。', '　　是唯一一种带叶的类，观赏效果极佳，所以受到很多花友的喜爱。人工栽培樱麒麟的难度并不高，其生性强健，抗旱能力较强，但是不耐寒，所以人工栽培需注意给予适宜的环境。　　樱麒麟生性强健，喜温暖湿润的环境，抗旱力强，不耐寒，既喜阳也能耐阴，耐瘠薄，对土质要求不是很严，使用一般的田园土栽培，就能枝繁叶茂。我国华南大部分地区均可露地栽培，北方可盆栽观赏。　　盆栽樱麒麟宜使用富含腐殖质、疏松、排水良好的沙质培养土栽植，栽前可在盆的底部放一些碎马蹄片作基肥。其生长期内可充分浇水，保持土壤湿润，但应掌握见干见湿。夏季室外养护需注意雨天盆内切勿积水。每隔10至15天应结合浇水，追施一次腐熟的有机液肥。如水肥管理得当，适宜，其花期可从5月至10月底。　　盆栽植株可在苗高10至15厘米时，进行打头处理，促使多发侧枝，并适度整枝绑扎，使其株形匀称丰满，姿态优美。冬季应将植株置于温度10°C以上室内，温度若低于6°C时，其叶片脱落进入休眠期，木质化的茎不会冻死。盆栽植株每2至3年可进行一次修根换土，以保证植株生长健壮。', '　　　　樱麒麟适宜在高温时节通过扦插进行繁殖。一般在4－9月份进行，每年以5至6月扦插发根最快。采用1至2年生的健壮枝，将枝条截成约10厘米长，带叶节的段作插穗。截口可蘸草木灰或在阴凉通风处晾干。将插穗斜插于干净的沙土中，深度宜3至5厘米为宜。插后遮阴并保持环境湿润，约15天左右可发根，1个月左右即可分栽。', 'http://img.boqiicdn.com/Data/BK/P/imagick21561454060521.jpg', 'http://www.boqii.com/entry/detail/2470.html', '');
INSERT INTO `plant_family` VALUES ('462', '多花指甲兰', 'Aerides rosea Lodd. ex Lindl. et Paxt.', '多花指甲兰', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2446/0,http://www.boqii.com/entry/photo/2446/4970', '植物　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '指甲兰属', '多花指甲兰', 'Aerides rosea Lodd. ex Lindl. et Paxt.', '', '　　 　　多花指甲兰茎粗壮，长5－20余厘米，连同叶鞘粗达2.5厘米。叶肉质，狭长圆形或带状，长达30厘米，宽2－3.5厘米，先端钝并且不等侧2裂。花序叶腋生，常1－3个，不分枝，比叶长；花序柄粗壮，被3枚长约1厘米的鳞片状鞘；花序轴较长，约为花序全长的1／2－3／5，密生许多花；花苞片绿色，质地厚，卵状披针形，长5－7毫米，先端渐尖；花梗和子房白色带淡紫色晕，长12－14毫米；子房棒状，三棱形；花白色带紫色斑点，开展；中萼片近倒卵形，长约12毫米，宽7毫米，先端钝，基部收窄，具4－5条脉；侧萼片稍斜卵圆形，长8毫米，宽7毫米，先端钝，具4－5条脉。', '　　', '　　　\n　一、分株繁殖\n　　成熟多花指甲兰植株一般基部会生出新芽，等新芽基部长出新根之后，可切下来另行栽种。　\n　二、扦插繁殖\n　　切取茎的上部（最好能带有气生根）进行扦插或栽植。', 'http://img.boqiicdn.com/Data/BK/P/imagick53701453369024.jpg', 'http://www.boqii.com/entry/detail/2446.html', '');
INSERT INTO `plant_family` VALUES ('463', '金晃', '', '金晃', '黄翁', '不容易死', '原产巴西南部里约格朗德州', 'http://www.boqii.com/entry/photo/2452/0,http://www.boqii.com/entry/photo/2452/4964', '', '', '', '', '仙人掌科', '南国玉属', '', '', '', '　　 　　金晃茎圆柱形，高60～70cm，直径10cm.，基部易出分枝。棱30或更多，刺座排列紧密。周刺15，刚毛状，长0.3～0.7cm.，黄白色；中刺3～4，长4cm，黄色，细针状。花着生茎顶端，长4cm，直径5cm j黄色。植株高20cm左右才开花，开花时球端白毛增多。', '　　金晃为', '　　　　金晃常用播种、扦插和嫁接繁殖。播种，在4－5月采用室内盆播，播后15－20天发芽，幼苗', 'http://img.boqiicdn.com/Data/BK/P/imagick83661453799270.jpg', 'http://www.boqii.com/entry/detail/2452.html', '');
INSERT INTO `plant_family` VALUES ('464', '彩云球', 'Echinopsis tubiflora', '彩云球', '草球、长盛球', '未知', '原产于南美洲，一般生长在高热、干燥、少雨的沙漠地带', 'http://www.boqii.com/entry/photo/2492/0,http://www.boqii.com/entry/photo/2492/4835', '　　', '被子植物门', '双子叶植物纲', '石竹目', '仙人掌科', '属', '彩云球', 'Echinopsis tubiflora', 'Echinopsis tubiflora', '　　彩云球原产于中美的西印度群岛， 　　彩云球体，茎粗可达30厘米，顶端花座特别发达。7－8年生球体才能开花结实，', '　　', '　　　　播种，自花受精植物，种子容易得到。以春季室内盆播为多，播后2周发芽，发芽率高。实生苗长成的球体，抗性较强。　　嫁接，以4－5年的植株，采用截顶，促其萌发子球，再以量天尺作砧木，采用平接法繁殖，嫁接球', 'http://img.boqiicdn.com/Data/BK/P/imagick9751455614848.jpg', 'http://www.boqii.com/entry/detail/2492.html', '');
INSERT INTO `plant_family` VALUES ('465', '黄雪光', 'Notocactus graessneri（K.Schum）A.Berger', '黄雪光', '', '未知', '原产巴西南部', 'http://www.boqii.com/entry/photo/2484/0,http://www.boqii.com/entry/photo/2484/4932', '植物　　', '被子植物门', '双子叶植物纲', '石竹目', '仙人掌科', '南国玉属', '黄雪光', 'Notocactus graessneri（K.Schum）A.Berger', '', '　　 　　黄雪光的株幅10cm或更大，有50－60条具疣突的棱；顶端有刺；周刺约有50枚，浅黄或金黄色；中刺5－6枚，长约2－3cm；花', '　　是的之一，不但外形独特，具有一定的观赏价值，还有一定的抗辐射的功效。很多花友都会将黄雪光摆放在家中，对净化室内空气有很大的作用。　　黄雪光喜温暖稍有湿润和阳光充足的环境。较耐寒，耐干旱和耐强光。喜含腐殖质丰富的排水良好的腐叶土。冬季温度不低10℃。　　盆栽用排水良好、肥沃的腐叶土或泥炭土加粗沙。期可适当浇水，但盆土不能过湿。全年施肥3－4次，以春、秋季为主。盛夏适当遮阴，但若长期光线不足，黄雪光开花少，花色不鲜艳，黄刺暗淡无光不挺拔，观赏价值欠佳。冬季放室内，保持盆土干燥。', '　　　　黄雪光常用播种和嫁接繁殖。播种，以春季室内盆播为主，播后约8－10天发芽，实生苗', 'http://img.boqiicdn.com/Data/BK/P/imagick13091455441076.jpg', 'http://www.boqii.com/entry/detail/2484.html', '');
INSERT INTO `plant_family` VALUES ('466', '红花文殊兰', 'Crinum amabile', '红花文殊兰', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2428/0,http://www.boqii.com/entry/photo/2428/4987', '　　', '被子植物门', '单子叶植物纲', '', '()科', '文殊兰属', '', 'Crinum amabile', '', '　　红花 　　红花文殊兰的植株高60～100厘米，叶片为大型宽带形，全缘，叶色翠绿。花葶自鳞茎中抽出，顶生伞形花序，每花序有小花20余朵；花被筒暗紫色，花瓣5枚，长条形，红色，边缘为白色或浅粉色的宽条纹，具芳香。', '　　常被用于盆栽观赏，但是在我国比较少见，主要于热带和亚热带地区。红花文殊兰的栽培难度并不算大，但是想要红花文殊兰能够并且开出漂亮的花，就需要注意在栽培过程中注意一些细节。　　红花文殊兰小苗多在春夏二季进行定植。可以使用中型花盆作为。在操作时先填少量盆土，然后放人20－30克马蹄片作为基肥。种苗经扶正填土后，略加按压，并留出沿C1浇透水一次即可。　　红花文殊兰喜微潮偏干的土壤环境，生长旺盛阶段应保证水分的供应，但冬春低温时节应该控制浇水。其对肥料的需求量较多，除在定植时施用适量基肥外，生长旺盛阶段可以梅周追施一次稀薄液体肥料。冬春低温时节，植株，不必进行追肥。红花文殊兰喜日光充足的环境，亦稍耐荫，最好保证植株得天接受II光照射不少于4小时；环境荫蔽，植株生长缓慢，颜色也显得较为暗淡。它喜温暖，不耐寒，在18一30的温度范围内生长较好，越冬温度不宜低于4℃。每月松土一次，有助于根系发育，能够促进植株更好生长。在生长旺盛阶段，植株对光线的要求较多，环境荫蔽会出现偏冠现象，因此要调整光照，定期转盆。在实际栽培中，红花文殊兰会被。卜斑病等所危害，偶尔会受到介壳虫的侵袭。', '　　红花　　红花文殊兰通常用播种和分株繁殖。播种宜在采收后即播，基质用沙质', 'http://img.boqiicdn.com/Data/BK/P/imagick90451452763747.jpg', 'http://www.boqii.com/entry/detail/2428.html', '');
INSERT INTO `plant_family` VALUES ('467', '红花羊蹄甲', 'Bauhinia blakeana  Dunn', '红花羊蹄甲', '红花紫荆、洋紫荆、玲甲花', '不容易死', '', 'http://www.boqii.com/entry/photo/1950/0,http://www.boqii.com/entry/photo/1950/5577', '植物　　', '被子植物门', '双子叶植物纲', '豆目', '豆科', '羊蹄甲属', '红花羊蹄甲', 'Bauhinia blakeana  Dunn', '', '　　 　　红花羊蹄甲是乔木；分枝多，小枝细长，被毛。叶革质，近圆形或阔心形，长8.5－13厘米，宽9－14厘米，基部心形，有时近截平，先端2裂约为叶全长的1／4－1／3，裂片顶钝或狭圆，上面无毛，下面疏被短柔毛；基出脉11－13条；叶柄长3.5－4厘米，被褐色短柔毛。', '　　', '　　　　红花羊蹄甲繁殖一般采用嫁接法，以羊蹄甲作砧木、用红花羊蹄甲作接穗进行嫁接；高空压条则用红花羊蹄甲为母株进行“圈接”，但大量繁殖受到限制。　　红花羊蹄甲主要还采用扦插进行盆栽繁殖，每年清明节前后，把红花羊蹄甲枝条，剪成约20厘米长插穗，进行扦插，基质在扦插前半个月　　5月份移栽上盆，先置阴凉处，逐渐移放在阳光充足地方进行正常蔚养。施用复合肥。根据盆花不同长势进行截顶矮化　　八、九月应控水控肥进行蹲苗，使枝短叶小，有利花芽分化。十月后则不能修剪，否则影响花开。在十一月盆栽的红花羊蹄甲陆续开花，花期长达三个月。', 'http://img.boqiicdn.com/Data/BK/P/imagick43821439805049.jpg', 'http://www.boqii.com/entry/detail/1950.html', '');
INSERT INTO `plant_family` VALUES ('468', '红辉艳', 'Echeveria ‘Spruce－Oliver’', '红辉艳', '红辉殿、姬红辉炎', '不容易死', '', 'http://www.boqii.com/entry/photo/2476/0,http://www.boqii.com/entry/photo/2476/4941', '', '', '', '', '景天科', '拟石莲属', '', '', '', '　　 　　红辉艳和', '　　红辉艳的栽培难度并不高，但是由于红辉艳的叶片有绒毛，所以比较容易积水，人工栽培时需注意浇水量，以免引起红辉艳烂根等情况。那么，如何才能养好红辉艳呢？　　红辉艳凉爽、干燥和阳光充足的环境，耐干旱和半阴，对水分要求不高，浇水过多，容易成徒长，叶片之间的距离拉长，植株不紧凑，不利于观赏。每15～20天施一次“低氮高磷、钾”的薄肥，施肥时注意肥水不要溅到叶片上，以免形成难看的斑痕，很难去掉。冬季放在室内阳光充足处，保持6～8℃的温度，节制浇水，以防烂根。盛夏高温时也不宜浇水过多，否则会因根部。在半阴处能正常，但叶缘及叶端的红色会减退，甚至消失。对紫外线的抵抗力很强。　　红辉艳每年早春换盆，加入腐叶土、培养土和粗沙的混合土。特别在冬季低温条件下，水分过多，根部易腐烂。夏季高温会有休眠，底部叶片会掉落，要减少浇水。阳台栽培切忌阵雨冲淋如枝条徒长或衰老，可剪短施肥，更新复壮。　　红辉艳在夏季高温时整个植株或完全停止，这个时候要通风良好且适当遮光，避免曝晒，节制浇水，不能长期雨淋，以免植株腐烂。红辉炎的繁殖一般是砍头爆小崽扦插，砍下来的植株可以直接扦插在干的颗粒土中，发根后就可以少量给水了，是个非常好养的品种。', '　　　　红辉艳的繁殖一般是砍头爆小崽扦插，砍下来的植株可以直接扦插在干的颗粒土中，发根后就可以少量给水了，是个非常好养的', 'http://img.boqiicdn.com/Data/BK/P/imagick71301454320419.jpg', 'http://www.boqii.com/entry/detail/2476.html', '');
INSERT INTO `plant_family` VALUES ('469', '英冠玉', 'Notocactus magnificus', '英冠玉', '', '不容易死', '原产南美巴西高原地区', 'http://www.boqii.com/entry/photo/2458/0,http://www.boqii.com/entry/photo/2458/4958', '　', '', '', '', '仙人掌科', '南国玉属', '', '', '', '　　 　　英冠玉为多年生肉质植物，茎幼时球形，后随', '　　英冠玉原产于南美巴西高原地区，是比较容易饲养的科品种。英冠玉的花鲜黄色，非常艳丽，并且开花容易，是很多仙人掌爱好者栽培的品种。　　英冠玉喜温暖干燥与阳光充足环境，耐干旱和半阴，不耐水湿。适温18°C—24°C，不耐寒，冬季温度不低于5°C，短期可耐0°C低温。以肥沃、疏松、排水良好的砂质壤土为宜，可用腐叶土、土和粗砂的混合土。栽培容易，生长强健迅速。根系发达，盆栽每年春季换盆，修剪根系。生长期盆土保持湿润，适量施肥。　　英冠玉在冬季保持土壤干燥，可增强抗寒能力。夏季要进行适当的蔽荫，耐寒，忌水涝。生长适温20℃—32℃。对土壤要求不严，但以通透性好的沙质土为佳，盆栽可用腐叶土、河沙等配成营养土。对水要求较低，在生长，盆土以稍湿润为佳，长期过湿易腐烂，冬季停止浇水，保持盆土干燥，忌积水。生长期施肥2—3次，以复合肥和有机肥为主，忌偏施氮肥，否则徒长，住行不美观。', '　　　　1、英冠玉播种：4—5月进行，发芽适温20°C—24°C，播后1—2周发芽，幼苗生长较快，翌年径粗可达1cm以上。　　2、英冠玉扦插：以春秋季进行为宜，将母株旁生子球切下，晾干伤口后插于沙床，经25—30天可生根。　　3、英冠玉嫁接：在5—6月进行，砧木可用', 'http://img.boqiicdn.com/Data/BK/P/imagick41453886238.jpg', 'http://www.boqii.com/entry/detail/2458.html', '');
INSERT INTO `plant_family` VALUES ('470', '不夜城芦荟', 'Aloe nobilis Haw.', '不夜城芦荟', '不夜城、大翠盘、高尚芦荟', '不容易死', '原产南非的大卡卢高原和小卡卢高原，现世界多地可栽培。', 'http://www.boqii.com/entry/photo/2042/0,http://www.boqii.com/entry/photo/2042/5485', '　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '芦荟属', '不夜城芦荟种', 'Aloe nobilis Haw.', '', '　　不夜城 　　不夜城芦荟属多年生肉质草本植物，植株单生或丛生，高30至50厘米，肉质叶绿色，幼苗时互生排列，成年后则为轮状互生。叶片披针形，肥厚多肉，叶缘有淡黄色锯齿状肉刺，叶面及叶背有散生的淡黄色肉质凸起。松散的总状花序从叶丛上部抽出，小花筒形，橙红色，冬末至早春开放。', '　　不夜城又名不夜城、大翠盘等，在冬末至早春会开花，常被用作家用观赏植物进行栽培。不夜城芦荟喜温暖、干燥，耐半荫、干旱，所以栽种难度并不高，但是如何才能将不夜城芦荟养的更漂亮呢？　　　不夜城芦荟根系发达，所以每年需要换一次盆。盆土宜用疏松、肥沃、排水、透气性良好的沙质土，可用腐叶土或草炭土、沙土或蛭石各2份，园土1份，另加少量腐熟的骨粉或草木灰作基肥。换盆时，需修剪过长、过老的根系，以利于植株的茁壮生长。反之则会消耗盆中大量养分，影响花芽形成。　　　每15～20天施1次腐熟的稀薄液肥或复合肥，有人将一些缓效肥撒在盆土表面，使植株慢慢吸收，效果也良好。施肥以马蹄片、麻酱渣等有机物以及发酵后的液肥为主，结合磷酸二氢钾，磷酸二胺等无机速效肥。在追施肥液时，要将盆土充分浇透。另外，还应避免将肥液滴在叶片上，否则会烧伤叶片或导致发生。栽培中如肥水不足、长期干旱，植株虽不会死亡，但叶片薄且色淡。　　　喜温暖、干燥、充足而柔和的阳光。　　不夜城芦荟要求日照时间长，光照充足。春秋季的日照时间、强度最适宜其生长。生长环境的光照条件充足，可使不夜城芦荟植株生长健壮，根系发达，株形紧凑。家庭盆栽，春秋季放在阳台上接受阳光直射，夏季放到通风良好的半阴处，冬季摆放到室内阳光充足的地方养护。若光照不足会造成植株徒长，株形松散不紧凑，叶片薄，而光照过强又会导致叶色呈褐绿色，影响观赏。夏季高温要注意通风良好，以免因闷热、潮湿而导致植株腐烂；并适当遮光，以免因烈日曝晒而产生日灼病，使叶面出现黑斑，另长期放在光照不足环境中栽培的植株，突然移到阳光下也会出现这种情况。　　　耐干旱，忌盆土积水，以盆土“不干不浇、浇则浇透”为原则，避免盆土积水导致烂根，但要求有一定的空气湿度，如有条件还可将植株置于封闭的大棚内养护，使其在具有一定空气湿度的环境中生长。这样培养的植株，叶片肥厚翠绿，株形紧凑，叶缘及叶面上的肉刺、肉质凸起显着。盛夏时节，气温高、蒸发量大，需要充分浇水并经常向叶面喷水；入秋后，要逐渐减少浇水，冬季保持盆土略干为好。　　　冬季移至室内有阳光的地方，若不低于10℃，可正常浇水，并酌情施薄肥，使植株继续生长；如温度保持不了10℃，应节制浇水，停止施肥，使植株休眠。　　　栽培中应经常松土，使土壤具有较好的透气性，有利于根系的生长。', '　　不夜城　　不夜城芦荟的繁殖，可结合换盆进行分株，方法是将植株基部萌发的幼苗取下，另行栽种即可。栽后保持盆土稍有潮气，有根无根都能成活。也可在　　不夜城锦的繁殖与不夜城芦荟相同，但小苗的叶片上最好有黄有绿，若全为黄色，因植株不能合成养分，栽后很难成活，故要等到小苗长出带有绿色的叶片后，再取下栽种；而纯绿色的小苗成活后，易出现“返祖”现象，会长成其原种“不夜城芦荟”。', 'http://img.boqiicdn.com/Data/BK/P/imagick56101442395759.jpg', 'http://www.boqii.com/entry/detail/2042.html', '');
INSERT INTO `plant_family` VALUES ('471', '紫蛮刀', 'Senecio crassissimus', '紫章', '紫蛮刀、紫金章、鱼尾冠、紫龙。', '不容易死', '主要分布于产马达加斯加岛的南部', 'http://www.boqii.com/entry/photo/2464/0,http://www.boqii.com/entry/photo/2464/4952', '　　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '千里光属', '', 'Senecio crassissimus', '', '　　 　　紫蛮刀的植株高50～80厘米，茎、枝均为绿色，有时略带紫晕，表面粗糙，残留有老叶脱落的鳞状物。肉质叶片倒卵形，青绿色，稍有白粉，叶缘及叶片基部均呈紫色，叶长4～6厘米，宽2～3厘米。头状花序高50～100厘米，小花群生，黄色或朱红色。', '　　', '　　　　紫蛮刀因为长的相对还好，1～2年换盆一次就差不多了，初春头次浇水前进行换盆。紫蛮刀会长高，砍头后有分枝。　　紫蛮刀的繁殖可以砍头扦插和砍分株。枝条扦插非常简单，把', 'http://img.boqiicdn.com/Data/BK/P/imagick94811453973299.jpg', 'http://www.boqii.com/entry/detail/2464.html', '');
INSERT INTO `plant_family` VALUES ('472', '蓟', 'Cirsium japonicum', '蓟', '', '不容易死', '分布于朝鲜、日本、中国，生长于海拔400米至2，100米的地区。', 'http://www.boqii.com/entry/photo/2041/0,http://www.boqii.com/entry/photo/2041/5486', '　', '', '', '', '菊科Compositae', '蓟属', '', 'Cirsium japonicum', '', '　　 　　蓟为多年生草本，有多数肉质圆锥根。茎直立，高50—100厘米，有分枝，基都有白色丝状毛。基部叶有柄，花时不凋落，倒披针形或倒卵状椭圆形，长15—30厘米，表面绿色，疏', '　　又名大蓟、刺蓟等，为多年生草本，由于蓟有一定的药用价值，所以常被人工栽培做药用。很多人不知道的是，蓟还是苏格兰的国花，那么人工栽培蓟应该注意哪些问题呢？　　　由于蓟各个阶段对温度都有一定的要求，因温度不同个生长发育的日期也不同，苗期最适宜温度（15－25）度，同化期最适宜温度（20－30）度，连坐期最适宜温度（25－30）度，种子成熟期最适宜温度（25－35）。蓟个生育阶段的日期温度过高和过低都不利于蓟的生长发育。　　　北方高寒地区的温度和光照条件，对蓟的营养生长，生殖，发育都十分有利，北方高寒地区光照较长为蓟延长生长生育，绿色体增多为蓟的丰产丰收奠定良好的基础。蓟分布广泛，适应性强，对土壤要求不十分严格，分布在各地的黑土，黄土，黑沙土，草甸土，沙壤土及轻碱土，白浆土都可正常生长。当种植在沙壤土上，沙壤土质地疏松，早春地温生快，连坐期相对缩短。但这类土壤保水性差容易缺水，使植株繁茂性差，对这类土壤要适时早播，水分充足的地块连坐期相对延长，植株繁茂。产量争加。　　　水是蓟生长生育过程中较重要的因素之一，蓟在干旱的情况下也可生长，但生育非常缓慢，连座期抽苔，降低产量。蓟开花时对水分供应也很敏感，此时植物体内新陈代谢过程最为旺盛，对水分要求达到顶峰，此阶段与特殊干旱，种子饱满性差毗粒种子增多，如高温干旱同时出现，造成土壤干旱，大气干旱，蓟授粉条件恶化，产量会有明显降低。', '　　　\n　一、播种\n　　1、选种：选粒大、饱满、色黑、无病虫害、发芽率高的种子。　　2、种子：　　3、播期：水飞蓟种子和幼苗不怕冻，可顶浆播种，种完小麦就可以种它，黑龙江省南部在4月上旬，北部在4月下旬。适期早播，利于水飞蓟先扎根，后长苗，根条发达，苗齐苗旺，提高产量。但也不能过早，过早地冻种达不到深度，地温低，出苗慢，不利保苗。　　\n二、播种方法\n　　1、直播。人工垄上刨坑，埯坑20－30cm，深度约8－10cm，每穴施磷酸二铵3g，覆土4cm，然后每埯播种3－4粒，再覆土3－4cm。如果天气干旱，可以座水播种，一般667平方米播量0.5kg左右。也可人工在垄上搂沟，施肥覆土，播种，种子间距3－5cm，播后覆土3－4cm。　　2、机械播种。用大豆精量点播机进行垄上直接播种。施肥箱播肥量控制在667平方米施磷酸二铵15kg以内，每1份种子拌1.5倍炒熟的小麦，要拉开均匀直接播种，一般667平方米用种子0.5kg，用熟小麦0.75kg。西部地区也可用播种机平播，行距60cm，株距3－5cm，667平方米用种子量0.6kg。　　3、育苗。做120cm宽的苗床，667平方米施有机肥5000kg，磷酸二铵15kg，均匀拌入床中。在床上按10cm行距开沟4cm深，以种距2cm撒播，然后覆土、浇水、盖小拱棚。水飞蓟出苗后要注意经常清除杂草。也可在塑料棚中用育苗秧盘育苗，每穴位放种子2－3粒。　　4、移栽。可在5月初移入田间。在垄上按株距20－30cm刨埯，埯施尿素1g拌入土中，放苗、盖土、浇水，然后再覆土。因水飞蓟是直根系，起苗时要深挖多带土，苗不能过大。移栽的分枝少，　　5、密度。在一般栽培条件下，', 'http://img.boqiicdn.com/Data/BK/P/imagick1421442309769.jpg', 'http://www.boqii.com/entry/detail/2041.html', '');
INSERT INTO `plant_family` VALUES ('473', '大叶莲花掌', 'Aeonium urbicum', '大叶莲花掌', '', '未知', '', 'http://www.boqii.com/entry/photo/2496/0,http://www.boqii.com/entry/photo/2496/4831', '　', '', '', '蔷薇目', '景天科', '莲花掌属', '', 'Aeonium urbicum', '', '　　大叶 　　大叶莲花掌的茎分枝少，具很多气根，分枝从基部生出，向外弯曲。莲座盘直径20－25cm，叶长圆状匙形，叶缘为明显的红色或堇紫色，叶蓝绿色。花绿白到淡粉色。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick84741455700832.jpg', 'http://www.boqii.com/entry/detail/2496.html', '');
INSERT INTO `plant_family` VALUES ('474', '五叶地锦', '', '五叶地锦', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2142/0,http://www.boqii.com/entry/photo/2142/5385', '　　', '被子植物门（Magnoliophyta）', '双子叶植物纲（Magnoliopsida）', '葡萄目（Vitales）', '葡萄科（Vitaceae）', '爬山虎属（Parthenocissus）', '五叶爬山虎', 'P.thomsoni', 'P.thomsoni', '　　 　　五叶地锦为木质藤本。小枝圆柱形，无毛。卷须总状5－9分枝，相隔2节间断与叶对生，卷须顶端嫩时尖细卷曲，后遇附着物扩大成吸盘。叶为掌状5小叶，小叶倒卵圆形、倒卵椭圆形或外侧小叶椭圆形，长5.5－15厘米，宽3－9厘米，最宽处在上部或外侧小叶最宽处在近中部，顶端短尾尖，基部楔形或阔楔形，边缘有粗锯齿，上面绿色，下面浅绿色，两面均无毛或下面脉上微被疏柔毛； 侧脉5－7对，网脉两面均不明显突出； 叶柄长5－14.5厘米，无毛，小叶有短柄或几无柄。', '　　为科属植物，其叶片变异很大，通常为宽卵形，边缘有粗锯齿。五叶地锦喜光也耐阴、耐寒，适应能力非常强，比较快，虽然叫五叶爬山虎，但是攀援能力却很差。　　五叶地锦的生命力极强，繁殖极易成活。五叶地锦的小苗成活生长一年后，就可以进行移栽定植。移栽五叶地锦时要深翻土壤，施足腐熟基肥。当小苗长至1米长时，要用铅丝、绳子牵向攀附物。　　五叶地锦耐贫瘠、干旱，耐荫、抗性强，栽培比较粗放。入冬后疏理枯枝，早春施以薄肥，可促进枝繁叶茂。南京为大陆性气候地区，应植于北墙和东墙基部，向着攀附物倾斜栽植。为防蔓基过早光秃和有利吸附，宜多行重剪。　　五叶地锦在生长期，可追施液肥2－3次。并经常锄草松土做围，以免被草淹没，促其健壮生长。五叶地锦怕涝渍，要注意防止土壤积水。五叶地锦耐修剪，在生长过程中，可依情修剪整理门窗处的枝蔓，以保持整洁、美观、方便。', '　　　\n　一、播种法：\n　　采收后的种子搓去果皮果肉，洗净晒干后可放在湿沙中低温贮藏—冬，保温、保湿有利于催芽，次年早春3月上中旬即可露地播种，薄膜覆盖，5月上旬即可出苗，　\n　二、扦插法：\n　　早春剪取茎蔓20－30cm，插入露地苗床，灌水，保持湿润，很快便可抽蔓成活，也可在夏、秋季用嫩枝带叶扦插，遮荫浇水　\n　三、压条法：\n　　可采用波浪状压条法，在雨季阴湿无云的天气进行，成活率高，秋季即可分离移栽，次年定植。', 'http://img.boqiicdn.com/Data/BK/P/imagick18571445590492.jpg', 'http://www.boqii.com/entry/detail/2142.html', '');
INSERT INTO `plant_family` VALUES ('475', '夜合花', 'Magnolia coco （Lour.） DC.', '夜合花', '', '不容易死', '中国南部及越南', 'http://www.boqii.com/entry/photo/2219/0,http://www.boqii.com/entry/photo/2219/5308', '植物　　', '被子植物门', '双子叶植物纲', '毛茛目', '木兰科', '木兰属', '', 'Magnolia coco （Lour.） DC.', '', '　　 　　夜合花为常绿灌木或小乔木，高2－4米，全株各部无毛；树皮灰色，小枝绿色，平滑，稍具角棱而有光泽。叶革质，椭圆形，狭椭圆形或倒卵状椭圆形，长7－14（－28）厘米，宽2－4.5 （－9）厘米，先端长渐尖，基部楔形，上面深绿色有光泽，稍起波皱，边缘稍反卷，侧脉每边8－10条，网眼稀疏；叶柄长5－10毫米；托叶痕达叶柄顶端。', '　　又名夜香木兰，但是夜合花花朵开放的时间较短，每朵花仅开1－2天，所以夜合花也成为了很多花友都非常的花卉。夜合花的树姿小巧，夏季会开出绿白色的球状小花，用来点缀环境非常不错。　　夜合花喜温暖湿润和阳光充足环境，对气候和土壤适应性强，耐阴，好肥。夜合花喜在温暖湿润和半阴半阳的环境中。宜排水良好，肥沃、微酸性砂质土壤，忌石灰质土壤但也耐瘠薄土壤和干旱气候。花朵开放时间短，每朵仅开1－2天，往往清晨开放，晚上闭合，故名夜合花。香味幽馨，入夜更烈。开花期适温为22－25℃，低于20℃开花延缓。　　盆栽有用山泥最好，忌用石灰质土壤栽培，一定要土壤酸性，PH为5。5至8。5。家庭栽植也可用菜园土6份，河沙4份，加半羹匙黑矾混合使用。夜合花4月中旬出室后放置散光处养护，透光率达30至40％为宜。春季2至3天浇水一次，北方春天干燥，易引起叶子发黄，故要每隔两三天连续浇矾肥水三四次。夏季宜半阴，经常喷水，增加空气湿度。入秋后，要少浇水。逐渐增加光照，使植株充实。秋季对枯枝和错位枝加以修剪整形。冬季入室置于阳光不直射的地方，白天保持10至12℃之间，晚间不低于5℃，不高于10℃以上，以免对不利，影响翌年开花。冬季保持盆土微湿即可。在生长期，每隔15天左右追施一次腐熟的饼肥液。花期前停施氮肥，多施磷、钾肥，以促花大香浓。入冬进室养护不需要施肥。', '　　夜合花为常绿灌木，原产于华南，是华南及东南亚地区广泛栽培供欣赏的　　夜合花喜湿润、肥沃土壤，耐荫，多生于海拔600～900m的常绿阔叶林下，对有毒气体抗性较差。通常用靠接法或高空压条法繁殖。嫁接以紫玉兰、火力楠、木莲等为砧木；高空压条繁殖在早春天气转暖后或秋天进行，生根后移入苗圃育成大苗，方可定植。近年也常用扦插繁殖，以一年生至二年生幼苗上剪穗沙插，成活率可达90％。　　条件好时也可扦插，插床要保持20度以上', 'http://img.boqiicdn.com/Data/BK/P/imagick9681447407531.jpg', 'http://www.boqii.com/entry/detail/2219.html', '');
INSERT INTO `plant_family` VALUES ('476', '花月夜', 'Echeveria pulidonis', '花月夜', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2475/0,http://www.boqii.com/entry/photo/2475/4942', '', '', '', '', '景天科', '', '', '', '', '　　 　　花月夜的植株叶片莲座型密集排列。叶片肥厚长勺形，叶缘较薄，有叶尖。叶色为浅绿，强光与昼夜', '　　花月夜的叶形和叶色较美，具有一定的观赏价值，但需要注意的是，不能长摆放在电视电脑旁，这回使得花月夜缺光而死。人工栽培花月夜需注意为其布置一个合适的环境，才能保证花月夜的成长。　　花月夜需要阳光充足和凉爽、干燥的环境，耐半阴，怕水涝，忌闷热潮湿。具有冷凉季节生长，夏季高温休眠的习性。夏季高温时整个植株或完全停止，这个时候要通风良好且适当遮光，避免曝晒，节制浇水，不能长期雨淋，以免植株。　　每年的9月至11月第二年的3月至6月为植株的生长期（花友的环境不一样，生长期也有长短），若光照不足会使植株叶片徒长，叶缘红色也会慢慢黯淡；而在阳光充足之处生长的植株，株型矮壮，叶片排列会紧凑。生长期需保持土壤湿润，避免积水。土壤可以了煤渣混合泥炭、少量珍珠岩，比例大概6：3：1。', '　　　　花月夜的繁殖一般是砍头爆小崽或叶片扦插，砍下来的植株可以直接扦插在干的颗粒土中，几天后少量给水，很容易就发根了。花月夜的叶片扦插有点慢，取下完整饱满的叶片，放在阴凉处晾干伤口，然后放置在土上，土不要太湿，有点湿度即可，它会慢慢发芽长出新植株的。', 'http://img.boqiicdn.com/Data/BK/P/imagick13601454319376.jpg', 'http://www.boqii.com/entry/detail/2475.html', '');
INSERT INTO `plant_family` VALUES ('477', '白车轴草', 'Trifolium repens L.', '白车轴草', '白花苜蓿，金花草，菽草翘摇', '不容易死', '非洲、中国', 'http://www.boqii.com/entry/photo/2266/0,http://www.boqii.com/entry/photo/2266/5259', '　　', '被子植物门', '子叶植物纲', '薇目', '科', '轴草属', '车轴草', 'Trifolium repens L.', 'Trifolium repens', '　　 　　白车轴草的花序球形，顶生，直径15－40mm；总花梗甚长，比叶柄长近1倍，具花20－50 （－80） 朵，密集；无总苞；苞片披针形，膜质，锥尖；花长7－12mm；花梗比花萼稍长或等长，开花立即下垂；萼钟形，具脉纹10条，萼齿5，披针形，稍不等长，短于萼筒，萼喉开张，无毛；花冠白色、乳黄色或淡红色，具香气。旗瓣椭圆形，比翼瓣和龙骨瓣长近1倍，龙骨瓣比翼瓣稍短；子房线状长圆形，花柱比子房略长，胚珠3－4粒。', '　　白车轴草有一定的侵入性，但是危害不重，对于局部地区的蔬菜、幼林有危害。白车轴草的适应性较强，有一定的观赏性，也是世界各国主要栽培的牧草之一，有着良好的经济价值。　　白车轴草苗期，易受杂草侵害，苗期应勤除杂草，春播的更应该如此。草层高20－25厘米时，可以适当刈割增强通风透气。刈后再生能力强，可迅速形成二茬草层。高温，白车轴草停止生长。形成草层覆盖后的2－3年间要及时去除大杂草。如果因夏季高温干旱形成缺苗，可在秋季补播，恢复草坪整齐。白车轴草病害少，有时也有褐斑病、白粉病发生，可先刈割，再用波尔多液、石硫合剂或等防治。白车轴草虫害较多，尤其是蛴螬和为害严重。对蛴螬选用的药剂为50％甲基异柳磷，按每亩地3公斤兑水3吨分别在4月中旬和7月下旬到8月上旬进行喷雾，喷雾后及时喷水，使药水湿透地面7－10厘米，蛴螬接触药土后。此法对少部分大龄幼虫效果仍不够理想。对于蜗牛，喷杀虫剂防治效果很差，而用蜗克星颗粒剂在傍晚撒于草坪内，则效果非常好，杀灭率达90％以上。　　白车轴草的施肥以磷、钾肥为主，施少量氮肥有利于壮苗。播种前，每亩施过磷酸钙20－25公斤以及一定数量的厩肥作基肥。出苗后，植株矮小、叶色黄的，要施少量氮肥，每亩施10公斤尿素或相应量的硫酸铵，促进壮苗。在3月追1次复合肥，按每亩30－40公斤开沟施入草坪根部，然后浇水，能明显增强长势，提高抗高温的能力，减少死草现象。', '　　　　白车轴草的种子田要播种国家或省级牧草种子质量标准规定的Ⅰ级种子，人工草地播种Ⅰ、Ⅱ、Ⅲ级种子均可。白车轴草种子硬实率较高，播种前要用机械方法擦伤种皮，或用浓硫酸浸泡腐蚀种皮等方法，进行种子　　播种后出苗前，若遇土壤板结时，要及时耙耱，破除板结层，以利出苗。苗期生长慢，为防杂草危害，要中耕松土除草1～2次；发现害虫危害，要及时防治。生长二年以上的草地，土层紧实，透气性差，在春、秋两季返青前和放牧刈割后的再生前，要进行耙地松土，并结合松土追肥，每亩施过磷酸钙20～25千克，或磷二氨5～8千克，以利新芽新根', 'http://img.boqiicdn.com/Data/BK/P/imagick36051448617938.jpg', 'http://www.boqii.com/entry/detail/2266.html', '');
INSERT INTO `plant_family` VALUES ('478', '粉紫重瓣木槿', 'Hibiscus syriacusf. amplissimus', '粉紫重瓣木槿', '', '不容易死', '山东等地', 'http://www.boqii.com/entry/photo/2439/0,http://www.boqii.com/entry/photo/2439/4977', '植物　', '被子植物门', '双子叶植物纲', '锦葵目', '锦葵科', '木槿属', '木槿', 'Hibiscus syriacusf. amplissimus', '', '　　 　　粉紫重瓣木槿为落叶灌木，高3～4米，小枝密被黄色星状绒毛。叶菱形至三角状卵形，长3～10厘米，宽2～4厘米，具深浅不同的3裂或不裂，先端钝，基部楔形，边缘具不整齐齿缺，下面沿叶脉微被毛或近无毛；叶柄长5～25毫米，上面被星状柔毛；托叶线形，长约6毫米，疏被柔毛。花单生于枝端叶腋间，花梗长4～14毫米，被星状短绒毛；小苞片6～8，线形，长6～15毫米，宽1～2毫米，密被星状疏绒毛；花萼钟形，长14～20毫米，密被星状短绒毛，裂片5，三角形；花钟形，粉紫色，直径5～6厘米，花瓣倒卵形，长3.5～4.5厘米，内面基部洋红色，重瓣，外面疏被纤毛和星状长柔毛；雄蕊柱长约3厘米；花柱枝无毛。蒴果卵圆形，直径约12毫米，密被黄色星状绒毛；种子肾形，背部被黄白色长柔毛。', '　　粉紫重瓣木槿为多年生灌木，其速度较快，可一年种植多年采收。粉紫重瓣木槿主要分布于我国的山东等地，人工栽培难度并不高，小编就为你介绍一下粉紫重瓣木槿的栽培要点，的朋友可以一起了解。　　粉紫重瓣木槿适应性强，南北各地都有栽培。喜阳光也能耐半阴。耐寒，在华北和西北大部分地区都能露地，对土壤要求不严，较耐瘠薄，能在粘重或碱性土壤中生长，惟忌干旱，生长期需适时适量浇水，经常保持土壤湿润。木槿管理比较粗放，耐修剪。　　粉紫重瓣木槿在天旱时适当浇水，生长旺季稍施稀薄液肥即可，每年只稍作修剪，使之通风透光就行。生长期保持土壤湿润。春季萌芽前施肥1次，6－10月开花期，施磷肥2次。通过修剪来控制株形和树姿，最好冬季剪枝到2尺高，3月份再剪枝一次，但不要剪枝太多。移植宜在落叶后进行。　　粉紫重瓣木槿可采用单行垄作栽培，垄间距110－120厘米，株距50－60厘米，垄中间开种植穴或种植沟。木槿移栽定植时，种植入或种植沟内要施足基肥，一般以垃圾土或腐熟的厩肥等农家肥为主，配合施入少量复合肥，移栽定植最好在幼苗进行，也可在多雨的生长进行。移栽时要剪去部分枝叶以利成活，定植后应浇1次定根水，并保持土壤湿润，直到成活。', '　　　\n　一、分株繁殖\n　　在早春发芽前，将　\n　二、扦插繁殖\n　　扦插可于3月中旬至4月上旬结合修枝整形进行，插穗选择木质化的健壮枝条，长10～12厘米，露天扦插于红壤或沙壤中，要保障土壤湿润，但成活率较低；最好扦插在有塑料膜保湿的苗床内，温度在17℃至20℃侧极易成活。　　选择1～2年生健壮、未萌芽的枝。切成长15～20cm的小段，扦插时备好一根小棍，按株、行距在苗床上插小洞，再将粉紫重瓣木槿枝条插入，压实土壤，入土深度10～15cm，即入土深度达插条的2／3为宜，插后立即灌足水。扦插时不必施任何基肥。　\n　三、播种繁殖\n　　一般在春季4月进行。果实10月成熟后，11～12月采种最适宜，采收后剥出种子低温干藏，到翌春4月条播或撒播。分株繁殖在秋天落叶后或早春发芽之前，挖取植株根际的萌株，另行栽植。栽前可适当修剪根部，并对地上部实行重短截。粉紫重瓣木槿适应性强，栽培简单，管理粗放，一般可任其自由生长。但为了提高其观赏效果，使其花繁色艳，应给予必要的管理。粉紫重瓣木槿在当年生新枝上开花，在秋季落叶后可进行适当修剪。修剪时宜疏剪与短截相结合，对长枝适度短截，疏去过密枝、细弱枝，使营养集中，丰满。在春季植株发芽后的4月中、下旬，应施1次　\n　四、压条育苗技术\n　　由于木横枝条极易生根，春季发芽前在母株旁挖浅沟，将1年生枝条水平压到小沟内，培土，保持压条沟内土壤湿润，很快生根抽梢。秋季落叶后从基部剪断压条，然后挖出苗木分割成苗。', 'http://img.boqiicdn.com/Data/BK/P/imagick76621453280530.jpg', 'http://www.boqii.com/entry/detail/2439.html', '');
INSERT INTO `plant_family` VALUES ('479', '蓝花鼠尾草', 'Salvia farinacea', '蓝花鼠尾草', '粉萼鼠尾草、一串蓝、 蓝丝线', '不容易死', '北美南部', 'http://www.boqii.com/entry/photo/2220/0,http://www.boqii.com/entry/photo/2220/5307', '　', '被子植物门', '双子叶植物纲', '管状花目', '唇形科', '鼠尾草属', '蓝花鼠尾草', 'Salvia farinacea', '', '　　蓝 　　蓝花鼠尾草的成株高度30－60cm，植株呈丛生状，植株被柔毛。茎为四角柱状，且有毛，下部略木质化，呈亚低木状。叶对生长椭圆形，长3－5cm，灰绿色，叶表有凹凸状织纹，且有折皱，灰白色，香味刺鼻浓郁。具长穗状花序，长约12 cm，花小紫色，花量大。', '　　蓝花原产于北美南部地区，为多年生草本。很多朋友对于蓝花鼠尾草和的辨别会有一定的障碍，但如果了解了蓝花鼠尾草的特点，还是能比较方便的分辨出和薰衣草的区别的。那么蓝花鼠尾草的栽培究竟有哪些注意事项呢？　　1、：上盆后温度降低至18℃，过一个月可降至15℃。如果温度在15℃以下，叶片就会发黄或脱落；温度在30℃以上时，则会出现花叶小、植株停止生长的现象。　　2、施肥：生长期施用稀释1500倍的硫铵，以改变叶色，效果较好。低温下不要施用尿素。为使植株根系健壮和枝叶茂盛，不断施肥非常重要，半月施用一次用含钙镁的复合100ppm。　　3、光照：喜阳光充足的环境，炎热的夏季需要进行适当遮阴，幼苗期加强光照防止徒长。', '　　蓝花　　种子每克920粒左右，一般选择200或者288穴盘进行播种，介质一般选择进口育苗草炭土或者经过　　发芽第一阶段胚根出现，并且根开始形成。此阶段不用施肥，但保持育苗介质的湿润非常重要，需要一定的光照。出苗后逐渐撤掉薄膜。每周用1000倍百菌清或甲托防猝倒病，连续喷施2至3次。　　发芽第二阶段继续生根，出现茎，且子叶已展开。保持适当湿度，防止过湿，可适当施用氮磷钾比例为20－10－20的水溶肥。　　发芽第三阶段根部可以插入穴盘的孔穴中，并出现几片真叶。加大肥料浓度，控制湿度和　　发芽第四阶段根系成团，有2至3对真叶。继续增大肥料浓度，温度和湿度与第三阶段相同，适当控制水分，加强通风，仍需防止徒长，为移栽做好准备。', 'http://img.boqiicdn.com/Data/BK/P/imagick67941447408159.jpg', 'http://www.boqii.com/entry/detail/2220.html', '');
INSERT INTO `plant_family` VALUES ('480', '结香', 'Oriental Paperbush', '结香', '打结花、打结树、黄瑞香，家香、喜花、梦冬花', '不容易死', '北自河南、陕西，南至长江流域以南各省区均有分布。', 'http://www.boqii.com/entry/photo/2150/0,http://www.boqii.com/entry/photo/2150/5377', '　　', '被子植物门', '双子叶植物纲', '()目', '瑞香科', '结香属', '结香', 'Edgeworthia chrysantha', '', '　　 　　结香为灌木，高约0.7－1.5米，小枝粗壮，褐色，常作三叉分枝，幼枝常被短柔毛，韧皮极坚韧，叶痕大，直径约5毫米。叶在花前凋落，长圆形，披针形至倒披针形，先端短尖，基部楔形或渐狭，长8－20厘米，宽2.5－5.5厘米，两面均被银灰色绢状毛，下面较多，侧脉纤细，弧形，每边10－13条，被柔毛。', '　　结香的观赏价值非常高，外形和)有点像，并且结香的药用价值也很高，所以是一种不可多得的，也受到了很多花友的喜爱。结香野生和人工栽种均可，那么，人工栽种结香需要注意哪些问题呢？　　喜温和凉爽的气候。在海拔500m以上山区种植，生长良好，在低海拔地区栽培，，植株矮小，开花花朵小，结实率低。以排水良好、土层疏松而肥沃的壤土栽培为宜。　　喜温暖并耐寒，能耐－20摄氏度以内的低温，冬季在－20～－10摄氏度时花期要延迟。　结香喜半阴，栽种可选择背靠北墙面向南之处，以盛夏可避烈日、冬季可晒太阳为最好。盆栽结香从秋到春宜放在曰照较好的地方，夏季放半阴处。水分：生长季节宜常浇水，以保持湿润状态，积水易烂根。　喜半湿润环境。　　花后施1次以氮肥为主的，促长枝叶，入秋施1次以磷钾肥为主的复合肥，促其花芽分化，其余时间不施肥。', '　　　\n　1、分株繁殖\n　　在早春萌芽前，取粗壮的萌蘖小苗，截断结香花与母株相连的根，另植于地里，即可成活。一年内可长到60厘米至70厘米。　\n　2、扦插繁殖\n　　一般在2月至3月进行，选取健壮的枝条，长度为10厘米至15厘米，用利刀将下部一刀削成马耳形，插入土中约一半左右，压实，浇透水，遮阴并保持土壤湿润，50天即可发根，次年可移植。', 'http://img.boqiicdn.com/Data/BK/P/imagick6921445851651.jpg', 'http://www.boqii.com/entry/detail/2150.html', '');
INSERT INTO `plant_family` VALUES ('481', '野牡丹', 'Melastoma candidum  D. Don', '野牡丹', '山石榴、大金香炉、猪古稔', '不容易死', '', 'http://www.boqii.com/entry/photo/2173/0,http://www.boqii.com/entry/photo/2173/5355', '　　', '被子植物门', '双子叶植物纲', '()目', '野牡丹科', '野牡丹属', '野牡丹', 'Melastoma candidum  D. Don', '', '　　 　　野牡丹是灌木，高0.5－1.5米，分枝多；茎钝四棱形或近圆柱形，密被紧贴的鳞片状糙伏毛，毛扁平边缘流苏状。叶片坚纸质，卵形或广卵形，顶端急尖，基部浅心形或近圆形，长4－10厘米，宽2－6厘米，全缘，7基出脉，两面被糙伏毛及短柔毛，背面基出脉隆起，被鳞片状糙伏毛，侧脉隆起，密被长柔毛；叶柄长5－15毫米，密被鳞片状糙伏毛。', '　　是在酸性土壤中非常常见的，由于野牡丹温暖湿润的气候，因此以向阳、疏松而含腐殖质多的土壤栽培为宜。小编就为你介绍一下野牡丹的栽培要点，喜欢野牡丹的朋友们可以一起了解。　　野牡丹生于海拔约120米以下的山坡松林下或开朗的灌草丛中，是酸性土常见的。印度支那也有。产中国云南、广西、广东、福建、台湾。模式标本采自广东南部沿海岛屿。　　由于野牡丹喜温暖湿润的气候，稍耐旱和耐瘠。因此以向阳、疏松而含腐殖质多的土壤栽培为好。野牡丹广泛分布于江南大部分省区的旷野山坡、山路旁灌丛林中、疏林下。喜阴，适宜在酸性土壤中，耐瘠薄，具有很好的抗病虫害能力，管理粗放。', '　　　　由于野牡丹喜温暖湿润的气候，稍耐旱和耐瘠。因此以向阳、疏松而含腐殖质多的土壤栽培为好。野牡丹广泛分布于江南大部分省区的旷野山坡、山路旁灌丛林中、疏林下。喜阴，适宜在酸性土壤中　　野牡丹采用种子繁殖方式。春季3月下旬至4月上旬播种，将种子混拦草木灰或细土，均匀地撒播于苗床上，覆盖细土2cm，然后盖草、浇水。每1h㎡播种量22.5～30kg，气温在25℃以上时，20d左右出苗，出苗后揭去盖草。苗高15cm左右，按行株距40cm×40cm开穴，每穴栽3株。', 'http://img.boqiicdn.com/Data/BK/P/imagick3051446455886.jpg', 'http://www.boqii.com/entry/detail/2173.html', '');
INSERT INTO `plant_family` VALUES ('482', '彼岸花', 'Red Spider Lily', '红花石蒜', '龙爪花、老鸦蒜、蒜头草、鬼擎火、幽灵花、地狱花', '不容易死', '', 'http://www.boqii.com/entry/photo/1993/0,http://www.boqii.com/entry/photo/1993/5533', '', '', '', '', '', '', '', '', '', '　　 　　彼岸花鳞茎近球形，外有紫褐色薄膜，直径1－3厘米。秋季出叶，叶狭带状，长约15厘米，宽约0.5厘米，顶端钝，深绿色，中间有粉绿色带。夏秋之交，花茎破土而出，伞形花序顶生，花茎高约30厘米；总苞片2枚，披针形，长约3.5厘米，宽约0.5厘米；有花4－7朵；花鲜红色；花被裂片狭倒披针形，长约3厘米，宽约0.5厘米，强度皱缩和反卷，花被筒绿色，长约0.5厘米；雄蕊显着伸出于花被外，比花被长1倍左右。花期8－9月，果期10月。　　　　　　　　　　　　　　　　　　　', '　　彼岸花为变种石蒜，需要注意的是，彼岸花只有红白两色，并且只有红色的才叫曼珠沙华（又名往生花），白色的则叫)华。如果你也彼岸花的话，可以考虑自己盆栽一盆，小编就为你整理了彼岸花盆栽的方法与注意事项。　　彼岸花喜欢散射光，不喜欢强光，所以光照不要太强。彼岸花对土的要求，通常是没什么要求的。不过它毕竟是南方花，所以土要酸性土，有点砂质性的，透气透水的那种。彼岸花一年四季地上都有观赏价值，有叶无花，有花无叶。　　种植深度不宜太深，以鳞茎顶刚埋入土面为好。土质要求排水良好的沙质土或疏松的，偏酸性土壤，栽植时施适量的基肥和栽培后灌透水；营养期，其间要经常灌水，保持土壤湿润，但不能积水，以防鳞茎腐烂。开花前20天至开花期必须要适量水份供给，以达到开花整齐一致，且花朵容易维持。　　石蒜适应性强，鳞茎有休眠现象，北方需要盆栽观赏，5月末种植的石蒜也应该能开花。北方栽培的适宜时间：应在春天（4－5月）栽种。多数喜爱温暖的气候，最高气温不超过30℃，旬平均气温24℃，适宜石蒜生长。播种10天，根系生长旺盛，叶片先后长出地面。冬季日平均气温8℃以上，最低气温达1℃，不影响石蒜生长。浇水不宜过多，否则会使其根茎腐烂。', '　　彼岸花的观赏性非常强，但是彼岸花的根茎是有毒的，误食会引起中毒症状，虽然彼岸花有一定的药用价值，但是如果不　　1、分球繁殖法：在　　2、播种法：一般只用于杂交育种。由于种子无休眠性，采种后应立即播种，20℃下15天后可见胚根露出。　　3、鳞块基底切割法：将清理好的鳞茎基底以米字型八分切割，切割深度约为鳞茎长的1／2～2／3。　　4、组织', 'http://img.boqiicdn.com/Data/BK/P/imagick19351441099726.jpg', 'http://www.boqii.com/entry/detail/1993.html', '');
INSERT INTO `plant_family` VALUES ('483', '富贵竹', 'Dracaena sanderiana', '富贵竹', '万寿竹、距花万寿竹、开运竹、富贵塔、丝带树、山德氏龙血树', '不容易死', '非洲西部的喀麦隆', 'http://www.boqii.com/entry/photo/1939/0,http://www.boqii.com/entry/photo/1939/5590', '', '', '', '', '', '', '', '', '', '　　富贵竹的 　　富贵竹主要　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　富贵竹是很多喜欢', '　　　\n　一、育苗移栽：\n　　另外，将茎段置于水中，即进行水插也可生根。　\n　二、大田直接扦插：\n　　春季扦插可在1月下旬（大寒后）至2月中下旬（雨水前后）进行，一般30～35天可生根。也可在3月中旬至4月上旬（春分至清明）扦插，尤以3月下旬种植最好，因为该时期', 'http://img.boqiicdn.com/Data/BK/P/imagick88601439458274.jpg', 'http://www.boqii.com/entry/detail/1939.html', '');
INSERT INTO `plant_family` VALUES ('484', '吊兰', '', '吊兰', '桂兰、葡萄兰、钓兰、树蕉瓜、浙鹤兰、倒吊兰、土洋参、八叶兰等', '不容易死', '原产非洲南部，世界各地广泛栽培', 'http://www.boqii.com/entry/photo/1929/0,http://www.boqii.com/entry/photo/1929/5601', '', '', '', '', '', '', '', '', '', '　　 　　吊兰为单子叶植物纲、百合科、吊兰属多年生常绿草本植物，根状茎平生或斜生，有多数肥厚的根。叶丛生，线形，叶细长，似　　　　　　　　　　　　　　　　　　　　　　', '　　的栽培难度比较低，这也是为什么很多朋友都能够自己栽培吊兰的一个原因。有的吊兰如果种的好，不但叶片翠绿，吊兰还会开花。那么在室内种植吊兰究竟有哪些技巧呢？室内栽培吊兰又应该给吊兰一个怎样的环境呢？　　吊兰性喜温暖湿润、半阴的环境。它适应性强，较耐旱、耐寒。不择土壤，在疏松的砂质壤土中生长较佳。对光线要求不严，一船适宜在中等光线条件下生长，亦耐弱光。　　除冬季气温过低不适于分株外，其它均可进行。盆栽2—3年的植株，在春季换盆时将密集的盆苗，去掉旧土，分成两至数丛，分别盆栽成为新株。吊兰也可利用走茎上的小植株繁殖。在生长季，剪取走茎上的小植株，种植在中或水中，待小植株长根后移植至盆中。　　吊兰盆栽常用腐叶土或泥炭土、园土和河沙等量混合并加少量基肥作为基质。每2—3年换盆一次，重新调制培养土。其肉质根贮水组织发达，抗旱力较强，但3—9月生长旺期需水量较大，要经常浇水及喷雾，以增加湿度。　　肥料以氮肥为主，但金心和金边不宜施氮肥过量，否则叶片的线斑会变得不明显。吊兰喜半阴环境，如放置地点光线过强或不足，叶片就容易变成淡绿色或黄绿色，缺乏生气，失去应有的观赏价值，甚至于枯而死。', '　　　\n　一、播种\n　　这种方法用的比较少，一般在3月份比较适宜，撒上吊兰种子，盖上5mm的土层，浇水湿透，不能有存水，以免种子浸泡水中，　\n　二、分株\n　　分株繁殖比较麻烦，需要将吊兰植株取出，把吊兰从土中剥离出来，然后切割出新的植株来，需要注意的是，新的植株必须有根有茎叶，才能保证植株的生长。　\n　三、扦插\n　　最简单常用的方法，成活率也比较高，需要吊兰生长比较旺盛，有长新芽的匍匐茎，把匍匐茎剪下来，直接插如土中，一周便可生根成活。　　\n四、繁殖后\n　　1、换盆换土。为了保证茎叶生长茂盛，可以一年换盆换土，并把枯腐根去除，保证土壤中的基肥充足。　　2、浇水。吊兰喜阴湿环境，土培的吊兰一定要保证土壤潮湿，但是温度过低时不能太湿，否则会　　3、施肥。主要是氮肥，氮肥一般对家养观赏　　4、光照。吊兰喜阴湿，应避免强光照射，可偶尔拿出室外晾晒。　　5、温度。吊兰一般的15度到25度生长良好，5度以下遍会冻伤植株。', 'http://img.boqiicdn.com/Data/BK/P/imagick32161439285452.jpg', 'http://www.boqii.com/entry/detail/1929.html', '');
INSERT INTO `plant_family` VALUES ('485', '花毛莨', 'Ranunculus asiaticus （L.） Lepech.', '花毛茛', '芹菜花、波斯毛茛、陆莲花', '不容易死', '世界多地', 'http://www.boqii.com/entry/photo/2145/0,http://www.boqii.com/entry/photo/2145/5382', '植物界', '被子植物门', '双子叶植物纲', '毛茛目', '毛茛科', '花毛茛属', '花毛茛', 'Ranunculus asiaticus （L.） Lepech.', 'Ranunculus asiaticus', '　　 　　花毛茛株姿玲珑秀美，花色丰富艳丽，为多年宿根草本花卉。株高20厘米～40厘米，块根纺锤形，常数个聚生于根颈部；茎单生，或少数分枝，有毛；基生叶阔卵形，具长柄，茎生叶无柄，为2回3出羽状复叶；花单生或数朵顶生，花径3厘米～4厘米；花期4月～5月。地下具纺缍状小块根，长约2厘米，直径1厘米。地上株丛高约30厘米，茎长纤细而直立，分枝少，具刚毛。根生叶具长柄，椭圆形，多为三出叶，有粗钝锯齿。', '　　在昆明地区俗称“洋牡丹”，为多年生宿根草本花卉。现在，花毛莨在世界各国均有栽培，是非常适合冬春促成栽培的花卉。由于花毛莨的受欢迎程度，现在，种植面积也在逐年增加。　花毛茛地栽盆栽均宜。栽植时要施入充足的基肥。盆栽可用园土2份、腐叶土与厩肥各1份作盆土。　花毛茛新芽出土后，可适当控水，以防植株旺长。待叶片展开以后，保持土壤潮湿，不可过旱缺水，尤其是在植株8至10片叶时，否则会影响花芽分化。　花毛茛喜光，只有保证每天不少于4小时的光照，植株才能良好。另外，花毛茛是长日照，可根据其特性控制花期。　花毛茛在10℃至20℃之间生长良好，新芽出土后可适当降低温度，以防徒长，尤其是夜间温度要低。定植6至7周后，植株进入花芽分化期，此时应保持温度在5℃至15℃之间。　花毛茛是喜肥的花卉，在栽培过程中应勤追肥。每隔一周追一次肥，最好用有机肥与无机肥交替施肥。即第一次用稀薄鸡猪粪浸出液，第二次追肥则用3‰的磷酸二氢钾溶液，第三次再用有机肥料，如此交替追肥，则大大地促使花蕾分化。　花毛茛生长期如果高温高湿，容易引起、黄叶和茎基病腐。主要虫害有根蛆、潜叶蝇，用40％氧化乐果乳油1000倍液喷杀；根腐病用50％苯来特可湿性粉剂1000倍液浇灌。　花毛茛现蕾初期，每株选留3－5个健壮花蕾，减余摘去。这时盆土宜稍干些。花后如果不需要留种，应及时剪除残花。', '　　花毛莨一般用播种的方法进行繁殖，也可以通过块根进行无性繁殖保存下来。现在花毛莨常被盆栽或切花使用，随着人们对花毛莨的喜爱，其栽培面积也越来越大了。那么花毛莨在播种繁殖的过程中应该注意哪些　\n　1、留种采种\n　　为采集优良种子，要根据选种目标的要求，确定采种母株，标明记号，加强　　\n2、低温催芽\n　　花毛茛正常播种期为秋季，宜在温度降到20℃以下的10月播种。但不同年份温度相差较大，发芽时间长短不一。如能控制种子发芽适温在10℃至15℃，约20天发芽。早播，温度高于20℃不发芽，直至下降到发芽温度，播后发芽所需时间长；晚播，', 'http://img.boqiicdn.com/Data/BK/P/imagick16311445592064.jpg', 'http://www.boqii.com/entry/detail/2145.html', '');
INSERT INTO `plant_family` VALUES ('486', '玉蝶', 'Echeveria secunda var. glauca', '玉蝶', '石莲花、宝石花、石莲掌、莲花掌、八宝掌', '不容易死', '原产地墨西哥伊达尔戈州', 'http://www.boqii.com/entry/photo/1994/0,http://www.boqii.com/entry/photo/1994/5532', '　', '被子植物门 Magnoliophyta', '双子叶植物纲 Magnoliopsida', '蔷薇目 Rosales', '景天科 Crassulaceae', '石莲花属 Echeveria', '石莲花 E.glauca', 'Echeveria secunda var. glauca', 'Echeveria secunda', '　　玉蝶又称 　　玉蝶的植株具短茎，易从基部萌生，匍匐茎顶端有小莲座叶丛，其沾土即生根，成为新的植株。因此，地栽多年的玉蝶往往是成片', '　　是我国最常见的群生多肉之一，玉蝶的外形好似一朵盛开的绿色莲花，并且植株会根据光照的强弱出现不同的变化。玉蝶的生长速度比较快，非常容易长高，如果不注意的话，也很容易出现摊大饼的情况，小编就为你整理了玉蝶的栽培方法及，的朋友们可以一起学习。　玉蝶生长较快，在充足光照的前提下，可以给予其足够的水分，配土接近干透就可浇透一次水。浇水的时间可选择春冬的临近中午较暖和的时间段和夏季下午或者晚上较为凉爽的时间段。如果无法把握正确的浇水节奏，那么，摸摸玉蝶的叶片，感觉叶片发焉发软，那就是缺水的症状了。配土可选择透气排水性良好的土壤，如泥炭土、颗粒土1：1的比例配置，也可以不用这么讲究，用园土都行，但要注意浇水频率，园土容易积水潮湿不透气。　除了盛夏适当遮阴，其余时间均可全日照，充足的光照，可以让玉蝶的株型紧凑叶色动人。光照不足，玉蝶株型松散，叶片会变得比较细长，颜色显得较淡。　　这个玉蝶明显光照不足，摊大饼了，可看出株型较散，叶片细长而无力，这种情况再增加光照，就要等待重新生长出的叶片，再焕发精彩了。　所有的多肉都喜欢通风，可有效避免病菌滋生。网购回来的玉蝶，缓苗期间可用潮土种下将玉蝶放在明亮通风处1－2周，再逐渐增加光照，期间可酌情浇水，玉蝶缓苗的时候，下部叶片容易老化枯去，这是正常现象，不用太担心。　　夏季温度上30℃的时候，应适当遮阴，加强通风，节制浇水，浇水可浇透但不要让土壤长期潮湿，由于玉蝶容易群生，间接造成其底部不通风，因潮湿引起的闷热可能导致玉蝶黑腐，总的来说玉蝶不怎么耐热，夏季光照太强，往往叶片颜色会先变得有点浅黄（很好看），然后…就黑腐了，出现这种情况可以考虑及早砍杆子。冬季温度低于5℃，应控制浇水或断水，若再低，则要搬进室内越冬，尽量选择向阳的室内。', '　　　　玉蝶的繁殖可选择枝插或者叶插，叶插枝插期间，应放置于通风明亮无直射光处，光照太强或太暗会抑制叶插的成功率，待小苗长出后，逐渐增加光照。　\n　叶插：\n　　\n枝插：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick98431441099802.jpg', 'http://www.boqii.com/entry/detail/1994.html', '');
INSERT INTO `plant_family` VALUES ('487', '兰花', 'Orchid', '兰花', '中国兰、春兰、兰草、兰华、幽兰、山兰、国香、空谷仙子、香祖', '不容易死', '', 'http://www.boqii.com/entry/photo/1991/0,http://www.boqii.com/entry/photo/1991/5536', '', '', '', '', '', '', '', '', '', '　　 　　兰花为附生或地生草本，罕有腐生，通常具假鳞茎；假鳞茎卵球形、椭圆形或梭形，较少不存在或延长成茎状，通常包藏于叶基部的鞘之内。叶数枚至多枚，通常生于假鳞茎基部或下部节上，二列，带状或罕有倒披针形至狭椭圆形，基部一般有宽阔的鞘并围抱假鳞茎，有关节。　　　　　　　　　　　　　　　　　　　　', '　　是我国非常有名的观赏花卉，很多花友都会选择在自家的家居环境或中栽种上一株兰花，还能起到美化家居的效果。但是由于兰花给人一种比较高贵的感觉，很多花友都不知道应该如何才能养好兰花，小编就带你来了解一下栽种兰花时的。　兰花对土壤要求不严。最好选择疏松肥沃且排水良好的砂质土壤和杂草土灰的混合，更利于兰花的生长。　由于兰花是短日照植物，每日日照不需要太久，室内用散射光照射即可。　由于兰花耐寒，温度方面的调控可以粗放，最适宜生长和开花的温度在15度到25度之间。　兰喜肥，肥力充足才可以让兰花生长更快，还会促使二月兰的开花结果一年施肥4次。定期的施肥也会让花色则更艳丽，果实将更饱满。　　兰花浇水千万不要直接装了自来水就去浇，最好用雨水和泉水，这样才能吸收的更多的营养。浇时要从盆边浇，不能直接从兰花中间往下浇，但是在冬季保持二成湿就可以了。　二月兰种植常见害虫有蚜虫、菜青虫、蜗牛、潜叶蝇等。若发现害虫，要及时进行防治。　兰花并不会很娇嫩，可淋雨，但非常的怕梅雨、暴雨，否则就会造成烂心、烂叶，梅雨季节，可适当撒少量草木灰。　保持二月兰较好的观赏效果，就必须控制不令其结实，一般在结实期用剪草机将其修剪到10～15cm的高度。　　对于生长差的兰花，应进行大量的摘花，这样才能保证正常的生长，对于长势较好的品种，也可适当摘去一些花苞，这样花可开久些，又可使新叶多抽，老叶也不易枯死。', '　　　\n　一、分株繁殖\n　　在春秋两季均可进行，一般每隔三年分株一次。凡植株生长健壮，假球茎密集的都可分株，分株后每丛至少要保存5个连结在一起的假球茎。分株前要减少灌水，使盆土较干。分株后上盆时，先以碎瓦片覆在盆底孔上，再铺上粗石子，占盆深度1／5～1／4，再放粗粒土及少量细土，然后用富含腐殖质的沙质壤土栽植。栽植深度以将假球茎刚刚埋入土中力度，盆边缘留2cm沿口，上铺翠云草或细石子，最后浇透水，置阴处10～15天，保持土壤潮湿，逐渐减少浇水，进行正常　\n　二、播种繁殖\n　　兰花种子极细，种子内仅有一个', 'http://img.boqiicdn.com/Data/BK/P/imagick31061441015519.jpg', 'http://www.boqii.com/entry/detail/1991.html', '');
INSERT INTO `plant_family` VALUES ('488', '王莲', 'Victoria regia Lindl.', '王莲', '', '不容易死', '', 'http://www.boqii.com/entry/photo/1988/0,http://www.boqii.com/entry/photo/1988/5539', '　　', '被子植物门', '双子叶植物纲', '毛茛目', '睡莲科', '王莲属', '王莲', 'Victoria regia Lindl.', '', '　　 玉莲 　　王莲初生叶呈针状，长至2－3片时矛状，4－5片时呈戟形，6－7片叶时完全展开呈椭圆形至圆形，到11片叶后叶缘上翘呈盘状，叶缘直立，叶片圆形，像圆盘浮在水面，直径可达2米以上，叶面光滑，绿色略带微红，有皱褶，背面紫红色，叶柄绿色，长2－4米，叶子背面和叶柄有许多坚硬的剌，叶脉为放射网状。王莲巨大的叶不仅引人注目，而且其负载能力更让人吃惊。一片大的叶片能够负重70千克，这是由于其叶片和叶脉内具有很多大的空腔，腔内充满气体，使叶片浮于水面。叶子背面生长着粗壮的叶脉，板状隆起，纵横交错构成一个一个的高10厘米以上的方形小格，有利于保持叶片开展性，增加叶片的排水力和负载力。', '　　王莲是睡莲科王莲属中比较名贵的观赏植物，也是世界上叶片面积最大的双子叶植物，其浮力极大，几岁小孩坐在上面都不会下沉，所以非常特别。王莲也会开花，并且其花朵颜色在生长过程中会出现白、红、紫三种颜色变化，非常特殊。那么如此奇特的王莲究竟应该如何栽培呢？　　　在定植的同时，应准备覆盖薄膜。起初，幼苗在露地中适应性不强，白天与夜晚大，遇上阴雨可能烂叶，所以薄膜应在I店天翻开，阴雨天和夜问狡盖，持续到6月中旬为止。　　　在定杭后。幼苗期还剩25天左右的时间里，应每10天追肥一次，以复合肥为主。到速生期时，叶径日均增长量为20cm，平均每3－4天生一片叶，此时应每5天追一次肥。开花后，由于天气炎热，温度高，植株生长旺盛，开花现若率高。施肥时可用带孔的薄膜小袋装20g左右速效磷肥埋入离权不远的地方，入泥深约10cm，每次退肥时要改换位置，以利根系平衡发育。　　　注水深度与王莲发育相当有关。王莲是浅水，水位一般不超过植株茎顶端0.4m，水位变化幅度也应控制在0.3m以内，睛天宜多，阴天宜少。在移植后的幼苗期，应以苗的生长状况来调节水位。　　　春天，在温室培育时，阳光不充足，可在距苗1.5m的上方安装100w的电灯，增加光照强片和光照时间。在池内应经常清除缠绕王莲叶花的水中植物，如青苔，水绵、浮萍等。随时剪去植株上衰烂的老叶，保持池水清洁，并空出水面让新叶生长。　　　当遇到水蛆等害虫时，可在小布袋内装上浸有或的锯屑，固定在有虫的叶片下，局部杀灭害虫，也可全全池喷洒，清池。当池水不流通时，王莲易患病，其症状表现为：初期叶面出现褐色斑点，具黄色晕圈，以后逐渐扩展蔓延，呈水渍状病斑，后期有几个斑坟汇合，叶片大块。发病时，可采用放干池水，清洁池塘，或用杀菌剂喷洒叶面防治。', '　　　　\n一、品种选择\n　　王莲有两种，一种为亚马逊王莲，主产于南美亚马逊河流域，叶面较大，叶缘稍低，在25℃时才能开花，另一种为克鲁兹王莲，主产于巴拉那河流域，叶面较小，叶缘较高，在18℃时便能开花。为了使王莲能在当地露地栽培，一般选择克鲁兹王莲。我院引种的是克鲁兹王莲。　　\n二、种子选择\n　　王莲果实中常伴有成熟的和未完全成熟的两种种子，成熟种子比未成熟种子的发芽率低，但它萌发周期短，生长速度快。在人工催芽的情况下，成熟种子播后5一6天发芽，一周结束，未完全成熟种子发芽较迟，一般2一3周结束。成熟种子的发芽期为一个月，未完全成熟种子则为2个月。所以应选用成熟种子来播种。成熟种子比未完全成熟种子轻，呈深绿色。另外，当年收获的种子，不能选在当年播种，因为王莲种子与其它莲属种子不同，它有一段休眠期，来完成有机体内的生理代谢，不宜播种。　\n　三、播种期\n　　在长江流域，3月上旬至4月上旬，播种早晚对主莲生长无明显影响。北方温室　\n　四、催芽\n　　处理种子的方法一般是刻伤或磨破种皮（不伤胚乳）。催芽有三种方式：一是温水池催芽，取处理过的种子10－15粒置入培养皿中，正放入温水池里，池水　\n　五、育苗\n　　经催芽的初生幼苗，约zo天后，生有2片叶，3一5条根时，便开始移植上盆进行育苗。先发芽的先移植，一般用口径为lOcm左右的小盆，内装较细的泥和少量砂土（砂土覆盖泥土），不宜过满，每盆一株。栽植深度以种壳略高出土面为宜，正放入温水中，使叶片浮在水面上。整个过程　\n　六、定植\n　　带土将苗移植在池幼和缸中，移植深度似苗带土而与外围土面相平为宜，然后在上面盖2－3cm细砂，保持水位高出泥土10－－15cm。', 'http://img.boqiicdn.com/Data/BK/P/imagick19901441013789.jpg', 'http://www.boqii.com/entry/detail/1988.html', '');
INSERT INTO `plant_family` VALUES ('489', '量天尺', 'Hylocereus undatus （Haw.） Britt. et Rose', '量天尺', '霸王鞭、霸王花、剑花、三角火旺、三棱柱、三棱箭、龙骨花', '不容易死', '中美洲至南美洲北部，夏威夷、澳大利亚、中国、世界各地广泛栽培', 'http://www.boqii.com/entry/photo/2125/0,http://www.boqii.com/entry/photo/2125/5402', '　', '被子植物门', '双子叶植物纲', '仙人掌目', '仙人掌科', '量天尺属', '量天尺', 'Hylocereus undatus （Haw.） Britt. et Rose', 'Hylocere usundatus', '　　 　　量天尺为攀援肉质灌木，长3－15米，具气根。分枝多数，延伸，具3角或棱，长0.2－0.5米，宽3－8（－12）厘米，棱常翅状，边缘波状或圆齿状，深绿色至淡蓝绿色，无毛，老枝边缘常胼胀状，淡褐色，骨质；小窠沿棱排列，相距3－5厘米，直径约2毫米；每小窠具1－3根开展的硬刺；刺锥形，长2－5 （－10）毫米，灰褐色至黑色。', '　　量天尺又名龙骨花、三角柱、霸王花等，为仙人掌科多肉植物，是生命力极强的植物。量天尺不但是很好养的多肉植物，还能净化空气中的甲醛、苯、氡、氨等有害气体，深受人们的欢迎。那么量天尺在栽培过程中应该注意哪些问题呢？　　量天尺（霸王花）喜疏松、肥沃、富含腐殖质的土壤。盆栽用土可用1份腐叶土和1份粗沙混合并加入少量腐熟的鸡粪或牛粪配成的土。　　夏季要放在半阴的环境条件下。冬季要求光照充足，放在室内向阳处，温度宜保持10℃以上，温度低于10℃时易发生冻害。　　春季浇水不宜过多，每10－15天浇1次水即可，但每天应向植株喷水，增加空气湿度。夏季应每天浇水1次，宜在早晨或傍晚浇水。冬季盆土应保持适度干燥，可用塑料薄膜套盆包扎保护越冬。越冬栽培环境既要保持较高的温度，又要保持较高的空气湿度。　　量天尺（霸王花）修剪：　　第一，将很少开花的老枝剪掉。　　第二，利用顶端新芽活力旺盛，开花多的优势，摘除下面长出的弱芽，使其顶芽充分、伸长，发挥出顶端优势。霸王花在5～11月份开花，约7～8期，每期间隔20天左右。花的大小是现蕾后的25～30天。此时，也是最佳的采收期。最佳的采收是花开后的翌日清晨或下午。上市和出口的花是加工制成的干花。', '　　量天尺的栽培难度并不高，一般可用扦插方式进行繁殖，成活率也比较高。由于量天尺对于很多有害气体的吸附能力比较强，所以也深受人们的欢迎。一般，量天尺多用扦插的方法进行繁殖。　　量天尺常剪断扦插成活后，做蟹爪兰、　　量天尺扦插繁殖容易生根，扦插基质可用素沙或腐熟的腐叶土加草木灰，后者效果较前者为好。', 'http://img.boqiicdn.com/Data/BK/P/imagick59361445245627.jpg', 'http://www.boqii.com/entry/detail/2125.html', '');
INSERT INTO `plant_family` VALUES ('490', '铁兰', 'Tillandsia cyanea', '紫凤梨', '铁兰、紫花凤梨 、紫花铁兰、球拍铁兰', '不容易死', '原产厄瓜多尔', 'http://www.boqii.com/entry/photo/1964/0,http://www.boqii.com/entry/photo/1964/5563', '　', '被子植物门', '单子叶植物纲', '凤梨目', '凤梨科', '铁兰属', '紫凤梨', 'Tillandsia cyanea Linden ex K. Koch', '', '　　 　　铁兰为多年生草本植物。株高约30cm，莲座状叶丛，中部下凹，先斜出后横生，弓状。淡绿色至绿色，基部酱褐色，叶背绿褐色。总苞呈扇状，粉红色，自下而上开紫红色花。花径约3cm。苞片观赏期可达4个月。紫凤梨还有许多其他的', '　　就是我们常说的紫凤梨，由于铁兰的颜色非常漂亮，并且很适合制作成盆栽栽种在室内，所以也深受人们的喜爱。现在铁兰还被用于作为陪衬的材料，不但典雅，还非常新奇。　　　铁兰喜明亮光线，高温、高湿的环境，忌阳光直射，在原产地生于热带森林的大树上，较耐干燥和寒冷。生长适温20～30℃，最低温10℃。繁殖可以用分栽基生芽法繁殖，也可用播种法繁殖。酷热应遮荫，并充分浇水，冬季应置室内阳光充足处，并控制水分，温度不得低于10摄氏度。　　　1、摆放位置：铁兰喜光线明亮、半阴、温热、湿度较高的环境。可以将其摆放在有明亮漫射光的环境之中。　　2、温度：在高于16℃的环境里终年生长，冬季应移在温室里，夜间最低温度不要低于10℃。　　3、浇水：生长期间要充分给水，炎热时每日需为植株喷2次水。冬季需保持盆土潮润。　　4、追肥：每月施半浓度的液肥一次。有些品种的铁兰无须施肥。　　5、栽培与换盆：宜用排水性良好的壤土栽培，一般无须换盆。　　6、繁殖：家庭种植可用分生基出芽法繁殖。当基出芽长至8厘米长时，将其解取种植。', '　　铁兰为多年附生草本　　铁兰繁殖可用分生基的方法繁殖，春季从母株茎基部萌生出许多小的吸芽（即子株），此时即可结合换盆，把母株从盆内托出，去掉根系的陈土，可以轻微抖动，不要大量伤及根部。　　选择生长健壮、株形大的子株，用利刀连根切下，切面应平滑，以利于愈合。切下的子株用田园土加粗砂混合上盆。上盆后用塑料薄膜遮盖住盆株，放在荫蔽处', 'http://img.boqiicdn.com/Data/BK/P/imagick97711440064187.jpg', 'http://www.boqii.com/entry/detail/1964.html', '');
INSERT INTO `plant_family` VALUES ('491', '钱串子', '', '钱串子', '', '不容易死', '', 'http://www.boqii.com/entry/photo/1910/0,http://www.boqii.com/entry/photo/1910/5619', '', '', '', '', '', '', '', '', '', '　　很多人饲养 　　1、水黄：因浇水过勤引起，其特点是老叶无明显变化、幼叶变黄，此应立即控水。　　2、旱黄：因缺水、干旱引起，其特点是自下而上老叶先黄，若缺水　　3、肥黄：因施肥过勤或浓度过高引起；特点是幼叶肥厚，有光泽，且凹凸不平；应控肥、中耕、浇水。　　4、饿黄：因肥料不足、施肥浓度偏低，且施肥间隔时间过长而引起；其特点为幼叶、嫩茎处先黄，如见此现象后不及时施肥，也会造成全株黄叶甚至死亡；对缺肥的花卉，切忌一次大量施用浓肥，以免造成烧根。　　5、是缺铁性黄叶。温室中木本花卉等，由于土壤肥力条件变化大，常会出现黄叶现象，特点是幼叶明显，老叶较轻，叶肉黄色，叶脉绿色，并形成典型网络；可施用硫酸亚铁水溶液来解决，其方法为：饼肥7份，硫酸亚铁5份，水200份配成倍液浇之。 　　钱串子花应经常修剪整形，剪去过乱的枝条，以保持株形的优美。由于老株的茎容易中空，使肉质口十萎缩、脱落，从而造成植株下部没有叶，显得光秃秃的，很不美观，应繁殖新株，对老株进行更新。钱串子花生长过于拥挤时可在春季或秋季换盆，种植盆应根据植株的大小进行　　春季是钱串子养殖的好季节，不但钱串子在冬季生长的比较快，春节在家里放置一个钱串子也是一个非常好的寓意。钱串子不只可当小品盆栽栽种，也可运用于花艺设计上，挑选特殊的盆器再加一点巧思就可以呈现不同的风貌，也可让其攀爬于墙面或是树干上美化。钱串子不需太多管理的特性，也是园艺新手可以选择的入门植物之一。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick52191428056622.jpg', 'http://www.boqii.com/entry/detail/1910.html', '');
INSERT INTO `plant_family` VALUES ('492', '袖珍椰子', '', '袖珍椰子', '矮生椰子、袖珍棕、矮棕', '不容易死', '中美洲热带地区', 'http://www.boqii.com/entry/photo/1996/0,http://www.boqii.com/entry/photo/1996/5531', '', '', '', '', '', '', '', '', '', '　　 　　袖珍椰子盆栽时，株高不超过1米，其茎干细长直立，不分枝，深绿色，上有　Chamaedorea Elegans植物界　　　　　　　　', '　　袖珍椰子为科常绿小乔木，由于袖珍椰子的植株不大，是现在非常常见的室内。原产于墨西哥北部和危地马拉的袖珍椰子性喜高湿环境，耐阴，所以非常适合栽种在室内。　　1、光照：小盆栽袖珍椰子喜阴，要是摆放在室内进行培养就可以放在荫蔽的环境或有隐约的散光的地方。小盆栽袖珍椰子最忌讳的受到强光的直接照射，仅仅是一会儿的曝晒，同样会导致叶片干燥枯黄，失去原有的色泽。相反，小盆栽袖珍椰子要是长期摆放在过分阴暗的位置，叶片的色泽同样会变浅，失去原有的光泽度。小盆栽袖珍椰子放在房间外进行培育的可以罩点遮光网，遮挡60％左右的光照。　　2、：小盆栽袖珍椰子要是在温度高、湿度高及半阴的环境下，它的长势较快些，小盆栽袖珍椰子最忌讳的就是直射的光束。期处于20℃～30℃的温度最为适合，的室内温度12℃～I4℃为宜，最低温度不得处于l0℃以下。13℃便进到休眠状态，室内温度为8℃左右就可以安全的度过寒冬。　　3、水分：小盆栽袖珍椰子有着强吸水性，生长期间可以经常加加水，使盆土处于湿润状态，休眠期的水量就得控制了。小盆栽袖珍椰子夏季浇水得充足，也要常常喷点水在叶片上，用来增加空气的湿度，盆内可以留有积水。从l0月一直到第二年的2月是小盆栽袖珍椰子的相对休眠时期（夜晚温度在l2℃～14℃），减少浇水只要使盆土湿润就好，防止气温太低从而出现根烂、叶片发黄及坏死现象。若将小盆栽袖珍椰子放在带有暖气的空调房内栽培，就应该使盆土保持湿润，也得常常喷水在叶片上，使叶面的湿度增强。', '　　　　1、播种法：长势好且健壮的小盆栽袖珍椰子植株3－4年能开花，并进行人工授粉得种籽，6～7个月时间它的果实才能成熟。刚采摘的小盆栽袖珍椰子种子便能进行播种，在播种之前小盆栽袖珍椰子种子要用35℃～40℃温水浸36小时，等到小盆栽袖珍椰子种子吸收水分膨胀后种下，放在1.5cm处填土，用孔口细小的喷头浇透水，在盆口上方用塑料薄膜盖上，使温度加以提升，控制在22℃～25℃的温度范围，小盆栽袖珍椰子种子会在30－40天内萌发。直到幼苗冒出出2片或3片真叶时就可以连带土团装盆了。　　2、分株繁殖：小盆栽袖珍椰子在出苗到拔节的时期分蘖比较多，因此要对它进行分株。最好是在', 'http://img.boqiicdn.com/Data/BK/P/imagick11411441100146.jpg', 'http://www.boqii.com/entry/detail/1996.html', '');
INSERT INTO `plant_family` VALUES ('493', '绣球花', 'Hydrangea macrophylla （Thunb.） Ser.', '绣球', '八仙花、粉团花、草绣球、紫绣球、紫阳花', '不容易死', '', 'http://www.boqii.com/entry/photo/2024/0,http://www.boqii.com/entry/photo/2024/5503', '', '', '', '', '', '', '', '', '', '　　 　　绣球是灌木，高1－4米；茎常于基部发出多数放射枝而形成一圆形灌丛；枝圆柱形，粗壮，紫灰色至淡灰色，无毛，具少数长形皮孔。叶纸质或近革质，倒卵形或阔椭圆形，长6－15厘米，宽4－11.5厘米，先端骤尖，具短尖头，基部钝圆或阔楔形，边缘于基部以上具粗齿，两面无毛或仅下面中脉两侧被稀疏卷曲短柔毛，脉腋间常具少许髯毛；侧脉6－8对，直，向上斜举或上部近边缘处微弯拱，上面平坦，下面微凸，小脉网状，两面明显；叶柄粗壮，长1－3.5厘米，无毛。　　　　　　　　　　　　　　绣球花族　　　　　', '　　绣球花又名八仙花，几乎全为无性花，而我们看到的所谓的花其实是萼片。在我国，绣球花的栽培是比较早的，明、清时代的江南园林中就有绣球花的栽种。现在绣球花的颜色繁多，并且经过人工培育后，花大色艳，非常受人喜爱。那么如何才能栽种出漂亮的绣球花呢？　　　栽培绣球花应该选择荫蔽处，经常保持土壤湿润，但也不易浇水过多，炎热夏季蒸发量大，每天需浇水1次。春秋2～3天浇水1次，冬季要节制浇水，一般一个月沿着盆边浇水少许即可。雨季则要注意排水，受涝而发生根部。盆栽八仙花常用15～20厘米口径的盆。盆栽植株在春季萌芽后要注意充分浇水，以保证叶片不萎蔫。　　　　在八仙花的生长期间每2～3周施以豆饼、人粪尿或鸡粪沤制而成的稀释液肥一次，以促进生长和花芽分化。花期喷0.2％的磷酸二氢钾溶液，可使枝叶繁茂，粗壮挺立。在碱性土上栽培，适宜经常施以硫酸亚铁水溶液或硫酸亚铁与其它有机肥料一起沤制的矾肥水，以中和土壤碱性。盆土宜用壤土、腐叶土或者堆肥土等量配合，并加入适量的河沙。夏季气温高，肥水如果过大，容易引起徒长，这时可摘心或喷嘧啶醇50～100毫克／千克控制高度。　　　春暖后应移至荫棚下，遮光50％左右。8月以后增加光照，以促进绣球花的花芽分化。', '　　　　绣球花常用扦插、分株、压条和嫁接繁殖，以扦插为主，可于梅雨期间，选取幼龄母树上的健壮嫩枝作插穗，插穗基部需带节，并沾以泥浆，长20厘米左右，摘去下部叶片。扦插适温为13～18℃，插后需遮荫，经常保持湿润，约15天到1个月发根，成活后第二年可移植。分株繁殖则宜在早春萌芽前进行。将已生根的枝条与母株分离，直接盆栽，浇水不宜过多，在半阴处', 'http://img.boqiicdn.com/Data/BK/P/imagick97091441877962.jpg', 'http://www.boqii.com/entry/detail/2024.html', '');
INSERT INTO `plant_family` VALUES ('494', '昙花', 'Epiphyllum', '昙花', '琼花、昙华、鬼仔花、韦陀花', '不容易死', '', 'http://www.boqii.com/entry/photo/1999/0,http://www.boqii.com/entry/photo/1999/5528', '', '', '', '', '', '', '', '', '', '　　 　　昙花高2－6米，老茎圆柱状，木质化。分枝多数，叶状侧扁，披针形至长圆状披针形，长15－100厘米，宽5－12厘米，先端长渐尖至急尖，或圆形，边缘波状或具深圆齿，基部急尖、短渐尖或渐狭成柄状，深绿色，无毛，中肋粗大，宽2－6毫米，于两面突起，老株分枝产生气根；小窠排列于齿间凹陷处，小形，无刺，初具少数绵毛，后裸露。　　　　　　　　　　　　　　　　　　　　　', '　　由于其开花只有短短的1－2小时，并且多余晚间开放，所以是很多花友都非常的观赏花卉，在我国南北方家庭中普及度都非常广。昙花虽然开花较短，但是花白色，大而长，香气四溢，所以深受人们的欢迎。　　　昙花喜富有腐殖质、排水好、疏松、肥沃的微酸性沙质土壤。盆土配制比例一般为：腐叶土∶园土∶沙土＝4∶4∶2。土配好后，最好在太阳下暴晒杀菌。种植时，在盆底放一层碎瓦片或砖片，增加透气排水。　　　昙花喜湿润的土壤和较高的空气湿度，怕水涝。秋末、冬季、初春气温较低时，昙花处于半休眠状态，应严格控制浇水，使盆土处于偏干状态，干透后略微浇点水即可。春季气温上升后，昙花开始恢复，可逐渐加大浇水量，保持土壤湿润。生长旺盛时除浇水外，还应向植株周围洒水，以增加空气湿度，并加强通风。　　　昙花较喜肥，对的要求也较多。以腐熟的有机肥为好，加上少量的骨粉或过磷酸钙。在准备土壤时加入，与盆土混合均匀，施用量为盆土的1／20至1／30。春季新茎长出后，开始追肥，生长期间如见叶片发黄，应追施500倍硫酸亚铁溶液一次，现花蕾后追施1000倍磷酸二氢钾一次，花凋谢后，每隔20天左右，增施一次磷、钾肥，秋末应停止施肥。', '　　由于　　昙花在繁殖时节多用播种法或扦插法。播种法生长较慢，开花时节也延迟，因此多用扦插法种植。简单易行的扦插法能够大力缩短开花　　昙花扦插繁殖的步骤：　　1、选一片健康的叶子，或者选取１－２年生健壮、肥厚壮茎作插穗，最好是稍长一点的，用剪刀剪下来；　　2、根据需求把叶子剪成几段，长１０－１５厘米；　　3、放在太阳不会直接晒到的地方等待剪开的地方（切口）晾干，晾２－３天；　　4、待剪口干燥后插入盛有　　5、不常浇水，让土稍微干燥点，如果干得厉害就少浇点水。隔３－４天喷少许水，经常扦插基质半湿润，插后约４周生根，可移至见弱光处，注意喷水，根长３－４厘米时上盆；　　6、等2——3个星期，应该就能长根了。　　注意：昙花冬季是', 'http://img.boqiicdn.com/Data/BK/P/imagick41971441187207.jpg', 'http://www.boqii.com/entry/detail/1999.html', '');
INSERT INTO `plant_family` VALUES ('495', '米兰花', 'Orchid', '米仔兰', '真珠兰、珍珠兰、金粟兰、鱼子兰、茶兰、鸡爪兰，米兰球', '不容易死', '原产于亚热带云南、福建等地 广西 四川', 'http://www.boqii.com/entry/photo/1940/0,http://www.boqii.com/entry/photo/1940/5589', '', '', '', '', '', '', '', '', '', '　　米 　　米兰花为常绿灌木或小乔木，茎多小枝。幼枝顶部具有星状锈色鳞片，后脱落。奇数羽状复叶，互生，叶长5－12（－16）厘米，叶轴和叶柄具狭翅叶轴有窄翅，小叶3—5，对生，厚纸质，长2－7（－11）厘米，宽1－3.5（－5）厘米，倒卵形至长椭圆形，顶端1片最大，下部的远较顶端的为小，先端钝，基部楔形，两面无毛，全缘，叶脉明显，侧脉每边约8条，极纤细，和网脉均于两面微凸起。　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　米是大叶米兰的小叶变种，其开花时气味和兰花非常像，并且也是很好的风景树，所以深受人们的喜爱。的栽培难度并不高，不过，想要种出漂亮并且花香四溢的米兰花可是需要花费一些功夫的。　　米兰花喜欢气候温暖，空气湿润和阳光充足的环境，但是不耐寒冷，稍耐阴。土壤疏松肥沃的微酸性最好。冬季的温度最好在10度以上，米兰花喜欢湿润但浇水也不宜过量，否则导致根部。叶片枯萎脱落；花期浇水过多会引起花蕾掉落，浇水过少容易造成米兰花叶子枯黄，因此，夏季气温高的时候，每天浇水1－2次。多往叶子上喷砂水，保持湿润。米兰花施肥的时候也要适当。米兰花在一年之内会开多次花，每开过一次花之后，都应及时追肥2～3次充分腐熟的稀薄液肥，这样才能开花不绝，香气浓郁。米兰花喜酸性土，盆栽宜选用以腐叶土为主的培养土。旺盛期，每周喷施一次0.2％硫酸亚铁液，则叶绿花繁。　　1、阳光。米兰花四季都应放在阳光充足的地方。如把米兰花置于光线充足、通风良好的庭园或阳台上，每天光照在8小时至12小时以上，会使植株叶色浓绿，枝条生长粗壮，开花的次数多，花色鲜黄，香气也较浓郁。如果让米兰花处在阳光不足而又蔽荫的环境条件下，会使植株枝叶徒长、瘦弱，开花次数减少，香气清淡。　　2、浇水。米兰花喜湿润，浇水要按气候干湿情况而定，既要保持盆土湿润又不能长期水分过多。过干则对米兰生长不利，出现叶片萎蔫，维持较高的空气湿度才对米兰生长有利，在天旱和生长旺盛期，最好每天叶面喷水1～2次。　　3、温度。米兰花性喜温暖，温度越高，它开出来的花就越香。一般来说，温度处在30℃以上，在充足的阳光照射下，开出来的花就浓香；反之，处在30℃以下的环境下，如果又处在光照不足的蔽荫处，开出来的花就没有在温度高时的香。养好米兰花，温度适宜范围在20℃至35℃之间，在6月至10月期间开花可达5次之多。', '　　和很多花卉不同的是，米　　\n一、扦插法\n　　用扦插法繁殖米兰简便易行，且数量多。米兰的扦插方法可分两种：一种是头年生的老枝扦插，老枝扦插　　扦条的选择，不论是隔年生老枝或是当年生嫩枝，都应选择健壮、充实、生长势好的枝条作扦条。　　嫩枝扦插繁殖一般在每年6－7月间采条扦插。选取当年生长健壮的枝条，剪成约10厘米长，剪除下面的叶片，顶端留2—3片小叶。插前最好用维生素B12针剂浸～会，以促进生根。　　扦插用花盆作插床，用蛭石或河沙为扦插基质，插深4－5厘米，插后压实浇透水，并用塑料薄膜覆盖，要求保持高温多湿，温度28－30C，以后每日喷水2－3次，保持土层湿润，40－50天即可生根。　　\n二、高位压条法\n　　高压法以在温度较高、湿度较大的条件下进行为好。压条时间一般在5—8月间，以6月上旬梅雨季节最好，成活率高，生根快。因为这一时期，环境湿度比较高。实践证明，这一时期起的高压40天后就陆续生根，到10月份，若养护得法，还可以开花1—2次。7月份起高压也可以，但这时正是盛夏酷暑之时，太阳猛烈，水分蒸发快，环境干燥，高压部位枝叶容易枯焦，愈合发根要慢一些。故高压后，要把盆栽的母本米兰放在半阴半阳或半日照的地方，否则容易枯焦。　　高压部位的选择，应在不影响整棵母株的形态下，选择隔年生、木质化的健壮枝条，在长度15—25厘米处，去除叶片，进行环状剥皮。　　高位压条选用当年半木质化的健壮无病虫害的枝条，粗0。5厘米以上，在离开分枝点的下方7－8厘米环状剥皮，用泥团或湿蛭石、苔藓包于环剥处，外加塑料薄膜包扎紧，留口供浇水，经常保持湿润，经2－3个月后生根，即可从母株上切取上盆，易于开花。高位压条可分为套盆式和包泥式。　　1、套盆式：选择一年生已木质化的健壮枝条，套上盆底盆眼扩大的花盆，要使花盆套稳固定。在套入花盆内的米兰枝条上作宽l厘米的环状剥皮，然后在其周围填上泥土压实，浇透水，此后每天要浇水，始终要保持所包泥土湿润。一般两个月即可生根，切离母株，另行栽培。　　2、包泥式：选择一年生木质化的健壮枝条，在离枝条基部10厘米左右的部位，作环状剥皮，其上部留4－5个小枝，下部侧枝全部剪除，用事先调制好的泥土（用肥土和苔醉混合；放火炉上烘干，再用沸水捏和、凉透）包在剥皮处，外包塑料酶膜，用线扎紧，下部不使其漏水，上部稍松，便于注水。包扎部分要有10厘米长，宜径5厘米。以后要每天向包扎处注水，使其保持湿润。两个月可生根，切离母株另栽。　　对初学高压者来说。环状剥皮很重要，剥得好，多数能发根成活，反之不会成活。环状剥皮的方法是：用小刀在选定的枝条部位，P下切两道圆圈，间距为＿1.5厘米，不要伤及木质部，然后削去（或剥去）中间的皮层就可以了。但对应该剥去的皮层一定要剥干净，一直剥至四周木质部出现并呈现光滑时为止。这样才能正常愈合和生根，否则很难成活。　　也可用“手指甲剥皮法”，方法是选定环状剥皮部位后，用拇指指甲由上向下剥，剥去高度约1—15厘米四周皮层，此种剥皮方法的要求同上。环状剥皮后，用事先准备好的泥团（半碗肥上加半碗苔藓，放在火炉上烘干，再加沸水捏和而成）包于环剥处，长约10厘米，直径约5厘米，外用塑料薄膜包裹，并用线扎紧，不使漏水（上口要能供浇水）。若高压枝条平伸不向上，要用绳子拉向主干，或另立支柱，以利灌水。要经常保持湿润，这是成活的关键，倘若有一天疏忽忘记灌水，塑料袋内的土壤干燥，新根随即枯死。一般2个月可生新根。若新根不多，应再等待。只要管理细心，不使干涸，总能生根成活。　　判断高压米兰是否生根，是看高压后高压部分的叶片是否呈淡黄色（不是枯黄），若呈现淡黄色说明开始愈合，再过一段时间，透过塑料袋若能看到长出白色嫩根，并逐渐布满袋内，证明不但完成活，而且生长良好。这时，可以连塑料袋一起用利剪剪下来，轻轻拆去塑料袋（勿弄碎泥团），分种在别的盆内，浇足水后放置半j弱半阳或阴处。经10天左右，脱去部分黄叶，就可以放到有阳光照射的地方。此后不久会长出新叶，发出花蕾，吐出芳香。', 'http://img.boqiicdn.com/Data/BK/P/imagick68961439459080.jpg', 'http://www.boqii.com/entry/detail/1940.html', '');
INSERT INTO `plant_family` VALUES ('496', '帝王花', 'Protea cynaroides （L.） L.', '帝王花', '菩提花，海神花', '不容易死', '南非全国均有分布', 'http://www.boqii.com/entry/photo/2240/0,http://www.boqii.com/entry/photo/2240/5287', '', '', '', '', '', '', '', '', '', '　　帝王花又名普蒂亚花，由于帝王花久开不败，所以也被誉为世界上最富贵华丽的 帝王花 　　帝王花为多年生、多花茎常绿灌木　　　　　　　　　　　　　　　　　　　　', '　　由于久开不败，所以有着“花中之王”的美名，代表着旺盛且顽强的生命力。现在很多朋友也会将帝王花作为切花，象征着胜利、圆满和吉祥。那么这种特别的在人工栽培的过程中应该注意哪些呢？　　帝王花喜温暖、稍干燥和阳光充足环境，不耐寒，宜爽水，忌积水，要求疏松和排水良好的酸性土壤，冬季温度一般不低于7度，个别品种可耐零度左右。幼苗的土壤需排水好。在生长期中，夏季需凉爽干燥气候，烈日时适当遮荫，适宜生长温度为27度，冬季需要温暖、充足的阳光及稍高的空气湿度环境。冬季温度不得低于7℃。个别品种可耐0℃左右。　　帝王花幼苗的土壤需排水好。在生长期中，夏季需凉爽干燥气候，烈日时适当遮荫，适宜生长温度为27度，冬季需要温暖、充足的阳光及稍高的空气湿度环境。　　野生的红火球帝王花生长在深厚的沙质土壤里，人工栽种时，只要是排水良好的土壤，它们都可以适应的很好，尤其是有点坡度，可以协助排水的山坡地最佳。虽然野生的植株是生长在疏林下面，栽培时最好种在全日照的环境下，花才会长的较好。　　帝王花幼苗的土壤需排水好，生长期，夏季需凉爽、干燥气候，烈日时适当遮阴。冬季需要温暖、充足阳光和稍高的空气湿度环境。花期和生长旺盛期，适当浇水春、秋季各施肥1次。　　帝王花在生长期喷促花王3号，能把营养生长机能转化成生殖机能，抑制主梢疯长，促进花芽分化，多开花，多坐果，促。再在幼果期喷壮果蒂灵，提高营养输送量。防落花、落果、僵果、畸形果的产生。使果实着色靓丽、果型美、品味佳。', '　　　　\n一、播种繁殖\n　　常在秋季进行，将用新高脂膜拌种的种子播种，播后保持湿润，出苗后不能过湿，稍干燥，待出现1对真叶时移栽上盆，放置通风和光照充足处　　\n二、插杆繁殖\n　　选择帝王花母本剪取半木质化位置以上的枝条作为插穗，保留叶片4～6枚。基质采用泥炭和珍珠岩按体积比为4：6混合，调整pH值5.5～6.5，EC值小于0.5。用1000ppm的吲哚－3－丁酸溶液浸插穗基部，浸泡15分钟后立即风干。扦插深度为插穗长度的1／3～1／4。扦插后按常规技术进行', 'http://img.boqiicdn.com/Data/BK/P/imagick15111447926149.jpg', 'http://www.boqii.com/entry/detail/2240.html', '');
INSERT INTO `plant_family` VALUES ('497', '风信子', 'Hyacinth ', '风信子', '洋水仙', '不容易死', '', 'http://www.boqii.com/entry/photo/1897/0,http://www.boqii.com/entry/photo/1897/5632', '', '', '', '', '', '', '', '', '', ' 　　有些美丽让人望而却步，有些美丽只能让人铭记，而风信子却给了我们真实的感受，花开时芳香味十足，地栽、盆栽、水培都可以，风信子的花朵　　风信子习性喜阳、耐寒，适合生长在凉爽湿润的环境和疏松、肥沃的砂质土中，忌积水。 喜冬季温暖湿润、夏季凉爽稍干燥、阳光充足或半阴的环境。喜肥，宜肥沃、排水良好的沙壤土。地植、盆栽、水养均可。　　秋季生根，早春新芽出土，3月开花，5月下旬果熟，6月上旬地上部分枯萎而进入休眠。在休眠期进行花芽分化，分化适温25℃左右，分化过程1个月左右。花芽分化后至伸长生长之前要有二个月左右的低温阶段，气温不能超过13℃。　　风信子在生长过程中，鳞茎在2-6℃低温时根系生长最好。芽萌动适温为5-10℃，叶片生长适温为5-12℃，现蕾开花期以15-18℃最有利。鳞茎的贮藏温度为20-28℃，最适为25℃，对花芽分化最为理想。可耐受短时霜冻。喜凉爽、空气湿润、阳光充足的环境，较耐寒。　　用壤土、腐叶土、细沙等混合做营养土，然后装入盆中，种上风信子。一般10～11月栽植，3月开花。　　风信子喜光照充足的环境，光照是它开花的重要限制因子。在栽培过程中，应该保证植株每天接受不少于4 h的直射日光。在光照充足的情况下，风信子能够生长得更为茁壮，花朵的颜色也更加鲜艳。　　喜凉爽、忌高温，是风信子对温度的基本要求。在8℃～18℃的温度范围内生长良好。在其花期控制过程中，环境温度不宜低于0\"C。 　　对于种球生产来说，在风信子的生长旺盛阶段合理施肥十分重要。但由于通常在其花期控制过程中所使用的主要是商　　在风信子的花朵开放后，应该将其置于无日光直射的明亮之处。保持环境通风。如果有条件将气温降低，则花期可明显延长，风信子的花朵较耐低温，即使放在5\"C的条件下也并无妨碍，与放在15℃的环境相比，其花期可延长数日之久。开花后，可移入室内观赏，每日适当给一定的光照，防止叶片、花茎陡长。　　等花谢后，可以除去残花养球。在日常管理中可以2周左右施一次氮肥（饼肥），促进土壤中的球茎发育，养球的好坏直接影响来年的再次开花。在　　在风信子的常规栽培中，主要有根腐病、花叶病、黄腐病、灰霉病、菌核病、软腐病等的危害，应该加强日常管理，进行相应的防治工作。一般来说，在其花期控制时，如能选用无病种球，并加强管理，则上述病害不会发生。　　风信子开花时很美，但是风信子有毒，如果很喜欢建议放在卧室外养殖。另外，皮肤易过敏的花友建议不要养，因为风信子的花粉容易引起皮肤过敏。家有小孩的，不要让小孩触摸，放到小孩触碰不到的地方。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick79391428055079.jpg', 'http://www.boqii.com/entry/detail/1897.html', '');
INSERT INTO `plant_family` VALUES ('498', '桃美人', 'Pachyphytum ', '桃美人', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2012/0,http://www.boqii.com/entry/photo/2012/5515', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '厚叶草属', '', 'Pachyphytum \'Blue Haze\'', '', '　　 　　桃美人茎短且粗，直立。单株约12 ～ 20片叶，老株群生。叶肉质，互生，排列呈延长的莲座状，呈倒卵形，长2－4厘米，宽、厚各2厘米左右，先端平滑钝圆，有轻微的钝尖（养的好的桃美人几乎看不到叶尖）叶背面圆凸，正面较平，顶端；叶片表面覆盖白粉，衬托叶片的粉红色，看起来植株呈现漂亮的淡紫或淡粉色，非常可爱。花序较矮；花倒钟形，红色，串状排列。可以异花授粉。', '　　桃美人在昼夜', '　　和很多多肉', 'http://img.boqiicdn.com/Data/BK/P/imagick1361441704641.jpg', 'http://www.boqii.com/entry/detail/2012.html', '');
INSERT INTO `plant_family` VALUES ('499', '四季海棠', 'Begonia semperflorens', '四季海棠', '蚬肉秋海棠、玻璃翠、四季秋海棠、瓜子', '不容易死', '南美巴西，北欧的丹麦、瑞典、挪威等，荷兰、英国和法国等。', 'http://www.boqii.com/entry/photo/2238/0,http://www.boqii.com/entry/photo/2238/5289', '', '', '', '', '', '', '', '', '', '　　 　　四季海棠为肉质草本，高15－30厘米；根纤维状；茎直立，肉质，无毛，基部多分枝，多叶。叶卵形或宽卵形，长5－8厘米，基部略偏斜，边缘有锯齿和　　　　　　　　　　　　　　　　　　　　　　　　　　　　　', '　　为多年生常绿草本植物，如果温度适宜，则可四季开花。自然花期则以春夏为盛，花色有红、粉红、白色等，在中国，是非常重要的花坛之一，也有很多花友将四季海棠作为盆栽养护。　　喜温暖，生长最为18～22°。不耐寒，低于10℃：时，越冬温度为5°。因植株柔软多汁，容易受低温的伤害，应在低温时做好保暖防寒的工作。如能保持白天18°、夜间10°以上的温度，则植株可继续开花。畏炎热，32°以上高温时植株生长不良、开花差，并进入半休眠状态。应在气温超过25°时采取遮荫、加强通风和勤喷叶面水等措施来降低环境温度。但对于耐高温和耐强光照射的品种，则不宜遮荫，但需经常喷水。　　喜光，对光照有较强的适应性，开花不受日照长短的影响，但在昼长夜短时生长与开花最好。忌强烈阳光的曝晒，光照过烈时叶片易卷缩，并出现焦斑，5～9月应给予遮荫。但不宜过阴，否则植株生长柔弱、茎干细长、叶色变淡、开花量减少。其他时间则需给予充足的光照，植株在充足的阳光下开花整齐、花色鲜丽、叶色有光泽。　喜稍湿润的土壤环境，不耐干旱，也不耐水湿。浇水要“干湿相间”，保持盆土湿润而不过于干旱、不过湿。过干，叶片会变黄萎蔫；过湿，则易烂根。夏季高温时由于生长受到抑制，所以应适当控制浇水，保持盆土略干的状态，浇水多而盆土过湿易引起落叶烂根。冬季更需控制水分，只要使盆土略湿润即可。　　生长季在天晴干燥时，要经常向枝叶及周围喷水，以提高空气相对湿度。适宜生长空气相对湿度应维持在白天75％以上、夜间89%。以上。　　喜肥。春暖气温升至15℃以上后，由于植株开花量大，且开花不断，会消耗很多的养分，应及时供应肥料，才能保证植株正常的生长与开花。应每10～15天追施1次氮磷钾结合的稀薄肥料，以促使不断地孕蕾与开花。养分不足时叶片会薄而黄，且易产生落叶、落蕾。忌施浓肥，浓肥极易引起肥害，导致叶片枯焦，甚至植株枯死。施肥时的盆土要求偏干，以利植株的吸收。新繁殖的幼株应施以氮肥为主的肥料，以促使枝叶生长，并迅速成形。夏季温度达30°以上、冬季温度低于15°时，应停止施肥。冬季如能维持15°以上的温度，则应继续施肥，可使开花不断。秋末初冬如继续施肥，特别是单纯施用氮肥，会使植株生长过嫩而容易遭受寒害。　　新繁殖的植株在长至10厘米左右时要进行摘心，以促使腋芽萌发新枝，植株及早形成丰满的株形。花后也需进行摘心，以促使分枝。摘心后的半个月，新萌生的枝条又能孕育花蕾并开花。这样不但能控制植株高度，而且可开花不断。春天应结合翻盆，对过高的植株进行重剪，以控制高度并促使分枝。', '　　　\n　1、播种法：\n　　\n2、扦插法：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick88991447925084.jpg', 'http://www.boqii.com/entry/detail/2238.html', '');
INSERT INTO `plant_family` VALUES ('500', '白粉藤', '', '白粉藤', '独脚乌桕、夜牵牛、白面水鸡、青龙跌打、山葫芦、山鸡蛋', '不容易死', '广东、广西、贵州、云南', 'http://www.boqii.com/entry/photo/2273/0,http://www.boqii.com/entry/photo/2273/5252', '　　', '被子植物门', '双子叶植物纲', '鼠李目', '葡萄科', '白粉藤属', '白粉藤', '', '', '　　 　　白粉藤为草质藤本。小枝圆柱形，有纵棱纹，常被白粉，无毛。卷须2叉分枝，相隔2节间断与叶对生。叶心状卵圆形，长5－13厘米，宽4－9厘米，顶端急尖或渐尖，基部心形，边缘每侧有9－12个细锐锯齿，上面绿色，下面浅绿色，两面均无毛；基出脉3－5，中脉有侧脉3－4对，网脉不明显；叶柄长2.5－7厘米，无毛；托叶褐色，膜质，肾形，长5－6厘米，宽2－3厘米，无毛。', '　　我们可能对白粉藤的药用价值比较熟悉，其实白粉藤也可以作为中小盆栽悬吊栽培。白粉藤的叶色浓绿，嫩芽披银白色柔毛，非常适合摆放在书房、客厅等处。那么人工栽培白粉藤应该注意哪些问题呢？', '　　　　白粉藤的繁殖可用嫩枝扦插。插穗选用一年生半木质化的顶梢或侧枝，剪去插条下部2～3枚叶片减少水分蒸发。用等量的草炭土和砂子混合作扦插基质。将基质', 'http://img.boqiicdn.com/Data/BK/P/imagick22231448960884.jpg', 'http://www.boqii.com/entry/detail/2273.html', '');
INSERT INTO `plant_family` VALUES ('501', '蓝石莲', 'Echeveria peacockii ', '皮氏石莲', '', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/2107/0,http://www.boqii.com/entry/photo/2107/5420', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '石莲花属', '皮氏石莲', 'Echeveria peacockii \'desmetiana\'', '', '　　 　　皮氏石莲，多肉', '　　比较特别的是其叶片是非常少见的粉色，在光照不足的情况下就会变成蓝绿色，所以人工栽种蓝石莲需要注意为其提供一个合适的环境，以免蓝石莲因为环境而发生疾病甚至死亡的情况。　　蓝石莲喜温暖、干燥、阳光充足和通风的环境，无明显休眠期。耐干旱，不耐寒，稍耐半阴，忌水湿。夏季高温时植株有短暂的休眠期，植株或完全停滞，此时要防止太阳直射；春、秋季和初夏是植株的主要生长期，可给予充足光照。高温期节制浇水；生长期干透浇透，保持适当干燥，冬季温度低于5℃控制浇水。盆土要求肥沃，并具有良好的排水性。夏季高温休眠期不可施肥，生长期可适当施肥。　　生长在高海拔地区的旁，故不耐积水。喜欢温暖，干燥，阳光充足的气候，适当阴凉也可以（不能忍受强光），最佳生长温度为20－30℃，温度越低肉色越鲜艳，不耐霜冻。2－4月播种，从播种到开花需17－20周，发芽需光。35000粒／克。　　蓝石莲需要接受充足日照叶色才会艳丽，株型才会更紧实美观。日照太少则叶色浅，叶片排列松散，拉长，叶片变薄。蓝石莲是中大型植株，随着生长的状态可以1－3年换盆一次，盆径可以比株径大1～2寸，这样可促进植株成长。介质一定要乾燥后才浇水，可以施用缓效肥。　　生长适温15－25度，冬季不低于5度；配土一般用泥炭＋＋珍珠岩各一份，并添加适量的骨粉，也可用腐叶土3份、河沙3份、园土1份、炉渣1份混合配制；生长期浇水干透浇透，空气干燥时可向植株周围洒水，但叶面，特别是叶丛中心不宜积水，否则会造成烂心，夏季高温要适度遮阴，通风和节水；生长期施肥一般每20天左右一次。', '　　蓝石莲的繁殖一般可以用叶插、扦插及种子繁殖。有的朋友或许会问，蓝石莲开花后会不会死亡，播种繁殖会不会在结籽的时候导致老叶枯萎，其实，蓝石莲不像瓦松属的多肉　　蓝石莲的繁殖一般采用砍头和扦插繁殖，当然也可以播种。砍头全年都可以进行，扦插繁殖的话，叶插与扦插都可以，一般以叶插为主，比较容易成功，此外也可以把侧芽掰下进行扦插。　　蓝石莲种子的繁殖方法：　　蓝石莲由于种子非常的　　另外一个盆器中播种最好要选择相同的', 'http://img.boqiicdn.com/Data/BK/P/imagick61451444641171.jpg', 'http://www.boqii.com/entry/detail/2107.html', '');
INSERT INTO `plant_family` VALUES ('502', '玉扇', 'Haworthia truncata', '玉扇', '截形十二卷', '不容易死', '原产于非洲南部', 'http://www.boqii.com/entry/photo/1982/0,http://www.boqii.com/entry/photo/1982/5545', '　　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '十二卷属', '玉扇', 'Haworthia truncata', '', '　　 　　玉扇植株低矮无茎，叶片肉质直立，往两侧直向伸长，稍向内弯，对生，排列于两方，呈扇形，顶部略凹陷，呈截面状，看起就好像有人用刀子切过一样。表面粗糙，绿色至暗绿褐色，有小疣状突起。在原产地时，叶片会埋于土中，只露出叶片先端，不同品种的叶片截面上，会出现各种不同呈透明状的花纹。花纹大多为白色，绿色的花纹十分珍贵。总状花序，花茎长20～25厘米，花筒状，白色，中肋绿色，长1.5厘米。', '　　玉扇性喜凉爽、充足并且柔和的阳光，由于玉扇在干燥的夏季会进入夏眠状态，所以夏季对于玉扇的养护则需要特别认真。玉扇的栽培并没有我们想象中那么简单，想要养出漂亮的玉扇并不容易。', '　　　\n　一、叶插繁殖：\n　\n　二、根插繁殖：\n　　还有种根插繁殖的方法比较残忍，就是在未翻盆前，抓住玉扇的身体直接扭断所有的根，让根在原盆内发芽。这种方法也要保持土壤干燥，有湿度就可以了，出芽后再浇水。　　\n三、砍头繁殖：\n　　砍头繁殖最好是在玉扇生长的旺盛期进行，这样基座上出芽就快，母头发根也快。在11月－12月之间砍头繁殖比较合适，砍下的母头发根后到来年5－6月玉扇开花还有个缓冲期，对植物杂交授粉繁殖影响也是最小。事先考虑好保留几片叶在基座上，抓住玉扇叶片轻掰玉扇身体见有隙缝露出就可以下刀了，先开条小口子，在轻掰玉扇，会发现玉扇基部的口子会越来越大，此时就用小刀调整割的方向，直到母头和基座分开为止。上杀菌粉，母头吹干2星期后种植在半湿润土壤中即可　　其实有性繁殖才是瓦苇繁殖之中的“如来神掌”。玉扇繁殖的真正的乐趣所在，玉扇异花授粉。不同玉扇杂交过后会出现很多不同形状，不同窗面的玉扇，这就是我们苦苦追求的方向。', 'http://img.boqiicdn.com/Data/BK/P/imagick62631440581354.jpg', 'http://www.boqii.com/entry/detail/1982.html', '');
INSERT INTO `plant_family` VALUES ('503', '一叶兰', 'Common Aspidistra', '一叶兰', '蜘蛛抱蛋', '不容易死', '中国南方各省区、中国海南岛、台湾等', 'http://www.boqii.com/entry/photo/1963/0,http://www.boqii.com/entry/photo/1963/5564', '　', '被子植物门 Magnoliophyta', '单子叶植物纲 Liliopsida', '', '百合科Liliaceae', '抱蛋属Aspidistra Ker－Gawl', '蜘蛛抱蛋', 'Aspidistra Elatior Blume', 'Aspidistra Elatior', '　　 　　一叶兰的根状茎近圆柱形，直径5～10毫米，具节和鳞片。叶单生，彼此相距1～3厘米， 矩圆状披针形、披针形至近椭圆形，长21～46厘米，宽8～11厘米，先端渐尖，基部楔形，边缘多少皱波状，两面绿色，有时稍具黄白色斑点或条纹。', '　　对于空气净化是有一定作用的，特别在新房装修好的时候，在家中摆放一盆一叶兰是可以起到很好的净化空气的作用的，不过由于晚上一叶兰是吸氧的，所以最好不要放在室内。　　一叶兰原产于中国海南岛和台湾。性喜温暖、阴湿，耐贫瘠，不耐寒，喜疏松、肥沃、排水良好的沙质壤土。　　1、土壤。一叶兰对土壤要求不严，耐瘠薄，但以疏松、肥沃的微酸性砂质壤土为好。盆栽时可用腐叶土、泥炭土和园土等量混合作为基质。　　2、水分。季要充分浇水，保持盆土经常保持湿润，并经常向叶面喷水增湿，以利萌芽抽长新叶，秋末后可适当减少浇水量。　　3、光照。可以常年在明亮的室内栽培，但无论在室内或室外，都不能放在直射阳光下；短的阳光暴晒也可能造成叶片灼伤，降低观赏价值。一叶兰极耐阴，即使在阴暗室内也可观赏数月之久，但长期过于阴暗不利于新叶的萌发和生长，所以如摆放在阴暗室内，最好每隔一段时间，将其移到有明亮光线的地方一段时间，以利生长与观赏。尤其在新叶萌发至新叶生长成熟这段时间不能放在过于阴暗处。', '　　　　用分株法繁殖一叶兰，先剪去老根及枯叶，用刀切取根状茎，按每丛4～5叶分成数丛，另行上盆。盆土用园土2份、腐叶土1份、厩肥和砻糠灰各0.5份混均配制，并在盆底垫铺碎瓦片，以利排水。上盆时栽植不要太深，盆土与根茎平齐，浇透水放置通风半阴处，否则叶片易变黄，甚至枯萎。应放置室内通风半阴处。冬季室温不低于5度，放置于南窗阳光充足处。', 'http://img.boqiicdn.com/Data/BK/P/imagick34351440063746.jpg', 'http://www.boqii.com/entry/detail/1963.html', '');
INSERT INTO `plant_family` VALUES ('504', '龟背竹', 'Monstera deliciosa', '', '', '不容易死', '原产于墨西哥热带雨林中，我国引种栽培十分广泛。', 'http://www.boqii.com/entry/photo/1901/0,http://www.boqii.com/entry/photo/1901/5628', '', '', '', '', '', '', '', '', '', '　　 　　龟背竹幼叶呈心形状，无孔，长大后成广卵形，叶脉间有椭圆形的穿孔，叶具长柄，深绿色。佛焰花序，佛焰苞舟形，11月开花，淡黄色。龟背竹又名“蓬莱蕉”、“电线草”，是　　通过查阅资料，我们了解到龟背竹为中国植物图谱数据库收录的　　而且，龟背竹并不在收录的52种促癌植物中，它不会释放有害气体，危害大家健康的。相反，龟背竹是天然的清道夫，可以清除空气中的有害物质，净化空气。有实验表明，龟背竹可以清除空气中百分之八十的有害气体，非常适合刚装修完的家中。　　除此之外，龟背竹还有夜间吸收二氧化碳的奇特本领，龟背竹内含有许多有机酸，这些有机酸能与夜间吸收的二氧化碳产生化学反应，变成另一种有机酸保留下来。到白天，这种变化的有机酸又还原成原来的有机酸，而把二氧化碳分解出来，进行光合作用。龟背竹是不会在夜间和大家争夺氧气的，还会清除人体呼吸释放的二氧化碳，使室内空气保持清新，帮助人们睡眠。 　　1、土壤：龟背竹喜疏松、排水良好的土壤，可用园土、河沙、腐叶土混台配制。　　2、阳光：龟背竹较耐阴，忌烈日，喜散射光，应避免强光直射。阳光过强，叶片会遭灼伤；光线太暗，叶片颜色又会淡化。夏季可将花盆摆在北窗，冬季需充足阳光，宜放朝南的窗台上。　　3、温度：龟背竹喜温暖，生长适温为15－25℃。冬季室内越冬不能低于5℃。　　4、水分：龟背竹喜湿润，盆土保持干而不裂、润而不湿为好。空气湿度以60％为佳。夏季每天应给叶面喷雾和淋水，保持叶色鲜亮。冬季不能给叶面喷水，否则叶面会出现黑色斑点，甚至发黑腐烂。　　5、施肥：4－9月为生长旺盛期，每半个月施1次稀薄液肥。生长期2周左右浇1次二八成或三七成氮素液肥，促使植株健壮。秋后增施磷、钾肥，使茎干粗壮，防止倒伏。　　6、修剪：定型后茎节叶片生长过于稠密、枝蔓生长过长时，　　7、病虫防治：危害龟背竹的主要病虫害是介壳虫和灰斑病，可用40％氧化乐果乳剂1000倍液喷杀，灰斑病时要加强植株养护，及时除虫，剪除部分病叶，用70％托布津1000倍液或0.5％等量式波尔多液喷洒。　　龟背竹虽然有一定毒性，但是龟背竹的毒性对空气不会造成污染，所以还是比较适合饲养在室内的观叶植物。但是小编要提醒各位朋友们，有小孩和宠物的家庭一定要注意不要误食了，不然会引起中毒的情况。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick25931428055715.jpg', 'http://www.boqii.com/entry/detail/1901.html', '');
INSERT INTO `plant_family` VALUES ('505', '玉露', 'Haworthia cooperi var. pilifera f. truncata', '玉露', '', '不容易死', '', 'http://www.boqii.com/entry/photo/1894/0,http://www.boqii.com/entry/photo/1894/5635', '', '', '', '', '', '', '', '', '', '　　玉露为百合科十二卷属多肉植物中的“软叶系”品种，目前，玉露的变种及杂交出的品种有很多，由于玉露的植株小巧，叶色晶莹剔透，所以是近年来人气较旺的多肉品种之一。想要养出健康漂亮的玉露一定要先了解玉露的生长习性，玉露和其他的多肉植物不一样，对于浇水量是可以比其他多肉多一点的。 　　玉露喜凉爽的半阴环境，主要生长期在较为凉爽的春秋季节，要求有一定的空气湿度。耐干旱，不耐寒，忌高温潮湿和烈日暴晒，怕阴蔽，怕土壤积水，生产中一般采用温室内盆栽或苗床地栽。 水晶殿 　　由于目前玉露的品种比较混乱，有些品种并不是玉露，但是外形却和玉露非常相似，如水晶殿，所以一定要注意你的玉露品种，这样才能正确的饲养你的玉露。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick3461428054611.jpg', 'http://www.boqii.com/entry/detail/1894.html', '');
INSERT INTO `plant_family` VALUES ('506', '生石花', 'lithops', '生石花', '石头花、石头草、小牛蹄', '不容易死', '南非，纳米比亚，博兹瓦纳，安哥拉', 'http://www.boqii.com/entry/photo/1893/0,http://www.boqii.com/entry/photo/1893/5636', '', '', '', '', '', '', '', '', '', '　　一些新手朋友可能或多或少都听说过生石花是比较好饲养的，其实这是个误区，在中国的部分 　　南非专家建议栽培生石花最好不用含腐殃质很多的土，也不用草炭，如果取材方便，可以用完全风化了的花岗石碎屑。日本栽培者喜欢用桐生砂作为生石花的介质。桐生砂完全颗粒状，排水好，含有机质不多，栽培生石花很安全。　　有些爱好者栽培生石花相对比较大胆，有人使用优质草炭，也有人使用山泥，栽培部分强健种类时甚至在介质中混入一些园土。以下是上海地区较为常用的儿种配方：　　配方一：50％硅石（石英砂，可以理解为河沙）、30％优质草炭，20％谷壳炭（只适用于较强健的种类）。　　配方二：50％赤玉土、10％珍珠岩、20％谷壳炭、20％优质草炭。　　配方三：40％硅石、40％鹿沼土、20％谷壳炭。　　配方四：50％桐生砂、40％赤玉土、10％谷壳炭。　　此外，小的轻石、兰石也要准备一点，可放在盆底作为排水物，也可铺在土面上。要　　Cole夫妇（国外生石花权威专家，科尔编号的制定者）建议种植生石花的盆盆的深度不小于125 mm，盆的直径不小于100 mm。因为生石花的根有时可达75 mm，有的种类叶长可达50 mm。这样的大盆在大苗定植时是合适的，但小苗则可以用浅的育苗盆。　　定植用的花盆可以用一般塑料盆。有的群生植株也可以用紫砂盆。盆底排水物（浮石、兰石、陶粒）垫的高度为盆高的五分之一，日本专家建议在排水层中混入腐熟的干的有机肥，不方便时也可以用少许缓释颗粒肥代替。种植用的土不要分层，粗、中、细可以混在一起。上盆时，盆土将生石花根部的吸收部分（即须根部分 ）遮住就可以。盆土表面可铺比重较大的小石子（直径3mm～6mm）。从生石花对生叶下面的一段粗的直根到对生叶的一半，最好都被这种石头包围。小苗移植时可用扁的育苗盆，底部铺一薄层排水物（轻石、兰石、日向土），排水物上面再铺上配好的介质。　　种植生石花的介质颗粒大小视生石花苗的大小而定。小苗的介质要细并铺得薄，移植后不用像定植上盆那样在介质表而铺一层石头。一般移植时介质应有一定的潮润。移苗完毕后随即喷一次杀菌剂，2－3日后可泅水（浸润）让苗吸足水分。生石花的小苗在一年之内没有太明显的休眠期，因此只要不是黄梅和酷暑期都可以移植。而定植上盆的时机，Cole夫妇建议在夏季（我们大多数喜欢在秋季），他们认为秋季移植可能根系未及长好就进入休眠。对新生叶不利。因此，如果夏季栽培环境不太酷热，可以一试。 　　许多人对生石花的浇水过于谨慎，有人一个　　Cole夫妇认为生石花不喜欢氮肥过多，他们建议肥料中的氮、磷、钾比例为6：20：30。　　种植生石花的环境的温度应尽量控制在较温和的范围内，即夏季不要太热、冬季不要太冷。在此前提下昼夜保持较大的　　生石花的外形非常特殊，在饲养到一定时间后还会开出不一样的花，是很多植物爱好者们非常喜欢的品种，但是养到生石花开花是非常不容易的，一定要注意日常的饲养方法才能让你的生石花长的健康并且开出漂亮的花。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick49321428054281.jpg', 'http://www.boqii.com/entry/detail/1893.html', '');
INSERT INTO `plant_family` VALUES ('507', '君子兰', 'Bush lily', '君子兰', '大花君子兰、大叶石蒜、剑叶石蒜、达木兰', '不容易死', '', 'http://www.boqii.com/entry/photo/1985/0,http://www.boqii.com/entry/photo/1985/5542', '', '', '', '', '', '', '', '', '', '　　君子兰如果养的好的话， 　　君子兰根肉质纤维状，为乳白色，十分粗壮。根系粗大，很有肉质感。君子兰茎基部宿存的叶基部扩大互抱成假鳞茎状。叶片从根部短缩的茎上呈二列叠出，排列整齐，宽阔呈带形，顶端圆润，质地硬而厚实，并有光泽及脉纹。基生叶质厚，叶形似剑，叶片革质，深绿色，具光泽，带状，长30－50厘米，最长可达85厘米，宽3－5厘米，下部渐狭，互生排列，全缘。　　　　　　　　　　　　　　　　　', '　　君子兰原产于南非的山林地带，所以性喜温暖、怕寒、耐阴，栽培难度可以说并不高。但是想要养出健康长寿的君子兰却并不是那么简单的。君子兰在栽培过程中往往会出现很多，大部分都是由于栽培不当导致的，小编就为你介绍一下，如何科学正确的养好君子兰。　（盆土一般按如下比例配制）森林腐殖土：河沙：煤渣7：2：1　　君子兰最适宜森林腐殖土，这种土肥沃，透气利水。腐殖土可以到市场上买，也可以自己汇制，收集各种，嫩草烂菜叶等再掺合一部分鸡、鸭、鹅、猪、羊、牛、马粪掩埋在地下汇制1—2年充分腐熟，取出后在强烈阳光下摊薄曝晒或者经过0℃的冷处理，充分杀虫灭菌然后揉碎过筛搅拌均匀，即可装袋使用。（也可用福尔马林灭菌）　君子兰施肥原则是，宁稀不浓，肥料浓度大会烧伤根系导致叶片枯焦。一般在期育蕾期及花后应及时追施腐熟得饼肥，或杂鱼烂虾汇制得液肥水为好，浓度为15％—20％。7—10天一次（追施液肥水时应顺盆边浇，不要沾在叶子上或鳞茎里。沾上，应及时用清水冲掉）。君子兰春秋两季是生长旺季可以施肥，夏冬为休眠期禁肥（忌浓，生肥）。　　君子兰浇水不能过勤过多，一般是干透或半干时浇。春秋是君子兰生长的旺季要适时浇水，原则“浇透不浇漏”夏季高温，冬季寒冷君子兰基本处于休眠状态，因此要少浇水，以防烂根。空气干燥或温度过高应适当叶面喷水或洒水保持湿度和降温（注意：河水、雨雪水、井水为好，自来水不能直接浇应放1—2天氧气挥发了。冬季中午浇夏季早晚浇。春秋下午浇。总之水温和盆土温度不能相差过大）　君子兰属半荫植物，无光不行。强光也不行。特别是夏天，最怕强光。否则叶生容易灼伤。冬季阳光较弱，可多见阳光。君子兰既怕热又怕冷，（超过35℃，低于8℃都会停止生长）因此君子兰适宜散射光和15—25℃温度。所以在室外种，夏天要注意遮阳，冬季要注意保暖。另外为了君子兰两列叶子长的均匀，对称，要注意转盆，一般每隔8—10天转一次盆，转180°。　　养君子兰要经常换盆，一般每隔1—2年换一次，在春秋生长旺季进行，君子兰用盆宜小不宜大，否则容易烂根，一般2—3叶片用口径10公分的盆，4—5叶片用13公分的盆，6—8叶片用20公分的盆开花用35公分的盆。　①叶斑病，初期病状为褐色小斑点，后期病斑干枯。中心出现黑色颗粒状物。这种病多发于高温干燥条件下。措施，可喷洒50％的多菌灵，洒水降温，保持湿度。②，多发于下层叶子上。初期像油点。淡黄色，透光，后逐渐变褐色软腐或干枯，如有发生，可加强通风，土壤，也可用青霉素、土霉素等稀释5000倍喷洒叶片或涂抹病斑均有一定效果。', '　　由于　　1、新的播种法。在播种盆内先放入1／3腐熟马粪土，上铺2／3干净的河沙，然后将已用30～40℃的恒温水烫漂12～24小时的种子置于上面，再覆盖一薄层经过　　播种后将盆放在有底温的或炕或电褥子上，底温保持在20～30℃，过高或过低都不利于种子的萌发。用这种方法育苗发芽快，一般3天左右便可长出胚根，而常规繁殖则需25～30天。　　2、组织培养法。该法是以乳熟期的种子为材料，经过常规的消毒灭菌，在一定的温度和光照条件下，', 'http://img.boqiicdn.com/Data/BK/P/imagick25891440582262.jpg', 'http://www.boqii.com/entry/detail/1985.html', '');
INSERT INTO `plant_family` VALUES ('508', '姬玉露', '', '姬玉露', '', '不容易死', '原产地位于南非', 'http://www.boqii.com/entry/photo/2084/0,http://www.boqii.com/entry/photo/2084/5443', '　', '被子植物门', '单子叶植物纲', '', '独尾草科', '', '姬玉露', '', '', '　　姬 　　姬玉露喜凉爽的半阴环境，增加空气湿度后非常透亮。迷你可爱，适合迷你组合栽培。花盆尽量小些比较好。主要', '　　正如姬玉露的名字一样，姬玉露小巧、通透、色泽淡雅，是百合科十二卷属中非常可爱的多肉。但是，很多人都会觉得姬玉露比较难养，特别容易烂根，那么如何才能养好姬玉露呢？　　　先在盆底垫上较大颗粒的兰石，放入姬玉露使根系舒展，一手扶住玉露一手沿四壁倒入拌有少量泥炭的颗粒土至盆的二分之一，姬玉露喜欢疏松肥沃，排水透气性良好，含有石灰质，并有较粗颗粒度的沙质土壤中生长。常用腐叶土2份、粗沙或3份的混合土栽种，并掺入少量骨粉等，还可用赤玉土、兰石、植金石等人工合成材料栽种，但要加入适量的泥炭土，以增加土壤的有机质含量，最后倒入颗粒土至盆沿0.5厘米的地方结束。　　　姬玉露生长期浇水原则是不干不浇，浇则浇透，阳光苗木网提示避免积水，更不能雨淋，尤其是不能长期雨淋，以避免烂根。但也不宜长期干旱，否则植株虽然不会死亡，但叶片干瘪，叶色黯淡。空气干燥时可经常向植株及周围环境喷水，在生长季节可用剪去上半部的透明无色饮料瓶将植株罩起来，使其在空气湿润的小环境中生长，可使叶片饱满窗的透明度更高。但夏季高温季节一定要把饮料瓶去掉，以免因闷热潮湿导致植株死亡。　　　适宜姬玉露生长的温度是摄氏15到25度、湿度在70－90之间。以上海为例，春、秋二季温度适宜，玉露生长迅速，往往体内汁液来不及充盈，象个没充足气的气球，窗面如披白粉光泽度略低。夏季温度高，玉露停止生长进入休眠，窗面发白透明度下降。冬季室内温度应能保持在5度以上，生长缓慢呈现半休眠状态，体内汁液充盈，象个充足气的气球，窗面光泽度最高、透明度也最佳。　　　对光照较为敏感，若光照过强，叶片生长不良，呈浅红褐色，有时强烈的直射光还会灼伤叶片，留下难看的斑痕。而栽培场所过于阴蔽，又会造成株型松散，不紧凑，叶片瘦长，窗的透明度差，这样的植株很难恢复原来的品相，只能等这批徒长的叶片慢慢脱落，再长出健壮的新叶。而在半阴处生长的植株，叶片肥厚饱满，透明度高，因此，5～9月可加一层遮阳网，10月至翌年4月要去掉遮阳网，给予全光照。　　　主要病害有烂根病，是因栽培材料的通透性不好、土壤长期积水而造成的。因此应改善栽培环境，选用疏松透气性好的土壤栽种，不要长期积水。此外，植株中心若长期积水会造成烂心。如果长期不换土，会因根系衰老中空而造成植株生理性病害，使植株停止生长，叶片干瘪，不饱满，遇到这种情况应及时换土。虫害有根粉蚧，可在种植前对土壤进行高温处理，并在土壤中加入杀虫药物。　　　由于姬玉露的根系会分泌酸性物质，造成土壤酸化，使根部老化中空，可每年春季或秋季换盆一次。阳光苗木网提示姬玉露生长期如果发现植株生长停滞，叶片干瘪，很可能是根系损坏，应及时翻盆整理根系。翻盆时将老化中空的根系剪掉，过长的根系剪短，保留粗壮的白色新根，再用新的栽种。新栽的植株可勤喷水，但要少浇水，这样可使植株尽快恢复生长。由于玉露的花朵观赏价值不高，若不留种，可将花葶从基部拔掉，以免消耗过多养分。需注意的是花葶不要用剪刀剪，要用手左右晃着拔掉，这样可以避免残花梗留在叶片之间，对以后新叶的生长造成不利影响。', '　　很多多肉爱好者都非常喜欢姬玉露的外形，由于姬玉露上半段呈透明或半透明状，所以也被称为“有窗植物”。很多朋友或许对于姬玉露的繁殖方法并不清楚，就让小编带你来了解一下。　\n　1、分株\n　　可结合换盆进行，也可在生长季节挖取玉露母株旁边的幼株，有根或无根都能成活，有根可直接栽种，无根的苗要晾1～2天，等伤口干燥后再种植，新栽的植株浇水不宜过多，以免引起腐烂，等长出新根后再进行正常管理。　\n　2、扦插\n　　姬玉露在植株下部的叶腋会长出幼芽，对于不易生幼芽的　\n　3、叶插\n　　可选择健壮充实的肉质叶，姬玉露生长期在　\n　4、播种\n　　只有通过人工授粉，姬玉露才能结籽。一般在开花时选择天气晴朗的上午进行，方法是选择两株同时开花的玉露，也可用同为十二卷属的寿、万象等', 'http://img.boqiicdn.com/Data/BK/P/imagick62681443518582.jpg', 'http://www.boqii.com/entry/detail/2084.html', '');
INSERT INTO `plant_family` VALUES ('509', '澳洲杉', 'Araucaria heterophyll', '', '', '不容易死', '大洋洲诺福克岛以及澳大利亚东北部', 'http://www.boqii.com/entry/photo/1904/0,http://www.boqii.com/entry/photo/1904/5625', '', '', '', '', '', '', '', '', '', '　　澳洲杉是世界上三大观赏树木之一，但是现在很多人都将澳洲杉修剪后做盆栽饲养。由于澳洲杉的生命力十分顽强，不怕强光，也能承受低光，并且四季常绿，是观赏价值非常高的 　　在养护过程中，澳洲杉多久浇一次水，这要根据盆土湿度来决定了。在夏季，一般情况下，一个礼拜浇水两次就足够了。在冬天对于浇水的控制，可以比夏季减少一次。　　澳洲杉盆景在春到秋季间，应多浇水，但忌盆内积水。高温干燥时，要对盆株及附近的地面喷水，以降温增湿。浇水要及时，不要待土壤干燥后再浇水。自秋末以后，逐渐减少浇水，以增强其抗寒力。　　夏季在盆土半干时浇，浇水的时候沿盆边浇一圈即可。如果天气很干燥的时候，要在澳洲杉盆景的周围喷水，作用是增加空气的湿润度，以给其创造一个湿润的适宜环境。　　1、夏、秋季为　　2、生长过程中，为避免主干向一面倾斜，宜半月转盆一次，让植株均匀受光。此外，幼树树干脆弱，容易弯曲变形，宜从幼株时就立以支柱以固定主干。为防止植株长得过高，应每隔2－3年在春暖后换盆一次。平时要注意保护好侧枝，以免被损害而影响株形。 　　3、澳洲杉在正常情况下，不必修剪枝条，让其自然生长。生长适温为10～25℃，越冬温度为5℃以上。越冬季节，可给予一定的光照，盆土也不可过干，晴朗天气还应喷水增加湿度。　　4、土壤：澳洲杉适合于排水良好富含腐殖质的微酸性砂质壤土，盆栽时，以园土、腐叶土、泥炭苔混合配制而成的基质为好。盆栽多用小苗，并应根据苗的大小选择相宜的花盆。　　5、光照：澳洲杉　　6、温度：生长季节长，除夏季温度超过32℃时，澳洲杉整年都能生长。　　7、施肥：生长季节应每隔2周追施一次　　8、虫病害：澳洲杉病虫害极少，在室内养护时，多见介壳虫危害，可喷施杀扑磷、毒死蜱·机乳油、国光蚧必死等　　澳洲杉的观赏价值是比较高的，制作成盆栽放在室内饲养的话，可以为室内环境增添生机。虽然澳洲杉的生命力十分顽强，但是如果不注意饲养的话，就会影响澳洲杉的观赏价值。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick94471428056030.jpg', 'http://www.boqii.com/entry/detail/1904.html', '');
INSERT INTO `plant_family` VALUES ('510', '建兰', 'Cymbidium ensifolium （L.） Sw.', '建兰', '四季兰、雄兰、骏河兰、剑蕙', '不容易死', '', 'http://www.boqii.com/entry/photo/2029/0,http://www.boqii.com/entry/photo/2029/5498', '　　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '兰属', '建兰', 'Cymbidium ensifolium （L.） Sw.', '', '　　 　　建兰是地生植物；假鳞茎卵球形，长1.5－2.5厘米，宽1－1.5厘米，包藏于叶基之内。叶2－4（－6）枚，带形，有光泽，长30－60厘米，宽1－1.5（－2.5）厘米，前部边缘有时有细齿，关节位于距基部2－4厘米处。', '　　建兰为地生，也可盆栽。建兰的栽培管理难度并不高，但是由于现在建兰的普及率不高，所以对于建兰栽培养护的介绍也不多，小编就为你整理了关于建兰的养护管理的相关资料，有需要的朋友可以一起了解。　基质的作用在于固定植株、涵养水分，肥分的含量则不重要。选择基质必须先了解其特性。煅烧过的泥塘土、珍珠石、火山土都非常适宜作其介质，使用前先充分浸湿，让它充分吸水效果更佳。稻壳、花生壳、树皮等有机物也可当作介质使用，因其含有肥分，必须和其他无机物混合使用，但比率不可太高，一般不可超过30％，碳化处理后效果较为理想。河床里的细石、硬土块或砂石厂的碎石也是非常理想的介质，不但排水良好，含水性高，价格又便宜，但缺点是太重，一般都是和有机介质混合使用。　　兰花栽植可分为庭院栽植和田地大面积栽植。一般家庭养兰可选用阳台或天台，也可以在窗台搭建小棚，以质地粗糙、无上轴、边底多孔、有盆脚的兰盆栽兰较好。　　建兰原始生长环境为向东或向南接近山顶之原始丛林且有少许阳光之处，夏季有丰沛的雨量，干燥的冬季亦有晨昏雾露供应其生长所需，若以遮光率计算，用80％塑胶网遮阴即可达到相同的效果。由于其营养生长需要高温，生殖生长则靠日夜温差，生长温度以15～30℃最为理想。　　建兰所需的养分和其他植物相同，除需光合作用所需碳水化合物外，氮、磷、钾、硫、镁、钙及其他微量元素都不可或缺。建兰繁殖率强，开花率高，极适合栽培，在无遮雨设施的情况下肥料流失较严重，在基肥方面宜用长效固体肥料，追肥适用速效性液体肥。　　速效性有机液肥，即目前最物科技之糖醋液及微生物有机液肥，使用上极为方便，直接用水稀释喷洒，而且还可抑制病虫害，速效性化学肥，如花宝、百得肥、益肥丹、尿素之类。液体肥料使用方法，最好选在清晨进行，因为液体肥料多数为速效性肥，无光合作用下不为植物吸收利用。施肥之前不要先浇水，否则流失者多于吸收者。无论施什么肥，均应施在盆边，切不能施在兰头或兰头附近，以免灼伤演化成。万一不慎肥料落在兰头上，也应及时用清水冲去。　　浇水以雨水和自来水为佳，夏秋季节以早晚为好，冬春季节以中午适宜，生长旺季可适当多浇点水，冬春浇水宜少，以盆土湿润稍干为宜，切忌浇半截水。浇水的方法，不仅盆底要出水，介质更需要完全湿透。干湿不均易发霉而致根腐。浇水次数，视盆大小、介质保水性、湿度高低、光照强弱、温度的高低及通风的情况来斟酌。', '　　建兰又称雄兰、骏河兰、剑蕙等，是地生植物，现在也常被人们盆栽，经过人们不断的栽培，建兰的　　1、上芽早、　　2、长势健、分蘖强，可平价出售。建兰长势强健，只要环境。适宜，肥水充沛，一般都是3～4枚叶的壮株，并具硕大的假鳞茎。所以，上年的新株一般都能抽发2～3个新株、还相继开l～2葶花，虽多时一母株能发5～6苗草；为其他兰种所罕见。分蘖力强、繁殖系数大，本来是促发展的好事，可因发展快，普及不够，往往带来兰花滞销、积压、跌价的情况，甚至出现毁兰的副作用。对此，笔者以为除宣传促销外，应平价出售，以利于兰业的昌盛。　　3、适见阳，略偏干，求多花。建兰开花有自己的独特性，即在长日照条件下盈蕾并开花。花芽分化宜“阳而干”，花芽出土后无　　4、冬保暖，夏遮凉，保安全。怕冻是建兰的习性之一，这一点仅次于墨兰，远不如春蕙。若在露地莳养无保暖设施，其受冻的概率较大。一般通－2℃即要受冻。所以养建兰冬季应在室内或在大棚中保暖越冬，气温不能低于0℃。夏日太烈时应稍加遮阳，避免直射光（尤其是中午），即使仅l／3至半幅叶子灼伤了，也会影响其生长和开花。除此两项外其他管理措施如土、肥、水、药等粗放一些亦无妨。保安全至关生死存亡，故不能不提。', 'http://img.boqiicdn.com/Data/BK/P/imagick52821441964775.jpg', 'http://www.boqii.com/entry/detail/2029.html', '');
INSERT INTO `plant_family` VALUES ('511', '姜花', 'Hedychium coronarium', '姜花', '蝴蝶姜、穗花山奈、蝴蝶花、香雪花、夜寒苏、姜兰花、姜黄', '不容易死', '中国、印度、越南、马来西亚至澳大利亚。', 'http://www.boqii.com/entry/photo/2159/0,http://www.boqii.com/entry/photo/2159/5368', '　', '被子植物门', '单子叶植物纲', '芭蕉目', '姜科', '姜花属', '', 'Hedychium coronarium Koen。', 'Hedychium coronarium', '　　 　　姜花茎高1－2米。叶片长圆状披针形或披针形，长20－40厘米，宽4.5－8厘米，顶端长渐尖，基部急尖，叶面光滑，叶背被短柔毛；无柄；叶舌薄膜质，长2－3厘米。穗状花序顶生，椭圆形，长10－20厘米，宽4－8厘米；苞片呈覆瓦状排列，卵圆形，长4.5－5厘米，宽2.5－4厘米，每一苞片内有花2－3朵；花芬芳，白色，花萼管长约4厘米，顶端一侧开裂；花冠管纤细，长8厘米，裂片披针形，长约5厘米，后方的1枚呈兜状，顶端具小尖头；侧生退化雄蕊长圆状披针形，长约5厘米；唇瓣倒心形，长和宽约6厘米，白色，基部稍黄，顶端2裂；花丝长约3厘米，花药室长1.5厘米；子房被绢毛。', '　　', '　　　　姜花分有性繁殖和无性繁殖。姜花采用分株繁殖法繁殖速度也快。室外可以　　金姜花对土壤适应性强，栽培土质以肥沃疏松、排水良好之壤土或砂质壤土最为适宜，但土壤应经常保持湿润或靠近水源，则', 'http://img.boqiicdn.com/Data/BK/P/imagick98821446087002.jpg', 'http://www.boqii.com/entry/detail/2159.html', '');
INSERT INTO `plant_family` VALUES ('512', '琉璃苣', 'Borage', '琉璃苣', '星星草', '不容易死', '原产东地中海地区（欧洲与非洲北部地区），现欧洲和北美广泛栽培', 'http://www.boqii.com/entry/photo/2155/0,http://www.boqii.com/entry/photo/2155/5372', '　', '', '', '', '紫草科', '琉璃苣属', '琉璃苣', 'Borago officinalis', '', '　　 　　琉璃苣为一年生草本植物，株高可达120厘米。叶互生粗糙如黄瓜叶，有柄。花期7月，花蓝色，成疏散、有叶的聚伞花序，具长柄。小坚果，平滑或有乳头状突起。', '　　原产于地中海沿岸及小亚细亚，现在在欧洲和北美被广泛栽培，花期为7月。除了用来观赏，琉璃苣还常被人食用，不但可以做蜜源，其叶还能用作蔬菜及调味。　　琉璃苣喜温植物，耐高温多雨，也耐干旱，不耐寒，要求不太贫瘠的土壤。习性是喜肥沃，微碱性土壤。琉璃苣原产东地中海地区，现欧洲和北美广泛栽培，产地分布在欧洲与非洲北部地区。　　琉璃苣苗期进行除草、松土，直播苗于3片真叶弱苗，多余苗，每穴留苗1～2株，叶片生长期保持田间湿润，开花后减少浇水，一般无病虫，不使用农药。', '　　很多朋友对琉璃苣的认识是因为电视剧《爱上琉璃苣女孩》，其实，这种花现在在欧洲和北美被广泛栽培，并且还用作蔬菜及调味料，是一种经济价值比较高的植物。那么琉璃苣又是怎样进行繁殖的呢？　　琉璃苣的栽培可直播或育苗移植。露地栽培一般宜春季播种，保护地栽培可根据需要全年进行。种子为小坚果，种皮较硬，播种前宜用温水浸泡1～2天，每天　　1、定植：育苗移植在3～5片真叶时定植，株距20～30cm，行距30～40cm，种植后浇透水。　　2、田间管理：苗期进行除草、松土，直播苗于3片真叶', 'http://img.boqiicdn.com/Data/BK/P/imagick60931445938977.jpg', 'http://www.boqii.com/entry/detail/2155.html', '');
INSERT INTO `plant_family` VALUES ('513', '薄雪火绒草', 'Leontopodium japonicum', '薄雪火绒草', '薄雪草、火艾、小毛香，小白头翁', '不容易死', '', 'http://www.boqii.com/entry/photo/2291/0,http://www.boqii.com/entry/photo/2291/5233', '', '被子植物门', '双子叶植物纲', '菊目', '菊科（COMPOSITAE）', '火绒草属', '', 'Leontopodium japonicum', '', '　　火绒草一般指 　　薄雪火绒草为多年生草本。根状茎分枝稍长，有数个簇生的花茎和幼茎。茎直立，高10－50厘米，有时达80厘米，不分枝或有伞房状花序枝，稀有长分枝或基部有分枝，基部稍木质，上部被白色薄茸毛，下部不久', '　　为多年生草本，非常适合园栽种或盆栽观赏。薄雪火绒草是一种珍贵的，集观花、观叶于一体，是藏族古老文化中神圣之花。　　薄雪火绒草常在沟边，沟边草丛，林中，路边，山顶草丛，山坡，山坡草丛中，山坡灌丛，山坡林缘，山坡林中。　　薄雪火绒草适宜生长在肥沃疏松的腐叶土壤中，所以盆土要注意选择腐叶沃土。播种出苗后需间苗，具3片真叶时即可移盆栽。生长期盆土不宜过湿。　　每月施肥一次，注意肥液不能沾污叶片。冬季盆土保持稍干燥为好。', '　　　\n　分株繁殖：\n　\n　播种繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick26951449222780.jpg', 'http://www.boqii.com/entry/detail/2291.html', '');
INSERT INTO `plant_family` VALUES ('514', '火烧花', 'Mayodendron igneum', '火烧花', '缅木、火花树、炮仗花', '不容易死', '中国台湾、广东、广西、云南南部、越南、老挝、缅甸、印度', 'http://www.boqii.com/entry/photo/2401/0,http://www.boqii.com/entry/photo/2401/5014', '植物　　', '被子植物门', '双子叶植物纲', '管状花目', '紫葳科', '火烧花属', '火烧花', 'Mayodendron igneum', '', '　　 　　火烧花为常绿乔木，高可达15米，胸径15-20厘米；树皮光滑，嫩枝具长椭圆形白色皮孔。大型奇数2回羽状复叶，长达60厘米，中轴圆柱形，有沟纹；小叶卵形至卵状披针形，长8-12厘米，宽2.5-4厘米，顶端长渐尖，基部阔楔形，偏斜，全缘，两面无毛，侧脉5-6对；侧生小叶柄长5毫米，顶生小叶柄长达3厘米。', '　　原产于热带亚热带地区，耐干热和半荫，但是不耐寒冷，所以人工栽培火烧花需要注意为其布置合适的栽培环境。火烧花为常绿乔木，现在常被用于园林绿化，是优良的园林树种。　　火烧花树冠庞大，枝叶含水量多，根系较浅且较少，头重脚轻，极易遭受风害，种植时应适当深植，并踩实，以后及时培土、修枝，确保树形庄重美丽。在庭园、草坪、公园等地孤植火焰树时，应将分枝点定在1.5m左右，并通过修剪，使树冠呈球形、伞形等形状发展。栽植后要加强抚育。头3年，每年砍杂、除草、松土、扩穴、施肥2～3次；4年后，每年抚育1～2次。　　火烧花栽培以肥沃和排水良好的沙质壤土或壤土为宜。定植时施足基肥，在高温及干旱期就注意给幼树补充水分。火焰树对需求不高，但在发育时也需适当补充肥料，以复合肥及有机肥为主。', '　　　　火烧花由于其多季开花，可以多季采种，因而播种繁殖是繁殖种苗的主要方法。其蒴果成熟时，果皮由青色转为黑褐色，此时，采下果实放在无风处晾干或晒干，裂後轻轻敲出种子，在适宜　　火烧花的扦插成活率低，采用营养繁殖时可用嫁接、高空压条等方法提高成活率并进行矮化然後用于盆栽。采用营养繁殖获得的植株，一般1至2年即可开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick39421452156183.jpg', 'http://www.boqii.com/entry/detail/2401.html', '');
INSERT INTO `plant_family` VALUES ('515', '月宫殿', '', '月宫殿', '红花月宫殿', '不容易死', '', 'http://www.boqii.com/entry/photo/2395/0,http://www.boqii.com/entry/photo/2395/5020', '', '', '', '', '', '', '', '', '', '　　 ', '　　月宫殿为科多年生常绿肉质，原产于墨西哥。和很多一样，月宫殿的栽培难度并不高，但是需要注意不能过多的浇水，以免引起月宫殿烂根。　　月宫殿喜温暖干燥和阳光充足环境。不耐寒，耐半阴，怕烈暴晒。宜疏松、肥沃带微酸性的沙壤土。冬季温度不低于5℃。　　月宫殿播种苗较困难，严格控制浇水。夏季生长期保持盆土湿润，冬季盆土稍有潮气即行，过湿易发害。生长过程中，每半月施肥1次。嫁接苗和成年植株管理比较简单，生长期经常浇水，冬季花期需遮阴，每年3－4月换盆。3－4年的母株需更新。', '　　　　月宫殿时常采用播种和嫁接的方式进行繁殖，播种在4~5月比较适宜，一般在室内的盆栽里进行播种，播后后大概10天就会发芽，月宫殿的幼苗十分的稚嫩，盆土切忌时而干时而湿，不能进行强光直射，最好放在遮阴处，月宫殿的实生苗一般在3~4年才会开花，嫁接则以6~9个月比较好，接穗常用一年生的月宫殿实生苗或从母株上割取子球进行嫁接。', 'http://img.boqiicdn.com/Data/BK/P/imagick83401452070962.jpg', 'http://www.boqii.com/entry/detail/2395.html', '');
INSERT INTO `plant_family` VALUES ('516', '大花金鸡菊', 'Coreopsis grandiflora Hogg.', '大花金鸡菊', '剑叶波斯菊', '不容易死', '', 'http://www.boqii.com/entry/photo/2239/0,http://www.boqii.com/entry/photo/2239/5288', '　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '金鸡菊属', '大花金鸡菊', 'Coreopsis grandiflora Hogg.', 'Coreopsis grandiflora', '　　大花 　　大花金鸡菊为多年生草本，高20－100厘米。茎直立，下部常有稀疏的糙毛，上部有分枝。叶对生；基部叶有长柄、披针形或匙形；下部叶羽状全裂，裂片长圆形；中部及上部叶3－5深裂，裂片线形或披针形，中裂片较大，两面及边缘有细毛。头状花序单生于枝端，径4－5厘米，具长花序梗。总苞片外层较短，披针形，长6－8毫米，顶端尖，有缘毛；内层卵形或卵状披针形，长10－13毫米；托片线状钻形。舌状花6－10个，舌片宽大，黄色，长1.5－2.5厘米；管状花长5毫米，两性。瘦果广椭圆形或近圆形，长2.5－3毫米，边缘具膜质宽翅，顶端具2短鳞片。花期5－9月。', '　　大花)为菊科多年生宿根草本，花期为6－9月，由于其较耐寒并且耐旱性非常强，所以在我国被广泛栽培。人工栽培的难度并不高，只要根据其习性进行环境布置，大花金鸡菊都能良好。　　大花金鸡菊原产美国南部。喜温暖、湿润和阳光充足环境，较耐寒，耐旱性极强，对土壤要求不严，耐清薄土壤，但在疏松、中等肥沃和排水良好的壤土中生长良好。有自播繁衍能力。栽培比较简单，要求肥水适当，否则易影响孕蕾开花，因此花期应停止施肥，防止枝叶徒长。花后应及时剪去花梗，以利基部萌发新苗，一般植株在栽植5一6年后进行更新。花期停止施肥，防止枝叶徒长而影响开花；花后及时剪去花梗，以利萌发新株。', '　　大花　　大花金鸡菊对土壤要求不高，耐寒、耐旱，发芽　　大花金鸡菊的播种繁殖一般于春季进行播种，播后4个月即可开花。露地种植常自播繁衍。另外也可在秋季进行分株繁硝。选择', 'http://img.boqiicdn.com/Data/BK/P/imagick45131447925692.jpg', 'http://www.boqii.com/entry/detail/2239.html', '');
INSERT INTO `plant_family` VALUES ('517', '紫牡丹', 'HOUSELEEK', '大红卷绢', '蜘蛛巢万代草', '500年', '中南欧、北非高加索和小亚细亚', 'http://www.boqii.com/entry/photo/2487/0,http://www.boqii.com/entry/photo/2487/4929', '', '', '', '', '', '长生草', '', '', '', '　　 　　紫牡丹是比较耐寒的', '　　在近几年开始传入我国，该极易杂交，所以繁殖出的名称和数量都非常混乱。紫牡丹是非常耐寒的品种，但是对高温比较敏感，所以人工栽培过程中应注意给予合适的环境。　　多肉紫牡丹十分耐寒，对高温敏感，栽培中要注意空气流通，夏季易。土壤下层宜腐质土，上层宜沙土，微酸性。繁殖用走出枝条萌生的子株，叶插也十分容易，杂交极易获得种子。　　夏季高温时和冬季寒冷时植株都处于休眠状态，主要期在较为凉爽的春、秋，生长期要求有充足的阳光，如果光照不足会导致株形松散，不紧凑，影响其观赏，而在光照充足处生长的植株，叶片肥厚饱满，株形紧凑，叶色靓丽。', '　　多肉　　多肉紫牡丹常用播种繁殖。多肉紫牡丹春季播种，发芽适温13－18°C，春季或初夏分株。繁殖用走出枝条萌生的子株，叶插也十分容易，杂交极易获得种子。', 'http://img.boqiicdn.com/Data/BK/P/imagick27841455441839.jpg', 'http://www.boqii.com/entry/detail/2487.html', '');
INSERT INTO `plant_family` VALUES ('518', '琉璃殿', 'Haworthia limifolia', '琉璃殿', '旋叶鹰爪草', '不容易死', '原产南非德兰士瓦省', 'http://www.boqii.com/entry/photo/2453/0,http://www.boqii.com/entry/photo/2453/4963', '', '', '', '百合目', '百合科', '十二卷属', '琉璃殿', 'Haworthia limifolia', '', '　　 　　琉璃殿的莲座状叶盘10厘米大，叶20枚左右，排列时向一个方向偏转似风车一般。叶卵圆状三角形，先端急尖，正面凹背面因突，有明显的龙骨突。深绿色，有无数同样', '　　琉璃殿的外形非常特殊，是很多多肉爱好者都非常喜欢的多肉。如果你是新手朋友，第一次养护琉璃殿的话，就需要看一下下面的文章，让小编来为你介绍一下琉璃殿的栽培方法。琉璃殿　　养护琉璃殿应该保持其盆土湿润，切忌时干时湿，有条件的可每月施一次肥。夏季高温期，琉璃殿的生长开始变得十分缓慢，但不是休眠。冬季当环境达到10℃以上时，琉璃殿仍可正常生长，5～10℃时，低于5℃时停止生长。　　栽培中以充足明亮的散射光为佳，否则叶色发红，降低观赏价值。土要求保，忌过于粘重。栽植时，用盆不要太小，水分要稳定，浇水不能忽小忽大。本种耐寒性较好，冬季不低于8℃即可安全越冬；对夏季高温闷热天气也有一定的抵抗力。因生长较慢，每2年换盆1次。盆土用腐叶土、培养土和粗砂的混合土，加入少量干牛粪和骨粉。', '　　　　琉璃殿常用分株和扦插繁殖。分株，全年均可进行，常在4－5月换盆时，将母株侧旁分生的小植株剥离母体，直接盆栽，刚盆栽的浇水不宜多，以免影响根部恢复。扦插，5－6月将肉质叶片轻轻切下，基部带上半木质化部分，插于沙床，室温在18至22℃时，约20－25天可生根。', 'http://img.boqiicdn.com/Data/BK/P/imagick90911453799487.jpg', 'http://www.boqii.com/entry/detail/2453.html', '');
INSERT INTO `plant_family` VALUES ('519', '水仙花', 'Narcissus', '水仙', '凌波仙子、金盏银台、落神香妃、玉玲珑、金银台、雪中花、天蒜等', '不容易死', '', 'http://www.boqii.com/entry/photo/1966/0,http://www.boqii.com/entry/photo/1966/5561', '', '', '', '', '', '', '', '', '', '　　水仙又名中国水仙，在中国，水仙一般作为年宵 　　水仙的鳞茎卵球形。叶宽线形，扁平，长20－40厘米，宽8－15毫米，钝头，全缘，粉绿色。花茎几与叶等长；伞形花序有花4－8朵；佛焰苞状总苞膜质；花梗长短不一；花被管细，灰绿色，近三棱形，长约2厘米，花被裂片6，卵圆形至阔椭圆形，顶端具短尖头，扩展，白色，芳香；副花冠浅杯状，淡黄色，不皱缩，长不及花被的一半；雄蕊6，着生于花被管内，花药基着；子房3室，每室有胚珠多数，花柱细长，柱头3裂。蒴果室背开裂。花期春季。　　　　　　　　　　　　　　　　水仙　　　', '　　水仙花在我国是非常常见的观赏，但是水仙花往往需要经过几个月的栽培才能够开出漂亮的花。一般，大家都希望自己的水仙花能够在过年前就能开花了，这样也能够增添节日气氛，那么想要栽种出漂亮的水仙花应该怎么做呢？　　1、挑选种球要有讲究，主要注意看形状、观、按压感三大要点。看形：优质的水仙鳞茎，一般个体大、形扁、质硬，表皮纵脉条纹距离较宽，中膜绷得很紧，皮色光亮，根盘宽大肥厚。　　2、选择适当的生长环境。水仙性喜阳光、温暖，要求空气湿度大，不甚耐寒，且怕炎热，营养生长期需要湿润而又不积水的沙质的土壤。水仙和其它宿类多年生草本花卉不同，它具有秋季开始生长，开花，春季贮藏养分，夏季休眠的特点。　　3、正确选择水培法或土培法对水仙进行栽培。　　土培法家庭较少采用，即利用大多数润土花卉的法来栽培水仙。于10月中、下旬，用肥沃的沙质土壤把大块鳞茎栽入小呈有孔的花盆中，栽入一半露出一半，鳞下面应事先垫一些细沙，以利排水。　　4、预防“哑花”。　　所谓“哑花”，是指水仙在水养过程中，花葶中途夭折，花蕾枯萎或花蕾未开先衰的现象。“哑花”现象主要由以下几种原因引起。', '　　水仙花一般都是需要经过几个月的种植才能够开花，有的花友在自己的水仙花花期过了之后就会想要自己动手来进行繁殖了。但由于水仙花是比较有名的球种　\n　一、侧球繁殖\n　　这是最普通常用的一种繁殖方法。储球着生在鳞茎球外的两侧，仅基部与母球相连，很容易自行脱离母体，秋季将其与母球分离，单独种植，次年产生新球。　\n　二、侧芽繁殖\n　　侧芽是包在鳞茎球内部的芽。只在进行球根阉割时，才随挖出的碎鳞片一起脱离母体，拣出白芽，秋季撒播在苗床上，翌年产生新球。　　\n三、双鳞片繁殖\n　　1个鳞茎球内包含着很多侧芽，有明显可见的，有隐而不见的。但其基本规律是闲两张鳞片1个芽。用带有两个鳞片的鳞茎盘作繁殖材料就叫双鳞片繁殖。其方法是把鳞茎先放在低温4～10℃处4～8周，然后在常温中把鳞茎盘切小，使每块带有两个鳞片，并将鳞片上端切除留下2厘米作繁殖材料，然后用塑料袋盛含水50％的蛭石或含水6％的砂，把繁殖材料放入袋中，封闭袋口，置20～28℃　\n　四、组织培养\n　　用MS培养基，每升附加30克蔗糖与5克的活性炭，用芽尖作外植体，或', 'http://img.boqiicdn.com/Data/BK/P/imagick86171440064872.jpg', 'http://www.boqii.com/entry/detail/1966.html', '');
INSERT INTO `plant_family` VALUES ('520', '圆叶福禄桐', 'Polyscias balfouriana', '圆叶福禄桐', '圆叶南洋参', '不容易死', '原产热带区，主要分布于南太平洋和亚洲东南部的群岛上。', 'http://www.boqii.com/entry/photo/2243/0,http://www.boqii.com/entry/photo/2243/5282', '植物　　', '', '', '', '五加科', '南洋森属', '', 'Polyscias balfouriana', '', '　　 　　圆叶福禄桐的植株多分枝，茎干灰褐色，密布皮孔。枝条柔软，叶互生，3小叶的羽状复叶或单叶，小叶宽卵形或近圆形，基部心形，边缘有细锯齿，叶面绿色。', '　　圆叶福禄桐的叶片鲜亮多变，非常适合用于室内观赏，也成为了今年较流行的观叶植物。圆叶福禄桐的人工栽培难度不高，喜欢高温的环境，不耐寒。人工栽培圆叶福禄桐应注意以下几点：　　　它的生长近温为15～30℃，其中4～10月可保持在20～30℃，10月至翌年4月保持在13～20℃。漂亮的植物通常娇气一些，福禄桐亦然。它的斑叶抗寒性就差一些。一般情况下，即便是一般的纯绿叶品种，冬季也应维持不低于10℃的室温。当夏季气温达32℃以上时，也不能听之任之，批量生产的要搭棚遮荫，家庭观赏的要放于阴凉处，并向周围喷水降温，为其创造一个与原生条件比较接近的凉爽小环境。秋末冬初，当气温降至15℃时，要及时将其搬到室内，以免植株受寒害。冬季若室温能维持20℃以上，则其茎叶仍继续生长；若温度不高，则植株停止生长，进入半休眠状态。　　　以圆叶福禄桐为例，它需明亮的光照，光照不足易造成茎叶徒长、叶包暗淡、隐褪，但同时又忌强光暴晒，特别是初夏久雨初晴后，要防止叶片被灼伤。家庭盆栽，平时可放在朝南面口附近的通风良好处，夏季可放在北向或东向窗前，冬季应放于室内光线较好处。进行生产性栽培，自仲春至中秋，均应置于荫棚下，根据光线的强弱和光照的长短，遮光40～60％。总之，在半光照、有明亮散射光的环境下，它生长最为旺盛。　　　盆栽福禄桐喜欢较湿润的土壤和空气环境。生长期要有充足的水分供应，对待盆土表面变干后再浇水，土壤略干一点也无妨，但不能浇水过多，避免造成积水烂根。盛夏温度较高，除浇水要充足外，还需每天给叶面喷水一次，既可使叶面洁净光亮，又可提高植株周围的空气湿度。秋末冬初，当气温降至15℃以下时，要控制浇水。冬季则应减少烧水量，或以喷水代浇水，盆土保持微润稍干，但喷洒叶面时，要注意使水温与室温基本一致。　　　以疏松肥沃、排水良好的沙壤土为最佳，为其提供一个疏松、湿润、肥沃的土壤环境。盆栽用土可用腐叶土4份、园土4份、沙2份和少量沤制过的饼肥末或骨粉混合配制。生长可结合施肥，每月给盆株松土一次，使盆土长期保持通透良好，避免因盆土板结而造成烂根。露地或荫棚下的植株，在梅雨季节或遇连绵阴雨的天气，应加强检查，发现盆内有积水，要及时倒去并翻盆换土，以免落叶或烂根。一般情况下，每两年于春季换土－次。', '　　　　圆叶福禄桐的繁殖可剪取1年至2年生的枝条进行扦插，栽培土质选择性不严，排水需良好。春秋两季均可进行，但以春插效果更佳。可于3～4月间，剪取10～15厘米叶片，只保留端部的2～3片叶，下切口最好位于节下0。2厘米处，并用500ppm的吲哚丁酸或1号ABT生根药液浸泡10秒钟，再将其插入沙床或　　5～6月间，选择', 'http://img.boqiicdn.com/Data/BK/P/imagick78381448270793.jpg', 'http://www.boqii.com/entry/detail/2243.html', '');
INSERT INTO `plant_family` VALUES ('521', '花菱草', 'California poppy', '花菱草', '加州罂粟、金英花、人参花， 洋丽春', '不容易死', '美国及墨西哥', 'http://www.boqii.com/entry/photo/2360/0,http://www.boqii.com/entry/photo/2360/5056', '　', '被子植物门', '双子叶植物纲', '毛茛目', '罂粟科', '花菱草属', '花菱草', 'Eschscholtzia californica Cham.', 'Eschscholtzia californica', '　　 　　花菱草的花单生于茎和分枝顶端；花梗长5～15厘米，花托凹陷，漏斗状或近管状，长3～4毫米，花开后成杯状，边缘波状反折；花萼卵珠形，长约1厘米，顶端呈短圆锥状，萼片2，花期脱落；花瓣4，三角状扇形，长2.5～3厘米，黄色，基部具橙黄色斑点；雄蕊多数，约40枚以上，花丝丝状，基部加宽，长约3毫米，花药条形，长5～6毫米，橙黄色；子房狭长，花柱短，柱头4，钻状线形，不等长。', '　　花菱草茎叶嫩绿带灰色，花色鲜艳夺目，非常漂亮，受到很多花友的喜爱。花菱草原产于美国加利福尼亚州，为多年生草本，是良好的花带、花境及盆栽材料。　　花菱草较耐寒，喜冷凉干燥气候，不易湿热，宜疏松肥沃，排水良好、上层深厚的沙质壤土，也耐瘠土，炎热的夏季处于半休眠状态，常枯死，秋后再萌发。　　喜欢较干燥的空气环境，阴雨天过长，易受病菌侵染。怕雨淋，晚上保持叶片干燥。最适空气相对湿度为40～60％。　　喜欢冷凉气候，忌酷热，耐霜寒。对冬季温度要求不是很严，只要不受到霜冻就能安全；在春末夏初温度在30℃以上时，最适宜的生长温度为15～25℃。　　在晚秋、冬、早春三季，由于温度不是很高，就要给予它直射阳光的照射，以利于它进行和形成花芽、开花、结实。夏季若遇到高温天气，需要给它遮掉大约50％的阳光。　花菱草对肥水要求较多，但怕乱施肥、施浓肥和偏施氮、磷、钾肥，要求遵循“淡肥勤施、量少次多、营养齐全”和“间干间湿，干要干透，不干不浇，浇就浇透”的两个施肥（水）原则，并且在施肥过后，晚上要保持叶片和花朵干燥。', '　　花菱草为一、二年生草本　\n　一、播种繁殖\n　　用播种法繁殖，冬季土壤不结冻的地区行秋播。北方地区于早春在室内育苗，15～20℃条件下，7天左右出苗。于真叶开展前及时起苗上盆，无霜后，脱盆带土定植（切勿伤根，否则不易恢复　　\n二、播种后的管理\n　　在秋季播种后，遇到寒潮低温时，可以用塑料薄膜把花盆包起来，以利保温保湿；幼苗出土后，要及时把薄膜揭开，并在每天上午的9：30之前，或者在下午的3：30之后让幼苗接受太阳的光照，否则幼苗会生长得非常柔弱；大多数的种子出齐后，需要适当地间苗：把有病的、生长不', 'http://img.boqiicdn.com/Data/BK/P/imagick61971450947848.jpg', 'http://www.boqii.com/entry/detail/2360.html', '');
INSERT INTO `plant_family` VALUES ('522', '金丝梅', 'Hypericum patulum Thunb.ex Murray', '金丝梅', '芒种花、云南连翘、断痔果', '不容易死', '中国陕西、四川、江西、湖南、湖北、安徽、江苏等省及日本', 'http://www.boqii.com/entry/photo/2352/0,http://www.boqii.com/entry/photo/2352/5064', '植物　', '被子植物门', '双子叶植物纲', '侧膜胎座目', '藤黄科', '金丝桃属', '金丝梅', 'Hypericum patulum Thunb.ex Murray', '', '　　 　　金丝梅高0.3－1.5米，丛状，具开张的枝条，有时略多叶。茎淡红至橙色，幼时具4纵线棱或4棱形，很快具2纵线棱，有时最后呈圆柱形；节间长0.8－4厘米，短于或稀有长于叶；皮层灰褐色。', '　　', '　　　　1、分株：从头年12月到翌年3月均可进行。分栽后遮阴半月，可开花，两年后又可分株。　　2、扦插：9－10月集中扦插，插条长10－12cm，插后搭小拱棚即可转入正常', 'http://img.boqiicdn.com/Data/BK/P/imagick4511450777112.jpg', 'http://www.boqii.com/entry/detail/2352.html', '');
INSERT INTO `plant_family` VALUES ('523', '广布红门兰', 'Orchis chusua D.Don', '广布红门兰', '库莎红门兰', '不容易死', '', 'http://www.boqii.com/entry/photo/2445/0,http://www.boqii.com/entry/photo/2445/4971', '植物　　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '红门兰属', '广布红门兰', 'Orchis chusua D.Don', '', '　　 　　广布红门兰植株高5－45厘米。块茎长圆形或圆球形，长1－1.5厘米，直径约1厘米，肉质，不裂。茎直立，圆柱状，纤细或粗壮，基部具1－3枚筒状鞘，鞘之上具1－5枚叶，多为2－3枚，叶之上不具或具1－3枚小的、披针形苞片状叶。叶片长圆状披针形、披针形或线状披针形至线形，长3－15厘米，宽0.2－3厘米，上面无紫色斑点，先端急尖或渐尖，基部收狭成抱茎的鞘。', '　　广布红门兰性喜阴，忌阳光直射。广布红门兰的栽培难度并不高，由于其具有较高的园艺价值，所以受到很多花友的喜爱，也被很多花友栽培。那么如何才能养出健康漂亮的广布红门兰呢？　　广布红门兰盆栽时间一般在春季3－4月或秋季10－11月，花盆以口小、盆深、底孔大的为佳。新从山上挖来的野生苗需理植于瓦盆（泥盆）中，这样)泥易干，通气性好。容易发根。兰花种植在盆中的方法与一般不同，尤其是名种兰花，翻种移盆必须洗根。方法足将根浸入清水中，用旧或毛笔轻轻洗刷，切勿用力过大伤根，用剪刀将残叶、黄叶、断裂根、发黑根剪去，注意勿伤幼芽。然后将好的植株放在阴凉通风处晾干，待根部发白并显细小皱纹柔软时，再植入盆中。', '　　　　广布红门兰在春秋两季均可进行，一般每隔三年分株一次。凡植株', 'http://img.boqiicdn.com/Data/BK/P/imagick601453368794.jpg', 'http://www.boqii.com/entry/detail/2445.html', '');
INSERT INTO `plant_family` VALUES ('524', '子宝', 'Gasteria gracilis var. minima', '子宝', '元宝花', '', '原产于南非', 'http://www.boqii.com/entry/photo/2166/0,http://www.boqii.com/entry/photo/2166/3428', '　　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '鲨鱼掌属', '子宝', 'Gasteria gracilis var. minima', '', '　　子宝又名元宝花，是百合科鲨 　　子宝的叶肉质较厚，像舌头，叶面光滑，带有白色斑点，同', '　　是比较常见的非常受欢迎的多肉植物，由于子宝的植株娇小，所以非常适合盆养，并且栽培难度也较低，是市场上比较常见的多肉。　　子宝喜欢半阴通风的地方，喜疏松肥沃、排水良好的砂质壤土做栽培基质，如果有条件，所用盆土可由腐叶、细砂、园土配制；较耐寒，越冬温度不低于5℃；夏季不能暴晒，子宝暴晒会灼伤，晒出黑斑及叶片薄、不鲜绿等不良状况，较耐旱。　　浇水要注意不干不浇，浇则浇透的原则，冬季更要控制水分，多浇容易烂根，特别提示子宝烂根不易发现，很多养子宝的人都有这种感觉：放在桌上的子宝，天天也看着，当有一天把它拿在手里碰它一下却倒了，原来里面全了。建议夏天20～30天浇一次水，30～40天。　　放在房间桌上的子宝要注意通风、透光，长期在黑暗的情况下要适当在有阳光的时候拿出外面受光；冬季可安全越冬，无需其他防护措施；放阳台养护的夏季不能太阳暴晒，适宜明亮的散射光，冬季搬进室内，防受冻。　　子宝常有幼株从基旁长出，可根据生长情况分株换盆。', '　　　　子宝喜欢半阴通风的地方，喜疏松肥沃、排水良好的砂质壤土做栽培基质，如果有条件，所用盆土可由腐叶、细砂、园土配制；较耐寒，越冬　　子宝生长虽然缓慢，但其基部常萌生许多小芽，因此繁殖多为分株，也可播种。子宝植株幼小，生长较慢，富有特色，品种多样，适宜用小盆栽种，陈设于窗台、案头、书桌、阳台等处，是比较理想的桌旁栽培植物。', 'http://img.boqiicdn.com/Data/BK/P/imagick1941446197445.jpg', 'http://www.boqii.com/entry/detail/2166.html', '');
INSERT INTO `plant_family` VALUES ('525', '黄花鸢尾', 'Iris wilsonii  C. H. Wright', '黄花鸢尾', '黄菖蒲', '不容易死', '', 'http://www.boqii.com/entry/photo/2345/0,http://www.boqii.com/entry/photo/2345/5072', '　　', '被子植物门', '单子叶植物纲', '百合目', '鸢尾科', '鸢尾属', '', 'Iris wilsonii  C. H. Wright', '', '　　 　　黄花鸢尾植株基部有老叶残留的纤维。根状茎粗壮，斜伸；须根黄白色，少分枝，有皱缩的横纹。叶基生，灰绿色，宽条形，长25－55厘米，宽5－8毫米，顶端渐尖，有3－5条不明显的纵脉。', '　　为多年生草本植物，植株基部有老叶残留的纤维。黄花鸢尾在花盛开时向外倾斜，花黄色，观赏价值比较高，也受到很多花友们的，越来越多的朋友将黄花鸢尾盆栽在家中观赏。　　黄花鸢尾喜温暖、湿润和阳光充足环境。较耐寒，怕干旱，稍耐阴。生长适温15～35℃，10℃以下低温生长停滞，华北、西南、江南可以露地越冬，春季再发叶。黄花鸢尾在野生状态下生长于灌木林缘，阳坡地、林缘及水边湿地。种植环境喜湿润且排水良好，富含腐殖质的沙壤土或轻黏土，有一定的耐碱能力，在pH值为8.7、含盐量0.2％的轻度盐碱土中能正常生长。喜光，也较耐阴，在半阴环境下也可正常生长。喜温凉气候，耐寒性强。　　黄花鸢尾盆栽可作摆放或室内装饰，与其他的鸢尾属植物，依地形变化、株高、花色及水位差别进行搭配布置。花可作材料。花色、花型丰富，既可观叶，又能观花，是园林水景造景中的佳品，观赏价值高。水池边际配上3～5丛，自然多姿，更显生动活泼。成片种植的群体景观好。', '　　　　有性繁殖即种子繁殖。可随采随播，播种前要先用温水浸泡12h左右，然后将种子捞出，洗净，去除不能发芽的种子，之后将浸泡的种子撒播在已装好的　　无性繁殖在清明前进行，先将地下茎挖出，清洗干净，去掉老根、茎，再用快刀分切成块状，最好用代森纳进行', 'http://img.boqiicdn.com/Data/BK/P/imagick87441450690929.jpg', 'http://www.boqii.com/entry/detail/2345.html', '');
INSERT INTO `plant_family` VALUES ('526', '郁李', 'Cerasus japonica （Thunb.） Lois.', '郁李', '爵梅，秧李', '不容易死', '黑龙江，吉林，辽宁，河北，山东，河南，浙江', 'http://www.boqii.com/entry/photo/2178/0,http://www.boqii.com/entry/photo/2178/5350', '', '', '', '', '', '', '', '', '', '　　 　　郁李为落叶灌木，高1～1.5米。树皮灰褐色，有不规则的纵条纹；幼枝黄棕色，光滑。桃红色宝石般的花蕾，繁密如云的花朵，深红色的果实，都非常美丽可爱，是园林中重要的观花、观　　　　　　　　　　　　　　　　　　　　　　', '　　', '　　　\n　一、分株繁殖\n　　郁李萌蘖性强，根蘖很多，宜在春季萌动前将母株根部的萌蘖苗用利刀分开，每株可分3株至5株，然后移栽即可。一般成活后两年可见花。　\n　二、扦插繁殖\n　　可于2月至3月扦插，选取一年生粗壮萌蘖的下段，剪成长10厘米至15厘米并带有两三个芽作为插穗，插入土中2／3。扦插后浇透水，保持较高空气湿度，1个月左右即可生根。由于郁李的根容易产生不定芽，用根插繁殖效果也较好。　\n　三、播种繁殖\n　　春秋季节均可播种，春季可在2月下旬至3月中下旬，秋季可在9月至10中旬，但以秋播为好。可于6月上旬采种，堆熟后将种籽洗净阴干，至秋季播种，或将种籽作低温沙藏后，翌年春季露地播种即可。播种量按每平方米10克左右即可，播种深度4厘米至5厘米，播后覆盖一层细细的土，并用稻草或其他物体覆盖表面，保持土壤湿度，使其出苗整齐。　\n　四、嫁接繁殖\n　　嫁接主要采用“T”形芽接，选健壮的一二年生优良郁李', 'http://img.boqiicdn.com/Data/BK/P/imagick10361446542361.jpg', 'http://www.boqii.com/entry/detail/2178.html', '');
INSERT INTO `plant_family` VALUES ('527', '萍蓬草', 'Nuphar pumilum （Hoffm.） DC.', '萍蓬草', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2182/0,http://www.boqii.com/entry/photo/2182/5346', '　', '被子植物门', '', '', '睡莲科', '萍蓬草属', '萍蓬草', 'Nuphar pumilum （Hoffm.） DC.', '', '　　 　　萍蓬草为多年水生草本；根状茎直径2－3厘米。叶纸质，宽卵形或卵形，少数椭圆形，长6－17厘米，宽6－12厘米，先端圆钝，基部具弯缺，心形，裂片远离，圆钝，上面光亮，无毛，下面密生柔毛，侧脉羽状，几次二歧分枝；叶柄长20－50厘米，有柔毛。花直径3－4厘米；花梗长40－50厘米，有柔毛；萼片黄色，外面中央绿色，矩圆形或椭圆形，长1－2厘米；花瓣窄楔形，长5－7毫米，先端微凹；柱头盘常10浅裂，淡黄色或带红色。浆果卵形，长约3厘米；种子矩圆形，长5毫米，褐色。花期5－7月，果期7－9月。', '　　萍蓬草为多年生浮叶型水生草本植物，是夏季非常常见的观叶植物，也是水景园中非常重要的观赏植物。萍蓬草在温暖、湿润且阳光充足的环境下，耐低温，水深不宜超过1米。　　　　温度对萍蓬草属的生长发育有着极为重要的关系。武汉4－7月的平均温度为16.5－21.7℃，对苗期的幼苗最为适宜；8月平均温度超过29℃时，对该植物的生长发育有一定的影响，当气温长期在38℃时，植株停止生长或生长极慢；当气温在42℃以上时，地表气温在53℃时，随之升高，就会出现腐叶，重者会造成植物的死亡。因此，在此期间必须保持水源的流畅。萍蓬草属植物的最适宜的温度：月均温度范围为16.5—24—29—13℃。当日均温度（11月下旬或12月上旬）为10℃左右时植株终止生长。　　光照对萍蓬草的生长发育的影响不大。在武汉的光照条件下能正常生长。　　　萍蓬草植物对土壤的pH要求不十分严格，在pH＝5.5－7.5的条件下都能正常地生长发育。但肥力与它有着密切的关系，土壤肥沃，花多，色彩艳丽，花期长，整个植株生长旺盛，观赏期长，反之，失去观赏价值。　　　我们选用缸高65厘米、缸内径65－80厘米，池内径直径1×1米或2×2米，深60厘米的定植条件。', '　　很多朋友往往会分不清睡莲和', 'http://img.boqiicdn.com/Data/BK/P/imagick99921446629229.jpg', 'http://www.boqii.com/entry/detail/2182.html', '');
INSERT INTO `plant_family` VALUES ('528', '姬凤梨', 'Cryptanthus acaulis Beer', '姬凤梨', '蟹叶姬凤梨、紫锦凤梨', '不容易死', '原产于南美 热带地区，主要分布在巴西的原始森林中', 'http://www.boqii.com/entry/photo/2193/0,http://www.boqii.com/entry/photo/2193/5334', '　　', '', '', '', '凤梨科', '凤梨属', '姬凤梨', '', 'Cryptanthus acaulis Beer', '　　 　　姬凤梨地下部分具有块状根茎，地上部分几乎无茎。叶从根茎上密集丛生，每簇有数片叶子，水平 伸展呈莲座状，叶片坚硬，边缘呈波状，且具有软刺，叶片呈条带形，先端渐尖，叶背有白色磷状物，叶肉肥厚革质，表面绿褐色。花两性，白色，', '　　是凤梨类中株型特别小的一种，也正因为其植株小巧玲珑，所以是很难得的袖珍型观叶植物，深受人们的喜爱。姬凤梨常被盆栽或与其他植物组合盆栽，那么如何才能养好姬凤梨呢？　　姬凤梨株形规则，色彩绚丽，适宜作桌面、窗台等处的观赏装饰，是优良的室内观叶植物。也可作为旱生盆景、瓶栽植物的一部分。亦可在室内作吊挂或栽植于室外架上、假山石上等，是较好的绿化美化材料。栽培　夏季遮荫养护，室内摆设可放置于南窗具有散射光的地方。　　生长适温为30℃左右。冬季20℃左右的情况下可以继续正常生长，12℃以上能安全。生长旺季要经常浇水，并向地面喷水，增加湿度，但不要向叶簇喷水，防止烂叶。盆栽姬凤梨选用腐叶土或锯末、煤烟灰、河沙、园土的混合土，盆底要留有通气的空隙。地上部分要每2～3年更新一次，去除老叶，保留地下根茎。养殖姬凤梨采用播种法、扦插法和分株法养殖。', '　　姬凤梨的株型小巧，并且规则，非常适合放在桌面、窗台等处作为观赏装饰用，是优良的室内观叶　　\n播种法：\n　　\n扦插法：\n　　\n分株法：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick71231446802281.jpg', 'http://www.boqii.com/entry/detail/2193.html', '');
INSERT INTO `plant_family` VALUES ('529', '小玉', 'cremnosedum ＇little gem＇', '小玉', '特利尔宝石', '不容易死', '', 'http://www.boqii.com/entry/photo/2457/0,http://www.boqii.com/entry/photo/2457/4959', '', '', '', '', '景天科', '拟石莲属', '', '', '', '　　 　　小玉叶片短梭型，叶片', '　　小玉又名特利尔宝石，是小型，非常容易群生，很多朋友都觉得小玉像微缩版的)。如果将小玉重在大盆里，等到群生后会非常壮观，那么如何才能养好小玉呢？　　小玉稍耐寒，冬季给予充足的阳光，保持盆土适度干燥，能耐0℃的低温。零下5度叶片的顶端生长点就会出现冻伤，干枯，整个冬季基本断水，5度以下就要开始慢慢断水。　　小玉在夏季高温时整个植株生长缓慢，有的地区完全停止生长，可放在通风、凉爽处，并节制浇水，不能长期雨淋，以免植株。春、秋两季的生长旺盛期，要多见阳光，避免水过多，水大容易黑腐病换盆一次，盆土宜用排水、透气性良好的沙壤土。', '　　　　小玉的繁殖一般是砍头和扦插，砍下来的植株可以直接扦插在干的颗粒土中，几天后少量给水，很容易就发根了。在是叶插，选', 'http://img.boqiicdn.com/Data/BK/P/imagick86941453885708.jpg', 'http://www.boqii.com/entry/detail/2457.html', '');
INSERT INTO `plant_family` VALUES ('530', '德国鸢尾', 'Iris germanica  L.', '德国鸢尾', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2196/0,http://www.boqii.com/entry/photo/2196/5331', '　　', '被子植物门', '单子叶植物纲', '百合目', '鸢尾科', '鸢尾属', '德国鸢尾', 'Iris germanica  L.', '', '　　 　　德国鸢尾是多年生草本植物。根状茎粗壮而肥厚，常分枝，扁圆形，斜伸，具环纹，黄褐色；须根肉质，黄白色。叶直立或略弯曲，淡绿色、灰绿色或深绿色，常具白粉，剑形，长20－50厘米，宽2－4厘米，顶端渐尖，基部鞘状，常带红褐色，无明显的中脉。', '　　原产于欧洲，但在我国被广泛栽培。由于德国鸢尾的园艺较多，花色丰富艳丽，所以常常被用于布置花坛，也成为了非常重要的材料。德国鸢尾花代表了神圣的意思。　德国鸢尾对土壤的pH值要求不严，在pH值为6～8的土壤上均可正常，但在中性至微碱性土壤（pH7.0～7.2范围）上生长最好。在酸性土壤中，可加入适量石灰粉将土壤调至中性；在碱性很强的土壤中，可加入适量的腐殖酸土将栽培土调至微碱性或中性。　春季干旱地区，萌芽生长至开花阶段应保持土壤适度潮湿，以保证花、叶迅速生长发育对水的需要；花后，可不必特殊供水，多雨季节更要注意排水，以免导致根茎的。　生长期进行两次追肥，春秋季各1次；施用量60g／m2。春季用骨粉4份，过磷酸钙2份，硫酸钾1份，硫酸铵1份混合后作追肥；秋季用骨粉4份，过磷酸钙2份，硫酸钾1份混合后作追肥。', '　　　　德国鸢尾很少能结实种子，除在进行杂交育种研究时采用的繁殖技术外，生产上多采用分栽根状茎和组织　　分株', 'http://img.boqiicdn.com/Data/BK/P/imagick28481446803429.jpg', 'http://www.boqii.com/entry/detail/2196.html', '');
INSERT INTO `plant_family` VALUES ('531', '含笑', 'Michelia figo （Lour.） Spreng.', '含笑花', '含笑美、含笑梅、山节子、白兰花、唐黄心树、香蕉花、香蕉灌木', '不容易死', '原产于广东和福建，现长江流域至江南、台湾等各地均有栽培', 'http://www.boqii.com/entry/photo/1936/0,http://www.boqii.com/entry/photo/1936/5593', '', '', '', '', '', '', '', '', '', '　　 　　含笑花高2－3米，树皮灰褐色，分枝繁密；芽、嫩枝，叶柄，花梗均密被黄褐色绒毛。叶革质，狭椭圆形或倒卵状椭圆形，长4－10厘米，宽1.8－4.5厘米，先端钝短尖，基部楔形或阔楔形，上面有光泽，无毛，下面中脉上留有褐色平伏毛，余脱落无毛，叶柄长2－4毫米，托叶痕长达叶柄顶端。　　　　　　　　　　　　　　　　　　　　　　　　', '　　含笑在开花时苞润如玉、浓香扑鼻，是非常适合栽培在庭院、绿地、草坪及树丛中的，由于含笑对氯气有这很好的抗性，所以在暖地的厂矿绿化中能够经常见到含笑的身影。很多花友都对含笑特别有兴趣，想要自己栽培，小编就为你整理了含笑栽培过程中的一些，想要栽培含笑的朋友可以一起了解一下。　　含笑在南方既可地栽也可盆栽，北方均为盆栽。地栽时植株要带土球，于3月中旬至4月中旬进行，最好选择疏林下土质疏松、排水良好的地方定植。盆栽者需选用微酸性、透气性能好、富含腐殖质的土壤，栽后留3厘米沿口，浇透水放阴凉处缓苗。缓苗后移庭院，要适当遮阴，以免强光灼伤叶片。含笑喜湿润，但怕涝，浇水要见干见湿。春季干旱多风，每天早、晚应喷水。以保持空气湿润；夏季气温高，浇水要充足，但连续阴雨天要及时倾倒盆内积水，以防烂根；冬季应控制浇水量，否则，盆土过湿，容易烂根落叶。在刚显蕾时应适当多浇些水，花蕾形成后又不宜浇水太多，不然容易落蕾；花期可适当增加浇水量。含笑虽喜肥，但在基肥充足的情况下，期施肥不宜太多，从9月下旬开始要停止施肥。冬季人室养护，室温不能低于5c。春暖后再移室外养护。一般每年翻盆换土I次，宜在花谢后进行。', '　　　　\n一、扦插法\n　　用此法可在短期内养殖较多的植株，但生长比嫁接苗慢。扦插时间以春、夏季为合适。春插在3月下旬进行，选1－2年生枝梢，长10－15厘米，剪去下部叶片，插入黄土拌河砂（6：4）作基质的苗床内，插后要求遮荫（透光率30％左右），经常保持床面湿润，待生根后上盆定植。夏插选当年生半木质化枝条，长8厘米左右，方法同春插。需要注意的是夏季气温高，空气湿度大，具有各种病孳生的条件。因此，必须对扦插基质进行消毒。另外，如能用200ppm的吲哚丁酸浸泡插条的基部15分钟，取出晾干后再扦插，可加速发根和提高成活率。　\n　二、压条法\n　　压条和扦插实为一个原理，都是利用枝条生长不定根的能力。扦插是脱离了母体进行的，虽然养殖量较大，但成活的可靠性不及压条，而且家庭一般养殖2－3株已够，故压条法养殖含笑最适宜家庭采用。压条在含笑生长期的任何时候都可进行。但以4月份最为合适，选取大小适当、　　嫁接养殖，常以紫玉兰、天目木兰为砧木进行枝接，也易成活。嫁接时间，春接宜在3月下旬至4月上旬含笑萌发前。秋接，宜在9月下旬至lO月上旬。秋接的苗要加强抚育，春接的管理容易，嫁接成活率一般可达85％。嫁接一般采用切接法，接穗选择母树中、上部的健壮一年生枝，长1－2节，不带叶片，操作技术按一般切接常规。切接后，为防止水分浸入伤口，需覆盖稻草，露出顶梢，约经25天，接穗即可愈合并开始发芽，这时把盖草去掉，及时抹除砧木上的萌芽。　　\n四、播种法\n　　此法适宜大量养殖，但开花时期晚，花朵略小。播种可随采随播，也可以经砂藏，到次年2月下旬至3月上旬进行。苗床宜用排水良好的砂质壤土。少量播种，可直接播在花盆内。播后，用焦碳泥土覆盖，置放阴处，约经1个月时间即可出苗。出苗后平时可按一般播种苗管理。第二年春季带土移栽。', 'http://img.boqiicdn.com/Data/BK/P/imagick911439373556.jpg', 'http://www.boqii.com/entry/detail/1936.html', '');
INSERT INTO `plant_family` VALUES ('532', '雨心', 'Crassula Vo lkensii', '雨心', '紫雨心', '', '南非东部', 'http://www.boqii.com/entry/photo/2465/0,http://www.boqii.com/entry/photo/2465/3730', '', '', '', '', '景天科', '青锁龙属', '', '', '', '　　 　　雨心肉质的叶子梭形，对生，排列较紧密，绿色的叶片正面有浅褐色或褐紫色细密的点状', '　　是比较容易丛生的多肉，由于雨心的叶片上有斑点，所以非常特别。雨心的栽培难度不高，但是有爱开花的习性，所以有一定的观赏价值，也受到很多花友的喜爱。　　　雨心沐太阳浴，喜欢半阴凉爽的环境。耐寒、耐热，适温15－20摄氏度，冬季温度不低于5摄氏度。春、秋、冬适合全日照养植，以防止植株陡长，使叶面色泽鲜艳。　　　浇水干透浇透，夏季需在半阴通风处养护，浇水不宜太多。生长季节要保证充足的水分供给，保持盆土湿润，即使在夏季和冬季，也不能让盆土长期处于干燥状态，否则，造成根系干枯，会导致植株死亡。　　　雨心对土壤的要求不是很高，介质要求疏松、通透性好的沙壤土。', '　　　　雨心扦插繁殖时，挑选长势良好无病虫害的母株，剪取10厘米左右的茎段，除去插条的下部叶片，在阴凉处晾1至2天。生根基质一定要排水良好，可选用河砂或泥炭土作为生根基质，砂与泥炭土的比例为1：1，为了减少成本，亦可用含有碎砖块的建筑下脚料。　　扦插时，插条入土4厘米，炎夏　　采取扦插方法生根迅速，且不用蘸取生根激素，一般夏季7天即可生根，扦插后3至4周植株即开始生长，有的长出侧芽，有的在顶部接着原来的部分继续生长。　　切记，扦插生根阶段勿浇水过量，可保持基质偏干，每天光照至少达到12至14小时，这样生根更加迅速。', 'http://img.boqiicdn.com/Data/BK/P/imagick32851453973478.jpg', 'http://www.boqii.com/entry/detail/2465.html', '');
INSERT INTO `plant_family` VALUES ('533', '方鳞绿塔', 'Crassula pyramidalis', '方鳞绿塔', '', '不容易死', '日本和英国', 'http://www.boqii.com/entry/photo/2466/0,http://www.boqii.com/entry/photo/2466/4951', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '青锁龙属', '', 'Crassula pyramidalis Thunb.Y', 'Crassula pyramidalis', '　　 　　方鳞绿塔的植株丛生，茎细易分枝，茎和分枝通常垂直向上。叶片如同方塔一样，在茎和分枝上排列成4棱，叶片对生，排列非常紧密，当光线不足时叶片也会轻微散乱。花着生于植株顶端，很小。', '　　方鳞绿塔主要分布在日本和英国，现在世界多国也有引进，人工栽培方鳞绿塔的难度并不高，但需要为其布置一个合适的环境才能让方鳞绿塔健康成长。　　方鳞绿塔对水分和阳光需求都不是太多，可半阴养，不过缺光过长会徒长得很厉害，叶片松散。夏季休眠，冬季生长，切忌大湿大水，水分过多容易。　　方鳞绿塔正常为绿色，日照时间增加和温差增大后会慢慢变红，特别容易群生。光照保持在60000至90000勒克斯，过低的照度会导致茎段徒长。大部分景天类植物喜欢光照充足的环境，但也稍耐阴。它们生长一般需要直射阳光，这样才能保证其健壮生长，而且叶片有健康的叶色。景天类植物摆放时要有一定的间距以防徒长，视不同的株型大小做决定。　　夜间生长的适温为15°C至18°C，白天生长适温为24°C至26°C。由于原产高原地带，景天类植物大部分都可以耐受极端低温（短时间的结冰）和极为干燥的天气。', '　　　　方鳞绿塔的繁殖方式以扦插为主，剪下一小段插入土中即可。扦插繁殖时，挑选长势良好无病虫害的母株，剪取10厘米左右的茎段，除去插条的下部叶片，在阴凉处晾1至2天。生根基质一定要排水良好，可选用河砂或泥炭土作为生根基质，砂与泥炭土的比例为1：1，为了减少成本，亦可用含有碎砖块的建筑下脚料。　　方鳞绿塔使用用分株、茎或叶片扦插或用种子繁殖。但是，在大规模', 'http://img.boqiicdn.com/Data/BK/P/imagick87671453973793.jpg', 'http://www.boqii.com/entry/detail/2466.html', '');
INSERT INTO `plant_family` VALUES ('534', '海杧果', 'Cerbera manghas Linn', '海杧果', '黄金茄、牛金茄、牛心荔、黄金调、山杭果、香军树、山样子', '不容易死', '', 'http://www.boqii.com/entry/photo/2437/0,http://www.boqii.com/entry/photo/2437/4978', '植物　', '被子植物门', '双子叶植物纲', '龙胆目', '()科', '海杧果属', '海杧果', 'Cerbera manghas Linn', 'Cerbera manghas', '　　 　　海杧果为乔木，高4～8米，胸径6～20厘米；树皮灰褐色；枝条粗厚，绿色，具不明显皮孔，无毛；全株具丰富乳汁。叶厚纸质，倒卵状长圆形或倒卵状披针形，稀长圆形，顶端钝或短渐尖，基部楔形，长6～37厘米，宽2.3～7.8厘米，无毛，叶面深绿色，叶背浅绿色；中脉和侧脉在叶面扁平，在叶背凸起，侧脉在叶缘前网结；叶柄长2.5～5厘米，浅绿色，无毛。', '　　为常绿小乔木，由于其叶片及果实外貌都非常像芒果，故此命名。海杧果叶大花多，姿态优美，是优良的海岸防护林树种，非常适合用于栽培观赏或用于海岸防潮。　　海杧果产中国广东、广西、台湾、海南等地，澳大利亚和亚洲，喜温暖湿润气候。海杧果，属于)科、海杧果属。多分枝，叶互生，卵状倒披针形；花白色美丽。生海滨湿地。叶大花多，姿态优美，适于庭园栽培观赏或用于海岸防潮。海杧果全株有毒，果实剧毒。少量即可致死，烤后毒性更大。其茎、叶、果均含有剧毒的白色乳汁，人、畜误食能中毒致死，一般在食用后的3～6小时内便会毒性发作。所以海杧果只是一种赏心悦目而不能一饱口福的“”。　　由于海杧果非常漂亮吸引，及具有强韧的生命力，故被广泛栽植为行道园景树。白色的花瓣、星星的红心就像是摘一颗星星，远看好像桐花树一般。', '　　或许很多人都在网上听说过　　人工繁殖海芒果以扦插为主，也可播种、压条繁殖。前插在春季、夏季均可进行，插前将插穗基部浸入清水中7－10天，要　　压条可于雨季进行，埋土压、筒压均可。分蘖繁殖尤为便利。　　播种可于春末进行，18－21°C发芽，成苗率较高。', 'http://img.boqiicdn.com/Data/BK/P/imagick47551453109696.jpg', 'http://www.boqii.com/entry/detail/2437.html', '');
INSERT INTO `plant_family` VALUES ('535', '多花紫藤', 'Wisteria floribunda', '多花紫藤', '日本紫藤', '不容易死', '', 'http://www.boqii.com/entry/photo/2412/0,http://www.boqii.com/entry/photo/2412/5003', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '蝶形花科', '紫藤属', '', 'Wisteria floribunda', '', '　　多花 　　多花紫藤为落叶藤本；树皮赤褐色。茎右旋，枝较细柔，分枝密，叶茂盛，初时密被褐色短柔毛，后秃净。羽状复叶长20-30厘米；托叶线形，早落；小叶5-9对，薄纸质，卵状披针形，自下而上等大或逐渐狭短，长4-8厘米，宽1-2.5厘米，先端渐尖，基部钝或歪斜，嫩时两面被平伏毛，后渐秃净；小叶柄长3-4毫米，干后变黑色，被柔毛；小托叶刺毛状，长约3毫米，易脱落。', '　　多花)的观赏价值非常高，其园艺种在花色、花序长度、瓣型均有较大变化。多花紫藤不但可以观赏，还有一定的药用价值，对于解毒、止吐泻都有很好的作用。　　栽植多花紫藤应选择土层深厚、土壤肥沃且排水良好的高燥处，过度潮湿易烂根。栽植一般在秋季落叶后至春季萌芽前。多花紫藤主根粗长，侧根少，不耐移植，因此在移栽时，植株要带土球，或不带土球，对枝干实行重剪，栽植穴施有机肥作基肥．栽后浇透水。对较大植株，在栽植前应设置坚固耐久的棚架，栽后将粗大枝条绑缚架上，使其沿架攀缘。多花紫藤的日常简单，可根据土壤的水肥状况进行适当地水肥管理。　　多花紫藤的修剪是管理中的一项重要工作，修剪时间宜在，修剪时可通过去密留稀和人工牵引使枝条分布均匀。为了促使花繁叶茂，还应根据其生跃习性进行合理修剪，因多花紫藤发枝能力强，花芽着生在一年生枝的基部叶腋，生长枝顶端易干枯，因此要对当年生的新枝进行回缩，剪去1/3～1/2，并将细弱枝、枯枝齐分枝基部剪除。　　多花紫藤为藤本植物，一般依附棚架或其他支撑物攀缘而上。如果采用缚杆支撑、扭蔓、修剪整形等栽培措施，可以培育成伞形树状多花紫藤，别有趣味。　　要让树状多花紫藤保持形状不变，在养护上必须下功夫。因为它毕竟是一种有极强攀缘能力的藤本植物，虽然能培育成树状，但它的属性没改变，抽生的藤蔓只要一搭上可攀缘之物，又会缠绕而上。所以在时，既不能让藤蔓搭上它物，又不能让其无限制地自由缠绕，必须经常不断地牵蔓、修剪、整形，控制藤蔓生长，否则会长得不伦不类，既非藤状，也非树状，一旦出现此种形态，非但开花量会减少，甚至会多年不开花。', '　　多花　\n　一、扦插繁殖\n　　插条繁殖一般采用硬枝插条。3月中下旬枝条萌芽前，选取1～2年生的粗壮枝条，剪成15cm左右长的插穗，插入事先准备好的苗床，扦插深度为插穗长度的2/3。插后喷水，加强　　插根是利用多花紫藤根上容易产生不定芽。3月中下旬挖取0.5～2.0cm粗的根系，剪成10～12cm长的插穗，插入苗床，扦插深度保持插穗的上切口与地面相平。其他　　\n二、播种繁殖\n　　播种繁殖是在3月进行。11月采收种子，去掉荚果皮，晒干装袋贮藏。播前用热水浸种，待开　　压条、分株、嫁接均在3月中、下旬进行。', 'http://img.boqiicdn.com/Data/BK/P/imagick10711452504411.jpg', 'http://www.boqii.com/entry/detail/2412.html', '');
INSERT INTO `plant_family` VALUES ('536', '八千代', 'Sedum corynephyllum', '八千代', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2047/0,http://www.boqii.com/entry/photo/2047/5480', '', '', '', '', '', '', '', '', '', '　　 　　八千代的成株可高20－30厘米，多分枝。叶片松散地簇生于分枝顶部，叶肉质，圆柱形，表面平整光滑，稍向上内弯，顶端圆钝较基部稍细，叶长3－4厘米，粗约0。6厘米，叶色灰绿或浅蓝绿色。在阳光充足的条件下，叶先端呈橙色或橙黄色，在冷凉八千代　　　　　　　　　　　　　', '　　为景天科景天属多肉，是小型的肉质灌木，现在很多多肉爱好者会将八千代制作成小型悬垂盆景，或者与其他成组合盆景。那么八千代应该如何栽培比较好呢？小编就为你介绍一下。　　八千代性喜温暖和阳光充足的环境，不耐寒，无明显。喜光照，有较强的耐旱性。适应性强，对土壤要求不严。盆土干透即可浇水，浇要浇透底。除了夏季稍微注意节制浇水和不要在密闭的环境里莳养以外，栽培难度不算太大。该品种主在冷凉季节生长，比较耐寒，在5℃左右还能生长，冬季温度只要不低于0℃，栽培的土壤在较为潮湿的状态下植株都不至于受冻。　　八千代的生长适温15－25度，冬季不低于3度；人工栽培时，浇水生长季干透浇透；生长季施肥一般每月一次。', '　　很多朋友对于多肉不了解的话很容易在　　八千代成丛栽培或是较多分枝聚在一起，可谓是怡红快绿，别有韵致。许多爱好者都爱将八千代制作成小型的悬垂盆景，或与其它掌类和多肉植物搭配成组合盆景，点缀于居室、　　八千代的繁殖方式主要是扦插繁殖，用枝插或者叶插均可。八千代的繁殖较为容易，在', 'http://img.boqiicdn.com/Data/BK/P/imagick97611442482299.jpg', 'http://www.boqii.com/entry/detail/2047.html', '');
INSERT INTO `plant_family` VALUES ('537', '马利筋', 'Blood-flower Milkweed', '马利筋', '金凤花、尖尾凤、莲生桂子花、芳草花', '不容易死', '', 'http://www.boqii.com/entry/photo/2397/0,http://www.boqii.com/entry/photo/2397/5018', '　　', '被子植物门', '双子叶植物纲', '龙胆目', '萝藦科', '马利筋属', '马利筋', 'Asclepias curassavica L.', '', '　　 　　马利筋为多年生直立草本，灌木状，高达80厘米，全株有白色乳汁；茎淡灰色，无毛或有微毛。叶膜质，披针形至椭圆状披针形，长6-14厘米，宽1-4厘米，顶端短渐尖或急尖，基部楔形而下延至叶柄，无毛或在脉上有微毛；侧脉每边约8条；叶柄长0.5-1厘米。聚伞花序顶生或腋生，着花10-20朵；花萼裂片披针形，被柔毛；花冠紫红色，裂片长圆形，长5毫米，宽3毫米，反折；副花冠生于合蕊冠上，5裂，黄色，匙形，有柄，内有舌状片；花粉块长圆形，下垂，着粉腺紫红色。蓇葖披针形，长6-10厘米，直径1-1.5厘米，两端渐尖；种子卵圆形，长约6毫米，宽3毫米，顶端具白色绢质种毛；种毛长2.5厘米。花期几乎全年，果期8-12月。', '　　马利筋原产于热带美洲，所以人工栽培时对环境的温度要求比较高。值得注意的是，马利筋全株有毒，尤其以乳汁毒性最强，但是含有强心甙，所以也有一定的药用价值。那么人工栽培马利筋应该注意哪些呢？　　　由于马利筋原产于热带地区，喜欢高温高湿环境，因此对冬季的温度的要求很严，当环境温度在10℃以下停止，在霜冻出现时不能安全越冬。　　在夏季：　　1、加强空气对流，以使其体内的温度能散发出去；　　2、放在半荫处，或给它遮荫50%；　　3、给它适当喷雾，每天2～3次。　　在冬季：　　1、搬到室内光线明亮的地方养护；　　2、在室外，可用薄膜把它包起来越冬，但要每隔两天就要在中午温度较高时把薄膜揭开让它透气。　　　对于盆栽的马利筋，除了在上盆时添加有机外，在平时的养护过程中，还要进行适当地肥水管理。　　春、夏、秋三季：这三个季节是它的生长旺季，肥水管理按照“花宝”——清水——“花宝”——清水顺序循环，间隔周期大约为1～4天，晴天或高温期间隔周期短些，阴雨天或低温期间隔周期长些或者不浇。　　冬季：在冬季，主要是做好控肥控水工作，肥水管理按照“花宝”——清水——清水——“花宝”——清水——清水顺序循环，间隔周期大约为3～7天，晴天或高温期间隔周期短些，阴雨天或低温期间隔周期长些或者不浇。　　对于地栽的植株，春夏两季根据干旱情况，施用2～4次肥水：先在根颈部以外30～100公分开一圈小沟（植株越大，则离根颈部越远），沟宽、深都为20公分。沟内撒进25～50斤有机肥，或者1～5两颗粒复合肥（化肥），然后浇上透水。入冬以后开春以前，照上述方法再施肥一次，但不用浇水。', '　　　\n　一、播种\n　　马利筋在深秋、早春季或冬季播种后，遇到寒潮低温时，可以用塑料薄膜把花盆包起来，以利保温保湿；幼苗出土后，要及时把薄膜揭开，并在每天上午的9：30之前，或者在下午的3：30之后让幼苗接受太阳的光照，否则幼苗会　\n　二、扦插\n　　马利筋繁殖除了用播种的方法外，最常用的就是扦插繁殖。这种繁殖方法常于春末秋初用当年生的枝条进行嫩枝扦插，或于早春用去年生的枝条进行老枝扦插。扦插基质选用扦插的营养土或河砂、泥碳土等材料。　　进行嫩枝扦插繁殖时，在春末至早秋植株生长旺盛时，选用当年生粗壮枝条作为插穗。把枝条剪下后，选取壮实的部位，剪成5～15公分长的一段，每段要带3个以上的叶节。剪取插穗时需要注意的是，上面的剪口在最上一个叶节的上方大约1公分处平剪，下面的剪口在最下面的叶节下方大约为0.5公分处斜剪，上下剪口都要平整刀要锋利)。　　马利筋进行硬枝扦插时，在早春气温回升后，选取去年的健壮枝条做插穗。每段插穗通常保留3～4个节，剪取的方法同嫩枝扦插。', 'http://img.boqiicdn.com/Data/BK/P/imagick55381452071903.jpg', 'http://www.boqii.com/entry/detail/2397.html', '');
INSERT INTO `plant_family` VALUES ('538', '华北珍珠梅', 'Sorbaria kirilowii （Regel）Maxim.', '华北珍珠梅', '吉氏珍珠梅、穗形t度灶、珍珠树、干狼柴、米帘子、鱼子花', '不容易死', '河北、河南、山东、山西、陕西、甘肃、青海、内蒙古等。', 'http://www.boqii.com/entry/photo/2396/0,http://www.boqii.com/entry/photo/2396/5019', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '珍珠梅属', '', 'Sorbaria kirilowii （Regel）Maxim.', 'Sorbaria kirilowii', '　　华北 　　华北珍珠梅为灌木，高达3米，枝条开展；小枝圆柱形，稍有弯曲，光滑无毛，幼时绿色，老时红褐色；冬芽卵形，先端急尖，无毛或近于无毛，红褐色。羽状复叶，具有小叶片13~21，连叶柄在内长21~25厘米，宽7~9厘米，光滑无毛；小叶片对生，相距1.5~2厘米，披针形至长圆披针形，长4~7厘米，宽1.5~2厘米，先端渐尖，稀尾尖，基部圆形至宽楔形，边缘有尖锐重锯齿，上下两面均无毛或在脉腋间具短柔毛，羽状网脉，侧脉15~23对近平行，下面显著；小叶柄短或近于无柄，无毛；托叶膜质，线状披针形，长8~15毫米，先端钝或尖，全缘或顶端稍有锯齿，无毛或近于无毛。', '　　华北)的生态价值比较高，现在分布在我国多个省区。的抗污染及净化空气的能力比较高，对于烟尘、二气化硫硫化氢等有害气体有不同程度的吸收和抗性，所以是园林中比较受欢迎的。　　华北珍珠梅为中性树种，喜温暖湿润气候，喜光也稍耐阴，抗寒能力强，对土壤的要求不严，较耐干旱瘠薄，喜湿润肥沃、排水良好之地。树姿秀丽，叶片幽雅，花序大而茂盛，小花洁白如雪而芳香，含苞欲放的球形小花蕾圆润如串串珍珠，花开似梅，花期长，可达3个月，陆续开花，花谢之后，将其花序剪除，它又能继续生出新的花枝，二次开的花更为繁密美丽，其花期可一直延至10月份。', '　　华北　\n　一、播种繁殖\n　　每年9~10月份采种，将朔果放在通风冷凉的室内，阴干，轻轻揉搓，除去种壳和杂质，放入纸袋内保存。将地耙平整细，种子混土撒播，播后覆盖细薄土，最好为腐殖土，随即用喷壶洒水，使种子与土壤紧密结合。播种后每天洒水1~2次，露地育苗3~5d出苗，苗期一定要保持土壤湿润。一年生苗高5~15cm，二年生可长至50cm左右。两年生移栽定植，株行距40cm×60cm，四至五年生出圃。　　\n二、硬枝扦插\n　　4月份，在健壮枝条上剪取插穗，插穗长度10~15cm，上端剪平，下端剪成马蹄形，切口平滑。扎成捆，下端浸泡在浓度为100mg/kg的ABT1号溶液中1h。插穗垂直插入土中地表保留1cm左右，株行距为10cm×30cm。插后立即浇透水，1~2周浇1次水，及时松土除草。插条一般20~30d生根发芽。硬枝扦插苗在扦插当年高度一般可达30~50cm，第2年春季移栽定植，株行距40cm×60cm，移栽时截干，促进分枝。定植后培育2~3a，植株高度可达到lm以上，每丛分枝5~10枝，即可出圃。　\n　三、嫩枝扦插\n　　6~8月份采集当年生半木质化无病虫嫩枝。穗条剪成长10~12cm的插穗，上部留2~4片小叶，除去下部叶片。下剪口斜切，平滑，浸泡在浓度为100mg/kg的ABT1号溶液中1h。插入由草炭土、', 'http://img.boqiicdn.com/Data/BK/P/imagick15441452071241.jpg', 'http://www.boqii.com/entry/detail/2396.html', '');
INSERT INTO `plant_family` VALUES ('539', '金樱子', 'Rosa laevigata  Michx.', '金樱子', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2067/0,http://www.boqii.com/entry/photo/2067/5460', '植物　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '蔷薇属', '金樱子', 'Rosa laevigata  Michx.', '', '　　 　　金樱子为常绿攀援灌木，高可达5米；小枝粗壮，散生扁弯皮刺，无毛，幼时被腺毛，老时逐渐脱落减少。小叶革质，通常3，稀5，连叶柄长5－10厘米；小叶片椭圆状卵形、倒卵形或披针状卵形，长2－6厘米，宽1.2－3.5厘米，先端急尖或圆钝，稀尾状渐尖，边缘有锐锯齿，上面亮绿色，无毛，下面黄绿色，幼时沿中肋有腺毛，老时逐渐脱落无毛；小叶柄和叶轴有皮刺和腺毛；托叶离生或基部与叶柄合生，披针形，边缘有细齿，齿尖有腺体，早落。', '　　', '　　金樱子夏季开花，花期很长，可达4个月，观赏价值与经济价值都非常高。一般可采用播种、扦插、分株、压条及嫁接的方法进行繁殖。', 'http://img.boqiicdn.com/Data/BK/P/imagick70241443001898.jpg', 'http://www.boqii.com/entry/detail/2067.html', '');
INSERT INTO `plant_family` VALUES ('540', '合欢', 'Albizia julibrissin Durazz.', '合欢', '“马缨花”、“绒花树”、“合昏”、“夜合”、“鸟绒”', '不容易死', '自伊朗至中国、日本。', 'http://www.boqii.com/entry/photo/2019/0,http://www.boqii.com/entry/photo/2019/5508', '', '', '', '', '', '', '', '', '', '　　合欢又名红粉扑花、夜合欢等，为豆科合欢属 合欢 　　合欢，　　　　　　　　　　　　　　亚科　　　　　', '　　合欢是一种观赏价值和经济价值都非常高的优良，深受人们的喜爱。由于成年的合欢树可以长到16米左右，所以适合栽种在、公园等园林绿化。合欢　　合欢树多生于山坡或栽培。合欢喜温暖湿润和阳光充足环境，对气候和土壤适应性强，宜在排水良好、肥沃土壤，但也耐瘠薄土壤和干旱气候，但不耐水涝。生长迅速。性喜光，喜温暖，耐寒、耐旱、耐土壤瘠薄及轻度碱，对二氧化硫、氯化氢等有害气体有较强的抗性。　　合欢树阳光充足的环境，以及湿润、肥沃、排水良好的土壤，耐寒也耐旱，但畏水湿。若种在砂质土壤中，植株生长将更好。他的根系复生能力很强，即使遭受严重损伤，仍能迅速恢复生长。9－10月份合欢果实成熟，荚果、种子细薄。植株生长到一定高度要进行合理修剪，特别要剪去病枝、交叉枝和徒长细弱枝。他的根有根瘤菌，具有改良土壤之功效。', '　　合欢为阳性树种，在我国很多地方均有种植，而长江、珠江流域较多。合欢的花色鲜艳，气味芬芳，不但可以美化环境还能用来作地震观测研究，作用非常广泛。合欢　　合欢花一般用种子播种繁殖，春秋都可播种，播前可用35℃温水浸种24小时，浅盆穴播，覆土1－－2厘米，以浸盆法给水，保持湿润，在15－－20℃条件下，经7－－10天出苗，苗高5厘米时上盆。采种时选健壮母株，加强', 'http://img.boqiicdn.com/Data/BK/P/imagick40201441791076.jpg', 'http://www.boqii.com/entry/detail/2019.html', '');
INSERT INTO `plant_family` VALUES ('541', '鹅掌楸', 'Liriodendron chinensis （Hemsl.） Sarg', '鹅掌楸', '马褂木，双飘树', '不容易死', '秦岭以南至越南北部，东起浙江，向西直至云南省。', 'http://www.boqii.com/entry/photo/2071/0,http://www.boqii.com/entry/photo/2071/5456', '　', '被子植物门', '双子叶植物纲', '毛茛目', '木兰科', '鹅掌楸属', '鹅掌楸', 'Liriodendron chinensis （Hemsl.） Sarg', '', '　　 　　鹅掌楸为乔木，高达40米，胸径1米以上，小枝灰色或灰褐色。叶马褂状，长4－12（18）厘米，近基部每边具1侧裂片，先端具2浅裂，下面苍白色，叶柄长4－8（－16）厘米。花杯状，花被片9，外轮3片绿色，萼片状，向外弯垂，内两轮6片、直立，花瓣状、倒卵形，长3－4厘米，绿色，具黄色纵条纹，花药长10－16毫米，花丝长5－6毫米，花期时雌蕊群超出花被之上，心皮黄绿色。', '　　在自然条件下种子的饱满率不到15％，而种子发芽率尽在5％一下，所以造成了鹅掌楸的低结实率，鹅掌楸在我国也是国家二级保护。那么鹅掌楸在栽培过程中应该注意哪些呢？　　鹅掌楸的幼苗喜温暖避风环境和肥沃的酸性土壤，在pH5.5－6.5的酸性土壤中育苗的效果最好。越冬时干藏的种子，春播时往往当年不发芽，有隔年萌发现象，故应秋播，或室外越冬埋藏后春播；也可以在春播前20天左右，用温水浸种后混湿砂放在背风向阳处催芽后播种。采用条播，行距一般为20－25厘米。鹅掌楸为两性花，有异熟孤雌生殖现象，雌蕊往往在含苞欲放时即已成熟，开花时柱头已枯黄，失去授粉能力。雌蕊虽未受精，却能继续，但种子无生命力，发芽率很低，通常只有5％左右，所以必须增加播种量，每亩约需25－30公斤。一般为带翅播种，覆土不仔细时，风雨后种子往往露出地表，所以需适当增加覆土厚度，可以达到厚1.5厘米。覆土后略加填压并盖草。', '　　鹅掌楸又名马褂木，其外形非常特别，有着“中国的郁金香树”的美名，是我国非常珍贵的行道树和　\n　一、种子繁殖\n　　用种子繁殖。必须用人工辅助授粉。秋季采种精选后在湿沙中层积　　1、采种　　母树宜选择　　2、育苗　　育苗地应选择避风向阳，土层深厚，肥沃湿润，排水良好的沙质壤土。秋末冬初深翻，翌春施基肥整平，挖好排水沟，修筑高床，苗床方向为东西向。育苗有播种和扦插两种方式。　　播种育苗采用条播，条距20～25cm。每亩播种量10～15kg。3月上旬播种，播后覆盖细土并覆以稻草。一般经20～30天出苗，之后揭草，注意及时中耕除草，适度遮荫，适时灌水施肥。1年生苗高可达40cm。　　3、栽植　　一般3月上中旬进行栽植。应选在比较背阴的山谷和山坡中下部。庭园绿化和行道树栽培应选择土壤深厚、肥沃、湿润的地段。栽植地在秋末冬初进行全面清理，定点挖穴，穴径60～80cm，深50～60cm，翌年3月上中旬施肥回土后栽植，用苗一般为2年生，起苗后注意防止　　4、管理　　定植后及时进行中耕除草、施肥、培土，于每年秋末冬初进行整枝。并注意防治病虫害。鹅掌楸主要病害有日灼病。主要虫害有卷叶蛾、大袋蛾等。卷叶蛾可用人工剪除枯梢，消灭幼虫和蛹，或在成虫期喷50％敌敌畏乳剂1000倍液的方法进行防治。大袋蛾可用人工摘除虫袋，或用90％敌百虫800～1000倍液喷杀幼虫的方法进行防治。　\n　二、扦插繁殖\n　　除了播种育苗以外，鹅掌楸还可用扦插法育苗。在豫南地区，多采用硬枝扦插的方法，其育苗方法简单易学、便于掌握。在落叶后翌年2月下旬，选择健壮母树，剪取一年生5毫米以上粗枝条作为插穗，穗长15厘米左右，每穗应具有2至3个饱满的芽，下端切口平剪，按株行距20厘米×30厘米插入土中3／4，扦插前可用生根粉浸30分钟左右。插条应随采随插，插好后要有遮荫设施，勤喷水。此法成苗率可达80％，一年生苗生长至80厘米以上，同样可以出圃造林。', 'http://img.boqiicdn.com/Data/BK/P/imagick88321443086974.jpg', 'http://www.boqii.com/entry/detail/2071.html', '');
INSERT INTO `plant_family` VALUES ('542', '刺槐', 'False Acacia， Black Locust', '刺槐', '洋槐、刺儿槐', '不容易死', '原生于北美洲，现被广泛引种到亚洲、欧洲等地', 'http://www.boqii.com/entry/photo/2077/0,http://www.boqii.com/entry/photo/2077/5450', '植物　', '被子植物门', '双子叶植物纲 Dicotyledoneae', '蔷薇目 Rosales', '豆科 Leguminosae', '刺槐属', '刺槐', 'Robinia pseudoacacia Linn。', 'Robinia pseudoacacia', '　　 　　刺槐为落叶乔木，高10～25米；树皮灰褐色至黑褐色，浅裂至深纵裂，稀光滑。小枝灰褐色，幼时有棱脊，微被毛，后无毛；具托叶刺，长达2厘米；冬芽小，被毛。羽状复叶长10～25（～40）厘米；叶轴上面具沟槽；小叶2～12对，常对生，椭圆形、长椭圆形或卵形，长2～5厘米，宽1.5～2.2厘米，先端圆，微凹，具小尖头，基部圆至阔楔形，全缘，上面绿色，下面灰绿色，幼时被短柔毛，后变无毛；小叶柄长1～3毫米；小托叶针芒状。', '　　早在1898年就被我国青岛地区从北美及欧洲等地区引入，现在，刺槐的经济价值非常高，对于很多种植的地区来说，都有着非同寻常的意义。那么刺槐在栽培过程中应该注意哪些呢？　　刺槐属强阳性树。在湿热气候不利于其，常导致树干低矮、弯曲。刺槐耐瘠薄，耐干旱，但不耐涝，对土壤适应性较强。萌芽力和根蘖性都很强。浅根性，侧根发达，但多分布在表土层中，在水湿和风口处易被吹倒和折断。根具有根瘤菌。　　目前我国的刺槐种植已经形成规模化，据调查，我国大陆除黑龙江和海南省外，其他省市自治区均有栽培，其中15个省将刺槐列为主要造林树种，全国刺槐人工林面积超过100万hm现在更是以每年新增6～7万hm造林面积的速度的发展，已演化为我国的一个乡土树种，由于刺槐的用途比较广泛，所以针对每个种植培育的侧重点也不尽相同，如我国的陕北高原地区，可利用刺槐较强的适应性，对于改善土壤环境有一定作用；在太行山地区，利用刺槐花的蜜源进行蜂业，从而增加地区经济等。刺槐树一般可生长至20多米高，由于不同气候条件的影响，树冠可分为灌木状和桅干状以及冠宽状，并且刺槐的叶子含有一定的氮、粗蛋白、粗纤维等元素，所以其叶子是很好的牛羊和鸡鸭以及其他的良好饲料。刺槐花根据不同的地区环境，通常在10年左右开始开花，其花期一般在4月至5月之间，甚至更长一些，可生产“槐花蜜”。其树根相对发达，入地深入可达3～6米，伸展长度可达30米，正因如此刺槐在较为贫瘠的土地上，具有良好的适应性，抗旱性，实用性及很高的经济价值。', '　　　　人工刺槐栽培技术可以分为育苗阶段和繁育阶段，首先，在育苗阶段需要对种子的　　刺槐的繁育8月之后不再灌水，增强木质化，提高抗抽干越冬能力。选用当年的刺槐苗即可，但要保持树苗根系在15～20CM范围，在春季栽苗即可，为了提高的成活率，需要对树苗根系进行化学处理，根据以往数据显示，经过萘乙酸浸泡12小时以上的树苗，其成活率可达到80％以上，但需要注意每株树苗需要有一定距离的间隔，45CM的距离较为适中，处理的当可培育出刺槐林。除此之外，还有无性繁殖、嫁接育苗、插根育苗等方法。　　由于成活的刺槐具有较强的适应性，所以对于', 'http://img.boqiicdn.com/Data/BK/P/imagick15061443173073.jpg', 'http://www.boqii.com/entry/detail/2077.html', '');
INSERT INTO `plant_family` VALUES ('543', '松果菊', 'Echinacea purpurea（Linn.） Moench', '松果菊', '紫锥花，紫锥菊，紫松果菊', '不容易死', '分布在北美，世界各地多有栽培', 'http://www.boqii.com/entry/photo/2388/0,http://www.boqii.com/entry/photo/2388/5028', '　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '松果菊属', '松果菊', 'Echinacea purpurea（Linn.） Moench', '', '　　 　　松果菊为多年生草本植物，株高50－150cm，全株具粗毛，茎直立。基生叶卵形或三角形，茎生叶卵状披针形，叶柄基部稍抱茎；头状花序单生于枝顶，或数多聚生，花径达10cm，舌状花紫红色，管状花橙黄色，花期6－7月。', '　　松果菊的外形和菊花非常像，并且色彩丰富艳丽，富有光泽，是菊科多年生草本植物。松果菊不但可以盆栽，还是很好的切花，并且，由于松果菊的花朵比较大，所以也能制作成干花。　　盆栽松果菊，盆栽土需疏松肥沃的混合土或土。栽植时每盆视盆大小，可种3－5棵苗。在初期需摘心1次，促使分枝。栽培植株每年更新一次为好。浇水不宜过多，梅雨，空气湿度大时更要控制浇水。生长期间要追施稀薄液肥，促使生长。花蕾形成时每周施肥1次。每次施肥后要洒清水，以免沾在植株上。为了避雨，培育时一般在温室进行，要放在通风较好，向阳处。最低不能低于10℃，炎热夏天需适当遮荫。', '　　由于松果菊的花朵较大，并且花色鲜艳，所以在绿化、美化环境的　\n　1、播种繁殖：\n　\n　2、分株繁殖：\n　　\n3、扦插繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick50071451899162.jpg', 'http://www.boqii.com/entry/detail/2388.html', '');
INSERT INTO `plant_family` VALUES ('544', '白牡丹', 'xGraptoveria ‘Titubans’', '白牡丹', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2424/0,http://www.boqii.com/entry/photo/2424/4991', '', '', '', '', '', '', '', '', '', '　　白牡丹为景天科多肉 　　白牡丹的茎叶多肉化，叶色灰白至灰绿，叶片表面有淡淡的白粉，叶尖在阳光下会出现轻微的粉红色，茎健壮，互生叶排列成莲座形，叶片倒卵形，先端急尖，白色的叶子如　　　　　　　　　　　　　　　', '　　白牡丹的叶子如同牡丹花绽开，故此得名，白牡丹的速度较快，并且枝叶繁茂，是比较容易栽培的。一旦白牡丹适应了当地的气候，即便放在屋顶任其接受烈日炙烤与暴雨冲淋，依然可以活得很美丽。　　白牡丹容易长侧枝，侧枝生长也比较迅速，缺光后植株的叶片会拉长，叶片与叶片间会空开很大的距离，叶片也变的比较薄，也不怎么白，会轻微泛蓝。白牡丹是一个容易长高且徒长的品种，要想养的叶片紧凑就需要强光照，不然给点水就徒长了，因叶片厚实使重量集中茎端，让老茎易斜倾，因此也容易养成老桩摆造型。花友平时浇水的时候尽量浇在土里，叶片沾上水分会影响美观，也容易被阳光灼伤。　　白牡丹是冬型种。喜温暖、干燥和通风的环境。适应力强，喜光、耐旱，也稍耐寒、耐阴。忌烈日暴晒和盆土积水。生长适温15－25摄氏度，冬季不低于5摄氏度。全日照，生长期一定要充分见光，否则就会“徒长没商量”。浇水坚持土干透后再浇水，一般1个月1次足矣。夏季适当遮荫和注意通风，冬季控制浇水，在室内向阳处。介质以肥沃、疏松即可。　　春天和秋天是白牡丹的生长期，可以全日照。夏天轻微休眠。通风遮阳，炎热夏季每个月4到5次水，不浇透。以维持白牡丹植株的正常生长就可以，夏季水太大容易腐烂。温度低于5度就要逐渐断水，3度以下保持盆土干燥，尽量保持不低于零下3度，寒冷的冬季水分大了会烂根。', '　　　　白牡丹的繁殖主要靠植株侧芽，叶片扦插和砍头，砍头后从残存茎根上长出的新芽来延续后代，且非常容易长侧芽，存活率比较高，叶插可以获得大批的苗，是大棚繁殖的首选，春季是侧芽爆发的', 'http://img.boqiicdn.com/Data/BK/P/imagick54011452762160.jpg', 'http://www.boqii.com/entry/detail/2424.html', '');
INSERT INTO `plant_family` VALUES ('545', '四海波', 'Faucaria tigrina', '四海波', '怒涛', '不容易死', '原产南非大卡鲁高原的石灰岩地区', 'http://www.boqii.com/entry/photo/2379/0,http://www.boqii.com/entry/photo/2379/5037', '　　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '肉黄菊属', '四海波', 'Faucaria tigrina', '', '　　 　　四海波植株密集丛生，非常肉质，叶十字交互对生，基部联合，先端三角形，叶缘和叶背龙骨突表皮硬膜化，大部分叶面有肉齿，叶缘有肉质粗纤毛，花大无柄，花色以黄色为多，夏季休眠。', '　　的株型娇小，适合盆栽，摆放在窗台、卧室、阳台或案几点缀都非常漂亮。人工栽培四海波需要注意浇水量，秋冬为其期，需要给予适当的肥水。　　四海波为小型肉质。叶扁菱形，肉质，常2～3对交互对生；灰绿色，有白点；叶缘有9～10反曲具纤毛的尖齿。花黄色，直径约5厘米，中午开放。沙质土小盆栽植，需排水良好。喜温暖及充足阳光，耐干旱。生长适温18～24℃，夏季高温时呈休眠状态；越冬15℃以上。放凉爽处，节制浇水。　　四海波喜温暖而忌酷暑、严寒，夏季休眠，需要遮荫50％，勤喷水而控制浇水，淋雨或浇水多易腐。秋冬生长期需要充足的光照及适当的肥水。　　只要掌握好夏季休眠期的控水、通风、遮荫、停肥等环节即可养护成功。', '　　四海波该属有30多个品种，常见的栽培品种有10余种，现在在世界多地均有栽培。人工栽培四海波的难度并不高，需要注意控制好夏季　　四海波', 'http://img.boqiicdn.com/Data/BK/P/imagick5421451553875.jpg', 'http://www.boqii.com/entry/detail/2379.html', '');
INSERT INTO `plant_family` VALUES ('546', '毛地黄', 'Digitalis purpurea', '毛地黄', '洋地黄、自由钟、指顶花、金钟、心脏草等', '不容易死', '原产欧洲西部，中国各地有栽培', 'http://www.boqii.com/entry/photo/2115/0,http://www.boqii.com/entry/photo/2115/5412', '　', '被子植物门', '双子叶植物纲', '管状花目', '玄参科', '毛地黄属', '', 'Digitalis purpurea', 'Digitalis purpurea', '　　 　　毛地黄除花冠外，全体被灰白色短柔毛和腺毛，有时茎上几无毛，高60－120厘米。茎单生或数条成丛。基生叶多数成莲座状，叶柄具狭翅，长可达15厘米；叶片卵形或长椭圆形，长5－15厘米，先端尖或钝，基部渐狭，边缘具带短尖的圆齿，少有锯齿；茎生叶下部的与基生叶同形，向上渐小，叶柄短直至无柄而成为苞片。', '　　成株高为60－120厘米，除花冠外，毛地黄全体被灰白色短柔毛和腺毛，有时茎上几无毛。毛地黄常被用于花坛的布置中，还可以作为自然式的布置，那么毛地黄在栽培过程中需要注意哪些问题呢？　　毛地黄适宜在湿润而排水良好的土壤上。　毛地黄喜半湿，稍耐旱，怕涝，浇水要适量，生长期见干即浇透，不可渍水，冬季以稍干微润为好。　　毛地黄喜光亦耐半阴，植于向阳地或散射光充足的半阴处都可以。在开花时节，考虑到花的质量和数量，可适当地增加光照。日照长度不会影响开花。　毛地黄生长的温度适应幅度在12℃～19℃，但在收尾阶段最理想的夜间温度为12℃～16℃。将种植在有一定保护冷床的条件下，就能生长出高质量的植物和花穗。　　性喜肥，生长期20天左右施一次全效有机液肥，氮磷钾复合肥或0。2％的磷酸二氢钾溶液也可。　　毛地黄常发生枯萎病、花叶病和蚜虫。发主病害时，及时清除病株，用石灰进行消淌毒。发生虫害时，可用40％氧化乐果乳油2000倍液喷杀，同时也能减花叶病发生。', '　　　　春、夏播于疏松肥美的土壤中，幼苗长至10cm左右移植露地。冬季育苗应尽量发明透风、湿润、凉快的环境。收获后要在第二年开花，而7月后收获第二年常不能开花。秋凉后生长快，冬季恰当保温，6～8月开花，至夏秋多因干冷枯死。如环境适合其有多年生习性，冬季防寒　　繁衍办法：常用收获繁衍。以9月秋播为主，播后不覆士，轻压即可，发芽适温为15－18℃。约10天发芽。基质的湿度要到达必定的规范。发芽进程中要有光照。也可春播。栽培治理：喜暖和湿润和阳光充沛环境，耐寒，生长适温为13－15℃。怕多雨、积水和高温，耐半阴、干早。冬季留意幼苗越冬', 'http://img.boqiicdn.com/Data/BK/P/imagick85191444730273.jpg', 'http://www.boqii.com/entry/detail/2115.html', '');
INSERT INTO `plant_family` VALUES ('547', '南洋杉', 'Araucaria cunninghamii Sweet', '南洋杉', '澳洲杉(详情介绍)，鳞叶南洋杉，塔形南洋杉', '不容易死', '澳大利亚和新几内亚，中国的广州、海南岛、厦门等地', 'http://www.boqii.com/entry/photo/2117/0,http://www.boqii.com/entry/photo/2117/5410', '', '', '', '', '', '', '', '', '', '　　 　　南洋杉，乔木，在原产地高达60～70米，胸径达1米以上，树皮灰褐色或暗灰色，粗，横裂；大枝平展或斜伸，幼树冠尖塔形，老则成平顶状，侧身小枝密生，下垂，近羽状排列。叶二型：幼树和侧枝的叶排列疏松，开展，锥状、针状、镰状或三角状，长7～17毫米，基部宽约2。5毫米，微弯，微具四棱或上（腹）面的棱脊不明显，上面有多数气孔线，下面气孔线不整齐或近于无气孔线，上部渐窄，先端具渐尖或微急尖的尖头；大枝及花果枝上之叶排列紧密而叠盖，斜上伸展，微向上弯，卵形，三角状卵形或三角状，无明显的脊背或下面有纵脊，长6～10毫米。球果卵圆形或椭圆形，长6～10厘米，宽约4厘米，基部宽，上部渐窄或微圆，先端尖或钝，中脉明显或不明显，上面灰绿色，有白粉，有多数气孔线，下面绿色，仅中下部有不整齐的疏生气孔线。雄球花单生枝顶，圆柱形。球果卵形或椭圆形，长6～10厘米，径4.5～7.5厘米；苞鳞楔状倒卵形，两侧具薄翅，先端宽厚，具锐脊，中央有急尖的长尾状尖头，尖头显着的向后反曲；舍庄重林的先端薄，不肥厚；种子椭圆形，两侧具结合而生的膜质翅。　　　　　　裸子植物门松柏纲　　　　　　　', '　　南洋杉又名异叶南洋杉，为南洋杉科、南洋杉属，不但可以作为园景树栽培，在长江流域以北更是有花友将其制作成盆栽观赏。南洋杉的栽培难度并没有想象中的那么简单，小编就为你介绍一下南洋杉的栽培方法。　　南洋杉喜光，需全光照，但忌强光。夏季置于室外树荫或半阴处。长期置于寒冷、阴暗的地方，植株会长得又细又高。9月应移入无霜冻、光照良好的冷室。温度应逐渐变化，10月后理想的温度为5～10℃。有规律地给植株浇水，冬季保持土壤潮湿。夏季盆土过干，冬季水量过大，空气相对温度在60％以下，都会使下层叶子发生软垂。冬季光线太暗或温度过高会造成针叶脱落或枯黄。生长季节每两周施一次无钙肥。一般2～3年在春季换一次盆，以防植株长得过高。　　盆栽用土可用腐叶土、园土加1／4沔沙及少量基肥配制，要求盆土疏松通气。北方盆栽植株可于5月中甸以后搬至室外向阳处、稍遮荫，避免夏季中午阳光直射。生长季节要保持盆土及周围环境湿润，但盆内不能积水。　　9月下旬移回室内，放在向阳处，每半月转一次盆，不使植株因趋光而长斜。在光线较暗的室内摆放不宜过长，一般2－3周后即要移至向阳处。冬季要控制浇水，间千间湿。温度应保持在10度以上。', '　　　　\n一、播种\n　　南洋杉可用播种或扦插进行繁殖。北方栽植的南洋杉很少结籽，常采用扦插繁殖。春季采集侧芽抽出的直立新梢或徒长枝条作插穗（若用侧枝、弱枝作插穗，　\n　二、扦插\n　　播种前最好先破伤种皮，以促进发芽，籽播幼苗直根长，须根少，幼苗移植时易造成死苗，抓好护根、细植、保温、遮荫等技术要点，则能提高幼苗成活率。对断根的幼苗可用清水洗后插于素砂中，适温下1～2周即可从断面重新发根。对断芽断茎带叶的幼苗，可照常定植，成活后经一定', 'http://img.boqiicdn.com/Data/BK/P/imagick37761444814442.jpg', 'http://www.boqii.com/entry/detail/2117.html', '');
INSERT INTO `plant_family` VALUES ('548', '香雪球', 'Sweet Alyssum', 'Lobularia maritima', '庭芥、小白花、玉蝶球', '不容易死', '产地中海沿岸。中国河北山西江苏浙江陕西新疆等省有栽培', 'http://www.boqii.com/entry/photo/2363/0,http://www.boqii.com/entry/photo/2363/5053', '　', '被子植物门 Angiospermae', '双子叶植物纲 Dicotyledoneae', '罂粟目 Rhoeadales', '十字花科 Cruciferae', '香雪球属 Lobularia', '香雪球', 'Lobularia maritima', '', '　　 　　香雪球为多年生草本，基部木质化，但栽培的不论当年生或隔年生均不木质化，高10－40厘米全珠被“丁”字毛，毛带银灰色。茎自基部向上分枝，常呈密丛。叶条形或披针形，长1.5－5厘米，宽1.5－5毫米，两端渐窄，全缘。', '　　株矮而多分枝，开花时会散发阵阵清香，是不知园的优良，也是花坛、花境的镶边材料。现在越来越多的花友将香雪球盆栽栽种在家中，那么人工栽培香雪球应该注意哪些问题呢？　　香雪球原产欧洲及西亚。喜冷凉，忌炎热，要求阳光充足，稍耐阴，宜疏松土壤，忌涝，较耐干旱、瘠薄。喜欢冷凉气候，忌酷热，耐霜寒。喜欢较干燥的空气环境，阴雨天过长，易受病菌侵染。香雪球怕雨淋，晚上保持叶片干燥。最适空气相对湿度为40～60％。　　香雪球扦插后必须保持空气的相对湿度在75～85％。可以通过给插穗进行喷雾来增加湿度，每天1～3次，晴天温度越高喷的次数越多，阴雨天温度越低喷的次数则少或不喷。但过度地喷雾，插穗容易被病菌侵染而腐烂，因为很多种类的病菌就存在于水中。', '　　香雪球喜冷凉、阳光，也耐半阴的环境，其适应性较强，人工栽培难度并不高。但如果阴雨天过长，香雪球则会比较容易受到病菌侵染。　　香雪球用种子、扦插繁殖都可以，但一般多用种子繁殖。北方地区多为春播，一般是3月在温室播种育苗，香雪球种子较一般　　北方地区多为春播，一般是3月在温室播种育苗，香雪球种子较一般花卉种子发芽快，出苗整齐，发芽适温为20℃，约5天出苗，3～4片真叶时定植上盆，6月开花。到夏季炎热时则生长不良，开花很少，此时要剪除已开过的花枝，加强肥水管理，秋季又可再次盛开。华北和南方地区多为秋播，冷床保护地越冬，翌年3月上盆或定植，4月开花。', 'http://img.boqiicdn.com/Data/BK/P/imagick39791451035156.jpg', 'http://www.boqii.com/entry/detail/2363.html', '');
INSERT INTO `plant_family` VALUES ('549', '快刀乱麻', 'Rhombophyllum nelii', '快刀乱麻', '', '不容易死', '产于南非开普省', 'http://www.boqii.com/entry/photo/2434/0,http://www.boqii.com/entry/photo/2434/4981', '　', '被子植物门', '双子叶植物纲', '中央种子目', '番杏科', '快刀乱麻属', '', 'Rhombophyllum nelii', '', '　　 　　快刀乱麻的植株呈肉质灌本状，高20～30厘米，茎有短节，多分技。叶集中在分枝顶端，对生，细长而侧扁，长约1.5厘米，先端两裂，外侧圆弧状，好似一把刀，叶色淡绿至灰绿色。花黄色，直径4厘米左右。', '　　为番杏科快刀乱麻属多肉，是多肉中较为代表性的之一，其叶形独特、花朵鲜艳，非常适合用于盆栽。快刀乱麻的生长旺盛期时冬季，但是不耐寒，所以人工栽培快刀乱麻需要注意其环境。　每1～2年换盆一次，春季进行。换盆时同时换土，盆土选择泥炭土与粗沙混合，在土中加入少量的骨粉。　　肉肉生长期适度浇水，一周一次。夏季温度高，空气湿度较低时需及时水分，也可喷雾增加空气湿度。冬季保持盆土干燥。另外开花期需要适当补充水分，否则花朵极易凋谢。　生长期每月施肥一次。　快刀乱麻花期时，植株孱弱，容易受到蚜虫危害，可用50％灭蚜威2000倍溶液喷杀。快刀乱麻也会受到叶斑病的侵害，叶片出现褐色斑点，可喷洒65％代森锰锌可湿性粉剂600液进行防治。', '快刀乱麻的繁殖可在　　　　快刀乱麻繁殖采用播种与砍头，也可以取侧芽扦插，异花授粉。快刀乱麻群生老桩还是比较耐看的。　　快刀乱麻在番杏科中属于中等肉质的灌木，但栽培较同类型灌木状', 'http://img.boqiicdn.com/Data/BK/P/imagick71201453108152.jpg', 'http://www.boqii.com/entry/detail/2434.html', '');
INSERT INTO `plant_family` VALUES ('550', '美女樱', 'Verbena hybrida Voss', '美女樱', '草五色梅、铺地马鞭草、铺地锦、四季绣球、美人樱', '不容易死', '原产巴西、秘鲁、乌拉圭等地', 'http://www.boqii.com/entry/photo/2004/0,http://www.boqii.com/entry/photo/2004/5523', '', '', '', '', '', '', '', '', '', '　　 　　美女樱全株有细绒毛，植株丛生而铺覆地面，株高10～50厘米，茎四棱；叶对生，深绿色；穗状花序顶生，密集呈伞房状，花小而密集，有白色、粉色、红色、复色等，具芳香。　　　　　　　　　　　　　　　　', '　　美女樱的花期为5－11月，在春秋两季可以说是美女樱的旺季。美女樱的栽种难度并不高，对于废水的要求也不多，但是在夏季就需要注意控制肥水，并且浇水也要注意外界天气来选择浇水周期的长短。　美女樱在生长过程中对水分比较敏感，怕干旱又忌积水。幼苗期盆土必须保持湿润，有利于幼苗生长。成苗后耐旱性加强，如气温高，耗水量大，要注意保证充足水分。若阴雨天较多时，轻者枝蔓徒长细弱，开花减少，重者茎叶逐渐萎蔫，甚至。　光照对美女樱的生长十分重要。美女樱从幼苗生长到开花均需充足阳光，茎叶生长健壮，花枝密集，开花不断，花色鲜艳。若长期处于半阴状态或光照不足，茎叶容易徒长，开花减少，花朵变小，花色不鲜艳。　　美女樱苗期需肥量较少，为了促进美女樱迅速生长，早成苗，缩短苗期，适当施肥必须的。美女樱苗期施肥要以勤施薄施为原则，以免伤根而影响后期。在大面积栽培美女樱时，为促使枝叶充实壮旺，延长开花期，建议多施有机质肥或增施磷钾肥。美女樱生长旺盛期每月应施肥1－2次。　　美女樱枝条呈匍匐性，如不适时合理进行修剪，会影响通风透光而造成基部自然枯死，有利于病虫害滋生，影响其正常生长发育。因此，大面积栽培，对过于密集的枝条应采取适时修剪残花老枝及病虫害枝，每年盛花期后进行重剪一次。', '　　美女樱的适应能力比较强，花期也非常长，可以说是', 'http://img.boqiicdn.com/Data/BK/P/imagick73521441533330.jpg', 'http://www.boqii.com/entry/detail/2004.html', '');
INSERT INTO `plant_family` VALUES ('551', '星点秋海棠', '', '星点秋海棠', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2318/0,http://www.boqii.com/entry/photo/2318/5205', '植物　', '被子植物门', '双子叶植物纲', '目', '秋海棠科', '秋海棠属', '', '', '', '　　 　　星点秋海棠为小灌木，多分枝。茎比较细，高60～100厘米，新枝绿色，老枝紫褐色，枝条先端下垂。叶椭圆状披针形，表面鲜绿色，具光泽，有无数银白色斑点。花朵白绿色。同属常见的栽培', '　　为灌木，且茎较细，为温带，喜欢散射光和温润的环境。但是星点秋海棠的耐寒性不强，所以人工栽培需注意越冬养护。　　土以腐叶土、泥炭土、园土等量混合为好，植株宜放于棚内半阴下或光线明亮处养护。叶片较嫩，容易发生溃烂，因此入夏后应注意遮荫，尽量避免阳光直射而引起叶缘灼伤。　　生长浇水要勤，保持盆土湿润。冬季室温低于15℃时，要严格控制浇水，或用喷雾代替浇水。生长适温为18～21℃，温度过高易引起焦叶。高温季节，要注意周围空气湿度，每天要喷洒2～3次。生长期可每月施一次富含磷、钾的复合肥，或2周施一次稀薄液肥。　　越冬温度不宜低于8℃。越冬期间若不善，如室温低、光线差，植株处于半休眠状态时，浇水或施肥过多，易烂根烂叶。一般地，冬季应将植株放于棚内早晚可见日光处，停肥控水，隔一周可用与室温接近的水淋洗一次叶面。平时要进行适当修剪，以保持优美的株姿及良好的通风透气性。', '　　　　1、播种繁殖可于早春进行，将成熟的种子播于繁殖盆中，内装腐殖土，保持16℃左右和一定湿度，即可生根。当幼苗出现2～3片真叶后，便可移植上盆。　　2、扦插繁殖以5～6月效果为佳，选取植株顶端嫩枝作插条，长约10～15厘米，插入　　3、丛生的', 'http://img.boqiicdn.com/Data/BK/P/imagick56881450084266.jpg', 'http://www.boqii.com/entry/detail/2318.html', '');
INSERT INTO `plant_family` VALUES ('552', '黄绿贝母兰', 'Coelogyne prolifera Lindl.', '黄绿贝母兰', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2444/0,http://www.boqii.com/entry/photo/2444/4972', '植物　　', '被子植物门', '单子叶植物纲', '微子目', '兰科', '贝母兰属', '黄绿贝母兰', 'Coelogyne prolifera Lindl.', '', '　　 　　黄绿贝母兰根状茎稍坚硬，粗5－6毫米，具较短节间，密被革质鳞片状鞘。假鳞茎彼此相距2.5－4厘米，狭卵状长圆形，长2.2－3.7厘米，粗1－1.2厘米，干后略有光泽，顶端生2枚叶，基部具数枚鞘。叶长圆状披针形或近长圆形，长8－13厘米，宽1.6－2.1－厘米，先端渐尖；叶柄长2－2.5厘米。', '　　的整体花瓣细密，但呈现了分裂的状态，这种状态是非常特别的，看着别有一番情趣，观赏价值非常高，受到很多花友的喜爱。　　黄绿贝母兰栽培一般在在春季3－4月或秋季10－11月，花盆以口小、盆深、底孔大的为佳。新从山上挖来的野生苗需理植于瓦盆中，这样)泥易干，通气性好。容易发根，2－3年后方可换人紫砂盆或瓷盆。兰花种植的方法与一般花卉不同，尤其是名种兰花，翻种移盆必须洗根。然后将好的植株放在阴凉通风处晾干，待根部发白并显细小皱纹柔软时，再植入盆中。　　栽培好黄绿贝母兰后，我们要学会简单的它，一般要浇水，浇水在兰花生长盛期，夏季一旦缺水，则盆兰生长不良，兰花需八分干、二分湿。浇水应本着“干则浇，湿则停，适当偏干”的原则。浇水必须浇透，不可浇半截水。　　另外就是要施肥，农家肥是很好的有机肥，但一定要堆放腐熟一年以上才能施用。可用这种肥液对水10－20倍浇施，尽量施在盆沿处，不根部，不沾兰叶。施用化肥时，要注意氮、磷、钾的平衡，并严格控制浓度。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick87811453368041.jpg', 'http://www.boqii.com/entry/detail/2444.html', '');
INSERT INTO `plant_family` VALUES ('553', '月光花', 'Calonyction aculeatum （Linn.） House', '月光花', '天茄儿、夕颜、嫦娥奔月', '不容易死', '原产地可能为热带美洲，现广布于全热带。', 'http://www.boqii.com/entry/photo/2229/0,http://www.boqii.com/entry/photo/2229/5298', '植物　', '被子植物门', '双子叶植物纲', '茄目', '旋花科', '月光花属', '月光花', 'Calonyction aculeatum （Linn.） House', '', '　　 　　月光花为一年生、大的缠绕草本，长可达10米，有乳汁，茎绿色，圆柱形，近平滑或多少具软刺。叶卵形，长10－20厘米，先端长锐尖或渐尖，基部心形，全缘或稍有角或分裂。花大，夜间开，芳香，1至多朵排列成总状，有时序轴之字曲折；萼片卵形，绿色，有长芒，3片外萼片长5－12毫米（除芒），芒较长，内萼片长7－15毫米（除芒），芒较短或无；花冠大，雪白色，极美丽，瓣中带淡绿色，管长7－12厘米，宽约5毫米，管上部不扩张或微扩张，冠檐浅的5圆裂，扩展，直径7－12厘米；花柱和雄蕊伸出花冠外；雄蕊5，花丝圆柱形，着生于管，花药大，基部箭形，淡黄色；花盘环状，厚，肉质；子房长圆锥状；花柱圆柱形，白色；柱头大， 2球状。', '　　在我国各地均有引种栽培，是比较普遍的观花，目前已经由人工广泛栽培了。月光花的生长强健，非常迅速，所以可以作为篱垣布景，别有一番风味。　　　适当浇水，不能过涝；防治鼠害、虫害：可用辛硫磷、拌麦麸子（毒饵）均可；及时锄草，喷施叶面肥；在真叶长到3～4片时开始定心，防止徒长；苗床25～28℃，夜间不低于15℃。　　一般苗龄35～40天，栽前5～7天炼苗；　　1、挖大穴。移栽前挖20cm×20cm大穴，株距1.3～1。6m，亩保苗80～100株左右，每穴施5～7.5kg农家肥和100～250g化肥（二铵、钾肥、镁粉比例为3∶1∶1）做底肥。　　2、人工移栽。移栽前把营养袋浇足水，将苗移植穴中，盖土，并浇足水。同时覆膜，抠眼放苗。也可选择双膜移栽，即移栽后加盖拱膜；　　　1、人工锄草，及时防治病虫害。　　2、结合追肥耢平空垄并铺草。每平方米用稻草或麦秸1kg左右，防止草荒。在主蔓长到50cm左右时，最好结合灌水，每株追施尿素100～250g，追肥不要距主根太近，防止烧根。不要将尿素散落于叶面上，防止烧叶。　　3、顺蔓、掐尖、打杈、人工授粉。顺蔓，每株留两个主蔓。两条主蔓均横向摆在空垄上，可培一次定向土。掐尖：一级分杈，长到3片叶时，开始掐尖，看住并掐调二、三级分杈，主蔓掐尖在8月23日以后。人工授粉：一般甜葫芦每天上午打杈，掐尖，下午16时开始授粉，过了处暑以后就可停止授粉，一般两条主蔓结瓜6～8个。', '　　　　月光花原产美洲热带，喜温暖。湿润气候，不耐严寒；对土壤要求不严，一般土壤都能适应，可以用种子繁殖。　　秋末采种晒干贮藏，来年3～4月播种，露地直播时，幼苗应在真叶长出后再移栽定植，定植时株行距为40～60cm×60～80cm。另外月光花蔓节上易生不定根，所以也可以扦插和压条繁殖。早春播于苗床，幼苗生出3～5片真叶时，即可定植花架或栅栏前任其攀援', 'http://img.boqiicdn.com/Data/BK/P/imagick26091447752942.jpg', 'http://www.boqii.com/entry/detail/2229.html', '');
INSERT INTO `plant_family` VALUES ('554', '翁柱', '', '翁柱', '白头翁', '不容易死', '', 'http://www.boqii.com/entry/photo/2482/0,http://www.boqii.com/entry/photo/2482/4935', '植物　　', '被子植物门', '双子叶植物纲', '', '', '', '', '', '', '　　 　　白头翁为仙人掌科。植株高大，圆柱状。多不分枝，偶有分枝。具棱20～30。刺座大，排列紧密，具细黄刺1～5，刺座上密生白毛，顶部白毛更多更长，好似白发老翁的头部。在原产地植株长到约6米高时才开花。花漏斗形，花瓣白色，中脉红色。其密生的白色长毛，奇态可掬，观赏价值很高。普遍受到', '　　原产于墨西哥的干旱地区，现在被人工栽培，常用于观赏，非常适合在门庭、书房和客室摆放。翁柱有着密生的白毛，在其原产地为大型种，人工栽培翁柱的难度并不高，那么如何才能养好翁柱呢？　　翁柱喜温暖干燥和阳光充足的环境。适应性强，较耐寒，耐干旱，耐高温。喜排水良好含石灰质的沙壤土。冬季不低于5℃。翁柱适应性强，夏季可耐40℃的高温，冬季可耐0℃的低温。植株很慢，4年实生苗约长高8厘米。　　盆栽翁柱的土壤除腐叶土、粗沙和碎砖以外，可加些陈灰墙屑。生长过程中盆土不宜过湿，特别夏季高温和冬季低温时。翁柱属柱状，为防止倒伏或生长弯曲，应设立支柱。其白色绵毛易脏，可在换盆时，用肥皂水冲洗，晾干后上盆，保持白色绵毛整洁。', '　　　　翁柱的繁殖常用播种、扦插和嫁接繁殖。播种，春季采用室内盆播，播后10－12天发芽，幼苗', 'http://img.boqiicdn.com/Data/BK/P/imagick47411454489523.jpg', 'http://www.boqii.com/entry/detail/2482.html', '');
INSERT INTO `plant_family` VALUES ('555', '黄脉爵床', 'Sanchezia nobilis Hook. f.', '黄脉爵床', '', '不容易死', '海南省， 广东省 厄瓜多尔', 'http://www.boqii.com/entry/photo/2288/0,http://www.boqii.com/entry/photo/2288/5237', '　　', '被子植物门 Angiospermae', '双子叶植物纲 Dicotyledoneae', '管状花目 Tubiflorae', '爵床科 Acanthaceae', '黄脉爵床属 Sanchezia', '', 'Sanchezia nobilis Hook. f.', '', '　　 　　黄脉爵床的叶具1－2.5厘米的柄，叶片矩圆形，倒卵形，顶端渐尖，或尾尖，基部楔形至宽楔形，下沿，边缘为波状圆齿，长9－15厘米，宽3.7－5.2厘米，侧脉7－12条。干时常黄色。顶生穗状花序小，苞片大，长1.5厘米，宽8毫米，花萼2.2厘米，花冠5厘米，冠管4.5厘米，冠檐5－6毫米；雄蕊4，花丝细长，伸出冠外，疏被长柔毛，花药2室，密被白色毛，背着，基部稍叉开；花柱细长，柱头伸出管外，高于花药。', '　　的外形非常特殊，但是由于其成株可高达2米，所以很少在室内栽种。并且黄脉爵床适合热带季雨林及雨林区的环境，所以在我国并不多见。　　黄脉爵床喜高温多湿和半阴环境，忌直射阳光，要求疏松、肥沃、水湿环境良好的土壤，不耐寒。在我国广东、海南、香港、云南等地园栽培。原产厄瓜多尔。适合庭园、花坛布置，也适合家庭、宾馆和窗橱摆饰。在我国，黄脉爵床主要分布的城市有：海口、三亚、琼海、高雄、台南、深圳、湛江、中山、珠海、澳门、香港、南宁、钦州北海、茂名、景洪等。', '　　　　黄脉爵床可以采用扦插或分株的方法进行繁殖，其中以扦插繁殖最为常用。分株繁殖可以结合春季换盆进行。扦插繁殖可以选择早春或秋季气温在25－30℃时进行。扦插时选择健壮的枝条，剪取4－5节长，去掉下部叶片和上部叶片的1／3－1／2，插人河沙或', 'http://img.boqiicdn.com/Data/BK/P/imagick32211449221547.jpg', 'http://www.boqii.com/entry/detail/2288.html', '');
INSERT INTO `plant_family` VALUES ('556', '美丽月见草', 'Oenothera speciosa', '美丽月见草', '夜来香、待霄草粉晚樱草、粉花月见草', '不容易死', '原产美洲温带，主要分布在亚热带常绿、落叶阔叶林区。', 'http://www.boqii.com/entry/photo/2244/0,http://www.boqii.com/entry/photo/2244/5281', '　　', '被子植物门', '双子叶植物纲', '()目', '柳叶菜科', '月见草属', '美丽月见草', 'Oenothera speciosa', 'Oenothera speciosa', '　　 　　多年生草本，具粗大主根（粗达1.5厘米）；茎常丛生，上升，长30－55厘米，多分枝，被曲柔毛，上部幼时密生，有时混', '　　美丽)的生长速度比较快，并且还能抑制杂草的生长，人工栽种的难度并不高。由于美丽月见草的外形非常漂亮，现在受到越来越多的花友们的喜爱，那么如何才能养好美丽月见草呢？　　美丽月见草的适应性强，对土壤要求不严，耐寒、耐旱，耐瘠薄，喜光，忌积水，抽蔓开花需要一定的低温刺激。　　美丽月见草庭院栽培在通风敞亮处，疏松肥沃、排水良好的沙壤土地段，最好，也可盆栽摆放阳台观赏，在静夜的月光下，阵阵幽香令人神清气爽。美丽月见草自播能力强，经一次种植，其自播苗即可每年自生，开花不绝。　　美丽月见草对水肥要求不严。一般在栽植前施足有机肥和腐殖质，生长期间通常不需要追肥。对氮肥比较敏感，容易徒长枝叶，水肥过于充足或长时间疏于，容易旺长倒伏并花量减少；一般盛花前追施1次液肥，可以提升开花效果，并促使种子饱满。　　夏季适当浇水，通常在降雨量丰沛的年份不需浇灌，枯水的年份适当浇灌1～2次。入冬前浇灌防冻水，可提高抗旱、耐寒和能力；早春浇透返青水，可促进早日萌发。栽培后期，注意控制水肥，以控制旺长，保持良好景观效果。', '　　美丽　\n　一、播种\n　　美丽月见草每1g种子有10000余粒，自播能力强，发芽适温18～25℃。露地播种春秋皆宜，保护地播种可周年进行，每1m2苗床撒播种子0.3g。将播种地施少量基肥深翻，按照1。5m宽做成平畦，耙平踏实，小水灌透；种子掺2倍细沙充分混合，均匀撒播，覆盖沙土或　\n　二、分株\n　　分株繁殖在整个生长　\n　三、扦插\n　　扦插繁殖于5～6月份最佳，用泥炭和珍珠岩按照2：1比例混合成扦插基质，铺设8cm厚度即可。剪取顶芽保留3～4节，或将健壮嫩枝截成8～10cm的插穗，扦插在基质中，做全光照喷雾', 'http://img.boqiicdn.com/Data/BK/P/imagick58931448271191.jpg', 'http://www.boqii.com/entry/detail/2244.html', '');
INSERT INTO `plant_family` VALUES ('557', '旋风麒麟', 'Euphorbia groenewaldii', '旋风麒麟', '', '未知', '', 'http://www.boqii.com/entry/photo/2490/0,http://www.boqii.com/entry/photo/2490/4838', '　　', '被子植物门', '双子叶植物纲', '大戟目', '大戟科', '大戟属', '', 'Euphorbia groenewaldii', '', '　　 　　旋风麒麟包括极短的主茎在内共高18厘米，全茎粗7厘米。分枝3—7，老株分枝匍匐状，长5—7厘米、直径1.2—3厘米。3棱螺旋状，棱缘强烈地曲折。表皮蓝绿色带暗淡的花纹。棱缘上有类似疣突的突起，长0.5—1厘米，每个突起上有一对0.3—1厘米长的褐色刺。', '　　为大戟属中的小型珍奇种，由于其棱螺旋状在大裁属种类中十分罕见，所以受到很多花友的喜爱，现在也供园作为标本陈列。那么，人工栽培旋风麒麟应该注意哪些问题呢？　　土要求排水良好并有一定肥分，可用腐叶土、园土、粗砂等份混合。春至秋的生长期中可定期浇水。冬季保持盆土干燥，旋风麒麟虽可耐3℃低温，但经常在此低温下茎枝表皮呈红褐色，且会皱缩，因而最好能维持10℃以上并适当浇水。晚春至秋天可在室外培养，生长更为迅速。冬季维持在5℃以上。　　本种有一个广泛栽培的带化变异种春峰。生长比原种更迅速。而带斑锦（白色斑）的带化种春峰锦就很稀有了。', '　　　　人工繁殖旋风麒麟可以用扦插繁殖，从基部切取分枝，干燥数天后插入半潮介质中，保持温暖和半阴条件，生根慢，要有耐心等待。', 'http://img.boqiicdn.com/Data/BK/P/imagick62801455613686.jpg', 'http://www.boqii.com/entry/detail/2490.html', '');
INSERT INTO `plant_family` VALUES ('558', '贝壳花', 'Moluccella laevis', '贝壳花', '领圈花、象耳', '不容易死', '亚洲西部及叙利亚', 'http://www.boqii.com/entry/photo/2279/0,http://www.boqii.com/entry/photo/2279/5246', '', '', '', '', '', '', '', '', '', '　　 　　贝壳花的高度为40－100cm，心状叶对生，具钝齿。贝壳花的种子是三角形的，播下后1周左右出苗，幼苗　　　　　　　　　　　　　　　　　', '　　的外形非常特别，很多花友都因为贝壳花独特的外形而自己栽培。其实贝壳花不但可以用于观赏，它也是一种非常环保的，现在，贝壳花不但盆栽观赏，还常作为的配花。那么贝壳花的栽培过程中应该注意哪些呢？　日照需良好。　贝壳花性喜温暖，生育适温15～25度。　贝壳花栽培土质用肥沃的壤土，排水需良好。贝壳花苗高10～15公分，摘心1次，促使分枝。　贝壳花栽培用土以肥沃、疏松、排水良好的壤土为佳，土质不宜过粘，否则不发棵，生长缓慢。　贝壳花移栽成活后开始施肥，半月一次，开花后停止施肥。为促其分枝，可进行摘心。　长势强健，极少有病虫害发生，但要注意潜叶蝇的危害。为观赏需要，可分期分比播种。', '　　　　贝壳花一般用播种方法进行繁殖，春、夏、秋均可，播种适温为15－25℃，约一周发芽，5－6片真叶时即可移栽。栽培用土以肥沃、疏松、排水良好的壤土为佳，土质不宜过粘，否则不发棵，', 'http://img.boqiicdn.com/Data/BK/P/imagick83321449046924.jpg', 'http://www.boqii.com/entry/detail/2279.html', '');
INSERT INTO `plant_family` VALUES ('559', '半岛玉', '', '半岛玉', '仙巴掌、仙人扇、霸王树、火焰、火掌。', '未知', '墨西哥加利福尼亚半岛', 'http://www.boqii.com/entry/photo/2493/0,http://www.boqii.com/entry/photo/2493/4834', '', '', '', '', '', '', '', '', '', '　　 　　半岛玉的球形壮观，有威武雄壮的强刺，是球形', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick91781455700046.jpg', 'http://www.boqii.com/entry/detail/2493.html', '');
INSERT INTO `plant_family` VALUES ('560', '中斑莲花掌', 'Aeonium tabuliforme f.cristata', '中斑莲花掌', '', '未知', '墨西哥', 'http://www.boqii.com/entry/photo/2494/0,http://www.boqii.com/entry/photo/2494/4833', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '莲花掌属', '莲花掌变种', 'Aeonium tabuliforme f.cristata', '', '　　中斑 　　中斑莲花掌的根茎粗壮，有多数长丝状气生根。叶蓝灰色，近圆形或倒卵形，先端圆钝近平截形，红色，无叶柄。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick51261455700356.jpg', 'http://www.boqii.com/entry/detail/2494.html', '');
INSERT INTO `plant_family` VALUES ('561', '玉牛掌', '', '玉牛掌', '玉牛角', '未知', '非洲南部', 'http://www.boqii.com/entry/photo/2495/0,http://www.boqii.com/entry/photo/2495/4832', '', '', '', '', '', '', '', '', '', '　　 　　玉牛掌喜温暖干燥和阳光充足环境，不耐寒，怕高温，不耐湿但耐干旱。玉牛掌以肥沃、排水良好的沙壤土为好，冬季　　玉牛掌盆栽玉牛掌浇水不需过多，特别在夏季和冬季', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick76211455700560.jpg', 'http://www.boqii.com/entry/detail/2495.html', '');
INSERT INTO `plant_family` VALUES ('562', '仙人镜', 'Prickly Pear', '仙人镜', '郁金香仙人掌、沙漠仙人掌', '未知', '美国', 'http://www.boqii.com/entry/photo/2497/0,http://www.boqii.com/entry/photo/2497/4830', '', '', '', '', '', '', '', '', '', '　　 　　仙人镜从野生到被广泛移入室内栽培，它反映了城市居民选择盆花品种的一种趋势。因楼房面积有限、空气干燥，　　室内盆栽仙人镜，以选择小型、花多的球型种类为宜，栽培中不能认为这类植物耐旱，而忽略对它的正常浇水与施肥。室内栽培，可在窗台上用铅丝与塑料薄膜营造一个高温、高湿的封闭式空间，大多数仙人掌在这样的条件下不仅生长快而且色泽晶莹。　　仙人镜要求排水透气良好、含石灰质的沙土或沙壤土。新栽植的仙人掌先不要浇水，每天喷雾几次即可，半个月后才可少量浇水，一个月后新根长出才能正常浇水。冬季气温低，植株进入休眠时，要节制浇水。开春后随着气温的升高，植株休眠逐渐解除，浇水可逐步增加。每10天到半个月施一次腐熟的稀薄液肥，冬季则不要施肥。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick69631455701042.jpg', 'http://www.boqii.com/entry/detail/2497.html', '');
INSERT INTO `plant_family` VALUES ('563', '玛瑙殿', '', '玛瑙殿', '翠纹卧牛', '未知', '原产非洲南部', 'http://www.boqii.com/entry/photo/2498/0,http://www.boqii.com/entry/photo/2498/4828', '', '', '', '', '', '', '', '', '', '　　玛瑙殿是一款比较经典的多肉植物，很多朋友会觉得它的外表和 　　玛瑙殿喜温暖干燥和阳光充足环境。较耐寒，耐干旱和半阴。宜肥沃、排水好的沙壤土。冬季', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick87281455786713.jpg', 'http://www.boqii.com/entry/detail/2498.html', '');
INSERT INTO `plant_family` VALUES ('564', '鸡冠掌', '', '鸡冠掌', '千羽鹤', '不容易死', '原产墨西哥，现多国均有栽培。', 'http://www.boqii.com/entry/photo/2501/0,http://www.boqii.com/entry/photo/2501/4089', '', '', '', '', '', '', '', '', '', '　　 　　鸡冠掌繁殖以扦插为主，叶插出苗后有一定几率会变回皮氏石莲花。鸡冠掌宜在春天将老株切开扦插，新株对', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick85631455787925.jpg', 'http://www.boqii.com/entry/detail/2501.html', '');
INSERT INTO `plant_family` VALUES ('565', '大卫', 'Crassula lanuginose', '大卫', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2478/0,http://www.boqii.com/entry/photo/2478/4939', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '青锁龙属', '', 'Crassula lanuginose V.pachystemon', 'Crassula lanuginose', '　　 　　大卫，小型种多肉植物。茎细，叶，肉质，圆卵形，或瓜子形，边缘薄，中间鼓起，有点像小型围棋子，对生，绿色，茎叶间会生出新枝叶，形成丛生状。全株有白色毫毛，叶背面的毛较稀松，叶正面的毛更细微，叶缘的毛的排列和长短较整齐，犹如“眼睫毛”，在充足的光照下，或', '　　多肉大卫比较特别的是其叶缘的毛排列长短比较整齐，非常像“眼睫毛”。在光照充足的情况下，大卫的叶片甚至整个植株都会变成红色或紫红色，那么如何养好大卫呢？　　　大卫喜光，喜阳光充足的地方，耐半阴，适温15－25摄氏度，冬季不低于5摄氏度。除冬季放在室内向阳处外，其余都放在室外养护，夏季应适当遮阳。　　　大卫耐干旱，怕水湿，夏季要控制浇水量，避免因为浇水过大而导致，梅雨季节和下暴雨天气，要短暂移至室内，防止暴雨冲洗，或形成积水，同时须加强通风。平时浇水的时候可以每次少浇点水，次数多些，防止过湿、久旱。　　　大卫对土壤的要求不是很高，平时的种植可以用腐叶土、粗沙的混合土，在里面加入少量骨粉和干牛粪即可。', '　　大卫的管理粗放，一般可用小口径的盆来栽培，人工栽培大卫的难度并不高，繁殖一般用扦插的方法。大卫的植株小巧，成活率比较高，是很多多肉爱好者都非常　　大卫', 'http://img.boqiicdn.com/Data/BK/P/imagick74541454404260.jpg', 'http://www.boqii.com/entry/detail/2478.html', '');
INSERT INTO `plant_family` VALUES ('566', '风信子', 'Hyacinth', '风信子', '洋水仙、西洋水仙、五色水仙、时样锦', '不容易死', '', 'http://www.boqii.com/entry/photo/1912/0,http://www.boqii.com/entry/photo/1912/5617', '', '', '', '', '', '', '', '', '', '　　 　　　　　　　　　　　　　　　　　', '　　风信子有被称作“西洋水仙”，风信子的花语为“只要点燃生命之火，便可同享丰盛人生”，也是现在驰名中外的香花。在我国，风信子的栽种也非常普遍，特别到了过年的时候，风信子也是很有名的年宵花。那么风信子究竟应该如何栽培呢？　　风信子的具体栽培方法：花市场供应的有两种，一种是9—10月间供应的，像)干头一样是干鳞茎。另一种是经过培育已有花苞的，这种风信子在春节前买来时，就可以水养，放在室内窗口观赏闻香。对干鳞茎的栽培方法，应拣阳光充足、地势高燥、排水良好之处，并施足基肥（为豆饼屑、骨粉或沤制的有机肥）。在秋冬生长期，再施入磷钾为主的追肥1—2次。　　平时土壤保持微湿，忌过湿或积水，这样到次年3月，一般都能开花。而盆栽的方法，基本和地植的相同，用疏松土每盆1—4个鳞茎，施足基肥，放置室外向阳处，生长期追肥，地区11月份移入室内向阳处，室温保持5—10℃，到3月前后，亦能开花飘香。　　至于开过花后的风信子，能否再度开花？还必须经过下列过程：花谢后剪去枯叶，干藏室内通风处，9月间再地植或盆栽，施入基肥和以后追肥，促使母鳞茎分裂，帮助子鳞茎长大，当培大到一定程度时，才能再开花。', '　　很多朋友栽培风信子往往等到其开过一次花之后就扔了，其实，风信子是可以每年都开花的。并且如果你有兴趣自己繁殖风信子的话也可以自己在家中进行繁殖，一般风信子有分球繁殖和播种繁殖两种方法。', 'http://img.boqiicdn.com/Data/BK/P/imagick7921438766601.jpg', 'http://www.boqii.com/entry/detail/1912.html', '');
INSERT INTO `plant_family` VALUES ('567', '胧月', '', '胧月', '宝石花', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/2472/0,http://www.boqii.com/entry/photo/2472/4945', '　', '被子植物门', '双子叶植物纲', '()目', '景天科', '风车草属', '', '', '', '　　 　　胧月为多年生常绿亚灌木。丛生。多枚叶片在枝顶簇生，排列成莲座状，株型相对同属其他品种较为疏松。茎匍匐或下垂，通常从基部分枝。高度通常不高于30厘米，茎直径约0.8－1.2厘米。叶基生，无柄，肥厚，灰蓝色或灰绿色，阳光充足时呈淡粉红色或淡紫色。花五星形，白色，花朵直径约1.5厘米，乳白色，花朵盛开期为3－4月间。花冠5裂，上有放射状排列的紫红色斑点，雄蕊10，两轮排列，花药鲜红色，中央具5枚淡红色的离生雌蕊，与雄蕊及花冠裂片相映成趣，犹如闪耀的明星。', '　　胧月是非常好养护的多肉品种之一，其株型和', '　　　　胧月的人工繁殖多采用扦插繁殖，在其', 'http://img.boqiicdn.com/Data/BK/P/imagick90891454318229.jpg', 'http://www.boqii.com/entry/detail/2472.html', '');
INSERT INTO `plant_family` VALUES ('568', '爱之蔓', 'Ceropegia woodii', '爱之蔓', '心蔓、吊金钱、蜡花', '不容易死', '原产于南非及津巴布韦', 'http://www.boqii.com/entry/photo/2217/0,http://www.boqii.com/entry/photo/2217/5310', '　　', '被子植物门', '双子叶植物纲', '捩花目', '萝藦科', '吊灯花属', '爱之蔓', 'Ceropegia woodii', '', '　　 　　爱之蔓具蔓性，可匍匐于地面或悬垂，长度可达150－200cm。叶心形，对生，长1.0－1.5cm，宽约1.5cm，叶面上有灰色网状花纹，叶背呈紫红色；叶腋处会长出圆形块茎，称“零余子”，有贮存养分、水分及繁殖的功用。春、夏季时，成株会开出红褐色、壶状的花，长约2.5cm，花后结出羊角状的果实。', '　　的叶片是成串的心形，所以常被当做爱情的象征。爱之蔓有一定的攀爬性，可以悬垂，作为垂盆植物栽培，别有一番风味。但是爱之蔓需要在核实的生长环境下才能变得更漂亮，小编就为你介绍一下如何将爱之蔓养好。　　爱之蔓性喜温暖。光线充足时，其生长繁茂，在散射光的条件下生长更好。夏季忌上午11时至下午4时的强阳光直晒，否则叶片发黄、焦边，影响观赏。但放置环境也不能过阴或完全不见阳光，这样会使茎蔓瘦弱，叶小质薄，也会降低观赏价值。　　爱之蔓喜生于稍湿润的土壤中，亦较耐旱，故盆土以半干半湿、间干间湿为宜。浇水过多，盆土长期过湿，盆内有渍水易引起烂根。在室外培养时，雨季应把其放置在通风避雨处，以防雨淋后盆土过湿，植株沤根而坏死。在室内栽培时，春、秋季应3～4天浇一次水；夏季2～3天浇一次水，天气酷热时，可喷水雾润泽枝叶；冬季应节制浇水，可10～15天浇水一次，保持盆土微湿润即可。如发现蔓梢叶萎蔫时，则是缺水的表现，应及时水分，使植株迅速恢复正常生长。　　喜淡薄，忌施浓肥和单用氮肥。在室内培养，10～15天施一次氮、磷、钾相结合的液肥，每日可向叶面增喷0.1％～0.2％的磷酸二氢钾水溶液，则可使叶色鲜艳、亮丽。　　爱之蔓最适宜的为15～28℃，春秋季是吊金钱的旺盛生长期；夏季气温如超过32℃，则生长停滞，需适当遮荫、通风降低气温。冬季8℃以下，开始掉叶枯萎，在室外可把块茎埋在地下或把盆放在温暖处，翌春会从其小土豆形的块根上萌发出新蔓；如在室内，室温在10℃以上，可不落叶。', '　　　　1、扦插繁殖法：取一对叶子（带一点茎节）或2－3对叶子，自然晾干一周，然后扦插于栽培介质中，浇透水，也可以盖上透明塑料薄膜来提高湿度，约三周就会长出新芽，然后掀去薄膜，让其自然。　　2、高压繁殖法：直接将一段枝条用铁丝固定在介质表面，并保持湿度，也可长成新株。下面的图片有我的高压繁殖，把生长2米长的枝条全部放在介质上繁殖。　　3、零余子繁殖法：直接将长有零余子的枝条剪下，将零余子浅埋入介质中，浇一次透水，两周后即会发根长成新株。　　4、播种繁殖法：选择20度以上的季节进行播种繁殖，最好取当年生种子（萌发力强、出苗率高），播种方法同样可以借鉴', 'http://img.boqiicdn.com/Data/BK/P/imagick81271447406517.jpg', 'http://www.boqii.com/entry/detail/2217.html', '');
INSERT INTO `plant_family` VALUES ('569', '白雪姬', 'Tradescantia sillamontana', '白雪姬', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2307/0,http://www.boqii.com/entry/photo/2307/5217', '', '', '', '', '', '', '', '', '', '　　 　　白雪姬的茎直立或稍匍匐，高15～20厘米，短粗的肉质茎硬而直，被有浓密的白色长毛。叶互生，绿色或褐绿色，稍具肉质，长卵形，叶长约2厘米，宽1厘米，也被有浓密的白毛。小花淡紫粉色，着生于茎的顶部。　　　　　　　　　　　　　　', '　　为多年生肉质草本植物，原产于中南美洲的危地马拉、墨西哥等国，现在在很多地区均有栽培。白雪姬的叶片有浓密的白色，比较特殊，受到很多多肉爱好者的喜爱。　　白雪姬适宜温暖、湿润的环境和充足而柔和的阳光，耐半阴和干旱，不耐寒，忌烈日曝晒和盆土积水。生长适温16～24℃，在此条件下可将植株放在光线明亮又无直射阳光处养护，若光照不足，会使，叶与叶之间的距离拉长，茎、叶上的白毛稀疏，影响观赏；若光线过强，则叶片呈褐色，也影响美观。生长期保持盆土湿润而不积水，空气干燥时可用洁净的水向植株及周围地面喷洒，但水珠不能长时间停留在叶面上，否则会造成叶片。每月施一次腐熟的稀薄液肥或复合肥，但肥量不宜多，以免茎、叶生长过旺，使株形凌乱。　　夏季高温时可适当遮光，并加强通风，否则会因闷热、潮湿导致植株腐烂。冬季放在室内阳光充足处，节制浇水，8～10℃可越冬。由于植株生长较快，栽培中要经常修剪整形，及时将过长的茎剪短，摘除下部发黄枯烂的叶片，以保持株形的整洁美观。因为植株密布长毛，沾上污物后很难清除，因此施肥时要格外小心，防止肥液污染植株。并将花盆放在室内洁净处养护，以避免室外雨淋污染叶片。每年的3～4月换盆一次。　　盆土要求疏松肥沃，具有良好的排水透气性，可用腐叶土2份、园土1份、粗沙或蛭石3份的混合土栽种，并加入少量骨粉作基肥。由于白雪姬的新株比老株更具观赏性，栽培中应经常繁殖新株，对老株进行更新。', '　　　　白雪姬的繁殖可结合换盆进行分株，方法是把', 'http://img.boqiicdn.com/Data/BK/P/imagick31061449740255.jpg', 'http://www.boqii.com/entry/detail/2307.html', '');
INSERT INTO `plant_family` VALUES ('570', '花叶木薯', 'Manibot esculenta cv. Variegata', '花叶木薯', '斑叶木薯', '不容易死', '', 'http://www.boqii.com/entry/photo/2308/0,http://www.boqii.com/entry/photo/2308/5215', '　　', '被子植物门', '双子叶植物纲', '大戟目', '大戟科', '木薯属', '花叶木薯', 'Manibot esculenta cv. Variegata', '', '　　 　　花叶木薯为直立灌木，株高1.5米左右，长块根，根部肉质。叶掌状3～7深裂，裂片披针形，全缘，裂片中央有不规则的黄色斑块。叶面绿色，叶柄红色，花序腋生，有花数朵。', '　　花叶木薯的普及度并不高，但是是非常适合在的观叶。花叶木薯喜温暖和阳光充足的环境，不耐寒，所以人工栽培花叶木薯不宜过干或过湿。　　盆栽花叶木薯，土壤适宜采用疏松、肥沃、排水良好的微酸性土壤。生长期要充分浇水，但盆土湿度不可过大，否则会使根部腐烂。而土壤过干或过干时湿，也可导致植株落叶。冬季落叶，应逐渐减少浇水次数，盆土保持稍干燥。若处于低温潮湿的栽培环境，肉质根易腐烂。栽培过程中，可每月施肥一次，生长旺盛期还应增施2～3次磷、钾肥，可避免枝叶徒长，并可保持叶片瑰丽。　　花叶木薯的生长适温为：3～9月为25～30℃；9～3月为18～20℃，越冬温度要求高于15℃。若室温低于10℃，则可使植株停止生长，且会引起落叶。花叶木薯生长迅速，萌发力强，扦插苗盆栽后高20～25厘米时，需进行摘心，促其多分枝。盆栽植株，宜每年换盆一次，并结合对地上部枝条进行修剪，每盆留3～4主枝即可。压低株型，剪除杈枝和枯枝，使植株保持优美的株型。', '　　花叶木薯是比较适合在室内栽培的观叶　　\n1、扦插繁殖：\n　\n　2、播种繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick91821449740559.jpg', 'http://www.boqii.com/entry/detail/2308.html', '');
INSERT INTO `plant_family` VALUES ('571', '龙鳞', 'Haworthia tessellata', '龙鳞', '蛇皮掌', '可不死', '', 'http://www.boqii.com/entry/photo/2500/0,http://www.boqii.com/entry/photo/2500/4090', '', '', '', '', '', '', '', '', '', '　　其实 　　龙鳞繁殖常用分株和播种繁殖，分株全年均可进行，常在4－5月换盆时，将母株侧旁分生的小植株剥离母体，直接盆栽，刚盆栽的浇水不宜多，以免影响根部恢复，播种一般4－5月采用室内盆播，发芽适温为18－21℃，播后14－21℃发芽，幼苗生长较慢。', '', '', 'http://img.boqiicdn.com/Data/BK/P/imagick26121455787707.jpg', 'http://www.boqii.com/entry/detail/2500.html', '');
INSERT INTO `plant_family` VALUES ('572', '半枝莲', 'Scutellaria barbata', '半枝莲', '并头草、韩信草、赶山鞭、牙刷草', '不容易死', '阿根廷、巴西南部、乌拉圭以及中国大陆等地', 'http://www.boqii.com/entry/photo/2230/0,http://www.boqii.com/entry/photo/2230/5297', '', '', '', '', '', '', '', '', '', '　　 　　半枝莲为多年生草本，半枝莲根茎短粗，生出簇生的须状根。茎直立，高12～35（55）厘米，四棱形，基部组1～2毫米，无毛或在序轴上部疏被紧贴的小毛，不分枝或具或多或少的分枝。花单生于茎或分枝上部叶腋内，具花的茎部长4～11厘米；苞叶下部者似叶，但较小，长达8毫米，上部者更变小，长2～4.5毫米，椭圆形至长椭圆形，全缘，上面散布下面沿脉疏被小毛；花梗长1～2毫米，被微柔毛，中部有一对长约0.5毫米具纤毛的针状小苞片。　　　　　　Scutellaria barbata　　　　　　　　　　　　　　　　　　　　　', '　　半枝莲现在主要分布在阿根廷、巴西南部以及我国大陆的公园等处，原产于南美洲，所以温暖湿润及半荫的环境。人工栽种半枝莲的难度不高。半枝莲全草可入药，所以经济价值比较高，是很多朋友们都喜欢栽种的观花植物。　　具3片叶时移苗或上盆，盆栽时，花盆口径15厘米的每盆栽苗3株，口径20厘米的每盆栽苗5～6株。露地定植的株距为10～15厘米。对土壤适应性极强，但在肥沃疏松而排水良好的土壤中生长最好。露地栽植要避免种植在地势低洼、易积水的地方。盆栽基质可用园土、腐叶土、砻糠灰等材料配制。忌黏重土壤，否则易造成根茎。　　喜温暖，生长适宜温度为20～30.0。不耐寒，最低温度应不低于8°。能耐高温，但30°0以上时不但开花变小，花数也会减少。　　对光照反应敏感，为强阳性花卉。不耐荫蔽，整个生长期都需要充足的光照，才能使植株正常生长与开花。夏季高温天气，正值植株生长与开花的最旺时期，也需给予充足的阳光，植株才能开花茂盛、花色鲜艳。偏阴时植株徒长，开花少而小。如遇多阴或多雨天气，开花会变差，同时容易茎根腐烂。大花只在晴天上午开花，所以称为“半日花”；温度太高的晴天也会提早闭合。　由于肉质的茎叶能贮藏水分，所以具较强的抗旱能力，在较干旱的条件下也能生长与开花。但要使植株能良好生长与开花，也需供给适当的水分。忌过湿和积水，7尺分多时容易引起植株茎叶徒长，甚至烂根。浇水应掌握“不干不浇，涕则浇透”的原则，避免盆土过湿。梅雨期在雨后要及时倒去盆中的积水。　　喜干燥的环境，空气相对湿度不宜大，否则会引起烂茎现象。　　对要求不高，但给予合理的阳水才能生长与开花良好。肥料不足时，植株与花朵均小。苗期需追施2～3次稀薄的氮肥，以使幼苗苗壮和促进分枝。人夏后每半月追施1次氮磷钾结合的肥料，以促使植株的旺盛生长与开花。', '　　　\n　一、种子繁殖：\n　\n　二、分株繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick61151447753372.jpg', 'http://www.boqii.com/entry/detail/2230.html', '');
INSERT INTO `plant_family` VALUES ('573', '尖叶杜英', 'ElaeocarpusapiculatusMasters', '长芒杜英', '', '不容易死', '产于中国云南南部，广东和海南。中南半岛及马来西亚也有分布', 'http://www.boqii.com/entry/photo/2214/0,http://www.boqii.com/entry/photo/2214/5313', '植物界', '被子植物门', '双子叶植物纲', '锦葵目', '杜英科', '杜英属', '长芒杜英', '', 'ElaeocarpusapiculatusMasters', '　　 　　尖叶杜英为乔木，高达30米，胸高直径达2米（据野外采集记录），树皮灰色；小枝粗壮，直径8－12毫米，被灰褐色柔毛，有多数圆形的叶柄遗留斑痕，干后皱缩多直条纹。', '　　四季常绿，树形如塔，花色洁白，由于尖叶杜英的花是倒挂的，非常特别，所以也成为了园林风景树及行道树。那么人工栽种尖叶杜英应该注意哪些问题呢？　　1、温度管理：由于它原产于热带地区，喜欢高温高湿环境，因此对冬季的温度的要求很严，在有霜冻出现的地区不能安全。　　2、光照管理：对光线要求不严，喜欢阳光充足，也耐半荫。　　3、肥水管理：对于盆栽的植株，除了在上盆时添加有机外，在平时的过程中，还要进行适当地肥水管理。　　春、夏、秋三季：这三个是它的生长旺季，肥水管理按照“花宝”——清水——“花宝”——清水顺序循环，间隔周期大约为1～4天，晴天或高温期间隔周期短些，阴雨天或低温期间隔周期长些或者不浇。　　冬季：在冬季休眠期，主要是做好控肥控水工作，肥水管理按照“花宝”——清水——清水——“花宝”——清水——清水顺序循环，间隔周期大约为3～7天，晴天或高温期间隔周期短些，阴雨天或低温期间隔周期长些或者不浇。　　对于地栽的植株，春夏两季根据干旱情况，施用2～4次肥水：先在根颈部以外30～100公分开一圈小沟（植株越大，则离根颈部越远），沟宽、深都为20公分。沟内撒进25～50斤有机肥，或者1～5两颗粒复合肥（化肥），然后浇上透水。入冬以后开春以前，照上述方法再施肥一次，但不用浇水。　　4、修剪：适宜在冬季修剪，在冬季植株进入休眠或半休眠期，要把瘦弱、病虫、枯死、过密等枝条剪掉。', '　　　\n　一、选种：\n　　播种前首先要对种子进行挑选，种子选得好不好，直接关系到播种能否成功。　　1、最好是选用当年采收的种子。种子保存的　　2、选用籽粒饱满、没有残缺或畸形的种子。　　3、选用没有病虫害的种子。　\n　二、\n　　消毒包含两个概念，一个是指对种子进行消毒，另一个是指对播种用基质进行消毒。家庭对种子消毒常用60℃左右的热水浸种一刻钟，然后再用温热水催芽12～24小时。对播种用的基质进行消毒，最好的方法就是把它放到锅里炒热，什么病虫都能烫死。　\n　三、催芽：\n　　用温热水（　　\n四、播种：\n　　对于用手或其它工具难以夹起来的', 'http://img.boqiicdn.com/Data/BK/P/imagick29951447321008.jpg', 'http://www.boqii.com/entry/detail/2214.html', '');
INSERT INTO `plant_family` VALUES ('574', '铭月', 'Sedum nussbaumerianum', '铭月', '', '不容易死', '墨西哥（韦拉克鲁兹市）', 'http://www.boqii.com/entry/photo/2277/0,http://www.boqii.com/entry/photo/2277/5248', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '景天属', '', 'Sedum nussbaumerianum', '', '　　 　　铭月的叶片呈覆瓦状互生，通常形状为披针形或倒卵形，长约1.2－3.0厘米，先端锐利或稍尖，有花距。排列方式似龙骨状。非常肉质多汁。', '　　铭月在不同的环境下会长成不同的和形状，想要铭月不死并不难，但想要铭月变得好看却并非易事。人工栽培铭月需要根据其习性来布置环境，小编就为你介绍一下铭月在栽培过程中需要注意哪些问题。　　铭月植株容易长侧枝，侧枝生长也比较迅速，缺光后植株的叶片会拉长，叶片与叶片间会空开很大的距离，叶片也变的较薄，颜色也不怎么黄，铭月是一个容易长高且徒长的，要想养的叶片紧凑且颜色金黄就需要强光照，不然给点水就徒长了，颜色也就出不来，不过铭月是非常容易养成老桩摆造型的，铭月花开白色，散开的簇状花序，花开五瓣，花朵向上。　　铭月的土壤可用泥炭混合煤渣，比例3：7，铭月是个非常好养的品种，菜园土都可以养的很好，所以没有特别的配土比例。浇水是干透才浇透，不干不浇水。　　春天和秋天是生长期，可以全日照。夏天轻微休眠。通风遮阳，炎热夏季每个月4到5次水，不浇透。以维持植株的正常生长就可以，夏季水太大容易。　　温度低于5度就要逐渐断水，3度以下保持盆土干燥，尽量保持不低于零下3度。这样就可以安全过冬了，寒冷的冬季水分大了会烂根。花友平时浇水的时候尽量浇在土里，叶片倒是可以在天气和通风很多情况下经常洗洗，保持叶片的干净度。其实铭月还是非常好养的，是新手练习的首选品种之一。', '　　　　铭月繁殖主要靠植株侧芽，叶片扦插和砍头，砍头后从残存茎根上长出的新芽来延续后代，且非常容易长侧芽，存活率比较高，叶插可以获得大批的苗，是大棚繁殖的首选，播种还真的没有播过，春季是侧芽爆发的季节，此时繁殖', 'http://img.boqiicdn.com/Data/BK/P/imagick13941449045790.jpg', 'http://www.boqii.com/entry/detail/2277.html', '');
INSERT INTO `plant_family` VALUES ('575', '枫香树', 'Liquidambar formosana Hance', '枫香树', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2095/0,http://www.boqii.com/entry/photo/2095/5432', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '金缕梅科', '枫香树属', '枫香', 'Liquidambar formosana Hance', 'Liquidambar formosana', '　　 　　枫香树落叶乔木，高达30米，胸径最大可达1米，树皮灰褐色，方块状剥落；小枝干后灰色，被柔毛，略有皮孔；芽体卵形，长约1厘米，略被微毛，鳞状苞片敷有树脂，干后棕黑色，有光泽。叶薄革质，阔卵形，掌状3裂，中央裂片较长，先端尾状渐尖；两侧裂片平展；基部心形；上面绿色，干后灰绿色，不发亮；下面有短柔毛，或变秃净仅在脉腋间有毛；掌状脉3－5条，在上下两面均显着，网脉明显可见；边缘有锯齿，齿尖有腺状突；叶柄长达11厘米，常有短柔毛；托叶线形，游离，或略与叶柄连生，长1－1.4厘米，红褐色，被毛，早落。', '　　的叶色在秋季的时候会变成彤红色，是非常优美的秋色叶树种，不但可以作为观赏用树种，还能作为行道树，其树脂还可入药，经济价值非常高。现在还有花友将枫香树做成高贵的，栽培难度并不高。　　枫香树的适应性强，迅速，性喜阳光。根深抗风，耐火烧，萌发力强，多散生于酸性或中性土壤的平地和村落附近。性喜温暖至高温，生长适温为18－－28摄氏度。对二氧化硫，氯气有较强的抗性。　　枫香树对栽培土质要求不严，只要土层深厚，排水良好之地既可栽植。但以湿润的腐殖质壤土或砂质壤土为佳。日照需充足，使用有机肥或复合肥，春，夏季各施一次。盆栽必须修剪徒长枝，并减少施氮肥，促进分枝。', '　　', 'http://img.boqiicdn.com/Data/BK/P/imagick85711444296142.jpg', 'http://www.boqii.com/entry/detail/2095.html', '');
INSERT INTO `plant_family` VALUES ('576', '小冠花', 'Coronilla variaL.', '小冠花', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2350/0,http://www.boqii.com/entry/photo/2350/5067', '植物界', '被子植物门', '双子叶植物纲', '豆目科蝶形花科', '', '小冠花属', '', 'Coronilla variaL.', '', '　　 　　小冠花的自然株丛高25－50cm。根系粗壮，侧根发达，根上具不定芽、有根瘤。叶为奇数羽状复叶，小叶互生，11－27枚长椭圆形或倒卵形。因花序似冠，并且花色多变（即由粉红变为后期的紫红），故得别名多变小冠花。荚果细长如指状，3－12节共长2－3厘米，节易断，每节含1粒种子；种子细长、肾状，黑褐色。', '　　为多年生草本，其适应性强，强健且病虫害较少。小冠花在我国已有二十多年应用历史，在美国则有其实多年应用历史。那么如何才能养好小冠花呢？　　小冠花喜温暖湿润气候，但因其根蘖芽潜伏于地表下20厘米左右处，故抗寒越冬能力较强，在西安绿草期约为220天，在武汉、潜江约为300天以上，基本长绿。　　该草生长需水较多，但因根系发达，在陕西公路坡脚一年可达1.4米，二年竟达4.8米深。每平方米侧根可达百余条，也较抗旱，一般在年降水400－450毫米的地方无灌溉条件也能正常生长。不耐涝，水淹数日后会烂根而全株死亡。　　小冠花苗期生长较慢，如暂不考虑边坡冲刷，加强管护，六个月内可达覆盖率80％以上。为了配合尽快防止水土流失，根据不同的施工和立地条件，配以禾本科草混播，可以在40天内覆盖地表80％以上，小冠花需约两年时间才能全部“吃掉”伴生草种覆盖地表。一旦小冠花覆盖地表将会长期绿草如茵、花色鲜艳。小冠花在陕西省公路上已有十几年历史，并推广到湖南、湖北、河南、河北、山西等地。在美国公路上已有六七十年使用历史，各方面反映良好。', '　　　　每亩用种量0.5－1KG，春', 'http://img.boqiicdn.com/Data/BK/P/imagick31251450776209.jpg', 'http://www.boqii.com/entry/detail/2350.html', '');
INSERT INTO `plant_family` VALUES ('577', '元宝枫', 'Shantung Maple', '元宝枫', '平基槭、华北五角槭、色树、元宝树、枫香树', '不容易死', '', 'http://www.boqii.com/entry/photo/2085/0,http://www.boqii.com/entry/photo/2085/5442', '', '', '', '', '', '', '', '', '', '　　 　　元宝枫为落叶乔木，高达10m，单叶对生，掌状5裂，裂片先端渐尖，有时中裂片或中部3裂片又3裂，叶基通常截形最下部两裂片有时向下开展。花小而黄绿色，花成顶生聚伞花序，4月花与叶同放。翅果扁平，翅较宽而略长于果核，形似元宝。　　　　　　　　　　　　　　　　　　　　', '　　是非常着名的秋季观红叶的树种，为弱阳性，耐半荫，较抗风，但是炎热的地区对于元宝枫的比较不利。元宝枫对于二氧化硫、氟化氢的抗性比较强，吸附粉尘的能力也比较强，是很好的景观树种。　　元宝枫的萌蘖力强，深根性，抗风雪能力较强，植于背风、湿润和有侧方遮荫处更好。在雨季需注意为元宝枫排水，积水会导致烂根。生长保持土壤湿润，入秋保持干燥，以利叶片转红。　　移栽，4年生以上大苗移栽时需带土坨。栽植时栽植穴内施1－1.5千克腐熟堆肥或厩肥，栽后浇足定根水，以后每隔1－2年迫施有机肥1次。休眠期适当定冠修剪，待植株长到3米以上则不必再行修剪。', '　　　\n　一、播种\n　　元宝枫繁殖常用播种、嫁接和扦插的方法。以播种方法为主。播种育苗多在春季，也可在秋季随采随播。秋天当翅果由绿变黄时即可采收，晒于后除去果皮，种子即播，也可干藏　　每亩播种量15公斤至20公斤，条播或撒播均可，播前用40－50C的温水浸种2小时，捞出洗净后与粗砂2倍量掺拌均匀，堆置室内催芽，其上用湿润草帘覆盖，每隔1－2天翻动1次，约15天左右待种子有1／3左右发芽时即可播种。　　一般采用大田开沟垄播，垄距为60－70厘米，播后覆土2厘米厚，稍加镇压，覆草保持苗床湿润，半月后便可出苗。幼苗出土3周后间苗，6－7月份抹侧芽1次。1年生苗木高达lm左右。　　北京地区因冬季干冷，枝梢易受冻害，需在秋季落叶后将苗木移入假植沟中越冬。春季移栽后要注意主干的　\n　二、嫁接\n　　优良　\n　三、扦插\n　　扦插可用半硬枝条，易于生根。扦插一般在5月至6月', 'http://img.boqiicdn.com/Data/BK/P/imagick50931443519165.jpg', 'http://www.boqii.com/entry/detail/2085.html', '');
INSERT INTO `plant_family` VALUES ('578', '宝草', 'Haworthia cymbiformis var.triebnet poelln', '水晶掌', '三角琉璃莲、宝草', '不容易死', '南非', 'http://www.boqii.com/entry/photo/2052/0,http://www.boqii.com/entry/photo/2052/5475', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '百合科', '十二卷属', '水晶掌', 'Haworthia cymbiformis var.triebnet poelln', 'Haworthia cymbiformis', '　　 　　宝草的植株矮小，株高一般5～6厘米。叶片互生，长圆形或匙状，肉质肥厚，生于极短的茎上，紧密排列为莲座状，叶色翠绿色，叶肉呈半透明状，叶面有8～12条暗褐色条纹或中间有褐色、青色的斑块，叶缘粉红色，有细锯齿。顶生总状花序，花极小。是常见的多肉植物之一。', '　　宝草就是我们常说的水晶掌，原产于南非，喜温暖而湿润及半阴的环境，耐干燥，适宜的生长为20－25℃。宝草的植株并不大，并且栽培难度不是很高，小编就为你介绍一下宝草的栽培要点，的朋友可以一起了解。　　宝草喜温暖而湿润及半荫的环境，耐干旱，忌炎热，不耐寒，生长适温为20～25℃，要求肥沃、排水良好的沙质土壤。　　盆栽宜用肥沃的壤土和粗砂各半，酌加少量骨粉的土。它的根系很浅，应采用比较小的浅盆栽植。　　不太好肥，只要每年春季施以磷、钾肥为主的淡液肥l～2次即可。追肥不可将肥液滴洒在叶片上，否则就会出现黄斑。　　由于宝草肉质叶片内贮藏有较多水分，所以平时浇水不宜太勤，生长2～3天浇1次水，保持盆土适度湿润即可。夏季高温炎热时，植株呈现休眠或半休眠状态，此时应予遮荫并节制浇水。如果过阴或浇水过多，则叶片肥厚，颜色单一，植株柔弱，枝干下垂，降低观赏价值。秋凉后即可正常浇水，保持盆土潮润。　　宝草生长适温为20℃至25℃，若气温超过32℃且通风不良时，嫩叶易。冬季室内要求冷凉，以不超过12℃为宜。对阳光比较敏感，在阳光太强处，植株生长不良，呈浅红色。在半阴处的植株，则碧绿透明，宛如晶莹翡翠，十分可爱。', '　　　　水晶掌常以分株法繁殖，将母株分切为几部分，每一部分独立栽植即可。盆栽基质可以用沙2份、草炭土1份的混合土。春秋', 'http://img.boqiicdn.com/Data/BK/P/imagick30931442568396.jpg', 'http://www.boqii.com/entry/detail/2052.html', '');
INSERT INTO `plant_family` VALUES ('579', '锦绣杜鹃', 'Rhododendron pulchrum Sweet', '锦绣杜鹃', '映山红', '不容易死', '中国南方', 'http://www.boqii.com/entry/photo/2324/0,http://www.boqii.com/entry/photo/2324/5198', '植物　', '被子植物门', '双子叶植物纲', '杜鹃花目', '杜鹃花科', '杜鹃属', '', 'Rhododendron pulchrum Sweet', '', '　　 　　锦绣杜鹃高1.5－2.5米；枝开展，淡灰褐色，被淡棕色糙伏毛。叶薄革质，椭圆状长圆形至椭圆状披针形或长圆状倒披针形，长2－5（－7）厘米，宽1－2.5厘米，先端钝尖，基部楔形，边缘反卷，全缘，上面深绿色，初时散生淡黄褐色糙伏毛，后近于无毛，下面淡绿色，被微柔毛和糙伏毛，中脉和侧脉在上面下凹，下面显着凸出；叶柄长3－6毫米，密被棕褐色糙伏毛。', '　　为常绿灌木，成株可高达2米，在我国的江苏、浙江、江西等地均有栽培，是着名的栽培。锦绣杜鹃的栽培变种和品种繁多，成片栽植开花后非常漂亮。　　锦绣杜鹃喜凉爽湿润和阳光充足的环境。耐寒，怕热，耐半阴，不耐长强光暴晒。适温15～28℃，冬季能耐－8℃低温。土壤以肥沃、疏松、排水良好的酸性沙质壤土为宜。产于中国，但至今未见野生。现分布于江苏、福建等地。　　适宜成片栽植，开花时万紫千红，可增添园林的自然景观效果。也可在旁、池畔、草坪边缘丛栽，增添庭园气氛。盆栽摆放宾馆、居室和公共场所，绚丽夺目。', '　　　　扦插繁殖方法：在梅雨季进行。选取半成熟嫩枝，长12～15厘米，去掉基部2～3片叶，留顶端叶片并剪去一半。插条用0.8％吲哚丁酸溶液　　锦绣杜鹃属', 'http://img.boqiicdn.com/Data/BK/P/imagick13721450171647.jpg', 'http://www.boqii.com/entry/detail/2324.html', '');
INSERT INTO `plant_family` VALUES ('580', '红蓼', 'Kiss Me Over The Garden Gate', '红蓼', '荭草、红草、大红蓼、东方蓼、大毛蓼、游龙、狗尾巴花', '不容易死', '', 'http://www.boqii.com/entry/photo/2206/0,http://www.boqii.com/entry/photo/2206/5321', '　', '被子植物门', '双子叶植物纲', '石竹目', '蓼科', '蓼属', '红蓼', 'Polygonum orientale Linn.', '', '　　 　　红蓼是一年生草本。茎直立，粗壮，高1－2米，上部多分枝，密被开展的长柔毛。叶宽卵形、宽椭圆形或卵状披针形，长10－20厘米，宽5－12厘米，顶端渐尖，基部圆形或近心形，微下延，边缘全缘，密生缘毛，两面密生短柔毛，叶脉上密', '　　的适应能力比较强，不但可以做成盆栽观赏用，其果实还有药用，所以红蓼是集药用、观赏及芽菜为一体的，经济价值非常高。人工栽培红蓼可以根据其习性来进行环境的布置及栽种。　　红蓼原产中国、澳大利亚，喜温暖湿润的环境，喜光照充足；宜植于肥沃、湿润之地，也耐瘠薄，适应性强。　　红蓼常生于沟边、河川两岸的草地、沼泽潮湿处。生沟边湿地、村边路旁，海拔30－2700米。适应性很强，喜在水旁湿地。　　红蓼喜温暖湿润环境，土壤要求湿润、疏松，可在屋旁和沟边栽培。当红蓼苗长出2～3片真叶时，匀苗、补苗，每穴有苗2～3株，并行中耕除草、追肥1次。至6月再行中除、追肥1次，以人畜粪水为主。若遇干旱要注意浇水。', '　　　　红蓼常用播种法繁殖，于春天3－4月进行，春季播种繁殖。可自播繁衍，栽培管理简单。　　秋天，当红蓼的种子成熟时，采集其种子，放在干燥的地方，第二年3月将种子撒在需要种植的地方，覆盖2厘米～3厘米的细土，每星期用喷壶洒透水1至2遍。出苗后要间苗株距20厘米左右。干旱', 'http://img.boqiicdn.com/Data/BK/P/imagick85081447149197.jpg', 'http://www.boqii.com/entry/detail/2206.html', '');
INSERT INTO `plant_family` VALUES ('581', '布纹球', 'Euphorbia obesa', '布纹球', 'baseball plant', '不容易死', '南非', 'http://www.boqii.com/entry/photo/2404/0,http://www.boqii.com/entry/photo/2404/5011', '　', '', '', '', '大戟科', '大戟属', '', '', 'Euphorbia obesa', '　　 　　布纹球植株小球形，直径8—12厘米，单生，不产生仔球，球体灰绿，有红褐色纵横交错的条纹，近顶部条纹较密；具阔棱8，上有褐色小钝齿；雌雄异株植物。同属中见于栽培的还有：贵青玉(E.meloformis)，产南非，球形，多单生，但也可从基部长出仔球，具', '　　布纹球的期是夏季，这和很多多肉有很大的不同，所以人工栽培布纹球时需要注意根据其生长习性来制定栽培方法。布纹球的汁白色，有毒，人工栽培时需要注意切勿入口。　　　性喜温暖和阳光充足，过度潮湿和阴暗会造成茎下部生褐斑。　　　　土要求排水良好的素沙土。冬季最好维持5℃以上并适当维持盆土干燥。布纹球配土比较简单，珍珠岩混合了泥炭，加了和煤渣，比例随意，透气为主。　　　　布纹球生长期给水基本是干透再给水，不兜头淋，通风不好容易烂的。春季给水必须，注意天气的变化。', '　　　　布纹球的繁殖用播种，如欲留种，则栽培中要注意雌雄株的搭配及授粉。少水多日照，介质越舒水越好，夏型。原生地的生长环境大都在岩石堆或是树阴下，年雨量大约只有200~300mm，但日夜　　在大戟属', 'http://img.boqiicdn.com/Data/BK/P/imagick11061452244313.jpg', 'http://www.boqii.com/entry/detail/2404.html', '');
INSERT INTO `plant_family` VALUES ('582', '印度橡皮树', 'Ficus elastica Roxb. ex Hornem.', '印度榕', '印度橡皮树、印度榕树、缅树', '不容易死', '原产印度及马来西亚，中国各地多有栽培。', 'http://www.boqii.com/entry/photo/2263/0,http://www.boqii.com/entry/photo/2263/5262', '　　', '被子植物门', '双子叶植物纲', '荨麻目', '桑科', '榕属', '', 'Ficus elastica Roxb. ex Hornem.', '', '　　印度 　　印度橡皮树全株光滑，无比毛，茎秆生气生根，有乳胶汁。叶宽大具长柄，厚革质，具光泽，亮绿色，长椭圆形或矩圆形，先端渐尖，边全缘。幼芽红色，具苞片。侧脉与中肋成直角。新芽生出时，包在淡红色的托叶中，颇美丽。印度橡皮树为常绿大乔木，高达30米，在原产地可高达45米。树冠开展，具气生根，有乳汁。叶厚革质，有光泽，长椭圆形或矩圆形，长15－30厘米，宽7－9厘米。托叶单生，淡红色。花序托成对着生于叶腋，矩圆形，成熟时黄色，长约厘米；雄花、雌花和瘿花生于同一花序托中。', '　　　　1、温度：喜温暖的环境，最低温度13摄氏度。　　2、光线：一些乔木型。较强光照，夏季可放在室外阳光下栽培。另外一些需要部分遮阴，复季遮阴50％左右，冬季温室内不遮阴。在光线比较暗的房间内摆放不宜太久，3－4周后移到光线好的地方恢复栽培。　　3、水分：乔木型的种类需要浇水，每次浇透，盆土变干时再浇；垂吊型的种类需保持盆土湿润，但不能积水。冬季室温低，应减少浇水，保持盆土微潮。　　4、空气湿度：喜欢高湿，在湿度高的环境中许多种类可以生出非常漂亮的气生根。经常向叶面、茎秆上喷水。　　5、换盆：根据需要2年换盆1次，通常在春季进行。树桩盆景需根据每株的形状进行修剪。', '　　印度　　印度橡皮树常用播种和扦插法繁殖。播种繁殖种子收获后需沙藏，翌年3月下旬在露地苗床条播，行距20－25cm。幼苗怕晒，出苗后应搭设苇帘遮阴，第二年可拆掉苇帘，第三年早春苗移栽一次，再培养一年即可出圃。扦插繁殖枸骨的实生苗', 'http://img.boqiicdn.com/Data/BK/P/imagick31881448616851.jpg', 'http://www.boqii.com/entry/detail/2263.html', '');
INSERT INTO `plant_family` VALUES ('583', '榆叶梅', 'Amygdalus triloba', '榆叶梅', '榆梅、小桃红、榆叶鸾枝', '不容易死', '原产中国北部，各地几乎都有分布', 'http://www.boqii.com/entry/photo/2059/0,http://www.boqii.com/entry/photo/2059/5468', '', '', '', '', '', '', '', '', '', '　　 　　榆叶梅短枝上的叶常簇生，一年生枝上的叶互生；叶片宽椭圆形至倒卵形，长2－6厘米，宽1.5－3（4）厘米，先端短渐尖，常3裂，基部宽楔形，上面具疏柔毛或无毛，下面被短柔毛，叶边具粗锯齿或重锯齿；叶柄长5－10毫米，被短柔毛。　　　　　　　　　　　　　　　　　　　', '　　的枝叶茂密，花繁色艳，在园林、公园等处常有栽种，现在也有朋友会将榆叶梅盆栽，或做。榆叶梅的栽培难度并不高，但是不耐水涝，所以在栽培过程中应注意采用中性至微碱性而疏松肥沃的沙壤土为佳。　　栽植可在秋季落叶后至早春芽萌动前进行。如欲移植成龄植株，可在前一年的7一8月，以保留根系完好为度，由两面或三面施以断根，可以使其多长须根，对栽后成活有利。　　栽培中需注意修剪。在幼龄阶段，每当花谢以后应对花枝适当短截，促使腋芽萌发后多形成一些侧枝。当植株进人中年以后，株丛已长得相当稠密，这时应停止短截，将丛内过密的枝条疏剪掉一部分。花谢后要及时摘除幼果，以免消耗营养而影响来年开花。还可在定植以后修剪成小乔木状，由于这种小乔木状树冠主干上的侧枝稠密适度，营养分配更加合理，因此不必再摘除幼果，让成串的果实挂满枝头，鲜红美丽，仍具有一定的观赏价值。花后需施追肥，以利于花芽分化，使来年花大而繁。', '　　榆叶梅为蔷薇科李属落叶灌木，成株的榆叶梅可高达3－4米，一般在春季开花，并且开花时繁花似锦，非常好看。现在也有花友会将榆叶梅盆栽或做　　\n1、嫁接繁殖：\n　\n　2、扦插繁殖：\n　\n　3、分株繁殖：\n　　\n4、压条繁殖：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick10031442829686.jpg', 'http://www.boqii.com/entry/detail/2059.html', '');
INSERT INTO `plant_family` VALUES ('584', '麻叶绣线菊', 'Spiraea cantoniensis Lour.', '麻叶绣线菊', '', '不容易死', '中国、日本', 'http://www.boqii.com/entry/photo/2271/0,http://www.boqii.com/entry/photo/2271/5254', '植物　　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '绣线菊属', '', 'Spiraea cantoniensis Lour.', 'Spiraea cantoniensis', '　　 　　麻叶绣线菊为小枝细瘦，圆柱形，呈拱形弯曲，幼时暗红褐色，无毛；冬芽小，卵形，先端尖，无毛，有数枚外露鳞片。叶片菱状披针形至菱状长圆形，长3－5厘米，宽1.5－2厘米，先端急尖，基部楔形，边缘自近中部以上有缺刻状锯齿，上面深绿色，下面灰蓝色，两面无毛，有羽状叶脉；叶柄长4－7毫米，无毛。伞房花序具多数花朵；花梗长8－14毫米，无毛；苞片线形，无毛；花直径5－7毫米；萼筒钟状，外面无毛，内面被短柔毛；萼片三角形或卵状三角形，先端急尖或短渐尖，内面微被短柔毛；花瓣近圆形或倒卵形，先端微凹或圆钝，长与宽各约2.5－4毫米，白色；雄蕊20－28，稍短于花瓣或几与花瓣等长；花盘由大小不等的近圆形裂片组成，裂片先端有时微凹，排列成圆环形；子房近无毛，花柱短于雄蕊。蓇葖果直立开张，无毛，花柱顶生，常倾斜开展，具直立开张萼片。', '　　麻叶绣线菊开花繁密，盛花期时枝条全被细小的白花覆盖，非常漂亮。现在在路边、草坪、花坛等地都能见到它们的身影，并且观赏价值非常高。麻叶绣线菊不但可以用作观赏，还有一定的药用价值，对于消肿止痛有着很好的治疗效果。　　麻叶绣线菊性喜温暖和阳光充足的环境。稍耐寒、耐阴，较耐干旱，忌湿涝。分蘖力强。生长适温15—24℃，冬季能耐－5℃低温。土壤以肥沃、疏松和排水良好的沙壤土为宜。　　麻叶绣线菊的生长势旺盛，因此比较粗放，对肥水的要求也不高，定植应在落叶期进行，一般需带土栽植。一般在深秋需施1次腐熟的有机肥，就能维持到第2年旺盛生长及开花期。生长期施肥1－2次。花谢后应适当修剪掉一些过密枝和老弱枝，保证具有良好的透光状况。树势较差的植株，可在休眠期进行重修更新，并加施。　　麻叶绣线菊虽不择土壤，但在微酸性的沙质壤土中长势最好；又由于麻叶绣线菊喜肥，故在壤土的配制上尽可能满足以上特性，才能使麻叶绣线)多枝繁。因而应选红壤土7成，腐叶质3成，拌匀。栽植时，透水层上应放入几块蹄片、牛角和适量的骨粉作基肥，覆盖一层壤土，再将扦插的麻叶绣线菊移入盆中；移苗时应小心，力求多带宿土少伤须根，填实土浇透定根水，将盆移至通风阴凉处缓苗半月。　　当麻叶绣线菊开始抽芽，应将盆移到阳光充足通风良好的环境，满足其5小时以上的光照，视其长势开始追肥。追肥不宜过浓，应遵循薄肥勤施的原则，以免烧根。但花前和晚秋可适当重些。当麻叶绣线菊的叶芽长至10厘米左右时，要经常对叶芽进行封顶打杈，并消除基部的蘖芽，这样能使树冠丰满，更具观赏性。', '　　麻叶绣线球的栽培难度并不高，非常适合在园林中做观赏用。在麻叶绣线球的盛花期，其盛开的白色小花会覆盖枝条，非常漂亮。人工繁殖麻叶绣线球可以用播种、扦插和分株的方法，小编就为你简单介绍一下麻叶绣线球的繁殖方法。麻叶绣线球　　\n播种：\n　\n　扦插：\n　\n　分株：\n', 'http://img.boqiicdn.com/Data/BK/P/imagick93971448877187.jpg', 'http://www.boqii.com/entry/detail/2271.html', '');
INSERT INTO `plant_family` VALUES ('585', '猬实', 'Kolkwitzia amabilis Graebn.', '蝟实', '猬实', '不容易死', '分布于山西、陕西、甘肃、湖北。', 'http://www.boqii.com/entry/photo/2314/0,http://www.boqii.com/entry/photo/2314/5209', '　', '被子植物门', '双子叶植物纲', '茜草目', '忍冬科', '蝟实属', '蝟实', 'Kolkwitzia amabilis Graebn.', '', '　　 　　猬实多分枝直立灌木，高达3米；幼枝红褐色，被短柔毛及糙毛，老枝光滑，茎皮剥落。叶椭圆形至卵状椭圆形，长3－8厘米，宽1.5－2.5厘米，顶端尖或渐尖，基部圆或阔楔形，全缘，少有浅齿状，上面深绿色，两面散生短毛，脉上和边缘密被直柔毛和', '　　猬实原产于我国中部，为观赏灌木，有一定的观赏价值，并且对于研究植物区系、古地理和忍冬科系统', '　　　\n　一、播种\n　　播种应在9月采收成熟果实，取种子用湿沙层积贮藏龙卧藏　\n　二、扦插\n　　扦插可在春季选取粗壮休眠枝，或在6～7月间用半木质化嫩枝，露地苗床扦插，容易生根成活。　　\n三、分株\n　　分株于春、秋两季均可，秋季分株后假植到春天栽植，易于成活。　　猬实栽培容易，经过砂藏催芽的种子，在3月下旬至4月上旬条播，半月出苗。', 'http://img.boqiicdn.com/Data/BK/P/imagick92301449825126.jpg', 'http://www.boqii.com/entry/detail/2314.html', '');
INSERT INTO `plant_family` VALUES ('586', '中国芦荟', 'Aloe chinensis Berger', '中国芦荟', '唐芦荟、中华芦荟、芦荟、油葱、象鼻草、斑纹芦荟、草芦苇、龙角', '不容易死', '', 'http://www.boqii.com/entry/photo/2400/0,http://www.boqii.com/entry/photo/2400/5015', '　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '芦荟属', '中国芦荟', 'Aloe chinensis Berger', 'Aloe chinensis', '　　中国 　　中国芦荟的根为须根。茎短，直立。叶簇生顶部，螺旋状排列，有时为二列排列。叶子肥厚，叶片披针形。叶长30-80厘米，叶宽3-16厘米，叶厚2.5-6厘米，叶子先端渐尖，基部略抱茎。叶片浅绿色，有时有浅白色斑点大而明显，随着叶片的生长，斑点逐渐消失，叶缘有刺状齿。花为总状花序，高40-80厘米，花疏散，呈黄色，有时为紫色或带斑点，外有膜质苞片。花被筒状，中部以上6裂，雄蕊6枚，子房上位。果为蒴果，三角形，长约0.8厘米。花期7～8月。', '　　可以说是人们最熟悉的多肉植物了，由于中国芦荟对于美容养颜有着很好的作用，所以很多朋友都会在家中饲养。但是，想要中国芦荟养好却不是那么容易，中国芦荟在夏季会有一个短暂的休眠期，在这个时期就需要注意控制浇水量，避免中国芦荟烂根死亡。　　　春季栽植或翻盆按士。旺盛的植株一般每1-2年换1次盆，并选择大一号陶盆。盆土要用排水良好、不积水的疏松土壤，一般采用泥炭上或腐殖土加1/3河沙和少量基肥配制而成的作基质。刚上盆的幼苗要控制水分，待缓过苗后再进行正常管理。栽时要特别注意不要栽得太深，不能把最下部的叶片埋入土中，以叶片腐烂。对无茎的芦荟，栽种时在盆面与叶片接触的部分铺一层粗沙。我国除华南、西南地区可地栽外，其他地区多温室盆栽。　　　芦荟喜光，可置于室外阳光充足处，也可稍有遮荫，阳光越足，叶子越美丽，花也越丰富。室内应摆放在南窗台，尽量给以充足光照。芦荟适宜生长温度为20-30℃。秋末入室，冬季室内温度应保持在5℃以上，最低不能低于3℃，但要防止霜冻。　　　　芦荟喜温暖、干燥的环境，抗旱能力强，但生长旺盛期春、夏、秋三季要适当多浇水，经常保持盆土湿润，但不能积水。若因积水，盆土变黏，要及时按盆，并去掉旧土，以免根系腐烂。盛夏时有短的休眠期，应放在通风的半阴处，控制浇水。冬季要少浇水，当盆土大部分变干时再浇水。生长期每月施2-3次腐熟的稀薄液肥。冬季停止施肥。', '　　中国　　分生繁殖在芦荟整个　　扦插繁殖是利用不带根主茎和侧枝的下端可以发生不定根的特性，分离繁殖芦荟新的植株。芦荟扦插气温25—28℃为宜。土温较气温高2-4℃时，可促进发根。气温低下18℃时抑制发根。扦插土壤不宜过湿，空气相对湿度以80%一90%为宜。扦插初期庇适当遮荫，当根系大量发生后，可逐渐给予充足的阳光。于生长期采取生长充实的主茎或侧枝，在通风干燥处晾晒，待切口稍干燥后再插入土壤中。扦插不宜太深，不倒即成。', 'http://img.boqiicdn.com/Data/BK/P/imagick48741452155827.jpg', 'http://www.boqii.com/entry/detail/2400.html', '');
INSERT INTO `plant_family` VALUES ('587', '红粉台阁', 'Echeveria runyonii cv', '红粉台阁', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2394/0,http://www.boqii.com/entry/photo/2394/5021', '', '', '', '', '', '', '', '', '', '　　 　　红粉台阁植株的颈部粗壮，会随着', '　　红粉台阁是)的中大型园艺，其叶片呈莲座型密集排列，成株的株径可达到10cm以上。人工栽培红粉台阁的难度并不高，但是想要红粉台阁更漂亮的话就需要给予充足的光照。　　红粉台阁需要接受充足日照叶色才会艳丽，株型才会更紧实美观，叶片才会肥厚。日照太少则叶色浅，叶片排列松散，叶片变薄。粉红台阁是中大型植株，随着生长的状态须每1~2年换盆一次，盆径可以比株径大1~2寸，这样可促进植株成长。介质一定要乾燥后才浇水，可以每季度施用长效肥一次。　　露天养，一旦温度高于35度，就会移到明亮的散射光下慢慢断水，整个夏季的少水或不给水，到了9月中旬温度下来了，就开始恢复浇水，适应了露天环境的粉红台阁夏天还是可以正常生长的，休眠不太明显。冬季如果温度能够保持0度以上，都是可以给水的，0度以下就要断水，否则就容易冻伤。　　冬季虽然寒冷，可也不是一个冬季都不给一点水，也会在适当的时候微微给点水在植株的根部，切勿喷雾或给大水，叶心水分停留太久，容易引起。春季温度上升后就可以慢慢恢复正常给水。　　粉红台阁还是非常好养的一个品种，四季中除了夏季要注意适当遮阳，其他都可以全日照。土壤用的是泥炭混合了颗粒的煤渣河沙等，土表铺设干净的浮石，配土以透气为主。', '　　　　红粉台阁在强光与昼夜温差大或冬季低温期叶色会深红，弱光则叶色浅蓝。叶缘常会显现粉红色。叶面上覆有微白粉，老叶白粉掉落後呈光滑状。夏季开花，穗状花序长度可达20㎝以上，开橘色钟形花朵。红粉台阁的繁殖采用枝插法与叶插法，全年都可以进行。以叶插为主，也可以扦插。', 'http://img.boqiicdn.com/Data/BK/P/imagick92511452070420.jpg', 'http://www.boqii.com/entry/detail/2394.html', '');
INSERT INTO `plant_family` VALUES ('588', '醉鱼草', 'Buddleja lindleyana Fortune', '醉鱼草', '闭鱼花，痒见消，鱼尾草，樚木，五霸蔷', '不容易死', '西南及江苏、安徽、浙江、江西、福建、湖北、湖南、广东等地。', 'http://www.boqii.com/entry/photo/2195/0,http://www.boqii.com/entry/photo/2195/5332', '植物　', '被子植物门', '双子叶植物纲', '捩花目', '马钱科', '醉鱼草属', '醉鱼草', 'Buddleja lindleyana Fortune', 'Buddleja lindleyana', '　　醉 　　醉鱼草为灌木，高1－3米。茎皮褐色；小枝具四棱，棱上略有窄翅；幼枝、叶片下面、叶柄、花序、苞片及小苞片均密被星状短绒毛和腺毛。叶对生，萌芽枝条上的叶为互生或近轮生，叶片膜质，卵形、椭圆形至长圆状披针形，长3－11厘米，宽1－5厘米，顶端渐尖，基部宽楔形至圆形，边缘全缘或具有波状齿，上面深绿色，幼时被星状短柔毛，后变无毛，下面灰黄绿色；侧脉每边6－8条，上面扁平，干后凹陷，下面略凸起；叶柄长2－15毫米。', '　　醉鱼草花朵繁茂，花香优雅，是公园常见的优良观赏。由于醉鱼草的全株有小毒，将其捣碎后投入河中能够使活鱼麻醉，便于捕捉，故此命名。醉鱼草在园林绿化中可以用来装点山石、庭院等，也可以用作切花。　　醉鱼草喜温暖湿润气候和深厚肥沃的土壤，适应性强，但不耐水湿。醉鱼草抗逆性强、耐严寒酷暑，、节水耐旱。在气温高达40℃及－15℃的情况下，可正常，安全，能忍受－30℃的低温。互叶醉鱼草叶片暂时性萎蔫系数为1.292％，极耐干旱，在年降水量180～400毫米的地区每年灌溉3到4次，400毫米左右地区每年灌水1至2次，即可生长开花，是节水耐旱的良好观赏植物。　　醉鱼草生长期粗放，不需防寒等越冬保护措施；病虫害少，可减少成本及对环境的污染；发枝力强，耐修剪，一般宜在花后进行修剪；极少施肥，在定植前施腐熟的基肥即可。', '　　醉　　醉鱼草以5、6月　　用木片把河沙划开一道深5厘米的沟，将蘸过生根剂的插穗摆放整齐后覆沙，拍实喷水。扦插　　在生根前每天喷水2次，以便降温保湿，保持棚内温度28℃左右，相对湿度90％以上。5月、6月份约20天生根，7月、8月份2周开始生根。生根后控制水分，注意通风，根据生根情况，揭去拱棚。炼苗一周后移栽。', 'http://img.boqiicdn.com/Data/BK/P/imagick28241446802781.jpg', 'http://www.boqii.com/entry/detail/2195.html', '');
INSERT INTO `plant_family` VALUES ('589', '金鱼草', 'Snapdragon， Dragon', '金鱼草', '龙头花、狮子花、龙口花、洋彩雀', '不容易死', '原产地中海，广西南宁有引种栽培。', 'http://www.boqii.com/entry/photo/2160/0,http://www.boqii.com/entry/photo/2160/5367', '', '', '', '', '', '', '', '', '', '　　金 　　金鱼草为多年生直立草本，茎基部有时木质化，高可达80厘米。茎基部无毛，中上部被腺毛，基部有时分枝。叶下部的对生，上部的常互生，具短柄；叶片无毛，披针形至矩圆状披针形，长2－6厘米，全缘。总状花序顶生，密被腺毛；花梗长5－7毫米；花萼与花梗近等长，5深裂，裂片卵形，钝或急尖；花冠颜色多种，从红色、紫色至白色，长3－5厘米，基部在前面下延成兜状，上唇直立，宽大，2半裂，下唇3浅裂，在中部向上唇隆起，封闭喉部，使花冠呈假面状；雄蕊4枚，2强。　　　　　　　　　　　　　　', '　　金鱼草为多年生草本，常作一二年生栽培。花期在5－6月。由于金鱼草的栽培难度并不高，并且花色鲜艳，花型特别，深受人们的欢迎，很多花友都会盆栽金鱼草，放置在家中改善家居环境。　　金鱼草原产南欧地中海沿岸及北非。耐寒，不耐酷暑，能耐半阴。喜疏松、肥沃、排水良好的土壤，要求pH5.5－7.0。为相对性长日照植物，晚生种对长日照敏感，长日照明显地促进花芽分化，但对花芽的影响不大。温度与花芽分化无直接关系，但对株高、花穗和花数有明显影响。生育适温为15－20℃，夜温不低于5℃。现蕾后如遇较低温度，较大花蕾会受寒害。为多年生草本花卉，常作一二年生栽培。　　金鱼草为喜光性草本。阳光充足条件下，植株矮生，丛状紧凑，生长整齐，高度一致，开花整齐，花色鲜艳。半阴条件下，植株生长偏高，花序伸长，花色较淡。对光照长短反应不敏感，如花雨系列金鱼草对日照长短几乎不敏感。春化阶段，高温对金鱼草不利，开花适温为15℃至16℃，有些品种温度超过15℃，不出现分枝，影响株态。金鱼草对水分比较敏感，不能积水，否则根系腐烂，茎叶枯黄凋萎。金鱼草为喜光性草本，阳光充足条件下，植株矮生，丛状紧凑，生长整齐，高度一致，开花整齐，花色鲜艳；半阴条件下，植株生长偏高，花序伸长，花色较淡。对光照长短反应不敏感，如花雨系列金鱼草对日照长短几乎不敏感。喜排水良好、富含腐殖质、肥沃稍粘重土壤，中性或碱性尤佳。', '　　金　\n　一、适时播种\n　　金鱼草可用播种和扦插法繁殖，但以播种繁殖为主，播种通常以9月中旬为宜。播种基质用　\n　二、播后管理\n　　播种后的管理，主要是水分管理，浇水要均匀，不可使盆面过干过湿。夜间将玻璃掀去，使之通风透气，白天再盖好，防止水分蒸发。种子播后7、8天就可萌芽出土。幼苗出土后可掀去玻璃，使之接受光照。', 'http://img.boqiicdn.com/Data/BK/P/imagick45541446087242.jpg', 'http://www.boqii.com/entry/detail/2160.html', '');
INSERT INTO `plant_family` VALUES ('590', '花叶芋', 'Caladium bicolor （Ait.） Vent.', '五彩芋', '', '不容易死', '原产南美亚马逊河流域', 'http://www.boqii.com/entry/photo/2162/0,http://www.boqii.com/entry/photo/2162/5365', '', '', '', '', '', '', '', '', '', '　　花叶芋学名五彩芋，为多年生常绿草本 花叶芋 　　花叶芋的叶柄光滑，长15－25厘米，为叶片长的3－7倍；叶片表面满布各色透明或不透明斑点，背面粉绿色，戟状卵形至卵状三角形，先端骤狭具凸尖，后裂片长约为前裂片的1／2，长圆状卵形，钝，1／3－11／5联合，弯缺深、尖或钝，前裂片I级侧脉下部的几水平伸出，上部的2对上升，集合脉与边缘稍远离，后裂片基脉相交成60度角。　　　　　单子叶植物纲　天南星科　　　　　', '　　就是我们常说的五彩芋，为多年生草本，有块茎。值得注意的是，花叶芋的块茎扁球形，有毒，误食后悔出现喉舌麻痹的。人工栽种时需要注意避免误食。　　花叶芋喜高温、多湿和半阴环境，不耐寒。期6～10月，适温为21～27℃；10月至翌年6月为块茎，适温18～24℃。生长期低于18℃，叶片生长不挺拔，新叶萌发较困难。气温高于30℃新叶萌发快，叶片柔薄，观叶期缩短。块茎休眠期如室温低于15℃，块茎极易腐烂。土壤要求肥沃、疏松和排水良好的腐叶土或泥炭土。土壤过湿或干旱对花叶芋叶片生长不利，块茎湿度过大容易腐烂。　　花叶芋喜散射光，不宜过分强烈，烈日暴晒叶片易发生灼伤现象，叶色模糊、脉纹暗淡，观赏性差。如光线不足，叶彩斑变暗，叶徒长而显软弱。如遮荫过长，叶片柔嫩，叶柄伸长，叶色不鲜，叶柄容易折断。　　喜阳光，不宜过分强烈。如光线不足，叶彩斑变暗，叶徒长而显软弱。　喜水湿。春夏两季需大量浇水。　　不耐寒，生长适温为25－30℃，最低不可低于15℃，气温22℃块茎抽芽长叶，降至12℃时，叶片枯黄。　生长期每周施肥1次，氮、磷、钾搭配施用，以氮肥为主。　　要求土壤疏松、肥沃、排水良好。', '　　　　\n一、播种\n　　花叶芋在采种后需立即播种，花叶芋种子不耐贮藏，否则发芽率很快下降。幼苗阶段叶片呈绿色，到出现一定数目叶片后叶面开始呈现彩斑。组培繁殖，采用MS培养基加1毫克／升激动素、2，4－D　　种子因彩叶芋种子不耐储藏，播种繁殖要在彩叶芋种子采收后立即进行，否则会大大降低发芽率。　　\n二、分株\n　　分株彩叶芋常用分株繁殖。4～5月在块茎萌芽前，将块茎周围的小块茎剥下，若块茎有伤，则用草木灰或硫磺粉涂抹，晾干数日待伤口干燥后盆栽。　　分割块茎如果块茎较大、芽点较多的母球可进行分割繁殖。用刀切割带芽块茎，待切面干燥愈合后再盆栽。无论是分割繁殖还是分株繁殖，室温都应保持在20℃以上，否则栽植块茎易受潮而难以发芽，反而造成', 'http://img.boqiicdn.com/Data/BK/P/imagick19991446109584.jpg', 'http://www.boqii.com/entry/detail/2162.html', '');
INSERT INTO `plant_family` VALUES ('591', '大王黛粉叶', 'Le roi Dieffenbachia', '大王黛粉叶', '', '不容易死', '', 'http://www.boqii.com/entry/photo/2303/0,http://www.boqii.com/entry/photo/2303/5221', '　', '被子植物门', '', '', '', '', '大王黛粉叶', '', '', '　　大王黛粉叶又名 　　大王黛粉叶为多年生常绿草本。茎粗壮，直立，高达2米。盆栽时株高有1米左右。叶片大，长椭圆形，深绿色，有光泽，沿中脉两侧有乳白色条纹和斑点。常见栽培的暑白黛粉叶是大王黛粉叶的一个优良栽培', '　　大王的叶片较大，水分蒸发较快，所以生长期需要较多的水量。的耐阴性较强，非常适合在室内栽种，如果光照过多，叶片表面则会变粗糙，色泽不协调，观赏价值变低。　　大王黛粉叶株高1～2米，在巨大的绿色叶片上生有不规则的白色斑点或条纹。世界着名的室内盆栽。泥炭土或腐叶土盆栽。生长期两周左右施液体肥一次；经常保持盆土中有充足水分。喜半阴和湿润环境。忌强光直晒，春、夏、秋三季遮阴50％左右；经常向植株周围洒水，增加空气湿度。喜高温，怕寒冷；生长适温18～30℃，应在16℃以上。', '　　大王　　大王黛粉叶多采用扦插繁殖。扦插一般于4～6月进行，取顶端茎长约10～15厘米作插穗，剪去下部叶片，将切口处涂以木炭土和沙等体积混合的基质中，置于较荫蔽处，保持21～24℃温度，插后约半个月开始生根，一个月后即可上盆。', 'http://img.boqiicdn.com/Data/BK/P/imagick81151449652972.jpg', 'http://www.boqii.com/entry/detail/2303.html', '');
INSERT INTO `plant_family` VALUES ('592', '红花酢浆草', 'Oxalis rubra', '红花酢浆草', '花花草、夜合梅、大花酢浆草、三夹莲、铜锤草', '不容易死', '巴西及南非好望角', 'http://www.boqii.com/entry/photo/2235/0,http://www.boqii.com/entry/photo/2235/5292', '　　', '被子植物门', '双子叶植物纲', '牻牛儿苗目', '酢浆草科', '酢浆草属', '', 'Oxalis，shamrock，sorrel', '', '　　 　　红花酢浆草为多年生草本，株高10－20cm，地下具球形根状茎，白色透明。基生叶，叶柄较长，三小叶复叶，小叶倒心形，三角状排列。花从叶丛中抽生，伞形花序顶生，总花梗稍高出叶丛，花期4－10月。花与叶对阳光均敏感，白天、晴天开放，夜间及阴雨天闭合。叶、叶柄及花梗均含大量有机酸，pH在1左右，口尝有明显酸味，蒴果。', '　　原产于巴西，所以阴湿的环境，由于红花酢浆草不耐寒，所以在较寒冷的地区只能温室栽培。人工栽培红花酢浆草的难度并不高，盆栽或地载的方式均可，小编就为你介绍一下红花酢浆草栽培的。　　栽植以二月下旬至三月上中旬为最佳时间，以叶片长出，叶柄短于1cm为好。栽植以后，即现绿色。多盆栽也可地栽。　　盆栽植株除随株形增大而每年换盆外，也要更新土壤，过于拥挤的植株要结合分株繁殖。要注意及时清除枯黄叶片和花后的花柄。每年在翻盆换土时加入一定量的基肥，以磷、钾为主。期要追旅稀薄豆饼水，并注意追肥后用清水重新叶片，叶部勿滞留肥分，否则易烧叶。　　地栽的栽植方式可满铺、散铺。土壤耙平后，将分成2cm大小的红花酢浆草用工具埋入土中，栽植全部结束后，浇一遍透水。地栽植株也要在生长几年后挖出地下部分进行“间苗”或疏苗。在冬季要灌足冻水。土壤疏松时要进行轻微镇压。', '　　　　\n1、分株繁殖\n　　红花酢浆草根茎繁殖力很强，很容易分生。可全年进行。一株多年生老株可以分离出十多株球茎。分生新株栽植得当可很快回恢复长势，抽生新叶。秋前分株当年即可开花。　　\n2、播种繁殖\n　　种子成熟后易崩裂，很难采摘，要掌握好时机及时采收。成熟的种子呈棕褐色，较', 'http://img.boqiicdn.com/Data/BK/P/imagick15331447840759.jpg', 'http://www.boqii.com/entry/detail/2235.html', '');
INSERT INTO `plant_family` VALUES ('593', '金焰绣线菊', 'Spiraea x bumalda cv.Gold Flame', '金焰绣线菊', '', '不容易死', '原产地美国，北京1990年4月从美国引种。现中国各地均产。', 'http://www.boqii.com/entry/photo/2233/0,http://www.boqii.com/entry/photo/2233/5294', '植物　', '被子植物门', '双子叶植物纲', '蔷薇目', '蔷薇科', '绣线菊属', '金焰绣线菊', 'Spiraea x bumalda cv.Gold Flame', 'Spiraea x bumalda', '　　 　　金焰绣线菊为落叶小灌木，株高60～110cm，冠幅90～120cm，老枝黑褐色，新枝黄褐色，枝条呈折线状，不通直，柔软。冬芽小，有鳞片，单叶互生，边缘具尖锐重锯齿，羽状脉。叶长0.8～3.0cm，宽0.5～1.6cm，叶柄0.2～0.4cm。', '　　为落叶灌木，由于其叶色有丰富的季相变化，并且花期长，花良多，已经成为了观赏价值较高的新优小灌木。人工栽种金焰绣线菊的难度并不高，小编就为你整理了金焰绣线菊的栽种要点，的朋友可以一起了解。　　　两季均可进行。一般以地栽观赏为主。应选在阳光充足、通风良好之处，挖穴蘸浆栽植成活率较高。在荫蔽的环境中则生长不良。　　　　州地区可露地。在光照充足及20－25℃温度条件下生长发育良好。冬季低于－25℃温度时会发生冻害，甚至导致。　　　　种前施足基肥，一般施腐熟的粪肥，深翻树穴，将与土壤拌均匀。栽植后浇透水。绣线菊怕水大，水大易烂根，因此平时保持土壤湿润即可。绣线菊喜肥，生长盛期每月施3－4次腐熟的饼肥水，花期施2－3次磷、钾肥（磷酸二氢钾），秋末施1次越冬肥，以腐热的粪肥或厩肥为好，冬季停止施肥，减少浇少量。　　　　以季为好。早春于萌芽前剪去干枯枝、过密枝、病弱枝、老化枝，使株形美观，花繁叶茂，植株旺盛生长。', '　　金焰绣线菊的花叶　\n　1、扦插季节\n　　在乌鲁木齐、昌吉、玛纳斯等地区7月上旬盛花期过后，结合整形修剪进行扦插繁殖。一般选择在无风的清晨、傍晚或阴天进行扦插较好。　\n　2、整地准备扦插床\n　　扦插地点选择背风向阳、干净整洁、用水方便的地方，选用干净河沙做基质，做成长10－12m，宽1－1.2m，田埂高25～30cm的扦插床，床内铺一层河沙，厚度15～20cm，整平床面，并在床面上方1.5－2m处打架覆盖透光度10％～30％的遮阳网。　\n　3、插穗准备\n　　结合整形修剪，选择当年生半木质化且无病虫害的健壮枝条，枝条基部粗0。2cm以上，剪成10cm左右的插穗，插穗的下切口剪成平滑的平面或斜面，并剪去插条下部5～7cm处的叶片，因金焰绣线菊属皮孔生根类型，操作时切忌撕裂插穗表皮，保留顶端4－6片叶子，用500mg·kg－1的α－NAA溶液或50～200mg·kg－1。的ABT1号生根粉溶液速蘸插条基部，插条蘸溶液的深度2－3cm。　　\n4、扦插方法\n　　扦插前用0.5％', 'http://img.boqiicdn.com/Data/BK/P/imagick31771447840409.jpg', 'http://www.boqii.com/entry/detail/2233.html', '');
INSERT INTO `plant_family` VALUES ('594', '黄槐', 'Cassia surattensis', '黄槐决明', '黄槐，粉叶决明，黄槐决明', '不容易死', '', 'http://www.boqii.com/entry/photo/2170/0,http://www.boqii.com/entry/photo/2170/5358', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '苏木科', '决明属', '黄槐决明', 'Cassia surattensis', '', '　　 　　黄槐为灌木或小乔木，高5－7米；分枝多，小枝有肋条；树皮颇光滑，灰褐色；嫩枝、叶轴、叶柄被微柔毛。叶长10－15厘米；叶轴及叶柄呈扁四方形，在叶轴上面最下2或3对小叶之间和叶柄上部有棍棒状腺体2－3枚；小叶7－9对，长椭圆形或卵形，长2－5厘米，宽1－1.5厘米，下面粉白色，被疏散、紧贴的长柔毛，边全缘；小叶柄长1－1.5毫米，被柔毛；托叶线形，弯曲，长约1厘米，早落。　　花瓣鲜黄至深黄色，卵形至倒卵形，长1.5－2厘米；雄蕊10枚，全部能育，最下2枚有较长自认花丝，花药长椭圆形，2侧裂；子房线形，被毛。', '　　为常绿小乔木或灌木，成株后可高达4－5米，虽然几乎全年开花，但是花盛期为3－12月。黄槐在日落后，叶片会闭合，进行运动，而冬季的11月至隔年2月则为落叶期。　　黄槐为阳性，耐半阴，耐旱，不抗风，喜光，喜高温多湿气侯，要求深厚而排水良好的土壤，以砂壤土为最好；耐旱、耐热，快速，缺点是根浅风强则易倒。黄槐喜高温高湿、光照，不耐寒。2℃～5℃易受冻害，在华南北部正常年份可越冬。耐土壤干旱，也耐水湿，喜肥。　　黄槐可以带土移植，移植时可施基肥，成活后无需特殊，修剪成小乔木状。每年可施肥1～2次。花期特长，开花时节，花色金黄，非常适宜作冬暖地区的树及行道树。北方常在温室种植。　　1、适时扦插和截干上盆，在冬末初春，趁黄槐叶芽未萌动之前，剪取枝或根扦插和截干上盆，因这时黄槐处于积累养分和半休眠状态，这是上盆成功和提高成活率的关键。　　2、注意遮荫和经常浇水。特别要注意第一次萌芽后加强管理，防止脱水萎缩，要认识到第2次长新芽才算真正成活。　　3、上盆后的黄槐应先放于凉爽处，约10天后再逐渐移到阳光充足的地方，进行正常管理。', '　　黄槐几乎全年开花，花大并且鲜黄色，非常漂亮。黄槐可用播种、根插及扦插法三种方法进行繁殖。由于黄槐的种子比较容易获得，所以更常采用的是播种繁殖法。　　\n一、播种繁殖法\n　　春播，因种皮有细胞紧密结合的栅栏层，透水性差，播种前，用始温85－90度的水浸种24小时，余硬粒再　\n　二、根插法\n　　冬末或春初，切取粗壮的黄槐根约15cm节段进行扦插，无须遮荫，保持土壤湿润，约1个月后其根就能成活并可上盆。成活率高达90％。黄槐根插法，不但充分利用和增加了扦插繁殖材料，还可根据黄槐根部的不同形态制成黄槐　\n　三、扦插法\n　　在冬末初春，黄槐叶芽未萌动之前，把黄槐的枝干切成约20cm长的节段进行扦插，扦插后要注意遮荫，保持土壤湿润。约2个月后，扦插黄槐的枝条已生根成活，此时可陆续上盆，上盆后把它放于阴凉地方1－2周，再逐渐移到阳光充足的地方，以后扦插上盆的黄槐各项', 'http://img.boqiicdn.com/Data/BK/P/imagick48311446199042.jpg', 'http://www.boqii.com/entry/detail/2170.html', '');
INSERT INTO `plant_family` VALUES ('595', '玉翁', 'Mammillaria hahniana', '玉翁', '', '不容易死', '原产墨西哥', 'http://www.boqii.com/entry/photo/2171/0,http://www.boqii.com/entry/photo/2171/5357', '', '', '', '', '', '', '', '', '', '　　 　　玉翁为多年生肉质草本。植株单生，圆球形至椭圆形，体色鲜绿。高度20厘米以下，球径15厘米以下，具13～21个圆锥形的疣状突起，呈螺旋形排列的棱，疣腋间有15～20根3～4厘米长的白毛，新刺座有白色茸毛，白色刚毛状辐射周刺30～35枚，尖端褐色的中刺2～3枚。春季桃红色小型钟状花围绕球成圈开放，花径1～1.5厘米。　　　　　　石竹目　　　　　', '　　原产于墨西哥，为仙人掌科乳突球属植物。春天，玉翁会有桃红色的小花围绕球成一个圈，非常特别，也深受仙人掌爱好者的喜爱。那么如何才能养出漂亮的玉翁呢？　　玉翁性喜光照充足，球体在充分光照下，越发红艳喜人，但夏季仍应稍予遮荫；宜排水良好的肥沃壤土。习性耐干，怕寒冷，繁殖和栽培方法与金琥、绯牡丹相同。为盆栽观赏的植物。　　如盆土过湿，光线过弱，温度过高，都不利其。盆土宜用沙，壤土，泥煤苔，细砾，比例为2：1：1：1。平时生长适温24～26℃。冬天一般要入室，只要室内能保持5～6℃的温度，便可安全越冬。当室内气温接近0℃时，要注意也寒，除控制浇水外，白天必须放于向阳窗口，晚上要注意保暖。在生长期间浇水也不要过多，需要让沙土完全干透，平均3到4星期浇一次水，浇水不能沾到球体，但长期缺水或供水不足也影响其生长。喜欢淡肥，可半年施一次释稀的肥。', '　　玉翁的栽培难度并不高，但是玉翁原产于墨西哥，所以人工栽培的时候需要注意浇水量，以免过量浇水导致玉翁　\n　一、播种\n　　播种繁殖在4～6月进行，发芽　\n　二、扦插\n　　室外扦插以4～10月月为宜，夏季高温多雨不能扦插。但在温室一年四季均可扦插。扦插基质用河沙加上少量锯。以饱满充实的子球作插穗，若子球太幼小，易腐烂。插穗的切面要光滑，切面上涂木炭粉或硫磺粉后放阴凉处，晾2～3天，待汁干、切面收缩后即可扦插。插时不要插得太深，切口稍入土为宜。插后放半阴处，并喷水，以保持土壤湿润，40天左右即可生根成活。　\n　三、嫁接\n　　砧木用仙人球或', 'http://img.boqiicdn.com/Data/BK/P/imagick90261446454870.jpg', 'http://www.boqii.com/entry/detail/2171.html', '');
INSERT INTO `plant_family` VALUES ('596', '桃叶珊瑚', 'Aucuba chinensis Benth.', '桃叶珊瑚', '青木、东瀛珊瑚', '不容易死', '中国、越南、日本', 'http://www.boqii.com/entry/photo/2172/0,http://www.boqii.com/entry/photo/2172/5356', '植物　', '被子植物门', '双子叶植物纲', '伞形目', '山茱萸科', '桃叶珊瑚属', '', 'Aucuba chinensis Benth.', 'Aucuba chinensis', '　　 　　桃叶珊瑚高3－6（－12）米；小枝粗壮，二歧分枝，绿色，光滑；皮孔白色，长椭圆形或椭圆形，较稀疏；叶痕大，显着。冬芽球状，鳞片4对，交互对生，外轮较短，卵形，其余为阔椭圆形，内二轮外侧先端被柔毛。叶革质，椭圆形或阔椭圆形，稀倒卵状椭圆形，长10－20厘米，宽3.5－8厘米，先端锐尖或钝尖，基部阔楔形或楔形，稀两侧不对称，边缘微反卷，常具5－8对锯齿或腺状齿，有时为粗锯齿；叶上面深绿色，下面淡绿色，中脉在上面微显着，下面突出，侧脉6－8（－10）对，稀与中脉相交近于直角；叶柄长2－4厘米，粗壮，光滑。', '　　是耐阴植物，所以夏季的高温和暴晒会让桃叶珊瑚晒伤甚至死亡。桃叶珊瑚对于烟尘和大气污染的抵抗性强，是很好的园林绿化材料，小编就为介绍一下桃叶珊瑚的栽培方法及注意事项。　　桃叶珊瑚盆栽可放置在阳台或室内。如放在室外，夏季要防止烈日曝晒，还要保持土壤的湿润和进行遮阳，否则，叶片容易枯焦。若遇连续多雨的或空气闷热时，一定要注意排水通风，不然枝叶易患白绢病。盆的大小要和植株的大小相适应。用园土2份、腐叶土1份及砻糠灰0.5份混合后的土壤作较好。移栽宜在春季或雨季进行。期每月施1次20％腐熟饼肥水或人粪尿、秋季增施磷、钾肥1－2次，这样，可使叶色油绿光亮，观赏性更强。', '　　桃叶珊瑚栽培难度较低，　　桃叶珊瑚常用扦插繁殖和播种繁殖。扦插繁殖，以5－6月期间最好，选用当年生健壮充实的桃叶珊瑚枝条。基部带有少许2年生枝条，长约15厘米，顶端留2片叶，插人沙床内。桃叶珊瑚枝条插后需遮荫，适时浇水，保持一定的空气湿度和　　桃叶珊瑚也可采用水插法，简单方便，成活率高。对于扦插难以成活的其他桃叶珊瑚变种，可用实生苗作砧木进行嫁接繁殖。播种繁殖，冬季果实成熟，去掉果肉洗清后沙藏。春季播种，因种子有生理后熟期，当年出苗较少，第2年大量出苗。', 'http://img.boqiicdn.com/Data/BK/P/imagick40031446455506.jpg', 'http://www.boqii.com/entry/detail/2172.html', '');
INSERT INTO `plant_family` VALUES ('597', '五爪金龙', 'Palmate－leaved Morning Glory', '五爪金龙', '槭叶牵牛、番仔藤、台湾牵牛花、掌叶牵牛、五爪龙', '不容易死', '', 'http://www.boqii.com/entry/photo/2119/0,http://www.boqii.com/entry/photo/2119/5408', '　', '被子植物门', '双子叶植物纲', '管状花目', '旋花科', '番薯属', '五爪金龙', 'Ipomoea cairica （L.） Sweet', 'Ipomoea cairica', '　　 　　五爪金龙为多年生缠绕草本，全体无毛，老时根上具块根。茎细长，有细棱，有时有小疣状突起。叶掌状5深裂或全裂，裂片卵状披针形、卵形或椭圆形，中裂片较大，长4～5厘米，宽2～2.5厘米，两侧裂片稍小，顶端渐尖或稍钝，具小短尖头，基部楔形渐狭，全缘或不规则微波状，基部1对裂片通常再2裂；叶柄长2～8厘米，基部具小的掌状5裂的假托叶（腋生短枝的叶片）。聚伞花序腋生，花序梗长2～8厘米，具1～3花，或偶有3朵以上；苞片及小苞片均小，鳞片状，早落；花梗长0.5～2厘米，有时具小疣状突起；萼片稍不等长，外方2片较短，卵形，长5～6毫米，外面有时有小疣状突起，内萼片稍宽，长7～9毫米，萼片边缘干膜质，顶端钝圆或具不明显的小短尖头；花冠紫红色、紫色或淡红色、偶有白色，漏斗状，长5～7厘米；雄蕊不等长，花丝基部稍扩大下延贴生于花冠管基部以上，被毛；子房无毛，花柱纤细，长于雄蕊，柱头2球形。蒴果近球形，高约1厘米，2室，4瓣裂。种子黑色，长约5毫米，边缘被褐色柔毛。', '　　', '　　　　五爪金龙可以通过播种或扦插法繁殖，5月份播种最为合适，覆土1厘米，5～6天可发芽。双叶展开时即可分苗。繁育系统的研究表明五爪金龙是自交不亲和植物，其种子仅能通过异花授粉获得。　　五爪金龙通常以种子繁殖，种子量大，发芽率高，繁殖容易，', 'http://img.boqiicdn.com/Data/BK/P/imagick55391444815681.jpg', 'http://www.boqii.com/entry/detail/2119.html', '');
INSERT INTO `plant_family` VALUES ('598', '锦带花', 'Oldfashioned Weigela', '锦带花', '锦带、五色海棠、山脂麻、海仙花', '不容易死', '', 'http://www.boqii.com/entry/photo/2132/0,http://www.boqii.com/entry/photo/2132/5395', '', '', '', '', '', '', '', '', '', '　　 　　锦带花属落叶灌木，高达1－3米；幼枝稍四方形，有2列短柔毛；树皮灰色。芽顶端尖，具3－4对鳞片，常光滑。叶矩圆形、椭圆形至倒卵状椭圆形，长5－10厘米，顶端渐尖，基部阔楔形至圆形，边缘有锯齿，上面疏生短柔毛，脉上毛较密，下面密生短柔毛或绒毛，具短柄至无柄。　　　　　　　　　　　　　　　　　　　　', '　　的迅速并且花期非常长，其花色鲜艳明亮，是很多花友都非常的花卉品种。锦带花对于有毒气体有着较强的抗性，非常适合在工矿区栽植。那么，人工栽种锦带花需要注意哪些呢？　　锦带花原生与中国、朝鲜和日本。喜凉爽湿润和阳光充足的环境。适应性很强，耐半阴和干旱。生长适温15～20℃，冬季能耐－15℃低温。土壤以肥沃、疏松和排水良好的沙质壤土为宜。　　锦带花喜光、耐寒。早春定植时每株施1－1.5千克腐熟肥，以后隔年秋季于根际穴施或沟施1次有机肥，舂早时适时浇水。对春旱与春寒敏感，易干梢，故花前应剪除千枯枝条，盛花后及时剪除花枝，以促进枝条生长。老枝寿命短，需从基部重剪更新。栽培中常见四线盲蝽、康氏粉蚧及卷足蜡蚧、吹绵蚧和棕轮心圆蚧危害，可分别喷洒40％乐果、乳油2000倍液及50％马拉松乳油1500－2000倍液。', '　　　　\n1、分株：\n　\n　2、扦插：\n　\n　3、压条：\n　\n　4、播种：\n　　锦带花的', 'http://img.boqiicdn.com/Data/BK/P/imagick68981445332762.jpg', 'http://www.boqii.com/entry/detail/2132.html', '');
INSERT INTO `plant_family` VALUES ('599', '红稚儿', 'Crassula pubescens', '红稚儿', '', '不容易死', '原产地位于墨西哥', 'http://www.boqii.com/entry/photo/2327/0,http://www.boqii.com/entry/photo/2327/5094', '', '', '', '', '', '', '', '', '', '　　红稚儿为景天科、青锁龙属多肉 红稚儿 　　红稚儿为多年生肉质草本植物，植株丛生，有细小的分枝，茎肉质，　　　　　　　　　　　　　　　　　　　　　　', '　　红稚儿为多年生肉质草本植物，喜欢温暖干燥且阳光充足的环境，耐半荫，无明显休眠期。当红稚儿在光照充足的情况下，会变成火红的颜色，非常抢眼。那么红稚儿应该如何栽培呢？　　红稚儿最好养在全日照的阳光房里，期需保持土壤湿润，避免积水。土壤用煤渣混合泥炭、少量珍珠岩，比例大概5：4：1，土表铺设小石头。红稚儿能耐零下4℃左右的低温，是室内的，非露天，再低叶片的顶端生长点就会出现冻伤，干枯，只要冻伤不太厉害来年会在枯萎处重新萌发新侧枝。整个冬季基本断水，5度以下就要开始慢慢断水。夏季高温时整个植株或完全停止，这个时候要通风良好且适当遮光，避免曝晒，节制浇水，不能长期雨淋，以免植株。红稚儿在养殖过程中需经常修剪，剪去过乱的枝条，以保持株形的漂亮体态。是生长比较迅速的青锁龙品种之一。', '　　　　红稚儿的繁殖可以用叶插与砍头，一般就是砍头，取', 'http://img.boqiicdn.com/Data/BK/P/imagick91781450257475.jpg', 'http://www.boqii.com/entry/detail/2327.html', '');
INSERT INTO `plant_family` VALUES ('600', '鸡冠花', 'Cockscomb Flower、COCKSCOMB', '鸡冠花', '鸡髻花、老来红、芦花鸡冠、笔鸡冠、小头鸡冠、凤尾鸡冠', '不容易死', '原产亚洲 热带，中国南北各地区', 'http://www.boqii.com/entry/photo/2284/0,http://www.boqii.com/entry/photo/2284/5241', '', '', '', '', '', '', '', '', '', '　　 　　鸡冠花为一年生直立草本，高30－80cm。全株无毛，粗壮。分枝少，近上部扁平，绿色或带红色，有棱纹凸起。单叶互生，具柄；叶片长5－13cm，宽2－6cm，先端渐尖或长尖，基部渐窄成柄，全缘。中部以下多花；苞片、小苞片和花被片干膜质，宿存；胞果卵形，长约3mm，熟时盖裂，包于宿存花被内。种子肾形，黑色，光泽。　　　　　　　　　　　　　　　　　　　　　　', '　　鸡冠花又叫鸡公花等，为芜科青箱属的一年生草本。鸡冠花在我国栽培已有上千年的历史了，也越来越多，那么，人工栽培鸡冠花应该注意哪些呢？　　鸡冠花原产于印度、东南亚热带亚热带地区，性喜高温而空气干爽环境，适生为20～30度，不耐寒凉，需光照长而充足，要求含腐殖质疏松肥沃的沙质土壤，不耐瘠薄。可用适量一般农家肥作基肥。鸡冠花繁殖可用播种繁殖，高棵型种宜在早春温室或阳畦播种，一般露地播种宜在5月中旬。播种筱土宜薄，以看不见种子为度，幼苗长出1～2片真叶时分植。苗期起大土佗倒畦移植一两次，蹲苗促发侧根，使植株茁壮。移植不可散佗。　　鸡冠花的浇水不宜过多，以免徒长。但高温期要求水分充足。同时应防土壤干燥和湿热积涝。施肥鸡冠花在生长过程中，必须充分控水控肥，在花蕾形成时追肥，否则会造成徒长。盆栽临近花期可追施稀薄液肥1－2次。', '　　　　鸡冠花可以选择种子繁殖法，清明时选好地块，施足基肥，耕细耙匀，整平作畦，将咱子均匀地撒于畦面，略盖严种子，踏实浇透水，一般在气温15－－20℃时，10－－15天可出苗。夏播于芒种后，抢旱灭苍茌，也可与白芍，牡丹或其它作物套种，亩用种一斤。苗高2寸，按行距1尺，株距8寸间苗，间下的苗可移载其它田块，移载后一定要浇水。幼苗期一定要除草松土，不太干旱时，尽量少浇水。苗高尺许，要施追肥一次。封垅后稍适当打去老叶，开花抽穗时，如果天气干旱，要适当浇水，雨季低洼处严防积水。抽穗后可将下部叶腑间的花芽抹除，以利养分集中于顶部主穗', 'http://img.boqiicdn.com/Data/BK/P/imagick56591449133906.jpg', 'http://www.boqii.com/entry/detail/2284.html', '');
INSERT INTO `plant_family` VALUES ('601', '银合欢', 'Horse Tamarind', '银合欢', '白合欢', '不容易死', '原产热带美洲，现广布于各热带地区，如海南，台湾，云南等。', 'http://www.boqii.com/entry/photo/2329/0,http://www.boqii.com/entry/photo/2329/5089', '　', '被子植物门', '双子叶植物纲', '蔷薇目', '含羞草科', '银合欢属', '银合欢', 'Leucaena glauca （L.） Benth.', '', '　　 　　灌木或小乔木，高2－6米；幼枝被短柔毛，老枝无毛，具褐色皮孔，无刺；三角形，小。羽片4－8对，长5－9（－16）厘米，叶轴被柔毛，在最下一对羽片着生处有黑色腺体1枚；小叶5－15对，线状长圆形，长7－13毫米，宽1.5－3毫米，先端急尖，基部楔形，边缘被短柔毛，中脉偏向小叶上缘，两侧不等宽。头状花序通常1－2个腋生，直径2－3厘米；苞片紧贴，被毛，早落；总花梗长2－4厘米；花白色；花萼长约3毫米，顶端具5细齿，外面被柔毛；花瓣狭倒披针形，长约5毫米，背被疏柔毛；雄蕊10枚，通常被疏柔毛，长约7毫米；子房具短柄，上部被柔毛，柱头凹下呈杯状。荚果带状，长10－18厘米，宽1.4－3厘米，顶端凸尖，基部有柄，纵裂，被微柔毛；种子6－25颗，卵形，长约7.5毫米，褐色，扁平，光亮。花期4－7月；果期8－10月。', '　　为灌木或小乔木，大约在公元1600年以前传入菲律宾，18世纪印尼和非洲把银合欢作咖啡、可可、金鸡纳和胡椒等作物的荫蔽树或氮来源树种。现在银合欢的作用非常广，经济价值也比较高。　　银合欢原产于热带地区，喜温暖湿润的气候条件，最适为25—30℃，12℃，低于10℃，高于35℃，停止生长，0℃以下叶片受害脱落，–3—–4.5℃时，植株上部及部分枝条枯死，–5—–6℃时地上部枯死。翌春，仍有部分植株抽芽生长。　　银合欢属阳性树种，稍耐荫，在无荫蔽条件下生长最好，对日照要求不太严格，在华南诸省区均可开花结实，广东，广西、海南生长最好。湖北武昌冬季枯萎，但也可收到部分种子，但种子质量较差。　　银合欢根系发达，一年生植株根系达1—2m，5年生可达5m以上。近地表侧根着生直径2—20mm，多浅裂，粉红色根瘤。由于根系发达能吸收土层深处的水分，耐旱能力强。在年降雨量1000—3000mm地区生长良好，但也能在250mm地区生长。能耐南方旱季少雨条件，数月无雨，仍能存活。不耐水渍，长时间积水生长不良。　　银合欢对土壤要求不严。最适合于种植在中性或微碱性（pH6.0—7.7）的土壤，在缝隙中也能生长。据报道，在PH7。2的石灰岩土壤上生长较好。18个月龄，株高4.3m，比pH5—5.5红壤上种植的株高多2倍。当表土pH5.5以下时，则根不能生长。　　在酸性土壤上种植的银合欢，早花、早实、早衰。耐盐能力中等，当土壤含盐量为0.22—0.36％时，仍能正常生长。耐高铝低铁，但锰过高（550ppm以上）生长受阻。据报道，在全氮含量为0.1％、速效磷6.5ppm、速效钾137ppm的土壤环境中种植，3月龄株高1.4m，日增长1.5cm，单株干重80g，而全氮，速效磷，速效钾为前者的46％、71％、57％的土壤上种植，株高及日增长量仅为前者的52％，单株干重为前者的33％，说明银合欢在肥沃的土壤上生长效果最好。', '　　银合欢的经济价值非常高，耐旱能力较强，非常适合作为荒山造林树种，此外，银合欢的叶片可作绿肥及家畜饲料。人工栽培银合欢的难度并不高，繁殖可用移栽法或直播法。　\n　一、移栽法\n　　1、苗床整地　　翻耕后除净杂草，起畦，畦辐1.5～2.0米×8～10米，施适量基肥，酸性重的土壤（PH5。5以下）每亩加施石灰50～100公斤。　　2、种子　　用热水（82℃）浸泡3～5分钟，或沸水（100℃）浸泡50－100秒钟，凉干拌以银合欢根瘤菌种制成丸衣化种子。　　3、播种　　气温稳定在15℃以上时，在苗床上开行条播经处理的银合欢种子，株行距1O×35厘米，覆土2～3厘米。播后保持土壤湿润一周内即出苗。如不作苗床，也可用营养杯育苗。　　4、移栽　　苗木高0.2～1.0米时可以移植，以穴植效果最好，穴径60厘米，深50厘米，施适量磷肥、石灰及有机肥，株行距60～80×100～150厘米。移植应在阴雨天或浇足定根水。　　5、　　苗木定植后前期　\n　二、直播法\n　　适用于建植大面积人工收割地或放牧地，用手播或机器撒播，但要处理好地面（', 'http://img.boqiicdn.com/Data/BK/P/imagick4981450257920.jpg', 'http://www.boqii.com/entry/detail/2329.html', '');
INSERT INTO `plant_family` VALUES ('602', '黄花夹竹桃', 'Thevetia peruviana', '黄花夹竹桃', '酒杯花、台湾柳、柳木子、相等子、大飞酸子、黄花状元竹、断肠草', '不容易死', '原产于南美洲、中美洲及印度，现广泛栽植于热带及亚热带地区', 'http://www.boqii.com/entry/photo/2362/0,http://www.boqii.com/entry/photo/2362/5054', '　', '被子植物门', '双子叶植物纲', '龙胆目', '夹竹桃科', '黄花夹竹桃属', '黄花夹竹桃', 'Thevetia peruviana （Pers.） K. Schum.', 'Thevetia peruviana', '　　黄花 　　黄花夹竹桃为乔木，高达5米，全株无毛；树皮棕褐色，皮孔明显；多枝柔软，小枝下垂；全株具丰富乳汁。花大，黄色，具香味，顶生聚伞花序，长5－9厘米；花梗长2－4厘米；花萼绿色，5裂、裂片三角形，长5－9毫米，宽1.5－3毫米；花冠漏斗状，花冠筒喉部具5个被毛的鳞片，花冠裂片向左覆盖，比花冠筒长：雄蕊着生于花冠筒的喉部，花丝丝状；子房无毛， 2裂，胚珠每室2颗，柱头圆形，端部2裂。花期5－12月，果期8月－翌年春季。有白花‘Alba’', '　　黄花夹竹桃在我国长江流域以南地区可露地栽培，在北方只能盆栽观赏，室内越冬，以免植株冻伤甚至。黄花夹竹桃喜光好肥，但不耐水湿，树体受害后较容易恢复。　　黄花夹竹桃的适应性强，栽培管理比较容易，无论地栽还是盆栽都比较粗放。在地栽的地方，移植需在春季进行，移植时应进行重剪。黄花夹竹桃生长迅速，多呈丛生状，一般在6月间，宜将过密枝、过长枝从基部剪除。对于树势过强的树，9月间还应再进行一次修剪，以保持枝与枝的适当空间。主要病害有黄花夹竹桃褐斑病、丛枝病、细菌性瘿疣病等，可在发病初期喷洒或甲基托布津等药剂。害虫主要有黄花夹竹桃紫蝶、黄花夹竹桃蚜、橘棉蚧、褐软蚧、网纹绵蚧等，可在幼虫或若虫期喷洒敌百虫或敌敌畏等药剂。　　盆栽黄花夹竹桃，除了要求排水良好外，还需肥水充足。春季萌发后需进行整形修剪，对植株中的徒长枝和纤弱枝，可以从基部剪去；对内膛过密枝，也宜疏剪一部分，使枝条分布均匀，树形保持丰富。　　1～2年换盆一次，换盆应在修剪后进行。夏季是黄花夹竹桃生长旺盛和开花时期，需水量大，每天除早晚各浇一次水外，如见盆土过干，应再增加一次喷水，以防嫩枝萎蔫和影响花朵寿命。9月以后要扣水，抑制植株继续生长，使枝条组织老熟，增加养分积累，以利越冬。越冬的温度需维持在8～10℃，低于0℃，即要落叶。黄花夹竹桃系喜肥，盆栽除施足基肥外，在生长期每月应追施一次。', '　　黄花　　黄花夹竹桃以扦插繁殖为主，也可用压条等法繁殖。扦插，在春季和夏季都可进行。春季剪取一二年生枝条，截成15～20厘米的段，20根左右捆成一束，浸于清水中，入水深为茎段的1／3，每1～2天换同', 'http://img.boqiicdn.com/Data/BK/P/imagick60721450949713.jpg', 'http://www.boqii.com/entry/detail/2362.html', '');
INSERT INTO `plant_family` VALUES ('603', '串叶松香草', 'Silphium perfoliatum L.', '串叶松香草', '串叶草', '不容易死', '原产北美，由朝鲜引进中国。', 'http://www.boqii.com/entry/photo/2330/0,http://www.boqii.com/entry/photo/2330/5087', '　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '松香草属', '串叶松香草', 'Silphium perfoliatum L.', '', '　　串叶松 　　串叶松香草茎上对生叶片的基部相连呈杯状，茎从两叶中间贯穿而出，故名串叶松香草。一年生串叶松香草当年植株呈丛叶莲座状，不抽茎，根圆形肥大、粗壮，具水平状多节的根茎和营养根。根茎出数个具有紫红色鳞片的根基芽。第二年每小根茎形成一个新枝。植株形略似菊芋。株高1.5～2米，叶片大，长椭圆形，叶缘有疏锯齿，叶面有刚毛，基叶有叶柄，茎方、四棱茎，叶对生，无柄，茎叶基部叶片相连。', '　　为北美洲独有的一属植物，于1979年从朝鲜被引入我国，现在在我国各省均有栽培。串叶松香草不但可以用于观赏，还有很高的营养价值，非常适合用作。　　串叶松香草喜肥沃湿润的土壤，在沙土、黏土、酸性土、碱性土均能很好生长，对于红黄壤适应性能好。对水肥要求较高，根系能深入土层下部吸收深层水分，因而出耐旱特性，同时有大量须根分布在耕作层内，又能充分吸收土壤中的营养物质，因此在降水量充足的条件下，能迅速生长，在干旱时期不致旱死。串叶松香草耐高温，在盛夏不浇水，叶片也不下垂，水、肥、热条件越好越能发挥其增产潜力。耐寒冷，在－42～－38℃时也不会，但大部分茎叶萎缩，进入休眠期。适于pH值（5～6）的土壤上栽培。', '　　串叶松　　串叶松香草可以进行无性繁殖，在粗放', 'http://img.boqiicdn.com/Data/BK/P/imagick73461450258830.jpg', 'http://www.boqii.com/entry/detail/2330.html', '');
INSERT INTO `plant_family` VALUES ('604', '凝脂莲', 'Sedum clavatum', '凝脂莲', '乙姬牡丹，乙女牡丹，劳尔、峡谷景天', '不容易死', '墨西哥', 'http://www.boqii.com/entry/photo/2353/0,http://www.boqii.com/entry/photo/2353/5063', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '景天属', '', 'Sedum clavatum', '', '　　 　　凝脂莲为多年生半灌木，多分枝，凝脂莲常从茎的下部生出新芽，形成群生。叶匙形，互生，排列成莲座状；表面光洁，正面平坦，背面微微隆起，肉质厚实，翠绿色或嫩绿色，叶面上被白粉，并透出密布的极细微的白色颗粒。在光照充足、', '　　凝脂莲因其外形如脂状的嫩叶与娇翠的花色构成了他如牡丹般的俊美，深受多肉爱好者的喜爱。凝脂莲比较容易群生，叶片呼声，所以观赏价值比较高。人工栽培凝脂莲的难度并不高，但是想要凝脂莲健康漂亮却并不简单。　　凝脂莲花开在叶尖而不是茎上，经过足够的光照后，在春季开花就会开出一簇簇粉白色的小花，犹如刚出沐浴处子。在冬季，凝脂莲的优势就体现的淋漓尽致，其他的在夏季可能会萎蔫，但是凝脂莲却能越变越美丽，越来越水灵。尤其是度天以后，在初秋的低温和光照条件下，其叶片会由绿转红，叶片更加美丽动人，就好像出嫁的女儿，那一刻红的动人。　　凝脂莲生性喜爱光照，只有接受足够的光照以后，其叶片才能出落的艳丽肥嫩。凝脂莲在其养殖过程中，每隔2年左有就要进行换盆操作，放弃盆栽过小影响其正常的生长。换盆的时候不要立马浇水，等其干燥以后再进行浇水。　　施肥的话，大约每一个季度施肥一次即可，肥料可选长效肥。因为凝脂莲属于小型植株，最好将其养在室内做观赏用，室内比较容易控制。夏季的时候，如果温度超过了35摄氏度后，就要采取适当的遮阳操作，并且减少浇水的量和次数，甚至可以做到不给水。一直等到入秋等气温下降以后才恢复供水。冬季的时候，如果温度低于0度，也要减少对其供水，防止将植物冻伤，浇水的方法可以采用人工滴水的办法，适当的滴在植物的根部即可。然后一直到春季再恢复供水。凝脂莲对于土壤的要求不高，主要以透气性为主，家庭有条件的可以选择用泥炭和煤渣河沙等混合配制，在其表面还需要铺设一层干净的河沙。', '　　　　1、叶插：将完整的成熟叶片平铺在潮润的沙土上，叶面朝上，叶背朝下，不必覆土，放置阴凉处，10天左右从叶片基部可长出小叶丛及新根，将根系埋入土中。出根后适当浇水，晒光（忌暴晒），渐渐地便会长成一棵茁壮的新株。　　2、枝干扦插：可用蘖枝或顶枝，剪取的插穗长短不限，但剪口要干燥后，去掉下部叶片，再插入沙床，避免过多水分蒸发。插后一般20天左右生根，生根后即可浇水；生根前底部叶片干枯、萎缩属正常现象，根系长好，水分吸收充足后悔自然恢复。土壤不能太湿，否则剪口易发黄', 'http://img.boqiicdn.com/Data/BK/P/imagick44761450863076.jpg', 'http://www.boqii.com/entry/detail/2353.html', '');
INSERT INTO `plant_family` VALUES ('605', '甘菊', 'Camomile', '甘菊', '岩香菊、野菊花', '不容易死', '欧洲大陆、中国甘肃、新疆及西藏等地', 'http://www.boqii.com/entry/photo/2225/0,http://www.boqii.com/entry/photo/2225/5302', '　　', '被子植物门', '双子叶植物纲', '桔梗目', '菊科', '菊属', '', 'Chrysanthemum lavandulifolium （Fisch.ex Trautv.） Ling et Shih', '', '　　 　　甘菊为多年生草本，高0.3－1.5米，有地下匍匐茎。茎直立，自中部以上多分枝或仅上部伞房状花序分枝。茎枝有稀疏的柔毛，但上部及花序梗上的毛稍多。基部和下部叶花期脱落。', '　　和我们常说的洋甘菊并不同，甘菊是菊花起源的重要亲本之一。甘菊的经济价值比较高，不但可以用于观赏，还能食用，栽培难度也不高，所以深受人们的喜爱。　　甘菊生物学特性喜温暖湿润气候、阳光充足、忌遮荫。耐寒，稍耐旱，怕水涝，喜肥。生山坡、上、河谷、河岸、荒地及黄土丘陵地，海拔630－2800米。　　最适20℃左右，在0－10℃以下能生长，花期能耐－4℃，根可耐－16～－17℃的低温。对土壤要求不严。以地热高燥，背风向阳，疏松肥沃，含丰富的腐殖质，排水良好，pH6－8的砂质壤土或壤土栽培为宜。忌连作。可与早玉米、桑、蚕豆、烟草、油菜、、小麦间套作。粘重土、低洼积水地不宜栽种。', '　　　　1、扦插繁殖、育苗移栽法：4月下旬至5月上旬截取母株的幼枝作插穗，随剪随插，插穗长10－12cm，顶端留2片叶，除去下部2－3节的叶片，插入土中5cm，顶端露出3cm，按行距24cm开沟，沟深14cm，每隔15－20cm，扦插1株，覆土压实，浇水。扦插后要遮荫，经常浇水保湿，松土除草，每隔半月施稀人粪尿1次，约经15－20d生根，待　　2、分株繁殖：11月选优良植株，收花后割除残茎，培土', 'http://img.boqiicdn.com/Data/BK/P/imagick64101447667538.jpg', 'http://www.boqii.com/entry/detail/2225.html', '');
INSERT INTO `plant_family` VALUES ('606', '萱草', 'Hemerocallis fulva （L.） L.', '萱草', '黄花菜，金针菜、鹿葱、川草花、忘郁、丹棘等', '不容易死', '原产于中国、西伯利亚、日本和东南亚', 'http://www.boqii.com/entry/photo/2051/0,http://www.boqii.com/entry/photo/2051/5476', '　　', '被子植物门', '单子叶植物纲', '百合目', '百合科', '萱草属', '萱草', 'Hemerocallis fulva （L.） L.', '', '　　 　　萱草根茎肉质，中下部有纺锤状膨大；叶一般较宽；花早上开晚上凋谢，无香味，桔红色至桔黄色，内花被裂片下部一般有∧形采斑。这些特征可以区别于本国产的其他', '　　', '　　　\n　一、分株繁殖\n　　分株繁殖于叶枯萎后或早春萌发前进行，将根株掘起剪去枯根及过多的须根，分株即可。一次分株后可4～5年后再分株，分株苗当年即可开花。一般每个母株可分生3～4株，个别品种，例如“金金娃”可分生6～7株。　\n　二、播种繁殖\n　　种子繁殖宜秋播，一般播后4星期左右出苗。夏秋种子采下后如立即播种，20天左右出苗。播种苗培育2年后开花。　　播种繁殖宜在秋、冬季将种子作沙藏', 'http://img.boqiicdn.com/Data/BK/P/imagick65281442483704.jpg', 'http://www.boqii.com/entry/detail/2051.html', '');
INSERT INTO `plant_family` VALUES ('607', '剪秋罗', 'Lychnis fulgens', '剪秋罗', '大花剪秋罗', '不容易死', '日本、俄罗斯、朝鲜及云南、山西、内蒙古、黑龙江、四川等地', 'http://www.boqii.com/entry/photo/2411/0,http://www.boqii.com/entry/photo/2411/5004', '　', '被子植物门 Angiospermae', '双子叶植物纲 Dicotyledoneae', '中央种子目 Centrospermae', '石竹科 Caryophyllaceae', '剪秋罗属 Lychnis', '', 'Lychnis fulgens', '', '　　 　　剪秋罗为多年生草本，高50-80厘米，全株被柔毛。根簇生，纺锤形，稍肉质。茎直立，不分枝或上部分枝。叶片卵状长圆形或卵状披针形，长4-10厘米，宽2-4厘米，基部圆形，稀宽楔形，不呈柄状，顶端渐尖，两面和边缘均被粗毛。二歧聚伞花序具数花，稀多数花，紧缩呈伞房状；花直径3.5-5厘米，花梗长3-12毫米；苞片卵状披针形，草质，密被长柔毛和缘毛；花萼筒状棒形，长15-20毫米，直径3-3.5厘米，后期上部微膨大，被稀疏白色长柔毛，沿脉较密，萼齿三角状，顶端急尖；', '　　的花型奇特，耐寒力较强，但怕夏季酷暑，人工栽培需注意避免暴晒。由于剪秋罗在凋零后依然芳香依旧，不像别的花只有在开花的时候才会香，所以受到很多花友的喜爱。　　剪秋罗属性喜凉爽、湿润的气候。高温多雨季节不良。在蔽荫的环境及疏松、排水良好的土壤中生长良好。常用播种和分株方法繁殖。栽培容易，幼苗期需注意摘心。电长期保持土壤湿润与施肥。雨季要时排水。其花瓣呈剪碎状。美丽异常。可作开花地被或作花坛、盆花、之用。', '　　　　剪秋罗以分株繁殖为主，春秋两季均可分栽。也可用分株时切断的粗根扦插，将根段全部埋人土中，让上切口与土面相齐，蔽荫养护。根段上切口处的不定芽萌发后可抽生株丛，下面萌生新根，成活率很高。还可在3?4月间播种，5月上旬分苗定植，7月份就能开花。8月下旬在冷床或温室盆播，来年4月初定植，5月下旬可全部开花。因属宿根', 'http://img.boqiicdn.com/Data/BK/P/imagick57051452503551.jpg', 'http://www.boqii.com/entry/detail/2411.html', '');
INSERT INTO `plant_family` VALUES ('608', '毛叶莲花掌', 'Aeonium simsii', '毛叶莲花掌', '', '不容易死', '原产大西洋的加那利群岛', 'http://www.boqii.com/entry/photo/2468/0,http://www.boqii.com/entry/photo/2468/4949', '　　', '被子植物门', '双子叶植物纲', '蔷薇目', '景天科', '莲花掌属', '莲花掌', 'Aeonium simsii', '', '　　毛叶 　　毛叶莲花掌为丛生垫状，小枝多叶，叶不易脱落，排列成莲座状，线皮针形，长6－9cm。宽0.6cm浅绿色，具红张，叶缘有0.2－0.4cm长的白毛，花金黄。', '　　又名墨染，为景天科、莲花掌属多肉植物。毛叶莲花掌的枝叶繁茂，四季常青，有一定的观赏价值，人工栽培毛叶莲花掌的难度并不高，所以受到很多多肉爱好者的喜爱。　　毛叶莲花掌冬季需温暖，夏季宜凉爽。土壤可用肥沃又排水透气好的养殖土种植，煤渣混合泥炭珍珠岩，差不多透气就可以。期浇水不宜多，切忌积水和雨淋。保持干燥，如湿度大、光线不足，叶片易徒长。夏季应保持半阴、通风。多喷水，保持较高的空气。秋季生长旺盛期，每月施肥1次。冬季要求阳光充足，温度不宜过高，以维持10℃最好。', '　　毛叶　　毛叶莲花掌多用扦插法繁殖，可剪取分枝顶端作插穗，插入素沙土中，插后保持盆土稍有潮润极易生根。或者用叶插和茎插，插后约3－4周生根，扦插容易生根，成苗块。插种，种子', 'http://img.boqiicdn.com/Data/BK/P/imagick80451454059293.jpg', 'http://www.boqii.com/entry/detail/2468.html', '');
