DROP TABLE IF EXISTS `plant_family`;
CREATE TABLE `plant_family` (
  `plantID` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) DEFAULT NULL,
  `engName` varchar(255) DEFAULT NULL,
  `botanicalName` varchar(255) DEFAULT NULL COMMENT '学名',
  `alias` varchar(255) DEFAULT NULL COMMENT '别名',
  `life` varchar(255) DEFAULT NULL COMMENT '寿命',
  `area` varchar(255) DEFAULT NULL COMMENT '区域',
  `imageURL` tinytext COMMENT '图片地址',
  `kingdom` varchar(255) DEFAULT NULL COMMENT '界',
  `phylum` varchar(255) DEFAULT NULL COMMENT '门',
  `class` varchar(255) DEFAULT NULL COMMENT '纲',
  `order` varchar(255) DEFAULT NULL COMMENT '目',
  `family` varchar(255) DEFAULT NULL COMMENT '科',
  `genus` varchar(255) DEFAULT NULL COMMENT '属',
  `species` varchar(255) DEFAULT NULL COMMENT '种',
  `latinName` varchar(255) DEFAULT NULL COMMENT '拉丁名称',
  `binomialNomenclature` varchar(255) DEFAULT NULL COMMENT '二名法',
  `des` text COMMENT '简介',
  `feature` text COMMENT '体态',
  `careKnowledge` text COMMENT '养护知识',
  `coverURL` varchar(255) DEFAULT NULL COMMENT '封面图片地址',
  `scrapyURL` varchar(255) DEFAULT NULL,
  `scrapyTime` varchar(0) DEFAULT NULL,
  PRIMARY KEY (`plantID`)
) ENGINE=InnoDB AUTO_INCREMENT=609 DEFAULT CHARSET=utf8mb4;

